local LOADING_HOST_NAME = "NodeHubLoadingHost"

-- WAJIB PlayerGui saja (setelah loading).
-- gethui/CoreGui/protect_gui → Plugin capability error.
local function destroyNamedGui(name)
    local pg = PlayerGui:FindFirstChild(name)
    if pg then
        pcall(function()
            pg:Destroy()
        end)
    end
    pcall(function()
        if typeof(gethui) == "function" then
            local hui = gethui()
            local old = hui and hui:FindFirstChild(name)
            if old then
                old:Destroy()
            end
        end
    end)
    pcall(function()
        local cg = game:GetService("CoreGui")
        local old = cg:FindFirstChild(name)
        if old then
            old:Destroy()
        end
    end)
    -- host SurfaceGui milik kita (bukan LoadingScreenMenu game)
    pcall(function()
        local host = workspace:FindFirstChild(LOADING_HOST_NAME)
        if host then
            host:Destroy()
        end
    end)
end

local function isLoadingActive()
    local menu = workspace:FindFirstChild("LoadingScreenMenu")
    -- Menu masih ada → hub HARUS di host (di atas loading), meski PlotId sudah ada
    if menu ~= nil then
        return true
    end
    if LP:GetAttribute("LoadingScreenDone") == true then
        return false
    end
    -- Active nyangkut tanpa menu: baru pakai worldReady biar tidak stuck di host
    if LP:GetAttribute("LoadingScreenActive") == true then
        local worldReady = workspace:FindFirstChild("Gardens") ~= nil
            and LP:GetAttribute("PlotId") ~= nil
            and LP.Character ~= nil
        if worldReady then
            return false
        end
        return true
    end
    return false
end

-- Host SurfaceGui SENDIRI di depan kamera (lebih dekat dari loading -16).
-- Jangan parent ke LoadingScreenMenu game — saat loading destroy, hub ikut hilang.
local function keepHubAboveLoading(sg, overlay, miniBtn)
    task.spawn(function()
        local hostPart, hostGui, renderConn
        local usingHost = false

        local function destroyHost()
            if renderConn then
                pcall(function()
                    renderConn:Disconnect()
                end)
                renderConn = nil
            end
            -- JANGAN Destroy host kalau overlay/mini masih child-nya
            if hostPart then
                local stillHolding = false
                pcall(function()
                    if overlay and overlay:IsDescendantOf(hostPart) then
                        stillHolding = true
                    end
                    if miniBtn and miniBtn:IsDescendantOf(hostPart) then
                        stillHolding = true
                    end
                end)
                if not stillHolding then
                    pcall(function()
                        hostPart:Destroy()
                    end)
                end
            end
            hostPart, hostGui = nil, nil
        end

        local function restoreToScreenGui()
            if not (sg and sg.Parent) then
                return false
            end
            -- cabut dari host DULU (terpisah pcall), baru enable ScreenGui
            if overlay and overlay.Parent ~= sg then
                pcall(function()
                    overlay.Parent = sg
                end)
            end
            if miniBtn and miniBtn.Parent ~= sg then
                pcall(function()
                    miniBtn.Parent = sg
                end)
            end
            pcall(function()
                if overlay then
                    overlay.Active = false
                end
                sg.Enabled = true
                sg.DisplayOrder = 99999
            end)
            usingHost = false
            destroyHost()
            return sg.Enabled == true
        end

        local hostDestroyConn
        local function watchHostDestroy(part)
            if hostDestroyConn then
                pcall(function()
                    hostDestroyConn:Disconnect()
                end)
                hostDestroyConn = nil
            end
            if not part then return end
            hostDestroyConn = part.Destroying:Connect(function()
                if usingHost and sg and sg.Parent and overlay then
                    task.defer(restoreToScreenGui)
                end
            end)
        end

        local function ensureHost()
            if hostPart and hostPart.Parent and hostGui and hostGui.Parent then
                return hostGui
            end
            -- reparent dulu sebelum buang host rusak
            if overlay and sg and overlay.Parent ~= sg then
                pcall(function()
                    overlay.Parent = sg
                end)
            end
            if miniBtn and sg and miniBtn.Parent ~= sg then
                pcall(function()
                    miniBtn.Parent = sg
                end)
            end
            destroyHost()

            local part = Instance.new("Part")
            part.Name = LOADING_HOST_NAME
            part.Anchored = true
            part.CanCollide = false
            -- WAJIB true: SurfaceGui terima klik lewat raycast part.
            part.CanQuery = true
            part.CanTouch = false
            part.CastShadow = false
            part.Transparency = 1
            part.Size = Vector3.new(1, 1, 0.1)
            part:SetAttribute("GAG2HubHost", true)
            part.Parent = workspace

            local gui = Instance.new("SurfaceGui")
            gui.Name = "NodeHubHostGui"
            gui.AlwaysOnTop = true
            gui.Active = true
            gui.LightInfluence = 0
            gui.ResetOnSpawn = false
            gui.ZIndexBehavior = Enum.ZIndexBehavior.Sibling
            gui.SizingMode = Enum.SurfaceGuiSizingMode.FixedSize
            gui.PixelsPerStud = 50
            gui.Face = Enum.NormalId.Front
            gui.MaxDistance = 1000
            gui.Parent = part

            hostPart, hostGui = part, gui
            watchHostDestroy(part)

            renderConn = RunService.RenderStepped:Connect(function()
                if not (hostPart and hostPart.Parent) then
                    return
                end
                local cam = workspace.CurrentCamera
                if not cam then
                    return
                end
                -- Loading game di Z=-16; kita di -10 → di depan loading
                local halfFov = math.rad(cam.FieldOfView / 2)
                local dist = 10
                local h = math.tan(halfFov) * dist * 2
                local w = h * (cam.ViewportSize.X / math.max(cam.ViewportSize.Y, 1))
                hostPart.Size = Vector3.new(w, h, 0.1)
                hostPart.CFrame = cam.CFrame * CFrame.new(0, 0, -dist) * CFrame.Angles(0, math.pi, 0)
                hostGui.CanvasSize = cam.ViewportSize
            end)

            return hostGui
        end

        local function sinkLoadingGuiInput()
            local menu = workspace:FindFirstChild("LoadingScreenMenu")
            if not menu then return end
            pcall(function()
                for _, d in ipairs(menu:GetDescendants()) do
                    if d:IsA("BasePart") then
                        d.CanQuery = false
                    elseif d:IsA("SurfaceGui") then
                        d.Active = false
                    end
                end
            end)
        end

        local function attachToHost()
            local gui = ensureHost()
            if not gui or not overlay then
                return
            end
            pcall(function()
                if overlay.Parent ~= gui then
                    overlay.Parent = gui
                end
                overlay.ZIndex = 10
                overlay.Active = true
                if miniBtn then
                    if miniBtn.Parent ~= gui then
                        miniBtn.Parent = gui
                    end
                    miniBtn.ZIndex = 11
                    miniBtn.Active = true
                end
                if sg then
                    sg.Enabled = false
                end
            end)
            sinkLoadingGuiInput()
            usingHost = true
        end

        while sg and sg.Parent do
            if not overlay or not overlay.Parent then
                break
            end
            if isLoadingActive() then
                attachToHost()
            else
                restoreToScreenGui()
                for _ = 1, 20 do
                    if not (sg and sg.Parent) then break end
                    if isLoadingActive() then
                        break
                    end
                    if sg.Enabled ~= true then
                        pcall(function()
                            sg.Enabled = true
                            sg.DisplayOrder = 99999
                        end)
                    end
                    if LP:GetAttribute("LoadingScreenDone") == true
                        and workspace:FindFirstChild("LoadingScreenMenu") == nil then
                        break
                    end
                    task.wait(0.15)
                end
                if not isLoadingActive() then
                    break
                end
            end
            task.wait(0.15)
        end

        if sg and sg.Parent then
            restoreToScreenGui()
            pcall(function()
                sg.Enabled = true
                sg.DisplayOrder = 99999
            end)
        end
        if hostDestroyConn then
            pcall(function()
                hostDestroyConn:Disconnect()
            end)
        end
    end)
end 

