    self.activeSubKey   = nil
    self.footerConfig = {
        default = nil,
    }
    
    -- setelah self.content dan self.footer dibuat & di-Parent
self._footerHeight = self.footer.Size.Y.Offset   -- misal 32 / 36 px (pakai yang ada sekarang)

-- simpan size content saat footer ON (default)
