    miniBtn.BackgroundColor3 = COLOR_PANEL
    miniBtn.AutoButtonColor = false
    miniBtn.BorderSizePixel = 0
    miniBtn.Image = iconId
    miniBtn.ScaleType = Enum.ScaleType.Fit
