-- ======================
-- INTERNAL: UPDATE LABEL
-- ======================
function MainUI:_updateContentLabel()
    local mainKey = self.activeMainKey or "-"
    local subKey  = self.activeSubKey or "-"
    --self.contentLabel.Text = string.format("Content: MainTab = %s | SubTab = %s", mainKey, subKey)
end

-- ======================
-- API: REGISTER MAIN TAB
-- ======================
function MainUI:RegisterMainTab(key, label, order)
    if self.mainTabButtons[key] then
        return -- sudah ada
    end

    self.mainTabs[key] = {
        label = label or key,
        order = order or 1,
    }

    local btn = Instance.new("TextButton")
    btn.Name = "Tab_" .. key
    btn.Size = UDim2.new(1, 0, 0, 26)
    btn.BackgroundColor3 = COLOR_PANEL
    btn.AutoButtonColor = false
    btn.Font = Enum.Font.GothamBold
    btn.Text = string.upper(label or key)
    btn.BorderSizePixel = 0
    btn.TextSize = 12
    btn.TextXAlignment = Enum.TextXAlignment.Center
    btn.TextColor3 = COLOR_WHITE
    btn.LayoutOrder = order or 1
    btn.Parent = self.sidebar

    local pad = Instance.new("UIPadding")
    pad.PaddingLeft = UDim.new(0, 0)
    pad.Parent = btn

    local underline = Instance.new("Frame")
    underline.Name = "Underline"
    underline.BackgroundColor3 = COLOR_YELLOW
    underline.Size = UDim2.new(0, 0, 0, 2)
    underline.Position = UDim2.new(0, 8, 1, -2)
    underline.BorderSizePixel = 0
    underline.BackgroundTransparency = 0.35
    underline.Parent = btn

    self.mainTabButtons[key] = btn

    btn.MouseEnter:Connect(function()
        if self.activeMainKey ~= key then
            tweenColor(btn, "TextColor3", COLOR_YELLOW)
        end
    end)

    btn.MouseLeave:Connect(function()
        if self.activeMainKey ~= key then
            tweenColor(btn, "TextColor3", COLOR_WHITE)
        end
    end)

    btn.MouseButton1Click:Connect(function()
        self:SetActiveMainTab(key)
    end)
end

-- ======================
-- API: REGISTER SUB TAB
-- ======================
function MainUI:RegisterSubTab(mainKey, subKey, label, builderFn, order)
    self.subTabs[mainKey] = self.subTabs[mainKey] or {}
    self.subTabs[mainKey][subKey] = {
        label   = label or subKey,
        order   = order or 1,
        builder = builderFn,
    }

    -- kalau mainKey sedang aktif, rebuild bar subtab
    if self.activeMainKey == mainKey then
        self:_rebuildSubTabs(mainKey)
    end
end

-- INTERNAL: rebuild bar sub tab untuk 1 mainKey
-- INTERNAL: rebuild bar sub tab untuk 1 mainKey
function MainUI:_rebuildSubTabs(mainKey)
    -- hapus tombol lama
    for _, child in ipairs(self.subBar:GetChildren()) do
        if child:IsA("TextButton") then
            child:Destroy()
        end
    end
    self.subTabButtons = {}

    local list = self.subTabs[mainKey]
    if not list then return end

    -- sort by order
    local arr = {}
    for sk, info in pairs(list) do
        table.insert(arr, { key = sk, info = info })
    end
    table.sort(arr, function(a,b)
        return (a.info.order or 1) < (b.info.order or 1)
    end)

    ----------------------------------------------------------------
    -- AUTO WIDTH: makin banyak sub tab → makin kecil
    ----------------------------------------------------------------
    local count = #arr
    local baseWidth = 80
    local minWidth  = 73
    local maxWidth  = 120
    local btnWidth  = baseWidth

    if count > 0 then
        if count <= 4 then
            btnWidth = baseWidth
        else
            local shrinkStep = 8
            btnWidth = baseWidth - (count - 4) * shrinkStep
        end
        btnWidth = math.clamp(btnWidth, minWidth, maxWidth)
    end

    ----------------------------------------------------------------
    -- BUILD BUTTONS: style D (glow border)
    ----------------------------------------------------------------
    for _, item in ipairs(arr) do
        local subKey = item.key
        local info   = item.info

        local btn = Instance.new("TextButton")
        btn.Name = "Sub_" .. subKey
        btn.AutoButtonColor = false
        btn.Size = UDim2.new(0, btnWidth, 1, 0)
        btn.BackgroundColor3 = COLOR_PANEL          -- gelap, menyatu dengan bar
        btn.BorderSizePixel = 0
        btn.Text = info.label
        btn.TextSize = 12
        btn.Font = Enum.Font.GothamBold
        btn.TextTruncate = Enum.TextTruncate.AtEnd
        btn.TextColor3 = COLOR_GRAY_TEXT            -- non-aktif default
        btn.LayoutOrder = info.order or 1
        btn.Parent = self.subBar
        createCorner(btn, 999)

        -- border neon / ghost
        local stroke = createStroke(btn, Color3.fromRGB(90,90,90), 1, 0.5)
        -- Transparency 0.5 → ghost, non-aktif

        self.subTabButtons[subKey] = {
            button = btn,
            stroke = stroke,
        }

        -- hover effect: sedikit terang kalau belum aktif
        btn.MouseEnter:Connect(function()
            if self.activeSubKey ~= subKey then
                tweenColor(btn, "TextColor3", Color3.fromRGB(220,220,220))
                stroke.Transparency = 0.3
            end
        end)

        btn.MouseLeave:Connect(function()
            if self.activeSubKey ~= subKey then
                tweenColor(btn, "TextColor3", COLOR_GRAY_TEXT)
                stroke.Transparency = 0.5
            end
        end)

        btn.MouseButton1Click:Connect(function()
            self:_setActiveSubTab(mainKey, subKey)
        end)
    end
end


function MainUI:_applySubTabVisual(activeSubKey)
    local style = self.subTabStyle or "pill"

        ----------------------------------------------------------------
    -- STYLE D: glow neon capsule border
    ----------------------------------------------------------------
    for sKey, pack in pairs(self.subTabButtons) do
        local btn    = pack.button
        local stroke = pack.stroke

        if sKey == subKey then
            -- 🔥 AKTIF → border neon kuning, teks kuning
            tweenColor(btn, "BackgroundColor3", Color3.fromRGB(16,16,16))
            tweenColor(btn, "TextColor3", COLOR_YELLOW)

            if stroke then
                stroke.Color        = COLOR_YELLOW
                stroke.Thickness    = 2
                stroke.Transparency = 0     -- full terlihat
            end
        else
            -- 🌑 NON-AKTIF → border abu ghost, teks abu
            tweenColor(btn, "BackgroundColor3", COLOR_PANEL)
            tweenColor(btn, "TextColor3", COLOR_GRAY_TEXT)

            if stroke then
                stroke.Color        = Color3.fromRGB(90,90,90)
                stroke.Thickness    = 1
                stroke.Transparency = 0.5   -- ghost
            end
        end
    end

end

-- ======================
-- API: SET ACTIVE MAIN TAB
-- ======================
function MainUI:SetActiveMainTab(key)
    self.activeMainKey = key

    for name, btn in pairs(self.mainTabButtons) do
        local underline = btn:FindFirstChild("Underline")
        if name == key then
            tweenColor(btn, "TextColor3", COLOR_YELLOW)
            if underline then
                underline.Size = UDim2.new(1, -16, 0, 2)
                underline.BackgroundTransparency = 0
            end
        else
            tweenColor(btn, "TextColor3", COLOR_WHITE)
            if underline then
                underline.Size = UDim2.new(0, 0, 0, 2)
                underline.BackgroundTransparency = 0.35
            end
        end
    end

    self:_rebuildSubTabs(key)

    -- pick pertama berdasarkan order
    local list = self.subTabs[key]
    if list then
        local firstKey
        local firstOrder = math.huge
        for sk, info in pairs(list) do
            local o = info.order or 1
            if o < firstOrder then
                firstOrder = o
                firstKey = sk
            end
        end
        if firstKey then
            self:_setActiveSubTab(key, firstKey)
        end
    end

    local footerList = self.footerConfig[key] or self.footerConfig.default
self:_renderFooter(footerList)
self:_updateContentLabel()
end

-- INTERNAL: set active sub tab + panggil builder
function MainUI:_setActiveSubTab(mainKey, subKey)
    self.activeSubKey = subKey

    ----------------------------------------------------------------
    -- STYLE D: glow neon capsule border
    ----------------------------------------------------------------
    for sKey, pack in pairs(self.subTabButtons) do
        local btn    = pack.button
        local stroke = pack.stroke

        if sKey == subKey then
            -- 🔥 AKTIF → border neon kuning, teks kuning
            tweenColor(btn, "BackgroundColor3", Color3.fromRGB(16,16,16))
            tweenColor(btn, "TextColor3", COLOR_YELLOW)

            if stroke then
                stroke.Color        = COLOR_YELLOW
                stroke.Thickness    = 2
                stroke.Transparency = 0     -- full terlihat
            end
        else
            -- 🌑 NON-AKTIF → border abu ghost, teks abu
            tweenColor(btn, "BackgroundColor3", COLOR_PANEL)
            tweenColor(btn, "TextColor3", COLOR_GRAY_TEXT)

            if stroke then
                stroke.Color        = Color3.fromRGB(90,90,90)
                stroke.Thickness    = 1
                stroke.Transparency = 0.5   -- ghost
            end
        end
    end

    ----------------------------------------------------------------
    -- sisanya tetap sama
    ----------------------------------------------------------------
    self:ClearSubContent()

    local info = self.subTabs[mainKey] and self.subTabs[mainKey][subKey]
    if info and info.builder then
        local ok, err = pcall(info.builder)
        if not ok then
            warn(string.format("[NodeHub] SubTab %s/%s builder error: %s", tostring(mainKey), tostring(subKey), tostring(err)))
            self:CreateRowLabel(self.content, "Tab error: " .. tostring(err))
        end
    end

    self:_updateContentLabel()
end


-- ======================
-- API: CLEAR SUB CONTENT
-- ======================
function MainUI:ClearSubContent()
    if type(self._pendingInputCommits) == "table" then
        for _, fn in ipairs(self._pendingInputCommits) do
            pcall(fn)
        end
        self._pendingInputCommits = {}
    end

    local G = (getgenv and getgenv()) or _G
    if type(G.__GAG2_BEFORE_TAB_CHANGE) == "function" then
        pcall(G.__GAG2_BEFORE_TAB_CHANGE)
    end

    for _, child in ipairs(self.content:GetChildren()) do
        if child ~= self.contentLabel and not child:IsA("UIListLayout") and not child:IsA("UIPadding") then
            child:Destroy()
        end
    end
end


function MainUI:CloseDropdownOverlays()
    local root = self._sg or self.right or PlayerGui
    if not root then return end
    for _, desc in ipairs(root:GetDescendants()) do
        if desc.Name == "NodeHubDropdownOverlay" or desc.Name == "NodeHubModeOverlay" then
            pcall(function() desc:Destroy() end)
        end
    end
end


function MainUI:RefreshContentLayout()
    local content = self.content
    if not content or not content.Parent then
        return
    end
    self._contentLayoutGen = (tonumber(self._contentLayoutGen) or 0) + 1
    local gen = self._contentLayoutGen
    task.defer(function()
        if gen ~= self._contentLayoutGen then
            return
        end
        pcall(function()
            if not content.Parent then return end
            content.Size = UDim2.new(
                content.Size.X.Scale,
                content.Size.X.Offset,
                content.Size.Y.Scale,
                content.Size.Y.Offset
            )
            for _, child in ipairs(content:GetChildren()) do
                if child:IsA("Frame") and child.Name:sub(1, 8) == "Section_" then
                    if child.AutomaticSize == Enum.AutomaticSize.Y then
                        child.Size = UDim2.new(1, 0, 0, 0)
                    end
                end
            end
        end)
    end)
end


function MainUI:CreateSection(title, defaultExpanded)
    title = title or "Section"

    -- kalau nggak diisi, default = tutup
    if defaultExpanded == nil then
        defaultExpanded = false
    end

    -- Root section frame (auto height)
    local section = Instance.new("Frame")
    section.Name = "Section_" .. title
    section.BackgroundTransparency = 1
    section.Size = UDim2.new(1, 0, 0, 0)
    section.AutomaticSize = Enum.AutomaticSize.Y
    section.LayoutOrder = #self.content:GetChildren() + 1
    section.Parent = self.content

    local sectionLayout = Instance.new("UIListLayout")
    sectionLayout.FillDirection = Enum.FillDirection.Vertical
    sectionLayout.SortOrder = Enum.SortOrder.LayoutOrder
    sectionLayout.Padding = UDim.new(0, 2)
    sectionLayout.Parent = section

    -- Header (clickable, buat buka/tutup)
    local header = Instance.new("TextButton")
    header.Name = "Header"
    header.AutoButtonColor = false
    header.BackgroundColor3 = COLOR_PANEL_ALT
    header.Size = UDim2.new(1, 0, 0, 26)
    header.LayoutOrder = 1
    header.ZIndex = 2
    header.Text = ""
    header.BorderSizePixel = 0
    header.Parent = section
    createCorner(header, 8)
    createStroke(header, COLOR_YELLOW, 1, 0.3)

    -- Title label kiri
    local titleLabel = Instance.new("TextLabel")
    titleLabel.Name = "Title"
    titleLabel.BackgroundTransparency = 1
    titleLabel.Size = UDim2.new(1, -40, 1, 0)
    titleLabel.Position = UDim2.new(0, 10, 0, 0)
    titleLabel.Font = Enum.Font.GothamBold
    titleLabel.TextXAlignment = Enum.TextXAlignment.Left
    titleLabel.TextSize = 13
    titleLabel.TextColor3 = COLOR_YELLOW
    titleLabel.Text = title
    titleLabel.Active = false
    titleLabel.Parent = header

    -- Icon panah kanan (▶ / ▼)
    local arrow = Instance.new("TextLabel")
    arrow.Name = "Arrow"
    arrow.BackgroundTransparency = 1
    arrow.Size = UDim2.new(0, 20, 1, 0)
    arrow.Position = UDim2.new(1, -26, 0, 0)
    arrow.Font = Enum.Font.GothamBold
    arrow.TextSize = 14
    arrow.TextXAlignment = Enum.TextXAlignment.Center
    arrow.TextColor3 = COLOR_GRAY_TEXT
    arrow.Text = "▼"
    arrow.Active = false
    arrow.Parent = header

    -- Body tempat isi section nanti
    local body = Instance.new("Frame")
    body.Name = "Body"
    body.BackgroundTransparency = 1
    body.Size = UDim2.new(1, 0, 0, 0)
    body.LayoutOrder = 2
    body.ZIndex = 1
    body.AutomaticSize = Enum.AutomaticSize.Y
    body.ClipsDescendants = true
    body.Parent = section

    local bodyPad = Instance.new("UIPadding")
    bodyPad.PaddingTop = UDim.new(0, 4)
    bodyPad.PaddingBottom = UDim.new(0, 4)
    bodyPad.PaddingLeft = UDim.new(0, 8)
    bodyPad.PaddingRight = UDim.new(0, 4)
    bodyPad.Parent = body

    local bodyLayout = Instance.new("UIListLayout")
    bodyLayout.FillDirection = Enum.FillDirection.Vertical
    bodyLayout.SortOrder = Enum.SortOrder.LayoutOrder
    bodyLayout.Padding = UDim.new(0, 4)
    bodyLayout.Parent = body

    local function refreshSectionLayout()
        self:RefreshContentLayout()
    end

    bodyLayout:GetPropertyChangedSignal("AbsoluteContentSize"):Connect(refreshSectionLayout)

    -- state buka/tutup
    local expanded = defaultExpanded

    local function setExpanded(on)
        expanded = on == true
        body.Visible = expanded
        arrow.Text = expanded and "▼" or "▶"

        if expanded then
            body.AutomaticSize = Enum.AutomaticSize.Y
            body.Size = UDim2.new(1, 0, 0, 0)
        else
            body.AutomaticSize = Enum.AutomaticSize.None
            body.Size = UDim2.new(1, 0, 0, 0)
        end

        refreshSectionLayout()
    end

    -- klik header → toggle
    header.MouseButton1Click:Connect(function()
        setExpanded(not expanded)
    end)

    -- hover effect halus
    header.MouseEnter:Connect(function()
        tweenColor(header, "BackgroundColor3", Color3.fromRGB(24, 24, 24))
    end)

    header.MouseLeave:Connect(function()
        tweenColor(header, "BackgroundColor3", COLOR_PANEL_ALT)
    end)

    -- set awal
    setExpanded(defaultExpanded)

    -- ⬅️ sekarang return 2 hal: body & fungsi setExpanded
    return body, setExpanded
end



function MainUI:ApplyRowLabelStyle(label, styleKeyOrOpts)
    return applyRowLabelStyle(label, styleKeyOrOpts)
end

function MainUI:GetRowLabelThemes()
    return ROW_LABEL_THEMES
end

----------------------------------------------------------
-- ROW: LABEL (optional description)
----------------------------------------------------------
function MainUI:CreateRowLabel(parent, text, desc, order, styleKey)
    local row = Instance.new("Frame")
    row.Name = "RowLabel"
    row.BackgroundTransparency = 1
    row.Size = UDim2.new(1, 0, 0, desc and 34 or 22)
    row.AutomaticSize = Enum.AutomaticSize.None
    row.LayoutOrder = order or (#parent:GetChildren() + 1)
    row.Parent = parent

    local title = Instance.new("TextLabel")
    title.BackgroundTransparency = 1
    title.Position = UDim2.new(0, 0, 0, 0)
    title.Size = UDim2.new(1, 0, 0, 18)
    title.Font = Enum.Font.Gotham
    title.TextXAlignment = Enum.TextXAlignment.Left
    title.TextSize = 12
    title.Text = text or ""
    title.Parent = row
    applyRowLabelStyle(title, styleKey or "default")

    if desc and desc ~= "" then
        local sub = Instance.new("TextLabel")
        sub.BackgroundTransparency = 1
        sub.Position = UDim2.new(0, 0, 0, 18)
        sub.Size = UDim2.new(1, 0, 0, 14)
        sub.Font = Enum.Font.Gotham
        sub.TextXAlignment = Enum.TextXAlignment.Left
        sub.TextSize = 11
        sub.Text = desc
        sub.Parent = row
        applyRowLabelStyle(sub, "info")
    end

    -- ⬅️ Tambah return kedua (title)
    return row, title
end


----------------------------------------------------------
-- ROW: TOGGLE (pill kanan)
--
-- Return: row, setGet, api
--   setGet(value, silent)  — set state; silent=true tidak panggil onChanged
--   api.set / api.setOn / api.setOff / api.get — sama, untuk dipakai di modul lain
--
-- momentary (arg7):
--   true  = ON lalu auto OFF setelah 1 detik (mode pulse)
--   number = ON lalu auto OFF setelah N detik
-- Untuk auto OFF setelah event eksternal (mis. save selesai), pakai api.setOff(true)
----------------------------------------------------------
function MainUI:CreateRowToggle(parent, labelText, initial, onChanged, order, labelStyle, momentary)
    local row = Instance.new("Frame")
    row.Name = "RowToggle"
    row.BackgroundTransparency = 1
    row.Size = UDim2.new(1, 0, 0, 26)
    row.LayoutOrder = order or (#parent:GetChildren() + 1)
    row.Parent = parent

    local label = Instance.new("TextLabel")
    label.Name = "Label"
    label.BackgroundTransparency = 1
    label.Position = UDim2.new(0, 0, 0, 0)
    label.Size = UDim2.new(1, -70, 1, 0)
    label.Font = Enum.Font.Gotham
    label.TextXAlignment = Enum.TextXAlignment.Left
    label.TextSize = 12
    label.Text = labelText or "Toggle"
    label.Parent = row
    applyRowLabelStyle(label, labelStyle or "toggle")

    local toggleBtn = Instance.new("TextButton")
    toggleBtn.Name = "Toggle"
    toggleBtn.AutoButtonColor = false
    toggleBtn.BackgroundColor3 = Color3.fromRGB(30,30,30)
    toggleBtn.Size = UDim2.new(0, 48, 0, 20)
    toggleBtn.Position = UDim2.new(1, -52, 0.5, -10)
    toggleBtn.Text = ""
    toggleBtn.BorderSizePixel = 0
    toggleBtn.Parent = row
    createCorner(toggleBtn, 10)
    createStroke(toggleBtn, Color3.fromRGB(60,60,60), 1, 0.6)

    local knob = Instance.new("Frame")
    knob.Name = "Knob"
    knob.Size = UDim2.new(0, 18, 0, 18)
    knob.Position = UDim2.new(0, 1, 0, 1)
    knob.BackgroundColor3 = Color3.fromRGB(220,220,220)
    knob.BorderSizePixel = 0
    knob.Parent = toggleBtn
    createCorner(knob, 9)

    local state = initial and true or false
    local bgTween = nil

    local function stopBgTween()
        if bgTween then
            pcall(function() bgTween:Cancel() end)
            bgTween = nil
        end
    end

    local function applyState(animate)
        stopBgTween()
        if state then
            knob.Position = UDim2.new(1, -19, 0, 1)
            if animate then
                bgTween = TweenService:Create(
                    toggleBtn,
                    TweenInfo.new(0.12, Enum.EasingStyle.Quad, Enum.EasingDirection.Out),
                    { BackgroundColor3 = COLOR_YELLOW }
                )
                bgTween:Play()
            else
                toggleBtn.BackgroundColor3 = COLOR_YELLOW
            end
        else
            knob.Position = UDim2.new(0, 1, 0, 1)
            if animate then
                bgTween = TweenService:Create(
                    toggleBtn,
                    TweenInfo.new(0.12, Enum.EasingStyle.Quad, Enum.EasingDirection.Out),
                    { BackgroundColor3 = Color3.fromRGB(30, 30, 30) }
                )
                bgTween:Play()
            else
                toggleBtn.BackgroundColor3 = Color3.fromRGB(30, 30, 30)
            end
        end
    end

    applyState(false)

    toggleBtn.MouseButton1Click:Connect(function()
        local pulseSec = nil
        if momentary == true then
            pulseSec = 1
        elseif type(momentary) == "number" and momentary > 0 then
            pulseSec = momentary
        end

        if pulseSec then
            if state then
                return
            end
            state = true
            applyState(true)
            if onChanged then
                pcall(onChanged, true)
            end
            task.delay(pulseSec, function()
                state = false
                applyState(false)
            end)
            return
        end

        state = not state
        applyState(true)
        if onChanged then
            onChanged(state)
        end
    end)

    -- getter/setter
    local function setGet(value, silent)
        if value ~= nil then
            state = value and true or false
            applyState(false)

            if (not silent) and onChanged then
                onChanged(state)
            end
        end

        return state
    end

    local api = {}

    function api.get()
        return state
    end

    function api.set(value, silent)
        return setGet(value, silent)
    end

    function api.setOn(silent)
        return setGet(true, silent)
    end

    function api.setOff(silent)
        return setGet(false, silent)
    end

    return row, setGet, api
end

----------------------------------------------------------
-- ROW: INPUT (text box dengan label kiri)
-- FIX:
--  ✅ text tidak keluar box (clip + padding)
--  ✅ bisa truncate "..." kalau kepanjangan
--  ✅ clearOnFocus opsional (arg5 boolean)
--  ✅ kalau clearOnFocus=false dan user klik doang (tanpa ngetik),
--     value BALIK ke currentValue (tidak jadi kosong)
--  ✅ allow empty kalau user memang sengaja mengosongkan (touched=true)
--
-- Signature:
--   CreateRowInput(parent, label, defaultText, onChanged, [clearOnFocusOrOrder], [maybeOrder])
--   arg5 number  => order
--   arg5 boolean => clearOnFocus (true=clear seperti lama, false=tidak clear)
----------------------------------------------------------
function MainUI:CreateRowInput(parent, labelText, defaultText, onChanged, noClearOrOrder, maybeOrder)
    local order = nil
    local clearOnFocus = true

    if type(noClearOrOrder) == "number" then
        order = noClearOrOrder
    elseif type(noClearOrOrder) == "boolean" then
        clearOnFocus = (noClearOrOrder == true)
        order = maybeOrder
    else
        clearOnFocus = true
        order = maybeOrder
    end

    local row = Instance.new("Frame")
    row.Name = "RowInput"
    row.BackgroundTransparency = 1
    row.Size = UDim2.new(1, 0, 0, 28)
    row.LayoutOrder = order or (#parent:GetChildren() + 1)
    row.Parent = parent

    local label = Instance.new("TextLabel")
    label.Name = "Label"
    label.BackgroundTransparency = 1
    label.Position = UDim2.new(0, 0, 0, 0)
    label.Size = UDim2.new(0.6, 0, 1, 0)
    label.Font = Enum.Font.Gotham
    label.TextXAlignment = Enum.TextXAlignment.Left
    label.TextSize = 12
    label.TextColor3 = COLOR_GRAY_TEXT
    label.Text = labelText or "Input"
    label.Parent = row

    local currentValue = (defaultText ~= nil) and tostring(defaultText) or ""
    local beforeFocusValue = currentValue
    local liveText = currentValue
    local committed = false

    local box = Instance.new("TextBox")
    box.Name = "Input"
    box.BackgroundColor3 = Color3.fromRGB(18,18,18)
    box.Size = UDim2.new(0.2, 0, 1, -5)
    box.Position = UDim2.new(0.79, 4, 0, 3)
    box.Font = Enum.Font.Gotham
    box.TextXAlignment = Enum.TextXAlignment.Center
    box.ClearTextOnFocus = false -- biar kita kontrol sendiri
    box.TextSize = 12
    box.TextColor3 = Color3.fromRGB(230,230,230)
    box.PlaceholderText = ""
    box.ClipsDescendants = true
    box.Parent = row

    local pad = Instance.new("UIPadding")
    pad.PaddingLeft  = UDim.new(0, 6)
    pad.PaddingRight = UDim.new(0, 6)
    pad.Parent = box

    pcall(function()
        box.TextTruncate = Enum.TextTruncate.AtEnd
    end)

    createCorner(box, 6)
    createStroke(box, Color3.fromRGB(60,60,60), 1, 0.6)

    local function trim(s)
        return (s and s:match("^%s*(.-)%s*$")) or ""
    end

    -- touched detection (lebih aman)
    local touched = false
    local internalSet = false

    local function setBoxText(v)
        internalSet = true
        box.Text = v
        internalSet = false
    end

    setBoxText(currentValue)

    local function commitPending()
        if committed then return end
        if not onChanged then return end

        local newText = liveText
        if box and box.Parent then
            newText = trim(box.Text)
        end
        newText = trim(newText)

        if newText == trim(currentValue) then return end

        committed = true
        currentValue = newText
        liveText = newText
        if box and box.Parent then
            setBoxText(currentValue)
        end
        onChanged(currentValue)
    end

    box:GetPropertyChangedSignal("Text"):Connect(function()
        if internalSet then return end
        liveText = trim(box.Text)
        if box:IsFocused() then
            touched = true
        end
    end)

    box.Focused:Connect(function()
        tweenColor(box, "BackgroundColor3", Color3.fromRGB(24,24,24))
        beforeFocusValue = currentValue
        touched = false
        committed = false

        if clearOnFocus and trim(box.Text) == trim(currentValue) then
            setBoxText("")
            liveText = ""
        end
    end)

    box.FocusLost:Connect(function(enterPressed)
        tweenColor(box, "BackgroundColor3", Color3.fromRGB(18,18,18))

        local newText = trim(box.Text)

        if not touched and newText == trim(currentValue) then
            setBoxText(currentValue)
            liveText = currentValue
            return
        end

        commitPending()
    end)

    box.Destroying:Connect(commitPending)

    self._pendingInputCommits = self._pendingInputCommits or {}
    table.insert(self._pendingInputCommits, commitPending)

    row.Destroying:Connect(function()
        for i = #self._pendingInputCommits, 1, -1 do
            if self._pendingInputCommits[i] == commitPending then
                table.remove(self._pendingInputCommits, i)
                break
            end
        end
    end)

    -- setter/getter
    local function setGet(value)
        if value ~= nil then
            currentValue = tostring(value)
            liveText = currentValue
            committed = false
            setBoxText(currentValue)
        end
        return currentValue
    end

    return row, setGet, commitPending
end


----------------------------------------------------------
-- ROW: SIMPLE LIST (list of toggle-buttons)
-- entries: { "Item A", "Item B", ... } atau
--          { {name="Item A", key="a"}, ... }
----------------------------------------------------------
function MainUI:CreateRowList(parent, titleText, entries, onItemToggle, order, labelStyle)
    entries      = entries or {}
    onItemToggle = onItemToggle or function() end

    --------------------------------------------------
    -- ROW + TITLE
    --------------------------------------------------
    local row = Instance.new("Frame")
    row.Name = "RowList"
    row.BackgroundTransparency = 1
    row.Size = UDim2.new(1, 0, 0, 0)
    row.AutomaticSize = Enum.AutomaticSize.Y
    row.LayoutOrder = order or (#parent:GetChildren() + 1)
    row.Parent = parent


    local title = Instance.new("TextLabel")
    title.Name = "Title"
    title.BackgroundTransparency = 1
    title.Position = UDim2.new(0, 0, 0, 0)
    title.Size = UDim2.new(1, 0, 0, 18)
    title.Font = Enum.Font.Gotham
    title.TextXAlignment = Enum.TextXAlignment.Left
    title.TextSize = 12
    title.Text = titleText or "List"
    title.Parent = row
    applyRowLabelStyle(title, labelStyle or "list")

    --------------------------------------------------
    -- CONTAINER LIST
    --------------------------------------------------
    local container = Instance.new("Frame")
    container.Name = "ListContainer"
    container.BackgroundColor3 = Color3.fromRGB(15, 15, 15)
    container.Position = UDim2.new(0, 0, 0, 20)
    container.Size = UDim2.new(1, 0, 0, 0)
    container.AutomaticSize = Enum.AutomaticSize.Y
    container.Parent = row

    createCorner(container, 6)
    createStroke(container, Color3.fromRGB(40, 40, 40), 1, 0.5)

    local pad = Instance.new("UIPadding")
    pad.PaddingTop    = UDim.new(0, 4)
    pad.PaddingBottom = UDim.new(0, 4)
    pad.PaddingLeft   = UDim.new(0, 4)
    pad.PaddingRight  = UDim.new(0, 4)
    pad.Parent = container

    local layout = Instance.new("UIListLayout")
    layout.FillDirection = Enum.FillDirection.Vertical
    layout.SortOrder = Enum.SortOrder.LayoutOrder
    layout.Padding = UDim.new(0, 2)
    layout.Parent = container

--------------------------------------------------
-- SEARCH BOX (FIX POSITION)
--------------------------------------------------
local searchText = ""

local searchWrap = Instance.new("Frame")
searchWrap.Name = "SearchWrap"
searchWrap.Parent = container
searchWrap.BackgroundTransparency = 1
searchWrap.Size = UDim2.new(1, 0, 0, 26)
searchWrap.LayoutOrder = -1

local searchBox = Instance.new("TextBox")
searchBox.Name = "SearchBox"
searchBox.Parent = searchWrap
searchBox.BackgroundColor3 = Color3.fromRGB(18, 18, 18)
searchBox.BorderSizePixel = 0
searchBox.Size = UDim2.new(1, 0, 0, 22)
searchBox.Position = UDim2.new(0, 0, 0, 0)
searchBox.Font = Enum.Font.Gotham
searchBox.TextSize = 11
searchBox.TextColor3 = Color3.fromRGB(210, 210, 210)
searchBox.PlaceholderText = "Search..."
searchBox.PlaceholderColor3 = Color3.fromRGB(105, 105, 105)
searchBox.TextXAlignment = Enum.TextXAlignment.Center
searchBox.Text = ""
searchBox.ClearTextOnFocus = false

createCorner(searchBox, 4)
createStroke(searchBox, Color3.fromRGB(32, 32, 32), 1, 0.45)


local searchPad = Instance.new("UIPadding")
searchPad.PaddingBottom = UDim.new(0, 4) -- jarak bawah (atur 3–6 sesuai selera)
searchPad.Parent = searchBox
    --------------------------------------------------
    -- STATE INTERNAL
    --------------------------------------------------
    local selectedMap    = {}           -- [key] = true/false
    local currentEntries = entries      -- list aktif sekarang

    local function normalizeEntry(e)
        if type(e) == "table" then
            return e.key or e.name, e.name or tostring(e.key)
        else
            return e, tostring(e)
        end
    end

local function norm(s)
    s = tostring(s or ""):lower()
    s = s:gsub("%s+", " ")
    return s
end

local function parsePet(label)
    label = tostring(label or "")

    -- ambil KG
    local kg = tonumber(label:match("([%d%.]+)%s*KG")) or 0

    -- hapus [Mutation]
    label = label:gsub("^%b[]%s*", "")

    -- ambil petType
    local petType = label:match("^(.-)%s*|") or label

    return petType, kg
end

local function filterAndSort(list)
    local result = {}
    local q = norm(searchText)

    for _, e in ipairs(list) do
        local key, label = normalizeEntry(e)

        if q == "" 
            or norm(label):find(q, 1, true)
            or norm(key):find(q, 1, true)
        then
            table.insert(result, e)
        end
    end

    table.sort(result, function(a, b)
        local ak = normalizeEntry(a)
        local bk = normalizeEntry(b)

        local aSel = selectedMap[ak] == true
        local bSel = selectedMap[bk] == true

        if aSel ~= bSel then
            return aSel
        end

        local _, aLabel = normalizeEntry(a)
local _, bLabel = normalizeEntry(b)

local aType, aKg = parsePet(aLabel)
local bType, bKg = parsePet(bLabel)

-- 1. selected tetap di atas (jangan diubah)
-- ini sudah ada di atas, jangan dihapus

-- 2. sort petType
if aType ~= bType then
    return aType < bType
end

-- 3. sort KG (besar dulu)
return aKg < bKg


    end)

    return result
end
    --------------------------------------------------
    -- BUILD BUTTONS
    --------------------------------------------------
    local function buildButtons(listOpt)
        -- kalau dipanggil dengan list baru → update currentEntries
        if listOpt then
            currentEntries = listOpt
        end

        local list = filterAndSort(currentEntries or {})

        -- clear lama
        for _, child in ipairs(container:GetChildren()) do
            if child:IsA("TextButton") then
                child:Destroy()
            end
        end

        for i, e in ipairs(list) do
            local key, labelText = normalizeEntry(e)

            -- kalau belum ada state, lihat dari field entry (selected / on)
            if selectedMap[key] == nil then
                if type(e) == "table" and (e.selected or e.on) then
                    selectedMap[key] = true
                else
                    selectedMap[key] = false
                end
            end

            local btn = Instance.new("TextButton")
            btn.Name = "Item_" .. tostring(key)
            btn.AutoButtonColor = false
            btn.BackgroundColor3 = Color3.fromRGB(22, 22, 22)
            btn.Size = UDim2.new(1, 0, 0, 22)
            btn.Text = "  " .. labelText
            btn.Font = Enum.Font.Gotham
            btn.TextXAlignment = Enum.TextXAlignment.Left
            btn.TextSize = 12
            btn.TextColor3 = Color3.fromRGB(200, 200, 200)
            btn.LayoutOrder = i
            btn.Parent = container
            createCorner(btn, 4)

            local function applyVisual()
                if selectedMap[key] then
                    tweenColor(btn, "BackgroundColor3", COLOR_YELLOW)
                    btn.TextColor3 = Color3.fromRGB(0, 0, 0)
                else
                    tweenColor(btn, "BackgroundColor3", Color3.fromRGB(22, 22, 22))
                    btn.TextColor3 = Color3.fromRGB(200, 200, 200)
                end
            end
            applyVisual()

            btn.MouseButton1Click:Connect(function()
                selectedMap[key] = not selectedMap[key]
                applyVisual()
                buildButtons()
                onItemToggle(key, selectedMap[key], labelText)
            end)
            

        end
    end

    -- build pertama
    buildButtons(currentEntries)
    searchBox:GetPropertyChangedSignal("Text"):Connect(function()
    searchText = searchBox.Text
    buildButtons()
    end)
    --------------------------------------------------
    -- API
    --------------------------------------------------
    local function api(action, payload)
        if action == "setList" or action == "setItems" then
            -- ganti isi list + rebuild
            buildButtons(payload or {})

        elseif action == "setSelected" and type(payload) == "table" then
            -- ganti state selectedMap sesuai payload
            selectedMap = {}
            for k, v in pairs(payload) do
                if v then
                    selectedMap[k] = true
                end
            end
            -- redraw pakai currentEntries
            buildButtons()

        elseif action == "getSelected" then
            local result = {}
            for k, v in pairs(selectedMap) do
                if v then
                    table.insert(result, k)
                end
            end
            return result
        end
    end

    return row, api
end



----------------------------------------------------------
-- ROW: DROPDOWN (single / multi) dgn overlay + search
----------------------------------------------------------
-- opts:
-- {
--   label       = "Target Player",
--   placeholder = "Select...",
--   mode        = "single" / "multi"  (default: "single")
--   getItems    = function() return { "A", "B" } end
--                -- ATAU langsung table: { "A","B" } / { {key="a",name="A"}, ... }
--   initial     =   -- SINGLE: "key" / "name"
--                 -- MULTI : { [key]=true, [key2]=true }
--   onChanged   = function(mode, selected) end
--   emptyUntilSearch = false  -- true: list kosong sampai user ketik search
--   deferItemLoad = false     -- true: skip scan getItems saat create; load saat dropdown dibuka
--   preserveItemOrder = false -- true: urutan dari getItems (pakai index / item.sort / item.order)
--   maxResults  = nil         -- number: batas item (mis. 10)
--   searchGetItems = function(query) return {} end  -- override sumber item saat search
--   searchPlaceholder = "Search..."
--   hintText    = "..."       -- keterangan di bawah row (English)
-- }
function MainUI:CreateRowDropdown(parent, opts)
    opts = opts or {}
    local mode        = (opts.mode == "multi") and "multi" or "single"
    local labelText   = opts.label or "Dropdown"
    local panelTitle  = opts.panelTitle or opts.dropdownTitle or labelText
    local placeholder = opts.placeholder or "Select..."
    local emptyUntilSearch = opts.emptyUntilSearch == true
    local deferItemLoad = opts.deferItemLoad == true
    local preserveItemOrder = opts.preserveItemOrder == true
    local maxResults = tonumber(opts.maxResults)
    local searchGetItems = opts.searchGetItems

    local api = {}
    local itemsLoaded = false

    -- Sumber item bisa function atau table
    local itemsSource = opts.getItems or {}

    local function getItemsList()
        if type(itemsSource) == "function" then
            local ok, res = pcall(itemsSource)
            if ok and type(res) == "table" then
                return res
            else
                warn("[NodeHubDropdown] getItems() tidak mengembalikan table, pakai {}")
                return {}
            end
        elseif type(itemsSource) == "table" then
            return itemsSource
        else
            warn("[NodeHubDropdown] getItems bukan function/table, pakai {}")
            return {}
        end
    end

    local function coerceSingleKey(value)
        if value == nil then return nil end
        if type(value) == "table" then
            for k, v in pairs(value) do
                if v == true or v == 1 or v == "true" then
                    return tostring(k)
                end
            end
            return nil
        end
        local key = tostring(value)
        if key:match("^table:%s*0x") then
            return nil
        end
        return key ~= "" and key or nil
    end

    local onChanged   = opts.onChanged
    local onClose     = opts.onClose

    -- state
    local currentItems = {}
    local keyToLabel   = {}

    local selectedKey  = nil
    local selectedMap  = {}

    if mode == "single" then
        selectedKey = coerceSingleKey(opts.initial)
    else
        if type(opts.initial) == "table" then
            for k, v in pairs(opts.initial) do
                if v == true or v == 1 or v == "true" then
                    selectedMap[tostring(k)] = true
                end
            end
        end
    end

    ------------------------------------------------------
    -- ROW + LABEL + BUTTON
    ------------------------------------------------------
    local row = Instance.new("Frame")
    row.Name = "RowDropdown"
    row.BackgroundTransparency = 1
    row.Size = UDim2.new(1, 0, 0, 34)
    row.LayoutOrder = tonumber(opts.order) or (#parent:GetChildren() + 1)
    row.Parent = parent

    local label = Instance.new("TextLabel")
    label.Name = "Label"
    label.BackgroundTransparency = 1
    label.Position = UDim2.new(0, 0, 0, 0)
    label.Size = UDim2.new(0.6, 0, 1, 0)
    label.Font = Enum.Font.Gotham
    label.TextXAlignment = Enum.TextXAlignment.Left
    label.TextSize = 12
    label.Text = labelText
    label.Parent = row
    applyRowLabelStyle(label, opts.labelStyle or "default")

    local button = Instance.new("TextButton")
    button.Name = "DropdownButton"
    button.AutoButtonColor = false
    button.BackgroundColor3 = Color3.fromRGB(18,18,18)
    button.Size = UDim2.new(0.4, 0, 1, -8)
    button.Position = UDim2.new(0.60, 0, 0, 3)
    button.Font = Enum.Font.Gotham
    button.TextXAlignment = Enum.TextXAlignment.Center
    button.TextSize = 11
    button.TextColor3 = Color3.fromRGB(230,230,230)
    button.Text = "  " .. placeholder
    button.Parent = row
    createCorner(button, 6)
    createStroke(button, Color3.fromRGB(60,60,60), 1, 0.6)

    local arrow = Instance.new("TextLabel")
    arrow.Name = "Arrow"
    arrow.BackgroundTransparency = 1
    arrow.Size = UDim2.new(0, 16, 1, 0)
    arrow.Position = UDim2.new(1, -18, 0, 0)
    arrow.Font = Enum.Font.GothamBold
    arrow.TextSize = 12
    arrow.TextXAlignment = Enum.TextXAlignment.Center
    arrow.TextColor3 = Color3.fromRGB(200,200,200)
    arrow.Text = "▼"
    arrow.Parent = button

    local function normalizeItem(e)
        if type(e) == "table" then
            local key = e.key or e.name or e.label
            local lbl = e.name or e.label
            if type(key) == "table" then
                key = key.key or key.name or key.label
            end
            if type(lbl) == "table" then
                lbl = lbl.name or lbl.label or lbl.key
            end
            if lbl == nil then
                lbl = key
            end
            key = tostring(key or "")
            lbl = tostring(lbl or key)
            if lbl:match("^table:%s*0x") then
                lbl = key
            end
            if key:match("^table:%s*0x") then
                key = ""
                lbl = ""
            end
            local icon = e.icon or e.image
            if type(icon) == "number" then
                icon = "rbxassetid://" .. tostring(math.floor(icon))
            elseif type(icon) == "string" and icon:match("^%d+$") then
                icon = "rbxassetid://" .. icon
            end
            return key, lbl, icon
        else
            local key = tostring(e)
            return key, key, nil
        end
    end

    local function syncItemLabels()
        keyToLabel = {}
        for _, e in ipairs(getItemsList() or {}) do
            local k, lbl = normalizeItem(e)
            keyToLabel[k] = lbl
        end
        itemsLoaded = true
        if type(opts.labelForKey) == "function" then
            if mode == "multi" then
                for k, on in pairs(selectedMap) do
                    if on and not keyToLabel[k] then
                        local ok, lbl = pcall(opts.labelForKey, k)
                        if ok and type(lbl) == "string" and lbl ~= "" then
                            keyToLabel[k] = lbl
                        end
                    end
                end
            elseif mode == "single" and selectedKey and not keyToLabel[selectedKey] then
                local ok, lbl = pcall(opts.labelForKey, selectedKey)
                if ok and type(lbl) == "string" and lbl ~= "" then
                    keyToLabel[selectedKey] = lbl
                end
            end
        end
    end

    local function resolveItemLabel(key)
        key = tostring(key or "")
        if key == "" or key:match("^table:%s*0x") then return "" end
        if keyToLabel[key] and keyToLabel[key] ~= "" then
            return keyToLabel[key]
        end
        if type(opts.labelForKey) == "function" then
            local ok, lbl = pcall(opts.labelForKey, key)
            if ok and type(lbl) == "string" and lbl ~= "" then
                keyToLabel[key] = lbl
                return lbl
            end
        end
        return key
    end

    local function refreshButtonText()
        if mode == "single" then
            if not selectedKey then
                button.Text = "  " .. placeholder
                return
            end
            local label = resolveItemLabel(selectedKey)
            button.Text = "  " .. label
            return
        end

        local names = {}
        for k, on in pairs(selectedMap) do
            if on then
                table.insert(names, resolveItemLabel(k))
            end
        end
        table.sort(names)

        if #names == 0 then
            button.Text = "  " .. placeholder
            return
        end

        local maxChars = 25
        local total = table.concat(names, ", ")
        if #total <= maxChars then
            button.Text = "  " .. total
            return
        end

        local shown, used = {}, 0
        for i, name in ipairs(names) do
            local part = (i == 1) and name or (", " .. name)
            if used + #part > maxChars then break end
            table.insert(shown, name)
            used += #part
        end
        local rest = #names - #shown
        local txt = table.concat(shown, ", ")
        if rest > 0 then
            txt ..= (" +%d"):format(rest)
        end
        button.Text = "  " .. txt
    end

    local function resolveSelectedKey(key)
        if not key or mode ~= "single" then
            return key
        end
        key = tostring(key)
        if keyToLabel[key] then
            return key
        end
        local lower = key:lower()
        for k, lbl in pairs(keyToLabel) do
            if k:lower() == lower or lbl:lower() == lower then
                return k
            end
        end
        local compact = lower:gsub("[^%w]", "")
        for k, lbl in pairs(keyToLabel) do
            if k:lower():gsub("[^%w]", "") == compact then
                return k
            end
            if lbl:lower():gsub("[^%w]", "") == compact then
                return k
            end
        end
        return key
    end

local function openDropdown()
    if deferItemLoad and not itemsLoaded then
        syncItemLabels()
    end
    -- parent: panel kanan / main frame NodeHub
    local parentFrame = self.right or self.mainFrame

    --------------------------------------------------
    -- OVERLAY DI DALAM NODEHUB (BLOCK CLICK DI BAWAH)
    --------------------------------------------------
    local overlay = Instance.new("TextButton")
    overlay.Name = "NodeHubDropdownOverlay"
    overlay.BackgroundColor3 = Color3.fromRGB(0,0,0)
    overlay.BackgroundTransparency = 0.25      -- agak gelap
    overlay.AutoButtonColor = false
    overlay.BorderSizePixel = 0
    overlay.Text = ""
    overlay.Size = UDim2.new(1, 0, 1, 0)
    overlay.Position = UDim2.new(0, 0, 0, 0)
    overlay.ZIndex = 98
    overlay.Active = true
    overlay.Parent = parentFrame

    --------------------------------------------------
    -- PANEL DROPDOWN (TENGAH NODEHUB)
    --------------------------------------------------
    local panel = Instance.new("Frame")
    panel.Name = "DropdownPanel"
    panel.Size = UDim2.new(0, 280, 0, 260)
    panel.AnchorPoint = Vector2.new(0.5, 0.5)
    panel.Position = UDim2.new(0.5, 0, 0.5, 0)
    panel.BackgroundColor3 = COLOR_PANEL
    panel.ZIndex = 99                 -- di atas overlay
    panel.Active = true
    panel.Parent = overlay
    createCorner(panel, 10)
    createStroke(panel, COLOR_YELLOW, 1, 0.3)

    local pad = Instance.new("UIPadding")
    pad.PaddingTop    = UDim.new(0, 8)
    pad.PaddingBottom = UDim.new(0, 8)
    pad.PaddingLeft   = UDim.new(0, 8)
    pad.PaddingRight  = UDim.new(0, 8)
    pad.Parent = panel

    --------------------------------------------------
    -- HEADER: LABEL (KIRI) + TOMBOL X (KANAN)
    --------------------------------------------------
    local header = Instance.new("Frame")
    header.Name = "Header"
    header.BackgroundTransparency = 1
    header.Size = UDim2.new(1, 0, 0, 24)
    header.Position = UDim2.new(0, 0, 0, 0)
    header.ZIndex = 100
    header.Parent = panel

    local headerLabel = Instance.new("TextLabel")
    headerLabel.Name = "HeaderLabel"
    headerLabel.BackgroundTransparency = 1
    headerLabel.Size = UDim2.new(1, -28, 1, 0) -- sisakan space untuk X
    headerLabel.Position = UDim2.new(0, 0, 0, 0)
    headerLabel.Font = Enum.Font.Gotham
    headerLabel.TextSize = 12
    headerLabel.TextXAlignment = Enum.TextXAlignment.Left
    headerLabel.TextColor3 = COLOR_GRAY_TEXT
    headerLabel.Text = panelTitle
    headerLabel.ZIndex = 101
    headerLabel.Parent = header

    local closeBtn = Instance.new("TextButton")
    closeBtn.Name = "CloseButton"
    closeBtn.Size = UDim2.new(0, 22, 0, 22)
    closeBtn.AnchorPoint = Vector2.new(1, 0.5)
    closeBtn.Position = UDim2.new(1, 0, 0.5, 0)
    closeBtn.BackgroundColor3 = Color3.fromRGB(18,18,18)
    closeBtn.AutoButtonColor = false
    closeBtn.BorderSizePixel = 0
    closeBtn.Text = "X"
    closeBtn.Font = Enum.Font.GothamBold
    closeBtn.TextSize = 12
    closeBtn.TextColor3 = COLOR_WHITE
    closeBtn.ZIndex = 101
    closeBtn.Parent = header
    createCorner(closeBtn, 6)
    createStroke(closeBtn, COLOR_YELLOW, 1, 0.4)

    --------------------------------------------------
    -- SEARCH (DI BAWAH HEADER, FULL WIDTH)
    --------------------------------------------------
    local search = Instance.new("TextBox")
    search.Name = "SearchBox"
    search.Size = UDim2.new(1, 0, 0, 24)
    -- 24 (header) + 4 margin = 28
    search.Position = UDim2.new(0, 0, 0, 28)
    search.BackgroundColor3 = Color3.fromRGB(18,18,18)
    search.PlaceholderText = opts.searchPlaceholder or "Search..."
    search.ClearTextOnFocus = false
    search.Font = Enum.Font.Gotham
    search.TextSize = 12
    search.TextXAlignment = Enum.TextXAlignment.Center
    search.TextColor3 = Color3.fromRGB(230,230,230)
    search.ZIndex = 100
    search.Parent = panel
    createCorner(search, 6)
    createStroke(search, Color3.fromRGB(60,60,60), 1, 0.6)

    --------------------------------------------------
    -- LIST (DI BAWAH SEARCH)
    --------------------------------------------------
    -- total tinggi header+margin+search+margin = 24 + 4 + 24 + 8 = 60
    local listTopOffset = 60

    local list = Instance.new("ScrollingFrame")
    list.Name = "List"
    list.Size = UDim2.new(1, 0, 1, -listTopOffset)
    list.Position = UDim2.new(0, 0, 0, listTopOffset)
    list.BackgroundTransparency = 1
    list.ScrollBarThickness = 4
    list.ScrollBarImageTransparency = 0
    list.AutomaticCanvasSize = Enum.AutomaticSize.Y
    list.CanvasSize = UDim2.new(0, 0, 0, 0)
    list.ZIndex = 100
    list.Parent = panel

    local layout = Instance.new("UIListLayout")
    layout.FillDirection = Enum.FillDirection.Vertical
    layout.SortOrder = Enum.SortOrder.LayoutOrder
    layout.Padding = UDim.new(0, 3)
    layout.Parent = list

    --------------------------------------------------
    -- REBUILD LIST (SAMA KAYAK KODEMU SEBELUMNYA)
    --------------------------------------------------
    local function trimSearchText(s)
        return tostring(s or ""):gsub("^%s+", ""):gsub("%s+$", "")
    end

    local rebuildGen = 0

local function rebuildList()
    rebuildGen += 1
    local myGen = rebuildGen

    currentItems = {}
    keyToLabel   = {}
    local onDeleteItem = opts.onDeleteItem

    local rawItems = {}
    local qTrim = trimSearchText(search.Text)
    local useSearchProvider = type(searchGetItems) == "function"
    if useSearchProvider then
        if emptyUntilSearch and qTrim == "" then
            rawItems = {}
        else
            local ok, res = pcall(searchGetItems, qTrim)
            if myGen ~= rebuildGen then return end
            if ok and type(res) == "table" then
                rawItems = res
            else
                rawItems = {}
            end
        end
    else
        rawItems = getItemsList() or {}
    end

    if myGen ~= rebuildGen then return end

  -- build items + label map (dedupe by key)
    local itemKeysSeen = {}
    for idx, e in ipairs(rawItems) do
        local k, lbl, icon = normalizeItem(e)
        if k ~= "" and not itemKeysSeen[k] then
            itemKeysSeen[k] = true
            local sortKey = nil
            if type(e) == "table" then
                sortKey = tonumber(e.order) or tonumber(e.sort)
            end
            if not sortKey and preserveItemOrder then
                sortKey = idx
            elseif not sortKey and type(e) == "table" then
                sortKey = tonumber(e.key)
            end
            table.insert(currentItems, { key = k, label = lbl, icon = icon, sortKey = sortKey })
            keyToLabel[k] = lbl
        end
    end

    for _, e in ipairs(getItemsList() or {}) do
        local k, lbl = normalizeItem(e)
        if k ~= "" and lbl ~= "" then
            keyToLabel[k] = keyToLabel[k] or lbl
        end
    end

    local knownKeys = {}
    for _, info in ipairs(currentItems) do
        knownKeys[info.key] = true
    end
    if mode == "multi" then
        for k, on in pairs(selectedMap) do
            if on and not knownKeys[k] then
                local lbl = resolveItemLabel(k)
                table.insert(currentItems, { key = k, label = lbl })
                keyToLabel[k] = lbl
                knownKeys[k] = true
            end
        end
    elseif mode == "single" and selectedKey and not knownKeys[selectedKey] then
        local lbl = resolveItemLabel(selectedKey)
        table.insert(currentItems, { key = selectedKey, label = lbl })
        keyToLabel[selectedKey] = lbl
    end

    if myGen ~= rebuildGen then return end

    -- clear old list children (buttons/labels/frames)
    for _, c in ipairs(list:GetChildren()) do
        if not c:IsA("UIListLayout") and not c:IsA("UIPadding") then
            c:Destroy()
        end
    end

    local q = (search.Text or ""):lower()

    -- helper: check selected
    local function isSelected(k)
        if mode == "single" then
            return selectedKey == k
        else
            return selectedMap[k] == true
        end
    end

    if emptyUntilSearch and qTrim == "" and #currentItems == 0 then
        local hintItem = Instance.new("TextLabel")
        hintItem.Name = "EmptySearchHint"
        hintItem.BackgroundTransparency = 1
        hintItem.Size = UDim2.new(1, 0, 0, 36)
        hintItem.Font = Enum.Font.Gotham
        hintItem.TextSize = 11
        hintItem.TextColor3 = COLOR_GRAY_TEXT
        hintItem.TextWrapped = true
        hintItem.TextXAlignment = Enum.TextXAlignment.Center
        hintItem.Text = "Type to search..."
        hintItem.LayoutOrder = 1
        hintItem.ZIndex = 101
        hintItem.Parent = list
        return
    end

    -- filter + split selected/rest
    local picked, rest = {}, {}
    for _, info in ipairs(currentItems) do
        local lbl = tostring(info.label or "")
        local low = lbl:lower()
        local passFilter = useSearchProvider or q == "" or low:find(q, 1, true)
        if passFilter then
            if isSelected(info.key) then
                table.insert(picked, info)
            else
                table.insert(rest, info)
            end
        end
    end

    -- optional: sort per group biar rapi (numeric order > label A-Z)
    local function bySort(a, b)
        local sa, sb = a.sortKey, b.sortKey
        if sa and sb and sa ~= sb then return sa < sb end
        if sa and not sb then return true end
        if sb and not sa then return false end
        return tostring(a.label):lower() < tostring(b.label):lower()
    end
    table.sort(picked, bySort)
    table.sort(rest, bySort)

    -- merge: selected dulu
    local ordered = {}
    for _, v in ipairs(picked) do table.insert(ordered, v) end
    for _, v in ipairs(rest)   do table.insert(ordered, v) end

    if maxResults and maxResults > 0 and #ordered > maxResults then
        local capped = {}
        for i = 1, maxResults do
            capped[i] = ordered[i]
        end
        ordered = capped
    end

    local idx = 0

    -- render
    for _, info in ipairs(ordered) do
        if myGen ~= rebuildGen then return end

        local k   = info.key
        local lbl = info.label
        local icon = info.icon

        idx += 1

        local rowH = (icon and icon ~= "") and 26 or 22
        local textPad = 6

        local btnItem = Instance.new("TextButton")
        btnItem.Name = "Item_" .. tostring(k)
        btnItem.AutoButtonColor = false
        btnItem.BackgroundColor3 = Color3.fromRGB(22,22,22)
        btnItem.Size = UDim2.new(1, 0, 0, rowH)
        btnItem.Text = ""
        btnItem.Font = Enum.Font.Gotham
        btnItem.TextXAlignment = Enum.TextXAlignment.Center
        btnItem.TextSize = 12
        btnItem.TextColor3 = Color3.fromRGB(220,220,220)
        btnItem.LayoutOrder = idx
        btnItem.ZIndex = 101
        btnItem.Parent = list
        createCorner(btnItem, 4)

        if icon and icon ~= "" then
            local img = Instance.new("ImageLabel")
            img.Name = "Icon"
            img.BackgroundTransparency = 1
            img.Size = UDim2.new(0, 18, 0, 18)
            img.Position = UDim2.new(0, 6, 0.5, -9)
            img.Image = icon
            img.ScaleType = Enum.ScaleType.Fit
            img.ZIndex = 102
            img.Parent = btnItem
            textPad = 28
        end
        
        local txt = Instance.new("TextLabel")
txt.BackgroundTransparency = 1
txt.Size = onDeleteItem and UDim2.new(1, -(textPad + 30), 1, 0) or UDim2.new(1, -textPad, 1, 0)
txt.Position = UDim2.new(0, textPad, 0, 0)
txt.Font = Enum.Font.Gotham
txt.TextXAlignment = onDeleteItem and Enum.TextXAlignment.Left or Enum.TextXAlignment.Center
txt.TextSize = 12
txt.TextColor3 = Color3.fromRGB(220,220,220)
txt.Text = tostring(lbl)
txt.ZIndex = 102
txt.Parent = btnItem

local deleting = false
if onDeleteItem then
    local del = Instance.new("TextButton")
    del.Name = "DeleteButton"
    del.Size = UDim2.new(0, 20, 0, 20)
    del.Position = UDim2.new(1, -24, 0.5, -10)
    del.BackgroundColor3 = Color3.fromRGB(45, 20, 20)
    del.AutoButtonColor = false
    del.Text = "X"
    del.Font = Enum.Font.GothamBold
    del.TextSize = 11
    del.TextColor3 = Color3.fromRGB(255,255,255)
    del.ZIndex = 103
    del.Active = true
    del.Parent = btnItem

    createCorner(del, 5)
    createStroke(del, Color3.fromRGB(255,80,80), 1, 0.3)

del.MouseButton1Click:Connect(function()
    deleting = true

    selectedMap[k] = nil
    if selectedKey == k then
        selectedKey = nil
    end

    if onDeleteItem then
        pcall(function()
            onDeleteItem(k, info)
        end)
    end

    if mode == "single" and not selectedKey then
        for _, e in ipairs(getItemsList() or {}) do
            local kk = normalizeItem(e)
            if kk and kk ~= k then
                selectedKey = kk
                break
            end
        end
        if not selectedKey then
            for _, e in ipairs(getItemsList() or {}) do
                local kk = normalizeItem(e)
                if kk then
                    selectedKey = kk
                    break
                end
            end
        end
    end

    refreshButtonText()
    rebuildList()

    task.defer(function()
        deleting = false
    end)
end)
end

        local function applyVisual()
            if mode == "single" then
if selectedKey == k then
    tweenColor(btnItem, "BackgroundColor3", COLOR_YELLOW)

    btnItem.TextColor3 = COLOR_PANEL
    txt.TextColor3 = COLOR_PANEL
else
    tweenColor(btnItem, "BackgroundColor3", Color3.fromRGB(22,22,22))

    btnItem.TextColor3 = Color3.fromRGB(220,220,220)
    txt.TextColor3 = Color3.fromRGB(220,220,220)
end
            else
if selectedMap[k] then
    tweenColor(btnItem, "BackgroundColor3", COLOR_YELLOW)

    btnItem.TextColor3 = COLOR_PANEL
    txt.TextColor3 = COLOR_PANEL
else
    tweenColor(btnItem, "BackgroundColor3", Color3.fromRGB(22,22,22))

    btnItem.TextColor3 = Color3.fromRGB(220,220,220)
    txt.TextColor3 = Color3.fromRGB(220,220,220)
end
            end
        end
        applyVisual()

        btnItem.MouseButton1Click:Connect(function()
                if deleting then
        return
    end
            if mode == "single" then
                selectedKey = k
                refreshButtonText()
                if onChanged then
                    onChanged("single", selectedKey)
                end
                overlay:Destroy()
            else
                selectedMap[k] = not selectedMap[k]
                refreshButtonText()
                if onChanged then
                    local copy = {}
                    for kk, vv in pairs(selectedMap) do
                        if vv then copy[kk] = true end
                    end
                    onChanged("multi", copy)
                end

                -- biar langsung “naik ke atas” setelah dipilih/dilepas
                rebuildList()
                return
            end

            -- single: juga rebuild biar highlight konsisten (optional)
            -- rebuildList()
        end)
    end
end


    local searchDebounceToken = 0
    search:GetPropertyChangedSignal("Text"):Connect(function()
        searchDebounceToken += 1
        local token = searchDebounceToken
        task.delay(0.15, function()
            if token ~= searchDebounceToken then return end
            rebuildList()
        end)
    end)

    --------------------------------------------------
    -- CLOSE HANDLER (X & KLIK DI LUAR PANEL)
    --------------------------------------------------
    local UserInputService = game:GetService("UserInputService")

    local function closeOverlay()
        if api then
            api._rebuildOpenList = nil
        end
        if onClose then
            pcall(onClose)
        end
        if overlay and overlay.Parent then
            overlay:Destroy()
        end
    end

    closeBtn.MouseButton1Click:Connect(closeOverlay)

    overlay.MouseButton1Click:Connect(function()
        local mousePos = UserInputService:GetMouseLocation()
        local pPos = panel.AbsolutePosition
        local pSize = panel.AbsoluteSize

        local x, y = mousePos.X, mousePos.Y
        local insideX = x >= pPos.X and x <= pPos.X + pSize.X
        local insideY = y >= pPos.Y and y <= pPos.Y + pSize.Y

        -- kalau klik di LUAR panel → close, kalau di dalam panel → abaikan
        if not (insideX and insideY) then
            closeOverlay()
        end
    end)

    search.Text = ""
    if api then
        api._rebuildOpenList = rebuildList
    end
    rebuildList()
end




    button.MouseEnter:Connect(function()
        tweenColor(button, "BackgroundColor3", Color3.fromRGB(24,24,24))
    end)
    button.MouseLeave:Connect(function()
        tweenColor(button, "BackgroundColor3", Color3.fromRGB(18,18,18))
    end)
    button.MouseButton1Click:Connect(openDropdown)

    if deferItemLoad then
        refreshButtonText()
    else
        syncItemLabels()
        if mode == "single" and selectedKey then
            selectedKey = resolveSelectedKey(selectedKey)
        end
        refreshButtonText()
    end

    if mode == "multi" and type(onChanged) == "function" and next(selectedMap) then
        task.defer(function()
            local copy = {}
            for k, v in pairs(selectedMap) do
                if v then copy[k] = true end
            end
            if next(copy) then
                onChanged("multi", copy)
            end
        end)
    elseif mode == "single" and type(onChanged) == "function" and selectedKey then
        task.defer(function()
            onChanged("single", selectedKey)
        end)
    end

    function api.getMode()
        return mode
    end

    function api.setMode(newMode)
        if newMode == "multi" then
            mode = "multi"
        else
            mode = "single"
        end
        refreshButtonText()
    end

    function api.setSelected(value)
        if mode == "single" then
            selectedKey = coerceSingleKey(value)
        else
            selectedMap = {}
            if type(value) == "table" then
                for k, v in pairs(value) do
                    if v == true or v == 1 or v == "true" then
                        selectedMap[tostring(k)] = true
                    end
                end
            end
        end
        refreshButtonText()
    end

    function api.getSelected()
        if mode == "single" then
            return selectedKey
        else
            local copy = {}
            for k, v in pairs(selectedMap) do
                if v then copy[k] = true end
            end
            return copy
        end
    end

    function api.refreshLabel()
        refreshButtonText()
    end

    function api.refreshItems()
        syncItemLabels()
        refreshButtonText()
        if type(api._rebuildOpenList) == "function" then
            pcall(api._rebuildOpenList)
        end
    end

    local outer = row
    local hintText = opts.hintText
    if type(hintText) == "string" and hintText ~= "" then
        local savedOrder = row.LayoutOrder
        outer = Instance.new("Frame")
        outer.Name = "RowDropdownWrap"
        outer.BackgroundTransparency = 1
        outer.Size = UDim2.new(1, 0, 0, 0)
        outer.AutomaticSize = Enum.AutomaticSize.Y
        outer.LayoutOrder = savedOrder
        outer.Parent = parent

        row.LayoutOrder = 1
        row.Parent = outer

        local wrapLayout = Instance.new("UIListLayout")
        wrapLayout.FillDirection = Enum.FillDirection.Vertical
        wrapLayout.SortOrder = Enum.SortOrder.LayoutOrder
        wrapLayout.Padding = UDim.new(0, 4)
        wrapLayout.Parent = outer

        local hint = Instance.new("TextLabel")
        hint.Name = "Hint"
        hint.BackgroundTransparency = 1
        hint.Size = UDim2.new(1, 0, 0, 0)
        hint.AutomaticSize = Enum.AutomaticSize.Y
        hint.Font = Enum.Font.Gotham
        hint.TextSize = 10
        hint.TextColor3 = COLOR_GRAY_TEXT
        hint.TextWrapped = true
        hint.TextXAlignment = Enum.TextXAlignment.Left
        hint.TextYAlignment = Enum.TextYAlignment.Top
        hint.Text = hintText
        hint.LayoutOrder = 2
        hint.Parent = outer
    end

    return outer, api
end

function MainUI:OpenModePicker(items, currentId, onChosen, titleText)
    -- items: { {id="auto", label="AUTO - ..."}, ... }
    -- currentId: string (misal "auto")
    -- onChosen(id): callback

    -- ROOT GUI (bukan cuma panel kanan)


    local parentGui = self._sg or PlayerGui   -- ⬅️ ScreenGui
    local parentFrame = parentGui             -- ⬅️ pakai ini, bukan self.right

    --------------------------------------------------
    -- OVERLAY DI DALAM ROOT UI
    --------------------------------------------------
    local overlay = Instance.new("TextButton")
    overlay.Name = "NodeHubModeOverlay"
    overlay.BackgroundColor3 = Color3.fromRGB(0,0,0)
    overlay.BackgroundTransparency = 0.25
    overlay.AutoButtonColor = false
    overlay.BorderSizePixel = 0
    overlay.Text = ""
    overlay.Size = UDim2.new(1, 0, 1, 0)         -- full screen
    overlay.Position = UDim2.new(0, 0, 0, 0)
    overlay.ZIndex = 98
    overlay.Active = true
    overlay.Parent = parentGui     

    --------------------------------------------------
    -- PANEL TENGAH
    --------------------------------------------------
    local panel = Instance.new("Frame")
    panel.Name = "ModePanel"
    panel.Size = UDim2.new(0, 300, 0, 260) -- lebar default, nanti diubah
    panel.AnchorPoint = Vector2.new(0.5, 0.5)
    panel.Position = UDim2.new(0.5, 0, 0.5, 0)
    panel.BackgroundColor3 = COLOR_PANEL
    panel.ZIndex = 99
    panel.Active = true
    panel.Parent = overlay
    createCorner(panel, 10)
    createStroke(panel, COLOR_YELLOW, 1, 0.3)

    local pad = Instance.new("UIPadding")
    pad.PaddingTop    = UDim.new(0, 8)
    pad.PaddingBottom = UDim.new(0, 8)
    pad.PaddingLeft   = UDim.new(0, 8)
    pad.PaddingRight  = UDim.new(0, 8)
    pad.Parent = panel

    --------------------------------------------------
    -- CLOSE BUTTON
    --------------------------------------------------
    local closeBtn = Instance.new("TextButton")
    closeBtn.Size = UDim2.new(0, 22, 0, 22)
    closeBtn.AnchorPoint = Vector2.new(1, 0)
    closeBtn.Position = UDim2.new(1, 2, 0, 0)
    closeBtn.BackgroundColor3 = Color3.fromRGB(18,18,18)
    closeBtn.AutoButtonColor = false
    closeBtn.BorderSizePixel = 0
    closeBtn.Text = "X"
    closeBtn.Font = Enum.Font.GothamBold
    closeBtn.TextSize = 12
    closeBtn.TextColor3 = COLOR_WHITE
    closeBtn.ZIndex = 101
    closeBtn.Parent = panel
    createCorner(closeBtn, 6)
    createStroke(closeBtn, COLOR_YELLOW, 1, 0.4)

    --------------------------------------------------
    -- TITLE + SEARCH
    --------------------------------------------------
    local title = Instance.new("TextLabel")
    title.BackgroundTransparency = 1
    title.Size = UDim2.new(1, -24, 0, 20)
    title.Position = UDim2.new(0, 0, 0, 0)
    title.Font = Enum.Font.GothamBold
    title.TextSize = 13
    title.TextXAlignment = Enum.TextXAlignment.Left
    title.TextColor3 = COLOR_YELLOW
    title.Text = tostring(titleText or "Select Mode")
    title.ZIndex = 100
    title.Parent = panel

    local search = Instance.new("TextBox")
    search.Name = "SearchBox"
    search.Size = UDim2.new(1, 0, 0, 24)
    search.Position = UDim2.new(0, 0, 0, 24)
    search.BackgroundColor3 = Color3.fromRGB(18,18,18)
    search.PlaceholderText = "Search..."
    search.ClearTextOnFocus = false
    search.Font = Enum.Font.Gotham
    search.TextSize = 12
    search.TextXAlignment = Enum.TextXAlignment.Center
    search.TextColor3 = Color3.fromRGB(230,230,230)
    search.ZIndex = 100
    search.Parent = panel
    createCorner(search, 6)
    createStroke(search, Color3.fromRGB(60,60,60), 1, 0.6)

    --------------------------------------------------
    -- LIST
    --------------------------------------------------
    local list = Instance.new("ScrollingFrame")
    list.Name = "List"
    list.Size = UDim2.new(1, 0, 1, -56)
    list.Position = UDim2.new(0, 0, 0, 52)
    list.BackgroundTransparency = 1
    list.ScrollBarThickness = 4
    list.ScrollBarImageTransparency = 0
    list.AutomaticCanvasSize = Enum.AutomaticSize.Y
    list.CanvasSize = UDim2.new(0, 0, 0, 0)
    list.ZIndex = 100
    list.Parent = panel

    local layout = Instance.new("UIListLayout")
    layout.FillDirection = Enum.FillDirection.Vertical
    layout.SortOrder = Enum.SortOrder.LayoutOrder
    layout.Padding = UDim.new(0, 3)
    layout.Parent = list

    --------------------------------------------------
    -- CLOSE HANDLER
    --------------------------------------------------
    local function closeOverlay()
        if overlay and overlay.Parent then
            overlay:Destroy()
        end
    end

    closeBtn.MouseButton1Click:Connect(closeOverlay)

    local UIS = game:GetService("UserInputService")
    overlay.MouseButton1Click:Connect(function()
        local mp   = UIS:GetMouseLocation()
        local pPos = panel.AbsolutePosition
        local pSz  = panel.AbsoluteSize

        local insideX = mp.X >= pPos.X and mp.X <= pPos.X + pSz.X
        local insideY = mp.Y >= pPos.Y and mp.Y <= pPos.Y + pSz.Y
        if not (insideX and insideY) then
            closeOverlay()
        end
    end)

    --------------------------------------------------
    -- HITUNG LEBAR PANEL DARI TEKS TERPANJANG
    --------------------------------------------------
    --------------------------------------------------
-- HITUNG LEBAR PANEL DARI TEKS TERPANJANG
--------------------------------------------------
local function resizePanelWidthFromItems()
    if not TextService or not TextService.GetTextSize then
        panel.Size = UDim2.new(0, 300, 0, 260)
        return
    end

    local maxWidth  = 0
    local font      = Enum.Font.Gotham
    local textSize  = 11

    for _, opt in ipairs(items or {}) do
        local id   = tostring(opt.id)
        local text = opt.label or id
        local full = string.format("  [%s]  %s", id, text)

        local bounds = TextService:GetTextSize(
            full,
            textSize,
            font,
            Vector2.new(10000, 24)
        )

        if bounds.X > maxWidth then
            maxWidth = bounds.X
        end
    end

    -- hitung padding kiri/kanan dari UIPadding panel
    local padLeft  = pad and pad.PaddingLeft and pad.PaddingLeft.Offset or 0
    local padRight = pad and pad.PaddingRight and pad.PaddingRight.Offset or 0

    -- sedikit margin ekstra di kiri/kanan button
    local extraMargin = 15

    local desiredWidth = maxWidth + padLeft + padRight + extraMargin

    -- MIN & MAX LEBAR PANEL
    desiredWidth = math.clamp(desiredWidth, 340, 680)

    -- tinggi tetap 260
    panel.Size = UDim2.new(0, desiredWidth, 0, 290)
end


    resizePanelWidthFromItems()

    --------------------------------------------------
    -- REBUILD LIST
    --------------------------------------------------
    local function rebuildList()
        for _, c in ipairs(list:GetChildren()) do
            if c:IsA("TextButton") then
                c:Destroy()
            end
        end

        local q   = string.lower(search.Text or "")
        local idx = 0
        local cur = tostring(currentId or "")

        for _, opt in ipairs(items or {}) do
            local id   = tostring(opt.id)
            local text = opt.label or id
            local low  = string.lower(text)

            if q == "" or string.find(low, q, 1, true) then
                idx += 1

                local btn = Instance.new("TextButton")
                btn.Name = "Item_" .. id
                btn.AutoButtonColor = false
                btn.BackgroundColor3 = (id == cur)
                    and COLOR_YELLOW
                    or Color3.fromRGB(22,22,22)

                btn.Size = UDim2.new(1, 0, 0, 24)
                btn.Text = string.format("  %s", text)
                btn.Font = Enum.Font.Gotham
                btn.TextXAlignment = Enum.TextXAlignment.Left
                btn.TextSize = 12
                btn.TextColor3 = (id == cur)
                    and COLOR_PANEL
                    or Color3.fromRGB(220,220,220)
                btn.LayoutOrder = idx
                btn.ZIndex = 101

                -- jangan di-"..." (biar full, panel sudah dilebarkan)
                btn.TextTruncate = Enum.TextTruncate.None

                btn.Parent = list
                createCorner(btn, 4)

                btn.MouseButton1Click:Connect(function()
                    currentId = id
                    if onChosen then
                        onChosen(id)
                    end
                    closeOverlay()
                end)
            end
        end
    end

    search:GetPropertyChangedSignal("Text"):Connect(rebuildList)
    search.Text = ""
    rebuildList()
end


-- ======================
-- API: FOOTER BUTTONS
-- ======================
-- list: {
--   { text="START", kind="primary"/"danger"/"normal", order=1, onClick=function() end },
--   ...
-- }
-- RENDER FOOTER DARI LIST
-- ======================
-- API: FOOTER BUTTONS
-- ======================
-- list: {
--   { text="START", kind="primary"/"danger"/"normal", order=1, onClick=function() end },
--   ...
-- }
local TweenService = game:GetService("TweenService")
local RunService   = game:GetService("RunService")

local RUN_STROKE_NAME = "__RUN_ELECTRIC_STROKE"
local RUN_GRAD_NAME   = "__RUN_ELECTRIC_GRAD"
local RUN_TOKEN_ATTR  = "__RUN_ELECTRIC_TOKEN"

function MainUI:_applyRunningStyle(btn, isRunning)
    if not (btn and btn:IsA("GuiObject")) then return end

    -- STOP: cleanup
    if not isRunning then
        btn:SetAttribute(RUN_TOKEN_ATTR, nil)
        local st = btn:FindFirstChild(RUN_STROKE_NAME)
        if st then st:Destroy() end
        return
    end

    -- ensure stroke
    local st = btn:FindFirstChild(RUN_STROKE_NAME)
    if not st then
        st = Instance.new("UIStroke")
        st.Name = RUN_STROKE_NAME
        st.ApplyStrokeMode = Enum.ApplyStrokeMode.Border
        st.Thickness = 2
        st.Transparency = 0.08
        st.Color = Color3.fromRGB(255, 217, 0) -- kuning NodeHub
        st.Parent = btn
    end

    -- ensure gradient (kilat)
    local grad = st:FindFirstChild(RUN_GRAD_NAME)
    if not grad then
        grad = Instance.new("UIGradient")
        grad.Name = RUN_GRAD_NAME
        grad.Rotation = 0
        grad.Parent = st

        -- Pola "electric": gelap → terang → putih → terang → gelap
        grad.Color = ColorSequence.new({
            ColorSequenceKeypoint.new(0.00, Color3.fromRGB(120, 90, 0)),
            ColorSequenceKeypoint.new(0.40, Color3.fromRGB(255, 217, 0)),
            ColorSequenceKeypoint.new(0.50, Color3.fromRGB(255, 255, 230)),
            ColorSequenceKeypoint.new(0.60, Color3.fromRGB(255, 217, 0)),
            ColorSequenceKeypoint.new(1.00, Color3.fromRGB(120, 90, 0)),
        })
    end

    -- anti double-loop: token unik
    local token = tostring(os.clock()) .. "_" .. tostring(math.random(1, 1e9))
    btn:SetAttribute(RUN_TOKEN_ATTR, token)

    -- Gerak listrik: rotation cepat + jitter + flicker
    task.spawn(function()
        local baseThickness = 1
        local baseTrans     = 0.08
        local rot = 0

        while btn.Parent and btn:GetAttribute(RUN_TOKEN_ATTR) == token do
            rot = (rot + 35 + math.random(-6, 6)) % 360
            grad.Rotation = rot

            if math.random() < 0.18 then
                grad.Rotation = (grad.Rotation + math.random(40, 120)) % 360
            end

            if math.random() < 0.22 then
                st.Transparency = math.clamp(baseTrans + (math.random() * 0.20), 0, 0.35)
            else
                st.Transparency = baseTrans
            end

            if math.random() < 0.16 then
                st.Thickness = baseThickness + 1
            else
                st.Thickness = baseThickness
            end

            task.wait(0.1 + math.random() * 0.02)
        end
    end)
end

-- helper: ambil running dari loop (support method ":" / "." / fallback .running)
function MainUI:_getLoopRunningForActiveTab()
    local mainKey = self.activeMainKey
    local loop

    if mainKey == "auto_hatch" then
        loop = rawget(_G, "auto_hatchLoop")

    -- ✅ NM+LVL bisa pakai ID "autokg" ATAU "auto_nmlevel"
    elseif mainKey == "autokg" or mainKey == "auto_nmlevel" then
        loop = rawget(_G, "AutoKGLoop")

    elseif mainKey == "agebreak" then
        loop = rawget(_G, "AutoAgeBreakLoop")

    else
        loop = nil
    end

    if not loop then return false end

    if type(loop.IsRunning) == "function" then
        local ok, v = pcall(function()
            return loop:IsRunning()
        end)
        if ok then return v == true end
    end

    if type(loop.isRunning) == "function" then
        local ok, v = pcall(function()
            return loop:isRunning()
        end)
        if ok then return v == true end
    end

    return loop.running == true
end


-- helper: cari tombol start yang benar utk tab aktif
function MainUI:_findFooterStartButton()
    if type(self.footerButtons) ~= "table" then return nil end

    if self.activeMainKey == "auto_hatch" then
        local b = self.footerButtons["auto_hatch_start"]
        if b then return b end
    end

    -- ✅ tambah prioritas untuk NM+LVL
    if self.activeMainKey == "autokg" then
        local b = self.footerButtons["autokg_start"]
        if b then return b end
    end
    if self.activeMainKey == "auto_nmlevel" then
        local b = self.footerButtons["auto_nmlevel_start"]
        if b then return b end
    end

    if self.activeMainKey == "agebreak" then
        local b = self.footerButtons["agebreak_start"]
        if b then return b end
    end

    -- fallback: cari yang key/text mengandung "start"
    for k, b in pairs(self.footerButtons) do
        if b and b.Parent then
            local kk = tostring(k):lower()
            local tt = tostring(b.Text or ""):lower()
            if kk:find("start", 1, true) or tt:find("start", 1, true) then
                return b
            end
        end
    end

    return nil
end


function MainUI:_startFooterRunningWatcher()
    if self.__footerRunWatcherStarted then return end
    self.__footerRunWatcherStarted = true

    task.spawn(function()
        local lastRunning = nil
        local lastMainKey = nil

        while self and self.mainFrame and self.mainFrame.Parent do
            local running = self:_getLoopRunningForActiveTab()
            local mainKey = self.activeMainKey

            if (running ~= lastRunning) or (mainKey ~= lastMainKey) then
                lastRunning = running
                lastMainKey = mainKey

                local btn = self:_findFooterStartButton()
                if btn then
                    self:_applyRunningStyle(btn, running)

                    if mainKey == "auto_hatch" then
                        btn.Text = running and "⚡ RUNNING." or "⚡ START"

                    -- ✅ Auto KG label
                    elseif mainKey == "autokg" or mainKey == "auto_nmlevel" then
                        btn.Text = running and "⚡ RUNNING." or "⚡ START KG"

                    elseif mainKey == "agebreak" then
                        btn.Text = running and "RUNNING" or "START AGE BREAK"

                    else
                        btn.Text = running and "RUNNING" or "START"
                    end
                end
            end

            task.wait(0.25)
        end
    end)
end


function MainUI:_renderFooter(list)
    local TextService = game:GetService("TextService")

    -- bersihkan footer lama
    for _, child in ipairs(self.footer:GetChildren()) do
        if child:IsA("TextButton") then
            child:Destroy()
        end
    end
    self.footerButtons = {}

    -- cek apakah ada tombol footer?
    local hasButtons = (type(list) == "table" and #list > 0)

    -- kalau TIDAK ADA tombol → sembunyikan footer & panjangkan content
    if not hasButtons then
        if self.footer then
            self.footer.Visible = false
        end
        if self._contentSizeNoFooter then
            self.content.Size = self._contentSizeNoFooter
        end
        return
    end

    -- kalau ADA tombol → footer kelihatan & content pakai size normal
    if self.footer then
        self.footer.Visible = true
    end
    if self._contentSizeWithFooter then
        self.content.Size = self._contentSizeWithFooter
    end

    -- start watcher sekali
    self:_startFooterRunningWatcher()

    --------------------------------------------------
    -- helper ukur text → auto width
    --------------------------------------------------
    local function measureTextWidth(text, font, textSize)
        text = tostring(text or "")
        local ok, bounds = pcall(function()
            return TextService:GetTextSize(text, textSize, font, Vector2.new(10000, 1000))
        end)
        if ok and bounds then
            return bounds.X
        end
        return #text * (textSize * 0.6) -- fallback kasar
    end

    --------------------------------------------------
    -- render tombol seperti biasa (AUTO WIDTH)
    --------------------------------------------------
    for idx, def in ipairs(list) do
        local kind = def.kind or "normal"
        local text = def.text or ("Btn" .. idx)

        local bgColor  = COLOR_PANEL
        local txtColor = COLOR_WHITE
        local strokeT  = 1
        local strokeTr = 0.4

        -- font & size harus fix sebelum hitung width
        local font = Enum.Font.GothamBold
        local textSize = 12

        if kind == "primary" then
            bgColor  = COLOR_YELLOW
            txtColor = COLOR_PANEL
            strokeT  = 2
            strokeTr = 0.1
        elseif kind == "danger" then
            bgColor  = Color3.fromRGB(80, 0, 0)
            txtColor = COLOR_WHITE
            strokeT  = 2
            strokeTr = 0.1
        end

        -- ✅ AUTO WIDTH berdasarkan text
        local paddingX = 22     -- kiri+kanan (biar lega)
        local minW = 70
        local maxW = 240        -- clamp biar gak kepanjangan (mode button dll)

        local textW = measureTextWidth(text, font, textSize)
        local width = math.clamp(math.floor(textW + paddingX + 0.5), minW, maxW)

        -- optional: kind min width
        if kind == "primary" then
            width = math.max(width, 120)
        elseif kind == "danger" then
            width = math.max(width, 90)
        end

        local btn = Instance.new("TextButton")
        btn.Size = UDim2.new(0, width, 1, 0)
        btn.AutoButtonColor = false
        btn.BackgroundColor3 = bgColor
        btn.Text = text
        btn.TextSize = textSize
        btn.Font = font
        btn.TextColor3 = txtColor
        btn.LayoutOrder = def.order or idx
        btn.TextWrapped = false
        btn.TextTruncate = Enum.TextTruncate.AtEnd
        btn.Parent = self.footer

        createCorner(btn, 999)
        createStroke(btn, COLOR_YELLOW, strokeT, strokeTr)

        if def.onClick then
            btn.MouseButton1Click:Connect(def.onClick)
        end

        local key = def.key or text
        btn:SetAttribute("__FOOTER_KEY", tostring(key))
        self.footerButtons[key] = btn

        -- apply running style kalau def.running true
        self:_applyRunningStyle(btn, def.running == true)

        if def.onReady then
            pcall(def.onReady, btn)
        end
    end
end


-- DEFAULT FOOTER (berlaku global jika tidak ada override per-tab)
function MainUI:SetFooterButtons(list)
    self.footerConfig.default = list
    if not self.activeMainKey then
        self:_renderFooter(list)
    else
        if not self.footerConfig[self.activeMainKey] then
            self:_renderFooter(list)
        end
    end
end

-- FOOTER KHUSUS UNTUK MAIN TAB TERTENTU
function MainUI:SetFooterButtonsFor(mainKey, list)
    self.footerConfig[mainKey] = list
    if self.activeMainKey == mainKey then
        self:_renderFooter(list)
    end
end


function MainUI:_setMinimized(state)
    state = state and true or false
    self.isMinimized = state

    if state then
        -- MINIMIZE: tutup panel utama, buka icon
        if self.overlay then
            self.overlay.Visible = false
        end
        if self.mainFrame then
            self.mainFrame.Visible = false
        end
        if self._miniBtn then
            self._miniBtn.Visible = true
        end
    else
        -- RESTORE: buka panel utama, tutup icon
        if self.overlay then
            self.overlay.Visible = true
        end
        if self.mainFrame then
            self.mainFrame.Visible = true
        end
        if self._miniBtn then
            self._miniBtn.Visible = false
        end
    end
end

function MainUI:Minimize()
    self:_setMinimized(true)
end

function MainUI:Restore()
    self:_setMinimized(false)
end

MainUI.RowLabelThemes = ROW_LABEL_THEMES

return MainUI end,                required = true },
    { key = "AutoClaimDrop",           name = "Auto Claim Drop",         factory = function() -- AutoClaimDrop — claim items in workspace.DroppedItems (ProximityPrompt + Networking)

local Players = game:GetService("Players")
local ProximityPromptService = game:GetService("ProximityPromptService")
local ReplicatedStorage = game:GetService("ReplicatedStorage")

local LP = Players.LocalPlayer
local G = (getgenv and getgenv()) or _G

local M = {}

local enabled, loopToken, recent = false, 0, {}
local claimBusy = false
local stats = { claimed = 0, lastStatus = "Ready", lastMethod = "" }
local droppedItemNet, pickupRemotes = nil, {}

local MIN_INTERVAL = 0
local RECENT_SEC = 0.05
local SCAN_RANGE = 80
local NUDGE_RANGE = 80
local NEAR_DIST = 8
local NUDGE_MIN_DIST = 14
local WAIT_POLL = 0.015

local PICKUP_REMOTE_KEYS = {
    "RequestPickup", "RequestPickUp", "Pickup", "PickUp", "Claim", "Collect", "Take",
}

local function _disconnectGlobal()
    local c = G.__GAG2_AUTO_CLAIM_DROP_CONN or rawget(_G, "__GAG2_AUTO_CLAIM_DROP_CONN")
    if c then pcall(function() c:Disconnect() end) end
    G.__GAG2_AUTO_CLAIM_DROP_CONN = nil
    rawset(_G, "__GAG2_AUTO_CLAIM_DROP_CONN", nil)
end

_disconnectGlobal()

local function _setStatus(msg, method)
    stats.lastStatus = tostring(msg or "")
    if method then stats.lastMethod = tostring(method) end
    G.AUTO_CLAIM_DROP_STATUS = stats.lastStatus
    rawset(_G, "AUTO_CLAIM_DROP_STATUS", stats.lastStatus)
end

local function _promptFn()
    if type(fireproximityprompt) == "function" then return fireproximityprompt end
    return rawget(_G, "fireproximityprompt")
end

local function _getConnectionsFn()
    if type(getconnections) == "function" then return getconnections end
    return rawget(_G, "getconnections")
end

local function _loadNetworking()
    if droppedItemNet then return true end
    local ok, net = pcall(function() return require(ReplicatedStorage.SharedModules.Networking) end)
    if not ok or type(net) ~= "table" or type(net.DroppedItem) ~= "table" then return false end
    droppedItemNet = net.DroppedItem
    pickupRemotes = {}
    local seen = {}
    for _, key in ipairs(PICKUP_REMOTE_KEYS) do
        local r = droppedItemNet[key]
        if r and not seen[r] then
            seen[r] = true
            pickupRemotes[#pickupRemotes + 1] = { key = key, remote = r }
        end
    end
    for key, r in pairs(droppedItemNet) do
        if key ~= "RequestDrop" and key ~= "PickupFx" and not seen[r] then
            local lk = string.lower(tostring(key))
            if lk:find("pick") or lk:find("claim") or lk:find("collect") or lk:find("take") then
                seen[r] = true
                pickupRemotes[#pickupRemotes + 1] = { key = tostring(key), remote = r }
            end
        end
    end
    return true
end

local function _netFire(remote, ...)
    if not remote then return false end
    local args = table.pack(...)
    local ok = pcall(function()
        if type(remote.Fire) == "function" then
            remote:Fire(table.unpack(args, 1, args.n))
            return
        end
        if typeof(remote) == "Instance" then
            if remote:IsA("RemoteFunction") then
                remote:InvokeServer(table.unpack(args, 1, args.n))
                return
            end
            remote:FireServer(table.unpack(args, 1, args.n))
        end
    end)
    return ok
end

local function _getDroppedFolder()
    return workspace:FindFirstChild("DroppedItems")
end

local function _visualPart(model)
    if not model or not model:IsA("Model") then return nil end
    local visual = model:FindFirstChild("Visual")
    if not visual then return nil end
    if visual:IsA("BasePart") then return visual end
    if visual:IsA("Model") then
        if visual.PrimaryPart then return visual.PrimaryPart end
        return visual:FindFirstChildWhichIsA("BasePart", true)
    end
    return nil
end

local function _dropPosition(model)
    local part = _visualPart(model)
    if part then return part.Position end
    local anchor = model:FindFirstChild("PromptAnchor")
    if anchor and anchor:IsA("BasePart") then return anchor.Position end
    if model.PrimaryPart then return model.PrimaryPart.Position end
    return nil
end

local function _distanceToModel(model, hrp)
    local pos = _dropPosition(model)
    if not pos or not hrp then return math.huge end
    return (hrp.Position - pos).Magnitude
end

local function _findNearestDrop(hrp, maxDist)
    local folder = _getDroppedFolder()
    if not hrp or not folder then return nil, nil, folder end
    maxDist = tonumber(maxDist) or SCAN_RANGE
    local best, bestDist = nil, math.huge
    for _, m in ipairs(folder:GetChildren()) do
        if not m:IsA("Model") then continue end
        local d = _distanceToModel(m, hrp)
        if d <= maxDist and d < bestDist then best, bestDist = m, d end
    end
    return best, bestDist, folder
end

local function _waitVisualPart(model, timeout)
    timeout = tonumber(timeout) or 5
    local deadline = os.clock() + timeout
    while os.clock() < deadline do
        if not model or not model.Parent then return nil end
        local part = _visualPart(model)
        if part then return part end
        task.wait(WAIT_POLL)
    end
    return _visualPart(model)
end

local function _findPrompt(model)
    if not model then return nil end
    local anchor = model:FindFirstChild("PromptAnchor")
    if anchor then
        local pp = anchor:FindFirstChildWhichIsA("ProximityPrompt", true)
        if pp then return pp end
    end
    local visual = model:FindFirstChild("Visual")
    if visual then
        local pp = visual:FindFirstChildWhichIsA("ProximityPrompt", true)
        if pp then return pp end
    end
    return model:FindFirstChildWhichIsA("ProximityPrompt", true)
end

local function _waitPrompt(model, timeout)
    timeout = tonumber(timeout) or 2
    local deadline = os.clock() + timeout
    while os.clock() < deadline do
        if not model or not model.Parent then return nil end
        local pp = _findPrompt(model)
        if pp then return pp end
        task.wait(WAIT_POLL)
    end
    return _findPrompt(model)
end

local function _pickupArgs(model)
    local cat = model:GetAttribute("ItemCategory")
    local id = model:GetAttribute("ItemId") or model:GetAttribute("Id") or model:GetAttribute("UUID")
    return {
        { model },
        { cat, id },
        { tostring(cat or ""), tostring(id or "") },
        { id },
        { tostring(id or "") },
        { model.Name },
    }
end

local function _prepPrompt(pp)
    if not pp then return end
    pcall(function()
        pp.Enabled = true
        pp.RequiresLineOfSight = false
        pp.MaxActivationDistance = math.max(tonumber(pp.MaxActivationDistance) or 10, 9999)
    end)
end

local function _firePromptFast(pp)
    if not pp then return false, "no_prompt" end
    pcall(function() ProximityPromptService.Enabled = true end)
    _prepPrompt(pp)
    local fn = _promptFn()
    if type(fn) == "function" then
        if pcall(fn, pp, true) then return true, "hold" end
        if pcall(fn, pp) then return true, "tap" end
    end
    return _firePrompt(pp)
end

local function _boostPrompt(pp)
    if not pp then return {} end
    local saved = {
        MaxActivationDistance = pp.MaxActivationDistance,
        RequiresLineOfSight = pp.RequiresLineOfSight,
        Enabled = pp.Enabled,
    }
    pcall(function()
        pp.Enabled = true
        pp.RequiresLineOfSight = false
        pp.MaxActivationDistance = math.max(tonumber(pp.MaxActivationDistance) or 10, 9999)
    end)
    return saved
end

local function _restorePrompt(pp, saved)
    if not pp or type(saved) ~= "table" then return end
    pcall(function()
        if saved.MaxActivationDistance ~= nil then pp.MaxActivationDistance = saved.MaxActivationDistance end
        if saved.RequiresLineOfSight ~= nil then pp.RequiresLineOfSight = saved.RequiresLineOfSight end
        if saved.Enabled ~= nil then pp.Enabled = saved.Enabled end
    end)
end

local function _firePrompt(pp)
    if not pp then return false, "no_prompt" end
    pcall(function() ProximityPromptService.Enabled = true end)

    local saved = _boostPrompt(pp)
    local fn = _promptFn()
    local okMethod = nil

    if type(fn) == "function" then
        if pcall(fn, pp, true) then okMethod = "fireproximityprompt_hold" end
        if not okMethod and pcall(fn, pp) then okMethod = "fireproximityprompt" end
        if not okMethod then
            local hold = tonumber(pp.HoldDuration) or 0
            if hold > 0 and pcall(fn, pp, hold + 0.25) then okMethod = "fireproximityprompt_duration" end
        end
    end

    if not okMethod then
        local getconn = _getConnectionsFn()
        if type(getconn) == "function" then
            for _, ev in ipairs({ pp.Triggered, pp.TriggerEnded, pp.PromptButtonHoldEnded }) do
                for _, c in ipairs(getconn(ev)) do
                    if c.Function and pcall(c.Function) then okMethod = "prompt_conn" break end
                    if c.fire and pcall(c.fire) then okMethod = "prompt_conn_fire" break end
                end
                if okMethod then break end
            end
        end
    end

    if not okMethod and (tonumber(pp.HoldDuration) or 0) > 0 then
        task.spawn(function()
            pcall(function() pp:InputHoldBegin() end)
            task.wait((tonumber(pp.HoldDuration) or 0) + 0.15)
            pcall(function() pp:InputHoldEnd() end)
        end)
        okMethod = "input_hold_spawn"
    end

    _restorePrompt(pp, saved)
    return okMethod ~= nil, okMethod or "prompt_fail"
end

local function _tryPickupRemotes(model)
    if not _loadNetworking() or #pickupRemotes == 0 then return false, "no_remote" end
    local argSets = _pickupArgs(model)
    for _, entry in ipairs(pickupRemotes) do
        for _, args in ipairs(argSets) do
            if _netFire(entry.remote, table.unpack(args)) then
                return true, "remote:" .. tostring(entry.key)
            end
        end
    end
    return false, "remote_fail"
end

local function _unequipHeld()
    local char = LP.Character
    if not char then return end
    local hum = char:FindFirstChildOfClass("Humanoid")
    if hum then pcall(function() hum:UnequipTools() end) end
end

local function _nudgeNear(model, hrp)
    local part = _visualPart(model)
    if not part or not hrp then return false, "no_part" end
    local delta = hrp.Position - part.Position
    local dist = delta.Magnitude
    if dist <= NEAR_DIST then return true, "already_near" end
    if dist > NUDGE_RANGE then return false, "too_far" end
    local flat = Vector3.new(delta.X, 0, delta.Z)
    if flat.Magnitude < 0.05 then flat = Vector3.new(1, 0, 0) else flat = flat.Unit end
    local stand = part.Position + flat * 3.5 + Vector3.new(0, 2.5, 0)
    pcall(function() hrp.CFrame = CFrame.new(stand, part.Position) end)
    return true, "nudged"
end

local function _attemptClaim(model, hrp)
    if not model or not model.Parent then return false, "gone" end
    local char = LP.Character
    hrp = (char and char:FindFirstChild("HumanoidRootPart")) or hrp
    if not hrp then return false, "no_hrp" end

    local pp = _findPrompt(model)
    if not pp and not _visualPart(model) then
        _waitVisualPart(model, 0.12)
    end
    pp = pp or _findPrompt(model) or _waitPrompt(model, 0.08)
    if not pp then return false, "no_prompt" end

    if pp.Enabled == false or model:GetAttribute("OwnerRestricted") == true then
        _prepPrompt(pp)
        pcall(function()
            for _, d in ipairs(model:GetDescendants()) do
                if d:IsA("ProximityPrompt") then
                    d.Enabled = true
                    d.RequiresLineOfSight = false
                end
            end
        end)
    end

    if char and char:FindFirstChildOfClass("Tool") then
        _unequipHeld()
    end

    if _distanceToModel(model, hrp) > NUDGE_MIN_DIST then
        _nudgeNear(model, hrp)
    end

    local ok, method = _firePromptFast(pp)
    if ok then return true, method end

    return _tryPickupRemotes(model)
end

local function _modelCollected(model, folder)
    if not model then return true end
    if not model.Parent then return true end
    if folder and model.Parent ~= folder then return true end
    return false
end

local function _resolveEnabledFromStore()
    local api = G.__GAG2_AUTO_GIFT_CLAIM_DROP_API or rawget(_G, "__GAG2_AUTO_GIFT_CLAIM_DROP_API")
    if G.__GAG2_AUTO_GIFT_UI_READY == true and type(api) == "table" and type(api.get) == "function" then
        local ok, v = pcall(api.get, api)
        if ok and v ~= nil then return v == true end
    end
    local s = G.__GAG2_AUTO_GIFT or rawget(_G, "__GAG2_AUTO_GIFT")
    if type(s) == "table" then return s.auto_claim_drop == true end
    local main = G.MAIN or rawget(_G, "MAIN")
    if type(main) == "table" and type(main.auto) == "table" and type(main.auto.gift) == "table" then
        return main.auto.gift.auto_claim_drop == true
    end
    return false
end

function M.Stop()
    enabled = false
    claimBusy = false
    loopToken += 1
    _disconnectGlobal()
    _setStatus("Stopped")
end

function M.Start()
    M.Stop()
    enabled = true
    local myToken = loopToken
    pcall(function() ProximityPromptService.Enabled = true end)
    _loadNetworking()
    _setStatus("Running")

    task.spawn(function()
        while enabled and loopToken == myToken do
            if not claimBusy then
                local hrp = LP.Character and LP.Character:FindFirstChild("HumanoidRootPart")
                local best, bestDist, folder = _findNearestDrop(hrp, SCAN_RANGE)
                local now = os.clock()
                if best and folder and not (recent[best] and now - recent[best] < RECENT_SEC) then
                    claimBusy = true
                    local target = best
                    local ok, method = _attemptClaim(target, hrp)
                    claimBusy = false
                    if enabled and loopToken == myToken then
                        if ok then
                            if _modelCollected(target, folder) then
                                recent[target] = nil
                                stats.claimed = (stats.claimed or 0) + 1
                                _setStatus(string.format("Claimed (%d)", stats.claimed), method)
                            else
                                recent[target] = os.clock()
                                _setStatus("Retry claim...", method)
                            end
                        else
                            _setStatus(string.format("Claim failed (%.0f studs) — %s", bestDist or 0, tostring(method)), method)
                        end
                    end
                end
            end
            if MIN_INTERVAL > 0 then task.wait(MIN_INTERVAL) else task.wait() end
        end
    end)
end

function M.ApplyRuntime(on)
    if on == true then M.Start() else M.Stop() end
end
M.ApplyPickupRuntime = M.ApplyRuntime

function M.SyncFromStore()
    M.ApplyRuntime(_resolveEnabledFromStore())
end

function M.IsRunning()
    return enabled == true
end

function M.GetStats()
    _loadNetworking()
    local keys = {}
    if droppedItemNet then
        for k in pairs(droppedItemNet) do keys[#keys + 1] = tostring(k) end
        table.sort(keys)
    end
    return {
        running = enabled == true,
        claimed = stats.claimed or 0,
        lastStatus = stats.lastStatus,
        lastMethod = stats.lastMethod or "",
        pickupRemotes = #pickupRemotes,
        droppedItemKeys = keys,
        hasFirePrompt = type(_promptFn()) == "function",
        hasGetConnections = type(_getConnectionsFn()) == "function",
    }
end

local function _scanDrops(hrp)
    local folder = _getDroppedFolder()
    local rows = {}
    if not folder then return folder, rows end
    for _, m in ipairs(folder:GetChildren()) do
        if not m:IsA("Model") then continue end
        local part = _visualPart(m)
        local dist = hrp and part and (hrp.Position - part.Position).Magnitude or nil
        rows[#rows + 1] = {
            name = m.Name,
            dist = dist,
            hasVisual = m:FindFirstChild("Visual") ~= nil,
            hasPrompt = _findPrompt(m) ~= nil,
            category = tostring(m:GetAttribute("ItemCategory") or ""),
            ownerRestricted = m:GetAttribute("OwnerRestricted") == true,
            droppedBy = m:GetAttribute("DroppedBy"),
        }
    end
    table.sort(rows, function(a, b)
        return (a.dist or math.huge) < (b.dist or math.huge)
    end)
    return folder, rows
end

function M.GetDiagnostics()
    local hrp = LP.Character and LP.Character:FindFirstChild("HumanoidRootPart")
    local folder, drops = _scanDrops(hrp)
    local st = M.GetStats()
    return {
        loaded = true,
        running = enabled == true,
        claimBusy = claimBusy == true,
        storeEnabled = _resolveEnabledFromStore(),
        folder = folder and folder:GetFullName() or nil,
        dropCount = #drops,
        drops = drops,
        stats = st,
        statusGlobal = G.AUTO_CLAIM_DROP_STATUS or rawget(_G, "AUTO_CLAIM_DROP_STATUS"),
    }
end

function M.PrintDiagnostics()
    return M.GetDiagnostics()
end
M.PrintStats = M.PrintDiagnostics
M.Debug = M.PrintDiagnostics

function M.DebugClaimNearest()
    _loadNetworking()
    local hrp = LP.Character and LP.Character:FindFirstChild("HumanoidRootPart")
    if not hrp then return false, "no_hrp" end
    local best, dist, folder = _findNearestDrop(hrp, math.huge)
    if not folder then return false, "no_folder" end
    if not best then return false, "no_drop" end
    local hasPrompt = _findPrompt(best) ~= nil
    local ok, method = _attemptClaim(best, hrp)
    return ok, method or "fail", best.Name, dist, hasPrompt
end

G.AutoClaimDrop = M
G.AutoClaimDropModule = M
rawset(_G, "AutoClaimDrop", M)
rawset(_G, "AutoClaimDropModule", M)
