local GIFT_MAX_PER_BATCH = 999999
-- Legacy save keys → current MailboxItemCatalog category names
local GIFT_LEGACY_ALIASES = { Tools = "Pets", DustyPots = "EmptyPots", InstyPots = "EmptyPots" }

local function clampGiftMaxPerBatch(n)
    n = math.floor(tonumber(n) or GIFT_MAX_PER_BATCH)
    if n < 1 then n = 1 end
    if n > GIFT_MAX_PER_BATCH then n = GIFT_MAX_PER_BATCH end
    return n
end

local function migrateLegacyGiftMaxPerBatch(s)
    if type(s) ~= "table" then return end
    s.max_per_batch = clampGiftMaxPerBatch(s.max_per_batch)
    if s.max_per_batch == 20 or s.max_per_batch == 1000 or s.max_per_batch == 9999 or s.max_per_batch == 10000 then
        s.max_per_batch = GIFT_MAX_PER_BATCH
    end
end

local function migrateLegacyGiftStore(s)
    if type(s) ~= "table" then return end
    s.categories = type(s.categories) == "table" and s.categories or {}
    s.selected = type(s.selected) == "table" and s.selected or {}
    s.send_totals = type(s.send_totals) == "table" and s.send_totals or {}
    for legacy, canon in pairs(GIFT_LEGACY_ALIASES) do
        if s.categories[legacy] == true then
            s.categories[canon] = true
            s.categories[legacy] = false
        end
        if type(s.selected[legacy]) == "table" and next(s.selected[legacy]) then
            s.selected[canon] = s.selected[canon] or {}
            for k, v in pairs(s.selected[legacy]) do
                if v == true then s.selected[canon][k] = true end
            end
            s.selected[legacy] = {}
        end
        if s.send_totals[legacy] ~= nil and s.send_totals[canon] == nil then
            s.send_totals[canon] = s.send_totals[legacy]
        end
    end
end

local GIFT_HARVESTED_FRUITS_CAT = "HarvestedFruits"

local function getAutoGiftModule()
    return G.AutoGiftModule or G.AutoGift or _G.AutoGiftModule or _G.AutoGift
end

local function getAutoClaimDropModule()
    local acd = G.AutoClaimDropModule or G.AutoClaimDrop or rawget(_G, "AutoClaimDropModule") or rawget(_G, "AutoClaimDrop")
    if type(acd) == "table" then return acd end
