    end
    return nil
end

local function isGiftCategoryNoList(catKey)
    return tostring(catKey or "") == GIFT_HARVESTED_FRUITS_CAT
end

local function _parseScaledPriceLocal(txt)
    txt = tostring(txt or ""):lower():gsub("%s+", ""):gsub(",", "")
    if txt == "" then return nil end
    local sign = 1
    if txt:sub(1, 1) == "-" then
        sign = -1
        txt = txt:sub(2)
    end
    local suffixes = {
        { "juta", 1000000 }, { "jt", 1000000 },
        { "ribu", 1000 }, { "rb", 1000 },
        { "b", 1000000000 }, { "m", 1000000 }, { "k", 1000 },
    }
    for _, pair in ipairs(suffixes) do
        local suf, mult = pair[1], pair[2]
        if #txt > #suf and txt:sub(-#suf) == suf then
            local n = tonumber(txt:sub(1, -#suf - 1))
            if n then return math.floor(n * mult * sign) end
        end
    end
    local n = tonumber(txt)
    if n then return math.floor(n * sign) end
    return nil
end

local function _formatPriceLocal(n)
    n = math.floor(tonumber(n) or 0)
    if n <= 0 then return "0" end
    if n >= 1000000000 then return string.format("%.2fB", n / 1000000000) end
    if n >= 1000000 then return string.format("%.2fM", n / 1000000) end
    if n >= 1000 then return string.format("%.1fK", n / 1000) end
    return tostring(n)
end

local function parseGiftSendTotalPrice(txt)
    local ag = getAutoGiftModule()
    if type(ag) == "table" and type(ag.ParseSendTotalPrice) == "function" then
        local ok, n = pcall(ag.ParseSendTotalPrice, ag, txt)
        if ok and type(n) == "number" then return n end
    end
    local parsed = _parseScaledPriceLocal(txt)
    if parsed ~= nil then return math.max(0, parsed) end
    return math.max(0, math.floor(tonumber(txt) or 0))
end

local function formatGiftSendTotalDisplay(n)
    local ag = getAutoGiftModule()
    if type(ag) == "table" and type(ag.FormatSendTotalPrice) == "function" then
        local ok, s = pcall(ag.FormatSendTotalPrice, ag, n)
        if ok and type(s) == "string" then return s end
    end
    return _formatPriceLocal(n)
end

local function buildGiftCatUiDefs()
    local cached = G.__GAG2_GIFT_CAT_UI_DEFS
    if type(cached) == "table" and #cached > 0 then
        return cached
    end
    local ag = G.AutoGiftModule or G.AutoGift or _G.AutoGiftModule or _G.AutoGift
    if type(ag) ~= "table" then return {} end
    if type(ag.GetCategoryDefs) == "function" then
        local ok, defs = pcall(ag.GetCategoryDefs, ag)
        if ok and type(defs) == "table" and #defs > 0 then
            local out = {}
            local seen = {}
            for _, def in ipairs(defs) do
                local key = def.key
                if type(key) == "string" and key ~= "" and not seen[key] then
                    seen[key] = true
                    local label = def.label or key
                    out[#out + 1] = {
                        key = key,
                        label = label,
                        itemLabel = label .. " list",
                        placeholder = "All " .. string.lower(label) .. "...",
                    }
                end
            end
            G.__GAG2_GIFT_CAT_UI_DEFS = out
            _G.__GAG2_GIFT_CAT_UI_DEFS = out
            return out
        end
    end
    return {}
end

local function invalidateGiftCatUiDefsCache()
    G.__GAG2_GIFT_CAT_UI_DEFS = nil
    _G.__GAG2_GIFT_CAT_UI_DEFS = nil
end

local function defaultGiftCategoryMap()
    local t = {}
    for _, def in ipairs(buildGiftCatUiDefs()) do
        t[def.key] = false
    end
    local store = G.__GAG2_AUTO_GIFT
    if type(store) == "table" and type(store.categories) == "table" then
        for key in pairs(store.categories) do
            if t[key] == nil then t[key] = false end
        end
    end
    return t
end

local function defaultGiftSelectedMap()
    local t = {}
    for _, def in ipairs(buildGiftCatUiDefs()) do
        t[def.key] = {}
    end
    local store = G.__GAG2_AUTO_GIFT
    if type(store) == "table" and type(store.selected) == "table" then
        for key in pairs(store.selected) do
