local function getGiftCatKeys()
    local keys = {}
    for _, def in ipairs(buildGiftCatUiDefs()) do
        keys[#keys + 1] = def.key
    end
    return keys
end

local function normalizeGiftOnceHarvestCalcMode(mode)
    return (tostring(mode or "base"):lower() == "stock") and "stock" or "base"
end

local GIFT_ONCE_HARVEST_CALC_ITEMS = {
    { key = "base", name = "Base" },
    { key = "stock", name = "Base + Stock + Friend" },
}

local GIFT_ONCE_SEND_MODE_ITEMS = {
    { key = "price", name = "Price" },
    { key = "total", name = "Total" },
}

local function normalizeOnceSendMode(mode)
    return (tostring(mode or "total"):lower() == "price") and "price" or "total"
end

local function onceSendModeIsPrice(modeOrStore)
    if type(modeOrStore) == "table" then
        local once = modeOrStore.once
        if type(once) == "table" then
            return normalizeOnceSendMode(once.send_mode) == "price"
        end
        return false
    end
    return normalizeOnceSendMode(modeOrStore) == "price"
end

local function onceCategoryShowsItemList(profileKey, catKey, _sendMode)
    if profileKey ~= "once" then
        return not isGiftCategoryNoList(catKey)
    end
    return true
end

local function firstEnabledCategoryKey(categories)
    categories = type(categories) == "table" and categories or {}
    for _, def in ipairs(buildGiftCatUiDefs()) do
        if categories[def.key] == true then
            return def.key
        end
    end
    return nil
end

local function giftOnceUsesPriceMode(categories, sendMode)
    sendMode = normalizeOnceSendMode(sendMode)
    if sendMode ~= "price" then
        return false
    end
    if type(categories) ~= "table" then
        return false
    end
    for _, def in ipairs(buildGiftCatUiDefs()) do
        if categories[def.key] == true then
            return def.key == GIFT_HARVESTED_FRUITS_CAT
        end
    end
    return false
end

local function normalizeGiftProfileFields(p, forceSingle)
    if type(p) ~= "table" then
        p = {
            categories = defaultGiftCategoryMap(),
            selected = defaultGiftSelectedMap(),
            category_mode = "single",
            send_total = 1000,
            after_send_mode = "keep",
            harvest_price_threshold_pct = 10,
            harvest_price_calc_mode = "base",
            send_mode = "total",
            auto_unfav = false,
            recipient_username = "",
            recipient_user_id = 0,
            recipient_display = "",
        }
    end
    migrateLegacyGiftStore(p)
    p.categories = type(p.categories) == "table" and p.categories or {}
    for _, key in ipairs(getGiftCatKeys()) do
        p.categories[key] = (p.categories[key] == true)
    end
    p.selected = type(p.selected) == "table" and p.selected or {}
    for _, key in ipairs(getGiftCatKeys()) do
        p.selected[key] = cleanSelectedMap(p.selected[key] or {})
    end
    if forceSingle then
        p.category_mode = "single"
    else
        p.category_mode = (tostring(p.category_mode or "single"):lower() == "multi") and "multi" or "single"
    end
    p.send_total = math.floor(tonumber(p.send_total) or 1000)
    if p.send_total < 1 then p.send_total = 1 end
    p.harvest_price_threshold_pct = math.floor(tonumber(p.harvest_price_threshold_pct) or 10)
    if p.harvest_price_threshold_pct < 0 then p.harvest_price_threshold_pct = 0 end
    if p.harvest_price_threshold_pct > 100 then p.harvest_price_threshold_pct = 100 end
    p.harvest_price_calc_mode = normalizeGiftOnceHarvestCalcMode(p.harvest_price_calc_mode)
    if p.send_mode == nil then
        if p.categories[GIFT_HARVESTED_FRUITS_CAT] == true
            and firstEnabledCategoryKey(p.categories) == GIFT_HARVESTED_FRUITS_CAT then
            p.send_mode = "price"
        else
            p.send_mode = "total"
        end
    end
    p.send_mode = normalizeOnceSendMode(p.send_mode)
    p.auto_unfav = (p.auto_unfav == true) or (p.autoUnfav == true)
    p.autoUnfav = nil
    p.after_send_mode = (tostring(p.after_send_mode or "keep"):lower() == "reset") and "reset" or "keep"
    p.recipient_username = tostring(p.recipient_username or ""):gsub("^%s+", ""):gsub("%s+$", ""):gsub("^@", "")
    p.recipient_user_id = math.floor(tonumber(p.recipient_user_id) or 0)
    p.recipient_display = tostring(p.recipient_display or "")
    return p
end

local function defaultGiftProfile(forceSingle)
    return normalizeGiftProfileFields({
        categories = defaultGiftCategoryMap(),
        selected = defaultGiftSelectedMap(),
        category_mode = forceSingle and "single" or "single",
        send_total = 1000,
        after_send_mode = "keep",
        harvest_price_threshold_pct = 10,
        harvest_price_calc_mode = "base",
        send_mode = "total",
        auto_unfav = false,
        recipient_username = "",
        recipient_user_id = 0,
        recipient_display = "",
    }, forceSingle == true)
end

local function migrateGiftProfileRecipients(s)
    if type(s) ~= "table" then return end
    s.once = normalizeGiftProfileFields(s.once, true)
    s.loop = normalizeGiftProfileFields(s.loop, false)
    local sharedUid = math.floor(tonumber(s.recipient_user_id) or 0)
    local sharedUser = tostring(s.recipient_username or "")
    local sharedDisp = tostring(s.recipient_display or "")
    if sharedUid > 0 or sharedUser ~= "" then
        if s.once.recipient_user_id <= 0 and s.once.recipient_username == "" then
            s.once.recipient_user_id = sharedUid
            s.once.recipient_username = sharedUser
            s.once.recipient_display = sharedDisp
        end
        if s.loop.recipient_user_id <= 0 and s.loop.recipient_username == "" then
            s.loop.recipient_user_id = sharedUid
            s.loop.recipient_username = sharedUser
            s.loop.recipient_display = sharedDisp
        end
    end
    s.recipient_username = s.once.recipient_username
    s.recipient_user_id = s.once.recipient_user_id
    s.recipient_display = s.once.recipient_display
end

local function migrateGiftProfiles(s)
    if type(s) ~= "table" then return end
    local legacyCats = type(s.categories) == "table" and s.categories or nil
    local legacySel = type(s.selected) == "table" and s.selected or nil
    if type(s.once) ~= "table" then
        s.once = normalizeGiftProfileFields({
            categories = legacyCats or defaultGiftCategoryMap(),
            selected = legacySel or defaultGiftSelectedMap(),
            send_total = s.send_total,
            after_send_mode = s.after_send_mode,
            category_mode = "single",
        }, true)
    else
        s.once = normalizeGiftProfileFields(s.once, true)
    end
    if type(s.loop) ~= "table" then
        local loopCats = defaultGiftCategoryMap()
        local loopSel = defaultGiftSelectedMap()
        if type(legacyCats) == "table" then
            for k, v in pairs(legacyCats) do loopCats[k] = v end
        end
        if type(legacySel) == "table" then
            for k, v in pairs(legacySel) do loopSel[k] = cleanSelectedMap(v) end
        end
        s.loop = normalizeGiftProfileFields({
            categories = loopCats,
            selected = loopSel,
            category_mode = s.category_mode,
            after_send_mode = s.after_send_mode,
        }, false)
    else
        s.loop = normalizeGiftProfileFields(s.loop, false)
    end
    migrateGiftProfileRecipients(s)
end

local function giftCategoryModeFromProfile(p, forceSingle)
    if forceSingle then return "single" end
    p = type(p) == "table" and p or {}
    return (tostring(p.category_mode or "single"):lower() == "multi") and "multi" or "single"
end

local function ensureAutoGiftStore()
    local s = G.__GAG2_AUTO_GIFT
    if type(s) ~= "table" then
        s = {
            enabled = false,
            auto_send = false,
            auto_claim_mail = false,
            auto_accept_gift = false,
            auto_claim_drop = false,
            suppress_fake_friend_request = true,
            recipient_username = "",
            recipient_user_id = 0,
            recipient_display = "",
            skip_equipped = true,
            max_per_batch = GIFT_MAX_PER_BATCH,
            note = "",
            delay_sec = 10,
            send_totals = defaultGiftSendTotals(),
            once = defaultGiftProfile(true),
            loop = defaultGiftProfile(false),
            show_gift_history = false,
            gift_history_retain_days = 7,
        }
        G.__GAG2_AUTO_GIFT = s
    end

    s.enabled = (s.enabled == true)
    s.auto_send = (s.auto_send == true)
    s.auto_claim_mail = (s.auto_claim_mail == true)
    s.auto_accept_gift = (s.auto_accept_gift == true)
    s.auto_claim_drop = (s.auto_claim_drop == true)
    if s.suppress_fake_friend_request == nil then s.suppress_fake_friend_request = true end
    s.suppress_fake_friend_request = (s.suppress_fake_friend_request == true)
    s.recipient_username = tostring(s.recipient_username or "")
    s.recipient_user_id = math.floor(tonumber(s.recipient_user_id) or 0)
    s.recipient_display = tostring(s.recipient_display or "")
    s.skip_equipped = (s.skip_equipped ~= false)
    s.max_per_batch = clampGiftMaxPerBatch(s.max_per_batch)
    migrateLegacyGiftMaxPerBatch(s)
    s.note = tostring(s.note or "")
    s.delay_sec = tonumber(s.delay_sec) or 10
    if s.delay_sec < 10 then s.delay_sec = 10 end
    s.show_gift_history = (s.show_gift_history == true)
    s.gift_history_retain_days = math.floor(math.max(1, math.min(90, tonumber(s.gift_history_retain_days) or 7)))

    s.send_totals = type(s.send_totals) == "table" and s.send_totals or {}
    if not s._profilesMigrated then
        for _, key in ipairs(getGiftCatKeys()) do
            local n = math.floor(tonumber(s.send_totals[key]) or 20)
            if n < 1 then n = 1 end
            s.send_totals[key] = n
        end
        migrateGiftProfiles(s)
        s._profilesMigrated = true
    else
        if type(s.once) ~= "table" then
            s.once = defaultGiftProfile(true)
        end
        if type(s.loop) ~= "table" then
            s.loop = defaultGiftProfile(false)
        end
    end

    local curEpoch = tonumber(G.__GAG2_GIFT_STORE_EPOCH) or tonumber(_G.__GAG2_GIFT_STORE_EPOCH) or 0
    if curEpoch > (tonumber(s._storeEpoch) or 0) then
        s._hydrated = false
        s._profilesMigrated = false
        s._storeEpoch = curEpoch
    end

    if not s._hydrated then
        local m = getMainRef()
        if type(m) == "table" and type(m.auto) == "table" and type(m.auto.gift) == "table" then
            local g = m.auto.gift
            s.enabled = (g.enabled == true)
            s.auto_send = (g.auto_send == true)
            s.auto_claim_mail = (g.auto_claim_mail == true)
            s.auto_accept_gift = (g.auto_accept_gift == true)
            s.auto_claim_drop = (g.auto_claim_drop == true)
            s.recipient_username = tostring(g.recipient_username or "")
            s.recipient_user_id = math.floor(tonumber(g.recipient_user_id) or 0)
            s.recipient_display = tostring(g.recipient_display or "")
            s.skip_equipped = (g.skip_equipped ~= false)
            s.max_per_batch = clampGiftMaxPerBatch(g.max_per_batch)
            migrateLegacyGiftMaxPerBatch(s)
            s.note = tostring(g.note or "")
            s.delay_sec = tonumber(g.delay_sec) or 10
            s.show_gift_history = (g.show_gift_history == true)
            s.gift_history_retain_days = math.floor(math.max(1, math.min(90, tonumber(g.gift_history_retain_days) or 7)))
            if type(g.once) == "table" then
                s.once = normalizeGiftProfileFields(g.once, true)
            elseif type(g.categories) == "table" or type(g.selected) == "table" then
                s.once = normalizeGiftProfileFields({
                    categories = g.categories,
                    selected = type(g.selected) == "table" and g.selected or {},
                    send_total = g.send_total,
                    after_send_mode = g.after_send_mode,
                    category_mode = "single",
                }, true)
            end
            if type(g.loop) == "table" then
                s.loop = normalizeGiftProfileFields(g.loop, false)
            elseif type(g.categories) == "table" or type(g.selected) == "table" then
                s.loop = normalizeGiftProfileFields({
                    categories = g.categories,
                    selected = type(g.selected) == "table" and g.selected or {},
                    category_mode = g.category_mode,
                    after_send_mode = g.after_send_mode,
                }, false)
            end
            migrateGiftProfiles(s)
            migrateGiftProfileRecipients(s)
            s._profilesMigrated = true
            if type(g.send_totals) == "table" then
                s.send_totals = s.send_totals or {}
                for _, key in ipairs(getGiftCatKeys()) do
                    if g.send_totals[key] ~= nil then
                        s.send_totals[key] = math.floor(tonumber(g.send_totals[key]) or 20)
                    end
                end
            end
        end
        s._hydrated = true
    end

    G.__GAG2_AUTO_GIFT = s
    _G.__GAG2_AUTO_GIFT = s
    return s
end

local function readGiftHistoryShowPref()
    local api = G.__GAG2_AUTO_GIFT_HISTORY_TOGGLE_API or rawget(_G, "__GAG2_AUTO_GIFT_HISTORY_TOGGLE_API")
    if type(api) == "table" and type(api.get) == "function" then
        local ok, v = pcall(api.get)
        if ok then return v == true end
    end
    local s = ensureAutoGiftStore()
    if s.show_gift_history == true then return true end
    local m = getMainRef()
    if type(m) == "table" and type(m.auto) == "table" and type(m.auto.gift) == "table" then
        return m.auto.gift.show_gift_history == true
    end
    return false
end

local applyGiftHistoryPanelVisible
local forceGiftHistoryPanelVisible

applyGiftHistoryPanelVisible = function(show)
    show = show == true
    local s = ensureAutoGiftStore()
    s.show_gift_history = show
    local hist = getGiftMailHistoryModule()
    if type(hist) == "table" then
        if type(hist.SetRetainDays) == "function" then
            pcall(hist.SetRetainDays, s.gift_history_retain_days or 7)
        end
        if type(hist.SetPanelVisible) == "function" then
            pcall(hist.SetPanelVisible, show)
        elseif type(hist.Init) == "function" then
            pcall(hist.Init, {
                retain_days = s.gift_history_retain_days or 7,
                show_panel = show,
            })
        end
        if show and type(hist.Refresh) == "function" then
            pcall(hist.Refresh)
        end
    end
    -- hard fallback kalau module instance beda / stale
    local pg = game:GetService("Players").LocalPlayer
    pg = pg and pg:FindFirstChild("PlayerGui")
    if pg then
        local sg = pg:FindFirstChild("GAG2_GiftMailHistory")
        if sg then
            sg.Enabled = show
            local panel = sg:FindFirstChild("GiftMailHistoryPanel", true)
            if panel then
                panel.Visible = show
            end
        end
    end
    return true
end

forceGiftHistoryPanelVisible = function(on)
    on = on == true
    applyGiftHistoryPanelVisible(on)
    local pg = game:GetService("Players").LocalPlayer
    pg = pg and pg:FindFirstChild("PlayerGui")
    if not pg then return end
    if on then
        local hub = pg:FindFirstChild("NodeHubNeonUI")
        if hub then
            local stray = hub:FindFirstChild("GiftMailHistoryPanel", true)
            while stray do
                pcall(function() stray:Destroy() end)
                stray = hub:FindFirstChild("GiftMailHistoryPanel", true)
            end
        end
    end
    local sg = pg:FindFirstChild("GAG2_GiftMailHistory")
    if sg then
        sg.Enabled = on
        local panel = sg:FindFirstChild("GiftMailHistoryPanel", true)
        if panel then
            panel.Visible = on
        end
    end
end

G.__GAG2_FORCE_GIFT_HISTORY_VISIBLE = forceGiftHistoryPanelVisible
_G.__GAG2_FORCE_GIFT_HISTORY_VISIBLE = forceGiftHistoryPanelVisible

local function applyGiftHistoryUiFromStore()
    local s = ensureAutoGiftStore()
    local show = readGiftHistoryShowPref()
    s.show_gift_history = show
    local hist = getGiftMailHistoryModule()
    if type(hist) ~= "table" then
        task.spawn(function()
            hist = ensureGiftMailHistoryModule()
            if type(hist) ~= "table" then
                warn("[GAG2] GiftMailHistory belum load — upload module/GiftMailHistory.lua ke server")
                return
            end
            forceGiftHistoryPanelVisible(show)
        end)
        return
    end
    forceGiftHistoryPanelVisible(show)
end

local function giftProfilePayload(p, forceSingle)
    p = normalizeGiftProfileFields(p, forceSingle == true)
    local categories = {}
    local selected = {}
    for _, key in ipairs(getGiftCatKeys()) do
        categories[key] = (p.categories[key] == true)
        selected[key] = mapToArray(p.selected[key])
    end
    return {
        categories = categories,
        selected = selected,
        category_mode = giftCategoryModeFromProfile(p, forceSingle == true),
        send_total = math.floor(tonumber(p.send_total) or 1000),
        after_send_mode = p.after_send_mode,
        harvest_price_threshold_pct = math.floor(tonumber(p.harvest_price_threshold_pct) or 10),
        harvest_price_calc_mode = normalizeGiftOnceHarvestCalcMode(p.harvest_price_calc_mode),
        send_mode = normalizeOnceSendMode(p.send_mode),
        auto_unfav = (p.auto_unfav == true),
        recipient_username = p.recipient_username,
        recipient_user_id = p.recipient_user_id,
        recipient_display = p.recipient_display,
    }
end

local function giftPayloadFromStore(s)
    s = ensureAutoGiftStore()
    local send_totals = {}
    for _, key in ipairs(getGiftCatKeys()) do
        send_totals[key] = math.floor(tonumber(s.send_totals and s.send_totals[key]) or 20)
    end
    local oncePayload = giftProfilePayload(s.once, true)
    local loopPayload = giftProfilePayload(s.loop, false)
    return {
        enabled = (s.enabled == true),
        auto_send = (s.auto_send == true),
        auto_claim_mail = (s.auto_claim_mail == true),
        auto_accept_gift = (s.auto_accept_gift == true),
        auto_claim_drop = (s.auto_claim_drop == true),
        suppress_fake_friend_request = (s.suppress_fake_friend_request ~= false),
        recipient_username = tostring(s.once.recipient_username or s.recipient_username or ""),
        recipient_user_id = math.floor(tonumber(s.once.recipient_user_id or s.recipient_user_id) or 0),
        recipient_display = tostring(s.once.recipient_display or s.recipient_display or ""),
        skip_equipped = (s.skip_equipped == true),
        max_per_batch = clampGiftMaxPerBatch(s.max_per_batch),
        note = tostring(s.note or ""),
        delay_sec = tonumber(s.delay_sec) or 10,
        send_totals = send_totals,
        once = oncePayload,
        loop = loopPayload,
        categories = oncePayload.categories,
        selected = oncePayload.selected,
        category_mode = loopPayload.category_mode,
        send_list_mode = (s.auto_send == true) and "loop" or "send_total",
        send_total = oncePayload.send_total,
        after_send_mode = oncePayload.after_send_mode,
        show_gift_history = (s.show_gift_history == true),
        gift_history_retain_days = math.floor(tonumber(s.gift_history_retain_days) or 7),
    }
end

local function giftConfigFromProfile(s, profile)
    s = ensureAutoGiftStore()
    local p = (profile == "loop") and s.loop or s.once
    local forceSingle = profile ~= "loop"
    p = normalizeGiftProfileFields(p, forceSingle)
    local categories = {}
    local selected = {}
    local send_totals = {}
    for _, key in ipairs(getGiftCatKeys()) do
        categories[key] = p.categories[key] == true
        selected[key] = cleanSelectedMap(p.selected[key])
        send_totals[key] = math.floor(tonumber(s.send_totals and s.send_totals[key]) or 20)
    end
    return {
        enabled = s.enabled,
        auto_send = (profile == "loop") and s.auto_send or false,
        auto_claim_mail = s.auto_claim_mail,
        auto_accept_gift = s.auto_accept_gift,
        auto_claim_drop = s.auto_claim_drop,
        suppress_fake_friend_request = (s.suppress_fake_friend_request ~= false),
        recipient_username = p.recipient_username,
        recipient_user_id = p.recipient_user_id,
        recipient_display = p.recipient_display,
        categories = categories,
        selected = selected,
        skip_equipped = s.skip_equipped,
        max_per_batch = s.max_per_batch,
        note = s.note,
        delay_sec = s.delay_sec,
        send_totals = send_totals,
        category_mode = giftCategoryModeFromProfile(p, forceSingle),
        send_list_mode = (profile == "loop") and "loop" or "send_total",
        send_total = math.floor(tonumber(p.send_total) or 1000),
        after_send_mode = p.after_send_mode,
        harvest_price_threshold_pct = math.floor(tonumber(p.harvest_price_threshold_pct) or 10),
        harvest_price_calc_mode = normalizeGiftOnceHarvestCalcMode(p.harvest_price_calc_mode),
        once_send_mode = normalizeOnceSendMode(p.send_mode),
        auto_unfav = (p.auto_unfav == true),
    }
end

local function giftConfigFromStore(s, profile)
    if profile == "once" or profile == "loop" then
        return giftConfigFromProfile(s, profile)
    end
    s = ensureAutoGiftStore()
    if s.auto_send == true then
        return giftConfigFromProfile(s, "loop")
    end
    return giftConfigFromProfile(s, "once")
end

local function giftCategoryModeFromStore(s)
    return giftCategoryModeFromProfile(ensureAutoGiftStore().loop, false)
end

local function safeDdGetSelected(api)
    if type(api) ~= "table" then return nil end
    local fn = api.getSelected
    if type(fn) ~= "function" then return nil end
    local ok, sel = pcall(fn, api)
    if ok then return sel end
    ok, sel = pcall(fn)
    if ok then return sel end
    return nil
end

local function readGiftDropdownSelected(key)
    return safeDdGetSelected(G[key] or rawget(_G, key))
end

local function readOnceSendModeFromUi(fallback)
    local sel = readGiftDropdownSelected("__GAG2_AUTO_GIFT_ONCE_SEND_MODE")
    if sel ~= nil and tostring(sel) ~= "" then
        return normalizeOnceSendMode(sel)
    end
    return normalizeOnceSendMode(fallback or ensureAutoGiftStore().once.send_mode)
end

local function categoriesMapFromDd(api, categoryMode)
    local sel = safeDdGetSelected(api)
    if sel == nil then return {} end
    if categoryMode == "single" then
        local key = sel
        if type(key) == "table" then
            key = nil
            for k, v in pairs(sel) do
                if v == true then
                    key = tostring(k)
                    break
                end
            end
        end
        local cats = {}
        for _, def in ipairs(buildGiftCatUiDefs()) do
            cats[def.key] = (key ~= nil and tostring(key) == def.key)
        end
        return cats
    end
    if type(sel) ~= "table" then
        return {}
    end
    return cleanSelectedMap(sel)
end

local function selectedMapFromDd(dd, categoryMode)
    local sel = safeDdGetSelected(dd)
    if sel == nil then return nil end
    if categoryMode == "single" then
        if type(sel) == "table" then
            return cleanSelectedMap(sel)
        end
        if tostring(sel) ~= "" then
            return { [tostring(sel)] = true }
        end
        return {}
    end
    if type(sel) ~= "table" then
        return {}
    end
    return cleanSelectedMap(sel)
end

local function readGiftUiValue(key, mode)
    mode = mode or "fn"
    local api = G[key] or rawget(_G, key)
    if mode == "toggle" then
        if type(api) == "table" and type(api.get) == "function" then
            local ok, v = pcall(api.get, api)
            if ok then return v end
        end
        return nil
    end
    if type(api) == "function" then
        local ok, v = pcall(api)
        if ok then return v end
    end
    if type(api) == "table" and type(api.get) == "function" then
        local ok, v = pcall(api.get, api)
        if ok then return v end
    end
    return nil
end

local function writeAutoGiftToMain()
    local s = ensureAutoGiftStore()
    G.__GAG2_AUTO_GIFT = s
    _G.__GAG2_AUTO_GIFT = s

    G.AUTO_GIFT_ENABLED = s.enabled
    _G.AUTO_GIFT_ENABLED = s.enabled
    G.AUTO_GIFT_AUTO_SEND = s.auto_send
    _G.AUTO_GIFT_AUTO_SEND = s.auto_send

    local m = getMainRef()
    if type(m) == "table" then
        m.auto = m.auto or {}
        m.auto.gift = giftPayloadFromStore(s)
        G.MAIN = m
        _G.MAIN = m
    end

    local payload = giftPayloadFromStore(s)
    patchAutoOnly("gift", payload)

    return s
end

local function mergeGiftProfileOpts(profile, opts)
    if type(opts) ~= "table" then return end
    local s = ensureAutoGiftStore()
    local forceSingle = profile ~= "loop"
    local p = (profile == "loop") and s.loop or s.once
    p = normalizeGiftProfileFields(p, forceSingle)
    if type(opts.categories) == "table" then
        for _, key in ipairs(getGiftCatKeys()) do
            if opts.categories[key] ~= nil then
                p.categories[key] = (opts.categories[key] == true)
            end
        end
    end
    if type(opts.selected) == "table" then
        for _, key in ipairs(getGiftCatKeys()) do
            if opts.selected[key] ~= nil then
                p.selected[key] = cleanSelectedMap(opts.selected[key])
            end
        end
    end
    if opts.category_mode ~= nil and not forceSingle then
        p.category_mode = (tostring(opts.category_mode):lower() == "multi") and "multi" or "single"
    end
    if opts.send_total ~= nil then
        local n = parseGiftSendTotalPrice(opts.send_total)
        if n < 1 then n = 1 end
        p.send_total = n
    end
    if opts.harvest_price_threshold_pct ~= nil then
        local pct = math.floor(tonumber(opts.harvest_price_threshold_pct) or 10)
        if pct < 0 then pct = 0 end
        if pct > 100 then pct = 100 end
        p.harvest_price_threshold_pct = pct
    end
    if opts.harvest_price_calc_mode ~= nil then
        p.harvest_price_calc_mode = normalizeGiftOnceHarvestCalcMode(opts.harvest_price_calc_mode)
    end
    if opts.send_mode ~= nil then
        p.send_mode = normalizeOnceSendMode(opts.send_mode)
    end
    if opts.auto_unfav ~= nil or opts.autoUnfav ~= nil then
        local v = opts.auto_unfav
        if v == nil then v = opts.autoUnfav end
        p.auto_unfav = (v == true)
    end
    if opts.after_send_mode ~= nil then
        p.after_send_mode = (tostring(opts.after_send_mode):lower() == "reset") and "reset" or "keep"
    end
    if opts.recipient_username ~= nil then
        p.recipient_username = tostring(opts.recipient_username or ""):gsub("^%s+", ""):gsub("%s+$", ""):gsub("^@", "")
    end
    if opts.recipient_user_id ~= nil then
        p.recipient_user_id = math.floor(tonumber(opts.recipient_user_id) or 0)
    end
    if opts.recipient_display ~= nil then
        p.recipient_display = tostring(opts.recipient_display or "")
    end
    if profile == "loop" then
        s.loop = normalizeGiftProfileFields(p, false)
    else
        s.once = normalizeGiftProfileFields(p, true)
        s.recipient_username = s.once.recipient_username
        s.recipient_user_id = s.once.recipient_user_id
        s.recipient_display = s.once.recipient_display
    end
end

local function writeAutoGiftState(opts)
    local s = ensureAutoGiftStore()
    if type(opts) == "table" then
        if opts.enabled ~= nil then s.enabled = (opts.enabled == true) end
        if opts.auto_send ~= nil then s.auto_send = (opts.auto_send == true) end
        if opts.auto_claim_mail ~= nil then s.auto_claim_mail = (opts.auto_claim_mail == true) end
        if opts.auto_accept_gift ~= nil then s.auto_accept_gift = (opts.auto_accept_gift == true) end
        if opts.auto_claim_drop ~= nil then s.auto_claim_drop = (opts.auto_claim_drop == true) end
        if opts.suppress_fake_friend_request ~= nil then
            s.suppress_fake_friend_request = (opts.suppress_fake_friend_request == true)
        end
        if opts.recipient_username ~= nil or opts.recipient_user_id ~= nil or opts.recipient_display ~= nil then
            mergeGiftProfileOpts("once", {
                recipient_username = opts.recipient_username,
                recipient_user_id = opts.recipient_user_id,
                recipient_display = opts.recipient_display,
            })
            s.recipient_username = s.once.recipient_username
            s.recipient_user_id = s.once.recipient_user_id
            s.recipient_display = s.once.recipient_display
        end
        if opts.skip_equipped ~= nil then s.skip_equipped = (opts.skip_equipped == true) end
        if opts.max_per_batch ~= nil then
            s.max_per_batch = clampGiftMaxPerBatch(opts.max_per_batch)
        end
        if opts.note ~= nil then s.note = tostring(opts.note or "") end
        if opts.delay_sec ~= nil then
            local d = tonumber(opts.delay_sec) or 10
            if d < 10 then d = 10 end
            s.delay_sec = d
        end
        if opts.show_gift_history ~= nil then
            s.show_gift_history = (opts.show_gift_history == true)
        end
        if opts.gift_history_retain_days ~= nil then
            s.gift_history_retain_days = math.floor(math.max(1, math.min(90, tonumber(opts.gift_history_retain_days) or 7)))
        end
        if type(opts.once) == "table" then
            mergeGiftProfileOpts("once", opts.once)
        end
        if type(opts.loop) == "table" then
            mergeGiftProfileOpts("loop", opts.loop)
        end
        if type(opts.send_totals) == "table" then
            s.send_totals = s.send_totals or {}
            for _, key in ipairs(getGiftCatKeys()) do
                if opts.send_totals[key] ~= nil then
                    local n = math.floor(tonumber(opts.send_totals[key]) or 20)
                    if n < 1 then n = 1 end
                    s.send_totals[key] = n
                end
            end
        end
        -- legacy flat patch → once profile
        if type(opts.categories) == "table" or type(opts.selected) == "table"
            or opts.send_total ~= nil or opts.after_send_mode ~= nil then
            mergeGiftProfileOpts("once", {
                categories = opts.categories,
                selected = opts.selected,
                send_total = opts.send_total,
                after_send_mode = opts.after_send_mode,
            })
        end
        if opts.category_mode ~= nil then
            mergeGiftProfileOpts("loop", { category_mode = opts.category_mode })
        end
        if opts.send_list_mode ~= nil then
            local m = tostring(opts.send_list_mode):lower():gsub("%s+", "")
            s.auto_send = not (m == "sendtotal" or m == "send_total" or m == "total")
        end
    end
    return writeAutoGiftToMain()
end

local patchGift
local function patchGiftProfile(profile, opts, syncFn)
    local wrap = {}
    wrap[profile] = opts
    patchGift(wrap, syncFn)
end

patchGift = function(opts, syncFn)
    writeAutoGiftState(opts)
    if syncFn then pcall(syncFn) end
    saveNow()
end

local function syncAutoGiftStoreFromMain()
    local s = ensureAutoGiftStore()
    local m = getMainRef()
    if type(m) == "table" and type(m.auto) == "table" and type(m.auto.gift) == "table" then
        local g = m.auto.gift
        s.enabled = (g.enabled == true)
        s.auto_send = (g.auto_send == true)
        s.auto_claim_mail = (g.auto_claim_mail == true)
        s.auto_accept_gift = (g.auto_accept_gift == true)
        s.auto_claim_drop = (g.auto_claim_drop == true)
        if type(g.recipient_username) == "string" and g.recipient_username ~= "" then
            if s.recipient_username == "" then s.recipient_username = g.recipient_username end
        end
        if (tonumber(g.recipient_user_id) or 0) > 0 then
            if (tonumber(s.recipient_user_id) or 0) <= 0 then
                s.recipient_user_id = math.floor(tonumber(g.recipient_user_id))
            end
        end
        if type(g.recipient_display) == "string" and g.recipient_display ~= "" then
            if s.recipient_display == "" then s.recipient_display = g.recipient_display end
        end
        if g.note ~= nil and tostring(g.note) ~= "" and tostring(s.note or "") == "" then
            s.note = tostring(g.note)
        end
        if tonumber(g.delay_sec) and (tonumber(s.delay_sec) or 0) <= 0 then
            s.delay_sec = tonumber(g.delay_sec)
        end
        if tonumber(g.max_per_batch) then
            s.max_per_batch = clampGiftMaxPerBatch(g.max_per_batch)
            migrateLegacyGiftMaxPerBatch(s)
        end
        if g.skip_equipped ~= nil then
            s.skip_equipped = (g.skip_equipped == true)
        end
        if g.show_gift_history ~= nil then
            s.show_gift_history = (g.show_gift_history == true)
        end
        if g.gift_history_retain_days ~= nil then
            s.gift_history_retain_days = math.floor(math.max(1, math.min(90, tonumber(g.gift_history_retain_days) or 7)))
        end
        if type(g.once) == "table" then
            s.once = normalizeGiftProfileFields(g.once, true)
        end
        if type(g.loop) == "table" then
            s.loop = normalizeGiftProfileFields(g.loop, false)
        end
        migrateGiftProfileRecipients(s)
    end
    G.__GAG2_AUTO_GIFT = s
    _G.__GAG2_AUTO_GIFT = s
    return s
end

local function readAutoGiftEnabled()
    local s = ensureAutoGiftStore()
    if s.enabled == true then return true end
    syncAutoGiftStoreFromMain()
    return ensureAutoGiftStore().enabled == true
end

local function targetOptsFromDd(ddKey, profileKey)
    local store = ensureAutoGiftStore()
    local prof = (profileKey == "loop") and store.loop or store.once
    local targetDd = G[ddKey] or rawget(_G, ddKey)
    local sel = safeDdGetSelected(targetDd)
    if sel == nil or tostring(sel) == "" then return nil end
    local uid = math.floor(tonumber(sel) or 0)
    if uid <= 0 then return nil end
    local FSL = G.FriendStealList or rawget(_G, "FriendStealList")
    local username = ""
    if type(FSL) == "table" and type(FSL.getUsername) == "function" then
        username = tostring(FSL.getUsername(uid) or "")
    end
    local display = username
    local p = game:GetService("Players"):GetPlayerByUserId(uid)
    if p then
        username = p.Name
        display = p.DisplayName
    end
    if username == "" and prof.recipient_user_id == uid and prof.recipient_username ~= "" then
        username = prof.recipient_username
    end
    if display == "" and prof.recipient_user_id == uid and prof.recipient_display ~= "" then
        display = prof.recipient_display
    end
    local out = { recipient_user_id = uid }
    if username ~= "" then out.recipient_username = username end
    if display ~= "" then out.recipient_display = display end
    return out
end

local function giftOnceSendCountDisplay(categories, store)
    store = store or ensureAutoGiftStore()
    categories = type(categories) == "table" and categories or store.once.categories
    local catKey = firstEnabledCategoryKey(categories)
    local n = 20
    if catKey and type(store.send_totals) == "table" then
        n = math.floor(tonumber(store.send_totals[catKey]) or 20)
    end
    if n < 1 then n = 1 end
    return tostring(n)
end

local function flushGiftProfileFromUi(profile)
    local forceSingle = profile ~= "loop"
    local prefix = (profile == "loop") and "LOOP" or "ONCE"
    local catMode = forceSingle and "single" or giftCategoryModeFromStore()
    local catDd = G["__GAG2_AUTO_GIFT_" .. prefix .. "_CAT"] or rawget(_G, "__GAG2_AUTO_GIFT_" .. prefix .. "_CAT")
    local cats = {}
    if type(catDd) == "table" then
        cats = categoriesMapFromDd(catDd, catMode)
    end
    local sel = {}
    local store = ensureAutoGiftStore()
    local prof = (profile == "loop") and store.loop or store.once
    for _, catKey in ipairs(getGiftCatKeys()) do
        local enabled = cats[catKey] == true or (not next(cats) and prof.categories[catKey] == true)
        if enabled then
            local dd = G["__GAG2_AUTO_GIFT_" .. prefix .. "_DD_" .. catKey]
                or rawget(_G, "__GAG2_AUTO_GIFT_" .. prefix .. "_DD_" .. catKey)
            if type(dd) == "table" then
                local m = selectedMapFromDd(dd, "multi")
                if m ~= nil then
                    sel[catKey] = m
                end
            end
        end
    end
    local out = {}
    local targetKey = (profile == "loop") and "__GAG2_AUTO_GIFT_LOOP_TARGET_DD" or "__GAG2_AUTO_GIFT_ONCE_TARGET_DD"
    local targetOpts = targetOptsFromDd(targetKey, profile)
    if targetOpts == nil and profile ~= "loop" then
        targetOpts = targetOptsFromDd("__GAG2_AUTO_GIFT_TARGET_DD", profile)
    end
    if type(targetOpts) == "table" then
        for k, v in pairs(targetOpts) do out[k] = v end
    end
    if next(cats) then out.categories = cats end
    if next(sel) then out.selected = sel end
    if not forceSingle then
        local catModeSel = readGiftDropdownSelected("__GAG2_AUTO_GIFT_LOOP_CATEGORY_MODE")
        if catModeSel ~= nil then
            out.category_mode = tostring(catModeSel)
        end
        local afterSendSel = readGiftDropdownSelected("__GAG2_AUTO_GIFT_LOOP_AFTER_SEND_MODE")
        if afterSendSel ~= nil then
            out.after_send_mode = tostring(afterSendSel)
        end
    else
        local store = ensureAutoGiftStore()
        local sendModeSel = readGiftDropdownSelected("__GAG2_AUTO_GIFT_ONCE_SEND_MODE")
        local sendMode = normalizeOnceSendMode(sendModeSel or store.once.send_mode)
        if sendMode == "price" then
            local priceVal = readGiftUiValue("__GAG2_AUTO_GIFT_ONCE_SEND_TOTAL_PRICE", "fn")
            if priceVal ~= nil then
                out.send_total = parseGiftSendTotalPrice(priceVal)
            end
        else
            local countVal = readGiftUiValue("__GAG2_AUTO_GIFT_ONCE_SEND_TOTAL", "fn")
            if countVal ~= nil then
                local cats = out.categories or store.once.categories
                local catKey = firstEnabledCategoryKey(cats)
                local n = math.floor(tonumber(countVal) or 0)
                if catKey and n >= 1 then
                    out.send_totals = { [catKey] = n }
                end
            end
        end
        local afterSendSel = readGiftDropdownSelected("__GAG2_AUTO_GIFT_ONCE_AFTER_SEND_MODE")
        if afterSendSel ~= nil then
            out.after_send_mode = tostring(afterSendSel)
        end
        local thresholdVal = readGiftUiValue("__GAG2_AUTO_GIFT_ONCE_HARVEST_THRESHOLD", "fn")
        if thresholdVal ~= nil then
            local pct = math.floor(tonumber(thresholdVal) or 0)
            if pct >= 0 and pct <= 100 then
                out.harvest_price_threshold_pct = pct
            end
        end
        local calcModeSel = readGiftDropdownSelected("__GAG2_AUTO_GIFT_ONCE_HARVEST_CALC_MODE")
        if calcModeSel ~= nil then
            out.harvest_price_calc_mode = normalizeGiftOnceHarvestCalcMode(calcModeSel)
        end
        local autoUnfavVal = readGiftUiValue("__GAG2_AUTO_GIFT_ONCE_AUTO_UNFAV", "toggle")
        if autoUnfavVal ~= nil then
            out.auto_unfav = (autoUnfavVal == true)
        end
        if sendModeSel ~= nil then
            out.send_mode = sendMode
        end
    end
    return out
end

local function flushAutoGiftFromUI()
    if G.__GAG2_RESETTING == true then return end
    if G.__GAG2_AUTO_GIFT_UI_READY ~= true then
        syncAutoGiftStoreFromMain()
        writeAutoGiftToMain()
        return
    end

    local ok, err = pcall(function()
        local opts = {}
        local noteVal = readGiftUiValue("__GAG2_AUTO_GIFT_NOTE_API", "fn")
        if noteVal ~= nil then
            opts.note = tostring(noteVal)
        end
        local delayVal = readGiftUiValue("__GAG2_AUTO_GIFT_DELAY_API", "fn")
        if delayVal ~= nil then
            opts.delay_sec = tonumber(delayVal)
        end
        local claimVal = readGiftUiValue("__GAG2_AUTO_GIFT_CLAIM_API", "toggle")
        if claimVal ~= nil then
            opts.auto_claim_mail = claimVal == true
        end
        local acceptVal = readGiftUiValue("__GAG2_AUTO_GIFT_ACCEPT_NORMAL_API", "toggle")
        if acceptVal ~= nil then
            opts.auto_accept_gift = acceptVal == true
        end
        local claimDropVal = readGiftUiValue("__GAG2_AUTO_GIFT_CLAIM_DROP_API", "toggle")
        if claimDropVal ~= nil then
            opts.auto_claim_drop = claimDropVal == true
        end

        local onceUi = flushGiftProfileFromUi("once")
        if next(onceUi) ~= nil then opts.once = onceUi end
        local loopUi = flushGiftProfileFromUi("loop")
        if next(loopUi) ~= nil then opts.loop = loopUi end

        local autoSendVal = readGiftUiValue("__GAG2_AUTO_GIFT_AUTO_SEND_API", "toggle")
        if autoSendVal ~= nil then
            opts.auto_send = autoSendVal == true
        end

        local historyVal = readGiftUiValue("__GAG2_AUTO_GIFT_HISTORY_TOGGLE_API", "toggle")
        if historyVal ~= nil then
            opts.show_gift_history = historyVal == true
        end

        if next(opts) ~= nil then
            writeAutoGiftState(opts)
        else
            syncAutoGiftStoreFromMain()
            writeAutoGiftToMain()
        end
    end)

    if not ok then
        error(err)
    end

    G.__GAG2_FLUSH_AUTO_GIFT = flushAutoGiftFromUI
    _G.__GAG2_FLUSH_AUTO_GIFT = flushAutoGiftFromUI
end

local function applyAutoGiftRuntime(_on)
    local s = ensureAutoGiftStore()
    local profile = (s.auto_send == true) and "loop" or "once"
    local cfg = giftConfigFromProfile(s, profile)

    local ag = getAutoGiftModule()
    if type(ag) ~= "table" then return end

    if type(ag.ApplyConfig) == "function" then
        pcall(ag.ApplyConfig, ag, cfg)
    end
    if type(ag.ApplyClaimRuntime) == "function" then
        pcall(ag.ApplyClaimRuntime, ag, s.auto_claim_mail == true)
    end
    if type(ag.ApplyAcceptGiftRuntime) == "function" then
        pcall(ag.ApplyAcceptGiftRuntime, ag, s.auto_accept_gift == true)
    end
    local claimOn = s.auto_claim_drop == true
    if G.__GAG2_AUTO_GIFT_UI_READY == true then
        local claimDropVal = readGiftUiValue("__GAG2_AUTO_GIFT_CLAIM_DROP_API", "toggle")
        if claimDropVal ~= nil then claimOn = claimDropVal == true end
    end
    local acd = getAutoClaimDropModule()
    if type(acd) == "table" and type(acd.ApplyRuntime) == "function" then
        pcall(acd.ApplyRuntime, acd, claimOn)
    end
    if type(ag.ApplyFakeFriendSuppressRuntime) == "function" then
        pcall(ag.ApplyFakeFriendSuppressRuntime, ag, s.suppress_fake_friend_request ~= false)
    end
    if type(ag.ApplyAutoSendRuntime) == "function" then
        pcall(ag.ApplyAutoSendRuntime, ag, s.auto_send == true)
    end
end

local function applyGiftOnceRuntime()
    local s = ensureAutoGiftStore()
    local ag = getAutoGiftModule()
    if type(ag) ~= "table" then return end
    if type(ag.ApplyConfig) == "function" then
        pcall(ag.ApplyConfig, ag, giftConfigFromProfile(s, "once"))
    end
end

local function applyGiftLoopRuntime()
    local s = ensureAutoGiftStore()
    local ag = getAutoGiftModule()
    if type(ag) ~= "table" then return end
    if type(ag.ApplyConfig) == "function" then
        pcall(ag.ApplyConfig, ag, giftConfigFromProfile(s, "loop"))
    end
    if type(ag.ApplyAutoSendRuntime) == "function" then
        pcall(ag.ApplyAutoSendRuntime, ag, s.auto_send == true)
    end
end

local function copyGiftCategoryMap(src)
    local out = {}
    src = type(src) == "table" and src or {}
    for _, key in ipairs(getGiftCatKeys()) do
        out[key] = (src[key] == true)
    end
    return out
end

local function setGiftProfileStatus(profileKey, msg)
    profileKey = (profileKey == "loop") and "loop" or "once"
    msg = tostring(msg or "")
    if profileKey == "loop" then
        G.AUTO_GIFT_LOOP_STATUS = msg
        _G.AUTO_GIFT_LOOP_STATUS = msg
    else
        G.AUTO_GIFT_ONCE_STATUS = msg
        _G.AUTO_GIFT_ONCE_STATUS = msg
    end
end

local function readGiftProfileStatus(profileKey, ag)
    profileKey = (profileKey == "loop") and "loop" or "once"
    if type(ag) == "table" and type(ag.GetProfileStatus) == "function" then
        local ok, st = pcall(ag.GetProfileStatus, ag, profileKey)
        if ok and type(st) == "string" and st ~= "" then
            return st
        end
    end
    local gkey = (profileKey == "loop") and "AUTO_GIFT_LOOP_STATUS" or "AUTO_GIFT_ONCE_STATUS"
    local txt = G[gkey] or rawget(_G, gkey) or ""
    if txt ~= "" then
        return txt
    end
    return "Ready"
end

local function setGiftAvailabilityStatus(msg)
    msg = tostring(msg or "")
    setGiftProfileStatus("once", msg)
    local ag = getAutoGiftModule()
    if type(ag) == "table" and type(ag.SetStatus) == "function" then
        pcall(ag.SetStatus, ag, msg, "once")
    end
    local refreshOnce = G.__GAG2_REFRESH_GIFT_ONCE_STATUS or rawget(_G, "__GAG2_REFRESH_GIFT_ONCE_STATUS")
    if type(refreshOnce) == "function" then
        pcall(refreshOnce)
    end
end

local function failSendOnce(msg)
    msg = tostring(msg or "Kirim gagal")
    setGiftAvailabilityStatus(msg)
    if msg:lower():find("cooldown", 1, true) then
        return
    end
    local api = G.__GAG2_AUTO_GIFT_SEND_API or rawget(_G, "__GAG2_AUTO_GIFT_SEND_API")
    if type(api) == "table" and type(api.set) == "function" then
        pcall(api.set, false, true)
    end
end

local function sendGiftNow(isOn)
    local flushFn = flushAutoGiftFromUI
        or G.__GAG2_FLUSH_AUTO_GIFT
        or rawget(_G, "__GAG2_FLUSH_AUTO_GIFT")
    if type(flushFn) ~= "function" then
        failSendOnce("Gift flush missing — re-execute hub")
        return
    end
    local flushOk, flushErr = pcall(flushFn)
    if not flushOk then
        failSendOnce("UI flush error: " .. tostring(flushErr))
        return
    end
    G.AUTO_GIFT_FLUSH_OK = true
    _G.AUTO_GIFT_FLUSH_OK = true
    writeAutoGiftState({ auto_send = false })
    local autoSendApi = G.__GAG2_AUTO_GIFT_AUTO_SEND_API or rawget(_G, "__GAG2_AUTO_GIFT_AUTO_SEND_API")
    if type(autoSendApi) == "table" and type(autoSendApi.set) == "function" then
        pcall(autoSendApi.set, false, true)
    end
    applyGiftOnceRuntime()
    applyAutoGiftRuntime(nil)
    local ag = getAutoGiftModule()
    if type(ag) ~= "table" then
        failSendOnce("AutoGift module not loaded — re-execute hub")
        return
    end
    if isOn == false then
        if type(ag.StopSendJob) == "function" then
            pcall(ag.StopSendJob, ag)
        end
        return
    end

    local s = ensureAutoGiftStore()
    local once = type(s.once) == "table" and s.once or s
    local onceUid = math.floor(tonumber(once.recipient_user_id) or 0)
    local onceUser = tostring(once.recipient_username or "")
    if onceUid <= 0 and onceUser ~= "" then
        if type(ag.LookupRecipient) == "function" then
            pcall(ag.LookupRecipient, ag, onceUser)
            pcall(ag.ApplyConfig, ag, giftConfigFromProfile(ensureAutoGiftStore(), "once"))
        end
    end

    if type(ag.StartSendJob) == "function" then
        if type(ag.IsSendJobRunning) == "function" and ag.IsSendJobRunning(ag) then
            failSendOnce("Send job sudah jalan — tunggu atau toggle OFF dulu")
            return
        end
        G.AUTO_GIFT_ONCE_STATUS = "Menghitung plan..."
        _G.AUTO_GIFT_ONCE_STATUS = G.AUTO_GIFT_ONCE_STATUS
        local refreshFn = G.__GAG2_REFRESH_GIFT_ONCE_STATUS or rawget(_G, "__GAG2_REFRESH_GIFT_ONCE_STATUS")
        if type(refreshFn) == "function" then
            pcall(refreshFn)
        end
        task.spawn(function()
            if type(ag.StartSendJob) == "function" and type(ag.IsSendJobRunning) == "function" and ag.IsSendJobRunning(ag) then
                failSendOnce("Send job sudah jalan — tunggu atau toggle OFF dulu")
                return
            end
            local ok, started, reason = pcall(ag.StartSendJob, ag)
            if not ok then
                failSendOnce("Send error: " .. tostring(started))
            elseif started ~= true then
                local errMsg = tostring(reason or G.AUTO_GIFT_ONCE_STATUS or "StartSendJob gagal")
                failSendOnce(errMsg)
            else
                G.AUTO_GIFT_ONCE_STATUS = "Mengirim..."
                _G.AUTO_GIFT_ONCE_STATUS = G.AUTO_GIFT_ONCE_STATUS
                if type(refreshFn) == "function" then
                    pcall(refreshFn)
                end
            end
        end)
    else
        failSendOnce("StartSendJob missing — upload AutoGift.lua")
    end
end

local function refreshGiftItemDropdowns()
    local refreshFn = G.__GAG2_REFRESH_GIFT_ITEM_DROPDOWNS
        or rawget(_G, "__GAG2_REFRESH_GIFT_ITEM_DROPDOWNS")
    if type(refreshFn) == "function" then
        pcall(refreshFn)
        return
    end
    for _, prefix in ipairs({ "ONCE", "LOOP" }) do
        for _, key in ipairs(getGiftCatKeys()) do
            local dd = G["__GAG2_AUTO_GIFT_" .. prefix .. "_DD_" .. key]
                or rawget(_G, "__GAG2_AUTO_GIFT_" .. prefix .. "_DD_" .. key)
            if type(dd) == "table" and type(dd.refreshItems) == "function" then
                pcall(dd.refreshItems, dd)
            end
        end
    end
end

local function syncAutoGiftAll()
    local ag = getAutoGiftModule()
    if type(ag) == "table" then
        if type(ag.IsCatalogLoaded) == "function" and not ag.IsCatalogLoaded(ag) then
            if type(ag.ReloadCatalog) == "function" then
                pcall(ag.ReloadCatalog, ag)
                invalidateGiftCatUiDefsCache()
            end
        end
    end
    if G.__GAG2_RESETTING == true then
        syncAutoGiftStoreFromMain()
        writeAutoGiftToMain()
        applyAutoGiftRuntime(nil)
        return
    end
    if G.__GAG2_AUTO_GIFT_UI_READY == true then
        flushAutoGiftFromUI()
        refreshGiftItemDropdowns()
    else
        syncAutoGiftStoreFromMain()
        writeAutoGiftToMain()
    end
    applyAutoGiftRuntime(nil)
end

local function saveAutoGiftNow()
    if G.__GAG2_AUTO_GIFT_UI_READY == true then
        flushAutoGiftFromUI()
    else
        writeAutoGiftToMain()
    end
    saveNow()
end

function M.initStore()
    _ensureBridge()
    G.__GAG2_READ_AUTO_GIFT = readAutoGiftEnabled
    G.__GAG2_WRITE_AUTO_GIFT = writeAutoGiftState
    G.__GAG2_WRITE_AUTO_GIFT_MAIN = writeAutoGiftToMain
    G.__GAG2_SYNC_AUTO_GIFT = syncAutoGiftAll
    G.__GAG2_GIFT_CONFIG_FROM_STORE = giftConfigFromStore
    _G.__GAG2_GIFT_CONFIG_FROM_STORE = giftConfigFromStore
    G.__GAG2_FLUSH_AUTO_GIFT = flushAutoGiftFromUI
    G.__GAG2_SAVE_AUTO_GIFT = saveAutoGiftNow
    registerFlush("gift", flushAutoGiftFromUI)
    _G.__GAG2_READ_AUTO_GIFT = readAutoGiftEnabled
    _G.__GAG2_WRITE_AUTO_GIFT = writeAutoGiftState
    _G.__GAG2_WRITE_AUTO_GIFT_MAIN = writeAutoGiftToMain
    _G.__GAG2_SYNC_AUTO_GIFT = syncAutoGiftAll
    _G.__GAG2_FLUSH_AUTO_GIFT = flushAutoGiftFromUI
    _G.__GAG2_SAVE_AUTO_GIFT = saveAutoGiftNow
    ensureAutoGiftStore()
    syncAutoGiftAll()
end

function M.RegisterSubTab(ui)
    if type(ui) ~= "table" then return end
    _ensureBridge()

    G.__GAG2_GIFT_UI_BOOTSTRAP = true
    _G.__GAG2_GIFT_UI_BOOTSTRAP = true

    local FriendStealList = G.FriendStealList or rawget(_G, "FriendStealList")

    local function setInputApi(key, val)
        local fn = G[key] or rawget(_G, key)
        if type(fn) == "function" then
            pcall(fn, val)
        end
    end

    G.__GAG2_AUTO_GIFT_UI_READY = false
_G.__GAG2_AUTO_GIFT_UI_READY = false

local GIFT = ensureAutoGiftStore()

local GIFT_CAT_UI = buildGiftCatUiDefs()
if #GIFT_CAT_UI == 0 then
    task.spawn(function()
        local ag = getAutoGiftModule()
        if type(ag) == "table" and type(ag.ReloadCatalog) == "function" then
            pcall(ag.ReloadCatalog, ag)
            invalidateGiftCatUiDefsCache()
        end
        for _ = 1, 3 do
            task.wait(0.15)
            GIFT_CAT_UI = buildGiftCatUiDefs()
            if #GIFT_CAT_UI > 0 then break end
        end
    end)
end

local function categoriesToMultiMap(cats)
    local out = {}
    cats = type(cats) == "table" and cats or {}
    for _, def in ipairs(buildGiftCatUiDefs()) do
        if cats[def.key] == true then
            out[def.key] = true
        end
    end
    return out
end

local function setupGiftStatusLabel(row, lbl)
    if not row or not lbl then return end
    lbl.TextWrapped = true
    lbl.TextTruncate = Enum.TextTruncate.None
    lbl.TextYAlignment = Enum.TextYAlignment.Top
    lbl.AutomaticSize = Enum.AutomaticSize.Y
    lbl.Size = UDim2.new(1, 0, 0, 0)
    row.AutomaticSize = Enum.AutomaticSize.Y
    row.Size = UDim2.new(1, 0, 0, 0)
end

local function giftStatusTargetLine(prof)
    if type(prof) ~= "table" then return "" end
    if prof.recipient_display ~= "" and prof.recipient_user_id > 0 then
        return "Target: " .. tostring(prof.recipient_display)
    end
    if prof.recipient_username ~= "" then
        return "Target: @" .. tostring(prof.recipient_username)
    end
    return ""
end

local function isBlockingGiftStatus(msg)
    msg = tostring(msg or ""):lower()
    if msg == "" or msg == "ready" or msg == "mengirim..." then return false end
    return msg:find("pilih", 1, true)
        or msg:find("kurang", 1, true)
        or msg:find("gagal", 1, true)
        or msg:find("error", 1, true)
        or msg:find("minimal", 1, true)
        or msg:find("tidak", 1, true)
        or msg:find("belum", 1, true)
        or msg:find("missing", 1, true)
        or msg:find("disabled", 1, true)
        or msg:find("not ready", 1, true)
        or msg:find("validasi", 1, true)
        or msg:find("value", 1, true)
        or msg:find("jalan", 1, true)
end

local function isGiftJobActive(ag, profileKey)
    if type(ag) ~= "table" then return false end
    profileKey = (profileKey == "loop") and "loop" or "once"
    if profileKey == "once" then
        if type(ag.IsSendJobRunning) == "function" then
            local ok, running = pcall(ag.IsSendJobRunning, ag)
            if ok and running == true then return true end
        end
        return false
    end
    if type(ag.IsAutoSendRunning) == "function" then
        local ok, running = pcall(ag.IsAutoSendRunning, ag)
        if ok and running == true then return true end
    end
    return false
end

local function appendGiftCooldownStatus(txt, ag, profileKey)
    if not isGiftJobActive(ag, profileKey) then return txt end
    if type(ag.GetSendCooldownRemain) ~= "function" then return txt end
    local ok, cdRemain = pcall(ag.GetSendCooldownRemain, ag)
    if not ok or type(cdRemain) ~= "number" or cdRemain <= 0.05 then return txt end
    local lower = tostring(txt):lower()
    if lower:find("cooldown", 1, true) or lower:find("tunggu", 1, true) then
        return txt
    end
    local cdTxt = "Cooldown: " .. tostring(math.ceil(cdRemain)) .. "s"
    if txt == "" or txt == "Ready" then
        return cdTxt
    end
    return txt .. " | " .. cdTxt
end

local function giftStatusPollInterval(ag, profileKey)
    if isGiftJobActive(ag, profileKey) then return 0.35 end
    if type(ag) == "table" and type(ag.GetSendCooldownRemain) == "function" then
        local ok, cd = pcall(ag.GetSendCooldownRemain, ag)
        if ok and type(cd) == "number" and cd > 0.05 and isGiftJobActive(ag, profileKey) then
            return 0.35
        end
    end
    return 2.5
end

local function refreshStatusLabel(lbl, profileKey)
    if not lbl or not lbl.Parent then return end
    profileKey = (profileKey == "loop") and "loop" or "once"
    local gift = G.__GAG2_AUTO_GIFT or rawget(_G, "__GAG2_AUTO_GIFT")
    if type(gift) ~= "table" then return end
    GIFT = gift
    local prof = (profileKey == "loop") and gift.loop or gift.once
    local ag = getAutoGiftModule()
    local profileStatus = readGiftProfileStatus(profileKey, ag)
    local flushOk = G.AUTO_GIFT_FLUSH_OK == true or rawget(_G, "AUTO_GIFT_FLUSH_OK") == true
    local staleFlush = profileStatus:find("flush error", 1, true)
        or profileStatus:find("UI flush", 1, true)
    local txt = profileStatus ~= "" and profileStatus or "Ready"
    if flushOk and staleFlush then
        txt = "Ready"
    end
    if isBlockingGiftStatus(profileStatus) then
        txt = profileStatus
    end
    local targetLine = giftStatusTargetLine(prof)
    if targetLine ~= "" then
        if isBlockingGiftStatus(profileStatus) then
            txt = targetLine .. "\n" .. txt
        else
            txt = targetLine .. " | " .. txt
        end
    end
    txt = appendGiftCooldownStatus(txt, ag, profileKey)
    lbl.Text = "Status: " .. txt
end

local function giftRecipientListForProfile(profileKey)
    local store = ensureAutoGiftStore()
    local p = (profileKey == "loop") and store.loop or store.once
    p = normalizeGiftProfileFields(p, profileKey ~= "loop")
    if p.recipient_user_id > 0 then
        return {
            {
                userId = p.recipient_user_id,
                username = (p.recipient_username ~= "" and p.recipient_username) or nil,
            },
        }
    end
    return {}
end

local function applyGiftTargetFromDropdown(profileKey, key)
    profileKey = (profileKey == "loop") and "loop" or "once"
    key = tostring(key or "")
    if key == "" then
        patchGiftProfile(profileKey, {
            recipient_username = "",
            recipient_user_id = 0,
            recipient_display = "",
        }, function()
            if profileKey == "loop" then
                applyGiftLoopRuntime()
            else
                applyGiftOnceRuntime()
            end
        end)
        return
    end

    local uid = math.floor(tonumber(key) or 0)
    if uid <= 0 then return end

    local username = ""
    local display = ""
    if type(FriendStealList) == "table" and type(FriendStealList.getUsername) == "function" then
        username = tostring(FriendStealList.getUsername(uid) or "")
    end
    display = username
    local p = game:GetService("Players"):GetPlayerByUserId(uid)
    if p then
        username = p.Name
        display = p.DisplayName
    end

    patchGiftProfile(profileKey, {
        recipient_username = username,
        recipient_user_id = uid,
        recipient_display = display,
    }, function()
        GIFT = ensureAutoGiftStore()
        local ag = getAutoGiftModule()
        if type(ag) == "table" and type(ag.ApplyConfig) == "function" then
            pcall(ag.ApplyConfig, ag, giftConfigFromProfile(GIFT, profileKey))
        end
        if username ~= "" and display ~= "" then
            setGiftProfileStatus(profileKey, "Target: " .. display)
        end
        if profileKey == "loop" then
            applyGiftLoopRuntime()
        else
            applyGiftOnceRuntime()
        end
    end)

    if username == "" and type(FriendStealList) == "table" and type(FriendStealList.displayLabel) == "function" then
        local label = FriendStealList.displayLabel(uid, giftRecipientListForProfile(profileKey))
        local parsed = tostring(label or ""):match("^(.-)%s+%(")
        if parsed and parsed ~= "" then
            patchGiftProfile(profileKey, { recipient_username = parsed }, function()
                if profileKey == "loop" then
                    applyGiftLoopRuntime()
                else
                    applyGiftOnceRuntime()
                end
            end)
        end
    end
end

local function createGiftTargetDropdown(body, profileKey, FriendStealListMod)
    local store = ensureAutoGiftStore()
    local prof = (profileKey == "loop") and store.loop or store.once
    prof = normalizeGiftProfileFields(prof, profileKey ~= "loop")
    local initial = (prof.recipient_user_id > 0) and tostring(prof.recipient_user_id) or nil
    local ddKey = (profileKey == "loop") and "__GAG2_AUTO_GIFT_LOOP_TARGET_DD" or "__GAG2_AUTO_GIFT_ONCE_TARGET_DD"
    if type(FriendStealListMod) ~= "table" then
        ui:CreateRowLabel(body, "FriendStealList module missing — upload FriendStealList.lua", nil, nil, "muted")
        return nil
    end
    local _, ddApi = ui:CreateRowDropdown(body, {
        label = "Target",
        panelTitle = "Select recipient",
        placeholder = "Search Roblox username...",
        mode = "single",
        emptyUntilSearch = true,
        maxResults = 10,
        searchPlaceholder = "Search Roblox username...",
        initial = initial,
        getItems = function()
            return FriendStealListMod.toDropdownItems(giftRecipientListForProfile(profileKey))
        end,
        searchGetItems = function(query)
            return FriendStealListMod.searchUsers(query, 10)
        end,
        labelForKey = function(key)
            if type(FriendStealListMod.displayLabel) == "function" then
                return FriendStealListMod.displayLabel(key, giftRecipientListForProfile(profileKey))
            end
            return tostring(key)
        end,
        onChanged = function(_, key)
            applyGiftTargetFromDropdown(profileKey, key)
            local api = G[ddKey] or rawget(_G, ddKey)
            if type(api) == "table" and type(api.refreshItems) == "function" then
                pcall(api.refreshItems, api)
            end
        end,
    })
    G[ddKey] = ddApi
    _G[ddKey] = ddApi
    if profileKey == "once" then
        G.__GAG2_AUTO_GIFT_TARGET_DD = ddApi
        _G.__GAG2_AUTO_GIFT_TARGET_DD = ddApi
    end
    return ddApi
end

