onceSendTotalRow, onceSendTotalSetFn = ui:CreateRowInput(
    bodyGiftOnce,
    initPriceMode and "Send total price (1K / 1M)" or "Send total",
    initPriceMode and formatGiftSendTotalDisplay(initStore.once.send_total or 1000)
        or giftOnceSendCountDisplay(initStore.once.categories, initStore),
    function(txt)
        local store = ensureAutoGiftStore()
        local mode = normalizeOnceSendMode(onceSendTotalActiveMode or readOnceSendModeFromUi())
        if giftOnceUsesPriceMode(store.once.categories, mode) then
            local n = parseGiftSendTotalPrice(txt)
            if n < 1 then return end
            patchGiftProfile("once", { send_total = math.floor(n) }, function()
                applyGiftOnceRuntime()
            end)
            checkGiftSendTotalAvailability("once", n, true)
            return
        end
        local store = ensureAutoGiftStore()
        local n = tonumber(txt)
        if n == nil or n < 1 then return end
        local catKey = firstEnabledCategoryKey(store.once.categories)
        if not catKey then return end
        patchGift({ send_totals = { [catKey] = math.floor(n) } }, function()
            applyGiftOnceRuntime()
        end)
        checkGiftSendTotalAvailability("once", n, false)
    end
)
