local function applyOnceUiFromProfile(prof)
    prof = normalizeGiftProfileFields(prof, true)
    onceUi.setSyncing(true)
    if type(targetDdApi) == "table" and type(targetDdApi.setSelected) == "function" then
        local uid = math.floor(tonumber(prof.recipient_user_id) or 0)
        pcall(targetDdApi.setSelected, uid > 0 and tostring(uid) or nil)
    end
    local afterDd = G.__GAG2_AUTO_GIFT_ONCE_AFTER_SEND_MODE or rawget(_G, "__GAG2_AUTO_GIFT_ONCE_AFTER_SEND_MODE")
    if type(afterDd) == "table" and type(afterDd.setSelected) == "function" then
        pcall(afterDd.setSelected, (prof.after_send_mode == "reset") and "reset" or "keep")
    end
    applyOnceSendTotalInputsFromProfile(prof)
    local thresholdFn = G.__GAG2_AUTO_GIFT_ONCE_HARVEST_THRESHOLD or rawget(_G, "__GAG2_AUTO_GIFT_ONCE_HARVEST_THRESHOLD")
    if type(thresholdFn) == "function" then
        pcall(thresholdFn, tostring(prof.harvest_price_threshold_pct or 10))
    end
    local autoUnfavApi = G.__GAG2_AUTO_GIFT_ONCE_AUTO_UNFAV or rawget(_G, "__GAG2_AUTO_GIFT_ONCE_AUTO_UNFAV")
    if type(autoUnfavApi) == "table" and type(autoUnfavApi.set) == "function" then
        pcall(autoUnfavApi.set, prof.auto_unfav == true, true)
    end
    local calcDd = G.__GAG2_AUTO_GIFT_ONCE_HARVEST_CALC_MODE or rawget(_G, "__GAG2_AUTO_GIFT_ONCE_HARVEST_CALC_MODE")
    if type(calcDd) == "table" and type(calcDd.setSelected) == "function" then
        pcall(calcDd.setSelected, normalizeGiftOnceHarvestCalcMode(prof.harvest_price_calc_mode))
    end
    onceUi.applyCategorySelection(prof.categories, false)
    for _, def in ipairs(buildGiftCatUiDefs()) do
        local entry = onceUi.itemDropdowns[def.key]
        if entry and not entry.noList and type(entry.dd) == "table" and type(entry.dd.setSelected) == "function" then
            pcall(entry.dd.setSelected, cleanSelectedMap(prof.selected[def.key]))
        end
    end
    onceUi.setSyncing(false)
end

local function applyLoopUiFromProfile(prof)
    prof = normalizeGiftProfileFields(prof, false)
    loopUi.setSyncing(true)
    if type(loopTargetDdApi) == "table" and type(loopTargetDdApi.setSelected) == "function" then
        local uid = math.floor(tonumber(prof.recipient_user_id) or 0)
        pcall(loopTargetDdApi.setSelected, uid > 0 and tostring(uid) or nil)
    end
    local afterDd = G.__GAG2_AUTO_GIFT_LOOP_AFTER_SEND_MODE or rawget(_G, "__GAG2_AUTO_GIFT_LOOP_AFTER_SEND_MODE")
    if type(afterDd) == "table" and type(afterDd.setSelected) == "function" then
        pcall(afterDd.setSelected, (prof.after_send_mode == "reset") and "reset" or "keep")
    end
    if type(loopUi.catModeDd) == "table" and type(loopUi.catModeDd.setSelected) == "function" then
        local cm = giftCategoryModeFromProfile(prof, false)
        pcall(loopUi.catModeDd.setSelected, cm)
    end
    loopUi.applyGiftCategoryMode(giftCategoryModeFromProfile(prof, false), false)
    loopUi.applyCategorySelection(prof.categories, false)
    for _, def in ipairs(buildGiftCatUiDefs()) do
        local entry = loopUi.itemDropdowns[def.key]
        if entry and not entry.noList and type(entry.dd) == "table" and type(entry.dd.setSelected) == "function" then
            pcall(entry.dd.setSelected, cleanSelectedMap(prof.selected[def.key]))
        end
    end
    loopUi.setSyncing(false)
end

local function resetGiftOnceUi()
    G.__GAG2_RESETTING = true
    _G.__GAG2_RESETTING = true

    local s = ensureAutoGiftStore()
    local keepAfterSend = s.once and s.once.after_send_mode or "keep"
    local keepCategories = copyGiftCategoryMap(s.once and s.once.categories)
    local keepThreshold = s.once and s.once.harvest_price_threshold_pct or 10
    local keepCalcMode = s.once and s.once.harvest_price_calc_mode or "base"
    local keepAutoUnfav = s.once and s.once.auto_unfav == true
    s.once = defaultGiftProfile(true)
    s.once.after_send_mode = keepAfterSend
    s.once.categories = keepCategories
    s.once.harvest_price_threshold_pct = keepThreshold
    s.once.harvest_price_calc_mode = keepCalcMode
    s.once.auto_unfav = keepAutoUnfav
    s.recipient_username = s.once.recipient_username
    s.recipient_user_id = s.once.recipient_user_id
    s.recipient_display = s.once.recipient_display

    applyOnceUiFromProfile(s.once)
    writeAutoGiftToMain()
    applyGiftOnceRuntime()

    G.__GAG2_RESETTING = false
    _G.__GAG2_RESETTING = false
    saveNow()
end
G.__GAG2_RESET_GIFT_ONCE = resetGiftOnceUi
_G.__GAG2_RESET_GIFT_ONCE = resetGiftOnceUi

local function resetGiftLoopUi()
    G.__GAG2_RESETTING = true
    _G.__GAG2_RESETTING = true

    local s = ensureAutoGiftStore()
    local keepAfterSend = s.loop and s.loop.after_send_mode or "keep"
    local keepCategories = copyGiftCategoryMap(s.loop and s.loop.categories)
    local keepCategoryMode = (s.loop and s.loop.category_mode == "multi") and "multi" or "single"
    s.auto_send = false
    s.loop = defaultGiftProfile(false)
    s.loop.after_send_mode = keepAfterSend
    s.loop.categories = keepCategories
    s.loop.category_mode = keepCategoryMode
    if type(G.__GAG2_AUTO_GIFT_AUTO_SEND_API) == "table"
        and type(G.__GAG2_AUTO_GIFT_AUTO_SEND_API.set) == "function" then
        pcall(G.__GAG2_AUTO_GIFT_AUTO_SEND_API.set, false, true)
    end

    applyLoopUiFromProfile(s.loop)
    writeAutoGiftToMain()
    applyGiftLoopRuntime()

    G.__GAG2_RESETTING = false
    _G.__GAG2_RESETTING = false
    saveNow()
end
G.__GAG2_RESET_GIFT_LOOP = resetGiftLoopUi
_G.__GAG2_RESET_GIFT_LOOP = resetGiftLoopUi

local function resetGiftMailboxUi()
    resetGiftOnceUi()
    resetGiftLoopUi()
end
G.__GAG2_RESET_GIFT_MAILBOX = resetGiftMailboxUi
_G.__GAG2_RESET_GIFT_MAILBOX = resetGiftMailboxUi

G.__GAG2_GIFT_SEND_JOB_DONE = function(ok, keepToggle)
    if ok ~= true and keepToggle ~= true then
        local ag = getAutoGiftModule()
        if type(ag) == "table" and type(ag.GetStats) == "function" then
            local stOk, st = pcall(ag.GetStats, ag)
            if stOk and type(st) == "table" then
                local onceSt = st.lastStatusOnce or st.lastStatus
                if onceSt and onceSt ~= "" then
                    G.AUTO_GIFT_ONCE_STATUS = onceSt
                    _G.AUTO_GIFT_ONCE_STATUS = onceSt
                end
            end
        end
    end
    local refreshFn = G.__GAG2_REFRESH_GIFT_ONCE_STATUS or rawget(_G, "__GAG2_REFRESH_GIFT_ONCE_STATUS")
    if type(refreshFn) == "function" then
        pcall(refreshFn)
    end
    if keepToggle == true then
        return
    end
    local api = G.__GAG2_AUTO_GIFT_SEND_API or rawget(_G, "__GAG2_AUTO_GIFT_SEND_API")
    if type(api) == "table" and type(api.set) == "function" then
        pcall(api.set, false, true)
    end
end
_G.__GAG2_GIFT_SEND_JOB_DONE = G.__GAG2_GIFT_SEND_JOB_DONE

do
    local store = ensureAutoGiftStore()
    refreshOnceSendModeUi(store.once.send_mode)
    G.__GAG2_GIFT_UI_BOOTSTRAP = false
    _G.__GAG2_GIFT_UI_BOOTSTRAP = false
end

end

function M.RegisterAutoAccept(ui)
    if type(ui) ~= "table" then return end
    _ensureBridge()

    local GIFT = ensureAutoGiftStore()

    ----------------------------------------------------------------
    -- Accept Gift
    ----------------------------------------------------------------
    local bodyClaimMail = ui:CreateSection("Accept Gift", false)

    do
        local _, _, api = ui:CreateRowToggle(bodyClaimMail, "Gift mail", GIFT.auto_claim_mail == true, function(isOn)
            patchGift({ auto_claim_mail = isOn == true }, function() applyAutoGiftRuntime(nil) end)
        end)
        G.__GAG2_AUTO_GIFT_CLAIM_API = api
        _G.__GAG2_AUTO_GIFT_CLAIM_API = api
    end

    do
        local _, _, api = ui:CreateRowToggle(bodyClaimMail, "Auto accept normal gift", GIFT.auto_accept_gift == true, function(isOn)
            patchGift({ auto_accept_gift = isOn == true }, function() applyAutoGiftRuntime(nil) end)
        end)
        G.__GAG2_AUTO_GIFT_ACCEPT_NORMAL_API = api
        _G.__GAG2_AUTO_GIFT_ACCEPT_NORMAL_API = api
    end

    do
        local _, _, api = ui:CreateRowToggle(bodyClaimMail, "Claim drop item", GIFT.auto_claim_drop == true, function(isOn)
            patchGift({ auto_claim_drop = isOn == true }, function()
                applyAutoGiftRuntime(nil)
                local acd = getAutoClaimDropModule()
                if type(acd) == "table" then
                    if isOn == true and type(acd.Start) == "function" then
                        pcall(acd.Start, acd)
                    elseif type(acd.Stop) == "function" then
                        pcall(acd.Stop, acd)
                    end
                end
            end)
        end)
        G.__GAG2_AUTO_GIFT_CLAIM_DROP_API = api
        _G.__GAG2_AUTO_GIFT_CLAIM_DROP_API = api
    end

    do
        local suppressOn = GIFT.suppress_fake_friend_request ~= false
        local _, _, api = ui:CreateRowToggle(bodyClaimMail, "Hide popup", suppressOn, function(isOn)
            patchGift({ suppress_fake_friend_request = isOn == true }, function() applyAutoGiftRuntime(nil) end)
        end)
        G.__GAG2_AUTO_GIFT_SUPPRESS_FRIEND_API = api
        _G.__GAG2_AUTO_GIFT_SUPPRESS_FRIEND_API = api
    end

    if G.__GAG2_AUTO_GIFT_CLAIM_API and type(G.__GAG2_AUTO_GIFT_CLAIM_API.set) == "function" then
        G.__GAG2_AUTO_GIFT_CLAIM_API.set(GIFT.auto_claim_mail == true, true)
    end
    if G.__GAG2_AUTO_GIFT_ACCEPT_NORMAL_API and type(G.__GAG2_AUTO_GIFT_ACCEPT_NORMAL_API.set) == "function" then
        G.__GAG2_AUTO_GIFT_ACCEPT_NORMAL_API.set(GIFT.auto_accept_gift == true, true)
    end
    if G.__GAG2_AUTO_GIFT_CLAIM_DROP_API and type(G.__GAG2_AUTO_GIFT_CLAIM_DROP_API.set) == "function" then
        G.__GAG2_AUTO_GIFT_CLAIM_DROP_API.set(GIFT.auto_claim_drop == true, true)
    end
    if G.__GAG2_AUTO_GIFT_SUPPRESS_FRIEND_API and type(G.__GAG2_AUTO_GIFT_SUPPRESS_FRIEND_API.set) == "function" then
        G.__GAG2_AUTO_GIFT_SUPPRESS_FRIEND_API.set(GIFT.suppress_fake_friend_request ~= false, true)
    end
end

function M.finalizeGiftTab()
    _ensureBridge()

    local store = ensureAutoGiftStore()
    local onceTargetDd = G.__GAG2_AUTO_GIFT_ONCE_TARGET_DD
        or G.__GAG2_AUTO_GIFT_TARGET_DD
        or rawget(_G, "__GAG2_AUTO_GIFT_ONCE_TARGET_DD")
        or rawget(_G, "__GAG2_AUTO_GIFT_TARGET_DD")
    if type(onceTargetDd) == "table" and type(onceTargetDd.setSelected) == "function" then
        local uid = math.floor(tonumber(store.once.recipient_user_id) or 0)
        pcall(onceTargetDd.setSelected, uid > 0 and tostring(uid) or nil)
    end
    local loopTargetDd = G.__GAG2_AUTO_GIFT_LOOP_TARGET_DD or rawget(_G, "__GAG2_AUTO_GIFT_LOOP_TARGET_DD")
    if type(loopTargetDd) == "table" and type(loopTargetDd.setSelected) == "function" then
        local uid = math.floor(tonumber(store.loop.recipient_user_id) or 0)
        pcall(loopTargetDd.setSelected, uid > 0 and tostring(uid) or nil)
    end

    G.__GAG2_AUTO_GIFT_UI_READY = true
    _G.__GAG2_AUTO_GIFT_UI_READY = true
    task.defer(function()
        if G.__GAG2_AUTO_GIFT_UI_READY ~= true then return end
        G.__GAG2_GIFT_SKIP_DROPDOWN_REFRESH = true
        syncAutoGiftAll()
        G.__GAG2_GIFT_SKIP_DROPDOWN_REFRESH = nil
        applyGiftHistoryUiFromStore()
        local syncAcd = G.__GAG2_SYNC_AUTO_CLAIM_DROP or rawget(_G, "__GAG2_SYNC_AUTO_CLAIM_DROP")
        if type(syncAcd) == "function" then pcall(syncAcd) end
    end)
end

function M.applyUiDefaults(gift, setToggleApi, setInputApi)
    if type(gift) ~= "table" then return end
    setToggleApi("__GAG2_AUTO_GIFT_CLAIM_API", gift.auto_claim_mail)
    setToggleApi("__GAG2_AUTO_GIFT_ACCEPT_NORMAL_API", gift.auto_accept_gift)
    setToggleApi("__GAG2_AUTO_GIFT_CLAIM_DROP_API", gift.auto_claim_drop)
    setToggleApi("__GAG2_AUTO_GIFT_AUTO_SEND_API", gift.auto_send == true)
    local showHist = gift.show_gift_history == true
    setToggleApi("__GAG2_AUTO_GIFT_HISTORY_TOGGLE_API", showHist)
    do
        local s = ensureAutoGiftStore()
        s.show_gift_history = showHist
        s.gift_history_retain_days = math.floor(tonumber(gift.gift_history_retain_days) or 7)
    end
    setInputApi("__GAG2_AUTO_GIFT_HISTORY_RETAIN_DAYS", tostring(gift.gift_history_retain_days or 7))
    task.defer(applyGiftHistoryUiFromStore)
    do
        local onceProfile = type(gift.once) == "table" and gift.once or gift
        local loopProfile = type(gift.loop) == "table" and gift.loop or gift
        local onceTargetDd = G.__GAG2_AUTO_GIFT_ONCE_TARGET_DD
            or G.__GAG2_AUTO_GIFT_TARGET_DD
            or rawget(_G, "__GAG2_AUTO_GIFT_ONCE_TARGET_DD")
            or rawget(_G, "__GAG2_AUTO_GIFT_TARGET_DD")
        if type(onceTargetDd) == "table" and type(onceTargetDd.setSelected) == "function" then
            local uid = math.floor(tonumber(onceProfile.recipient_user_id or gift.recipient_user_id) or 0)
            pcall(onceTargetDd.setSelected, uid > 0 and tostring(uid) or nil)
        end
        local loopTargetDd = G.__GAG2_AUTO_GIFT_LOOP_TARGET_DD or rawget(_G, "__GAG2_AUTO_GIFT_LOOP_TARGET_DD")
        if type(loopTargetDd) == "table" and type(loopTargetDd.setSelected) == "function" then
            local uid = math.floor(tonumber(loopProfile.recipient_user_id) or 0)
            pcall(loopTargetDd.setSelected, uid > 0 and tostring(uid) or nil)
        end
    end
    local onceProfile = type(gift.once) == "table" and gift.once or gift
    local loopProfile = type(gift.loop) == "table" and gift.loop or gift
    G.__GAG2_GIFT_SKIP_DROPDOWN_REFRESH = true
    _G.__GAG2_GIFT_SKIP_DROPDOWN_REFRESH = true
    local onceSendMode = normalizeOnceSendMode(onceProfile.send_mode or ensureAutoGiftStore().once.send_mode)
    applyOnceSendTotalInputsFromProfile(onceProfile, gift)
    do
        local sendModeDd = G.__GAG2_AUTO_GIFT_ONCE_SEND_MODE or rawget(_G, "__GAG2_AUTO_GIFT_ONCE_SEND_MODE")
        if type(sendModeDd) == "table" and type(sendModeDd.setSelected) == "function" then
            pcall(sendModeDd.setSelected, onceSendMode)
        end
        refreshOnceSendModeUi(onceSendMode)
    end
    setInputApi("__GAG2_AUTO_GIFT_ONCE_HARVEST_THRESHOLD", tostring(onceProfile.harvest_price_threshold_pct or 10))
    do
        local calcDd = G.__GAG2_AUTO_GIFT_ONCE_HARVEST_CALC_MODE or rawget(_G, "__GAG2_AUTO_GIFT_ONCE_HARVEST_CALC_MODE")
        if type(calcDd) == "table" and type(calcDd.setSelected) == "function" then
            pcall(calcDd.setSelected, normalizeGiftOnceHarvestCalcMode(onceProfile.harvest_price_calc_mode))
        end
    end
    do
        local onceAfterDd = G.__GAG2_AUTO_GIFT_ONCE_AFTER_SEND_MODE or rawget(_G, "__GAG2_AUTO_GIFT_ONCE_AFTER_SEND_MODE")
        if type(onceAfterDd) == "table" and type(onceAfterDd.setSelected) == "function" then
            local mode = (onceProfile.after_send_mode == "reset") and "reset" or "keep"
            pcall(onceAfterDd.setSelected, mode)
        end
        local loopAfterDd = G.__GAG2_AUTO_GIFT_LOOP_AFTER_SEND_MODE or rawget(_G, "__GAG2_AUTO_GIFT_LOOP_AFTER_SEND_MODE")
        if type(loopAfterDd) == "table" and type(loopAfterDd.setSelected) == "function" then
            local mode = (loopProfile.after_send_mode == "reset") and "reset" or "keep"
            pcall(loopAfterDd.setSelected, mode)
        end
        local loopModeDd = G.__GAG2_AUTO_GIFT_LOOP_CATEGORY_MODE or rawget(_G, "__GAG2_AUTO_GIFT_LOOP_CATEGORY_MODE")
        if type(loopModeDd) == "table" and type(loopModeDd.setSelected) == "function" then
            local cm = tostring(loopProfile.category_mode or gift.category_mode or "single"):lower()
            pcall(loopModeDd.setSelected, (cm == "multi") and "multi" or "single")
        end
    end
    local restoreGiftUi = G.__GAG2_RESTORE_GIFT_CATEGORY_UI or rawget(_G, "__GAG2_RESTORE_GIFT_CATEGORY_UI")
    if type(restoreGiftUi) == "function" then
        pcall(restoreGiftUi)
    end
    G.__GAG2_GIFT_SKIP_DROPDOWN_REFRESH = nil
    _G.__GAG2_GIFT_SKIP_DROPDOWN_REFRESH = nil
end

G.SectionAutoGift = M
_G.SectionAutoGift = M

return M end,            required = false },
    { key = "SectionAutoNormalGift",   name = "Section Auto Normal Gift", factory = function() -- section_auto_normal_gift.lua — Gift Normal (nearby send) store + UI
-- Dipanggil dari tabs_auto.lua (tab Auto → Gift)

local G = (getgenv and getgenv()) or _G
local M = {}

local saveNow
local patchAutoOnly
local getAutoFn
local cleanSelectedMap
local mapToArray
local arrayToMap
local registerFlush

function M.initBridge(bridge)
    if type(bridge) ~= "table" then return end
    saveNow = bridge.saveNow
    patchAutoOnly = bridge.patchAutoOnly
    getAutoFn = bridge.getAuto
    cleanSelectedMap = bridge.cleanSelectedMap
    mapToArray = bridge.mapToArray
    arrayToMap = bridge.arrayToMap
    registerFlush = bridge.registerFlush
end

local function _ensureBridge()
    if type(saveNow) ~= "function" or type(cleanSelectedMap) ~= "function" then
        error("SectionAutoNormalGift.initBridge belum dipanggil dari tabs_auto.lua")
    end
end

local function getAuto(key)
    if type(getAutoFn) == "function" then return getAutoFn(key) end
    local main = G.MAIN or rawget(_G, "MAIN")
    if type(main) == "table" and type(main.auto) == "table" then
        return main.auto[key]
    end
    return nil
end

local function _arrayToMap(arr)
    if type(arrayToMap) == "function" then return arrayToMap(arr) end
    local m = {}
    if type(arr) == "table" then
        for _, v in ipairs(arr) do
            if v ~= nil and tostring(v) ~= "" then m[tostring(v)] = true end
        end
        if next(m) then return m end
        for k, v in pairs(arr) do
            if v == true or v == 1 or v == "true" then m[tostring(k)] = true end
        end
    end
    return m
end

if type(G.__GAG2_NORMAL_GIFT) ~= "table" then
    G.__GAG2_NORMAL_GIFT = {
        target_user_id = 0,
        target_name = "",
        category = "Seeds",
        selected = {},
        send_total = 1,
        send_mode = "total",
        harvest_price_threshold_pct = 10,
        harvest_price_calc_mode = "base",
        teleport_to_target = true,
    }
end
_G.__GAG2_NORMAL_GIFT = G.__GAG2_NORMAL_GIFT

local ensureNormalGiftStore

local function getNormalGiftModule()
    return G.NormalGiftModule or G.NormalGift or _G.NormalGiftModule or _G.NormalGift
end

local function safeDdGetSelected(api)
    if type(api) ~= "table" then return nil end
    local fn = api.getSelected
    if type(fn) ~= "function" then return nil end
    local ok, sel = pcall(fn, api)
    if ok then return sel end
    ok, sel = pcall(fn)
    if ok then return sel end
    return nil
end

local function buildNormalGiftCatUiDefs()
    local ng = getNormalGiftModule()
    if type(ng) ~= "table" then return {} end
    if type(ng.GetCategoryDefs) == "function" then
        local ok, defs = pcall(function()
            return ng:GetCategoryDefs()
        end)
        if ok and type(defs) == "table" and #defs > 0 then
            local out = {}
            for _, def in ipairs(defs) do
                local label = def.label or def.key
                out[#out + 1] = {
                    key = def.key,
                    label = label,
                    itemLabel = label .. " list",
                    placeholder = "Select " .. string.lower(label) .. "...",
                }
            end
            return out
        end
    end
    return {}
end

local function readNormalGiftCategory()
    local active = G.__GAG2_NORMAL_GIFT_ACTIVE_CAT or rawget(_G, "__GAG2_NORMAL_GIFT_ACTIVE_CAT")
    if active ~= nil and tostring(active) ~= "" and tostring(active) ~= "_none" then
        return tostring(active)
    end
    local catDd = G.__GAG2_NORMAL_GIFT_CAT_DD or rawget(_G, "__GAG2_NORMAL_GIFT_CAT_DD")
    if type(catDd) == "table" and type(catDd.getSelected) == "function" then
        local ok, sel = pcall(catDd.getSelected, catDd)
        if not ok then ok, sel = pcall(catDd.getSelected) end
        if ok and sel ~= nil and tostring(sel) ~= "" then
            return tostring(sel)
        end
    end
    return tostring((type(ensureNormalGiftStore) == "function" and ensureNormalGiftStore().category) or "Seeds")
end

local function resolveNormalGiftTarget(key)
    key = tostring(key or ""):gsub("^%s+", ""):gsub("%s+$", "")
    if key == "" then return 0, "", nil end

    local PlayersSvc = game:GetService("Players")
    local uid = math.floor(tonumber(key) or 0)
    if uid > 0 then
        local p = PlayersSvc:GetPlayerByUserId(uid)
        if p and p ~= PlayersSvc.LocalPlayer then
            return p.UserId, p.Name, p
        end
    end

    local lower = key:lower():gsub("^@", "")
    for _, p in ipairs(PlayersSvc:GetPlayers()) do
        if p ~= PlayersSvc.LocalPlayer then
            local label = p.DisplayName .. " (@" .. p.Name .. ")"
            if p.Name:lower() == lower
                or p.DisplayName:lower() == lower
                or label:lower() == lower
                or label:lower():find(lower, 1, true)
                or lower:find(p.Name:lower(), 1, true) then
                return p.UserId, p.Name, p
            end
        end
    end

    local ng = getNormalGiftModule()
    if type(ng) == "table" and type(ng.ListServerPlayers) == "function" then
        local ok, list = pcall(ng.ListServerPlayers)
        if ok and type(list) == "table" then
            for _, item in ipairs(list) do
                local itemKey = tostring(item.key or "")
                if itemKey == key or itemKey:lower() == lower then
                    local pid = math.floor(tonumber(item.userId or itemKey) or 0)
                    if pid > 0 then
                        local p = PlayersSvc:GetPlayerByUserId(pid)
                        if p then return p.UserId, p.Name, p end
                    end
                end
                local itemName = tostring(item.name or ""):lower()
                if itemName == lower or itemName:find(lower, 1, true) then
                    local pid = math.floor(tonumber(item.userId or item.key) or 0)
                    if pid > 0 then
                        local p = PlayersSvc:GetPlayerByUserId(pid)
                        if p then return p.UserId, p.Name, p end
                    end
                end
            end
        end
    end

    return 0, "", nil
end

local function normalGiftTargetReady()
    local ensureFn = ensureNormalGiftStore
        or G.__GAG2_ENSURE_NORMAL_GIFT_STORE
        or rawget(_G, "__GAG2_ENSURE_NORMAL_GIFT_STORE")
    if type(ensureFn) ~= "function" then
        return false, nil
    end
    local s = ensureFn()
    if s.target_user_id > 0 then
        local _, _, p = resolveNormalGiftTarget(tostring(s.target_user_id))
        if p then return true, p end
    end
    if s.target_name ~= "" then
        local _, _, p = resolveNormalGiftTarget(s.target_name)
        if p then return true, p end
    end
    local playerDd = G.__GAG2_NORMAL_GIFT_PLAYER_DD or rawget(_G, "__GAG2_NORMAL_GIFT_PLAYER_DD")
    local sel = safeDdGetSelected(playerDd)
    if sel ~= nil and tostring(sel) ~= "" then
        local _, _, p = resolveNormalGiftTarget(sel)
        if p then return true, p end
    end
    return false, nil
end

local function isNormalGiftHarvestCategory(cat)
    cat = tostring(cat or ""):lower():gsub("[%s_]+", "")
    return cat == "harvestedfruits" or cat == "harvestedfruit" or cat == "harvestedfruid"
end

local function prefetchNormalGiftHarvestSources()
    local ng = getNormalGiftModule()
    if type(ng) == "table" and type(ng.PrefetchHarvestSources) == "function" then
        pcall(ng.PrefetchHarvestSources, ng)
    end
end

local function buildNormalGiftItemList(cat)
    local ok, items = pcall(function()
        cat = tostring(cat or readNormalGiftCategory() or "Seeds")
        if cat == "" then cat = "Seeds" end
        if cat == "_none" then return {} end

        local ng = getNormalGiftModule()
        if type(ng) ~= "table" or type(ng.GetItemsForCategory) ~= "function" then
            return {}
        end

        local okFetch, list = pcall(function()
            return ng:GetItemsForCategory(cat)
        end)
        if okFetch and type(list) == "table" then
            if #list == 0 and isNormalGiftHarvestCategory(cat) then
                prefetchNormalGiftHarvestSources()
            end
            return list
        end

        if isNormalGiftHarvestCategory(cat) then
            okFetch, list = pcall(function()
                return ng:GetItemsForCategory("HarvestedFruits")
            end)
            if okFetch and type(list) == "table" then
                if #list == 0 then
                    prefetchNormalGiftHarvestSources()
                end
                return list
            end
        end

        return {}
    end)
    if ok and type(items) == "table" then
        return items
    end
    return {}
end

local GIFT_NORMAL_SEND_MODE_ITEMS = {
    { key = "price", name = "Price" },
    { key = "total", name = "Total" },
}

local GIFT_NORMAL_HARVEST_CALC_ITEMS = {
    { key = "base", name = "Base" },
    { key = "stock", name = "Base + Stock + Friend" },
}

local function normalizeNormalGiftSendMode(mode)
    return (tostring(mode or "total"):lower() == "price") and "price" or "total"
end

local function normalizeNormalGiftHarvestCalcMode(mode)
    return (tostring(mode or "base"):lower() == "stock") and "stock" or "base"
end

local function parseNormalGiftSendTotalPrice(txt)
    local ng = getNormalGiftModule()
    if type(ng) == "table" and type(ng.ParseSendTotalPrice) == "function" then
        local ok, n = pcall(ng.ParseSendTotalPrice, ng, txt)
        if ok and type(n) == "number" then return n end
    end
    local ag = G.AutoGiftModule or G.AutoGift or rawget(_G, "AutoGiftModule") or rawget(_G, "AutoGift")
    if type(ag) == "table" and type(ag.ParseSendTotalPrice) == "function" then
        local ok, n = pcall(ag.ParseSendTotalPrice, ag, txt)
        if ok and type(n) == "number" then return n end
    end
    return math.max(0, math.floor(tonumber(txt) or 0))
end

local function formatNormalGiftSendTotalDisplay(n)
    local ng = getNormalGiftModule()
    if type(ng) == "table" and type(ng.FormatSendTotalPrice) == "function" then
        local ok, s = pcall(ng.FormatSendTotalPrice, ng, n)
        if ok and type(s) == "string" then return s end
    end
    local ag = G.AutoGiftModule or G.AutoGift or rawget(_G, "AutoGiftModule") or rawget(_G, "AutoGift")
    if type(ag) == "table" and type(ag.FormatSendTotalPrice) == "function" then
        local ok, s = pcall(ag.FormatSendTotalPrice, ag, n)
        if ok and type(s) == "string" then return s end
    end
    n = math.floor(tonumber(n) or 0)
    if n >= 1000000 then return string.format("%.2fM", n / 1000000) end
    if n >= 1000 then return string.format("%.1fK", n / 1000) end
    return tostring(n)
end

local function normalGiftUsesPriceMode(store)
    store = type(store) == "table" and store or ensureNormalGiftStore()
    if normalizeNormalGiftSendMode(store.send_mode) ~= "price" then return false end
    local cat = store.category
    if cat == nil or tostring(cat) == "" then
        cat = readNormalGiftCategory()
    end
    return isNormalGiftHarvestCategory(cat)
end

local ngSendTotalLabel = nil
local ngSendTotalSetFn = nil
local ngHarvestConfigLabel = nil
local ngHarvestPriceRows = {}

local function setNormalGiftSendTotalInputValue(store)
    if type(ngSendTotalSetFn) ~= "function" then return end
    store = store or ensureNormalGiftStore()
    if normalGiftUsesPriceMode(store) then
        pcall(ngSendTotalSetFn, formatNormalGiftSendTotalDisplay(store.send_total or 1000))
    else
        pcall(ngSendTotalSetFn, tostring(store.send_total or 1))
    end
end

local function refreshNormalGiftSendTotalRow(store)
    store = store or ensureNormalGiftStore()
    local priceMode = normalGiftUsesPriceMode(store)
    if ngSendTotalLabel then
        ngSendTotalLabel.Text = priceMode and "Send total price (1K / 1M)" or "Total send"
    end
    setNormalGiftSendTotalInputValue(store)
end

local function refreshNormalGiftSendModeUi(store)
    store = store or ensureNormalGiftStore()
    local priceMode = normalizeNormalGiftSendMode(store.send_mode) == "price"
    if ngHarvestConfigLabel then
        ngHarvestConfigLabel.Visible = true
    end
    for _, row in ipairs(ngHarvestPriceRows) do
        if row then row.Visible = priceMode end
    end
    refreshNormalGiftSendTotalRow(store)
end

G.__GAG2_REFRESH_NORMAL_GIFT_SEND_MODE = refreshNormalGiftSendModeUi
_G.__GAG2_REFRESH_NORMAL_GIFT_SEND_MODE = refreshNormalGiftSendModeUi

local function countNormalGiftSelected(map)
    map = cleanSelectedMap(map or {})
    local n = 0
    for _, v in pairs(map) do
        if v == true then n = n + 1 end
    end
    return n
end

ensureNormalGiftStore = function()
    local s = G.__GAG2_NORMAL_GIFT
    if type(s) ~= "table" then
        s = {
            target_user_id = 0,
            target_name = "",
            category = "Seeds",
            selected = {},
            send_total = 1,
            send_mode = "total",
            harvest_price_threshold_pct = 10,
            harvest_price_calc_mode = "base",
            teleport_to_target = true,
        }
        G.__GAG2_NORMAL_GIFT = s
    end

    s.target_user_id = math.floor(tonumber(s.target_user_id) or 0)
    s.target_name = tostring(s.target_name or "")
    s.category = tostring(s.category or "Seeds")
    if s.category == "" then s.category = "Seeds" end
    s.selected = cleanSelectedMap(s.selected)
    s.send_mode = normalizeNormalGiftSendMode(s.send_mode)
    s.harvest_price_threshold_pct = math.floor(tonumber(s.harvest_price_threshold_pct) or 10)
    if s.harvest_price_threshold_pct < 0 then s.harvest_price_threshold_pct = 0 end
    if s.harvest_price_threshold_pct > 100 then s.harvest_price_threshold_pct = 100 end
    s.harvest_price_calc_mode = normalizeNormalGiftHarvestCalcMode(s.harvest_price_calc_mode)
    if normalizeNormalGiftSendMode(s.send_mode) == "price" and isNormalGiftHarvestCategory(s.category) then
        s.send_total = math.floor(math.max(1, tonumber(s.send_total) or 1000))
    else
        s.send_total = math.floor(math.max(1, tonumber(s.send_total) or 1))
    end
    if s.teleport_to_target == nil then s.teleport_to_target = true end
    s.teleport_to_target = (s.teleport_to_target == true)

    if not s._hydrated then
        local ngMain = getAuto("normalGift")
        if type(ngMain) == "table" then
            if (tonumber(ngMain.target_user_id) or 0) > 0 then
                s.target_user_id = math.floor(tonumber(ngMain.target_user_id))
            end
            if ngMain.target_name ~= nil and tostring(ngMain.target_name) ~= "" then
                s.target_name = tostring(ngMain.target_name)
            end
            if ngMain.category ~= nil and tostring(ngMain.category) ~= "" then
                s.category = tostring(ngMain.category)
            end
            if type(ngMain.selected) == "table" and next(ngMain.selected) then
                s.selected = cleanSelectedMap(_arrayToMap(ngMain.selected))
            end
            if ngMain.send_total ~= nil then
                if normalizeNormalGiftSendMode(ngMain.send_mode) == "price"
                    and isNormalGiftHarvestCategory(ngMain.category) then
                    s.send_total = math.floor(math.max(1, tonumber(ngMain.send_total) or 1000))
                else
                    s.send_total = math.floor(math.max(1, tonumber(ngMain.send_total) or 1))
                end
            end
            if ngMain.send_mode ~= nil then
                s.send_mode = normalizeNormalGiftSendMode(ngMain.send_mode)
            end
            if ngMain.harvest_price_threshold_pct ~= nil then
                s.harvest_price_threshold_pct = math.floor(tonumber(ngMain.harvest_price_threshold_pct) or 10)
            end
            if ngMain.harvest_price_calc_mode ~= nil then
                s.harvest_price_calc_mode = normalizeNormalGiftHarvestCalcMode(ngMain.harvest_price_calc_mode)
            end
            if ngMain.teleport_to_target ~= nil then
                s.teleport_to_target = (ngMain.teleport_to_target == true)
            end
        end
        s._hydrated = true
    end

    G.__GAG2_NORMAL_GIFT = s
    _G.__GAG2_NORMAL_GIFT = s
    return s
end
G.__GAG2_ENSURE_NORMAL_GIFT_STORE = ensureNormalGiftStore
_G.__GAG2_ENSURE_NORMAL_GIFT_STORE = ensureNormalGiftStore

local function normalGiftPayloadFromStore(s)
    s = ensureNormalGiftStore()
    return {
        target_user_id = s.target_user_id,
        target_name = s.target_name,
        category = s.category,
        selected = mapToArray(s.selected),
        send_total = s.send_total,
        send_mode = s.send_mode,
        harvest_price_threshold_pct = s.harvest_price_threshold_pct,
        harvest_price_calc_mode = s.harvest_price_calc_mode,
        teleport_to_target = s.teleport_to_target == true,
    }
end

local function writeNormalGiftToMain()
    local s = ensureNormalGiftStore()
    G.__GAG2_NORMAL_GIFT = s
    _G.__GAG2_NORMAL_GIFT = s
    patchAutoOnly("normalGift", normalGiftPayloadFromStore(s))
    return s
end

local function writeNormalGiftState(opts)
    local s = ensureNormalGiftStore()
    if type(opts) == "table" then
        if opts.target_user_id ~= nil then
            s.target_user_id = math.floor(tonumber(opts.target_user_id) or 0)
        end
        if opts.target_name ~= nil then
            s.target_name = tostring(opts.target_name or "")
        end
        if opts.category ~= nil and tostring(opts.category) ~= "" then
            s.category = tostring(opts.category)
        end
        if type(opts.selected) == "table" then
            if opts.selected[1] ~= nil then
                s.selected = cleanSelectedMap(_arrayToMap(opts.selected))
            else
                s.selected = cleanSelectedMap(opts.selected)
            end
        end
        if opts.send_total ~= nil then
            local priceMode = normalGiftUsesPriceMode({
                send_mode = opts.send_mode or s.send_mode,
                category = opts.category or s.category,
            })
            if priceMode then
                local n = parseNormalGiftSendTotalPrice(opts.send_total)
                if n < 1 then n = 1 end
                s.send_total = math.floor(n)
            else
                local n = math.floor(tonumber(opts.send_total) or 1)
                if n < 1 then n = 1 end
                s.send_total = n
            end
        end
        if opts.send_mode ~= nil then
            s.send_mode = normalizeNormalGiftSendMode(opts.send_mode)
        end
        if opts.harvest_price_threshold_pct ~= nil then
            local n = tonumber(opts.harvest_price_threshold_pct)
            if n ~= nil then
                if n < 0 then n = 0 end
                if n > 100 then n = 100 end
                s.harvest_price_threshold_pct = math.floor(n)
            end
        end
        if opts.harvest_price_calc_mode ~= nil then
            s.harvest_price_calc_mode = normalizeNormalGiftHarvestCalcMode(opts.harvest_price_calc_mode)
        end
        if opts.teleport_to_target ~= nil then
            s.teleport_to_target = (opts.teleport_to_target == true)
        end
    end
    return writeNormalGiftToMain()
end

local function patchNormalGift(opts, syncFn)
    writeNormalGiftState(opts)
    if syncFn then pcall(syncFn) end
    saveNow()
end

local function applyNormalGiftRuntime()
    local s = ensureNormalGiftStore()
    local ng = getNormalGiftModule()
    if type(ng) ~= "table" then return end
    if type(ng.ApplyConfig) == "function" then
        pcall(function()
            ng.ApplyConfig({
                target_user_id = s.target_user_id,
                target_name = s.target_name,
                category = readNormalGiftCategory(),
                selected = s.selected,
                send_total = s.send_total,
                send_mode = s.send_mode,
                harvest_price_threshold_pct = s.harvest_price_threshold_pct,
                harvest_price_calc_mode = s.harvest_price_calc_mode,
                teleport_to_target = s.teleport_to_target,
            })
        end)
    end
end

local function flushNormalGiftFromUI()
    if G.__GAG2_RESETTING == true then return end
    local opts = {}

    local playerDd = G.__GAG2_NORMAL_GIFT_PLAYER_DD or rawget(_G, "__GAG2_NORMAL_GIFT_PLAYER_DD")
    local playerKey = safeDdGetSelected(playerDd)
    if playerKey ~= nil and tostring(playerKey) ~= "" then
        local uid, name = resolveNormalGiftTarget(playerKey)
        if uid > 0 then opts.target_user_id = uid end
        if name ~= "" then opts.target_name = name end
    end

    local catDd = G.__GAG2_NORMAL_GIFT_CAT_DD or rawget(_G, "__GAG2_NORMAL_GIFT_CAT_DD")
    local activeCat = G.__GAG2_NORMAL_GIFT_ACTIVE_CAT or rawget(_G, "__GAG2_NORMAL_GIFT_ACTIVE_CAT")
    local catKey = activeCat
    if catKey == nil or tostring(catKey) == "" then
        catKey = safeDdGetSelected(catDd)
    end
    if catKey ~= nil and tostring(catKey) ~= "" and tostring(catKey) ~= "_none" then
        opts.category = tostring(catKey)
    end

    local itemDd = G.__GAG2_NORMAL_GIFT_ITEM_DD or rawget(_G, "__GAG2_NORMAL_GIFT_ITEM_DD")
    local itemSel = safeDdGetSelected(itemDd)
    if itemSel ~= nil then
        if type(itemSel) == "table" then
            opts.selected = cleanSelectedMap(itemSel)
        elseif tostring(itemSel) ~= "" then
            opts.selected = { [tostring(itemSel)] = true }
        end
    end

    local totalFn = G.__GAG2_NORMAL_GIFT_SEND_TOTAL or rawget(_G, "__GAG2_NORMAL_GIFT_SEND_TOTAL")
    if type(totalFn) == "function" then
        local txt = totalFn()
        local s2 = ensureNormalGiftStore()
        if normalGiftUsesPriceMode(s2) then
            local n = parseNormalGiftSendTotalPrice(txt)
            if n and n >= 1 then opts.send_total = math.floor(n) end
        else
            local n = tonumber(txt)
            if n and n >= 1 then
                opts.send_total = math.floor(n)
            end
        end
    end

    local sendModeDd = G.__GAG2_NORMAL_GIFT_SEND_MODE or rawget(_G, "__GAG2_NORMAL_GIFT_SEND_MODE")
    local sendModeSel = safeDdGetSelected(sendModeDd)
    if sendModeSel ~= nil and tostring(sendModeSel) ~= "" then
        opts.send_mode = normalizeNormalGiftSendMode(sendModeSel)
    end

    local thresholdFn = G.__GAG2_NORMAL_GIFT_HARVEST_THRESHOLD or rawget(_G, "__GAG2_NORMAL_GIFT_HARVEST_THRESHOLD")
    if type(thresholdFn) == "function" then
        local n = tonumber(thresholdFn())
        if n ~= nil then opts.harvest_price_threshold_pct = math.floor(n) end
    end

    local calcDd = G.__GAG2_NORMAL_GIFT_HARVEST_CALC_MODE or rawget(_G, "__GAG2_NORMAL_GIFT_HARVEST_CALC_MODE")
    local calcSel = safeDdGetSelected(calcDd)
    if calcSel ~= nil and tostring(calcSel) ~= "" then
        opts.harvest_price_calc_mode = normalizeNormalGiftHarvestCalcMode(calcSel)
    end

    if next(opts) ~= nil then
        writeNormalGiftState(opts)
    else
        writeNormalGiftToMain()
    end
end

local function sendNormalGiftNow(isOn)
    local sendApi = G.__GAG2_NORMAL_GIFT_SEND_API or rawget(_G, "__GAG2_NORMAL_GIFT_SEND_API")
    if isOn == false then
        local ng = getNormalGiftModule()
        if type(ng) == "table" and type(ng.StopSend) == "function" then
            pcall(ng.StopSend, ng)
        end
        return
    end

    flushNormalGiftFromUI()
    local s = ensureNormalGiftStore()
    local itemDd = G.__GAG2_NORMAL_GIFT_ITEM_DD or rawget(_G, "__GAG2_NORMAL_GIFT_ITEM_DD")
    local itemSel = safeDdGetSelected(itemDd)
    local selMap = (type(itemSel) == "table") and cleanSelectedMap(itemSel) or s.selected
    local cat = readNormalGiftCategory()
    if countNormalGiftSelected(selMap) < 1 and not isNormalGiftHarvestCategory(cat) then
        G.NORMAL_GIFT_STATUS = "Select at least 1 item in list"
        _G.NORMAL_GIFT_STATUS = G.NORMAL_GIFT_STATUS
        if type(sendApi) == "table" and type(sendApi.set) == "function" then
            pcall(sendApi.set, false, true)
        end
        return
    end

    local ng = getNormalGiftModule()
    if type(ng) ~= "table" or type(ng.SendNow) ~= "function" then
        G.NORMAL_GIFT_STATUS = "NormalGift module not loaded"
        _G.NORMAL_GIFT_STATUS = G.NORMAL_GIFT_STATUS
        return
    end

    task.spawn(function()
        local opts = {
            target_user_id = s.target_user_id,
            target_name = s.target_name,
            category = readNormalGiftCategory(),
            selected = selMap,
            send_total = s.send_total,
            send_mode = s.send_mode,
            harvest_price_threshold_pct = s.harvest_price_threshold_pct,
            harvest_price_calc_mode = s.harvest_price_calc_mode,
            teleport_to_target = s.teleport_to_target,
        }

        local ok, err = pcall(function()
            local started, reason = ng.SendNow(opts)
            if started ~= true then
                local msg = tostring(reason or "Send failed")
                if reason ~= "busy" and type(ng.GetStats) == "function" then
                    local okStats, st = pcall(ng.GetStats, ng)
                    if okStats and type(st) == "table" and st.lastStatus and st.lastStatus ~= "" then
                        msg = tostring(st.lastStatus)
                    end
                end
                G.NORMAL_GIFT_STATUS = msg
                _G.NORMAL_GIFT_STATUS = G.NORMAL_GIFT_STATUS
                if type(sendApi) == "table" and type(sendApi.set) == "function" then
                    pcall(sendApi.set, false, true)
                end
            end
        end)
        if not ok then
            G.NORMAL_GIFT_STATUS = "Send error: " .. tostring(err)
            _G.NORMAL_GIFT_STATUS = G.NORMAL_GIFT_STATUS
            if type(sendApi) == "table" and type(sendApi.set) == "function" then
                pcall(sendApi.set, false, true)
            end
        end
    end)
end

local function syncNormalGiftAll()
    if G.__GAG2_RESETTING == true then
        writeNormalGiftToMain()
        applyNormalGiftRuntime()
        return
    end
    if G.__GAG2_NORMAL_GIFT_UI_READY == true then
        flushNormalGiftFromUI()
    else
        writeNormalGiftToMain()
    end
    applyNormalGiftRuntime()
end

G.__GAG2_SYNC_NORMAL_GIFT = syncNormalGiftAll
G.__GAG2_FLUSH_NORMAL_GIFT = flushNormalGiftFromUI
_G.__GAG2_SYNC_NORMAL_GIFT = syncNormalGiftAll
_G.__GAG2_FLUSH_NORMAL_GIFT = flushNormalGiftFromUI

function M.initStore()
    _ensureBridge()
    registerFlush("normalGift", flushNormalGiftFromUI)
    ensureNormalGiftStore()
    applyNormalGiftRuntime()
end

function M.RegisterSubTab(ui)
    if type(ui) ~= "table" then return end
    _ensureBridge()

