local function refreshNgStatusLabel(lbl)
    if not lbl or not lbl.Parent then return end
    local ok, err = pcall(function()
        local ensureFn = ensureNormalGiftStore
            or G.__GAG2_ENSURE_NORMAL_GIFT_STORE
            or rawget(_G, "__GAG2_ENSURE_NORMAL_GIFT_STORE")
        if type(ensureFn) ~= "function" then return end
        NGIFT = ensureFn()
        local globalStatus = tostring(G.NORMAL_GIFT_STATUS or rawget(_G, "NORMAL_GIFT_STATUS") or "")
        local moduleStatus = ""
        local busy = false
        local ng = getNormalGiftModule()
        if type(ng) == "table" and type(ng.GetStats) == "function" then
            local okStats, st = pcall(ng.GetStats, ng)
            if okStats and type(st) == "table" then
                moduleStatus = tostring(st.lastStatus or "")
                busy = (st.busy == true)
            end
        end
        local txt = "Ready"
        if busy and moduleStatus ~= "" then
            txt = moduleStatus
        elseif globalStatus ~= "" and globalStatus ~= "Ready" then
            txt = globalStatus
        elseif moduleStatus ~= "" and moduleStatus ~= "Ready" then
            txt = moduleStatus
        end
        local tname = NGIFT.target_name
        local ready, target = normalGiftTargetReady()
        if ready and target then
            tname = target.Name
        end
        if tname ~= "" then
            txt = "Target: @" .. tostring(tname):gsub("^@", "") .. " | " .. txt
        end
        lbl.Text = "Status: " .. txt
    end)
    if not ok then
        lbl.Text = "Status: UI error"
    end
end

