    SeedTool = "Seeds", Sprinkler = "Sprinklers", Rake = "Rakes", WateringCan = "WateringCans",
    Shovel = "Shovels", Trowel = "Trowels", Crowbar = "Crowbars", Build = "Builds",
    Mushroom = "Mushrooms", Gnome = "Gnomes", Raccoon = "Raccoons", Crate = "Crates",
    Teleporter = "Teleporters", PlayerMagnet = "PlayerMagnets", FruitMagnet = "FruitMagnets",
    PetTeleporter = "PetTeleporters", PetLure = "PetLures", SeedPack = "SeedPacks", Egg = "Eggs",
    Wheelbarrow = "Wheelbarrows", Ladder = "Ladders", FreezeRay = "FreezeRays", PowerHose = "PowerHoses",
    EmptyPot = "EmptyPots", Flashbang = "Flashbangs", Bird = "Birds", Pet = "Pets",
}

local function ag() return G.AutoGiftModule or G.AutoGift end
local function ng() return G.NormalGiftModule or G.NormalGift end

function H._setStatus(msg)
    stats.lastStatus = tostring(msg or "Ready")
    G.AUTO_DROP_STATUS = stats.lastStatus
    rawset(_G, "AUTO_DROP_STATUS", stats.lastStatus)
end

function H._cat(c)
    local n = tostring(c or ""):lower():gsub("[%s_]+", "")
    if n == "harvestedfruits" or n == "harvestedfruit" then return "HarvestedFruits" end
    return tostring(c or "Seeds")
end

function H._isHarvest(c) return H._cat(c) == "HarvestedFruits" end

function H._isPetCat(c)
    local n = tostring(c or ""):lower():gsub("[%s_]+", "")
    return n == "pets" or n == "birds" or n == "tools"
end

function H._petDropCategory(catKey)
    catKey = H._cat(catKey)
    if tostring(catKey):lower() == "tools" then return "Pets" end
    return catKey
end

function H._normSet(src)
    local out = {}
    if type(src) ~= "table" then return out end
    for k, v in pairs(src) do if v == true or v == 1 or v == "true" then out[tostring(k)] = true end end
    for _, v in ipairs(src) do if v ~= nil and tostring(v) ~= "" then out[tostring(v)] = true end end
    return out
end

function H._hasSel(m)
    for _, v in pairs(H._normSet(m)) do if v then return true end end
    return false
end

function H._strip(s) return tostring(s or ""):gsub("%s+x%s+.+$", ""):gsub("%s+$", "") end

function H._normKey(v)
    v = H._strip(v):lower():gsub("[%s_%-%.'']+", "")
    if v:sub(-4) == "seed" then v = v:sub(1, -5) end
    return v
end

function H._callable(r)
    if r == nil then return false end
    if type(r) == "table" then return type(r.Fire) == "function" or type(r.Invoke) == "function" end
    if typeof(r) == "Instance" then
        return r:IsA("RemoteEvent") or r:IsA("UnreliableRemoteEvent") or r:IsA("BindableEvent") or r:IsA("RemoteFunction")
    end
    return type(r) == "function"
end

function H._fireNet(r, ...)
    if not H._callable(r) then return false end
    local a = table.pack(...)
    local ok = pcall(function()
        if type(r) == "function" then return r(table.unpack(a, 1, a.n)) end
        if typeof(r) == "Instance" then
            if r:IsA("RemoteFunction") then return r:InvokeServer(table.unpack(a, 1, a.n)) end
            return r:FireServer(table.unpack(a, 1, a.n))
        end
        if type(r.Fire) == "function" then return r:Fire(table.unpack(a, 1, a.n)) end
        if type(r.Invoke) == "function" then return r:Invoke(table.unpack(a, 1, a.n)) end
    end)
    return ok
end

function H._ensureDropRemote()
    if H._callable(RequestDrop) then return true end
    local ok, net = pcall(function() return require(ReplicatedStorage.SharedModules.Networking) end)
    if ok and type(net.DroppedItem) == "table" then RequestDrop = net.DroppedItem.RequestDrop end
    return H._callable(RequestDrop)
end

function H._ensureBackpackNet()
    if H._callable(DropBackpackGetLayout) and H._callable(DropBackpackPromoteFruit) then return true end
    local ok, net = pcall(function() return require(ReplicatedStorage.SharedModules.Networking) end)
    if ok and type(net.Backpack) == "table" then
        DropBackpackGetLayout = DropBackpackGetLayout or net.Backpack.GetLayout
        DropBackpackPromoteFruit = DropBackpackPromoteFruit or net.Backpack.PromoteFruit
    end
    return H._callable(DropBackpackGetLayout)
end

function H._invalidateBag()
    bagCache, bagCacheAt = nil, 0
    local a = ag()
    if type(a) == "table" and type(a.InvalidateHarvestFruitCache) == "function" then pcall(a.InvalidateHarvestFruitCache, a) end
end

function H._backpack() return LP:FindFirstChild("Backpack") or LP:FindFirstChildOfClass("Backpack") end

function H._fruitId(inst)
    if not inst or type(inst.GetAttribute) ~= "function" then return "" end
    return tostring(inst:GetAttribute("Id") or inst:GetAttribute("UUID") or "")
end

function H._isFruitId(id)
    id = tostring(id or "")
    return id ~= "" and not id:find("%s") and #id >= 8
        and not (id:match("^[%a'%-]+$") and not id:match("[%d_]"))
end

function H._isHarvestInst(inst)
    if not inst or type(inst.GetAttribute) ~= "function" then return false end
    if inst:GetAttribute("SeedTool") or inst:GetAttribute("Pet") or inst:GetAttribute("PetId") then return false end
    if inst:GetAttribute("PottedPlant") == true or inst:GetAttribute("MainCategory") == "Seed" then return false end
    local f = inst:GetAttribute("FruitName") or inst:GetAttribute("Fruit")
    if f and tostring(f) ~= "" then return true end
    if inst:GetAttribute("FruitProxy") == true then return true end
    local hf = inst:GetAttribute("HarvestedFruit")
    if hf == true or (type(hf) == "string" and hf ~= "") then return true end
    return inst:GetAttribute("Id") and (inst:GetAttribute("Weight") or inst:GetAttribute("SizeMultiplier"))
end

function H._matchId(inst, id)
    id = tostring(id or "")
    if id == "" then return false end
    if H._fruitId(inst) == id then return true end
    if not inst or type(inst.GetAttribute) ~= "function" then return false end
    local petId = inst:GetAttribute("PetId")
    if type(petId) == "string" and petId == id then return true end
    local uid = inst:GetAttribute("Id") or inst:GetAttribute("UUID") or inst:GetAttribute("InstanceId")
    return uid ~= nil and tostring(uid) == id
end

function H._findPetTool(id)
    id = tostring(id or "")
    if id == "" then return nil end
    local found = nil
    local function scan(container)
        if not container or found then return end
        for _, inst in ipairs(container:GetDescendants()) do
            if inst:IsA("Tool") and H._matchId(inst, id) then
                found = inst
                return
            end
        end
    end
    scan(LP.Character)
    scan(H._backpack())
    return found
end

function H._findTool(id)
    return H._findPetTool(id)
end

function H._eachTool(fn)
    for _, c in ipairs({ LP.Character, H._backpack() }) do
        if c then for _, t in ipairs(c:GetChildren()) do if t:IsA("Tool") then fn(t) end end end
    end
end

function H._fpu()
    if FruitProxyUtil == nil then
        pcall(function() FruitProxyUtil = require(ReplicatedStorage.SharedModules.FruitProxyUtil) end)
        if type(FruitProxyUtil) ~= "table" then FruitProxyUtil = false end
    end
    return FruitProxyUtil ~= false and FruitProxyUtil or nil
end

function H._clearChar()
    local char, bp = LP.Character, H._backpack()
    if not char or not bp then return end
    for _, t in ipairs(char:GetChildren()) do if t:IsA("Tool") then pcall(function() t.Parent = bp end) end end
    local hum = char:FindFirstChildOfClass("Humanoid")
    if hum then pcall(function() hum:UnequipTools() end) end
end

function H._toolReady(t)
    if not t then return false end
    local n = t:GetAttribute("ToolDescendants")
    if type(n) == "number" and #t:GetDescendants() < n then return false end
    for _, d in ipairs(t:GetDescendants()) do
        if (d:IsA("Weld") or d:IsA("WeldConstraint")) and (not d.Part0 or not d.Part1) then return false end
    end
    return true
end

function H._equip(t)
    local char, bp = LP.Character, H._backpack()
    local hum = char and char:FindFirstChildOfClass("Humanoid")
    if not t or not char or not bp or not hum or not t.Parent then return false end
    if t.Parent ~= bp and t.Parent ~= char then
        if t:IsDescendantOf(bp) then pcall(function() t.Parent = bp end) else return false end
    end
    if t.Parent == char then return true end
    H._clearChar()
    local dl = os.clock() + 0.5
    while os.clock() < dl and not H._toolReady(t) do RunService.Heartbeat:Wait() end
    if t.Parent == bp then pcall(function() t.Parent = char end) end
    dl = os.clock() + 0.5
    while os.clock() < dl do
        if t.Parent == char then return true end
        task.wait(0.02)
    end
    pcall(function() hum:EquipTool(t) end)
    task.wait(0.04)
    return t.Parent == char
end

function H._promote(id)
    id = tostring(id or "")
    if not H._isFruitId(id) then return false end
    local t = H._findTool(id)
    if t then return t.Parent == LP.Character or H._equip(t) end
    H._clearChar()
    local f = H._fpu()
    if f then
        if type(f.Pending) ~= "table" then f.Pending = {} end
        f.Pending.Equip = id
        if type(f.RequestPromote) == "function" then pcall(f.RequestPromote, id) end
    end
    H._ensureBackpackNet()
    if H._callable(DropBackpackPromoteFruit) then H._fireNet(DropBackpackPromoteFruit, id) end
    H._invalidateBag()
    local dl = os.clock() + PROMOTE_WAIT
    while os.clock() < dl do
        if dropCancel then return false end
        t = H._findTool(id)
        if t then return t.Parent == LP.Character or H._equip(t) end
        task.wait(0.05)
    end
    t = H._findTool(id)
    return t and H._equip(t)
end

function H._resolveDropId(t, uuid)
    if t and t.Parent then
        if t:GetAttribute("HarvestedFruit") == true then
            local id = t:GetAttribute("Id")
            if id and tostring(id) ~= "" then return tostring(id) end
        end
        if H._isHarvestInst(t) then
            local id = H._fruitId(t)
            if H._isFruitId(id) then return id end
        end
    end
    return H._isFruitId(uuid) and tostring(uuid) or ""
end

function H._equippedDrop()
    local char = LP.Character
    if not char then return nil, nil end
    for _, t in ipairs(char:GetChildren()) do
        if not t:IsA("Tool") then continue end
        if t:GetAttribute("HarvestedFruit") == true then
            local id = t:GetAttribute("Id")
            if id and tostring(id) ~= "" then return "HarvestedFruits", tostring(id) end
        end
        if H._isHarvestInst(t) then
            local id = H._fruitId(t)
            if H._isFruitId(id) then return "HarvestedFruits", id end
        end
        local petId = t:GetAttribute("PetId")
        if type(petId) == "string" and petId ~= "" then return "Pets", petId end
        for attr, gt in pairs(GIFT_ATTR) do
            local v = t:GetAttribute(attr)
            if v ~= nil and v ~= false and tostring(v) ~= "" then return gt, tostring(v) end
        end
    end
    return nil, nil
end

function H._requestDrop(cat, id)
    if not H._ensureDropRemote() then return false end
    cat, id = tostring(cat or ""), tostring(id or "")
    if cat == "" or id == "" then return false end
    return pcall(function()
        if type(RequestDrop) == "table" and RequestDrop.Fire then RequestDrop:Fire(cat, id)
        else H._fireNet(RequestDrop, cat, id) end
    end)
end

function H._hasUuid(uuid, refresh)
    uuid = tostring(uuid or "")
    if uuid == "" then return false end
    if H._findTool(uuid) then return true end
    local bag = H._getBag(refresh == true)
    return type(bag) == "table" and bag[uuid] ~= nil
end

function H._getBag(refresh)
    local now = os.clock()
    if not refresh and bagCache and (now - bagCacheAt) < BAG_CACHE_SEC then return bagCache end
    local a = ag()
    if type(a) == "table" and type(a.GetHarvestFruitBag) == "function" then
        local ok, bag = pcall(a.GetHarvestFruitBag, a, refresh == true)
        if ok and type(bag) == "table" then bagCache, bagCacheAt = bag, now return bag end
    end
    bagCache, bagCacheAt = {}, now
    return bagCache
end

function H._fav(item)
    if type(item) ~= "table" then return false end
    local a, n = ag(), ng()
    for _, mod in ipairs({ a, n }) do
        if type(mod) == "table" and type(mod.IsHarvestFavorited) == "function" then
            local ok, yes = pcall(mod.IsHarvestFavorited, mod, item)
            if ok and yes then return true end
        end
    end
    local function f(v) return v == true or v == 1 or v == "true" or v == "1" end
    return f(item.IsFavorite) or f(item.Favorite) or f(item.Favorited) or f(item.isFavorite) or f(item.d)
end

function H._expandSel(catKey, sel)
    sel = H._normSet(sel)
    if not next(sel) then return sel end
    local n = ng()
    if type(n) == "table" and type(n.NormalizeSelected) == "function" then
        local ok, out = pcall(n.NormalizeSelected, n, catKey, sel)
        if ok and type(out) == "table" and next(out) then return out end
    end
    return sel
end

function H._matchSel(item, sel)
    if not H._hasSel(sel) then return true end
    sel = H._expandSel("HarvestedFruits", sel)
    local keys = { tostring(item.uuid or ""), tostring(item.key or ""), H._strip(item.name or "") }
    if type(item.raw) == "table" then keys[#keys + 1] = tostring(item.raw.FruitName or item.raw.Fruit or "") end
    local norm = {}
    for k, v in pairs(sel) do if v then norm[H._normKey(k)] = true end end
    for _, k in ipairs(keys) do
        if k ~= "" and (sel[k] or norm[H._normKey(k)]) then return true end
    end
    return false
end

function H._bagUuid(key, entry)
    if type(entry) == "table" then
        for _, f in ipairs({ "Id", "id", "UUID", "Uuid", "FruitId", "c" }) do
            local v = entry[f]
            if v and H._isFruitId(v) then return tostring(v) end
        end
    end
    key = tostring(key or "")
    return H._isFruitId(key) and key or ""
end

function H._listHarvest(sel)
    sel = H._normSet(sel)
    local out, seen = {}, {}

    local function add(uuid, tool, entry)
        uuid = tostring(uuid or "")
        if uuid == "" or seen[uuid] then return end
        local item = { uuid = uuid, key = uuid, name = type(entry) == "table" and tostring(entry.FruitName or "") or "", raw = entry, tool = tool }
        if H._fav(item) or not H._matchSel(item, sel) then return end
        seen[uuid] = true
        out[#out + 1] = { uuid = uuid, tool = tool }
    end

    H._eachTool(function(t)
        if not H._isHarvestInst(t) then return end
        local id = t:GetAttribute("Id") or t:GetAttribute("UUID")
        if H._isFruitId(id) then add(tostring(id), t, { FruitName = t.Name }) end
    end)

    local a = ag()
    if type(a) == "table" and type(a.CollectCategoryCandidates) == "function" then
        local ok, rows = pcall(a.CollectCategoryCandidates, a, "HarvestedFruits", sel)
        if ok and type(rows) == "table" then
            for _, row in ipairs(rows) do
                local uuid = tostring(row.ItemKey or "")
                if uuid ~= "" then add(uuid, H._findTool(uuid), row.Entry) end
            end
        end
    end

    for key, entry in pairs(H._getBag(true)) do
        if tostring(key):sub(1, 1) ~= "_" then add(H._bagUuid(key, entry), H._findTool(H._bagUuid(key, entry)), entry) end
    end
    return out
end

function H._stackCount(t)
    if not t then return 1 end
    local c = t:GetAttribute("Count")
    return type(c) == "number" and math.max(1, math.floor(c)) or 1
end

function H._afterDropRequest()
    task.wait(0.02)
    H._clearChar()
end

function H._confirm(uuid, tool)
    uuid = tostring(uuid or "")
    local t0, dl = os.clock(), os.clock() + CONFIRM_MAX
    while os.clock() < dl do
        if dropCancel then return false end
        if os.clock() - t0 >= CONFIRM_MIN then
            if tool and not tool.Parent then return true end
            if uuid ~= "" and not H._findTool(uuid) then
                H._invalidateBag()
                local bag = H._getBag(true)
                if type(bag) ~= "table" or not bag[uuid] then return true end
            end
        end
        task.wait(0.02)
    end
    return false
end

function H._confirmGeneric(tool, before)
    local t0 = os.clock()
    while os.clock() - t0 < GENERIC_CONFIRM do
        if dropCancel then return false end
        if os.clock() - t0 >= CONFIRM_MIN then
            if not tool or not tool.Parent then return true end
            if H._stackCount(tool) < before then return true end
        end
        task.wait(0.02)
    end
    return (not tool or not tool.Parent) or H._stackCount(tool) < before
end

function H._dropHarvest(entry)
    if type(entry) ~= "table" then return false end
    local uuid = tostring(entry.uuid or "")
    if not H._isFruitId(uuid) then return false end

    H._clearChar()
    local tool = entry.tool
    if tool and tool.Parent and tool.Parent ~= LP.Character then
        if not H._equip(tool) then return false end
    elseif not tool or not tool.Parent then
        if not H._promote(uuid) then return false end
    end
    task.wait(EQUIP_SETTLE)

    tool = H._findTool(uuid)
    local cat, dropId = H._equippedDrop()
    if not dropId or dropId == "" then
        cat, dropId = "HarvestedFruits", H._resolveDropId(tool, uuid)
    end
    if dropId == "" or not H._requestDrop(cat or "HarvestedFruits", dropId) then
        H._clearChar()
        return false
    end
    H._afterDropRequest()
    H._invalidateBag()
    local ok = H._confirm(dropId, tool)
    if not ok then H._clearChar() end
    return ok
end

function H._delay(mul)
    local sec = (tonumber(cfg.drop_delay_sec) or 0) * (tonumber(mul) or 1)
    if sec > 0 then task.wait(sec) end
end

function H._runHarvestJob(goal, sel)
    if not H._ensureBackpackNet() then H._setStatus("Backpack not ready") return end
    H._invalidateBag()
    local entries = H._listHarvest(sel)
    if #entries == 0 then H._setStatus("No fruits") return end

    local dropped, skips, retries, idx = 0, {}, {}, 1
    H._setStatus(string.format("Dropping 0/%d", goal))

    while dropped < goal and not dropCancel do
        if H._dropHasTarget() and not H._stickNearDropTarget() then
            H._setStatus("Too far from target — stopping")
            break
        end
        if idx > #entries then
            entries = H._listHarvest(sel)
            idx = 1
            if #entries == 0 then break end
        end
        local entry = entries[idx]
        idx += 1
        if not entry or skips[entry.uuid] then continue end

        retries[entry.uuid] = (retries[entry.uuid] or 0) + 1
        if retries[entry.uuid] > RETRY_MAX then skips[entry.uuid] = true continue end

        H._setStatus(string.format("Dropping %d/%d", dropped + 1, goal))
        if H._dropHarvest(entry) then
            dropped += 1
            stats.dropped = dropped
            retries[entry.uuid] = nil
            stats._fail = 0
            H._setStatus(string.format("Dropped %d/%d", dropped, goal))
            H._delay(1)
        else
            stats._fail = (stats._fail or 0) + 1
            if stats._fail >= SKIP_MAX then break end
            H._delay(0.4)
        end
    end
    stats._fail = nil
    stats.dropped = dropped
    H._clearChar()
    if dropCancel then H._setStatus(string.format("Stopped %d/%d", dropped, goal))
    elseif dropped >= goal then H._setStatus(string.format("Done %d/%d", dropped, goal))
    else H._setStatus(string.format("Stopped %d/%d", dropped, goal)) end
end

function H._toolInfo(t)
    if not t or not t:IsA("Tool") then return nil end
    if H._isHarvestInst(t) then
        local id = H._fruitId(t)
        return { giftType = "HarvestedFruits", uuid = id, key = id, name = t.Name, tool = t }
    end
    local petId = t:GetAttribute("PetId")
    if type(petId) == "string" and petId ~= "" then return { giftType = "Pets", uuid = petId, key = petId, name = t.Name } end
    for attr, gt in pairs(GIFT_ATTR) do
        local v = t:GetAttribute(attr)
        if v ~= nil and v ~= false and tostring(v) ~= "" then
            return { giftType = gt, uuid = tostring(t:GetAttribute("Id") or v), key = tostring(v), name = tostring(v) }
        end
    end
    return nil
end

function H._matchCat(info, catKey, sel)
    if not info or H._cat(info.giftType) ~= H._cat(catKey) then return false end
    if not H._hasSel(sel) then return true end
    sel = H._expandSel(catKey, sel)
    local keys = { tostring(info.uuid or ""), tostring(info.key or ""), H._strip(info.name or "") }
    local norm = {}
    for k, v in pairs(sel) do if v then norm[H._normKey(k)] = true end end
    for _, k in ipairs(keys) do if k ~= "" and (sel[k] or norm[H._normKey(k)]) then return true end end
    return false
end

function H._findTools(catKey, sel)
    catKey = H._cat(catKey)
    sel = H._hasSel(sel) and H._expandSel(catKey, sel) or {}
    local out = {}

    if H._isPetCat(catKey) then
        local a = ag()
        if type(a) == "table" and type(a.BuildInventoryItems) == "function" then
            local canon = H._petDropCategory(catKey)
            local ok, items = pcall(a.BuildInventoryItems, a, canon)
            if ok and type(items) == "table" then
                for _, it in ipairs(items) do
                    local id = tostring(it.key or "")
                    if id == "" or id == "_none" then continue end
                    local info = {
                        giftType = "Pets",
                        uuid = id,
                        key = id,
                        name = tostring(it.name or id),
                    }
                    if not H._matchCat(info, "Pets", sel) then continue end
                    local tool = H._findPetTool(id)
                    if tool and tool.Parent then
                        out[#out + 1] = { tool = tool, info = info }
                    end
                end
                if #out > 0 then return out end
            end
        end
    end

    local n = ng()
    if type(n) == "table" and type(n.CollectCandidates) == "function" then
        pcall(n.EnsureGiftReady, n, 4)
        local ok, list = pcall(n.CollectCandidates, n, catKey, sel, true)
        if ok and type(list) == "table" then
            for _, item in ipairs(list) do
                local t = item.tool or item.inst
                if t and t.Parent then out[#out + 1] = { tool = t, info = item } end
            end
            if #out > 0 then return out end
        end
    end
    H._eachTool(function(t)
        local info = H._toolInfo(t)
        if H._matchCat(info, catKey, sel) then out[#out + 1] = { tool = t, info = info } end
    end)
    return out
end

function H._dropGeneric(slot)
    local tool = slot and slot.tool
    if not tool or not tool.Parent then return false end
    H._clearChar()
    if not H._equip(tool) then return false end
    local cat, id = H._equippedDrop()
    if not cat or not id then H._clearChar() return false end
    local before = H._stackCount(tool)
    if not H._requestDrop(cat, id) then H._clearChar() return false end
    H._afterDropRequest()
    local ok = H._confirmGeneric(tool, before)
    if not ok then H._clearChar() end
    return ok
end

function H._runGenericJob(goal, catKey, sel)
    H._setStatus(string.format("Dropping 0/%d", goal))
    local dropped, fails = 0, 0
    if #H._findTools(catKey, sel) == 0 then H._setStatus("No items") return end

    while dropped < goal and not dropCancel do
        if H._dropHasTarget() and not H._stickNearDropTarget() then
            H._setStatus("Too far from target — stopping")
            break
        end
        local tools = H._findTools(catKey, sel)
        if #tools == 0 then break end
        H._setStatus(string.format("Dropping %d/%d", dropped + 1, goal))
        if H._dropGeneric(tools[1]) then
            dropped += 1
            stats.dropped = dropped
            fails = 0
            H._setStatus(string.format("Dropped %d/%d", dropped, goal))
            H._delay(1)
        else
            fails += 1
            if fails >= FAIL_MAX then break end
            H._clearChar()
            H._delay(0.25)
        end
    end
    H._clearChar()
    stats.dropped = dropped
    H._setStatus(dropped >= goal and string.format("Done %d/%d", dropped, goal) or string.format("Stopped %d/%d", dropped, goal))
end

function H._finish()
    H._teleResumeNow()
    H._clearChar()
    dropBusy = false
    dropCancel = false
    local dd = G.__GAG2_AUTO_DROP_ITEM_DD or rawget(_G, "__GAG2_AUTO_DROP_ITEM_DD")
    if type(dd) == "table" and type(dd.refreshItems) == "function" then pcall(dd.refreshItems, dd) end
    local done = G.__GAG2_AUTO_DROP_DONE or rawget(_G, "__GAG2_AUTO_DROP_DONE")
    if type(done) == "function" then pcall(done, stats.dropped > 0) end
end

function M.ForceReset() dropCancel, dropBusy = true, false H._invalidateBag() end

function M.WaitUntilIdle(timeout)
    local dl = os.clock() + (tonumber(timeout) or 3)
    while dropBusy and os.clock() < dl do task.wait(0.03) end
    return not dropBusy
end

function M.Stop()
    dropCancel = true
    if dropBusy then H._setStatus("Stopping...") end
end

function M.IsBusy() return dropBusy end

function M.GetStats()
    return { busy = dropBusy, lastStatus = stats.lastStatus,
        dropped = stats.dropped, goal = stats.goal }
end

function H._distanceToPlayer(target)
    local char = LP.Character
    local tchar = target and target.Character
    if not char or not tchar then return math.huge end
    local hrp = char:FindFirstChild("HumanoidRootPart")
    local thrp = tchar:FindFirstChild("HumanoidRootPart")
    if not hrp or not thrp then return math.huge end
    return (hrp.Position - thrp.Position).Magnitude
end

function H._resolveTarget()
    local uid = math.floor(tonumber(cfg.target_user_id) or 0)
    if uid > 0 then
        local p = Players:GetPlayerByUserId(uid)
        if p and p ~= LP then return p end
    end
    local name = tostring(cfg.target_name or ""):gsub("^%s+", ""):gsub("%s+$", "")
    if name ~= "" then
        local lower = name:lower():gsub("^@", "")
        for _, p in ipairs(Players:GetPlayers()) do
            if p ~= LP then
                local label = p.DisplayName .. " (@" .. p.Name .. ")"
                if p.Name:lower() == lower or p.DisplayName:lower() == lower
                    or label:lower() == lower or label:lower():find(lower, 1, true) then
                    return p
                end
            end
        end
    end
    return nil
end

function H._teleport(cf)
    if typeof(cf) ~= "CFrame" then return false end
    local char = LP.Character
    local hrp = char and char:FindFirstChild("HumanoidRootPart")
    if not char or not hrp then return false end
    local ok = pcall(function()
        if char.PrimaryPart then char:PivotTo(cf) else hrp.CFrame = cf end
    end)
    if ok then task.wait(AFTER_TP_SEC) end
    return ok
end

function H._teleportNearTarget(target)
    local tchar = target and target.Character
    local thrp = tchar and tchar:FindFirstChild("HumanoidRootPart")
    if not thrp then return false end
    local char = LP.Character
    local hrp = char and char:FindFirstChild("HumanoidRootPart")
    if not hrp then return false end
    local toUs = hrp.Position - thrp.Position
    local dir = toUs.Magnitude > 1 and toUs.Unit or -thrp.CFrame.LookVector
    local flat = Vector3.new(dir.X, 0, dir.Z)
    if flat.Magnitude < 0.05 then flat = Vector3.new(0, 0, -1) else flat = flat.Unit end
    local pos = thrp.Position + flat * TP_STAND_DIST + Vector3.new(0, TP_Y_OFFSET, 0)
    return H._teleport(CFrame.new(pos, thrp.Position))
end

local function _getAutoTeleMod()
    return G.AutoTele or rawget(_G, "AutoTele")
end

function H._teleIsOn()
    local mod = _getAutoTeleMod()
    if type(mod) == "table" and type(mod.IsEnabled) == "function" then
        return mod.IsEnabled() == true
    end
    local s = rawget(_G, "__GAG2_AUTO_TELE") or G.__GAG2_AUTO_TELE
    if type(s) == "table" then return s.enabled == true end
    return G.AUTO_TELE_ENABLED == true or rawget(_G, "AUTO_TELE_ENABLED") == true
end

function H._teleWasRunning()
    local mod = _getAutoTeleMod()
    if type(mod) == "table" and type(mod.IsRunning) == "function" then
        return mod.IsRunning() == true
    end
    return false
end

function H._dropHasTarget()
    local uid = math.floor(tonumber(cfg.target_user_id) or 0)
    local name = tostring(cfg.target_name or ""):gsub("^%s+", ""):gsub("%s+$", "")
    return uid > 0 or name ~= ""
end

function H._isNearDropTarget(target)
    return target and H._distanceToPlayer(target) <= DROP_NEAR_DIST
end

function H._teleportNearTargetOnce(target)
    local n = ng()
    if type(n) == "table" and type(n.TeleportToTarget) == "function" then
        if select(1, n.TeleportToTarget(n, target)) then return true end
    end
    return H._teleportNearTarget(target)
end

function H._needsDropTeleport()
    return H._dropHasTarget() and cfg.teleport_to_target == true
end

function H._beginDropNearTargetSession()
    if not H._needsDropTeleport() then return end
    dropNearTargetActive = true
    teleWasOn = H._teleIsOn() == true
    dropTelePaused = teleWasOn
    G.__GAG2_AUTO_TELE_SUPPRESS = true
    rawset(_G, "__GAG2_AUTO_TELE_SUPPRESS", true)
    local mod = _getAutoTeleMod()
    if type(mod) == "table" and type(mod.Stop) == "function" then
        pcall(mod.Stop, mod)
    end
end

function H._teleKeepPaused()
    if not dropNearTargetActive then return end
    G.__GAG2_AUTO_TELE_SUPPRESS = true
    rawset(_G, "__GAG2_AUTO_TELE_SUPPRESS", true)
    local mod = _getAutoTeleMod()
    if type(mod) == "table" and type(mod.IsRunning) == "function" and type(mod.Stop) == "function" then
        if mod:IsRunning() then pcall(mod.Stop, mod) end
    end
end

function H._teleStopForDrop()
    H._beginDropNearTargetSession()
end

function H._teleResumeNow()
    if not dropNearTargetActive and not dropTelePaused then return end
    local resume = teleWasOn == true
    dropNearTargetActive = false
    dropTelePaused = false
    teleWasOn = false
    G.__GAG2_AUTO_TELE_SUPPRESS = false
    rawset(_G, "__GAG2_AUTO_TELE_SUPPRESS", false)
    if not resume then return end
    local mod = _getAutoTeleMod()
    if type(mod) == "table" and type(mod.IsEnabled) == "function" and mod.IsEnabled() then
        if type(mod.Start) == "function" then
            pcall(mod.Start, mod)
        elseif type(mod.EnsureRunning) == "function" then
            pcall(mod.EnsureRunning, mod)
        end
    end
end

function H._retryTeleportNearTarget(target, maxAttempts, statusPrefix)
    maxAttempts = math.max(1, math.floor(tonumber(maxAttempts) or TP_MAX_ATTEMPTS))
    statusPrefix = tostring(statusPrefix or "Teleporting near")
    for attempt = 1, maxAttempts do
        if dropCancel then return false end
        H._teleKeepPaused()
        H._setStatus(string.format("%s %s (%d/%d)...", statusPrefix, target.Name, attempt, maxAttempts))
        H._teleportNearTargetOnce(target)
        task.wait(TP_RETRY_WAIT)
        if H._isNearDropTarget(target) then
            H._setStatus(string.format("Near %s (%.0f studs)", target.Name, H._distanceToPlayer(target)))
            return true
        end
    end
    return false
end

function H._stickNearDropTarget()
    if not H._dropHasTarget() then return true end
    if cfg.teleport_to_target ~= true then return true end
    H._teleKeepPaused()
    local target = H._resolveTarget()
    if not target then
        H._setStatus("Target player not in server")
        return false
    end
    if H._isNearDropTarget(target) then return true end
    return H._retryTeleportNearTarget(target, TP_STICK_ATTEMPTS, "Returning near")
end

function H._ensureNearDropTarget()
    local uid = math.floor(tonumber(cfg.target_user_id) or 0)
    local name = tostring(cfg.target_name or ""):gsub("^%s+", ""):gsub("%s+$", "")
    if uid <= 0 and name == "" then return true end
    if cfg.teleport_to_target ~= true then return true end

    local target = H._resolveTarget()
    if not target then
        H._setStatus("Target player not in server")
        return false
    end
    if H._isNearDropTarget(target) then
        H._setStatus(string.format("Near %s", target.Name))
        return true
    end
    if H._retryTeleportNearTarget(target, TP_MAX_ATTEMPTS, "Teleporting near") then
        return true
    end
    H._setStatus(string.format("Too far (%.0f studs) — teleport failed", H._distanceToPlayer(target)))
    return false
end

function M.TeleportToTarget(targetOrKey)
    local target = targetOrKey
    if typeof(targetOrKey) ~= "Instance" or not targetOrKey:IsA("Player") then
        target = H._resolveTarget()
    end
    if not target then H._setStatus("Select a player in this server") return false, "no_target" end
    local n = ng()
    if type(n) == "table" and type(n.TeleportToTarget) == "function" then
        local ok = select(1, n.TeleportToTarget(n, target))
        if ok then H._setStatus(string.format("Teleported near %s", target.Name)) return true end
    end
    if H._teleportNearTarget(target) then
        H._setStatus(string.format("Teleported near %s", target.Name))
        return true
    end
    H._setStatus("Teleport failed")
    return false, "tp_fail"
end

function M.ApplyConfig(a, b)
    local p = type(b) == "table" and b or type(a) == "table" and a
    if not p then return end
    if p.category then cfg.category = H._cat(p.category) end
    if type(p.selected) == "table" then cfg.selected = H._normSet(p.selected) end
    if p.drop_total then cfg.drop_total = math.max(1, math.floor(tonumber(p.drop_total) or 1)) end
    if p.drop_delay_sec ~= nil then
        cfg.drop_delay_sec = math.clamp(tonumber(p.drop_delay_sec) or 0, 0, 30)
    end
    if p.target_user_id ~= nil then cfg.target_user_id = math.floor(tonumber(p.target_user_id) or 0) end
    if p.target_name ~= nil then cfg.target_name = tostring(p.target_name or "") end
    if p.teleport_to_target ~= nil then cfg.teleport_to_target = (p.teleport_to_target == true) end
end

function M.SyncFromGlobals()
    local s = G.__GAG2_AUTO_DROP or rawget(_G, "__GAG2_AUTO_DROP")
    if type(s) == "table" then M.ApplyConfig(s) end
    local main = G.MAIN or rawget(_G, "MAIN")
    if type(main) == "table" and type(main.auto) == "table" and type(main.auto.dropItem) == "table" then
        M.ApplyConfig(main.auto.dropItem)
    end
end

function M.PrepHarvest() H._invalidateBag() H._getBag(true) end

function M.GetHarvestItemLabels()
    H._invalidateBag()
    local a = ag()
    if type(a) == "table" and type(a.BuildInventoryItems) == "function" then
        local ok, items = pcall(a.BuildInventoryItems, a, "HarvestedFruits")
        if ok and type(items) == "table" and #items > 0 then
            local out = {}
            for _, it in ipairs(items) do out[#out + 1] = { key = it.key, name = it.name, giftType = "HarvestedFruits", count = it.count } end
            table.sort(out, function(x, y) return tostring(x.name) < tostring(y.name) end)
            return out
        end
    end
    local grouped, out = {}, {}
    for uuid, entry in pairs(H._getBag(false)) do
        if tostring(uuid):sub(1, 1) == "_" or H._fav(entry) then continue end
        local label = type(entry) == "table" and tostring(entry.FruitName or "") or "Fruit"
        if label == "" then label = "Fruit" end
        grouped[label] = (grouped[label] or 0) + 1
    end
    for label, count in pairs(grouped) do
        out[#out + 1] = { key = label, name = count > 1 and string.format("%s x %d", label, count) or label, giftType = "HarvestedFruits", count = count }
    end
    table.sort(out, function(x, y) return tostring(x.name) < tostring(y.name) end)
    return out
end

function M.GetPetItemLabels()
    local a = ag()
    if type(a) ~= "table" or type(a.BuildInventoryItems) ~= "function" then return {} end
    local ok, items = pcall(a.BuildInventoryItems, a, "Pets")
    if ok and type(items) == "table" then return items end
    return {}
end

function M.RunNow(a, b)
    if dropBusy then
        M.Stop()
        M.WaitUntilIdle(2)
        if dropBusy then M.ForceReset() end
    end
    local patch = type(b) == "table" and b or type(a) == "table" and b == nil and a
    if patch then M.ApplyConfig(patch) else M.SyncFromGlobals() end

    local catKey = H._cat(cfg.category)
    local sel = H._expandSel(catKey, cfg.selected)
    local goal = math.max(1, math.floor(tonumber(cfg.drop_total) or 1))
    if not H._ensureDropRemote() then H._setStatus("Remote not ready") return false, "remote" end
    if H._isHarvest(catKey) and not H._ensureBackpackNet() then H._setStatus("Backpack not ready") return false end

    dropBusy, dropCancel = true, false
    stats.dropped, stats.goal = 0, goal
    task.spawn(function()
        local ok, err = pcall(function()
            H._beginDropNearTargetSession()
            if not H._ensureNearDropTarget() then return end
            if H._isHarvest(catKey) then H._runHarvestJob(goal, sel) else H._runGenericJob(goal, catKey, sel) end
        end)
        if not ok then H._setStatus("Error") end
        H._finish()
    end)
    return true, "started"
end

function M.DebugDropOne()
    if not H._ensureDropRemote() then return false end
    local t
    H._eachTool(function(x) if not t and H._isHarvestInst(x) then t = x end end)
    return t and H._dropHarvest({ uuid = H._fruitId(t), tool = t })
end

function M.DebugDropHarvest(count, delaySec)
    count = math.max(1, math.floor(tonumber(count) or 5))
    delaySec = math.max(0.05, tonumber(delaySec) or 0.3)
    if not H._ensureDropRemote() or not H._ensureBackpackNet() then return 0 end
    local entries = H._listHarvest({})
    local n, goal = 0, math.min(count, #entries)
    for i = 1, goal do
        if H._dropHarvest(entries[i]) then n += 1 end
        entries = H._listHarvest({})
        task.wait(delaySec)
    end
    return n
end

G.AutoDropModule, G.AutoDrop = M, M
rawset(_G, "AutoDropModule", M)
rawset(_G, "AutoDrop", M)

return M
 end,                       required = false },
    { key = "SectionAutoDrop",         name = "Section Auto Drop",       factory = function() -- section_auto_drop.lua — Drop Item UI (Gift / Drop tab)

local G = (getgenv and getgenv()) or _G
local M = {}

local saveNow, patchAutoOnly, getAutoFn, cleanSelectedMap, mapToArray, arrayToMap, registerFlush

function M.initBridge(bridge)
    if type(bridge) ~= "table" then return end
    saveNow = bridge.saveNow
    patchAutoOnly = bridge.patchAutoOnly
    getAutoFn = bridge.getAuto
    cleanSelectedMap = bridge.cleanSelectedMap
    mapToArray = bridge.mapToArray
    arrayToMap = bridge.arrayToMap
    registerFlush = bridge.registerFlush
end

local function _ensureBridge()
    if type(saveNow) ~= "function" or type(cleanSelectedMap) ~= "function" then
        error("SectionAutoDrop.initBridge belum dipanggil dari tabs_auto.lua")
    end
end

local function getAuto(key)
    if type(getAutoFn) == "function" then return getAutoFn(key) end
    local main = G.MAIN or rawget(_G, "MAIN")
    return type(main) == "table" and type(main.auto) == "table" and main.auto[key] or nil
end

local function _arrayToMap(arr)
    if type(arrayToMap) == "function" then return arrayToMap(arr) end
    local m = {}
    if type(arr) == "table" then
        for _, v in ipairs(arr) do
            if v ~= nil and tostring(v) ~= "" then m[tostring(v)] = true end
        end
        if next(m) then return m end
        for k, v in pairs(arr) do
            if v == true or v == 1 or v == "true" then m[tostring(k)] = true end
        end
    end
    return m
end

if type(G.__GAG2_AUTO_DROP) ~= "table" then
    G.__GAG2_AUTO_DROP = {
        category = "Seeds", selected = {}, drop_total = 1, drop_delay_sec = 1,
        target_user_id = 0, target_name = "", teleport_to_target = true,
    }
end
_G.__GAG2_AUTO_DROP = G.__GAG2_AUTO_DROP

local ensureDropStore

local function getNormalGift()
    return G.NormalGiftModule or G.NormalGift or _G.NormalGiftModule or _G.NormalGift
end

local function getAutoDrop()
    return G.AutoDropModule or G.AutoDrop or _G.AutoDropModule or _G.AutoDrop
end

local function safeDdGetSelected(api)
    if type(api) ~= "table" or type(api.getSelected) ~= "function" then return nil end
    local ok, sel = pcall(api.getSelected, api)
    if ok then return sel end
    ok, sel = pcall(api.getSelected)
    if ok then return sel end
    return nil
end

local function normalizeSelected(map)
    local out = cleanSelectedMap(map or {})
    if next(out) then return out end
    if type(map) ~= "table" then return out end
    for k, v in pairs(map) do
        if v == true or v == 1 or v == "true" or v == "1" then
            out[tostring(k)] = true
        end
    end
    for _, v in ipairs(map) do
        if v ~= nil and tostring(v) ~= "" then
            out[tostring(v)] = true
        end
    end
    return out
end

local function countSelected(map)
    map = normalizeSelected(map or {})
    local n = 0
    for k, v in pairs(map) do
        if v == true and k ~= "_none" then n += 1 end
    end
    return n
end

local function isHarvestCat(cat)
    cat = tostring(cat or ""):lower():gsub("[%s_]+", "")
    return cat == "harvestedfruits" or cat == "harvestedfruit" or cat == "harvestedfruid"
end

local function isPetDropCat(cat)
    cat = tostring(cat or ""):lower():gsub("[%s_]+", "")
    return cat == "pets" or cat == "birds" or cat == "tools"
end

local function readDropCategory()
    local catDd = G.__GAG2_AUTO_DROP_CAT_DD or rawget(_G, "__GAG2_AUTO_DROP_CAT_DD")
    if type(catDd) == "table" and type(catDd.getSelected) == "function" then
        local ok, sel = pcall(catDd.getSelected, catDd)
        if not ok then ok, sel = pcall(catDd.getSelected) end
        if ok and sel ~= nil and tostring(sel) ~= "" and tostring(sel) ~= "_none" then
            G.__GAG2_AUTO_DROP_ACTIVE_CAT = tostring(sel)
            _G.__GAG2_AUTO_DROP_ACTIVE_CAT = G.__GAG2_AUTO_DROP_ACTIVE_CAT
            return tostring(sel)
        end
    end
    local active = G.__GAG2_AUTO_DROP_ACTIVE_CAT or rawget(_G, "__GAG2_AUTO_DROP_ACTIVE_CAT")
    if active ~= nil and tostring(active) ~= "" and tostring(active) ~= "_none" then
        return tostring(active)
    end
    return tostring(ensureDropStore().category or "Seeds")
end

local function buildDropItemList(cat)
    cat = tostring(cat or readDropCategory() or "Seeds")
    if cat == "" or cat == "_none" then return {} end
    local ng = getNormalGift()
    if type(ng) == "table" and type(ng.GetItemsForCategory) == "function" then
        local ok, list = pcall(ng.GetItemsForCategory, ng, cat)
        if ok and type(list) == "table" and #list > 0 then
            return list
        end
    end
    if isHarvestCat(cat) then
        local ad = getAutoDrop()
        if type(ad) == "table" and type(ad.GetHarvestItemLabels) == "function" then
            local ok, list = pcall(ad.GetHarvestItemLabels, ad)
            if ok and type(list) == "table" then return list end
        end
    end
    if isPetDropCat(cat) then
        local ad = getAutoDrop()
        if type(ad) == "table" and type(ad.GetPetItemLabels) == "function" then
            local ok, list = pcall(ad.GetPetItemLabels, ad)
            if ok and type(list) == "table" then return list end
        end
        local ag = G.AutoGiftModule or G.AutoGift or rawget(_G, "AutoGiftModule") or rawget(_G, "AutoGift")
        if type(ag) == "table" and type(ag.BuildInventoryItems) == "function" then
            local canon = (tostring(cat):lower() == "tools") and "Pets" or cat
            local ok, list = pcall(ag.BuildInventoryItems, ag, canon)
            if ok and type(list) == "table" then return list end
        end
    end
    if type(ng) == "table" and type(ng.GetItemsForCategory) == "function" then
        local ok, list = pcall(ng.GetItemsForCategory, ng, cat)
        if ok and type(list) == "table" then return list end
    end
    return {}
end

local function resolveDropSelection(itemDd, cat)
    local store = ensureDropStore()
    local sel = normalizeSelected(store.selected)

    if type(itemDd) == "table" and type(itemDd.getSelected) == "function" then
        local raw = safeDdGetSelected(itemDd)
        if type(raw) == "table" then
            local fromUi = normalizeSelected(raw)
            if countSelected(fromUi) > 0 then
                sel = fromUi
            end
        elseif raw ~= nil and tostring(raw) ~= "" then
            sel = { [tostring(raw)] = true }
        end
    end

    local mainDrop = getAuto("dropItem")
    if countSelected(sel) < 1 and type(mainDrop) == "table" and type(mainDrop.selected) == "table" then
        local fromMain = normalizeSelected(_arrayToMap(mainDrop.selected))
        if countSelected(fromMain) > 0 then
            sel = fromMain
        end
    end

    return sel
end

local function resolveDropTarget(key)
    key = tostring(key or ""):gsub("^%s+", ""):gsub("%s+$", "")
    if key == "" then return 0, "", nil end

    local PlayersSvc = game:GetService("Players")
    local uid = math.floor(tonumber(key) or 0)
    if uid > 0 then
        local p = PlayersSvc:GetPlayerByUserId(uid)
        if p and p ~= PlayersSvc.LocalPlayer then
            return p.UserId, p.Name, p
        end
    end

    local lower = key:lower():gsub("^@", "")
    for _, p in ipairs(PlayersSvc:GetPlayers()) do
        if p ~= PlayersSvc.LocalPlayer then
            local label = p.DisplayName .. " (@" .. p.Name .. ")"
            if p.Name:lower() == lower
                or p.DisplayName:lower() == lower
                or label:lower() == lower
                or label:lower():find(lower, 1, true)
                or lower:find(p.Name:lower(), 1, true) then
                return p.UserId, p.Name, p
            end
        end
    end

    local ng = getNormalGift()
    if type(ng) == "table" and type(ng.ListServerPlayers) == "function" then
        local ok, list = pcall(ng.ListServerPlayers, ng)
        if ok and type(list) == "table" then
            for _, item in ipairs(list) do
                local itemKey = tostring(item.key or "")
                if itemKey == key or itemKey:lower() == lower then
                    local pid = math.floor(tonumber(item.userId or itemKey) or 0)
                    if pid > 0 then
                        local p = PlayersSvc:GetPlayerByUserId(pid)
                        if p then return p.UserId, p.Name, p end
                    end
                end
                local itemName = tostring(item.name or ""):lower()
                if itemName == lower or itemName:find(lower, 1, true) then
                    local pid = math.floor(tonumber(item.userId or item.key) or 0)
                    if pid > 0 then
                        local p = PlayersSvc:GetPlayerByUserId(pid)
                        if p then return p.UserId, p.Name, p end
                    end
                end
            end
        end
    end

    return 0, "", nil
end

local function buildDropPlayerItems()
    local ng = getNormalGift()
    if type(ng) == "table" and type(ng.ListServerPlayers) == "function" then
        local ok, list = pcall(ng.ListServerPlayers, ng)
        if ok and type(list) == "table" then return list end
    end
    return {}
end

local function readDropTeleportToggle()
    local api = G.__GAG2_AUTO_DROP_TP_TOGGLE_API or rawget(_G, "__GAG2_AUTO_DROP_TP_TOGGLE_API")
    if type(api) == "table" and type(api.get) == "function" then
        local ok, v = pcall(api.get, api)
        if ok and v ~= nil then return v == true end
    end
    return nil
end

local function applyDropRuntime()
    local ad = getAutoDrop()
    local s = ensureDropStore()
    if type(ad) == "table" and type(ad.ApplyConfig) == "function" then
        pcall(ad.ApplyConfig, ad, s)
    end
end

ensureDropStore = function()
    local s = G.__GAG2_AUTO_DROP
    if type(s) ~= "table" then
        s = {
            category = "Seeds", selected = {}, drop_total = 1, drop_delay_sec = 1,
            target_user_id = 0, target_name = "", teleport_to_target = true,
        }
    end
    s.category = tostring(s.category or "Seeds")
    if s.category == "" then s.category = "Seeds" end
    s.selected = normalizeSelected(s.selected or {})
    s.drop_total = math.max(1, math.floor(tonumber(s.drop_total) or 1))
    local delay = tonumber(s.drop_delay_sec) or 1
    if delay < 0 then delay = 0 end
    if delay > 30 then delay = 30 end
    s.drop_delay_sec = delay
    s.target_user_id = math.floor(tonumber(s.target_user_id) or 0)
    s.target_name = tostring(s.target_name or "")
    if s.teleport_to_target == nil then s.teleport_to_target = true end
    s.teleport_to_target = (s.teleport_to_target == true)

    if not s._hydrated then
        local mainDrop = getAuto("dropItem")
        if type(mainDrop) == "table" then
            if mainDrop.category ~= nil and tostring(mainDrop.category) ~= "" then
                s.category = tostring(mainDrop.category)
            end
            if type(mainDrop.selected) == "table" and next(mainDrop.selected) then
                s.selected = normalizeSelected(_arrayToMap(mainDrop.selected))
            end
            if mainDrop.drop_total ~= nil then
                s.drop_total = math.max(1, math.floor(tonumber(mainDrop.drop_total) or 1))
            end
            if mainDrop.drop_delay_sec ~= nil then
                s.drop_delay_sec = tonumber(mainDrop.drop_delay_sec) or 1
            end
            if mainDrop.target_user_id ~= nil then
                s.target_user_id = math.floor(tonumber(mainDrop.target_user_id) or 0)
            end
            if mainDrop.target_name ~= nil then
                s.target_name = tostring(mainDrop.target_name or "")
            end
            if mainDrop.teleport_to_target ~= nil then
                s.teleport_to_target = (mainDrop.teleport_to_target == true)
            end
        end
        s._hydrated = true
    end

    G.__GAG2_AUTO_DROP = s
    _G.__GAG2_AUTO_DROP = s
    return s
end
G.__GAG2_ENSURE_AUTO_DROP_STORE = ensureDropStore
_G.__GAG2_ENSURE_AUTO_DROP_STORE = ensureDropStore

local function writeDropToMain()
    local s = ensureDropStore()
    patchAutoOnly("dropItem", {
        category = s.category,
        selected = mapToArray(s.selected),
        drop_total = s.drop_total,
        drop_delay_sec = s.drop_delay_sec,
        target_user_id = s.target_user_id,
        target_name = s.target_name,
        teleport_to_target = s.teleport_to_target,
    })
    return s
end

local function writeDropState(opts)
    local s = ensureDropStore()
    if type(opts) == "table" then
        if opts.category ~= nil and tostring(opts.category) ~= "" then
            s.category = tostring(opts.category)
        end
        if type(opts.selected) == "table" then
            if opts.selected[1] ~= nil then
                s.selected = normalizeSelected(_arrayToMap(opts.selected))
            else
                s.selected = normalizeSelected(opts.selected)
            end
        end
        if opts.drop_total ~= nil then
            s.drop_total = math.max(1, math.floor(tonumber(opts.drop_total) or 1))
        end
        if opts.drop_delay_sec ~= nil then
            local d = tonumber(opts.drop_delay_sec) or 1
            if d < 0 then d = 0 end
            if d > 30 then d = 30 end
            s.drop_delay_sec = d
        end
        if opts.target_user_id ~= nil then
            s.target_user_id = math.floor(tonumber(opts.target_user_id) or 0)
        end
        if opts.target_name ~= nil then
            s.target_name = tostring(opts.target_name or "")
        end
        if opts.teleport_to_target ~= nil then
            s.teleport_to_target = (opts.teleport_to_target == true)
        end
    end
    G.__GAG2_AUTO_DROP = s
    _G.__GAG2_AUTO_DROP = s
    return writeDropToMain()
end

local function patchDrop(opts, syncFn)
    writeDropState(opts)
    if syncFn then pcall(syncFn) end
    saveNow()
end

local function flushDropFromUI()
    if G.__GAG2_RESETTING == true then return end
    local opts = {}
    local cat = readDropCategory()
    if cat ~= "" and cat ~= "_none" then opts.category = cat end

    local itemDd = G.__GAG2_AUTO_DROP_ITEM_DD or rawget(_G, "__GAG2_AUTO_DROP_ITEM_DD")
    local sel = resolveDropSelection(itemDd, cat)
    if countSelected(sel) > 0 then opts.selected = sel end

    local totalFn = G.__GAG2_AUTO_DROP_TOTAL or rawget(_G, "__GAG2_AUTO_DROP_TOTAL")
    if type(totalFn) == "function" then
        local n = tonumber(totalFn())
        if n and n >= 1 then opts.drop_total = math.floor(n) end
    end

    local delayFn = G.__GAG2_AUTO_DROP_DELAY or rawget(_G, "__GAG2_AUTO_DROP_DELAY")
    if type(delayFn) == "function" then
        local d = tonumber(delayFn())
        if d ~= nil and d >= 0 then opts.drop_delay_sec = d end
    end

    local playerDd = G.__GAG2_AUTO_DROP_PLAYER_DD or rawget(_G, "__GAG2_AUTO_DROP_PLAYER_DD")
    local playerKey = safeDdGetSelected(playerDd)
    if playerKey ~= nil and tostring(playerKey) ~= "" then
        local uid, name = resolveDropTarget(playerKey)
        if uid > 0 then opts.target_user_id = uid end
        if name ~= "" then opts.target_name = name end
    end

    local tpOn = readDropTeleportToggle()
    if tpOn ~= nil then opts.teleport_to_target = tpOn end

    if next(opts) ~= nil then writeDropState(opts) else writeDropToMain() end
    applyDropRuntime()
end

local function runDropNow(isOn)
    local toggleApi = G.__GAG2_AUTO_DROP_TOGGLE_API or rawget(_G, "__GAG2_AUTO_DROP_TOGGLE_API")
    local ad = getAutoDrop()
    if isOn == false then
        if type(ad) == "table" and type(ad.Stop) == "function" then pcall(ad.Stop, ad) end
        return
    end

    local cat = readDropCategory()
    flushDropFromUI()
    local s = ensureDropStore()
    local itemDd = G.__GAG2_AUTO_DROP_ITEM_DD or rawget(_G, "__GAG2_AUTO_DROP_ITEM_DD")

    if isHarvestCat(cat) then
        if type(ad) == "table" and type(ad.PrepHarvest) == "function" then
            pcall(ad.PrepHarvest, ad, true)
        else
            local ng = getNormalGift()
            if type(ng) == "table" and type(ng.CollectCandidates) == "function" then
                pcall(ng.CollectCandidates, ng, "HarvestedFruits", {}, true)
            end
        end
    end
    if type(itemDd) == "table" and type(itemDd.refreshItems) == "function" then
        pcall(itemDd.refreshItems, itemDd)
    end

    local selMap = resolveDropSelection(itemDd, cat)

    if type(ad) ~= "table" or type(ad.RunNow) ~= "function" then
        G.AUTO_DROP_STATUS = "AutoDrop module not loaded"
        _G.AUTO_DROP_STATUS = G.AUTO_DROP_STATUS
        if type(toggleApi) == "table" and type(toggleApi.set) == "function" then
            pcall(toggleApi.set, false, true)
        end
        return
    end

    task.spawn(function()
        if type(ad.IsBusy) == "function" and ad:IsBusy() then
            if type(ad.Stop) == "function" then pcall(ad.Stop, ad) end
            if type(ad.WaitUntilIdle) == "function" then
                pcall(ad.WaitUntilIdle, ad, 3)
            end
            if ad:IsBusy() and type(ad.ForceReset) == "function" then
                pcall(ad.ForceReset, ad)
            end
        end

        local runCfg = {
            category = cat,
            selected = selMap,
            drop_total = s.drop_total,
            drop_delay_sec = s.drop_delay_sec,
            target_user_id = s.target_user_id,
            target_name = s.target_name,
            teleport_to_target = s.teleport_to_target,
        }

        local ok, err = pcall(function()
            local started, reason = ad:RunNow(runCfg)
            if started == true then
                writeDropToMain()
                saveNow()
                return
            end
            if reason == "busy" and type(ad.ForceReset) == "function" then
                pcall(ad.ForceReset, ad)
                started = ad:RunNow(runCfg)
                if started == true then
                    writeDropToMain()
                    saveNow()
                    return
                end
            end
            local msg = "Drop failed"
            if reason == "busy" then
                msg = "Drop busy — try again"
            elseif reason == "remote" then
                msg = "DroppedItem remote not ready"
            end
            if type(ad.GetStats) == "function" then
                local okSt, st = pcall(ad.GetStats, ad)
                if okSt and type(st) == "table" and st.lastStatus and st.lastStatus ~= "" then
                    msg = tostring(st.lastStatus)
                end
            end
            G.AUTO_DROP_STATUS = msg
            _G.AUTO_DROP_STATUS = G.AUTO_DROP_STATUS
            if type(toggleApi) == "table" and type(toggleApi.set) == "function" then
                pcall(toggleApi.set, false, true)
            end
        end)
        if not ok then
            G.AUTO_DROP_STATUS = "Drop error: " .. tostring(err)
            _G.AUTO_DROP_STATUS = G.AUTO_DROP_STATUS
            if type(ad.ForceReset) == "function" then pcall(ad.ForceReset, ad) end
            if type(toggleApi) == "table" and type(toggleApi.set) == "function" then
                pcall(toggleApi.set, false, true)
            end
        end
    end)
end

local function syncDropAll()
    if G.__GAG2_RESETTING == true then
        writeDropToMain()
        return
    end
    if G.__GAG2_AUTO_DROP_UI_READY == true then
        flushDropFromUI()
    else
        writeDropToMain()
        applyDropRuntime()
    end
end

G.__GAG2_SYNC_AUTO_DROP = syncDropAll
G.__GAG2_FLUSH_AUTO_DROP = flushDropFromUI
_G.__GAG2_SYNC_AUTO_DROP = syncDropAll
_G.__GAG2_FLUSH_AUTO_DROP = flushDropFromUI

function M.initStore()
    _ensureBridge()
    registerFlush("dropItem", flushDropFromUI)
    ensureDropStore()
end

function M.RegisterSubTab(ui)
    if type(ui) ~= "table" then return end
    _ensureBridge()

    G.__GAG2_AUTO_DROP_UI_READY = false
    _G.__GAG2_AUTO_DROP_UI_READY = false

    local DROP = ensureDropStore()
    local bodyDrop = ui:CreateSection("Drop Item", false)

    local _, dropStatusLabel = ui:CreateRowLabel(bodyDrop, "Status: Ready", nil, nil, "info")
    task.spawn(function()
        while dropStatusLabel and dropStatusLabel.Parent do
            pcall(function()
                local txt = "Ready"
                local ad = getAutoDrop()
                if type(ad) == "table" and type(ad.GetStats) == "function" then
                    local okSt, st = pcall(ad.GetStats, ad)
                    if okSt and type(st) == "table" then
                        if st.busy and st.lastStatus and st.lastStatus ~= "" then
                            txt = st.lastStatus
                        elseif not st.busy then
                            local g = tostring(G.AUTO_DROP_STATUS or rawget(_G, "AUTO_DROP_STATUS") or "")
                            if g ~= "" and g ~= "Ready" then txt = g
                            elseif st.lastStatus and st.lastStatus ~= "" and st.lastStatus ~= "Ready" then
                                txt = st.lastStatus
                            end
                        end
                    end
                end
                dropStatusLabel.Text = "Status: " .. txt
            end)
            task.wait(0.4)
        end
    end)

    local dropPlayerInitial = (DROP.target_user_id > 0) and tostring(DROP.target_user_id) or nil
    local _, dropPlayerDd = ui:CreateRowDropdown(bodyDrop, {
        label = "Player",
        placeholder = "Select player in server...",
        mode = "single",
        getItems = buildDropPlayerItems,
        initial = dropPlayerInitial,
        onChanged = function(_, key)
            local uid, name = resolveDropTarget(key)
            patchDrop({
                target_user_id = uid,
                target_name = name,
            }, function()
                applyDropRuntime()
            end)
        end,
    })
    G.__GAG2_AUTO_DROP_PLAYER_DD = dropPlayerDd
    _G.__GAG2_AUTO_DROP_PLAYER_DD = dropPlayerDd

    local function buildCatItems()
        local seen = {}
        local items = {}

        local function addCat(key, name)
            key = tostring(key or "")
            if key == "" or key == "_none" or seen[key] then return end
            seen[key] = true
            items[#items + 1] = { key = key, name = tostring(name or key) }
        end

        local ng = getNormalGift()
        if type(ng) == "table" and type(ng.GetCategoryDefs) == "function" then
            local ok, defs = pcall(ng.GetCategoryDefs, ng)
            if ok and type(defs) == "table" then
                for _, def in ipairs(defs) do
                    addCat(def.key, def.label or def.key)
                end
            end
        end

        local ag = G.AutoGiftModule or G.AutoGift or rawget(_G, "AutoGiftModule") or rawget(_G, "AutoGift")
        if type(ag) == "table" and type(ag.GetCategoryDefs) == "function" then
            local ok, defs = pcall(ag.GetCategoryDefs, ag)
            if ok and type(defs) == "table" then
                for _, def in ipairs(defs) do
                    local key = tostring(def.key or def.name or "")
                    if isPetDropCat(key) then
                        addCat("Pets", "Pets")
                    else
                        addCat(key, def.label or def.name or key)
                    end
                end
            end
        end

        addCat("Pets", "Pets")

        if #items == 0 then
            addCat("Seeds", "Seeds")
        end

        table.sort(items, function(a, b) return tostring(a.name) < tostring(b.name) end)
        return items
    end

    local _, dropCatDd = ui:CreateRowDropdown(bodyDrop, {
        label = "Category",
        placeholder = "Seeds",
        mode = "single",
        getItems = buildCatItems,
        initial = DROP.category,
        onChanged = function(_, key)
            key = tostring(key or "Seeds")
            if key == "_none" then return end
            G.__GAG2_AUTO_DROP_ACTIVE_CAT = key
            _G.__GAG2_AUTO_DROP_ACTIVE_CAT = key
            patchDrop({ category = key, selected = {} }, function()
                local itemDd = G.__GAG2_AUTO_DROP_ITEM_DD or rawget(_G, "__GAG2_AUTO_DROP_ITEM_DD")
                if type(itemDd) == "table" and type(itemDd.setSelected) == "function" then
                    pcall(itemDd.setSelected, {})
                end
                if type(itemDd) == "table" and type(itemDd.refreshItems) == "function" then
                    pcall(itemDd.refreshItems, itemDd)
                end
            end)
        end,
    })
    G.__GAG2_AUTO_DROP_CAT_DD = dropCatDd
    _G.__GAG2_AUTO_DROP_CAT_DD = dropCatDd

    local dropItemInitial = normalizeSelected(DROP.selected)
    local _, dropItemDd = ui:CreateRowDropdown(bodyDrop, {
        label = "Items",
        placeholder = "Empty = drop all in category",
        mode = "multi",
        deferItemLoad = true,
        labelForKey = function(key)
            for _, it in ipairs(buildDropItemList(readDropCategory())) do
                if tostring(it.key or "") == tostring(key) then
                    return tostring(it.name or key)
                end
            end
            return tostring(key or "")
        end,
        getItems = function()
            return buildDropItemList(readDropCategory())
        end,
        initial = dropItemInitial,
        onChanged = function(_, selectedMap)
            patchDrop({ selected = normalizeSelected(selectedMap) })
        end,
    })
    G.__GAG2_AUTO_DROP_ITEM_DD = dropItemDd
    _G.__GAG2_AUTO_DROP_ITEM_DD = dropItemDd

    G.__GAG2_AUTO_DROP_ACTIVE_CAT = DROP.category
    _G.__GAG2_AUTO_DROP_ACTIVE_CAT = DROP.category

    if type(dropCatDd.setSelected) == "function" then pcall(dropCatDd.setSelected, DROP.category) end
    if type(dropItemDd.setSelected) == "function" then pcall(dropItemDd.setSelected, dropItemInitial) end

    local _, dropTotalSetFn = ui:CreateRowInput(bodyDrop, "Total", tostring(DROP.drop_total or 1), function(txt)
        local n = tonumber(txt)
        if n and n >= 1 then patchDrop({ drop_total = math.floor(n) }) end
    end, false)
    G.__GAG2_AUTO_DROP_TOTAL = dropTotalSetFn
    _G.__GAG2_AUTO_DROP_TOTAL = dropTotalSetFn

    local _, dropDelaySetFn = ui:CreateRowInput(bodyDrop, "Delay (sec)", tostring(DROP.drop_delay_sec or 1), function(txt)
        local d = tonumber(txt)
        if d ~= nil and d >= 0 then patchDrop({ drop_delay_sec = d }) end
    end, false)
    G.__GAG2_AUTO_DROP_DELAY = dropDelaySetFn
    _G.__GAG2_AUTO_DROP_DELAY = dropDelaySetFn

    local _, _, dropTpToggleApi = ui:CreateRowToggle(
        bodyDrop,
        "Teleport to target",
        DROP.teleport_to_target ~= false,
        function(isOn)
            patchDrop({ teleport_to_target = isOn == true }, function()
                applyDropRuntime()
            end)
        end
    )
    G.__GAG2_AUTO_DROP_TP_TOGGLE_API = dropTpToggleApi
    _G.__GAG2_AUTO_DROP_TP_TOGGLE_API = dropTpToggleApi

    local _, _, dropToggleApi = ui:CreateRowToggle(bodyDrop, "Enabled", false, function(isOn)
        runDropNow(isOn == true)
    end)
    G.__GAG2_AUTO_DROP_TOGGLE_API = dropToggleApi
    _G.__GAG2_AUTO_DROP_TOGGLE_API = dropToggleApi

    G.__GAG2_AUTO_DROP_DONE = function(_ok)
        local api = G.__GAG2_AUTO_DROP_TOGGLE_API or rawget(_G, "__GAG2_AUTO_DROP_TOGGLE_API")
        if type(api) == "table" and type(api.set) == "function" then
            pcall(api.set, false, true)
        end
    end
    _G.__GAG2_AUTO_DROP_DONE = G.__GAG2_AUTO_DROP_DONE

    if dropPlayerInitial and type(dropPlayerDd.setSelected) == "function" then
        pcall(dropPlayerDd.setSelected, dropPlayerInitial)
    end
    if type(dropTpToggleApi) == "table" and type(dropTpToggleApi.set) == "function" then
        pcall(dropTpToggleApi.set, DROP.teleport_to_target == true, true)
    end

    G.__GAG2_AUTO_DROP_UI_READY = true
    _G.__GAG2_AUTO_DROP_UI_READY = true
    syncDropAll()

    task.defer(function()
        task.wait(0.6)
        if type(dropItemDd.refreshItems) == "function" then pcall(dropItemDd.refreshItems, dropItemDd) end
        if countSelected(dropItemInitial) > 0 and type(dropItemDd.setSelected) == "function" then
            pcall(dropItemDd.setSelected, dropItemInitial)
        end
    end)
end

G.SectionAutoDrop = M
_G.SectionAutoDrop = M
return M
 end,            required = false },
    { key = "AutoTabs",                name = "Auto Tabs",               factory = function() -- tabs_auto.lua â€” Grow A Garden 2
-- Main tab: AUTO
-- Sub tabs: Auto (Collect / Plant / Sell), Buy, Gift

local M = {}

function M.Register(ui, STATE, PlantListView)
    STATE = rawget(_G, "STATE") or STATE or {}
    local G = (getgenv and getgenv()) or _G
    G.STATE = STATE

    G.__GAG2_AUTO_FAV_UI_DONE = false
    _G.__GAG2_AUTO_FAV_UI_DONE = false
    G.__GAG2_SPRINKLER_UI_REF = nil
    _G.__GAG2_SPRINKLER_UI_REF = nil

    PlantListView = PlantListView or G.PlantListView or {
        buildFruitItems = function() return {} end,
        buildSeedItems = function() return {} end,
        buildPlantSeedItems = function() return {} end,
        listFruitMutations = function() return {} end,
    }
    G.PlantListView = PlantListView

    ----------------------------------------------------------------
    -- UI ÃƒÂ¢Ã¢â‚¬Â Ã¢â‚¬Â State bridge (MAIN.auto.* via State API)
    ----------------------------------------------------------------
    local function getState()
        return G.__GAG2_STATE or rawget(_G, "__GAG2_STATE")
    end

    local _mainFallbackWarned = false

    local function ensureMain()
        local State = getState()
        if type(State) == "table" and type(State.getMain) == "function" then
            local ok, m = pcall(State.getMain)
            if ok and type(m) == "table" then
                G.MAIN = m
                _G.MAIN = m
                return m
            end
            if not ok and not _mainFallbackWarned then
                warn("[GAG2] State.getMain error:", tostring(m))
            end
        end

        local m = rawget(_G, "MAIN") or G.MAIN
        if type(m) == "table" then
            G.MAIN = m
            _G.MAIN = m
            return m
        end

        if not _mainFallbackWarned then
            _mainFallbackWarned = true
            warn("[GAG2] state.lua belum load â€” UI jalan tanpa save/load. Upload state.lua ke server.")
        end
        m = { auto = {}, misc = {} }
        G.MAIN = m
        _G.MAIN = m
        return m
    end

    local function saveNow()
        if G.__GAG2_RESETTING == true then return end
        local State = getState()
        if type(State) == "table" and type(State.saveFromUi) == "function" then
            pcall(State.saveFromUi)
            return
        end
        if type(G.__GAG2_STATE_SAVE) == "function" then
            pcall(G.__GAG2_STATE_SAVE)
        elseif ui and type(ui.SaveState) == "function" then
            pcall(function() ui:SaveState() end)
        end
    end

    local function getAuto(key)
        local State = getState()
        if type(State) == "table" and type(State.getAuto) == "function" then
            local ok, result = pcall(State.getAuto, key)
            if ok and type(result) == "table" then return result end
        end
        local m = ensureMain()
        if type(m) == "table" and type(m.auto) == "table" then
            return m.auto[key] or {}
        end
        return {}
    end

    local function patchAuto(key, partial, syncFn)
        local State = getState()
        if type(State) == "table" and type(State.patchAuto) == "function" then
            pcall(State.patchAuto, key, partial)
        else
            local m = ensureMain()
            if type(m) == "table" and type(partial) == "table" then
                m.auto = m.auto or {}
                local cur = type(m.auto[key]) == "table" and m.auto[key] or {}
                for k, v in pairs(partial) do cur[k] = v end
                m.auto[key] = cur
                G.MAIN = m
                _G.MAIN = m
            end
        end
        if syncFn then pcall(syncFn) end
        saveNow()
    end

    local function registerFlush(id, fn)
        local State = getState()
        if type(State) == "table" and type(State.registerFlush) == "function" then
            pcall(State.registerFlush, id, fn)
        end
    end

    local function autoSave()
        saveNow()
    end

    G.__GAG2_AUTO_SAVE = autoSave
    G.__GAG2_PERSIST_STATE = saveNow
    _G.__GAG2_PERSIST_STATE = saveNow

    local function toggleApiGet(apiKey)
        local api = G[apiKey] or rawget(_G, apiKey)
        if type(api) == "table" and type(api.get) == "function" then
            return api.get() == true
        end
        return nil
    end

    local function patchAutoOnly(key, partial)
        local State = getState()
        if type(State) == "table" and type(State.patchAuto) == "function" then
            pcall(State.patchAuto, key, partial, { noSync = true })
        else
            local m = ensureMain()
            if type(m) == "table" and type(partial) == "table" then
                m.auto = m.auto or {}
                local cur = type(m.auto[key]) == "table" and m.auto[key] or {}
                for k, v in pairs(partial) do cur[k] = v end
                m.auto[key] = cur
                G.MAIN = m
                _G.MAIN = m
            end
        end
    end

    local function registerToggleFlush(id, autoKey, apiKey, field)
        field = field or "enabled"
        registerFlush(id, function()
            local on = toggleApiGet(apiKey)
            if on == nil then
                local st = getAuto(autoKey)
                if type(st) == "table" then
                    on = (st[field] == true)
                end
            end
            if on == nil then return end
            local State = getState()
            if type(State) == "table" and type(State.patchAuto) == "function" then
                local patch = {}
                patch[field] = on
                pcall(State.patchAuto, autoKey, patch, { noSync = true })
            end
        end)
    end

    local function getMainRef()
        return ensureMain()
    end

    ----------------------------------------------------------------
    -- Auto Claim Seed ÃƒÂ¢Ã¢â€šÂ¬Ã¢â‚¬Â state persist (survive tab rebuild)
    ----------------------------------------------------------------
    if type(G.__GAG2_CLAIM_SEED) ~= "table" then
        G.__GAG2_CLAIM_SEED = { enabled = false }
    end
    _G.__GAG2_CLAIM_SEED = G.__GAG2_CLAIM_SEED

    local function readClaimSeedEnabled()
        local cs = getAuto("claimSeed")
        if type(cs) == "table" then
            return cs.enabled == true
        end
        local store = G.__GAG2_CLAIM_SEED or rawget(_G, "__GAG2_CLAIM_SEED")
        if type(store) == "table" then
            return store.enabled == true
        end
        return false
    end

    local function _syncClaimSeedGlobals(on)
        on = (on == true)
        if type(G.__GAG2_CLAIM_SEED) ~= "table" then G.__GAG2_CLAIM_SEED = {} end
        G.__GAG2_CLAIM_SEED.enabled = on
        _G.__GAG2_CLAIM_SEED = G.__GAG2_CLAIM_SEED
        AUTO_CLAIM_SEED_ENABLED = on
        G.AUTO_CLAIM_SEED_ENABLED = on
        _G.AUTO_CLAIM_SEED_ENABLED = on
        return on
    end

    local function writeClaimSeedState(on)
        on = _syncClaimSeedGlobals(on)
        local State = getState()
        if type(State) == "table" and type(State.patchAuto) == "function" then
            pcall(State.patchAuto, "claimSeed", { enabled = on }, { noSync = true })
        else
            local m = getMainRef()
            if type(m) == "table" then
                m.auto = m.auto or {}
                m.auto.claimSeed = type(m.auto.claimSeed) == "table" and m.auto.claimSeed or { enabled = false }
                m.auto.claimSeed.enabled = on
                G.MAIN = m
                _G.MAIN = m
            end
        end
        return on
    end

    local function applyClaimSeedModuleOnly(on)
        on = (on == true)
        local acs = G.AutoClaimSeed or G.AutoClaimSeedModule or rawget(_G, "AutoClaimSeed")
        if type(acs) ~= "table" or next(acs) == nil then
            warn("[GAG2] Auto Claim Seed module belum loaded â€” re-execute hub")
            return
        end

        -- SetEnabled/ApplyRuntime cuma terima (on), jangan pass module sebagai arg pertama
        if type(acs.SetEnabled) == "function" then
            pcall(acs.SetEnabled, on)
        elseif type(acs.ApplyRuntime) == "function" then
            pcall(acs.ApplyRuntime, on)
        elseif on then
            if type(acs.EnsureRunning) == "function" then
                pcall(acs.EnsureRunning)
            elseif type(acs.Start) == "function" then
                pcall(acs.Start)
            end
        else
            if type(acs.Stop) == "function" then pcall(acs.Stop) end
        end
    end

    local function applyClaimSeedRuntime(on)
        on = (on == true)
        writeClaimSeedState(on)
        applyClaimSeedModuleOnly(on)
    end

    local function syncAutoClaimSeedAll()
        local on = readClaimSeedEnabled()
        _syncClaimSeedGlobals(on)
        local acs = G.AutoClaimSeed or G.AutoClaimSeedModule or rawget(_G, "AutoClaimSeed")
        if type(acs) == "table" and next(acs) ~= nil and on and type(acs.EnsureRunning) == "function" then
            pcall(acs.EnsureRunning)
            return
        end
        applyClaimSeedModuleOnly(on)
    end

    local function saveClaimSeedNow()
        saveNow()
    end

    local function persistClaimSeedBeforeTabChange()
        local toggleOn = toggleApiGet("__GAG2_CLAIM_SEED_TOGGLE_API")
        if toggleOn ~= nil then
            writeClaimSeedState(toggleOn == true)
            return
        end
        writeClaimSeedState(readClaimSeedEnabled())
    end

    local function flushClaimSeedState()
        local toggleOn = toggleApiGet("__GAG2_CLAIM_SEED_TOGGLE_API")
        if toggleOn == nil then return end
        writeClaimSeedState(toggleOn == true)
    end

