    local function restartAutoTeleIfOn()
        writeAutoTeleToMain()
        if not readAutoTeleEnabled() then return end
        local at = G.AutoTele or rawget(_G, "AutoTele")
        if type(at) ~= "table" then return end
        if type(at.InvalidateCache) == "function" then
            pcall(at.InvalidateCache, at)
        end
        if type(at.ApplyRuntime) == "function" then
            pcall(at.ApplyRuntime, at, true)
        elseif type(at.EnsureRunning) == "function" then
            pcall(at.EnsureRunning, at)
        end
        if type(at.TeleportNow) == "function" then
            pcall(at.TeleportNow, at)
        end
    end

