    -- Pet tab persist (dragonEgg + sellPet) â€” flush even when Pet sub-tab closed
    ----------------------------------------------------------------
    local function readDragonEggEnabled()
        local on = toggleApiGet("__GAG2_DRAGON_EGG_ENABLE_API")
        if on ~= nil then return on == true end
        if G.AUTO_DRAGON_EGG_ENABLED == true or rawget(_G, "AUTO_DRAGON_EGG_ENABLED") == true then
            return true
        end
        local st = getAuto("dragonEgg")
        return type(st) == "table" and st.enabled == true
    end

    local function readSellPetEnabled()
        local on = toggleApiGet("__GAG2_SELL_PET_ENABLE_API")
        if on ~= nil then return on == true end
        if G.AUTO_SELL_PET_ENABLED == true or rawget(_G, "AUTO_SELL_PET_ENABLED") == true then
            return true
        end
        local st = getAuto("sellPet")
        return type(st) == "table" and st.enabled == true
    end

    local function readSellPetPets()
        local dd = G.__GAG2_SELL_PET_DROPDOWN_API or rawget(_G, "__GAG2_SELL_PET_DROPDOWN_API")
        if type(dd) == "table" and type(dd.getSelected) == "function" then
            local ok, sel = pcall(dd.getSelected, dd)
            if ok and type(sel) == "table" and next(sel) then
                return mapToArray(cleanSelectedMap(sel))
            end
        end
        local gsel = G.AUTO_SELL_PET_SELECTED or rawget(_G, "AUTO_SELL_PET_SELECTED")
        if type(gsel) == "table" and next(gsel) then
            return mapToArray(cleanSelectedMap(gsel))
        end
        local st = getAuto("sellPet")
        if type(st) == "table" and type(st.pets) == "table" then
            return st.pets
        end
        return {}
    end

    local function writeDragonEggState(on)
        on = (on == true)
        G.AUTO_DRAGON_EGG_ENABLED = on
        _G.AUTO_DRAGON_EGG_ENABLED = on
        patchAutoOnly("dragonEgg", { enabled = on })
        return on
    end

    local function writeSellPetState(on, pets)
        on = (on == true)
        local selMap = cleanSelectedMap(arrayToMap(type(pets) == "table" and pets or {}))
        local petList = mapToArray(selMap)
        G.AUTO_SELL_PET_ENABLED = on
        _G.AUTO_SELL_PET_ENABLED = on
        G.AUTO_SELL_PET_SELECTED = selMap
        _G.AUTO_SELL_PET_SELECTED = selMap
        patchAutoOnly("sellPet", { enabled = on, pets = petList })
        return on, petList
    end

    local function flushDragonEggState()
        writeDragonEggState(readDragonEggEnabled())
    end

    local function flushSellPetState()
        writeSellPetState(readSellPetEnabled(), readSellPetPets())
    end

