    ----------------------------------------------------------------
    -- Auto Shovel â€” plants + heightRule + enabled disimpan
    ----------------------------------------------------------------
    if type(G.__GAG2_SHOVEL) ~= "table" then
        G.__GAG2_SHOVEL = { enabled = false, plants = {}, heightRule = "0" }
    elseif G.__GAG2_SHOVEL.heightRule == nil then
        G.__GAG2_SHOVEL.heightRule = "0"
    end
    _G.__GAG2_SHOVEL = G.__GAG2_SHOVEL

    local function normalizeShovelHeightRule(txt)
        local hr = tostring(txt or "0"):gsub("%s+", "")
        if hr == "" then hr = "0" end
        return hr
    end

    local function readShovelEnabled()
        local store = G.__GAG2_SHOVEL or rawget(_G, "__GAG2_SHOVEL")
        return type(store) == "table" and store.enabled == true
    end

    local function readShovelHeightRule()
        local store = G.__GAG2_SHOVEL or rawget(_G, "__GAG2_SHOVEL")
        if type(store) == "table" and store.heightRule ~= nil then
            return normalizeShovelHeightRule(store.heightRule)
        end
        local hr = G.AUTO_SHOVEL_HEIGHT_RULE or rawget(_G, "AUTO_SHOVEL_HEIGHT_RULE")
        return normalizeShovelHeightRule(hr)
    end

    local function readShovelPlantsSelected()
        local store = G.__GAG2_SHOVEL or rawget(_G, "__GAG2_SHOVEL")
        if type(store) == "table" and type(store.plants) == "table" then
            local map = cleanSelectedMap(arrayToMap(store.plants))
            if map._none then map._none = nil end
            return map
        end
        local map = G.AUTO_SHOVEL_PLANTS_SELECTED or rawget(_G, "AUTO_SHOVEL_PLANTS_SELECTED")
        if type(map) == "table" then
            map = cleanSelectedMap(map)
            if map._none then map._none = nil end
            return map
        end
        return {}
    end

    local function countShovelSelected(map)
        map = cleanSelectedMap(map or readShovelPlantsSelected())
        if map._none then map._none = nil end
        local n = 0
        for k, v in pairs(map) do
            if v == true and k ~= "_none" then n = n + 1 end
        end
        return n
    end

    local function writeShovelState(enabled, plantsMap, heightRule)
        enabled = (enabled == true)
        plantsMap = cleanSelectedMap(plantsMap or readShovelPlantsSelected())
        heightRule = normalizeShovelHeightRule(
            heightRule ~= nil and heightRule or readShovelHeightRule()
        )

        if type(G.__GAG2_SHOVEL) ~= "table" then
            G.__GAG2_SHOVEL = { enabled = false, plants = {}, heightRule = "0" }
        end
        G.__GAG2_SHOVEL.enabled = enabled
        G.__GAG2_SHOVEL.plants = mapToArray(plantsMap)
        G.__GAG2_SHOVEL.heightRule = heightRule
        _G.__GAG2_SHOVEL = G.__GAG2_SHOVEL

        AUTO_SHOVEL_ENABLED = enabled
        G.AUTO_SHOVEL_ENABLED = enabled
        _G.AUTO_SHOVEL_ENABLED = enabled
        AUTO_SHOVEL_PLANTS_SELECTED = plantsMap
        G.AUTO_SHOVEL_PLANTS_SELECTED = plantsMap
        _G.AUTO_SHOVEL_PLANTS_SELECTED = plantsMap
        AUTO_SHOVEL_HEIGHT_RULE = heightRule
        G.AUTO_SHOVEL_HEIGHT_RULE = heightRule
        _G.AUTO_SHOVEL_HEIGHT_RULE = heightRule
    end

    local function syncShovelPlantsFromMain()
        local sh = getAuto("shovel")
        if type(sh) == "table" then
            local map = cleanSelectedMap(arrayToMap(type(sh.plants) == "table" and sh.plants or {}))
            if map._none then map._none = nil end
            writeShovelState(sh.enabled == true, map, sh.heightRule or "0")
            return map
        end
        return readShovelPlantsSelected()
    end

    local function persistShovelState()
        patchAuto("shovel", {
            enabled = readShovelEnabled(),
            plants = mapToArray(readShovelPlantsSelected()),
            heightRule = readShovelHeightRule(),
        })
    end

    local function persistShovelPlants(plantsMap)
        plantsMap = cleanSelectedMap(plantsMap or readShovelPlantsSelected())
        if plantsMap._none then plantsMap._none = nil end
        writeShovelState(readShovelEnabled(), plantsMap)
        persistShovelState()
    end

    local function persistShovelHeightRule(heightRule)
        heightRule = normalizeShovelHeightRule(heightRule)
        writeShovelState(readShovelEnabled(), readShovelPlantsSelected(), heightRule)
        persistShovelState()
    end

    local function applyShovelRuntime(on)
        on = (on == true)
        if on and countShovelSelected() < 1 then
            on = false
        end
        local as = G.AutoShovel or G.AutoShovelModule or rawget(_G, "AutoShovel")
        if type(as) ~= "table" then return on end
        if type(as.ApplyRuntime) == "function" then
            pcall(as.ApplyRuntime, as, on)
        elseif on then
            if type(as.Start) == "function" then pcall(as.Start, as) end
        else
            if type(as.Stop) == "function" then pcall(as.Stop, as) end
        end
        return on
    end

    local function pruneShovelSelection(dropdownApi, toggleApi)
        local AS = G.AutoShovel or G.AutoShovelModule or rawget(_G, "AutoShovel")
        local sel = readShovelPlantsSelected()
        local changed = false
        if type(AS) == "table" and type(AS.PruneSelectionToGarden) == "function" then
            local ok, pruned, didChange = pcall(AS.PruneSelectionToGarden, AS, sel)
            if ok and didChange and type(pruned) == "table" then
                sel = pruned
                changed = true
            end
        end
        if not changed then
            return sel, false
        end

        local on = readShovelEnabled()
        if countShovelSelected(sel) < 1 then
            on = false
        end
        writeShovelState(on, sel)
        persistShovelPlants(sel)
        applyShovelRuntime(on)

        if dropdownApi and type(dropdownApi.setSelected) == "function" then
            dropdownApi.setSelected(sel)
        end
        if dropdownApi and type(dropdownApi.refreshLabel) == "function" then
            dropdownApi.refreshLabel()
        end
        if not on and toggleApi and type(toggleApi.set) == "function" then
            toggleApi.set(false, true)
        end
        return sel, true
    end

    local function syncAutoShovelAll()
        local on = readShovelEnabled()
        local sel = readShovelPlantsSelected()
        if on and countShovelSelected(sel) < 1 then
            on = false
        end
        writeShovelState(on, sel)
        applyShovelRuntime(on)
    end

    G.__GAG2_READ_SHOVEL = readShovelEnabled
    G.__GAG2_WRITE_SHOVEL = writeShovelState
    G.__GAG2_SYNC_AUTO_SHOVEL = syncAutoShovelAll
    _G.__GAG2_READ_SHOVEL = readShovelEnabled
    _G.__GAG2_WRITE_SHOVEL = writeShovelState
    _G.__GAG2_SYNC_AUTO_SHOVEL = syncAutoShovelAll

