            end
            if ui and type(ui.SaveState) == "function" then
                pcall(function() ui:SaveState() end)
            end
        end
        _G.__GAG2_BEFORE_TAB_CHANGE = G.__GAG2_BEFORE_TAB_CHANGE
    end

    local function parseKgRule(txt)
        txt = tostring(txt or ""):gsub("%s+", "")
        if txt == "" then
            return 0, "above"
        end
        local n = tonumber(txt)
        if not n then
            return 0, "above"
        end
        if n < 0 then
            return math.abs(n), "below"
        end
        return n, "above"
    end

    local function normalizeCollectPriority(v)
        local s = tostring(v or "off"):lower():gsub("%s+", "")
        if s == "price" or s == "highestprice" then return "price" end
        if s == "rarity" or s == "highestrarity" then return "rarity" end
        if s == "weight" or s == "heaviest" or s == "heaviestkg" or s == "kg" then return "weight" end
        if s == "off" or s == "normal" or s == "normalscanorder" then return "off" end
        return "off"
    end

    local function applyCollectPriority(mode)
        mode = normalizeCollectPriority(mode)
        local State = getState()
        if type(State) == "table" and type(State.patchAuto) == "function" then
            pcall(State.patchAuto, "collect", { priority = mode }, { noSync = true })
        else
            local m = rawget(_G, "MAIN") or G.MAIN
            if type(m) == "table" then
                m.auto = m.auto or {}
                m.auto.collect = m.auto.collect or {}
                m.auto.collect.priority = mode
                G.MAIN = m
                _G.MAIN = m
            end
        end
        G.AUTO_COLLECT_PRIORITY = mode
        _G.AUTO_COLLECT_PRIORITY = mode
        return mode
    end

    local function readCollectPriorityFromUi(fallback)
        local api = G.__GAG2_COLLECT_PRIORITY_API or rawget(_G, "__GAG2_COLLECT_PRIORITY_API")
        if type(api) == "table" and type(api.getSelected) == "function" then
            local ok, sel = pcall(api.getSelected, api)
            if not ok then ok, sel = pcall(api.getSelected) end
            if ok and sel ~= nil and tostring(sel) ~= "" then
                return normalizeCollectPriority(sel)
            end
        end
        local pr = G.AUTO_COLLECT_PRIORITY or rawget(_G, "AUTO_COLLECT_PRIORITY")
        if pr ~= nil then
            return normalizeCollectPriority(pr)
        end
        local live = getAuto("collect")
        if type(live) == "table" and live.priority ~= nil then
            return normalizeCollectPriority(live.priority)
        end
        return normalizeCollectPriority(fallback or "off")
    end

    local function flushAutoCollectState()
        applyCollectPriority(readCollectPriorityFromUi())
    end

    G.__GAG2_FLUSH_AUTO_COLLECT = flushAutoCollectState
    _G.__GAG2_FLUSH_AUTO_COLLECT = flushAutoCollectState

    ----------------------------------------------------------------
    -- garden scan (status only)
    ----------------------------------------------------------------
    local function getCollectHarvestBreakdown()
        local ac = G.AutoCollectFruit or G.CollectFruitModule
        if type(ac) == "table" and type(ac.PeekHarvestBreakdown) == "function" then
            local ok, br = pcall(ac.PeekHarvestBreakdown, ac)
            if ok and type(br) == "table" then
                return {
                    inFilter  = math.max(0, math.floor(tonumber(br.inFilter) or 0)),
                    outFilter = math.max(0, math.floor(tonumber(br.outFilter) or 0)),
                }
            end
        end
        local inN = 0
        if type(ac) == "table" and type(ac.PeekFilteredCount) == "function" then
            local ok, n = pcall(ac.PeekFilteredCount, ac)
            if ok and type(n) == "number" then inN = math.max(0, math.floor(n)) end
        end
        return { inFilter = inN, outFilter = 0 }
    end

    ----------------------------------------------------------------
    -- MAIN TAB: AUTO
    ----------------------------------------------------------------
    ui:RegisterMainTab("auto", "AUTO", 1)

    ----------------------------------------------------------------
    -- SUB TAB: Auto (Collect + Sell)
    ----------------------------------------------------------------
    ui:RegisterSubTab("auto", "auto", "Auto", function()
        local MAIN = ensureMain()
        MAIN.auto = MAIN.auto or {}

        local AC_STATE = getAuto("collect")
        AC_STATE.enabled   = (AC_STATE.enabled == true)
        do
            local d = tonumber(AC_STATE.delay)
            if d == nil then d = 0.1 end
            if d < 0 then d = 0 end
            if d > 1 then d = 1 end
            AC_STATE.delay = d
        end
        AC_STATE.rules = type(AC_STATE.rules) == "table" and AC_STATE.rules or {}
        AC_STATE.rulesOrder = type(AC_STATE.rulesOrder) == "table" and AC_STATE.rulesOrder or {}
        AC_STATE.filterMode = "rules"
        AC_STATE.eclipseSpawnEnabled = (AC_STATE.eclipseSpawnEnabled == true)
        do
            local kgRule = tostring(AC_STATE.eclipseSpawnKgRule or "0")
            if kgRule:gsub("%s+", "") == "" then kgRule = "0" end
            AC_STATE.eclipseSpawnKgRule = kgRule
        end
        do
            local pr = G.AUTO_COLLECT_PRIORITY or rawget(_G, "AUTO_COLLECT_PRIORITY") or AC_STATE.priority
            pr = normalizeCollectPriority(pr)
            AC_STATE.priority = pr
        end

        local function collectDelayDisplay()
            local n = tonumber(AC_STATE.delay)
            return (n ~= nil) and n or 0.1
        end

        local function readCollectDelayFromUi()
            local fn = G.__GAG2_COLLECT_DELAY_API or rawget(_G, "__GAG2_COLLECT_DELAY_API")
            if type(fn) == "function" then
                local ok, v = pcall(fn)
                if ok and v ~= nil then
                    local n = tonumber(v)
                    if n ~= nil then
                        if n < 0 then n = 0 end
                        if n > 1 then n = 1 end
                        return n
                    end
                end
            end
            return collectDelayDisplay()
        end

        local function readEclipseSpawnFromUi(live)
            live = type(live) == "table" and live or {}
            local onApi = G.__GAG2_ECLIPSE_SPAWN_ENABLE_API or rawget(_G, "__GAG2_ECLIPSE_SPAWN_ENABLE_API")
            local enabled = live.eclipseSpawnEnabled == true or AC_STATE.eclipseSpawnEnabled == true
            if type(onApi) == "table" and type(onApi.get) == "function" then
                local ok, v = pcall(onApi.get, onApi)
                if ok then enabled = (v == true) end
            end
            local kgFn = G.__GAG2_ECLIPSE_SPAWN_KG_API or rawget(_G, "__GAG2_ECLIPSE_SPAWN_KG_API")
            local kgRule = tostring(live.eclipseSpawnKgRule or AC_STATE.eclipseSpawnKgRule or "0")
            if type(kgFn) == "function" then
                local ok, v = pcall(kgFn)
                if ok and v ~= nil then
                    kgRule = tostring(v)
                end
            end
            if kgRule:gsub("%s+", "") == "" then kgRule = "0" end
            return enabled, kgRule
        end

        local function collectSnapshot()
            local live = getAuto("collect")
            local on = toggleApiGet("__GAG2_COLLECT_ENABLE_API")
            local priority = readCollectPriorityFromUi(live.priority or AC_STATE.priority)
            AC_STATE.priority = priority
            if type(live) == "table" then
                live.priority = priority
            end
            local eclipseOn, eclipseKg = readEclipseSpawnFromUi(live)
            AC_STATE.eclipseSpawnEnabled = eclipseOn
            AC_STATE.eclipseSpawnKgRule = eclipseKg
            return {
                enabled = on ~= nil and on or (live.enabled == true),
                delay = readCollectDelayFromUi(),
                priority = priority,
                filterMode = "rules",
                rules = live.rules,
                rulesOrder = live.rulesOrder,
                eclipseSpawnEnabled = eclipseOn,
                eclipseSpawnKgRule = eclipseKg,
            }
        end

        registerFlush("collect", function()
            flushAutoCollectState()
            patchAutoOnly("collect", collectSnapshot())
        end)

        AUTO_COLLECT_FRUIT_ENABLED = AC_STATE.enabled
        G.AUTO_COLLECT_FRUIT_ENABLED = AC_STATE.enabled
        _G.AUTO_COLLECT_FRUIT_ENABLED = AC_STATE.enabled

        G.AUTO_COLLECT_DELAY = AC_STATE.delay
        _G.AUTO_COLLECT_DELAY = AC_STATE.delay
        G.AUTO_COLLECT_PRIORITY = AC_STATE.priority
        _G.AUTO_COLLECT_PRIORITY = AC_STATE.priority
        G.AUTO_COLLECT_FILTER_MODE = "rules"
        _G.AUTO_COLLECT_FILTER_MODE = "rules"
        G.AUTO_COLLECT_RULES = AC_STATE.rules
        _G.AUTO_COLLECT_RULES = AC_STATE.rules
        G.AUTO_COLLECT_RULES_ORDER = AC_STATE.rulesOrder
        _G.AUTO_COLLECT_RULES_ORDER = AC_STATE.rulesOrder
        G.AUTO_COLLECT_ECLIPSE_SPAWN = AC_STATE.eclipseSpawnEnabled == true
        _G.AUTO_COLLECT_ECLIPSE_SPAWN = G.AUTO_COLLECT_ECLIPSE_SPAWN
        G.AUTO_COLLECT_ECLIPSE_SPAWN_KG_RULE = AC_STATE.eclipseSpawnKgRule or "0"
        _G.AUTO_COLLECT_ECLIPSE_SPAWN_KG_RULE = G.AUTO_COLLECT_ECLIPSE_SPAWN_KG_RULE

        local COLLECT_PRIORITY_ITEMS = {
            { key = "off",    name = "Normal (scan order)" },
            { key = "price",  name = "Highest Price" },
            { key = "rarity", name = "Highest Rarity" },
            { key = "weight", name = "Heaviest (kg)" },
        }

        local function syncAutoCollectModule()
            local live = getAuto("collect")
            G.AUTO_COLLECT_FRUIT_ENABLED = (live.enabled == true)
            _G.AUTO_COLLECT_FRUIT_ENABLED = G.AUTO_COLLECT_FRUIT_ENABLED

            G.AUTO_COLLECT_DELAY = collectDelayDisplay()
            _G.AUTO_COLLECT_DELAY = G.AUTO_COLLECT_DELAY
            G.AUTO_COLLECT_PRIORITY = normalizeCollectPriority(live.priority or AC_STATE.priority or "off")
            _G.AUTO_COLLECT_PRIORITY = G.AUTO_COLLECT_PRIORITY
            G.AUTO_COLLECT_FILTER_MODE = "rules"
            _G.AUTO_COLLECT_FILTER_MODE = "rules"
            G.AUTO_COLLECT_RULES = live.rules
            _G.AUTO_COLLECT_RULES = live.rules
            G.AUTO_COLLECT_RULES_ORDER = live.rulesOrder
            _G.AUTO_COLLECT_RULES_ORDER = live.rulesOrder

            local eclipseOn = live.eclipseSpawnEnabled == true
            local eclipseKg = tostring(live.eclipseSpawnKgRule or AC_STATE.eclipseSpawnKgRule or "0")
            if eclipseKg:gsub("%s+", "") == "" then eclipseKg = "0" end
            AC_STATE.eclipseSpawnEnabled = eclipseOn
            AC_STATE.eclipseSpawnKgRule = eclipseKg
            G.AUTO_COLLECT_ECLIPSE_SPAWN = eclipseOn
            _G.AUTO_COLLECT_ECLIPSE_SPAWN = eclipseOn
            G.AUTO_COLLECT_ECLIPSE_SPAWN_KG_RULE = eclipseKg
            _G.AUTO_COLLECT_ECLIPSE_SPAWN_KG_RULE = eclipseKg

            local ac = G.AutoCollectFruit or G.CollectFruitModule
            if type(ac) == "table" then
                local function __call(fn, ...)
                    if type(ac[fn]) == "function" then
                        pcall(ac[fn], ...)
                    end
                end

                __call("SetDelay", G.AUTO_COLLECT_DELAY)
                __call("setDelay", G.AUTO_COLLECT_DELAY)
                __call("SetPriority", G.AUTO_COLLECT_PRIORITY)
                __call("setPriority", G.AUTO_COLLECT_PRIORITY)
                __call("SetFilterMode", "rules")
                __call("setFilterMode", "rules")
                __call("SetRules", G.AUTO_COLLECT_RULES, G.AUTO_COLLECT_RULES_ORDER)
                __call("setRules", G.AUTO_COLLECT_RULES, G.AUTO_COLLECT_RULES_ORDER)
                __call("SetEclipseSpawn", {
                    enabled = eclipseOn,
                    kgRule = eclipseKg,
                })
                __call("setEclipseSpawn", {
                    enabled = eclipseOn,
                    kgRule = eclipseKg,
                })

                if G.AUTO_COLLECT_FRUIT_ENABLED then
                    __call("EnsureRunning")
                    __call("ensureRunning")
                else
                    __call("Stop")
                    __call("stop")
                end
            end
        end

        G.__GAG2_SYNC_AUTO_COLLECT = syncAutoCollectModule

        local body = ui:CreateSection("Auto Collect", false)

        local _, statusInFilter = ui:CreateRowLabel(
            body,
            "Match filter: ...",
            nil,
            nil,
            "muted"
        )

        local _, statusOutFilter = ui:CreateRowLabel(
            body,
            "Skipped: ...",
            nil,
            nil,
            "muted"
        )

        local _, statusEclipseSpawn = ui:CreateRowLabel(
            body,
            "Eclipse spawn: OFF",
            nil,
            nil,
            "muted"
        )

        local function refreshCollectStatus()
            local br = getCollectHarvestBreakdown()
            local ac = G.AutoCollectFruit or G.CollectFruitModule
            local st
            if type(ac) == "table" and type(ac.GetStats) == "function" then
                local ok, s = pcall(ac.GetStats, ac)
                if ok and type(s) == "table" then st = s end
            end

            local inN = br.inFilter or 0
            local outN = br.outFilter or 0
            local runHint = "OFF"
            if st then
                if st.backpackFull == true then
                    runHint = "backpack full"
                elseif st.enabled ~= true then
                    runHint = "OFF"
                elseif st.remoteReady ~= true then
                    runHint = "no remote"
                elseif st.loopAlive == true then
                    runHint = (st.lastTickCollected == 1) and "collecting" or "running"
                elseif st.running == true then
                    runHint = "starting..."
                else
                    runHint = "paused"
                end
            end

            if statusInFilter and statusInFilter.Parent then
                statusInFilter.Text = ("Match filter: %d  (%s)"):format(inN, runHint)
            end
            if statusOutFilter and statusOutFilter.Parent then
                local extra = ""
                if st and st.batchPending and st.batchPending > 0 then
                    extra = ("  queue: %d"):format(st.batchPending)
                end
                statusOutFilter.Text = ("Skipped: %d%s"):format(outN, extra)
            end

            if statusEclipseSpawn and statusEclipseSpawn.Parent then
                local spawnOn = AC_STATE.eclipseSpawnEnabled == true
                    or (st and st.eclipseSpawnEnabled == true)
                if not spawnOn then
                    statusEclipseSpawn.Text = "Eclipse spawn: OFF"
                else
                    local peek
                    if type(ac) == "table" and type(ac.PeekEclipseSpawnStatus) == "function" then
                        local okP, p = pcall(ac.PeekEclipseSpawnStatus, ac)
                        if okP and type(p) == "table" then peek = p end
                    end
                    local n = peek and tonumber(peek.count) or 0
                    local kg = peek and tonumber(peek.bestKg) or 0
                    local weather = tostring((peek and peek.weather) or "")
                    if weather == "" then weather = "?" end
                    local phase = "wait"
                    if peek and peek.backpackFull == true then
                        phase = "backpack full"
                    elseif peek and peek.weatherEclipse == true then
                        phase = "hold"
                    elseif peek and peek.done == true then
                        phase = "done 1x · wait next weather"
                    elseif n > 0 then
                        phase = "ready"
                    else
                        phase = "no ripe"
                    end
                    if n > 0 then
                        statusEclipseSpawn.Text = ("Eclipse spawn: %d ready · %.1fkg · %s · %s")
                            :format(n, kg, weather, phase)
                    else
                        statusEclipseSpawn.Text = ("Eclipse spawn: 0 ready · %s · %s"):format(weather, phase)
                    end
                end
            end
        end

        task.defer(function()
            pcall(refreshCollectStatus)
        end)

        task.spawn(function()
            while body and body.Parent do
                task.wait(5)
                pcall(refreshCollectStatus)
            end
        end)

        local collectRulesCtx = {
            rulesKind = "collect",
            RULES_STATE = AC_STATE,
            body = body,
            ui = ui,
            AC_STATE = AC_STATE,
            getAuto = getAuto,
            patchAuto = patchAuto,
            patchAutoOnly = patchAutoOnly,
            registerFlush = registerFlush,
            cleanSelectedMap = cleanSelectedMap,
            mapToArray = mapToArray,
            arrayToMap = arrayToMap,
            PlantListView = PlantListView,
            syncAutoCollectModule = syncAutoCollectModule,
        }

