            tostring(AC_STATE.eclipseSpawnKgRule or "0"),
            function(txt)
                local kgRule = tostring(txt or "0")
                if kgRule:gsub("%s+", "") == "" then kgRule = "0" end
                AC_STATE.eclipseSpawnKgRule = kgRule
                G.AUTO_COLLECT_ECLIPSE_SPAWN_KG_RULE = kgRule
                _G.AUTO_COLLECT_ECLIPSE_SPAWN_KG_RULE = kgRule
                patchAuto("collect", { eclipseSpawnKgRule = kgRule }, syncAutoCollectModule)
            end,
            false
        )
        G.__GAG2_ECLIPSE_SPAWN_KG_API = eclipseKgFn
        _G.__GAG2_ECLIPSE_SPAWN_KG_API = eclipseKgFn

        local _, _, eclipseSpawnApi = ui:CreateRowToggle(
            body,
            "Collect 1 Eclipse Bloom (spawn weather)",
            (AC_STATE.eclipseSpawnEnabled == true),
            function(isOn)
                AC_STATE.eclipseSpawnEnabled = (isOn == true)
