                if #items == 0 then
                    items[1] = { key = "_none", name = "(Save position dulu)" }
                end
                return items
            end,
            initial = AUTO_PLANT_SELECTED_POSITIONS,
            onDeleteItem = function(key)
                key = tostring(key or "")
                if key == "" or key == "_none" then return end

                local ap = G.AutoPlant or G.AutoPlantModule
                local deleted = false
                if type(ap) == "table" and type(ap.DeletePosition) == "function" then
                    local ok, result = pcall(ap.DeletePosition, ap, key)
                    deleted = (ok == true and result ~= false)
                end

                if not deleted then
                    local positions = AP_STATE.positions
                    if type(positions) == "table" then
                        for i = #positions, 1, -1 do
                            local entry = positions[i]
                            if type(entry) == "table" and tostring(entry.id) == key then
                                table.remove(positions, i)
                                deleted = true
                            end
                        end
                    end
                    AP_STATE.positions = positions
                end

                AUTO_PLANT_SELECTED_POSITIONS[key] = nil
                AP_STATE.selectedPositions = mapToArray(AUTO_PLANT_SELECTED_POSITIONS)
                AP_STATE.selectedPosition = AP_STATE.selectedPositions[1] and normalizePlantPositionId(AP_STATE.selectedPositions[1]) or nil

                if positionDropdownApi and positionDropdownApi.refreshItems then
                    positionDropdownApi.refreshItems()
                end
                if positionDropdownApi and positionDropdownApi.setSelected then
                    positionDropdownApi.setSelected(AUTO_PLANT_SELECTED_POSITIONS)
                end
                if positionDropdownApi and positionDropdownApi.refreshLabel then
                    positionDropdownApi.refreshLabel()
                end

                patchAuto("plant", {
                    positions = AP_STATE.positions,
                    selectedPositions = AP_STATE.selectedPositions,
                    selectedPosition = AP_STATE.selectedPosition,
                }, syncAutoPlantModule)
            end,
            onChanged = function(_, selectedMap)
