        local function writeSellGlobals()
            local live = getAuto("sell")
            local api = G.__GAG2_SELL_ENABLE_API or rawget(_G, "__GAG2_SELL_ENABLE_API")
            if type(api) == "table" and type(api.get) == "function" then
                live.enabled = (api.get() == true)
            end
            G.AUTO_SELL_ENABLED = (live.enabled == true)
            _G.AUTO_SELL_ENABLED = G.AUTO_SELL_ENABLED
            if live.minCount ~= nil then
                G.AUTO_SELL_MIN_COUNT = tonumber(live.minCount)
                _G.AUTO_SELL_MIN_COUNT = G.AUTO_SELL_MIN_COUNT
            end
            if live.delay ~= nil then
                G.AUTO_SELL_DELAY = tonumber(live.delay)
                _G.AUTO_SELL_DELAY = G.AUTO_SELL_DELAY
            end
            if live.sellWhenFull ~= nil then
                G.AUTO_SELL_WHEN_FULL = (live.sellWhenFull == true)
                _G.AUTO_SELL_WHEN_FULL = G.AUTO_SELL_WHEN_FULL
            end
            G.AUTO_SELL_FILTER_MODE = "rules"
            _G.AUTO_SELL_FILTER_MODE = "rules"
            G.AUTO_SELL_RULES = live.rules
            _G.AUTO_SELL_RULES = live.rules
            G.AUTO_SELL_RULES_ORDER = live.rulesOrder
            _G.AUTO_SELL_RULES_ORDER = live.rulesOrder
            patchAutoOnly("sell", {
                enabled = (live.enabled == true),
                minCount = live.minCount,
                delay = live.delay,
                sellWhenFull = (live.sellWhenFull == true),
                filterMode = "rules",
                rules = live.rules,
                rulesOrder = live.rulesOrder,
            })
        end
        G.__GAG2_PUSH_SELL = writeSellGlobals
        _G.__GAG2_PUSH_SELL = writeSellGlobals

        registerFlush("sell", function()
            writeSellGlobals()
        end)

        task.defer(writeSellGlobals)

        local function getFruitStatusText(useHeavy)
            local count, maxCap, total
            local filtered
            local AS = G.AutoSellFruit
            if useHeavy and AS and type(AS.GetFruitStats) == "function" then
                local ok, c, m, t = pcall(function() return AS:GetFruitStats() end)
                if ok then
                    count, maxCap, total = c, m, t
                end
            end
            if count == nil then
                local LP = game:GetService("Players").LocalPlayer
                count = tonumber(LP:GetAttribute("FruitCount")) or 0
                maxCap = tonumber(LP:GetAttribute("MaxFruitCapacity"))
                total = count
            end
            if useHeavy and AS and type(AS.HasFilterActive) == "function" then
                local ok, on = pcall(AS.HasFilterActive, AS)
                if ok and on == true then
                    filtered = count
                    count = total or count
                end
            end
            local base = (maxCap and maxCap > 0) and ("Fruit: %d / %d"):format(count, maxCap)
                or ("Fruit: %d"):format(count)
            if filtered ~= nil then
                base = base .. (" - match filter: %d"):format(filtered)
            end
            if AS_STATE.sellWhenFull == true then
                if filtered ~= nil then
                    return base .. " - sell match when full"
                end
                return base .. " - sell when full"
            end
            if filtered ~= nil then
                return base .. (" - sell match at >= %d"):format(sellMinCountDisplay())
            end
            return base .. (" - sell at >= %d"):format(sellMinCountDisplay())
        end

        local _, setSellWhenFullToggle

        local function syncAutoSellModule()
            writeSellGlobals()

            local as = G.AutoSellFruit
            if type(as) ~= "table" then return end

            local function __callSell(fn, ...)
                if type(as[fn]) == "function" then
                    pcall(as[fn], ...)
                end
            end

            __callSell("SetMinCount", G.AUTO_SELL_MIN_COUNT)
            __callSell("setMinCount", G.AUTO_SELL_MIN_COUNT)
            __callSell("SetDelay", G.AUTO_SELL_DELAY)
            __callSell("setDelay", G.AUTO_SELL_DELAY)
            __callSell("SetSellWhenFull", G.AUTO_SELL_WHEN_FULL == true)
            __callSell("setSellWhenFull", G.AUTO_SELL_WHEN_FULL == true)
            __callSell("SetFilterMode", "rules")
            __callSell("setFilterMode", "rules")
            __callSell("SetRules", G.AUTO_SELL_RULES, G.AUTO_SELL_RULES_ORDER)
            __callSell("setRules", G.AUTO_SELL_RULES, G.AUTO_SELL_RULES_ORDER)

            if G.AUTO_SELL_ENABLED then
                __callSell("Start")
                __callSell("start")
            else
                __callSell("Stop")
                __callSell("stop")
            end

            task.defer(function()
                __callSell("CheckNow")
                __callSell("checkNow")
            end)
        end

