        local function buildShovelPlantItems()
            local AS = G.AutoShovel or G.AutoShovelModule or rawget(_G, "AutoShovel")
            if type(AS) == "table" and type(AS.BuildShovelDropdownItems) == "function" then
                local ok, items = pcall(AS.BuildShovelDropdownItems, AS)
                if ok and type(items) == "table" then return items end
