            return { { key = "_none", name = "(No plants in garden)" } }
        end

        local function resolveAutoShovel()
            local AS = G.AutoShovel or G.AutoShovelModule
                or rawget(_G, "AutoShovel") or rawget(_G, "AutoShovelModule")
            if type(AS) == "table" then
                return AS
            end
            local ensure = G.__GAG2_ENSURE_LOADED_MODULE or rawget(_G, "__GAG2_ENSURE_LOADED_MODULE")
            if type(ensure) == "function" then
                local ok, mod = pcall(ensure, "AutoShovel")
                if ok and type(mod) == "table" then
                    G.AutoShovel = mod
                    G.AutoShovelModule = mod
                    _G.AutoShovel = mod
                    _G.AutoShovelModule = mod
                    return mod
                end
            end
            return nil
        end

        local function readShovelMatchCounts()
            local AS = resolveAutoShovel()
            local typeMatch, heightMatch, heightSkipped = 0, 0, 0
            if type(AS) ~= "table" then
                return typeMatch, heightMatch, heightSkipped
            end

            local sel = readShovelPlantsSelected()
            if type(AS.GetMatchBreakdown) == "function" then
                local ok, br = pcall(function()
                    return AS.GetMatchBreakdown(sel)
                end)
                if ok and type(br) == "table" then
                    return tonumber(br.typeMatch) or 0,
                        tonumber(br.heightMatch) or 0,
                        tonumber(br.heightSkipped) or 0
                end
            end

            if type(AS.CountMatchingSelected) == "function" then
                local ok, n = pcall(function()
                    return AS.CountMatchingSelected(sel)
                end)
                if ok and type(n) == "number" then
                    heightMatch = math.max(0, math.floor(n))
                    typeMatch = heightMatch
                end
            end
            return typeMatch, heightMatch, heightSkipped
        end

        local function shovelStatusText()
            local types = countShovelSelected()
            local hr = readShovelHeightRule()
            local typeMatch, heightMatch, heightSkipped = readShovelMatchCounts()

            if types < 1 then
                return string.format("Selected: 0 | Match: 0 | Height: %s", hr)
            end
            return string.format(
                "Selected: %d type(s) | Match: %d | In garden: %d | Skip height: %d | Height: %s",
                types,
                heightMatch,
                typeMatch,
                heightSkipped,
                hr
            )
        end

        local function refreshShovelStatus()
            if shovelStatusLabel and shovelStatusLabel.Parent then
                local ok, txt = pcall(shovelStatusText)
                shovelStatusLabel.Text = ok and txt or "..."
            end
        end

        _, shovelStatusLabel = ui:CreateRowLabel(
            bodyShovel,
            shovelStatusText(),
            nil,
            nil,
            "accent"
        )

        _, shovelDropdownApi = ui:CreateRowDropdown(bodyShovel, {
            label       = "Select Plant",
            placeholder = "Plants in garden...",
            mode        = "multi",
            deferItemLoad = true,
            getItems = function()
                return buildShovelPlantItems()
            end,
            initial = shovelSelected,
            onChanged = function(_, selectedMap)
                selectedMap = cleanSelectedMap(selectedMap)
                if selectedMap._none then selectedMap._none = nil end

                local wantOn = readShovelEnabled()
                if countShovelSelected(selectedMap) < 1 then
                    wantOn = false
                    writeShovelState(false, selectedMap)
                    persistShovelPlants(selectedMap)
                    applyShovelRuntime(false)
                    if shovelToggleApi and type(shovelToggleApi.set) == "function" then
                        shovelToggleApi.set(false, true)
                    end
                else
                    writeShovelState(wantOn, selectedMap)
                    persistShovelPlants(selectedMap)
                    applyShovelRuntime(wantOn)
                end
                refreshShovelStatus()
            end,
        })

        ui:CreateRowInput(
            bodyShovel,
            "Plant Height (- below / + above)",
            tostring(shovelHeightRule or "0"),
            function(txt)
                persistShovelHeightRule(txt)
                refreshShovelStatus()
            end,
            false
        )

        G.__GAG2_SHOVEL_DROPDOWN = shovelDropdownApi
        _G.__GAG2_SHOVEL_DROPDOWN = shovelDropdownApi

        G.__GAG2_ON_SHOVEL_PLANTS_CHANGED = function()
            if shovelDropdownApi and type(shovelDropdownApi.refreshItems) == "function" then
                shovelDropdownApi.refreshItems()
            end
            refreshShovelStatus()
        end
        _G.__GAG2_ON_SHOVEL_PLANTS_CHANGED = G.__GAG2_ON_SHOVEL_PLANTS_CHANGED

        refreshShovelStatus()
        task.spawn(function()
            while bodyShovel and bodyShovel.Parent do
                task.wait(readShovelEnabled() and 1.2 or 3)
                pcall(refreshShovelStatus)
            end
        end)

        local _, _, shovelToggleApi = ui:CreateRowToggle(
            bodyShovel,
            "Enable Auto Shovel Plant",
            shovelOn,
            function(isOn)
                if isOn == true and countShovelSelected() < 1 then
                    warn("[GAG2] Auto Shovel Plant: pilih minimal 1 plant dulu")
                    if shovelToggleApi and type(shovelToggleApi.set) == "function" then
                        shovelToggleApi.set(false, true)
                    end
                    writeShovelState(false, readShovelPlantsSelected())
                    persistShovelState()
                    applyShovelRuntime(false)
                    refreshShovelStatus()
                    return
                end
                writeShovelState(isOn == true, readShovelPlantsSelected())
                persistShovelState()
                applyShovelRuntime(isOn == true)
                refreshShovelStatus()
            end
        )

        if shovelToggleApi and type(shovelToggleApi.set) == "function" then
            shovelToggleApi.set(readShovelEnabled(), true)
        end

        applyShovelRuntime(readShovelEnabled())
        refreshShovelStatus()

        do
            local SectionShovelFruit = G.SectionAutoShovelFruit or rawget(_G, "SectionAutoShovelFruit")
            if type(SectionShovelFruit) == "table" and type(SectionShovelFruit.Register) == "function" then
                pcall(SectionShovelFruit.Register, {
                    ui = ui,
                    getAuto = getAuto,
                    patchAuto = patchAuto,
                    patchAutoOnly = patchAutoOnly,
                    registerFlush = registerFlush,
                    cleanSelectedMap = cleanSelectedMap,
                    arrayToMap = arrayToMap,
                    mapToArray = mapToArray,
                    toggleApiGet = toggleApiGet,
                    PlantListView = PlantListView,
                })
            else
                warn("[GAG2] SectionAutoShovelFruit tidak ditemukan â€” upload section_auto_shovel_fruit.lua")
            end
        end

        ----------------------------------------------------------------
        -- Auto Teleport Garden (di atas Auto Claim Seed)
        ----------------------------------------------------------------
        local TELE_LOC_ITEMS = {
            { key = "center", name = "Garden Center" },
            { key = "spawn", name = "Garden Spawn" },
        }

        local TELE_MODE_ITEMS = {
            { key = "normal", name = "Normal" },
            { key = "underground", name = "Underground" },
        }

        local function normalizeTeleLoc(v)
            if tostring(v or "") == "spawn" then return "spawn" end
            return "center"
        end

        local function normalizeTeleMode(v)
            if tostring(v or "") == "underground" then return "underground" end
            return "normal"
        end

        local TELE = getAuto("autoTele")
        TELE.enabled = (TELE.enabled == true)
        TELE.delay = tonumber(TELE.delay) or 10
        if TELE.delay < 1 then TELE.delay = 1 end
        TELE.selectedLocation = normalizeTeleLoc(TELE.selectedLocation)
        TELE.mode = normalizeTeleMode(TELE.mode)
        local teleOn = (TELE.enabled == true)
        writeAutoTeleToMain()

        registerFlush("autoTele", function()
            local on = toggleApiGet("__GAG2_TELE_ENABLE_TOGGLE_API")
            patchAutoOnly("autoTele", {
                enabled = on ~= nil and on or (TELE.enabled == true),
                delay = TELE.delay,
                selectedLocation = TELE.selectedLocation,
                mode = TELE.mode,
            })
        end)

        local bodyAutoTele = ui:CreateSection("Auto Teleport Garden", false)

        _, teleModeDropdownApi = ui:CreateRowDropdown(bodyAutoTele, {
            label       = "Mode",
            placeholder = "Normal",
            mode        = "single",
            getItems = function() return TELE_MODE_ITEMS end,
            initial = TELE.mode,
            onChanged = function(_, selectedKey)
                TELE.mode = normalizeTeleMode(selectedKey)
                writeAutoTeleToMain()
                patchAuto("autoTele", { mode = TELE.mode }, restartAutoTeleIfOn)
            end,
        })

        _, teleLocDropdownApi = ui:CreateRowDropdown(bodyAutoTele, {
            label       = "Location",
            placeholder = "Garden Center",
            mode        = "single",
            getItems = function() return TELE_LOC_ITEMS end,
            initial = TELE.selectedLocation,
            onChanged = function(_, selectedKey)
                TELE.selectedLocation = normalizeTeleLoc(selectedKey)
                patchAuto("autoTele", { selectedLocation = TELE.selectedLocation }, restartAutoTeleIfOn)
            end,
        })

        ui:CreateRowInput(
            bodyAutoTele,
            "Check Delay (sec)",
            tostring(TELE.delay),
            function(txt)
                local n = tonumber(txt)
                if n == nil or n < 1 then return end
                TELE.delay = n
                patchAuto("autoTele", { delay = n }, restartAutoTeleIfOn)
            end,
            false
        )

        local _, _, teleEnableToggleApi = ui:CreateRowToggle(
            bodyAutoTele,
            "Enable Auto Teleport Garden",
            teleOn,
            function(isOn)
                TELE.enabled = (isOn == true)
                patchAuto("autoTele", { enabled = isOn == true }, function()
                    applyAutoTeleRuntime(isOn == true)
                end)
            end
        )
        G.__GAG2_TELE_ENABLE_TOGGLE_API = teleEnableToggleApi
        _G.__GAG2_TELE_ENABLE_TOGGLE_API = teleEnableToggleApi

        if teleEnableToggleApi and type(teleEnableToggleApi.set) == "function" then
            teleEnableToggleApi.set(teleOn, true)
        end

        syncAutoTeleAll()

        ----------------------------------------------------------------
        -- Auto Claim Seed (toggle ÃƒÂ¢Ã¢â€šÂ¬Ã¢â‚¬Â teleport + ClickPack)
        ----------------------------------------------------------------
        local claimOn = readClaimSeedEnabled()

        local bodyClaimSeed = ui:CreateSection("Auto Claim Seed", false)

        local _, _, claimToggleApi = ui:CreateRowToggle(
            bodyClaimSeed,
            "Enable Auto Claim Seed",
            claimOn,
            function(isOn)
                local on = (isOn == true)
                patchAuto("claimSeed", { enabled = on }, function()
                    _syncClaimSeedGlobals(on)
                    applyClaimSeedModuleOnly(on)
                end)
            end
        )
        G.__GAG2_CLAIM_SEED_TOGGLE_API = claimToggleApi
        _G.__GAG2_CLAIM_SEED_TOGGLE_API = claimToggleApi

        if claimToggleApi and type(claimToggleApi.set) == "function" then
            claimToggleApi.set(claimOn, true)
        end

        applyClaimSeedModuleOnly(claimOn)
    end, 1)

