    ui:RegisterSubTab("auto", "buy", "Buy", function()
        local MAIN = ensureMain()

        MAIN.auto = MAIN.auto or {}
        MAIN.auto.buy = MAIN.auto.buy or {}

        local BUY_STATE = getAuto("buy")
        BUY_STATE.seed = type(BUY_STATE.seed) == "table" and BUY_STATE.seed or { enabled = false, items = {} }
        BUY_STATE.gear = type(BUY_STATE.gear) == "table" and BUY_STATE.gear or { enabled = false, items = {} }
        BUY_STATE.props = type(BUY_STATE.props) == "table" and BUY_STATE.props or { enabled = false, items = {} }

        BUY_STATE.seed.enabled = (BUY_STATE.seed.enabled == true)
        BUY_STATE.gear.enabled = (BUY_STATE.gear.enabled == true)
        BUY_STATE.props.enabled = (BUY_STATE.props.enabled == true)
        BUY_STATE.seed.items = type(BUY_STATE.seed.items) == "table" and BUY_STATE.seed.items or {}
        BUY_STATE.gear.items = type(BUY_STATE.gear.items) == "table" and BUY_STATE.gear.items or {}
        BUY_STATE.props.items = type(BUY_STATE.props.items) == "table" and BUY_STATE.props.items or {}

        local BUY_SEED_SELECTED = cleanSelectedMap(arrayToMap(BUY_STATE.seed.items))
        local BUY_GEAR_SELECTED = cleanSelectedMap(arrayToMap(BUY_STATE.gear.items))
        local BUY_PROPS_SELECTED = cleanSelectedMap(arrayToMap(BUY_STATE.props.items))

        local AUTO_BUY_SEED_ENABLED = BUY_STATE.seed.enabled
        local AUTO_BUY_GEAR_ENABLED = BUY_STATE.gear.enabled
        local AUTO_BUY_PROPS_ENABLED = BUY_STATE.props.enabled

        local PET_STORE = syncBuyPetStoreFromMain()
        writeBuyPetToMain()

        local ShopListView = G.ShopListView
        local PetListView = G.PetListView

        local function writeBuyGlobals()
            if type(G.__GAG2_FLUSH_BUY_AUCTION) == "function" then
                pcall(G.__GAG2_FLUSH_BUY_AUCTION)
            end

            local seedApi = G.__GAG2_BUY_SEED_ENABLE_API or rawget(_G, "__GAG2_BUY_SEED_ENABLE_API")
            local gearApi = G.__GAG2_BUY_GEAR_ENABLE_API or rawget(_G, "__GAG2_BUY_GEAR_ENABLE_API")
            local propsApi = G.__GAG2_BUY_PROPS_ENABLE_API or rawget(_G, "__GAG2_BUY_PROPS_ENABLE_API")
            if type(seedApi) == "table" and type(seedApi.get) == "function" then
                BUY_STATE.seed.enabled = (seedApi.get() == true)
            end
            if type(gearApi) == "table" and type(gearApi.get) == "function" then
                BUY_STATE.gear.enabled = (gearApi.get() == true)
            end
            if type(propsApi) == "table" and type(propsApi.get) == "function" then
                BUY_STATE.props.enabled = (propsApi.get() == true)
            end

            local main = ensureMain()
            if type(main) ~= "table" then return end
            main.auto = main.auto or {}
            main.auto.buy = main.auto.buy or {}
            local buy = main.auto.buy

            buy.seed = type(buy.seed) == "table" and buy.seed or { enabled = false, items = {} }
            buy.gear = type(buy.gear) == "table" and buy.gear or { enabled = false, items = {} }
            buy.props = type(buy.props) == "table" and buy.props or { enabled = false, items = {} }

            buy.seed.enabled = (BUY_STATE.seed.enabled == true)
            buy.gear.enabled = (BUY_STATE.gear.enabled == true)
            buy.props.enabled = (BUY_STATE.props.enabled == true)
            buy.seed.items = mapToArray(BUY_SEED_SELECTED)
            buy.gear.items = mapToArray(BUY_GEAR_SELECTED)
            buy.props.items = mapToArray(BUY_PROPS_SELECTED)

            writeBuyPetToMain()
            buy.pet = type(main.auto.buy.pet) == "table" and main.auto.buy.pet or buy.pet

            patchAutoOnly("buy", {
                seed = { enabled = buy.seed.enabled, items = buy.seed.items },
                gear = { enabled = buy.gear.enabled, items = buy.gear.items },
                props = { enabled = buy.props.enabled, items = buy.props.items },
                pet = {
                    enabled = buy.pet.enabled,
                    auto_tame = buy.pet.auto_tame,
                    max_steal_price = buy.pet.max_steal_price,
                    items = type(buy.pet.items) == "table" and buy.pet.items or {},
                },
            })

            G.AUTO_BUY_SEED_ENABLED = buy.seed.enabled
            _G.AUTO_BUY_SEED_ENABLED = buy.seed.enabled
            G.AUTO_BUY_GEAR_ENABLED = buy.gear.enabled
            _G.AUTO_BUY_GEAR_ENABLED = buy.gear.enabled
            G.AUTO_BUY_PROPS_ENABLED = buy.props.enabled
            _G.AUTO_BUY_PROPS_ENABLED = buy.props.enabled

            G.BUY_SEED_SELECTED = BUY_SEED_SELECTED
            _G.BUY_SEED_SELECTED = BUY_SEED_SELECTED
            G.BUY_GEAR_SELECTED = BUY_GEAR_SELECTED
            _G.BUY_GEAR_SELECTED = BUY_GEAR_SELECTED
            G.BUY_PROPS_SELECTED = BUY_PROPS_SELECTED
            _G.BUY_PROPS_SELECTED = BUY_PROPS_SELECTED

            G.MAIN = main
            _G.MAIN = main
            MAIN = main
            BUY_STATE = buy
        end
        G.__GAG2_PUSH_BUY = writeBuyGlobals
        _G.__GAG2_PUSH_BUY = writeBuyGlobals

        registerFlush("buy", function()
            writeBuyGlobals()
        end)

        local function getAutoBuy()
            return G.AutoBuyModule or G.AutoBuy or _G.AutoBuyModule or _G.AutoBuy
        end

        local function syncAutoBuyModule()
            writeBuyGlobals()

            local ab = getAutoBuy()
            if type(ab) ~= "table" then return end

            local function __call(fn, ...)
                if type(ab[fn]) == "function" then
                    pcall(ab[fn], ab, ...)
                end
            end

            __call("SetSelected", "seed", BUY_SEED_SELECTED)
            __call("SetSelected", "gear", BUY_GEAR_SELECTED)
            __call("SetSelected", "props", BUY_PROPS_SELECTED)

            if BUY_STATE.seed.enabled then
                __call("SetEnabled", "seed", true)
            else
                __call("SetEnabled", "seed", false)
            end
            if BUY_STATE.gear.enabled then
                __call("SetEnabled", "gear", true)
            else
                __call("SetEnabled", "gear", false)
            end
            if BUY_STATE.props.enabled then
                __call("SetEnabled", "props", true)
            else
                __call("SetEnabled", "props", false)
            end

            __call("SyncFromGlobals")

            local anyOn = BUY_STATE.seed.enabled or BUY_STATE.gear.enabled or BUY_STATE.props.enabled
            if anyOn then
                __call("Start")
                __call("start")
            else
                __call("Stop")
                __call("stop")
            end
        end

        G.__GAG2_SYNC_AUTO_BUY = syncAutoBuyModule

        local bodySeed = ui:CreateSection("Auto Buy Seed", true)
        local bodyGear = ui:CreateSection("Auto Buy Gear", false)
        local bodyProps = ui:CreateSection("Auto Buy Props", false)

        local BUY_LIST_SORT = { sortBy = "rarity" }

        ui:CreateRowDropdown(bodySeed, {
            label       = "Select Seed",
            placeholder = "Select Seed...",
            mode        = "multi",
            preserveItemOrder = true,
            deferItemLoad = true,
            getItems = function()
                if PlantListView and type(PlantListView.buildSeedItems) == "function" then
                    return PlantListView.buildSeedItems(BUY_LIST_SORT) or {}
                end
                local ab = getAutoBuy()
                if type(ab) == "table" and type(ab.GetLists) == "function" then
                    local ok, seeds = pcall(ab.GetLists, ab)
                    if ok then return seeds or {} end
                end
                return {}
            end,
            initial = BUY_SEED_SELECTED,
            onChanged = function(_, selectedMap)
                BUY_SEED_SELECTED = cleanSelectedMap(selectedMap)
                patchAuto("buy", { seed = { items = mapToArray(BUY_SEED_SELECTED) } }, syncAutoBuyModule)
            end,
        })

        local _, _, seedEnableApi = ui:CreateRowToggle(bodySeed, "Enable Auto Buy Seed", AUTO_BUY_SEED_ENABLED, function(isOn)
            BUY_STATE.seed.enabled = (isOn == true)
            AUTO_BUY_SEED_ENABLED = BUY_STATE.seed.enabled
            patchAuto("buy", { seed = { enabled = isOn == true } }, syncAutoBuyModule)
        end)
        G.__GAG2_BUY_SEED_ENABLE_API = seedEnableApi
        _G.__GAG2_BUY_SEED_ENABLE_API = seedEnableApi

        ui:CreateRowDropdown(bodyGear, {
            label       = "Select Gear",
            placeholder = "Select Gear...",
            mode        = "multi",
            preserveItemOrder = true,
            deferItemLoad = true,
            getItems = function()
                if ShopListView and type(ShopListView.buildGearItems) == "function" then
                    return ShopListView.buildGearItems(BUY_LIST_SORT) or {}
                end
                local ab = getAutoBuy()
                if type(ab) == "table" and type(ab.GetLists) == "function" then
                    local ok, _, gears = pcall(ab.GetLists, ab)
                    if ok then return gears or {} end
                end
                return {}
            end,
            initial = BUY_GEAR_SELECTED,
            onChanged = function(_, selectedMap)
                BUY_GEAR_SELECTED = cleanSelectedMap(selectedMap)
                patchAuto("buy", { gear = { items = mapToArray(BUY_GEAR_SELECTED) } }, syncAutoBuyModule)
            end,
        })

        local _, _, gearEnableApi = ui:CreateRowToggle(bodyGear, "Enable Auto Buy Gear", AUTO_BUY_GEAR_ENABLED, function(isOn)
            BUY_STATE.gear.enabled = (isOn == true)
            AUTO_BUY_GEAR_ENABLED = BUY_STATE.gear.enabled
            patchAuto("buy", { gear = { enabled = isOn == true } }, syncAutoBuyModule)
        end)
        G.__GAG2_BUY_GEAR_ENABLE_API = gearEnableApi
        _G.__GAG2_BUY_GEAR_ENABLE_API = gearEnableApi

        ui:CreateRowDropdown(bodyProps, {
            label       = "Select Crate",
            placeholder = "Select Crate...",
            mode        = "multi",
            preserveItemOrder = true,
            deferItemLoad = true,
            getItems = function()
                if ShopListView and type(ShopListView.buildPropsItems) == "function" then
                    return ShopListView.buildPropsItems(BUY_LIST_SORT) or {}
                end
                local ab = getAutoBuy()
                if type(ab) == "table" and type(ab.GetLists) == "function" then
                    local ok, _, _, props = pcall(ab.GetLists, ab)
                    if ok then return props or {} end
                end
                return {}
            end,
            initial = BUY_PROPS_SELECTED,
            onChanged = function(_, selectedMap)
                BUY_PROPS_SELECTED = cleanSelectedMap(selectedMap)
                patchAuto("buy", { props = { items = mapToArray(BUY_PROPS_SELECTED) } }, syncAutoBuyModule)
            end,
        })

        local _, _, propsEnableApi = ui:CreateRowToggle(bodyProps, "Enable Auto Buy Props", AUTO_BUY_PROPS_ENABLED, function(isOn)
            BUY_STATE.props.enabled = (isOn == true)
            AUTO_BUY_PROPS_ENABLED = BUY_STATE.props.enabled
            patchAuto("buy", { props = { enabled = isOn == true } }, syncAutoBuyModule)
        end)
        G.__GAG2_BUY_PROPS_ENABLE_API = propsEnableApi
