            _G.__GAG2_AUTO_DROP_ACTIVE_CAT = G.__GAG2_AUTO_DROP_ACTIVE_CAT
        end

        local restoreGiftUi = G.__GAG2_RESTORE_GIFT_CATEGORY_UI or rawget(_G, "__GAG2_RESTORE_GIFT_CATEGORY_UI")
        if type(restoreGiftUi) == "function" then
            pcall(restoreGiftUi)
        end

        clearDropdownApi("__GAG2_SHOVEL_DROPDOWN")
    end

    G.__GAG2_AUTO_TAB_CTX = {
        ui               = ui,
        getAuto          = getAuto,
        patchAuto        = patchAuto,
        patchAutoOnly    = patchAutoOnly,
        registerFlush    = registerFlush,
        cleanSelectedMap = cleanSelectedMap,
