    _G.__GAG2_AUTO_TAB_CTX = G.__GAG2_AUTO_TAB_CTX

    local prevApplyUiDefaults = G.__GAG2_APPLY_UI_DEFAULTS
    G.__GAG2_APPLY_UI_DEFAULTS = function()
        if type(prevApplyUiDefaults) == "function" then
            pcall(prevApplyUiDefaults)
        end
        applyAutoUiDefaults()
    end
    _G.__GAG2_APPLY_UI_DEFAULTS = G.__GAG2_APPLY_UI_DEFAULTS
end

return M
 end,                      required = true },
    { key = "PlantListView",           name = "PlantListView",           factory = function() -- PlantListView.lua — Grow A Garden 2
-- Katalog seed/fruit dari SharedModules.SeedData
-- Owned seeds untuk Auto Plant: sama seperti Auto Gift (BuildInventoryItems "Seeds")

local ReplicatedStorage = game:GetService("ReplicatedStorage")

local G = (getgenv and getgenv()) or _G

local SharedModules = ReplicatedStorage:WaitForChild("SharedModules")
local SeedDataModule = SharedModules:WaitForChild("SeedData")
local MutationDataModule = SharedModules:WaitForChild("MutationData")

local M = {}

local _catalogCache = nil
local _mutationCache = nil
local _sourceTag = "SharedModules.SeedData"

----------------------------------------------------------------
-- catalog (shop / collect — bukan inventory player)
----------------------------------------------------------------
local function _safeRequire(inst)
    if not inst or not inst:IsA("ModuleScript") then return nil end
    local ok, mod = pcall(require, inst)
    if ok then return mod end
    return nil
end

local function _normalizeSeedEntry(entry, keyHint)
    if type(entry) ~= "table" then return nil end
    local seedName = entry.SeedName or entry.Name or keyHint
    if not seedName or tostring(seedName) == "" then return nil end
    return {
        SeedName             = tostring(seedName),
        Rarity               = entry.Rarity,
        RestockShop          = entry.RestockShop,
        IsSingleHarvest      = entry.IsSingleHarvest,
        MutationSeed         = (entry.MutationSeed == true),
        PurchasePrice        = entry.PurchasePrice,
        SeedShopDisplayOrder = entry.SeedShopDisplayOrder,
        raw                  = entry,
    }
end

local function _mergeSeedData(into, seedData)
    if type(seedData) ~= "table" then return end
    local function add(entry, keyHint)
        local norm = _normalizeSeedEntry(entry, keyHint)
        if norm then into[norm.SeedName] = norm end
    end
    if #seedData > 0 then
        for _, entry in ipairs(seedData) do add(entry) end
        return
    end
    for key, entry in pairs(seedData) do
        if type(entry) == "table" then add(entry, key) end
    end
end

local function _loadCatalogFromGame()
    local merged = {}
    local seedData = _safeRequire(SeedDataModule)
    if type(seedData) ~= "table" then
        _sourceTag = "SharedModules.SeedData (error)"
        return merged
    end
    _mergeSeedData(merged, seedData)
    _sourceTag = "SharedModules.SeedData"
    return merged
end

local function _getCatalogMap()
    if _catalogCache then return _catalogCache end
    _catalogCache = _loadCatalogFromGame()
    return _catalogCache
end

local function _catalogToSortedArray(map, opts)
    opts = opts or {}
    local out = {}
    for _, info in pairs(map) do
        if opts.includeMutationSeeds or not info.MutationSeed then
            out[#out + 1] = info
        end
    end
    table.sort(out, function(a, b)
        local oa = tonumber(a.SeedShopDisplayOrder) or 9999
        local ob = tonumber(b.SeedShopDisplayOrder) or 9999
        if oa ~= ob then return oa < ob end
        return tostring(a.SeedName) < tostring(b.SeedName)
    end)
    return out
end

local function _toDropdownItems(entries)
    local out = {}
    for _, info in ipairs(entries) do
        out[#out + 1] = {
            key   = info.SeedName,
            name  = info.SeedName,
            right = info.Rarity,
            raw   = info,
        }
    end
    return out
end

local function _itemRarityAndPrice(it)
    local raw = type(it) == "table" and type(it.raw) == "table" and it.raw or {}
    local nested = type(raw.raw) == "table" and raw.raw or {}
    local rarity = raw.Rarity or raw.rarity or nested.Rarity or nested.rarity
    if (not rarity or tostring(rarity) == "") and type(it.right) == "string" then
        rarity = it.right:match("^(.-)%s*·") or it.right
        rarity = tostring(rarity):gsub("%s+$", "")
    end
    local price = tonumber(
        raw.PurchasePrice or raw.price or raw.Cost or raw.Price or raw.FallbackPrice
            or nested.PurchasePrice or nested.price or nested.Cost or nested.Price
    ) or 0
    return tostring(rarity or ""), price
end

local function _gameRarityRank(rarityName)
    local FSV = G.FruitSellValue or rawget(_G, "FruitSellValue")
    if type(FSV) == "table" and type(FSV.getRarityRank) == "function" then
        local ok, rank = pcall(FSV.getRarityRank, FSV, rarityName)
        if ok and type(rank) == "number" and rank > 0 then
            return rank
        end
    end
    return 0
end

function M.sortDropdownByRarity(items)
    if type(items) ~= "table" or #items < 2 then return items end

    local rarityMaxPrice = {}
    for _, it in ipairs(items) do
        local rarity, price = _itemRarityAndPrice(it)
        if rarity ~= "" then
            rarityMaxPrice[rarity] = math.max(rarityMaxPrice[rarity] or 0, price)
        end
    end

    local tiers = {}
    for rarity, price in pairs(rarityMaxPrice) do
        tiers[#tiers + 1] = { rarity = rarity, price = price }
    end
    table.sort(tiers, function(a, b)
        local ra = _gameRarityRank(a.rarity)
        local rb = _gameRarityRank(b.rarity)
        if ra ~= rb then
            if ra > 0 and rb > 0 then return ra > rb end
            if ra > 0 then return true end
            if rb > 0 then return false end
        end
        if a.price ~= b.price then return a.price > b.price end
        return tostring(a.rarity) < tostring(b.rarity)
    end)

    local rank = {}
    local total = #tiers
    for i, item in ipairs(tiers) do
        local gameRank = _gameRarityRank(item.rarity)
        rank[item.rarity] = (gameRank > 0) and gameRank or (total - i + 1)
    end

    table.sort(items, function(a, b)
        local ra = rank[select(1, _itemRarityAndPrice(a))] or 0
        local rb = rank[select(1, _itemRarityAndPrice(b))] or 0
        if ra ~= rb then return ra > rb end
        local pa = select(2, _itemRarityAndPrice(a))
        local pb = select(2, _itemRarityAndPrice(b))
        if pa ~= pb then return pa > pb end
        return tostring(a.name or a.key) < tostring(b.name or b.key)
    end)

    for i, it in ipairs(items) do
        it.sort = i
        it.order = i
    end
    return items
end

local function _maybeSortDropdown(items, opts)
    if not (type(opts) == "table" and tostring(opts.sortBy or ""):lower() == "rarity") then
        return items
    end
    local out = {}
    for i, it in ipairs(items) do
        out[i] = it
    end
    return M.sortDropdownByRarity(out)
end

----------------------------------------------------------------
-- owned seeds — cache dari tabs_auto (AutoGift dipanggil async, tidak saat load)
----------------------------------------------------------------
local function _cachedOwnedItems()
    local cached = G.__GAG2_PLANT_SEED_LIST_CACHE or rawget(_G, "__GAG2_PLANT_SEED_LIST_CACHE")
    if type(cached) == "table" then return cached end
    return {}
end

local function _canonSeedName(s)
    s = tostring(s or ""):lower():gsub("[^%w]+", "")
    if s:sub(-4) == "seed" then s = s:sub(1, -5) end
    return s
end

local function _itemDisplayName(it)
    local name = tostring(it.key or "")
    if name == "" and type(it.name) == "string" then
        name = it.name:match("^(.-)%s+x%s+") or it.name
    end
    return name
end

local function _itemCount(it)
    local n = tonumber(it.count) or tonumber(it.right)
    if n then return math.max(0, math.floor(n)) end
    if type(it.name) == "string" then
        local tail = it.name:match("%s+x%s+(.+)$")
        if tail then
            tail = tail:gsub(",", "")
            if tail:sub(-1) == "K" then
                return math.max(0, math.floor((tonumber(tail:sub(1, -2)) or 0) * 1000))
            end
            if tail:sub(-1) == "M" then
                return math.max(0, math.floor((tonumber(tail:sub(1, -2)) or 0) * 1000000))
            end
            return math.max(0, math.floor(tonumber(tail) or 0))
        end
    end
    return 0
end

local function _matchesSeedSelection(name, selectedMap)
    if type(selectedMap) ~= "table" or not next(selectedMap) then return true end
    local key = _canonSeedName(name)
    if key == "" then return false end
    for sel, on in pairs(selectedMap) do
        if on == true then
            local sk = _canonSeedName(sel)
            if sk ~= "" and (key == sk or key:find(sk, 1, true) or sk:find(key, 1, true)) then
                return true
            end
        end
    end
    return false
end

local function _ownedSeedItems(_forceRefresh)
    return _cachedOwnedItems()
end

local _mutationApi = nil
local _mutationApiTried = false

local function _mutationDataApi()
    if _mutationApiTried then return _mutationApi end
    _mutationApiTried = true
    local mod = _safeRequire(MutationDataModule)
    if type(mod) == "table" then
        _mutationApi = mod
    end
    return _mutationApi
end

local function _fmtPriceMulti(m)
    m = tonumber(m)
    if not m or m <= 0 then return nil end
    if math.abs(m - math.floor(m + 0.5)) < 1e-6 then
        return "x" .. tostring(math.floor(m + 0.5))
    end
    return "x" .. string.format("%.4g", m)
end

local function _priceMultiplierFor(name)
    name = tostring(name or "")
    if name == "" then return nil end
    local api = _mutationDataApi()
    if type(api) == "table" and type(api.ReturnPriceMultiplier) == "function" then
        local ok, multi = pcall(api.ReturnPriceMultiplier, name)
        if ok then
            multi = tonumber(multi)
            if multi and multi > 0 then return multi end
        end
    end
    local child = MutationDataModule:FindFirstChild(name)
    local mod = _safeRequire(child)
    if type(mod) == "table" then
        local multi = tonumber(mod.PriceMultiplier)
        if multi and multi > 0 then return multi end
    end
    return nil
end

local function _loadMutationNames()
    if _mutationCache then return _mutationCache end
    local names = {}
    for _, child in ipairs(MutationDataModule:GetChildren()) do
        if child:IsA("ModuleScript") and child.Name ~= "" then
            names[child.Name] = true
        end
    end
    local arr = {}
    for n in pairs(names) do arr[#arr + 1] = n end
    table.sort(arr)
    _mutationCache = arr
    return _mutationCache
end

----------------------------------------------------------------
-- public API
----------------------------------------------------------------
function M.getSourceTag()
    _getCatalogMap()
    return _sourceTag
end

function M.refresh()
    _catalogCache = nil
    _mutationCache = nil
    _mutationApi = nil
    _mutationApiTried = false
    return M.getSourceTag()
end

function M.getCatalogMap()
    return _getCatalogMap()
end

function M.getCatalog(opts)
    return _catalogToSortedArray(_getCatalogMap(), opts or {})
end

function M.findBySeedName(name)
    if not name then return nil end
    return _getCatalogMap()[tostring(name)]
end

function M.buildSeedItems(opts)
    local items = _toDropdownItems(_catalogToSortedArray(_getCatalogMap(), { includeMutationSeeds = true }))
    return _maybeSortDropdown(items, opts)
end

function M.buildFruitItems()
    return _toDropdownItems(_catalogToSortedArray(_getCatalogMap(), { includeMutationSeeds = false }))
end

function M.buildSeedItemsForCollect()
    return M.buildFruitItems()
end

--- Auto Plant dropdown — inventory player via AutoGift (category Seeds)
function M.buildPlantSeedItems()
    return _ownedSeedItems(false)
end

function M.countOwnedSeeds(selectedMap)
    selectedMap = type(selectedMap) == "table" and selectedMap or {}
    local sum = 0
    for _, it in ipairs(_ownedSeedItems(false)) do
        local name = _itemDisplayName(it)
        if _matchesSeedSelection(name, selectedMap) then
            sum += _itemCount(it)
        end
    end
    return sum
end

function M.getOwnedSeedCounts()
    local out = {}
    for _, it in ipairs(_ownedSeedItems(false)) do
        local name = _itemDisplayName(it)
        if name ~= "" then
            out[name] = _itemCount(it)
        end
    end
    return out
end

function M.refreshOwnedSeeds()
    return _cachedOwnedItems()
end

function M.listOwnedSeedNames()
    local names = {}
    for _, it in ipairs(_ownedSeedItems(false)) do
        local name = _itemDisplayName(it)
        if name ~= "" then names[#names + 1] = name end
    end
    return names
end

function M.listMutationNames()
    return _loadMutationNames()
end

function M.getMutationMultiplier(name)
    return _priceMultiplierFor(name)
end

function M.formatMutationLabel(name)
    name = tostring(name or "")
    if name == "" then return "" end
    local multi = _priceMultiplierFor(name)
    local tag = _fmtPriceMulti(multi)
    if tag then
        return name .. " (" .. tag .. ")"
    end
    return name
end

function M.listFruitMutations()
    local out = {}
    for _, name in ipairs(_loadMutationNames()) do
        local multi = _priceMultiplierFor(name)
        out[#out + 1] = {
            key = name, -- selection/filter tetap nama asli
            name = M.formatMutationLabel(name),
            multi = multi,
        }
    end
    table.sort(out, function(a, b)
        local am = tonumber(a.multi) or 0
        local bm = tonumber(b.multi) or 0
        if am ~= bm then return am > bm end
        return tostring(a.key) < tostring(b.key)
    end)
    return out
end

function M.listMutations()
    return M.listFruitMutations()
end

G.PlantListView = M
_G.PlantListView = M

return M
 end,                  required = false },
    { key = "FruitSellValue",          name = "FruitSellValue",          factory = function() -- FruitSellValue.lua — harga jual buah (100% dari module game)
-- Sumber: SharedModules.FruitValueCalc, SellValueData, SeedData, MutationData
-- Tidak ada hardcode harga/rarity — ikut update game otomatis.

local Players           = game:GetService("Players")
local ReplicatedStorage = game:GetService("ReplicatedStorage")

local M = {}

local LP = Players.LocalPlayer
local G  = (getgenv and getgenv()) or _G

local SharedModules = ReplicatedStorage:WaitForChild("SharedModules", 15)

local function _requireChild(name)
    if not SharedModules then return nil end
    local inst = SharedModules:FindFirstChild(name)
    if inst and inst:IsA("ModuleScript") then
        local ok, mod = pcall(require, inst)
        if ok then return mod end
    end
    return nil
end

local _calcFn       = nil
local _sellFlagsMod = nil
local _seedByName   = {} -- [SeedName] = entry SeedData
local _rarityRank   = {} -- [Rarity string] = rank (dari PurchasePrice game)
local _lastRefresh  = 0
local REFRESH_SEC   = 30
local _fruitViz   = nil
local _fruitVizAt = 0
local VIZ_CACHE_SEC = 30
local _getFruitBidFn = nil
local _bidCache = {}
local BID_CACHE_SEC = 45
local FRIEND_BOOST_PER_FRIEND = 0.1

local _noFriendCalcInst = {
    GetAttribute = function(_, attr)
        if attr == "Friends" then return 0 end
        if LP then return LP:GetAttribute(attr) end
        return nil
    end,
}

local function _friendBoostMultiplier(friendCount)
    if friendCount == nil then
        friendCount = LP and LP:GetAttribute("Friends") or 0
    end
    friendCount = tonumber(friendCount) or 0
    return 1 + friendCount * FRIEND_BOOST_PER_FRIEND
end

local function _stripFriendBoost(price, friendCount)
    price = tonumber(price) or 0
    if price <= 0 then return 0 end
    local mult = _friendBoostMultiplier(friendCount)
    if mult <= 1 then return price end
    return math.floor(price / mult + 0.5)
end

local function _includesFriendBoost()
    return G.FRUIT_PRICE_INCLUDE_FRIEND_BOOST == true
        or rawget(_G, "FRUIT_PRICE_INCLUDE_FRIEND_BOOST") == true
end

function M.includesFriendBoost()
    return _includesFriendBoost()
end

function M.setIncludeFriendBoost(on)
    on = (on == true)
    G.FRUIT_PRICE_INCLUDE_FRIEND_BOOST = on
    _G.FRUIT_PRICE_INCLUDE_FRIEND_BOOST = on
    M.clearBidCache()
end

function M.getEspPriceMode()
    local mode = G.FRUIT_BACKPACK_ESP_PRICE_MODE or rawget(_G, "FRUIT_BACKPACK_ESP_PRICE_MODE")
    if mode == nil then
        local MAIN = G.MAIN or rawget(_G, "MAIN")
        local st = MAIN and MAIN.misc and MAIN.misc.fruit_backpack_esp
        if type(st) == "table" then
            mode = st.price_mode
        end
    end
    if tostring(mode or ""):lower() == "stock" then
        return "stock"
    end
    return "base"
end

function M.setEspPriceMode(mode)
    mode = (tostring(mode or ""):lower() == "stock") and "stock" or "base"
    G.FRUIT_BACKPACK_ESP_PRICE_MODE = mode
    _G.FRUIT_BACKPACK_ESP_PRICE_MODE = mode
    G.FRUIT_PRICE_INCLUDE_FRIEND_BOOST = (mode == "stock")
    _G.FRUIT_PRICE_INCLUDE_FRIEND_BOOST = (mode == "stock")
    M.clearBidCache()
end

local function _ensureSellFlagsMod()
    if _sellFlagsMod == false then
        return nil
    end
    if type(_sellFlagsMod) == "table" then
        return _sellFlagsMod
    end
    if not SharedModules then return nil end

    local candidates = {}
    local flagsRoot = SharedModules:FindFirstChild("Flags")
    if flagsRoot then
        local inst = flagsRoot:FindFirstChild("SellFlags")
        if inst then candidates[#candidates + 1] = inst end
    end
    local direct = SharedModules:FindFirstChild("SellFlags")
    if direct then candidates[#candidates + 1] = direct end

    for _, inst in ipairs(candidates) do
        if inst:IsA("ModuleScript") then
            local ok, mod = pcall(require, inst)
            if ok and type(mod) == "table" then
                _sellFlagsMod = mod
                return _sellFlagsMod
            end
        end
    end

    if flagsRoot then
        for _, inst in ipairs(flagsRoot:GetChildren()) do
            if inst:IsA("ModuleScript") then
                local n = inst.Name:lower()
                if n:find("sell", 1, true) or n:find("stock", 1, true) or n:find("price", 1, true) then
                    local ok, mod = pcall(require, inst)
                    if ok and type(mod) == "table" then
                        _sellFlagsMod = mod
                        return _sellFlagsMod
                    end
                end
            end
        end
    end
    _sellFlagsMod = false
    return nil
end

local function _resolveFruitNames(fruitName)
    local out, seen = {}, {}
    local function add(n)
        n = tostring(n or "")
        if n == "" or seen[n] then return end
        seen[n] = true
        out[#out + 1] = n
    end
    add(fruitName)
    if fruitName == "" then return out end

    local okEntry, got = pcall(function()
        return M.getSeedEntry(fruitName)
    end)
    if okEntry and type(got) == "table" then
        add(got.SeedName)
        add(got.Name)
        add(got.FruitName)
    end

    local svd = _requireChild("SellValueData")
    if type(svd) == "table" then
        for _, name in ipairs(out) do
            if svd[name] ~= nil then return out end
        end
        local nk = M.normKey(fruitName)
        for key in pairs(svd) do
            if type(key) == "string" and M.normKey(key) == nk then
                add(key)
            end
        end
    end
    return out
end

local function _readFlagMapNumber(flagObj, fruitName, names)
    if type(flagObj) ~= "table" then return nil end
    local data
    if type(flagObj.Get) == "function" then
        local ok, v = pcall(flagObj.Get, flagObj)
        if ok then data = v end
    elseif rawget(flagObj, "Value") ~= nil then
        data = flagObj.Value
    end
    if type(data) == "number" and data > 0 then
        return data
    end
    if type(data) ~= "table" then return nil end
    names = names or _resolveFruitNames(fruitName)
    for _, name in ipairs(names) do
        local v = data[name]
        if type(v) == "number" and v > 0 then return v end
    end
    local nk = M.normKey(fruitName)
    for key, v in pairs(data) do
        if type(key) == "string" and type(v) == "number" and v > 0 and M.normKey(key) == nk then
            return v
        end
    end
    return nil
end

function M.getStockMultiplier(fruitName)
    fruitName = tostring(fruitName or "")
    if fruitName == "" then return 1 end

    local mod = _ensureSellFlagsMod()
    local names = _resolveFruitNames(fruitName)

    if type(mod) == "table" then
        local apiNames = {
            "GetStockMultiplier", "GetPriceStockMultiplier", "GetPriceStock",
            "GetMultiplier", "GetRate", "GetStockRate",
        }
        for _, api in ipairs(apiNames) do
            local fn = mod[api]
            if type(fn) == "function" then
                for _, name in ipairs(names) do
                    local ok, v = pcall(fn, name)
                    if ok and type(v) == "number" and v > 0 then return v end
                    ok, v = pcall(fn, mod, name)
                    if ok and type(v) == "number" and v > 0 then return v end
                end
            end
        end

        local flagKeys = {
            "PriceStockMultipliers", "StockMultipliers", "PriceStock",
            "SellPriceMultipliers", "Multipliers", "Rates", "StockRates",
        }
        for _, key in ipairs(flagKeys) do
            local v = _readFlagMapNumber(mod[key], fruitName, names)
            if type(v) == "number" and v > 0 then return v end
        end

        for key, obj in pairs(mod) do
            if type(key) == "string" and type(obj) == "table" and type(obj.Get) == "function" then
                local v = _readFlagMapNumber(obj, fruitName, names)
                if type(v) == "number" and v > 0 then return v end
            end
        end

        if type(mod.Apply) == "function" then
            local probe = 10000
            for _, name in ipairs(names) do
                local ok, result = pcall(mod.Apply, name, probe)
                if ok and type(result) == "number" and result > 0 then
                    return result / probe
                end
                ok, result = pcall(mod.Apply, mod, name, probe)
                if ok and type(result) == "number" and result > 0 then
                    return result / probe
                end
            end
        end
    end

    return 1
end

local function _callSellFlagsApply(mod, fruitName, baseValue)
    baseValue = tonumber(baseValue) or 0
    if baseValue <= 0 or type(mod) ~= "table" then return baseValue end

    local mult = M.getStockMultiplier(fruitName)
    if type(mult) == "number" and mult > 0 and mult ~= 1 then
        return math.floor(baseValue * mult + 0.5)
    end

    local fn = mod.Apply
    if type(fn) ~= "function" then return baseValue end

    for _, name in ipairs(_resolveFruitNames(fruitName)) do
        local ok, value = pcall(fn, name, baseValue)
        if ok and type(value) == "number" then
            return value
        end
        ok, value = pcall(fn, mod, name, baseValue)
        if ok and type(value) == "number" then
            return value
        end
    end
    return baseValue
end

function M.applyStockRate(fruitName, baseValue)
    baseValue = tonumber(baseValue) or 0
    if baseValue <= 0 then return 0 end
    local mod = _ensureSellFlagsMod()
    if not mod then
        local mult = M.getStockMultiplier(fruitName)
        if mult ~= 1 then
            return math.floor(baseValue * mult + 0.5)
        end
        return baseValue
    end
    local ok, value = pcall(_callSellFlagsApply, mod, fruitName, baseValue)
    if ok and type(value) == "number" then
        return value
    end
    return baseValue
end

function M.getBackpackEspPrice(name, multi, mutation, decayAlpha, mode, fruitId, bidPrice)
    mode = tostring(mode or M.getEspPriceMode()):lower()
    if mode ~= "stock" then mode = "base" end

    multi = tonumber(multi) or 0
    name = tostring(name or "")
    fruitId = tostring(fruitId or "")
    if name == "" or multi <= 0 then return 0 end

    if mode == "base" then
        local base = M.calculate(name, multi, mutation, _noFriendCalcInst, decayAlpha)
        if base <= 0 then return 0 end
        local bid = tonumber(bidPrice) or 0
        if bid > 0 then
            return math.floor(base + bid + 0.5)
        end
        return base
    end

    -- Stock: harga server Steven (sudah include friend + hot rate)
    if fruitId ~= "" then
        local bid = M.getNpcBidRaw(fruitId)
        if bid > 0 then return bid end
    end

    local price = M.calculate(name, multi, mutation, LP, decayAlpha)
    if price <= 0 then
        price = M.calculate(name, multi, mutation, _noFriendCalcInst, decayAlpha)
    end
    if price <= 0 then return 0 end

    local mult = M.getStockMultiplier(name)
    if type(mult) == "number" and mult > 0 and mult ~= 1 then
        return math.floor(price * mult + 0.5)
    end

    local ok, adjusted = pcall(M.applyStockRate, name, price)
    if ok and type(adjusted) == "number" and adjusted > 0 then
        return adjusted
    end
    return price
end

local function _calcInst()
    if _includesFriendBoost() then
        return LP
    end
    return _noFriendCalcInst
end

local function _applyPricePolicy(price)
    price = tonumber(price) or 0
    if price <= 0 or _includesFriendBoost() then
        return price
    end
    return _stripFriendBoost(price)
end

local function _ensureNpcNetworking()
    if _getFruitBidFn then return true end
    if not SharedModules then return false end
    local ok, net = pcall(function()
        return require(SharedModules:WaitForChild("Networking"))
    end)
    if not ok or type(net) ~= "table" or type(net.NPCS) ~= "table" then
        return false
    end
    local remote = net.NPCS.GetFruitBid
    if type(remote) == "function" then
        _getFruitBidFn = remote
    elseif type(remote) == "table" and type(remote.Fire) == "function" then
        _getFruitBidFn = function(fruitId)
            return remote:Fire(fruitId)
        end
    elseif type(remote) == "userdata" and type(remote.InvokeServer) == "function" then
        _getFruitBidFn = function(fruitId)
            return remote:InvokeServer(fruitId)
        end
    end
    return _getFruitBidFn ~= nil
end

function M.clearBidCache()
    table.clear(_bidCache)
end

function M.getNpcBidRaw(fruitId)
    fruitId = tostring(fruitId or "")
    if fruitId == "" then return 0 end

    local now = os.clock()
    local cached = _bidCache[fruitId]
    if cached and (now - cached.at) < BID_CACHE_SEC then
        return cached.raw
    end

    if not _ensureNpcNetworking() then return 0 end

    local ok, bid = pcall(_getFruitBidFn, fruitId)
    if not ok or type(bid) ~= "table" then return 0 end

    local raw = tonumber(bid.CurrentSellValue or bid.currentSellValue
        or bid.SellValue or bid.sellValue) or 0
    if raw > 0 then
        _bidCache[fruitId] = { raw = raw, at = now }
    end
    return raw
end

function M.getNpcBid(fruitId)
    return _applyPricePolicy(M.getNpcBidRaw(fruitId))
end

function M.applyFriendBoost(price, friendCount)
    price = tonumber(price) or 0
    if price <= 0 then return 0 end
    return math.floor(price * _friendBoostMultiplier(friendCount) + 0.5)
end

function M.normKey(s)
    return tostring(s or ""):lower():gsub("[%s_%-%.'']+", "")
end

----------------------------------------------------------------
-- load / refresh dari game
----------------------------------------------------------------
local function _ingestSeedEntry(entry, into, rarityMaxPrice)
    if type(entry) ~= "table" then return end
    local seedName = entry.SeedName or entry.Name
    if not seedName or tostring(seedName) == "" then return end
    seedName = tostring(seedName)
    into[seedName] = entry
    local rarity = entry.Rarity
    if rarity then
        local price = tonumber(entry.PurchasePrice) or 0
        rarityMaxPrice[rarity] = math.max(rarityMaxPrice[rarity] or 0, price)
    end
end

local function _rebuildRarityRank(rarityMaxPrice)
    local list = {}
    for rarity, price in pairs(rarityMaxPrice) do
        list[#list + 1] = { rarity = rarity, price = price }
    end
    table.sort(list, function(a, b)
        if a.price ~= b.price then return a.price > b.price end
        return tostring(a.rarity) < tostring(b.rarity)
    end)
    local rank = {}
    local total = #list
    for i, item in ipairs(list) do
        -- i=1 = tier termahal/terbaik → score tertinggi (sort desc)
        rank[item.rarity] = total - i + 1
    end
    return rank
end

local function _indexSeedData(seedData)
    local byName = {}
    local rarityMaxPrice = {}
    if type(seedData) ~= "table" then
        return byName, _rebuildRarityRank(rarityMaxPrice)
    end
    if #seedData > 0 then
        for _, entry in ipairs(seedData) do
            _ingestSeedEntry(entry, byName, rarityMaxPrice)
        end
    else
        for _, entry in pairs(seedData) do
            _ingestSeedEntry(entry, byName, rarityMaxPrice)
        end
    end
    return byName, _rebuildRarityRank(rarityMaxPrice)
end

function M.refresh(force)
    local now = os.clock()
    if not force and _calcFn and (now - _lastRefresh) < REFRESH_SEC then
        return _calcFn ~= nil
    end

    _calcFn = nil
    local calcMod = _requireChild("FruitValueCalc")
    if type(calcMod) == "function" then
        _calcFn = calcMod
    elseif type(calcMod) == "table" then
        if type(calcMod.Calculate) == "function" then
            _calcFn = calcMod.Calculate
        elseif type(calcMod.calculate) == "function" then
            _calcFn = calcMod.calculate
        end
    end

    local seedData = _requireChild("SeedData")
    _seedByName, _rarityRank = _indexSeedData(seedData)

    -- PlantListView juga dari SeedData game — merge kalau ada
    local PLV = G.PlantListView or _G.PlantListView
    if type(PLV) == "table" and type(PLV.getCatalogMap) == "function" then
        local ok, catalog = pcall(PLV.getCatalogMap, PLV)
        if ok and type(catalog) == "table" then
            local rarityMaxPrice = {}
            for seedName, info in pairs(_seedByName) do
                if info.Rarity then
                    local price = tonumber(info.PurchasePrice) or 0
                    rarityMaxPrice[info.Rarity] = math.max(rarityMaxPrice[info.Rarity] or 0, price)
                end
            end
            for seedName, info in pairs(catalog) do
                if type(info) == "table" and not _seedByName[seedName] then
                    _seedByName[seedName] = info.raw or info
                end
                local r = type(info) == "table" and (info.Rarity or (info.raw and info.raw.Rarity))
                local p = type(info) == "table" and (
                    info.PurchasePrice or (info.raw and info.raw.PurchasePrice)
                )
                if r then
                    rarityMaxPrice[r] = math.max(rarityMaxPrice[r] or 0, tonumber(p) or 0)
                end
            end
            _rarityRank = _rebuildRarityRank(rarityMaxPrice)
        end
    end

    _lastRefresh = now
    return _calcFn ~= nil
end

local function _ensureCalc()
    if not _calcFn then
        M.refresh(true)
    end
    return _calcFn
end

----------------------------------------------------------------
-- resolve dari model buah
----------------------------------------------------------------
local function _looksLikeId(s)
    s = tostring(s or "")
    if s == "" then return true end
    if s:match("^%d+_[%x%-]+") then return true end
    if #s >= 32 and s:match("^[%x%-]+$") then return true end
    if s:find("_", 1, true) and s:find("-", 1, true) and not s:match("^[%a][%a ]*$") then
        return true
    end
    return false
end

local function _attrText(model, key)
    if not model then return nil end
    local v = model:GetAttribute(key)
    if type(v) ~= "string" or v == "" then return nil end
    return v
end

local function _pickNameFromModel(model)
    if not model then return nil end
    local keys = {
        "CorePartName", "FruitType", "FruitName", "ItemName", "SeedName",
    }
    for _, key in ipairs(keys) do
        local v = _attrText(model, key)
        if v and not _looksLikeId(v) then
            return v
        end
    end
    local cfg = _attrText(model, "ConfigPathName")
    if cfg and not _looksLikeId(cfg) then
        return cfg
    end
    return nil
end

function M.resolveSeedName(model)
    if not model then return "" end

    local name = _pickNameFromModel(model)
    if name then return tostring(name) end

    local p = model.Parent
    for _ = 1, 8 do
        if not p then break end
        local pn = _pickNameFromModel(p)
        if pn then return tostring(pn) end
        if p.Name == "Plants" or p.Name == "Gardens" then break end
        p = p.Parent
    end

    local cfg = _attrText(model, "ConfigPathName") or _attrText(model, "SeedName")
    if cfg then
        local tail = cfg:match("([^/]+)$")
        if tail and not _looksLikeId(tail) then
            return tail
        end
    end

    local fallback = tostring(model.Name or "")
    if fallback ~= "" and not _looksLikeId(fallback) then
        return fallback
    end
    return ""
end

local function _getFruitVisualizer()
    local now = os.clock()
    if _fruitViz and (now - _fruitVizAt) <= VIZ_CACHE_SEC then
        return _fruitViz
    end
    _fruitVizAt = now
    _fruitViz = nil

    local ps = LP:FindFirstChild("PlayerScripts")
    local controllers = ps and ps:FindFirstChild("Controllers")
    local mod = controllers and controllers:FindFirstChild("FruitVisualizerController")
    if mod and mod:IsA("ModuleScript") then
        local ok, ctrl = pcall(require, mod)
        if ok and type(ctrl) == "table" then
            _fruitViz = ctrl
        end
    end
    return _fruitViz
end

local function _vizWeight(viz, model)
    if not viz or not model then return nil end
    local ok, kg = pcall(viz.CalculateFruitWeight, viz, model)
    if ok and type(kg) == "number" and kg > 0 then
        return kg
    end
    if type(viz.CalculatePlantWeight) == "function" then
        ok, kg = pcall(viz.CalculatePlantWeight, viz, model)
        if ok and type(kg) == "number" and kg > 0 then
            return kg
        end
    end
    return nil
end

-- Garden: display kg (billboard / BaseWeight×SizeMulti). Bukan SizeMultiplier (multi harga).
function M.resolveWeight(model)
    if not model then return 0 end

    if model:IsA("Tool") then
        local harvestKg = tonumber(model:GetAttribute("Weight"))
        if harvestKg and harvestKg > 0 then
            return harvestKg
        end
    end

    local viz = _getFruitVisualizer()
    if viz then
        local kg = _vizWeight(viz, model)
        if kg then return kg end
        local parent = model.Parent
        if parent and parent:IsA("Model") then
            kg = _vizWeight(viz, parent)
            if kg then return kg end
        end
    end

    local node, depth = model, 0
    while node and depth < 8 do
        if node:IsA("Model") then
            local bw = tonumber(node:GetAttribute("BaseWeight"))
            local sm = tonumber(node:GetAttribute("SizeMulti") or node:GetAttribute("SizeMultiplier"))
            local og = tonumber(node:GetAttribute("OvertimeGrowth")) or 1
            if bw and bw > 0 and sm and sm > 0 then
                return bw * sm * og
            end
            local harvestKg = tonumber(node:GetAttribute("Weight"))
            if harvestKg and harvestKg > 0 then
                return harvestKg
            end
        end
        if node.Name == "Gardens" then break end
        node = node.Parent
        depth += 1
    end
    return 0
end

function M.resolveMulti(model)
    if not model then return 0 end
    local node, depth = model, 0
    while node and depth < 8 do
        if node:IsA("Model") or node:IsA("Tool") then
            local multi = tonumber(node:GetAttribute("SizeMultiplier") or node:GetAttribute("SizeMulti"))
            if multi and multi > 0 then
                return multi
            end
        end
        if node.Name == "Gardens" then break end
        node = node.Parent
        depth += 1
    end
    return 0
end

local function _isWeightBracket(token)
    local t = tostring(token or ""):match("^%s*(.-)%s*$")
    if t == "" then return true end
    if t:lower():match("^[%d%.]+%s*kg$") then return true end
    return tonumber(t) ~= nil
end

local function _mutationFromToolName(model)
    if not model then return nil end
    local raw = tostring(model.Name or "")
    if raw == "" then return nil end
    local parts = {}
    for bracket in string.gmatch(raw, "%[([^%]]+)%]") do
        local token = tostring(bracket):match("^%s*(.-)%s*$")
        if token and token ~= "" and not _isWeightBracket(token) then
            parts[#parts + 1] = token
        end
    end
    if #parts == 0 then return nil end
    if #parts == 1 then return parts[1] end
    return table.concat(parts, "+")
end

function M.resolveMutation(model)
    if not model then return nil end
    local raw = model:GetAttribute("Mutation")
    if type(raw) == "string" and raw ~= "" then return raw end
    return _mutationFromToolName(model)
end

function M.resolveBidPrice(model)
    if not model or type(model.GetAttribute) ~= "function" then return 0 end
    local bid = tonumber(model:GetAttribute("BidPrice"))
    if bid and bid > 0 then
        return bid
    end
    local node, depth = model.Parent, 1
    while node and depth < 8 do
        if type(node.GetAttribute) == "function" then
            bid = tonumber(node:GetAttribute("BidPrice"))
            if bid and bid > 0 then
                return bid
            end
        end
        if node.Name == "Gardens" then break end
        node = node.Parent
        depth += 1
    end
    return 0
end

function M.getSeedEntry(seedName)
    _ensureCalc()
    seedName = tostring(seedName or "")
    if seedName == "" then return nil end
    return _seedByName[seedName]
end

function M.getRarity(seedName)
    local entry = M.getSeedEntry(seedName)
    if type(entry) == "table" and entry.Rarity then
        return tostring(entry.Rarity)
    end
    return nil
end

----------------------------------------------------------------
-- Calculate — delegate ke FruitValueCalc game
-- Calculate(seedName, weight, mutation, inst, discount)
----------------------------------------------------------------
function M.calculate(seedName, weight, mutation, inst, discount)
    local calc = _ensureCalc()
    if not calc then return 0 end
    seedName = tostring(seedName or "")
    weight = tonumber(weight) or 0
    if seedName == "" then return 0 end
    local ok, value = pcall(calc, seedName, weight, mutation, inst or _calcInst(), discount)
    if ok and type(value) == "number" then return value end
    return 0
end

function M.getBackpackPrice(name, weight, mutation, fruitId, decayAlpha)
    if fruitId ~= nil and tostring(fruitId) ~= "" then
        local bid = M.getNpcBid(fruitId)
        if bid > 0 then return bid end
    end
    return M.calculate(name, weight, mutation, _calcInst(), decayAlpha)
end

function M.fromFruit(model, _inst)
    if not model then return 0 end
    local name = model:GetAttribute("FruitName")
    if type(name) ~= "string" or name == "" then
        name = M.resolveSeedName(model)
    else
        name = tostring(name)
    end
    local multi = M.resolveMulti(model)
    local fruitId = model:GetAttribute("Id") or model:GetAttribute("id")
        or model:GetAttribute("UUID") or model:GetAttribute("FruitId")
    if fruitId then
        local bid = M.getNpcBid(fruitId)
        if bid > 0 then return bid end
    end
    if not multi or multi <= 0 then
        return 0
    end
    return M.calculate(name, multi, M.resolveMutation(model), _calcInst(), model:GetAttribute("DecayAlpha"))
end

function M.rarityScore(model)
    if not model then return 0 end
    _ensureCalc()
    local seedName = M.resolveSeedName(model)
    local entry = _seedByName[seedName]
    local rarity = type(entry) == "table" and entry.Rarity
    if not rarity then return 0 end
    return _rarityRank[rarity] or 0
end

function M.priorityScore(model, mode, inst)
    mode = tostring(mode or "off"):lower()
    if mode == "price" then
        return M.fromFruit(model, inst)
    elseif mode == "rarity" then
        return M.rarityScore(model) * 1e9 + M.fromFruit(model, inst)
    elseif mode == "weight" then
        return M.resolveWeight(model)
    end
    return 0
end

function M.isReady()
    return _ensureCalc() ~= nil
end

M.isready = M.isReady

-- init
pcall(function() M.refresh(true) end)
pcall(function() M.setEspPriceMode(M.getEspPriceMode()) end)

G.FruitSellValue = M
_G.FruitSellValue = M

return M
 end,                 required = false },
    { key = "AutoCollect",             name = "Auto Collect",            factory = function() -- AutoCollect.lua — Grow A Garden 2 (lightweight batch cache)
-- Pola: isi cache plot sendiri → fire satu per delay → scan ulang saat batch habis

local Players           = game:GetService("Players")
local ReplicatedStorage = game:GetService("ReplicatedStorage")
local CollectionService = game:GetService("CollectionService")

local LP = Players.LocalPlayer
local G  = (getgenv and getgenv()) or _G
local M  = {}

local CollectFruit = nil

local function _remoteCanFire(remote)
    if not remote then return false end
    if type(remote.Fire) == "function" then return true end
    if type(remote.FireServer) == "function" then return true end
    if type(remote.InvokeServer) == "function" then return true end
    return false
end

local function _ensureCollectRemote()
    if CollectFruit and _remoteCanFire(CollectFruit) then
        return true
    end
    CollectFruit = nil

    local ok, net = pcall(function()
        local sm = ReplicatedStorage:WaitForChild("SharedModules", 8)
        return sm and require(sm:WaitForChild("Networking", 8))
    end)
    if ok and type(net) == "table" and type(net.Garden) == "table" then
        CollectFruit = net.Garden.CollectFruit
    end
    return _remoteCanFire(CollectFruit)
end

local FruitSellValue
pcall(function()
    FruitSellValue = require(script.Parent.FruitSellValue)
end)
if type(FruitSellValue) ~= "table" then
    FruitSellValue = G.FruitSellValue or _G.FruitSellValue
end

local HARVEST_TAG      = "HarvestPrompt"
local COUNT_CACHE_SEC  = 4.0
local AC_CACHE_SEC     = 0.4
local PROMPT_SCAN_CACHE_SEC = 1.2
local SCAN_MIN_SEC     = 0.5
local IDLE_WAIT_SEC    = 0.45

local running            = false
local loopId             = 0
local loopAliveId        = 0
local batchList          = {}
local batchIdx           = 1
local cachedAC           = nil
local cachedACAt         = 0
local cachedPlot         = nil
local cachedPlotAt       = 0
local PLOT_CACHE_SEC     = 3.0
local _lastTickCollected = 0
local _totalCollected    = 0
local _readyCache        = 0
local _readyCacheAt      = 0
local _filteredCache     = 0
local _filteredCacheAt   = 0
local weightCache        = {}
local WEIGHT_CACHE_SEC   = 30
local promptScanCache    = { plot = nil, at = 0, list = {} }
local _fruitViz          = nil
local _fruitVizAt        = 0
local VIZ_CACHE_SEC      = 30

local function _getFruitVisualizer()
    local now = os.clock()
    if _fruitViz and (now - _fruitVizAt) <= VIZ_CACHE_SEC then
        return _fruitViz
    end
    _fruitVizAt = now
    _fruitViz = nil
    local ps = LP:FindFirstChild("PlayerScripts")
    local c = ps and ps:FindFirstChild("Controllers")
    local m = c and c:FindFirstChild("FruitVisualizerController")
    if m and m:IsA("ModuleScript") then
        local ok, mod = pcall(require, m)
        if ok and type(mod) == "table" then
            _fruitViz = mod
        end
    end
    return _fruitViz
end

local function _kgFromViz(viz, model)
    if not viz or not model then return nil end
    local ok, w = pcall(viz.CalculateFruitWeight, viz, model)
    if ok and type(w) == "number" and w > 0 then return w end
    ok, w = pcall(function() return viz:CalculateFruitWeight(model) end)
    if ok and type(w) == "number" and w > 0 then return w end
    if type(viz.CalculatePlantWeight) == "function" then
        ok, w = pcall(viz.CalculatePlantWeight, viz, model)
        if ok and type(w) == "number" and w > 0 then return w end
        ok, w = pcall(function() return viz:CalculatePlantWeight(model) end)
        if ok and type(w) == "number" and w > 0 then return w end
    end
    return nil
end

local function _attrId(inst, name)
    if not inst then return "" end
    local v = inst:GetAttribute(name)
    if v == nil then return "" end
    v = tostring(v)
    if v == "" then return "" end
    return v
end

-- Match HarvestPromptController: IDs from the harvest model ancestor of the prompt.
local function _resolvePlotFruitIds(model)
    if not model then return "", "" end

    local plantId = _attrId(model, "PlantId")
    local fruitId = _attrId(model, "FruitId")
    if plantId ~= "" then
        return plantId, fruitId
    end

    local node, depth = model.Parent, 0
    while node and depth < 12 do
        if node:IsA("Model") then
            if plantId == "" then
                plantId = _attrId(node, "PlantId")
            end
            if fruitId == "" then
                fruitId = _attrId(node, "FruitId")
            end
            if plantId ~= "" then
                return plantId, fruitId
            end
        end
        if node.Name == "Gardens" then break end
        node = node.Parent
        depth += 1
    end
    return plantId, fruitId
end

local function _idsFromPrompt(prompt)
    if not prompt or not prompt.Parent then return "", "" end
    local model = prompt.Parent:FindFirstAncestorWhichIsA("Model")
    if not model then return "", "" end
    return _resolvePlotFruitIds(model)
end

