local function _dbg()
    return G.AUTO_COLLECT_DEBUG == true or _G.AUTO_COLLECT_DEBUG == true
end

local function _log(...)
    if _dbg() then print("[GAG2-AC]", ...) end
end

local function _warn(...)
    print("[GAG2-AC]", ...)
end

local function _normalizeDelay(v, default)
    default = default or 0.1
    local d = tonumber(v)
    if d == nil then return default end
    if d < 0 then return 0 end
    return d
end

local function _liveDelay()
    local raw = G.AUTO_COLLECT_DELAY
    if raw == nil then raw = rawget(_G, "AUTO_COLLECT_DELAY") end
    if raw == nil then
        local MAIN = rawget(_G, "MAIN") or G.MAIN
        local ac = MAIN and MAIN.auto and MAIN.auto.collect
        raw = ac and ac.delay
    end
    return _normalizeDelay(raw, 0.1)
end

local function _fireDelaySec(ac)
    local d = tonumber(ac and ac.delay)
    if d == nil then
        d = _liveDelay()
    end
    d = tonumber(d) or 0
    if d < 0 then d = 0 end
    return d
end

local function _waitAfterFire(ac)
    local d = _fireDelaySec(ac)
    if d > 0 then
        task.wait(d)
    else
        task.wait()
    end
end

local function _clearBatchCaches()
    batchIdx = 1
    table.clear(batchList)
    _readyCacheAt = 0
    _filteredCacheAt = 0
end

local function _invalidatePromptScan()
    promptScanCache.plot = nil
    promptScanCache.at = 0
    table.clear(promptScanCache.list)
end

----------------------------------------------------------------
-- state
----------------------------------------------------------------
local function _hasAny(map)
    if type(map) ~= "table" then return false end
    for _, v in pairs(map) do
        if v == true then return true end
    end
    return false
end

local function _normalizeSet(src)
    if type(src) ~= "table" then return {} end
    local out = {}
    for i = 1, #src do
        local v = src[i]
        if v ~= nil and tostring(v) ~= "" then out[tostring(v)] = true end
    end
    if next(out) then return out end
    for k, v in pairs(src) do
        if v == true or v == 1 or v == "true" then out[tostring(k)] = true end
    end
    return out
end

local function _setToArray(map)
    local out = {}
    if type(map) ~= "table" then return out end
    for k, v in pairs(map) do
        if v == true then out[#out + 1] = tostring(k) end
    end
    table.sort(out)
    return out
end

local function _batchFilterKey(ac)
    if type(ac) ~= "table" then return "" end
    local parts = {
        tostring(ac.priority or "off"),
        tostring(#(ac.rules or {})),
        (ac.eclipseSpawnEnabled == true) and "1" or "0",
        tostring(ac.eclipseSpawnKg or 0),
        tostring(ac.eclipseSpawnKgMode or "above"),
    }
    for _, r in ipairs(ac.rules or {}) do
        parts[#parts + 1] = table.concat({
            tostring(r.id or ""),
            (r.enabled == false) and "0" or "1",
            (r.requireMut == true) and "1" or "0",
            table.concat(_setToArray(r.fruits), ","),
            table.concat(_setToArray(r.mutations), ","),
            tostring(r.kg or 0),
            tostring(r.kgMode or "above"),
            tostring(r.minPrice or 0),
            tostring(r.minPriceMode or "above"),
        }, ":")
    end
    return table.concat(parts, "|")
end

local function _canon(s)
    return tostring(s or ""):lower():gsub("[^%w]+", "")
end

local function _normalizeKgFilter(kg, mode)
    kg = tonumber(kg) or 0
    mode = tostring(mode or "above")
    if kg < 0 then
        kg = math.abs(kg)
        mode = "below"
    end
    if mode ~= "below" then
        mode = "above"
    end
    return kg, mode
end

local function _parseKgRuleInput(txt)
    txt = tostring(txt or ""):gsub("%s+", "")
    if txt == "" then
        return 0, "above"
    end
    local n = tonumber(txt)
    if not n then
        return 0, "above"
    end
    if n < 0 then
        return math.abs(n), "below"
    end
    return n, "above"
end

local function _liveKgFilter()
    local rule = G.AUTO_COLLECT_KG_RULE or rawget(_G, "AUTO_COLLECT_KG_RULE")
    if type(rule) == "string" and rule:gsub("%s+", "") ~= "" then
        return _parseKgRuleInput(rule)
    end
    return _normalizeKgFilter(
        G.AUTO_COLLECT_KG or rawget(_G, "AUTO_COLLECT_KG"),
        G.AUTO_COLLECT_KG_MODE or rawget(_G, "AUTO_COLLECT_KG_MODE")
    )
end

local function _formatKgRule(kg, mode)
    kg = tonumber(kg) or 0
    mode = tostring(mode or "above")
    if kg <= 0 then
        return "0"
    end
    if mode == "below" then
        return "-" .. tostring(kg)
    end
    return tostring(kg)
end

local function _normalizePriceFilter(price, mode)
    price = tonumber(price) or 0
    mode = tostring(mode or "above")
    if price < 0 then
        price = math.floor(math.abs(price))
        mode = "below"
    end
    if mode ~= "below" then
        mode = "above"
    end
    return math.floor(math.max(0, price)), mode
end

local function _parseScaledNumber(txt)
    txt = tostring(txt or ""):lower():gsub("%s+", ""):gsub(",", "")
    if txt == "" then return nil end
    local sign = 1
    if txt:sub(1, 1) == "-" then
        sign = -1
        txt = txt:sub(2)
    end
    local suffixes = {
        { "juta", 1000000 }, { "jt", 1000000 },
        { "ribu", 1000 }, { "rb", 1000 },
        { "b", 1000000000 }, { "m", 1000000 }, { "k", 1000 },
    }
    for _, pair in ipairs(suffixes) do
        local suf, mult = pair[1], pair[2]
        if #txt > #suf and txt:sub(-#suf) == suf then
            local n = tonumber(txt:sub(1, -#suf - 1))
            if n then return n * mult * sign end
        end
    end
    local n = tonumber(txt)
    if n then return n * sign end
    return nil
end

local function _parsePriceRuleInput(txt)
    txt = tostring(txt or ""):gsub("%s+", "")
    if txt == "" then
        return 0, "above"
    end
    local n = _parseScaledNumber(txt) or tonumber(txt)
    if not n then
        return 0, "above"
    end
    if n < 0 then
        return math.abs(n), "below"
    end
    return n, "above"
end

local function _formatPriceRule(price, mode)
    price = tonumber(price) or 0
    mode = tostring(mode or "above")
    if price <= 0 then return "0" end
    if mode == "below" then return "-" .. tostring(price) end
    return tostring(price)
end

local function _getFruitPrice(fruit)
    if type(FruitSellValue) == "table" and type(FruitSellValue.fromFruit) == "function" then
        local ok, price = pcall(FruitSellValue.fromFruit, fruit)
        if ok then return tonumber(price) or 0 end
    end
    return 0
end

local _loadCollectRules

local function _readEnabled()
    if G.AUTO_COLLECT_FRUIT_ENABLED == true or rawget(_G, "AUTO_COLLECT_FRUIT_ENABLED") == true then
        return true
    end
    local MAIN = rawget(_G, "MAIN") or G.MAIN
    local ac = MAIN and MAIN.auto and MAIN.auto.collect
    return type(ac) == "table" and ac.enabled == true
end

local function _readEclipseSpawnConfig(ac)
    ac = type(ac) == "table" and ac or {}
    local enabled = G.AUTO_COLLECT_ECLIPSE_SPAWN
    if enabled == nil then enabled = rawget(_G, "AUTO_COLLECT_ECLIPSE_SPAWN") end
    if enabled == nil then enabled = ac.eclipseSpawnEnabled end
    enabled = (enabled == true)

    local kgRule = G.AUTO_COLLECT_ECLIPSE_SPAWN_KG_RULE
        or rawget(_G, "AUTO_COLLECT_ECLIPSE_SPAWN_KG_RULE")
        or ac.eclipseSpawnKgRule
    local kg, kgMode
    if type(kgRule) == "string" and kgRule:gsub("%s+", "") ~= "" then
        kg, kgMode = _parseKgRuleInput(kgRule)
    else
        kg, kgMode = _normalizeKgFilter(ac.eclipseSpawnKg, ac.eclipseSpawnKgMode)
    end
    return enabled, kg, kgMode, _formatKgRule(kg, kgMode)
end

local function getACState()
    local MAIN = rawget(_G, "MAIN") or G.MAIN
    local ac = MAIN and MAIN.auto and MAIN.auto.collect
    ac = type(ac) == "table" and ac or {}

    local rawDelay = G.AUTO_COLLECT_DELAY
    if rawDelay == nil then rawDelay = rawget(_G, "AUTO_COLLECT_DELAY") end
    if rawDelay == nil then rawDelay = ac.delay end
    local delay = _normalizeDelay(rawDelay, 0.1)

    local enabled = _readEnabled()

    local priority = tostring(
        G.AUTO_COLLECT_PRIORITY or rawget(_G, "AUTO_COLLECT_PRIORITY") or ac.priority or "off"
    ):lower()
    if priority ~= "price" and priority ~= "rarity" and priority ~= "weight" then
        priority = "off"
    end

    local _, rules = _loadCollectRules(ac)
    local eclipseOn, eclipseKg, eclipseKgMode, eclipseKgRule = _readEclipseSpawnConfig(ac)

    return {
        enabled = enabled,
        delay = delay,
        priority = priority,
        filterMode = "rules",
        rules = rules,
        useRules = #rules > 0,
        eclipseSpawnEnabled = eclipseOn,
        eclipseSpawnKg = eclipseKg,
        eclipseSpawnKgMode = eclipseKgMode,
        eclipseSpawnKgRule = eclipseKgRule,
    }
end

local function _applyLiveFilters(ac)
    if type(ac) ~= "table" then return end
    ac.filterMode = "rules"
    ac.rules = select(2, _loadCollectRules(ac))
    ac.useRules = #(ac.rules or {}) > 0
end

local function getACStateCached()
    local now = os.clock()
    if cachedAC and (now - cachedACAt) <= AC_CACHE_SEC then
        cachedAC.enabled = _readEnabled()
        cachedAC.delay = _liveDelay()
        local pr = G.AUTO_COLLECT_PRIORITY or rawget(_G, "AUTO_COLLECT_PRIORITY")
        if pr then
            pr = tostring(pr):lower()
            if pr == "price" or pr == "rarity" or pr == "weight" then
                cachedAC.priority = pr
            end
        end
        _applyLiveFilters(cachedAC)
        do
            local MAIN = rawget(_G, "MAIN") or G.MAIN
            local mainAc = MAIN and MAIN.auto and MAIN.auto.collect
            local eclipseOn, eclipseKg, eclipseKgMode, eclipseKgRule = _readEclipseSpawnConfig(mainAc)
            cachedAC.eclipseSpawnEnabled = eclipseOn
            cachedAC.eclipseSpawnKg = eclipseKg
            cachedAC.eclipseSpawnKgMode = eclipseKgMode
            cachedAC.eclipseSpawnKgRule = eclipseKgRule
        end
        return cachedAC
    end
    cachedAC = getACState()
    cachedAC.delay = _liveDelay()
    cachedACAt = now
    return cachedAC
end

local function _invalidateACCache()
    cachedAC = nil
    cachedACAt = 0
    _clearBatchCaches()
    _invalidatePromptScan()
    table.clear(weightCache)
end

local function _writeMainCollect(patch)
    local MAIN = rawget(_G, "MAIN") or G.MAIN
    if type(MAIN) ~= "table" then return end
    MAIN.auto = MAIN.auto or {}
    MAIN.auto.collect = MAIN.auto.collect or {}
    for k, v in pairs(patch) do
        MAIN.auto.collect[k] = v
    end
    G.MAIN = MAIN
    _G.MAIN = MAIN
end

----------------------------------------------------------------
-- garden + fruit
----------------------------------------------------------------
local function _plotOwnedByLocal(plot)
    if not plot then return false end
    local uid, name = LP.UserId, LP.Name
    local function match(v)
        if v == nil then return false end
        return v == uid or v == name or tostring(v) == tostring(uid) or tostring(v) == name
    end
    if match(plot:GetAttribute("OwnerId")) then return true end
    if match(plot:GetAttribute("Owner")) then return true end
    if match(plot:GetAttribute("UserId")) then return true end
    return false
end

local function getPlayerPlot(force)
    local now = os.clock()
    if not force and cachedPlot and cachedPlot.Parent and (now - cachedPlotAt) <= PLOT_CACHE_SEC then
        return cachedPlot
    end

    local gardens = workspace:FindFirstChild("Gardens")
    if not gardens then
        cachedPlot = nil
        cachedPlotAt = now
        return nil
    end

    local plotId = LP:GetAttribute("PlotId")
    if plotId ~= nil then
        local byId = gardens:FindFirstChild("Plot" .. tostring(plotId))
        if byId then
            cachedPlot = byId
            cachedPlotAt = now
            return byId
        end
    end

    for _, plot in ipairs(gardens:GetChildren()) do
        if _plotOwnedByLocal(plot) then
            cachedPlot = plot
            cachedPlotAt = now
            return plot
        end
    end

    local byName = gardens:FindFirstChild("Plot" .. LP.Name)
    cachedPlot = byName
    cachedPlotAt = now
    return byName
end

local function _fruitFromPrompt(prompt)
    if not prompt or not prompt.Parent then return nil end
    local model = prompt.Parent:FindFirstAncestorWhichIsA("Model")
    if model and _attrId(model, "PlantId") ~= "" then
        return model
    end
    local node, best = prompt.Parent, nil
    while node do
        if node:IsA("Model") then
            local pid = _attrId(node, "PlantId")
            if pid ~= "" then
                best = node
                if _attrId(node, "FruitId") ~= "" then
                    return node
                end
            end
        end
        if node.Name == "Gardens" then break end
        node = node.Parent
    end
    return best or model
end

local function _parseKgText(text)
    return tonumber(tostring(text or ""):match("([%d%.]+)%s*[kK][gG]"))
end

local function _weightFromBillboard(model)
    if not model then return nil end
    local node, depth = model, 0
    while node and depth < 6 do
        if node:IsA("Model") then
            for _, ch in ipairs(node:GetChildren()) do
                if ch:IsA("BillboardGui") or ch:IsA("SurfaceGui") then
                    for _, d in ipairs(ch:GetDescendants()) do
                        if d:IsA("TextLabel") then
                            local w = _parseKgText(d.Text)
                            if w and w > 0 then return w end
                        end
                    end
                elseif ch:IsA("TextLabel") then
                    local w = _parseKgText(ch.Text)
                    if w and w > 0 then return w end
                end
            end
        end
        if node.Name == "Gardens" then break end
        node = node.Parent
        depth += 1
    end
    return nil
end

local function _weightFromAttrs(model)
    if not model then return nil end
    local node, depth = model, 0
    while node and depth < 10 do
        if node:IsA("Model") then
            local bw = tonumber(node:GetAttribute("BaseWeight"))
            local sm = tonumber(node:GetAttribute("SizeMulti") or node:GetAttribute("SizeMultiplier"))
            local og = tonumber(node:GetAttribute("OvertimeGrowth")) or 1
            if bw and bw > 0 and sm and sm > 0 then
                return bw * sm * og
            end
            local w = tonumber(node:GetAttribute("Weight"))
            if w and w > 0 then return w end
        end
        if node.Name == "Gardens" then break end
        node = node.Parent
        depth += 1
    end
    return nil
end

local function _getName(model)
    if type(FruitSellValue) == "table" and type(FruitSellValue.resolveSeedName) == "function" then
        local ok, name = pcall(FruitSellValue.resolveSeedName, model)
        if ok and type(name) == "string" and name ~= "" then
            return name
        end
    end
    return model:GetAttribute("CorePartName")
        or model:GetAttribute("FruitType")
        or model:GetAttribute("FruitName")
        or model:GetAttribute("ItemName")
        or model:GetAttribute("SeedName")
        or model:GetAttribute("ConfigPathName")
        or model.Name
end

local function _getWeight(model)
    if not model then return 0 end

    local plantId, fruitId = _resolvePlotFruitIds(model)
    if plantId == "" then return 0 end

    local cacheKey = plantId .. "|" .. fruitId
    local now = os.clock()
    local cached = weightCache[cacheKey]
    if cached and (now - cached.at) <= WEIGHT_CACHE_SEC then
        return cached.w
    end

    local w = _weightFromAttrs(model)
    if not w then
        local viz = _getFruitVisualizer()
        w = _kgFromViz(viz, model)
        if not w and model.Parent and model.Parent:IsA("Model") then
            w = _kgFromViz(viz, model.Parent)
        end
    end
    if not w and type(FruitSellValue) == "table" and type(FruitSellValue.resolveWeight) == "function" then
        local ok, val = pcall(FruitSellValue.resolveWeight, model)
        if ok and type(val) == "number" and val > 0 then
            w = val
        end
    end
    if not w then
        w = _weightFromBillboard(model)
    end
    w = tonumber(w) or 0
    weightCache[cacheKey] = { w = w, at = now }
    return w
end

local function _parseMutationList(inst)
    local raw = inst and inst:GetAttribute("Mutation")
    if type(raw) ~= "string" or raw == "" then return {} end
    local out = {}
    for token in string.gmatch(raw, "[^%+%,]+") do
        token = tostring(token):match("^%s*(.-)%s*$")
        if token and token ~= "" then out[#out + 1] = token end
    end
    return out
end

local NO_MUTATION_LABEL = "No Mutation"

local function _isNoMutationKey(name)
    local c = _canon(name)
    return c == "nomutation" or c == "none" or tostring(name or "") == NO_MUTATION_LABEL
end

local _mutNameList = nil

local function _getMutationNames()
    if _mutNameList then return _mutNameList end
    _mutNameList = {}
    local PLV = G.PlantListView or _G.PlantListView
    if type(PLV) == "table" and type(PLV.listMutationNames) == "function" then
        local ok, list = pcall(PLV.listMutationNames, PLV)
        if ok and type(list) == "table" then
            for _, n in ipairs(list) do
                if not _isNoMutationKey(n) then
                    _mutNameList[#_mutNameList + 1] = n
                end
            end
        end
    end
    if #_mutNameList == 0 then
        _mutNameList = { "Gold", "Rainbow" }
    end
    return _mutNameList
end

local function _fruitHasMutation(inst)
    if not inst then return false end
    if type(FruitSellValue) == "table" and type(FruitSellValue.resolveMutation) == "function" then
        local ok, mut = pcall(FruitSellValue.resolveMutation, inst)
        if ok and type(mut) == "string" and mut ~= "" then
            return true
        end
    end
    for _, mutName in ipairs(_parseMutationList(inst)) do
        local lower = mutName:lower()
        if lower ~= "none" and lower ~= "normal" and not _isNoMutationKey(mutName) then
            return true
        end
    end
    for _, name in ipairs(_getMutationNames()) do
        if inst:GetAttribute(name) == true then
            return true
        end
    end
    return false
end

local function matchSet(selectedMap, value)
    if not _hasAny(selectedMap) then return true end
    local needle = _canon(value)
    for k, v in pairs(selectedMap) do
        if v == true and _canon(k) == needle then return true end
    end
    return false
end

local function matchMutation(selectedMap, inst)
    if not _hasAny(selectedMap) then return true end
    if not inst then return false end

    if selectedMap[NO_MUTATION_LABEL] == true and not _fruitHasMutation(inst) then
        return true
    end

    for mutName, on in pairs(selectedMap) do
        if on == true and not _isNoMutationKey(mutName) and inst:GetAttribute(mutName) == true then
            return true
        end
    end
    for _, mutName in ipairs(_parseMutationList(inst)) do
        if not _isNoMutationKey(mutName) and matchSet(selectedMap, mutName) then
            return true
        end
    end
    if type(FruitSellValue) == "table" and type(FruitSellValue.resolveMutation) == "function" then
        local ok, raw = pcall(FruitSellValue.resolveMutation, inst)
        if ok and type(raw) == "string" and raw ~= "" then
            for token in string.gmatch(raw, "[^%+%,]+") do
                if matchSet(selectedMap, token) then
                    return true
                end
            end
        end
    end
    return false
end

local function matchKg(weight, kg, mode)
    kg, mode = _normalizeKgFilter(kg, mode)
    weight = tonumber(weight) or 0
    if kg <= 0 then
        return true
    end
    if mode == "below" then
        return weight > 0 and weight <= kg
    end
    return weight >= kg
end

local function _matchesAllFilters(fruit, ac)
    if ac.anyFruit and not matchSet(ac.fruits, _getName(fruit)) then return false end
    if ac.anyMut and not matchMutation(ac.mutations, fruit) then return false end
    if ac.anyKg and not matchKg(_getWeight(fruit), ac.kg, ac.kgMode) then return false end
    return true
end

local function matchPrice(price, filterPrice, mode)
    filterPrice = tonumber(filterPrice) or 0
    if filterPrice <= 0 then return true end
    price = tonumber(price) or 0
    mode = tostring(mode or "above")
    if mode == "below" then
        return price > 0 and price <= filterPrice
    end
    return price >= filterPrice
end

local function _ruleToPersist(rule)
    return {
        id = rule.id,
        enabled = rule.enabled,
        fruits = _setToArray(rule.fruits),
        mutations = _setToArray(rule.mutations),
        kg = rule.kg,
        kgMode = rule.kgMode,
        kgRule = rule.kgRule,
        minPrice = rule.minPrice,
        minPriceMode = rule.minPriceMode,
        priceRule = rule.priceRule,
        requireMut = rule.requireMut,
    }
end

local function _normalizeCollectRule(raw)
    raw = type(raw) == "table" and raw or {}
    local fruits = _normalizeSet(raw.fruits)
    local mutations = _normalizeSet(raw.mutations)
    local kg, kgMode = _normalizeKgFilter(raw.kg, raw.kgMode)
    if type(raw.kgRule) == "string" and raw.kgRule:gsub("%s+", "") ~= "" then
        kg, kgMode = _parseKgRuleInput(raw.kgRule)
    end
    local minPrice, minPriceMode = _normalizePriceFilter(raw.minPrice, raw.minPriceMode)
    if type(raw.priceRule) == "string" and raw.priceRule:gsub("%s+", "") ~= "" then
        minPrice, minPriceMode = _parsePriceRuleInput(raw.priceRule)
    end
    local requireMut = raw.requireMut == true
    return {
        id = tostring(raw.id or ""),
        enabled = raw.enabled ~= false,
        fruits = fruits,
        mutations = mutations,
        kg = kg,
        kgMode = kgMode,
        kgRule = type(raw.kgRule) == "string" and raw.kgRule or _formatKgRule(kg, kgMode),
        minPrice = minPrice,
        minPriceMode = minPriceMode,
        priceRule = type(raw.priceRule) == "string" and raw.priceRule or _formatPriceRule(minPrice, minPriceMode),
        requireMut = requireMut,
        anyFruit = _hasAny(fruits),
        anyMut = _hasAny(mutations),
        anyPrice = minPrice > 0,
    }
end

_loadCollectRules = function(ac)
    ac = type(ac) == "table" and ac or {}
    local MAIN = rawget(_G, "MAIN") or G.MAIN
    local mainAc = MAIN and MAIN.auto and MAIN.auto.collect

    local rawRules = G.AUTO_COLLECT_RULES or rawget(_G, "AUTO_COLLECT_RULES")
        or ac.rules or (mainAc and mainAc.rules)
    local order = G.AUTO_COLLECT_RULES_ORDER or rawget(_G, "AUTO_COLLECT_RULES_ORDER")
        or ac.rulesOrder or (mainAc and mainAc.rulesOrder)

    local byId = {}
    if type(rawRules) == "table" then
        if #rawRules > 0 then
            for _, r in ipairs(rawRules) do
                local norm = _normalizeCollectRule(r)
                if norm.id == "" then
                    norm.id = "r" .. tostring(_)
                end
                byId[norm.id] = norm
            end
        else
            for id, r in pairs(rawRules) do
                if type(r) == "table" then
                    local norm = _normalizeCollectRule(r)
                    norm.id = tostring(norm.id ~= "" and norm.id or id)
                    byId[norm.id] = norm
                end
            end
        end
    end

    local out, seen = {}, {}
    if type(order) == "table" then
        for _, id in ipairs(order) do
            id = tostring(id or "")
            local rule = byId[id]
            if rule and not seen[id] then
                seen[id] = true
                out[#out + 1] = rule
            end
        end
    end
    for id, rule in pairs(byId) do
        if not seen[id] then
            out[#out + 1] = rule
        end
    end
    return "rules", out
end

local function _matchesCollectRule(fruit, rule)
    if type(rule) ~= "table" or rule.enabled == false then return false end
    if rule.anyFruit and not matchSet(rule.fruits, _getName(fruit)) then return false end
    if rule.kg > 0 and not matchKg(_getWeight(fruit), rule.kg, rule.kgMode) then return false end
    if rule.requireMut == true then
        if rule.anyMut then
            if not matchMutation(rule.mutations, fruit) then return false end
        elseif not _fruitHasMutation(fruit) then
            return false
        end
    elseif rule.anyMut and not matchMutation(rule.mutations, fruit) then
        return false
    end
    if rule.anyPrice and not matchPrice(_getFruitPrice(fruit), rule.minPrice, rule.minPriceMode) then return false end
    return true
end

local function _matchesRulesMode(fruit, ac)
    local rules = ac.rules
    if type(rules) ~= "table" or #rules == 0 then
        return true
    end
    for _, rule in ipairs(rules) do
        if _matchesCollectRule(fruit, rule) then
            return true
        end
    end
    return false
end

local function _isEclipseBloomFruit(fruit)
    if not fruit then return false end
    local n = _canon(_getName(fruit))
    if n == "" then return false end
    if n == "eclipsebloom" then return true end
    return n:find("eclipsebloom", 1, true) ~= nil
end

local function _weatherKey(w)
    if w == nil then return "" end
    return tostring(w)
end

local function _isEclipseWeatherName(w)
    local c = _canon(w)
    if c == "" then return false end
    if c == "eclipse" or c == "eclipsed" or c == "solareclipse" then return true end
    -- Hindari false-positive "eclipsebloom"
    if c:find("eclipsebloom", 1, true) then return false end
    return c:find("eclipse", 1, true) ~= nil
end

-- Eclipse di GAG2 = map event (WeatherValues.Eclipse_Playing), BUKAN ActiveWeather
-- ActiveWeather sering tetap "Day"/"Night" saat Eclipse jalan.
local function _readEclipseMapPlaying()
    local WeatherValues = ReplicatedStorage:FindFirstChild("WeatherValues")
    if WeatherValues then
        for _, name in ipairs({ "Eclipse", "Eclipsed", "SolarEclipse", "Solar Eclipse" }) do
            if WeatherValues:GetAttribute(name .. "_Playing") == true then
                return true, name
            end
        end
        -- Scan semua *_Playing yang namanya mengandung eclipse
        for attrName, val in pairs(WeatherValues:GetAttributes()) do
            if val == true and type(attrName) == "string" then
                local base = attrName:match("^(.+)_Playing$")
                if base and _isEclipseWeatherName(base) then
                    return true, base
                end
            end
        end
    end

    local WP = G.WeatherPredict or G.WeatherPredictModule
        or rawget(_G, "WeatherPredict") or rawget(_G, "WeatherPredictModule")
    if type(WP) == "table" then
        if type(WP.IsWeatherLive) == "function" then
            for _, name in ipairs({ "Eclipse", "Eclipsed", "SolarEclipse", "Solar Eclipse" }) do
                local ok, hit = pcall(WP.IsWeatherLive, WP, name)
                if ok and hit == true then
                    return true, name
                end
            end
        end
        if type(WP.GetLiveMapWeathers) == "function" then
            local ok, list = pcall(WP.GetLiveMapWeathers, WP)
            if ok and type(list) == "table" then
                for _, n in ipairs(list) do
                    if _isEclipseWeatherName(n) then
                        return true, n
                    end
                end
            end
        end
    end

    -- Fallback terakhir: ActiveWeather (jarang dipakai untuk Eclipse)
    local aw = workspace:GetAttribute("ActiveWeather")
    if _isEclipseWeatherName(aw) then
        return true, tostring(aw)
    end
    return false, nil
end

local function _isEclipseWeather()
    local on = _readEclipseMapPlaying()
    return on == true
end

-- Key untuk status + deteksi transisi: "Day|Eclipse" / "Day|-"
local function _liveWeatherKey()
    local aw = _weatherKey(workspace:GetAttribute("ActiveWeather"))
    if aw == "" then aw = "?" end
    local on, mapName = _readEclipseMapPlaying()
    if on then
        return aw .. "|" .. tostring(mapName or "Eclipse")
    end
    return aw .. "|-"
end

local function _liveWeatherLabel()
    local on, mapName = _readEclipseMapPlaying()
    if on then
        return tostring(mapName or "Eclipse")
    end
    local aw = _weatherKey(workspace:GetAttribute("ActiveWeather"))
    if aw == "" then return "?" end
    return aw
end

-- Toggle ON: Eclipse Bloom yang match kg di-hold dari rule AC biasa
local function _isEclipseSpawnReserved(fruit, ac)
    if not ac or ac.eclipseSpawnEnabled ~= true then return false end
    if not _isEclipseBloomFruit(fruit) then return false end
    local kg = tonumber(ac.eclipseSpawnKg) or 0
    if kg <= 0 then return true end -- 0 = any kg → semua Eclipse Bloom di-hold
    return matchKg(_getWeight(fruit), kg, ac.eclipseSpawnKgMode)
end

local function _fruitAge(fruit)
    if not fruit then return 0 end
    local age = tonumber(fruit:GetAttribute("Age"))
    if age and age > 0 then return age end
    local node, depth = fruit.Parent, 0
    while node and depth < 10 do
        if node:IsA("Model") then
            age = tonumber(node:GetAttribute("Age"))
            if age and age > 0 then return age end
        end
        if node.Name == "Gardens" then break end
        node = node.Parent
        depth += 1
    end
    return 0
end

local function _allowed(fruit, ac)
    if not fruit or not fruit.Parent then return false end
    if _isEclipseSpawnReserved(fruit, ac) then
        return false
    end
    return _matchesRulesMode(fruit, ac)
end

local function _promptCollectable(prompt, ac, applyFilter)
    if not prompt or not prompt.Parent or not prompt:IsA("ProximityPrompt") then return false end
    if prompt:GetAttribute("Collected") then return false end
    local fruit = _fruitFromPrompt(prompt)
    if not fruit or not fruit.Parent then return false end
    local plantId = select(1, _idsFromPrompt(prompt))
    if plantId == "" then
        plantId = select(1, _resolvePlotFruitIds(fruit))
    end
    if plantId == "" then return false end
    if applyFilter and ac and not _allowed(fruit, ac) then return false end
    return true
end

local function _makeKey(plantId, fruitId)
    return tostring(plantId) .. "|" .. tostring(fruitId or "")
end

----------------------------------------------------------------
-- scan plot (GetTagged HarvestPrompt, filter plot sendiri)
----------------------------------------------------------------
local function _iterPlotHarvestPrompts(plot, force)
    if not plot then return {} end

    local now = os.clock()
    if not force
        and promptScanCache.plot == plot
        and (now - promptScanCache.at) <= PROMPT_SCAN_CACHE_SEC
        and #promptScanCache.list > 0 then
        return promptScanCache.list
    end

    local out = {}
    local checked = 0
    for _, prompt in ipairs(CollectionService:GetTagged(HARVEST_TAG)) do
        if prompt:IsA("ProximityPrompt") and prompt:IsDescendantOf(plot) then
            out[#out + 1] = prompt
        end
        checked += 1
        if checked >= 200 then
            checked = 0
            task.wait()
        end
    end

    promptScanCache.plot = plot
    promptScanCache.at = now
    promptScanCache.list = out
    return out
end

local function _scanPlotTargets(ac, applyFilter)
    local plot = getPlayerPlot()
    if not plot then return 0, nil end

    local n = 0
    local seen = {}
    local list = applyFilter and {} or nil
    local needScore = applyFilter and ac.priority ~= "off"

    for _, prompt in ipairs(_iterPlotHarvestPrompts(plot)) do
        if not _promptCollectable(prompt, ac, applyFilter) then continue end

        local fruit = _fruitFromPrompt(prompt)
        local plantId, fruitId = _idsFromPrompt(prompt)
        if plantId == "" then
            plantId, fruitId = _resolvePlotFruitIds(fruit)
        end
        local key = _makeKey(plantId, fruitId)
        if seen[key] then continue end
        seen[key] = true
        n += 1

        if list then
            local score = 0
            if needScore and type(FruitSellValue) == "table"
                and type(FruitSellValue.priorityScore) == "function" then
                local ok, sc = pcall(FruitSellValue.priorityScore, fruit, ac.priority, fruit)
                if ok and type(sc) == "number" then score = sc end
            end
            list[#list + 1] = {
                plantId = plantId,
                fruitId = fruitId,
                key = key,
                score = score,
            }
        end
    end

    if list and ac.priority ~= "off" and #list > 1 then
        table.sort(list, function(a, b)
            return (a.score or 0) > (b.score or 0)
        end)
    end

    return n, list
end

local function countReadyTargets()
    local now = os.clock()
    if now - _readyCacheAt <= COUNT_CACHE_SEC then
        return _readyCache
    end
    _readyCache = _scanPlotTargets(nil, false)
    _readyCacheAt = now
    return _readyCache
end

local function countFilteredTargets()
    local now = os.clock()
    if now - _filteredCacheAt <= COUNT_CACHE_SEC then
        return _filteredCache
    end
    _filteredCache = _scanPlotTargets(getACStateCached(), true)
    _filteredCacheAt = now
    return _filteredCache
end

----------------------------------------------------------------
-- batch cache + collect
----------------------------------------------------------------
local _consecutiveFireFail = 0
local FIRE_FAIL_SKIP      = 8

local function _isBackpackFull()
    local count = tonumber(LP:GetAttribute("FruitCount"))
    local maxCap = tonumber(LP:GetAttribute("MaxFruitCapacity"))
    if count == nil or maxCap == nil or maxCap <= 0 then return false end
    return count >= maxCap
end

local function _collectPacketOk(fireResult)
    if fireResult == false then return false end
    if type(fireResult) == "table" then
        if fireResult.Success == false or fireResult.success == false then return false end
    end
    return true
end

local function _tryCollectRemote(fn, ...)
    if type(fn) ~= "function" then return false end
    local args = table.pack(...)
    local results = table.pack(pcall(function()
        return fn(CollectFruit, table.unpack(args, 1, args.n))
    end))
    if not results[1] then return false end
    return _collectPacketOk(results[2])
end

local function _fireCollect(plantId, fruitId)
    plantId = tostring(plantId or "")
    fruitId = tostring(fruitId or "")
    if plantId == "" then return false end
    if not _ensureCollectRemote() then return false end
    if _isBackpackFull() then return false end

    -- HarvestPromptController always passes (PlantId, FruitId or "").
    if type(CollectFruit.Fire) == "function" then
        return _tryCollectRemote(CollectFruit.Fire, plantId, fruitId)
    end
    if type(CollectFruit.FireServer) == "function" then
        return _tryCollectRemote(CollectFruit.FireServer, plantId, fruitId)
    end
    if type(CollectFruit.InvokeServer) == "function" then
        return _tryCollectRemote(CollectFruit.InvokeServer, plantId, fruitId)
    end
    return false
end

local function _refillBatch(ac)
    batchIdx = 1
    table.clear(batchList)

    local _, list = _scanPlotTargets(ac, true)
    if not list then return 0 end

    for i = 1, #list do
        batchList[i] = list[i]
    end

    batchIdx = 1
    return #batchList
end

local function _batchEmpty()
    return batchIdx > #batchList
end

local function _fireNextFromBatch()
    if _batchEmpty() then return 0 end

    local item = batchList[batchIdx]
    if not item then
        batchIdx += 1
        return 0
    end

    if _fireCollect(item.plantId, item.fruitId) then
        batchIdx += 1
        _consecutiveFireFail = 0
        _totalCollected += 1
        _lastTickCollected = 1
        _invalidatePromptScan()
        _readyCacheAt = 0
        _filteredCacheAt = 0
        return 1
    end

    _lastTickCollected = 0
    _consecutiveFireFail += 1
    if _consecutiveFireFail >= FIRE_FAIL_SKIP then
        _consecutiveFireFail = 0
        batchIdx += 1
    end
    return 0
end

-- Collect 1 khusus spawn weather: coba UUID lain kalau Fire gagal
-- Simple: Eclipse → hold; ≠ Eclipse → collect 1x per ActiveWeather (Day/Night/Moon/...)
-- Tidak bergantung Eclipse_Playing ON→OFF (sering miss → stuck "wait next Eclipse")
local eclipseSpawnCollectedWeather = nil -- ActiveWeather saat last collect 1x
local eclipseSpawnTryAt = 0
local ECLIPSE_SPAWN_TRY_SEC = 0.75

local function _activeWeatherCycleKey()
    local aw = _weatherKey(workspace:GetAttribute("ActiveWeather"))
    if aw == "" then return "?" end
    return aw
end

local function _eclipseSpawnDoneThisWeather()
    return eclipseSpawnCollectedWeather ~= nil
        and eclipseSpawnCollectedWeather == _activeWeatherCycleKey()
end

local function _listEclipseSpawnCandidates(ac, forceScan)
    local out = {}
    if not ac or ac.eclipseSpawnEnabled ~= true then return out end
    local plot = getPlayerPlot()
    if not plot then return out end

    local seen = {}
    for _, prompt in ipairs(_iterPlotHarvestPrompts(plot, forceScan == true)) do
        if prompt and prompt.Parent and prompt:IsA("ProximityPrompt")
            and not prompt:GetAttribute("Collected") then
            local fruit = _fruitFromPrompt(prompt)
            if fruit and fruit.Parent and _isEclipseSpawnReserved(fruit, ac) then
                local plantId, fruitId = _idsFromPrompt(prompt)
                if plantId == "" then
                    plantId, fruitId = _resolvePlotFruitIds(fruit)
                end
                local key = _makeKey(plantId, fruitId)
                if plantId ~= "" and not seen[key] then
                    seen[key] = true
                    out[#out + 1] = {
                        plantId = plantId,
                        fruitId = fruitId,
                        key = key,
                        age = _fruitAge(fruit),
                        kg = _getWeight(fruit),
                        fruit = fruit,
                    }
                end
            end
        end
    end

    table.sort(out, function(a, b)
        local aa, bb = tonumber(a.age) or 0, tonumber(b.age) or 0
        if aa ~= bb then return aa > bb end
        return (tonumber(a.kg) or 0) > (tonumber(b.kg) or 0)
    end)
    return out
end

local function _tryEclipseSpawnCollect(ac)
    if not ac or ac.eclipseSpawnEnabled ~= true then return false end
    if _isEclipseWeather() then return false end
    if _eclipseSpawnDoneThisWeather() then return false end
    if _isBackpackFull() then return false end
    if not _ensureCollectRemote() then return false end

    -- Urut age tertinggi dulu; gagal → UUID berikutnya
    local list = _listEclipseSpawnCandidates(ac, true)
    for i = 1, #list do
        local item = list[i]
        if _fireCollect(item.plantId, item.fruitId) then
            _totalCollected += 1
            _lastTickCollected = 1
            _invalidatePromptScan()
            _readyCacheAt = 0
            _filteredCacheAt = 0
            return true
        end
        task.wait(0.05)
    end
    return false
end

local function _tickEclipseSpawn(ac)
    if not ac or ac.eclipseSpawnEnabled ~= true then
        eclipseSpawnCollectedWeather = nil
        return false
    end

    -- Saat map Eclipse: hold; clear flag supaya setelah Eclipse (ActiveWeather sama) boleh 1x lagi
    if _isEclipseWeather() then
        eclipseSpawnCollectedWeather = nil
        return false
    end

    -- ≠ Eclipse: 1x per ActiveWeather; ganti Day/Night/Moon → boleh collect lagi
    if _eclipseSpawnDoneThisWeather() then return false end

    local now = os.clock()
    if (now - eclipseSpawnTryAt) < ECLIPSE_SPAWN_TRY_SEC then
        return false
    end
    eclipseSpawnTryAt = now

    if _tryEclipseSpawnCollect(ac) then
        eclipseSpawnCollectedWeather = _activeWeatherCycleKey()
        return true
    end
    return false
end

local function collectLoop(myId)
    loopAliveId = myId
    _log("loop start", myId)

    local lastFilterKey = ""
    local plotWaitAt = 0
    local lastScanAt = 0

    while running and myId == loopId do
        local ac = getACStateCached()
        local filterKey = _batchFilterKey(ac)
        if filterKey ~= lastFilterKey then
            if lastFilterKey ~= "" then
                _clearBatchCaches()
                table.clear(weightCache)
            end
            lastFilterKey = filterKey
        end

        if not ac.enabled then
            task.wait(0.35)
        elseif _isBackpackFull() then
            task.wait(0.75)
        elseif not _ensureCollectRemote() then
            task.wait(0.5)
        else
            -- Prioritas: 1 Eclipse Bloom untuk spawn weather (bukan lewat rules batch)
            if _tickEclipseSpawn(ac) then
                _waitAfterFire(ac)
            elseif _batchEmpty() then
                local plot = getPlayerPlot()
                if not plot then
                    if os.clock() - plotWaitAt >= 2 then
                        plotWaitAt = os.clock()
                        cachedPlot = nil
                        cachedPlotAt = 0
                        _invalidatePromptScan()
                        getPlayerPlot(true)
                    end
                    task.wait(0.35)
                else
                    local now = os.clock()
                    if (now - lastScanAt) < SCAN_MIN_SEC then
                        task.wait(0.12)
                    else
                        lastScanAt = now
                        local n = _refillBatch(ac)
                        if n == 0 then
                            task.wait(IDLE_WAIT_SEC)
                        end
                    end
                end
            else
                _fireNextFromBatch()
                _waitAfterFire(ac)
            end
        end
    end

    if loopAliveId == myId then loopAliveId = 0 end
    _log("loop end", myId)
end

----------------------------------------------------------------
-- public API
----------------------------------------------------------------
local function _coerceOn(a, b)
    if type(a) == "table" then return b == true end
    return a == true
end

function M.SetEnabled(a, b)
    local on = _coerceOn(a, b)
    G.AUTO_COLLECT_FRUIT_ENABLED = on
    _G.AUTO_COLLECT_FRUIT_ENABLED = on
    _writeMainCollect({ enabled = on })
    _invalidateACCache()

    if on then
        running = true
        if loopAliveId > 0 and loopAliveId == loopId then return end
        loopId += 1
        local myId = loopId
        task.spawn(function()
            local ok, err = pcall(collectLoop, myId)
            if not ok then
                _warn("loop error:", err)
                if loopAliveId == myId then loopAliveId = 0 end
            end
        end)
    else
        running = false
        loopId += 1
    end
end

M.setEnabled = M.SetEnabled
M.Start = function() return M.SetEnabled(true) end
M.start = M.Start
M.Stop = function() return M.SetEnabled(false) end
M.stop = M.Stop
M.IsRunning = function()
    return running == true and loopAliveId > 0
end
M.isRunning = M.IsRunning

function M.EnsureRunning()
    if not _readEnabled() then
        M.Stop()
        return false
    end
    if running and loopAliveId > 0 and loopAliveId == loopId then
        return true
    end
    M.Start()
    return running and loopAliveId > 0
end
M.ensureRunning = M.EnsureRunning

local function _applySet(keyGlobal, keyMain, map)
    map = _normalizeSet(map)
    G[keyGlobal] = map
    _G[keyGlobal] = map
    _writeMainCollect({ [keyMain] = _setToArray(map) })
    _invalidateACCache()
    return map
end

function M.SetFruits(a, b)
    local map = (type(a) == "table" and b ~= nil) and b or a
    return _applySet("AUTO_COLLECT_FRUITS_SELECTED", "fruits", map)
end

