M.setSelected = M.SetFruits
M.setFruits   = M.SetFruits

function M.SetMutations(a, b)
    local map = (type(a) == "table" and b ~= nil) and b or a
    return _applySet("AUTO_COLLECT_MUTATIONS_SELECTED", "mutations", map)
end

M.setMutations = M.SetMutations

function M.SetKgFilter(a, b, c)
    local kg, mode
    if type(a) == "table" then
        kg, mode = b, c
    else
        kg, mode = a, b
    end
    kg, mode = _normalizeKgFilter(kg, mode)
    local rule = _formatKgRule(kg, mode)
    local curRule = G.AUTO_COLLECT_KG_RULE or rawget(_G, "AUTO_COLLECT_KG_RULE")
    if tonumber(G.AUTO_COLLECT_KG or rawget(_G, "AUTO_COLLECT_KG")) == kg
        and tostring(G.AUTO_COLLECT_KG_MODE or rawget(_G, "AUTO_COLLECT_KG_MODE") or "") == mode
        and tostring(curRule or "") == rule then
        return
    end
    G.AUTO_COLLECT_KG = kg
    G.AUTO_COLLECT_KG_MODE = mode
    G.AUTO_COLLECT_KG_RULE = rule
    _G.AUTO_COLLECT_KG = kg
    _G.AUTO_COLLECT_KG_MODE = mode
    _G.AUTO_COLLECT_KG_RULE = rule
    _writeMainCollect({ kg = kg, kgMode = mode, kgRule = rule })
    _invalidateACCache()
end

M.setKgFilter = M.SetKgFilter

function M.SetFilterMode(_mode)
    G.AUTO_COLLECT_FILTER_MODE = "rules"
    _G.AUTO_COLLECT_FILTER_MODE = "rules"
    _writeMainCollect({ filterMode = "rules" })
    _invalidateACCache()
    return "rules"
end

M.setFilterMode = M.SetFilterMode

function M.SetRules(rules, order)
    rules = type(rules) == "table" and rules or {}
    order = type(order) == "table" and order or {}
    G.AUTO_COLLECT_RULES = rules
    _G.AUTO_COLLECT_RULES = rules
    G.AUTO_COLLECT_RULES_ORDER = order
    _G.AUTO_COLLECT_RULES_ORDER = order
    _writeMainCollect({ rules = rules, rulesOrder = order })
    _invalidateACCache()
end

M.setRules = M.SetRules

function M.AddRule(rule)
    rule = _normalizeCollectRule(rule)
    if rule.id == "" then
        rule.id = "r" .. tostring(math.floor(os.clock() * 1000)) .. "_" .. tostring(math.random(1000, 9999))
    end
    local ac = getACStateCached()
    local rules, order = {}, {}
    for _, r in ipairs(ac.rules or {}) do
        rules[#rules + 1] = _ruleToPersist(r)
        order[#order + 1] = r.id
    end
    rules[#rules + 1] = _ruleToPersist(rule)
    order[#order + 1] = rule.id
    M.SetRules(rules, order)
    return rule.id
end

M.addRule = M.AddRule

function M.RemoveRule(ruleId)
    ruleId = tostring(ruleId or "")
    if ruleId == "" then return end
    local ac = getACStateCached()
    local rules, order = {}, {}
    for _, r in ipairs(ac.rules or {}) do
        if r.id ~= ruleId then
            rules[#rules + 1] = _ruleToPersist(r)
            order[#order + 1] = r.id
        end
    end
    M.SetRules(rules, order)
end

M.removeRule = M.RemoveRule

function M.GetRules()
    local ac = getACStateCached()
    return ac.rules or {}, "rules"
end

M.getRules = M.GetRules

function M.SetDelay(a, b)
    local n = _normalizeDelay(type(a) == "table" and b or a, 0.1)
    G.AUTO_COLLECT_DELAY = n
    _G.AUTO_COLLECT_DELAY = n
    _writeMainCollect({ delay = n })
    _invalidateACCache()
end

M.setDelay = M.SetDelay

function M.SetPriority(a, b)
    local mode = (type(a) == "table" and b) or a
    mode = tostring(mode or "off"):lower()
    if mode ~= "price" and mode ~= "rarity" and mode ~= "weight" then
        mode = "off"
    end
    G.AUTO_COLLECT_PRIORITY = mode
    _G.AUTO_COLLECT_PRIORITY = mode
    _writeMainCollect({ priority = mode })
    _invalidateACCache()
    return mode
end

M.setPriority = M.SetPriority

function M.SetEclipseSpawn(cfg)
    cfg = type(cfg) == "table" and cfg or {}
    local enabled = cfg.enabled
    if enabled == nil then enabled = cfg.eclipseSpawnEnabled end
    enabled = (enabled == true)

    local kgRule = cfg.kgRule or cfg.eclipseSpawnKgRule
    local kg, kgMode
    if type(kgRule) == "string" and kgRule:gsub("%s+", "") ~= "" then
        kg, kgMode = _parseKgRuleInput(kgRule)
    else
        kg, kgMode = _normalizeKgFilter(cfg.kg or cfg.eclipseSpawnKg, cfg.kgMode or cfg.eclipseSpawnKgMode)
    end
    kgRule = _formatKgRule(kg, kgMode)

    G.AUTO_COLLECT_ECLIPSE_SPAWN = enabled
    _G.AUTO_COLLECT_ECLIPSE_SPAWN = enabled
    G.AUTO_COLLECT_ECLIPSE_SPAWN_KG_RULE = kgRule
    _G.AUTO_COLLECT_ECLIPSE_SPAWN_KG_RULE = kgRule
    _writeMainCollect({
        eclipseSpawnEnabled = enabled,
        eclipseSpawnKgRule = kgRule,
        eclipseSpawnKg = kg,
        eclipseSpawnKgMode = kgMode,
    })
    if not enabled then
        eclipseSpawnCollectedWeather = nil
    end
    _invalidateACCache()
    return {
        enabled = enabled,
        kgRule = kgRule,
        kg = kg,
        kgMode = kgMode,
    }
end

M.setEclipseSpawn = M.SetEclipseSpawn

function M.GetEclipseSpawn()
    local on, kg, mode, rule = _readEclipseSpawnConfig(
        ((rawget(_G, "MAIN") or G.MAIN) or {}).auto
            and (rawget(_G, "MAIN") or G.MAIN).auto.collect
    )
    return {
        enabled = on,
        kg = kg,
        kgMode = mode,
        kgRule = rule,
        done = _eclipseSpawnDoneThisWeather(),
        weatherEclipse = _isEclipseWeather(),
        weather = _liveWeatherLabel(),
        cycleWeather = _activeWeatherCycleKey(),
    }
end

M.getEclipseSpawn = M.GetEclipseSpawn

-- Status UI: jumlah siap + 1 buah age tertinggi (match kg hold)
function M.PeekEclipseSpawnStatus()
    local ac = getACStateCached()
    local info = {
        enabled = ac.eclipseSpawnEnabled == true,
        kgRule = ac.eclipseSpawnKgRule or "0",
        count = 0,
        bestAge = 0,
        bestKg = 0,
        bestFruitId = "",
        done = _eclipseSpawnDoneThisWeather(),
        weatherEclipse = _isEclipseWeather(),
        weather = _liveWeatherLabel(),
        cycleWeather = _activeWeatherCycleKey(),
    }
    if not info.enabled then
        return info
    end

    local list = _listEclipseSpawnCandidates(ac, false)
    info.count = #list
    if list[1] then
        info.bestAge = tonumber(list[1].age) or 0
        info.bestKg = tonumber(list[1].kg) or 0
        info.bestFruitId = tostring(list[1].fruitId or "")
    end
    return info
end

M.peekEclipseSpawnStatus = M.PeekEclipseSpawnStatus

function M.EstimateFruitValue(model)
    if type(FruitSellValue) == "table" and type(FruitSellValue.fromFruit) == "function" then
        return FruitSellValue.fromFruit(model)
    end
    return 0
end

M.estimateFruitValue = M.EstimateFruitValue

function M.SyncFromState()
    local ac = getACState()
    M.SetFilterMode("rules")
    if type(ac.rules) == "table" then
        local rules, order = {}, {}
        for _, r in ipairs(ac.rules) do
            rules[#rules + 1] = _ruleToPersist(r)
            order[#order + 1] = r.id
        end
        local MAIN = rawget(_G, "MAIN") or G.MAIN
        local mainRules = MAIN and MAIN.auto and MAIN.auto.collect and MAIN.auto.collect.rules
        local mainOrder = MAIN and MAIN.auto and MAIN.auto.collect and MAIN.auto.collect.rulesOrder
        if type(mainRules) == "table" and #mainRules > 0 then
            M.SetRules(mainRules, mainOrder or {})
        else
            M.SetRules(rules, order)
        end
    end
    M.SetDelay(ac.delay)
    M.SetPriority(ac.priority)
    M.SetEclipseSpawn({
        enabled = ac.eclipseSpawnEnabled == true,
        kgRule = ac.eclipseSpawnKgRule,
        kg = ac.eclipseSpawnKg,
        kgMode = ac.eclipseSpawnKgMode,
    })
    if ac.enabled then
        G.AUTO_COLLECT_FRUIT_ENABLED = true
        _G.AUTO_COLLECT_FRUIT_ENABLED = true
        running = true
        M.EnsureRunning()
    else
        M.SetEnabled(false)
    end
end

M.syncFromState = M.SyncFromState

