function M.GetStats()
    local pending = 0
    if batchIdx <= #batchList then
        pending = #batchList - batchIdx + 1
    end
    local ac = getACStateCached()
    return {
        running = running,
        loopId = loopId,
        loopAlive = loopAliveId > 0,
        enabled = _readEnabled(),
        remoteReady = _ensureCollectRemote(),
        backpackFull = _isBackpackFull(),
        readyQueue = countReadyTargets(),
        filteredQueue = countFilteredTargets(),
        batchPending = pending,
        lastTickCollected = _lastTickCollected,
        totalCollected = _totalCollected,
        delay = _fireDelaySec(ac),
        priority = ac.priority,
        eclipseSpawnEnabled = ac.eclipseSpawnEnabled == true,
        eclipseSpawnKgRule = ac.eclipseSpawnKgRule,
        eclipseSpawnDone = _eclipseSpawnDoneThisWeather(),
        eclipseSpawnCycleWeather = _activeWeatherCycleKey(),
        weatherEclipse = _isEclipseWeather(),
    }
end

function M.DumpState()
    local st = M.GetStats()
    local ac = getACStateCached()
    _warn("========== AUTO COLLECT DUMP ==========")
    _warn("running:", st.running, "| enabled:", ac.enabled, "| remote:", _ensureCollectRemote())
    _warn("ready:", st.readyQueue, "| filtered:", st.filteredQueue, "| batch:", st.batchPending)
    _warn("last fire:", st.lastTickCollected, "| total fired:", st.totalCollected)
    _warn("filters: rules=", #(ac.rules or {}), "useRules=", ac.useRules)
    _warn("priority:", ac.priority)
    _warn("=======================================")
    return st
end

function M.CheckFilter()
    local ac = getACStateCached()
    local plot = getPlayerPlot(true)
    local out = {
        enabled = ac.enabled,
        running = running and loopAliveId > 0,
        remote = _ensureCollectRemote(),
        plot = plot and plot.Name or nil,
        ready = 0,
        filtered = 0,
        blocked = {},
    }

    if not plot then
        _warn("[AC Check] plot tidak ketemu")
        return out
    end

    for _, prompt in ipairs(_iterPlotHarvestPrompts(plot)) do
        if prompt:GetAttribute("Collected") then continue end
        local fruit = _fruitFromPrompt(prompt)
        if not fruit then
            out.blocked[#out.blocked + 1] = { why = "no fruit model" }
            continue
        end
        local plantId = select(1, _resolvePlotFruitIds(fruit))
        if plantId == "" then
            out.blocked[#out.blocked + 1] = { why = "no PlantId", model = fruit.Name }
            continue
        end
        out.ready += 1

        if not _allowed(fruit, ac) then
            if #out.blocked < 5 then
                out.blocked[#out.blocked + 1] = {
                    why = "rules",
                    name = _getName(fruit),
                    weight = _getWeight(fruit),
                }
            end
            continue
        end
        out.filtered += 1
    end

    _warn("[AC Check] enabled=", out.enabled, "running=", out.running,
        "remote=", out.remote, "plot=", out.plot)
    _warn("[AC Check] ready=", out.ready, "filtered=", out.filtered,
        "rules=", #(ac.rules or {}))
    for i, b in ipairs(out.blocked) do
        _warn("[AC Check] blocked sample", i, b.why, b.name or "", b.weight or "", b.rule or "")
    end
    return out
end

local function _whyBlocked(fruit, ac)
    if not fruit or not fruit.Parent then
        return "no_fruit"
    end
    if _matchesRulesMode(fruit, ac) then
        return nil
    end
    return "rules", _getName(fruit), _getWeight(fruit)
end

function M.DebugFilterScan(opts)
    opts = type(opts) == "table" and opts or {}
    local maxShow = math.floor(tonumber(opts.maxShow) or 20)
    if maxShow < 1 then maxShow = 20 end
    local doPrint = (opts.print ~= false)

    M.InvalidateCountCache()
    _invalidateACCache()

    local ac = getACStateCached()
    local plot = getPlayerPlot(true)
    local out = {
        plot = plot and plot.Name or nil,
        ruleCount = #(ac.rules or {}),
        readyTotal = 0,
        inFilter = 0,
        outFilter = 0,
        blocked = { rules = 0, no_fruit = 0, no_plant = 0, collected = 0 },
        inSamples = {},
        outSamples = {},
        countReady = 0,
        countFiltered = 0,
        peekHarvest = 0,
    }

    if not plot then
        if doPrint then warn("[AC-FilterDbg] plot tidak ketemu") end
        return out
    end

    for _, prompt in ipairs(_iterPlotHarvestPrompts(plot, true)) do
        if prompt:GetAttribute("Collected") then
            out.blocked.collected += 1
            continue
        end

        local fruit = _fruitFromPrompt(prompt)
        if not fruit then
            out.blocked.no_fruit += 1
            continue
        end

        local plantId = select(1, _resolvePlotFruitIds(fruit))
        if plantId == "" then
            out.blocked.no_plant += 1
            continue
        end

        out.readyTotal += 1
        local name = _getName(fruit)
        local weight = _getWeight(fruit)
        local why, wname, wweight = _whyBlocked(fruit, ac)

        if not why then
            out.inFilter += 1
            if #out.inSamples < maxShow then
                out.inSamples[#out.inSamples + 1] = {
                    name = tostring(name),
                    weight = weight,
                }
            end
        else
            out.outFilter += 1
            local key = why
            if out.blocked[key] ~= nil then
                out.blocked[key] += 1
            end
            if #out.outSamples < maxShow then
                out.outSamples[#out.outSamples + 1] = {
                    why = why,
                    name = tostring(wname or name),
                    weight = tonumber(wweight or weight) or 0,
                }
            end
        end
    end

    out.countReady = M.CountReady()
    out.countFiltered = M.CountFiltered()
    out.peekHarvest = M.PeekHarvestCount()

    if doPrint then
        print("========== AUTO COLLECT FILTER DEBUG ==========")
        print("plot:", out.plot or "?")
        print("rules:", out.ruleCount, "(OR — kosong = collect semua)")
        print("--- counts ---")
        print("ready total (semua HarvestPrompt):", out.readyTotal)
        print("IN filter  (masuk AC / label / gate):", out.inFilter)
        print("OUT filter (di luar filter):", out.outFilter)
        print("CountReady():", out.countReady, "| CountFiltered():", out.countFiltered,
            "| PeekHarvest():", out.peekHarvest)
        if out.inFilter ~= out.peekHarvest or out.inFilter ~= out.countFiltered then
            warn("[AC-FilterDbg] mismatch label vs scan — coba tunggu 1 loop atau re-run debug")
        end
        print("--- blocked by reason ---")
        print("  rules:", out.blocked.rules)
        print("--- sample IN filter (max", maxShow, ") ---")
        for i, row in ipairs(out.inSamples) do
            print(string.format("  [%d] IN  %s  %.2fkg", i, row.name, row.weight or 0))
        end
        if out.inFilter > #out.inSamples then
            print(string.format("  ... +%d lagi IN", out.inFilter - #out.inSamples))
        end
        print("--- sample OUT filter (max", maxShow, ") ---")
        for i, row in ipairs(out.outSamples) do
            print(string.format("  [%d] OUT %-9s %s  %.2fkg",
                i, row.why, row.name, row.weight or 0))
        end
        if out.outFilter > #out.outSamples then
            print(string.format("  ... +%d lagi OUT", out.outFilter - #out.outSamples))
        end
        print("===============================================")
    end

    return out
end

M.debugFilterScan = M.DebugFilterScan
_G.__GAG2_COLLECT_FILTER_DEBUG = M.DebugFilterScan
G.__GAG2_COLLECT_FILTER_DEBUG = M.DebugFilterScan

