function M.PeekHarvestBreakdown()
    local total = M.PeekReadyCount()
    local inFilter = M.PeekFilteredCount()
    if inFilter > total then
        inFilter = total
    end
    return {
        total = total,
        inFilter = inFilter,
        outFilter = math.max(0, total - inFilter),
    }
end

