function M.NormalizeRulesList(rawRules, order)
    rawRules = type(rawRules) == "table" and rawRules or {}
    order = type(order) == "table" and order or {}
    local byId = {}
    if #rawRules > 0 then
        for _, r in ipairs(rawRules) do
            local norm = _normalizeCollectRule(r)
            if norm.id == "" then
                norm.id = "r" .. tostring(_)
            end
            byId[norm.id] = norm
        end
    else
        for id, r in pairs(rawRules) do
            if type(r) == "table" then
                local norm = _normalizeCollectRule(r)
                norm.id = tostring(norm.id ~= "" and norm.id or id)
                byId[norm.id] = norm
            end
        end
    end
    local out, seen = {}, {}
    for _, id in ipairs(order) do
        id = tostring(id or "")
        local rule = byId[id]
        if rule and not seen[id] then
            seen[id] = true
            out[#out + 1] = rule
        end
    end
    for id, rule in pairs(byId) do
        if not seen[id] then
            out[#out + 1] = rule
        end
    end
    return out
end
M.normalizeRulesList = M.NormalizeRulesList

function M.MatchesRulesState(fruit, state)
    if not fruit or not fruit.Parent then return false end
    state = type(state) == "table" and state or {}
    return _matchesRulesMode(fruit, { rules = state.rules or {} })
end
M.matchesRulesState = M.MatchesRulesState

function M.GetFruitName(model)
    return _getName(model)
end
M.getFruitName = M.GetFruitName

-- Gate untuk Auto Watering / Auto Sprinkler: pause jika match filter = 0 stabil 10s
-- (buah ada tapi semua skipped / out of filter).
local GROW_ASSIST_ZERO_PAUSE_SEC = 10
local _growAssistZeroSince = nil
local _growAssistLastIn = -1
local _growAssistPaused = false

function M.ResetGrowAssistGate()
    _growAssistZeroSince = nil
    _growAssistLastIn = -1
    _growAssistPaused = false
end

M.resetGrowAssistGate = M.ResetGrowAssistGate

function M.CheckGrowAssistGate()
    local br = M.PeekHarvestBreakdown()
    local inN = math.max(0, math.floor(tonumber(br.inFilter) or 0))
    local outN = math.max(0, math.floor(tonumber(br.outFilter) or 0))
    local total = math.max(0, math.floor(tonumber(br.total) or 0))

    if inN > 0 then
        _growAssistZeroSince = nil
        _growAssistLastIn = inN
        _growAssistPaused = false
        return true, nil, inN, outN
    end

    if total <= 0 and outN <= 0 then
        _growAssistZeroSince = nil
        _growAssistLastIn = 0
        _growAssistPaused = false
        return true, nil, 0, 0
    end

    if inN ~= _growAssistLastIn then
        _growAssistLastIn = inN
        _growAssistZeroSince = os.clock()
        _growAssistPaused = false
    elseif not _growAssistZeroSince then
        _growAssistZeroSince = os.clock()
    end

    if os.clock() - _growAssistZeroSince >= GROW_ASSIST_ZERO_PAUSE_SEC then
        _growAssistPaused = true
        return false, "collect_idle", inN, outN
    end

    return true, "collect_wait", inN, outN
end

M.checkGrowAssistGate = M.CheckGrowAssistGate

function M.IsGrowAssistPaused()
    return _growAssistPaused == true
end

M.isGrowAssistPaused = M.IsGrowAssistPaused

function M.CollectOnce()
    local ac = getACStateCached()
    if _batchEmpty() then
        _refillBatch(ac)
    end
    return _fireNextFromBatch()
end

M.collectOnce = M.CollectOnce

