_G.AUTO_COLLECT_BURST = nil

local _plotWatchBound = false
local function _bindPlotWatch()
    if _plotWatchBound then return end
    _plotWatchBound = true

    local function onPlotReady()
        cachedPlot = nil
        cachedPlotAt = 0
        CollectFruit = nil
        _invalidatePromptScan()
        if _readEnabled() then
            pcall(M.EnsureRunning)
        end
    end

    pcall(function()
        LP:GetAttributeChangedSignal("PlotId"):Connect(onPlotReady)
    end)

    task.spawn(function()
        local gardens = workspace:FindFirstChild("Gardens")
            or workspace:WaitForChild("Gardens", 60)
        if gardens then
            gardens.ChildAdded:Connect(onPlotReady)
            onPlotReady()
        end
    end)
end

task.defer(function()
    _bindPlotWatch()
    pcall(function() M.SyncFromState() end)
    if _readEnabled() then
        pcall(M.EnsureRunning)
    end
end)

return M
 end,                    required = false },
    { key = "AutoSell",                name = "Auto Sell",               factory = function() -- AutoSell.lua — Grow A Garden 2
-- Tanpa filter: Networking.NPCS.PreviewSellAll / SellAll
-- Dengan filter: scan backpack → SellFruit(fruitId) satu per satu

