local function _getEspBackpack()
    return G.EspFruitBackpack or _G.EspFruitBackpack
end

local function _fsv()
    if type(FruitSellValue) == "table" then return FruitSellValue end
    FruitSellValue = G.FruitSellValue or _G.FruitSellValue
    if type(FruitSellValue) == "table" then return FruitSellValue end
    pcall(function() FruitSellValue = require(script.Parent.FruitSellValue) end)
    if type(FruitSellValue) == "table" then return FruitSellValue end
    return nil
end

local function _writeMainSell(patch)
    local MAIN = rawget(_G, "MAIN") or G.MAIN
    if type(MAIN) ~= "table" then return end
    MAIN.auto = MAIN.auto or {}
    MAIN.auto.sell = MAIN.auto.sell or {}
    for k, v in pairs(patch) do
        MAIN.auto.sell[k] = v
    end
    G.MAIN = MAIN
    _G.MAIN = MAIN
end

local function _normalizeSet(src)
    if type(src) ~= "table" then return {} end
    local out = {}
    for i = 1, #src do
        local v = src[i]
        if v ~= nil and tostring(v) ~= "" then out[tostring(v)] = true end
    end
    if next(out) then return out end
    for k, v in pairs(src) do
        if v == true or v == 1 or v == "true" then out[tostring(k)] = true end
    end
    return out
end

local function _arrayToMap(arr)
    return _normalizeSet(arr)
end

local function _canon(s)
    return tostring(s or ""):lower():gsub("[%s_%-]+", "")
end

local function _hasAny(map)
    if type(map) ~= "table" then return false end
    for _, v in pairs(map) do
        if v == true then return true end
    end
    return false
end

local function _normalizeKgFilter(kg, mode)
    kg = tonumber(kg) or 0
    mode = tostring(mode or "above")
    if kg < 0 then
        kg = math.abs(kg)
        mode = "below"
    end
    if mode ~= "below" then mode = "above" end
    return kg, mode
end

local function _normalizePriceFilter(price, mode)
    price = tonumber(price) or 0
    mode = tostring(mode or "above")
    if price < 0 then
        price = math.floor(math.abs(price))
        mode = "below"
    end
    if mode ~= "below" then mode = "above" end
    return price, mode
end

local function _parseKgRuleInput(txt)
    txt = tostring(txt or ""):gsub("%s+", "")
    if txt == "" then return 0, "above" end
    local n = tonumber(txt)
    if not n then return 0, "above" end
    if n < 0 then return math.abs(n), "below" end
    return n, "above"
end

local function _parseScaledNumber(txt)
    txt = tostring(txt or ""):lower():gsub("%s+", ""):gsub(",", "")
    if txt == "" then return nil end
    local sign = 1
    if txt:sub(1, 1) == "-" then
        sign = -1
        txt = txt:sub(2)
    end
    local suffixes = {
        { "juta", 1000000 }, { "jt", 1000000 },
        { "ribu", 1000 }, { "rb", 1000 },
        { "b", 1000000000 }, { "m", 1000000 }, { "k", 1000 },
    }
    for _, pair in ipairs(suffixes) do
        local suf, mult = pair[1], pair[2]
        if #txt > #suf and txt:sub(-#suf) == suf then
            local n = tonumber(txt:sub(1, -#suf - 1))
            if n then return n * mult * sign end
        end
    end
    local n = tonumber(txt)
    if n then return n * sign end
    return nil
end

local function _parsePriceRuleInput(txt)
    local n = _parseScaledNumber(txt)
    if not n then return 0, "above" end
    if n < 0 then return math.floor(math.abs(n)), "below" end
    return math.floor(n), "above"
end

local function _priceRuleActive(txt)
    txt = tostring(txt or ""):gsub("%s+", ""):gsub(",", "")
    return txt ~= "" and txt ~= "0"
end

local function _formatKgRule(kg, mode)
    kg = tonumber(kg) or 0
    mode = tostring(mode or "above")
    if kg <= 0 then return "0" end
    if mode == "below" then return "-" .. tostring(kg) end
    return tostring(kg)
end

local function _formatPriceRule(price, mode)
    price = tonumber(price) or 0
    mode = tostring(mode or "above")
    if price <= 0 then return "0" end
    if mode == "below" then return "-" .. tostring(price) end
    return tostring(price)
end

local function _setToArray(map)
    local out = {}
    if type(map) ~= "table" then return out end
    for k, v in pairs(map) do
        if v == true then out[#out + 1] = tostring(k) end
    end
    table.sort(out)
    return out
end

local function _normalizeSellRule(raw)
    raw = type(raw) == "table" and raw or {}
    local fruits = _normalizeSet(raw.fruits)
    local mutations = _normalizeSet(raw.mutations)
    local kg, kgMode = _normalizeKgFilter(raw.kg, raw.kgMode)
    if type(raw.kgRule) == "string" and raw.kgRule:gsub("%s+", "") ~= "" then
        kg, kgMode = _parseKgRuleInput(raw.kgRule)
    end
    local minPrice, minPriceMode = _normalizePriceFilter(raw.minPrice, raw.minPriceMode)
    local priceRule = raw.priceRule
    if type(priceRule) ~= "string" or priceRule:gsub("%s+", "") == "" then
        priceRule = raw.minPriceRule
    end
    if type(priceRule) == "string" and priceRule:gsub("%s+", "") ~= "" then
        minPrice, minPriceMode = _parsePriceRuleInput(priceRule)
    end
    local requireMut = raw.requireMut == true
    return {
        id = tostring(raw.id or ""),
        enabled = raw.enabled ~= false,
        fruits = fruits,
        mutations = mutations,
        kg = kg,
        kgMode = kgMode,
        kgRule = type(raw.kgRule) == "string" and raw.kgRule ~= ""
            and raw.kgRule or _formatKgRule(kg, kgMode),
        minPrice = minPrice,
        minPriceMode = minPriceMode,
        priceRule = type(priceRule) == "string" and priceRule ~= ""
            and priceRule or _formatPriceRule(minPrice, minPriceMode),
        requireMut = requireMut,
        anyFruit = _hasAny(fruits),
        anyMut = _hasAny(mutations),
        anyPrice = minPrice > 0,
    }
end

local function _loadSellRules(st)
    st = type(st) == "table" and st or {}
    local MAIN = rawget(_G, "MAIN") or G.MAIN
    local mainSt = MAIN and MAIN.auto and MAIN.auto.sell

    local rawRules = G.AUTO_SELL_RULES or rawget(_G, "AUTO_SELL_RULES")
        or st.rules or (mainSt and mainSt.rules)
    local order = G.AUTO_SELL_RULES_ORDER or rawget(_G, "AUTO_SELL_RULES_ORDER")
        or st.rulesOrder or (mainSt and mainSt.rulesOrder)

    local byId = {}
    if type(rawRules) == "table" then
        if #rawRules > 0 then
            for i, r in ipairs(rawRules) do
                local norm = _normalizeSellRule(r)
                if norm.id == "" then
                    norm.id = "sr" .. tostring(i)
                end
                byId[norm.id] = norm
            end
        else
            for id, r in pairs(rawRules) do
                if type(r) == "table" then
                    local norm = _normalizeSellRule(r)
                    norm.id = tostring(norm.id ~= "" and norm.id or id)
                    byId[norm.id] = norm
                end
            end
        end
    end

    local out, seen = {}, {}
    if type(order) == "table" then
        for _, id in ipairs(order) do
            id = tostring(id or "")
            local rule = byId[id]
            if rule and not seen[id] then
                seen[id] = true
                out[#out + 1] = rule
            end
        end
    end
    for id, rule in pairs(byId) do
        if not seen[id] then
            out[#out + 1] = rule
        end
    end
    return "rules", out
end

local function _readSellWhenFull(st)
    if type(st) == "table" then
        if st.sellWhenFull == true then return true end
        if st.sellWhenFull == false then return false end
    end
    if G.AUTO_SELL_WHEN_FULL == true or rawget(_G, "AUTO_SELL_WHEN_FULL") == true then
        return true
    end
    if G.AUTO_SELL_WHEN_FULL == false or rawget(_G, "AUTO_SELL_WHEN_FULL") == false then
        return false
    end
    return true
end

local function getFilterState()
    local _, rules = _loadSellRules({})
    return {
        rules = rules,
        filterMode = "rules",
        hasFilter = type(rules) == "table" and #rules > 0,
    }
end

local function _hasActiveFilter(st)
    st = st or getFilterState()
    return type(st.rules) == "table" and #st.rules > 0
end

function M.HasFilterActive()
    return _hasActiveFilter()
end

M.hasFilterActive = M.HasFilterActive

local function getSellState()
    local MAIN = rawget(_G, "MAIN") or G.MAIN
    local st = MAIN and MAIN.auto and MAIN.auto.sell
    st = type(st) == "table" and st or {}

    local enabled = (G.AUTO_SELL_ENABLED == true)
        or (rawget(_G, "AUTO_SELL_ENABLED") == true)
        or (st.enabled == true)

    local minCount = tonumber(st.minCount)
    if minCount == nil then
        minCount = tonumber(G.AUTO_SELL_MIN_COUNT or rawget(_G, "AUTO_SELL_MIN_COUNT")) or 100
    end
    if minCount < 1 then minCount = 1 end

    local delay = tonumber(st.delay)
    if delay == nil then
        delay = tonumber(G.AUTO_SELL_DELAY or rawget(_G, "AUTO_SELL_DELAY")) or 0.5
    end
    if delay < 0 then delay = 0 end

    local filterMode, rules = _loadSellRules(st)
    local hasFilter = type(rules) == "table" and #rules > 0
    local rulesOrder = G.AUTO_SELL_RULES_ORDER or rawget(_G, "AUTO_SELL_RULES_ORDER")
        or st.rulesOrder or (MAIN and MAIN.auto and MAIN.auto.sell and MAIN.auto.sell.rulesOrder) or {}

    local out = {
        enabled      = enabled,
        minCount     = minCount,
        delay        = delay,
        sellWhenFull = _readSellWhenFull(st),
        filterMode   = filterMode,
        rules        = rules,
        rulesOrder   = type(rulesOrder) == "table" and rulesOrder or {},
        hasFilter    = hasFilter,
    }
    return out
end

----------------------------------------------------------------
local function _fruitId(tool)
    if not tool or type(tool.GetAttribute) ~= "function" then return "" end
    return tostring(tool:GetAttribute("Id") or tool:GetAttribute("id")
        or tool:GetAttribute("UUID") or tool:GetAttribute("Uuid")
        or tool:GetAttribute("FruitId") or tool:GetAttribute("fruitId")
        or tool:GetAttribute("c") or "")
end

local function _isFavorited(tool)
    if not tool or type(tool.GetAttribute) ~= "function" then return false end
    local function truthy(v)
        return v == true or v == 1 or v == "true" or v == "1"
    end
    return truthy(tool:GetAttribute("IsFavorite"))
        or truthy(tool:GetAttribute("Favorite"))
        or truthy(tool:GetAttribute("Favorited"))
        or truthy(tool:GetAttribute("isFavorite"))
end

local function _isFruitTool(inst)
    if not inst or not inst.Parent then return false end
    if inst:GetAttribute("SeedTool") or inst:GetAttribute("Pet") then return false end
    if inst:GetAttribute("PottedPlant") == true then return false end
    if tostring(inst:GetAttribute("MainCategory") or "") == "Seed" then return false end
    if FruitProxyUtil and type(FruitProxyUtil.IsFruitInstance) == "function" then
        local ok, yes = pcall(FruitProxyUtil.IsFruitInstance, inst)
        if ok and yes then return true end
    end
    if inst:GetAttribute("FruitName") or inst:GetAttribute("Fruit") then return true end
    if inst:GetAttribute("FruitProxy") == true then return true end
    local hf = inst:GetAttribute("HarvestedFruit")
    if hf == true or (type(hf) == "string" and hf ~= "") then return true end
    if inst:GetAttribute("Id") and inst:GetAttribute("Weight") then return true end
    return inst:IsA("Tool")
end

local function _eachFruitTool(fn)
    if type(fn) ~= "function" then return end
    local seen = {}
    local function scan(root)
        if not root then return end
        for _, inst in ipairs(root:GetChildren()) do
            if not seen[inst] and _isFruitTool(inst) then
                seen[inst] = true
                fn(inst)
            end
        end
    end
    scan(LP:FindFirstChild("Backpack") or LP:FindFirstChildOfClass("Backpack"))
    scan(LP.Character)
end

local function _fruitName(tool)
    if not tool then return "" end
    local fsv = _fsv()
    if fsv and type(fsv.resolveSeedName) == "function" then
        local ok, name = pcall(fsv.resolveSeedName, tool)
        if ok and name ~= nil and tostring(name) ~= "" then
            return tostring(name)
        end
    end
    return tostring(tool:GetAttribute("FruitName") or tool:GetAttribute("Fruit") or tool.Name or "")
end

local function _fruitWeight(tool)
    if not tool then return 0 end
    local attrW = tonumber(tool:GetAttribute("Weight"))
    if attrW and attrW > 0 then return attrW end
    local fsv = _fsv()
    if fsv and type(fsv.resolveWeight) == "function" then
        local ok, w = pcall(fsv.resolveWeight, tool)
        if ok and type(w) == "number" and w > 0 then return w end
    end
    return 0
end

local function _buildEspPriceMap()
    local map = {}
    local esp = _getEspBackpack()
    if not esp or type(esp.ScanFruits) ~= "function" then return map end
    local list, byId = esp.ScanFruits()
    if type(byId) == "table" then
        for id, entry in pairs(byId) do
            if type(entry) == "table" then
                local p = 0
                if type(esp.GetCachedEntryPrice) == "function" then
                    p = tonumber(esp:GetCachedEntryPrice(entry)) or 0
                end
                if p <= 0 and type(esp.GetEntryPrice) == "function" then
                    p = tonumber(esp:GetEntryPrice(entry)) or 0
                end
                if p > 0 then map[id] = p end
            end
        end
    elseif type(list) == "table" then
        for _, entry in ipairs(list) do
            local id = tostring(entry.id or "")
            if id ~= "" then
                local p = 0
                if type(esp.GetCachedEntryPrice) == "function" then
                    p = tonumber(esp:GetCachedEntryPrice(entry)) or 0
                end
                if p <= 0 and type(esp.GetEntryPrice) == "function" then
                    p = tonumber(esp:GetEntryPrice(entry)) or 0
                end
                if p > 0 then map[id] = p end
            end
        end
    end
    return map
end

local function _priceToolQuick(tool, priceMap)
    if not tool then return 0 end
    local id = _fruitId(tool)
    if id ~= "" and type(priceMap) == "table" then
        local cached = priceMap[id]
        if type(cached) == "number" and cached > 0 then return cached end
    end
    local fsv = _fsv()
    if not fsv then return 0 end
    if type(fsv.getBackpackEspPrice) == "function" then
        local name = _fruitName(tool)
        local multi = 0
        if type(fsv.resolveMulti) == "function" then
            local ok, m = pcall(fsv.resolveMulti, tool)
            if ok and type(m) == "number" then multi = m end
        end
        if multi <= 0 then
            multi = tonumber(tool:GetAttribute("SizeMultiplier") or tool:GetAttribute("SizeMulti")) or 0
        end
        if multi > 0 and name ~= "" then
            local bid = tonumber(tool:GetAttribute("BidPrice")) or 0
            local mode = "base"
            if type(fsv.getEspPriceMode) == "function" then
                local ok, m = pcall(fsv.getEspPriceMode)
                if ok and type(m) == "string" and m ~= "" then mode = m end
            end
            local ok, p = pcall(fsv.getBackpackEspPrice, name, multi, tool:GetAttribute("Mutation"),
                tool:GetAttribute("DecayAlpha"), mode, id ~= "" and id or nil, bid)
            if ok and type(p) == "number" and p > 0 then return p end
        end
    end
    if type(fsv.fromFruit) == "function" then
        local ok, p = pcall(fsv.fromFruit, tool, LP)
        if ok and type(p) == "number" and p > 0 then return p end
    end
    return 0
end

local function _fruitPrice(tool, priceMap)
    return _priceToolQuick(tool, priceMap)
end

local function _appendMutationTokens(out, raw)
    if type(raw) ~= "string" or raw == "" then return end
    for token in string.gmatch(raw, "[^%+%,]+") do
        token = tostring(token):match("^%s*(.-)%s*$")
        if token and token ~= "" then out[#out + 1] = token end
    end
end

local function _parseMutationList(tool)
    local out = {}
    if tool then
        _appendMutationTokens(out, tool:GetAttribute("Mutation"))
    end
    if #out == 0 then
        local fsv = _fsv()
        if fsv and type(fsv.resolveMutation) == "function" then
            local ok, raw = pcall(fsv.resolveMutation, tool)
            if ok then _appendMutationTokens(out, raw) end
        end
    end
    return out
end

local function _isNoMutationKey(name)
    local c = _canon(name)
    return c == "nomutation" or c == "none" or tostring(name or "") == NO_MUTATION_LABEL
end

local function _fruitHasMutation(tool)
    if not tool then return false end
    local fsv = _fsv()
    if fsv and type(fsv.resolveMutation) == "function" then
        local ok, mut = pcall(fsv.resolveMutation, tool)
        if ok and type(mut) == "string" and mut ~= "" then return true end
    end
    for _, name in ipairs(_parseMutationList(tool)) do
        if name ~= "" and not _isNoMutationKey(name) then return true end
    end
    return false
end

local function _matchSet(selectedMap, value)
    if not _hasAny(selectedMap) then return true end
    local needle = _canon(value)
    for k, v in pairs(selectedMap) do
        if v == true and _canon(k) == needle then return true end
    end
    return false
end

local function _matchMutation(selectedMap, tool)
    if not _hasAny(selectedMap) then return true end
    if not tool then return false end
    if selectedMap[NO_MUTATION_LABEL] == true and not _fruitHasMutation(tool) then
        return true
    end
    local rawMut = tool:GetAttribute("Mutation")
    if type(rawMut) == "string" and rawMut ~= "" then
        if _matchSet(selectedMap, rawMut) then return true end
        for token in string.gmatch(rawMut, "[^%+%,]+") do
            if _matchSet(selectedMap, token) then return true end
        end
    end
    for mutName, on in pairs(selectedMap) do
        if on == true and not _isNoMutationKey(mutName) and tool:GetAttribute(mutName) == true then
            return true
        end
    end
    for _, mutName in ipairs(_parseMutationList(tool)) do
        if not _isNoMutationKey(mutName) and _matchSet(selectedMap, mutName) then
            return true
        end
    end
    local fsv = _fsv()
    if fsv and type(fsv.resolveMutation) == "function" then
        local ok, raw = pcall(fsv.resolveMutation, tool)
        if ok and type(raw) == "string" and raw ~= "" then
            for token in string.gmatch(raw, "[^%+%,]+") do
                if _matchSet(selectedMap, token) then return true end
            end
        end
    end
    return false
end

local function _matchKg(weight, kg, mode)
    kg, mode = _normalizeKgFilter(kg, mode)
    weight = tonumber(weight) or 0
    if kg <= 0 then return true end
    if mode == "below" then
        return weight > 0 and weight <= kg
    end
    return weight >= kg
end

local function _matchPrice(price, filterPrice, mode)
    filterPrice, mode = _normalizePriceFilter(filterPrice, mode)
    price = tonumber(price) or 0
    if filterPrice <= 0 then return true end
    if mode == "below" then
        return price > 0 and price <= filterPrice
    end
    return price >= filterPrice
end

local function _rulesNeedPrice(rules)
    if type(rules) ~= "table" then return false end
    for _, rule in ipairs(rules) do
        if type(rule) == "table" and rule.anyPrice then return true end
    end
    return false
end

local function _matchesSellRule(tool, rule, priceMap)
    if type(rule) ~= "table" or rule.enabled == false then return false end
    if rule.anyFruit and not _matchSet(rule.fruits, _fruitName(tool)) then return false end
    if rule.kg > 0 and not _matchKg(_fruitWeight(tool), rule.kg, rule.kgMode) then return false end
    if rule.requireMut == true then
        if rule.anyMut then
            if not _matchMutation(rule.mutations, tool) then return false end
        elseif not _fruitHasMutation(tool) then
            return false
        end
    elseif rule.anyMut and not _matchMutation(rule.mutations, tool) then
        return false
    end
    if rule.anyPrice and not _matchPrice(_fruitPrice(tool, priceMap), rule.minPrice, rule.minPriceMode) then
        return false
    end
    return true
end

local function _matchesRulesMode(tool, st, priceMap)
    local rules = st and st.rules
    if type(rules) ~= "table" or #rules == 0 then
        return true
    end
    for _, rule in ipairs(rules) do
        if _matchesSellRule(tool, rule, priceMap) then
            return true
        end
    end
    return false
end

local function _matchesFilters(tool, ac, priceMap)
    return _matchesRulesMode(tool, ac, priceMap)
end

local function _filterCacheKey(ac)
    local parts = { tostring(#(ac.rules or {})) }
    for _, r in ipairs(ac.rules or {}) do
        parts[#parts + 1] = table.concat({
            tostring(r.id or ""),
            table.concat(_setToArray(r.fruits), ","),
            table.concat(_setToArray(r.mutations), ","),
            tostring(r.kg or 0),
            tostring(r.kgMode or "above"),
            tostring(r.minPrice or 0),
            tostring(r.minPriceMode or "above"),
        }, ":")
    end
    return table.concat(parts, "|")
end

local function _invalidateFilterCache()
    filterCache.at = 0
    filterCache.key = ""
    filterCache.items = nil
end

local function _copyFilterItems(dest, src)
    table.clear(dest)
    if type(src) ~= "table" then return dest end
    for i, item in ipairs(src) do
        dest[i] = item
    end
    return dest
end

local function _scanFilteredTools(ac, collectList)
    ac = ac or getSellState()
    if not _hasActiveFilter(ac) then
        return 0, collectList
    end

    local key = _filterCacheKey(ac)
    local now = os.clock()
    if filterCache.key == key
        and (now - filterCache.at) < FILTER_CACHE_SEC
        and type(filterCache.items) == "table" then
        if collectList then
            return filterCache.n, _copyFilterItems(collectList, filterCache.items)
        end
        return filterCache.n, nil
    end

    local priceMap = _rulesNeedPrice(ac.rules) and _buildEspPriceMap() or nil
    local n = 0
    local list = {}
    local seenId = {}

    _eachFruitTool(function(tool)
        if _isFavorited(tool) then return end
        local id = _fruitId(tool)
        if id == "" or seenId[id] then return end
        if not _matchesFilters(tool, ac, priceMap) then return end
        seenId[id] = true
        n += 1
        list[#list + 1] = { id = id, tool = tool }
    end)

    filterCache.n = n
    filterCache.at = now
    filterCache.key = key
    filterCache.items = list

    if collectList then
        return n, _copyFilterItems(collectList, list)
    end
    return n, nil
end

function M.GetFilteredCount()
    return _scanFilteredTools(getSellState(), nil)
end

M.getFilteredCount = M.GetFilteredCount

function M.PeekFilteredCount()
    return M.GetFilteredCount()
end

M.peekFilteredCount = M.PeekFilteredCount

----------------------------------------------------------------
local function getPlayerFruitStats()
    local count = tonumber(LP:GetAttribute("FruitCount"))
    local maxCap = tonumber(LP:GetAttribute("MaxFruitCapacity"))
    return count, maxCap
end

local function _npcFire(name, ...)
    local npcs = Networking and Networking.NPCS
    local pkt = npcs and npcs[name]
    if not pkt then
        return false, "missing_packet_" .. tostring(name)
    end
    if type(pkt.Fire) ~= "function" then
        return false, "no_fire_" .. tostring(name)
    end

    local args = table.pack(...)
    local results = table.pack(pcall(function()
        if args.n > 0 then
            return pkt:Fire(table.unpack(args, 1, args.n))
        end
        return pkt:Fire()
    end))
    if not results[1] then
        return false, results[2]
    end
    return true, results[2], results[3], results[4], results[5]
end

local function _pickSellPayload(...)
    local n = select("#", ...)
    for i = 1, n do
        local v = select(i, ...)
        if type(v) == "table" then
            return v
        end
    end
    if n >= 1 and type(select(1, ...)) == "boolean" then
        local msg = select(2, ...)
        return {
            Success = select(1, ...),
            Message = type(msg) == "string" and msg or nil,
        }
    end
    return nil
end

local function _sellCountFrom(res)
    if type(res) ~= "table" then return 0 end
    return tonumber(res.SoldCount or res.soldCount or res.Count or res.count) or 0
end

local function _previewCountFrom(res)
    if type(res) ~= "table" then return nil end
    local n = tonumber(res.FruitCount or res.fruitCount or res.SellCount or res.sellCount
        or res.NumFruits or res.numFruits or res.ItemCount or res.itemCount
        or res.Count or res.count)
    return n
end

local function _previewSellable(res)
    if type(res) ~= "table" then return nil end
    local count = _previewCountFrom(res)
    if count and count > 0 then return count end

    local price = tonumber(res.SellPrice or res.sellPrice or res.TotalSellPrice or res.totalSellPrice
        or res.TotalPrice or res.totalPrice or res.Value or res.value)
    if price and price > 0 then
        return math.max(count or 0, 1)
    end

    if res.Success == true or res.success == true then
        if count ~= nil then return count end
        return 1
    end

    return count
end

local function _normalizeSellResult(ok, a, b, c)
    local res = _pickSellPayload(a, b, c)
    if res == nil and ok then
        if type(a) == "boolean" then
            res = {
                Success = a,
                Message = type(b) == "string" and b or nil,
                SoldCount = type(c) == "number" and c or nil,
            }
        elseif type(a) == "number" then
            res = { Success = a > 0, SoldCount = a, Message = type(b) == "string" and b or nil }
        else
            res = a
        end
    end
    if ok and res == nil and a == nil then
        res = { Success = true }
    end
    return res
end

local function previewSellAll()
    local ok, a, b, c = _npcFire("PreviewSellAll")
    if not ok then return nil end
    return _pickSellPayload(a, b, c)
end

local function _invalidatePreviewCache()
    previewCache.at = 0
end

local function _fetchPreviewCount()
    local now = os.clock()
    if now - previewCache.at < PREVIEW_CACHE_SEC then
        return previewCache.n
    end
    local preview = previewSellAll()
    local n = _previewCountFrom(preview) or 0
    previewCache.n = n
    previewCache.at = now
    return n
end

local function getTotalFruitCount()
    local attrCount = tonumber(LP:GetAttribute("FruitCount")) or 0
    return math.max(attrCount, _fetchPreviewCount())
end

local function getFruitCount()
    local st = getSellState()
    if st.hasFilter then
        return M.GetFilteredCount()
    end
    return getTotalFruitCount()
end

local function getMaxFruitCapacity()
    local maxCap = select(2, getPlayerFruitStats())
    if type(maxCap) == "number" and maxCap > 0 then return maxCap end
    return nil
end

local function getSellThreshold(st)
    st = st or getSellState()
    if st.sellWhenFull == true and not st.hasFilter then
        local maxCap = getMaxFruitCapacity()
        if maxCap then return maxCap end
    end
    return st.minCount
end

local function _isNearFull(count, maxCap)
    if not maxCap or maxCap <= 0 then return false end
    return count >= maxCap or count >= math.floor(maxCap * FULL_NEAR_RATIO)
end

local function _sellSucceeded(res)
    if type(res) ~= "table" then
        return res == true
    end
    if res.Success == true or res.success == true then return true end
    if res.Success == false or res.success == false then return false end
    if _sellCountFrom(res) > 0 then return true end
    return false
end

local function _syncFavBeforeSell()
    local af = G.AutoFav or G.AutoFavModule or _G.AutoFav
    if type(af) ~= "table" or type(af.SyncBeforeSell) ~= "function" then
        return 0, 0
    end
    if type(af.HasPendingFav) == "function" then
        local pending = select(1, af:HasPendingFav())
        if not pending then return 0, 0 end
    end

    local ok, favN, unfavN = pcall(af.SyncBeforeSell, af, {
        beforeSell = true,
        fireDelay = 0,
        maxWallSec = PRE_SELL_SYNC_WALL,
    })
    if ok then
        return tonumber(favN) or 0, tonumber(unfavN) or 0
    end
    return 0, 0
end

local function _singleSellGap(st)
    local d = tonumber(st and st.delay)
    if d == nil or d <= 0 then
        return SINGLE_SELL_GAP
    end
    return math.max(SINGLE_SELL_GAP, math.min(SINGLE_SELL_GAP_MAX, d * 0.06))
end

local function sellFilteredNow()
    if externalPaused then return false, "paused" end
    if busySelling then return false, "busy" end
    if os.clock() - lastSellAt < FILTER_SELL_BUSY_SEC then return false, "cooldown" end

    local st = getSellState()
    if not st.hasFilter then
        return false, "no_filter"
    end

    local matches = {}
    local matchCount = _scanFilteredTools(st, matches)
    if matchCount <= 0 then
        lastEmptySellAt = os.clock()
        return false, "nothing_to_sell"
    end

    busySelling = true

    local sold = 0
    local gap = _singleSellGap(st)
    local total = #matches

    for i, item in ipairs(matches) do
        if not item.id or item.id == "" then continue end
        if item.tool and item.tool.Parent and _isFavorited(item.tool) then continue end

        local ok, a, b, c = _npcFire("SellFruit", item.id)
        local res = _normalizeSellResult(ok, a, b, c)
        if ok and _sellSucceeded(res) then
            sold += 1
        elseif type(res) == "table" and (res.Reason == "Favorited" or res.reason == "Favorited") then
            continue
        end
        if i < total then
            task.wait(gap)
        end
    end

    lastSellAt = os.clock()
    busySelling = false
    _invalidatePreviewCache()
    _invalidateFilterCache()

    if sold > 0 then
        return true, { Success = true, SoldCount = sold, Filtered = true }
    end

    lastEmptySellAt = os.clock()
    return false, "sell_failed"
end

local function sellAllNow()
    if externalPaused then return false, "paused" end
    if busySelling then return false, "busy" end
    if os.clock() - lastSellAt < SELL_BUSY_SEC then return false, "cooldown" end

    local st = getSellState()
    if st.hasFilter then
        return sellFilteredNow()
    end

    busySelling = true

    local fruitCount = getTotalFruitCount()
    if fruitCount <= 0 then
        busySelling = false
        return false, "empty"
    end

    local maxCap = getMaxFruitCapacity()
    local forceSell = st.sellWhenFull and _isNearFull(fruitCount, maxCap)

    local favN, unfavN = _syncFavBeforeSell()
    if favN > 0 or unfavN > 0 then
        task.wait(0.15)
    end

    local preview = nil
    local sellable = nil
    if not forceSell and fruitCount < HEAVY_INVENTORY_COUNT then
        preview = previewSellAll()
        sellable = _previewSellable(preview)
    end

    if (sellable == nil or sellable <= 0) and fruitCount > 0 then
        if forceSell or fruitCount >= HEAVY_INVENTORY_COUNT then
            sellable = fruitCount
        end
    end

    if not forceSell and sellable ~= nil and sellable <= 0 then
        busySelling = false
        lastEmptySellAt = os.clock()
        return false, "nothing_to_sell"
    end

    local ok, a, b, c = _npcFire("SellAll")
    local res = _normalizeSellResult(ok, a, b, c)

    lastSellAt = os.clock()
    busySelling = false

    if ok and (_sellSucceeded(res) or a == true) then
        _invalidatePreviewCache()
        _invalidateFilterCache()
        return true, res
    end

    lastEmptySellAt = os.clock()
    return false, res
end

local function _shouldSellNow(st)
    st = st or getSellState()
    local totalCount = getTotalFruitCount()
    local maxCap = getMaxFruitCapacity()

    if st.hasFilter then
        local filteredCount = filterCache.n
        if filterCache.key ~= _filterCacheKey(st)
            or (os.clock() - filterCache.at) >= FILTER_CACHE_SEC then
            filteredCount = M.GetFilteredCount()
        end
        if filteredCount <= 0 then return false end
        if st.sellWhenFull and _isNearFull(totalCount, maxCap) then
            return true
        end
        if not st.sellWhenFull and filteredCount >= st.minCount then
            return true
        end
        return false
    end

    if st.sellWhenFull then
        return _isNearFull(totalCount, maxCap)
    end

    local threshold = getSellThreshold(st)
    return totalCount >= threshold
end

local function _loopDelay(st, count, threshold)
    st = st or getSellState()
    local d = tonumber(st.delay) or 0
    if st.hasFilter then
        if d <= 0 then return 0 end
        return math.max(FILTER_LOOP_MIN_SEC, d * 0.35)
    end
    if st.sellWhenFull and count >= threshold then
        return LOOP_MIN_SEC
    end
    local maxCap = getMaxFruitCapacity()
    if maxCap and _isNearFull(count, maxCap) then
        return LOOP_MIN_SEC
    end
    if d <= 0 then return 0 end
    return math.max(LOOP_MIN_SEC, d)
end

local function _emptySellBackoff(st)
    if st and st.hasFilter then
        return FILTER_EMPTY_BACKOFF
    end
    return EMPTY_SELL_BACKOFF
end

local function tryAutoSell()
    local st = getSellState()
    if not st.enabled or busySelling or externalPaused then return end
    if os.clock() - lastEmptySellAt < _emptySellBackoff(st) then return end

    if _shouldSellNow(st) then
        sellAllNow()
    end
end

local function _onInventoryChanged()
    _invalidatePreviewCache()
    _invalidateFilterCache()
    task.defer(tryAutoSell)
end

local function _bindInventoryWatcher(root)
    if not root then return end
    local keyAdd, keyRem = root, tostring(root) .. "_rem"
    if invConns[keyAdd] then return end
    invConns[keyAdd] = root.ChildAdded:Connect(_onInventoryChanged)
    invConns[keyRem] = root.ChildRemoved:Connect(_onInventoryChanged)
end

local function _ensureInventoryWatchers()
    _bindInventoryWatcher(LP:FindFirstChild("Backpack") or LP:FindFirstChildOfClass("Backpack"))
    _bindInventoryWatcher(LP.Character)
    if childAddedConn then return end
    childAddedConn = LP.ChildAdded:Connect(function(child)
        if child.Name == "Backpack" or child:IsA("Backpack") then
            _bindInventoryWatcher(child)
            _onInventoryChanged()
        elseif child:IsA("Model") then
            task.defer(function()
                _bindInventoryWatcher(LP.Character)
            end)
        end
    end)
end

local function _bindFruitCountWatcher()
    if #attrConns > 0 then return end
    table.insert(attrConns, LP:GetAttributeChangedSignal("FruitCount"):Connect(function()
        _invalidatePreviewCache()
        _invalidateFilterCache()
        tryAutoSell()
    end))
    table.insert(attrConns, LP:GetAttributeChangedSignal("MaxFruitCapacity"):Connect(function()
        tryAutoSell()
    end))
end

local function _unbindWatchers()
    for _, conn in ipairs(attrConns) do
        conn:Disconnect()
    end
    table.clear(attrConns)
    for key, conn in pairs(invConns) do
        conn:Disconnect()
        invConns[key] = nil
    end
    if childAddedConn then
        childAddedConn:Disconnect()
        childAddedConn = nil
    end
end

local function mainLoop(myId)
    _bindFruitCountWatcher()
    _ensureInventoryWatchers()

    while running and loopId == myId do
        local st = getSellState()
        local count = getFruitCount()
        local threshold = getSellThreshold(st)
        tryAutoSell()
        task.wait(_loopDelay(st, count, threshold))
    end

    _unbindWatchers()
end

----------------------------------------------------------------
-- public API
----------------------------------------------------------------
local function _coerceOn(a, b)
    if type(a) == "table" then return b == true end
    return a == true
end

function M.SetEnabled(a, b)
    local on = _coerceOn(a, b)

    G.AUTO_SELL_ENABLED = on
    _G.AUTO_SELL_ENABLED = on
    _writeMainSell({ enabled = on })

    if on then
        if not running then
            running = true
            loopId += 1
            local myId = loopId
            task.spawn(function() mainLoop(myId) end)
        end
        task.defer(tryAutoSell)
    else
        running = false
        _unbindWatchers()
    end
end

M.setEnabled = M.SetEnabled

function M.Start()
    return M.SetEnabled(true)
end

M.start = M.Start

function M.Stop()
    return M.SetEnabled(false)
end

M.stop = M.Stop

function M.IsRunning()
    return running == true
end

M.isRunning = M.IsRunning

-- Soft pause: loop stays on / toggle state tetap, auto-sell skip sampai Resume.
-- Nested-safe (depth). Tidak mengubah MAIN.auto.sell.enabled.
function M.Pause(reason)
    pauseDepth += 1
    externalPaused = true
    if reason ~= nil then
        pauseReason = tostring(reason)
    end
    return pauseDepth
end

M.pause = M.Pause

function M.Resume()
    if pauseDepth > 0 then
        pauseDepth -= 1
    end
    if pauseDepth <= 0 then
        pauseDepth = 0
        externalPaused = false
        pauseReason = nil
        if running then
            task.defer(tryAutoSell)
        end
    end
    return pauseDepth
end

M.resume = M.Resume

function M.IsPaused()
    return externalPaused == true
end

M.isPaused = M.IsPaused

function M.GetPauseReason()
    return pauseReason
end

function M.IsBusy()
    return busySelling == true
end

M.isBusy = M.IsBusy

-- Tunggu sell fruit selesai (atau timeout). Return true jika idle.
function M.WaitIdle(timeoutSec)
    timeoutSec = tonumber(timeoutSec) or 15
    local deadline = os.clock() + math.max(0.1, timeoutSec)
    while busySelling and os.clock() < deadline do
        task.wait(0.05)
    end
    return not busySelling
end

M.waitIdle = M.WaitIdle

-- Pause AutoSell + AutoFav/Unfav (runtime only). Pair dengan ResumePeers.
function M.PausePeers(reason)
    -- Toleransi M:PausePeers("x") → reason jadi self table
    if type(reason) == "table" then reason = nil end
    reason = reason or "external"
    M.Pause(reason)
    local af = G.AutoFav or G.AutoFavModule or _G.AutoFav or _G.AutoFavModule
    if type(af) == "table" and type(af.Pause) == "function" then
        pcall(function()
            af.Pause(reason)
        end)
    end
    return true
end

M.pausePeers = M.PausePeers

function M.ResumePeers()
    local af = G.AutoFav or G.AutoFavModule or _G.AutoFav or _G.AutoFavModule
    if type(af) == "table" and type(af.Resume) == "function" then
        pcall(function()
            af.Resume()
        end)
    end
    M.Resume()
    return true
end

M.resumePeers = M.ResumePeers

-- Pause peers → tunggu idle → jalankan fn → selalu ResumePeers.
function M.WithPeerHold(fn, reason, idleTimeout)
    -- Toleransi M:WithPeerHold(fn, reason, idle)
    if type(fn) ~= "function" and type(reason) == "function" then
        fn, reason, idleTimeout = reason, idleTimeout, nil
    end
    if type(fn) ~= "function" then
        return false, "bad_fn"
    end
    if type(reason) == "table" then reason = nil end
    M.PausePeers(reason or "hold")
    M.WaitIdle(idleTimeout or 15)
    local ok, a, b, c = pcall(fn)
    M.ResumePeers()
    if not ok then
        return false, a
    end
    return true, a, b, c
end

M.withPeerHold = M.WithPeerHold

function M.SetMinCount(n)
    n = tonumber(n)
    if n == nil then return end
    if n < 1 then n = 1 end
    G.AUTO_SELL_MIN_COUNT = n
    _G.AUTO_SELL_MIN_COUNT = n
    _writeMainSell({ minCount = n })
    task.defer(tryAutoSell)
end

M.setMinCount = M.SetMinCount

function M.SetDelay(n)
    n = tonumber(n)
    if n == nil then return end
    if n < 0 then n = 0 end
    G.AUTO_SELL_DELAY = n
    _G.AUTO_SELL_DELAY = n
    _writeMainSell({ delay = n })
end

M.setDelay = M.SetDelay

function M.SetSellWhenFull(on)
    on = (on == true)
    G.AUTO_SELL_WHEN_FULL = on
    _G.AUTO_SELL_WHEN_FULL = on
    _writeMainSell({ sellWhenFull = on })
    task.defer(tryAutoSell)
end

M.setSellWhenFull = M.SetSellWhenFull

function M.SetFilterMode(_mode)
    G.AUTO_SELL_FILTER_MODE = "rules"
    _G.AUTO_SELL_FILTER_MODE = "rules"
    _writeMainSell({ filterMode = "rules" })
    _invalidateFilterCache()
    return "rules"
end

M.setFilterMode = M.SetFilterMode

function M.SetRules(rules, order)
    rules = type(rules) == "table" and rules or {}
    order = type(order) == "table" and order or {}
    G.AUTO_SELL_RULES = rules
    _G.AUTO_SELL_RULES = rules
    G.AUTO_SELL_RULES_ORDER = order
    _G.AUTO_SELL_RULES_ORDER = order
    _writeMainSell({ rules = rules, rulesOrder = order, filterMode = "rules" })
    _invalidateFilterCache()
end

M.setRules = M.SetRules

function M.GetRules()
    local st = getSellState()
    return st.rules or {}, "rules"
end

M.getRules = M.GetRules

function M.GetTotalFruitCount()
    return getTotalFruitCount()
end

M.getTotalFruitCount = M.GetTotalFruitCount

function M.GetFruitCount()
    return getFruitCount()
end

M.getFruitCount = M.GetFruitCount

function M.GetMaxFruitCapacity()
    return getMaxFruitCapacity()
end

M.getMaxFruitCapacity = M.GetMaxFruitCapacity

function M.GetFruitStats()
    -- UI/status only: pakai attribute player, jangan PreviewSellAll / scan berat saat load.
    local attrCount = tonumber(LP:GetAttribute("FruitCount")) or 0
    local maxCap = getMaxFruitCapacity()
    local st = getSellState()
    if st.hasFilter then
        return M.GetFilteredCount(), maxCap, attrCount
    end
    return attrCount, maxCap
end

M.getFruitStats = M.GetFruitStats

function M.SellNow()
    return sellAllNow()
end

M.sellNow = M.SellNow

function M.CheckNow()
    task.defer(tryAutoSell)
end

