function M.SyncFromState()
    local st = getSellState()
    M.SetMinCount(st.minCount)
    M.SetDelay(st.delay)
    M.SetSellWhenFull(st.sellWhenFull)
    M.SetFilterMode("rules")
    M.SetRules(st.rules or {}, st.rulesOrder or {})
    _invalidateFilterCache()
    M.SetEnabled(st.enabled)
end

M.syncFromState = M.SyncFromState

function M.GetStats()
    local st = getSellState()
    local total = getTotalFruitCount()
    local filtered = st.hasFilter and M.GetFilteredCount() or nil
    local maxCap = getMaxFruitCapacity()
    return {
        running = running,
        fruitCount = st.hasFilter and (filtered or 0) or total,
        totalFruitCount = total,
        filteredCount = filtered,
        hasFilter = st.hasFilter,
        maxCapacity = maxCap,
        minCount = st.minCount,
        sellWhenFull = st.sellWhenFull,
        threshold = getSellThreshold(st),
        nearFull = _isNearFull(total, maxCap),
        busy = busySelling,
        paused = externalPaused,
        pauseDepth = pauseDepth,
        pauseReason = pauseReason,
        moduleVersion = MODULE_VERSION,
    }
end

M.getStats = M.GetStats
M.ModuleVersion = MODULE_VERSION
