 end,                       required = false },
    { key = "AutoPlant",               name = "Auto Plant",              factory = function() -- AutoPlant.lua — Grow A Garden 2 (lightweight)
-- Plant: Networking.Plant.PlantSeed:Fire(position, seedToolId, tool)
-- Seed label/limit: backpack qty delta (start → remaining), bukan Fire count / plants di plot
-- Updates: spiral 1200 slot, batch rescan 100, gameplay guard, vuln stop via AutoVuln

local Players            = game:GetService("Players")
local ReplicatedStorage  = game:GetService("ReplicatedStorage")
local CollectionService  = game:GetService("CollectionService")
local UserInputService   = game:GetService("UserInputService")
local GuiService         = game:GetService("GuiService")

