local Gardens = workspace:WaitForChild("Gardens")

local function _isGameplayBlocked()
    -- Hanya block saat cutscene/offline growth benar-benar jalan.
    -- Jangan cek OfflineAnimation GUI — sering ada di PlayerGui meski tidak tampil.
    -- Jangan cek LoadingScreenActive — sering stuck true di cloud phone.
    if G.__GAG2_OFFLINE_GROWTH_BUSY == true or _G.__GAG2_OFFLINE_GROWTH_BUSY == true then
        return true, "offline_growth"
    end
    if LP:GetAttribute("OfflineCutscenePlaying") == true then return true, "offline_cutscene" end
    if LP:GetAttribute("CutsceneInputBlocked") == true then return true, "cutscene_blocked" end
    return false
end

