local RANDOM_MAX_TRY   = 12
local RANDOM_PART_MARGIN = 0.92
local PLANTS_PER_TICK  = 8
local CENTER_PLANTS_PER_TICK = 8
local CENTER_MAX_SCAN  = 400
local POSITION_PLANT_SPACING = GAME_MIN_PLANT_DIST
local POSITION_CIRCLE_BATCH = 100  -- refresh plot setiap N slot (bukan batas tanam)
local POSITION_MAX_SCAN = 1200     -- spiral sampai ~1000+ seed per anchor
local MAX_BLOCKED_SKIP_PER_TICK = 16
local PLANT_AREA_COLUMN_NAMES = { "PlantAreaColumn1", "PlantAreaColumn2" }
local PLOT_CACHE_SEC   = 2

local running          = false
