local function _log(...)
end

local function _notifyPositionsChanged()
    if type(G.__GAG2_ON_PLANT_POSITIONS_CHANGED) == "function" then
        pcall(G.__GAG2_ON_PLANT_POSITIONS_CHANGED)
    end
end

local function _notifySeedStatsChanged()
