local function _writeMainPlant(patch)
    local MAIN = rawget(_G, "MAIN") or G.MAIN
    if type(MAIN) ~= "table" then return end
    MAIN.auto = MAIN.auto or {}
    MAIN.auto.plant = MAIN.auto.plant or {}
    for k, v in pairs(patch) do
        MAIN.auto.plant[k] = v
    end
    G.MAIN = MAIN
    _G.MAIN = MAIN
end

local function _normalizeSet(src)
    if type(src) ~= "table" then return {} end
    local out = {}
    for i = 1, #src do
        local v = src[i]
        if v ~= nil and tostring(v) ~= "" then
            out[tostring(v)] = true
        end
    end
    if next(out) then return out end
    for k, v in pairs(src) do
        if v == true or v == 1 or v == "true" then
            out[tostring(k)] = true
        end
    end
    return out
end

local function _safeStr(v)
    if v == nil then return "" end
    return tostring(v)
end

local function _canon(s)
    return _safeStr(s):lower():gsub("[^%w]+", "")
end

local function _normSeedKey(v)
    v = _canon(v)
    if v:sub(-4) == "seed" then
        v = v:sub(1, -5)
    end
    return v
end

local function _seedKeyMatch(a, b)
    if a == nil or b == nil then return false end
    local ca, cb = _normSeedKey(a), _normSeedKey(b)
    if ca == "" or cb == "" then return false end
    if ca == cb then return true end
    if #ca >= 3 and #cb >= 3 and (ca:find(cb, 1, true) or cb:find(ca, 1, true)) then
        return true
    end
    return false
end

local function _getPlantListView()
    return G.PlantListView or rawget(_G, "PlantListView")
end

local function _isMutationSeedTool(tool)
    if not tool then return false end
    if tool:GetAttribute("MutationSeed") == true then return true end

    local seedName = tool:GetAttribute("SeedName") or tool.Name
    local plv = _getPlantListView()
    if plv and type(plv.findBySeedName) == "function" then
        local ok, entry = pcall(plv.findBySeedName, plv, seedName)
        if ok and type(entry) == "table" and entry.MutationSeed == true then
            return true
        end
    end

    local muts = {}
    if plv and type(plv.listMutationNames) == "function" then
        local ok, list = pcall(plv.listMutationNames, plv)
        if ok and type(list) == "table" then
            for _, n in ipairs(list) do
                muts[_normSeedKey(n)] = true
            end
        end
    end

    return muts[_normSeedKey(seedName)] == true
end

local function _isAvatarBlockedError(err)
    err = tostring(err or ""):lower()
    return err:find("avatar", 1, true) ~= nil
        or err:find("equip the", 1, true) ~= nil
end

local function _seedToolId(tool)
    return tostring(tool and tool:GetAttribute("SeedTool") or tool and tool.Name or "")
end

local function _isSeedToolSkipped(tool)
    local id = _seedToolId(tool)
    if id == "" then return false end
    local untilAt = skippedSeedUntil[id]
    if not untilAt then return false end
    if os.clock() >= untilAt then
        skippedSeedUntil[id] = nil
        return false
    end
    return true
end

local function _markSeedToolSkipped(tool, seconds)
    local id = _seedToolId(tool)
    if id == "" then return end
    skippedSeedUntil[id] = os.clock() + (tonumber(seconds) or 90)
end

local function _iterInventoryContainers()
    local out = {}
    local seen = {}

    local function add(c)
        if c and not seen[c] then
            seen[c] = true
            out[#out + 1] = c
        end
    end

    add(LP:FindFirstChildOfClass("Backpack"))
    add(LP:FindFirstChild("Backpack"))
    add(LP:FindFirstChild("TasRansel"))
    add(LP.Character)

    for _, ch in ipairs(LP:GetChildren()) do
        if ch:IsA("Folder") or ch:IsA("Model") or ch:IsA("Backpack") then
            local n = ch.Name:lower()
            if n:find("backpack") or n:find("ransel") or n:find("tas") or n:find("inventory") then
                add(ch)
            end
        end
    end

    return out
end

local function _normalizePositionId(v)
    if v == nil then return nil end
    if type(v) == "table" then
        v = v.id or v.key
    end
    v = tostring(v)
    if v == "" or v:sub(1, 6) == "table:" then return nil end
    return v
end

local function _clearCircleCache(_anchorId)
    manualSlotCursor = 1
end

local function _maybeRefreshPlotOnCircleBatch(slot)
    if slot <= 1 then return end
    if (slot - 1) % POSITION_CIRCLE_BATCH == 0 then
        cachedPlotAt = 0
        _log("circle batch rescan slot", slot)
    end
end

local function getPlantState()
    local MAIN = rawget(_G, "MAIN") or G.MAIN
    local ap = MAIN and MAIN.auto and MAIN.auto.plant
    ap = type(ap) == "table" and ap or {}

    local seeds = G.AUTO_PLANT_SEEDS_SELECTED
        or rawget(_G, "AUTO_PLANT_SEEDS_SELECTED")
        or _normalizeSet(ap.seeds)

    local delay = tonumber(ap.delay)
    if delay == nil then
        delay = tonumber(G.AUTO_PLANT_DELAY or rawget(_G, "AUTO_PLANT_DELAY")) or 0
    end
    if delay < LOOP_MIN_SEC then delay = LOOP_MIN_SEC end

    local mode = tostring(G.AUTO_PLANT_MODE or rawget(_G, "AUTO_PLANT_MODE") or ap.mode or "random"):lower()
    if mode ~= "manual" and mode ~= "center" then mode = "random" end

    local positions = type(ap.positions) == "table" and ap.positions or {}

    local selectedPosition = _normalizePositionId(ap.selectedPosition)
    if selectedPosition == nil then
        selectedPosition = _normalizePositionId(G.AUTO_PLANT_SELECTED_POSITION)
    end

    local selectedPositions = _normalizeSet(ap.selectedPositions)
    if not next(selectedPositions) then
        selectedPositions = _normalizeSet(G.AUTO_PLANT_SELECTED_POSITIONS)
            or _normalizeSet(rawget(_G, "AUTO_PLANT_SELECTED_POSITIONS"))
    end
    if not next(selectedPositions) and selectedPosition then
        selectedPositions = { [selectedPosition] = true }
    end

    local enabled = (G.AUTO_PLANT_ENABLED == true)
        or (rawget(_G, "AUTO_PLANT_ENABLED") == true)
        or (ap.enabled == true)

    local savePosition = (G.AUTO_PLANT_SAVE_POSITION == true)
        or (rawget(_G, "AUTO_PLANT_SAVE_POSITION") == true)
        or (ap.savePosition == true)

    local plantTotal = tonumber(ap.plantTotal)
    if plantTotal == nil then
        plantTotal = tonumber(G.AUTO_PLANT_TOTAL or rawget(_G, "AUTO_PLANT_TOTAL")) or 0
    end
    if plantTotal < 0 then plantTotal = 0 end
    plantTotal = math.floor(plantTotal)

    return {
        enabled          = enabled,
        seeds            = _normalizeSet(seeds),
        delay            = delay,
        mode             = mode,
        positions        = positions,
        selectedPosition = selectedPosition,
        selectedPositions = selectedPositions,
        savePosition     = savePosition,
        plantTotal       = plantTotal,
    }
end

----------------------------------------------------------------
local function _plotOwnedByLocal(plot)
    if not plot then return false end
    local uid, name = LP.UserId, LP.Name
    local function match(v)
        if v == nil then return false end
        return v == uid or v == name or tostring(v) == tostring(uid) or tostring(v) == name
    end
    if match(plot:GetAttribute("OwnerId")) then return true end
    if match(plot:GetAttribute("Owner")) then return true end
    if match(plot:GetAttribute("OwnerUserId")) then return true end
    if match(plot:GetAttribute("UserId")) then return true end
    return false
end

local function _findPlotInGardens(gardens, plotId)
    if not gardens or plotId == nil then return nil end
    local idStr = tostring(plotId)
    for _, name in ipairs({ "Plot" .. idStr, idStr, "Plot_" .. idStr }) do
        local plot = gardens:FindFirstChild(name)
        if plot then return plot end
    end
    return nil
end

local function getPlayerPlot()
    local now = os.clock()
    if cachedPlot and cachedPlot.Parent and (now - cachedPlotAt) <= PLOT_CACHE_SEC then
        return cachedPlot
    end

    if not Gardens or not Gardens.Parent then
        cachedPlot = nil
        cachedPlotAt = now
        return nil
    end

    local plotId = LP:GetAttribute("PlotId")
    if plotId ~= nil then
        local plot = _findPlotInGardens(Gardens, plotId)
        if plot then
            cachedPlot = plot
            cachedPlotAt = now
            G.__GAG2_PLAYER_PLOT = plot
            _G.__GAG2_PLAYER_PLOT = plot
            return plot
        end
    end

    for _, plot in ipairs(Gardens:GetChildren()) do
        if _plotOwnedByLocal(plot) then
            cachedPlot = plot
            cachedPlotAt = now
            G.__GAG2_PLAYER_PLOT = plot
            _G.__GAG2_PLAYER_PLOT = plot
            return plot
        end
    end

    cachedPlot = nil
    cachedPlotAt = now
    return nil
end

if LP and not G.__GAG2_AUTO_PLANT_PLOT_ID_CONN then
    G.__GAG2_AUTO_PLANT_PLOT_ID_CONN = LP:GetAttributeChangedSignal("PlotId"):Connect(function()
        cachedPlot = nil
        cachedPlotAt = 0
        G.__GAG2_PLAYER_PLOT = nil
        _G.__GAG2_PLAYER_PLOT = nil
    end)
end

local function collectPlotSurfaces(plot)
    local list = {}
    local seen = {}

    local function add(inst)
        if inst and inst:IsA("BasePart") and not seen[inst] then
            seen[inst] = true
            list[#list + 1] = inst
        end
    end

    if Gardens and Gardens.Parent then
        local ok, parts = pcall(function()
            return Gardens:QueryDescendants("BasePart.PlantArea")
        end)
        if ok and type(parts) == "table" then
            for _, inst in ipairs(parts) do
                if inst:IsDescendantOf(plot) then
                    add(inst)
                end
            end
        end
    end
    if #list > 0 then return list end

    for _, inst in ipairs(CollectionService:GetTagged("PlantArea")) do
        if inst:IsDescendantOf(plot) then
            add(inst)
        end
    end
    if #list > 0 then return list end

    for _, desc in ipairs(plot:GetDescendants()) do
        if desc:IsA("BasePart") and desc.Name == "Can_Plant" then
            add(desc)
        end
    end
    if #list > 0 then return list end

    for _, desc in ipairs(plot:GetDescendants()) do
        if desc:IsA("BasePart") then
            local n = desc.Name:lower()
            if n:find("soil") or n:find("dirt") or n:find("ground")
                or n:find("farm") or n:find("plot") or n:find("grass") then
                add(desc)
            end
        end
    end
    if #list > 0 then return list end

    for _, desc in ipairs(plot:GetDescendants()) do
        if desc:IsA("BasePart") and desc.CanQuery ~= false then
            add(desc)
        end
    end
    return list
end

local function createPlantAreaParams(plot)
    local params = RaycastParams.new()
    params.FilterType = Enum.RaycastFilterType.Include
    local list = collectPlotSurfaces(plot)
    params.FilterDescendantsInstances = list
    return params, list
end

local function _getPlantGroundXZ(plant)
    if not plant then return nil end

    if plant:IsA("BasePart") then
        local p = plant.Position
        return p.X, p.Z
    end

    local pos = nil
    if plant:IsA("Model") then
        local ok, pivot = pcall(function()
            return plant:GetPivot().Position
        end)
        if ok and typeof(pivot) == "Vector3" then
            pos = pivot
        elseif plant.PrimaryPart then
            pos = plant.PrimaryPart.Position
        end
    end

    if not pos then
        local part = plant:FindFirstChildWhichIsA("BasePart", true)
        if part then pos = part.Position end
    end

    if pos then
        return pos.X, pos.Z
    end
    return nil
end

local function _countPlantsOnPlot(plot)
    plot = plot or getPlayerPlot()
    if not plot then return 0 end
    local plants = plot:FindFirstChild("Plants")
    if not plants then return 0 end
    return #plants:GetChildren()
end

local function isBlockedPlantSpot(pos, minDist, plot)
    minDist = tonumber(minDist) or MIN_PLANT_DIST
    if not pos then return true end

    plot = plot or getPlayerPlot()
    if not plot then return false end

    local plants = plot:FindFirstChild("Plants")
    if not plants then return false end

    local minDist2 = minDist * minDist
    local px, pz = pos.X, pos.Z

    for _, plant in ipairs(plants:GetChildren()) do
        local gx, gz = _getPlantGroundXZ(plant)
        if gx and gz then
            local dx = gx - px
            local dz = gz - pz
            if (dx * dx + dz * dz) < minDist2 then
                return true
            end
        end
    end

    return false
end

local function raycastPlantArea(origin, direction, plot)
    local params, list = createPlantAreaParams(plot)
    if #list == 0 then return nil end

    local filter = params.FilterDescendantsInstances
    for _ = 1, 5 do
        local hit = workspace:Raycast(origin, direction, params)
        if not hit then return nil end
        if hit.Instance.Transparency < 1 then
            return hit
        end
        local idx = table.find(filter, hit.Instance)
        if not idx then return hit end
        table.remove(filter, idx)
        params.FilterDescendantsInstances = filter
        if #filter == 0 then return nil end
    end
    return nil
end

_snapToPlantSurface = function(plot, pos)
    if not plot or not pos then return pos end
    local surfaces = collectPlotSurfaces(plot)
    if #surfaces == 0 then return pos end

    local params = RaycastParams.new()
    params.FilterType = Enum.RaycastFilterType.Include
    params.FilterDescendantsInstances = surfaces

    local hit = workspace:Raycast(
        pos + Vector3.new(0, 25, 0),
        Vector3.new(0, -50, 0),
        params
    )
    if hit and hit.Instance:IsDescendantOf(plot) then
        return hit.Position
    end
    return pos
end

local function _getPlantAreaColumns(plot)
    local cols = {}
    if not plot then return cols end
    local visual = plot:FindFirstChild("Visual")
    if visual then
        for _, name in ipairs(PLANT_AREA_COLUMN_NAMES) do
            local part = visual:FindFirstChild(name)
            if part and part:IsA("BasePart") then
                cols[#cols + 1] = part
            end
        end
    end
    if #cols == 0 then
        for _, name in ipairs(PLANT_AREA_COLUMN_NAMES) do
            local part = plot:FindFirstChild(name, true)
            if part and part:IsA("BasePart") then
                cols[#cols + 1] = part
            end
        end
    end
    table.sort(cols, function(a, b)
        if math.abs(a.Position.X - b.Position.X) > 0.01 then
            return a.Position.X < b.Position.X
        end
        return a.Position.Z < b.Position.Z
    end)
    return cols
end

local function _findPlantAreaColumn(plot, name)
    if not plot or not name or name == "" then return nil end
    local visual = plot:FindFirstChild("Visual")
    if visual then
        local part = visual:FindFirstChild(name)
        if part and part:IsA("BasePart") then return part end
    end
    local part = plot:FindFirstChild(name, true)
    if part and part:IsA("BasePart") then return part end
    return nil
end

local function _findPlantAreaColumnAt(plot, worldPos)
    if not plot or not worldPos then return nil end
    for _, part in ipairs(_getPlantAreaColumns(plot)) do
        local lp = part.CFrame:PointToObjectSpace(worldPos)
        local halfX = part.Size.X * 0.5
        local halfZ = part.Size.Z * 0.5
        if math.abs(lp.X) <= halfX and math.abs(lp.Z) <= halfZ then
            return part
        end
    end
    return nil
end

local function _getPrimaryPlantArea(plot)
    local cols = _getPlantAreaColumns(plot)
    if #cols > 0 then return cols[1] end
    local areas = collectPlotSurfaces(plot)
    if #areas == 0 then return nil end
    local best, bestArea = areas[1], 0
    for _, part in ipairs(areas) do
        if part:IsA("BasePart") then
            local a = part.Size.X * part.Size.Z
            if a > bestArea then
                best = part
                bestArea = a
            end
        end
    end
    return best
end

local function _findPlantAreaAt(plot, worldPos)
    if not plot or not worldPos then return nil end
    local col = _findPlantAreaColumnAt(plot, worldPos)
    if col then return col end
    for _, part in ipairs(collectPlotSurfaces(plot)) do
        if part:IsA("BasePart") then
            local lp = part.CFrame:PointToObjectSpace(worldPos)
            local halfX = part.Size.X * 0.5
            local halfZ = part.Size.Z * 0.5
            if math.abs(lp.X) <= halfX and math.abs(lp.Z) <= halfZ then
                return part
            end
        end
    end
    return nil
end

local function _worldInsidePlantArea(plot, worldPos)
    return _findPlantAreaAt(plot, worldPos) ~= nil
end

local function _clampPosOnPlantArea(plot, worldPos)
    if not plot or not worldPos then return worldPos end
    local part = _findPlantAreaColumnAt(plot, worldPos) or _findPlantAreaAt(plot, worldPos) or _getPrimaryPlantArea(plot)
    if not part then return worldPos end
    local lp = part.CFrame:PointToObjectSpace(worldPos)
    local halfX = part.Size.X * 0.5
    local halfZ = part.Size.Z * 0.5
    lp = Vector3.new(
        math.clamp(lp.X, -halfX * RANDOM_PART_MARGIN, halfX * RANDOM_PART_MARGIN),
        part.Size.Y * 0.5 + 0.05,
        math.clamp(lp.Z, -halfZ * RANDOM_PART_MARGIN, halfZ * RANDOM_PART_MARGIN)
    )
    return part.CFrame:PointToWorldSpace(lp)
end

local function _resolvePlantPos(plot, pos)
    if not plot or not pos then return nil end
    pos = _snapToPlantSurface(plot, pos) or pos
    local part = _findPlantAreaColumnAt(plot, pos) or _findPlantAreaAt(plot, pos) or _getPrimaryPlantArea(plot)
    if not part then return nil end
    local lp = part.CFrame:PointToObjectSpace(pos)
    local halfX = part.Size.X * 0.5 * RANDOM_PART_MARGIN
    local halfZ = part.Size.Z * 0.5 * RANDOM_PART_MARGIN
    lp = Vector3.new(
        math.clamp(lp.X, -halfX, halfX),
        part.Size.Y * 0.5 + 0.05,
        math.clamp(lp.Z, -halfZ, halfZ)
    )
    return part.CFrame:PointToWorldSpace(lp)
end

local function _partCenterPos(part)
    if not part or not part:IsA("BasePart") then return nil end
    return part.CFrame:PointToWorldSpace(
        Vector3.new(0, part.Size.Y * 0.5 + 0.05, 0)
    )
end

local function _resolvePlantPosOnPart(plot, part, worldPos)
    if not plot or not part or not worldPos then return nil end
    local lp = part.CFrame:PointToObjectSpace(worldPos)
    local halfX = part.Size.X * 0.5 * RANDOM_PART_MARGIN
    local halfZ = part.Size.Z * 0.5 * RANDOM_PART_MARGIN
    lp = Vector3.new(
        math.clamp(lp.X, -halfX, halfX),
        part.Size.Y * 0.5 + 0.05,
        math.clamp(lp.Z, -halfZ, halfZ)
    )
    return part.CFrame:PointToWorldSpace(lp)
end

local function _listPlantAreaAnchors(plot)
    local anchors = {}
    if not plot then return anchors end
    for _, part in ipairs(_getPlantAreaColumns(plot)) do
        local pos = _partCenterPos(part)
        if pos then
            anchors[#anchors + 1] = {
                part = part,
                parts = { part },
                pos = pos,
                root = part,
            }
        end
    end
    return anchors
end

local function _listPlantAreaCenters(plot)
    local centers = {}
    for _, anchor in ipairs(_listPlantAreaAnchors(plot)) do
        centers[#centers + 1] = anchor.pos
    end
    return centers
end

local function _getPlotAreaCenter(plot)
    if not plot then return nil end
    local cols = _getPlantAreaColumns(plot)
    if #cols > 0 then
        return _partCenterPos(cols[1])
    end
    local surfaces = collectPlotSurfaces(plot)
    if #surfaces == 0 then return nil end
    local sx, sy, sz, n = 0, 0, 0, 0
    for _, p in ipairs(surfaces) do
        if p:IsA("BasePart") then
            sx += p.Position.X
            sy += p.Position.Y
            sz += p.Position.Z
            n += 1
        end
    end
    if n <= 0 then return nil end
    return Vector3.new(sx / n, sy / n + 0.05, sz / n)
end

local function _plotPivotCFrame(plot)
    if not plot then return nil end
    local ok, pivot = pcall(function()
        return plot:GetPivot()
    end)
    if ok and typeof(pivot) == "CFrame" then
        return pivot
    end
    local part = _getPrimaryPlantArea(plot)
    return part and part.CFrame or nil
end

local function _writePositionLocal(entry, plot, worldPos)
    if type(entry) ~= "table" or not plot or not worldPos then return false end
    local cf = _plotPivotCFrame(plot)
    if cf then
        local lp = cf:PointToObjectSpace(worldPos)
        entry.plx = lp.X
        entry.ply = lp.Y
        entry.plz = lp.Z
    end
    local part = _findPlantAreaColumnAt(plot, worldPos) or _findPlantAreaAt(plot, worldPos) or _getPrimaryPlantArea(plot)
    if part and part:IsA("BasePart") then
        local lp = part.CFrame:PointToObjectSpace(worldPos)
        local halfX = math.max(part.Size.X * 0.5, 0.01)
        local halfZ = math.max(part.Size.Z * 0.5, 0.01)
        entry.areaName = part.Name
        entry.nu = lp.X / halfX
        entry.nv = lp.Z / halfZ
    end
    return true
end

local function _worldFromPositionLocal(entry, plot)
    if type(entry) ~= "table" or not plot then return nil end
    local nu = tonumber(entry.nu)
    local nv = tonumber(entry.nv)
    if nu ~= nil and nv ~= nil then
        local part = nil
        local areaName = tostring(entry.areaName or "")
        if areaName ~= "" then
            part = _findPlantAreaColumn(plot, areaName)
            if not part then
                for _, p in ipairs(collectPlotSurfaces(plot)) do
                    if p:IsA("BasePart") and p.Name == areaName then
                        part = p
                        break
                    end
                end
            end
        end
        part = part or _getPrimaryPlantArea(plot)
        if part then
            local halfX = part.Size.X * 0.5
            local halfZ = part.Size.Z * 0.5
            nu = math.clamp(nu, -0.92, 0.92)
            nv = math.clamp(nv, -0.92, 0.92)
            local lp = Vector3.new(nu * halfX, part.Size.Y * 0.5 + 0.05, nv * halfZ)
            return part.CFrame:PointToWorldSpace(lp)
        end
    end
    local plx = tonumber(entry.plx)
    local ply = tonumber(entry.ply)
    local plz = tonumber(entry.plz)
    if plx and ply and plz then
        local cf = _plotPivotCFrame(plot)
        if cf then
            return cf:PointToWorldSpace(Vector3.new(plx, ply, plz))
        end
    end
    return nil
end

local function _entryPlotIdStr(entry)
    if type(entry) ~= "table" or entry.plotId == nil then return nil end
    return tostring(entry.plotId)
end

local function _currentPlotIdStr()
    local pid = LP:GetAttribute("PlotId")
    return pid ~= nil and tostring(pid) or nil
end

local function _savedOnCurrentPlot(entry)
    local saved = _entryPlotIdStr(entry)
    local cur = _currentPlotIdStr()
    if not saved or not cur then return true end
    return saved == cur
end

local function _needsPlotRecenter(entry, plot)
    if type(entry) ~= "table" or not plot then return false end
    local fromLocal = _worldFromPositionLocal(entry, plot)
    if fromLocal and _worldInsidePlantArea(plot, fromLocal) then
        return false
    end
    local x, y, z = tonumber(entry.x), tonumber(entry.y), tonumber(entry.z)
    if x and y and z and _worldInsidePlantArea(plot, Vector3.new(x, y, z)) then
        return false
    end
    return true
end

local function _persistPlantPositions(positions)
    local MAIN = rawget(_G, "MAIN") or G.MAIN
    if type(MAIN) ~= "table" then return false end
    MAIN.auto = MAIN.auto or {}
    MAIN.auto.plant = MAIN.auto.plant or {}
    MAIN.auto.plant.positions = positions
    G.MAIN = MAIN
    _G.MAIN = MAIN
    _notifyPositionsChanged()
    return true
end

local function _reanchorEntryToPlotCenter(entry, plot)
    if type(entry) ~= "table" or not plot then return nil end
    local center = nil
    local areaName = tostring(entry.areaName or "")
    if areaName ~= "" then
        local col = _findPlantAreaColumn(plot, areaName)
        if col then center = _partCenterPos(col) end
    end
    center = center or _getPlotAreaCenter(plot)
    if not center then return nil end
    entry.x = center.X
    entry.y = center.Y
    entry.z = center.Z
    local plotId = LP:GetAttribute("PlotId")
    if plotId ~= nil then
        entry.plotId = plotId
    end
    _writePositionLocal(entry, plot, center)
    _log("reanchor pos to plot center", entry.id, center)
    local MAIN = rawget(_G, "MAIN") or G.MAIN
    if type(MAIN) == "table" and type(MAIN.auto) == "table" and type(MAIN.auto.plant) == "table" then
        _persistPlantPositions(MAIN.auto.plant.positions)
    end
    manualSlotCursor = 1
    _clearCircleCache(entry.id)
    if os.clock() - manualWarnAt > 8 then
        manualWarnAt = os.clock()
    end
    return center
end

local function vecFromSaved(entry, plot)
    if type(entry) ~= "table" then return nil end
    plot = plot or getPlayerPlot()
    if not plot then return nil end
    local fromLocal = _worldFromPositionLocal(entry, plot)
    if fromLocal and _worldInsidePlantArea(plot, fromLocal) then
        return _snapToPlantSurface(plot, fromLocal)
    end
    local x, y, z = tonumber(entry.x), tonumber(entry.y), tonumber(entry.z)
    if x and y and z then
        local pos = Vector3.new(x, y, z)
        if _worldInsidePlantArea(plot, pos) then
            return _snapToPlantSurface(plot, pos)
        end
    end
    if _needsPlotRecenter(entry, plot) then
        return _reanchorEntryToPlotCenter(entry, plot)
    end
    return nil
end

local function _getStandingPlotPosition(plot)
    local char = LP.Character
    local hrp = char and char:FindFirstChild("HumanoidRootPart")
    if not hrp or not plot then return nil end

    local surfaces = collectPlotSurfaces(plot)
    if #surfaces == 0 then return nil end

    local params = RaycastParams.new()
    params.FilterType = Enum.RaycastFilterType.Include
    params.FilterDescendantsInstances = surfaces

    local hit = workspace:Raycast(hrp.Position + Vector3.new(0, 10, 0), Vector3.new(0, -40, 0), params)
    if hit and hit.Instance:IsDescendantOf(plot) then
        return hit.Position
    end

    for _, part in ipairs(surfaces) do
        if part:IsA("BasePart") then
            local lp = part.CFrame:PointToObjectSpace(hrp.Position)
            local halfX = part.Size.X * 0.55
            local halfZ = part.Size.Z * 0.55
            if math.abs(lp.X) <= halfX and math.abs(lp.Z) <= halfZ then
                return Vector3.new(
                    hrp.Position.X,
                    part.Position.Y + part.Size.Y * 0.5 + 0.05,
                    hrp.Position.Z
                )
            end
        end
    end

    return nil
end

local function seedMatchesTool(tool, selectedSeeds)
    if not tool or not tool:IsA("Tool") then return false end
    local seedAttr = tool:GetAttribute("SeedTool")
    if seedAttr == nil then return false end

    if not next(selectedSeeds) then
        return not _isMutationSeedTool(tool)
    end

    local toolNames = {
        tostring(seedAttr),
        tostring(tool.Name),
        tostring(tool:GetAttribute("SeedName") or ""),
    }

    for sel, on in pairs(selectedSeeds) do
        if on == true then
            for _, tname in ipairs(toolNames) do
                if tname ~= "" and _seedKeyMatch(sel, tname) then
                    return true
                end
            end
        end
    end
    return false
end

local function findAllSeedTools(selectedSeeds)
    local found = {}
    local seen = {}

    local function scan(container)
        if not container then return end
        for _, inst in ipairs(container:GetDescendants()) do
            if inst:IsA("Tool") and seedMatchesTool(inst, selectedSeeds) and not _isSeedToolSkipped(inst) then
                local id = _seedToolId(inst)
                if id ~= "" and not seen[id] then
                    seen[id] = true
                    found[#found + 1] = inst
                end
            end
        end
    end

    for _, container in ipairs(_iterInventoryContainers()) do
        scan(container)
    end
    return found
end

local function _countSeedTools(selectedSeeds)
    return #findAllSeedTools(selectedSeeds)
end

-- Live backpack qty (Count/Amount/… per tool). Jangan dedupe by SeedTool type —
-- tiap Tool instance dihitung; dipakai untuk label start→remaining (bukan Fire/plot).
local function _toolStackCount(tool)
    if not tool then return 0 end
    local n = tonumber(tool:GetAttribute("Count"))
        or tonumber(tool:GetAttribute("Amount"))
        or tonumber(tool:GetAttribute("Stack"))
        or tonumber(tool:GetAttribute("Qty"))
        or tonumber(tool:GetAttribute("Quantity"))
    if n and n > 0 then
        return math.floor(n)
    end
    return 1
end

local function _countLiveSeedUnits(selectedSeeds)
    selectedSeeds = type(selectedSeeds) == "table" and selectedSeeds or {}
    local sum = 0
    local seenInst = {}

    local function scan(container)
        if not container then return end
        for _, inst in ipairs(container:GetDescendants()) do
            if inst:IsA("Tool") and not seenInst[inst] and seedMatchesTool(inst, selectedSeeds) then
                seenInst[inst] = true
                sum += _toolStackCount(inst)
            end
        end
    end

    for _, container in ipairs(_iterInventoryContainers()) do
        scan(container)
    end
    return sum
end

local function _countInventorySeeds(selectedSeeds)
    selectedSeeds = type(selectedSeeds) == "table" and selectedSeeds or {}
    local live = _countLiveSeedUnits(selectedSeeds)
    if live > 0 then
        return live
    end

    local cached = G.__GAG2_PLANT_SEED_LIST_CACHE or rawget(_G, "__GAG2_PLANT_SEED_LIST_CACHE")
    if type(cached) == "table" and #cached > 0 then
        local plv = _getPlantListView()
        if plv and type(plv.countOwnedSeeds) == "function" then
            local ok, n = pcall(plv.countOwnedSeeds, plv, selectedSeeds)
            if ok and type(n) == "number" and n > 0 then
                return math.max(0, math.floor(n))
            end
        end
        local sum = 0
        for _, it in ipairs(cached) do
            local n = tonumber(it.count)
            if not n and type(it.right) == "string" then
                local tail = it.right:gsub(",", "")
                local low = tail:lower()
                if low:sub(-1) == "k" then
                    n = (tonumber(tail:sub(1, -2)) or 0) * 1000
                elseif low:sub(-1) == "m" then
                    n = (tonumber(tail:sub(1, -2)) or 0) * 1000000
                else
                    n = tonumber(tail)
                end
            else
                n = n or tonumber(it.right)
            end
            sum += math.max(0, math.floor(n or 0))
        end
        if sum > 0 then return sum end
    end
    local plv = _getPlantListView()
    if plv and type(plv.countOwnedSeeds) == "function" then
        local ok, n = pcall(plv.countOwnedSeeds, plv, selectedSeeds)
        if ok and type(n) == "number" and n > 0 then
            return math.max(0, math.floor(n))
        end
    end
    return _countSeedTools(selectedSeeds)
end

-- planted = seed awal sesi − sisa di backpack (bukan Fire, bukan #plants di plot).
-- Hanya live tool qty — jangan pakai cache bag mailbox (bisa beda dari yang plantable).
local function _syncSessionPlantedFromInventory(st)
    st = st or getPlantState()
    local remaining = _countLiveSeedUnits(st.seeds)
    if not sessionStartLocked and remaining > 0 then
        sessionStartTotal = remaining
        sessionStartLocked = true
    end
    local planted = 0
    if sessionStartTotal > 0 then
        planted = math.max(0, sessionStartTotal - remaining)
    end
    sessionPlanted = planted
    return planted, remaining
end

local function _resetSessionSeedStats(st)
    st = st or getPlantState()
    sessionStartTotal = _countLiveSeedUnits(st.seeds)
    sessionStartLocked = sessionStartTotal > 0
    sessionPlanted = 0
    sessionUserLimit = math.max(0, math.floor(tonumber(st.plantTotal) or 0))
    _notifySeedStatsChanged()
end

local function _canPlantMore(st)
    local planted, remaining = _syncSessionPlantedFromInventory(st)
    if remaining <= 0 then
        return false
    end
    if sessionUserLimit > 0 then
        return planted < sessionUserLimit
    end
    return true
end

local function _isPlantSessionDone(st)
    st = st or getPlantState()
    local planted, remaining = _syncSessionPlantedFromInventory(st)
    if remaining <= 0 and sessionStartTotal > 0 then
        return true, "no_seeds"
    end
    if sessionUserLimit > 0 and planted >= sessionUserLimit then
        return true, "limit"
    end
    return false, nil
end

local function _autoStopPlantSession(st, reason)
    st = st or getPlantState()
    if not st.enabled then return end

    M.SetEnabled(false)
    _writeMainPlant({ enabled = false })

    local api = G.__GAG2_PLANT_ENABLE_API or rawget(_G, "__GAG2_PLANT_ENABLE_API")
    if type(api) == "table" and type(api.setOff) == "function" then
        pcall(api.setOff, true)
    end

    if type(G.__GAG2_SYNC_AUTO_PLANT) == "function" then
        pcall(G.__GAG2_SYNC_AUTO_PLANT)
    end

    if type(G.__GAG2_ON_PLANT_AUTO_FINISHED) == "function" then
        pcall(G.__GAG2_ON_PLANT_AUTO_FINISHED)
    end

    _notifySeedStatsChanged()
    _log("auto stop", tostring(reason or ""))
end

local function plantGapSec(st)
    st = st or getPlantState()
    local d = tonumber(st.delay)
    if d == nil then d = 0 end
    if d <= 0 then return 0 end
    return math.max(PLANT_MIN_GAP, d)
end

local function _firePlantRemote(pos, seedId, tool)
    if not PlantSeed then return false, "no_remote" end

    local function tryCall(fn)
        local ok, err = pcall(fn)
        return ok, err
    end

    if type(PlantSeed.Fire) == "function" then
        local ok, err = tryCall(function() PlantSeed:Fire(pos, seedId, tool) end)
        if ok then return true end
        lastPlantFailReason = tostring(err or "fire_fail")
    end

    if typeof(PlantSeed) == "Instance" and PlantSeed:IsA("RemoteEvent") then
        local ok, err = tryCall(function() PlantSeed:FireServer(pos, seedId, tool) end)
        if ok then return true end
        lastPlantFailReason = tostring(err or "fireserver_fail")
    end

    if type(PlantSeed) == "table" then
        for _, key in ipairs({ "Remote", "_remote", "remote", "Event", "_event" }) do
            local inner = PlantSeed[key]
            if typeof(inner) == "Instance" and inner:IsA("RemoteEvent") then
                local ok = tryCall(function() inner:FireServer(pos, seedId, tool) end)
                if ok then return true end
            end
        end
    end

    return false, lastPlantFailReason ~= "" and lastPlantFailReason or "fire_fail"
end

local function plantAtPosition(pos, tool, st, opts)
    opts = type(opts) == "table" and opts or {}
    local blocked, blockReason = _isGameplayBlocked()
    if blocked then
        lastPlantFailReason = blockReason or "cutscene"
        return false, lastPlantFailReason
    end
    if not tool or not tool.Parent then
        lastPlantFailReason = "no_tool"
        return false, "no_tool"
    end
    if not _canPlantMore() then
        lastPlantFailReason = "limit"
        return false, "limit"
    end
    local plot = getPlayerPlot()
    if not plot or not pos then
        lastPlantFailReason = "no_plot"
        return false, "no_surface"
    end
    pos = opts.lockPart and _resolvePlantPosOnPart(plot, opts.lockPart, pos)
        or _resolvePlantPos(plot, pos)
    if not pos then
        lastPlantFailReason = "no_surface"
        return false, "no_surface"
    end
    if not opts.ignoreGap and plantGapSec(st) > 0 and os.clock() - lastPlantAt < plantGapSec(st) then
        lastPlantFailReason = "cooldown"
        return false, "cooldown"
    end

    local seedId = tool:GetAttribute("SeedTool")
    if seedId == nil then
        lastPlantFailReason = "no_seed_attr"
        return false, "no_seed_attr"
    end

    local ok, err = _firePlantRemote(pos, seedId, tool)
    if ok then
        lastPlantAt = os.clock()
        lastPlantFailReason = ""
        -- Jangan ++ dari Fire: tunggu konsumsi seed, hitung dari backpack delta
        task.defer(function()
            task.wait(0.05)
            _syncSessionPlantedFromInventory(st)
            _notifySeedStatsChanged()
        end)
        _log("plant", seedId, pos)
        return true
    end
    lastPlantFailReason = tostring(err or "plant_fail")
    return false, lastPlantFailReason
end

local function tryPlantAt(pos, st, opts)
    st = st or getPlantState()
    opts = type(opts) == "table" and opts or {}
    local plot = getPlayerPlot()
    if not plot then return false, "no_plot" end
    local minDist = tonumber(opts.minDist) or MIN_PLANT_DIST
    if not opts.ignoreBlocked and isBlockedPlantSpot(pos, minDist, plot) then
        return false, "blocked"
    end

    local tools = findAllSeedTools(st.seeds)
    if #tools == 0 then return false, "no_seed_tool" end

    local lastErr = "plant_fail"
    for i = 1, #tools do
        local tool = tools[((seedToolRotate + i - 2) % #tools) + 1]
        local ok, err = plantAtPosition(pos, tool, st, opts)
        if ok then
            seedToolRotate = ((seedToolRotate + i - 2) % #tools) + 1
            return true
        end
        lastErr = err or lastErr
        if _isAvatarBlockedError(err) then
            _markSeedToolSkipped(tool, 90)
            if os.clock() - randomWarnAt > 8 then
                randomWarnAt = os.clock()
            end
        else
            break
        end
    end
    return false, lastErr
end

local function randomPointOnPart(part)
    local size = part.Size
    local cf = part.CFrame
    local margin = RANDOM_PART_MARGIN
    local rx = (math.random() - 0.5) * size.X * margin
    local rz = (math.random() - 0.5) * size.Z * margin
    return (cf * CFrame.new(rx, size.Y * 0.5, rz)).Position
end

local function _guardSeedTools(st)
    if next(st.seeds) and _countSeedTools(st.seeds) == 0 then
        lastPlantFailReason = "no_seed_tool"
        if os.clock() - randomWarnAt > 8 then
            randomWarnAt = os.clock()
        end
        return false
    end
    return true
end

local function tryRandomPlant(st)
    local plot = getPlayerPlot()
    if not plot then
        if os.clock() - randomWarnAt > 8 then
            randomWarnAt = os.clock()
        end
        return false
    end

    if not _guardSeedTools(st) then return false end

    local surfaces = collectPlotSurfaces(plot)
    if #surfaces == 0 then
        if os.clock() - randomWarnAt > 8 then
            randomWarnAt = os.clock()
        end
        return false
    end

    local areaParts = {}
    for _, inst in ipairs(surfaces) do
        if inst:IsA("BasePart") then
            areaParts[#areaParts + 1] = inst
        end
    end
    if #areaParts == 0 then return false end

    local planted = 0
    for _ = 1, RANDOM_MAX_TRY do
        if not _canPlantMore() or planted >= PLANTS_PER_TICK then break end
        local part = areaParts[math.random(1, #areaParts)]
        local pos = randomPointOnPart(part)
        local ok = tryPlantAt(pos, st, {
            minDist = RANDOM_MIN_PLANT_DIST,
            ignoreGap = planted > 0,
        })
        if ok then
            planted += 1
        end
    end
    if planted > 0 then return true end

    if os.clock() - randomWarnAt > 8 then
        randomWarnAt = os.clock()
    end
    return false
end

local function _positionEntryById(positions, id)
    if type(positions) ~= "table" then return nil end
    id = tostring(id or "")
    if id == "" then return nil end
    for _, entry in ipairs(positions) do
        if type(entry) == "table" and tostring(entry.id) == id then
            return entry
        end
    end
    return nil
end

local function _resolveSelectedAnchorIds(st)
    local ids = {}
    local selected = st.selectedPositions
    if type(selected) == "table" and next(selected) then
        for id, on in pairs(selected) do
            if on == true then
                ids[#ids + 1] = tostring(id)
            end
        end
    elseif st.selectedPosition then
        ids[1] = tostring(st.selectedPosition)
    elseif type(st.positions) == "table" then
        for _, entry in ipairs(st.positions) do
            if type(entry) == "table" and entry.id then
                ids[#ids + 1] = tostring(entry.id)
            end
        end
    end
    table.sort(ids)
    return ids
end

local function _offsetForPositionSlot(slot)
    if slot <= 1 then
        return Vector3.zero
    end

    local spacing = POSITION_PLANT_SPACING
    local remaining = slot - 1
    local ring = 1
    while remaining > 8 * ring do
        remaining -= 8 * ring
        ring += 1
    end

    local idx = remaining - 1
    local r = ring
    local side = 2 * r
    if idx < side then
        return Vector3.new((-r + idx) * spacing, 0, -r * spacing)
    elseif idx < 2 * side then
        local i = idx - side
        return Vector3.new(r * spacing, 0, (-r + i) * spacing)
    elseif idx < 3 * side then
        local i = idx - 2 * side
        return Vector3.new((r - i) * spacing, 0, r * spacing)
    end
    local i = idx - 3 * side
    return Vector3.new(-r * spacing, 0, (r - i) * spacing)
end

local function tryManualPlant(st)
    st = st or getPlantState()
    local positions = st.positions
    if type(positions) ~= "table" or #positions == 0 then
        if os.clock() - manualWarnAt > 5 then
            manualWarnAt = os.clock()
        end
        return false
    end

    local anchorIds = _resolveSelectedAnchorIds(st)
    if #anchorIds == 0 then
        if os.clock() - manualWarnAt > 5 then
            manualWarnAt = os.clock()
        end
        return false
    end

    if not _guardSeedTools(st) then return false end

    local plot = getPlayerPlot()
    if not plot then return false end

    if manualAnchorCursor > #anchorIds or manualAnchorCursor < 1 then
        manualAnchorCursor = 1
    end
    if manualSlotCursor > POSITION_MAX_SCAN or manualSlotCursor < 1 then
        manualSlotCursor = 1
    end

    local spacing = POSITION_PLANT_SPACING

    for _ = 1, #anchorIds do
        local anchorIdx = manualAnchorCursor
        local entry = _positionEntryById(positions, anchorIds[anchorIdx])
        local anchor = entry and vecFromSaved(entry, plot)
        if not anchor then
            manualAnchorCursor += 1
            if manualAnchorCursor > #anchorIds then manualAnchorCursor = 1 end
            manualSlotCursor = 1
        else
            local blockedSkips = 0
            for slot = manualSlotCursor, POSITION_MAX_SCAN do
                if not _canPlantMore() then return false end

                _maybeRefreshPlotOnCircleBatch(slot)

                local offset = _offsetForPositionSlot(slot)
                local pos = _resolvePlantPos(plot, anchor + offset)
                if not pos then
                    if slot == 1 and entry then
                        local center = _reanchorEntryToPlotCenter(entry, plot)
                        if center then
                            anchor = center
                            pos = _resolvePlantPos(plot, center)
                        end
                    end
                    if not pos then
                        manualSlotCursor = slot + 1
                        break
                    end
                end

                local ok, err = tryPlantAt(pos, st, { minDist = spacing })
                if ok then
                    manualSlotCursor = slot + 1
                    return true
                end
                if err == "no_seed_tool" or err == "limit" or err == "cutscene" then
                    return false
                end
                if slot == 1 and err ~= "blocked" and entry
                    and (_needsPlotRecenter(entry, plot) or not _worldInsidePlantArea(plot, pos)) then
                    local center = _reanchorEntryToPlotCenter(entry, plot)
                    if center then
                        anchor = center
                        pos = _resolvePlantPos(plot, center)
                        if pos then
                            ok, err = tryPlantAt(pos, st, { minDist = spacing })
                            if ok then
                                manualSlotCursor = slot + 1
                                return true
                            end
                        end
                    end
                end
                if err ~= "blocked" then
                    manualSlotCursor = slot + 1
                    break
                end

                blockedSkips += 1
                if blockedSkips >= MAX_BLOCKED_SKIP_PER_TICK then
                    manualSlotCursor = slot + 1
                    break
                end
            end

            if manualSlotCursor > POSITION_MAX_SCAN then
                _log("spiral full, wrap anchor", manualAnchorCursor, POSITION_MAX_SCAN)
                manualAnchorCursor += 1
                if manualAnchorCursor > #anchorIds then
                    manualAnchorCursor = 1
                end
                manualSlotCursor = 1
            else
                break
            end
        end
    end

    return false
end

local function tryCenterPlant(st)
    local plot = getPlayerPlot()
    if not plot then
        if os.clock() - randomWarnAt > 8 then
            randomWarnAt = os.clock()
        end
        return false
    end

    if not _guardSeedTools(st) then return false end

    local anchors = _listPlantAreaAnchors(plot)
    if #anchors == 0 then return false end

    if centerAnchorCursor > #anchors or centerAnchorCursor < 1 then
        centerAnchorCursor = 1
    end
    if centerSlotCursor > POSITION_MAX_SCAN or centerSlotCursor < 1 then
        centerSlotCursor = 1
    end

    local spacing = POSITION_PLANT_SPACING

    local anchor0 = anchors[centerAnchorCursor]
    if anchor0 and centerSlotCursor > 1 then
        local centerPos = _resolvePlantPosOnPart(plot, anchor0.part, anchor0.pos)
        if centerPos and not isBlockedPlantSpot(centerPos, spacing, plot) then
            centerSlotCursor = 1
        end
    end

    for _ = 1, #anchors do
        local anchor = anchors[centerAnchorCursor]
        local blockedSkips = 0

        for slot = centerSlotCursor, POSITION_MAX_SCAN do
            if not _canPlantMore() then return false end

            _maybeRefreshPlotOnCircleBatch(slot)

            local offset = _offsetForPositionSlot(slot)
            local target = anchor.pos + offset
            local pos = _resolvePlantPosOnPart(plot, anchor.part, target)
            if not pos then
                centerSlotCursor = slot + 1
                break
            end

            if slot == 1 and not _worldInsidePlantArea(plot, pos) then
                pos = _resolvePlantPosOnPart(plot, anchor.part, anchor.pos)
                if not pos then
                    centerSlotCursor = slot + 1
                    break
                end
            end

            local ok, err = tryPlantAt(pos, st, {
                minDist = spacing,
                lockPart = anchor.part,
            })
            if ok then
                centerSlotCursor = slot + 1
                return true
            end
            if err == "no_seed_tool" or err == "limit" or err == "cutscene" then
                return false
            end
            if err ~= "blocked" then
                centerSlotCursor = slot + 1
                break
            end

            blockedSkips += 1
            if blockedSkips >= MAX_BLOCKED_SKIP_PER_TICK then
                centerSlotCursor = slot + 1
                break
            end
        end

        if centerSlotCursor > POSITION_MAX_SCAN then
            centerSlotCursor = 1
            centerAnchorCursor += 1
            if centerAnchorCursor > #anchors then
                centerAnchorCursor = 1
            end
        else
            break
        end
    end

    return false
end

local function plantTick(st)
    if not _canPlantMore() then return false end
    st = st or getPlantState()
    if st.mode == "manual" then
        return tryManualPlant(st)
    end
    if st.mode == "center" then
        return tryCenterPlant(st)
    end
    return tryRandomPlant(st)
end

local function mainLoop(myId)
    _log("loop start", myId)
    local lastWarnAt = 0
    local lastIdleWarnAt = 0
    while running and loopId == myId do
        local st = getPlantState()
        local blocked, blockReason = _isGameplayBlocked()
        if st.enabled and not blocked then
            local okTick, tickErr = pcall(function()
                local done, reason = _isPlantSessionDone(st)
                if done then
                    _autoStopPlantSession(st, reason)
                else
                    local planted = plantTick(st)
                    if planted then
                        lastIdleWarnAt = 0
                        _syncSessionPlantedFromInventory(st)
                        _notifySeedStatsChanged()
                    elseif os.clock() - lastIdleWarnAt > 10 then
                        lastIdleWarnAt = os.clock()
                        _syncSessionPlantedFromInventory(st)
                        _notifySeedStatsChanged()
                    end
                    local doneAfter, reasonAfter = _isPlantSessionDone(st)
                    if doneAfter then
                        _autoStopPlantSession(st, reasonAfter)
                    elseif st.delay > 0 then
                        _notifySeedStatsChanged()
                    end
                end
            end)
            if not okTick then
                local now = os.clock()
                if now - lastWarnAt > 8 then
                    lastWarnAt = now
                end
            end
        elseif st.enabled and blocked then
            if os.clock() - lastIdleWarnAt > 10 then
                lastIdleWarnAt = os.clock()
            end
        end
        if st.delay > 0 then
            task.wait(st.delay)
        else
            task.wait()
        end
    end
    _log("loop end", myId)
end

----------------------------------------------------------------
-- save position
----------------------------------------------------------------
local _bindSaveListener
local _disableSaveMode

local function _isMouseOverBlockingUI()
    local ui = G.__GROWAGARDEN2_UI
    if not ui then return false end

    local loc = UserInputService:GetMouseLocation()
    local inset = GuiService:GetGuiInset()
    local x, y = loc.X, loc.Y - inset.Y

    local function hitsRoot(root)
        if not root or not root.Parent then return false end
        for _, obj in ipairs(GuiService:GetGuiObjectsAtPosition(x, y)) do
            if obj == root or obj:IsDescendantOf(root) then
                return true
            end
        end
        return false
    end

    if hitsRoot(ui.mainFrame) then return true end

    local sg = ui._sg
    if sg then
        for _, desc in ipairs(sg:GetDescendants()) do
            if desc.Name == "NodeHubDropdownOverlay" or desc.Name == "NodeHubModeOverlay" then
                if hitsRoot(desc) then return true end
            end
        end
    end

    return false
end

local function _isTargetOnPlot(target, plot)
    if not target or not plot then return false end
    return target:IsDescendantOf(plot)
end

local function _resolveSaveHit(plot, preferStanding)
    if preferStanding then
        local stand = _getStandingPlotPosition(plot)
        if stand then return stand end
    end

    local cam = workspace.CurrentCamera
    if cam then
        local loc = UserInputService:GetMouseLocation()
        local ray = cam:ViewportPointToRay(loc.X, loc.Y)
        local hit = raycastPlantArea(ray.Origin, ray.Direction * 5000, plot)
        if hit and _isTargetOnPlot(hit.Instance, plot) then
            return hit.Position
        end
    end

    local mouse = LP:GetMouse()
    if mouse and mouse.Target and mouse.Hit and _isTargetOnPlot(mouse.Target, plot) then
        return mouse.Hit.Position
    end

    if not preferStanding then
        return _getStandingPlotPosition(plot)
    end

    return nil
end

local function _commitSavePosition(pos)
    if not pos then return false end

    local MAIN = rawget(_G, "MAIN") or G.MAIN
    if type(MAIN) ~= "table" then return false end

    MAIN.auto = MAIN.auto or {}
    MAIN.auto.plant = MAIN.auto.plant or {}

    local id = ("pos_%d"):format(math.floor(os.clock() * 1000))
    local positions = type(MAIN.auto.plant.positions) == "table" and MAIN.auto.plant.positions or {}
    local plotId = LP:GetAttribute("PlotId")
    local row = {
        id = id,
        x = pos.X,
        y = pos.Y,
        z = pos.Z,
        plotId = plotId,
    }
    local plot = getPlayerPlot()
    if plot then
        _writePositionLocal(row, plot, pos)
    end
    positions[#positions + 1] = row
    MAIN.auto.plant.positions = positions

    local selected = type(MAIN.auto.plant.selectedPositions) == "table"
        and MAIN.auto.plant.selectedPositions or {}
    local found = false
    for _, sid in ipairs(selected) do
        if tostring(sid) == id then
            found = true
            break
        end
    end
    if not found then
        selected[#selected + 1] = id
    end
    MAIN.auto.plant.selectedPositions = selected
    MAIN.auto.plant.selectedPosition = selected[1] or id
    G.MAIN = MAIN
    _G.MAIN = MAIN

    G.AUTO_PLANT_SELECTED_POSITION = MAIN.auto.plant.selectedPosition
    _G.AUTO_PLANT_SELECTED_POSITION = MAIN.auto.plant.selectedPosition
    G.AUTO_PLANT_SELECTED_POSITIONS = _normalizeSet(selected)
    _G.AUTO_PLANT_SELECTED_POSITIONS = G.AUTO_PLANT_SELECTED_POSITIONS

    _clearCircleCache()
    _notifyPositionsChanged()
    _log("saved pos", id, pos)

    _disableSaveMode()
    return true
end

_disableSaveMode = function()
    saveModeActive = false
    G.AUTO_PLANT_SAVE_POSITION = false
    _G.AUTO_PLANT_SAVE_POSITION = false
    _writeMainPlant({ savePosition = false })
    saveEnableAt = 0

    if type(G.__GAG2_ON_PLANT_SAVE_MODE_CHANGED) == "function" then
        pcall(G.__GAG2_ON_PLANT_SAVE_MODE_CHANGED, false)
    end

    local api = G.__GAG2_PLANT_SAVE_TOGGLE_API
    if type(api) == "table" and type(api.setOff) == "function" then
        pcall(api.setOff, true)
    end
end

local function trySavePositionFromMouse(force)
    if not saveModeActive and not getPlantState().savePosition then return false end
    if not force and os.clock() < saveEnableAt then return false end
    if not force and os.clock() - lastClickAt < 0.15 then return false end
    lastClickAt = os.clock()

    local plot = getPlayerPlot()
    if not plot then
        return false
    end

    local pos = _resolveSaveHit(plot, force == true)
    if not pos then
        if not force and _isMouseOverBlockingUI() then
            return false
        end
        return false
    end

    return _commitSavePosition(pos)
end

_bindSaveListener = function()
    if saveInputConn then return end

    saveInputConn = UserInputService.InputEnded:Connect(function(input)
        if input.UserInputType ~= Enum.UserInputType.MouseButton1
            and input.UserInputType ~= Enum.UserInputType.Touch then
            return
        end
        task.defer(trySavePositionFromMouse)
    end)

    UserInputService.InputBegan:Connect(function(input)
        if input.UserInputType ~= Enum.UserInputType.MouseButton1
            and input.UserInputType ~= Enum.UserInputType.Touch then
            return
        end
        task.delay(0.05, trySavePositionFromMouse)
    end)
end

