-- public API
----------------------------------------------------------------
function M.SetEnabled(on)
    on = (on == true)

    G.AUTO_PLANT_ENABLED = on
    _G.AUTO_PLANT_ENABLED = on
    _writeMainPlant({ enabled = on })

    if on then
        manualSlotCursor = 1
        manualAnchorCursor = 1
        centerSlotCursor = 1
        centerAnchorCursor = 1
        sessionStartLocked = false
        _clearCircleCache()
        _resetSessionSeedStats()
        running = true
        loopId += 1
        local myId = loopId
        task.spawn(function() mainLoop(myId) end)
    else
        running = false
        _syncSessionPlantedFromInventory()
        _notifySeedStatsChanged()
    end
end

M.setEnabled = M.SetEnabled
function M.Start() return M.SetEnabled(true) end
M.start = M.Start
function M.Stop() return M.SetEnabled(false) end
M.stop = M.Stop

function M.SetSavePosition(on)
    on = (on == true)
    if not on then
        saveModeActive = false
        G.AUTO_PLANT_SAVE_POSITION = false
        _G.AUTO_PLANT_SAVE_POSITION = false
        _writeMainPlant({ savePosition = false })
        saveEnableAt = 0
        return
    end

    saveModeActive = true
    G.AUTO_PLANT_SAVE_POSITION = true
    _G.AUTO_PLANT_SAVE_POSITION = true
    _writeMainPlant({ savePosition = true })

    local ui = G.__GROWAGARDEN2_UI
    if ui and type(ui.CloseDropdownOverlays) == "function" then
        pcall(ui.CloseDropdownOverlays, ui)
    end

    task.defer(function()
        M.SaveStandingPosition()
    end)
end

M.setSavePosition = M.SetSavePosition

function M.SetPlantTotal(a, b)
    local n = tonumber(b)
    if n == nil then n = tonumber(a) end
    if n == nil then return end
    if n < 0 then n = 0 end
    n = math.floor(n)
    G.AUTO_PLANT_TOTAL = n
    _G.AUTO_PLANT_TOTAL = n
    sessionUserLimit = n
    if not running then
        sessionPlanted = 0
    end
    _writeMainPlant({ plantTotal = n })
    _notifySeedStatsChanged()
end

M.setPlantTotal = M.SetPlantTotal

function M.SetMode(mode)
    mode = tostring(mode or "random"):lower()
    if mode ~= "manual" and mode ~= "center" then mode = "random" end
    manualSlotCursor = 1
    manualAnchorCursor = 1
    centerSlotCursor = 1
    centerAnchorCursor = 1
    _clearCircleCache()
    G.AUTO_PLANT_MODE = mode
    _G.AUTO_PLANT_MODE = mode
    _writeMainPlant({ mode = mode })
end

M.setMode = M.SetMode

function M.SetSelectedPosition(id)
    id = _normalizePositionId(id)
    local selected = id and { id } or {}
    G.AUTO_PLANT_SELECTED_POSITION = id
    _G.AUTO_PLANT_SELECTED_POSITION = id
    G.AUTO_PLANT_SELECTED_POSITIONS = _normalizeSet(selected)
    _G.AUTO_PLANT_SELECTED_POSITIONS = G.AUTO_PLANT_SELECTED_POSITIONS
    _writeMainPlant({
        selectedPosition = id,
        selectedPositions = selected,
    })
end

M.setSelectedPosition = M.SetSelectedPosition

function M.SetSelectedPositions(ids)
    local selected = {}
    if type(ids) == "table" then
        if ids[1] ~= nil then
            for _, v in ipairs(ids) do
                local id = _normalizePositionId(v)
                if id then selected[#selected + 1] = id end
            end
        else
            for k, v in pairs(ids) do
                if v == true then
                    local id = _normalizePositionId(k)
                    if id then selected[#selected + 1] = id end
                end
            end
        end
    end
    G.AUTO_PLANT_SELECTED_POSITIONS = _normalizeSet(selected)
    _G.AUTO_PLANT_SELECTED_POSITIONS = G.AUTO_PLANT_SELECTED_POSITIONS
    G.AUTO_PLANT_SELECTED_POSITION = selected[1]
    _G.AUTO_PLANT_SELECTED_POSITION = selected[1]
    _writeMainPlant({
        selectedPositions = selected,
        selectedPosition = selected[1],
    })
end

M.setSelectedPositions = M.SetSelectedPositions

function M.SyncFromState()
    local st = getPlantState()
    saveModeActive = false
    if st.savePosition then
        G.AUTO_PLANT_SAVE_POSITION = false
        _G.AUTO_PLANT_SAVE_POSITION = false
        _writeMainPlant({ savePosition = false })
    end
    M.SetEnabled(st.enabled)
end

M.syncFromState = M.SyncFromState

function M.GetPlayerPlot()
    return getPlayerPlot()
end

M.getPlayerPlot = M.GetPlayerPlot

function M.GetState()
    return getPlantState()
end

M.getState = M.GetState

function M.CountSeedTools(selectedSeeds)
    if selectedSeeds == nil then
        return _countInventorySeeds(getPlantState().seeds)
    end
    if type(selectedSeeds) == "table" then
        return _countInventorySeeds(_normalizeSet(selectedSeeds))
    end
    return 0
end

M.countSeedTools = M.CountSeedTools

function M.CountEquippedSeedTools(selectedSeeds)
    if selectedSeeds == nil then
        return _countSeedTools(getPlantState().seeds)
    end
    if type(selectedSeeds) == "table" then
        return _countSeedTools(_normalizeSet(selectedSeeds))
    end
    return 0
end

M.countEquippedSeedTools = M.CountEquippedSeedTools

function M.BuildOwnedSeedItems()
    local cached = G.__GAG2_PLANT_SEED_LIST_CACHE or rawget(_G, "__GAG2_PLANT_SEED_LIST_CACHE")
    if type(cached) == "table" and #cached > 0 then
        return cached
    end
    local plv = _getPlantListView()
    if plv and type(plv.buildPlantSeedItems) == "function" then
        local ok, items = pcall(plv.buildPlantSeedItems, plv)
        if ok and type(items) == "table" and #items > 0 then return items end
    end
    return {}
end

M.buildOwnedSeedItems = M.BuildOwnedSeedItems

function M.GetSeedStats()
    local ok, stats = pcall(function()
        local st = getPlantState()
        local planted, remaining = _syncSessionPlantedFromInventory(st)
        local totalInventory = _countInventorySeeds({})
        local startTotal = sessionStartTotal
        if startTotal <= 0 then
            startTotal = remaining
        end
        local target = sessionUserLimit
        if target <= 0 then
            target = startTotal
        end
        return {
            remaining = remaining,
            totalInventory = totalInventory,
            startTotal = startTotal,
            planted = planted,
            total = startTotal,
            plantTotal = sessionUserLimit,
            target = target,
            equippedTools = _countSeedTools(st.seeds),
            liveUnits = remaining,
        }
    end)
    if ok and type(stats) == "table" then
        return stats
    end
    return {
        remaining = 0,
        totalInventory = 0,
        startTotal = sessionStartTotal,
        planted = sessionPlanted,
        total = sessionStartTotal,
        plantTotal = sessionUserLimit,
        target = 0,
        equippedTools = 0,
        liveUnits = 0,
    }
end

M.getSeedStats = M.GetSeedStats

function M.SaveStandingPosition()
    saveModeActive = true
    G.AUTO_PLANT_SAVE_POSITION = true
    _G.AUTO_PLANT_SAVE_POSITION = true
    saveEnableAt = 0

    local plot = getPlayerPlot()
    if not plot then
        _disableSaveMode()
        return false
    end

    local pos = _getStandingPlotPosition(plot)
    if not pos then
        _disableSaveMode()
        return false
    end

    return _commitSavePosition(pos)
end

M.saveStandingPosition = M.SaveStandingPosition

function M.SavePositionNow()
    saveModeActive = true
    saveEnableAt = 0
    return trySavePositionFromMouse(true) == true
end

M.savePositionNow = M.SavePositionNow

function M.DeletePosition(id)
    id = tostring(id or "")
    if id == "" then return false end

    local MAIN = rawget(_G, "MAIN") or G.MAIN
    if type(MAIN) ~= "table" then return false end

    MAIN.auto = MAIN.auto or {}
    MAIN.auto.plant = MAIN.auto.plant or {}
    local positions = type(MAIN.auto.plant.positions) == "table" and MAIN.auto.plant.positions or {}

    local removed = false
    for i = #positions, 1, -1 do
        local entry = positions[i]
        if type(entry) == "table" and tostring(entry.id) == id then
            table.remove(positions, i)
            removed = true
        end
    end
    if not removed then return false end

    MAIN.auto.plant.positions = positions

    local selected = {}
    for _, sid in ipairs(type(MAIN.auto.plant.selectedPositions) == "table" and MAIN.auto.plant.selectedPositions or {}) do
        if tostring(sid) ~= id then
            selected[#selected + 1] = sid
        end
    end
    MAIN.auto.plant.selectedPositions = selected
    MAIN.auto.plant.selectedPosition = selected[1] and tostring(selected[1]) or nil
    G.MAIN = MAIN
    _G.MAIN = MAIN
    G.AUTO_PLANT_SELECTED_POSITION = MAIN.auto.plant.selectedPosition
    _G.AUTO_PLANT_SELECTED_POSITION = MAIN.auto.plant.selectedPosition
    G.AUTO_PLANT_SELECTED_POSITIONS = _normalizeSet(selected)
    _G.AUTO_PLANT_SELECTED_POSITIONS = G.AUTO_PLANT_SELECTED_POSITIONS
    _clearCircleCache(id)
    _notifyPositionsChanged()
    return true
end

M.deletePosition = M.DeletePosition

function M.PrintDiagnostics()
    local st = getPlantState()
    local plot = getPlayerPlot()
    local blocked, blockReason = _isGameplayBlocked()
    local surfaces = plot and collectPlotSurfaces(plot) or {}
    local anchors = plot and _listPlantAreaAnchors(plot) or {}
    local lines = {
        "=== GAG2 Auto Plant (light) ===",
        "enabled: " .. tostring(st.enabled),
        "mode: " .. tostring(st.mode),
        "delay: " .. tostring(st.delay),
        "blocked: " .. tostring(blocked) .. (blockReason and (" (" .. blockReason .. ")") or ""),
        "plot: " .. tostring(plot and plot.Name or "NIL"),
        "plotId: " .. tostring(LP:GetAttribute("PlotId")),
        "surfaces: " .. tostring(#surfaces),
        "garden zones: " .. tostring(#anchors),
    }
    if st.mode == "center" and #anchors > 0 then
        lines[#lines + 1] = "zone center[1]: " .. tostring(anchors[1].pos)
        lines[#lines + 1] = "zone root[1]: " .. tostring(anchors[1].root and anchors[1].root.Name or "?")
        lines[#lines + 1] = "center slot: " .. tostring(centerSlotCursor)
            .. " anchor: " .. tostring(centerAnchorCursor)
    end
    local planted, remaining = _syncSessionPlantedFromInventory(st)
    lines[#lines + 1] = "seed tools: " .. tostring(_countSeedTools(st.seeds))
    lines[#lines + 1] = "seed units live: " .. tostring(remaining)
        .. " (start " .. tostring(sessionStartTotal) .. ")"
    lines[#lines + 1] = "slot cursor: " .. tostring(manualSlotCursor) .. "/" .. tostring(POSITION_MAX_SCAN)
        .. " (batch " .. tostring(POSITION_CIRCLE_BATCH) .. ")"
    lines[#lines + 1] = "session planted (inv delta): " .. tostring(planted)
    lines[#lines + 1] = "limit: " .. tostring(sessionUserLimit)
    lines[#lines + 1] = "last fail: " .. tostring(lastPlantFailReason ~= "" and lastPlantFailReason or "(none)")
    lines[#lines + 1] = "running: " .. tostring(running)
    lines[#lines + 1] = "loopId: " .. tostring(loopId)
    local msg = table.concat(lines, "\n")
    return msg
end

M.printDiagnostics = M.PrintDiagnostics

