    _G.AUTO_PLANT_DEBUG = true
    return true
end
_G.__GAG2_PLANT_DEBUG_ON = G.__GAG2_PLANT_DEBUG_ON

function M.TryDebugPlant()
    G.AUTO_PLANT_DEBUG = true
    _G.AUTO_PLANT_DEBUG = true
    local st = getPlantState()
    local plot = getPlayerPlot()
    if not plot then
        return M.PrintDiagnostics()
    end
    local tools = findAllSeedTools(st.seeds)
    if #tools == 0 then
        return M.PrintDiagnostics()
    end
    local center = _resolvePlantPos(plot, _getPlotAreaCenter(plot))
    if not center then
        return M.PrintDiagnostics()
    end
    tryPlantAt(center, st, { minDist = RANDOM_MIN_PLANT_DIST })
    return M.PrintDiagnostics()
end

M.tryDebugPlant = M.TryDebugPlant
G.__GAG2_PLANT_TRY = M.TryDebugPlant
_G.__GAG2_PLANT_TRY = M.TryDebugPlant

_bindSaveListener()

return M
 end,                      required = false },
    { key = "AutoTrowel",              name = "Auto Trowel",             factory = function() -- AutoTrowel.lua — Grow A Garden 2
-- Move plant: Networking.Trowel.MovePlant:Fire(plantName, position, rotationDeg)

local Players           = game:GetService("Players")
local ReplicatedStorage = game:GetService("ReplicatedStorage")
local UserInputService  = game:GetService("UserInputService")

local LP = Players.LocalPlayer
local G  = (getgenv and getgenv()) or _G
local M  = {}

local Networking = require(ReplicatedStorage.SharedModules.Networking)
local MovePlant  = Networking.Trowel and Networking.Trowel.MovePlant

local Gardens = workspace:WaitForChild("Gardens")

local MOVE_COOLDOWN     = 0.35
local PLOT_CACHE_SEC    = 2
local POSITION_RADIUS   = 3

local running           = false
local loopId            = 0
local lastMoveAt        = 0
local cachedPlot        = nil
local cachedPlotAt      = 0
local saveInputConn     = nil
local saveModeActive    = false
local saveEnableAt      = 0
local lastClickAt       = 0
local sessionMovedCount     = 0
local lastSessionMovedCount = 0
local stallCount            = 0
local lastFinishReason      = nil

local EQUIP_WAIT        = 0.6
local MOVE_VERIFY_WAIT  = 0.45
local STALL_LIMIT       = 12

local function _dbg()
    return G.AUTO_TROWEL_DEBUG == true or _G.AUTO_TROWEL_DEBUG == true
end

local function _log(...)
    if not _dbg() then return end
    print("[GAG2-ATrw]", ...)
end

local function _normalizePositionId(v)
    if v == nil then return nil end
    if type(v) == "table" then v = v.id or v.key end
    v = tostring(v)
    if v == "" or v:sub(1, 6) == "table:" then return nil end
    return v
end

local function _writeMain(patch)
    local MAIN = rawget(_G, "MAIN") or G.MAIN
    if type(MAIN) ~= "table" then return end
    MAIN.auto = MAIN.auto or {}
    MAIN.auto.trowel = MAIN.auto.trowel or {}
    for k, v in pairs(patch) do
        if k ~= "enabled" then
            MAIN.auto.trowel[k] = v
        end
    end
    MAIN.auto.trowel.enabled = false
    G.MAIN = MAIN
    _G.MAIN = MAIN
end

local function _notifyPositionsChanged()
    if type(G.__GAG2_ON_TROWEL_POSITIONS_CHANGED) == "function" then
        pcall(G.__GAG2_ON_TROWEL_POSITIONS_CHANGED)
    end
end

local function _notifyStatsChanged()
    if type(G.__GAG2_ON_TROWEL_STATS_CHANGED) == "function" then
        pcall(G.__GAG2_ON_TROWEL_STATS_CHANGED)
    end
end

local function _finishRun(reason)
    lastFinishReason = reason
    lastSessionMovedCount = sessionMovedCount
    sessionMovedCount = 0
    stallCount = 0
    running = false
    G.AUTO_TROWEL_ENABLED = false
    _G.AUTO_TROWEL_ENABLED = false
    _writeMain({ enabled = false })
    _disableSaveMode()

    local api = G.__GAG2_TROWEL_ENABLE_API or rawget(_G, "__GAG2_TROWEL_ENABLE_API")
    if type(api) == "table" and type(api.setOff) == "function" then
        pcall(api.setOff, true)
    elseif type(api) == "table" and type(api.set) == "function" then
        pcall(api.set, false, true)
    end

    if type(G.__GAG2_ON_TROWEL_AUTO_FINISHED) == "function" then
        pcall(G.__GAG2_ON_TROWEL_AUTO_FINISHED, reason)
    end

    _notifyStatsChanged()
end

----------------------------------------------------------------
-- Plant type key (same idea as Auto Shovel)
----------------------------------------------------------------
local function _mutationNamesFallback()
    local PLV = G.PlantListView or rawget(_G, "PlantListView")
    if type(PLV) == "table" and type(PLV.listMutationNames) == "function" then
        local ok, list = pcall(PLV.listMutationNames, PLV)
        if ok and type(list) == "table" and #list > 0 then return list end
    end
    return { "Gold", "Rainbow" }
end

function M.GetPlantDisplayName(plant)
    if not plant then return "Unknown" end
    local name = plant:GetAttribute("SeedName")
        or plant:GetAttribute("ConfigPathName")
        or plant:GetAttribute("CorePartName")
        or plant:GetAttribute("FruitType")
        or plant:GetAttribute("ItemName")
        or plant.Name
    name = tostring(name or ""):gsub("^%s+", ""):gsub("%s+$", "")
    if name == "" then name = plant.Name or "Unknown" end
    return name
end

function M.GetPlantMutation(plant)
    if not plant then return nil end
    local mut = plant:GetAttribute("Mutation")
    if type(mut) == "string" then
        mut = mut:gsub("^%s+", ""):gsub("%s+$", "")
        if mut ~= "" and mut:lower() ~= "none" and mut:lower() ~= "normal" then
            return mut
        end
    end
    for _, name in ipairs(_mutationNamesFallback()) do
        if plant:GetAttribute(name) == true then
            return name
        end
    end
    return nil
end

function M.GetPlantTypeKey(plant)
    local name = M.GetPlantDisplayName(plant)
    local mut = M.GetPlantMutation(plant)
    if mut then
        return mut .. " " .. name
    end
    return name
end

local function _plantMatchesTypeKey(plant, typeKey)
    if not plant or not typeKey or typeKey == "" then return false end
    if M.GetPlantTypeKey(plant) == typeKey then return true end
    if tostring(plant.Name) == typeKey then return true end
    return false
end

local function _normalizePlantKey(v)
    if v == nil then return nil end
    if type(v) == "table" then
        v = v.key or v.name or v.id
    end
    v = tostring(v or "")
    if v == "" or v == "_none" or v:sub(1, 6) == "table:" then return nil end
    return v
end

local function _selectedMapFromAny(src)
    local out = {}
    if type(src) ~= "table" then return out end
    if src[1] ~= nil then
        for _, v in ipairs(src) do
            local key = _normalizePlantKey(v)
            if key then out[key] = true end
        end
        return out
    end
    for k, v in pairs(src) do
        if v == true then
            local key = _normalizePlantKey(k)
            if key then out[key] = true end
        else
            local key = _normalizePlantKey(v)
            if key then out[key] = true end
        end
    end
    return out
end

local function _mapHasSelection(map)
    if type(map) ~= "table" then return false end
    for k, v in pairs(map) do
        if v == true and k ~= "_none" then return true end
    end
    return false
end

local function _mapToArray(map)
    local out = {}
    if type(map) ~= "table" then return out end
    for k, v in pairs(map) do
        if v == true and k ~= "_none" then
            out[#out + 1] = tostring(k)
        end
    end
    table.sort(out)
    return out
end

local function _plantMatchesSelected(plant, plantsSelected)
    if not plant or not _mapHasSelection(plantsSelected) then return false end
    for typeKey in pairs(plantsSelected) do
        if typeKey ~= "_none" and plantsSelected[typeKey] == true then
            if _plantMatchesTypeKey(plant, typeKey) then
                return true
            end
        end
    end
    return false
end

local function getTrowelState()
    local MAIN = rawget(_G, "MAIN") or G.MAIN
    local st = MAIN and MAIN.auto and MAIN.auto.trowel
    st = type(st) == "table" and st or {}

    local delay = tonumber(st.delay)
    if delay == nil then
        delay = tonumber(G.AUTO_TROWEL_DELAY or rawget(_G, "AUTO_TROWEL_DELAY")) or 1
    end
    if delay < 0 then delay = 0 end

    local positions = type(st.positions) == "table" and st.positions or {}
    local selectedPosition = _normalizePositionId(st.selectedPosition)
    if selectedPosition == nil then
        selectedPosition = _normalizePositionId(G.AUTO_TROWEL_SELECTED_POSITION)
    end

    local plantsSelected = _selectedMapFromAny(st.plants)
    if not _mapHasSelection(plantsSelected) then
        plantsSelected = _selectedMapFromAny(
            G.AUTO_TROWEL_PLANTS_SELECTED or rawget(_G, "AUTO_TROWEL_PLANTS_SELECTED")
        )
    end
    -- legacy single selectedPlant
    if not _mapHasSelection(plantsSelected) then
        local selectedPlant = st.selectedPlant
        if selectedPlant == nil or selectedPlant == "" then
            selectedPlant = G.AUTO_TROWEL_SELECTED_PLANT or rawget(_G, "AUTO_TROWEL_SELECTED_PLANT")
        end
        local key = _normalizePlantKey(selectedPlant)
        if key then plantsSelected[key] = true end
    end

    local plants = _mapToArray(plantsSelected)
    local selectedPlant = plants[1]

    local moveTotal = tonumber(st.moveTotal)
    if moveTotal == nil then
        moveTotal = tonumber(G.AUTO_TROWEL_MOVE_TOTAL or rawget(_G, "AUTO_TROWEL_MOVE_TOTAL")) or 0
    end
    if moveTotal < 0 then moveTotal = 0 end
    moveTotal = math.floor(moveTotal)

    local rotation = tonumber(st.rotation)
    if rotation == nil then
        rotation = tonumber(G.AUTO_TROWEL_ROTATION or rawget(_G, "AUTO_TROWEL_ROTATION")) or 0
    end
    rotation = rotation % 360

    local enabled = (G.AUTO_TROWEL_ENABLED == true)
        or (rawget(_G, "AUTO_TROWEL_ENABLED") == true)

    local savePosition = (G.AUTO_TROWEL_SAVE_POSITION == true)
        or (rawget(_G, "AUTO_TROWEL_SAVE_POSITION") == true)
        or (st.savePosition == true)

    return {
        enabled          = enabled,
        plants           = plants,
        plantsSelected   = plantsSelected,
        selectedPlant    = selectedPlant,
        positions        = positions,
        selectedPosition = selectedPosition,
        savePosition     = savePosition,
        delay            = delay,
        rotation         = rotation,
        moveTotal        = moveTotal,
    }
end

local function _plotOwnedByLocal(plot)
    if not plot then return false end
    local uid, name = LP.UserId, LP.Name
    local function match(v)
        if v == nil then return false end
        return v == uid or v == name or tostring(v) == tostring(uid) or tostring(v) == name
    end
    if match(plot:GetAttribute("OwnerId")) then return true end
    if match(plot:GetAttribute("Owner")) then return true end
    if match(plot:GetAttribute("OwnerUserId")) then return true end
    if match(plot:GetAttribute("UserId")) then return true end
    return false
end

local function getPlayerPlot()
    local now = os.clock()
    if cachedPlot and cachedPlot.Parent and (now - cachedPlotAt) <= PLOT_CACHE_SEC then
        return cachedPlot
    end
    if not Gardens or not Gardens.Parent then
        cachedPlot = nil
        cachedPlotAt = now
        return nil
    end
    local plotId = LP:GetAttribute("PlotId")
    if plotId ~= nil then
        local plot = Gardens:FindFirstChild("Plot" .. tostring(plotId))
        if plot then
            cachedPlot = plot
            cachedPlotAt = now
            return plot
        end
    end
    for _, plot in ipairs(Gardens:GetChildren()) do
        if _plotOwnedByLocal(plot) then
            cachedPlot = plot
            cachedPlotAt = now
            return plot
        end
    end
    cachedPlot = nil
    cachedPlotAt = now
    return nil
end

local function getPlantsFolder(plot)
    plot = plot or getPlayerPlot()
    return plot and plot:FindFirstChild("Plants") or nil
end

local function vecFromSaved(entry)
    if type(entry) ~= "table" then return nil end
    local x, y, z = tonumber(entry.x), tonumber(entry.y), tonumber(entry.z)
    if x and y and z then return Vector3.new(x, y, z) end
    return nil
end

local function resolveTargetPosition(st)
    st = st or getTrowelState()
    local positions = st.positions
    if type(positions) ~= "table" or #positions == 0 then return nil end
    if st.selectedPosition then
        for _, entry in ipairs(positions) do
            if type(entry) == "table" and tostring(entry.id) == tostring(st.selectedPosition) then
                return vecFromSaved(entry)
            end
        end
    end
    return vecFromSaved(positions[1])
end

local function getPlantPivot(plant)
    if not plant then return nil end
    local ok, pivot = pcall(function() return plant:GetPivot() end)
    if ok and typeof(pivot) == "CFrame" then
        return pivot.Position
    end
    local pp = plant.PrimaryPart or plant:FindFirstChildWhichIsA("BasePart", true)
    return pp and pp.Position or nil
end

local function horizontalDistance(a, b)
    local dx = a.X - b.X
    local dz = a.Z - b.Z
    return math.sqrt(dx * dx + dz * dz)
end

function M.BuildGardenPlantItems()
    local AS = G.AutoShovel or G.AutoShovelModule
    if type(AS) == "table" and type(AS.BuildGardenPlantItems) == "function" then
        local ok, items = pcall(AS.BuildGardenPlantItems, AS)
        if ok and type(items) == "table" then return items end
    end

    local items = {}
    local folder = getPlantsFolder()
    if not folder then
        return { { key = "_none", name = "(No plants in garden)" } }
    end

    local groups = {}
    for _, plant in ipairs(folder:GetChildren()) do
        if plant:IsA("Model") then
            local typeKey = M.GetPlantTypeKey(plant)
            local g = groups[typeKey]
            if not g then
                g = { key = typeKey, name = typeKey, count = 0 }
                groups[typeKey] = g
            end
            g.count = g.count + 1
        end
    end

    for _, g in pairs(groups) do
        items[#items + 1] = {
            key = g.key,
            name = string.format("%s x %d", g.name, g.count),
            count = g.count,
        }
    end

    table.sort(items, function(a, b)
        return tostring(a.name) < tostring(b.name)
    end)

    if #items == 0 then
        items[1] = { key = "_none", name = "(No plants in garden)" }
    end
    return items
end

M.buildGardenPlantItems = M.BuildGardenPlantItems

function M.CountOutsideRadius(a, b, c, d)
    local typeKeyOrMap, targetPos, radius = a, b, c
    -- Support salah panggil method-style: (self, key, pos, r)
    if type(a) == "table" and (a.CountOutsideRadius or a.BuildGardenPlantItems) then
        typeKeyOrMap, targetPos, radius = b, c, d
    end
    radius = tonumber(radius) or POSITION_RADIUS
    local folder = getPlantsFolder()
    if not folder or not typeKeyOrMap or not targetPos then return 0 end
    if typeof(targetPos) ~= "Vector3" then return 0 end

    local plantsSelected
    if type(typeKeyOrMap) == "table" then
        plantsSelected = _selectedMapFromAny(typeKeyOrMap)
    else
        local key = _normalizePlantKey(typeKeyOrMap)
        plantsSelected = key and { [key] = true } or {}
    end
    if not _mapHasSelection(plantsSelected) then return 0 end

    local n = 0
    for _, plant in ipairs(folder:GetChildren()) do
        if plant:IsA("Model") and _plantMatchesSelected(plant, plantsSelected) then
            local pos = getPlantPivot(plant)
            if pos and horizontalDistance(pos, targetPos) > radius then
                n += 1
            end
        end
    end
    return n
end

function M.GetSessionMovedCount()
    if running then return sessionMovedCount end
    return lastSessionMovedCount
end

function M.IsRunning()
    return running
end

local function scanMoveCandidates(st, targetPos)
    local folder = getPlantsFolder()
    local plantsSelected = st and st.plantsSelected
    if not folder or not targetPos or not _mapHasSelection(plantsSelected) then return {} end

    local out = {}
    for _, plant in ipairs(folder:GetChildren()) do
        if plant:IsA("Model") and _plantMatchesSelected(plant, plantsSelected) then
            local pos = getPlantPivot(plant)
            if pos and horizontalDistance(pos, targetPos) > POSITION_RADIUS then
                out[#out + 1] = {
                    plant = plant,
                    fireName = tostring(plant.Name),
                    dist = horizontalDistance(pos, targetPos),
                }
            end
        end
    end

    table.sort(out, function(a, b)
        return a.dist > b.dist
    end)
    return out
end

local function _isTrowelTool(tool)
    if not tool or not tool:IsA("Tool") then return false end
    if tool:GetAttribute("Trowel") then return true end
    if tool:GetAttribute("Shovel") then return false end
    return tool.Name:lower():find("trowel", 1, true) ~= nil
end

local function _getEquippedTrowel()
    local char = LP and LP.Character
    if not char then return nil end
    for _, ch in ipairs(char:GetChildren()) do
        if ch:IsA("Tool") and _isTrowelTool(ch) then
            return ch
        end
    end
    return nil
end

local function _findTrowelTool()
    local equipped = _getEquippedTrowel()
    if equipped then return equipped end

    local bp = LP and LP:FindFirstChild("Backpack")
    if not bp then return nil end
    for _, tool in ipairs(bp:GetChildren()) do
        if _isTrowelTool(tool) then
            return tool
        end
    end
    return nil
end

local function _equipTrowel()
    if _getEquippedTrowel() then return true end

    local tool = _findTrowelTool()
    if not tool then return false end

    local char = LP and LP.Character
    local hum = char and char:FindFirstChildOfClass("Humanoid")
    if not hum then return false end

    pcall(function() hum:EquipTool(tool) end)

    local deadline = os.clock() + EQUIP_WAIT
    while os.clock() < deadline do
        if _getEquippedTrowel() then return true end
        task.wait(0.03)
    end
    return _getEquippedTrowel() ~= nil
end

local function _plantNearTarget(plant, targetPos)
    local pos = getPlantPivot(plant)
    return pos and horizontalDistance(pos, targetPos) <= POSITION_RADIUS
end

local function _moveSucceeded(plant, targetPos, beforePos)
    if not plant or not plant.Parent then return true end
    if _plantNearTarget(plant, targetPos) then return true end
    if not beforePos then return false end
    local afterPos = getPlantPivot(plant)
    if not afterPos then return false end
    return horizontalDistance(afterPos, targetPos) < horizontalDistance(beforePos, targetPos) - 0.5
end

local function _getStandingPlotPosition(plot)
    local char = LP.Character
    local hrp = char and char:FindFirstChild("HumanoidRootPart")
    if not hrp or not plot then return nil end
    if not plot:IsDescendantOf(workspace) then return nil end
    local pos = hrp.Position
    local ref = plot:FindFirstChild("PlotSizeReference")
    if ref and ref:IsA("BasePart") then
        local localPos = ref.CFrame:PointToObjectSpace(pos)
        local half = ref.Size / 2
        if math.abs(localPos.X) <= half.X and math.abs(localPos.Z) <= half.Z then
            return Vector3.new(pos.X, hrp.Position.Y - 2.5, pos.Z)
        end
    end
    return Vector3.new(pos.X, hrp.Position.Y - 2.5, pos.Z)
end

local function _disableSaveMode()
    saveModeActive = false
    G.AUTO_TROWEL_SAVE_POSITION = false
    _G.AUTO_TROWEL_SAVE_POSITION = false
    _writeMain({ savePosition = false })
    saveEnableAt = 0
    if type(G.__GAG2_ON_TROWEL_SAVE_MODE_CHANGED) == "function" then
        pcall(G.__GAG2_ON_TROWEL_SAVE_MODE_CHANGED, false)
    end
    local api = G.__GAG2_TROWEL_SAVE_TOGGLE_API
    if type(api) == "table" and type(api.setOff) == "function" then
        pcall(api.setOff, true)
    end
end

local function _commitSavePosition(pos)
    if not pos then return false end
    local MAIN = rawget(_G, "MAIN") or G.MAIN
    if type(MAIN) ~= "table" then return false end

    MAIN.auto = MAIN.auto or {}
    MAIN.auto.trowel = MAIN.auto.trowel or {}
    local positions = type(MAIN.auto.trowel.positions) == "table" and MAIN.auto.trowel.positions or {}

    local id = ("tpos_%d"):format(math.floor(os.clock() * 1000))
    positions[#positions + 1] = {
        id = id,
        x = pos.X,
        y = pos.Y,
        z = pos.Z,
    }
    MAIN.auto.trowel.positions = positions
    MAIN.auto.trowel.selectedPosition = id
    G.MAIN = MAIN
    _G.MAIN = MAIN

    G.AUTO_TROWEL_SELECTED_POSITION = id
    _G.AUTO_TROWEL_SELECTED_POSITION = id

    _notifyPositionsChanged()
    print(("[GAG2] Trowel position saved (#%d)"):format(#positions))
    _disableSaveMode()
    return true
end

local function trySavePositionFromStanding()
    if not saveModeActive and not getTrowelState().savePosition then return false end
    if os.clock() < saveEnableAt then return false end
    if os.clock() - lastClickAt < 0.15 then return false end
    lastClickAt = os.clock()

    local plot = getPlayerPlot()
    if not plot then
        warn("[GAG2] Save trowel failed: plot not found")
        return false
    end
    local pos = _getStandingPlotPosition(plot)
    if not pos then
        warn("[GAG2] Save trowel failed: stand on plot tile first")
        return false
    end
    return _commitSavePosition(pos)
end

local function _bindSaveListener()
    if saveInputConn then return end
    saveInputConn = UserInputService.InputEnded:Connect(function(input)
        if not saveModeActive then return end
        if input.UserInputType ~= Enum.UserInputType.MouseButton1
            and input.UserInputType ~= Enum.UserInputType.Touch then
            return
        end
        trySavePositionFromStanding()
    end)
end

local function tryMoveOnce(st)
    st = st or getTrowelState()
    if not MovePlant or not MovePlant.Fire then
        warn("[GAG2-ATrw] Networking.Trowel.MovePlant not found")
        return false, "no_remote"
    end
    if not _mapHasSelection(st.plantsSelected) then return false, "no_plant" end

    local targetPos = resolveTargetPosition(st)
    if not targetPos then return false, "no_position" end

    if st.moveTotal > 0 and sessionMovedCount >= st.moveTotal then
        _finishRun("total_reached")
        return false, "total_reached"
    end

    local candidates = scanMoveCandidates(st, targetPos)
    if #candidates == 0 then
        _finishRun("all_in_range")
        return false, "all_in_range"
    end

    if os.clock() - lastMoveAt < MOVE_COOLDOWN then return false, "cooldown" end

    if not _equipTrowel() then
        stallCount += 1
        if stallCount >= STALL_LIMIT then
            warn("[GAG2-ATrw] Auto Trowel stopped: equip Trowel in backpack first")
            _finishRun("no_trowel")
        end
        return false, "no_trowel"
    end

    local pick = candidates[1]
    local plant = pick.plant
    local beforePos = getPlantPivot(plant)
    lastMoveAt = os.clock()

    local ok, err = pcall(function()
        MovePlant:Fire(pick.fireName, targetPos, st.rotation or 0)
    end)
    if not ok then
        warn("[GAG2-ATrw] MovePlant error:", tostring(err))
        stallCount += 1
        if stallCount >= STALL_LIMIT then
            _finishRun("fire_error")
        end
        return false, "fire_error"
    end

    task.wait(MOVE_VERIFY_WAIT)

    if not _moveSucceeded(plant, targetPos, beforePos) then
        stallCount += 1
        _log("move_not_verified", pick.fireName, stallCount)
        if stallCount >= STALL_LIMIT then
            warn("[GAG2-ATrw] Auto Trowel stopped: plant did not move (equip Trowel?)")
            _finishRun("stalled")
        end
        return false, "move_failed"
    end

    stallCount = 0
    sessionMovedCount += 1
    _notifyStatsChanged()
    _log("moved", pick.fireName, targetPos, st.rotation, sessionMovedCount)

    if st.moveTotal > 0 and sessionMovedCount >= st.moveTotal then
        _finishRun("total_reached")
    end

    return true
end

local function mainLoop(myId)
    while running and loopId == myId do
        local st = getTrowelState()
        if st.enabled then
            pcall(tryMoveOnce, st)
        end
        task.wait(st.delay)
    end
end

function M.SetEnabled(on)
    on = (on == true)
    G.AUTO_TROWEL_ENABLED = on
    _G.AUTO_TROWEL_ENABLED = on
    _writeMain({ enabled = on })

    if on then
        sessionMovedCount = 0
        lastSessionMovedCount = 0
        stallCount = 0
        lastFinishReason = nil
        _notifyStatsChanged()
        if not running then
            running = true
            loopId += 1
            local myId = loopId
            task.spawn(function() mainLoop(myId) end)
        end
    else
        running = false
        sessionMovedCount = 0
        stallCount = 0
        _notifyStatsChanged()
        _disableSaveMode()
    end
end

function M.GetLastFinishReason()
    return lastFinishReason
end

function M.HasEquippedTrowel()
    return _getEquippedTrowel() ~= nil
end

function M.HasTrowelTool()
    return _findTrowelTool() ~= nil
end

M.hasTrowelTool = M.HasTrowelTool

function M.SetSelectedPlants(plantsOrMap, maybeMap)
    -- Support method-style: SetSelectedPlants(self, map)
    if type(plantsOrMap) == "table" and (plantsOrMap.SetSelectedPlants or plantsOrMap.BuildGardenPlantItems) then
        plantsOrMap = maybeMap
    end
    local map = _selectedMapFromAny(plantsOrMap)
    map._none = nil
    local arr = _mapToArray(map)
    G.AUTO_TROWEL_PLANTS_SELECTED = map
    _G.AUTO_TROWEL_PLANTS_SELECTED = map
    G.AUTO_TROWEL_SELECTED_PLANT = arr[1]
    _G.AUTO_TROWEL_SELECTED_PLANT = arr[1]
    _writeMain({ plants = arr, selectedPlant = arr[1] })
end

function M.SetSelectedPlant(typeKey, maybeKey)
    -- Support salah panggil method-style: SetSelectedPlant(self, key)
    -- Juga terima multi map/array → SetSelectedPlants
    if type(typeKey) == "table" and (typeKey.SetSelectedPlant or typeKey.BuildGardenPlantItems) then
        typeKey = maybeKey
    end
    if type(typeKey) == "table" then
        -- map/array of plants
        if typeKey.key or typeKey.name or typeKey.id then
            typeKey = typeKey.key or typeKey.name or typeKey.id
        else
            return M.SetSelectedPlants(typeKey)
        end
    end
    if typeKey == nil or typeKey == "" or typeKey == "_none" then
        return M.SetSelectedPlants({})
    end
    typeKey = tostring(typeKey)
    if typeKey:sub(1, 6) == "table:" then
        return M.SetSelectedPlants({})
    end
    return M.SetSelectedPlants({ [typeKey] = true })
end

function M.SetSelectedPosition(id, maybeId)
    -- Support salah panggil method-style: SetSelectedPosition(self, id)
    if type(id) == "table" and (id.SetSelectedPosition or id.BuildGardenPlantItems) then
        id = maybeId
    elseif type(id) == "table" then
        id = id.id or id.key
    end
    id = _normalizePositionId(id)
    G.AUTO_TROWEL_SELECTED_POSITION = id
    _G.AUTO_TROWEL_SELECTED_POSITION = id
    _writeMain({ selectedPosition = id })
end

function M.SetMoveTotal(n, maybeN)
    -- Support salah panggil method-style: SetMoveTotal(self, n)
    if type(n) == "table" and (n.SetMoveTotal or n.BuildGardenPlantItems) then
        n = maybeN
    end
    n = math.floor(tonumber(n) or 0)
    if n < 0 then n = 0 end
    G.AUTO_TROWEL_MOVE_TOTAL = n
    _G.AUTO_TROWEL_MOVE_TOTAL = n
    _writeMain({ moveTotal = n })
end

function M.SetSavePosition(on)
    on = (on == true)
    if not on then
        saveModeActive = false
        _disableSaveMode()
        return
    end
    saveModeActive = true
    saveEnableAt = os.clock() + 0.2
    G.AUTO_TROWEL_SAVE_POSITION = true
    _G.AUTO_TROWEL_SAVE_POSITION = true
    _writeMain({ savePosition = true })
    _bindSaveListener()
end

function M.SaveStandingPosition()
    saveModeActive = true
    saveEnableAt = 0
    return trySavePositionFromStanding()
end

function M.SyncFromState()
    local st = getTrowelState()
    M.SetMoveTotal(st.moveTotal)
    M.SetEnabled(st.enabled)
end

function M.Start() return M.SetEnabled(true) end
function M.Stop() return M.SetEnabled(false) end
M.setEnabled = M.SetEnabled
M.start = M.Start
M.stop = M.Stop
M.syncFromState = M.SyncFromState

function M.GetState()
    return getTrowelState()
end

M.getState = M.GetState
M.getPlayerPlot = getPlayerPlot
M.GetPlayerPlot = getPlayerPlot

G.AutoTrowel = M
G.AutoTrowelModule = M
_G.AutoTrowel = M
_G.AutoTrowelModule = M

return M
 end,                     required = false },
    { key = "SectionAutoTrowel",       name = "Section Auto Trowel",     factory = function() -- section_auto_trowel.lua — UI section Auto Trowel (tab Auto)

local G = (getgenv and getgenv()) or _G
local M = {}

function M.Register(ctx)
    if type(ctx) ~= "table" or type(ctx.ui) ~= "table" then return end

    local ui = ctx.ui
    local getAuto       = ctx.getAuto
    local patchAuto     = ctx.patchAuto
    local patchAutoOnly = ctx.patchAutoOnly
    local registerFlush = ctx.registerFlush
    local cleanSelectedMap = ctx.cleanSelectedMap
    local arrayToMap    = ctx.arrayToMap
    local mapToArray    = ctx.mapToArray

    local function _arrayToMapLocal(arr)
        if type(arrayToMap) == "function" then return arrayToMap(arr) end
        local out = {}
        if type(arr) ~= "table" then return out end
        for _, v in ipairs(arr) do
            local k = tostring(v or "")
            if k ~= "" and k ~= "_none" then out[k] = true end
        end
        return out
    end

    local function _mapToArrayLocal(map)
        if type(mapToArray) == "function" then return mapToArray(map) end
        local out = {}
        if type(map) ~= "table" then return out end
        for k, v in pairs(map) do
            if v == true and k ~= "_none" then out[#out + 1] = tostring(k) end
        end
        table.sort(out)
        return out
    end

    local function _cleanSelectedMapLocal(map)
        if type(cleanSelectedMap) == "function" then return cleanSelectedMap(map) end
        local out = {}
        if type(map) ~= "table" then return out end
        for k, v in pairs(map) do
            if v == true and tostring(k) ~= "" and k ~= "_none" then
                out[tostring(k)] = true
            end
        end
        return out
    end

    -- Enable toggle: session only
    if type(G.__GAG2_TROWEL) ~= "table" then
        G.__GAG2_TROWEL = { enabled = false }
    end
    _G.__GAG2_TROWEL = G.__GAG2_TROWEL

    local function readTrowelEnabled()
        local s = G.__GAG2_TROWEL or rawget(_G, "__GAG2_TROWEL")
        return type(s) == "table" and s.enabled == true
    end

    local function writeTrowelRuntime(enabled)
        if type(G.__GAG2_TROWEL) ~= "table" then
            G.__GAG2_TROWEL = { enabled = false }
        end
        G.__GAG2_TROWEL.enabled = (enabled == true)
        _G.__GAG2_TROWEL = G.__GAG2_TROWEL
        G.AUTO_TROWEL_ENABLED = G.__GAG2_TROWEL.enabled
        _G.AUTO_TROWEL_ENABLED = G.AUTO_TROWEL_ENABLED
    end

    local TR_STATE = getAuto("trowel")
    TR_STATE.positions = type(TR_STATE.positions) == "table" and TR_STATE.positions or {}
    TR_STATE.plants = type(TR_STATE.plants) == "table" and TR_STATE.plants or {}
    TR_STATE.savePosition = false
    if TR_STATE.moveTotal == nil then TR_STATE.moveTotal = 0 end
    TR_STATE.moveTotal = math.floor(tonumber(TR_STATE.moveTotal) or 0)
    if TR_STATE.moveTotal < 0 then TR_STATE.moveTotal = 0 end

    local function normalizePositionId(v)
        if v == nil then return nil end
        if type(v) == "table" then v = v.id or v.key end
        v = tostring(v)
        if v == "" or v:sub(1, 6) == "table:" then return nil end
        return v
    end

    local function normalizeSelectedPlantKey(v)
        if v == nil then return nil end
        if type(v) == "table" then
            v = v.key or v.name or v.id
        end
        v = tostring(v or "")
        if v == "" or v == "_none" or v:sub(1, 6) == "table:" then return nil end
        return v
    end

    -- migrate legacy selectedPlant → plants
    if (#TR_STATE.plants == 0) and TR_STATE.selectedPlant then
        local legacy = normalizeSelectedPlantKey(TR_STATE.selectedPlant)
        if legacy then TR_STATE.plants = { legacy } end
    end
    local AUTO_TROWEL_PLANTS_SELECTED = _cleanSelectedMapLocal(_arrayToMapLocal(TR_STATE.plants))
    TR_STATE.plants = _mapToArrayLocal(AUTO_TROWEL_PLANTS_SELECTED)
    TR_STATE.selectedPlant = TR_STATE.plants[1]

    TR_STATE.selectedPosition = normalizePositionId(TR_STATE.selectedPosition)
    TR_STATE.enabled = false
    if patchAutoOnly then
        patchAutoOnly("trowel", { enabled = false })
    end
    writeTrowelRuntime(false)
    if patchAutoOnly then
        patchAutoOnly("trowel", {
            plants = TR_STATE.plants,
            selectedPlant = TR_STATE.selectedPlant,
        })
    end

    local function delayDisplay()
        local n = tonumber(TR_STATE.delay)
        return (n ~= nil) and n or 1
    end

    local function moveTotalDisplay()
        local n = tonumber(TR_STATE.moveTotal)
        return (n ~= nil) and math.floor(n) or 0
    end

    local function buildPositionItems()
        local items = {}
        local positions = TR_STATE.positions
        if type(positions) ~= "table" then return items end
        for i, entry in ipairs(positions) do
            if type(entry) == "table" and entry.id then
                local x = tonumber(entry.x) or 0
                local z = tonumber(entry.z) or 0
                items[#items + 1] = {
                    key = tostring(entry.id),
                    name = ("Pos %d (%.0f, %.0f)"):format(i, x, z),
                }
            end
        end
        return items
    end

    local positionDropdownApi
    local plantDropdownApi
    local saveToggleApi
    local trowelEnableApi
    local statusLabel

    local function trowelStatusText()
        local mod = G.AutoTrowel or G.AutoTrowelModule
        local moved = 0
        local isRunning = TR_STATE.enabled == true
        local finishReason = nil
        if type(mod) == "table" then
            if type(mod.IsRunning) == "function" then
                local ok, on = pcall(mod.IsRunning, mod)
                if ok then isRunning = (on == true) end
            end
            if type(mod.GetLastFinishReason) == "function" then
                local ok, r = pcall(mod.GetLastFinishReason, mod)
                if ok then finishReason = r end
            end
            if type(mod.GetSessionMovedCount) == "function" then
                local ok, n = pcall(mod.GetSessionMovedCount, mod)
                if ok and type(n) == "number" then moved = math.max(0, math.floor(n)) end
            end
        end
        local total = moveTotalDisplay()

        if not isRunning and finishReason then
            if finishReason == "all_in_range" then
                if total > 0 then
                    return ("Done — moved %d / %d (all already in range)"):format(moved, total)
                end
                return ("Done — moved %d (all already in range)"):format(moved)
            elseif finishReason == "total_reached" then
                return ("Done — moved %d / %d"):format(moved, total > 0 and total or moved)
            elseif finishReason == "no_trowel" then
                return "Stopped — equip Trowel in backpack"
            elseif finishReason == "stalled" then
                return ("Stopped — move failed (moved %d)"):format(moved)
            end
            return ("Done — moved %d"):format(moved)
        end

        local outside = 0
        -- CountOutsideRadius berat di garden besar — hanya saat running
        local hasPlants = false
        for k, v in pairs(AUTO_TROWEL_PLANTS_SELECTED) do
            if v == true and k ~= "_none" then
                hasPlants = true
                break
            end
        end
        if isRunning
            and type(mod) == "table"
            and type(mod.CountOutsideRadius) == "function"
            and hasPlants
            and TR_STATE.selectedPosition then
            local positions = TR_STATE.positions
            local target = nil
            if type(positions) == "table" then
                for _, entry in ipairs(positions) do
                    if type(entry) == "table" and tostring(entry.id) == tostring(TR_STATE.selectedPosition) then
                        local x, y, z = tonumber(entry.x), tonumber(entry.y), tonumber(entry.z)
                        if x and y and z then target = Vector3.new(x, y, z) end
                        break
                    end
                end
            end
            if target then
                local ok, n = pcall(mod.CountOutsideRadius, AUTO_TROWEL_PLANTS_SELECTED, target, 3)
                if ok and type(n) == "number" then outside = math.max(0, math.floor(n)) end
            end
        end
        local extra = ""
        if isRunning and type(mod) == "table" then
            -- Cek backpack+equipped (bukan hanya yang sedang dipegang)
            local hasTool = false
            if type(mod.HasTrowelTool) == "function" then
                local ok, has = pcall(mod.HasTrowelTool)
                hasTool = ok and has == true
            elseif type(mod.HasEquippedTrowel) == "function" then
                local ok, has = pcall(mod.HasEquippedTrowel)
                hasTool = ok and has == true
            end
            if not hasTool then
                extra = " | equip Trowel"
            end
        end
        if total > 0 then
            return ("Moved %d / %d | outside 3 studs: %d%s"):format(moved, total, outside, extra)
        end
        return ("Moved %d | outside 3 studs: %d (0 = all)%s"):format(moved, outside, extra)
    end

    local function refreshTrowelStatus()
        if statusLabel and statusLabel.Parent then
            local ok, txt = pcall(trowelStatusText)
            statusLabel.Text = ok and txt or "..."
        end
    end

    local function writeTrowelPersist()
        TR_STATE.plants = _mapToArrayLocal(AUTO_TROWEL_PLANTS_SELECTED)
        TR_STATE.selectedPlant = TR_STATE.plants[1]
        patchAutoOnly("trowel", {
            enabled = false,
            plants = TR_STATE.plants,
            selectedPlant = TR_STATE.selectedPlant,
            positions = type(TR_STATE.positions) == "table" and TR_STATE.positions or {},
            selectedPosition = TR_STATE.selectedPosition,
            savePosition = false,
            delay = TR_STATE.delay,
            rotation = tonumber(TR_STATE.rotation) or 0,
            moveTotal = moveTotalDisplay(),
        })
    end

    local function writeTrowelGlobals()
        local api = G.__GAG2_TROWEL_ENABLE_API or rawget(_G, "__GAG2_TROWEL_ENABLE_API")
        if type(api) == "table" and type(api.get) == "function" then
            writeTrowelRuntime(api.get() == true)
        else
            writeTrowelRuntime(readTrowelEnabled())
        end

        TR_STATE.plants = _mapToArrayLocal(AUTO_TROWEL_PLANTS_SELECTED)
        TR_STATE.selectedPlant = TR_STATE.plants[1]

        G.AUTO_TROWEL_DELAY = tonumber(TR_STATE.delay) or 1
        _G.AUTO_TROWEL_DELAY = G.AUTO_TROWEL_DELAY
        G.AUTO_TROWEL_PLANTS_SELECTED = AUTO_TROWEL_PLANTS_SELECTED
        _G.AUTO_TROWEL_PLANTS_SELECTED = AUTO_TROWEL_PLANTS_SELECTED
        G.AUTO_TROWEL_SELECTED_PLANT = TR_STATE.selectedPlant
        _G.AUTO_TROWEL_SELECTED_PLANT = TR_STATE.selectedPlant
        G.AUTO_TROWEL_SELECTED_POSITION = TR_STATE.selectedPosition
        _G.AUTO_TROWEL_SELECTED_POSITION = TR_STATE.selectedPosition
        G.AUTO_TROWEL_MOVE_TOTAL = moveTotalDisplay()
        _G.AUTO_TROWEL_MOVE_TOTAL = G.AUTO_TROWEL_MOVE_TOTAL
        G.AUTO_TROWEL_SAVE_POSITION = false
        _G.AUTO_TROWEL_SAVE_POSITION = false

