    end

    G.__GAG2_PUSH_TROWEL = writeTrowelGlobals
    _G.__GAG2_PUSH_TROWEL = writeTrowelGlobals

    registerFlush("trowel", function()
        writeTrowelGlobals()
    end)

    writeTrowelGlobals()

    local function syncAutoTrowelModule()
        writeTrowelGlobals()
        local mod = G.AutoTrowel or G.AutoTrowelModule
        if type(mod) ~= "table" then return end

        -- JANGAN kirim `mod` sebagai arg pertama — API ini bukan method (self).
        -- Kalau dikirim, SetSelectedPlant mendapat table → selectedPlant "table: 0x..." → no_plant forever.
        local function __call(fn, ...)
            local f = mod[fn]
            if type(f) == "function" then
                pcall(f, ...)
            end
        end

        if type(mod.SetSelectedPlants) == "function" then
            pcall(mod.SetSelectedPlants, AUTO_TROWEL_PLANTS_SELECTED)
        else
            __call("SetSelectedPlant", TR_STATE.selectedPlant)
        end
        __call("SetSelectedPosition", TR_STATE.selectedPosition)
        __call("SetMoveTotal", moveTotalDisplay())

        if G.AUTO_TROWEL_ENABLED then
            __call("Start")
        else
            __call("Stop")
        end
        refreshTrowelStatus()
    end

    G.__GAG2_SYNC_AUTO_TROWEL = syncAutoTrowelModule
    _G.__GAG2_SYNC_AUTO_TROWEL = syncAutoTrowelModule

    G.__GAG2_ON_TROWEL_POSITIONS_CHANGED = function()
        local main = G.MAIN or _G.MAIN
        if type(main) == "table" and type(main.auto) == "table" and type(main.auto.trowel) == "table" then
            TR_STATE.positions = type(main.auto.trowel.positions) == "table" and main.auto.trowel.positions or TR_STATE.positions
            TR_STATE.selectedPosition = normalizePositionId(main.auto.trowel.selectedPosition)
