    G.__GAG2_ON_TROWEL_STATS_CHANGED = refreshTrowelStatus
    _G.__GAG2_ON_TROWEL_STATS_CHANGED = refreshTrowelStatus

    local bodyTrowel = ui:CreateSection("Auto Trowel", false)

    _, statusLabel = ui:CreateRowLabel(
