        trowelStatusText(),
        nil,
        nil,
        "muted"
    )
    refreshTrowelStatus()

    _, plantDropdownApi = ui:CreateRowDropdown(bodyTrowel, {
        label       = "Select Plants",
        placeholder = "Plants in garden...",
        mode        = "multi",
        deferItemLoad = true, -- scan garden hanya saat dropdown dibuka
        getItems = function()
