            local positions = TR_STATE.positions
            if type(positions) ~= "table" then return end

            for i = #positions, 1, -1 do
                local entry = positions[i]
                if type(entry) == "table" and tostring(entry.id) == key then
                    table.remove(positions, i)
                end
            end

            TR_STATE.positions = positions
            if tostring(TR_STATE.selectedPosition) == key then
