                syncAutoTrowelModule()
                refreshTrowelStatus()
            end)
        end,
    })

    _, _, saveToggleApi = ui:CreateRowToggle(
        bodyTrowel,
        "Save Position (stand on tile -> ON)",
        false,
        function(isOn)
            if not isOn then
                TR_STATE.savePosition = false
                writeTrowelGlobals()
                local mod = G.AutoTrowel or G.AutoTrowelModule
                if type(mod) == "table" and type(mod.SetSavePosition) == "function" then
                    pcall(mod.SetSavePosition, mod, false)
                end
                return
            end

            if type(ui.CloseDropdownOverlays) == "function" then
                pcall(ui.CloseDropdownOverlays, ui)
            end

            G.__GAG2_TROWEL_SAVE_TOGGLE_API = saveToggleApi
            TR_STATE.savePosition = true
            writeTrowelGlobals()

            local mod = G.AutoTrowel or G.AutoTrowelModule
            if type(mod) == "table" and type(mod.SaveStandingPosition) == "function" then
                local ok = mod:SaveStandingPosition()
                if not ok then
                    TR_STATE.savePosition = false
                    writeTrowelGlobals()
                    if saveToggleApi and saveToggleApi.setOff then
                        saveToggleApi.setOff(true)
                    end
                end
            elseif type(mod) == "table" and type(mod.SetSavePosition) == "function" then
                pcall(mod.SetSavePosition, mod, true)
            else
                warn("[GAG2] AutoTrowel module not loaded — reload script")
                TR_STATE.savePosition = false
                if saveToggleApi and saveToggleApi.setOff then
                    saveToggleApi.setOff(true)
                end
            end
        end
    )
    G.__GAG2_TROWEL_SAVE_TOGGLE_API = saveToggleApi

    ui:CreateRowInput(
        bodyTrowel,
        "Total Plants to Move (0 = all)",
        tostring(moveTotalDisplay()),
        function(text)
            local n = tonumber(text)
            if n == nil or n < 0 then return end
            TR_STATE.moveTotal = math.floor(n)
            patchAuto("trowel", { moveTotal = TR_STATE.moveTotal }, function()
                syncAutoTrowelModule()
                refreshTrowelStatus()
