        readTrowelEnabled(),
        function(isOn)
            writeTrowelRuntime(isOn == true)
            syncAutoTrowelModule()
        end
    )

    G.__GAG2_TROWEL_ENABLE_API = trowelEnableApi
    _G.__GAG2_TROWEL_ENABLE_API = trowelEnableApi

    G.__GAG2_ON_TROWEL_AUTO_FINISHED = function(reason)
        writeTrowelRuntime(false)
        if trowelEnableApi and type(trowelEnableApi.setOff) == "function" then
            pcall(trowelEnableApi.setOff, true)
        elseif trowelEnableApi and type(trowelEnableApi.set) == "function" then
            pcall(trowelEnableApi.set, false, true)
        end
        refreshTrowelStatus()
        if reason == "no_trowel" or reason == "stalled" then
