        end
    end
    _G.__GAG2_ON_TROWEL_AUTO_FINISHED = G.__GAG2_ON_TROWEL_AUTO_FINISHED

    -- Status saja — JANGAN refreshItems / BuildGardenPlantItems tiap 2s (ganggu Auto Trowel di farm besar)
    task.spawn(function()
        while bodyTrowel and bodyTrowel.Parent do
            task.wait(1.5)
            pcall(refreshTrowelStatus)
        end
    end)

    syncAutoTrowelModule()
    G.__GAG2_AUTO_TROWEL_UI_DONE = true
    _G.__GAG2_AUTO_TROWEL_UI_DONE = true
end

G.SectionAutoTrowel = M
_G.SectionAutoTrowel = M

return M
 end,            required = false },
    { key = "AutoPlot",                name = "Auto Pot",                factory = function() -- AutoPlot.lua — Grow A Garden 2
-- Auto pot mature plants + auto pickup/place potted plants.

local Players           = game:GetService("Players")
local ReplicatedStorage = game:GetService("ReplicatedStorage")
local CollectionService = game:GetService("CollectionService")
local UserInputService  = game:GetService("UserInputService")

local LP = Players.LocalPlayer
local G  = (getgenv and getgenv()) or _G
