local Gardens = workspace:WaitForChild("Gardens")

local Networking
local PotPlantRemote
local PlacePottedPlantRemote
local PickUpPottedPlantRemote
local PottedPlantPlacedEvent
local SeedData
local PlacementGrid

pcall(function()
    Networking = require(ReplicatedStorage.SharedModules.Networking)
    PotPlantRemote = Networking.Garden and Networking.Garden.PotPlant
    PlacePottedPlantRemote = Networking.PotPlacement and Networking.PotPlacement.PlacePottedPlant
    PickUpPottedPlantRemote = Networking.PotPlacement and Networking.PotPlacement.PickUpPottedPlant
    PottedPlantPlacedEvent = Networking.PotPlacement and Networking.PotPlacement.PottedPlantPlaced
end)
pcall(function()
    SeedData = require(ReplicatedStorage.SharedModules.SeedData)
end)
pcall(function()
    PlacementGrid = require(ReplicatedStorage.ClientModules.PlacementGrid)
end)

local LOOP_MIN_SEC     = 0.1
local PLOT_CACHE_SEC          = 2
local PLACED_POTS_CACHE_SEC   = 3
local PLANTS_FOLDER_CACHE_SEC = 2
local IDLE_LOOP_SEC           = 1
local ACTION_CONFIRM_TIMEOUT  = 0.6
local PICKUP_CONFIRM_TIMEOUT  = 0.35
local PICKUP_PLOT_BFS_DEPTH   = 5
local PICKUP_TRY_PER_TICK     = 4

local running          = false
local loopId           = 0
local cachedPlot       = nil
local cachedPlotAt     = 0
local propSurfaceCache = nil
local propSurfaceCacheAt = 0
local propSurfaceCachePlot = nil
local placedPotsCache     = nil
local placedPotsCacheAt   = 0
local placedPotsCachePlot = nil
local cachedPlantsFolder  = nil
local cachedPlantsFolderAt = 0
local cachedPlantVisualizer = nil

local sessionPotCount       = 0
local sessionPlaceCount     = 0
local sessionCollectCount   = 0
local lastSessionPotCount   = 0
local lastSessionPlaceCount = 0
local lastSessionCollectCount = 0
local lastStatus           = "Idle"
local lastFinishReason     = nil

local saveInputConn   = nil
local saveModeActive  = false
local saveEnableAt    = 0
local lastClickAt     = 0

local slotCursor = 0
local pickupCursor = 0

local function _dbg()
    return G.AUTO_PLOT_DEBUG == true or _G.AUTO_PLOT_DEBUG == true
end

local function _log(...)
    if not _dbg() then return end
    print("[GAG2-APlot]", ...)
end

local function _notifyStatsChanged()
    if type(G.__GAG2_ON_PLOT_STATS_CHANGED) == "function" then
        pcall(G.__GAG2_ON_PLOT_STATS_CHANGED)
    end
end

local function _notifySlotsChanged()
    if type(G.__GAG2_ON_PLOT_SLOTS_CHANGED) == "function" then
        pcall(G.__GAG2_ON_PLOT_SLOTS_CHANGED)
    end
end

local function _writeMain(patch)
    local MAIN = rawget(_G, "MAIN") or G.MAIN
    if type(MAIN) ~= "table" then return end
    MAIN.auto = MAIN.auto or {}
    MAIN.auto.plot = MAIN.auto.plot or {}
    for k, v in pairs(patch) do
        MAIN.auto.plot[k] = v
    end
    G.MAIN = MAIN
    _G.MAIN = MAIN
end

local function _normalizeSlotId(v)
    if v == nil then return nil end
    if type(v) == "table" then v = v.id or v.key end
    v = tostring(v)
    if v == "" or v == "_none" or v:sub(1, 6) == "table:" then return nil end
    return v
end

local function _selectedMapFromArray(arr)
    local out = {}
    if type(arr) ~= "table" then return out end
    for _, v in ipairs(arr) do
        local key = tostring(v)
        if key ~= "" and key ~= "_none" then
            out[key] = true
        end
    end
    return out
end

local function _mapHasSelection(map)
    if type(map) ~= "table" then return false end
    for k, v in pairs(map) do
        if v == true and k ~= "_none" then return true end
    end
    return false
end

function M.GetPlantDisplayName(plant)
    if not plant then return "Unknown" end
    local AT = G.AutoTrowel or G.AutoTrowelModule
    if type(AT) == "table" and type(AT.GetPlantDisplayName) == "function" then
        local ok, name = pcall(AT.GetPlantDisplayName, AT, plant)
        if ok and type(name) == "string" and name ~= "" then return name end
    end
    local name = plant:GetAttribute("SeedName")
        or plant:GetAttribute("PlantName")
        or plant:GetAttribute("ConfigPathName")
        or plant.Name
    return tostring(name or "Unknown")
end

function M.GetPlantTypeKey(plant)
    local AT = G.AutoTrowel or G.AutoTrowelModule
    if type(AT) == "table" and type(AT.GetPlantTypeKey) == "function" then
        local ok, key = pcall(AT.GetPlantTypeKey, AT, plant)
        if ok and type(key) == "string" and key ~= "" then return key end
    end
    return M.GetPlantDisplayName(plant)
end

local function _plantMatchesTypeKey(plant, typeKey)
    if not plant or not typeKey or typeKey == "" then return false end
    if M.GetPlantTypeKey(plant) == typeKey then return true end
    if tostring(plant.Name) == typeKey then return true end
    return false
end

local function _plotOwnedByLocal(plot)
    if not plot then return false end
    local uid, name = LP.UserId, LP.Name
    local function match(v)
        if v == nil then return false end
        return v == uid or v == name or tostring(v) == tostring(uid) or tostring(v) == name
    end
    if match(plot:GetAttribute("OwnerId")) then return true end
    if match(plot:GetAttribute("Owner")) then return true end
    if match(plot:GetAttribute("OwnerUserId")) then return true end
    if match(plot:GetAttribute("UserId")) then return true end
    return false
end

local function getPlayerPlot()
    local now = os.clock()
    if cachedPlot and cachedPlot.Parent and (now - cachedPlotAt) <= PLOT_CACHE_SEC then
        return cachedPlot
    end
    if not Gardens or not Gardens.Parent then
        cachedPlot = nil
        cachedPlotAt = now
        return nil
    end
    local plotId = LP:GetAttribute("PlotId")
    if plotId ~= nil then
        local plot = Gardens:FindFirstChild("Plot" .. tostring(plotId))
        if plot then
            cachedPlot = plot
            cachedPlotAt = now
            return plot
        end
    end
    for _, plot in ipairs(Gardens:GetChildren()) do
        if _plotOwnedByLocal(plot) then
            cachedPlot = plot
            cachedPlotAt = now
            return plot
        end
    end
    cachedPlot = nil
    cachedPlotAt = now
    return nil
end

local function getPlantVisualizer()
    if cachedPlantVisualizer then return cachedPlantVisualizer end
    local ok, vis = pcall(function()
        local ps = LP:FindFirstChild("PlayerScripts")
        if not ps then return nil end
        local controllers = ps:FindFirstChild("Controllers")
        if not controllers then return nil end
        local mod = controllers:FindFirstChild("PlantVisualizerController")
        if not mod then return nil end
        return require(mod)
    end)
    if ok and type(vis) == "table" then
        cachedPlantVisualizer = vis
        return vis
    end
    return nil
end

local function getPlantsFolder(plot)
    local now = os.clock()
    if cachedPlantsFolder and cachedPlantsFolder.Parent
        and (now - cachedPlantsFolderAt) <= PLANTS_FOLDER_CACHE_SEC then
        return cachedPlantsFolder
    end

    plot = plot or getPlayerPlot()
    local folder = nil

    local vis = getPlantVisualizer()
    if vis and type(vis.GetPlantsFolder) == "function" then
        local ok2, f = pcall(vis.GetPlantsFolder, vis, LP.UserId)
        if ok2 and f then folder = f end
    end

    if not folder and plot then
        folder = plot:FindFirstChild("Plants")
    end

    cachedPlantsFolder = folder
    cachedPlantsFolderAt = now
    return folder
end

local function getPlotState()
    local MAIN = rawget(_G, "MAIN") or G.MAIN
    local st = MAIN and MAIN.auto and MAIN.auto.plot
    st = type(st) == "table" and st or {}

    local plantsSelected = _selectedMapFromArray(st.plants)
    if not _mapHasSelection(plantsSelected) then
        plantsSelected = G.AUTO_PLOT_PLANTS_SELECTED or rawget(_G, "AUTO_PLOT_PLANTS_SELECTED") or {}
    end

    local slotsSelected = _selectedMapFromArray(st.selectedSlots)
    if not _mapHasSelection(slotsSelected) then
        slotsSelected = G.AUTO_PLOT_SELECTED_SLOTS or rawget(_G, "AUTO_PLOT_SELECTED_SLOTS") or {}
    end

    local placedSelected = _selectedMapFromArray(st.placedPlants)
    if not _mapHasSelection(placedSelected) then
        placedSelected = G.AUTO_PLOT_PLACED_POTS_SELECTED or rawget(_G, "AUTO_PLOT_PLACED_POTS_SELECTED") or {}
    end

    local placeToolsSelected = _selectedMapFromArray(st.placeTools)
    if not _mapHasSelection(placeToolsSelected) then
        placeToolsSelected = G.AUTO_PLOT_PLACE_TOOLS_SELECTED or rawget(_G, "AUTO_PLOT_PLACE_TOOLS_SELECTED") or {}
    end

    local potDelay = tonumber(st.potDelay)
    if potDelay == nil then potDelay = tonumber(G.AUTO_PLOT_POT_DELAY) or 1.5 end
    if potDelay > 0 and potDelay < LOOP_MIN_SEC then potDelay = LOOP_MIN_SEC end

    local placeDelay = tonumber(st.placeDelay)
    if placeDelay == nil then placeDelay = tonumber(G.AUTO_PLOT_PLACE_DELAY) or 1 end
    if placeDelay > 0 and placeDelay < LOOP_MIN_SEC then placeDelay = LOOP_MIN_SEC end

    local potTotal = tonumber(st.potTotal)
    if potTotal == nil then potTotal = tonumber(G.AUTO_PLOT_POT_TOTAL) or 0 end
    if potTotal < 0 then potTotal = 0 end
    potTotal = math.floor(potTotal)

    local placeTotal = tonumber(st.placeTotal)
    if placeTotal == nil then placeTotal = tonumber(G.AUTO_PLOT_PLACE_TOTAL) or 0 end
    if placeTotal < 0 then placeTotal = 0 end
    placeTotal = math.floor(placeTotal)

    local collectDelay = tonumber(st.collectDelay)
    if collectDelay == nil then collectDelay = tonumber(G.AUTO_PLOT_COLLECT_DELAY) or 1 end
    if collectDelay > 0 and collectDelay < LOOP_MIN_SEC then collectDelay = LOOP_MIN_SEC end

    local collectTotal = tonumber(st.collectTotal)
    if collectTotal == nil then collectTotal = tonumber(G.AUTO_PLOT_COLLECT_TOTAL) or 0 end
    if collectTotal < 0 then collectTotal = 0 end
    collectTotal = math.floor(collectTotal)

    local mode = tostring(st.placeMode or G.AUTO_PLOT_PLACE_MODE or "saved"):lower()
    if mode ~= "saved" then mode = "saved" end

    local autoPot = (st.autoPot == true) or (G.AUTO_PLOT_AUTO_POT == true)
    local autoPlace = (st.autoPlace == true) or (G.AUTO_PLOT_AUTO_PLACE == true)
    local autoCollect = (st.autoCollect == true) or (G.AUTO_PLOT_AUTO_COLLECT == true)

    return {
        autoPot          = autoPot,
        autoPlace        = autoPlace,
        autoCollect      = autoCollect,
        plants           = type(st.plants) == "table" and st.plants or {},
        plantsSelected   = plantsSelected,
        placedPlants     = type(st.placedPlants) == "table" and st.placedPlants or {},
        placedSelected   = placedSelected,
        placeTools       = type(st.placeTools) == "table" and st.placeTools or {},
        placeToolsSelected = placeToolsSelected,
        slots            = type(st.slots) == "table" and st.slots or {},
        selectedSlots    = type(st.selectedSlots) == "table" and st.selectedSlots or {},
        slotsSelected    = slotsSelected,
        selectedSlot     = _normalizeSlotId(st.selectedSlot),
        potDelay         = potDelay,
        placeDelay       = placeDelay,
        collectDelay     = collectDelay,
        potTotal         = potTotal,
        placeTotal       = placeTotal,
        collectTotal     = collectTotal,
        placeMode        = mode,
        saveSlot         = (st.saveSlot == true) or (G.AUTO_PLOT_SAVE_SLOT == true),
        rotation         = tonumber(st.rotation) or 0,
    }
end

local function _isSingleHarvest(plantName)
    if not plantName or plantName == "" then return true end
    if type(SeedData) ~= "table" then return false end
    for _, entry in pairs(SeedData) do
        if type(entry) == "table" and entry.SeedName == plantName then
            return entry.IsSingleHarvest == true
        end
    end
    return false
end

local function _extractPlantId(modelName)
    local name = tostring(modelName or "")
    return name:match("^%d+_(.+)$") or name
end

local function _isPlantMature(plant, plantName)
    local age = tonumber(plant:GetAttribute("Age")) or 0
    local maxAge = tonumber(plant:GetAttribute("MaxAge")) or 0
    if maxAge <= 0 then maxAge = 100 end
    return age >= maxAge
end

local function _isPlantPotted(plant, plantId)
    if plant:GetAttribute("IsPotted") == true then return true end
    local ok, sync = pcall(function()
        local ps = LP:FindFirstChild("PlayerScripts")
        local controllers = ps and ps:FindFirstChild("Controllers")
        local mod = controllers and controllers:FindFirstChild("GardenSyncController")
        if not mod then return nil end
        local ctrl = require(mod)
        if type(ctrl.GetPlant) == "function" then
            return ctrl:GetPlant(LP.UserId, plantId)
        end
        return nil
    end)
    if ok and type(sync) == "table" and sync.IsPotted == true then
        return true
    end
    return false
end

local function _plantEligibleForPot(plant, st, forPicker)
    if not plant or not plant:IsA("Model") then return false end
    if not forPicker and not plant:HasTag("InitializationComplete") then
        -- Tag bisa telat; izinkan kalau sudah dewasa.
        local plantName = M.GetPlantDisplayName(plant)
        if not _isPlantMature(plant, plantName) then
            return false
        end
    end

    local plantName = M.GetPlantDisplayName(plant)
    if _isSingleHarvest(plantName) then return false end

    local plantId = _extractPlantId(plant.Name)
    if not forPicker then
        if _isPlantPotted(plant, plantId) then return false end
        if not _isPlantMature(plant, plantName) then return false end
    end

    if not forPicker and _mapHasSelection(st.plantsSelected) then
        local matched = false
        for typeKey in pairs(st.plantsSelected) do
            if _plantMatchesTypeKey(plant, typeKey) then
                matched = true
                break
            end
        end
        if not matched then return false end
    end

    return true, plantId, plantName
end

function M.BuildPlantPickerItems()
    local AT = G.AutoTrowel or G.AutoTrowelModule
    if type(AT) == "table" and type(AT.BuildGardenPlantItems) == "function" then
        local ok, items = pcall(AT.BuildGardenPlantItems, AT)
        if ok and type(items) == "table" and #items > 0 then
            return items
        end
    end

    local items = {}
    local folder = getPlantsFolder()
    if not folder then
        return { { key = "_none", name = "(No plants in garden)" } }
    end

    local groups = {}
    for _, plant in ipairs(folder:GetChildren()) do
        if plant:IsA("Model") then
            local ok = _plantEligibleForPot(plant, getPlotState(), true)
            if ok then
                local typeKey = M.GetPlantTypeKey(plant)
                local g = groups[typeKey]
                if not g then
                    g = { key = typeKey, name = typeKey, count = 0 }
                    groups[typeKey] = g
                end
                g.count += 1
            end
        end
    end

    for _, g in pairs(groups) do
        items[#items + 1] = {
            key = g.key,
            name = string.format("%s x %d", g.name, g.count),
            count = g.count,
        }
    end

    table.sort(items, function(a, b)
        return tostring(a.name) < tostring(b.name)
    end)

    if #items == 0 then
        items[1] = { key = "_none", name = "(No plants in garden)" }
    end
    return items
end

M.buildPlantPickerItems = M.BuildPlantPickerItems

function M.BuildEligiblePlantItems()
    local items = {}
    local folder = getPlantsFolder()
    if not folder then
        return { { key = "_none", name = "(No plants in garden)" } }
    end

    local st = getPlotState()
    local groups = {}
    for _, plant in ipairs(folder:GetChildren()) do
        if plant:IsA("Model") then
            local ok = _plantEligibleForPot(plant, st)
            if ok then
                local typeKey = M.GetPlantTypeKey(plant)
                local g = groups[typeKey]
                if not g then
                    g = { key = typeKey, name = typeKey, count = 0 }
                    groups[typeKey] = g
                end
                g.count += 1
            end
        end
    end

    for _, g in pairs(groups) do
        items[#items + 1] = {
            key = g.key,
            name = string.format("%s x %d", g.name, g.count),
            count = g.count,
        }
    end

    table.sort(items, function(a, b)
        return tostring(a.name) < tostring(b.name)
    end)

    if #items == 0 then
        items[1] = { key = "_none", name = "(No eligible plants)" }
    end
    return items
end

M.buildEligiblePlantItems = M.BuildEligiblePlantItems

local function _isUnderGardenPlantsFolder(model, plot)
    if not model or not plot then return false end
    local plantsFolder = plot:FindFirstChild("Plants")
    return plantsFolder and model:IsDescendantOf(plantsFolder) or false
end

local function _isPickupProximityPrompt(prompt)
    if not prompt or not prompt:IsA("ProximityPrompt") then return false end
    if prompt.Name == "PickUpPottedPlantPrompt" then return true end
    local action = tostring(prompt.ActionText or ""):lower()
    if action:find("pick up", 1, true) or action:find("pickup", 1, true) then
        return true
    end
    return false
end

local function _findPickupPrompt(model)
    if not model then return nil end
    local named = model:FindFirstChild("PickUpPottedPlantPrompt", true)
    if named and named:IsA("ProximityPrompt") then return named end
    for _, desc in ipairs(model:GetChildren()) do
        if desc:IsA("ProximityPrompt") and _isPickupProximityPrompt(desc) then
            return desc
        end
        if desc:IsA("Model") or desc:IsA("Folder") then
            local nested = desc:FindFirstChild("PickUpPottedPlantPrompt", true)
            if nested and nested:IsA("ProximityPrompt") then return nested end
        end
    end
    return nil
end

local function _isGardenPottedPlant(plant)
    if not plant or not plant:IsA("Model") then return false end
    if plant:GetAttribute("IsPotted") == true then return true end
    if plant:FindFirstChild("PotVisual") then return true end
    return _findPickupPrompt(plant) ~= nil
end

local function _hasPickupPrompt(model)
    return _findPickupPrompt(model) ~= nil
end

-- StartOrder 6: prompt ancestor -> if PotVisual, naik ke parent Model -> PlantId di root itu.
local function _resolvePickupPotRoot(model)
    if not model or not model:IsA("Model") then return nil end
    local root = model
    if root.Name == "PotVisual" then
        local parent = root.Parent
        if parent and parent:IsA("Model") then
            root = parent
        end
    end
    return root
end

local function _resolvePickupPotFromPrompt(prompt)
    if not _isPickupProximityPrompt(prompt) then return nil end
    local model = prompt:FindFirstAncestorOfClass("Model")
    if not model then return nil end
    return _resolvePickupPotRoot(model)
end

local function _isPickupPotOwned(root, plot)
    if not root then return false end
    if plot and root:IsDescendantOf(plot) then return true end
    local folder = getPlantsFolder()
    if folder and root:IsDescendantOf(folder) then return true end
    if folder and root.Parent == folder then return true end
    return false
end

local function _getPlacedPotPlantId(model)
    local root = _resolvePickupPotRoot(model)
    if not root then return nil end
    local plantId = root:GetAttribute("PlantId")
    if plantId == nil or plantId == "" then
        plantId = _extractPlantId(root.Name)
    end
    if plantId == nil or plantId == "" then return nil end
    return tostring(plantId)
end

local function _getPlacedPotDisplayName(model)
    local root = _resolvePickupPotRoot(model) or model
    if not root then return "Unknown" end

    local folder = getPlantsFolder()
    if folder and (root.Parent == folder or root:IsDescendantOf(folder)) then
        local name = M.GetPlantDisplayName(root)
        if type(name) == "string" and name ~= "" then
            return name .. " (Potted)"
        end
    end

    local name = root:GetAttribute("PlantName")
        or root:GetAttribute("SeedName")
        or root:GetAttribute("ConfigPathName")
    if type(name) == "string" and name ~= "" then return name end

    for _, ch in ipairs(root:GetChildren()) do
        if ch:IsA("Model") then
            local n = ch:GetAttribute("SeedName")
                or ch:GetAttribute("PlantName")
                or ch:GetAttribute("ConfigPathName")
            if type(n) == "string" and n ~= "" then return n end
        end
    end

    local potVisual = root:FindFirstChild("PotVisual", true)
    if potVisual and potVisual:IsA("Model") then
        local n = potVisual:GetAttribute("PlantName")
            or potVisual:GetAttribute("SeedName")
            or potVisual:GetAttribute("ConfigPathName")
        if type(n) == "string" and n ~= "" then return n end
    end

    return tostring(root.Name or "Unknown")
end

local function _getPlacedPotTypeKey(model)
    local root = _resolvePickupPotRoot(model) or model
    local folder = getPlantsFolder()
    if root and folder and (root.Parent == folder or root:IsDescendantOf(folder)) then
        return M.GetPlantTypeKey(root)
    end
    return _getPlacedPotDisplayName(model)
end

local function _isPlacedPotModel(model, plot)
    if not model or not model:IsA("Model") then return false end
    if not _isPickupPotOwned(_resolvePickupPotRoot(model) or model, plot) then return false end
    if model.Name == "PotVisual" or _hasPickupPrompt(model) then
        return _getPlacedPotPlantId(model) ~= nil
    end
    local root = _resolvePickupPotRoot(model)
    if root and root ~= model and _hasPickupPrompt(root) then
        return _getPlacedPotPlantId(root) ~= nil
    end
    local plantId = _extractPlantId(model.Name)
    if _isPlantPotted(model, plantId) and _hasPickupPrompt(model) then
        return plantId ~= nil and plantId ~= ""
    end
    return false
end

local function _matchesTypeKey(typeKey, selectedMap)
    if not _mapHasSelection(selectedMap) then return true end
    typeKey = tostring(typeKey or "")
    if typeKey == "" then return false end
    if selectedMap[typeKey] == true then return true end
    for key in pairs(selectedMap) do
        if tostring(key) == typeKey then return true end
    end
    return false
end

local function _placedPotMatchesSelection(model, selectedMap)
    return _matchesTypeKey(_getPlacedPotTypeKey(model), selectedMap)
end

local function _scanPotCandidate(st)
    local folder = getPlantsFolder()
    if not folder then return nil end

    local best = nil
    for _, plant in ipairs(folder:GetChildren()) do
        local ok, plantId = _plantEligibleForPot(plant, st)
        if ok then
            best = { plant = plant, plantId = plantId }
            break
        end
    end
    return best
end

local function _getBackpack()
    return LP:FindFirstChild("Backpack") or LP:FindFirstChildOfClass("Backpack")
end

local function _isPottedPlantTool(tool)
    return tool and tool:IsA("Tool") and tool:GetAttribute("PottedPlant") == true
end

local function _getPottedToolTypeKey(tool)
    if not tool then return "Unknown" end
    local name = tool:GetAttribute("PlantName")
        or tool:GetAttribute("SeedName")
        or tool:GetAttribute("ConfigPathName")
        or tool.Name
    if type(name) == "string" and name ~= "" then
        return name
    end
    return tostring(tool.Name or "Unknown")
end

local function _pottedToolMatchesSelection(tool, selectedMap)
    return _matchesTypeKey(_getPottedToolTypeKey(tool), selectedMap)
end

local function _enumeratePottedPlantTools()
    local out = {}
    local char = LP.Character
    if char then
        for _, ch in ipairs(char:GetChildren()) do
            if _isPottedPlantTool(ch) then
                out[#out + 1] = ch
            end
        end
    end
    local bp = _getBackpack()
    if bp then
        for _, tool in ipairs(bp:GetChildren()) do
            if _isPottedPlantTool(tool) then
                out[#out + 1] = tool
            end
        end
    end
    return out
end

local function _findTool(predicate)
    local char = LP.Character
    if char then
        for _, ch in ipairs(char:GetChildren()) do
            if predicate(ch) then return ch end
        end
    end
    local bp = _getBackpack()
    if bp then
        for _, tool in ipairs(bp:GetChildren()) do
            if predicate(tool) then return tool end
        end
    end
    return nil
end

local function _findPottedPlantTool(st)
    st = st or getPlotState()
    local selected = st.placeToolsSelected

    local bp = _getBackpack()
    if bp then
        for _, tool in ipairs(bp:GetChildren()) do
            if _isPottedPlantTool(tool) and _pottedToolMatchesSelection(tool, selected) then
                return tool
            end
        end
    end
    local char = LP.Character
    if char then
        for _, ch in ipairs(char:GetChildren()) do
            if _isPottedPlantTool(ch) and _pottedToolMatchesSelection(ch, selected) then
                return ch
            end
        end
    end
    return nil
end

local function _pottedToolId(tool)
    if not tool then return nil end
    local id = tool:GetAttribute("Id")
    if id ~= nil and id ~= "" then return id end
    id = tool:GetAttribute("ToolId")
    if id ~= nil and id ~= "" then return id end
    return nil
end

local function _countMatchingPottedTools(st)
    st = st or getPlotState()
    local selected = st.placeToolsSelected
    local n = 0
    for _, tool in ipairs(_enumeratePottedPlantTools()) do
        if _pottedToolMatchesSelection(tool, selected) then
            n += 1
        end
    end
    return n
end

local function _countAllPottedTools()
    return #_enumeratePottedPlantTools()
end

local function _pickupSucceeded(toolsBefore, modelRef)
    if _countAllPottedTools() > toolsBefore then return true end
    if modelRef and not modelRef.Parent then return true end
    return false
end

local function _placeSucceeded(st, toolsBefore)
    return _countMatchingPottedTools(st) < toolsBefore
end

local function _waitUntilConfirmed(timeout, checkFn, hookBuilders)
    local done = false
    local conns = {}

    local function cleanup()
        for _, conn in ipairs(conns) do
            pcall(function()
                conn:Disconnect()
            end)
        end
        table.clear(conns)
    end

    local function tryDone()
        if done then return true end
        if checkFn() then
            done = true
            cleanup()
            return true
        end
        return false
    end

    if type(hookBuilders) == "table" then
        for _, build in ipairs(hookBuilders) do
            if type(build) == "function" then
                local conn = build(function()
                    tryDone()
                end)
                if conn then
                    conns[#conns + 1] = conn
                end
            end
        end
    end

    local deadline = os.clock() + timeout
    while not done and os.clock() < deadline do
        if tryDone() then
            return true
        end
        task.wait()
    end

    cleanup()
    return checkFn()
end

local function _awaitPickupConfirmed(modelRef, toolsBefore)
    if _pickupSucceeded(toolsBefore, modelRef) then return true end

    local done = false
    local conns = {}
    local bp = _getBackpack()

    local function check()
        return _pickupSucceeded(toolsBefore, modelRef)
    end

    if bp then
        conns[#conns + 1] = bp.ChildAdded:Connect(function(ch)
            if ch:IsA("Tool") and ch:GetAttribute("PottedPlant") == true then
                done = true
            end
        end)
    end
    if modelRef then
        conns[#conns + 1] = modelRef.AncestryChanged:Connect(function()
            if not modelRef.Parent then
                done = true
            end
        end)
    end

    local deadline = os.clock() + PICKUP_CONFIRM_TIMEOUT
    while not done and os.clock() < deadline do
        if check() then
            done = true
            break
        end
        task.wait(0.05)
    end

    for _, conn in ipairs(conns) do
        pcall(function()
            conn:Disconnect()
        end)
    end
    return check()
end

local function _awaitPlaceConfirmed(st, toolsBefore)
    local hooks = {}
    local placedByEvent = false

    if PottedPlantPlacedEvent and PottedPlantPlacedEvent.OnClientEvent then
        hooks[#hooks + 1] = function(cb)
            return PottedPlantPlacedEvent.OnClientEvent:Connect(function()
                placedByEvent = true
                cb()
            end)
        end
    end

    local bp = _getBackpack()
    if bp then
        hooks[#hooks + 1] = function(cb)
            return bp.ChildRemoved:Connect(function(ch)
                if ch:IsA("Tool") and ch:GetAttribute("PottedPlant") == true then
                    cb()
                end
            end)
        end
    end

    local char = LP.Character
    if char then
        hooks[#hooks + 1] = function(cb)
            return char.ChildRemoved:Connect(function(ch)
                if ch:IsA("Tool") and ch:GetAttribute("PottedPlant") == true then
                    cb()
                end
            end)
        end
    end

    return _waitUntilConfirmed(ACTION_CONFIRM_TIMEOUT, function()
        return placedByEvent or _placeSucceeded(st, toolsBefore)
    end, hooks)
end

local function _defaultActiveStatus(st)
    st = st or getPlotState()
    if st.autoPlace then return "Waiting place..." end
    if st.autoCollect then return "Waiting pickup..." end
    if st.autoPot then return "Waiting pot..." end
    return "Running..."
end

local function _autoFlagsEnabled(st)
    st = st or getPlotState()
    if st.autoPot or st.autoPlace or st.autoCollect then return true end
    if G.AUTO_PLOT_AUTO_POT == true or G.AUTO_PLOT_AUTO_PLACE == true or G.AUTO_PLOT_AUTO_COLLECT == true then
        return true
    end
    if rawget(_G, "AUTO_PLOT_AUTO_POT") == true
        or rawget(_G, "AUTO_PLOT_AUTO_PLACE") == true
        or rawget(_G, "AUTO_PLOT_AUTO_COLLECT") == true then
        return true
    end
    return false
end

local function _isPlotActive(st)
    return running or _autoFlagsEnabled(st)
end

local function _countRemainingPlacedPots(st)
    st = st or getPlotState()
    local plot = getPlayerPlot()
    if not plot then return 0 end
    return #_buildPickupList(plot, st)
end

local function _firePlaceRemote(pos, rotationDeg, tool)
    local toolId = _pottedToolId(tool)
    if not PlacePottedPlantRemote then return false, "no_remote" end
    if type(PlacePottedPlantRemote.Fire) ~= "function" then
        return false, "no_fire"
    end
    if toolId == nil then return false, "no_id" end

    local ok, err = pcall(function()
        PlacePottedPlantRemote:Fire(pos, rotationDeg, toolId)
    end)
    return ok, err
end

local function _collectPropSurfaces(plot)
    plot = plot or getPlayerPlot()
    local now = os.clock()
    if propSurfaceCache and plot == propSurfaceCachePlot and (now - propSurfaceCacheAt) <= 5 then
        return propSurfaceCache
    end

    local areas = {}
    if plot then
        for _, desc in ipairs(plot:GetDescendants()) do
            if desc:IsA("BasePart") and CollectionService:HasTag(desc, "PropArea") then
                areas[#areas + 1] = desc
            end
        end
        if #areas == 0 then
            for _, inst in ipairs(CollectionService:GetTagged("PropArea")) do
                if inst:IsA("BasePart") and inst:IsDescendantOf(plot) then
                    areas[#areas + 1] = inst
                end
            end
        end
    end

    propSurfaceCache = areas
    propSurfaceCacheAt = now
    propSurfaceCachePlot = plot
    return areas
end

local function _resolveGroundPosition(pos, plot)
    if typeof(pos) ~= "Vector3" then return nil end
    plot = plot or getPlayerPlot()
    if not plot then return pos end

    local surfaces = _collectPropSurfaces(plot)
    if #surfaces == 0 then
        return Vector3.new(pos.X, pos.Y - 3, pos.Z)
    end

    local params = RaycastParams.new()
    params.FilterType = Enum.RaycastFilterType.Include
    params.FilterDescendantsInstances = surfaces

    local origin = Vector3.new(pos.X, 500, pos.Z)
    local hit = workspace:Raycast(origin, Vector3.new(0, -1000, 0), params)
    if hit and hit.Instance:IsDescendantOf(plot) then
        return Vector3.new(pos.X, hit.Position.Y + 0.05, pos.Z)
    end

    for _, part in ipairs(surfaces) do
        if part:IsA("BasePart") then
            local lp = part.CFrame:PointToObjectSpace(pos)
            local halfX = part.Size.X * 0.5
            local halfZ = part.Size.Z * 0.5
            if math.abs(lp.X) <= halfX and math.abs(lp.Z) <= halfZ then
                return Vector3.new(
                    pos.X,
                    part.Position.Y + part.Size.Y * 0.5 + 0.05,
                    pos.Z
                )
            end
        end
    end
    return pos
end

local function _snapPosition(pos, plot)
    if typeof(pos) ~= "Vector3" then return nil end
    local spawn = plot and plot:FindFirstChild("SpawnPoint")
    if PlacementGrid and spawn and type(PlacementGrid.SnapToGrid) == "function" then
        local ok, gridSnapped = pcall(PlacementGrid.SnapToGrid, pos, spawn, 0.5)
        if ok and typeof(gridSnapped) == "Vector3" then
            return gridSnapped
        end
    end
    local x = math.floor(pos.X / 0.5 + 0.5) * 0.5
    local z = math.floor(pos.Z / 0.5 + 0.5) * 0.5
    return _resolveGroundPosition(Vector3.new(x, pos.Y, z), plot)
end

local function _vecFromSaved(entry)
    if type(entry) ~= "table" then return nil end
    local x, y, z = tonumber(entry.x), tonumber(entry.y), tonumber(entry.z)
    if x and y and z then return Vector3.new(x, y, z) end
    return nil
end

local function _placePositionFromSaved(entry)
    return _vecFromSaved(entry)
end

local function _getPlaceRotation(entry, st, plot)
    local spawn = plot and plot:FindFirstChild("SpawnPoint")
    local gardenY = 0
    if PlacementGrid and spawn and type(PlacementGrid.GetGardenRotationY) == "function" then
        local ok, rot = pcall(PlacementGrid.GetGardenRotationY, spawn)
        if ok and type(rot) == "number" then
            gardenY = rot
        end
    end
    local offsetDeg = tonumber(entry and entry.rotation) or tonumber(st.rotation) or 0
    return math.deg(gardenY) + offsetDeg
end

local function _invalidatePlacedPotsCache()
    placedPotsCache = nil
    placedPotsCacheAt = 0
    placedPotsCachePlot = nil
end

local function _makePickupEntry(root, inGarden)
    if not root or not root:IsA("Model") or not root.Parent then return nil end

    local plantId = root:GetAttribute("PlantId")
    if plantId == nil or plantId == "" then
        plantId = _extractPlantId(root.Name)
    end
    plantId = plantId and tostring(plantId) or ""
    if plantId == "" then return nil end

    local typeKey
    local displayName
    if inGarden then
        typeKey = M.GetPlantTypeKey(root)
        local name = M.GetPlantDisplayName(root)
        displayName = (type(name) == "string" and name ~= "") and (name .. " (Potted)") or typeKey
    else
        typeKey = _getPlacedPotTypeKey(root)
        displayName = _getPlacedPotDisplayName(root)
    end

    return {
        model = root,
        plantId = plantId,
        typeKey = typeKey,
        displayName = displayName,
    }
end

local function _appendPickupRoot(out, seen, root, inGarden, plot)
    if not root or seen[root] then return end
    if not _isPickupPotOwned(root, plot) then return end
    local entry = _makePickupEntry(root, inGarden)
    if not entry then return end
    seen[root] = true
    out[#out + 1] = entry
end

local function _scanPlotPotVisualsBfs(plot, addRoot)
    if not plot then return end

    local frontier = { plot }
    for _ = 1, PICKUP_PLOT_BFS_DEPTH do
        local nextFrontier = {}
        for _, node in ipairs(frontier) do
            for _, child in ipairs(node:GetChildren()) do
                if child:IsA("Model") and child.Name == "PotVisual" then
                    addRoot(_resolvePickupPotRoot(child), false)
                elseif child:IsA("Folder") or child:IsA("Model") then
                    if child.Name ~= "Plants" then
                        nextFrontier[#nextFrontier + 1] = child
                    end
                end
            end
        end
        frontier = nextFrontier
        if #frontier == 0 then break end
    end
end

local function _buildPickupList(plot, st)
    plot = plot or getPlayerPlot()
    st = st or getPlotState()

    local out = {}
    local seen = {}

    local function addRoot(root, inGarden)
        _appendPickupRoot(out, seen, root, inGarden, plot)
    end

    local plantsFolder = getPlantsFolder(plot)
    if plantsFolder then
        for _, plant in ipairs(plantsFolder:GetChildren()) do
            if plant:IsA("Model")
                and (plant:GetAttribute("IsPotted") == true or plant:FindFirstChild("PotVisual")) then
                addRoot(plant, true)
            end
        end
    end

    _scanPlotPotVisualsBfs(plot, addRoot)

    if not _mapHasSelection(st.placedSelected) then
        return out
    end

    local filtered = {}
    for _, entry in ipairs(out) do
        if _matchesTypeKey(entry.typeKey, st.placedSelected) then
            filtered[#filtered + 1] = entry
        end
    end
    return filtered
end

local function _rebuildPlacedPotsCache(plot)
    plot = plot or getPlayerPlot()
    local out = _buildPickupList(plot, getPlotState())
    placedPotsCache = out
    placedPotsCacheAt = os.clock()
    placedPotsCachePlot = plot
    return out
end

local function _getPlacedPotsCached(plot)
    plot = plot or getPlayerPlot()
    local now = os.clock()
    if placedPotsCache
        and (now - placedPotsCacheAt) <= PLACED_POTS_CACHE_SEC
        and (placedPotsCachePlot == plot or (not plot and placedPotsCachePlot == nil)) then
        return placedPotsCache
    end
    return _rebuildPlacedPotsCache(plot)
end

local function _scanPlacedPots(plot, st)
    plot = plot or getPlayerPlot()
    st = st or getPlotState()
    if st and _mapHasSelection(st.placedSelected) then
        return _buildPickupList(plot, st)
    end
    return _getPlacedPotsCached(plot)
end

local function _resolvePlaceSlots(st)
    local out = {}
    local slots = st.slots
    if type(slots) ~= "table" then return out end

    if _mapHasSelection(st.slotsSelected) then
        for _, entry in ipairs(slots) do
            if type(entry) == "table" and entry.id and st.slotsSelected[tostring(entry.id)] then
                out[#out + 1] = entry
            end
        end
    else
        for _, entry in ipairs(slots) do
            if type(entry) == "table" and entry.id then
                out[#out + 1] = entry
            end
        end
    end
    return out
end

local function _nextPlaceSlot(st, plot)
    local slots = _resolvePlaceSlots(st)
    if #slots == 0 then return nil end

    for _ = 1, #slots do
        slotCursor = (slotCursor % #slots) + 1
        local entry = slots[slotCursor]
        local pos = _vecFromSaved(entry)
        if pos then
            return entry, pos
        end
    end
    return nil
end

function M.BuildPlaceToolPickerItems()
    local groups = {}
    for _, tool in ipairs(_enumeratePottedPlantTools()) do
        local typeKey = _getPottedToolTypeKey(tool)
        local g = groups[typeKey]
        if not g then
            g = { key = typeKey, name = typeKey, count = 0 }
            groups[typeKey] = g
        end
        g.count += 1
    end

    local items = {}
    for _, g in pairs(groups) do
        items[#items + 1] = {
            key = g.key,
            name = string.format("%s x %d", g.name, g.count),
            count = g.count,
        }
    end

    table.sort(items, function(a, b)
        return tostring(a.name) < tostring(b.name)
    end)

    if #items == 0 then
        items[1] = { key = "_none", name = "(No potted tools in inventory)" }
    end
    return items
end

M.buildPlaceToolPickerItems = M.BuildPlaceToolPickerItems

function M.BuildPlacedPotPickerItems()
    local plot = getPlayerPlot()
    local groups = {}

    if plot then
        for _, entry in ipairs(_scanPlacedPots(plot)) do
            local g = groups[entry.typeKey]
            if not g then
                g = { key = entry.typeKey, name = entry.typeKey, count = 0 }
                groups[entry.typeKey] = g
            end
            g.count += 1
        end
    end

    local items = {}
    for _, g in pairs(groups) do
        items[#items + 1] = {
            key = g.key,
            name = string.format("%s x %d", g.name, g.count),
            count = g.count,
        }
    end

    table.sort(items, function(a, b)
        return tostring(a.name) < tostring(b.name)
    end)

    if #items == 0 then
        items[1] = { key = "_none", name = "(No potted plants to pickup)" }
    end
    return items
end

M.buildPlacedPotPickerItems = M.BuildPlacedPotPickerItems

local function tryCollectOnce(st)
    st = st or getPlotState()
    if not st.autoCollect then return false, "disabled" end
    if st.collectTotal > 0 and sessionCollectCount >= st.collectTotal then
        return false, "collect_total_reached"
    end
    if not PickUpPottedPlantRemote or not PickUpPottedPlantRemote.Fire then
        return false, "no_remote"
    end

    local plot = getPlayerPlot()
    if not plot then
        lastStatus = "Plot not found"
        return false, "no_plot"
    end

    local pots = _buildPickupList(plot, st)
    if #pots == 0 then
        if st.collectTotal == 0 then
            if sessionCollectCount > 0 then
                lastStatus = ("Done — picked up %d"):format(sessionCollectCount)
            elseif _mapHasSelection(st.placedSelected) then
                lastStatus = "No matching placed pots"
            else
                lastStatus = "No placed pots"
            end
            return false, "no_pot"
        end
        if _mapHasSelection(st.placedSelected) then
            lastStatus = "No matching placed pots"
        else
            lastStatus = "No placed pots"
        end
        return false, "no_pot_wait"
    end

    local tries = math.min(#pots, PICKUP_TRY_PER_TICK)
    for _ = 1, tries do
        pickupCursor = (pickupCursor % #pots) + 1
        local candidate = pots[pickupCursor]
        local modelRef = candidate and candidate.model
        if modelRef and modelRef.Parent and candidate.plantId then
            lastStatus = "Picking up..."
            local toolsBefore = _countAllPottedTools()
            local ok, err = pcall(function()
                PickUpPottedPlantRemote:Fire(candidate.plantId)
            end)
            if not ok then
                warn("[GAG2-APlot] PickUpPottedPlant error:", tostring(err))
                lastStatus = "Pickup failed"
                return false, "fire_error"
            end

            if _awaitPickupConfirmed(modelRef, toolsBefore) then
                sessionCollectCount += 1
                _invalidatePlacedPotsCache()
                _log("picked up", candidate.plantId, candidate.displayName, sessionCollectCount)
                _notifyStatsChanged()
                return true
            end
        end
    end

    lastStatus = "Pickup skipped"
    return false, "pickup_failed"
end

local function tryPotOnce(st)
    st = st or getPlotState()
    if not st.autoPot then return false, "disabled" end
    if st.potTotal > 0 and sessionPotCount >= st.potTotal then
        return false, "pot_total_reached"
    end
    if not PotPlantRemote or not PotPlantRemote.Fire then
        return false, "no_remote"
    end
    if LP:GetAttribute("PlotId") == nil then
        lastStatus = "Waiting plot..."
        return false, "no_plot"
    end

    local candidate = _scanPotCandidate(st)
    if not candidate then
        if _mapHasSelection(st.plantsSelected) then
            lastStatus = "Selected plants not ready"
        else
            lastStatus = "No eligible plants"
        end
        return false, "no_plant"
    end

    lastStatus = "Potting..."

    local ok, err = pcall(function()
        PotPlantRemote:Fire(candidate.plantId)
    end)
    if not ok then
        warn("[GAG2-APlot] PotPlant error:", tostring(err))
        lastStatus = "Pot failed"
        return false, "fire_error"
    end

    sessionPotCount += 1
    _log("potted", candidate.plantId, sessionPotCount)
    _notifyStatsChanged()
    return true
end

local function tryPlaceOnce(st)
    st = st or getPlotState()
    if not st.autoPlace then return false, "disabled" end
    if st.placeTotal > 0 and sessionPlaceCount >= st.placeTotal then
        return false, "place_total_reached"
    end
    if not PlacePottedPlantRemote or not PlacePottedPlantRemote.Fire then
        return false, "no_remote"
    end

    local tool = _findPottedPlantTool(st)
    if not tool then
        if _mapHasSelection(st.placeToolsSelected) then
            lastStatus = "No matching potted tools"
        else
            lastStatus = "No potted plant tool"
        end
        return false, "no_tool"
    end

    local plot = getPlayerPlot()
    if not plot then
        lastStatus = "Plot not found"
        return false, "no_plot"
    end

    local entry, pos = _nextPlaceSlot(st, plot)
    if not entry or not pos then
        lastStatus = "No free slot"
        return false, "no_slot"
    end

    pos = _placePositionFromSaved(entry)
    if not pos then
        lastStatus = "Invalid slot"
        return false, "bad_slot"
    end
    pos = _snapPosition(pos, plot) or pos

    lastStatus = "Placing..."

    local rotation = _getPlaceRotation(entry, st, plot)
    local toolsBefore = _countMatchingPottedTools(st)
    local ok, err = _firePlaceRemote(pos, rotation, tool)
    if not ok then
        warn("[GAG2-APlot] PlacePottedPlant error:", tostring(err))
        lastStatus = "Place failed"
        return false, "fire_error"
    end

    if not _awaitPlaceConfirmed(st, toolsBefore) then
        lastStatus = "Place skipped"
        return false, "place_failed"
    end

    sessionPlaceCount += 1
    _invalidatePlacedPotsCache()
    _log("placed", _pottedToolId(tool), pos, rotation, sessionPlaceCount)
    _notifyStatsChanged()
    return true
end

local FEATURE_STOP_REASONS = {
    pot = {
        pot_total_reached = true,
        no_plant = true,
    },
    place = {
        place_total_reached = true,
        no_tool = true,
        no_slot = true,
    },
    collect = {
        collect_total_reached = true,
        no_pot = true,
    },
}

local function _stopFeature(st, feature, reason)
    st = st or getPlotState()
    feature = tostring(feature or "")
    local patch = {}

    if feature == "pot" and st.autoPot then
        patch.autoPot = false
        G.AUTO_PLOT_AUTO_POT = false
        _G.AUTO_PLOT_AUTO_POT = false
    elseif feature == "place" and st.autoPlace then
        patch.autoPlace = false
        G.AUTO_PLOT_AUTO_PLACE = false
        _G.AUTO_PLOT_AUTO_PLACE = false
    elseif feature == "collect" and st.autoCollect then
        patch.autoCollect = false
        G.AUTO_PLOT_AUTO_COLLECT = false
        _G.AUTO_PLOT_AUTO_COLLECT = false
    else
        return false
    end

    _writeMain(patch)
    if feature == "collect" and reason == "no_pot" then
        lastFinishReason = "collect_all_done"
    else
        lastFinishReason = tostring(reason or "done")
    end

    if type(G.__GAG2_ON_PLOT_FEATURE_FINISHED) == "function" then
        pcall(G.__GAG2_ON_PLOT_FEATURE_FINISHED, feature, reason)
    end

    st = getPlotState()
    if not st.autoPot and not st.autoPlace and not st.autoCollect then
        lastSessionPotCount = sessionPotCount
        lastSessionPlaceCount = sessionPlaceCount
        lastSessionCollectCount = sessionCollectCount
        lastStatus = "Done"
        M.Stop()
        if type(G.__GAG2_ON_PLOT_AUTO_FINISHED) == "function" then
            pcall(G.__GAG2_ON_PLOT_AUTO_FINISHED, reason or "done")
        end
    end
    return true
end

local function _maybeStopFeature(st, feature, reason)
    local reasons = FEATURE_STOP_REASONS[feature]
    if not reasons or not reasons[reason] then
        return false
    end
    return _stopFeature(st, feature, reason)
end

local function _finishIfDone(st)
    st = st or getPlotState()
    local potDone = not st.autoPot or (st.potTotal > 0 and sessionPotCount >= st.potTotal)
    local placeDone = not st.autoPlace or (st.placeTotal > 0 and sessionPlaceCount >= st.placeTotal)
    local collectDone = not st.autoCollect or (st.collectTotal > 0 and sessionCollectCount >= st.collectTotal)

    if not (potDone and placeDone and collectDone) then
        return false
    end
    if not (st.autoPot or st.autoPlace or st.autoCollect) then
        return false
    end

    if st.autoPot and st.potTotal > 0 and sessionPotCount >= st.potTotal then
        _stopFeature(st, "pot", "pot_total_reached")
        st = getPlotState()
    end
    if st.autoPlace and st.placeTotal > 0 and sessionPlaceCount >= st.placeTotal then
        _stopFeature(st, "place", "place_total_reached")
        st = getPlotState()
    end
    if st.autoCollect and st.collectTotal > 0 and sessionCollectCount >= st.collectTotal then
        _stopFeature(st, "collect", "collect_total_reached")
    end
    return not getPlotState().autoPot and not getPlotState().autoPlace and not getPlotState().autoCollect
end

local function _delayForFeature(st, feature)
    st = st or getPlotState()
    feature = tostring(feature or "")
    if feature == "collect" then
        return tonumber(st.collectDelay) or 1
    elseif feature == "place" then
        return tonumber(st.placeDelay) or 1
    elseif feature == "pot" then
        return tonumber(st.potDelay) or 1.5
    end
    return LOOP_MIN_SEC
end

local function _tickOnce()
    local st = getPlotState()
    if not _autoFlagsEnabled(st) then
        return false
    end

    if _finishIfDone(st) then return false end

    if st.autoCollect then
        local ok, reason = tryCollectOnce(st)
        if ok then return true, "collect" end
        if _maybeStopFeature(st, "collect", reason) then
            st = getPlotState()
            if not st.autoPot and not st.autoPlace and not st.autoCollect then
                return false
            end
        end
    end

    if st.autoPlace then
        if not _findPottedPlantTool(st) then
            _maybeStopFeature(st, "place", "no_tool")
            st = getPlotState()
            if not st.autoPot and not st.autoPlace and not st.autoCollect then
                return false
            end
        else
            local ok, reason = tryPlaceOnce(st)
            if ok then return true, "place" end
            if _maybeStopFeature(st, "place", reason) then
                st = getPlotState()
                if not st.autoPot and not st.autoPlace and not st.autoCollect then
                    return false
                end
            end
        end
    end

    if st.autoPot then
        local ok, reason = tryPotOnce(st)
        if ok then return true, "pot" end
        if _maybeStopFeature(st, "pot", reason) then
            st = getPlotState()
            if not st.autoPot and not st.autoPlace and not st.autoCollect then
                return false
            end
        end
    end

    return false
end

local function mainLoop(myId)
    while running and loopId == myId do
        local st = getPlotState()
        local acted = false
        local actedFeature = nil
        if _autoFlagsEnabled(st) then
            local ok, result, feature = pcall(_tickOnce)
            if ok and result == true then
                acted = true
                actedFeature = feature
            elseif ok and not result and _isPlotActive(st) then
                if lastStatus == "Idle" or lastStatus == "Starting..." then
                    lastStatus = _defaultActiveStatus(st)
                end
            end
        end

        local delay = LOOP_MIN_SEC
        if acted and actedFeature then
            delay = _delayForFeature(st, actedFeature)
        elseif lastStatus == "No placed pots"
            or lastStatus == "No matching placed pots"
            or lastStatus == "No potted plant tool"
            or lastStatus == "No matching potted tools"
            or lastStatus == "No free slot"
            or lastStatus == "No eligible plants"
            or lastStatus == "Selected plants not ready"
            or lastStatus == "Waiting plot..." then
            delay = IDLE_LOOP_SEC
        end
        if delay > 0 and delay < LOOP_MIN_SEC then delay = LOOP_MIN_SEC end
        task.wait(delay)
    end
end

function M.IsRunning()
    return running
end

function M.GetStatusText()
    local st = getPlotState()
    if not running and (
        lastFinishReason == "total_reached"
        or lastFinishReason == "collect_total_reached"
        or lastFinishReason == "collect_all_done"
        or lastFinishReason == "pot_total_reached"
        or lastFinishReason == "place_total_reached"
    ) then
        if st.potTotal > 0 or st.placeTotal > 0 or st.collectTotal > 0 then
            return ("Done — potted %d / %d, placed %d / %d, picked up %d / %d"):format(
                lastSessionPotCount,
                st.potTotal > 0 and st.potTotal or lastSessionPotCount,
                lastSessionPlaceCount,
                st.placeTotal > 0 and st.placeTotal or lastSessionPlaceCount,
                lastSessionCollectCount,
                st.collectTotal > 0 and st.collectTotal or lastSessionCollectCount
            )
        end
        return ("Done — potted %d, placed %d, picked up %d"):format(
            lastSessionPotCount, lastSessionPlaceCount, lastSessionCollectCount
        )
    end

    if _isPlotActive(st) then
        local base = lastStatus
        if base == "Idle" or base == "Starting..." or base == "" then
            base = _defaultActiveStatus(st)
        end
        local extra = ""
        if st.potTotal > 0 then
            extra = extra .. (" · pot %d/%d"):format(sessionPotCount, st.potTotal)
        elseif sessionPotCount > 0 then
            extra = extra .. (" · potted %d"):format(sessionPotCount)
        end
        if st.placeTotal > 0 then
            extra = extra .. (" · place %d/%d"):format(sessionPlaceCount, st.placeTotal)
        elseif sessionPlaceCount > 0 then
            extra = extra .. (" · placed %d"):format(sessionPlaceCount)
        end
        local remainTools = 0
        local remainPots = 0
        pcall(function()
            remainTools = _countMatchingPottedTools(st)
        end)
        if st.autoPlace and remainTools > 0 then
            extra = extra .. (" · %d tool left"):format(remainTools)
        end
        if st.collectTotal > 0 then
            extra = extra .. (" · pickup %d/%d"):format(sessionCollectCount, st.collectTotal)
        elseif sessionCollectCount > 0 then
            extra = extra .. (" · picked up %d"):format(sessionCollectCount)
        end
        pcall(function()
            remainPots = _countRemainingPlacedPots(st)
        end)
        if remainPots > 0 then
            extra = extra .. (" · %d pot left"):format(remainPots)
        end
        if not running and _autoFlagsEnabled(st) then
            extra = extra .. " · starting"
        end
        return base .. extra
    end

    if not _autoFlagsEnabled(st) then
        return "Idle"
    end
    return _defaultActiveStatus(st)
end

function M.GetSessionCollectCount()
    return running and sessionCollectCount or lastSessionCollectCount
end

function M.GetSessionPotCount()
    return running and sessionPotCount or lastSessionPotCount
end

function M.GetSessionPlaceCount()
    return running and sessionPlaceCount or lastSessionPlaceCount
end

local function _getStandingPlotPosition(plot)
    local char = LP.Character
    local hrp = char and char:FindFirstChild("HumanoidRootPart")
    if not hrp or not plot then return nil end

    local surfaces = _collectPropSurfaces(plot)
    if #surfaces > 0 then
        local params = RaycastParams.new()
        params.FilterType = Enum.RaycastFilterType.Include
        params.FilterDescendantsInstances = surfaces

        local hit = workspace:Raycast(hrp.Position + Vector3.new(0, 10, 0), Vector3.new(0, -40, 0), params)
        if hit and hit.Instance:IsDescendantOf(plot) then
            return _snapPosition(hit.Position, plot)
        end
    end

    return _snapPosition(Vector3.new(hrp.Position.X, hrp.Position.Y - 3, hrp.Position.Z), plot)
end

local function _disableSaveMode()
    saveModeActive = false
    G.AUTO_PLOT_SAVE_SLOT = false
    _G.AUTO_PLOT_SAVE_SLOT = false
    _writeMain({ saveSlot = false })
    saveEnableAt = 0
    if type(G.__GAG2_ON_PLOT_SAVE_MODE_CHANGED) == "function" then
        pcall(G.__GAG2_ON_PLOT_SAVE_MODE_CHANGED, false)
    end
    local api = G.__GAG2_PLOT_SAVE_TOGGLE_API
    if type(api) == "table" and type(api.setOff) == "function" then
        pcall(api.setOff, true)
    end
end

local function _commitSaveSlot(pos, rotation)
    if not pos then return false end
    local plot = getPlayerPlot()
    if not plot then return false end

    pos = _snapPosition(pos, plot)
    if not pos then return false end

    local MAIN = rawget(_G, "MAIN") or G.MAIN
    if type(MAIN) ~= "table" then return false end

    MAIN.auto = MAIN.auto or {}
    MAIN.auto.plot = MAIN.auto.plot or {}
    local slots = type(MAIN.auto.plot.slots) == "table" and MAIN.auto.plot.slots or {}

    local id = ("pslot_%d"):format(math.floor(os.clock() * 1000))
    slots[#slots + 1] = {
        id = id,
        x = pos.X,
        y = pos.Y,
        z = pos.Z,
        rotation = tonumber(rotation) or 0,
    }

    local selected = type(MAIN.auto.plot.selectedSlots) == "table" and MAIN.auto.plot.selectedSlots or {}
    local found = false
    for _, sid in ipairs(selected) do
        if tostring(sid) == id then
            found = true
            break
        end
    end
    if not found then
        selected[#selected + 1] = id
    end

    MAIN.auto.plot.slots = slots
    MAIN.auto.plot.selectedSlot = id
    MAIN.auto.plot.selectedSlots = selected
    MAIN.auto.plot.saveSlot = false
    G.MAIN = MAIN
    _G.MAIN = MAIN

    _notifySlotsChanged()
    print(("[GAG2-APlot] Slot saved (#%d)"):format(#slots))
    _disableSaveMode()
    return true, id
end

function M.SaveStandingSlot()
    local plot = getPlayerPlot()
    if not plot then
        warn("[GAG2-APlot] Save slot failed: plot not found")
        return false
    end
    local pos = _getStandingPlotPosition(plot)
    if not pos then
        warn("[GAG2-APlot] Save slot failed: character position unavailable")
        return false
    end
    local st = getPlotState()
    return _commitSaveSlot(pos, st.rotation)
end

function M.DeleteSlot(id)
    id = tostring(id or "")
    if id == "" then return false end

    local MAIN = rawget(_G, "MAIN") or G.MAIN
    if type(MAIN) ~= "table" then return false end
    MAIN.auto = MAIN.auto or {}
    MAIN.auto.plot = MAIN.auto.plot or {}
    local slots = type(MAIN.auto.plot.slots) == "table" and MAIN.auto.plot.slots or {}

    local removed = false
    for i = #slots, 1, -1 do
        local entry = slots[i]
        if type(entry) == "table" and tostring(entry.id) == id then
            table.remove(slots, i)
            removed = true
        end
    end
    if not removed then return false end

    local selected = {}
    for _, sid in ipairs(type(MAIN.auto.plot.selectedSlots) == "table" and MAIN.auto.plot.selectedSlots or {}) do
        if tostring(sid) ~= id then
            selected[#selected + 1] = sid
        end
    end

    MAIN.auto.plot.slots = slots
    MAIN.auto.plot.selectedSlots = selected
    if tostring(MAIN.auto.plot.selectedSlot) == id then
        MAIN.auto.plot.selectedSlot = selected[1]
    end
    G.MAIN = MAIN
    _G.MAIN = MAIN

    _notifySlotsChanged()
    return true
end

local function _bindSaveListener()
    if saveInputConn then return end
    saveInputConn = UserInputService.InputEnded:Connect(function(input)
        if not saveModeActive then return end
        if input.UserInputType ~= Enum.UserInputType.MouseButton1
            and input.UserInputType ~= Enum.UserInputType.Touch then
            return
        end
        if os.clock() < saveEnableAt then return end
        if os.clock() - lastClickAt < 0.15 then return end
        lastClickAt = os.clock()
        M.SaveStandingSlot()
    end)
end

function M.SetSaveSlot(on)
    on = (on == true)
    if not on then
        saveModeActive = false
        _disableSaveMode()
        return
    end
    saveModeActive = true
    saveEnableAt = os.clock() + 0.2
    G.AUTO_PLOT_SAVE_SLOT = true
    _G.AUTO_PLOT_SAVE_SLOT = true
    _writeMain({ saveSlot = true })
    _bindSaveListener()
end

function M.SyncFromState()
    if _autoFlagsEnabled() then
        M.Start()
    else
        M.Stop()
    end
end

function M.Start()
    if not _autoFlagsEnabled() then
        return false
    end
    if running then
        _notifyStatsChanged()
        return true
    end
    sessionPotCount = 0
    sessionPlaceCount = 0
    sessionCollectCount = 0
    lastFinishReason = nil
    slotCursor = 0
    pickupCursor = 0
    lastStatus = "Starting..."
    running = true
    loopId += 1
    local myId = loopId
    task.spawn(function()
        local ok, err = pcall(mainLoop, myId)
        if not ok then
            warn("[GAG2-APlot] loop error:", tostring(err))
            if loopId == myId then
                running = false
            end
        end
    end)
    _notifyStatsChanged()
    return true
end

function M.Stop()
    running = false
    lastSessionPotCount = sessionPotCount
    lastSessionPlaceCount = sessionPlaceCount
    lastSessionCollectCount = sessionCollectCount
    _disableSaveMode()
    _notifyStatsChanged()
end

function M.SetAutoPot(on)
    on = (on == true)
    G.AUTO_PLOT_AUTO_POT = on
    _G.AUTO_PLOT_AUTO_POT = on
    _writeMain({ autoPot = on })
    if on then
        M.Start()
    elseif not getPlotState().autoPlace and not getPlotState().autoCollect then
        M.Stop()
    end
end

function M.SetAutoPlace(on)
    on = (on == true)
    G.AUTO_PLOT_AUTO_PLACE = on
    _G.AUTO_PLOT_AUTO_PLACE = on
    _writeMain({ autoPlace = on })
    if on then
        M.Start()
    elseif not getPlotState().autoPot and not getPlotState().autoCollect then
        M.Stop()
    end
end

function M.SetAutoCollect(on)
    on = (on == true)
    G.AUTO_PLOT_AUTO_COLLECT = on
    _G.AUTO_PLOT_AUTO_COLLECT = on
    _writeMain({ autoCollect = on })
    if on then
        M.Start()
    elseif not getPlotState().autoPot and not getPlotState().autoPlace then
        M.Stop()
    end
end

M.getPlayerPlot = getPlayerPlot
M.GetPlayerPlot = getPlayerPlot
M.getPlotState = getPlotState
M.GetPlotState = getPlotState

G.AutoPlot = M
G.AutoPlotModule = M
_G.AutoPlot = M
_G.AutoPlotModule = M

return M
 end,                       required = false },
    { key = "SectionAutoPlot",         name = "Section Auto Pot",        factory = function() -- section_auto_plot.lua — UI section Auto Pot (tab Auto)

local G = (getgenv and getgenv()) or _G
local M = {}

function M.Register(ctx)
    if type(ctx) ~= "table" or type(ctx.ui) ~= "table" then return end

    local ui = ctx.ui
    local getAuto       = ctx.getAuto
    local patchAuto     = ctx.patchAuto
    local patchAutoOnly = ctx.patchAutoOnly
    local registerFlush = ctx.registerFlush
    local cleanSelectedMap = ctx.cleanSelectedMap
    local arrayToMap    = ctx.arrayToMap
    local mapToArray    = ctx.mapToArray

    local PL_STATE = getAuto("plot")
    PL_STATE.plants = type(PL_STATE.plants) == "table" and PL_STATE.plants or {}
    PL_STATE.placedPlants = type(PL_STATE.placedPlants) == "table" and PL_STATE.placedPlants or {}
    PL_STATE.placeTools = type(PL_STATE.placeTools) == "table" and PL_STATE.placeTools or {}
    PL_STATE.slots = type(PL_STATE.slots) == "table" and PL_STATE.slots or {}
    PL_STATE.selectedSlots = type(PL_STATE.selectedSlots) == "table" and PL_STATE.selectedSlots or {}
    PL_STATE.placeMode = tostring(PL_STATE.placeMode or "saved"):lower()
    if PL_STATE.placeMode ~= "saved" then PL_STATE.placeMode = "saved" end
    PL_STATE.saveSlot = false
    if PL_STATE.potDelay == nil then PL_STATE.potDelay = 1.5 end
    if PL_STATE.placeDelay == nil then PL_STATE.placeDelay = 1 end
    if PL_STATE.collectDelay == nil then PL_STATE.collectDelay = 1 end
    if PL_STATE.potTotal == nil then PL_STATE.potTotal = 0 end
    if PL_STATE.placeTotal == nil then PL_STATE.placeTotal = 0 end
    if PL_STATE.collectTotal == nil then PL_STATE.collectTotal = 0 end

    local AUTO_PLOT_PLANTS_SELECTED = cleanSelectedMap(arrayToMap(PL_STATE.plants))
    local AUTO_PLOT_PLACED_POTS_SELECTED = cleanSelectedMap(arrayToMap(PL_STATE.placedPlants))
    local AUTO_PLOT_PLACE_TOOLS_SELECTED = cleanSelectedMap(arrayToMap(PL_STATE.placeTools))
    local AUTO_PLOT_SELECTED_SLOTS = cleanSelectedMap(arrayToMap(PL_STATE.selectedSlots))

    local function potDelayDisplay()
        local n = tonumber(PL_STATE.potDelay)
        return (n ~= nil) and n or 1.5
    end

    local function placeDelayDisplay()
        local n = tonumber(PL_STATE.placeDelay)
        return (n ~= nil) and n or 1
    end

    local function potTotalDisplay()
        local n = tonumber(PL_STATE.potTotal)
        return (n ~= nil) and math.floor(n) or 0
    end

    local function placeTotalDisplay()
        local n = tonumber(PL_STATE.placeTotal)
        return (n ~= nil) and math.floor(n) or 0
    end

    local function collectDelayDisplay()
        local n = tonumber(PL_STATE.collectDelay)
        return (n ~= nil) and n or 1
    end

    local function collectTotalDisplay()
        local n = tonumber(PL_STATE.collectTotal)
        return (n ~= nil) and math.floor(n) or 0
    end

    local function normalizeSlotId(v)
        if v == nil then return nil end
        if type(v) == "table" then v = v.id or v.key end
        v = tostring(v)
        if v == "" or v == "_none" or v:sub(1, 6) == "table:" then return nil end
        return v
    end

    PL_STATE.selectedSlot = normalizeSlotId(PL_STATE.selectedSlot)

    local function buildSlotItems()
        local items = {}
        local slots = PL_STATE.slots
        if type(slots) ~= "table" then return items end
        for i, entry in ipairs(slots) do
            if type(entry) == "table" and entry.id then
                local x = tonumber(entry.x) or 0
                local z = tonumber(entry.z) or 0
                items[#items + 1] = {
                    key = tostring(entry.id),
                    name = ("Loc %d (%.0f, %.0f)"):format(i, x, z),
                }
            end
        end
        if #items == 0 then
            items[1] = { key = "_none", name = "(Save slot dulu)" }
        end
        return items
    end

    local function writePlotGlobals()
        G.AUTO_PLOT_AUTO_POT = (PL_STATE.autoPot == true)
        _G.AUTO_PLOT_AUTO_POT = G.AUTO_PLOT_AUTO_POT
        G.AUTO_PLOT_AUTO_PLACE = (PL_STATE.autoPlace == true)
        _G.AUTO_PLOT_AUTO_PLACE = G.AUTO_PLOT_AUTO_PLACE
        G.AUTO_PLOT_AUTO_COLLECT = (PL_STATE.autoCollect == true)
        _G.AUTO_PLOT_AUTO_COLLECT = G.AUTO_PLOT_AUTO_COLLECT
        G.AUTO_PLOT_POT_DELAY = tonumber(PL_STATE.potDelay) or 1.5
        _G.AUTO_PLOT_POT_DELAY = G.AUTO_PLOT_POT_DELAY
        G.AUTO_PLOT_PLACE_DELAY = tonumber(PL_STATE.placeDelay) or 1
        _G.AUTO_PLOT_PLACE_DELAY = G.AUTO_PLOT_PLACE_DELAY
        G.AUTO_PLOT_COLLECT_DELAY = collectDelayDisplay()
        _G.AUTO_PLOT_COLLECT_DELAY = G.AUTO_PLOT_COLLECT_DELAY
        G.AUTO_PLOT_POT_TOTAL = potTotalDisplay()
        _G.AUTO_PLOT_POT_TOTAL = G.AUTO_PLOT_POT_TOTAL
        G.AUTO_PLOT_PLACE_TOTAL = placeTotalDisplay()
        _G.AUTO_PLOT_PLACE_TOTAL = G.AUTO_PLOT_PLACE_TOTAL
        G.AUTO_PLOT_COLLECT_TOTAL = collectTotalDisplay()
        _G.AUTO_PLOT_COLLECT_TOTAL = G.AUTO_PLOT_COLLECT_TOTAL
        G.AUTO_PLOT_PLACE_MODE = PL_STATE.placeMode
        _G.AUTO_PLOT_PLACE_MODE = PL_STATE.placeMode
        G.AUTO_PLOT_PLANTS_SELECTED = AUTO_PLOT_PLANTS_SELECTED
        _G.AUTO_PLOT_PLANTS_SELECTED = AUTO_PLOT_PLANTS_SELECTED
        G.AUTO_PLOT_PLACED_POTS_SELECTED = AUTO_PLOT_PLACED_POTS_SELECTED
        _G.AUTO_PLOT_PLACED_POTS_SELECTED = AUTO_PLOT_PLACED_POTS_SELECTED
        G.AUTO_PLOT_PLACE_TOOLS_SELECTED = AUTO_PLOT_PLACE_TOOLS_SELECTED
        _G.AUTO_PLOT_PLACE_TOOLS_SELECTED = AUTO_PLOT_PLACE_TOOLS_SELECTED
        G.AUTO_PLOT_SELECTED_SLOTS = AUTO_PLOT_SELECTED_SLOTS
        _G.AUTO_PLOT_SELECTED_SLOTS = AUTO_PLOT_SELECTED_SLOTS
        G.AUTO_PLOT_SAVE_SLOT = false
        _G.AUTO_PLOT_SAVE_SLOT = false

        patchAutoOnly("plot", {
            autoPot         = (PL_STATE.autoPot == true),
            autoPlace       = (PL_STATE.autoPlace == true),
            autoCollect     = (PL_STATE.autoCollect == true),
            plants          = mapToArray(AUTO_PLOT_PLANTS_SELECTED),
            placedPlants    = mapToArray(AUTO_PLOT_PLACED_POTS_SELECTED),
            placeTools      = mapToArray(AUTO_PLOT_PLACE_TOOLS_SELECTED),
            slots           = type(PL_STATE.slots) == "table" and PL_STATE.slots or {},
            selectedSlots   = mapToArray(AUTO_PLOT_SELECTED_SLOTS),
            selectedSlot    = PL_STATE.selectedSlot,
            potDelay        = PL_STATE.potDelay,
            placeDelay      = PL_STATE.placeDelay,
            collectDelay    = PL_STATE.collectDelay,
            potTotal        = potTotalDisplay(),
            placeTotal      = placeTotalDisplay(),
            collectTotal    = collectTotalDisplay(),
            placeMode       = PL_STATE.placeMode,
            saveSlot        = false,
            rotation        = tonumber(PL_STATE.rotation) or 0,
        })
    end

    G.__GAG2_PUSH_PLOT = writePlotGlobals
    _G.__GAG2_PUSH_PLOT = writePlotGlobals

    registerFlush("plot", function()
        writePlotGlobals()
    end)

    writePlotGlobals()

    local statusLabel
    local plantDropdownApi
    local placedPotDropdownApi
    local placeToolDropdownApi
    local slotDropdownApi
    local saveSlotToggleApi
    local potEnableApi
    local placeEnableApi
    local collectEnableApi

    local function refreshPlotStatus()
        if not (statusLabel and statusLabel.Parent) then return end

        local mod = G.AutoPlot or G.AutoPlotModule
        local active = (PL_STATE.autoPot == true)
            or (PL_STATE.autoPlace == true)
            or (PL_STATE.autoCollect == true)

        if not active then
            statusLabel.Text = "Idle"
            return
        end

        if type(mod) ~= "table" then
            statusLabel.Text = "AutoPlot not loaded"
            return
        end

        local txt = "Running..."
        if type(mod.GetStatusText) == "function" then
            local ok, s = pcall(mod.GetStatusText, mod)
            if ok and type(s) == "string" and s ~= "" and s ~= "Idle" then
                txt = s
            elseif PL_STATE.autoPlace then
                txt = "Waiting place..."
            elseif PL_STATE.autoCollect then
                txt = "Waiting pickup..."
            elseif PL_STATE.autoPot then
                txt = "Waiting pot..."
            end
        end
        if type(mod.IsRunning) == "function" and not mod:IsRunning() then
            txt = txt .. " · restarting"
        end
        statusLabel.Text = txt
    end

    local function syncPlotModule()
        writePlotGlobals()
        local mod = G.AutoPlot or G.AutoPlotModule
        if type(mod) ~= "table" then
            refreshPlotStatus()
            return
        end

        if PL_STATE.autoPot or PL_STATE.autoPlace or PL_STATE.autoCollect then
            if type(mod.Start) == "function" then
                pcall(mod.Start, mod)
            end
        else
            if type(mod.Stop) == "function" then
                pcall(mod.Stop, mod)
            end
        end
        refreshPlotStatus()
    end

    local function syncSlotsFromPersisted()
        local main = G.MAIN or _G.MAIN
        if type(main) == "table" and type(main.auto) == "table" and type(main.auto.plot) == "table" then
            local ps = main.auto.plot
            if type(ps.slots) == "table" then
                PL_STATE.slots = ps.slots
            end
            if type(ps.selectedSlots) == "table" then
                PL_STATE.selectedSlots = ps.selectedSlots
            end
            PL_STATE.selectedSlot = normalizeSlotId(ps.selectedSlot)
        end
    end

    G.__GAG2_SYNC_AUTO_PLOT = syncPlotModule
    _G.__GAG2_SYNC_AUTO_PLOT = syncPlotModule

    G.__GAG2_ON_PLOT_SLOTS_CHANGED = function()
        local main = G.MAIN or _G.MAIN
        if type(main) == "table" and type(main.auto) == "table" and type(main.auto.plot) == "table" then
            local ps = main.auto.plot
            PL_STATE.slots = type(ps.slots) == "table" and ps.slots or PL_STATE.slots
            PL_STATE.selectedSlots = type(ps.selectedSlots) == "table" and ps.selectedSlots or PL_STATE.selectedSlots
            PL_STATE.selectedSlot = normalizeSlotId(ps.selectedSlot)
        end
        AUTO_PLOT_SELECTED_SLOTS = cleanSelectedMap(arrayToMap(PL_STATE.selectedSlots))
        writePlotGlobals()
        if slotDropdownApi and type(slotDropdownApi.refreshItems) == "function" then
            slotDropdownApi.refreshItems()
        end
        if slotDropdownApi and type(slotDropdownApi.setSelected) == "function" then
            slotDropdownApi.setSelected(AUTO_PLOT_SELECTED_SLOTS)
        end
        refreshPlotStatus()
    end
    _G.__GAG2_ON_PLOT_SLOTS_CHANGED = G.__GAG2_ON_PLOT_SLOTS_CHANGED

    G.__GAG2_ON_PLOT_STATS_CHANGED = refreshPlotStatus
    _G.__GAG2_ON_PLOT_STATS_CHANGED = refreshPlotStatus

    G.__GAG2_ON_PLOT_SAVE_MODE_CHANGED = function(on)
        PL_STATE.saveSlot = (on == true)
        writePlotGlobals()
        if saveSlotToggleApi and type(saveSlotToggleApi.set) == "function" then
            saveSlotToggleApi.set(on, true)
        end
    end

    G.__GAG2_ON_PLOT_FEATURE_FINISHED = function(feature, reason)
        feature = tostring(feature or "")
        reason = tostring(reason or "done")

        if feature == "pot" then
            PL_STATE.autoPot = false
            if potEnableApi and type(potEnableApi.setOff) == "function" then
                pcall(potEnableApi.setOff, true)
            elseif potEnableApi and type(potEnableApi.set) == "function" then
                pcall(potEnableApi.set, false, true)
            end
            patchAutoOnly("plot", { autoPot = false })
        elseif feature == "place" then
            PL_STATE.autoPlace = false
            if placeEnableApi and type(placeEnableApi.setOff) == "function" then
                pcall(placeEnableApi.setOff, true)
            elseif placeEnableApi and type(placeEnableApi.set) == "function" then
                pcall(placeEnableApi.set, false, true)
            end
            patchAutoOnly("plot", { autoPlace = false })
        elseif feature == "collect" then
            PL_STATE.autoCollect = false
            if collectEnableApi and type(collectEnableApi.setOff) == "function" then
                pcall(collectEnableApi.setOff, true)
            elseif collectEnableApi and type(collectEnableApi.set) == "function" then
                pcall(collectEnableApi.set, false, true)
            end
            patchAutoOnly("plot", { autoCollect = false })
        end

        writePlotGlobals()
        refreshPlotStatus()
