    { key = "SprinklerListView",       name = "SprinklerListView",       factory = function() -- SprinklerListView.lua — Grow A Garden 2
-- List sprinkler dari SharedModules.SprinklerData

local ReplicatedStorage = game:GetService("ReplicatedStorage")
local Players           = game:GetService("Players")

local LP = Players.LocalPlayer
local M = {}

local G = (getgenv and getgenv()) or _G

local _catalogCache = nil

local function _safeRequire(inst)
    if not inst or not inst:IsA("ModuleScript") then return nil end
    local ok, mod = pcall(require, inst)
    if ok and type(mod) == "table" then return mod end
    return nil
end

local function _normalizeEntry(entry, keyHint)
    if type(entry) ~= "table" then return nil end
    local name = entry.SprinklerName or entry.Name or keyHint
    if not name or tostring(name) == "" then return nil end
    return {
        SprinklerName = tostring(name),
        Radius        = tonumber(entry.Radius) or 0,
        Lifetime      = tonumber(entry.Lifetime),
        raw           = entry,
    }
end

local function _loadCatalog()
    if _catalogCache then return _catalogCache end

    local merged = {}
    local root = ReplicatedStorage:FindFirstChild("SharedModules")
    local dataMod = root and root:FindFirstChild("SprinklerData")
    local data = dataMod and _safeRequire(dataMod)

    if type(data) == "table" then
        if #data > 0 then
            for _, entry in ipairs(data) do
                local norm = _normalizeEntry(entry)
                if norm then merged[norm.SprinklerName] = norm end
            end
        else
            for key, entry in pairs(data) do
                if type(entry) == "table" then
                    local norm = _normalizeEntry(entry, key)
                    if norm then merged[norm.SprinklerName] = norm end
                end
            end
        end
    end

    _catalogCache = merged
    return merged
end

function M.refresh()
    _catalogCache = nil
    return _loadCatalog()
end

function M.getCatalogMap()
    return _loadCatalog()
end

function M.findByName(name)
    if not name then return nil end
    return _loadCatalog()[tostring(name)]
end

function M.buildSprinklerItems()
    return M.buildInventorySprinklerItems()
end

local function _iterInventoryContainers()
    local out, seen = {}, {}
    local function add(c)
        if c and not seen[c] then
            seen[c] = true
            out[#out + 1] = c
        end
    end
    add(LP:FindFirstChildOfClass("Backpack"))
    add(LP:FindFirstChild("Backpack"))
    add(LP:FindFirstChild("TasRansel"))
    add(LP.Character)
    for _, ch in ipairs(LP:GetChildren()) do
        if ch:IsA("Folder") or ch:IsA("Model") or ch:IsA("Backpack") then
            local n = ch.Name:lower()
            if n:find("backpack") or n:find("ransel") or n:find("tas") or n:find("inventory") then
                add(ch)
            end
        end
    end
    return out
end

function M.buildInventorySprinklerItems()
    local counts = {}
    for _, container in ipairs(_iterInventoryContainers()) do
        for _, inst in ipairs(container:GetChildren()) do
            if inst:IsA("Tool") then
                local attr = inst:GetAttribute("Sprinkler")
                if attr ~= nil then
                    local name = tostring(attr)
                    if name ~= "" then
                        counts[name] = (counts[name] or 0) + 1
                    end
                end
            end
        end
    end

    local out = {}
    for name, count in pairs(counts) do
        local info = M.findByName(name)
        out[#out + 1] = {
            key   = name,
            name  = name,
            right = ("x%d"):format(count),
            raw   = info or { SprinklerName = name, Radius = 16 },
        }
    end
    table.sort(out, function(a, b)
        return tostring(a.name) < tostring(b.name)
    end)
    if #out == 0 then
        return { { key = "_none", name = "(No sprinklers in inventory)" } }
    end
    return out
end

function M.countInventorySprinklers(selected)
    selected = type(selected) == "table" and selected or {}
    local hasFilter = next(selected) ~= nil
    local total = 0
    for _, container in ipairs(_iterInventoryContainers()) do
        for _, inst in ipairs(container:GetChildren()) do
            if inst:IsA("Tool") then
                local attr = inst:GetAttribute("Sprinkler")
                if attr ~= nil then
                    local name = tostring(attr)
                    if name ~= "" and (not hasFilter or selected[name] == true) then
                        total += 1
                    end
                end
            end
        end
    end
    return total
end

-- Legacy catalog list (radius lookup still uses SprinklerData)
function M.buildCatalogSprinklerItems()
    local out = {}
    for _, info in pairs(_loadCatalog()) do
        out[#out + 1] = {
            key   = info.SprinklerName,
            name  = info.SprinklerName,
            right = info.Radius and info.Radius > 0 and ("R" .. tostring(info.Radius)) or nil,
            raw   = info,
        }
    end
    table.sort(out, function(a, b)
        return tostring(a.name) < tostring(b.name)
    end)
    return out
end

function M.getCoverageRadius(info)
    info = type(info) == "table" and info or M.findByName(info)
    local r = info and tonumber(info.Radius) or 0
    if r <= 0 then return 8 end
    -- SprinklerRadius part pakai Size = Vector3.new(Radius, ..., Radius) → diameter
    return r * 0.5
end

function M.getPlacementSpacing(info)
    info = type(info) == "table" and info or M.findByName(info)
    local r = info and tonumber(info.Radius) or 0
    if r <= 0 then return 16 end
    return r
end

G.SprinklerListView = M
_G.SprinklerListView = M

return M
 end,              required = false },
