local function _stripFruitSuffix(msg)
    return tostring(msg or "")
        :gsub("%s*%(%d+%)%s*$", "")
        :gsub("%s*·%s*collect%s+%d+(?:/%d+)?%s*", " · ")
        :gsub("%s*·%s*skipped%s+%d+(?:/%d+)?%s*", " · ")
        :gsub("%s*·%s*skip%s+%d+(?:/%d+)?%s*", " · ")
        :gsub("%s*·%s*backpack%s+%d+(?:/%d+)?%s*", " · ")
        :gsub("%s*·%s*max buah%s+%d+%s*", " · ")
        :gsub("%s*·%s*slots%s+%d+%s*", " · ")
        :gsub("%s*·%s*fruit%s+%d+(?:/%d+)?%s*$", "")
        :gsub("%s*·%s*$", "")
        :gsub("%s+$", "")
end

local function _composeStatusText(base, st)
    local msg = _stripFruitSuffix(base)
    if msg == "" then msg = STATUS_TEXT.idle or "Waiting" end
    -- Keep base short for UI row width
    if #msg > 28 then
        msg = msg:sub(1, 27) .. "…"
    end
    local pauseSkipAt = 0
    local pauseCollectAt = 0
    local pauseBackpackAt = 0
    if type(st) == "table" then
        pauseSkipAt = math.floor(tonumber(st.pauseSkippedFruit) or 0)
        pauseCollectAt = math.floor(tonumber(st.pauseCollectFruit) or 0)
        pauseBackpackAt = math.floor(tonumber(st.pauseBackpackTotal) or 0)
    else
        pauseSkipAt = math.floor(tonumber(G.AUTO_SPRINKLER_PAUSE_SKIPPED_FRUIT or rawget(_G, "AUTO_SPRINKLER_PAUSE_SKIPPED_FRUIT")) or 0)
        pauseCollectAt = math.floor(tonumber(G.AUTO_SPRINKLER_PAUSE_COLLECT_FRUIT or rawget(_G, "AUTO_SPRINKLER_PAUSE_COLLECT_FRUIT")) or 0)
        pauseBackpackAt = math.floor(tonumber(G.AUTO_SPRINKLER_PAUSE_BACKPACK_TOTAL or rawget(_G, "AUTO_SPRINKLER_PAUSE_BACKPACK_TOTAL")) or 0)
    end
    local skipN = math.floor(tonumber(lastSkippedCount) or 0)
    local collectN = math.floor(tonumber(lastCollectCount) or 0)
    local backpackN = math.floor(tonumber(lastBackpackCount) or 0)
    local slots = math.floor(tonumber(lastFruitSlots) or 0)
    local parts = { msg }
    if pauseCollectAt > 0 then
        parts[#parts + 1] = string.format("C%d/%d", collectN, pauseCollectAt)
    else
        parts[#parts + 1] = string.format("C%d", collectN)
    end
    if pauseSkipAt > 0 then
        parts[#parts + 1] = string.format("Sk%d/%d", skipN, pauseSkipAt)
    else
        parts[#parts + 1] = string.format("Sk%d", skipN)
    end
    if pauseBackpackAt > 0 then
        parts[#parts + 1] = string.format("Bp%d/%d", backpackN, pauseBackpackAt)
    else
        parts[#parts + 1] = string.format("Bp%d", backpackN)
    end
    parts[#parts + 1] = string.format("Mx%d", slots)
    return table.concat(parts, " · ")
end

local function _publishStatus(reason, detail)
    lastFailReason = tostring(reason or "")
    if lastFailReason == "garden_full" then
        return
    end
    -- Base pendek seperti AutoWatering — detail panjang (Super Sprinkler y+…)
    -- bikin label terlihat stuck & counter C/Sk ketutup truncate.
    local msg = _statusMessage(lastFailReason)
    if detail ~= nil and detail ~= ""
        and lastFailReason ~= "skip_pause"
        and lastFailReason ~= "collect_pause"
        and lastFailReason ~= "backpack_pause" then
        local d = tostring(detail)
        local yTag = d:match("y%+%d+")
        if yTag then
            msg = msg .. " " .. yTag
        elseif #d <= 16 then
            msg = msg .. " (" .. d .. ")"
        end
    end
    lastStatusBase = msg
    local full = _composeStatusText(msg)
    G.__GAG2_SPRINKLER_STATUS = full
    _G.__GAG2_SPRINKLER_STATUS = full
end

local function _log(...)
end

local function _fail(reason, ...)
    _publishStatus(reason)
    return false, reason
end

local function _writeMain(patch)
    local MAIN = rawget(_G, "MAIN") or G.MAIN
    if type(MAIN) ~= "table" then return end
    MAIN.auto = MAIN.auto or {}
    MAIN.auto.sprinkler = MAIN.auto.sprinkler or {}
    for k, v in pairs(patch) do
        MAIN.auto.sprinkler[k] = v
    end
    G.MAIN = MAIN
    _G.MAIN = MAIN
end

local function _normalizeSet(src)
    if type(src) ~= "table" then return {} end
    local out = {}
    for i = 1, #src do
        local v = src[i]
        if v ~= nil and tostring(v) ~= "" then
            out[tostring(v)] = true
        end
    end
    if next(out) then return out end
    for k, v in pairs(src) do
        if v == true or v == 1 or v == "true" then
            out[tostring(k)] = true
        end
    end
    return out
end

local function _canon(s)
    s = tostring(s or ""):lower():gsub("[^%w]+", "")
    return s
end

-- Base type tanpa akhiran "sprinkler" — exact only.
-- JANGAN pakai string.find: "commonsprinkler" ⊂ "uncommonsprinkler" → Common≈Uncommon (salah).
local function _sprinklerBaseCanon(s)
    local c = _canon(s)
    c = c:gsub("sprinklers$", ""):gsub("sprinkler$", "")
    return c
end

local function _sprinklerTypeMatch(a, b)
    if a == nil or b == nil then return false end
    if tostring(a) == tostring(b) then return true end
    local ca, cb = _canon(a), _canon(b)
    if ca == "" or cb == "" then return false end
    if ca == cb then return true end
    local ba, bb = _sprinklerBaseCanon(a), _sprinklerBaseCanon(b)
    if ba == "" or bb == "" then return false end
    return ba == bb
end

local function _isSameSprinklerType(a, b)
    return a ~= nil and b ~= nil and _sprinklerTypeMatch(a, b)
end

local function _nameMatchesSelected(name, selected)
    if name == nil or not next(selected) then return false end
    selected = _normalizeSet(selected)
    if selected[tostring(name)] or selected[_canon(name)] then return true end
    for key in pairs(selected) do
        if _isSameSprinklerType(name, key) then return true end
    end
    return false
end

local function _resolveSelectedSprinklers(st)
    st = type(st) == "table" and st or {}
    local fromGlobal = G.AUTO_SPRINKLER_SELECTED or rawget(_G, "AUTO_SPRINKLER_SELECTED")
    local normalized = _normalizeSet(fromGlobal)
    if next(normalized) then return normalized end

    normalized = _normalizeSet(st.sprinklers)
    if next(normalized) then return normalized end

    local MAIN = rawget(_G, "MAIN") or G.MAIN
    local arr = type(MAIN) == "table"
        and type(MAIN.auto) == "table"
        and type(MAIN.auto.sprinkler) == "table"
        and MAIN.auto.sprinkler.sprinklers
    if type(arr) == "table" then
        return _normalizeSet(arr)
    end
    return {}
end

local function _getSLV()
    return G.SprinklerListView or rawget(_G, "SprinklerListView")
end

local function _getShovel()
    return G.AutoShovel or G.AutoShovelModule or rawget(_G, "AutoShovel")
end

local function getSprinklerState()
    local MAIN = rawget(_G, "MAIN") or G.MAIN
    local st = MAIN and MAIN.auto and MAIN.auto.sprinkler
    st = type(st) == "table" and st or {}

    local sprinklers = _resolveSelectedSprinklers(st)

    local plants = G.AUTO_SPRINKLER_PLANTS_SELECTED
        or rawget(_G, "AUTO_SPRINKLER_PLANTS_SELECTED")
        or _normalizeSet(st.plants)

    local delay = tonumber(st.delay)
    if delay == nil then
        delay = tonumber(G.AUTO_SPRINKLER_DELAY or rawget(_G, "AUTO_SPRINKLER_DELAY")) or 2
    end
    if delay < LOOP_MIN_SEC then delay = LOOP_MIN_SEC end

    local settleDelay = tonumber(st.settleDelay)
    if settleDelay == nil then
        settleDelay = tonumber(G.AUTO_SPRINKLER_SETTLE_DELAY or rawget(_G, "AUTO_SPRINKLER_SETTLE_DELAY")) or 0
    end
    if settleDelay < 0 then settleDelay = 0 end

    local pauseSkippedFruit = tonumber(st.pauseSkippedFruit)
    if pauseSkippedFruit == nil then
        pauseSkippedFruit = tonumber(G.AUTO_SPRINKLER_PAUSE_SKIPPED_FRUIT or rawget(_G, "AUTO_SPRINKLER_PAUSE_SKIPPED_FRUIT")) or 0
    end
    pauseSkippedFruit = math.floor(pauseSkippedFruit)
    if pauseSkippedFruit < 0 then pauseSkippedFruit = 0 end

    local pauseCollectFruit = tonumber(st.pauseCollectFruit)
    if pauseCollectFruit == nil then
        pauseCollectFruit = tonumber(G.AUTO_SPRINKLER_PAUSE_COLLECT_FRUIT or rawget(_G, "AUTO_SPRINKLER_PAUSE_COLLECT_FRUIT")) or 0
    end
    pauseCollectFruit = math.floor(pauseCollectFruit)
    if pauseCollectFruit < 0 then pauseCollectFruit = 0 end

    local pauseBackpackTotal = tonumber(st.pauseBackpackTotal)
    if pauseBackpackTotal == nil then
        pauseBackpackTotal = tonumber(G.AUTO_SPRINKLER_PAUSE_BACKPACK_TOTAL or rawget(_G, "AUTO_SPRINKLER_PAUSE_BACKPACK_TOTAL")) or 0
    end
    pauseBackpackTotal = math.floor(pauseBackpackTotal)
    if pauseBackpackTotal < 0 then pauseBackpackTotal = 0 end

    local mode = tostring(G.AUTO_SPRINKLER_MODE or rawget(_G, "AUTO_SPRINKLER_MODE") or st.mode or "random"):lower()
    if mode ~= "near_plant" and mode ~= "location" and mode ~= "center" then mode = "random" end

    local locations = G.AUTO_SPRINKLER_LOCATIONS
        or rawget(_G, "AUTO_SPRINKLER_LOCATIONS")
        or st.locations
    locations = type(locations) == "table" and locations or {}

    local selectedLocations = G.AUTO_SPRINKLER_SELECTED_LOCATIONS
        or rawget(_G, "AUTO_SPRINKLER_SELECTED_LOCATIONS")
        or _normalizeSet(st.selectedLocations)

    local enabled = (G.AUTO_SPRINKLER_ENABLED == true)
        or (rawget(_G, "AUTO_SPRINKLER_ENABLED") == true)
        or (st.enabled == true)

    return {
        enabled            = enabled,
        sprinklers         = _normalizeSet(sprinklers),
        plants             = _normalizeSet(plants),
        mode               = mode,
        delay              = delay,
        settleDelay        = settleDelay,
        pauseSkippedFruit  = pauseSkippedFruit,
        pauseCollectFruit  = pauseCollectFruit,
        pauseBackpackTotal = pauseBackpackTotal,
        locations          = locations,
        selectedLocations  = selectedLocations,
    }
end

local function invalidateSprinklerCache()
    tickCache.existing = nil
    tickCache.existingAt = 0
    randomGrids = {}
end

local function invalidatePlantScanCache()
