    tickCache.targetsKey = nil
    tickCache.targetsAt = 0
    tickCache.areas = nil
    tickCache.areasAt = 0
    tickCache.rayParams = nil
    tickCache.rayOriginY = nil
    plantListCache.at = 0
    plantListCache.key = ""
    plantListCache.items = nil
end

local function invalidatePlacementCaches()
