local function _plantsFolderCount(plot)
    if not plot then return 0 end
    local folder = plot:FindFirstChild("Plants")
    return folder and #folder:GetChildren() or 0
end

local function computeSettleSec(plot, st)
    local user = tonumber(st and st.settleDelay)
    if user ~= nil and user > 0 then
        return math.clamp(user, 0.15, 5)
    end
    local n = _plantsFolderCount(plot)
    if n >= 500 then return 1.2
    elseif n >= 300 then return 1.0
    elseif n >= 200 then return 0.8
    elseif n >= 100 then return 0.55
    end
    return 0.35
end

local function getHarvestFilterCounts()
    -- Sama fallback dengan AutoWatering — modul sering expose sebagai AutoCollect
    local AC = G.AutoCollectFruit or G.CollectFruitModule or rawget(_G, "AutoCollectFruit")
        or G.AutoCollect or rawget(_G, "AutoCollect")
    if type(AC) ~= "table" then return 0, 0 end
    if type(AC.PeekHarvestBreakdown) == "function" then
        local ok, br = pcall(AC.PeekHarvestBreakdown, AC)
        if ok and type(br) == "table" then
            -- collect = semua buah siap ambil (tanpa filter AC)
            local collectN = math.max(0, math.floor(tonumber(br.total) or 0))
            local skipN = math.max(0, math.floor(tonumber(br.outFilter) or 0))
            return collectN, skipN
        end
    end
    if type(AC.PeekReadyCount) == "function" then
        local ok, n = pcall(AC.PeekReadyCount, AC)
        if ok then
            return math.max(0, math.floor(tonumber(n) or 0)), 0
        end
    end
    return 0, 0
end

local function countFruitSlots(plot)
    local now = os.clock()
    if (now - lastFruitSlotsAt) <= 2 and lastFruitSlots >= 0 then
        return lastFruitSlots
    end
    local total = 0
    if plot then
        local folder = plot:FindFirstChild("Plants")
        if folder then
            for _, plant in ipairs(folder:GetChildren()) do
                local locs = plant:FindFirstChild("FruitSpawnLocations")
                if locs then
                    total += #locs:GetChildren()
                end
            end
        end
    end
    lastFruitSlots = total
    lastFruitSlotsAt = now
    return total
end

-- Bukan local function — chunk main sudah di limit Luau 200 locals
function M.refreshStatusCounts(force, plot)
    local now = os.clock()
    local sc = M._statusCnt
    if type(sc) ~= "table" then
        sc = { at = 0, sec = 1.0 }
        M._statusCnt = sc
    end
    if not force and (now - (sc.at or 0)) < (sc.sec or 1.0) then
        return
    end
    sc.at = now

    -- getPlayerPlot didefinisikan lebih bawah; pakai plot arg / cache
    countFruitSlots(plot or cachedPlot)

    local collectN, skipN = getHarvestFilterCounts()
    lastCollectCount = collectN
    lastSkippedCount = skipN
    lastFruitCount = skipN
    lastBackpackCount = math.max(0, math.floor(tonumber(LP:GetAttribute("FruitCount")) or 0))
end

-- Pause bila collect / skipped / backpack total mencapai threshold (0=off).
local function checkSkippedFruitGate(st, plot)
    local pauseSkipAt = math.floor(tonumber(st and st.pauseSkippedFruit) or 0)
    local pauseCollectAt = math.floor(tonumber(st and st.pauseCollectFruit) or 0)
    local pauseBackpackAt = math.floor(tonumber(st and st.pauseBackpackTotal) or 0)
    M.refreshStatusCounts(true, plot)
    local collectN = lastCollectCount
    local skipN = lastSkippedCount
    local backpackN = lastBackpackCount

    if pauseCollectAt > 0 and collectN >= pauseCollectAt then
        skipGatePaused = true
        return false, "collect_pause", collectN
    end

    if pauseSkipAt > 0 and skipN >= pauseSkipAt then
        skipGatePaused = true
        return false, "skip_pause", skipN
    end

    if pauseBackpackAt > 0 and backpackN >= pauseBackpackAt then
        skipGatePaused = true
        return false, "backpack_pause", backpackN
    end

    skipGatePaused = false
    return true, nil, skipN
end

local collectPlantAreas

local function getCachedPlantAreas(plot, forceRefresh)
    if not plot then return {} end
    local now = os.clock()
    if not forceRefresh
        and tickCache.plot == plot
        and type(tickCache.areas) == "table" then
        local age = now - (tickCache.areasAt or 0)
        local ttl = (#tickCache.areas > 0) and PLANT_AREA_CACHE_SEC or EMPTY_AREA_CACHE_SEC
        if age <= ttl then
            return tickCache.areas
        end
    end
    if type(collectPlantAreas) ~= "function" then
        return {}
    end
    local areas = collectPlantAreas(plot)
    tickCache.plot = plot
    tickCache.areas = areas
    tickCache.areasAt = now
    tickCache.rayParams = nil
    tickCache.rayOriginY = nil
    return areas
end

local function getCachedRaycast(plot)
    local areas = getCachedPlantAreas(plot)
    if #areas == 0 then
        return nil, areas, 250
    end
    if tickCache.plot == plot and tickCache.rayParams then
        return tickCache.rayParams, areas, tickCache.rayOriginY or 250
    end
    local originY = 250
    for _, part in ipairs(areas) do
        if part:IsA("BasePart") then
            originY = math.max(originY, part.Position.Y + 80)
        end
    end
    local params = RaycastParams.new()
    params.FilterType = Enum.RaycastFilterType.Include
    params.FilterDescendantsInstances = areas
    tickCache.plot = plot
    tickCache.rayParams = params
    tickCache.rayOriginY = originY
    return params, areas, originY
end

local function snapToPlantAreaCached(plot, pos)
    if not plot or not pos then return nil end
    local params, _, originY = getCachedRaycast(plot)
    if not params then return pos end
    local hit = workspace:Raycast(
        Vector3.new(pos.X, originY, pos.Z),
        Vector3.new(0, -600, 0),
        params
    )
    if hit then
        local inst = hit.Instance
        if inst:IsDescendantOf(plot) then
            return hit.Position
        end
        local _, areas = getCachedRaycast(plot)
        for _, part in ipairs(areas) do
            if inst == part or inst:IsDescendantOf(part) or part:IsDescendantOf(inst) then
                return hit.Position
            end
        end
    end
    return pos
end

local function _findPlotInGardens(gardens, plotId)
    if not gardens or plotId == nil then return nil end
    local idStr = tostring(plotId)
    for _, name in ipairs({ "Plot" .. idStr, idStr, "Plot_" .. idStr }) do
        local plot = gardens:FindFirstChild(name)
        if plot then return plot end
    end
    return nil
end

----------------------------------------------------------------
local function getPlayerPlot()
    local now = os.clock()
    if cachedPlot and cachedPlot.Parent and (now - cachedPlotAt) <= PLOT_CACHE_SEC then
        return cachedPlot
    end

    if not Gardens or not Gardens.Parent then
        cachedPlot = nil
        cachedPlotAt = now
        return nil
    end

    local plotId = LP:GetAttribute("PlotId")
    if plotId ~= nil then
        local plot = _findPlotInGardens(Gardens, plotId)
        if plot then
            cachedPlot = plot
            cachedPlotAt = now
            return plot
        end
    end

    for _, plot in ipairs(Gardens:GetChildren()) do
        local owner = plot:GetAttribute("Owner") or plot:GetAttribute("OwnerId") or plot:GetAttribute("OwnerUserId")
        if owner ~= nil then
            if tostring(owner) == LP.Name or tonumber(owner) == LP.UserId then
                cachedPlot = plot
                cachedPlotAt = now
                return plot
            end
        end
    end

    cachedPlot = nil
    cachedPlotAt = now
    return nil
end

local function getPlotId(plot)
    local pid = LP:GetAttribute("PlotId")
    if pid ~= nil then
        local n = tonumber(pid)
        if n then return n end
    end
    if not plot then return nil end
    local n = tonumber(string.match(plot.Name, "%d+"))
    if n then return n end
    return nil
end

local function _describeRemote(remote)
    if typeof(remote) == "Instance" then
        return remote:GetFullName()
    end
    if type(remote) == "table" then
        for _, key in ipairs({ "Remote", "_remote", "remote", "Event", "_event" }) do
            local inner = remote[key]
            if typeof(inner) == "Instance" then
                return inner:GetFullName()
            end
        end
        return "Networking.Place.PlaceSprinkler"
    end
    return "MISSING"
end

local function _unwrapRemoteEvent(remote)
    if typeof(remote) == "Instance" then
        if remote:IsA("RemoteEvent") or remote:IsA("RemoteFunction") then
            return remote
        end
        return remote:FindFirstChildWhichIsA("RemoteEvent", true)
            or remote:FindFirstChildWhichIsA("RemoteFunction", true)
    end
    if type(remote) ~= "table" then return nil end
    for _, key in ipairs({ "Remote", "_remote", "remote", "Event", "_event", "RF", "RE" }) do
        local inner = remote[key]
        if inner then
            local found = _unwrapRemoteEvent(inner)
            if found then return found end
        end
    end
    return nil
end

local function _callPlaceRemote(remote, pos, sprinklerName, tool, plotId)
    if type(remote) ~= "table" and typeof(remote) ~= "Instance" then
        return false
    end

    local function tryFire(fn)
        local ok = pcall(fn)
        return ok
    end

    if type(remote.Fire) == "function" then
        if tryFire(function() remote:Fire(pos, sprinklerName, tool, plotId) end) then
            return true
        end
        if tryFire(function() remote:Fire(pos, sprinklerName, tool) end) then
            return true
        end
    end

    local re = _unwrapRemoteEvent(remote)
    if re and re:IsA("RemoteEvent") then
        if tryFire(function() re:FireServer(pos, sprinklerName, tool, plotId) end) then
            return true
        end
        if tryFire(function() re:FireServer(pos, sprinklerName, tool) end) then
            return true
        end
    end
    if re and re:IsA("RemoteFunction") then
        local ok = pcall(function() re:InvokeServer(pos, sprinklerName, tool, plotId) end)
        if ok then return true end
        ok = pcall(function() re:InvokeServer(pos, sprinklerName, tool) end)
        if ok then return true end
    end
    return false
end

local function _fireToolRemotes(tool, pos, sprinklerName, plotId)
    if not tool then return false end
    local roots = { tool }
    local char = LP.Character
    if char then roots[#roots + 1] = char end

    for _, root in ipairs(roots) do
        for _, desc in ipairs(root:GetDescendants()) do
            if desc:IsA("RemoteEvent") then
                local ok = pcall(function() desc:FireServer(pos, sprinklerName, plotId) end)
                if ok then return true end
                ok = pcall(function() desc:FireServer(pos, sprinklerName, tool, plotId) end)
                if ok then return true end
                ok = pcall(function() desc:FireServer(pos) end)
                if ok then return true end
            end
            if desc:IsA("RemoteFunction") then
                local ok = pcall(function() desc:InvokeServer(pos, sprinklerName, plotId) end)
                if ok then return true end
            end
        end
    end
    return false
end

local function _getPlaceRemote()
    if PlaceSprinkler and type(PlaceSprinkler.Fire) == "function" then
        return PlaceSprinkler
    end
    if type(Networking) == "table" and Networking.Place and Networking.Place.PlaceSprinkler then
        PlaceSprinkler = Networking.Place.PlaceSprinkler
        return PlaceSprinkler
    end
    return nil
end

local function plotIsPlaceable(plot)
    if not plot then return false end
    local myPlot = getPlayerPlot()
    return myPlot ~= nil and myPlot == plot
end

collectPlantAreas = function(plot)
    local list, seen = {}, {}

    local function add(inst)
        if inst and inst:IsA("BasePart") and not seen[inst] then
            seen[inst] = true
            list[#list + 1] = inst
        end
    end

    if Gardens and Gardens.Parent then
        local ok, parts = pcall(function()
            return Gardens:QueryDescendants("BasePart.PlantArea")
        end)
        if ok and type(parts) == "table" then
            for _, inst in ipairs(parts) do
                if inst:IsDescendantOf(plot) then
                    add(inst)
                end
            end
        end
    end

    if #list > 0 then return list end

    for _, inst in ipairs(CollectionService:GetTagged("PlantArea")) do
        if inst:IsDescendantOf(plot) then
            add(inst)
        end
    end

    if #list > 0 then return list end

    for _, desc in ipairs(plot:GetDescendants()) do
        if desc:IsA("BasePart") and desc.Name == "Can_Plant" then
            add(desc)
        end
    end

    return list
end

local function createPlantAreaParams(plot)
    local areas = getCachedPlantAreas(plot)
    local params = RaycastParams.new()
    params.FilterType = Enum.RaycastFilterType.Include
    params.FilterDescendantsInstances = areas
    return params, areas
end

local function snapToPlantArea(plot, pos)
    return snapToPlantAreaCached(plot, pos)
end

local function isOnPlantArea(plot, pos)
    return snapToPlantArea(plot, pos) ~= nil
end

local function isOnPlantArea(plot, pos)
    return snapToPlantArea(plot, pos) ~= nil
end

local function _getPlantAreaColumns(plot)
    local cols = {}
    if not plot then return cols end
    local visual = plot:FindFirstChild("Visual")
    if visual then
        for _, name in ipairs(PLANT_AREA_COLUMN_NAMES) do
            local part = visual:FindFirstChild(name)
            if part and part:IsA("BasePart") then
                cols[#cols + 1] = part
            end
        end
    end
    if #cols == 0 then
        for _, name in ipairs(PLANT_AREA_COLUMN_NAMES) do
            local part = plot:FindFirstChild(name, true)
            if part and part:IsA("BasePart") then
                cols[#cols + 1] = part
            end
        end
    end
    table.sort(cols, function(a, b)
        if math.abs(a.Position.X - b.Position.X) > 0.01 then
            return a.Position.X < b.Position.X
        end
        return a.Position.Z < b.Position.Z
    end)
    return cols
end

local function _findPlantAreaColumn(plot, name)
    if not plot or not name or name == "" then return nil end
    local visual = plot:FindFirstChild("Visual")
    if visual then
        local part = visual:FindFirstChild(name)
        if part and part:IsA("BasePart") then return part end
    end
    local part = plot:FindFirstChild(name, true)
    if part and part:IsA("BasePart") then return part end
    return nil
end

local function _findPlantAreaColumnAt(plot, worldPos)
    if not plot or not worldPos then return nil end
    for _, part in ipairs(_getPlantAreaColumns(plot)) do
        local lp = part.CFrame:PointToObjectSpace(worldPos)
        local halfX = part.Size.X * 0.5
        local halfZ = part.Size.Z * 0.5
        if math.abs(lp.X) <= halfX and math.abs(lp.Z) <= halfZ then
            return part
        end
    end
    return nil
end

local function _getPrimaryPlantArea(plot)
    local cols = _getPlantAreaColumns(plot)
    if #cols > 0 then return cols[1] end
    local areas = getCachedPlantAreas(plot)
    if #areas == 0 then return nil end
    local best, bestArea = nil, 0
    for _, part in ipairs(areas) do
        if part:IsA("BasePart") then
            local a = part.Size.X * part.Size.Z
            if a > bestArea then
                best = part
                bestArea = a
            end
        end
    end
    return best or areas[1]
end

local function _getPlotAreaCenter(plot)
    if not plot then return nil end
    local cols = _getPlantAreaColumns(plot)
    if #cols > 0 then
        local part = cols[1]
        return part.CFrame:PointToWorldSpace(Vector3.new(0, part.Size.Y * 0.5 + 0.05, 0))
    end
    local part = _getPrimaryPlantArea(plot)
    if part and part:IsA("BasePart") then
        return part.CFrame:PointToWorldSpace(Vector3.new(0, part.Size.Y * 0.5 + 0.05, 0))
    end
    return nil
end

local function _findPlantAreaAt(plot, worldPos)
    if not plot or not worldPos then return nil end
    local col = _findPlantAreaColumnAt(plot, worldPos)
    if col then return col end
    for _, part in ipairs(getCachedPlantAreas(plot)) do
        if part:IsA("BasePart") then
            local lp = part.CFrame:PointToObjectSpace(worldPos)
            local halfX = part.Size.X * 0.5
            local halfZ = part.Size.Z * 0.5
            if math.abs(lp.X) <= halfX and math.abs(lp.Z) <= halfZ then
                return part
            end
        end
    end
    return nil
end

local function _surfacePosOnPlantArea(plot, worldPos)
    if not plot or not worldPos then return worldPos end
    local part = _findPlantAreaAt(plot, worldPos) or _getPrimaryPlantArea(plot)
    if not part then return worldPos end
    local lp = part.CFrame:PointToObjectSpace(worldPos)
    local halfX = part.Size.X * 0.5
    local halfZ = part.Size.Z * 0.5
    lp = Vector3.new(
        math.clamp(lp.X, -halfX * 0.92, halfX * 0.92),
        part.Size.Y * 0.5 + 0.05,
        math.clamp(lp.Z, -halfZ * 0.92, halfZ * 0.92)
    )
    return part.CFrame:PointToWorldSpace(lp)
end

local function _resolveCenterPlacePos(plot, columnPart, worldPos)
    if not plot or not columnPart or not worldPos then return nil end
    local lp = columnPart.CFrame:PointToObjectSpace(worldPos)
    local halfX = columnPart.Size.X * 0.5
    local halfZ = columnPart.Size.Z * 0.5
    lp = Vector3.new(
        math.clamp(lp.X, -halfX * 0.92, halfX * 0.92),
        columnPart.Size.Y * 0.5 + 0.05,
        math.clamp(lp.Z, -halfZ * 0.92, halfZ * 0.92)
    )
    return columnPart.CFrame:PointToWorldSpace(lp)
end

local function _resolvePlacePos(plot, pos, opts)
    if not plot or not pos then return nil end
    opts = type(opts) == "table" and opts or {}
    if opts.columnPart then
        return _resolveCenterPlacePos(plot, opts.columnPart, pos)
    end
    pos = snapToPlantAreaCached(plot, pos) or pos
    return _surfacePosOnPlantArea(plot, pos)
end

local function _posKey(pos)
    if not pos then return "" end
    return string.format("%.1f:%.1f", pos.X, pos.Z)
end

local function _partCenterPos(part)
    if not part or not part:IsA("BasePart") then return nil end
    return part.CFrame:PointToWorldSpace(
        Vector3.new(0, part.Size.Y * 0.5 + 0.05, 0)
    )
end

local function _listGardenZones(plot)
    local zones = {}
    if not plot then return zones end
    for _, part in ipairs(_getPlantAreaColumns(plot)) do
        local pos = _partCenterPos(part)
        if pos then
            zones[#zones + 1] = {
                part = part,
                parts = { part },
                pos = pos,
                root = part,
            }
        end
    end
    return zones
end

local function _worldPosOnPlantArea(part, localX, localZ)
    if not part or not part:IsA("BasePart") then return nil end
    local lp = Vector3.new(localX, part.Size.Y * 0.5 + 0.05, localZ)
    return part.CFrame:PointToWorldSpace(lp)
end

local function _isInsidePlantAreaPart(part, worldPos, inset)
    inset = tonumber(inset) or RANDOM_GRID_INSET
    if not part or not worldPos then return false end
    local lp = part.CFrame:PointToObjectSpace(worldPos)
    local halfX = part.Size.X * 0.5 * inset
    local halfZ = part.Size.Z * 0.5 * inset
    return math.abs(lp.X) <= halfX and math.abs(lp.Z) <= halfZ
end

local function _isInsideGardenZone(parts, worldPos, inset)
    if not worldPos or type(parts) ~= "table" then return false end
    for _, part in ipairs(parts) do
        if _isInsidePlantAreaPart(part, worldPos, inset) then
            return true
        end
    end
    return false
end

local function _gardenZoneHasAnySprinkler(existing, parts)
    if type(existing) ~= "table" or type(parts) ~= "table" then return false end
    for _, s in ipairs(existing) do
        if s.pos and _isInsideGardenZone(parts, s.pos, 1.0) then
            return true
        end
    end
    return false
end

local function _centerHasAnySprinkler(existing, center)
    if not center or type(existing) ~= "table" then return false end
    local r2 = CENTER_SPRINKLER_RADIUS * CENTER_SPRINKLER_RADIUS
    for _, s in ipairs(existing) do
        if s.pos then
            local dx = s.pos.X - center.X
            local dz = s.pos.Z - center.Z
            if (dx * dx + dz * dz) <= r2 then
                return true
            end
        end
    end
    return false
end

local function _listPlantAreaCenters(plot)
    local centers = {}
    for _, zone in ipairs(_listGardenZones(plot)) do
        centers[#centers + 1] = zone.pos
    end
    return centers
end

local function _isInsideAnyPlantArea(plot, worldPos, inset)
    if not plot or not worldPos then return false end
    for _, part in ipairs(_getPlantAreaColumns(plot)) do
        if _isInsidePlantAreaPart(part, worldPos, inset) then
            return true
        end
    end
    for _, part in ipairs(getCachedPlantAreas(plot)) do
        if _isInsidePlantAreaPart(part, worldPos, inset) then
            return true
        end
    end
    return false
end

local function _isInsidePrimaryPlantArea(plot, worldPos, inset)
    return _isInsideAnyPlantArea(plot, worldPos, inset)
end

local function getSprinklerCatalogEntry(name)
    local slv = _getSLV()
    if slv and type(slv.findByName) == "function" then
        local ok, entry = pcall(slv.findByName, slv, name)
        if ok and type(entry) == "table" then return entry end
    end
    return { SprinklerName = tostring(name or ""), Radius = 16 }
end

local function getCoverageRadius(name)
    local slv = _getSLV()
    if slv and type(slv.getCoverageRadius) == "function" then
        local ok, r = pcall(slv.getCoverageRadius, slv, name)
        if ok and type(r) == "number" and r > 0 then return r end
    end
    local entry = getSprinklerCatalogEntry(name)
    local rad = tonumber(entry.Radius) or 16
    return rad * 0.5
end

local function getPlacementSpacing(name)
    local slv = _getSLV()
    if slv and type(slv.getPlacementSpacing) == "function" then
        local ok, s = pcall(slv.getPlacementSpacing, slv, name)
        if ok and type(s) == "number" and s > 0 then return s end
    end
    return tonumber(getSprinklerCatalogEntry(name).Radius) or 16
end

local function listExistingSprinklers(plot, forceRefresh)
    if not plot then return {} end

    local now = os.clock()
    if not forceRefresh
        and tickCache.plot == plot
        and type(tickCache.existing) == "table"
        and (now - (tickCache.existingAt or 0)) <= SPRINKLER_CACHE_SEC then
        return tickCache.existing
    end

    local out, seen = {}, {}

    local function addModel(model, name)
        if not model or seen[model] then return end
        seen[model] = true
        local pos = nil
        local ok, pivot = pcall(function()
            return model:GetPivot().Position
        end)
        if ok then pos = pivot end
        if not pos and model.PrimaryPart then
            pos = model.PrimaryPart.Position
        end
        if pos then
            local usePos = pos
            if model.PrimaryPart then
                usePos = model.PrimaryPart.Position
            end
            out[#out + 1] = {
                model  = model,
                pos    = usePos,
                name   = tostring(name or model.Name),
                radius = getCoverageRadius(name or model.Name),
            }
        end
    end

    local folder = plot:FindFirstChild("Sprinklers")
    if folder then
        for _, inst in ipairs(folder:GetChildren()) do
            if inst:IsA("Model") then
                addModel(
                    inst,
                    inst:GetAttribute("SprinklerName")
                        or inst:GetAttribute("Sprinkler")
                        or inst.Name
                )
            end
        end
    end

    for _, child in ipairs(plot:GetChildren()) do
        if child:IsA("Model") and sprinklerCatalog[child.Name] then
            addModel(child, child.Name)
        end
    end

    tickCache.plot = plot
    tickCache.existing = out
    tickCache.existingAt = now
    return out
end

local function isTooCloseToExisting(pos, existing, minGap)
    if not pos or type(existing) ~= "table" then return false end
    minGap = tonumber(minGap) or MIN_SPRINKLER_GAP
    for _, s in ipairs(existing) do
        if s.pos and (s.pos - pos).Magnitude < minGap then
            return true
        end
    end
    return false
end

local function isTooCloseToSprinkler(plot, pos, existing)
    existing = existing or (plot and listExistingSprinklers(plot))
    return isTooCloseToExisting(pos, existing, MIN_SPRINKLER_GAP)
end

local function isPlantCovered(pos, existing, coverageRadius, placingTypeName)
    for _, s in ipairs(existing) do
        if not placingTypeName or _isSameSprinklerType(s.name, placingTypeName) then
            local dist = (s.pos - pos).Magnitude
            local maxR = math.max(s.radius, coverageRadius)
            if dist <= maxR then
                return true
            end
        end
    end
    return false
end

-- Game client hanya cek jarak < 1 stud, bukan overlap radius coverage.
local function isValidSprinklerPos(pos, existing, _placingTypeName)
    if not pos then return false end
    return not isTooCloseToExisting(pos, existing, MIN_SPRINKLER_GAP)
end

local function _iterInventoryContainers()
    local out, seen = {}, {}
    local function add(c)
        if c and not seen[c] then
            seen[c] = true
            out[#out + 1] = c
        end
    end
    add(LP:FindFirstChildOfClass("Backpack"))
    add(LP:FindFirstChild("Backpack"))
    add(LP:FindFirstChild("TasRansel"))
    add(LP.Character)
    for _, ch in ipairs(LP:GetChildren()) do
        if ch:IsA("Folder") or ch:IsA("Model") or ch:IsA("Backpack") then
            local n = ch.Name:lower()
            if n:find("backpack") or n:find("ransel") or n:find("tas") or n:find("inventory") then
                add(ch)
            end
        end
    end
    return out
end

local function sprinklerMatchesTool(tool, selected)
    if not tool or not tool:IsA("Tool") then return false end
    local attr = tool:GetAttribute("Sprinkler")
    if attr == nil then return false end
    attr = tostring(attr)
    if not next(selected) then return false end
    if selected[attr] == true or selected[_canon(attr)] == true then return true end
    for key in pairs(selected) do
        if _isSameSprinklerType(attr, key) then return true end
    end
    return false
end

local function findSprinklerTools(selected)
    local found = {}
    for _, container in ipairs(_iterInventoryContainers()) do
        for _, inst in ipairs(container:GetChildren()) do
            if inst:IsA("Tool") and sprinklerMatchesTool(inst, selected) then
                found[#found + 1] = inst
            end
        end
    end
    return found
end

local function getSprinklerTypeName(tool)
    if not tool or not tool:IsA("Tool") then return nil end
    local attr = tool:GetAttribute("Sprinkler")
    if attr == nil then return nil end
    local name = tostring(attr)
    return (name ~= "") and name or nil
end

local function groupSprinklerToolsByType(selected)
    local groups = {}
    for _, tool in ipairs(findSprinklerTools(selected)) do
        local name = getSprinklerTypeName(tool)
        if name then
            local bucket = groups[name]
            if not bucket then
                bucket = {}
                groups[name] = bucket
            end
            bucket[#bucket + 1] = tool
        end
    end
    return groups
end

local function _resolveGroupName(name, groups)
    if not name or type(groups) ~= "table" then return nil end
    name = tostring(name)
    if groups[name] and #groups[name] > 0 then return name end
    local canon = _canon(name)
    for gname, tools in pairs(groups) do
        if #tools > 0 and (_canon(gname) == canon or _isSameSprinklerType(gname, name)) then
            return gname
        end
    end
    return nil
end

local function buildSprinklerTypeOrder(selected)
    selected = _normalizeSet(selected)
    local groups = groupSprinklerToolsByType(selected)
    local order, seen = {}, {}

    local function tryAdd(name)
        local gname = _resolveGroupName(name, groups)
        if gname and not seen[gname] then
            seen[gname] = true
            order[#order + 1] = gname
        end
    end

    local MAIN = rawget(_G, "MAIN") or G.MAIN
    local arr = type(MAIN) == "table"
        and type(MAIN.auto) == "table"
        and type(MAIN.auto.sprinkler) == "table"
        and MAIN.auto.sprinkler.sprinklers

    if type(arr) == "table" and #arr > 0 then
        for i = 1, #arr do
            tryAdd(arr[i])
        end
    end

    for name in pairs(selected) do
        tryAdd(name)
    end

    if next(selected) and #order == 0 then
        for gname, tools in pairs(groups) do
            if not seen[gname] and #tools > 0 and _nameMatchesSelected(gname, selected) then
                seen[gname] = true
                order[#order + 1] = gname
            end
        end
    end

    if not next(selected) and not next(seen) then
        for gname, tools in pairs(groups) do
            if not seen[gname] and #tools > 0 then
                seen[gname] = true
                order[#order + 1] = gname
            end
        end
    end

    table.sort(order)
    return order, groups
end

local function resetActiveSprinklerType()
    activeSprinklerType = nil
    typeRoundIndex = 1
    lastRoundSelKey = ""
    nearPlantScanIndex = 1
    invalidatePlacementCaches()
end

local function getAvailableSprinklerTypes(selected)
    local order, groups = buildSprinklerTypeOrder(selected)
    local avail = {}
    for _, name in ipairs(order) do
        if groups[name] and #groups[name] > 0 then
            avail[#avail + 1] = name
        end
    end
    return avail, groups, order
end

local function syncRoundRobinSelection(selected)
    local avail = select(1, getAvailableSprinklerTypes(selected))
    local selKey = table.concat(avail, "\0")
    if selKey ~= lastRoundSelKey then
        lastRoundSelKey = selKey
        typeRoundIndex = 1
    end
end

-- Multi-select: round-robin (1 each type per turn). Single type: keep placing that type.
local function resolveActiveSprinklerType(selected)
    local avail, groups = getAvailableSprinklerTypes(selected)
    if #avail == 0 then
        resetActiveSprinklerType()
        return nil, groups
    end

    syncRoundRobinSelection(selected)

    if #avail == 1 then
        activeSprinklerType = avail[1]
        return avail[1], groups
    end

    if typeRoundIndex > #avail or typeRoundIndex < 1 then
        typeRoundIndex = 1
    end

    local name = avail[typeRoundIndex]
    activeSprinklerType = name
    return name, groups
end

local function advanceSprinklerTypeRound(selected)
    local avail = select(1, getAvailableSprinklerTypes(selected))
    if #avail <= 1 then return end
    typeRoundIndex += 1
    if typeRoundIndex > #avail then
        typeRoundIndex = 1
    end
    _log("next round-robin type", avail[typeRoundIndex], "idx", typeRoundIndex)
end

local function findSprinklerToolOfType(selected, typeName)
    if not typeName then return nil end
    local _, groups = buildSprinklerTypeOrder(selected)
    local resolved = _resolveGroupName(typeName, groups)
    local tools = resolved and groups[resolved]
    if type(tools) ~= "table" or #tools == 0 then return nil end
    return tools[1]
end

local function countSprinklerToolsOfType(selected, typeName)
    if not typeName then return 0 end
    local _, groups = buildSprinklerTypeOrder(selected)
    local resolved = _resolveGroupName(typeName, groups)
    local tools = resolved and groups[resolved]
    return type(tools) == "table" and #tools or 0
end

local function ensureSprinklerEquipped(tool, equipWaitSec)
    if not tool or not tool:IsA("Tool") then return false end
    local char = LP.Character
    if not char then return false end
    if tool.Parent == char then return true end

    local hum = char:FindFirstChildOfClass("Humanoid")
    if not hum then return false end

    pcall(function() hum:EquipTool(tool) end)

    local deadline = os.clock() + (equipWaitSec or EQUIP_WAIT_BASE)
    while os.clock() < deadline do
        if tool.Parent == char then
            task.wait(0.05)
            return tool.Parent == char
        end
        task.wait(0.03)
    end
    return tool.Parent == char
end

local function unequipSprinklerTool(tool)
    local char = LP.Character
    if not char then return end
    local hum = char:FindFirstChildOfClass("Humanoid")
    if not hum then return end

    local equipped = tool
    if not (equipped and equipped:IsA("Tool") and equipped.Parent == char) then
        equipped = char:FindFirstChildOfClass("Tool")
        if not equipped and tool then
            equipped = char:FindFirstChild(tool.Name)
        end
    end

    if equipped and equipped:IsA("Tool") and equipped.Parent == char then
        pcall(function() hum:UnequipTools() end)
    end
end

local function onSprinklerPlaceSuccess(tool, ...)
    lastPlaceAt = os.clock()
    lastFailReason = ""
    sessionPlaced += 1
    _publishStatus("working", "x" .. tostring(sessionPlaced))
    invalidatePlacementCaches()
    unequipSprinklerTool(tool)
    _log(...)
    return true
end

local function _snapshotSprinklerKeys(plot)
    local keys, count = {}, 0
    local folder = plot and plot:FindFirstChild("Sprinklers")
    if folder then
        for _, child in ipairs(folder:GetChildren()) do
            if child:IsA("Model") then
                count += 1
                local sid = child:GetAttribute("SprinklerId")
                keys[sid ~= nil and tostring(sid) or child.Name] = true
            end
        end
    end
    return keys, count
end

local function _sprinklerPlaced(plot, pos, beforeKeys, beforeCount)
    if not plot then return false end

    local folder = plot:FindFirstChild("Sprinklers")
    if folder then
        for _, child in ipairs(folder:GetChildren()) do
            if child:IsA("Model") then
                local sid = child:GetAttribute("SprinklerId")
                local key = sid ~= nil and tostring(sid) or child.Name
                if not beforeKeys[key] then
                    local part = child.PrimaryPart
                        or child:FindFirstChildWhichIsA("BasePart", true)
                    if part and pos and (part.Position - pos).Magnitude <= 3 then
                        return true
                    end
                    if not pos then
                        return true
                    end
                end
            end
        end
    end

    local nowCount = #listExistingSprinklers(plot, true)
    return nowCount > (tonumber(beforeCount) or 0)
end

local function placeSprinklerAt(pos, tool, plotId, plot, st)
    local remote = _getPlaceRemote()
    if not remote then return false, "no_remote" end
    if not tool or not tool.Parent then return false, "no_tool" end
    if os.clock() - lastPlaceAt < PLACE_COOLDOWN then return false, "cooldown" end

    local sprinklerAttr = tool:GetAttribute("Sprinkler")
    if sprinklerAttr == nil then return false, "no_attr" end
    sprinklerAttr = tostring(sprinklerAttr)

    plot = plot or getPlayerPlot()
    plotId = tonumber(plotId) or getPlotId(plot)
    if not plotId then return false, "no_plot_id" end

    local settleSec = computeSettleSec(plot, st)
    local equipWaitSec = math.max(EQUIP_WAIT_BASE, settleSec + 0.25)
    local prePlaceSec = math.max(PRE_PLACE_BASE, settleSec * 0.35)
    local confirmSec = math.max(PLACE_CONFIRM_BASE, settleSec * 2)

    if not ensureSprinklerEquipped(tool, equipWaitSec) then
        return _fail("equip_fail", tool.Name)
    end
    task.wait(prePlaceSec)

    local char = LP.Character
    if char then
        local equipped = char:FindFirstChild(tool.Name)
        if equipped and equipped:IsA("Tool") then
            tool = equipped
        end
    end

    local beforeKeys, beforeCount = _snapshotSprinklerKeys(plot)
    local firePos = pos

    local function waitPlaced()
        local deadline = os.clock() + confirmSec
        while os.clock() < deadline do
            if plot and _sprinklerPlaced(plot, firePos, beforeKeys, beforeCount) then
                return true
            end
            if not tool.Parent then
                invalidateSprinklerCache()
                if plot and _sprinklerPlaced(plot, firePos, beforeKeys, beforeCount) then
                    return true
                end
            end
            task.wait(0.05)
        end
        return false
    end

    local function fireAndWait(name)
        if not _callPlaceRemote(remote, firePos, name, tool, plotId) then
            return false
        end
        return waitPlaced()
    end

    if fireAndWait(sprinklerAttr) then
        return onSprinklerPlaceSuccess(tool, "placed", sprinklerAttr, firePos, plotId)
    end

    if tool.Name ~= sprinklerAttr and fireAndWait(tool.Name) then
        return onSprinklerPlaceSuccess(tool, "placed", tool.Name, firePos, plotId)
    end

    if _fireToolRemotes(tool, firePos, sprinklerAttr, plotId) and waitPlaced() then
        return onSprinklerPlaceSuccess(tool, "placed via tool remote", sprinklerAttr, firePos, plotId)
    end

    invalidateSprinklerCache()
    unequipSprinklerTool(tool)
    return _fail("place_rejected", firePos, "plotId=" .. tostring(plotId))
end

local function countSprinklerTools(selected)
    return #findSprinklerTools(selected)
end

local function tryPlaceAt(plot, pos, st, typeName, existing, opts)
    if not plotIsPlaceable(plot) then
        return _fail("no_owner", plot and plot.Name)
    end

    existing = existing or listExistingSprinklers(plot)

    typeName = typeName or resolveActiveSprinklerType(st.sprinklers)
    if not typeName then
        return _fail("no_type")
    end

    pos = _resolvePlacePos(plot, pos, opts)
    if not pos then
        return _fail("no_surface")
    end
    if not isValidSprinklerPos(pos, existing, typeName) then
        if isTooCloseToExisting(pos, existing, MIN_SPRINKLER_GAP) then
            return _fail("too_close", pos)
        end
        return _fail("no_surface")
    end

    local plotId = getPlotId(plot)
    if not plotId then
        return _fail("no_plot_id")
    end

    local tool = findSprinklerToolOfType(st.sprinklers, typeName)
    if not tool then
        advanceSprinklerTypeRound(st.sprinklers)
        return _fail("no_tool", typeName)
    end

    local ok, err = placeSprinklerAt(pos, tool, plotId, plot, st)
    if ok then
        advanceSprinklerTypeRound(st.sprinklers)
        return true
    end
    return false, err or lastFailReason
end

local function applyNearPlaceYOffset(basePos, yOffset, plot)
    if not basePos then return nil end
    local boosted = basePos + Vector3.new(0, yOffset, 0)
    return snapToPlantAreaCached(plot, boosted) or boosted
end

-- near_plant: equip → place → deteksi sukses; gagal → naikkan Y posisi, retry (no TP)
local function tryPlaceAtWithRetry(plot, basePos, st, typeName, existing)
    if not plotIsPlaceable(plot) then
        return false, "no_owner"
    end

    existing = existing or listExistingSprinklers(plot)
    typeName = typeName or resolveActiveSprinklerType(st.sprinklers)
    if not typeName then
        return false, "no_type"
    end

    local plotId = getPlotId(plot)
    if not plotId then
        return false, "no_plot_id"
    end

    local tool = findSprinklerToolOfType(st.sprinklers, typeName)
    if not tool then
        return false, "no_tool"
    end

    local yOffset = 0
    local lastErr = "place_rejected"

    for attempt = 1, NEAR_Y_RETRY_ATTEMPTS do
        if not running then
            return false, "stopped"
        end

        local pos = applyNearPlaceYOffset(basePos, yOffset, plot)
        if not pos then
            lastErr = "no_surface"
        elseif not isValidSprinklerPos(pos, existing, typeName) then
            lastErr = isTooCloseToExisting(pos, existing, MIN_SPRINKLER_GAP) and "too_close" or "no_surface"
        else
            _publishStatus("working", tostring(typeName) .. " y+" .. tostring(yOffset))
            local ok, err = placeSprinklerAt(pos, tool, plotId, plot, st)
            if ok then
                return true
            end
            lastErr = err or lastFailReason or "place_rejected"
            _log("near retry", typeName, "attempt", attempt, "y+", yOffset, "err", lastErr)
        end

        if attempt < NEAR_Y_RETRY_ATTEMPTS then
            yOffset = math.min(NEAR_Y_RETRY_MAX, yOffset + NEAR_Y_RETRY_STEP)
            local waitLeft = PLACE_COOLDOWN - (os.clock() - lastPlaceAt)
            if waitLeft > 0 then
                task.wait(waitLeft)
            end
        end
    end

    return false, lastErr
end

local function filterUncoveredTargetsAnyType(targets, existing, selected)
    local avail = select(1, getAvailableSprinklerTypes(selected))
    local out = {}
    for _, entry in ipairs(targets) do
        for _, typeName in ipairs(avail) do
            local coverage = getCoverageRadius(typeName)
            if not isPlantCovered(entry.pos, existing, coverage, typeName) then
                out[#out + 1] = entry
                break
            end
        end
    end
    return out
end

local function getPlantAreasBounds(plot)
    local areas = getCachedPlantAreas(plot)
    if #areas == 0 then return nil end

    local minX, maxX, minZ, maxZ = math.huge, -math.huge, math.huge, -math.huge
    for _, part in ipairs(areas) do
        if part:IsA("BasePart") then
            local cf, size = part.CFrame, part.Size
            local hx, hz = size.X * 0.5, size.Z * 0.5
            for _, corner in ipairs({
                cf * Vector3.new(-hx, 0, -hz),
                cf * Vector3.new(hx, 0, -hz),
                cf * Vector3.new(-hx, 0, hz),
                cf * Vector3.new(hx, 0, hz),
            }) do
                minX = math.min(minX, corner.X)
                maxX = math.max(maxX, corner.X)
                minZ = math.min(minZ, corner.Z)
                maxZ = math.max(maxZ, corner.Z)
            end
        end
    end

    if minX == math.huge then return nil end
    return minX, maxX, minZ, maxZ
end

local function buildRandomGridForPart(part, plot, spacing, existing, placingTypeName)
    local points = {}
    if not part or not part:IsA("BasePart") then return points end
    spacing = tonumber(spacing) or 16
    spacing = math.max(spacing, MIN_SPRINKLER_GAP + 0.5)
    existing = existing or listExistingSprinklers(plot)

    local inset = RANDOM_GRID_INSET
    local halfX = part.Size.X * 0.5 * inset
    local halfZ = part.Size.Z * 0.5 * inset
    if halfX <= 0 or halfZ <= 0 then return points end

    local cols = math.max(1, math.floor((halfX * 2) / spacing))
    local rows = math.max(1, math.floor((halfZ * 2) / spacing))
    local spanX = math.min(halfX * 2, cols * spacing)
    local spanZ = math.min(halfZ * 2, rows * spacing)
    local startX = -spanX * 0.5 + spacing * 0.5
    local startZ = halfZ - spacing * 0.5

    for row = 0, rows - 1 do
        local localZ = startZ - row * spacing
        for col = 0, cols - 1 do
            local localX = startX + col * spacing
            local raw = _worldPosOnPlantArea(part, localX, localZ)
            local pos = raw and _resolvePlacePos(plot, raw)
            if pos
                and _isInsidePlantAreaPart(part, pos, inset)
                and isValidSprinklerPos(pos, existing, placingTypeName) then
                points[#points + 1] = pos
            end
        end
    end

    if #points == 0 then
        local centerRaw = _worldPosOnPlantArea(part, 0, 0)
        local center = centerRaw and _resolvePlacePos(plot, centerRaw)
        if center
            and _isInsidePlantAreaPart(part, center, inset)
            and isValidSprinklerPos(center, existing, placingTypeName) then
            points[1] = center
        end
    end

    return points
end

local function buildRandomGrid(plot, spacing, existing, placingTypeName)
    spacing = tonumber(spacing) or 16
    existing = existing or listExistingSprinklers(plot)

    local points, seen = {}, {}
    for _, part in ipairs(getCachedPlantAreas(plot)) do
        for _, pos in ipairs(buildRandomGridForPart(part, plot, spacing, existing, placingTypeName)) do
            local key = _posKey(pos)
            if not seen[key] then
                seen[key] = true
                points[#points + 1] = pos
            end
        end
    end
    return points
end

local CROSS_TYPE_RING_STEPS = 12

-- Posisi di sekitar sprinkler jenis lain (jarak 1 stud) — untuk multi-select di garden kecil.
local function buildCrossTypeRingPositions(plot, existing, placingTypeName)
    local out = {}
    if not plot or not placingTypeName or type(existing) ~= "table" then
        return out
    end

    local ringDist = math.max(CROSS_TYPE_MIN_GAP + 0.08, MIN_SPRINKLER_GAP + 0.08)
    for _, s in ipairs(existing) do
        if s.pos and s.name and not _isSameSprinklerType(s.name, placingTypeName) then
            for layer = 1, 2 do
                local dist = ringDist * layer
                for i = 0, CROSS_TYPE_RING_STEPS - 1 do
                    local angle = (math.pi * 2 * i) / CROSS_TYPE_RING_STEPS
                    local raw = s.pos + Vector3.new(
                        math.cos(angle) * dist,
                        0,
                        math.sin(angle) * dist
                    )
                    local pos = snapToPlantAreaCached(plot, raw)
                        or _surfacePosOnPlantArea(plot, raw)
                    if pos and isValidSprinklerPos(pos, existing, placingTypeName) then
                        out[#out + 1] = pos
                    end
                end
            end
        end
    end
    return out
end

local function buildPlacementCandidates(plot, typeName, existing)
    existing = existing or listExistingSprinklers(plot)
    local spacing = getPlacementSpacing(typeName)
    -- Random mode: grid saja (jarak penuh), tanpa ring 1 stud di samping sprinkler lain
    return buildRandomGrid(plot, spacing, existing, typeName)
end

local function getRandomGridState(plot, typeName, existing)
    existing = existing or listExistingSprinklers(plot)
    local spacing = getPlacementSpacing(typeName)
    local areas = getCachedPlantAreas(plot)
    local key = plot.Name .. "|" .. typeName .. "|" .. tostring(spacing)
        .. "|n=" .. tostring(#existing) .. "|a=" .. tostring(#areas)
    local entry = randomGrids[typeName]
    if not entry or entry.key ~= key or (#entry.points == 0 and #areas > 0) then
        entry = {
            key = key,
            points = buildPlacementCandidates(plot, typeName, existing),
            idx = 1,
        }
        randomGrids[typeName] = entry
    end
    return entry
end

local function getPlantTypeKey(plant)
    local AS = _getShovel()
    if AS and type(AS.GetPlantTypeKey) == "function" then
        local ok, key = pcall(AS.GetPlantTypeKey, AS, plant)
        if ok and key then return tostring(key) end
    end
    return tostring(
        plant:GetAttribute("SeedName")
            or plant:GetAttribute("ConfigPathName")
            or plant:GetAttribute("CorePartName")
            or plant:GetAttribute("FruitType")
            or plant.Name
    )
end

local function getPlantGroundPos(plant)
    if plant:IsA("BasePart") then return plant.Position end
    local ok, pos = pcall(function()
        return plant:GetPivot().Position
    end)
    if ok and typeof(pos) == "Vector3" then return pos end
    local part = plant:FindFirstChildWhichIsA("BasePart", true)
    return part and part.Position or nil
end

local function listTargetPlants(plot, selectedPlants, forceRefresh)
    if not plot or not next(selectedPlants) then return {} end

    local folder = plot:FindFirstChild("Plants")
    if not folder then return {} end

    local plantCount = #folder:GetChildren()
    local selKey = tostring(plantCount)
    for k in pairs(selectedPlants) do
        selKey = selKey .. "|" .. tostring(k)
    end

    local now = os.clock()
    if not forceRefresh
        and tickCache.plot == plot
        and tickCache.targetsKey == selKey
        and type(tickCache.targets) == "table"
        and (now - (tickCache.targetsAt or 0)) <= PLANT_SCAN_CACHE_SEC then
        return tickCache.targets
    end

    local out = {}
    for _, plant in ipairs(folder:GetChildren()) do
        if plant:IsA("Model") then
            local key = getPlantTypeKey(plant)
            if selectedPlants[key] or selectedPlants[_canon(key)] then
                local pos = getPlantGroundPos(plant)
                if pos then
                    out[#out + 1] = { plant = plant, key = key, pos = pos }
                end
            end
        end
    end

    tickCache.plot = plot
    tickCache.targets = out
    tickCache.targetsKey = selKey
    tickCache.targetsAt = now
    return out
end

local function hasUncoveredTargets(targets, existing, coverage, placingTypeName)
    for _, entry in ipairs(targets) do
        if not isPlantCovered(entry.pos, existing, coverage, placingTypeName) then
            return true
        end
    end
    return false
end

local function filterUncoveredTargets(targets, existing, coverage, placingTypeName)
    local out = {}
    for _, entry in ipairs(targets) do
        if not isPlantCovered(entry.pos, existing, coverage, placingTypeName) then
            out[#out + 1] = entry
        end
    end
    return out
end

local function findPlacementNearPlant(plot, plantPos, coverageRadius, existing, placingTypeName, opts)
    opts = type(opts) == "table" and opts or {}
    local slotCount = math.max(1, math.floor(tonumber(opts.slotCount) or 1))
    local slotIndex = math.max(1, math.floor(tonumber(opts.slotIndex) or 1))
    local coverage = math.max(tonumber(coverageRadius) or 8, MIN_SPRINKLER_GAP + 0.05)

    local function tryAt(raw)
        if not raw then return nil end
        local pos = snapToPlantAreaCached(plot, raw)
        if not pos then return nil end
        if not isValidSprinklerPos(pos, existing, placingTypeName) then return nil end
        local dx = pos.X - plantPos.X
        local dz = pos.Z - plantPos.Z
        if (dx * dx + dz * dz) <= (coverage * coverage) then
            return pos
        end
        return nil
    end

    -- Pack radius: semua type (N) muat di ring dengan gap >= ~1 stud
    local packR = MIN_SPRINKLER_GAP + 0.08
    if slotCount > 1 then
        packR = (MIN_SPRINKLER_GAP + 0.08) / (2 * math.sin(math.pi / slotCount))
    end
    packR = math.min(packR, coverage * 0.9)

    local baseAngle = ((slotIndex - 1) / slotCount) * (math.pi * 2)

    -- 1) Slot reserved (ring packing) + sedikit radius/angle nudge — ringan
    for _, mul in ipairs({ 1, 1.2, 1.45, 1.75, 2.2 }) do
        local r = math.min(math.max(packR * mul, MIN_SPRINKLER_GAP + 0.05), coverage * 0.92)
        local hit = tryAt(plantPos + Vector3.new(math.cos(baseAngle) * r, 0, math.sin(baseAngle) * r))
        if hit then return hit end
        for _, jitter in ipairs({ 0.18, -0.18, 0.35, -0.35 }) do
            local a = baseAngle + jitter
            hit = tryAt(plantPos + Vector3.new(math.cos(a) * r, 0, math.sin(a) * r))
            if hit then return hit end
        end
    end

    -- 2) Fallback padat tapi terbatas: 12 arah × beberapa radius
    local r0 = math.max(packR, MIN_SPRINKLER_GAP + 0.05)
    local rMax = coverage * 0.95
    local step = math.max(0.4, (rMax - r0) / 4)
    local steps = 12
    for r = r0, rMax + 0.001, step do
        for i = 0, steps - 1 do
            local a = (math.pi * 2 * i) / steps + slotIndex * 0.13
            local hit = tryAt(plantPos + Vector3.new(math.cos(a) * r, 0, math.sin(a) * r))
            if hit then return hit end
        end
    end

    return tryAt(plantPos)
end

local function findNearPlantBasePos(plot, plantPos, typeName, existing, opts)
    existing = existing or listExistingSprinklers(plot)
    local coverage = getCoverageRadius(typeName)
    local pos = findPlacementNearPlant(plot, plantPos, coverage, existing, typeName, opts)
    if pos and isValidSprinklerPos(pos, existing, typeName) then
        return pos
    end

    for _, ringPos in ipairs(buildCrossTypeRingPositions(plot, existing, typeName)) do
        if isValidSprinklerPos(ringPos, existing, typeName) then
            local dx = ringPos.X - plantPos.X
            local dz = ringPos.Z - plantPos.Z
            if (dx * dx + dz * dz) <= (coverage * coverage) then
                return ringPos
            end
        end
    end

    return pos
end

----------------------------------------------------------------
-- location mode (multi location x multi sprinkler type)
----------------------------------------------------------------

local function _notifyLocationsChanged()
    if type(G.__GAG2_ON_SPRINKLER_LOCATIONS_CHANGED) == "function" then
        pcall(G.__GAG2_ON_SPRINKLER_LOCATIONS_CHANGED)
    end
end

local function _writeLocationLocal(entry, plot, worldPos)
    if type(entry) ~= "table" or not plot or not worldPos then return false end
    entry.x = worldPos.X
    entry.y = worldPos.Y
    entry.z = worldPos.Z
    local part = _findPlantAreaColumnAt(plot, worldPos) or _findPlantAreaAt(plot, worldPos) or _getPrimaryPlantArea(plot)
    if part and part:IsA("BasePart") then
        local lp = part.CFrame:PointToObjectSpace(worldPos)
        local halfX = math.max(part.Size.X * 0.5, 0.01)
        local halfZ = math.max(part.Size.Z * 0.5, 0.01)
        entry.areaName = part.Name
        entry.nu = lp.X / halfX
        entry.nv = lp.Z / halfZ
    end
    return true
end

local function _worldFromLocationLocal(entry, plot)
    if type(entry) ~= "table" or not plot then return nil end
    local nu = tonumber(entry.nu)
    local nv = tonumber(entry.nv)
    if nu ~= nil and nv ~= nil then
        local part = nil
        local areaName = tostring(entry.areaName or "")
        if areaName ~= "" then
            part = _findPlantAreaColumn(plot, areaName)
            if not part then
                for _, p in ipairs(getCachedPlantAreas(plot)) do
                    if p:IsA("BasePart") and p.Name == areaName then
                        part = p
                        break
                    end
                end
            end
        end
        part = part or _getPrimaryPlantArea(plot)
        if part then
            local halfX = part.Size.X * 0.5
            local halfZ = part.Size.Z * 0.5
            nu = math.clamp(nu, -0.92, 0.92)
            nv = math.clamp(nv, -0.92, 0.92)
            local lp = Vector3.new(nu * halfX, part.Size.Y * 0.5 + 0.05, nv * halfZ)
            return part.CFrame:PointToWorldSpace(lp)
        end
    end
    return nil
end

local function vecFromSaved(entry, plot)
    if type(entry) ~= "table" then return nil end
    plot = plot or getPlayerPlot()
    if plot then
        local fromLocal = _worldFromLocationLocal(entry, plot)
        if fromLocal then
            return _resolvePlacePos(plot, fromLocal) or fromLocal
        end
    end
    local x = tonumber(entry.x)
    local y = tonumber(entry.y)
    local z = tonumber(entry.z)
    if x and y and z then return Vector3.new(x, y, z) end
    return nil
end

local function locationById(st, id)
    id = tostring(id or "")
    if id == "" then return nil end
    local locations = type(st.locations) == "table" and st.locations or {}
    for _, entry in ipairs(locations) do
        if type(entry) == "table" and tostring(entry.id) == id then
            return entry
        end
    end
    return nil
end

local function hasSprinklerTypeNearLocation(existing, basePos, typeName)
    if not basePos or not typeName or type(existing) ~= "table" then return false end
    local r2 = LOCATION_MATCH_RADIUS * LOCATION_MATCH_RADIUS
    for _, s in ipairs(existing) do
        if s.pos and s.name and _isSameSprinklerType(s.name, typeName) then
            local dx = s.pos.X - basePos.X
            local dz = s.pos.Z - basePos.Z
            if (dx * dx + dz * dz) <= r2 then
                return true
            end
        end
    end
    return false
end

local function hasSelectedSprinklerNearLocation(existing, basePos, selected)
    if not basePos or not next(selected) or type(existing) ~= "table" then return false end
    local r2 = LOCATION_MATCH_RADIUS * LOCATION_MATCH_RADIUS
    for _, s in ipairs(existing) do
        if s.pos and s.name and _nameMatchesSelected(s.name, selected) then
            local dx = s.pos.X - basePos.X
            local dz = s.pos.Z - basePos.Z
            if (dx * dx + dz * dz) <= r2 then
                return true
            end
        end
    end
    return false
end

local function buildLocationPlaceCandidates(plot, basePos, existing, typeName, typeIndex)
    local out = {}
    if not plot or not basePos then return out end
    typeIndex = tonumber(typeIndex) or 0
    existing = existing or listExistingSprinklers(plot)

    local function addCandidate(raw)
        local pos = _resolvePlacePos(plot, raw)
        if pos and isValidSprinklerPos(pos, existing, typeName) then
            out[#out + 1] = pos
        end
    end

    if typeIndex <= 0 then
        addCandidate(basePos)
    end

    local baseDist = math.max(LOCATION_RING_DIST, MIN_SPRINKLER_GAP + 0.25)
    for layer = 0, LOCATION_RING_LAYERS - 1 do
        local dist = baseDist + (typeIndex * 0.4) + (layer * 0.35)
        for i = 0, LOCATION_RING_STEPS - 1 do
            local angle = (math.pi * 2 * i) / LOCATION_RING_STEPS + (typeIndex * 0.55)
            addCandidate(basePos + Vector3.new(
                math.cos(angle) * dist,
                0,
                math.sin(angle) * dist
            ))
        end
    end

    return out
end

-- Center mode: satu sprinkler di tengah tiap PlantAreaColumn.
local function buildCenterPlaceCandidates(plot, center, existing, typeName, columnPart)
    local out = {}
    if not plot or not center or not typeName or not columnPart then return out end
    existing = existing or listExistingSprinklers(plot)

    if _centerHasAnySprinkler(existing, center) then
        return out
    end

    local pos = _resolveCenterPlacePos(plot, columnPart, center)
    if pos
        and _isInsidePlantAreaPart(columnPart, pos, 0.92)
        and isValidSprinklerPos(pos, existing, typeName) then
        out[1] = pos
    end

    return out
end

local function tryPlaceLocationItem(plot, item, st, existing)
    if type(item) ~= "table" or not item.basePos or not item.typeName then
        return false
    end

    existing = existing or listExistingSprinklers(plot)

    if hasSprinklerTypeNearLocation(existing, item.basePos, item.typeName) then
        return false
    end
    if not findSprinklerToolOfType(st.sprinklers, item.typeName) then
        return false
    end

    local candidates = buildLocationPlaceCandidates(
        plot,
        item.basePos,
        existing,
        item.typeName,
        item.typeIndex or 0
    )
    if #candidates == 0 then
        return _fail("too_close")
    end

    for ci = 1, #candidates do
        local pos = candidates[ci]
        if isValidSprinklerPos(pos, existing, item.typeName) then
            local ok = tryPlaceAt(plot, pos, st, item.typeName, existing)
            if ok then
                return true
            end

            local reason = lastFailReason
            if reason == "no_tool" or reason == "equip_fail" or reason == "no_remote" or reason == "no_plot_id" then
                return false
            end

            invalidateSprinklerCache()
            existing = listExistingSprinklers(plot, true)

            if reason == "cooldown" then
                local waitLeft = PLACE_COOLDOWN - (os.clock() - lastPlaceAt)
                if waitLeft > 0 then
                    task.wait(waitLeft)
                end
            end
        end
    end

    return false
end

local function buildLocationWork(st, plot, existing)
    existing = existing or (plot and listExistingSprinklers(plot)) or {}
    local selected = st.selectedLocations
    if type(selected) ~= "table" or next(selected) == nil then
        return {}
    end

    local cacheKey = plot and plot.Name or ""
    for id in pairs(selected) do
        cacheKey = cacheKey .. "|" .. tostring(id)
    end
    local avail = select(1, getAvailableSprinklerTypes(st.sprinklers))
    cacheKey = cacheKey .. "|" .. table.concat(avail, ",") .. "|n=" .. tostring(#existing)

    if locationWorkCache and locationWorkCache.key == cacheKey then
        return locationWorkCache.work
    end

    local work = {}
    local locIds = {}
    for id in pairs(selected) do
        locIds[#locIds + 1] = tostring(id)
    end
    table.sort(locIds)

    for _, locId in ipairs(locIds) do
        local entry = locationById(st, locId)
        local basePos = vecFromSaved(entry, plot)
        if basePos then
            local typeIdx = 0
            for _, typeName in ipairs(avail) do
                if not hasSprinklerTypeNearLocation(existing, basePos, typeName)
                    and findSprinklerToolOfType(st.sprinklers, typeName) then
                    local candidates = buildLocationPlaceCandidates(
                        plot, basePos, existing, typeName, typeIdx
                    )
                    if #candidates > 0 then
                        work[#work + 1] = {
                            locId = locId,
                            typeName = typeName,
                            basePos = basePos,
                            typeIndex = typeIdx,
                        }
                        typeIdx += 1
                    end
                end
            end
        end
    end

    locationWorkCache = { key = cacheKey, work = work, idx = 1 }
    return work
end

local function gardenHasWork(plot, st, existing, typeName)
    if not plot or not st or not typeName then return false end

    if st.mode == "location" then
        local work = buildLocationWork(st, plot, existing)
        return type(work) == "table" and #work > 0
    end

    if st.mode == "near_plant" then
        if not next(st.plants) then return false end
        local targets = listTargetPlants(plot, st.plants)
        if #targets == 0 then return false end
        local coverage = getCoverageRadius(typeName)
        return hasUncoveredTargets(targets, existing, coverage, typeName)
    end

    if st.mode == "center" then
        if not resolveActiveSprinklerType(st.sprinklers) then return false end
        for _, zone in ipairs(_listGardenZones(plot)) do
            if not _centerHasAnySprinkler(existing, zone.pos) then
                return true
            end
        end
        return false
    end

    local gridState = getRandomGridState(plot, typeName, existing)
    return gridState and #gridState.points > 0
end

local function gardenHasWorkForAnyType(plot, st, existing)
    local avail = select(1, getAvailableSprinklerTypes(st.sprinklers))
    for _, typeName in ipairs(avail) do
        if gardenHasWork(plot, st, existing, typeName) then
            return true
        end
    end
    return false
end

local function tryLocationMode(st, plot, existing)
    if not next(st.selectedLocations) then
        return _fail("no_locations")
    end

    existing = existing or listExistingSprinklers(plot)
    local work = buildLocationWork(st, plot, existing)
    if #work == 0 then
        return _fail("garden_full")
    end

    if not locationWorkCache or locationWorkCache.idx == nil then
        locationWorkCache = { key = locationWorkCache and locationWorkCache.key, work = work, idx = 1 }
    end

    local idx = locationWorkCache.idx or 1
    local tried = 0
    local maxTry = math.min(#work, 12)

    while tried < maxTry do
        if idx > #work then idx = 1 end
        local item = work[idx]
        idx += 1
        tried += 1
        if type(item) == "table" and item.basePos and item.typeName then
            local ok = tryPlaceLocationItem(plot, item, st, existing)
            if ok then
                if type(locationWorkCache) ~= "table" then
                    locationWorkCache = { work = work, idx = idx, key = nil }
                else
                    locationWorkCache.work = work
                    locationWorkCache.idx = idx
                    locationWorkCache.key = nil
                end
                return true
            end
        end
    end

    if type(locationWorkCache) == "table" then
        locationWorkCache.idx = idx
    end
    return false
end

local function _getStandingPlotPosition(plot)
    local char = LP.Character
    local hrp = char and char:FindFirstChild("HumanoidRootPart")
    if not hrp or not plot then return nil end

    local areas = getCachedPlantAreas(plot)
    if #areas == 0 then return nil end

    local params = RaycastParams.new()
    params.FilterType = Enum.RaycastFilterType.Include
    params.FilterDescendantsInstances = areas

    local hit = workspace:Raycast(hrp.Position + Vector3.new(0, 10, 0), Vector3.new(0, -40, 0), params)
    if hit and hit.Instance:IsDescendantOf(plot) then
        return hit.Position
    end

    for _, part in ipairs(areas) do
        if part:IsA("BasePart") then
            local lp = part.CFrame:PointToObjectSpace(hrp.Position)
            local halfX = part.Size.X * 0.55
            local halfZ = part.Size.Z * 0.55
            if math.abs(lp.X) <= halfX and math.abs(lp.Z) <= halfZ then
                return Vector3.new(
                    hrp.Position.X,
                    part.Position.Y + part.Size.Y * 0.5 + 0.05,
                    hrp.Position.Z
                )
            end
        end
    end
    return nil
end

local function _commitSaveLocation(pos)
    if not pos then return false end

    local MAIN = rawget(_G, "MAIN") or G.MAIN
    if type(MAIN) ~= "table" then return false end

    MAIN.auto = MAIN.auto or {}
    MAIN.auto.sprinkler = MAIN.auto.sprinkler or {}

    local id = ("loc_%d"):format(math.floor(os.clock() * 1000))
    local locations = type(MAIN.auto.sprinkler.locations) == "table" and MAIN.auto.sprinkler.locations or {}
    local row = { id = id }
    _writeLocationLocal(row, getPlayerPlot(), pos)
    locations[#locations + 1] = row
    MAIN.auto.sprinkler.locations = locations

    local selected = type(MAIN.auto.sprinkler.selectedLocations) == "table"
        and MAIN.auto.sprinkler.selectedLocations or {}
    local found = false
    for _, sid in ipairs(selected) do
        if tostring(sid) == id then
            found = true
            break
        end
    end
    if not found then
        selected[#selected + 1] = id
    end
    MAIN.auto.sprinkler.selectedLocations = selected
    MAIN.auto.sprinkler.saveLocation = false

    G.MAIN = MAIN
    _G.MAIN = MAIN
    G.AUTO_SPRINKLER_LOCATIONS = locations
    _G.AUTO_SPRINKLER_LOCATIONS = locations
    G.AUTO_SPRINKLER_SELECTED_LOCATIONS = _normalizeSet(selected)
    _G.AUTO_SPRINKLER_SELECTED_LOCATIONS = G.AUTO_SPRINKLER_SELECTED_LOCATIONS
    G.AUTO_SPRINKLER_SAVE_LOCATION = false
    _G.AUTO_SPRINKLER_SAVE_LOCATION = false

    locationWorkCache = nil
    _notifyLocationsChanged()
    _log("saved loc", id, pos)
    return true, id
end

function M.SaveStandingLocation()
    local plot = getPlayerPlot()
    if not plot then
        return false
    end

    local pos = _getStandingPlotPosition(plot)
    if not pos then
        return false
    end

    return _commitSaveLocation(pos)
end

M.saveStandingLocation = M.SaveStandingLocation

function M.DeleteLocation(id)
    id = tostring(id or "")
    if id == "" then return false end

    local MAIN = rawget(_G, "MAIN") or G.MAIN
    if type(MAIN) ~= "table" then return false end

    MAIN.auto = MAIN.auto or {}
    MAIN.auto.sprinkler = MAIN.auto.sprinkler or {}
    local locations = type(MAIN.auto.sprinkler.locations) == "table" and MAIN.auto.sprinkler.locations or {}

    local removed = false
    for i = #locations, 1, -1 do
        local entry = locations[i]
        if type(entry) == "table" and tostring(entry.id) == id then
            table.remove(locations, i)
            removed = true
        end
    end
    if not removed then return false end

    local selected = {}
    for _, sid in ipairs(type(MAIN.auto.sprinkler.selectedLocations) == "table" and MAIN.auto.sprinkler.selectedLocations or {}) do
        if tostring(sid) ~= id then
            selected[#selected + 1] = sid
        end
    end

    MAIN.auto.sprinkler.locations = locations
    MAIN.auto.sprinkler.selectedLocations = selected
    G.MAIN = MAIN
    _G.MAIN = MAIN
    G.AUTO_SPRINKLER_LOCATIONS = locations
    _G.AUTO_SPRINKLER_LOCATIONS = locations
    G.AUTO_SPRINKLER_SELECTED_LOCATIONS = _normalizeSet(selected)
    _G.AUTO_SPRINKLER_SELECTED_LOCATIONS = G.AUTO_SPRINKLER_SELECTED_LOCATIONS

    locationWorkCache = nil
    _notifyLocationsChanged()
    return true
end

M.deleteLocation = M.DeleteLocation

local function centerNeedsSprinkler(st, plot, existing, zone)
    if not zone or not st then return false end
    existing = existing or listExistingSprinklers(plot)
    if _centerHasAnySprinkler(existing, zone.pos) then
        return false
    end
    local typeName = resolveActiveSprinklerType(st.sprinklers)
    return typeName and findSprinklerToolOfType(st.sprinklers, typeName) ~= nil
end

local function tryCenterMode(st, plot, existing)
    existing = existing or listExistingSprinklers(plot, true)
    local typeName = resolveActiveSprinklerType(st.sprinklers)
    if not typeName then
        return _fail("no_type")
    end

    local zones = _listGardenZones(plot)
    if #zones == 0 then
        return _fail("no_plant_area")
    end

    if centerAreaCursor > #zones or centerAreaCursor < 1 then
        centerAreaCursor = 1
    end

    local anyNeed = false
    for _, zone in ipairs(zones) do
        if centerNeedsSprinkler(st, plot, existing, zone) then
            anyNeed = true
            break
        end
    end
    if not anyNeed then
        return _fail("garden_full")
    end

    for pass = 1, #zones do
        local idx = ((centerAreaCursor - 1 + pass - 1) % #zones) + 1
        local zone = zones[idx]
        if not centerNeedsSprinkler(st, plot, existing, zone) then
            continue
        end

        local candidates = buildCenterPlaceCandidates(
            plot, zone.pos, existing, typeName, zone.part
        )
        if #candidates == 0 then
            continue
        end

        for _, pos in ipairs(candidates) do
            _publishStatus("working", "center · " .. tostring(typeName))
            local ok = tryPlaceAt(plot, pos, st, typeName, existing, { columnPart = zone.part })
            if ok then
                centerAreaCursor = idx + 1
                if centerAreaCursor > #zones then
                    centerAreaCursor = 1
                end
                return true
            end
            if lastFailReason == "no_tool" or lastFailReason == "equip_fail"
                or lastFailReason == "no_remote" or lastFailReason == "no_plot_id" then
                return false
            end
            invalidateSprinklerCache()
            existing = listExistingSprinklers(plot, true)
        end
    end
    return _fail("place_rejected")
end

local function tryRandomMode(st, plot, existing, typeName)
    typeName = typeName or resolveActiveSprinklerType(st.sprinklers)
    if not typeName then
        return false
    end

    existing = existing or listExistingSprinklers(plot)
    local gridState = getRandomGridState(plot, typeName, existing)
    local randomGrid = gridState.points
    local randomIdx = gridState.idx

    if #randomGrid == 0 then
        return false
    end

    local tried = 0
    local maxTry = math.min(#randomGrid, 24)
    while tried < maxTry do
        if randomIdx > #randomGrid then randomIdx = 1 end
        local pos = randomGrid[randomIdx]
        randomIdx += 1
        tried += 1

        if pos and _isInsideAnyPlantArea(plot, pos)
            and isValidSprinklerPos(pos, existing, typeName) then
            local ok = tryPlaceAt(plot, pos, st, typeName, existing)
            if ok then
                table.remove(randomGrid, randomIdx - 1)
                if randomIdx > #randomGrid then randomIdx = 1 end
                gridState.idx = randomIdx
                gridState.points = randomGrid
                return true
            end
        end
    end

    gridState.idx = randomIdx
    return false
end

local function tryNearPlantMode(st, plot, existing)
    if not next(st.plants) then
        return false
    end

    existing = existing or listExistingSprinklers(plot)
    local avail = select(1, getAvailableSprinklerTypes(st.sprinklers))
    if #avail == 0 then
        return false
    end

    local targets = listTargetPlants(plot, st.plants)
    local uncovered = filterUncoveredTargetsAnyType(targets, existing, st.sprinklers)
    if #uncovered == 0 then
        return false
    end

    local batch = NEAR_PLANT_BATCH
    local n = #uncovered
    local start = nearPlantScanIndex
    if start < 1 or start > n then start = 1 end

    for i = 0, batch - 1 do
        if not running then break end

        local idx = ((start - 1 + i) % n) + 1
        local entry = uncovered[idx]
        local sessionPlaced = 0
        local typeCount = #avail

        for ti, typeName in ipairs(avail) do
            if not running then break end

            local coverage = getCoverageRadius(typeName)
            if isPlantCovered(entry.pos, existing, coverage, typeName) then
                continue
            end

            local slotOpts = { slotIndex = ti, slotCount = typeCount }
            local basePos = findNearPlantBasePos(plot, entry.pos, typeName, existing, slotOpts)
            if not basePos then
                -- Retry sekali dengan slot count lebih besar (spread lebih lebar)
                slotOpts.slotCount = math.max(typeCount + 2, 6)
                basePos = findNearPlantBasePos(plot, entry.pos, typeName, existing, slotOpts)
            end

            if not basePos then
                _log("near plant skip", typeName, "no base pos")
            else
                _publishStatus("working", tostring(typeName) .. " · " .. tostring(entry.key or "?"))
                local ok = tryPlaceAtWithRetry(plot, basePos, st, typeName, existing)
                if ok then
                    sessionPlaced += 1
                    existing = listExistingSprinklers(plot, true)
                else
                    -- Posisi tadinya valid tapi gagal di Y/server — coba 1 base alternatif
                    slotOpts.slotIndex = ((ti + 2) % typeCount) + 1
                    local altPos = findNearPlantBasePos(plot, entry.pos, typeName, existing, slotOpts)
                    if altPos and (altPos - basePos).Magnitude > 0.2 then
                        ok = tryPlaceAtWithRetry(plot, altPos, st, typeName, existing)
                        if ok then
                            sessionPlaced += 1
                            existing = listExistingSprinklers(plot, true)
                        end
                    end
                    if not ok then
                        _log("near plant fail", typeName, entry.key, lastFailReason)
                    end
                end

                if sessionPlaced > 0 then
                    local waitLeft = PLACE_COOLDOWN - (os.clock() - lastPlaceAt)
                    if waitLeft > 0 then
                        task.wait(waitLeft)
                    end
                end
            end
        end

        nearPlantScanIndex = (idx % n) + 1
        if sessionPlaced > 0 then
            return true
        end
    end

    nearPlantScanIndex = (start % n) + 1
    return false
end

local function computeLoopDelay(st, plot)
    local base = tonumber(st.delay) or 2
    if base < LOOP_MIN_SEC then base = LOOP_MIN_SEC end

    if lastFailReason == "garden_full" then
        return math.max(base, IDLE_BACKOFF_SEC)
    end

    if lastFailReason == "no_plant_area" then
        return math.max(base, 2)
    end

    if lastFailReason == "place_rejected" or lastFailReason == "no_surface" then
        return math.max(base, 1.5)
    end

    local n = _plantsFolderCount(plot)
    if n >= 500 then return math.max(base, 3.5)
    elseif n >= 300 then return math.max(base, 3)
    elseif n >= LARGE_GARDEN_PLANTS then return math.max(base, 2.5)
    elseif n >= 100 then return math.max(base, 1.5)
    end
    return base
end

-- Cari jenis berikutnya yang masih punya slot place (multi-select).
local function resolveSprinklerTypeWithWork(plot, st, existing, startName)
    local avail = select(1, getAvailableSprinklerTypes(st.sprinklers))
    if #avail == 0 then return nil end
    if #avail == 1 then
        local name = avail[1]
        if gardenHasWork(plot, st, existing, name) then
            return name
        end
        return nil
    end

    if startName and gardenHasWork(plot, st, existing, startName) then
        return startName
    end

    local startIdx = 1
    for i, name in ipairs(avail) do
        if name == startName then
            startIdx = i
            break
        end
    end

    for step = 1, #avail do
        local idx = ((startIdx - 1 + step) % #avail) + 1
        local name = avail[idx]
        if gardenHasWork(plot, st, existing, name) then
            typeRoundIndex = idx
            activeSprinklerType = name
            return name
        end
    end
    return nil
end

local function resolveSprinklerSelection(selected)
    return _normalizeSet(selected)
end

local function tick(st)
    st = st or getSprinklerState()
    st = {
        enabled           = st.enabled,
        sprinklers        = resolveSprinklerSelection(st.sprinklers),
        plants            = st.plants,
        mode              = st.mode,
        delay             = st.delay,
        settleDelay       = st.settleDelay,
        pauseSkippedFruit = st.pauseSkippedFruit,
        pauseCollectFruit = st.pauseCollectFruit,
        pauseBackpackTotal = st.pauseBackpackTotal,
        locations         = st.locations,
        selectedLocations = st.selectedLocations,
    }

    if not st.enabled then
        return _fail("idle")
    end

    local plotEarly = getPlayerPlot()
    local gateOk, gateReason, skipN = checkSkippedFruitGate(st, plotEarly)
    if not gateOk then
        _publishStatus(gateReason, skipN)
        return false
    end

    if countSprinklerTools(st.sprinklers) == 0 then
        return _fail("no_inventory_tools")
    end

    local plot = plotEarly
    if not plot then
        return _fail("no_plot")
    end

    local areas = getCachedPlantAreas(plot)
    if #areas == 0 then
        invalidatePlantScanCache()
        areas = getCachedPlantAreas(plot, true)
        if #areas == 0 then
            return _fail("no_plant_area")
        end
    end

    local existing = listExistingSprinklers(plot, true)
    local ok = false

    if st.mode == "near_plant" then
        local typeName = resolveActiveSprinklerType(st.sprinklers)
        if not typeName then
            return _fail("no_type")
        end

        if not next(st.plants) then
            return _fail("garden_full")
        end
        local targets = listTargetPlants(plot, st.plants)
        if #targets == 0 then
            return _fail("garden_full")
        end

        local hasWork = false
        for _, name in ipairs(select(1, getAvailableSprinklerTypes(st.sprinklers))) do
            if gardenHasWork(plot, st, existing, name) then
                hasWork = true
                break
            end
        end
        if not hasWork then
            return _fail("garden_full")
        end

        ok = tryNearPlantMode(st, plot, existing)
    elseif st.mode == "location" then
        if #select(1, getAvailableSprinklerTypes(st.sprinklers)) == 0 then
            return _fail("no_type")
        end
        ok = tryLocationMode(st, plot, existing)
    elseif st.mode == "center" then
        if #select(1, getAvailableSprinklerTypes(st.sprinklers)) == 0 then
            return _fail("no_type")
        end
        ok = tryCenterMode(st, plot, existing)
    else
        local typeName = resolveActiveSprinklerType(st.sprinklers)
        if not typeName then
            return _fail("no_type")
        end
        typeName = resolveSprinklerTypeWithWork(plot, st, existing, typeName)
        if not typeName then
            return _fail("garden_full")
        end
        ok = tryRandomMode(st, plot, existing, typeName)
    end

    if ok then
        _publishStatus("working", "x" .. tostring(sessionPlaced))
    elseif lastFailReason == "" then
        _publishStatus("place_rejected")
    end
    return ok
end

-- gardenNeedsSprinkler / mainLoop / warmInitialScan → M.* (hemat local limit 200)
function M.gardenNeedsSprinkler(plot, st)
    if not plot or not st then return false end
    local existing = listExistingSprinklers(plot)
    return gardenHasWorkForAnyType(plot, st, existing)
end

function M.mainLoop(myId)
    _log("loop start", myId)
    local lastWarnAt = 0
    while running and loopId == myId do
        local st = getSprinklerState()
        local waitSec = st.delay
        if st.enabled then
            local ok, err = pcall(tick, st)
            if not ok then
                _publishStatus("error", tostring(err))
                local now = os.clock()
                if now - lastWarnAt > 8 then
                    lastWarnAt = now
                end
            end
            local plot = getPlayerPlot()
            waitSec = computeLoopDelay(st, plot)
            if not ok and lastFailReason ~= "garden_full" and lastFailReason ~= "no_plant_area" then
                waitSec = st.delay
            end
        else
            _publishStatus("idle")
        end
        task.wait(waitSec)
    end
    _log("loop end", myId)
end

function M.warmInitialScan()
    for attempt = 1, 8 do
        if not running then return end
        local plot = getPlayerPlot()
        if plot then
            local ok, err = pcall(function()
                invalidatePlantScanCache()
                getCachedPlantAreas(plot, true)
                listExistingSprinklers(plot, true)
                local st = getSprinklerState()
                if next(st.plants) then
                    listTargetPlants(plot, st.plants, true)
                end
            end)
            local areas = getCachedPlantAreas(plot)
            if ok and #areas > 0 then
                return
            end
        end
        task.wait(0.4)
    end
end

