function M.SetEnabled(on)
    on = (on == true)
    G.AUTO_SPRINKLER_ENABLED = on
    _G.AUTO_SPRINKLER_ENABLED = on
    _writeMain({ enabled = on })

    if on then
        sessionPlaced = 0
        invalidateAllCaches()
        resetActiveSprinklerType()
        skipGatePaused = false
        lastFruitSlotsAt = 0
        _publishStatus("idle")
        task.spawn(M.warmInitialScan)
        if not running then
            running = true
            loopId += 1
            local myId = loopId
            task.spawn(function() M.mainLoop(myId) end)
        end
    else
        running = false
        loopId += 1
        skipGatePaused = false
        unequipSprinklerTool(nil)
        resetActiveSprinklerType()
        centerAreaCursor = 1
        _publishStatus("idle")
    end
end

