function M.PrintDiagnostics()
    local lines = {}
    local function add(s)
        lines[#lines + 1] = s
    end

    local st = getSprinklerState()
    add("=== GAG2 Auto Sprinkler Debug ===")
    add("enabled: " .. tostring(st.enabled))
    add("mode: " .. tostring(st.mode))
    add("delay: " .. tostring(st.delay))
    add("tools in bag: " .. tostring(countSprinklerTools(st.sprinklers)))
    local avail = select(1, getAvailableSprinklerTypes(st.sprinklers))
    add("available types: " .. tostring(#avail) .. (#avail > 0 and (" (" .. table.concat(avail, ", ") .. ")") or ""))
    add("selected types: " .. tostring(next(st.sprinklers) and "yes" or "all"))

    local plot = getPlayerPlot()
    local areas = plot and collectPlantAreas(plot) or {}
    add("plot: " .. (plot and plot:GetFullName() or "NIL"))
    if plot then
        add("Owner attr: " .. tostring(plot:GetAttribute("Owner")))
        add("plotId: " .. tostring(getPlotId(plot)))
        add("placeable: " .. tostring(plotIsPlaceable(plot)))
        add("PlantArea parts: " .. tostring(#areas))
    end

    local remote = _getPlaceRemote()
    add("PlaceSprinkler: " .. _describeRemote(remote))
    local catCount = 0
    for _ in pairs(sprinklerCatalog) do catCount += 1 end
    add("sprinkler catalog entries: " .. tostring(catCount))

    local name = resolveActiveSprinklerType(st.sprinklers)
    add("active type: " .. tostring(name))
    if plot and name then
        local existing = listExistingSprinklers(plot)
        add("existing on plot: " .. tostring(#existing))
        local spacing = getPlacementSpacing(name)
        local grid = buildPlacementCandidates(plot, name, existing)
        add("random grid spots: " .. tostring(#grid))
        if #grid > 0 then
            add("sample spot: " .. tostring(grid[1]))
        end
        add("needs sprinkler: " .. tostring(M.gardenNeedsSprinkler(plot, st)))
        if st.mode == "near_plant" then
            add("target plants: " .. tostring(#listTargetPlants(plot, st.plants)))
        elseif st.mode == "center" then
            local zones = _listGardenZones(plot)
            add("PlantArea tiles: " .. tostring(#areas))
            add("garden zones: " .. tostring(#zones))
            if #zones > 0 then
                local zone = zones[1]
                add("zone center[1]: " .. tostring(zone.pos))
                add("zone root[1]: " .. tostring(zone.root and zone.root.Name or "?"))
                add("zone needs sprinkler: "
                    .. tostring(centerNeedsSprinkler(st, plot, existing, zone)))
                add("center active type: " .. tostring(resolveActiveSprinklerType(st.sprinklers)))
            end
        end
    end

    add("last fail: " .. tostring(lastFailReason ~= "" and lastFailReason or "(none)"))
    add("running loop: " .. tostring(running))

    local msg = table.concat(lines, "\n")
    return msg
end

M.printDiagnostics = M.PrintDiagnostics

function M.TryDebugPlace()
    M.SetDebug(true)
    local st = getSprinklerState()
    local plot = getPlayerPlot()
    if not plot then
        M.PrintDiagnostics()
        return false
    end

    local name = resolveActiveSprinklerType(st.sprinklers)
    if not name then
        M.PrintDiagnostics()
        return false
    end

    local grid = buildPlacementCandidates(plot, name, listExistingSprinklers(plot))
    if #grid == 0 then
        M.PrintDiagnostics()
        return false
    end

    local ok = tryPlaceAt(plot, grid[1], st, name)
    M.PrintDiagnostics()
    return ok == true
end

M.tryDebugPlace = M.TryDebugPlace

function M.BuildGardenPlantItems()
    local AS = _getShovel()
    if AS and type(AS.BuildGardenPlantItems) == "function" then
        local ok, items = pcall(AS.BuildGardenPlantItems, AS)
        if ok and type(items) == "table" and #items > 0 then
            return items
        end
    end

    local plot = getPlayerPlot()
    if not plot then
        return { { key = "_none", name = "(Plot not found)" } }
    end

    local folder = plot:FindFirstChild("Plants")
    if not folder then
        return { { key = "_none", name = "(No plants in garden)" } }
    end

    local plantCount = #folder:GetChildren()
    local cacheKey = plot.Name .. "|" .. tostring(plantCount)
    local now = os.clock()
    if plantListCache.items
        and plantListCache.key == cacheKey
        and (now - plantListCache.at) <= PLANT_LIST_CACHE_SEC then
        return plantListCache.items
    end

    local groups = {}
    for _, plant in ipairs(folder:GetChildren()) do
        if plant:IsA("Model") then
            local key = getPlantTypeKey(plant)
            local g = groups[key]
            if not g then
                g = { key = key, name = key, count = 0 }
                groups[key] = g
            end
            g.count += 1
        end
    end

    local out = {}
    for _, g in pairs(groups) do
        out[#out + 1] = {
            key  = g.key,
            name = ("%s x %d"):format(g.name, g.count),
        }
    end
    table.sort(out, function(a, b) return a.name < b.name end)
    if #out == 0 then
        out[1] = { key = "_none", name = "(No plants in garden)" }
    end

    plantListCache.at = now
    plantListCache.key = cacheKey
    plantListCache.items = out
