    SP_STATE.selectedLocations = type(SP_STATE.selectedLocations) == "table" and SP_STATE.selectedLocations or {}
    SP_STATE.mode = tostring(SP_STATE.mode or "random"):lower()
    if SP_STATE.mode ~= "near_plant" and SP_STATE.mode ~= "location" and SP_STATE.mode ~= "center" then
        SP_STATE.mode = "random"
    end
