    local AUTO_SPRINKLER_SELECTED = cleanSelectedMap(arrayToMap(SP_STATE.sprinklers))
    local AUTO_SPRINKLER_PLANTS_SELECTED = cleanSelectedMap(arrayToMap(SP_STATE.plants))
    local AUTO_SPRINKLER_LOCATIONS_SELECTED = cleanSelectedMap(arrayToMap(SP_STATE.selectedLocations))

