        local n = tonumber(SP_STATE.pauseCollectFruit)
        return (n ~= nil) and n or 0
    end

    local function pauseBackpackDisplay()
        local n = tonumber(SP_STATE.pauseBackpackTotal)
        return (n ~= nil) and n or 0
    end

    local function buildLocationItems()
        local items = {}
        local locations = SP_STATE.locations
        if type(locations) ~= "table" then return items end
        for i, entry in ipairs(locations) do
            if type(entry) == "table" and entry.id then
                local plx = tonumber(entry.plx)
                local plz = tonumber(entry.plz)
                local nu = tonumber(entry.nu)
                local nv = tonumber(entry.nv)
                local ax = tonumber(entry.ax)
                local az = tonumber(entry.az)
                local lx = tonumber(entry.lx)
                local lz = tonumber(entry.lz)
                local x = tonumber(entry.x) or 0
                local z = tonumber(entry.z) or 0
                local label
                if plx and plz then
                    label = ("Loc %d (plot %.0f, %.0f)"):format(i, plx, plz)
                elseif nu and nv then
                    label = ("Loc %d (%.0f%%, %.0f%%)"):format(i, nu * 100, nv * 100)
                elseif ax and az then
                    label = ("Loc %d (tile %.0f, %.0f)"):format(i, ax, az)
                elseif lx and lz then
                    label = ("Loc %d (rel %.0f, %.0f)"):format(i, lx, lz)
                else
                    label = ("Loc %d (%.0f, %.0f)"):format(i, x, z)
                end
                items[#items + 1] = {
                    key = tostring(entry.id),
                    name = label,
                }
            end
        end
        if #items == 0 then
            items[1] = { key = "_none", name = "(Save location dulu)" }
