            local mod = G.AutoSprinkler or G.AutoSprinklerModule
            if type(mod) == "table" and type(mod.SaveStandingLocation) == "function" then
                mod:SaveStandingLocation()
                SP_STATE.saveLocation = false
                writeSprinklerGlobals()
                if saveLocationToggleApi and saveLocationToggleApi.setOff then
                    saveLocationToggleApi.setOff(true)
                end
                if locationDropdownApi and locationDropdownApi.refreshItems then
                    locationDropdownApi.refreshItems()
                end
            else
                warn("[GAG2] AutoSprinkler belum load — reload script")
                SP_STATE.saveLocation = false
                if saveLocationToggleApi and saveLocationToggleApi.setOff then
                    saveLocationToggleApi.setOff(true)
                end
            end
        end
