        tostring(delayDisplay()),
        function(text)
            local n = tonumber(text)
            if n == nil then return end
            if n < 0 then n = 0 end
            if n > 0 and n < 0.5 then n = 0.5 end
            SP_STATE.delay = n
            patchAuto("sprinkler", { delay = n }, syncSprinklerModule)
        end,
        false
    )

    ui:CreateRowInput(
        bodySprinkler,
        "Settle Delay (sec, 0=auto)",
