        tostring(pauseCollectDisplay()),
        function(text)
            local n = tonumber(text)
            if n == nil then return end
            n = math.floor(n)
            if n < 0 then n = 0 end
            SP_STATE.pauseCollectFruit = n
            patchAuto("sprinkler", { pauseCollectFruit = n }, syncSprinklerModule)
        end,
