 end,         required = false },
    { key = "WateringCanListView",     name = "WateringCanListView",     factory = function() -- WateringCanListView.lua — Grow A Garden 2
-- List watering can dari inventory (attribute WateringCan)

local ReplicatedStorage = game:GetService("ReplicatedStorage")
local Players           = game:GetService("Players")

local LP = Players.LocalPlayer
local M  = {}
local G  = (getgenv and getgenv()) or _G

local _catalogCache = nil

local function _safeRequire(inst)
    if not inst or not inst:IsA("ModuleScript") then return nil end
    local ok, mod = pcall(require, inst)
    if ok and type(mod) == "table" then return mod end
    return nil
end

local function _normalizeEntry(entry, keyHint)
    if type(entry) ~= "table" then return nil end
    local name = entry.Name or keyHint
    if not name or tostring(name) == "" then return nil end
    return {
        Name         = tostring(name),
        SplashRadius = tonumber(entry.SplashRadius) or 8,
        raw          = entry,
    }
end

local function _loadCatalog()
    if _catalogCache then return _catalogCache end
    local merged = {}
    local root = ReplicatedStorage:FindFirstChild("SharedModules")
    local dataMod = root and root:FindFirstChild("WateringcanData")
    local data = dataMod and _safeRequire(dataMod)
    if type(data) == "table" then
        if #data > 0 then
            for _, entry in ipairs(data) do
                local norm = _normalizeEntry(entry)
                if norm then merged[norm.Name] = norm end
            end
        else
            for key, entry in pairs(data) do
                if type(entry) == "table" then
                    local norm = _normalizeEntry(entry, key)
                    if norm then merged[norm.Name] = norm end
                end
            end
        end
    end
    _catalogCache = merged
    return merged
end

function M.refresh()
    _catalogCache = nil
    return _loadCatalog()
end

function M.getCatalogMap()
    return _loadCatalog()
end

function M.findByName(name)
    if not name then return nil end
    return _loadCatalog()[tostring(name)]
end

local function _iterInventoryContainers()
    local out, seen = {}, {}
    local function add(c)
        if c and not seen[c] then
            seen[c] = true
            out[#out + 1] = c
        end
    end
    add(LP:FindFirstChildOfClass("Backpack"))
    add(LP:FindFirstChild("Backpack"))
    add(LP.Character)
    for _, ch in ipairs(LP:GetChildren()) do
        if ch:IsA("Folder") or ch:IsA("Model") or ch:IsA("Backpack") then
            local n = ch.Name:lower()
            if n:find("backpack") or n:find("ransel") or n:find("tas") or n:find("inventory") then
                add(ch)
            end
        end
    end
    return out
end

function M.buildInventoryWateringCanItems()
    local counts = {}
    for _, container in ipairs(_iterInventoryContainers()) do
        for _, inst in ipairs(container:GetChildren()) do
            if inst:IsA("Tool") then
                local attr = inst:GetAttribute("WateringCan")
                if attr ~= nil then
                    local name = tostring(attr)
                    if name ~= "" then
                        counts[name] = (counts[name] or 0) + 1
                    end
                end
            end
        end
    end

    local out = {}
    for name, count in pairs(counts) do
        local info = M.findByName(name)
        local radius = info and info.SplashRadius or 8
        out[#out + 1] = {
            key   = name,
            name  = name,
            right = ("x%d · r%d"):format(count, radius),
            raw   = info or { Name = name, SplashRadius = radius },
        }
    end
    table.sort(out, function(a, b)
        return tostring(a.name) < tostring(b.name)
    end)
    if #out == 0 then
        return { { key = "_none", name = "(No watering cans in inventory)" } }
    end
    return out
end

G.WateringCanListView = M
_G.WateringCanListView = M

return M
 end,            required = false },
    { key = "AutoWatering",            name = "Auto Watering",           factory = function() -- AutoWatering.lua — Grow A Garden 2
-- Water via teleport: below (ascend) / above (descend).
-- After finish → teleport back to start position.
-- Multi-can: stay on hover until all selected cans succeed.
-- Remote: Networking.WateringCan.UseWateringCan:Fire(pos - Vector3(0, 0.3, 0), canName, tool)

local Players           = game:GetService("Players")
local RunService        = game:GetService("RunService")
local CollectionService = game:GetService("CollectionService")
local ReplicatedStorage = game:GetService("ReplicatedStorage")

local LP = Players.LocalPlayer
local G  = (getgenv and getgenv()) or _G
local M  = {}

local Networking = require(ReplicatedStorage.SharedModules.Networking)
local UseWateringCan = Networking.WateringCan and Networking.WateringCan.UseWateringCan
local WateringCanFx  = Networking.WateringCan and Networking.WateringCan.WateringCanFx

local LOOP_MIN_SEC    = 0.5
local WATER_COOLDOWN  = 0.5
local TP_SETTLE_BASE  = 0.35
local EQUIP_WAIT_BASE = 0.6
local PRE_FIRE_BASE   = 0.15
local POST_WATER_BASE = 0.35
local UNEQUIP_SETTLE_SEC = 0.35
local WATER_Y_OFFSET  = 0.3
local PLOT_CACHE_SEC  = 2
local BELOW_START     = -30
local ABOVE_START     = 28
local Y_STEP          = 4
local BELOW_Y_MAX     = 12
local ABOVE_Y_MIN     = -6
local MAX_ATTEMPTS    = 12
local FX_WAIT_SEC     = 1.2
local FX_RADIUS       = 20
local HOVER_SETTLE    = 0.2
local RETURN_SETTLE   = 0.12
local BOOT_WAIT_MAX   = 240
local POST_READY_DELAY = 0.75
local READY_POLL_SEC  = 0.35

local hoverConn = nil
local fxConn    = nil
local fxHit     = false
local stopHover

local running      = false
local loopId       = 0
local lastWaterAt  = 0
local plantIndex   = 0
local cachedPlot   = nil
local cachedPlotAt = 0
local teleWasOn    = false
local telePaused   = false
local lastFailReason = ""
local lastFruitCount = 0
local lastSkippedCount = 0
local lastCollectCount = 0
local lastBackpackCount = 0
local lastFruitSlots = 0
local lastFruitSlotsAt = 0
local lastStatusBase = "Waiting"
local skipGatePaused = false
local nextActionAt = 0
local lastDelaySec = 0
local statusCountsAt = 0
local STATUS_COUNTS_SEC = 1.0

local STATUS_TEXT = {
    no_plot      = "Plot not found",
    no_plants    = "No plants selected",
    no_targets   = "No matching plants",
    no_can       = "No watering can",
    no_remote    = "Remote missing",
    equip_fail   = "Equip failed",
    tp_fail      = "TP failed",
    fire_fail    = "Fire failed",
    water_fail   = "Water failed",
    cooldown     = "Cooldown",
    working      = "Watering",
    idle         = "Waiting",
    done         = "Watered",
    skip_pause   = "Paused (skip)",
    collect_pause = "Paused (collect)",
    backpack_pause = "Paused (BP)",
    delay_wait   = "Delay",
    loading      = "Loading...",
    not_ready    = "Garden not ready",
}

local function _statusMessage(reason)
    reason = tostring(reason or "")
    if reason == "" then return STATUS_TEXT.idle or "Idle" end
    return STATUS_TEXT[reason] or reason
end

local function _stripFruitSuffix(msg)
    return tostring(msg or "")
        :gsub("%s*%(%d+%)%s*$", "")
        :gsub("%s*·%s*delay%s+[%d%.]+s%s*", " · ")
        :gsub("%s*·%s*collect%s+%d+(?:/%d+)?%s*", " · ")
        :gsub("%s*·%s*skipped%s+%d+(?:/%d+)?%s*", " · ")
        :gsub("%s*·%s*skip%s+%d+(?:/%d+)?%s*", " · ")
        :gsub("%s*·%s*backpack%s+%d+(?:/%d+)?%s*", " · ")
        :gsub("%s*·%s*max buah%s+%d+%s*", " · ")
        :gsub("%s*·%s*slots%s+%d+%s*", " · ")
        :gsub("%s*·%s*fruit%s+%d+(?:/%d+)?%s*$", "")
        :gsub("%s*·%s*$", "")
        :gsub("%s+$", "")
end

local function _composeStatusText(base, st)
    local msg = _stripFruitSuffix(base)
    if msg == "" then msg = STATUS_TEXT.idle or "Waiting" end
    if #msg > 28 then
        msg = msg:sub(1, 27) .. "…"
    end
    local pauseSkipAt = 0
    local pauseCollectAt = 0
    local pauseBackpackAt = 0
    if type(st) == "table" then
        pauseSkipAt = math.floor(tonumber(st.pauseSkippedFruit) or 0)
        pauseCollectAt = math.floor(tonumber(st.pauseCollectFruit) or 0)
        pauseBackpackAt = math.floor(tonumber(st.pauseBackpackTotal) or 0)
    else
        pauseSkipAt = math.floor(tonumber(G.AUTO_WATERING_PAUSE_SKIPPED_FRUIT or rawget(_G, "AUTO_WATERING_PAUSE_SKIPPED_FRUIT")) or 0)
        pauseCollectAt = math.floor(tonumber(G.AUTO_WATERING_PAUSE_COLLECT_FRUIT or rawget(_G, "AUTO_WATERING_PAUSE_COLLECT_FRUIT")) or 0)
        pauseBackpackAt = math.floor(tonumber(G.AUTO_WATERING_PAUSE_BACKPACK_TOTAL or rawget(_G, "AUTO_WATERING_PAUSE_BACKPACK_TOTAL")) or 0)
    end
    local skipN = math.floor(tonumber(lastSkippedCount) or 0)
    local collectN = math.floor(tonumber(lastCollectCount) or 0)
    local backpackN = math.floor(tonumber(lastBackpackCount) or 0)
    local slots = math.floor(tonumber(lastFruitSlots) or 0)
    local delayLeft = nextActionAt - os.clock()
    local parts = { msg }
    if delayLeft > 0.05
        and lastFailReason ~= "skip_pause"
        and lastFailReason ~= "collect_pause"
        and lastFailReason ~= "backpack_pause"
        and lastFailReason ~= "working" then
        parts[#parts + 1] = string.format("d%.0fs", delayLeft)
    end
    if pauseCollectAt > 0 then
        parts[#parts + 1] = string.format("C%d/%d", collectN, pauseCollectAt)
    else
        parts[#parts + 1] = string.format("C%d", collectN)
    end
    if pauseSkipAt > 0 then
        parts[#parts + 1] = string.format("Sk%d/%d", skipN, pauseSkipAt)
    else
        parts[#parts + 1] = string.format("Sk%d", skipN)
    end
    if pauseBackpackAt > 0 then
        parts[#parts + 1] = string.format("Bp%d/%d", backpackN, pauseBackpackAt)
    else
        parts[#parts + 1] = string.format("Bp%d", backpackN)
    end
    parts[#parts + 1] = string.format("Mx%d", slots)
    return table.concat(parts, " · ")
end

local function _publishStatus(reason, detail)
    lastFailReason = tostring(reason or "")
    local msg = _statusMessage(lastFailReason)
    lastStatusBase = msg
    local full = _composeStatusText(msg)
    G.__GAG2_WATERING_STATUS = full
    _G.__GAG2_WATERING_STATUS = full
end

local function _beginDelayWait(waitSec)
    waitSec = tonumber(waitSec) or 0
    if waitSec < 0 then waitSec = 0 end
    lastDelaySec = waitSec
    nextActionAt = os.clock() + waitSec
    if waitSec > 0.05 then
        _publishStatus("delay_wait")
    end
end

local function _writeMain(patch)
    local MAIN = rawget(_G, "MAIN") or G.MAIN
    if type(MAIN) ~= "table" then return end
    MAIN.auto = MAIN.auto or {}
    MAIN.auto.watering = MAIN.auto.watering or {}
    for k, v in pairs(patch) do
        MAIN.auto.watering[k] = v
    end
    G.MAIN = MAIN
    _G.MAIN = MAIN
end

local function _normalizeSet(src)
    if type(src) ~= "table" then return {} end
    local out = {}
    for i = 1, #src do
        local v = src[i]
        if v ~= nil and tostring(v) ~= "" then
            out[tostring(v)] = true
        end
    end
    if next(out) then return out end
    for k, v in pairs(src) do
        if v == true or v == 1 or v == "true" then
            out[tostring(k)] = true
        end
    end
    return out
end

local function _canon(s)
    return tostring(s or ""):lower():gsub("[^%w]+", "")
end

local function _selectedMatch(selected, key)
    if not next(selected) then return true end
    local k = tostring(key)
    return selected[k] == true or selected[_canon(k)] == true
end

function M.GetState()
    local MAIN = rawget(_G, "MAIN") or G.MAIN
    local st = MAIN and MAIN.auto and MAIN.auto.watering
    st = type(st) == "table" and st or {}

    local plants = G.AUTO_WATERING_PLANTS_SELECTED
        or rawget(_G, "AUTO_WATERING_PLANTS_SELECTED")
        or _normalizeSet(st.plants)

    local cans = G.AUTO_WATERING_CANS_SELECTED
        or rawget(_G, "AUTO_WATERING_CANS_SELECTED")
        or _normalizeSet(st.cans)

    local delay = tonumber(st.delay)
    if delay == nil then
        delay = tonumber(G.AUTO_WATERING_DELAY or rawget(_G, "AUTO_WATERING_DELAY")) or 3
    end
    if delay < LOOP_MIN_SEC then delay = LOOP_MIN_SEC end

    local settleDelay = tonumber(st.settleDelay)
    if settleDelay == nil then
        settleDelay = tonumber(G.AUTO_WATERING_SETTLE_DELAY or rawget(_G, "AUTO_WATERING_SETTLE_DELAY")) or 0
    end
    if settleDelay < 0 then settleDelay = 0 end

    local pauseSkippedFruit = tonumber(st.pauseSkippedFruit)
    if pauseSkippedFruit == nil then
        pauseSkippedFruit = tonumber(G.AUTO_WATERING_PAUSE_SKIPPED_FRUIT or rawget(_G, "AUTO_WATERING_PAUSE_SKIPPED_FRUIT")) or 0
    end
    pauseSkippedFruit = math.floor(pauseSkippedFruit)
    if pauseSkippedFruit < 0 then pauseSkippedFruit = 0 end

    local pauseCollectFruit = tonumber(st.pauseCollectFruit)
    if pauseCollectFruit == nil then
        pauseCollectFruit = tonumber(G.AUTO_WATERING_PAUSE_COLLECT_FRUIT or rawget(_G, "AUTO_WATERING_PAUSE_COLLECT_FRUIT")) or 0
    end
    pauseCollectFruit = math.floor(pauseCollectFruit)
    if pauseCollectFruit < 0 then pauseCollectFruit = 0 end

    local pauseBackpackTotal = tonumber(st.pauseBackpackTotal)
    if pauseBackpackTotal == nil then
        pauseBackpackTotal = tonumber(G.AUTO_WATERING_PAUSE_BACKPACK_TOTAL or rawget(_G, "AUTO_WATERING_PAUSE_BACKPACK_TOTAL")) or 0
    end
    pauseBackpackTotal = math.floor(pauseBackpackTotal)
    if pauseBackpackTotal < 0 then pauseBackpackTotal = 0 end

    local tpMode = tostring(st.tpMode or G.AUTO_WATERING_TP_MODE or rawget(_G, "AUTO_WATERING_TP_MODE") or "below"):lower()
    if tpMode == "atas" or tpMode == "top" or tpMode == "over" or tpMode == "above" then
        tpMode = "above"
    else
        tpMode = "below"
    end

    local enabled = st.enabled
    if enabled == nil then
        enabled = G.AUTO_WATERING_ENABLED == true or rawget(_G, "AUTO_WATERING_ENABLED") == true
    end

    return {
        enabled             = (enabled == true),
        plants              = plants,
        cans                = cans,
        delay               = delay,
        settleDelay         = settleDelay,
        pauseSkippedFruit   = pauseSkippedFruit,
        pauseCollectFruit   = pauseCollectFruit,
        pauseBackpackTotal  = pauseBackpackTotal,
        tpMode              = tpMode,
    }
end

M.getState = M.GetState

local function getPlayerPlot()
    local now = os.clock()
    if cachedPlot and cachedPlot.Parent and (now - cachedPlotAt) <= PLOT_CACHE_SEC then
        return cachedPlot
    end
    cachedPlot = nil
    local plotId = LP:GetAttribute("PlotId")
    local gardens = workspace:FindFirstChild("Gardens")
    if not gardens then return nil end
    if plotId ~= nil then
        cachedPlot = gardens:FindFirstChild("Plot" .. tostring(plotId))
    end
    if not cachedPlot then
        for _, plot in ipairs(gardens:GetChildren()) do
            local owner = plot:GetAttribute("Owner") or plot:GetAttribute("OwnerId")
            if owner ~= nil and (tostring(owner) == LP.Name or tonumber(owner) == LP.UserId) then
                cachedPlot = plot
                break
            end
        end
    end
    cachedPlotAt = now
    return cachedPlot
end

local function loadingScreenActive()
    if not LP then return false end
    if LP:GetAttribute("LoadingScreenDone") == true then
        return false
    end
    if LP:GetAttribute("LoadingScreenActive") == true then
        return true
    end
    if workspace:FindFirstChild("LoadingScreenMenu") ~= nil then
        return true
    end
    return false
end

local function plotRuntimeReady()
    if not LP or not LP.Character then return false end
    local hrp = LP.Character:FindFirstChild("HumanoidRootPart")
    if not (hrp and hrp:IsA("BasePart")) then return false end
    if not workspace:FindFirstChild("Gardens") then return false end
    if LP:GetAttribute("PlotId") == nil then return false end
    local plot = getPlayerPlot()
    return plot ~= nil and plot.Parent ~= nil
end

local function isGameReady()
    if loadingScreenActive() then return false end
    return plotRuntimeReady()
end

local function waitForBootReady(myId)
    local deadline = os.clock() + BOOT_WAIT_MAX
    local settled = false
    while running and loopId == myId do
        if not workspace:FindFirstChild("Gardens") then
            pcall(function()
                workspace:WaitForChild("Gardens", 5)
            end)
        end

        if isGameReady() then
            if not settled then
                cachedPlot = nil
                task.wait(POST_READY_DELAY)
                settled = true
            end
            if isGameReady() then
                cachedPlot = nil
                return true
            end
        end

        if os.clock() >= deadline then
            return isGameReady()
        end

        if loadingScreenActive() then
            _publishStatus("loading")
        else
            _publishStatus("not_ready")
        end
        task.wait(READY_POLL_SEC)
    end
    return false
end

local function _plantsFolderCount(plot)
    if not plot then return 0 end
    local folder = plot:FindFirstChild("Plants")
    return folder and #folder:GetChildren() or 0
end

local function computeSettleSec(plot, st)
    local user = tonumber(st and st.settleDelay)
    if user ~= nil and user > 0 then
        return math.clamp(user, 0.15, 5)
    end
    local n = _plantsFolderCount(plot)
    if n >= 500 then return 1.2
    elseif n >= 300 then return 1.0
    elseif n >= 200 then return 0.8
    elseif n >= 100 then return 0.55
    end
    return TP_SETTLE_BASE
end

local function computeLoopDelay(st, plot)
    local base = tonumber(st and st.delay) or 3
    if base < LOOP_MIN_SEC then base = LOOP_MIN_SEC end
    local n = _plantsFolderCount(plot)
    if n >= 500 then return math.max(base, 3.5)
    elseif n >= 300 then return math.max(base, 3)
    elseif n >= 200 then return math.max(base, 2.5)
    elseif n >= 100 then return math.max(base, 1.5)
    end
    return base
end

local function getHarvestFilterCounts()
    local AC = G.AutoCollectFruit or G.CollectFruitModule or rawget(_G, "AutoCollectFruit")
        or G.AutoCollect or rawget(_G, "AutoCollect")
    if type(AC) ~= "table" then return 0, 0 end
    if type(AC.PeekHarvestBreakdown) == "function" then
        local ok, br = pcall(AC.PeekHarvestBreakdown, AC)
        if ok and type(br) == "table" then
            -- collect = semua buah siap ambil (tanpa filter AC)
            local collectN = math.max(0, math.floor(tonumber(br.total) or 0))
            local skipN = math.max(0, math.floor(tonumber(br.outFilter) or 0))
            return collectN, skipN
        end
    end
    if type(AC.PeekReadyCount) == "function" then
        local ok, n = pcall(AC.PeekReadyCount, AC)
        if ok then
            return math.max(0, math.floor(tonumber(n) or 0)), 0
        end
    end
    return 0, 0
end

local function countFruitSlots(plot)
    local now = os.clock()
    if (now - lastFruitSlotsAt) <= 2 and lastFruitSlots >= 0 then
        return lastFruitSlots
    end
    local total = 0
    if plot then
        local folder = plot:FindFirstChild("Plants")
        if folder then
            -- Hanya FindFirstChild — JANGAN GetDescendants (garden 3k+ buah = freeze UI)
            for _, plant in ipairs(folder:GetChildren()) do
                local locs = plant:FindFirstChild("FruitSpawnLocations")
                if locs then
                    total += #locs:GetChildren()
                end
            end
        end
    end
    lastFruitSlots = total
    lastFruitSlotsAt = now
    return total
end

local function refreshStatusCounts(force)
    local now = os.clock()
    if not force and (now - statusCountsAt) < STATUS_COUNTS_SEC then
        return
    end
    statusCountsAt = now

    local plot = getPlayerPlot()
    -- Hormati cache 2s di countFruitSlots (jangan paksa recount tiap status tick)
    countFruitSlots(plot)

    local collectN, skipN = getHarvestFilterCounts()
    lastCollectCount = collectN
    lastSkippedCount = skipN
    lastFruitCount = skipN
    lastBackpackCount = math.max(0, math.floor(tonumber(LP:GetAttribute("FruitCount")) or 0))
end

-- Pause bila collect / skipped / backpack total mencapai threshold (0=off).
local function checkSkippedFruitGate(st, plot)
    local pauseSkipAt = math.floor(tonumber(st and st.pauseSkippedFruit) or 0)
    local pauseCollectAt = math.floor(tonumber(st and st.pauseCollectFruit) or 0)
    local pauseBackpackAt = math.floor(tonumber(st and st.pauseBackpackTotal) or 0)
    refreshStatusCounts(true)
    local collectN = lastCollectCount
    local skipN = lastSkippedCount
    local backpackN = lastBackpackCount

    if pauseCollectAt > 0 and collectN >= pauseCollectAt then
        skipGatePaused = true
        return false, "collect_pause", collectN
    end

    if pauseSkipAt > 0 and skipN >= pauseSkipAt then
        skipGatePaused = true
        return false, "skip_pause", skipN
    end

    if pauseBackpackAt > 0 and backpackN >= pauseBackpackAt then
        skipGatePaused = true
        return false, "backpack_pause", backpackN
    end

    skipGatePaused = false
    return true, nil, skipN
end

local function getPlantTypeKey(plant)
    local AS = G.AutoSprinkler or G.AutoSprinklerModule or rawget(_G, "AutoSprinkler")
    if type(AS) == "table" and type(AS.BuildGardenPlantItems) == "function" then
        -- prefer shovel helper if available via sprinkler's chain
    end
    local shovel = G.AutoShovel or rawget(_G, "AutoShovel")
    if type(shovel) == "table" and type(shovel.GetPlantTypeKey) == "function" then
        local ok, key = pcall(shovel.GetPlantTypeKey, shovel, plant)
        if ok and key then return tostring(key) end
    end
    return tostring(
        plant:GetAttribute("SeedName")
            or plant:GetAttribute("ConfigPathName")
            or plant:GetAttribute("CorePartName")
            or plant:GetAttribute("FruitType")
            or plant.Name
    )
end

local function getPlantGroundPos(plant)
    if plant:IsA("BasePart") then return plant.Position end
    local ok, pos = pcall(function() return plant:GetPivot().Position end)
    if ok and typeof(pos) == "Vector3" then return pos end
    local part = plant:FindFirstChildWhichIsA("BasePart", true)
    return part and part.Position or nil
end

local function listTargetPlants(plot, selectedPlants)
    if not plot or not next(selectedPlants) then return {} end
    local folder = plot:FindFirstChild("Plants")
    if not folder then return {} end
    local out = {}
    for _, plant in ipairs(folder:GetChildren()) do
        if plant:IsA("Model") then
            local key = getPlantTypeKey(plant)
            if _selectedMatch(selectedPlants, key) then
                local pos = getPlantGroundPos(plant)
                if pos then
                    out[#out + 1] = { plant = plant, key = key, pos = pos }
                end
            end
        end
    end
    table.sort(out, function(a, b)
        return tostring(a.key) < tostring(b.key)
    end)
    return out
end

local function collectPlantAreas(plot)
    local out = {}
    for _, d in ipairs(plot:GetDescendants()) do
        if d:IsA("BasePart") and CollectionService:HasTag(d, "PlantArea") then
            out[#out + 1] = d
        end
    end
    return out
end

local function snapToPlantArea(plot, pos)
    if not plot or not pos then return nil end
    local areas = collectPlantAreas(plot)
    if #areas == 0 then return pos end
    local params = RaycastParams.new()
    params.FilterType = Enum.RaycastFilterType.Include
    params.FilterDescendantsInstances = areas
    local originY = pos.Y + 80
    for _, part in ipairs(areas) do
        originY = math.max(originY, part.Position.Y + 80)
    end
    local hit = workspace:Raycast(
        Vector3.new(pos.X, originY, pos.Z),
        Vector3.new(0, -600, 0),
        params
    )
    if hit and CollectionService:HasTag(hit.Instance, "PlantArea") and hit.Instance:IsDescendantOf(plot) then
        return hit.Position
    end
    return pos
end

local function iterInventory()
    local out, seen = {}, {}
    local function add(c)
        if c and not seen[c] then
            seen[c] = true
            out[#out + 1] = c
        end
    end
    add(LP:FindFirstChildOfClass("Backpack"))
    add(LP:FindFirstChild("Backpack"))
    add(LP:FindFirstChild("TasRansel"))
    add(LP.Character)
    for _, ch in ipairs(LP:GetChildren()) do
        if ch:IsA("Folder") or ch:IsA("Model") or ch:IsA("Backpack") then
            local n = ch.Name:lower()
            if n:find("backpack") or n:find("ransel") or n:find("tas") or n:find("inventory") then
                add(ch)
            end
        end
    end
    return out
end

local function _resolveCanGroupName(name, groups)
    if not name or type(groups) ~= "table" then return nil end
    name = tostring(name)
    if groups[name] and #groups[name] > 0 then return name end
    local canon = _canon(name)
    for gname, tools in pairs(groups) do
        if #tools > 0 and _canon(gname) == canon then
            return gname
        end
    end
    return nil
end

local function groupWateringCansByType(selected)
    local groups = {}
    local hasFilter = next(selected) ~= nil
    for _, container in ipairs(iterInventory()) do
        for _, inst in ipairs(container:GetChildren()) do
            if inst:IsA("Tool") then
                local attr = inst:GetAttribute("WateringCan")
                if attr ~= nil then
                    local name = tostring(attr)
                    if name ~= "" and (not hasFilter or _selectedMatch(selected, name)) then
                        local bucket = groups[name]
                        if not bucket then
                            bucket = {}
                            groups[name] = bucket
                        end
                        bucket[#bucket + 1] = inst
                    end
                end
            end
        end
    end
    return groups
end

local function buildWateringCanOrder(selected)
    selected = _normalizeSet(selected)
    local groups = groupWateringCansByType(selected)
    local order, seen = {}, {}

    local function tryAdd(name)
        local gname = _resolveCanGroupName(name, groups)
        if gname and not seen[gname] then
            seen[gname] = true
            order[#order + 1] = gname
        end
    end

    local MAIN = rawget(_G, "MAIN") or G.MAIN
    local arr = type(MAIN) == "table"
        and type(MAIN.auto) == "table"
        and type(MAIN.auto.watering) == "table"
        and MAIN.auto.watering.cans

    if type(arr) == "table" and #arr > 0 then
        for i = 1, #arr do
            tryAdd(arr[i])
        end
    end

    for name in pairs(selected) do
        tryAdd(name)
    end

    for gname, tools in pairs(groups) do
        if not seen[gname] and #tools > 0 then
            seen[gname] = true
            order[#order + 1] = gname
        end
    end

    return order, groups
end

local function getAvailableCanTypes(selected)
    local order, groups = buildWateringCanOrder(selected)
    local avail = {}
    for _, name in ipairs(order) do
        if groups[name] and #groups[name] > 0 then
            avail[#avail + 1] = name
        end
    end
    return avail, groups
end

local function findWateringCanTool(selected, typeName)
    if not typeName then return nil, nil end
    local _, groups = buildWateringCanOrder(selected)
    local resolved = _resolveCanGroupName(typeName, groups)
    local tools = resolved and groups[resolved]
    if type(tools) ~= "table" or #tools == 0 then return nil, nil end
    return tools[1], resolved
end

local function getHRP()
    local ch = LP.Character
    if not ch then return nil end
    local hrp = ch:FindFirstChild("HumanoidRootPart")
    return hrp and hrp:IsA("BasePart") and hrp or nil
end

local function getHum()
    local ch = LP.Character
    return ch and ch:FindFirstChildOfClass("Humanoid") or nil
end

local hoverRestore = {}
local hoverCf = nil
local sessionReturnCf = nil

local function restoreHoverHumanoid()
    local hum = getHum()
    local hrp = getHRP()
    if hum and hoverRestore.platformStand ~= nil then
        pcall(function() hum.PlatformStand = hoverRestore.platformStand end)
    elseif hum then
        pcall(function() hum.PlatformStand = false end)
    end
    if hum and hoverRestore.autoRotate ~= nil then
        pcall(function() hum.AutoRotate = hoverRestore.autoRotate end)
    elseif hum then
        pcall(function() hum.AutoRotate = true end)
    end
    if hrp then
        pcall(function()
            hrp.Anchored = false
            hrp.AssemblyLinearVelocity = Vector3.zero
            hrp.AssemblyAngularVelocity = Vector3.zero
        end)
    end
    hoverRestore = {}
end

local function applyWaterSoftLock(cf)
    if typeof(cf) ~= "CFrame" then return false end
    local hrp = getHRP()
    local hum = getHum()
    if not hrp or not hum or hum.Health <= 0 then return false end
    if hoverRestore.platformStand == nil then
        hoverRestore.platformStand = hum.PlatformStand
        hoverRestore.autoRotate = hum.AutoRotate
    end
    pcall(function()
        hum.PlatformStand = true
        hum.AutoRotate = false
        hum.Sit = false
        hrp.Anchored = false
        hrp.AssemblyLinearVelocity = Vector3.zero
        hrp.AssemblyAngularVelocity = Vector3.zero
        hrp.CFrame = cf
    end)
    return true
end

local function plantLookTarget(plant, groundPos)
    local ok, pivot = pcall(function() return plant:GetPivot().Position end)
    if ok and typeof(pivot) == "Vector3" then
        return pivot
    end
    return groundPos + Vector3.new(0, 10, 0)
end

local function offsetPos(groundPos, yOffset)
    return Vector3.new(groundPos.X, groundPos.Y + yOffset, groundPos.Z)
end

local function startHover(groundPos, lookTarget, yOffset)
    stopHover()
    local pos = offsetPos(groundPos, yOffset)
    hoverCf = CFrame.lookAt(pos, lookTarget)
    applyWaterSoftLock(hoverCf)
    hoverConn = RunService.Heartbeat:Connect(function()
        if typeof(hoverCf) == "CFrame" then
            applyWaterSoftLock(hoverCf)
        end
    end)
    return pos
end

stopHover = function()
    if hoverConn then
        hoverConn:Disconnect()
        hoverConn = nil
    end
    hoverCf = nil
end

local function _isHoverActive()
    return hoverConn ~= nil
        or typeof(hoverCf) == "CFrame"
        or hoverRestore.platformStand ~= nil
end

-- Surface snap if unlock happens while buried (prevents void freefall death).
local function surfaceSafeCFrame(fromCfOrPos)
    local fromPos
    if typeof(fromCfOrPos) == "CFrame" then
        fromPos = fromCfOrPos.Position
    elseif typeof(fromCfOrPos) == "Vector3" then
        fromPos = fromCfOrPos
    else
        local hrp = getHRP()
        fromPos = hrp and hrp.Position or nil
    end
    if typeof(fromPos) ~= "Vector3" then
        return nil
    end
    local origin = Vector3.new(fromPos.X, fromPos.Y + 200, fromPos.Z)
    local params = RaycastParams.new()
    params.FilterType = Enum.RaycastFilterType.Exclude
    local exclude = {}
    local char = LP.Character
    if char then
        table.insert(exclude, char)
    end
    -- Jangan pakai canopy plant sebagai "tanah" → TP ke atas lalu jatuh.
    local gardens = workspace:FindFirstChild("Gardens")
    if gardens then
        for _, plot in ipairs(gardens:GetChildren()) do
            local plants = plot:FindFirstChild("Plants")
            if plants then
                table.insert(exclude, plants)
            end
        end
    end
    params.FilterDescendantsInstances = exclude
    local hit = workspace:Raycast(origin, Vector3.new(0, -800, 0), params)
    local look = Vector3.new(0, 0, -1)
    if typeof(fromCfOrPos) == "CFrame" then
        local flat = Vector3.new(fromCfOrPos.LookVector.X, 0, fromCfOrPos.LookVector.Z)
        if flat.Magnitude > 0.05 then
            look = flat.Unit
        end
    end
    if hit then
        local safe = hit.Position + Vector3.new(0, 3, 0)
        -- Hit jauh di atas posisi sekarang = canopy/roof salah — jangan pakai.
        if safe.Y > fromPos.Y + 12 then
            return nil
        end
        return CFrame.lookAt(safe, safe + look)
    end
    -- Jangan fallback Y+8 (itu yang bikin "teleport ke atas lalu jatuh").
    return nil
end

-- CRITICAL: move to safe CF WHILE still soft-locked, THEN release PlatformStand.
-- Unlocking under plant (Y-30) first → freefall through map → death.
local function _stopHoverSession(returnCf)
    local wasHovering = _isHoverActive()
    local targetCf = typeof(returnCf) == "CFrame" and returnCf or sessionReturnCf
    local needRescue = wasHovering or typeof(targetCf) == "CFrame"

    stopHover()

    -- Disable idle (belum water / tidak hover): jangan surface snap / TP.
    if not needRescue then
        restoreHoverHumanoid()
        sessionReturnCf = nil
        if fxConn then
            fxConn:Disconnect()
            fxConn = nil
        end
        fxHit = false
        return
    end

    if typeof(targetCf) ~= "CFrame" then
        targetCf = surfaceSafeCFrame(getHRP() and getHRP().Position)
    end
    if typeof(targetCf) == "CFrame" then
        -- Keep PlatformStand true during place (hoverRestore still set).
        applyWaterSoftLock(targetCf)
        task.wait(RETURN_SETTLE)
    end

    restoreHoverHumanoid()
    sessionReturnCf = nil

    if fxConn then
        fxConn:Disconnect()
        fxConn = nil
    end
    fxHit = false
end

local function snapshotPlantAttrs(plant)
    local out = {}
    if not plant then return out end
    for name, val in pairs(plant:GetAttributes()) do
        out[name] = val
    end
    return out
end

local function attrsChanged(before, after)
    for k, v in pairs(after) do
        if before[k] ~= v then return true, k end
    end
    for k, v in pairs(before) do
        if after[k] ~= v then return true, k end
    end
    return false
end

local function bindFxListener(firePos, canName)
    fxHit = false
    if fxConn then
        fxConn:Disconnect()
        fxConn = nil
    end
    if not (WateringCanFx and WateringCanFx.OnClientEvent) then
        return
    end
    fxConn = WateringCanFx.OnClientEvent:Connect(function(fxPos, fxCan, player)
        if player ~= LP or tostring(fxCan) ~= tostring(canName) then
            return
        end
        if typeof(fxPos) == "Vector3" and (fxPos - firePos).Magnitude <= FX_RADIUS then
            fxHit = true
        end
    end)
end

local function detectPuddleFx(firePos)
    local tmp = workspace:FindFirstChild("Temporary")
    if not tmp then return false end
    for _, obj in ipairs(tmp:GetChildren()) do
        if obj.Name == "WateringCanFx" and obj:IsA("BasePart") then
            if (obj.Position - firePos).Magnitude <= FX_RADIUS then
                return true
            end
        end
    end
    return false
end

local function waitWaterSuccess(firePos, canName, attrsBefore, plant, timeoutSec)
    local t0 = os.clock()
    while (os.clock() - t0) < timeoutSec do
        if not running then
            return false, "stopped"
        end
        if fxHit then
            return true, "fx_remote"
        end
        if detectPuddleFx(firePos) then
            return true, "puddle_fx"
        end
        if attrsChanged(attrsBefore, snapshotPlantAttrs(plant)) then
            return true, "attr"
        end
        task.wait(0.05)
    end
    return false, "timeout"
end

local function ensureWateringCanEquipped(tool, equipWaitSec)
    if not tool or not tool:IsA("Tool") then return false, tool end
    local char = LP.Character
    if not char then return false, tool end
    if tool.Parent == char then
        task.wait(0.05)
        return true, tool
    end

    local hum = char:FindFirstChildOfClass("Humanoid")
    if not hum then return false, tool end

    pcall(function() hum:EquipTool(tool) end)

    local deadline = os.clock() + (equipWaitSec or EQUIP_WAIT_BASE)
    while os.clock() < deadline do
        if tool.Parent == char then
            task.wait(0.05)
            local equipped = char:FindFirstChild(tool.Name)
            if equipped and equipped:IsA("Tool") then
                return true, equipped
            end
            return true, tool
        end
        task.wait(0.03)
    end

    local equipped = char:FindFirstChild(tool.Name)
    if equipped and equipped:IsA("Tool") and equipped.Parent == char then
        return true, equipped
    end
    return tool.Parent == char, tool
end

local function unequipWateringCan(tool)
    local char = LP.Character
    if not char then return end
    local hum = char:FindFirstChildOfClass("Humanoid")
    if not hum then return end

    local equipped = tool
    if not (equipped and equipped:IsA("Tool") and equipped.Parent == char) then
        equipped = char:FindFirstChildOfClass("Tool")
        if not equipped and tool then
            equipped = char:FindFirstChild(tool.Name)
        end
    end

    if equipped and equipped:IsA("Tool") and equipped.Parent == char
        and equipped:GetAttribute("WateringCan") ~= nil then
        pcall(function() hum:UnequipTools() end)
    end
end

----------------------------------------------------------------
-- Auto Tele pause / resume (sama pola AutoClaimSeed / AutoBuyPet)
----------------------------------------------------------------
local function _getAutoTeleMod()
    return G.AutoTele or rawget(_G, "AutoTele")
end

local function _teleIsOn()
    local mod = _getAutoTeleMod()
    if type(mod) == "table" and type(mod.IsEnabled) == "function" then
        return mod.IsEnabled() == true
    end
    local s = rawget(_G, "__GAG2_AUTO_TELE") or G.__GAG2_AUTO_TELE
    if type(s) == "table" then return s.enabled == true end
    return G.AUTO_TELE_ENABLED == true or rawget(_G, "AUTO_TELE_ENABLED") == true
end

local function _teleWasRunning()
    local mod = _getAutoTeleMod()
    if type(mod) == "table" and type(mod.IsRunning) == "function" then
        return mod.IsRunning() == true
    end
    return false
end

local function _teleStopForWater()
    teleWasOn = _teleIsOn() and _teleWasRunning()
    if not teleWasOn then
        telePaused = false
        return
    end
    telePaused = true
    G.__GAG2_AUTO_TELE_SUPPRESS = true
    _G.__GAG2_AUTO_TELE_SUPPRESS = true
    local mod = _getAutoTeleMod()
    if type(mod) == "table" and type(mod.Stop) == "function" then
        pcall(mod.Stop, mod)
    end
end

local function _teleResumeNow()
    if not teleWasOn then
        telePaused = false
        G.__GAG2_AUTO_TELE_SUPPRESS = false
        _G.__GAG2_AUTO_TELE_SUPPRESS = false
        return
    end
    telePaused = false
    teleWasOn = false
    G.__GAG2_AUTO_TELE_SUPPRESS = false
    _G.__GAG2_AUTO_TELE_SUPPRESS = false
    local mod = _getAutoTeleMod()
    if type(mod) == "table" and type(mod.IsEnabled) == "function" and mod.IsEnabled() then
        if type(mod.Start) == "function" then
            pcall(mod.Start, mod)
        end
    end
end

local function _withTelePaused(fn)
    _teleStopForWater()
    local ok, a, b = pcall(fn)
    _teleResumeNow()
    if not ok then
        error(a)
    end
    return a, b
end

local function capturePlayerCFrame()
    local ch = LP.Character
    if not ch then return nil end
    local hrp = ch:FindFirstChild("HumanoidRootPart")
    if not (hrp and hrp:IsA("BasePart")) then return nil end
    local ok, cf = pcall(function() return hrp.CFrame end)
    if ok and typeof(cf) == "CFrame" then
        return cf
    end
    return nil
end

local function getTpModePlan(tpMode)
    if tpMode == "below" then
        return {
            startY = BELOW_START,
            step   = Y_STEP,
            limitY = BELOW_Y_MAX,
            dir    = 1,
        }
    end
    return {
        startY = ABOVE_START,
        step   = -Y_STEP,
        limitY = ABOVE_Y_MIN,
        dir    = -1,
    }
end

local function nextYOffset(yOffset, plan)
    if plan.dir > 0 then
        return math.min(plan.limitY, yOffset + plan.step)
    end
    return math.max(plan.limitY, yOffset + plan.step)
end

-- One can: hover (above=descend / below=ascend) until success
local function waterOneCanAtMode(ctx)
    if not UseWateringCan or type(UseWateringCan.Fire) ~= "function" then
        return false, "no_remote"
    end

    local groundPos  = ctx.groundPos
    local lookTarget = ctx.lookTarget
    local plant      = ctx.plant
    local firePos    = ctx.firePos
    local tool       = ctx.tool
    local canName    = ctx.canName
    local timing     = ctx.timing or {}
    local plan       = ctx.plan or getTpModePlan("below")

    local preFireSec   = timing.preFireSec or PRE_FIRE_BASE
    local postWaterSec = timing.postWaterSec or POST_WATER_BASE
    local equipWaitSec = timing.equipWaitSec or EQUIP_WAIT_BASE
    local fxWaitSec    = timing.fxWaitSec or FX_WAIT_SEC

    local yOffset = plan.startY
    bindFxListener(firePos, canName)

    for attempt = 1, MAX_ATTEMPTS do
        if not running then
            return false, "stopped"
        end

        startHover(groundPos, lookTarget, yOffset)
        task.wait(HOVER_SETTLE)

        local equipped, useTool = ensureWateringCanEquipped(tool, equipWaitSec)
        if not equipped or not useTool or useTool.Parent ~= LP.Character then
            if attempt >= MAX_ATTEMPTS then
                return false, "equip_fail"
            end
            yOffset = nextYOffset(yOffset, plan)
            task.wait(WATER_COOLDOWN)
        else
            tool = useTool
            local attrsBefore = snapshotPlantAttrs(plant)
            fxHit = false

            task.wait(preFireSec)

            local actualCanName = tostring(useTool:GetAttribute("WateringCan"))
            if actualCanName == "" then
                actualCanName = tostring(canName)
            end

            UseWateringCan:Fire(firePos, actualCanName, useTool)
            task.wait(postWaterSec)

            local ok, reason = waitWaterSuccess(firePos, actualCanName, attrsBefore, plant, fxWaitSec)
            if ok then
                -- Jangan unequip di sini — WateringCanController UpdatePreview akan
                -- Parent-lock spam kalau Destroy preview saat masih Heartbeat update.
                return true, reason
            end

            if attempt >= MAX_ATTEMPTS then
                return false, reason or "timeout"
            end

            yOffset = nextYOffset(yOffset, plan)
            task.wait(WATER_COOLDOWN)
        end
    end

    return false, "timeout"
end

-- All cans: one hover session, then return to start CFrame
local function waterPlantAllCans(plot, target, selectedCans, st)
    if not UseWateringCan then
        return false, "no_remote"
    end

    local settleSec = computeSettleSec(plot, st)
    local timing = {
        preFireSec   = math.max(PRE_FIRE_BASE, settleSec * 0.35),
        postWaterSec = math.max(POST_WATER_BASE, settleSec * 0.45),
        equipWaitSec = math.max(EQUIP_WAIT_BASE, settleSec + 0.25),
        fxWaitSec    = math.max(FX_WAIT_SEC, settleSec + 0.5),
    }

    local groundPos = snapToPlantArea(plot, target.pos)
    if not groundPos then
        return false, "tp_fail"
    end

    local avail = select(1, getAvailableCanTypes(selectedCans))
    if #avail == 0 then
        return false, "no_can"
    end

    local tpMode = (st and st.tpMode) or "below"
    local plan = getTpModePlan(tpMode)
    local lookTarget = plantLookTarget(target.plant, groundPos)
    local firePos = groundPos - Vector3.new(0, WATER_Y_OFFSET, 0)

    local watered = 0
    local usedNames = {}
    local lastReason = nil
    sessionReturnCf = capturePlayerCFrame()

    _teleStopForWater()

    local ok, err = pcall(function()
        startHover(groundPos, lookTarget, plan.startY)
        task.wait(HOVER_SETTLE)

        for i, canName in ipairs(avail) do
            if not running then break end

            local tool = select(1, findWateringCanTool(selectedCans, canName))
            if not tool then
                lastReason = "no_can"
            else
                if watered > 0 then
                    local waitLeft = WATER_COOLDOWN - (os.clock() - lastWaterAt)
                    if waitLeft > 0 then
                        task.wait(waitLeft)
                    end
                end

                _publishStatus("working")

                local canOk, canReason = waterOneCanAtMode({
                    groundPos  = groundPos,
                    lookTarget = lookTarget,
                    plant      = target.plant,
                    firePos    = firePos,
                    tool       = tool,
                    canName    = canName,
                    timing     = timing,
                    plan       = plan,
                })

                if canOk then
                    watered += 1
                    lastWaterAt = os.clock()
                    lastReason = canReason
                    usedNames[#usedNames + 1] = tostring(canName)
                else
                    lastReason = canReason or "water_fail"
                    break
                end

                if i < #avail and watered > 0 then
                    task.wait(WATER_COOLDOWN)
                end
            end
        end
    end)

    -- Surface first, then unequip — hindari Parent locked di Temporary saat masih Y-30.
    _stopHoverSession(sessionReturnCf)
    unequipWateringCan(nil)
    task.wait(UNEQUIP_SETTLE_SEC)
    _teleResumeNow()

    if not ok then
        return false, tostring(err)
    end

    if watered == 0 then
        return false, lastReason or "no_can"
    end

    if watered < #avail then
        return false, lastReason or "water_fail"
    end

    return true, table.concat(usedNames, " + ")
end

local function tickOnce(st)
    if not st.enabled then
        _publishStatus("idle")
        return false
    end

    if loadingScreenActive() then
        _publishStatus("loading")
        return false
    end

    if not isGameReady() then
        _publishStatus("not_ready")
        return false
    end

    local plot = getPlayerPlot()
    local gateOk, gateReason, skipN = checkSkippedFruitGate(st, plot)
    if not gateOk then
        _publishStatus(gateReason, skipN)
        return false
    end

    local now = os.clock()
    if now - lastWaterAt < WATER_COOLDOWN then
        _publishStatus("cooldown")
        return false
    end

    if not next(st.plants) then
        _publishStatus("no_plants")
        return false
    end

    if not plot then
        _publishStatus("no_plot")
        return false
    end

    local targets = listTargetPlants(plot, st.plants)
    if #targets == 0 then
        _publishStatus("no_targets")
        return false
    end

    plantIndex = (plantIndex % #targets) + 1
    local target = targets[plantIndex]

    local ok, detail = waterPlantAllCans(plot, target, st.cans, st)
    if ok then
        _publishStatus("done")
        return true
    end
    if detail == "fx_remote" or detail == "puddle_fx" or detail == "attr" then
        _publishStatus("water_fail")
        return false
    end
    _publishStatus(detail or "fire_fail")
    return false
end

local function mainLoop(myId)
    if not waitForBootReady(myId) then
        if running and loopId == myId then
            _publishStatus(loadingScreenActive() and "loading" or "not_ready")
        end
    end

    while running and loopId == myId do
        local st = M.GetState()
        local plot = getPlayerPlot()
        local waitSec = computeLoopDelay(st, plot)
        if st.enabled then
            if loadingScreenActive() then
                _publishStatus("loading")
                waitSec = READY_POLL_SEC
            elseif not isGameReady() then
                _publishStatus("not_ready")
                waitSec = READY_POLL_SEC
            else
                nextActionAt = 0
                local ok, err = pcall(tickOnce, st)
                if not ok then
                    _publishStatus("error", tostring(err))
                end
                waitSec = computeLoopDelay(st, getPlayerPlot())
                _beginDelayWait(waitSec)
            end
        else
            nextActionAt = 0
            _publishStatus("idle")
        end
        task.wait(waitSec)
    end
end

function M.SetEnabled(on)
    on = (on == true)
    G.AUTO_WATERING_ENABLED = on
    _G.AUTO_WATERING_ENABLED = on
    _writeMain({ enabled = on })

    if on then
        plantIndex = 0
        cachedPlot = nil
        skipGatePaused = false
        lastFruitSlotsAt = 0
        nextActionAt = 0
        if loadingScreenActive() then
            _publishStatus("loading")
        else
            _publishStatus("idle")
        end
        if not running then
            running = true
            loopId += 1
            local myId = loopId
            task.spawn(function() mainLoop(myId) end)
        end
    else
        running = false
        loopId += 1
        skipGatePaused = false
        nextActionAt = 0
        _stopHoverSession(sessionReturnCf)
        _teleResumeNow()
        unequipWateringCan(nil)
        _publishStatus("idle")
    end
end

M.setEnabled = M.SetEnabled
function M.Start() return M.SetEnabled(true) end
M.start = M.Start
function M.Stop() return M.SetEnabled(false) end
M.stop = M.Stop

function M.IsEnabled()
    return M.GetState().enabled
end

function M.GetStatusText()
    local st = M.GetState()
    if not st.enabled then
        return "Off"
    end
    -- Jangan scan garden di sini — UI status poll 0.5s; count di-update oleh loop watering.
    local base = lastStatusBase
        or G.__GAG2_WATERING_STATUS
        or _G.__GAG2_WATERING_STATUS
        or _statusMessage(lastFailReason)
    return _composeStatusText(base, st)
end

function M.GetFruitCount()
    return math.floor(tonumber(lastFruitCount) or 0)
end

M.getFruitCount = M.GetFruitCount

function M.SyncFromState()
    local st = M.GetState()
    M.SetEnabled(st.enabled)
end

M.syncFromState = M.SyncFromState

function M.BuildGardenPlantItems()
    local AS = G.AutoSprinkler or G.AutoSprinklerModule or rawget(_G, "AutoSprinkler")
    if type(AS) == "table" and type(AS.BuildGardenPlantItems) == "function" then
        local ok, items = pcall(AS.BuildGardenPlantItems, AS)
        if ok and type(items) == "table" then return items end
    end
    return { { key = "_none", name = "(No plants in garden)" } }
end

M.buildGardenPlantItems = M.BuildGardenPlantItems

G.AutoWatering = M
G.AutoWateringModule = M
_G.AutoWatering = M
_G.AutoWateringModule = M

G.__GAG2_WATERING_STATUS = "Off"
_G.__GAG2_WATERING_STATUS = "Off"

return M
