    { key = "AutoFav",                 name = "Auto Fav",                factory = function() -- AutoFav.lua — Grow A Garden 2
-- Auto favorite / unfavorite fruits (SetFruitFavorite)

local Players           = game:GetService("Players")
local ReplicatedStorage = game:GetService("ReplicatedStorage")

local LP = Players.LocalPlayer
local G  = (getgenv and getgenv()) or _G
local M  = {}

local FruitProxyUtil
local SetFruitFavorite
local FruitSellValue

pcall(function()
    FruitProxyUtil = require(ReplicatedStorage.SharedModules.FruitProxyUtil)
end)
pcall(function()
    local Networking = require(ReplicatedStorage.SharedModules.Networking)
    SetFruitFavorite = Networking and Networking.Backpack and Networking.Backpack.SetFruitFavorite
end)
pcall(function()
    FruitSellValue = require(script.Parent.FruitSellValue)
end)
if type(FruitSellValue) ~= "table" then
    FruitSellValue = G.FruitSellValue or _G.FruitSellValue
end

local function _fsv()
    if type(FruitSellValue) == "table" then return FruitSellValue end
    FruitSellValue = G.FruitSellValue or _G.FruitSellValue
    if type(FruitSellValue) == "table" then return FruitSellValue end
    pcall(function()
        FruitSellValue = require(script.Parent.FruitSellValue)
    end)
    if type(FruitSellValue) == "table" then return FruitSellValue end
    return nil
end

local function _ensureFavoriteRemote()
    if SetFruitFavorite and type(SetFruitFavorite.Fire) == "function" then
        return true
    end
    local ok, net = pcall(function()
        return require(ReplicatedStorage.SharedModules.Networking)
    end)
    if ok and type(net) == "table" and type(net.Backpack) == "table" then
        SetFruitFavorite = net.Backpack.SetFruitFavorite
    end
    return SetFruitFavorite ~= nil and type(SetFruitFavorite.Fire) == "function"
end

local FIRE_DELAY    = 0.05
local IDLE_WAIT_SEC = 1
local CAND_CACHE_SEC = 4.0
local PRE_SELL_BATCH = 80
local PRE_SELL_MAX_WALL_SEC = 10
local PRE_SELL_MAX_ZERO_ROUNDS = 2
local NO_MUTATION_LABEL = "No Mutation"
local MODULE_VERSION = "20260714c"

local function _getEspBackpack()
    return G.EspFruitBackpack or _G.EspFruitBackpack
end

local running = { fav = false, unfav = false }
local loopId  = { fav = 0, unfav = 0 }
local externalPaused = false
local pauseDepth = 0
local pauseReason = nil

-- Cache terpisah: fav = sudah di-fav script; unfav = sudah di-unfav script (anti spam)
local favCache = {}
local unfavCache = {}
do
    local extFav = G.__GAG2_FAV_CACHE or rawget(_G, "__GAG2_FAV_CACHE")
    if type(extFav) == "table" then
        favCache = extFav
    end
    local extUnfav = G.__GAG2_UNFAV_CACHE or rawget(_G, "__GAG2_UNFAV_CACHE")
    if type(extUnfav) == "table" then
        unfavCache = extUnfav
    end
end

local stats = {
    favProcessed   = 0,
    unfavProcessed = 0,
    lastStatus     = "Ready",
    lastError      = nil,
}

local candCache = {
    fav   = { n = 0, at = 0, key = "" },
    unfav = { n = 0, at = 0, key = "" },
}

local function _syncCache()
    G.__GAG2_FAV_CACHE = favCache
    _G.__GAG2_FAV_CACHE = favCache
    G.__GAG2_UNFAV_CACHE = unfavCache
    _G.__GAG2_UNFAV_CACHE = unfavCache
end

local function _truthyAttr(v)
    return v == true or v == 1 or v == "true" or v == "1"
end

local function _isFruitFavorited(tool)
    if not tool then return false end
    if type(tool) == "table" and typeof(tool) ~= "Instance" then
        if _truthyAttr(tool.IsFavorite) or _truthyAttr(tool.Favorite)
            or _truthyAttr(tool.Favorited) or _truthyAttr(tool.isFavorite)
            or _truthyAttr(tool.d) then
            return true
        end
        return false
    end
    if typeof(tool) ~= "Instance" or type(tool.GetAttribute) ~= "function" then
        return false
    end
    if _truthyAttr(tool:GetAttribute("IsFavorite")) then return true end
    if _truthyAttr(tool:GetAttribute("Favorite")) then return true end
    if _truthyAttr(tool:GetAttribute("Favorited")) then return true end
    if _truthyAttr(tool:GetAttribute("isFavorite")) then return true end
    if _truthyAttr(tool:GetAttribute("d")) then return true end
    return false
end

local function _isFavCached(id)
    id = tostring(id or "")
    return id ~= "" and favCache[id] == true
end

local function _isUnfavCached(id)
    id = tostring(id or "")
    return id ~= "" and unfavCache[id] == true
end

local function _markFavCached(id)
    id = tostring(id or "")
    if id == "" then return end
    favCache[id] = true
    unfavCache[id] = nil
    _syncCache()
end

local function _markUnfavCached(id)
    id = tostring(id or "")
    if id == "" then return end
    unfavCache[id] = true
    favCache[id] = nil
    _syncCache()
end

local function _clearFavCached(id)
    id = tostring(id or "")
    if id == "" then return end
    favCache[id] = nil
    _syncCache()
end

local function _clearUnfavCached(id)
    id = tostring(id or "")
    if id == "" then return end
    unfavCache[id] = nil
    _syncCache()
end

local function _dbg()
    return G.AUTO_FAV_DEBUG == true or _G.AUTO_FAV_DEBUG == true
end

local function _log(...)
    if _dbg() then print("[GAG2-Fav]", ...) end
end

local function _setStatus(msg, err)
    stats.lastStatus = tostring(msg or "")
    stats.lastError = err
    G.AUTO_FAV_STATUS = stats.lastStatus
    _G.AUTO_FAV_STATUS = stats.lastStatus
end

local function _normalizeSet(src)
    if type(src) ~= "table" then return {} end
    local out = {}
    for i = 1, #src do
        local v = src[i]
        if v ~= nil and tostring(v) ~= "" then out[tostring(v)] = true end
    end
    if next(out) then return out end
    for k, v in pairs(src) do
        if v == true or v == 1 or v == "true" then out[tostring(k)] = true end
    end
    return out
end

local function _arrayToMap(arr)
    return _normalizeSet(arr)
end

local function _canon(s)
    return tostring(s or ""):lower():gsub("[%s_%-]+", "")
end

local function _hasAny(map)
    if type(map) ~= "table" then return false end
    for _, v in pairs(map) do
        if v == true then return true end
    end
    return false
end

local function _normalizeKgFilter(kg, mode)
    kg = tonumber(kg) or 0
    mode = tostring(mode or "above")
    if kg < 0 then
        kg = math.abs(kg)
        mode = "below"
    end
    if mode ~= "below" then mode = "above" end
    return kg, mode
end

local function _normalizePriceFilter(price, mode)
    price = tonumber(price) or 0
    mode = tostring(mode or "above")
    if price < 0 then
        price = math.floor(math.abs(price))
        mode = "below"
    end
    if mode ~= "below" then mode = "above" end
    return price, mode
end

local function _parseKgRuleInput(txt)
    txt = tostring(txt or ""):gsub("%s+", "")
    if txt == "" then return 0, "above" end
    local n = tonumber(txt)
    if not n then return 0, "above" end
    if n < 0 then return math.abs(n), "below" end
    return n, "above"
end

local function _parseScaledNumber(txt)
    txt = tostring(txt or ""):lower():gsub("%s+", ""):gsub(",", "")
    if txt == "" then return nil end
    local sign = 1
    if txt:sub(1, 1) == "-" then
        sign = -1
        txt = txt:sub(2)
    end
    local suffixes = {
        { "juta", 1000000 }, { "jt", 1000000 },
        { "ribu", 1000 }, { "rb", 1000 },
        { "b", 1000000000 }, { "m", 1000000 }, { "k", 1000 },
    }
    for _, pair in ipairs(suffixes) do
        local suf, mult = pair[1], pair[2]
        if #txt > #suf and txt:sub(-#suf) == suf then
            local n = tonumber(txt:sub(1, -#suf - 1))
            if n then return n * mult * sign end
        end
    end
    local n = tonumber(txt)
    if n then return n * sign end
    return nil
end

local function _parsePriceRuleInput(txt)
    local n = _parseScaledNumber(txt)
    if not n then return 0, "above" end
    if n < 0 then return math.floor(math.abs(n)), "below" end
    return math.floor(n), "above"
end

local function _priceRuleActive(txt)
    txt = tostring(txt or ""):gsub("%s+", ""):gsub(",", "")
    return txt ~= "" and txt ~= "0"
end

local function _liveKgFilter(prefix, st)
    local rule = G[prefix .. "KG_RULE"] or rawget(_G, prefix .. "KG_RULE")
    if type(rule) == "string" and rule:gsub("%s+", "") ~= "" then
        return _parseKgRuleInput(rule)
    end
    if type(st.kgRule) == "string" and st.kgRule:gsub("%s+", "") ~= "" then
        return _parseKgRuleInput(st.kgRule)
    end
    return _normalizeKgFilter(
        G[prefix .. "KG"] or rawget(_G, prefix .. "KG") or st.kg,
        G[prefix .. "KG_MODE"] or rawget(_G, prefix .. "KG_MODE") or st.kgMode
    )
end

local function _livePriceFilter(prefix, st)
    local rule = G[prefix .. "MIN_PRICE_RULE"] or rawget(_G, prefix .. "MIN_PRICE_RULE")
    if type(rule) ~= "string" or rule:gsub("%s+", "") == "" then
        rule = type(st.minPriceRule) == "string" and st.minPriceRule or ""
    end
    if _priceRuleActive(rule) then
        local price, mode = _parsePriceRuleInput(rule)
        if price > 0 then return price, mode end
    end
    return _normalizePriceFilter(
        G[prefix .. "MIN_PRICE"] or rawget(_G, prefix .. "MIN_PRICE") or st.minPrice,
        G[prefix .. "MIN_PRICE_MODE"] or rawget(_G, prefix .. "MIN_PRICE_MODE") or st.minPriceMode
    )
end

local function _selectedMap(globalVal, stateArr)
    local fromGlobal = _normalizeSet(globalVal)
    if _hasAny(fromGlobal) then return fromGlobal end
    return _normalizeSet(_arrayToMap(stateArr))
end

local function _fruitId(tool)
    if not tool then return "" end
    if typeof(tool) == "Instance" and type(tool.GetAttribute) == "function" then
        return tostring(tool:GetAttribute("Id") or tool:GetAttribute("id")
            or tool:GetAttribute("UUID") or tool:GetAttribute("Uuid")
            or tool:GetAttribute("FruitId") or tool:GetAttribute("fruitId")
            or tool:GetAttribute("c") or "")
    end
    if type(tool) == "table" then
        return tostring(tool.Id or tool.id or tool.UUID or tool.Uuid or tool.FruitId or "")
    end
    return ""
end

local LAYOUT_ID_FIELDS = { "Id", "id", "UUID", "FruitId" }
local LAYOUT_MULTI_FIELDS = { "SizeMultiplier", "SizeMulti" }
local layoutMultiCache = { at = 0, byId = {} }
local LAYOUT_CACHE_SEC = 2.0

local function _pickLayoutField(t, fields)
    if type(t) ~= "table" then return nil end
    for _, f in ipairs(fields) do
        local v = t[f]
        if v ~= nil and tostring(v) ~= "" then return v end
    end
    return nil
end

local function _layoutFruitRow(raw)
    if type(raw) ~= "table" then return false end
    if raw.SeedTool or raw.Pet or raw.PottedPlant == true then return false end
    if tostring(raw.MainCategory or "") == "Seed" then return false end
    local id = _pickLayoutField(raw, LAYOUT_ID_FIELDS)
    if type(id) == "string" and #id >= 8 then return true end
    local name = tostring(_pickLayoutField(raw, { "FruitName", "Fruit", "Name", "name" }) or "")
    return name ~= ""
end

local function _collectLayoutRows(layout, out, depth, seen)
    if depth > 12 or type(layout) ~= "table" or seen[layout] then return end
    seen[layout] = true
    if _layoutFruitRow(layout) then
        out[#out + 1] = layout
        return
    end
    for _, v in pairs(layout) do
        if type(v) == "table" then
            if _layoutFruitRow(v) then
                out[#out + 1] = v
            else
                _collectLayoutRows(v, out, depth + 1, seen)
            end
        end
    end
end

local function _getBackpackLayout()
    local ok, net = pcall(function()
        return require(ReplicatedStorage.SharedModules.Networking)
    end)
    if not ok or type(net.Backpack) ~= "table" then return nil end
    local r = net.Backpack.GetLayout
    if not r then return nil end
    local ok2, layout
    if type(r) == "table" and r.Fire then ok2, layout = pcall(function() return r:Fire() end)
    elseif type(r) == "userdata" and r.InvokeServer then ok2, layout = pcall(function() return r:InvokeServer() end)
    elseif type(r) == "function" then ok2, layout = pcall(r) end
    return ok2 and type(layout) == "table" and layout or nil
end

local function _layoutMultiById()
    local now = os.clock()
    if layoutMultiCache.byId and (now - layoutMultiCache.at) <= LAYOUT_CACHE_SEC then
        return layoutMultiCache.byId
    end
    local byId = {}
    local layout = _getBackpackLayout()
    if layout then
        local rows = {}
        _collectLayoutRows(layout, rows, 0, {})
        for _, row in ipairs(rows) do
            local id = tostring(_pickLayoutField(row, LAYOUT_ID_FIELDS) or "")
            local multi = tonumber(_pickLayoutField(row, LAYOUT_MULTI_FIELDS)) or 0
            if id ~= "" and multi > 0 then
                byId[id] = multi
            end
        end
    end
    layoutMultiCache.at = now
    layoutMultiCache.byId = byId
    return byId
end

local function _layoutMultiForTool(tool)
    local id = _fruitId(tool)
    if id == "" then return 0 end
    return tonumber(_layoutMultiById()[id]) or 0
end

local function _getFilterState(key)
    key = (key == "unfav") and "unfav" or "fav"
    local MAIN = rawget(_G, "MAIN") or G.MAIN
    local st = MAIN and MAIN.auto and MAIN.auto[key]
    st = type(st) == "table" and st or {}

    local prefix = (key == "unfav") and "AUTO_UNFAV_" or "AUTO_FAV_"
    local enabled = (G[prefix .. "ENABLED"] == true) or (rawget(_G, prefix .. "ENABLED") == true) or (st.enabled == true)

    local fruits = _selectedMap(
        G[prefix .. "FRUITS_SELECTED"] or rawget(_G, prefix .. "FRUITS_SELECTED"),
        st.fruits
    )
    local mutations = _selectedMap(
        G[prefix .. "MUTATIONS_SELECTED"] or rawget(_G, prefix .. "MUTATIONS_SELECTED"),
        st.mutations
    )

    local kg, kgMode = _liveKgFilter(prefix, st)
    local minPrice, minPriceMode = _livePriceFilter(prefix, st)

    return {
        enabled    = enabled,
        fruits     = fruits,
        mutations  = mutations,
        kg         = kg,
        kgMode     = kgMode,
        minPrice   = minPrice,
        minPriceMode = minPriceMode,
        anyFruit   = _hasAny(fruits),
        anyMut     = _hasAny(mutations),
        anyKg      = kg > 0,
        anyPrice   = minPrice > 0,
    }
end

local function _fruitName(tool)
    if not tool then return "" end
    local fsv = _fsv()
    if fsv and type(fsv.resolveSeedName) == "function" then
        local ok, name = pcall(fsv.resolveSeedName, tool)
        if ok and name ~= nil and tostring(name) ~= "" then
            return tostring(name)
        end
    end
    return tostring(tool:GetAttribute("FruitName") or tool:GetAttribute("Fruit") or tool.Name or "")
end

local function _fruitWeight(tool)
    if not tool then return 0 end
    local attrW = tonumber(tool:GetAttribute("Weight"))
    if attrW and attrW > 0 then return attrW end
    local fsv = _fsv()
    if fsv and type(fsv.resolveWeight) == "function" then
        local ok, w = pcall(fsv.resolveWeight, tool)
        if ok and type(w) == "number" and w > 0 then return w end
    end
    return tonumber(tool:GetAttribute("Weight")) or 0
end

local function _priceToolQuick(tool)
    if not tool then return 0 end
    local fsv = _fsv()
    if not fsv then return 0 end

    if type(fsv.getBackpackEspPrice) == "function" then
        local name = _fruitName(tool)
        local multi = 0
        if type(fsv.resolveMulti) == "function" then
            local ok, m = pcall(fsv.resolveMulti, tool)
            if ok and type(m) == "number" then multi = m end
        end
        if multi <= 0 then
            multi = tonumber(tool:GetAttribute("SizeMultiplier") or tool:GetAttribute("SizeMulti")) or 0
        end
        if multi > 0 and name ~= "" then
            local id = _fruitId(tool)
            local bid = tonumber(tool:GetAttribute("BidPrice")) or 0
            local mode = "base"
            if type(fsv.getEspPriceMode) == "function" then
                local ok, m = pcall(fsv.getEspPriceMode)
                if ok and type(m) == "string" and m ~= "" then mode = m end
            end
            local ok, p = pcall(fsv.getBackpackEspPrice, name, multi, tool:GetAttribute("Mutation"),
                tool:GetAttribute("DecayAlpha"), mode, id ~= "" and id or nil, bid)
            if ok and type(p) == "number" and p > 0 then return p end
        end
    end

    if type(fsv.fromFruit) == "function" then
        local ok, p = pcall(fsv.fromFruit, tool, LP)
        if ok and type(p) == "number" and p > 0 then return p end
    end
    return 0
end

local function _mutationVariants(mut)
    if type(mut) ~= "string" or mut == "" then return { nil } end
    local out, seen = {}, {}
    local function add(v)
        if v == nil then
            if not seen["__nil__"] then
                seen["__nil__"] = true
                out[#out + 1] = nil
            end
            return
        end
        v = tostring(v):match("^%s*(.-)%s*$")
        if v == "" or seen[v] then return end
        seen[v] = true
        out[#out + 1] = v
    end
    add(mut)
    for token in string.gmatch(mut, "[^%+%,]+") do
        add(token)
    end
    add(nil)
    return out
end

local function _derivePriceMulti(tool, fsv, opts)
    opts = type(opts) == "table" and opts or {}
    local multi = 0
    if fsv and type(fsv.resolveMulti) == "function" then
        local ok, m = pcall(fsv.resolveMulti, tool)
        if ok and type(m) == "number" and m > 0 then multi = m end
    end
    if multi <= 0 then
        multi = tonumber(tool:GetAttribute("SizeMultiplier") or tool:GetAttribute("SizeMulti")) or 0
    end
    if multi <= 0 and not opts.skipLayout then
        multi = _layoutMultiForTool(tool)
    end
    return multi
end

local function _calcPriceVariants(fsv, name, multi, mut, decay, inst)
    if not fsv or type(fsv.calculate) ~= "function" or multi <= 0 or name == "" then
        return 0
    end
    for _, variant in ipairs(_mutationVariants(mut)) do
        local ok, p = pcall(fsv.calculate, name, multi, variant, inst or LP, decay)
        if ok and type(p) == "number" and p > 0 then return p end
    end
    return 0
end

local function _espPriceVariants(fsv, name, multi, mut, decay, mode, id, bidPrice)
    if not fsv or type(fsv.getBackpackEspPrice) ~= "function" or multi <= 0 or name == "" then
        return 0
    end
    for _, variant in ipairs(_mutationVariants(mut)) do
        local ok, p = pcall(fsv.getBackpackEspPrice, name, multi, variant, decay, mode, id, bidPrice)
        if ok and type(p) == "number" and p > 0 then return p end
    end
    return 0
end

local function _fruitPrice(tool, opts)
    if not tool then return 0 end
    opts = type(opts) == "table" and opts or {}

    if opts.fast then
        local fsv = _fsv()
        if fsv and type(fsv.fromFruit) == "function" then
            local ok, p = pcall(fsv.fromFruit, tool, LP)
            if ok and type(p) == "number" and p > 0 then return p end
        end
        local fsv2 = _fsv()
        local name = _fruitName(tool)
        if name == "" or not fsv2 then return 0 end
        local multi = _derivePriceMulti(tool, fsv2, { skipLayout = true })
        if multi <= 0 then return 0 end
        local mut = tool:GetAttribute("Mutation")
        return _calcPriceVariants(fsv2, name, multi, mut, tool:GetAttribute("DecayAlpha"), LP)
    end

    local fsv = _fsv()
    if not fsv then return 0 end
    if not opts.skipFsvRefresh and type(fsv.refresh) == "function" then
        pcall(fsv.refresh, true)
    end

    local name = _fruitName(tool)
    if name == "" then return 0 end

    local multi = _derivePriceMulti(tool, fsv, opts)
    if multi <= 0 then return 0 end

    local mut = tool:GetAttribute("Mutation")
    if (mut == nil or mut == "") and type(fsv.resolveMutation) == "function" then
        local okMut, m = pcall(fsv.resolveMutation, tool)
        if okMut then mut = m end
    end

    local decay = tool:GetAttribute("DecayAlpha")
    local id = _fruitId(tool)

    local bidPrice = tonumber(tool:GetAttribute("BidPrice")) or 0
    if bidPrice <= 0 and type(fsv.resolveBidPrice) == "function" then
        local okBid, b = pcall(fsv.resolveBidPrice, tool)
        if okBid and type(b) == "number" and b > 0 then bidPrice = b end
    end

    local espMode = "base"
    if type(fsv.getEspPriceMode) == "function" then
        local okMode, m = pcall(fsv.getEspPriceMode)
        if okMode and type(m) == "string" and m ~= "" then espMode = m end
    end

    local price = _espPriceVariants(fsv, name, multi, mut, decay, espMode, id, bidPrice)
    if price <= 0 and espMode ~= "base" then
        price = _espPriceVariants(fsv, name, multi, mut, decay, "base", id, bidPrice)
    end
    if price > 0 then return price end

    price = _calcPriceVariants(fsv, name, multi, mut, decay, LP)
    if price <= 0 then
        price = _calcPriceVariants(fsv, name, multi, mut, decay, nil)
    end
    if price > 0 then
        if bidPrice > 0 then
            return math.floor(price + bidPrice + 0.5)
        end
        return price
    end

    if type(fsv.getBackpackPrice) == "function" then
        for _, variant in ipairs(_mutationVariants(mut)) do
            local ok, p = pcall(fsv.getBackpackPrice, name, multi, variant, id ~= "" and id or nil, decay)
            if ok and type(p) == "number" and p > 0 then return p end
        end
    end

    if type(fsv.fromFruit) == "function" then
        local ok, p = pcall(fsv.fromFruit, tool, LP)
        if ok and type(p) == "number" and p > 0 then return p end
    end

    return 0
end

local function _appendMutationTokens(out, raw)
    if type(raw) ~= "string" or raw == "" then return end
    for token in string.gmatch(raw, "[^%+%,]+") do
        token = tostring(token):match("^%s*(.-)%s*$")
        if token and token ~= "" then out[#out + 1] = token end
    end
end

local function _parseMutationList(tool)
    local out = {}
    if tool then
        _appendMutationTokens(out, tool:GetAttribute("Mutation"))
    end
    if #out == 0 then
        local fsv = _fsv()
        if fsv and type(fsv.resolveMutation) == "function" then
            local ok, raw = pcall(fsv.resolveMutation, tool)
            if ok then _appendMutationTokens(out, raw) end
        end
    end
    return out
end

local function _isNoMutationKey(name)
    local c = _canon(name)
    return c == "nomutation" or c == "none" or tostring(name or "") == NO_MUTATION_LABEL
end

local function _fruitHasMutation(tool)
    if not tool then return false end
    local fsv = _fsv()
    if fsv and type(fsv.resolveMutation) == "function" then
        local ok, mut = pcall(fsv.resolveMutation, tool)
        if ok and type(mut) == "string" and mut ~= "" then return true end
    end
    for _, name in ipairs(_parseMutationList(tool)) do
        if name ~= "" then return true end
    end
    return false
end

local function _matchSet(selectedMap, value)
    if not _hasAny(selectedMap) then return true end
    local needle = _canon(value)
    for k, v in pairs(selectedMap) do
        if v == true and _canon(k) == needle then return true end
    end
    return false
end

local function _matchMutation(selectedMap, tool)
    if not _hasAny(selectedMap) then return true end
    if not tool then return false end
    if selectedMap[NO_MUTATION_LABEL] == true and not _fruitHasMutation(tool) then
        return true
    end
    local rawMut = tool:GetAttribute("Mutation")
    if type(rawMut) == "string" and rawMut ~= "" then
        if _matchSet(selectedMap, rawMut) then return true end
        for token in string.gmatch(rawMut, "[^%+%,]+") do
            if _matchSet(selectedMap, token) then return true end
        end
    end
    for mutName, on in pairs(selectedMap) do
        if on == true and not _isNoMutationKey(mutName) and tool:GetAttribute(mutName) == true then
            return true
        end
    end
    for _, mutName in ipairs(_parseMutationList(tool)) do
        if not _isNoMutationKey(mutName) and _matchSet(selectedMap, mutName) then
            return true
        end
    end
    local fsv = _fsv()
    if fsv and type(fsv.resolveMutation) == "function" then
        local ok, raw = pcall(fsv.resolveMutation, tool)
        if ok and type(raw) == "string" and raw ~= "" then
            for token in string.gmatch(raw, "[^%+%,]+") do
                if _matchSet(selectedMap, token) then
                    return true
                end
            end
        end
    end
    return false
end

local function _matchKg(weight, kg, mode)
    kg, mode = _normalizeKgFilter(kg, mode)
    weight = tonumber(weight) or 0
    if kg <= 0 then return true end
    if mode == "below" then
        return weight > 0 and weight <= kg
    end
    return weight >= kg
end

local function _matchPrice(price, filterPrice, mode)
    filterPrice, mode = _normalizePriceFilter(filterPrice, mode)
    price = tonumber(price) or 0
    if filterPrice <= 0 then return true end
    if mode == "below" then
        return price > 0 and price <= filterPrice
    end
    return price >= filterPrice
end

local function _matchesFilters(tool, ac, priceOpts)
    if ac.anyFruit and not _matchSet(ac.fruits, _fruitName(tool)) then return false end
    if ac.anyMut and not _matchMutation(ac.mutations, tool) then return false end
    if ac.anyKg and not _matchKg(_fruitWeight(tool), ac.kg, ac.kgMode) then return false end
    if ac.anyPrice and not _matchPrice(_fruitPrice(tool, priceOpts), ac.minPrice, ac.minPriceMode) then return false end
    return true
end

local function _isFruitTool(inst)
    if not inst or not inst.Parent then return false end
    if inst:GetAttribute("SeedTool") or inst:GetAttribute("Pet") then return false end
    if inst:GetAttribute("PottedPlant") == true then return false end
    if tostring(inst:GetAttribute("MainCategory") or "") == "Seed" then return false end
    if FruitProxyUtil and type(FruitProxyUtil.IsFruitInstance) == "function" then
        local ok, yes = pcall(FruitProxyUtil.IsFruitInstance, inst)
        if ok and yes then return true end
    end
    if inst:GetAttribute("FruitName") or inst:GetAttribute("Fruit") then return true end
    if inst:GetAttribute("FruitProxy") == true then return true end
    local hf = inst:GetAttribute("HarvestedFruit")
    if hf == true or (type(hf) == "string" and hf ~= "") then return true end
    if inst:GetAttribute("Id") and inst:GetAttribute("Weight") then return true end
    return inst:IsA("Tool")
end

local function _eachFruitTool(fn)
    if type(fn) ~= "function" then return end
    local seen = {}
    local function scan(root)
        if not root then return end
        -- Hanya direct children (seperti Backpack game) — GetDescendants scan part dalam tool = sangat lambat
        for _, inst in ipairs(root:GetChildren()) do
            if not seen[inst] and _isFruitTool(inst) then
                seen[inst] = true
                fn(inst)
            end
        end
    end
    scan(LP:FindFirstChild("Backpack") or LP:FindFirstChildOfClass("Backpack"))
    scan(LP.Character)
end

local function _toolMatchesFilter(tool, ac, priceMap)
    if not ac.anyFruit and not ac.anyMut and not ac.anyKg and not ac.anyPrice then
        return true
    end
    if ac.anyFruit and not _matchSet(ac.fruits, _fruitName(tool)) then return false end
    if ac.anyMut and not _matchMutation(ac.mutations, tool) then return false end
    if ac.anyKg and not _matchKg(_fruitWeight(tool), ac.kg, ac.kgMode) then return false end
    if ac.anyPrice then
        local id = _fruitId(tool)
        local price = (id ~= "" and priceMap and priceMap[id]) or 0
        if price <= 0 then price = _priceToolQuick(tool) end
        if not _matchPrice(price, ac.minPrice, ac.minPriceMode) then return false end
    end
    return true
end

local function _buildEspPriceMap()
    local map = {}
    local esp = _getEspBackpack()
    if not esp or type(esp.ScanFruits) ~= "function" then return map end
    local list, byId = esp.ScanFruits()
    if type(byId) == "table" then
        for id, entry in pairs(byId) do
            if type(entry) == "table" then
                local p = 0
                if type(esp.GetCachedEntryPrice) == "function" then
                    p = tonumber(esp:GetCachedEntryPrice(entry)) or 0
                end
                if p <= 0 and type(esp.GetEntryPrice) == "function" then
                    p = tonumber(esp:GetEntryPrice(entry)) or 0
                end
                if p > 0 then map[id] = p end
            end
        end
    elseif type(list) == "table" then
        for _, entry in ipairs(list) do
            local id = tostring(entry.id or "")
            if id ~= "" then
                local p = 0
                if type(esp.GetCachedEntryPrice) == "function" then
                    p = tonumber(esp:GetCachedEntryPrice(entry)) or 0
                end
                if p <= 0 and type(esp.GetEntryPrice) == "function" then
                    p = tonumber(esp:GetEntryPrice(entry)) or 0
                end
                if p > 0 then map[id] = p end
            end
        end
    end
    return map
end

local function _collectPendingFav(ac)
    ac = ac or _getFilterState("fav")
    local out = {}
    local priceMap = ac.anyPrice and _buildEspPriceMap() or nil

    _eachFruitTool(function(tool)
        local id = _fruitId(tool)
        if id == "" then return end
        if _isFruitFavorited(tool) then
            _markFavCached(id)
            return
        end
        if _isFavCached(id) then return end
        if _toolMatchesFilter(tool, ac, priceMap) then
            out[#out + 1] = tool
        end
    end)

    return out
end

local function _collectPendingUnfav(ac)
    ac = ac or _getFilterState("unfav")
    local out = {}
    local priceMap = ac.anyPrice and _buildEspPriceMap() or nil

    _eachFruitTool(function(tool)
        local id = _fruitId(tool)
        if id == "" then return end
        if not _isFruitFavorited(tool) then return end
        if _isUnfavCached(id) then return end
        if _toolMatchesFilter(tool, ac, priceMap) then
            out[#out + 1] = tool
        end
    end)

    return out
end

local function _pruneCache()
    local alive = {}
    _eachFruitTool(function(tool)
        local id = _fruitId(tool)
        if id ~= "" then
            alive[id] = true
            if unfavCache[id] and _isFruitFavorited(tool) then
                unfavCache[id] = nil
            end
            if favCache[id] and not _isFruitFavorited(tool) then
                favCache[id] = nil
            end
        end
    end)
    for id in pairs(favCache) do
        if not alive[id] then
            favCache[id] = nil
        end
    end
    for id in pairs(unfavCache) do
        if not alive[id] then
            unfavCache[id] = nil
        end
    end
    _syncCache()
end

local function _fireFavorite(tool, on)
    if not tool or not _ensureFavoriteRemote() then
        return false, "no_remote"
    end
    local id = _fruitId(tool)
    if id == "" then
        return false, "no_id"
    end
    on = (on == true)
    -- Sama seperti Backpack game: set attribute dulu, fire remote di background
    if typeof(tool) == "Instance" and type(tool.SetAttribute) == "function" then
        tool:SetAttribute("IsFavorite", on and true or nil)
    end
    if on then
        _markFavCached(id)
    else
        _markUnfavCached(id)
    end
    task.spawn(function()
        pcall(function()
            SetFruitFavorite:Fire(id, on)
        end)
    end)
    return true
end

local function _collectCandidates(mode, opts)
    opts = type(opts) == "table" and opts or {}
    local ac = _getFilterState(mode)
    if mode == "fav" then
        return _collectPendingFav(ac), ac
    end
    return _collectPendingUnfav(ac), ac
end

local function _runPass(mode, opts)
    opts = type(opts) == "table" and opts or {}
    local maxItems = math.floor(tonumber(opts.maxPerMode) or 0)
    local fireDelay = tonumber(opts.fireDelay)
    if fireDelay == nil or fireDelay < 0 then
        fireDelay = FIRE_DELAY
    end

    local collectOpts = {
        skipFsvRefresh = opts.skipFsvRefresh == true or opts.fastScan == true,
        fastScan = opts.fastScan == true,
    }
    if not collectOpts.skipFsvRefresh and not collectOpts.fastScan then
        local fsv = _fsv()
        if fsv and type(fsv.refresh) == "function" then
            pcall(fsv.refresh, true)
        end
        collectOpts.skipFsvRefresh = true
    end

    local wantOn = (mode == "fav")
    local list = _collectCandidates(mode, collectOpts)
    if #list == 0 then
        return false, "no_items", 0
    end

    local okCount = 0
    local limit = (#list)
    if maxItems > 0 and limit > maxItems then
        limit = maxItems
    end
    _setStatus(((mode == "fav") and "Fav" or "Unfav") .. (" scan: %d..."):format(limit))
    _log("pass", mode, limit, "of", #list)

    for i = 1, limit do
        local tool = list[i]
        if _fireFavorite(tool, wantOn) then
            okCount += 1
            if wantOn then
                stats.favProcessed += 1
            else
                stats.unfavProcessed += 1
            end
        end
        if i < limit and fireDelay > 0 then
            task.wait(fireDelay)
        end
    end

    if okCount > 0 then
        local tag = wantOn and "Fav" or "Unfav"
        _setStatus(("%s: %d buah"):format(tag, okCount))
        return true, "done", okCount
    end

    if wantOn and not _ensureFavoriteRemote() then
        _setStatus("Fav: remote belum ready")
        return false, "no_remote", 0
    end

    return false, "no_items", 0
end

local function _loop(mode, myId)
    task.wait(0.05)
    while running[mode] and loopId[mode] == myId do
        if externalPaused then
            task.wait(0.2)
        else
            local ac = _getFilterState(mode)
            if not ac.enabled then
                task.wait(0.5)
            else
                _pruneCache()
                local ok, reason = _runPass(mode)
                if reason == "no_items" then
                    _setStatus((mode == "fav") and "Fav: idle" or "Unfav: idle")
                    task.wait(IDLE_WAIT_SEC)
                elseif ok then
                    task.wait(0.05)
                else
                    task.wait(0.25)
                end
            end
        end
    end
end

local function _start(mode)
    mode = (mode == "unfav") and "unfav" or "fav"
    if running[mode] then return false end
    running[mode] = true
    loopId[mode] += 1
    local myId = loopId[mode]
    task.spawn(function()
        _loop(mode, myId)
    end)
    return true
end

local function _stop(mode)
    mode = (mode == "unfav") and "unfav" or "fav"
    running[mode] = false
    loopId[mode] += 1
end

local function _findFruitToolById(id)
    id = tostring(id or "")
    if id == "" then return nil end
    local found
    _eachFruitTool(function(tool)
        if not found and _fruitId(tool) == id then
            found = tool
        end
    end)
    return found
end

local function _layoutEntryFavorited(entry, depth)
    depth = math.floor(tonumber(depth) or 0)
    if depth > 5 or type(entry) ~= "table" then return false end
    if _truthyAttr(entry.IsFavorite) or _truthyAttr(entry.Favorite)
        or _truthyAttr(entry.Favorited) or _truthyAttr(entry.isFavorite)
        or _truthyAttr(entry.d) then
        return true
    end
    for _, key in ipairs({ "Attributes", "Data", "Fruit", "Entry", "Item" }) do
        local nested = entry[key]
        if type(nested) == "table" and _layoutEntryFavorited(nested, depth + 1) then
            return true
        end
    end
    return false
end

local function _getBackpackLayoutCached()
    local layout = G.__GAG2_NORMAL_GIFT_BACKPACK_LAYOUT or rawget(_G, "__GAG2_NORMAL_GIFT_BACKPACK_LAYOUT")
    if type(layout) == "table" then return layout end
    return _getBackpackLayout()
end

local function _layoutFavoritedById(id)
    id = tostring(id or "")
    if id == "" then return false end
    local layout = _getBackpackLayoutCached()
    if not layout then return false end
    local rows = {}
    _collectLayoutRows(layout, rows, 0, {})
    for _, row in ipairs(rows) do
        local rid = tostring(_pickLayoutField(row, LAYOUT_ID_FIELDS) or "")
        if rid == id and _layoutEntryFavorited(row, 0) then
            return true
        end
    end
    return false
end

-- Read-only: aman dipanggil meski Auto Fav / Auto Unfav toggle OFF.
function M.IsFruitFavorited(tool)
    if not tool then return false end
    if type(tool) == "table" and typeof(tool) ~= "Instance" then
        if _isFruitFavorited(tool) then return true end
        local id = _fruitId(tool)
        if id ~= "" then
            return M.IsFruitIdFavorited(id, nil)
        end
        return false
    end
    if typeof(tool) ~= "Instance" or type(tool.GetAttribute) ~= "function" then
        return false
    end
    if _isFruitFavorited(tool) then return true end
    local id = _fruitId(tool)
    if id ~= "" then
        if _layoutFavoritedById(id) then return true end
        if _isFavCached(id) then return true end
    end
    return false
end

-- Read-only: tidak fire remote, tidak ganggu loop Auto Fav/Unfav.
function M.IsFruitIdFavorited(id, toolHint)
    id = tostring(id or "")
    if id == "" then return false end
    if _isFavCached(id) then return true end

    local tool = toolHint
    if tool and (typeof(tool) ~= "Instance" or not tool.Parent) then
        tool = nil
    end
    if not tool then tool = _findFruitToolById(id) end
    if tool and _isFruitFavorited(tool) then return true end
    if _layoutFavoritedById(id) then return true end
    return false
end

function M.MarkFruitIdFavorited(id)
    _markFavCached(id)
end

M.isFruitFavorited = M.IsFruitFavorited
M.isFruitIdFavorited = M.IsFruitIdFavorited
M.markFruitIdFavorited = M.MarkFruitIdFavorited

function M.SetFavEnabled(on)
    on = (on == true)
    G.AUTO_FAV_ENABLED = on
    _G.AUTO_FAV_ENABLED = on
    _stop("fav")
