function M.StopFav() _stop("fav") end
function M.StartUnfav() return _start("unfav") end
function M.StopUnfav() _stop("unfav") end

-- Soft pause fav + unfav loops. Toggle/state MAIN tidak diubah.
function M.Pause(reason)
    pauseDepth += 1
    externalPaused = true
    if reason ~= nil then
        pauseReason = tostring(reason)
    end
    return pauseDepth
end

M.pause = M.Pause

function M.Resume()
    if pauseDepth > 0 then
        pauseDepth -= 1
    end
    if pauseDepth <= 0 then
        pauseDepth = 0
        externalPaused = false
        pauseReason = nil
    end
    return pauseDepth
end

M.resume = M.Resume

function M.IsPaused()
    return externalPaused == true
end

M.isPaused = M.IsPaused

function M.GetPauseReason()
    return pauseReason
end

-- One-shot favorite/unfavorite (tidak pakai filter Auto Fav/Unfav).
-- toolOrId: Tool instance atau fruit id string.
function M.SetFruitFavorite(toolOrId, on)
    on = (on == true)
    if typeof(toolOrId) == "Instance" then
        return _fireFavorite(toolOrId, on)
    end
    local id = tostring(toolOrId or "")
    if id == "" then return false, "no_id" end
    if not _ensureFavoriteRemote() then return false, "no_remote" end
    local tool = nil
    _eachFruitTool(function(t)
        if not tool and _fruitId(t) == id then
            tool = t
        end
    end)
    if tool then
        return _fireFavorite(tool, on)
    end
    if on then
        _markFavCached(id)
    else
        _markUnfavCached(id)
    end
    task.spawn(function()
        pcall(function()
            SetFruitFavorite:Fire(id, on)
        end)
    end)
    return true
end

M.setFruitFavorite = M.SetFruitFavorite

-- Unfav semua fruit favorited di backpack/character.
-- opts.fireDelay, opts.maxItems
function M.UnfavAllFavorited(opts)
    opts = type(opts) == "table" and opts or {}
    local fireDelay = tonumber(opts.fireDelay)
    if fireDelay == nil or fireDelay < 0 then fireDelay = FIRE_DELAY end
    local maxItems = math.floor(tonumber(opts.maxItems) or 0)
    local n = 0
    local list = {}
    _eachFruitTool(function(tool)
        if _isFruitFavorited(tool) then
            list[#list + 1] = tool
        end
    end)
    for i, tool in ipairs(list) do
        if maxItems > 0 and n >= maxItems then break end
        if _fireFavorite(tool, false) then
            n += 1
        end
        if fireDelay > 0 and i < #list then
            task.wait(fireDelay)
        end
    end
    return n
end

M.unfavAllFavorited = M.UnfavAllFavorited

-- Unfav favorited yang FruitName-nya ada di nameSet (map/list).
-- Stock sell: hanya tipe yang match stock.
function M.UnfavByFruitNames(nameSet, opts)
    -- Toleransi pemanggilan M:UnfavByFruitNames(set) → arg1 = self
    if type(nameSet) == "table" and nameSet.UnfavByFruitNames == M.UnfavByFruitNames then
        nameSet, opts = opts, nil
    end
    opts = type(opts) == "table" and opts or {}
    local fireDelay = tonumber(opts.fireDelay)
    if fireDelay == nil or fireDelay < 0 then fireDelay = FIRE_DELAY end
    local maxItems = math.floor(tonumber(opts.maxItems) or 0)

    local want = {}
    if type(nameSet) == "table" then
        local isArray = (#nameSet > 0)
        if isArray then
            for _, name in ipairs(nameSet) do
                local k = string.lower(tostring(name or ""))
                if k ~= "" then want[k] = true end
            end
        else
            for name, on in pairs(nameSet) do
                if on then
                    local k = string.lower(tostring(name or ""))
                    if k ~= "" then want[k] = true end
                end
            end
        end
    end
    if not next(want) then return 0 end

    local list = {}
    _eachFruitTool(function(tool)
        if not _isFruitFavorited(tool) then return end
        local name = string.lower(_fruitName(tool))
        if name ~= "" and want[name] then
            list[#list + 1] = tool
        end
    end)

    local n = 0
    for i, tool in ipairs(list) do
        if maxItems > 0 and n >= maxItems then break end
        if _fireFavorite(tool, false) then
            n += 1
        end
        if fireDelay > 0 and i < #list then
            task.wait(fireDelay)
        end
    end
    return n
end

M.unfavByFruitNames = M.UnfavByFruitNames

-- Unfav favorited by fruit id (map/list). Gift once harvest: hanya buah yang akan dikirim.
function M.UnfavByFruitIds(idSet, opts)
    if type(idSet) == "table" and idSet.UnfavByFruitIds == M.UnfavByFruitIds then
        idSet, opts = opts, nil
    end
    opts = type(opts) == "table" and opts or {}
    local fireDelay = tonumber(opts.fireDelay)
    if fireDelay == nil or fireDelay < 0 then fireDelay = FIRE_DELAY end
    local maxItems = math.floor(tonumber(opts.maxItems) or 0)

    local want = {}
    if type(idSet) == "table" then
        local isArray = (#idSet > 0)
        if isArray then
            for _, id in ipairs(idSet) do
                local k = tostring(id or "")
                if k ~= "" then want[k] = true end
            end
        else
            for id, on in pairs(idSet) do
                if on then
                    local k = tostring(id or "")
                    if k ~= "" then want[k] = true end
                end
            end
        end
    end
    if not next(want) then return 0 end

    local list = {}
    _eachFruitTool(function(tool)
        if not _isFruitFavorited(tool) then return end
        local id = _fruitId(tool)
        if id ~= "" and want[id] then
            list[#list + 1] = tool
        end
    end)

    local n = 0
    local fired = {}
    for i, tool in ipairs(list) do
        if maxItems > 0 and n >= maxItems then break end
        if _fireFavorite(tool, false) then
            n += 1
            local id = _fruitId(tool)
            if id ~= "" then fired[id] = true end
        end
        if fireDelay > 0 and i < #list then
            task.wait(fireDelay)
        end
    end
    -- Fallback: id yang tidak ketemu sebagai Tool — fire remote by id
    for id in pairs(want) do
        if not fired[id] then
            if maxItems > 0 and n >= maxItems then break end
            if M.SetFruitFavorite(id, false) then
                n += 1
                fired[id] = true
            end
            if fireDelay > 0 then
                task.wait(fireDelay)
            end
        end
    end
    return n
end

M.unfavByFruitIds = M.UnfavByFruitIds

function M.CheckFilter(mode)
    mode = (mode == "unfav") and "unfav" or "fav"
    local ac = _getFilterState(mode)
    local out = {
        mode = mode,
        enabled = ac.enabled,
        kg = ac.kg,
        kgMode = ac.kgMode,
        minPrice = ac.minPrice,
        minPriceMode = ac.minPriceMode,
        matched = 0,
        blocked = {},
    }

    _eachFruitTool(function(tool)
        local id = _fruitId(tool)
        if id == "" then return end
        local name = _fruitName(tool)
        local kg = _fruitWeight(tool)
        local price = _fruitPrice(tool)
        local mut = tool:GetAttribute("Mutation")

        if not ac.anyFruit and not ac.anyMut and not ac.anyKg and not ac.anyPrice then
            out.matched += 1
            return
        end

        if ac.anyFruit and not _matchSet(ac.fruits, name) then
            if #out.blocked < 5 then
                out.blocked[#out.blocked + 1] = { why = "fruit", name = name, kg = kg, price = price, mut = mut }
            end
            return
        end
        if ac.anyMut and not _matchMutation(ac.mutations, tool) then
            if #out.blocked < 5 then
                out.blocked[#out.blocked + 1] = { why = "mutation", name = name, kg = kg, price = price, mut = mut }
            end
            return
        end
        if ac.anyKg and not _matchKg(kg, ac.kg, ac.kgMode) then
            if #out.blocked < 5 then
                out.blocked[#out.blocked + 1] = { why = "kg", name = name, kg = kg, price = price, mut = mut }
            end
            return
        end
        if ac.anyPrice and not _matchPrice(price, ac.minPrice, ac.minPriceMode) then
            if #out.blocked < 5 then
                out.blocked[#out.blocked + 1] = { why = "price", name = name, kg = kg, price = price, mut = mut }
            end
            return
        end
        out.matched += 1
    end)

    print(("[GAG2-Fav Check:%s] kg=%s mode=%s | price=%s mode=%s | anyMut=%s anyKg=%s anyPrice=%s | matched=%d")
        :format(mode, ac.kg, ac.kgMode, ac.minPrice, ac.minPriceMode,
            ac.anyMut and "yes" or "no", ac.anyKg and "yes" or "no", ac.anyPrice and "yes" or "no", out.matched))
    for i, b in ipairs(out.blocked) do
        print("[GAG2-Fav Check] blocked", i, b.why, b.name or "", b.kg or "", b.price or "", b.mut or "")
    end
    return out
end

M.checkFilter = M.CheckFilter
_G.__GAG2_FAV_CHECK = function(mode) return M.CheckFilter(mode) end
_G.__GAG2_FAV_DIAG = function(mode) return M.Diagnose(mode) end
_G.__GAG2_FAV_CLEAR_CACHE = function() return M.ClearCache() end
_G.__GAG2_FAV_PRICE_DEBUG = function(needle)
    needle = tostring(needle or ""):lower()
    _eachFruitTool(function(tool)
        local name = _fruitName(tool):lower()
        if needle == "" or name:find(needle, 1, true) then
            local fsv = _fsv()
            print("[GAG2-Fav PriceDebug]", name,
                "kg=", _fruitWeight(tool),
                "multi=", _derivePriceMulti(tool, fsv),
                "mut=", tool:GetAttribute("Mutation"),
                "price=", _fruitPrice(tool),
                "fsv=", fsv and "ok" or "nil")
        end
    end)
end

local function _candidateCacheKey(mode, ac)
    return table.concat({
        mode,
        tostring(ac.kg or 0),
        tostring(ac.kgMode or "above"),
        tostring(ac.minPrice or 0),
        tostring(ac.minPriceMode or "above"),
        ac.anyFruit and "f1" or "f0",
        ac.anyMut and "m1" or "m0",
        ac.anyKg and "k1" or "k0",
        ac.anyPrice and "p1" or "p0",
    }, "|")
end

local function _storeCandidateCount(mode, ac, n)
    mode = (mode == "unfav") and "unfav" or "fav"
    local cache = candCache[mode]
    cache.n = math.max(0, math.floor(tonumber(n) or 0))
    cache.at = os.clock()
    cache.key = _candidateCacheKey(mode, ac)
end

function M.CountCandidates(mode, opts)
    mode = (mode == "unfav") and "unfav" or "fav"
    opts = type(opts) == "table" and opts or {}
    local list, ac = _collectCandidates(mode, {
        skipFsvRefresh = true,
        fastScan = opts.fastScan == true,
    })
    local n = #list
    _storeCandidateCount(mode, ac, n)
    return n
end

function M.HasPendingFav()
    local ac = _getFilterState("fav")
    if not ac.enabled then return false, 0 end
    local n = #_collectPendingFav(ac)
    return n > 0, n
end

M.hasPendingFav = M.HasPendingFav

function M.HasPendingUnfav()
    local ac = _getFilterState("unfav")
    if not ac.enabled then return false, 0 end
    local n = #_collectPendingUnfav(ac)
    return n > 0, n
end

M.hasPendingUnfav = M.HasPendingUnfav

function M.PeekCandidateCount(mode)
    mode = (mode == "unfav") and "unfav" or "fav"
    local ac = _getFilterState(mode)
    local cache = candCache[mode]
    local now = os.clock()
    local key = _candidateCacheKey(mode, ac)
    if cache.key == key and (now - cache.at) <= CAND_CACHE_SEC then
        return cache.n
    end
    return M.CountCandidates(mode)
end

M.peekCandidateCount = M.PeekCandidateCount

function M.FavOnce()
    _pruneCache()
    return _runPass("fav")
end

function M.UnfavOnce()
    _pruneCache()
    return _runPass("unfav")
end

-- Sebelum sell: 1x scan → fav semua pending → selesai (harga dari EspFruitBackpack cache)
function M.SyncBeforeSell(opts)
    if externalPaused then
        return 0, 0
    end
    opts = type(opts) == "table" and opts or {}
    local beforeSell = opts.beforeSell == true

    local favAc = _getFilterState("fav")
    local unfavAc = _getFilterState("unfav")
    local favN = 0
    local unfavN = 0

    if favAc.enabled then
        if beforeSell then
            local pending = _collectPendingFav(favAc)
            if #pending > 0 then
                local fireDelay = tonumber(opts.fireDelay)
                if fireDelay == nil or fireDelay < 0 then fireDelay = 0 end
                local maxWall = tonumber(opts.maxWallSec) or PRE_SELL_MAX_WALL_SEC
                local t0 = os.clock()
                for i = 1, #pending do
                    if (os.clock() - t0) >= maxWall then break end
                    if _fireFavorite(pending[i], true) then
                        favN += 1
                        stats.favProcessed += 1
                    end
                    if fireDelay > 0 and i < #pending then task.wait(fireDelay) end
                end
            end
        else
            local _, _, n = _runPass("fav", opts)
            favN = tonumber(n) or 0
        end
    end

    if not beforeSell and unfavAc.enabled then
        local _, _, n = _runPass("unfav", opts)
        unfavN = tonumber(n) or 0
    end

    _log("SyncBeforeSell", "beforeSell", beforeSell, "favOn", favAc.enabled, "fav", favN,
        "unfavOn", unfavAc.enabled, "unfav", unfavN)
    if favN > 0 or unfavN > 0 then
        _setStatus(("Pre-sell: fav %d, unfav %d"):format(favN, unfavN))
    elseif beforeSell and favAc.enabled then
        _setStatus("Pre-sell: tidak ada yang perlu di-fav")
    end

    return favN, unfavN
end

function M.GetStats()
    return {
        lastStatus = stats.lastStatus,
        lastError = stats.lastError,
        favProcessed = stats.favProcessed,
        unfavProcessed = stats.unfavProcessed,
        favRunning = running.fav,
        unfavRunning = running.unfav,
        paused = externalPaused,
        pauseDepth = pauseDepth,
        pauseReason = pauseReason,
        favReady = M.PeekCandidateCount("fav"),
        unfavReady = M.PeekCandidateCount("unfav"),
    }
end

function M.ClearCache()
    table.clear(favCache)
    table.clear(unfavCache)
    _syncCache()
end

function M.Diagnose(mode)
    mode = (mode == "unfav") and "unfav" or "fav"
    local ac = _getFilterState(mode)
    local toolCount, withId = 0, 0
    local sample = nil
    _eachFruitTool(function(tool)
        toolCount += 1
        local id = _fruitId(tool)
        if id ~= "" then withId += 1 end
        if not sample and id ~= "" then sample = tool end
    end)
    local fsv = _fsv()
    local fsvStatus = "missing"
    if fsv then
        fsvStatus = (type(fsv.isReady) == "function" and fsv:isReady()) and "ready" or "loaded"
    end
    print(("[GAG2-Fav Diagnose:%s] tools=%d withId=%d remote=%s enabled=%s fsv=%s")
        :format(mode, toolCount, withId, _ensureFavoriteRemote() and "ok" or "missing", ac.enabled and "yes" or "no", fsvStatus))
    local prefix = (mode == "unfav") and "AUTO_UNFAV_" or "AUTO_FAV_"
    local rawRule = G[prefix .. "MIN_PRICE_RULE"] or rawget(_G, prefix .. "MIN_PRICE_RULE") or ""
    print("  anyMut=", ac.anyMut, "anyKg=", ac.anyKg, "kg=", ac.kg, ac.kgMode,
        "anyPrice=", ac.anyPrice, "minPrice=", ac.minPrice, ac.minPriceMode, "rule=", rawRule)
    if _priceRuleActive(rawRule) and not ac.anyPrice then
        print("  WARN: price rule aktif tapi tidak terbaca — coba 3M / 3000000 / 3jt")
    end
    if sample then
        local multi = _derivePriceMulti(sample, _fsv())
        print("  sample mut=", sample:GetAttribute("Mutation"), "kg=", _fruitWeight(sample),
            "multi=", multi, "price=", _fruitPrice(sample), "match=", _matchesFilters(sample, ac))
    end
    local n = M.CountCandidates(mode)
    print("  candidates=", n, "status=", stats.lastStatus)
    return { tools = toolCount, withId = withId, candidates = n, ac = ac }
end

function M.SyncFromState()
    local fav = _getFilterState("fav")
    local unfav = _getFilterState("unfav")
    M.StopFav()
    M.StopUnfav()
    if fav.enabled then
        M.StartFav()
    end
    if unfav.enabled then
        M.StartUnfav()
    end
    if fav.enabled and unfav.enabled then
        _setStatus("Fav + Unfav aktif")
    elseif fav.enabled then
        _setStatus("Fav aktif")
    elseif unfav.enabled then
        _setStatus("Unfav aktif")
    end
end

M.syncFromState = M.SyncFromState

