 end,                        required = false },
    { key = "SectionAutoFav",          name = "Section Auto Fav",        factory = function() -- section_auto_fav.lua — UI Auto Fav / Auto Unfav Fruit (tab Auto)
-- Dipanggil dari tabs_auto.lua agar file utama tidak membengkak.

local G = (getgenv and getgenv()) or _G
local M = {}

local function parseKgRule(txt)
    txt = tostring(txt or ""):gsub("%s+", "")
    if txt == "" then return 0, "above" end
    local n = tonumber(txt)
    if not n then return 0, "above" end
    if n < 0 then return math.abs(n), "below" end
    return n, "above"
end

local function parseScaledNumber(txt)
    txt = tostring(txt or ""):gsub("%s+", ""):gsub(",", "")
    if txt == "" then return nil end
    local sign = 1
    if txt:sub(1, 1) == "-" then
        sign = -1
        txt = txt:sub(2)
    end
    local last = txt:sub(-1):upper()
    local mult = 1
    if last == "K" then
        mult = 1000
        txt = txt:sub(1, -2)
    elseif last == "M" then
        mult = 1000000
        txt = txt:sub(1, -2)
    elseif last == "B" then
        mult = 1000000000
        txt = txt:sub(1, -2)
    end
    local n = tonumber(txt)
    if not n then return nil end
    return n * mult * sign
end

local function parsePriceRule(txt)
    local n = parseScaledNumber(txt)
    if not n then return 0, "above" end
    if n < 0 then return math.floor(math.abs(n)), "below" end
    return math.floor(n), "above"
end

local function kgInputText(st)
    if type(st.kgRule) == "string" and st.kgRule:gsub("%s+", "") ~= "" then
        return st.kgRule
    end
    local kg = tonumber(st.kg) or 0
    local mode = tostring(st.kgMode or "above")
    if mode == "below" and kg > 0 then
        return "-" .. tostring(kg)
    end
    return tostring(kg)
end

local function priceInputText(st)
    if type(st.minPriceRule) == "string" and st.minPriceRule:gsub("%s+", "") ~= "" then
        return st.minPriceRule
    end
    local price = tonumber(st.minPrice) or 0
    local mode = tostring(st.minPriceMode or "above")
    if mode == "below" and price > 0 then
        return "-" .. tostring(price)
    end
    return tostring(price)
end

function M.Register(ctx)
    if type(ctx) ~= "table" or type(ctx.ui) ~= "table" then return end

    local ui = ctx.ui
    local getAuto = ctx.getAuto
    local patchAuto = ctx.patchAuto
    local patchAutoOnly = ctx.patchAutoOnly
    local registerFlush = ctx.registerFlush
    local cleanSelectedMap = ctx.cleanSelectedMap
    local arrayToMap = ctx.arrayToMap
    local mapToArray = ctx.mapToArray
    local toggleApiGet = ctx.toggleApiGet

    local PlantListView = G.PlantListView or rawget(_G, "PlantListView")

    local function buildBlock(key, sectionTitle, toggleLabel, enableApiGlobal)
        local ST = getAuto(key)
        if type(ST) ~= "table" then ST = {} end
        ST.fruits = type(ST.fruits) == "table" and ST.fruits or {}
        ST.mutations = type(ST.mutations) == "table" and ST.mutations or {}
        ST.kg = tonumber(ST.kg) or 0
        ST.kgMode = tostring(ST.kgMode or "above")
        ST.kgRule = type(ST.kgRule) == "string" and ST.kgRule or kgInputText(ST)
        ST.minPrice = tonumber(ST.minPrice) or 0
        ST.minPriceMode = tostring(ST.minPriceMode or "above")
