        local function syncModule()
            writeGlobals()
            local mod = G.AutoFav or G.AutoFavModule
            if type(mod) ~= "table" then return end
            if type(mod.SyncFromState) == "function" then
                pcall(mod.SyncFromState, mod)
            end
        end

        if key == "fav" then
            G.__GAG2_SYNC_AUTO_FAV = syncModule
