                local ok, n = pcall(mod.PeekCandidateCount, mod, key)
                if ok and type(n) == "number" then return n end
            end
            if type(mod) == "table" and type(mod.CountCandidates) == "function" then
                local ok, n = pcall(mod.CountCandidates, mod, key)
                if ok and type(n) == "number" then return n end
            end
            return 0
        end

        local _, statusTitle = ui:CreateRowLabel(
