                G[prefix .. "FRUITS_SELECTED"] = fruitsSelected
                _G[prefix .. "FRUITS_SELECTED"] = fruitsSelected
                ST.fruits = mapToArray(fruitsSelected)
                patchAuto(key, { fruits = ST.fruits }, syncModule)
            end,
        })

        ui:CreateRowDropdown(body, {
            label = "Select Mutation",
            placeholder = "All Mutation...",
