local EGG_MODULE_NAMES = { "EggData", "Eggs", "EggShopData", "PetEggData" }

local function _safeRequire(inst)
    if not inst or not inst:IsA("ModuleScript") then return nil end
    local ok, mod = pcall(require, inst)
    if ok and type(mod) == "table" then return mod end
    return nil
end

local function _firstModule(names)
