    if type(mod.Data) == "table" and #mod.Data > 0 then return mod.Data end
    if type(mod.Data) == "table" and next(mod.Data) ~= nil then return mod.Data end
    if type(mod.Gear) == "table" then return mod.Gear end
    if type(mod.Items) == "table" then return mod.Items end
    return mod
end

local function _normalizeEntry(entry, keyHint, orderHint)
    if type(entry) ~= "table" then return nil end

    local itemName = entry.CrateName or entry.ItemName or entry.GearName or entry.PropName
        or entry.PropId or entry.Name or entry.SeedName or entry.EggName
        or entry.PackName or entry.SeedPackName or keyHint
    if not itemName or tostring(itemName) == "" then return nil end

    local price = entry.Cost or entry.PurchasePrice or entry.Price or entry.FallbackPrice

    return {
        name     = tostring(itemName),
        itemType = entry.ItemType,
        rarity   = entry.Rarity,
        price    = price,
        order    = tonumber(entry.ShopDisplayOrder or entry.LayoutOrder or entry.SeedShopDisplayOrder)
            or tonumber(orderHint) or 9999,
        raw      = entry,
