    { key = "PetListView",             name = "PetListView",             factory = function() -- PetListView.lua — Grow A Garden 2
-- Catalog pet types + rarity dari SharedData.PetData (fallback: SharedModules.PetModules)

local ReplicatedStorage = game:GetService("ReplicatedStorage")

local SharedData = ReplicatedStorage:WaitForChild("SharedData", 15)
local SharedModules = ReplicatedStorage:WaitForChild("SharedModules", 15)

local M = {}

-- GAG2 pet rarities (SharedData.PetData): Common → Super
local GAG2_RARITY_TIER = {
    Common = 1,
    Uncommon = 2,
    Rare = 3,
    Legendary = 4,
    Mythic = 5,
    Super = 6,
}

local function _tierForRarity(rarityName)
    rarityName = tostring(rarityName or "")
    if rarityName == "" then return 0 end
    if GAG2_RARITY_TIER[rarityName] then
        return GAG2_RARITY_TIER[rarityName]
    end
    local want = rarityName:lower():gsub("[%s_%-]+", "")
    for name, tier in pairs(GAG2_RARITY_TIER) do
        if name:lower():gsub("[%s_%-]+", "") == want then
            return tier
        end
    end
    return 0
end

local function _safeRequire(inst)
    if not inst or not inst:IsA("ModuleScript") then return nil end
    local ok, mod = pcall(require, inst)
    if ok and type(mod) == "table" then return mod end
    return nil
end

local function _loadPetData()
    if not SharedData then return nil, "SharedData.PetData (missing SharedData)" end
    local root = SharedData:FindFirstChild("PetData")
    if not root or not root:IsA("ModuleScript") then
        return nil, "SharedData.PetData (missing)"
    end
    local mod = _safeRequire(root)
    if mod then return mod, "SharedData.PetData" end
    return nil, "SharedData.PetData (require failed)"
end

local function _loadPetModules()
    if not SharedModules then return nil, "SharedModules.PetModules (missing SharedModules)" end
    local root = SharedModules:FindFirstChild("PetModules")
    if not root then return nil, "SharedModules.PetModules (missing)" end

    if root:IsA("ModuleScript") then
        local mod = _safeRequire(root)
        if mod then return mod, "SharedModules.PetModules" end
    end

    local out = {}
    for _, child in ipairs(root:GetChildren()) do
        if child:IsA("ModuleScript") then
            local cfg = _safeRequire(child)
            if cfg then
                out[child.Name] = cfg
            end
        end
    end

    if next(out) then
        return out, "SharedModules.PetModules/*"
    end

    return nil, "SharedModules.PetModules (empty)"
end

local function _loadPetCatalog()
    local catalog, tag = _loadPetData()
    if catalog then return catalog, tag end
    return _loadPetModules()
end

local function _iterCatalog(catalog, fn)
    if type(catalog) ~= "table" then return end
    if catalog[1] ~= nil then
        for _, cfg in ipairs(catalog) do
            fn(nil, cfg)
        end
        return
    end
    for petName, cfg in pairs(catalog) do
        if type(cfg) == "function" then
            -- skip PetData helper methods (GetImage, GetDisplayName, ...)
        elseif type(cfg) == "table" then
            fn(petName, cfg)
        end
    end
end

local function _formatAssetId(raw)
    if raw == nil then return nil end
    if type(raw) == "number" then
        return "rbxassetid://" .. tostring(math.floor(raw))
    end
    local s = tostring(raw)
    if s == "" then return nil end
    if s:find("^rbxassetid://") or s:find("^http") then
        return s
    end
    if s:match("^%d+$") then
        return "rbxassetid://" .. s
    end
    return s
end

local function _resolvePetIcon(petName, cfg, catalog)
    if type(cfg) == "table" then
        local direct = _formatAssetId(cfg.Image or cfg.Icon or cfg.ImageId or cfg.Thumbnail)
        if direct then return direct end
    end
    if type(catalog) == "table" and type(catalog.GetImage) == "function" then
        local ok, img = pcall(catalog.GetImage, petName)
        if ok then
            local formatted = _formatAssetId(img)
            if formatted then return formatted end
        end
    end
    return nil
end

local function _normalizePetEntry(petName, cfg, catalog)
    petName = tostring(petName or "")
    if petName == "" then return nil end

    local rarity = nil
    local displayName = petName
    local assetName = nil
    if type(cfg) == "table" then
        rarity = cfg.Rarity or cfg.DisplayRarity
        displayName = cfg.DisplayName or petName
        assetName = cfg.AssetName or cfg.ModelName
    end

    return {
        name      = displayName,
        key       = petName,
        rarity    = rarity,
        assetName = assetName,
        icon      = _resolvePetIcon(petName, cfg, catalog),
        order     = 9999,
        raw       = cfg,
    }
end

local _petCache = nil
local _sourceTag = nil
local _rarityRank = {}
local _rarityOrder = {}

local function _petModuleRarity(cfg)
    if type(cfg) ~= "table" then return nil end
    local r = cfg.Rarity or cfg.DisplayRarity
    if r == nil or tostring(r) == "" then return nil end
    return tostring(r)
end

local function _petModulePrice(cfg)
    if type(cfg) ~= "table" then return 0 end
    return tonumber(cfg.BasePrice or cfg.PurchasePrice or cfg.Price or cfg.WildPrice or cfg.Cost or cfg.TamePrice) or 0
end

local function _rebuildRarityRank(rarityMaxPrice)
    local list = {}
    for rarity, price in pairs(rarityMaxPrice) do
        list[#list + 1] = { rarity = rarity, price = price }
    end
    table.sort(list, function(a, b)
        local ta = _tierForRarity(a.rarity)
        local tb = _tierForRarity(b.rarity)
        if ta ~= tb then
            if ta > 0 and tb > 0 then return ta > tb end
            if ta > 0 then return true end
            if tb > 0 then return false end
        end
        if a.price ~= b.price then return a.price > b.price end
        return tostring(a.rarity) < tostring(b.rarity)
    end)

    local rank = {}
    local order = {}
    local total = #list
    for i, item in ipairs(list) do
        rank[item.rarity] = total - i + 1
        order[#order + 1] = item.rarity
    end
    return rank, order
end

local function _ingestPetCfg(cfg, rarityMaxPrice)
    local rarity = _petModuleRarity(cfg)
    if not rarity then return end
    local price = _petModulePrice(cfg)
    rarityMaxPrice[rarity] = math.max(rarityMaxPrice[rarity] or 0, price)
end

function M.refreshRarityIndex(extraRarities)
    local rarityMaxPrice = {}

    local catalog = _loadPetCatalog()
    _iterCatalog(catalog, function(_, cfg)
        _ingestPetCfg(cfg, rarityMaxPrice)
    end)

    if type(extraRarities) == "table" then
        for _, rarity in ipairs(extraRarities) do
            rarity = tostring(rarity or "")
            if rarity ~= "" and not rarityMaxPrice[rarity] then
                local tier = _tierForRarity(rarity)
                rarityMaxPrice[rarity] = (tier > 0) and tier or 0
            end
        end
    end

    _rarityRank, _rarityOrder = _rebuildRarityRank(rarityMaxPrice)
    return _rarityRank, _rarityOrder
end

function M.getRarityRank(rarityName)
    rarityName = tostring(rarityName or "")
    if rarityName == "" then return 0 end

    local tier = _tierForRarity(rarityName)
    if tier > 0 then
        return tier
    end

    if next(_rarityRank) == nil then
        M.refreshRarityIndex()
    end
    if _rarityRank[rarityName] then
        return _rarityRank[rarityName]
    end
    local want = rarityName:lower()
    for k, v in pairs(_rarityRank) do
        if tostring(k):lower() == want then
            return v
        end
    end
    return 0
end

function M.getGag2RarityTier(rarityName)
    return _tierForRarity(rarityName)
end

function M.buildRarityItems(extraRarities)
    M.refreshRarityIndex(extraRarities)

    local out = {}
    for _, rarity in ipairs(_rarityOrder) do
        out[#out + 1] = { key = rarity, name = rarity }
    end

    if type(extraRarities) == "table" then
        local known = {}
        for _, item in ipairs(out) do
            known[item.key] = true
        end
        local extras = {}
        for _, rarity in ipairs(extraRarities) do
            rarity = tostring(rarity or "")
            if rarity ~= "" and not known[rarity] then
                extras[#extras + 1] = rarity
                known[rarity] = true
            end
        end
        table.sort(extras)
        for _, rarity in ipairs(extras) do
            out[#out + 1] = { key = rarity, name = rarity }
        end
    end

    return out
end

function M.getRarityColor(rarityName)
    rarityName = tostring(rarityName or "")
    if rarityName == "" then
        return Color3.fromRGB(255, 211, 0)
    end

    local rank = M.getRarityRank(rarityName)
    if next(_rarityOrder) == nil then
        M.refreshRarityIndex()
    end

    local maxRank = #_rarityOrder
    if rank > 0 and maxRank > 0 then
        local t = (maxRank > 1) and ((rank - 1) / (maxRank - 1)) or 0.5
        return Color3.fromHSV(0.08 + t * 0.72, 0.82, 1)
    end

    local h = 0
    for i = 1, #rarityName do
        h = (h + string.byte(rarityName, i) * i) % 360
    end
    return Color3.fromHSV(h / 360, 0.65, 0.95)
end

function M.getSourceTag()
    if _sourceTag then return _sourceTag end
    local _, tag = _loadPetCatalog()
    return tag or "SharedData.PetData (missing)"
end

function M.refresh()
    _petCache = nil
    _sourceTag = nil
    _rarityRank = {}
    _rarityOrder = {}
end

function M.buildPetItems()
    if _petCache then return _petCache end

    local catalog, tag = _loadPetCatalog()
    _sourceTag = tag or "SharedData.PetData (missing)"

    local arr = {}
    _iterCatalog(catalog, function(petName, cfg)
        local info = _normalizePetEntry(petName, cfg, catalog)
        if info then arr[#arr + 1] = info end
    end)

    table.sort(arr, function(a, b)
        return a.name < b.name
    end)

    local out = {}
    for _, info in ipairs(arr) do
        out[#out + 1] = {
            key   = info.key or info.name,
            name  = info.name,
            right = info.rarity,
            icon  = info.icon,
            raw   = info.raw,
        }
    end

    _petCache = out
    return _petCache
end

function M.getPetRarity(petName)
    petName = tostring(petName or "")
    if petName == "" then return nil end
    local want = petName:lower()
    for _, item in ipairs(M.buildPetItems()) do
        local key = tostring(item.key or "")
        local name = tostring(item.name or "")
        if key == petName or name == petName
            or key:lower() == want or name:lower() == want then
            local r = item.right
            if r ~= nil and tostring(r) ~= "" then
                return tostring(r)
            end
        end
    end
    return nil
end

function M.getPetIcon(petName)
    petName = tostring(petName or "")
    if petName == "" then return nil end
    local want = petName:lower()
    for _, item in ipairs(M.buildPetItems()) do
        local key = tostring(item.key or "")
        local name = tostring(item.name or "")
        if key == petName or name == petName
            or key:lower() == want or name:lower() == want then
            return item.icon
        end
    end
    return nil
end

function M.getPetBasePrice(petName)
    petName = tostring(petName or "")
    if petName == "" then return 0 end
    for _, item in ipairs(M.buildPetItems()) do
        if item.key == petName or item.name == petName then
            local raw = item.raw
            if type(raw) == "table" then
                return _petModulePrice(raw)
            end
        end
    end
    return 0
end

return M
 end,                    required = false },
    { key = "FriendStealList",         name = "FriendStealList",         factory = function() -- FriendStealList.lua — search Roblox users + store skip-steal friends (UI only for now)

local Players = game:GetService("Players")

local G = (getgenv and getgenv()) or _G
local M = G.FriendStealList or {}
G.FriendStealList = M

local nameCache = {}

local function trim(s)
    return tostring(s or ""):gsub("^%s+", ""):gsub("%s+$", "")
end

local function norm(s)
    return trim(s):lower()
end

function M.remember(userId, username)
    userId = tonumber(userId)
    if not userId or userId <= 0 then return end
    username = trim(username)
    if username ~= "" then
        nameCache[tostring(userId)] = username
    end
end

function M.getUsername(userId)
    userId = tonumber(userId)
    if not userId then return nil end
    local key = tostring(userId)
    if nameCache[key] then return nameCache[key] end
    local plr = Players:GetPlayerByUserId(userId)
    if plr then
        nameCache[key] = plr.Name
        return plr.Name
    end
    return nil
end

function M.normalizeList(raw)
    local out = {}
    local seen = {}
    if type(raw) ~= "table" then return out end

    local function add(uid, name)
        uid = tonumber(uid)
        if not uid or uid <= 0 or seen[uid] then return end
        seen[uid] = true
        name = trim(name)
        if name == "" then name = M.getUsername(uid) or ("UserId:" .. tostring(uid)) end
        M.remember(uid, name)
        out[#out + 1] = { userId = uid, username = name }
    end

    if raw[1] ~= nil then
        for _, row in ipairs(raw) do
            if type(row) == "table" then
                add(row.userId or row.id, row.username or row.name)
            elseif type(row) == "number" or type(row) == "string" then
                add(row, nil)
            end
        end
        return out
    end

    for k, v in pairs(raw) do
        if v == true or type(v) == "table" then
            if type(v) == "table" then
                add(v.userId or v.id or k, v.username or v.name)
            else
                add(k, nil)
            end
        end
    end
    return out
end

function M.toSelectedMap(list)
    local map = {}
    for _, row in ipairs(M.normalizeList(list)) do
        map[tostring(row.userId)] = true
    end
    return map
end

function M.fromSelectedMap(map, list)
    local out = {}
    local merged = {}
    for _, row in ipairs(M.normalizeList(list)) do
        merged[tostring(row.userId)] = row
    end
    if type(map) == "table" then
        for k, on in pairs(map) do
            if on then
                local key = tostring(k)
                local row = merged[key]
                if row then
                    out[#out + 1] = row
                else
                    local uid = tonumber(k)
                    if uid and uid > 0 then
                        local name = M.getUsername(uid) or ("UserId:" .. key)
                        out[#out + 1] = { userId = uid, username = name }
                    end
                end
            end
        end
    end
    table.sort(out, function(a, b)
        return norm(a.username) < norm(b.username)
    end)
    return out
end

function M.displayLabel(userId, list)
    userId = tonumber(userId)
    if not userId then return "" end
    if type(list) == "table" then
        for _, row in ipairs(M.normalizeList(list)) do
            if row.userId == userId and row.username and row.username ~= "" then
                return row.username .. " (" .. tostring(userId) .. ")"
            end
        end
    end
    local name = M.getUsername(userId)
    if name and name ~= "" then
        return name .. " (" .. tostring(userId) .. ")"
    end
    return "UserId:" .. tostring(userId)
end

function M.toDropdownItems(list)
    local items = {}
    for _, row in ipairs(M.normalizeList(list)) do
        items[#items + 1] = {
            key = tostring(row.userId),
            name = row.username .. " (" .. tostring(row.userId) .. ")",
        }
    end
    return items
end

function M.resolveUsername(username)
    username = trim(username):gsub("^@", "")
    if username == "" then return nil, "empty" end
    local ok, userId = pcall(function()
        return Players:GetUserIdFromNameAsync(username)
    end)
    if ok and type(userId) == "number" and userId > 0 then
        M.remember(userId, username)
        return userId, username
    end
    return nil, ok and "not_found" or tostring(userId)
end

-- Score username vs query: exact > prefix > substring (username only, min 3 chars).
local function scoreUsernameMatch(username, q, qLen)
    local n = norm(username)
    if n == q then return 100 end
    if qLen > 0 and n:sub(1, qLen) == q then return 80 end
    if qLen >= 3 and n:find(q, 1, true) then return 40 end
    return 0
end

function M.searchUsers(query, limit)
    limit = math.floor(tonumber(limit) or 10)
    if limit < 1 then limit = 10 end

    query = trim(query):gsub("^@", "")
    if query == "" then return {} end

    local q = norm(query)
    local qLen = #q
    local candidates = {}
    local seen = {}

    local function addCandidate(userId, username, score)
        userId = tonumber(userId)
        if not userId or userId <= 0 or score <= 0 then return end
        local skey = tostring(userId)
        if seen[skey] then
            for _, c in ipairs(candidates) do
                if c.userId == userId then
                    if score > c.score then
                        c.score = score
                        local u = trim(username)
                        if u ~= "" then c.username = u end
                    end
                    return
                end
            end
            return
        end
        seen[skey] = true
        username = trim(username)
        if username == "" then username = M.getUsername(userId) or ("UserId:" .. skey) end
        M.remember(userId, username)
        candidates[#candidates + 1] = { userId = userId, username = username, score = score }
    end

    for _, plr in ipairs(Players:GetPlayers()) do
        local s = scoreUsernameMatch(plr.Name, q, qLen)
        if s > 0 then
            addCandidate(plr.UserId, plr.Name, s + 5)
        end
    end

    if qLen >= 3 and not query:find("%s") then
        local uid = tonumber(query)
        if uid and uid > 0 then
            addCandidate(uid, M.getUsername(uid), 100)
        else
            local resolvedId, resolvedName = M.resolveUsername(query)
            if resolvedId then
                addCandidate(resolvedId, resolvedName, 100)
            end
        end
    end

    table.sort(candidates, function(a, b)
        if a.score ~= b.score then return a.score > b.score end
        return norm(a.username) < norm(b.username)
    end)

    local out = {}
    for i = 1, math.min(limit, #candidates) do
        local c = candidates[i]
        out[#out + 1] = {
            key = tostring(c.userId),
            name = c.username .. " (" .. tostring(c.userId) .. ")",
        }
    end
    return out
end

function M.isSkipOwner(ownerUserId, list)
    ownerUserId = tonumber(ownerUserId)
    if not ownerUserId or ownerUserId <= 0 then return false end
    for _, row in ipairs(M.normalizeList(list)) do
        if row.userId == ownerUserId then return true end
    end
    return false
end

return M
 end,                required = false },
    { key = "AutoBuy",                 name = "Auto Buy",                factory = function() -- AutoBuy.lua — Grow A Garden 2
-- Auto buy Seed / Gear / Props dari shop in-game.

local ReplicatedStorage = game:GetService("ReplicatedStorage")
local Players           = game:GetService("Players")

local LP = Players.LocalPlayer
local G  = (getgenv and getgenv()) or _G
local M  = {}

local SharedModules = ReplicatedStorage:WaitForChild("SharedModules")
local Networking    = require(SharedModules.Networking)

-- GAG2 packets (SharedModules.Networking):
--   SeedShop.PurchaseSeed(seedName)
--   GearShop.PurchaseGear(gearName)
--   CrateShop.PurchaseCrate(crateName)
local EXACT_REMOTES = {
    seed  = { net = Networking.SeedShop,  key = "PurchaseSeed",  path = "Networking.SeedShop.PurchaseSeed" },
    gear  = { net = Networking.GearShop,  key = "PurchaseGear",  path = "Networking.GearShop.PurchaseGear" },
    props = { net = Networking.CrateShop, key = "PurchaseCrate", path = "Networking.CrateShop.PurchaseCrate" },
}

local function _isFirePacket(obj)
    return type(obj) == "table" and type(obj.Fire) == "function"
end

local REMOTE_PATHS = {}
local REMOTES = {}

local function _ensureRemote(catKey)
    if REMOTES[catKey] then return REMOTES[catKey], REMOTE_PATHS[catKey] end

    local exact = EXACT_REMOTES[catKey]
    local pkt = exact and type(exact.net) == "table" and exact.net[exact.key]
    if _isFirePacket(pkt) then
        REMOTES[catKey] = pkt
        REMOTE_PATHS[catKey] = exact.path
        return pkt, exact.path
    end

    REMOTES[catKey] = nil
    REMOTE_PATHS[catKey] = nil
    return nil, nil
end

for _, cat in ipairs({ "seed", "gear", "props" }) do
    _ensureRemote(cat)
end

local StockValues = ReplicatedStorage:FindFirstChild("StockValues")

-- Live stock: ReplicatedStorage.StockValues.<Shop>.Items.<ItemName> (NumberValue)
local STOCK_VALUES_SHOPS = {
    seed  = { "SeedShop" },
    gear  = { "GearShop" },
    props = { "PropShop", "PropsShop", "CrateShop" },
}

local AFTER_BUY_SEC     = 0.12
local STOCK_POLL_SEC    = 2.0   -- ada stock, siap beli
local NO_MONEY_POLL_SEC = 8.0   -- pause per item kalau uang kurang (terkonfirmasi)
local NO_STOCK_POLL_SEC = 30    -- tidak ada stock → scan jarang (override: _G.AUTO_BUY_NO_STOCK_POLL)
local BUY_GAP = {
    seed  = 0.05,
    gear  = 0.08,
    props = 0.08,
}
local MAX_BUY_BURST = 6

local _stockFolderCache = {}
local _stockNodeCache = {}
local _watchConns = {}
local _watchSig = ""
local _buyDebounce = {}
local _priceCache = {}
local _brokeItems = {} -- key -> pause until (os.clock)
local _moneyConns = {}
local _lastMoney = nil

local running = false
local loopId  = 0

----------------------------------------------------------------
local function _dbg()
    return G.AUTO_BUY_DEBUG == true or _G.AUTO_BUY_DEBUG == true
end

local function _log(...)
    if not _dbg() then return end
    print("[GAG2-AB]", ...)
end

if not REMOTES.seed then
    warn("[GAG2-AB] Buy seed remote belum ketemu — jalankan _G.AutoBuy:GetDiagnostics() di console")
elseif _dbg() then
    _log("seed remote =", REMOTE_PATHS.seed)
end

local function _normalizeSet(src)
    if type(src) ~= "table" then return {} end
    local out = {}
    for i = 1, #src do
        local v = src[i]
        if v ~= nil and tostring(v) ~= "" then
            out[tostring(v)] = true
        end
    end
    if next(out) then return out end
    for k, v in pairs(src) do
        if v == true or v == 1 or v == "true" then
            out[tostring(k)] = true
        end
    end
    return out
end

local function _setToArray(map)
    local out = {}
    if type(map) ~= "table" then return out end
    for k, v in pairs(map) do
        if v == true then out[#out + 1] = tostring(k) end
    end
    table.sort(out)
    return out
end

local function _hasAnySelected(map)
    if type(map) ~= "table" then return false end
    for _, v in pairs(map) do
        if v == true then return true end
    end
    return false
end

local function _writeMainBuy(patch)
    local MAIN = rawget(_G, "MAIN") or G.MAIN
    if type(MAIN) ~= "table" then return end
    MAIN.auto = MAIN.auto or {}
    MAIN.auto.buy = MAIN.auto.buy or {}
    for k, v in pairs(patch) do
        MAIN.auto.buy[k] = v
    end
    G.MAIN = MAIN
    _G.MAIN = MAIN
end

local function getBuyState()
    local MAIN = rawget(_G, "MAIN") or G.MAIN
    local buy = MAIN and MAIN.auto and MAIN.auto.buy
    buy = type(buy) == "table" and buy or {}

    local seedOn = (G.AUTO_BUY_SEED_ENABLED == true)
        or (rawget(_G, "AUTO_BUY_SEED_ENABLED") == true)
        or (type(buy.seed) == "table" and buy.seed.enabled == true)

    local gearOn = (G.AUTO_BUY_GEAR_ENABLED == true)
        or (rawget(_G, "AUTO_BUY_GEAR_ENABLED") == true)
        or (type(buy.gear) == "table" and buy.gear.enabled == true)

    local propsOn = (G.AUTO_BUY_PROPS_ENABLED == true)
        or (rawget(_G, "AUTO_BUY_PROPS_ENABLED") == true)
        or (type(buy.props) == "table" and buy.props.enabled == true)

    return {
        seedEnabled  = seedOn,
        gearEnabled  = gearOn,
        propsEnabled = propsOn,
        seedSelected  = _normalizeSet(G.BUY_SEED_SELECTED or rawget(_G, "BUY_SEED_SELECTED") or (buy.seed and buy.seed.items)),
        gearSelected  = _normalizeSet(G.BUY_GEAR_SELECTED or rawget(_G, "BUY_GEAR_SELECTED") or (buy.gear and buy.gear.items)),
        propsSelected = _normalizeSet(G.BUY_PROPS_SELECTED or rawget(_G, "BUY_PROPS_SELECTED") or (buy.props and buy.props.items)),
    }
end

local function _readStockValue(inst)
    if not inst then return 0 end
    if inst:IsA("NumberValue") or inst:IsA("IntValue") then
        return math.max(0, math.floor(tonumber(inst.Value) or 0))
    end
    if inst:IsA("ValueBase") then
        return math.max(0, math.floor(tonumber(inst.Value) or 0))
    end
    if type(inst) == "number" then
        return math.max(0, math.floor(inst))
    end
    if type(inst) == "table" then
        return math.max(0, math.floor(tonumber(inst.Stock or inst.stock or inst.Value or inst.Amount or inst.Count) or 0))
    end
    return 0
end

local function _getStockValuesItemsFolder(catKey)
    local cached = _stockFolderCache[catKey]
    if cached and cached.Parent then return cached end

    if not StockValues then
        StockValues = ReplicatedStorage:FindFirstChild("StockValues")
    end
    if not StockValues then return nil end

    for _, shopName in ipairs(STOCK_VALUES_SHOPS[catKey] or {}) do
        local shop = StockValues:FindFirstChild(shopName)
        local items = shop and shop:FindFirstChild("Items")
        if items then
            _stockFolderCache[catKey] = items
            return items
        end
    end
    return nil
end

local function _getStockNode(catKey, itemName)
    local key = catKey .. "\0" .. itemName
    local node = _stockNodeCache[key]
    if node and node.Parent then return node end

    local folder = _getStockValuesItemsFolder(catKey)
    if not folder then return nil end

    node = folder:FindFirstChild(itemName)
    _stockNodeCache[key] = node
    return node
end

local function _readStockNode(node)
    if not node then return 0 end
    return _readStockValue(node)
end

local function _getLiveStockCount(catKey, itemName)
    local node = _getStockNode(catKey, itemName)
    if node then return _readStockNode(node) end

    local folder = _getStockValuesItemsFolder(catKey)
    if not folder then return nil end
    return 0
end

local function _collectLiveStocks(catKey)
    local folder = _getStockValuesItemsFolder(catKey)
    local out = {}
    if not folder then return out, false end

    for _, child in ipairs(folder:GetChildren()) do
        local count = _readStockValue(child)
        if count > 0 then
            out[child.Name] = count
        end
    end
    return out, true
end

local function _parseMoneyValue(raw)
    if raw == nil then return nil end
    if type(raw) == "number" then return raw end
    local s = tostring(raw):gsub(",", ""):gsub("%s+", "")
    if s == "" then return nil end
    local n = tonumber(s)
    if n then return n end
    local num, suf = s:match("^([%d%.]+)%s*([KMBkmb])?$")
    n = tonumber(num)
    if not n then return nil end
    suf = suf and suf:upper() or ""
    if suf == "K" then return n * 1000 end
    if suf == "M" then return n * 1000000 end
    if suf == "B" then return n * 1000000000 end
    return n
end

local function _getMoney()
    -- leaderstats = angka penuh (43,306,065). Attribute kadang format pendek (43.39) → salah hitung.
    local ls = LP:FindFirstChild("leaderstats")
    if ls then
        for _, n in ipairs({ "Sheckles", "Money", "Cash", "Coins" }) do
            local o = ls:FindFirstChild(n)
            if o and (o:IsA("IntValue") or o:IsA("NumberValue")) then
                local v = _parseMoneyValue(o.Value)
                if v ~= nil then return v end
            end
        end
    end

    local attr = LP:GetAttribute("Sheckles")
    if attr ~= nil then
        local v = _parseMoneyValue(attr)
        if v ~= nil then return v end
    end

    return nil
end

local function _mergePriceEntry(prices, entry, keyHint)
    if type(entry) ~= "table" then return end
    local itemName = entry.CrateName or entry.ItemName or entry.GearName
        or entry.PropName or entry.SeedName or entry.Name or keyHint
    if not itemName or tostring(itemName) == "" then return end
    local price = tonumber(entry.Cost or entry.PurchasePrice or entry.Price or entry.FallbackPrice)
    if price and price > 0 then
        prices[tostring(itemName)] = price
    end
end

local function _ensurePrices(catKey)
    if _priceCache[catKey] then return _priceCache[catKey] end

    local prices = {}

    if catKey == "seed" then
        local ok, seedData = pcall(require, SharedModules:WaitForChild("SeedData"))
        if ok and type(seedData) == "table" then
            if #seedData > 0 then
                for _, entry in ipairs(seedData) do
                    _mergePriceEntry(prices, entry)
                end
            else
                for key, entry in pairs(seedData) do
                    _mergePriceEntry(prices, entry, key)
                end
            end
        end
    elseif catKey == "gear" then
        for _, modName in ipairs({ "GearShopData", "GearData", "Gears" }) do
            local inst = SharedModules:FindFirstChild(modName)
            if inst and inst:IsA("ModuleScript") then
                local ok, data = pcall(require, inst)
                if ok and type(data) == "table" then
                    local catalog = data.Data or data.Gear or data.Items or data
                    if type(catalog) == "table" then
                        if #catalog > 0 then
                            for _, entry in ipairs(catalog) do
                                _mergePriceEntry(prices, entry)
                            end
                        else
                            for key, entry in pairs(catalog) do
                                _mergePriceEntry(prices, entry, key)
                            end
                        end
                    end
                end
                break
            end
        end
    elseif catKey == "props" then
        local crateRoot = SharedModules:FindFirstChild("CrateData")
        if crateRoot and crateRoot:IsA("ModuleScript") then
            local ok, crateApi = pcall(require, crateRoot)
            if ok and type(crateApi) == "table" then
                if type(crateApi.GetAllCrates) == "function" then
                    local ok2, all = pcall(function()
                        return crateApi.GetAllCrates()
                    end)
                    if ok2 and type(all) == "table" then
                        for key, entry in pairs(all) do
                            if type(entry) == "table" then
                                _mergePriceEntry(prices, entry, key)
                            end
                        end
                    end
                end
                for _, child in ipairs(crateRoot:GetChildren()) do
                    if child:IsA("ModuleScript") then
                        local ok3, entry = pcall(require, child)
                        if ok3 and type(entry) == "table" then
                            _mergePriceEntry(prices, entry, child.Name)
                        end
                    end
                end
            end
        end
    end

    _priceCache[catKey] = prices
    return prices
end

local function _getItemPrice(catKey, itemName)
    itemName = tostring(itemName or "")
    if itemName == "" then return nil end
    local prices = _ensurePrices(catKey)
    local price = tonumber(prices[itemName])
    if price and price > 0 then return price end

    local canon = itemName:lower():gsub("[^%w]+", "")
    for name, p in pairs(prices) do
        if tostring(name):lower():gsub("[^%w]+", "") == canon then
            p = tonumber(p)
            if p and p > 0 then return p end
        end
    end
    return nil
end

local function _itemKey(catKey, name)
    return tostring(catKey) .. "\0" .. tostring(name)
end

local function _clearBroke()
    table.clear(_brokeItems)
end

local function _noMoneyPollSec()
    local n = tonumber(G.AUTO_BUY_NO_MONEY_POLL or _G.AUTO_BUY_NO_MONEY_POLL) or NO_MONEY_POLL_SEC
    if n < 3 then n = 3 end
    if n > 120 then n = 120 end
    return n
end

local function _skipMoneyCheck()
    return G.AUTO_BUY_SKIP_MONEY_CHECK == true or _G.AUTO_BUY_SKIP_MONEY_CHECK == true
end

local function _isConfirmedPoor(catKey, name)
    if _skipMoneyCheck() then return false end
    local money = _getMoney()
    local price = _getItemPrice(catKey, name)
    return money ~= nil and price ~= nil and price > 0 and money < price
end

local function _markBroke(catKey, name)
    _brokeItems[_itemKey(catKey, name)] = os.clock() + _noMoneyPollSec()
    _log("broke", catKey, name, "money=", _getMoney(), "price=", _getItemPrice(catKey, name))
end

local function _isBroke(catKey, name)
    local untilAt = _brokeItems[_itemKey(catKey, name)]
    return type(untilAt) == "number" and os.clock() < untilAt
end

local function _canAfford(catKey, itemName)
    return not _isConfirmedPoor(catKey, itemName)
end

local function _bindMoneyWatch()
    if #_moneyConns > 0 then return end

    local function onMoneyMaybeChanged()
        local money = _getMoney()
        if money == nil then return end
        if _lastMoney == nil or money > _lastMoney then
            _clearBroke()
        end
        _lastMoney = money
    end

    table.insert(_moneyConns, LP:GetAttributeChangedSignal("Sheckles"):Connect(onMoneyMaybeChanged))

    local function hookLeaderstats(ls)
        if not ls then return end
        for _, n in ipairs({ "Sheckles", "Money", "Cash", "Coins" }) do
            local o = ls:FindFirstChild(n)
            if o and (o:IsA("IntValue") or o:IsA("NumberValue")) then
                table.insert(_moneyConns, o.Changed:Connect(onMoneyMaybeChanged))
            end
        end
    end

    hookLeaderstats(LP:FindFirstChild("leaderstats"))
    table.insert(_moneyConns, LP.ChildAdded:Connect(function(ch)
        if ch.Name == "leaderstats" then
            hookLeaderstats(ch)
            onMoneyMaybeChanged()
        end
    end))

    _lastMoney = _getMoney()
end

local function _clearMoneyWatch()
    for _, conn in ipairs(_moneyConns) do
        pcall(function() conn:Disconnect() end)
    end
    table.clear(_moneyConns)
end

local function _fireBuy(remote, itemName)
    if not remote or type(remote.Fire) ~= "function" then return false end
    return pcall(function()
        remote:Fire(tostring(itemName))
    end)
end

local function _resolveStocks(catKey)
    local live, hasLive = _collectLiveStocks(catKey)
    if hasLive then return live end
    return {}
end

local function _noStockPollSec()
    local n = tonumber(G.AUTO_BUY_NO_STOCK_POLL or _G.AUTO_BUY_NO_STOCK_POLL) or NO_STOCK_POLL_SEC
    if n < 5 then n = 5 end
    if n > 300 then n = 300 end
    return n
end

local function _hasRelevantStock(st)
    local function catHasStock(catKey, enabled, selected)
        if not enabled then return false end
        local hasFilter = _hasAnySelected(selected)
        if hasFilter then
            for name, on in pairs(selected) do
                if on and (_getLiveStockCount(catKey, tostring(name)) or 0) > 0 then
                    return true
                end
            end
            return false
        end
        return next(_resolveStocks(catKey)) ~= nil
    end

    return catHasStock("seed", st.seedEnabled, st.seedSelected)
        or catHasStock("gear", st.gearEnabled, st.gearSelected)
        or catHasStock("props", st.propsEnabled, st.propsSelected)
end

local function _loopWaitSec(st, bought)
    if bought > 0 then
        return AFTER_BUY_SEC
    end
    if _hasRelevantStock(st) then
        return STOCK_POLL_SEC
    end
    return _noStockPollSec()
end

local function _readStockCount(catKey, name, node)
    if node and node.Parent then
        return _readStockNode(node)
    end
    return _getLiveStockCount(catKey, name) or 0
end

local function _buyItemBurst(catKey, name, remote)
    if not remote then return 0 end
    name = tostring(name)

    if _isBroke(catKey, name) then
        return 0
    end

    if _isConfirmedPoor(catKey, name) then
        _markBroke(catKey, name)
        return 0
    end

    local key = catKey .. "\0" .. name
    if _buyDebounce[key] then return 0 end
    _buyDebounce[key] = true
    task.delay(0.15, function()
        _buyDebounce[key] = nil
    end)

    local node = _getStockNode(catKey, name)
    local gap = BUY_GAP[catKey] or 0.05
    local bought = 0

    for _ = 1, MAX_BUY_BURST do
        local count = _readStockCount(catKey, name, node)
        if count <= 0 then break end

        if _isConfirmedPoor(catKey, name) then
            _markBroke(catKey, name)
            break
        end

        if not _fireBuy(remote, name) then break end

        bought += 1
        _brokeItems[_itemKey(catKey, name)] = nil
        _log("buy", catKey, name, "left~", math.max(0, count - 1))

        if gap > 0 then
            task.wait(gap)
        end
    end

    return bought
end

local function _watchSignature(st)
    local parts = {
        st.seedEnabled and "1" or "0",
        st.gearEnabled and "1" or "0",
        st.propsEnabled and "1" or "0",
        table.concat(_setToArray(st.seedSelected), ","),
        table.concat(_setToArray(st.gearSelected), ","),
        table.concat(_setToArray(st.propsSelected), ","),
    }
    return table.concat(parts, "|")
end

local function _clearWatchers()
    for _, conn in ipairs(_watchConns) do
        pcall(function() conn:Disconnect() end)
    end
    table.clear(_watchConns)
    _watchSig = ""
end

local function _bindStockWatchers(st)
    local sig = _watchSignature(st)
    if sig == _watchSig then return end
    _clearWatchers()
    _watchSig = sig

    local function bindCat(catKey, enabled, selected)
        if not enabled then return end

        local remote = REMOTES[catKey] or select(1, _ensureRemote(catKey))
        if not remote then return end

        local folder = _getStockValuesItemsFolder(catKey)
        if not folder then return end

        local hasFilter = _hasAnySelected(selected)

        local function hookNode(node)
            if not node then return end
            _watchConns[#_watchConns + 1] = node.Changed:Connect(function()
                if not running then return end
                if _readStockNode(node) <= 0 then return end
                if hasFilter and not selected[node.Name] then return end
                if _isBroke(catKey, node.Name) then return end
                if _isConfirmedPoor(catKey, node.Name) then
                    _markBroke(catKey, node.Name)
                    return
                end
                task.defer(function()
                    if running then
                        _buyItemBurst(catKey, node.Name, remote)
                    end
                end)
            end)
        end

        if hasFilter then
            for name, on in pairs(selected) do
                if on then hookNode(_getStockNode(catKey, tostring(name))) end
            end
        else
            for _, child in ipairs(folder:GetChildren()) do
                hookNode(child)
            end
            _watchConns[#_watchConns + 1] = folder.ChildAdded:Connect(function(child)
                hookNode(child)
            end)
        end
    end

    bindCat("seed", st.seedEnabled, st.seedSelected)
    bindCat("gear", st.gearEnabled, st.gearSelected)
    bindCat("props", st.propsEnabled, st.propsSelected)
end

local function _processCategory(catKey, enabled, selected, remote)
    if not enabled then return 0 end

    remote = remote or select(1, _ensureRemote(catKey))
    if not remote then
        _log("skip", catKey, "remote missing")
        return 0
    end

    local hasFilter = _hasAnySelected(selected)
    local bought = 0

    if hasFilter then
        for name, on in pairs(selected) do
            if on then
                bought += _buyItemBurst(catKey, tostring(name), remote)
            end
        end
    else
        local stocks = _resolveStocks(catKey)
        for name, count in pairs(stocks) do
            if count > 0 then
                bought += _buyItemBurst(catKey, tostring(name), remote)
            end
        end
    end

    return bought
end

local function buyTick(st)
    st = st or getBuyState()
    local total = 0
    total += _processCategory("seed", st.seedEnabled, st.seedSelected, REMOTES.seed)
    total += _processCategory("gear", st.gearEnabled, st.gearSelected, REMOTES.gear)
    total += _processCategory("props", st.propsEnabled, st.propsSelected, REMOTES.props)
    return total
end

local function buyLoop(myId)
    _log("loop start", myId)
    _bindMoneyWatch()
    while running and myId == loopId do
        local st = getBuyState()
        if st.seedEnabled or st.gearEnabled or st.propsEnabled then
            _bindStockWatchers(st)
            local n = buyTick(st)
            task.wait(_loopWaitSec(st, n))
        else
            _clearWatchers()
            task.wait(0.5)
        end
    end
    _clearWatchers()
    _clearMoneyWatch()
    _log("loop end", myId)
end

