function M.GetLists()
    local PlantListView = G.PlantListView
    local ShopListView = G.ShopListView
    local seeds, gears, props = {}, {}, {}

    if type(PlantListView) == "table" and type(PlantListView.buildSeedItems) == "function" then
        seeds = PlantListView.buildSeedItems() or {}
    end
    if type(ShopListView) == "table" then
        if type(ShopListView.buildGearItems) == "function" then
            gears = ShopListView.buildGearItems() or {}
        end
        if type(ShopListView.buildPropsItems) == "function" then
            props = ShopListView.buildPropsItems() or {}
        end
    end

    return seeds, gears, props
end

function M.GetSeedStock(itemName)
    if not itemName then return 0 end
    return _getLiveStockCount("seed", tostring(itemName)) or 0
end

function M.GetAllSeedStocks()
    local stocks, ok = _collectLiveStocks("seed")
    return stocks, ok
end

function M.GetStock(catKey, itemName)
    catKey = tostring(catKey or "seed"):lower()
    if itemName then
        return _getLiveStockCount(catKey, tostring(itemName)) or 0
    end
    local stocks = select(1, _collectLiveStocks(catKey))
    return stocks
end

function M.GetRemotePath(catKey)
    catKey = tostring(catKey or "seed"):lower()
    local _, path = _ensureRemote(catKey)
    return path
end

function M.GetDiagnostics()
    local seedRemote, seedPath = _ensureRemote("seed")
    local gearRemote, gearPath = _ensureRemote("gear")
    local propsRemote, propsPath = _ensureRemote("props")
    local stocks, hasStock = _collectLiveStocks("seed")

    local sampleStock = {}
    if type(stocks) == "table" then
        local n = 0
        for name, count in pairs(stocks) do
            n += 1
            sampleStock[name] = count
            if n >= 5 then break end
        end
    end

    return {
        moduleLoaded = true,
        remotes = {
            seed  = { ok = seedRemote ~= nil,  path = seedPath },
            gear  = { ok = gearRemote ~= nil,  path = gearPath },
            props = { ok = propsRemote ~= nil, path = propsPath },
        },
        stockValues = {
            seedShop = hasStock,
            sample = sampleStock,
            blueberry = _getLiveStockCount("seed", "Blueberry") or 0,
        },
        poll = {
            afterBuySec = AFTER_BUY_SEC,
            stockPollSec = STOCK_POLL_SEC,
            noMoneyPollSec = _noMoneyPollSec(),
            noStockPollSec = _noStockPollSec(),
        },
        money = {
            sheckles = _getMoney(),
            skipCheck = _skipMoneyCheck(),
            pausedItems = (function()
                local n = 0
                for _, untilAt in pairs(_brokeItems) do
                    if type(untilAt) == "number" and os.clock() < untilAt then
                        n += 1
                    end
                end
                return n
            end)(),
        },
        state = getBuyState(),
        hint = (not seedRemote) and "Networking.SeedShop.PurchaseSeed tidak ditemukan — reload script"
            or "Uang kurang → pause "
                .. tostring(_noMoneyPollSec()) .. "s; restock watcher + fallback scan"
    }
end

function M.SyncFromGlobals()
    local st = getBuyState()
    G.AUTO_BUY_SEED_ENABLED = st.seedEnabled
    G.AUTO_BUY_GEAR_ENABLED = st.gearEnabled
    G.AUTO_BUY_PROPS_ENABLED = st.propsEnabled
    _G.AUTO_BUY_SEED_ENABLED = st.seedEnabled
    _G.AUTO_BUY_GEAR_ENABLED = st.gearEnabled
    _G.AUTO_BUY_PROPS_ENABLED = st.propsEnabled

    G.BUY_SEED_SELECTED = st.seedSelected
    G.BUY_GEAR_SELECTED = st.gearSelected
    G.BUY_PROPS_SELECTED = st.propsSelected
    _G.BUY_SEED_SELECTED = st.seedSelected
    _G.BUY_GEAR_SELECTED = st.gearSelected
    _G.BUY_PROPS_SELECTED = st.propsSelected
end

M.syncFromGlobals = M.SyncFromGlobals

function M.SetEnabled(cat, on)
    cat = tostring(cat or ""):lower()
    on = (on == true)

    if cat == "seed" or cat == "seeds" then
        G.AUTO_BUY_SEED_ENABLED = on
        _G.AUTO_BUY_SEED_ENABLED = on
        _writeMainBuy({ seed = { enabled = on, items = _setToArray(getBuyState().seedSelected) } })
    elseif cat == "gear" or cat == "gears" then
        G.AUTO_BUY_GEAR_ENABLED = on
        _G.AUTO_BUY_GEAR_ENABLED = on
        _writeMainBuy({ gear = { enabled = on, items = _setToArray(getBuyState().gearSelected) } })
    elseif cat == "props" or cat == "prop" then
        G.AUTO_BUY_PROPS_ENABLED = on
        _G.AUTO_BUY_PROPS_ENABLED = on
        _writeMainBuy({ props = { enabled = on, items = _setToArray(getBuyState().propsSelected) } })
    end

    if on then
        M.Start()
    else
        local st = getBuyState()
        if not st.seedEnabled and not st.gearEnabled and not st.propsEnabled then
            M.Stop()
        end
    end
end

function M.SetSelected(cat, map)
    cat = tostring(cat or ""):lower()
    map = _normalizeSet(map)

    if cat == "seed" or cat == "seeds" then
        G.BUY_SEED_SELECTED = map
        _G.BUY_SEED_SELECTED = map
        _writeMainBuy({ seed = { enabled = getBuyState().seedEnabled, items = _setToArray(map) } })
    elseif cat == "gear" or cat == "gears" then
        G.BUY_GEAR_SELECTED = map
        _G.BUY_GEAR_SELECTED = map
        _writeMainBuy({ gear = { enabled = getBuyState().gearEnabled, items = _setToArray(map) } })
    elseif cat == "props" or cat == "prop" then
        G.BUY_PROPS_SELECTED = map
        _G.BUY_PROPS_SELECTED = map
        _writeMainBuy({ props = { enabled = getBuyState().propsEnabled, items = _setToArray(map) } })
    end
    _watchSig = ""
end

function M.Start()
    _clearBroke()
    if not running then
        running = true
        loopId += 1
        local myId = loopId
        task.spawn(function() buyLoop(myId) end)
    end
end

M.start = M.Start

function M.Stop()
    running = false
    _clearWatchers()
    _clearMoneyWatch()
end

M.stop = M.Stop

function M.IsRunning()
    return running == true
end

function M.SyncFromState()
    M.SyncFromGlobals()
    local st = getBuyState()
    if st.seedEnabled or st.gearEnabled or st.propsEnabled then
        M.Start()
    else
        M.Stop()
    end
end

M.syncFromState = M.SyncFromState

function M.ClearBroke()
    _clearBroke()
end

function M.BuyOnce()
    return buyTick(getBuyState())
end

M.buyOnce = M.BuyOnce

G.AutoBuyModule = M
G.AutoBuy = M
_G.AutoBuyModule = M
_G.AutoBuy = M

pcall(function() M.SyncFromState() end)

return M
 end,                        required = false },
    { key = "Webhook",                 name = "Webhook",                 factory = function() -- Webhook.lua v2 — POST panel ke webhook.php (Discord embed)
-- Payload: event + player + petName + rarity + price + panel (tanpa fields/embed/blob)

local HttpService = game:GetService("HttpService")
local Players = game:GetService("Players")
local LP = Players.LocalPlayer
local G = (getgenv and getgenv()) or _G
local M = {}

M.VERSION = "2.16"

local function isNormalTrait(value)
    value = tostring(value or ""):lower():gsub("^%s+", ""):gsub("%s+$", "")
    return value == "" or value == "normal"
end

function M.formatPetDisplayName(baseName, petType, petSize)
    baseName = tostring(baseName or "")
    local extras = {}
    if not isNormalTrait(petType) then
        extras[#extras + 1] = tostring(petType)
    end
    if not isNormalTrait(petSize) then
        extras[#extras + 1] = tostring(petSize)
    end
    if #extras == 0 then
        return baseName
    end
    return baseName .. " ( " .. table.concat(extras, " , ") .. " )"
end

local API_URL = "https://golas.co.id/grow_a_garden25353466689966/webhook.php"
local EGG_HATCH_API_URL = "https://golas.co.id/grow_a_garden25353466689966/webhook_pet_egg.php"

local function apiUrl()
    local u = G.WEBHOOK_API_URL or _G.WEBHOOK_API_URL
    if type(u) == "string" and u ~= "" then
        return u
    end
    return API_URL
end

local function eggHatchApiUrl()
    local u = G.WEBHOOK_EGG_API_URL or rawget(_G, "WEBHOOK_EGG_API_URL")
    if type(u) == "string" and u ~= "" then
        return u
    end
    return EGG_HATCH_API_URL
end

local function getRequest()
    return (syn and syn.request)
        or (http and http.request)
        or http_request
        or (fluxus and fluxus.request)
        or request
end

local function parseHttpResponse(res)
    if type(res) ~= "table" then
        return true, { ok = true }
    end
    local code = tonumber(res.StatusCode or res.Status or res.status or res.status_code) or 0
    local text = tostring(res.Body or res.body or "")
    if code < 200 or code >= 300 then
        return false, ("HTTP %d: %s"):format(code, text:sub(1, 200))
    end
    if text == "" then
        return true, { ok = true }
    end
    local okJson, parsed = pcall(function()
        return HttpService:JSONDecode(text)
    end)
    if okJson and type(parsed) == "table" then
        if parsed.skipped == true then
            return true, parsed
        end
        return true, parsed
    end
    return true, { ok = true, raw = text }
end

local function httpPost(url, data)
    local headers = { ["Content-Type"] = "application/json" }
    local key = G.WEBHOOK_API_KEY or _G.WEBHOOK_API_KEY
    if type(key) == "string" and key ~= "" then
        headers["X-API-Key"] = key
    end

    local body = HttpService:JSONEncode(data)
    local req = getRequest()
    if type(req) == "function" then
        local ok, res = pcall(function()
            return req({
                Url = url,
                Method = "POST",
                Headers = headers,
                Body = body,
            })
        end)
        if ok then
            return parseHttpResponse(res)
        end
    end

    if HttpService.HttpEnabled then
        local ok, res = pcall(function()
            return HttpService:RequestAsync({
                Url = url,
                Method = "POST",
                Headers = headers,
                Body = body,
            })
        end)
        if ok and type(res) == "table" and res.Success == true then
            return parseHttpResponse({
                StatusCode = res.StatusCode,
                Body = res.Body,
            })
        end
        if ok and type(res) == "table" then
            return false, ("HttpService HTTP %d"):format(tonumber(res.StatusCode) or 0)
        end
    end

    return false, "no_http"
end

function M.PostJson(url, data)
    return httpPost(url, data)
end

function M.GetEggHatchApiUrl()
    return eggHatchApiUrl()
end

local function maskName(name)
    name = tostring(name or "")
    local len = #name
    if len == 0 then return "***" end
    if len <= 2 then return name:sub(1, 1) .. "*" end
    local half = math.max(1, math.floor(len / 2))
    return name:sub(1, half) .. string.rep("*", len - half)
end

local function buildPanel(player, basePetName, rarity, price, petType, petSize)
    local priceText = "-"
    local n = tonumber(price)
    if n and n > 0 then
        priceText = tostring(math.floor(n))
    end
    local lines = {
        "**Profile**",
        "| Username : " .. maskName(player),
        "",
        "**Pet Details**",
        "| Pet : " .. tostring(basePetName),
    }
    if not isNormalTrait(petType) then
        lines[#lines + 1] = "| Variant : " .. tostring(petType)
    end
    if not isNormalTrait(petSize) then
        lines[#lines + 1] = "| Size : " .. tostring(petSize)
    end
    lines[#lines + 1] = "| Rarity : " .. tostring(rarity)
    lines[#lines + 1] = "| Price : " .. priceText
    return table.concat(lines, "\n")
end

local function isBad(s)
    s = tostring(s or "")
    return s == "" or s == "Unknown"
end

function M.Send(data)
    if type(data) ~= "table" then
        return false, "bad_args"
    end
    return httpPost(apiUrl(), data)
end

--- Kirim notifikasi pet buy. Arg: { player, petName, petKey, petType, petSize, rarity, price }
function M.SendPetBuy(info)
    if type(info) ~= "table" then
        return false, "bad_args"
    end

    local player = tostring(info.player or LP.Name)
    local petKey = tostring(info.petKey or info.pet or "")
    local basePetName = tostring(info.petName or info.pet or "")
    local petType = info.petType or info.pet_type
    local petSize = info.petSize or info.pet_size
    local petName = M.formatPetDisplayName(basePetName, petType, petSize)
    local rarity = tostring(info.rarity or info.Rarity or info.r or "")
    local price = math.floor(tonumber(info.price) or 0)

    if isBad(basePetName) and isBad(petName) then
        return false, "no_pet"
    end
    if isBad(rarity) then
        return false, "no_rarity"
    end

    local panel = buildPanel(player, basePetName, rarity, price, petType, petSize)

    return M.Send({
        event = "PET_BUY",
        player = player,
        petName = petName,
        petKey = (petKey ~= "" and petKey) or basePetName,
        petType = isNormalTrait(petType) and nil or tostring(petType),
        petSize = isNormalTrait(petSize) and nil or tostring(petSize),
        pt = isNormalTrait(petType) and nil or tostring(petType),
        ps = isNormalTrait(petSize) and nil or tostring(petSize),
        rarity = rarity,
        price = price,
        panel = panel,
        luaVer = M.VERSION,
    })
end

local function eggHatchIsMatch(info)
    if type(info) ~= "table" then return false end
    if info.match == true or info.isMatch == true then return true end
    local raw = tostring(info.match or info.isMatch or ""):lower()
    if raw == "true" or raw == "1" then return true end
    return tostring(info.event or ""):upper() == "EGG_HATCH_MATCH"
end

local function optionalTrait(value)
    if isNormalTrait(value) then
        return nil
    end
    return tostring(value)
end

local function eggWebhookMaxOpenText(info)
    local maxOpen = tonumber(info.maxOpenEgg or info.max_open_egg)
    local target = tonumber(info.eggOpenTarget or info.egg_open_target)
    if maxOpen ~= nil and maxOpen > 0 then
        return tostring(math.floor(maxOpen))
    end
    if target ~= nil and target > 0 then
        return "All (" .. tostring(math.floor(target)) .. ")"
    end
    if maxOpen ~= nil and maxOpen <= 0 then
        return "All"
    end
    return "-"
end

local function eggWebhookBatchText(info)
    local opened = tonumber(info.eggOpenedThisCycle or info.egg_opened_this_cycle)
    local target = tonumber(info.eggOpenTarget or info.egg_open_target)
    if opened == nil or target == nil or target <= 0 then return nil end
    return tostring(math.max(0, math.floor(opened))) .. "/" .. tostring(math.max(0, math.floor(target)))
end

local function eggWebhookBatchRemainingText(info)
    local left = tonumber(info.eggBatchRemaining or info.egg_batch_remaining)
    if left == nil then
        local opened = tonumber(info.eggOpenedThisCycle or info.egg_opened_this_cycle)
        local target = tonumber(info.eggOpenTarget or info.egg_open_target)
        if opened ~= nil and target ~= nil and target > 0 then
            left = math.max(0, math.floor(target - opened))
        end
    end
    if left == nil then return nil end
    return tostring(math.max(0, math.floor(left)))
end

local function eggWebhookRemainingText(info)
    local left = tonumber(info.eggsRemaining or info.eggs_remaining or info.sisaEgg or info.sisa_egg)
    if left == nil then return "-" end
    return tostring(math.max(0, math.floor(left)))
end

local function eggWebhookMatchOpenText(info, isMatch)
    if not isMatch then return nil end
    local n = tonumber(info.matchOpenEgg or info.match_open_egg or info.eggOpenedThisCycle or info.egg_opened_this_cycle)
    if n == nil or n <= 0 then return nil end
    return "#" .. tostring(math.floor(n))
end

local function sendEggHatchNow(info, isMatch)
    local player = tostring(info.player or LP.Name)
    local petKey = tostring(info.petKey or info.pet or "")
    local basePetName = tostring(info.petName or info.pet or "")
    local petType = info.petType or info.pet_type
    local petSize = info.petSize or info.pet_size
    local eggName = tostring(info.eggName or info.egg or "")
    local petName = M.formatPetDisplayName(basePetName, petType, petSize)
    local rarity = tostring(info.rarity or info.Rarity or "")
    local hatchTitle = isMatch and "Egg Hatch match" or "Egg Hatch"

    if isBad(basePetName) and isBad(petName) then
        return false, "no_pet"
    end

    local panelLines = {
        "**Profile**",
        "| Username : " .. maskName(player),
        "",
        "**" .. hatchTitle .. "**",
        "| Egg : " .. (eggName ~= "" and eggName or "-"),
        "| Pet : " .. tostring(basePetName),
    }
    if not isNormalTrait(petType) then
        panelLines[#panelLines + 1] = "| Variant : " .. tostring(petType)
    end
    if not isNormalTrait(petSize) then
        panelLines[#panelLines + 1] = "| Size : " .. tostring(petSize)
    end
    if rarity ~= "" and not isBad(rarity) then
        panelLines[#panelLines + 1] = "| Rarity : " .. rarity
    end
    panelLines[#panelLines + 1] = "| Max Open Egg : " .. eggWebhookMaxOpenText(info)
    local batchText = eggWebhookBatchText(info)
    if batchText ~= nil then
        panelLines[#panelLines + 1] = "| Open Batch : " .. batchText
    end
    local batchLeft = eggWebhookBatchRemainingText(info)
    if batchLeft ~= nil then
        panelLines[#panelLines + 1] = "| Sisa Batch : " .. batchLeft
    end
    panelLines[#panelLines + 1] = "| Sisa Egg (Inv) : " .. eggWebhookRemainingText(info)
    local matchOpen = eggWebhookMatchOpenText(info, isMatch)
    if matchOpen ~= nil then
        panelLines[#panelLines + 1] = "| Match Open Egg : " .. matchOpen
    end

    local payload = {
        event = isMatch and "EGG_HATCH_MATCH" or "EGG_HATCH",
        match = isMatch,
        isMatch = isMatch,
        player = player,
        petName = petName,
        petKey = (petKey ~= "" and petKey) or basePetName,
        eggName = eggName,
        rarity = rarity,
        panel = table.concat(panelLines, "\n"),
        jobId = tostring(game.JobId),
        placeId = tostring(game.PlaceId),
        luaVer = M.VERSION,
    }

    local maxOpenEgg = tonumber(info.maxOpenEgg or info.max_open_egg)
    local eggOpenTarget = tonumber(info.eggOpenTarget or info.egg_open_target)
    local eggOpenedThisCycle = tonumber(info.eggOpenedThisCycle or info.egg_opened_this_cycle)
    local eggsRemaining = tonumber(info.eggsRemaining or info.eggs_remaining or info.sisaEgg or info.sisa_egg)
    local eggBatchRemaining = tonumber(info.eggBatchRemaining or info.egg_batch_remaining)
    local matchOpenEgg = tonumber(info.matchOpenEgg or info.match_open_egg)
    if maxOpenEgg ~= nil then payload.maxOpenEgg = math.max(0, math.floor(maxOpenEgg)) end
    if eggOpenTarget ~= nil then payload.eggOpenTarget = math.max(0, math.floor(eggOpenTarget)) end
    if eggOpenedThisCycle ~= nil then payload.eggOpenedThisCycle = math.max(0, math.floor(eggOpenedThisCycle)) end
    if eggBatchRemaining ~= nil then payload.eggBatchRemaining = math.max(0, math.floor(eggBatchRemaining)) end
    if eggsRemaining ~= nil then payload.eggsRemaining = math.max(0, math.floor(eggsRemaining)) end
    if isMatch and matchOpenEgg ~= nil and matchOpenEgg > 0 then
        payload.matchOpenEgg = math.floor(matchOpenEgg)
    elseif isMatch and eggOpenedThisCycle ~= nil and eggOpenedThisCycle > 0 then
        payload.matchOpenEgg = math.floor(eggOpenedThisCycle)
    end

    local pt = optionalTrait(petType)
    local ps = optionalTrait(petSize)
    if pt then
        payload.petType = pt
        payload.pt = pt
    end
    if ps then
        payload.petSize = ps
        payload.ps = ps
    end

    return httpPost(eggHatchApiUrl(), payload)
end

local function _logEggHatchPostFail(kind, detail, url)
    warn(("[Webhook] egg %s gagal (%s): %s"):format(
        tostring(kind or "hatch"),
        tostring(url or eggHatchApiUrl()),
        tostring(detail or "unknown")
    ))
end

local function _logEggHatchPostOk(kind, detail, url)
    if type(detail) == "table" and detail.skipped == true then
        warn(("[Webhook] egg %s skipped by PHP (%s): %s"):format(
            tostring(kind),
            tostring(url or eggHatchApiUrl()),
            tostring(detail.reason or "unknown")
        ))
    end
end

--- Kirim notifikasi egg hatch. Arg: { player, petName, petKey, petType, petSize, eggName, rarity, match, maxOpenEgg, eggOpenTarget, eggsRemaining, eggOpenedThisCycle, matchOpenEgg }
function M.SendEggHatch(info)
    if type(info) ~= "table" then
        return false, "bad_args"
    end

    local isMatch = eggHatchIsMatch(info)
    local url = eggHatchApiUrl()
    local ok, detail = sendEggHatchNow(info, isMatch)
    if ok ~= true then
        _logEggHatchPostFail(isMatch and "match" or "hatch", detail, url)
    else
        _logEggHatchPostOk(isMatch and "match" or "hatch", detail, url)
    end
    return ok, detail
end

--- Test ping ke webhook_pet_egg.php (GET health check)
function M.PingEggHatchApi()
    local url = eggHatchApiUrl()
    local req = getRequest()
    if type(req) == "function" then
        local ok, res = pcall(function()
            return req({ Url = url, Method = "GET" })
        end)
        if ok and type(res) == "table" then
            local code = tonumber(res.StatusCode or res.status) or 0
            local text = tostring(res.Body or res.body or "")
            return code >= 200 and code < 300, { code = code, body = text:sub(1, 300), url = url }
        end
    end
    if HttpService.HttpEnabled then
        local ok, res = pcall(function()
            return HttpService:RequestAsync({ Url = url, Method = "GET" })
        end)
        if ok and type(res) == "table" then
            return res.Success == true, {
                code = res.StatusCode,
                body = tostring(res.Body or ""):sub(1, 300),
                url = url,
            }
        end
    end
    return false, { error = "no_http", url = url }
end

function M.LoadFromUrl(url)
    url = url or G.WEBHOOK_MODULE_URL or _G.WEBHOOK_MODULE_URL
    if type(url) ~= "string" or url == "" then
        return false, "no_url"
    end
    if not url:find("^https?://", 1) then
        url = "https://" .. url
    end

    local req = getRequest()
    local body
    if req then
        local res = req({ Url = url, Method = "GET" })
        body = res and (res.Body or res.body)
    else
        body = game:HttpGet(url)
    end
    if type(body) ~= "string" or body == "" or body:sub(1, 1) == "<" then
        return false, "not_lua"
    end

    body = body:gsub("^%EF%BB%BF", "")
    local fn, err
    if load then
        fn, err = load(body, "webhook", "t", getgenv() or _G)
    end
    if type(fn) ~= "function" and loadstring then
        fn, err = loadstring(body, "webhook")
    end
    if type(fn) ~= "function" then
        return false, err or "compile_fail"
    end

    local ok, mod = pcall(fn)
    if not ok or type(mod) ~= "table" then
        return false, mod or "run_fail"
    end

    G.Webhook = mod
    G.WebhookModule = mod
    _G.Webhook = mod
    _G.WebhookModule = mod
    return true, mod
end

G.Webhook = M
G.WebhookModule = M
_G.Webhook = M
_G.WebhookModule = M

return M
 end,                       required = false },
    { key = "WebhookFruitCarrot",      name = "Webhook Fruit Carrot",    factory = function() -- WebhookFruitCarrot.lua — scan carrot di garden (sama logic EspFruitGarden)
-- Webhook saat carrot >= MIN_KG — hanya jika Auto Vuln Fruit toggle ON

local G = (getgenv and getgenv()) or _G
local M = {}

M.VERSION = "2.1"

local DEFAULT_CFG = {
    MIN_KG = 50,
    POLL_SEC = 1.0,          -- was 0.25 — webhook tidak perlu 4 scan/detik
    PROMPT_CACHE_SEC = 2.0,  -- cache daftar HarvestPrompt per plot
    API_URL = "https://golas.co.id/grow_a_garden25353466689966/webhook_fruit_carrot.php",
    SKIP_EXISTING = true, -- buah sudah >= MIN_KG saat script jalan → tidak kirim
}

local function cfg()
    local c = G.GAG2_CARROT_WEBHOOK_CFG or rawget(_G, "GAG2_CARROT_WEBHOOK_CFG")
    if type(c) ~= "table" then
        c = {}
        G.GAG2_CARROT_WEBHOOK_CFG = c
        _G.GAG2_CARROT_WEBHOOK_CFG = c
    end
    for k, v in pairs(DEFAULT_CFG) do
        if c[k] == nil then c[k] = v end
    end
    return c
end

local HttpService = game:GetService("HttpService")
local Players = game:GetService("Players")
local CollectionService = game:GetService("CollectionService")
local LP = Players.LocalPlayer

local HARVEST_TAG = "HarvestPrompt"
local PLOT_CACHE_SEC = 3

local FruitSellValue
pcall(function()
    FruitSellValue = require(script.Parent.FruitSellValue)
end)
if type(FruitSellValue) ~= "table" then
    FruitSellValue = G.FruitSellValue or rawget(_G, "FruitSellValue")
end

local function getSentStore()
    local t = G.__GAG2_CARROT_WH_SENT
    if type(t) ~= "table" then
        t = {}
        G.__GAG2_CARROT_WH_SENT = t
        _G.__GAG2_CARROT_WH_SENT = t
    end
    return t
end

local sentModels = {}
local fruitTrack = {} -- key -> last kg seen
local bootstrapped = false
local loopToken = 0
local cachedPlot = nil
local cachedPlotAt = 0
local promptScanCache = { plot = nil, at = 0, list = {} }
local fromSeedCache = { at = 0, label = "Unknown" }

local function _vulnFlagOn(gKey)
    if G[gKey] == true then return true end
    if rawget(_G, gKey) == true then return true end
    return false
end

local function isVulnFruitEnabled()
    local main = G.MAIN or rawget(_G, "MAIN")
    if type(main) == "table" and type(main.misc) == "table" and type(main.misc.auto_vuln) == "table" then
        local av = main.misc.auto_vuln
        return av.auto_save == true
            or av.auto_rejoin_rollback_seed0 == true
            or av.go_home_on_fruit == true
            or av.auto_rollback == true
            or av.auto_rejoin_loading_stuck == true
    end
    return _vulnFlagOn("AUTO_VULN_AUTO_SAVE")
        or _vulnFlagOn("AUTO_VULN_AUTO_REJOIN_ROLLBACK_SEED0")
        or _vulnFlagOn("AUTO_VULN_GO_HOME_ON_FRUIT")
        or _vulnFlagOn("AUTO_VULN_AUTO_ROLLBACK")
        or _vulnFlagOn("AUTO_VULN_AUTO_REJOIN_LOADING_STUCK")
end

M.IsVulnFruitEnabled = isVulnFruitEnabled

local function apiUrl()
    local u = cfg().API_URL or G.WEBHOOK_CARROT_API_URL or rawget(_G, "WEBHOOK_CARROT_API_URL")
    if type(u) == "string" and u ~= "" then return u end
    return "https://golas.co.id/grow_a_garden25353466689966/webhook_fruit_carrot.php"
end

local function getRequest()
    return (syn and syn.request)
        or (http and http.request)
        or http_request
        or (fluxus and fluxus.request)
        or request
end

local function httpPost(url, data)
    local req = getRequest()
    if not req then return false, "no_http" end

    local headers = { ["Content-Type"] = "application/json" }
    local key = G.WEBHOOK_API_KEY or rawget(_G, "WEBHOOK_API_KEY")
    if type(key) == "string" and key ~= "" then
        headers["X-API-Key"] = key
    end

    local body = HttpService:JSONEncode(data)
    local ok, res = pcall(function()
        return req({
            Url = url,
            Method = "POST",
            Headers = headers,
            Body = body,
        })
    end)
    if not ok then return false, tostring(res) end

    local code = res.StatusCode or res.status or 0
    local text = res.Body or res.body or ""
    if code < 200 or code >= 300 then
        return false, ("HTTP %d: %s"):format(code, text:sub(1, 200))
    end
    if text == "" then return true, { ok = true } end
    local okJson, parsed = pcall(function()
        return HttpService:JSONDecode(text)
    end)
    if okJson and type(parsed) == "table" then return true, parsed end
    return true, { ok = true }
end

local function maskName(name)
    name = tostring(name or "")
    local len = #name
    if len == 0 then return "***" end
    if len <= 2 then return name:sub(1, 1) .. "*" end
    local half = math.max(1, math.floor(len / 2))
    return name:sub(1, half) .. string.rep("*", len - half)
end

local function canonName(s)
    return tostring(s or ""):lower():gsub("[%s_%-]+", "")
end

local function isCarrotName(name)
    local c = canonName(name)
    return c:find("carrot", 1, true) ~= nil
end

local function fsv()
    local f = FruitSellValue or G.FruitSellValue or rawget(_G, "FruitSellValue")
    return type(f) == "table" and f or nil
end

local function parseKgText(text)
    return tonumber(tostring(text or ""):match("([%d%.]+)%s*[kK][gG]"))
end

local function walkModels(model, fn, maxDepth)
    maxDepth = maxDepth or 12
    local node, depth = model, 0
    while node and depth < maxDepth do
        if node:IsA("Model") then
            local stop = fn(node)
            if stop then return stop end
        end
        if node.Name == "Gardens" then break end
        node = node.Parent
        depth += 1
    end
    return nil
end

local function readGameBillboard(model)
    if not model then return nil end
    local kg = nil
    for _, d in ipairs(model:GetDescendants()) do
        if d:IsA("TextLabel") then
            local w = parseKgText(d.Text)
            if w and w > 0 and (not kg or w > kg) then kg = w end
        end
    end
    return kg
end

local function weightFromAttributes(model)
    local walked = walkModels(model, function(node)
        local bw = tonumber(node:GetAttribute("BaseWeight"))
        local sm = tonumber(node:GetAttribute("SizeMulti") or node:GetAttribute("SizeMultiplier"))
        local og = tonumber(node:GetAttribute("OvertimeGrowth")) or 1
        if bw and bw > 0 and sm and sm > 0 then
            return bw * sm * og
        end
        local w = tonumber(node:GetAttribute("Weight"))
        if w and w > 0 then return w end
        return nil
    end)
    if type(walked) == "number" and walked > 0 then return walked end
    return nil
end

-- Murah dulu (attribute / FSV), billboard GetDescendants cuma fallback
local function displayKg(model)
    if not model then return 0 end

    local f = fsv()
    if f and type(f.resolveWeight) == "function" then
        local ok, w = pcall(f.resolveWeight, model)
        if ok and type(w) == "number" and w > 0 then return w end
    end

    local attrKg = weightFromAttributes(model)
    if attrKg and attrKg > 0 then return attrKg end

    local bbKg = readGameBillboard(model)
    if bbKg and bbKg > 0 then return bbKg end

    return 0
end

local function fruitNameFast(model)
    if not model then return "?" end
    local n = model:GetAttribute("FruitName")
        or model:GetAttribute("CorePartName")
        or model:GetAttribute("FruitType")
    if n ~= nil and tostring(n) ~= "" then return tostring(n) end

    local f = fsv()
    if f and type(f.resolveSeedName) == "function" then
        local ok, resolved = pcall(f.resolveSeedName, model)
        if ok and type(resolved) == "string" and resolved ~= "" then return resolved end
    end
    return tostring(model.Name or "?")
end

local function normalizeSeedSet(src)
    if type(src) ~= "table" then return {} end
    local out = {}
    if src[1] ~= nil then
        for _, v in ipairs(src) do
            local s = tostring(v)
            if s ~= "" then out[s] = true end
        end
    else
        for k, v in pairs(src) do
            if v == true or v == 1 or v == "true" then
                out[tostring(k)] = true
            end
        end
    end
    return out
end

--- From Seed = seed yang dipilih di Auto Plant (UI selected seeds)
local function autoPlantFromSeedLabel()
    local seeds = nil

    local AP = G.AutoPlant or G.AutoPlantModule or rawget(_G, "AutoPlant")
    if type(AP) == "table" and type(AP.GetState) == "function" then
        local ok, st = pcall(AP.GetState, AP)
        if ok and type(st) == "table" and type(st.seeds) == "table" then
            seeds = st.seeds
        end
    end

    if type(seeds) ~= "table" or not next(seeds) then
        seeds = G.AUTO_PLANT_SEEDS_SELECTED or rawget(_G, "AUTO_PLANT_SEEDS_SELECTED")
    end

    if type(seeds) ~= "table" or not next(seeds) then
        local MAIN = rawget(_G, "MAIN") or G.MAIN
        local ap = MAIN and MAIN.auto and MAIN.auto.plant
        if type(ap) == "table" then
            seeds = ap.seeds
        end
    end

    seeds = normalizeSeedSet(seeds)
    local names = {}
    for name in pairs(seeds) do
        names[#names + 1] = name
    end
    table.sort(names)

    if #names == 0 then return "Unknown" end
    if #names == 1 then return names[1] end
    return table.concat(names, ", ")
end

local function getFromSeedLabel()
    local now = os.clock()
    if (now - fromSeedCache.at) < 10 then
        return fromSeedCache.label
    end
    fromSeedCache.label = autoPlantFromSeedLabel()
    fromSeedCache.at = now
    return fromSeedCache.label
end

--- GetTagged HarvestPrompt + filter plot (sama AutoCollect — jauh lebih ringan dari GetDescendants plot)
local function iterPlotHarvestPrompts(plot, force)
    if not plot then return {} end

    local CFG = cfg()
    local cacheSec = tonumber(CFG.PROMPT_CACHE_SEC) or 2.0
    local now = os.clock()
    if not force
        and promptScanCache.plot == plot
        and (now - promptScanCache.at) <= cacheSec
        and #promptScanCache.list > 0 then
        return promptScanCache.list
    end

    local out = {}
    local checked = 0
    for _, prompt in ipairs(CollectionService:GetTagged(HARVEST_TAG)) do
        if prompt:IsA("ProximityPrompt") and prompt:IsDescendantOf(plot) then
            out[#out + 1] = prompt
        end
        checked += 1
        if checked >= 200 then
            checked = 0
            task.wait()
        end
    end

    promptScanCache.plot = plot
    promptScanCache.at = now
    promptScanCache.list = out
    return out
end

local function isCarrotFruit(model, name)
    name = tostring(name or "")
    if isCarrotName(name) then return true end
    if not model then return false end

    for _, attr in ipairs({ "FruitName", "CorePartName", "FruitType", "SeedName" }) do
        if isCarrotName(model:GetAttribute(attr)) then return true end
    end

    local hit = walkModels(model, function(node)
        for _, attr in ipairs({ "FruitName", "CorePartName", "FruitType", "SeedName" }) do
            if isCarrotName(node:GetAttribute(attr)) then return true end
        end
        return nil
    end)
    return hit == true
end

local function isHarvestPrompt(prompt)
    if not prompt or not prompt:IsA("ProximityPrompt") then return false end
    if CollectionService:HasTag(prompt, HARVEST_TAG) then return true end
    local action = tostring(prompt.ActionText or ""):lower()
    if action:find("harvest", 1, true) or action:find("collect", 1, true) then
        return true
    end
    local obj = tostring(prompt.ObjectText or ""):lower()
    if obj:find("harvest", 1, true) or obj:find("fruit", 1, true) then
        return true
    end
    return tostring(prompt.Name or ""):lower():find("harvest", 1, true) ~= nil
end

local function fruitFromPrompt(prompt)
    if not prompt or not prompt.Parent then return nil end
    local node, best = prompt.Parent, nil
    while node do
        if node:IsA("Model") then
            local pid = node:GetAttribute("PlantId")
            if pid ~= nil and tostring(pid) ~= "" then
                best = node
                if node:GetAttribute("FruitId") ~= nil then return node end
            end
        end
        if node.Name == "Gardens" then break end
        node = node.Parent
    end
    return best or prompt.Parent:FindFirstAncestorWhichIsA("Model")
end

local function resolveIds(model)
    if not model then return "", "" end
    local plantId, fruitId = "", ""
    local node, depth = model, 0
    while node and depth < 12 do
        if node:IsA("Model") then
            if plantId == "" then
                local p = node:GetAttribute("PlantId")
                if p ~= nil and tostring(p) ~= "" then plantId = tostring(p) end
            end
            if fruitId == "" then
                local f = node:GetAttribute("FruitId")
                if f ~= nil and tostring(f) ~= "" then fruitId = tostring(f) end
            end
        end
        if node.Name == "Gardens" then break end
        node = node.Parent
        depth += 1
    end
    return plantId, fruitId
end

local function isFruitSent(plantId, fruitId, model)
    if model and sentModels[model] then return true end
    local sent = getSentStore()
    if sent[plantId .. "|"] then return true end
    if fruitId ~= "" and sent[plantId .. "|" .. fruitId] then return true end
    return false
end

local function markFruitSent(plantId, fruitId, model)
    local sent = getSentStore()
    sent[plantId .. "|"] = true
    if fruitId ~= "" then
        sent[plantId .. "|" .. fruitId] = true
    end
    if model then sentModels[model] = true end
end

local function matchOwner(v)
    if v == nil or not LP then return false end
    return v == LP.UserId or v == LP.Name
        or tostring(v) == tostring(LP.UserId) or tostring(v) == LP.Name
end

local function plotOwned(plot)
    if not plot then return false end
    if matchOwner(plot:GetAttribute("OwnerId")) then return true end
    if matchOwner(plot:GetAttribute("Owner")) then return true end
    if matchOwner(plot:GetAttribute("OwnerUserId")) then return true end
    if matchOwner(plot:GetAttribute("UserId")) then return true end

    for _, child in ipairs(plot:GetChildren()) do
        if child:IsA("ValueBase") then
            local n = child.Name:lower()
            if n:find("owner") or n:find("userid") or n:find("player") then
                if matchOwner(child.Value) then return true end
            end
        end
    end

    local myPlot = LP:GetAttribute("Plot") or LP:GetAttribute("PlotName")
        or LP:GetAttribute("GardenPlot") or LP:GetAttribute("PlotId")
    if myPlot and plot.Name == tostring(myPlot) then return true end
    if myPlot and plot.Name == ("Plot" .. tostring(myPlot)) then return true end
    return false
end

local function findPlotInGardens(gardens, plotId)
    if not gardens or plotId == nil then return nil end
    local idStr = tostring(plotId)
    for _, name in ipairs({ "Plot" .. idStr, idStr, "Plot_" .. idStr }) do
        local plot = gardens:FindFirstChild(name)
        if plot then return plot end
    end
    return nil
end

local function getPlot(force)
    local esp = G.EspFruitGarden or rawget(_G, "EspFruitGarden")
    if not force and type(esp) == "table" and type(esp.GetPlayerPlot) == "function" then
        local ok, plot = pcall(esp.GetPlayerPlot, esp)
        if ok and plot and plot.Parent then
            cachedPlot = plot
            cachedPlotAt = os.clock()
            return plot
        end
    end

    local now = os.clock()
    if not force and cachedPlot and cachedPlot.Parent and (now - cachedPlotAt) <= PLOT_CACHE_SEC then
        return cachedPlot
    end

    local autoTele = G.AutoTele or G.AutoTeleModule or rawget(_G, "AutoTele")
    if type(autoTele) == "table" and type(autoTele.GetPlayerPlot) == "function" then
        local ok, plot = pcall(autoTele.GetPlayerPlot, autoTele)
        if ok and plot and plot.Parent then
            cachedPlot = plot
            cachedPlotAt = now
            return plot
        end
    end

    local gardens = workspace:FindFirstChild("Gardens")
    if not gardens then
        cachedPlot = nil
        cachedPlotAt = now
        return nil
    end

    local plotId = LP:GetAttribute("PlotId")
    local byId = findPlotInGardens(gardens, plotId)
    if byId then
        cachedPlot = byId
        cachedPlotAt = now
        return byId
    end

    for _, plot in ipairs(gardens:GetChildren()) do
        if plotOwned(plot) then
            cachedPlot = plot
            cachedPlotAt = now
            return plot
        end
    end

    local char = LP.Character
    local hrp = char and char:FindFirstChild("HumanoidRootPart")
    if hrp then
        local params = RaycastParams.new()
        params.FilterType = Enum.RaycastFilterType.Include
        params.FilterDescendantsInstances = { gardens }
        local hit = workspace:Raycast(hrp.Position + Vector3.new(0, 6, 0), Vector3.new(0, -40, 0), params)
        if hit then
            for _, plot in ipairs(gardens:GetChildren()) do
                if hit.Instance:IsDescendantOf(plot) then
                    cachedPlot = plot
                    cachedPlotAt = now
                    return plot
                end
            end
        end
    end

    cachedPlot = gardens:FindFirstChild("Plot" .. LP.Name)
    cachedPlotAt = now
    return cachedPlot
end

local function buildPanel(player, fruit, kg, seed)
    local kgText = string.format("%.2f kg", tonumber(kg) or 0)
    return table.concat({
        "**Profile**",
        "| Username : " .. maskName(player),
        "",
        "**Fruit Details**",
        "| Fruit : " .. tostring(fruit),
        "| Carrot KG : " .. kgText,
        "| From Seed : " .. tostring(seed),
    }, "\n")
end

function M.Send(info)
    if type(info) ~= "table" then return false, "bad_args" end
    if not isVulnFruitEnabled() then return false, "vuln_fruit_off" end
    local CFG = cfg()

    local player = tostring(info.player or LP.Name)
    local fruit = tostring(info.fruitName or info.fruit or "Carrot")
    local kg = tonumber(info.kg) or 0
    local seed = tostring(info.fromSeed or info.from_seed or "Unknown")
    local minKg = tonumber(CFG.MIN_KG) or 50

    if kg < minKg then return false, "kg_too_low" end

    local panel = buildPanel(player, fruit, kg, seed)
    return httpPost(apiUrl(), {
        event = "FRUIT_CARROT",
        player = player,
        fruitName = fruit,
        kg = kg,
        fromSeed = seed,
        panel = panel,
        jobId = tostring(game.JobId),
        placeId = tostring(game.PlaceId),
        luaVer = M.VERSION,
    })
end

--- Scan via plot/Plants saja — O(n plant) bukan O(n seluruh descendant plot/server)
local function scanViaPlantsFolder(plot, fromSeedLabel)
    local folder = plot:FindFirstChild("Plants")
    if not folder then return nil end

    local hits = {}
    local seen = {}
    local seenModel = {}
    local batch = 0

    for _, plant in ipairs(folder:GetChildren()) do
        if plant:IsA("Model") then
            batch += 1

            local plantId, fruitId = resolveIds(plant)
            if plantId ~= "" and not isFruitSent(plantId, fruitId, plant) then
                local key = plantId .. "|" .. fruitId
                if not seen[key] then
                    local name = fruitNameFast(plant)
                    if isCarrotFruit(plant, name) then
                        local prompt = nil
                        for _, desc in ipairs(plant:GetDescendants()) do
                            if desc:IsA("ProximityPrompt") and isHarvestPrompt(desc) then
                                prompt = desc
                                break
                            end
                        end

                        if prompt and not prompt:GetAttribute("Collected") then
                            local model = fruitFromPrompt(prompt) or plant
                            if model and model.Parent and not seenModel[model] then
                                seen[key] = true
                                seenModel[model] = true
                                hits[#hits + 1] = {
                                    key = key,
                                    plantId = plantId,
                                    fruitId = fruitId,
                                    fruitName = name,
                                    kg = tonumber(displayKg(model)) or 0,
                                    fromSeed = fromSeedLabel,
                                    model = model,
                                }
                            end
                        end
                    end
                end
            end

            if batch >= 40 then
                batch = 0
                task.wait()
            end
        end
    end

    return hits
end

--- Scan carrot di plot — Plants folder dulu, fallback GetTagged HarvestPrompt
function M.Scan(_minKg)
    local plot = getPlot()
    if not plot then return {} end

    local fromSeedLabel = getFromSeedLabel()
    local viaPlants = scanViaPlantsFolder(plot, fromSeedLabel)
    if viaPlants then return viaPlants end

    local hits = {}
    local seen = {}
    local seenModel = {}

    for _, prompt in ipairs(iterPlotHarvestPrompts(plot)) do
        if not isHarvestPrompt(prompt) or prompt:GetAttribute("Collected") then continue end

        local model = fruitFromPrompt(prompt)
        if not model or not model.Parent then continue end
        if seenModel[model] then continue end

        local plantId, fruitId = resolveIds(model)
        if plantId == "" then continue end
        if isFruitSent(plantId, fruitId, model) then continue end

        local key = plantId .. "|" .. fruitId
        if seen[key] then continue end

        local name = fruitNameFast(model)
        if not isCarrotFruit(model, name) then continue end

        seen[key] = true
        seenModel[model] = true

        local kg = tonumber(displayKg(model)) or 0
        hits[#hits + 1] = {
            key = key,
            plantId = plantId,
            fruitId = fruitId,
            fruitName = name,
            kg = kg,
            fromSeed = fromSeedLabel,
            model = model,
        }
    end

    return hits
end

local function trackHit(plantId, fruitId, kg)
    local trackKey = plantId .. "|" .. fruitId
    fruitTrack[trackKey] = kg
    fruitTrack[plantId .. "|"] = kg
end

local function shouldFire(plantId, fruitId, model, kg, minKg)
    if isFruitSent(plantId, fruitId, model) then
        return false
    end

    local trackKey = plantId .. "|" .. fruitId
    local prev = fruitTrack[trackKey]
    trackHit(plantId, fruitId, kg)

    if kg < minKg then
        return false
    end

    if not prev or prev < minKg then
        return true
    end

    return false
end

local function pruneTrack(activeKeys)
    for key in pairs(fruitTrack) do
        if not activeKeys[key] then
            fruitTrack[key] = nil
        end
    end
end

local function tick()
    if not M._running then return end
    if not isVulnFruitEnabled() then return end

    local CFG = cfg()
    local minKg = tonumber(CFG.MIN_KG) or 50

    pcall(function()
        local plot = getPlot()
        if not plot then return end

        local hits = M.Scan(minKg)
        local active = {}

        if not bootstrapped and (CFG.SKIP_EXISTING ~= false) then
            for _, hit in ipairs(hits) do
                trackHit(hit.plantId, hit.fruitId, hit.kg)
                active[hit.key] = true
                active[hit.plantId .. "|"] = true
            end
            bootstrapped = true
            pruneTrack(active)
            return
        end
        bootstrapped = true

        for _, hit in ipairs(hits) do
            active[hit.key] = true
            active[hit.plantId .. "|"] = true

            if not shouldFire(hit.plantId, hit.fruitId, hit.model, hit.kg, minKg) then
                continue
            end

            markFruitSent(hit.plantId, hit.fruitId, hit.model)
            local ok = M.Send({
                player = LP.Name,
                fruitName = hit.fruitName,
                kg = hit.kg,
                fromSeed = hit.fromSeed,
                model = hit.model,
            })
            if not ok then
                local sent = getSentStore()
                sent[hit.plantId .. "|"] = nil
                if hit.fruitId ~= "" then
                    sent[hit.plantId .. "|" .. hit.fruitId] = nil
                end
                if hit.model then sentModels[hit.model] = nil end
            end
        end

        pruneTrack(active)
    end)
end

function M.Stop()
    M._running = false
    loopToken += 1
    promptScanCache.plot = nil
    promptScanCache.at = 0
    table.clear(promptScanCache.list)
end

function M.Start()
    if M._running then return end
    M.Stop()
    M._running = true
    bootstrapped = false
    table.clear(fruitTrack)

    local f = fsv()
    if f and type(f.refresh) == "function" then
        pcall(f.refresh, true)
    end

    loopToken += 1
    local myToken = loopToken
    task.spawn(function()
        while M._running and myToken == loopToken do
            tick()
            local pollSec = tonumber(cfg().POLL_SEC) or 1.0
            task.wait(math.max(0.5, pollSec))
        end
    end)
end

function M.SetEnabled(on)
    if on == true then
        M.Start()
    else
        M.Stop()
    end
end

M.setEnabled = M.SetEnabled

function M.IsEnabled()
    return M._running == true
end

G.WebhookFruitCarrot = M
G.WebhookFruitCarrotModule = M
G.GAG2CarrotWebhook = M
_G.WebhookFruitCarrot = M
_G.WebhookFruitCarrotModule = M
_G.GAG2CarrotWebhook = M

return M
 end,         required = false },
    { key = "AutoBuyPet",              name = "Auto Buy Pet",            factory = function() -- AutoBuyPet.lua — Grow A Garden 2
-- Simple: pause Auto Tele → garden → TP bawah pet (Y-7) → WildPetTame:Fire → sukses → garden → resume Auto Tele
-- Tanpa BuyPrompt. Webhook setelah pet sampai garden (hilang dari WildPetRef).

local Players           = game:GetService("Players")
local ReplicatedStorage = game:GetService("ReplicatedStorage")

local LP = Players.LocalPlayer
local G  = (getgenv and getgenv()) or _G
local M  = {}

local WildPetTame, WildPetTameResult

local function _ensureNetworking()
    if WildPetTame and WildPetTameResult then return true end
    local ok, net = pcall(function()
        return require(ReplicatedStorage:WaitForChild("SharedModules", 10):WaitForChild("Networking", 10))
    end)
    if ok and type(net) == "table" and type(net.Pets) == "table" then
        WildPetTame = net.Pets.WildPetTame
        WildPetTameResult = net.Pets.WildPetTameResult
    end
    return WildPetTame ~= nil
end

local SCAN_SEC        = 0.2
local UNDER_Y         = -7
