return M
 end,                     required = false },
    { key = "AutoBuyAuction",          name = "Auto Buy Auction",        factory = function() -- AutoBuyAuction.lua — auto beli Auction Stand (remote only, sama AuctioneerController)
-- Alur game (decompile u144/u55/u206):
--   RequestSnapshot:Fire() + Snapshot.OnClientEvent → manifest.lots + stock
--   StockUpdate → stock map saja (u149)
--   Beli: Auctioneer.CurrentPrice(lot, serverTime) + PurchaseLot:Fire(lotId, price)
-- UI Auction hanya tampilan — TIDAK wajib untuk auto buy.

local Players           = game:GetService("Players")
local ReplicatedStorage = game:GetService("ReplicatedStorage")
local RunService        = game:GetService("RunService")

local LP = Players.LocalPlayer
local G  = (getgenv and getgenv()) or _G
local M  = {}

local LOOP_SEC           = 1.0
local PURCHASE_GAP_SEC   = 0.35
local SNAPSHOT_EVERY_SEC = 8.0
local SNAPSHOT_WAIT_SEC  = 4.0

local GEAR_CATEGORIES = {
    Gear = true, Gears = true,
    Sprinklers = true, Rakes = true, WateringCans = true,
    Trowels = true, Shovels = true, Tools = true,
    Crates = true, Props = true,
}

local SLOT_CATEGORIES = {
    seed     = { Seeds = true, HarvestedFruits = true },
    seedpack = { SeedPacks = true },
    egg      = { Eggs = true },
}

local Networking, Auctioneer, PurchaseLot, RequestSnapshot
local AuctionFlags = nil

local running     = false
local loopId      = 0
local netReady    = false
local snapshot    = {
    lots = {},
    stock = {},
    rollIntervalSeconds = 0,
    rollWindowUnix = 0,
    timerShiftSeconds = 0,
}
local stockMap    = {}
local purchaseAt  = {}
local purchaseDebounceAt = {}
local pendingPurchases = {}
local cooldownUntil = {}
local lastSnapshotAt = 0
local lastPurchaseAt = 0
local eventConns  = {}
local eventsHooked = false
local _hookEvents
local _fireRequestSnapshot
local _ensureSnapshotLots
local _parseSnapshot
local _reconcileSnapshot
local _bootstrapAuction
local _waitForSnapshotSince
local _ensureAuctioneer
local _hasSnapshotData
local _lotSlot

local stats = {
    lastStatus = "Ready",
    lastError  = nil,
    lastBuy    = nil,
    buys       = 0,
    lotCount   = 0,
    matchedLots = 0,
    availableLots = 0,
    auctionGuiOpen = false,
}

local function _dbg()
    return G.AUTO_BUY_AUCTION_DEBUG == true or rawget(_G, "AUTO_BUY_AUCTION_DEBUG") == true
end

local function _log(...)
    if _dbg() then print("[GAG2-ABA]", ...) end
end

local function _setStatus(msg)
    stats.lastStatus = tostring(msg or "Ready")
    G.AUTO_BUY_AUCTION_STATUS = stats.lastStatus
    rawset(_G, "AUTO_BUY_AUCTION_STATUS", stats.lastStatus)
end

local function _syncStatsGlobals()
    G.AUTO_BUY_AUCTION_LOTS = stats.lotCount
    G.AUTO_BUY_AUCTION_MATCH = stats.matchedLots
    G.AUTO_BUY_AUCTION_BUYABLE = stats.availableLots
    G.AUTO_BUY_AUCTION_BUYS = stats.buys
    rawset(_G, "AUTO_BUY_AUCTION_LOTS", stats.lotCount)
    rawset(_G, "AUTO_BUY_AUCTION_MATCH", stats.matchedLots)
    rawset(_G, "AUTO_BUY_AUCTION_BUYABLE", stats.availableLots)
    rawset(_G, "AUTO_BUY_AUCTION_BUYS", stats.buys)
end

local guiControllerCache = nil

local function _getGuiController()
    if type(guiControllerCache) == "table" then
        return guiControllerCache
    end
    local ps = LP:FindFirstChild("PlayerScripts")
    if not ps then return nil end
    local controllers = ps:FindFirstChild("Controllers")
    if not controllers then return nil end
    local inst = controllers:FindFirstChild("GuiController")
    if not inst then return nil end
    local ok, mod = pcall(require, inst)
    if ok and type(mod) == "table" then
        guiControllerCache = mod
        return mod
    end
    return nil
end

local function _getGuiControllerWait(maxSec)
    maxSec = tonumber(maxSec) or 2
    local deadline = os.clock() + maxSec
    while os.clock() < deadline do
        local gc = _getGuiController()
        if gc then return gc end
        local ps = LP:FindFirstChild("PlayerScripts") or LP:WaitForChild("PlayerScripts", 0.25)
        if ps then
            ps:WaitForChild("Controllers", 0.25)
        end
        task.wait(0.05)
    end
    return _getGuiController()
end

local function _auctionScreenGui()
    local pg = LP:FindFirstChild("PlayerGui")
    local gui = pg and pg:FindFirstChild("Auction")
    if gui and gui:IsA("ScreenGui") then return gui end
    return nil
end

function M.IsAuctionGuiOpen()
    local gui = _auctionScreenGui()
    if gui and gui.Enabled then return true end
    local gc = _getGuiController()
    if gc and type(gc.IsOpen) == "function" then
        local ok, open = pcall(gc.IsOpen, gc, "Auction")
        if ok and open == true then return true end
    end
    return false
end

local OPEN_UI_WAIT_SEC = 2.5

local function _waitAuctionOpen(maxSec)
    maxSec = tonumber(maxSec) or OPEN_UI_WAIT_SEC
    local deadline = os.clock() + maxSec
    while os.clock() < deadline do
        local gui = _auctionScreenGui()
        if gui and gui.Enabled then return true end
        local gc = _getGuiController()
        if gc and type(gc.IsOpen) == "function" then
            local ok, open = pcall(gc.IsOpen, gc, "Auction")
            if ok and open == true then return true end
        end
        task.wait(0.05)
    end
    local gui = _auctionScreenGui()
    return gui ~= nil and gui.Enabled == true
end

local function _openViaGuiController()
    local gc = _getGuiController() or _getGuiControllerWait(2)
    if not gc or type(gc.Open) ~= "function" then
        return false, "GuiController tidak ada"
    end
    local ok, err = pcall(gc.Open, gc, "Auction", nil, { "HUD" })
    if not ok then
        return false, tostring(err)
    end
    return true
end

local function _enableAuctionGuiDirect()
    local gui = _auctionScreenGui()
    if not gui then return false end
    gui.Enabled = true
    return gui.Enabled == true
end

local function _findAuctionPrompt()
    local stand = workspace:FindFirstChild("AuctionStand")
    if not stand then return nil end
    for _, d in stand:GetDescendants() do
        if d:IsA("ProximityPrompt") and d:GetAttribute("DontShow") == nil then
            return d
        end
    end
    return stand:FindFirstChildWhichIsA("ProximityPrompt", true)
end

local function _tpNearPrompt(pp, dist)
    dist = tonumber(dist) or 6
    local char = LP.Character
    local hrp = char and char:FindFirstChild("HumanoidRootPart")
    if not hrp or not pp then return false end
    local attach = pp.Parent
    if not attach or not attach:IsA("BasePart") then
        attach = pp:FindFirstAncestorWhichIsA("BasePart")
    end
    if not attach then return false end
    local back = -attach.CFrame.LookVector
    local flat = Vector3.new(back.X, 0, back.Z)
    if flat.Magnitude < 0.05 then
        flat = Vector3.new(0, 0, -1)
    else
        flat = flat.Unit
    end
    local pos = attach.Position + flat * dist + Vector3.new(0, 2, 0)
    local cf = CFrame.new(pos, attach.Position)
    local ok = pcall(function()
        if char.PrimaryPart then
            char:PivotTo(cf)
        else
            hrp.CFrame = cf
        end
    end)
    if ok then task.wait(0.2) end
    return ok
end

local function _fireAuctionPrompt(pp)
    if not pp then return false end
    local fn = (type(fireproximityprompt) == "function" and fireproximityprompt)
        or rawget(_G, "fireproximityprompt")
    if type(fn) ~= "function" then return false end
    if pcall(fn, pp, true) then return true end
    return pcall(fn, pp)
end

local function _openViaNpc()
    local pp = _findAuctionPrompt()
    if not pp then return false end
    if not _tpNearPrompt(pp, 6) then return false end
    task.wait(0.15)
    return _fireAuctionPrompt(pp)
end

local function _refreshAfterOpen()
    if type(_hookEvents) == "function" then pcall(_hookEvents) end
    if type(_fireRequestSnapshot) == "function" then
        task.delay(0.4, function()
            pcall(_fireRequestSnapshot)
        end)
    end
end

function M.OpenAuctionGui()
    if M.IsAuctionGuiOpen() then
        stats.auctionGuiOpen = true
        _setStatus("Auction UI terbuka")
        return true
    end

    task.spawn(function()
        _setStatus("Membuka Auction UI...")

        local okGc, errGc = _openViaGuiController()
        if okGc and _waitAuctionOpen(1) then
            stats.auctionGuiOpen = true
            stats.lastError = nil
            _setStatus("Auction UI terbuka")
            _refreshAfterOpen()
            return
        end

        if _enableAuctionGuiDirect() and _waitAuctionOpen(0.5) then
            stats.auctionGuiOpen = true
            stats.lastError = nil
            _setStatus("Auction UI terbuka")
            _refreshAfterOpen()
            return
        end

        if _openViaNpc() and _waitAuctionOpen(2) then
            stats.auctionGuiOpen = true
            stats.lastError = nil
            _setStatus("Auction UI terbuka (NPC)")
            _refreshAfterOpen()
            return
        end

        okGc = _openViaGuiController()
        _enableAuctionGuiDirect()
        if _waitAuctionOpen(1.5) then
            stats.auctionGuiOpen = true
            stats.lastError = nil
            _setStatus("Auction UI terbuka")
            _refreshAfterOpen()
            return
        end

        stats.auctionGuiOpen = false
        stats.lastError = errGc or "Gagal buka Auction UI"
        _setStatus("Gagal buka Auction UI")
        _log("open fail", stats.lastError)
    end)

    return true
end

local function _stripSelectSuffix(s)
    s = tostring(s or "")
    s = s:gsub("%s+%+%d+$", "")  -- "Super Sprinkler +1" -> "Super Sprinkler"
    s = s:gsub("%s+x%s+[%d%.]+[kKmMbB]?$", "")
    return s
end

local function _normKey(s)
    return _stripSelectSuffix(s):lower():gsub("[%s_%-%.'']+", "")
end

local function _lotIdKey(lotId)
    return tostring(lotId or "")
end

local function _normalizeLot(lot)
    if typeof(lot) ~= "table" then return nil end
    local lotId = lot.lotId or lot.id or lot.Id
    if lotId == nil or tostring(lotId) == "" then return nil end
    lot.lotId = tostring(lotId)
    return lot
end

local function _collectLots(rawLots)
    local lots = {}
    if typeof(rawLots) ~= "table" then return lots end

    local function push(lot)
        lot = _normalizeLot(lot)
        if lot then lots[#lots + 1] = lot end
    end

    if #rawLots > 0 then
        for _, lot in ipairs(rawLots) do push(lot) end
    else
        for _, lot in pairs(rawLots) do push(lot) end
    end
    return lots
end

local function _connectRemoteEvent(remote, handler)
    if not remote then return false end
    local signal = remote.OnClientEvent
    if signal and type(signal.Connect) == "function" then
        eventConns[#eventConns + 1] = signal:Connect(handler)
        return true
    end
    if typeof(remote) == "Instance" and remote:IsA("RemoteEvent") then
        eventConns[#eventConns + 1] = remote.OnClientEvent:Connect(handler)
        return true
    end
    if type(remote.Connect) == "function" then
        eventConns[#eventConns + 1] = remote:Connect(handler)
        return true
    end
    return false
end

local function _findAuctionRemoteEvent(name)
    local ae = Networking and Networking.Auctioneer
    if ae and ae[name] then return ae[name] end
    for _, inst in ipairs(ReplicatedStorage:GetDescendants()) do
        if inst:IsA("RemoteEvent") and inst.Name == name then
            local p = inst.Parent
            while p and p ~= ReplicatedStorage do
                local pn = tostring(p.Name):lower()
                if pn:find("auction") then return inst end
                p = p.Parent
            end
        end
    end
    return nil
end

local function _normalizeSet(src)
    if type(src) ~= "table" then return {} end
    local out = {}
    for i = 1, #src do
        local v = src[i]
        if v ~= nil and tostring(v) ~= "" then out[tostring(v)] = true end
    end
    if next(out) then return out end
    for k, v in pairs(src) do
        if v == true or v == 1 or v == "true" then out[tostring(k)] = true end
    end
    return out
end

local function _hasAnySelected(map)
    if type(map) ~= "table" then return false end
    for _, v in pairs(map) do
        if v == true then return true end
    end
    return false
end

local function _parseMoneyValue(raw)
    if type(raw) == "number" then return raw end
    local txt = tostring(raw or ""):lower():gsub("%s+", ""):gsub(",", "")
    if txt == "" then return nil end
    local suffixes = {
        { "juta", 1000000 }, { "jt", 1000000 },
        { "ribu", 1000 }, { "rb", 1000 },
        { "b", 1000000000 }, { "m", 1000000 }, { "k", 1000 },
    }
    for _, pair in ipairs(suffixes) do
        local suf, mult = pair[1], pair[2]
        if #txt > #suf and txt:sub(-#suf) == suf then
            local n = tonumber(txt:sub(1, -#suf - 1))
            if n then return math.floor(n * mult) end
        end
    end
    return tonumber(txt)
end

function M.ParseMaxPrice(raw)
    return math.max(0, math.floor(_parseMoneyValue(raw) or 0))
end

function M.FormatMaxPrice(n)
    n = math.floor(tonumber(n) or 0)
    if n <= 0 then return "0" end
    if n >= 1000000000 then return string.format("%.2fB", n / 1000000000) end
    if n >= 1000000 then return string.format("%.2fM", n / 1000000) end
    if n >= 1000 then return string.format("%.1fK", n / 1000) end
    return tostring(n)
end

local function _fmtPrice(n)
    return M.FormatMaxPrice(n)
end

local function _readCatMaxPrice(a, slot, globalKey, legacyMax)
    local cat = type(a[slot]) == "table" and a[slot] or {}
    local v = cat.max_price
    if v ~= nil then
        return M.ParseMaxPrice(v)
    end
    v = G[globalKey]
    if v == nil then v = rawget(_G, globalKey) end
    if v ~= nil then
        return M.ParseMaxPrice(v)
    end
    return M.ParseMaxPrice(legacyMax)
end

local function _maxPriceForSlot(cfg, slot)
    local mp = cfg.max_prices
    if type(mp) ~= "table" then return 0 end
    return math.max(0, math.floor(tonumber(mp[slot]) or 0))
end

_lotSlot = function(category)
    category = tostring(category or "")
    if SLOT_CATEGORIES.seed[category] then return "seed" end
    if SLOT_CATEGORIES.seedpack[category] then return "seedpack" end
    if SLOT_CATEGORIES.egg[category] then return "egg" end
    if GEAR_CATEGORIES[category] then return "gear" end
    return "gear"
end

local function _maxPriceForLot(cfg, lot)
    if lot._matchSlot then
        return _maxPriceForSlot(cfg, lot._matchSlot)
    end
    return _maxPriceForSlot(cfg, _lotSlot(lot.category))
end

local function _priceOk(price, maxPrice)
    if type(price) ~= "number" or price < 0 then return false end
    if maxPrice <= 0 then return true end
    return price <= maxPrice
end

local function _getMoney()
    local ls = LP:FindFirstChild("leaderstats")
    if ls then
        for _, n in ipairs({ "Sheckles", "Money", "Cash", "Coins" }) do
            local o = ls:FindFirstChild(n)
            if o and (o:IsA("IntValue") or o:IsA("NumberValue")) then
                local v = _parseMoneyValue(o.Value)
                if v ~= nil then return v end
            end
        end
    end
    local attr = LP:GetAttribute("Sheckles")
    if attr ~= nil then
        return _parseMoneyValue(attr)
    end
    return nil
end

local function _getServerTime()
    local ok, t = pcall(function()
        return workspace:GetServerTimeNow()
    end)
    return ok and t or os.time()
end

-- u144 AuctioneerController — parse manifest.lots
local function _parseManifestLots(manifestLots)
    local lots = {}
    if typeof(manifestLots) ~= "table" then return lots end
    for _, lot in manifestLots do
        if typeof(lot) == "table" and typeof(lot.lotId) == "string" then
            lots[#lots + 1] = lot
        elseif typeof(lot) == "table" and lot.lotId ~= nil then
            lot.lotId = tostring(lot.lotId)
            if lot.lotId ~= "" then lots[#lots + 1] = lot end
        end
    end
    return lots
end

local function _waitGameAuctioneer(maxSec)
    maxSec = tonumber(maxSec) or 25
    local deadline = os.clock() + maxSec
    while os.clock() < deadline do
        local ps = LP:FindFirstChild("PlayerScripts")
        local controllers = ps and ps:FindFirstChild("Controllers")
        if controllers and controllers:FindFirstChild("AuctioneerController") then
            return true
        end
        task.wait(0.25)
    end
    return false
end

_ensureSnapshotLots = function()
    -- Remote only — tidak scrape GUI (game tidak butuh UI terbuka)
    return snapshot ~= nil and snapshot.lots ~= nil and #snapshot.lots > 0
end

local function _ensureNet()
    if netReady and RequestSnapshot then return true end
    local sm = ReplicatedStorage:FindFirstChild("SharedModules")
        or ReplicatedStorage:WaitForChild("SharedModules", 30)
    if not sm then
        stats.lastError = "SharedModules missing"
        return false
    end
    local netInst = sm:FindFirstChild("Networking") or sm:WaitForChild("Networking", 15)
    if not netInst then
        stats.lastError = "Networking module missing"
        return false
    end
    local ok, net = pcall(require, netInst)
    if not ok or type(net) ~= "table" or type(net.Auctioneer) ~= "table" then
        stats.lastError = "Networking.Auctioneer missing"
        return false
    end
    Networking = net
    local ae = net.Auctioneer
    PurchaseLot = ae.PurchaseLot
    RequestSnapshot = ae.RequestSnapshot
    if not RequestSnapshot then
        stats.lastError = "RequestSnapshot missing"
        return false
    end
    if not AuctionFlags then
        pcall(function()
            local flags = sm:FindFirstChild("Flags")
            local inst = flags and flags:FindFirstChild("AuctioneerFlags")
            if inst then AuctionFlags = require(inst) end
        end)
    end
    netReady = true
    stats.lastError = nil
    _ensureAuctioneer()
    return true
end

_ensureAuctioneer = function()
    if Auctioneer then return true end
    local sm = ReplicatedStorage:FindFirstChild("SharedModules")
    if not sm then return false end
    local ok, mod = pcall(function()
        return require(sm:WaitForChild("Auctioneer", 5))
    end)
    if ok and type(mod) == "table" then
        Auctioneer = mod
        return true
    end
    return false
end

_hasSnapshotData = function()
    return lastSnapshotAt > 0
end

_parseSnapshot = function(raw)
    if typeof(raw) ~= "table" then return false end
    local lots = {}
    local manifest = raw.manifest
    if typeof(manifest) == "table" and typeof(manifest.lots) == "table" then
        lots = _parseManifestLots(manifest.lots)
    elseif typeof(raw.lots) == "table" then
        lots = _collectLots(raw.lots)
    end

  -- Hanya pertahankan lot lama kalau payload tidak bawa daftar lot baru (mis. StockUpdate).
  -- manifest.lots = {} artinya roll baru / kosong — jangan tampilkan 6 lot expired.
    local hasNewLotList = (typeof(manifest) == "table" and manifest.lots ~= nil)
        or typeof(raw.lots) == "table"
    if #lots < 1 and not hasNewLotList and snapshot and snapshot.lots and #snapshot.lots > 0 then
        if typeof(raw.stock) == "table" then
            stockMap = raw.stock
            snapshot.stock = stockMap
        end
        lastSnapshotAt = os.clock()
        return true
    end

    snapshot = {
        lots = lots,
        stock = typeof(raw.stock) == "table" and raw.stock or {},
        rollIntervalSeconds = typeof(raw.rollIntervalSeconds) == "number" and raw.rollIntervalSeconds or 0,
        rollWindowUnix = typeof(raw.rollWindowUnix) == "number" and raw.rollWindowUnix or 0,
        timerShiftSeconds = typeof(raw.timerShiftSeconds) == "number" and raw.timerShiftSeconds or 0,
    }
    stockMap = snapshot.stock
    lastSnapshotAt = os.clock()
    if #lots < 1 then
        stats.lastError = "manifest.lots kosong"
    else
        stats.lastError = nil
    end
    _reconcileSnapshot(_getServerTime())
    _log("snapshot parsed", #snapshot.lots, "lots")
    return true
end

_fireRequestSnapshot = function()
    if not _ensureNet() or not RequestSnapshot then return false end
    _hookEvents()
    local function callSnapshot()
        if type(RequestSnapshot.Fire) == "function" then
            return RequestSnapshot:Fire()
        end
        if type(RequestSnapshot.InvokeServer) == "function" then
            return RequestSnapshot:InvokeServer()
        end
        return nil
    end
    local ok, data = pcall(callSnapshot)
    if not ok then
        stats.lastError = tostring(data)
        return false
    end
    if data ~= nil then
        _parseSnapshot(data)
        return _hasSnapshotData()
    end
    return false
end

_waitForSnapshotSince = function(sinceClock, maxSec)
    sinceClock = tonumber(sinceClock) or 0
    maxSec = tonumber(maxSec) or SNAPSHOT_WAIT_SEC
    local deadline = os.clock() + maxSec
    while os.clock() < deadline do
        if lastSnapshotAt >= sinceClock then
            return true
        end
        task.wait(0.1)
    end
    return lastSnapshotAt >= sinceClock
end

_bootstrapAuction = function(waitSec)
    waitSec = tonumber(waitSec) or SNAPSHOT_WAIT_SEC
    if not _ensureNet() then
        stats.lastError = "Networking belum ready"
        return false
    end
    _ensureAuctioneer()
    _hookEvents()
    if not eventsHooked then
        stats.lastError = "gagal hook Snapshot.OnClientEvent"
        return false
    end
    local startedAt = os.clock()
    pcall(_fireRequestSnapshot)
    if _hasSnapshotData() then return true end
    if _waitForSnapshotSince(startedAt, waitSec) then
        return _hasSnapshotData()
    end
    if not _hasSnapshotData() then
        stats.lastError = stats.lastError or "Snapshot event tidak datang (tunggu roll)"
    end
    return _hasSnapshotData()
end

local function _requestSnapshot(waitForEvent)
    if waitForEvent == nil then waitForEvent = true end
    return _bootstrapAuction(waitForEvent and SNAPSHOT_WAIT_SEC or 1)
end

local function _readCfg()
    local MAIN = rawget(_G, "MAIN") or G.MAIN
    local buy = MAIN and MAIN.auto and MAIN.auto.buy
    local a = type(buy) == "table" and buy.auction or nil
    a = type(a) == "table" and a or {}

    local enabled = (G.AUTO_BUY_AUCTION_ENABLED == true)
        or (rawget(_G, "AUTO_BUY_AUCTION_ENABLED") == true)
        or (a.enabled == true)

    local maxPrice = G.AUTO_BUY_AUCTION_MAX_PRICE
    if maxPrice == nil then maxPrice = rawget(_G, "AUTO_BUY_AUCTION_MAX_PRICE") end
    if maxPrice == nil then maxPrice = a.max_price end
    if maxPrice == nil then maxPrice = a.legacy_max_price end
    local legacyMax = M.ParseMaxPrice(maxPrice)

    return {
        enabled   = enabled,
        max_prices = {
            seed = _readCatMaxPrice(a, "seed", "AUTO_BUY_AUCTION_SEED_MAX_PRICE", legacyMax),
            gear = _readCatMaxPrice(a, "gear", "AUTO_BUY_AUCTION_GEAR_MAX_PRICE", legacyMax),
            seedpack = _readCatMaxPrice(a, "seedpack", "AUTO_BUY_AUCTION_SEEDPACK_MAX_PRICE", legacyMax),
            egg = _readCatMaxPrice(a, "egg", "AUTO_BUY_AUCTION_EGG_MAX_PRICE", legacyMax),
        },
        seed      = _normalizeSet(G.BUY_AUCTION_SEED_SELECTED or rawget(_G, "BUY_AUCTION_SEED_SELECTED") or (a.seed and a.seed.items)),
        gear      = _normalizeSet(G.BUY_AUCTION_GEAR_SELECTED or rawget(_G, "BUY_AUCTION_GEAR_SELECTED") or (a.gear and a.gear.items)),
        seedpack  = _normalizeSet(G.BUY_AUCTION_SEEDPACK_SELECTED or rawget(_G, "BUY_AUCTION_SEEDPACK_SELECTED") or (a.seedpack and a.seedpack.items)),
        egg       = _normalizeSet(G.BUY_AUCTION_EGG_SELECTED or rawget(_G, "BUY_AUCTION_EGG_SELECTED") or (a.egg and a.egg.items)),
    }
end

local function _matchesSelected(selected, ...)
    if not _hasAnySelected(selected) then return false end
    for i = 1, select("#", ...) do
        local name = tostring(select(i, ...) or "")
        if name ~= "" then
            if selected[name] == true then return true end
            local plain = _stripSelectSuffix(name)
            if plain ~= name and selected[plain] == true then return true end
            local nk = _normKey(name)
            for k, v in pairs(selected) do
                if v == true and _normKey(k) == nk then return true end
            end
        end
    end
    return false
end

local function _lotDisplayName(lot)
    if Auctioneer and type(Auctioneer.DisplayName) == "function" then
        local ok, name = pcall(Auctioneer.DisplayName, lot)
        if ok and typeof(name) == "string" and name ~= "" then return name end
    end
    return tostring(lot.item or "")
end

local function _lotSelected(lot, cfg)
    local display = _lotDisplayName(lot)
    local item = tostring(lot.item or "")
    for _, slot in ipairs({ "seed", "gear", "seedpack", "egg" }) do
        local selected = cfg[slot]
        if _matchesSelected(selected, item, display) then
            lot._matchSlot = slot
            return true
        end
    end
    return false
end

local function _stockLeft(lot)
    local id = _lotIdKey(lot.lotId)
    return stockMap[id] or stockMap[lot.lotId]
end

local function _rollWindowEnd(snap)
    snap = snap or snapshot
    if not snap then return 0 end
    local ri = tonumber(snap.rollIntervalSeconds) or 0
    local rw = tonumber(snap.rollWindowUnix) or 0
    local ts = tonumber(snap.timerShiftSeconds) or 0
    if ri <= 0 or rw <= 0 then return 0 end
    return rw + ri + ts
end

local function _rollRefreshRemain(serverTime)
    if not snapshot then return nil end
    serverTime = serverTime or _getServerTime()
    local endAt = _rollWindowEnd(snapshot)
    if endAt <= 0 then return nil end
    return endAt - serverTime
end

local function _isAuctionRollLive(serverTime)
    if not snapshot then return true end
    local endAt = _rollWindowEnd(snapshot)
    if endAt <= 0 then return true end
    return serverTime < endAt
end

local function _lotIsLive(lot, serverTime)
    -- u139 AuctioneerController: sold_out / expired / IsActive
    if typeof(lot) ~= "table" then return false end
    local stockLeft = _stockLeft(lot)
    if lot.stockQuantity ~= nil and stockLeft ~= nil and stockLeft <= 0 then
        return false
    end
    if typeof(lot.expiresAt) == "number" and lot.expiresAt <= serverTime then
        return false
    end
    if Auctioneer and type(Auctioneer.IsActive) == "function" then
        local ok, active = pcall(Auctioneer.IsActive, lot, serverTime, stockLeft)
        if ok and active == false then return false end
    end
    return true
end

_reconcileSnapshot = function(serverTime)
    if not snapshot then return end
    serverTime = serverTime or _getServerTime()

    if not _isAuctionRollLive(serverTime) then
        if snapshot.lots and #snapshot.lots > 0 then
            snapshot.lots = {}
            _log("roll window ended — cleared lots")
        end
        return
    end

    if not snapshot.lots or #snapshot.lots < 1 then return end
    local live = {}
    for _, lot in ipairs(snapshot.lots) do
        if _lotIsLive(lot, serverTime) then
            live[#live + 1] = lot
        end
    end
    if #live ~= #snapshot.lots then
        snapshot.lots = live
        _log("pruned dead lots", #live)
    end
end

local function _lotAvailable(lot, serverTime)
    if not _lotIsLive(lot, serverTime) then
        local stockLeft = _stockLeft(lot)
        if lot.stockQuantity ~= nil and stockLeft ~= nil and stockLeft <= 0 then
            return false, "sold_out"
        end
        if typeof(lot.expiresAt) == "number" and lot.expiresAt <= serverTime then
            return false, "expired"
        end
        return false, "inactive"
    end
    return true
end

local function _lotPriceForBuy(lot, serverTime)
    -- u55: harga selalu dari Auctioneer.CurrentPrice — tidak perlu UI terbuka
    if not _lotIsLive(lot, serverTime) then return nil end
    if not Auctioneer or type(Auctioneer.CurrentPrice) ~= "function" then return nil end
    local ok, price = pcall(Auctioneer.CurrentPrice, lot, serverTime)
    if ok and type(price) == "number" and price == price and price > 0 then
        return math.floor(price)
    end
    return nil
end

local function _lotPrice(lot, serverTime)
    return _lotPriceForBuy(lot, serverTime)
end

-- u139: expired / sold_out / ready + harga dari Auctioneer module
local function _analyzeLot(lot, serverTime)
    serverTime = serverTime or _getServerTime()
    _ensureAuctioneer()
    local stockLeft = _stockLeft(lot)
    local soldOut = lot.stockQuantity ~= nil and stockLeft ~= nil and stockLeft <= 0
    local expired = typeof(lot.expiresAt) == "number" and lot.expiresAt <= serverTime
    local active = nil
    if Auctioneer and type(Auctioneer.IsActive) == "function" then
        local ok, a = pcall(Auctioneer.IsActive, lot, serverTime, stockLeft)
        if ok then active = a end
    end
    local price = _lotPriceForBuy(lot, serverTime)
    local ready = _lotIsLive(lot, serverTime) and active ~= false and price ~= nil
    local state = "ready"
    if soldOut then state = "sold_out"
    elseif expired then state = "expired"
    elseif active == false then state = "inactive"
    elseif not price then state = "no_price"
    else state = "ready"
    end
    return {
        lotId = lot.lotId,
        item = _lotDisplayName(lot),
        price = price,
        stockLeft = stockLeft,
        soldOut = soldOut,
        expired = expired,
        active = active,
        ready = ready,
        state = state,
    }
end

local function _statusForCfg(cfg, serverTime)
    serverTime = serverTime or _getServerTime()
    if not _hasSnapshotData() then
        return "Menunggu snapshot"
    end
    _reconcileSnapshot(serverTime)
    if not snapshot or #snapshot.lots < 1 then
        local remain = _rollRefreshRemain(serverTime)
        if remain ~= nil and remain <= 0 then
            return "Auction ended — tunggu refresh"
        end
        if remain ~= nil and remain > 0 then
            local sec = math.max(0, math.floor(remain))
            return string.format("Lot kosong — refresh ~%dm %02ds", sec // 60, sec % 60)
        end
        return "Lot kosong — tunggu refresh"
    end
    for _, lot in ipairs(snapshot.lots) do
        if _lotSelected(lot, cfg) then
            local info = _analyzeLot(lot, serverTime)
            local maxP = _maxPriceForLot(cfg, lot)
            if info.price and maxP > 0 and info.price > maxP then
                return string.format("%s: %s > max %s",
                    info.item, _fmtPrice(info.price), _fmtPrice(maxP))
            end
            if info.ready and info.price and _priceOk(info.price, maxP) then
                return string.format("Siap beli %s @ %s", info.item, _fmtPrice(info.price))
            end
            return string.format("%s: %s", info.item, info.state)
        end
    end
    return "Scan auction..."
end

local function _refreshProgressStats(cfg)
    cfg = type(cfg) == "table" and cfg or _readCfg()
    if _ensureNet() and not Auctioneer then
        pcall(function()
            local sm = ReplicatedStorage:FindFirstChild("SharedModules")
            if sm then Auctioneer = require(sm:WaitForChild("Auctioneer", 2)) end
        end)
    end
    local serverTime = _getServerTime()
    _reconcileSnapshot(serverTime)
    stats.auctionGuiOpen = M.IsAuctionGuiOpen()
    stats.lotCount = snapshot and #snapshot.lots or 0
    stats.matchedLots = 0
    stats.availableLots = 0
    if not snapshot or stats.lotCount < 1 then
        _syncStatsGlobals()
        return
    end

    for _, lot in ipairs(snapshot.lots) do
        if not _lotIsLive(lot, serverTime) then continue end
        if _lotSelected(lot, cfg) then
            stats.matchedLots += 1
            local price = _lotPriceForBuy(lot, serverTime)
            if price and _priceOk(price, _maxPriceForLot(cfg, lot)) then
                stats.availableLots += 1
            end
        end
    end
    _syncStatsGlobals()
end

local function _canPurchaseNow(lotId)
    lotId = _lotIdKey(lotId)
    if pendingPurchases[lotId] then return false end
    local now = os.clock()
    if now < (cooldownUntil[lotId] or 0) then return false end
    local debounce = 0.25
    if AuctionFlags and AuctionFlags.PurchaseDebounceSeconds and type(AuctionFlags.PurchaseDebounceSeconds.Get) == "function" then
        local ok, v = pcall(AuctionFlags.PurchaseDebounceSeconds.Get, AuctionFlags.PurchaseDebounceSeconds)
        if ok and type(v) == "number" then debounce = v end
    end
    local lastDebounce = purchaseDebounceAt[lotId]
    if lastDebounce and debounce > now - lastDebounce then return false end
    if now - (purchaseAt[lotId] or 0) < debounce then return false end
    if now - lastPurchaseAt < PURCHASE_GAP_SEC then return false end
    return true
end

local function _tryBuyLot(lot, price, cfg)
    if not PurchaseLot or type(PurchaseLot.Fire) ~= "function" then
        stats.lastError = "PurchaseLot missing"
        return false, "no_remote"
    end
    if not _canPurchaseNow(lot.lotId) then return false, "debounce" end

    local serverTime = _getServerTime()
    local firePrice = _lotPriceForBuy(lot, serverTime)
    if type(firePrice) ~= "number" then return false, "no_price" end
    if not _priceOk(firePrice, _maxPriceForLot(cfg, lot)) then return false, "over_max" end

    local okAvail = _lotAvailable(lot, serverTime)
    if not okAvail then return false, "unavailable" end

    local money = _getMoney()
    if type(money) == "number" and money < firePrice then
        return false, "no_money"
    end

    local now = os.clock()
    purchaseDebounceAt[lot.lotId] = now
    pendingPurchases[lot.lotId] = {
        item = lot.item,
        price = firePrice,
        at = os.time(),
    }
    local ok, err = pcall(function()
        PurchaseLot:Fire(lot.lotId, firePrice)
    end)
    if not ok then
        purchaseDebounceAt[lot.lotId] = nil
        pendingPurchases[lot.lotId] = nil
        stats.lastError = tostring(err)
        return false, "fire_fail"
    end
    purchaseAt[lot.lotId] = now
    lastPurchaseAt = now
    local cd = 2.0
    if AuctionFlags and AuctionFlags.PurchaseCooldownSeconds and type(AuctionFlags.PurchaseCooldownSeconds.Get) == "function" then
        local okCd, v = pcall(AuctionFlags.PurchaseCooldownSeconds.Get, AuctionFlags.PurchaseCooldownSeconds)
        if okCd and type(v) == "number" and v > 0 then cd = math.max(cd, v) end
    end
    cooldownUntil[lot.lotId] = now + cd
    _setStatus(string.format("Beli %s @ %s...", tostring(lot.item), _fmtPrice(firePrice)))
    _log("buy fire", lot.lotId, lot.item, firePrice)
    return true
end

local function _tick()
    local cfg = _readCfg()
    _refreshProgressStats(cfg)

    if not cfg.enabled then
        _setStatus("Off")
        return LOOP_SEC
    end
    if not _hasAnySelected(cfg.seed) and not _hasAnySelected(cfg.gear)
        and not _hasAnySelected(cfg.seedpack) and not _hasAnySelected(cfg.egg) then
        _setStatus("Pilih item di dropdown")
        return LOOP_SEC
    end
    if not _ensureNet() then
        _setStatus("Auction remote belum ready")
        return LOOP_SEC * 2
    end
    if not eventsHooked then
        _hookEvents()
    end
    local needSnap = not _hasSnapshotData()
        or (os.clock() - lastSnapshotAt) > SNAPSHOT_EVERY_SEC
    if needSnap then
        _requestSnapshot(true)
    end
    if not _hasSnapshotData() then
        _setStatus(_statusForCfg(cfg, _getServerTime()))
        return LOOP_SEC
    end

    local serverTime = _getServerTime()
    _reconcileSnapshot(serverTime)

    if #snapshot.lots == 0 then
        _setStatus(_statusForCfg(cfg, serverTime))
        return LOOP_SEC
    end

    local holdStatus = nil
    for _, lot in ipairs(snapshot.lots) do
        if _lotSelected(lot, cfg) then
            local okAvail, why = _lotAvailable(lot, serverTime)
            local price = _lotPriceForBuy(lot, serverTime)
            local maxP = _maxPriceForLot(cfg, lot)
            if okAvail and price and _priceOk(price, maxP) then
                local bought, reason = _tryBuyLot(lot, price, cfg)
                if bought then return LOOP_SEC end
                if reason == "no_money" then
                    _setStatus("Sheckles tidak cukup")
                    return LOOP_SEC * 3
                end
                holdStatus = string.format("Gagal beli %s (%s)", tostring(lot.item), tostring(reason or "?"))
            elseif not okAvail then
                holdStatus = string.format("%s: %s", tostring(lot.item), tostring(why or "tidak tersedia"))
            elseif not price then
                holdStatus = string.format("Harga %s tidak terbaca", tostring(lot.item))
            elseif maxP > 0 and price > maxP then
                holdStatus = string.format("%s: %s > max %s",
                    _lotDisplayName(lot), _fmtPrice(price), _fmtPrice(maxP))
            end
        end
    end

    if holdStatus then
        _setStatus(holdStatus)
    else
        _setStatus(_statusForCfg(cfg, serverTime))
    end
    _refreshProgressStats(cfg)
    return LOOP_SEC
end

local function _hookEventsImpl()
    if eventsHooked or not _ensureNet() then return end
    local ae = Networking.Auctioneer
    local snapRemote = (ae and ae.Snapshot) or _findAuctionRemoteEvent("Snapshot")
    if not snapRemote then
        stats.lastError = "Auctioneer.Snapshot missing"
        return
    end

    local function onSnap(payload)
        if typeof(payload) == "table" then
            _parseSnapshot(payload)
            _reconcileSnapshot(_getServerTime())
            _refreshProgressStats(_readCfg())
            _log("Snapshot event", snapshot and #snapshot.lots or 0, "lots")
        end
    end
    local function onStock(payload)
        -- u149: hanya update stock map
        if typeof(payload) == "table" and typeof(payload.stock) == "table" then
            stockMap = payload.stock
            if snapshot then snapshot.stock = stockMap end
            task.defer(function()
                _reconcileSnapshot(_getServerTime())
                _refreshProgressStats(_readCfg())
            end)
        end
    end
    local function onResult(lotId, success)
        lotId = _lotIdKey(lotId)
        purchaseDebounceAt[lotId] = nil
        local pending = pendingPurchases[lotId]
        pendingPurchases[lotId] = nil
        if success == true and pending then
            stats.buys += 1
            stats.lastBuy = {
                lotId = lotId,
                item = pending.item,
                price = pending.price,
                at = pending.at or os.time(),
            }
            _setStatus(string.format(
                "Beli %s @ %s",
                tostring(pending.item or "?"),
                pending.price ~= nil and _fmtPrice(pending.price) or "?"
            ))
            _log("buy ok", lotId, pending.item, pending.price)
        elseif success == false then
            cooldownUntil[lotId] = nil
            purchaseAt[lotId] = nil
        end
    end

    if not _connectRemoteEvent(snapRemote, onSnap) then
        stats.lastError = "gagal hook Snapshot.OnClientEvent"
        return
    end
    local stockRemote = (ae and ae.StockUpdate) or _findAuctionRemoteEvent("StockUpdate")
    _connectRemoteEvent(stockRemote, onStock)
    local resultRemote = (ae and ae.PurchaseResult) or _findAuctionRemoteEvent("PurchaseResult")
    _connectRemoteEvent(resultRemote, onResult)
    eventsHooked = true
    _log("auction events hooked", #eventConns)
end
_hookEvents = _hookEventsImpl

local function _unhookEvents()
    for _, c in ipairs(eventConns) do
        pcall(function() c:Disconnect() end)
    end
    table.clear(eventConns)
end

function M.Start()
    if running then return end
    running = true
    loopId += 1
    local myId = loopId
    _hookEvents()
    task.spawn(function()
        _requestSnapshot(true)
        while running and loopId == myId do
            local waitSec = LOOP_SEC
            local ok, ret = pcall(_tick)
            if ok and type(ret) == "number" then waitSec = ret end
            task.wait(waitSec)
        end
    end)
end

function M.Stop()
    running = false
    loopId += 1
    _setStatus("Off")
end

function M.EnsureRunning()
    local cfg = _readCfg()
    if cfg.enabled then M.Start() else M.Stop() end
end

function M.SyncFromState()
    M.EnsureRunning()
end

function M.SyncFromGlobals()
    M.EnsureRunning()
end

function M.GetStats()
    local cfg = _readCfg()
    _refreshProgressStats(cfg)
    return {
        lastStatus = stats.lastStatus,
        lastError = stats.lastError,
        lastBuy = stats.lastBuy,
        buys = stats.buys,
        lotCount = stats.lotCount,
        matchedLots = stats.matchedLots,
        availableLots = stats.availableLots,
        snapshotAge = (snapshot and lastSnapshotAt > 0) and math.max(0, os.clock() - lastSnapshotAt) or nil,
        auctionGuiOpen = stats.auctionGuiOpen,
        enabled = cfg.enabled,
        running = running,
        max_prices = cfg.max_prices,
    }
end

function M.GetStatusLine()
    local st = M.GetStats()
    return "Status: " .. tostring(st.lastStatus or "Ready")
end

function M.GetDetailsLine()
    local st = M.GetStats()
    local parts = {
        string.format(
            "Lots %d · Match %d · Buyable %d · Purchases %d",
            tonumber(st.lotCount) or 0,
            tonumber(st.matchedLots) or 0,
            tonumber(st.availableLots) or 0,
            tonumber(st.buys) or 0
        ),
    }
    if type(st.lastBuy) == "table" then
        parts[#parts + 1] = string.format(
            "Last: %s @ %s",
            tostring(st.lastBuy.item or "?"),
            st.lastBuy.price ~= nil and _fmtPrice(st.lastBuy.price) or "?"
        )
    elseif st.lastError and st.lastError ~= "" and not st.running then
        parts[#parts + 1] = "Err: " .. tostring(st.lastError)
    end
    return table.concat(parts, " · ")
end

function M.GetStatusText()
    return M.GetStatusLine() .. "\n" .. M.GetDetailsLine()
end

function M.RefreshSnapshot()
    return _bootstrapAuction(SNAPSHOT_WAIT_SEC)
end

function M.AnalyzeLots()
    _ensureAuctioneer()
    local serverTime = _getServerTime()
    local out = {}
    if snapshot and snapshot.lots then
        for _, lot in ipairs(snapshot.lots) do
            out[#out + 1] = _analyzeLot(lot, serverTime)
        end
    end
    return out
end

function M.ProbeSnapshot()
    _hookEvents()
    local ok = M.RefreshSnapshot()
    local n = snapshot and #snapshot.lots or 0
    ok = ok or n > 0
    print("[GAG2-ABA] ProbeSnapshot ok=", ok, "lots=", n, "err=", stats.lastError)
    return ok, n, stats.lastError
end

-- Init + stats poller (jalan meski auto buy OFF — supaya Lots/Match akurat tanpa buka UI)
local statsLoopId = 0

local function _startStatsPoller()
    statsLoopId += 1
    local myId = statsLoopId
    task.spawn(function()
        -- u206: hook + RequestSnapshot segera (jangan tunggu 25 detik)
        for _ = 1, 20 do
            if _bootstrapAuction(SNAPSHOT_WAIT_SEC) then break end
            task.wait(0.5)
        end
        while statsLoopId == myId do
            if _ensureNet() then
                if not eventsHooked then _hookEvents() end
                local stale = not _hasSnapshotData()
                    or (os.clock() - lastSnapshotAt) > SNAPSHOT_EVERY_SEC
                if stale then
                    _bootstrapAuction(2)
                end
                _reconcileSnapshot(_getServerTime())
                local cfg = _readCfg()
                _refreshProgressStats(cfg)
                if not cfg.enabled or not running then
                    _setStatus(_statusForCfg(cfg, _getServerTime()))
                end
            else
                _setStatus("Auction remote belum ready")
            end
            task.wait(1.5)
        end
    end)
end

_startStatsPoller()

pcall(function() M.SyncFromState() end)

return M
 end,               required = false },
    { key = "SectionAutoBuyAuction",   name = "Section Auto Buy Auction", factory = function() -- section_auto_buy_auction.lua — max price parse/format sama Gift send total price

local G = (getgenv and getgenv()) or _G
local M = {}

local function parseScaledPrice(txt)
    txt = tostring(txt or ""):lower():gsub("%s+", ""):gsub(",", "")
    if txt == "" then return nil end
    local suffixes = {
        { "juta", 1000000 }, { "jt", 1000000 },
        { "ribu", 1000 }, { "rb", 1000 },
        { "b", 1000000000 }, { "m", 1000000 }, { "k", 1000 },
    }
    for _, pair in ipairs(suffixes) do
        local suf, mult = pair[1], pair[2]
        if #txt > #suf and txt:sub(-#suf) == suf then
            local n = tonumber(txt:sub(1, -#suf - 1))
            if n then return math.max(0, math.floor(n * mult)) end
        end
    end
    local n = tonumber(txt)
    if n then return math.max(0, math.floor(n)) end
    return nil
end

local function formatScaledPrice(n)
    n = math.floor(tonumber(n) or 0)
    if n <= 0 then return "0" end
    if n >= 1000000000 then return string.format("%.2fB", n / 1000000000) end
    if n >= 1000000 then return string.format("%.2fM", n / 1000000) end
    if n >= 1000 then return string.format("%.1fK", n / 1000) end
    return tostring(n)
end

function M.parseMaxPrice(raw)
    if type(raw) == "number" then
        return math.max(0, math.floor(raw))
    end
    local parsed = parseScaledPrice(raw)
    if parsed ~= nil then return parsed end
    return math.max(0, math.floor(tonumber(raw) or 0))
end

function M.formatMaxPrice(n)
    return formatScaledPrice(n)
end

local function cleanMap(map)
    local out = {}
    if type(map) ~= "table" then return out end
    for k, v in pairs(map) do
        if v == true or v == 1 or v == "true" then
            local key = tostring(k)
            if key ~= "" then out[key] = true end
        end
    end
    return out
end

function M.Register(ctx)
    if type(ctx) ~= "table" or type(ctx.ui) ~= "table" then return end

    local ui = ctx.ui
    local getAuto = ctx.getAuto
    local patchAutoOnly = ctx.patchAutoOnly
    local saveNow = ctx.saveNow
    local registerFlush = ctx.registerFlush
    local cleanSelectedMap = ctx.cleanSelectedMap or cleanMap
    local arrayToMap = ctx.arrayToMap
    local mapToArrayFn = ctx.mapToArray
    local PlantListView = ctx.PlantListView or G.PlantListView
    local ShopListView = ctx.ShopListView or G.ShopListView

    if type(getAuto) ~= "function" or type(patchAutoOnly) ~= "function" then
        warn("[GAG2] SectionAutoBuyAuction: missing getAuto/patchAutoOnly")
        return
    end

    local BUY = getAuto("buy")
    local A = type(BUY.auction) == "table" and BUY.auction or {}
    local enabled = (A.enabled == true)

    local function catItems(key)
        local cat = type(A[key]) == "table" and A[key] or {}
        if type(cat.items) == "table" and cat.items[1] ~= nil and arrayToMap then
            return cleanSelectedMap(arrayToMap(cat.items))
        end
        return cleanSelectedMap(cat.items)
    end

    local SEL_SEED = catItems("seed")
    local SEL_GEAR = catItems("gear")
    local SEL_SEEDPACK = catItems("seedpack")
