    local seedMax = M.parseMaxPrice(type(A.seed) == "table" and A.seed.max_price or 0)
    local gearMax = M.parseMaxPrice(type(A.gear) == "table" and A.gear.max_price or 0)
    local seedpackMax = M.parseMaxPrice(type(A.seedpack) == "table" and A.seedpack.max_price or 0)
    local eggMax = M.parseMaxPrice(type(A.egg) == "table" and A.egg.max_price or 0)

    local priceGets = {}
    local priceSets = {}

    local function buildAuction()
        local enableApi = G.__GAG2_BUY_AUCTION_ENABLE_API or rawget(_G, "__GAG2_BUY_AUCTION_ENABLE_API")
        if type(enableApi) == "table" and type(enableApi.get) == "function" then
            enabled = (enableApi.get() == true)
        end
        return {
            enabled = enabled,
            seed = { items = mapToArrayFn(SEL_SEED), max_price = seedMax },
            gear = { items = mapToArrayFn(SEL_GEAR), max_price = gearMax },
            seedpack = { items = mapToArrayFn(SEL_SEEDPACK), max_price = seedpackMax },
            egg = { items = mapToArrayFn(SEL_EGG), max_price = eggMax },
        }
    end

    local function syncGlobals(p)
        G.AUTO_BUY_AUCTION_ENABLED = p.enabled
        _G.AUTO_BUY_AUCTION_ENABLED = p.enabled
        G.AUTO_BUY_AUCTION_SEED_MAX_PRICE = p.seed.max_price
        _G.AUTO_BUY_AUCTION_SEED_MAX_PRICE = p.seed.max_price
        G.AUTO_BUY_AUCTION_GEAR_MAX_PRICE = p.gear.max_price
        _G.AUTO_BUY_AUCTION_GEAR_MAX_PRICE = p.gear.max_price
        G.AUTO_BUY_AUCTION_SEEDPACK_MAX_PRICE = p.seedpack.max_price
        _G.AUTO_BUY_AUCTION_SEEDPACK_MAX_PRICE = p.seedpack.max_price
        G.AUTO_BUY_AUCTION_EGG_MAX_PRICE = p.egg.max_price
        _G.AUTO_BUY_AUCTION_EGG_MAX_PRICE = p.egg.max_price
        G.BUY_AUCTION_SEED_SELECTED = SEL_SEED
        _G.BUY_AUCTION_SEED_SELECTED = SEL_SEED
        G.BUY_AUCTION_GEAR_SELECTED = SEL_GEAR
        _G.BUY_AUCTION_GEAR_SELECTED = SEL_GEAR
        G.BUY_AUCTION_SEEDPACK_SELECTED = SEL_SEEDPACK
        _G.BUY_AUCTION_SEEDPACK_SELECTED = SEL_SEEDPACK
        G.BUY_AUCTION_EGG_SELECTED = SEL_EGG
        _G.BUY_AUCTION_EGG_SELECTED = SEL_EGG
    end

    local function pullPricesFromUI()
        if priceGets.seed then seedMax = M.parseMaxPrice(priceGets.seed()) end
        if priceGets.gear then gearMax = M.parseMaxPrice(priceGets.gear()) end
        if priceGets.seedpack then seedpackMax = M.parseMaxPrice(priceGets.seedpack()) end
        if priceGets.egg then eggMax = M.parseMaxPrice(priceGets.egg()) end
    end

    local function refreshPriceDisplays()
        if priceSets.seed then pcall(priceSets.seed, M.formatMaxPrice(seedMax)) end
        if priceSets.gear then pcall(priceSets.gear, M.formatMaxPrice(gearMax)) end
        if priceSets.seedpack then pcall(priceSets.seedpack, M.formatMaxPrice(seedpackMax)) end
        if priceSets.egg then pcall(priceSets.egg, M.formatMaxPrice(eggMax)) end
    end

    local function pushAuction()
        pullPricesFromUI()
        local p = buildAuction()
        seedMax = p.seed.max_price
        gearMax = p.gear.max_price
        seedpackMax = p.seedpack.max_price
        eggMax = p.egg.max_price

        local m = rawget(_G, "MAIN") or G.MAIN
        if type(m) == "table" then
            m.auto = m.auto or {}
            m.auto.buy = m.auto.buy or {}
            m.auto.buy.auction = p
            G.MAIN = m
            _G.MAIN = m
        end

        patchAutoOnly("buy", { auction = p })
        syncGlobals(p)
        return p
    end

    local function saveAuction()
        pushAuction()
        refreshPriceDisplays()
        if type(saveNow) == "function" then
            pcall(saveNow)
        end
    end

