    _G.__GAG2_FLUSH_BUY_AUCTION = pushAuction
    G.__GAG2_SYNC_AUTO_BUY_AUCTION = pushAuction
    _G.__GAG2_SYNC_AUTO_BUY_AUCTION = pushAuction

    if type(registerFlush) == "function" then
        registerFlush("buy_auction", pushAuction)
    end

    local function getModule()
        return G.AutoBuyAuctionModule or G.AutoBuyAuction
            or rawget(_G, "AutoBuyAuctionModule") or rawget(_G, "AutoBuyAuction")
    end

    local function syncModule()
        local mod = getModule()
        if type(mod) ~= "table" then return end
        if enabled then
            if type(mod.Start) == "function" then pcall(mod.Start, mod)
            elseif type(mod.start) == "function" then pcall(mod.start, mod) end
        else
            if type(mod.Stop) == "function" then pcall(mod.Stop, mod)
            elseif type(mod.stop) == "function" then pcall(mod.stop, mod) end
        end
    end

