    local _, statusLabel = ui:CreateRowLabel(body, "Status: Ready", nil, nil, "info")
    local _, detailsLabel = ui:CreateRowLabel(body, "Lots 0 · Match 0 · Buyable 0 · Purchases 0", nil, nil, "info")

    task.spawn(function()
        while statusLabel and statusLabel.Parent do
            pcall(function()
                local mod = getModule()
                if type(mod) == "table" and type(mod.GetStatusLine) == "function" then
                    local okS, txtS = pcall(mod.GetStatusLine, mod)
                    if okS and type(txtS) == "string" then statusLabel.Text = txtS end
                else
                    statusLabel.Text = "Status: " .. tostring(
                        G.AUTO_BUY_AUCTION_STATUS or rawget(_G, "AUTO_BUY_AUCTION_STATUS") or "Ready"
                    )
                end
                if detailsLabel and detailsLabel.Parent then
                    if type(mod) == "table" and type(mod.GetDetailsLine) == "function" then
                        local ok, txt = pcall(mod.GetDetailsLine, mod)
                        if ok and type(txt) == "string" then detailsLabel.Text = txt end
                    else
                        detailsLabel.Text = string.format(
                            "Lots %d · Match %d · Buyable %d · Purchases %d",
                            tonumber(G.AUTO_BUY_AUCTION_LOTS or rawget(_G, "AUTO_BUY_AUCTION_LOTS")) or 0,
                            tonumber(G.AUTO_BUY_AUCTION_MATCH or rawget(_G, "AUTO_BUY_AUCTION_MATCH")) or 0,
                            tonumber(G.AUTO_BUY_AUCTION_BUYABLE or rawget(_G, "AUTO_BUY_AUCTION_BUYABLE")) or 0,
                            tonumber(G.AUTO_BUY_AUCTION_BUYS or rawget(_G, "AUTO_BUY_AUCTION_BUYS")) or 0
                        )
                    end
                end
            end)
            task.wait(0.5)
        end
    end)

    local PRICE_LABEL = " (0=any, 1K/1M/1B)"

    local function priceRow(key, label, value)
        local _, setPrice = ui:CreateRowInput(body, label .. PRICE_LABEL, M.formatMaxPrice(value), function(txt)
            local n = M.parseMaxPrice(txt)
            if key == "seed" then seedMax = n
            elseif key == "gear" then gearMax = n
            elseif key == "seedpack" then seedpackMax = n
            elseif key == "egg" then eggMax = n
            end
            saveAuction()
            syncModule()
        end, false)
        priceGets[key] = setPrice
        priceSets[key] = setPrice
    end

    ui:CreateRowDropdown(body, {
        label = "Select Seed",
        placeholder = "Select Options",
        mode = "multi",
        preserveItemOrder = true,
        getItems = function()
            if PlantListView and type(PlantListView.buildSeedItems) == "function" then
                return PlantListView.buildSeedItems(BUY_LIST_SORT) or {}
            end
            return {}
        end,
        initial = SEL_SEED,
        onChanged = function(_, selectedMap)
            SEL_SEED = cleanSelectedMap(selectedMap)
