    syncModule()
end

return M
 end,   required = false },
    { key = "AutoGiftPrice",           name = "Auto Gift Price",         factory = function() -- AutoGiftPrice.lua — harvest price combo search (subset of AutoGift)

local M = {}

function M.create(deps)
    deps = type(deps) == "table" and deps or {}
    local clampBatch = deps.clampBatch or function(n) return math.max(1, math.floor(tonumber(n) or 1)) end
    local maxBatch = tonumber(deps.maxBatch) or 999999
    local formatSellPrice = deps.formatSellPrice or tostring
    local isHarvested = deps.isHarvestedFruitsCategory or function() return false end
    local entrySellPrice = deps.entrySellPrice or function() return 0 end

    local PRICE_SUBSET_MAX_ITEMS = 200

    local function itemPrice(item)
        return math.floor(tonumber(item and item.SellPrice) or 0)
    end

    local function itemKey(item)
        return tostring(item and item.ItemKey or "")
    end

    local function poolFromCandidates(candidates)
        local pool = {}
        for _, item in ipairs(candidates) do
            local cat = item.Category
            if not isHarvested(cat) then
                continue
            end
            local price = math.floor(tonumber(item.SellPrice) or 0)
            if price <= 0 then
                price = entrySellPrice(cat, item.ItemKey, item.Entry)
                item.SellPrice = price
            end
            if price > 0 then
                pool[#pool + 1] = item
            end
        end
        return pool
    end

    local function formatBreakdown(pick)
        if type(pick) ~= "table" or #pick == 0 then return "" end
        local map = {}
        for _, item in ipairs(pick) do
            local p = math.floor(tonumber(item.SellPrice) or 0)
            if p > 0 then
                map[p] = (map[p] or 0) + 1
            end
        end
        local keys = {}
        for p in pairs(map) do
            keys[#keys + 1] = p
        end
        table.sort(keys)
        local parts = {}
        for _, p in ipairs(keys) do
            local c = map[p]
            if c > 1 then
                parts[#parts + 1] = tostring(c) .. "x" .. formatSellPrice(p)
            else
                parts[#parts + 1] = formatSellPrice(p)
            end
        end
        return table.concat(parts, "+")
    end

    local function filterPricePool(pool, maxSum)
        local items = {}
        for _, item in ipairs(pool) do
            local p = itemPrice(item)
            if p > 0 and p <= maxSum then
                items[#items + 1] = item
            end
        end
        return items
    end

    local function sortPriceItems(items, descending)
        table.sort(items, function(a, b)
            if descending then
                return itemPrice(a) > itemPrice(b)
            end
            return itemPrice(a) < itemPrice(b)
        end)
        return items
    end

    local function findMaxComboUnder(pool, maxSum, maxItems)
        maxSum = math.max(1, math.floor(tonumber(maxSum) or 0))
        maxItems = math.max(1, math.min(clampBatch(maxItems or maxBatch), #pool))
        local items = sortPriceItems(filterPricePool(pool, maxSum), true)
        local combo = {}
        local sum = 0
        for _, item in ipairs(items) do
            if #combo >= maxItems then
                break
            end
            local p = itemPrice(item)
            if sum + p <= maxSum then
                combo[#combo + 1] = item
                sum += p
            end
        end
        if #combo > 0 then
            return combo, sum
        end
        return nil, 0
    end

    local function tryBuildPriceCombo(items, minSum, maxSum, maxItems, descending)
        minSum = math.max(1, math.floor(tonumber(minSum) or 0))
        maxSum = math.max(minSum, math.floor(tonumber(maxSum) or 0))
        maxItems = math.max(1, math.min(clampBatch(maxItems or maxBatch), #items))
        if #items == 0 then
            return nil, 0
        end

        local order = sortPriceItems(items, descending == true)
        local combo = {}
        local usedKeys = {}
        local sum = 0

        local function tryAddFromList(list)
            for _, item in ipairs(list) do
                if sum >= minSum then
                    return
                end
                if #combo >= maxItems then
                    return
                end
                local key = itemKey(item)
                if key == "" or usedKeys[key] then
                    continue
                end
                local p = itemPrice(item)
                if p <= 0 or sum + p > maxSum then
                    continue
                end
                combo[#combo + 1] = item
                usedKeys[key] = true
                sum += p
            end
        end

        tryAddFromList(order)
        if sum < minSum then
            return nil, 0
        end

        local trimPasses = math.max(12, #order * 2)
        while trimPasses > 0 do
            if sum >= minSum and sum <= maxSum then
                return combo, sum
            end
            if sum <= maxSum and sum < minSum then
                tryAddFromList(sortPriceItems(order, false))
                if sum >= minSum and sum <= maxSum then
                    return combo, sum
                end
                return nil, 0
            end
            if sum <= maxSum then
                return nil, 0
            end

            trimPasses -= 1
            local removeIdx, removePrice = 1, 0
            for i, item in ipairs(combo) do
                local p = itemPrice(item)
                if p > removePrice then
                    removeIdx = i
                    removePrice = p
                end
            end
            local removed = table.remove(combo, removeIdx)
            usedKeys[itemKey(removed)] = nil
            sum -= removePrice

            for _, item in ipairs(sortPriceItems(order, false)) do
                if sum >= minSum and sum <= maxSum then
                    break
                end
                if #combo >= maxItems then
                    break
                end
                local key = itemKey(item)
                if key == "" or usedKeys[key] then
                    continue
                end
                local p = itemPrice(item)
                if p <= 0 or sum + p > maxSum then
                    continue
                end
                combo[#combo + 1] = item
                usedKeys[key] = true
                sum += p
            end
        end

        if sum >= minSum and sum <= maxSum then
            return combo, sum
        end
        return nil, 0
    end

    local function findPriceSubset(pool, minSum, maxSum, maxItems)
        minSum = math.max(1, math.floor(tonumber(minSum) or 0))
        maxSum = math.max(minSum, math.floor(tonumber(maxSum) or 0))
        maxItems = math.max(1, math.min(clampBatch(maxItems or maxBatch), #pool))
        if minSum > maxSum or #pool == 0 then
            return nil, 0
        end

        local items = filterPricePool(pool, maxSum)
        if #items == 0 then
            return nil, 0
        end
        if #items > PRICE_SUBSET_MAX_ITEMS then
            items = sortPriceItems(items, true)
            local trimmed = {}
            for i = 1, PRICE_SUBSET_MAX_ITEMS do
                trimmed[i] = items[i]
            end
            items = trimmed
        end

        local pick, total = tryBuildPriceCombo(items, minSum, maxSum, maxItems, true)
        if pick then
            return pick, total
        end
        pick, total = tryBuildPriceCombo(items, minSum, maxSum, maxItems, false)
        if pick then
            return pick, total
        end
        return nil, 0
    end

    local function pickToBatch(pick, total)
        if type(pick) ~= "table" or #pick == 0 then
            return nil, 0
        end
        local batch = {}
        for _, item in ipairs(pick) do
            batch[#batch + 1] = {
                Category = item.Category,
                ItemKey = item.ItemKey,
                Count = 1,
                SellPrice = itemPrice(item),
            }
        end
        return batch, total
    end

    local function buildMultiBatchPricePlan(candidates, targetMin, targetMax, maxItems)
        targetMin = math.max(1, math.floor(tonumber(targetMin) or 0))
        targetMax = math.max(targetMin, math.floor(tonumber(targetMax) or 0))
        maxItems = math.max(1, clampBatch(maxItems or 20))

        local pool = poolFromCandidates(candidates)
        if #pool == 0 then
            return nil, 0, #pool, 0
        end

        local sent = 0
        local allPick = {}
        local usedKeys = {}
        local batchCount = 0
        local maxRounds = math.ceil(#pool / math.max(1, maxItems)) + 2

        while sent < targetMin and batchCount < maxRounds do
            local remainMin = targetMin - sent
            local remainMax = targetMax - sent
            local available = {}
            for _, item in ipairs(pool) do
                local key = itemKey(item)
                if key ~= "" and not usedKeys[key] then
                    available[#available + 1] = item
                end
            end
            if #available == 0 then
                break
            end

            local pick, total = findPriceSubset(available, remainMin, remainMax, maxItems)
            if not pick then
                pick, total = findMaxComboUnder(available, remainMax, maxItems)
            end
            if not pick or #pick == 0 or total <= 0 then
                break
            end

            batchCount += 1
            for _, item in ipairs(pick) do
                allPick[#allPick + 1] = item
                usedKeys[itemKey(item)] = true
            end
            sent += total
            if sent >= targetMin and sent <= targetMax then
                break
            end
        end

        if sent >= targetMin and sent <= targetMax then
            return allPick, sent, #pool, batchCount
        end
        return nil, sent, #pool, batchCount
    end

    local function planPriceBatch(candidates, minSum, maxSum, maxItems, usedKeys)
        local pool = poolFromCandidates(candidates)
        if type(usedKeys) == "table" then
            local filtered = {}
            for _, item in ipairs(pool) do
                local key = itemKey(item)
                if key ~= "" and not usedKeys[key] then
                    filtered[#filtered + 1] = item
                end
            end
            pool = filtered
        end
        local pick, total = findPriceSubset(pool, minSum, maxSum, maxItems)
        if not pick then
            pick, total = findMaxComboUnder(pool, maxSum, maxItems)
        end
        if not pick then
            return nil, 0, pool
        end
        local batch, batchTotal = pickToBatch(pick, total)
        return batch, batchTotal, pool
    end

    local function pricePlanSummary(pick, total, minSum, maxSum, poolSize, batchCount)
        if type(pick) ~= "table" or #pick == 0 then
            return "Tidak ada kombinasi "
                .. formatSellPrice(minSum) .. "–" .. formatSellPrice(maxSum)
                .. " (" .. tostring(poolSize or 0) .. " buah dicek)"
        end
        local batchNote = ""
        if type(batchCount) == "number" and batchCount > 1 then
            batchNote = " / " .. tostring(batchCount) .. " batch"
        end
        return string.format(
            "Plan: %d buah %s (range %s–%s%s) [%s]",
            #pick,
            formatSellPrice(total),
            formatSellPrice(minSum),
            formatSellPrice(maxSum),
            batchNote,
            formatBreakdown(pick)
        )
    end

    return {
        poolFromCandidates = poolFromCandidates,
        formatBreakdown = formatBreakdown,
        buildMultiBatchPricePlan = buildMultiBatchPricePlan,
        planPriceBatch = planPriceBatch,
        pricePlanSummary = pricePlanSummary,
    }
end

return M
 end,                  required = false },
    { key = "GiftMailHistory",         name = "Gift Mail History",       factory = function() -- GiftMailHistory.lua — log gift mail sends to file + side panel UI

local HttpService = game:GetService("HttpService")
