local COLOR_PANEL = Color3.fromRGB(10, 10, 10)
local COLOR_PANEL_ALT = Color3.fromRGB(15, 15, 15)
local COLOR_CARD = Color3.fromRGB(12, 12, 12)
local COLOR_CARD_HEAD = Color3.fromRGB(16, 16, 16)
local COLOR_YELLOW = Color3.fromRGB(255, 211, 0)
local COLOR_WHITE = Color3.fromRGB(255, 255, 255)
local COLOR_GRAY = Color3.fromRGB(180, 180, 180)
local COLOR_DIM = Color3.fromRGB(105, 105, 105)
local COLOR_STROKE = Color3.fromRGB(60, 60, 60)
local COLOR_SEARCH = Color3.fromRGB(18, 18, 18)
