local _findPanelInstance, _rebindUiRefs, _setPanelVisible, _buildUi

local function _safeName(s)
    s = tostring(s or "player")
    s = s:gsub("[^%w%-_.]", "_"):gsub("_+", "_")
    return s:sub(1, 48)
end

local function _historyFile()
    return SAVE_DIR .. "/" .. _safeName(LP and LP.Name or "player") .. "_gift_mail_history.json"
end

local function _ensureFolder()
    if not CAN_FS then return false end
    if typeof(isfolder) == "function" and not isfolder(SAVE_DIR) then
        pcall(makefolder, SAVE_DIR)
    end
    return typeof(isfolder) == "function" and isfolder(SAVE_DIR)
end

local function _jsonEncode(t)
    local ok, s = pcall(function() return HttpService:JSONEncode(t) end)
    return ok and s or nil
end

local function _jsonDecode(s)
    local ok, t = pcall(function() return HttpService:JSONDecode(s) end)
    return ok and type(t) == "table" and t or nil
end

local function _clampRetainDays(n)
    n = math.floor(tonumber(n) or DEFAULT_RETAIN_DAYS)
    if n < 1 then n = 1 end
    if n > 90 then n = 90 end
    return n
end

local function _dayKey(ts)
    return os.date("%Y-%m-%d", ts or os.time())
end

local function _todayBatchCount()
    local today = _dayKey(os.time())
    local n = 0
    for _, e in ipairs(entries) do
        if type(e) == "table" and e.success == true then
            local day = tostring(e.day or _dayKey(e.ts))
            if day == today then
                n += math.max(1, math.floor(tonumber(e.send_batch) or 1))
            end
        end
    end
    return n
end

local function _limitCountColor(todayN)
    if todayN >= DAILY_GIFT_BATCH_LIMIT then return COLOR_FAIL end
    if todayN >= DAILY_GIFT_BATCH_LIMIT - 5 then return COLOR_YELLOW end
    return COLOR_OK
end

