end

function M.GetDailyGiftBatchLimit()
    return DAILY_GIFT_BATCH_LIMIT
end

function M.GetTodaySendBatchRemaining()
    return math.max(0, DAILY_GIFT_BATCH_LIMIT - _todayBatchCount())
end

local function _prune(list)
    list = type(list) == "table" and list or {}
    local cutoff = os.time() - retainDays * 86400
    local out = {}
    for _, e in ipairs(list) do
        if type(e) == "table" then
            local ts = math.floor(tonumber(e.ts) or 0)
            if ts <= 0 or ts >= cutoff then
                out[#out + 1] = e
            end
        end
    end
    if #out > MAX_ENTRIES then
        local start = #out - MAX_ENTRIES + 1
        local trimmed = {}
        for i = start, #out do
            trimmed[#trimmed + 1] = out[i]
        end
        out = trimmed
    end
    return out
end

local function _saveFile()
    if not CAN_FS or not _ensureFolder() then return false end
    entries = _prune(entries)
    local payload = {
        version = FILE_VERSION,
        retain_days = retainDays,
        entries = entries,
    }
    local json = _jsonEncode(payload)
    if not json then return false end
    local ok = pcall(writefile, _historyFile(), json)
    return ok == true
end

local function _loadFile()
    entries = {}
    if not CAN_FS then return entries end
    local path = _historyFile()
    if not isfile(path) then return entries end
    local ok, text = pcall(readfile, path)
    if not ok or type(text) ~= "string" or text == "" then return entries end
    local data = _jsonDecode(text)
    if not data then return entries end
    retainDays = _clampRetainDays(data.retain_days or retainDays)
    local raw = type(data.entries) == "table" and data.entries or {}
    local list = {}
    if #raw > 0 then
        list = raw
    else
        for _, v in pairs(raw) do
            if type(v) == "table" then
                list[#list + 1] = v
            end
        end
        table.sort(list, function(a, b)
            return (tonumber(a.ts) or 0) > (tonumber(b.ts) or 0)
        end)
    end
    entries = _prune(list)
    return entries
end

local function _findScrollFrame(content)
    if not content then return nil end
    local viewport = content:FindFirstChild("ListViewport")
    if viewport then
        return viewport:FindFirstChild("Scroll")
    end
    return content:FindFirstChild("Scroll")
end

local function _panelUiReady(root)
    if not root or not root.Parent then return false end
    if root:GetAttribute("UiVer") ~= UI_VER then return false end
    local content = root:FindFirstChild("Content")
    if not content then return false end
    local scroll = _findScrollFrame(content)
    local list = scroll and scroll:FindFirstChild("List")
    return scroll ~= nil and list ~= nil
end

local function _clearListCards()
    if not listFrame then return end
    for _, ch in ipairs(listFrame:GetChildren()) do
        if ch:IsA("Frame") or ch:IsA("TextLabel") then
            ch:Destroy()
        end
    end
end

local function _entryIndicesNewestFirst()
    local idx = {}
    for i = 1, #entries do
        if type(entries[i]) == "table" then
            idx[#idx + 1] = i
        end
    end
    if #idx == 0 then
        for k, e in pairs(entries) do
            if type(k) == "number" and type(e) == "table" then
                idx[#idx + 1] = k
            end
        end
        table.sort(idx)
    end
    table.sort(idx, function(a, b)
        local ta = math.floor(tonumber(entries[a] and entries[a].ts) or 0)
        local tb = math.floor(tonumber(entries[b] and entries[b].ts) or 0)
        if ta ~= tb then return ta > tb end
        return a > b
    end)
    return idx
end

local CAT_LABELS = {
    HarvestedFruits = "Harvested Fruits",
    Pets = "Pets",
    Seeds = "Seeds",
}
local CAT_ORDER = { HarvestedFruits = 1, Pets = 2, Seeds = 3 }

local function _catTheme(_cat)
    return {
        bg = COLOR_PANEL_ALT,
        head = Color3.fromRGB(18, 18, 18),
        accent = COLOR_WHITE,
        price = COLOR_YELLOW,
    }
end

local function _round(inst, r)
    local c = Instance.new("UICorner")
    if type(r) == "number" and r >= 100 then
        c.CornerRadius = UDim.new(1, 0)
    else
        c.CornerRadius = UDim.new(0, r or RADIUS)
    end
    c.Parent = inst
    return c
end

local function _softStroke(inst, color, t, tr)
    local s = Instance.new("UIStroke")
    s.Color = color or COLOR_STROKE
    s.Thickness = t or 1
    s.Transparency = tr or 0.55
    s.ApplyStrokeMode = Enum.ApplyStrokeMode.Border
    pcall(function()
        s.LineJoinMode = Enum.LineJoinMode.Round
    end)
    s.Parent = inst
    return s
end

local function _insetBorder(parent, opts)
    opts = type(opts) == "table" and opts or {}
    local radius = opts.radius or RADIUS
    local border = opts.border or COLOR_YELLOW
    local fill = opts.fill or COLOR_PANEL
    local inset = opts.inset or 1

    local shell = Instance.new("Frame")
    shell.Name = opts.name or "BorderShell"
    shell.BackgroundColor3 = border
    shell.BorderSizePixel = 0
    shell.Size = opts.size or UDim2.new(1, 0, 0, 0)
    shell.Parent = parent
    _round(shell, radius)

    local inner = Instance.new("Frame")
    inner.Name = opts.innerName or "BorderInner"
    inner.BackgroundColor3 = fill
    inner.BorderSizePixel = 0
    inner.ClipsDescendants = opts.clip == true
    if opts.clip == true then
        shell.ClipsDescendants = true
    end
    inner.Position = UDim2.new(0, inset, 0, inset)
    inner.Parent = shell
    _round(inner, math.max(radius - inset, 4))

    if opts.autoY == true then
        inner.Size = UDim2.new(1, -(inset * 2), 0, 0)
        inner.AutomaticSize = Enum.AutomaticSize.Y
        local function syncShell()
            local h = inner.AbsoluteSize.Y
            shell.Size = UDim2.new(1, 0, 0, math.max(h + (inset * 2), inset * 2))
        end
        inner:GetPropertyChangedSignal("AbsoluteSize"):Connect(syncShell)
        task.defer(syncShell)
    else
        inner.Size = UDim2.new(1, -(inset * 2), 1, -(inset * 2))
    end

    return shell, inner
end

local function _formatPrice(n)
    n = math.floor(tonumber(n) or 0)
    if n <= 0 then return "" end
    if n >= 1000000000 then return string.format("%.2fB", n / 1000000000) end
    if n >= 1000000 then return string.format("%.2fM", n / 1000000) end
    if n >= 1000 then return string.format("%.1fK", n / 1000) end
    return tostring(n)
end

local function _harvestTotalFromSummary(summary)
    local total = 0
    if type(summary) ~= "table" then return 0 end
    for _, row in ipairs(summary) do
        if row.cat == "HarvestedFruits" then
            total += math.max(0, math.floor(tonumber(row.price) or 0))
        end
    end
    return total
end

local function _resolveHarvestTotal(storedTotal, summary)
    local fromSummary = _harvestTotalFromSummary(summary)
    if fromSummary > 0 then
        return fromSummary
    end
    return math.max(0, math.floor(tonumber(storedTotal) or 0))
end

local function _catLabel(cat)
    cat = tostring(cat or "")
    if CAT_LABELS[cat] then return CAT_LABELS[cat] end
    return cat:gsub("(%l)(%u)", "%1 %2")
end

local function _catSortKey(cat)
    return CAT_ORDER[tostring(cat or "")] or 100
end

local function _isUuidLike(s)
    s = tostring(s or "")
    if #s < 12 then return false end
    return s:match("^[%x%-]+$") ~= nil
end

local function _fallbackTypeName(cat)
    cat = tostring(cat or "")
    if cat == "Pets" then return "Pet" end
    if cat == "HarvestedFruits" then return "Fruit" end
    if cat == "Seeds" then return "Seed" end
    return _catLabel(cat)
end

local function _displayItemName(name, cat)
    name = tostring(name or ""):gsub("^%s+", ""):gsub("%s+$", "")
    if name == "" or name == "?" then return nil end
    if _isUuidLike(name) then return nil end
    local catL = _catLabel(tostring(cat or ""))
    if name == catL or name == cat or name:lower() == catL:lower() then
        return nil
    end
    return name
end

local function _sanitizeDisplayName(name, cat)
    name = tostring(name or ""):gsub("^%s+", ""):gsub("%s+$", "")
    if name == "" or name == "?" or _isUuidLike(name) then
        return _fallbackTypeName(cat)
    end
    local dn = _displayItemName(name, cat)
    if dn then return dn end
    return _fallbackTypeName(cat)
end

local function _normalizeSummaryRow(row)
    if type(row) ~= "table" then return nil end
    local cat = tostring(row.cat or row.Category or "")
    local count = math.max(1, math.floor(tonumber(row.count or row.Count) or 1))
    local price = math.max(0, math.floor(tonumber(row.price or row.Price) or 0))
    if price <= 0 then
        local unit = math.max(0, math.floor(tonumber(row.UnitPrice or row.unitPrice) or 0))
        if unit > 0 then
            price = unit * count
        end
    end
    return {
        cat = cat,
        name = _sanitizeDisplayName(row.name or row.Name, cat),
        count = count,
        price = price,
    }
end

local function _getEntrySummary(e)
    if type(e.summary) == "table" and #e.summary > 0 then
        local out = {}
        for _, row in ipairs(e.summary) do
            local r = _normalizeSummaryRow(row)
            if r then out[#out + 1] = r end
        end
        return out
    end
    if type(e.summary) == "table" then
        local out = {}
        for _, row in pairs(e.summary) do
            if type(row) == "table" then
                local r = _normalizeSummaryRow(row)
                if r then out[#out + 1] = r end
            end
        end
        if #out > 0 then return out end
    end
    local items = type(e.items) == "table" and e.items or {}
    if #items == 0 then return {} end
    local groups, order = {}, {}
    for _, row in ipairs(items) do
        if type(row) == "table" then
            local cat = tostring(row.Category or "")
            local rawName = tostring(row.Name or row.ItemKey or row.ItemName or "?")
            local name = _sanitizeDisplayName(rawName, cat)
            local gkey = cat .. "\0" .. name
            if not groups[gkey] then
                groups[gkey] = { cat = cat, name = name, count = 0, price = 0 }
                order[#order + 1] = gkey
            end
            local g = groups[gkey]
            local cnt = math.max(1, math.floor(tonumber(row.Count) or 1))
            g.count += cnt
            local linePrice = math.floor(tonumber(row.Price or row.price) or 0)
            if linePrice <= 0 then
                local unit = math.floor(tonumber(row.UnitPrice or row.unitPrice) or 0)
                if unit > 0 then
                    linePrice = unit * cnt
                end
            end
            if linePrice > 0 then
                g.price += linePrice
            end
        end
    end
    local out = {}
    for _, gkey in ipairs(order) do
        out[#out + 1] = groups[gkey]
    end
    return out
end

local function _summarizeSummary(summary)
    if type(summary) ~= "table" or #summary == 0 then return "—" end
    local parts = {}
    for _, row in ipairs(summary) do
        local s = string.format("%s x%d", _sanitizeDisplayName(row.name, row.cat), row.count)
        if row.price and row.price > 0 then
            s = s .. " " .. _formatPrice(row.price)
        end
        parts[#parts + 1] = s
    end
    local text = table.concat(parts, ", ")
    if #text > 120 then text = text:sub(1, 117) .. "..." end
    return text
end

local function _summarizeItems(items)
    if type(items) ~= "table" or #items == 0 then return "—" end
    return _summarizeSummary(_getEntrySummary({ items = items }))
end

local function _entrySearchText(e)
    local summary = _getEntrySummary(e)
    local chunks = {
        tostring(e.recipient_username or ""),
        tostring(e.recipient_display or ""),
        tostring(e.recipient_user_id or ""),
        tostring(e.profile or ""),
        tostring(e.note or ""),
        tostring(e.message or ""),
        tostring(e.day or ""),
        _summarizeSummary(summary),
    }
    for _, row in ipairs(summary) do
        chunks[#chunks + 1] = row.cat
        chunks[#chunks + 1] = row.name
    end
    return table.concat(chunks, " "):lower()
end

local function _matchesSearch(e)
    local q = tostring(searchQuery or ""):lower():gsub("^%s+", ""):gsub("%s+$", "")
    if q == "" then return true end
    local ok, hit = pcall(function()
        return _entrySearchText(e):find(q, 1, true) ~= nil
    end)
    return ok and hit == true
end

local function _colorHex(c)
    return string.format("#%02X%02X%02X",
        math.floor((c.R or 0) * 255 + 0.5),
        math.floor((c.G or 0) * 255 + 0.5),
        math.floor((c.B or 0) * 255 + 0.5))
end

local function _richEscape(s)
    s = tostring(s or "")
    s = s:gsub("&", "&amp;"):gsub("<", "&lt;"):gsub(">", "&gt;")
    return s
end

local function _catIcon(cat)
    return CAT_ICONS[tostring(cat or "")] or "📦"
end

local function _makeLabel(parent, props)
    local lbl = Instance.new("TextLabel")
    lbl.BackgroundTransparency = 1
    lbl.Font = props.font or Enum.Font.Gotham
    lbl.TextSize = props.size or 12
    lbl.TextColor3 = props.color or COLOR_WHITE
    lbl.TextXAlignment = props.x or Enum.TextXAlignment.Left
    lbl.TextYAlignment = props.y or Enum.TextYAlignment.Top
    lbl.TextWrapped = props.wrap == true
    lbl.Text = props.text or ""
    lbl.Size = props.Size or UDim2.new(1, 0, 0, 16)
    lbl.Position = props.Position or UDim2.new()
    if props.rich == true then
        pcall(function() lbl.RichText = true end)
    end
    if props.truncate then
        lbl.TextTruncate = props.truncate
    end
    lbl.Parent = parent
    return lbl
end

local function _catSectionSubtitle(rows, harvestTotal, catKey)
    local names, total = {}, 0
    for _, item in ipairs(rows) do
        total += math.floor(tonumber(item.count) or 1)
        local n = _sanitizeDisplayName(item.name, catKey)
        if n and #names < 3 then
            names[#names + 1] = string.format("%s x%d", n, item.count)
        end
    end
    if #names > 0 then
        local s = table.concat(names, ", ")
        if #names < #rows then s = s .. "..." end
        if harvestTotal and harvestTotal > 0 then
            s = s .. "  ·  " .. _formatPrice(harvestTotal)
        end
        return s
    end
    if harvestTotal and harvestTotal > 0 then
        return string.format("%d item  ·  %s", total, _formatPrice(harvestTotal))
    end
    return string.format("%d item", total)
end

local function _compactEntryPreview(summary, harvestTotal)
    if type(summary) ~= "table" or #summary == 0 then return "—" end
    local byCat, order = {}, {}
    for _, row in ipairs(summary) do
        local cat = row.cat
        if not byCat[cat] then
            byCat[cat] = { count = 0, price = 0, names = {} }
            order[#order + 1] = cat
        end
        local g = byCat[cat]
        g.count += row.count
        g.price += row.price or 0
        local n = _sanitizeDisplayName(row.name, cat)
        if n then
            g.names[n] = (g.names[n] or 0) + row.count
        end
    end
    table.sort(order, function(a, b)
        local ka, kb = _catSortKey(a), _catSortKey(b)
        if ka ~= kb then return ka < kb end
        return tostring(a) < tostring(b)
    end)

    local parts = {}
    for _, cat in ipairs(order) do
        local g = byCat[cat]
        local nameCount = 0
        for _ in pairs(g.names) do nameCount += 1 end
        if nameCount == 1 then
            for n, c in pairs(g.names) do
                parts[#parts + 1] = string.format("%s x%d", n, c)
            end
        elseif cat == "HarvestedFruits" then
            local extra = g.price > 0 and (" · " .. _formatPrice(g.price)) or ""
            parts[#parts + 1] = string.format("%d fruit%s%s", g.count, g.count > 1 and "s" or "", extra)
        else
            parts[#parts + 1] = string.format("%s x%d", _fallbackTypeName(cat), g.count)
        end
    end
    if harvestTotal and harvestTotal > 0 and not byCat.HarvestedFruits then
        parts[#parts + 1] = _formatPrice(harvestTotal)
    end
    return table.concat(parts, " · ")
end

local function _chipWidth(text)
    text = tostring(text or "")
    return math.max(34, #text * 7 + 14)
end

local function _makeChip(parent, text, bg, fg, w)
    text = tostring(text or "")
    local h = 16
    local chip = Instance.new("Frame")
    chip.BackgroundColor3 = bg
    chip.BorderSizePixel = 0
    chip.Size = UDim2.new(0, w or _chipWidth(text), 0, h)
    chip.Parent = parent
    _round(chip, 100)
    _makeLabel(chip, {
        text = text,
        size = 8,
        color = fg,
        font = Enum.Font.GothamBold,
        x = Enum.TextXAlignment.Center,
        y = Enum.TextYAlignment.Center,
        Size = UDim2.new(1, 0, 1, 0),
    })
    return chip
end

local function _profileChipStyle(profile)
    profile = tostring(profile or "once"):upper()
    if profile == "LOOP" then
        return Color3.fromRGB(42, 36, 0), COLOR_YELLOW
    end
    if profile == "NORMAL" then
        return Color3.fromRGB(0, 36, 48), Color3.fromRGB(120, 210, 255)
    end
    return Color3.fromRGB(28, 28, 28), COLOR_GRAY
end

local function _buildItemRow(parent, name, count, linePrice, theme, catKey)
    theme = theme or _catTheme()
    catKey = tostring(catKey or "")
    local row = Instance.new("Frame")
    row.BackgroundTransparency = 1
    row.BorderSizePixel = 0
    row.Size = UDim2.new(1, 0, 0, 16)
    row.Parent = parent

    _makeLabel(row, {
        text = _catIcon(catKey) .. " " .. name,
        size = 10,
        color = COLOR_WHITE,
        font = Enum.Font.GothamMedium,
        y = Enum.TextYAlignment.Center,
        x = Enum.TextXAlignment.Left,
        Size = UDim2.new(0.56, 0, 1, 0),
    })
    _makeLabel(row, {
        text = "×" .. tostring(count),
        size = 9,
        color = COLOR_GRAY,
        font = Enum.Font.GothamBold,
        y = Enum.TextYAlignment.Center,
        x = Enum.TextXAlignment.Center,
        Size = UDim2.new(0.14, 0, 1, 0),
        Position = UDim2.new(0.56, 0, 0, 0),
    })
    local priceText = (linePrice and linePrice > 0) and _formatPrice(linePrice) or ""
    if priceText ~= "" then
        _makeLabel(row, {
            text = string.format(
                '<u><font color="%s"><b>%s</b></font></u>',
                _colorHex(theme.price or COLOR_YELLOW),
                priceText
            ),
            size = 9,
            color = theme.price or COLOR_YELLOW,
            font = Enum.Font.GothamBold,
            rich = true,
            y = Enum.TextYAlignment.Center,
            x = Enum.TextXAlignment.Right,
            Size = UDim2.new(0.3, 0, 1, 0),
            Position = UDim2.new(0.7, 0, 0, 0),
        })
    end
end

local function _buildCategoryBlock(parent, catKey, rows, harvestTotal)
    local theme = _catTheme(catKey)
    local icon = _catIcon(catKey)
    local label = _catLabel(catKey)

    _makeLabel(parent, {
        text = string.format(
            '%s <b><u><font color="%s">%s</font></u></b>',
            icon,
            _colorHex(COLOR_YELLOW),
            label
        ),
        font = Enum.Font.GothamMedium,
        size = 10,
        color = COLOR_YELLOW,
        rich = true,
        Size = UDim2.new(1, 0, 0, 14),
    })

    for _, item in ipairs(rows) do
        local price = math.floor(tonumber(item.price) or 0)
        local dn = _sanitizeDisplayName(item.name, catKey)
        _buildItemRow(parent, dn, math.floor(tonumber(item.count) or 1), price, theme, catKey)
    end

    if harvestTotal and harvestTotal > 0 then
        local foot = Instance.new("Frame")
        foot.BackgroundTransparency = 1
        foot.BorderSizePixel = 0
        foot.Size = UDim2.new(1, 0, 0, 16)
        foot.Parent = parent
        _makeLabel(foot, {
            text = "💰 Total harvest",
            size = 9,
            color = COLOR_DIM,
            font = Enum.Font.GothamMedium,
            y = Enum.TextYAlignment.Center,
            x = Enum.TextXAlignment.Left,
            Size = UDim2.new(0.6, 0, 1, 0),
        })
        _makeLabel(foot, {
            text = string.format(
                '<u><font color="%s"><b>%s</b></font></u>',
                _colorHex(COLOR_YELLOW),
                _formatPrice(harvestTotal)
            ),
            size = 10,
            color = COLOR_YELLOW,
            font = Enum.Font.GothamBold,
            rich = true,
            y = Enum.TextYAlignment.Center,
            x = Enum.TextXAlignment.Right,
            Size = UDim2.new(0.4, 0, 1, 0),
            Position = UDim2.new(0.6, 0, 0, 0),
        })
    end
end

local function _buildCard(parent, e, defaultExpanded)
    local ok = e.success == true
    local user = tostring(e.recipient_username or ""):gsub("^%s+", ""):gsub("%s+$", ""):gsub("^@", "")
    local disp = tostring(e.recipient_display or ""):gsub("^%s+", ""):gsub("%s+$", "")
    local who = disp
    if who == "" then who = user end
    if who == "" then
        local uid = math.floor(tonumber(e.recipient_user_id) or 0)
        who = uid > 0 and ("UserId " .. tostring(uid)) or "(no target)"
    elseif user ~= "" and user:lower() ~= who:lower() then
        who = who .. " @" .. user
    end

    local ts = math.floor(tonumber(e.ts) or os.time())
    local itemN = math.floor(tonumber(e.item_count) or 0)
    local sendN = math.floor(tonumber(e.send_batch) or 0)
    local profile = tostring(e.profile or "once"):upper()
    local summary = _getEntrySummary(e)
    local harvestTotal = _resolveHarvestTotal(e.harvest_total_price, summary)
    local preview = _compactEntryPreview(summary, harvestTotal)
    if #preview > 80 then preview = preview:sub(1, 77) .. "..." end

    local cardOpen = defaultExpanded == true
    local statusColor = ok and COLOR_OK or COLOR_FAIL
    local yHex = _colorHex(COLOR_YELLOW)
    local gHex = _colorHex(COLOR_GRAY)

    local card, cardInner = _insetBorder(parent, {
        name = "Entry_" .. tostring(e.id or "x"),
        radius = RADIUS_CARD,
        border = COLOR_YELLOW,
        fill = COLOR_CARD,
        autoY = true,
        inset = 1,
        clip = true,
    })

    local cardLayout = Instance.new("UIListLayout")
    cardLayout.SortOrder = Enum.SortOrder.LayoutOrder
    cardLayout.Padding = UDim.new(0, 0)
    cardLayout.Parent = cardInner

    local head = Instance.new("TextButton")
    head.Name = "CardHead"
    head.AutoButtonColor = false
    head.BackgroundColor3 = COLOR_CARD_HEAD
    head.BorderSizePixel = 0
    head.ClipsDescendants = true
    head.Size = UDim2.new(1, 0, 0, 0)
    head.AutomaticSize = Enum.AutomaticSize.Y
    head.Text = ""
    head.Parent = cardInner
    _round(head, math.max(RADIUS_CARD - 1, 4))

    local function syncCardShell()
        local h = cardInner.AbsoluteSize.Y
        card.Size = UDim2.new(1, 0, 0, math.max(h + 2, 2))
    end

    local headPad = Instance.new("UIPadding")
    headPad.PaddingLeft = UDim.new(0, 6)
    headPad.PaddingRight = UDim.new(0, 6)
    headPad.PaddingTop = UDim.new(0, 5)
    headPad.PaddingBottom = UDim.new(0, 5)
    headPad.Parent = head

    local headLayout = Instance.new("UIListLayout")
    headLayout.SortOrder = Enum.SortOrder.LayoutOrder
    headLayout.Padding = UDim.new(0, 2)
    headLayout.Parent = head

    local topRow = Instance.new("Frame")
    topRow.BackgroundTransparency = 1
    topRow.Size = UDim2.new(1, 0, 0, 18)
    topRow.Parent = head

    local topLayout = Instance.new("UIListLayout")
    topLayout.FillDirection = Enum.FillDirection.Horizontal
    topLayout.SortOrder = Enum.SortOrder.LayoutOrder
    topLayout.VerticalAlignment = Enum.VerticalAlignment.Center
    topLayout.Padding = UDim.new(0, 4)
    topLayout.Parent = topRow

    local statusLbl = _makeLabel(topRow, {
        text = ok and "✓" or "✗",
        font = Enum.Font.GothamBold,
        size = 12,
        color = statusColor,
        x = Enum.TextXAlignment.Center,
        y = Enum.TextYAlignment.Center,
        Size = UDim2.new(0, 14, 0, 16),
    })
    statusLbl.LayoutOrder = 1

    local nameLbl = _makeLabel(topRow, {
        text = string.format(
            '<b><font color="%s">👤 %s</font></b>',
            _colorHex(ok and COLOR_WHITE or COLOR_DIM),
            _richEscape(who)
        ),
        font = Enum.Font.GothamBold,
        size = 11,
        color = ok and COLOR_WHITE or COLOR_DIM,
        rich = true,
        Size = UDim2.new(1, -82, 0, 16),
    })
    nameLbl.LayoutOrder = 2
    nameLbl.TextTruncate = Enum.TextTruncate.AtEnd

    local chipBg, chipFg = _profileChipStyle(profile)
    local badge = _makeChip(topRow, profile, chipBg, chipFg)
    badge.LayoutOrder = 3

    local arrow = _makeLabel(topRow, {
        text = cardOpen and "▼" or "▶",
        size = 9,
        color = COLOR_YELLOW,
        font = Enum.Font.GothamBold,
        x = Enum.TextXAlignment.Center,
        y = Enum.TextYAlignment.Center,
        Size = UDim2.new(0, 12, 0, 14),
    })
    arrow.LayoutOrder = 4

    local meta = string.format(
        '<font color="%s">🕒 %s</font> · <b>📦 %d item</b> · <font color="%s"><u>#%d</u></font>',
        gHex,
        os.date("%d/%m/%Y %H:%M", ts),
        itemN,
        yHex,
        sendN > 0 and sendN or 1
    )
    _makeLabel(head, {
        text = meta,
        color = COLOR_DIM,
        size = 9,
        rich = true,
        Size = UDim2.new(1, 0, 0, 13),
    })

    local previewLbl
    if preview ~= "—" then
        previewLbl = _makeLabel(head, {
            text = string.format('<font color="%s"><i>📋 %s</i></font>', gHex, _richEscape(preview)),
            color = COLOR_GRAY,
            size = 9,
            rich = true,
            wrap = true,
            Size = UDim2.new(1, 0, 0, 0),
        })
        previewLbl.AutomaticSize = Enum.AutomaticSize.Y
        previewLbl.Visible = not cardOpen
    end

    local body = Instance.new("Frame")
    body.Name = "CardBody"
    body.BackgroundTransparency = 1
    body.BorderSizePixel = 0
    body.Size = UDim2.new(1, 0, 0, 0)
    body.AutomaticSize = Enum.AutomaticSize.Y
    body.Visible = cardOpen
    body.Parent = cardInner

    local bodyPad = Instance.new("UIPadding")
    bodyPad.PaddingTop = UDim.new(0, 2)
    bodyPad.PaddingBottom = UDim.new(0, 6)
    bodyPad.PaddingLeft = UDim.new(0, 6)
    bodyPad.PaddingRight = UDim.new(0, 6)
    bodyPad.Parent = body

    local bodyLayout = Instance.new("UIListLayout")
    bodyLayout.SortOrder = Enum.SortOrder.LayoutOrder
    bodyLayout.Padding = UDim.new(0, 2)
    bodyLayout.Parent = body

    if #summary == 0 then
        _makeLabel(body, {
            text = "—",
            color = COLOR_GRAY,
            size = 11,
            Size = UDim2.new(1, 0, 0, 14),
        })
    else
        local byCat, catOrder = {}, {}
        for _, row in ipairs(summary) do
            local cat = row.cat
            if not byCat[cat] then
                byCat[cat] = {}
                catOrder[#catOrder + 1] = cat
            end
            byCat[cat][#byCat[cat] + 1] = row
        end
        table.sort(catOrder, function(a, b)
            local ka, kb = _catSortKey(a), _catSortKey(b)
            if ka ~= kb then return ka < kb end
            return tostring(a) < tostring(b)
        end)

        for _, cat in ipairs(catOrder) do
            local sectionTotal = nil
            if cat == "HarvestedFruits" and harvestTotal > 0 then
                sectionTotal = harvestTotal
            end
            _buildCategoryBlock(body, cat, byCat[cat], sectionTotal)
        end
    end

    local msg = tostring(e.message or "")
    if msg ~= "" then
        _makeLabel(body, {
            text = string.format('<font color="%s"><i>💬 %s</i></font>', gHex, _richEscape(msg)),
            color = COLOR_DIM,
            size = 9,
            rich = true,
            wrap = true,
            Size = UDim2.new(1, 0, 0, 0),
        }).AutomaticSize = Enum.AutomaticSize.Y
    end

    if not cardOpen then
        body.AutomaticSize = Enum.AutomaticSize.None
        body.Size = UDim2.new(1, 0, 0, 0)
    end

    head.MouseButton1Click:Connect(function()
        cardOpen = not cardOpen
        if cardOpen then
            body.AutomaticSize = Enum.AutomaticSize.Y
            body.Size = UDim2.new(1, 0, 0, 0)
            body.Visible = true
        else
            body.Visible = false
            body.AutomaticSize = Enum.AutomaticSize.None
            body.Size = UDim2.new(1, 0, 0, 0)
        end
        arrow.Text = cardOpen and "▼" or "▶"
        if previewLbl then previewLbl.Visible = not cardOpen end
        syncCardShell()
        task.defer(syncCardShell)
    end)
end

local function _entryCount()
    local n = #entries
    if n > 0 then return n end
    local c = 0
    for k, e in pairs(entries) do
        if type(k) == "number" and type(e) == "table" then
            c = c + 1
        end
    end
    return c
end

local function _ensureListScrollRef()
    if listScroll and listScroll.Parent then return listScroll end
    local root = panelRoot
    if not root or not root.Parent then
        if type(_findPanelInstance) == "function" then
            root = select(1, _findPanelInstance())
        end
    end
    if not root then return nil end
    local content = root:FindFirstChild("Content")
    listScroll = _findScrollFrame(content)
    return listScroll
end

local function _buildFilteredIndices()
    local order = _entryIndicesNewestFirst()
    local out = {}
    for _, i in ipairs(order) do
        local e = entries[i]
        if type(e) == "table" and _matchesSearch(e) then
            out[#out + 1] = i
        end
    end
    return out
end

local function _updateCountLabel()
    local total = _entryCount()
    local todayN = _todayBatchCount()
    local limitCol = _limitCountColor(todayN)

    if limitLabel and limitLabel.Parent then
        limitLabel.RichText = true
        limitLabel.Text = string.format(
            '<font color="%s">Limit </font><b><font color="%s">%d</font></b><font color="%s"> / %d</font>',
            _colorHex(COLOR_DIM),
            _colorHex(limitCol),
            todayN,
            _colorHex(COLOR_DIM),
            DAILY_GIFT_BATCH_LIMIT
        )
    end

    if not countLabel then return end
    local q = tostring(searchQuery or ""):gsub("^%s+", ""):gsub("%s+$", "")
    countLabel.RichText = true
    if q ~= "" then
        countLabel.Text = string.format(
            '<font color="%s">📋</font> <b><font color="%s">%d</font></b><font color="%s"> / %d matches</font> <font color="%s">(%d total)</font>',
            _colorHex(COLOR_DIM),
            _colorHex(COLOR_YELLOW),
            renderedCount,
            _colorHex(COLOR_DIM),
            filteredMatchCount,
            _colorHex(COLOR_DIM),
            total
        )
    else
        countLabel.Text = string.format(
            '<font color="%s">📋</font> <b><font color="%s">%d</font></b><font color="%s"> / %d entries</font>',
            _colorHex(COLOR_DIM),
            _colorHex(COLOR_YELLOW),
            renderedCount,
            _colorHex(COLOR_DIM),
            filteredMatchCount
        )
    end
end

local function _appendHistoryCards(maxCount)
    if not listFrame or not listFrame.Parent then return 0 end
    maxCount = math.max(1, math.floor(tonumber(maxCount) or RENDER_PAGE_SIZE))
    local remain = filteredMatchCount - renderedCount
    if remain <= 0 then return 0 end

    local added = 0
    local batch = math.min(maxCount, remain)
    for j = 1, batch do
        local filterIdx = renderedCount + j
        local entryIdx = filteredIndices[filterIdx]
        local e = entries[entryIdx]
        if type(e) == "table" then
            local expand = (renderedCount == 0 and j == 1)
            local ok = pcall(_buildCard, listFrame, e, expand)
            if ok then
                added += 1
            end
        end
    end
    renderedCount += added
    _updateCountLabel()
    return added
end

local function _ensureHistoryFillViewport()
    if not listScroll or not listScroll.Parent then return end
    if renderedCount >= filteredMatchCount then return end
    local canvas = listScroll.AbsoluteCanvasSize.Y
    local view = listScroll.AbsoluteWindowSize.Y
    if view <= 0 then return end
    if canvas <= view + SCROLL_LOAD_THRESHOLD then
        if _appendHistoryCards(RENDER_PAGE_SIZE) > 0 then
            task.defer(_ensureHistoryFillViewport)
        end
    end
end

local function _tryLoadMoreHistoryCards()
    if scrollLoading then return end
    if renderedCount >= filteredMatchCount then return end
    if not listScroll or not listScroll.Parent then return end

    local pos = listScroll.CanvasPosition.Y
    local view = listScroll.AbsoluteWindowSize.Y
    local canvas = listScroll.AbsoluteCanvasSize.Y
    if view <= 0 or canvas <= 0 then return end
    if pos + view < canvas - SCROLL_LOAD_THRESHOLD then return end

    scrollLoading = true
    task.defer(function()
        _appendHistoryCards(RENDER_PAGE_SIZE)
        scrollLoading = false
        _ensureHistoryFillViewport()
    end)
end

local function _bindScrollLoadMore()
    if scrollConn then
        scrollConn:Disconnect()
        scrollConn = nil
    end
    if not listScroll or not listScroll.Parent then return end
    scrollConn = listScroll:GetPropertyChangedSignal("CanvasPosition"):Connect(function()
        _tryLoadMoreHistoryCards()
    end)
end

local function _refreshList()
    if not listFrame or not listFrame.Parent then
        if type(_rebindUiRefs) == "function" then
            pcall(_rebindUiRefs)
        end
    end
    if not listFrame or not listFrame.Parent then
        if type(_buildUi) == "function" then
            pcall(_buildUi)
        end
        if type(_rebindUiRefs) == "function" then
            pcall(_rebindUiRefs)
        end
    end
    if not listFrame or not listFrame.Parent then return end

    _ensureListScrollRef()
    _bindScrollLoadMore()
    filteredIndices = _buildFilteredIndices()
    filteredMatchCount = #filteredIndices
    renderedCount = 0
    scrollLoading = false
    _clearListCards()

    if listScroll then
        listScroll.CanvasPosition = Vector2.new(0, 0)
    end

    if filteredMatchCount == 0 then
        _updateCountLabel()
        _makeLabel(listFrame, {
            text = (_entryCount() == 0)
                and string.format('<font color="%s"><i>📭 Belum ada gift mail tercatat.</i></font>', _colorHex(COLOR_GRAY))
                or string.format('<font color="%s"><i>🔍 Tidak ada hasil search.</i></font>', _colorHex(COLOR_GRAY)),
            color = COLOR_GRAY,
            rich = true,
            x = Enum.TextXAlignment.Center,
            Size = UDim2.new(1, 0, 0, 40),
        })
        return
    end

    _appendHistoryCards(RENDER_PAGE_SIZE)
    task.defer(_ensureHistoryFillViewport)
end

local PANEL_W = 250
local PANEL_H = 420
local PANEL_PAD = 12
local CONTENT_PAD_L = 4
local SCROLL_W_OFF = 6
local CONTENT_W_OFF = CONTENT_PAD_L + SCROLL_W_OFF
local LIST_PAD_L = 0
local LIST_PAD_R = 2
local LIST_TOP_PAD = 0
local SEARCH_TOP = 40
local SEARCH_H = 26
local SEARCH_LIST_GAP = 2
local LIST_VIEWPORT_TOP = SEARCH_TOP + SEARCH_H + SEARCH_LIST_GAP
local LIST_VIEWPORT_BOTTOM = 10

local function _savePanelPos(frame)
    if not frame then return end
    local ap = frame.AnchorPoint
    local pos = frame.Position
    local saved = {
        ax = ap.X, ay = ap.Y,
        xs = pos.X.Scale, xo = pos.X.Offset,
        ys = pos.Y.Scale, yo = pos.Y.Offset,
    }
    G.__GAG2_GIFT_HISTORY_PANEL_POS = saved
    _G.__GAG2_GIFT_HISTORY_PANEL_POS = saved
end

local function _loadPanelPos(frame)
    if not frame then return end
    local saved = G.__GAG2_GIFT_HISTORY_PANEL_POS or _G.__GAG2_GIFT_HISTORY_PANEL_POS
    if type(saved) ~= "table" then return end
    frame.AnchorPoint = Vector2.new(tonumber(saved.ax) or 0.5, tonumber(saved.ay) or 0.5)
    frame.Position = UDim2.new(
        tonumber(saved.xs) or 0.5, tonumber(saved.xo) or 0,
        tonumber(saved.ys) or 0.5, tonumber(saved.yo) or 0
    )
end

local function _makePanelDraggable(frame, dragHandle)
    if not frame or not dragHandle then return end
    if frame:GetAttribute("DragReady") == true then return end
    frame:SetAttribute("DragReady", true)
    dragHandle.Active = true

    local dragging = false
    local dragStart
    local startPos

    dragHandle.InputBegan:Connect(function(input)
        if input.UserInputType == Enum.UserInputType.MouseButton1
            or input.UserInputType == Enum.UserInputType.Touch then
            dragging = true
            dragStart = input.Position
            startPos = frame.Position
        end
    end)

    local function stopDrag(input)
        if input.UserInputType ~= Enum.UserInputType.MouseButton1
            and input.UserInputType ~= Enum.UserInputType.Touch then
            return
        end
        if dragging then
            _savePanelPos(frame)
        end
        dragging = false
        dragStart = nil
        startPos = nil
    end

    dragHandle.InputEnded:Connect(stopDrag)
    UserInputService.InputEnded:Connect(stopDrag)

    UserInputService.InputChanged:Connect(function(input)
        if not dragging or not dragStart or not startPos then return end
        if input.UserInputType ~= Enum.UserInputType.MouseMovement
            and input.UserInputType ~= Enum.UserInputType.Touch then
            return
        end
        local delta = input.Position - dragStart
        frame.Position = UDim2.new(
            startPos.X.Scale, startPos.X.Offset + delta.X,
            startPos.Y.Scale, startPos.Y.Offset + delta.Y
        )
    end)
end

local function _ensurePanelDrag(root)
    if not root or root:GetAttribute("DragReady") == true then return end
    local content = root:FindFirstChild("Content")
    local header = content and content:FindFirstChild("Header")
    if header then
        _makePanelDraggable(root, header)
    end
end

local function _playerGui()
    if not LP then return nil end
    return LP:FindFirstChild("PlayerGui") or LP:WaitForChild("PlayerGui", 10)
end

local function _destroyExistingPanels()
    local pg = _playerGui()
    if not pg then return end
    local sg = pg:FindFirstChild("GAG2_GiftMailHistory")
    if sg then
        pcall(function() sg:Destroy() end)
    end
    panelRoot = nil
    gui = nil
    uiBuilt = false
    listFrame = nil
    countLabel = nil
    searchBox = nil
    G.__GAG2_GIFT_HISTORY_PANEL = nil
    G.__GAG2_GIFT_HISTORY_GUI = nil
    _G.__GAG2_GIFT_HISTORY_PANEL = nil
    _G.__GAG2_GIFT_HISTORY_GUI = nil
end

local function _bindGlobals()
    G.__GAG2_GIFT_HISTORY_GUI = gui
    G.__GAG2_GIFT_HISTORY_PANEL = panelRoot
    _G.__GAG2_GIFT_HISTORY_GUI = gui
    _G.__GAG2_GIFT_HISTORY_PANEL = panelRoot
end

_findPanelInstance = function()
    if panelRoot and panelRoot.Parent then
        return panelRoot, gui
    end
    local cached = G.__GAG2_GIFT_HISTORY_PANEL or rawget(_G, "__GAG2_GIFT_HISTORY_PANEL")
    local cachedGui = G.__GAG2_GIFT_HISTORY_GUI or rawget(_G, "__GAG2_GIFT_HISTORY_GUI")
    if typeof(cached) == "Instance" and cached.Parent then
        panelRoot = cached
        if typeof(cachedGui) == "Instance" then
            gui = cachedGui
        end
        if type(_rebindUiRefs) == "function" then
            _rebindUiRefs()
        end
        return panelRoot, gui
    end
    local pg = _playerGui()
    if not pg then return nil, nil end
    local sg = pg:FindFirstChild("GAG2_GiftMailHistory")
    if sg then
        gui = sg
        local panel = sg:FindFirstChild("GiftMailHistoryPanel", true)
        if panel then
            panelRoot = panel
            _bindGlobals()
            if type(_rebindUiRefs) == "function" then
                _rebindUiRefs()
            end
            return panelRoot, gui
        end
    end
    return nil, nil
end

_rebindUiRefs = function()
    local root = panelRoot
    if (not root or not root.Parent) then
        if type(_findPanelInstance) == "function" then
            _findPanelInstance()
        end
        root = panelRoot
    end
    if not root then return false end

    local content = root:FindFirstChild("Content")
    local scroll = _findScrollFrame(content) or root:FindFirstChild("Scroll")
    listScroll = scroll
    listFrame = scroll and scroll:FindFirstChild("List") or nil

    local header = (content and content:FindFirstChild("Header")) or root:FindFirstChild("Header")
    if header then
        countLabel = header:FindFirstChild("CountLabel")
        limitLabel = header:FindFirstChild("LimitLabel")
    end

    local searchWrap = (content and content:FindFirstChild("SearchWrap")) or root:FindFirstChild("SearchWrap")
    if searchWrap then
        local searchBg = searchWrap:FindFirstChild("SearchBg")
        local searchInner = searchBg and searchBg:FindFirstChild("SearchInner") or nil
        searchBox = searchInner and searchInner:FindFirstChild("Search") or nil
    end

    _bindScrollLoadMore()
    return listFrame ~= nil
end

_setPanelVisible = function(on)
    panelVisible = on == true
    local panel, sg = nil, nil
    if type(_findPanelInstance) == "function" then
        panel, sg = _findPanelInstance()
    end
    if panel then
        panel.Visible = panelVisible
    end
    if sg then
        sg.Enabled = panelVisible
    end
    if panelVisible then
        if _entryCount() == 0 then
            _loadFile()
        end
        _refreshList()
    end
end

