    local existing, existingGui = _findPanelInstance()
    if existing and existing.Parent and _panelUiReady(existing) then
        panelRoot = existing
        gui = existingGui
        uiBuilt = true
        hubMode = false
        if type(_rebindUiRefs) == "function" then
            pcall(_rebindUiRefs)
        end
        _ensurePanelDrag(panelRoot)
        if type(_setPanelVisible) == "function" then
            pcall(_setPanelVisible, panelVisible)
