function M.SetPanelVisible(onOrSelf, maybeOn)
    local on = onOrSelf
    if type(onOrSelf) == "table" then
        on = maybeOn
    end
    panelVisible = on == true
    local okFind = false
    if type(_findPanelInstance) == "function" then
        okFind = _findPanelInstance() ~= nil
    end
    if not okFind and type(_buildUi) == "function" then
        pcall(_buildUi)
    end
    if type(_setPanelVisible) == "function" then
        pcall(_setPanelVisible, panelVisible)
    end
    if panelVisible and type(_findPanelInstance) == "function" and not _findPanelInstance() then
        task.spawn(function()
            for _ = 1, 60 do
                task.wait(0.1)
                if type(_findPanelInstance) == "function" and _findPanelInstance() then break end
                if type(_buildUi) == "function" then
                    pcall(_buildUi)
                end
            end
            if type(_setPanelVisible) == "function" then
                pcall(_setPanelVisible, panelVisible)
            end
        end)
    end
end

function M.ForcePanelVisible(on)
    M.SetPanelVisible(on == true)
end

function M.Refresh()
    _loadFile()
    if not _panelUiReady(panelRoot) then
        if type(_buildUi) == "function" then
            pcall(_buildUi)
        end
    end
    if type(_rebindUiRefs) == "function" then
        pcall(_rebindUiRefs)
    end
    if panelVisible then
        _refreshList()
    end
end

function M.RecordSendBatch(batchSnap, opts)
    opts = type(opts) == "table" and opts or {}
    if opts.success ~= true then return false end
    if type(batchSnap) ~= "table" or #batchSnap == 0 then return false end

    local cfg = type(opts.cfg) == "table" and opts.cfg or {}
    local uid = math.floor(tonumber(cfg.recipient_user_id) or 0)
    local user = tostring(cfg.recipient_username or "")
    local disp = tostring(cfg.recipient_display or "")
    if uid <= 0 then
        local s = G.__GAG2_AUTO_GIFT or rawget(_G, "__GAG2_AUTO_GIFT")
        local p = (type(s) == "table" and type(s.once) == "table") and s.once or s
        if type(p) == "table" then
            uid = math.floor(tonumber(p.recipient_user_id) or 0)
            if user == "" then user = tostring(p.recipient_username or "") end
            if disp == "" then disp = tostring(p.recipient_display or "") end
        end
    end

    local groups, order = {}, {}
    local explicitHarvestTotal = math.floor(tonumber(opts.harvest_total_price) or 0)
    local harvestTotal = explicitHarvestTotal
    for _, row in ipairs(batchSnap) do
        local cat = tostring(row.Category or "")
        local name = _sanitizeDisplayName(row.Name or "?", cat)
        local gkey = cat .. "\0" .. name
        if not groups[gkey] then
            groups[gkey] = { cat = cat, name = name, count = 0, price = 0 }
            order[#order + 1] = gkey
        end
        local g = groups[gkey]
        local cnt = math.max(1, math.floor(tonumber(row.Count) or 1))
        g.count += cnt
        local linePrice = math.floor(tonumber(row.Price) or 0)
        if linePrice <= 0 then
            local unit = math.floor(tonumber(row.UnitPrice) or 0)
            if unit > 0 then
                linePrice = unit * cnt
            end
        end
        if linePrice > 0 then
            g.price += linePrice
            if explicitHarvestTotal <= 0 and cat == "HarvestedFruits" then
                harvestTotal += linePrice
            end
        end
    end
    local summary = {}
    for _, gkey in ipairs(order) do
        summary[#summary + 1] = groups[gkey]
    end

    return M.Record({
        ts = os.time(),
        profile = (tostring(opts.profile or "") ~= "" and tostring(opts.profile))
            or ((opts.auto_send == true or cfg.auto_send == true) and "loop" or "once"),
        success = opts.success == true,
        recipient_user_id = uid,
        recipient_username = user,
        recipient_display = disp,
        item_count = math.floor(tonumber(opts.total) or #batchSnap),
        send_batch = math.max(1, math.floor(tonumber(opts.sendBatchNum) or 1)),
        batch_rows = #batchSnap,
        note = tostring(cfg.note or ""),
        message = tostring(opts.msg or ""),
        summary = summary,
        harvest_total_price = harvestTotal,
    })
end

function M.Record(entry)
    if type(entry) ~= "table" then return false end

    local ts = math.floor(tonumber(entry.ts) or os.time())
    local summary = {}
    if type(entry.summary) == "table" then
        if #entry.summary > 0 then
            for _, row in ipairs(entry.summary) do
                local r = _normalizeSummaryRow(row)
                if r then summary[#summary + 1] = r end
            end
        else
            for _, row in pairs(entry.summary) do
                if type(row) == "table" then
                    local r = _normalizeSummaryRow(row)
                    if r then summary[#summary + 1] = r end
                end
            end
        end
    elseif type(entry.items) == "table" then
        summary = _getEntrySummary({ items = entry.items })
    end

    local harvestTotal = _resolveHarvestTotal(entry.harvest_total_price, summary)

    local row = {
        id = tostring(entry.id or (ts .. "_" .. tostring(math.random(1000, 9999)))),
        ts = ts,
        day = _dayKey(ts),
        profile = tostring(entry.profile or "once"),
        success = entry.success == true,
        recipient_user_id = math.floor(tonumber(entry.recipient_user_id) or 0),
        recipient_username = tostring(entry.recipient_username or ""),
        recipient_display = tostring(entry.recipient_display or ""),
        item_count = math.floor(tonumber(entry.item_count) or 0),
        send_batch = math.max(1, math.floor(tonumber(entry.send_batch) or 1)),
        batch_rows = math.floor(tonumber(entry.batch_rows) or #summary),
        note = tostring(entry.note or ""),
        message = tostring(entry.message or ""),
        summary = summary,
        harvest_total_price = harvestTotal,
    }

    entries[#entries + 1] = row
    entries = _prune(entries)
    _saveFile()

    _rebindUiRefs()
    if listFrame then
        _refreshList()
    elseif not uiBuilt and type(_buildUi) == "function" then
        pcall(_buildUi)
        if listFrame then
            _refreshList()
        end
    end

    return true
end

function M.Init(opts)
    opts = type(opts) == "table" and opts or {}
    if opts.retain_days ~= nil then
        retainDays = _clampRetainDays(opts.retain_days)
    end
    if opts.show_panel ~= nil then
        panelVisible = opts.show_panel == true
    end
    _loadFile()

    local function applyUi()
        _buildUi()
        _setPanelVisible(panelVisible)
    end

    applyUi()
    if panelVisible and (not panelRoot or not panelRoot.Parent) then
        task.spawn(function()
            for _ = 1, 60 do
                task.wait(0.1)
                if panelRoot and panelRoot.Parent then break end
                _buildUi()
            end
            _setPanelVisible(panelVisible)
        end)
    end
end

_loadFile()

G.GiftMailHistory = M
G.GiftMailHistoryModule = M
_G.GiftMailHistory = M
_G.GiftMailHistoryModule = M

return M
 end,               required = false },
