    local SF_STATE = getAuto("shovelFruit")
    SF_STATE.enabled = (SF_STATE.enabled == true)
    do
        local d = tonumber(SF_STATE.delay)
        if d == nil then d = 0.72 end
        if d < 0 then d = 0 end
        if d > 5 then d = 5 end
        SF_STATE.delay = d
    end
    SF_STATE.rules = type(SF_STATE.rules) == "table" and SF_STATE.rules or {}
    SF_STATE.rulesOrder = type(SF_STATE.rulesOrder) == "table" and SF_STATE.rulesOrder or {}
