        local mod = G.AutoShovelFruit or G.AutoShovelFruitModule or rawget(_G, "AutoShovelFruit")
        if type(mod) ~= "table" then return end
        local function __call(fn, ...)
            if type(mod[fn]) == "function" then pcall(mod[fn], ...) end
        end
        __call("SetDelay", G.AUTO_SHOVEL_FRUIT_DELAY)
