        end
    )
    G.__GAG2_SHOVEL_FRUIT_ENABLE_API = enableApi
    _G.__GAG2_SHOVEL_FRUIT_ENABLE_API = enableApi

    syncAutoShovelFruitModule()
end

G.SectionAutoShovelFruit = M
_G.SectionAutoShovelFruit = M

return M
