    local egg = M.GetEgg()
    if not egg or not egg.Parent then
        return false, "no_egg"
    end

    local prompt, main = _getPrompt(egg)
    if not prompt or not prompt.Enabled then
        return false, "no_prompt"
    end

    if not _tpToEgg(main, egg) then
        return false, "tp_fail"
    end

