    local ok, how = _triggerPrompt(prompt, egg)

    if _eggGone(egg) then
        _publishStatus("Hatched")
        return true, how or "hatched"
    end

    if ok then
        _publishStatus("Hatched")
        return true, how
    end

    _publishStatus(how == "no_executor_api" and "No executor API" or "Hatch failed")
    return false, how or "trigger_fail"
end

