local function _resolvePetTrait(tool, kind)
    if not tool then return nil end
    local SectionBuyPet = G.SectionAutoBuyPet or rawget(_G, "SectionAutoBuyPet")
    if kind == "type" then
        local raw = tool:GetAttribute("PetType") or tool:GetAttribute("Type")
