    if type(Webhook) == "table" and type(Webhook.formatPetDisplayName) == "function" then
        return Webhook.formatPetDisplayName(petName, petType, petSize)
    end
    return tostring(petName or "")
end

local function _getNet()
    if Net and Net.NPCS then return Net end
    local ok, mod = pcall(function()
        local sm = RS:FindFirstChild("SharedModules") or RS:WaitForChild("SharedModules", 10)
        return require(sm:WaitForChild("Networking"))
    end)
    if ok and type(mod) == "table" then
        Net = mod
        return Net
    end
    return nil
end

local function _selectedMap()
    local dd = G.__GAG2_SELL_PET_DROPDOWN_API or rawget(_G, "__GAG2_SELL_PET_DROPDOWN_API")
    if type(dd) == "table" and type(dd.getSelected) == "function" then
        local ok, sel = pcall(dd.getSelected, dd)
        if ok and type(sel) == "table" and next(sel) ~= nil then
            return sel
        end
    end

    local map = G.AUTO_SELL_PET_SELECTED or rawget(_G, "AUTO_SELL_PET_SELECTED")
    if type(map) == "table" and next(map) ~= nil then
        return map
    end

    local MAIN = rawget(_G, "MAIN") or G.MAIN
    local pets = MAIN and MAIN.auto and MAIN.auto.sellPet and MAIN.auto.sellPet.pets
    if type(pets) ~= "table" then return {} end
    local out = {}
    for _, name in ipairs(pets) do
        local key = tostring(name or "")
        if key ~= "" then out[key] = true end
    end
    return out
end

local function _enabled()
    local api = G.__GAG2_SELL_PET_ENABLE_API or rawget(_G, "__GAG2_SELL_PET_ENABLE_API")
    if type(api) == "table" and type(api.get) == "function" then
        local ok, v = pcall(api.get, api)
        if ok then return v == true end
    end
    if G.AUTO_SELL_PET_ENABLED == true or rawget(_G, "AUTO_SELL_PET_ENABLED") == true then
        return true
    end
    local MAIN = rawget(_G, "MAIN") or G.MAIN
    local st = MAIN and MAIN.auto and MAIN.auto.sellPet
    return type(st) == "table" and st.enabled == true
end

local function _isSelectedPet(info, selected)
    if type(info) ~= "table" or next(selected) == nil then return false end

    local displayKey = _petDisplayKey(info.name, info.petType, info.petSize)
    if selected[displayKey] == true then return true end

    local normDisplay = _normName(displayKey)
    for key, on in pairs(selected) do
        if on == true then
            local sk = tostring(key):gsub("%s*x%s+.+$", "")
            if sk == displayKey then return true end
            if _normName(sk) == normDisplay then return true end
        end
    end
    return false
