local function _petInfo(tool)
    if not tool or not tool:IsA("Tool") then return nil end

    local petAttr = tool:GetAttribute("Pet")
    local petName = petAttr
        or tool:GetAttribute("PetName")
        or tool:GetAttribute("PetType")

    if petAttr == nil and petName == nil then
        return nil
    end

    local petId = tool:GetAttribute("PetId")
        or tool:GetAttribute("PetID")
        or tool:GetAttribute("Id")
        or tool:GetAttribute("UUID")
        or tool:GetAttribute("InstanceId")

    if not petId then return nil end

    return {
        tool = tool,
        id = tostring(petId),
        name = tostring(petAttr or petName or tool.Name),
        petType = _resolvePetTrait(tool, "type"),
        petSize = _resolvePetTrait(tool, "size"),
    }
end

