    if not container then return end
    for _, inst in ipairs(container:GetChildren()) do
        if inst:IsA("Tool") then add(inst) end
    end
    for _, inst in ipairs(container:GetDescendants()) do
        if inst:IsA("Tool") then add(inst) end
    end
end

