    local lp = _getLP()
    if not lp then return {} end

    local out, seen = {}, {}
    local function add(tool)
        local info = _petInfo(tool)
        if info and not seen[info.id] then
            seen[info.id] = true
            out[#out + 1] = info
        end
    end

    _scanTools(lp:FindFirstChild("Backpack") or lp:FindFirstChildOfClass("Backpack"), add)
    _scanTools(lp.Character, add)

    return out
end

