        end
    end
    return out
end

local function _equipTool(tool)
    local lp = _getLP()
    if not lp or not tool then return false end

    if not tool.Parent then return false end

    local char = lp.Character
    if not char then
        char = lp.CharacterAdded:Wait()
        task.wait(0.2)
    end

    local hum = char:FindFirstChildOfClass("Humanoid")
    if not hum then return false end

    local bp = lp:FindFirstChild("Backpack") or lp:FindFirstChildOfClass("Backpack")
    if tool.Parent ~= bp and tool.Parent ~= char then
        return false
    end

    if char:FindFirstChildOfClass("Tool") and char:FindFirstChildOfClass("Tool") ~= tool then
        pcall(function() hum:UnequipTools() end)
        task.wait(0.15)
    end

    pcall(function() hum:EquipTool(tool) end)

    for _ = 1, 12 do
        if tool.Parent == char then return true end
        local equipped = char:FindFirstChildOfClass("Tool")
        if equipped and _petInfo(equipped) then return true end
        task.wait(0.05)
    end

    return tool.Parent == char
end

