        SP_STATE.pets = snap.pets
        patchAutoOnly("sellPet", snap)
    end

    local function syncSellPetModule()
        writeSellPetGlobals()
        local mod = G.AutoSellPet or G.AutoSellPetModule or rawget(_G, "AutoSellPet")
        if type(mod) ~= "table" then
            warn("[GAG2] AutoSellPet module belum loaded — re-execute hub")
            return
        end
        if G.AUTO_SELL_PET_ENABLED then
            if type(mod.Restart) == "function" then
                pcall(mod.Restart, mod)
            elseif type(mod.SetEnabled) == "function" then
                pcall(mod.SetEnabled, mod, true)
            elseif type(mod.Start) == "function" then
                pcall(mod.Start, mod)
            end
        else
            if type(mod.SetEnabled) == "function" then
                pcall(mod.SetEnabled, mod, false)
            elseif type(mod.Stop) == "function" then
                pcall(mod.Stop, mod)
            end
        end
    end

    local function persistSellPet()
        writeSellPetGlobals()
        if type(patchAuto) == "function" then
            patchAuto("sellPet", sellPetSnapshot(), syncSellPetModule)
        else
            syncSellPetModule()
        end
    end

    G.__GAG2_PUSH_SELL_PET = writeSellPetGlobals
    _G.__GAG2_PUSH_SELL_PET = writeSellPetGlobals
    G.__GAG2_SYNC_AUTO_SELL_PET = syncSellPetModule
    _G.__GAG2_SYNC_AUTO_SELL_PET = syncSellPetModule

    writeSellPetGlobals()

    local body = ui:CreateSection("Auto Sell Pet", false)
    local sellOn = SP_STATE.enabled == true

    local function currentSellPetSelected()
        local dd = G.__GAG2_SELL_PET_DROPDOWN_API or rawget(_G, "__GAG2_SELL_PET_DROPDOWN_API")
        if type(dd) == "table" and type(dd.getSelected) == "function" then
            local ok, sel = pcall(dd.getSelected, dd)
            if ok and type(sel) == "table" then
                return cleanSelectedMap(sel)
            end
        end
        local gsel = G.AUTO_SELL_PET_SELECTED or rawget(_G, "AUTO_SELL_PET_SELECTED")
        if type(gsel) == "table" and next(gsel) then
            return cleanSelectedMap(gsel)
        end
        return cleanSelectedMap(petsSelected)
    end

    local function refreshSellPetDropdown()
        local dd = G.__GAG2_SELL_PET_DROPDOWN_API or rawget(_G, "__GAG2_SELL_PET_DROPDOWN_API")
        if type(dd) == "table" and type(dd.refreshItems) == "function" then
            pcall(dd.refreshItems, dd)
        end
    end

    local _, petDdApi = ui:CreateRowDropdown(body, {
        label = "Pet list",
        placeholder = "Choose pets...",
        mode = "multi",
        deferItemLoad = true,
        labelForKey = function(key)
            return tostring(key or "")
        end,
        getItems = function()
            local ag = getAutoGiftModule()
            if type(ag) == "table" and type(ag.BuildInventoryItems) == "function" then
                local ok, items = pcall(ag.BuildInventoryItems, ag, "Pets", currentSellPetSelected())
                if ok and type(items) == "table" then return items end
            end
            return {}
        end,
        initial = petsSelected,
        onChanged = function(_, selectedMap)
            petsSelected = cleanSelectedMap(selectedMap)
            SP_STATE.pets = mapToArray(petsSelected)
            persistSellPet()
        end,
    })

    G.__GAG2_SELL_PET_DROPDOWN_API = petDdApi
    _G.__GAG2_SELL_PET_DROPDOWN_API = petDdApi
    G.__GAG2_REFRESH_SELL_PET_DROPDOWN = refreshSellPetDropdown
    _G.__GAG2_REFRESH_SELL_PET_DROPDOWN = refreshSellPetDropdown

    task.defer(function()
        if petDdApi and type(petDdApi.setSelected) == "function" and next(petsSelected) then
            petDdApi.setSelected(petsSelected)
            if type(petDdApi.refreshLabel) == "function" then
                petDdApi.refreshLabel()
            end
        end
    end)

    local _, _, enableApi = ui:CreateRowToggle(
        body,
        "Enabled Auto Sell Pet",
        sellOn,
        function(isOn)
            SP_STATE.enabled = (isOn == true)
            persistSellPet()
        end
    )

    G.__GAG2_SELL_PET_ENABLE_API = enableApi
    _G.__GAG2_SELL_PET_ENABLE_API = enableApi

    if enableApi and type(enableApi.set) == "function" then
        enableApi.set(sellOn, true)
    end

    syncSellPetModule()
end

G.SectionAutoSellPet = M
_G.SectionAutoSellPet = M

return M
 end,            required = false },
    { key = "AutoSellStock",           name = "Auto Sell Stock",         factory = function() -- AutoSellStock.lua — Grow A Garden 2
-- Jual per tipe buah yang Fruit Stock multiplier >= minMult.
-- Match → soft-pause peers → unfav tipe match (opsional) → SellFruit → resume.

local Players           = game:GetService("Players")
local ReplicatedStorage = game:GetService("ReplicatedStorage")

local LP = Players.LocalPlayer
local G  = (getgenv and getgenv()) or _G
local M  = {}

M.ModuleVersion = "20260715a"

local LOOP_SEC       = 2.5
local STOCK_CACHE_SEC = 8
local SELL_GAP       = 0.04
local UNFAV_SETTLE   = 0.2
local DAILY_MULT_FALLBACK = 2.2

local busy = false
local running = false
local loopId = 0
local lastStatus = ""
local stockCache = { at = 0, entries = {} }

local Networking
pcall(function()
    Networking = require(ReplicatedStorage.SharedModules.Networking)
end)

local FruitProxyUtil
pcall(function()
    FruitProxyUtil = require(ReplicatedStorage.SharedModules.FruitProxyUtil)
end)

local function _defaults()
    return {
        enabled          = false,
        minMult          = 1,
        minBackpackCount = 1,
        minTotalValue    = 0,
        autoUnfav        = false,
    }
end

local function _getMainCfg()
    local MAIN = rawget(_G, "MAIN") or G.MAIN
    if type(MAIN) ~= "table" then return nil end
    MAIN.auto = MAIN.auto or {}
    if type(MAIN.auto.sellStock) ~= "table" then
        MAIN.auto.sellStock = _defaults()
    end
    return MAIN.auto.sellStock
end

local function _publish(cfg)
    G.AUTO_SELL_STOCK = cfg
    _G.AUTO_SELL_STOCK = cfg
end

local function _setStatus(msg)
    lastStatus = tostring(msg or "")
    G.AUTO_SELL_STOCK_STATUS = lastStatus
    _G.AUTO_SELL_STOCK_STATUS = lastStatus
end

local function _autoSellFruit()
    -- Runtime name = AutoSellFruit (lihat AutoGift / main_ui). Jangan ambil Stock/Daily/Pet.
    local as = G.AutoSellFruit or rawget(_G, "AutoSellFruit")
    if type(as) ~= "table" then
        as = G.AutoSell or G.AutoSellModule
            or rawget(_G, "AutoSell") or rawget(_G, "AutoSellModule")
    end
    if type(as) ~= "table" then return nil end
    if as == M then return nil end
    if as == G.AutoSellStock or as == G.AutoSellStockModule then return nil end
    if as == G.AutoSellDaily or as == G.AutoSellDailyModule then return nil end
    if as == G.AutoSellPet or as == G.AutoSellPetModule then return nil end
    if type(as.PausePeers) ~= "function" and type(as.Pause) ~= "function" then
        return nil
    end
    return as
end

local function _autoFav()
    return G.AutoFav or G.AutoFavModule or _G.AutoFav or _G.AutoFavModule
end

local function _autoDaily()
    return G.AutoSellDaily or G.AutoSellDailyModule or _G.AutoSellDaily
end

local function _fsv()
    return G.FruitSellValue or _G.FruitSellValue
end

local function _net()
    if type(Networking) == "table" then return Networking end
    pcall(function()
        Networking = require(ReplicatedStorage.SharedModules.Networking)
    end)
    return Networking
end

local function _npcFire(name, ...)
    local net = _net()
    local pkt = net and net.NPCS and net.NPCS[name]
    if not pkt or type(pkt.Fire) ~= "function" then
        return false, "missing_" .. tostring(name)
    end
    local args = table.pack(...)
    local results = table.pack(pcall(function()
        if args.n > 0 then
            return pkt:Fire(table.unpack(args, 1, args.n))
        end
        return pkt:Fire()
    end))
    if not results[1] then
        return false, results[2]
    end
    return true, results[2], results[3], results[4]
end

----------------------------------------------------------------
-- inventory helpers
----------------------------------------------------------------
local function _fruitId(tool)
    if not tool or type(tool.GetAttribute) ~= "function" then return "" end
    return tostring(tool:GetAttribute("Id") or tool:GetAttribute("id")
        or tool:GetAttribute("UUID") or tool:GetAttribute("Uuid")
        or tool:GetAttribute("FruitId") or tool:GetAttribute("fruitId")
        or tool:GetAttribute("c") or "")
end

local function _normName(s)
    return string.lower((tostring(s or ""):gsub("%s+", "")))
end

local function _isNonFruitName(name)
    local n = _normName(name)
    if n == "" then return false end
    if n:find("seed", 1, true) then return true end
    if n == "shovel" or n == "wateringcan" or n == "build" then return true end
    return n:find("sprinkler", 1, true) ~= nil
        or n:find("sprink", 1, true) ~= nil
        or n:find("gear", 1, true) ~= nil
        or n:find("watering", 1, true) ~= nil
        or n:find("fertilizer", 1, true) ~= nil
        or n:find("egg", 1, true) ~= nil
        or n:find("trap", 1, true) ~= nil
end

local function _isFruitTool(inst)
    if not inst or not inst.Parent then return false end
    if inst:GetAttribute("SeedTool") or inst:GetAttribute("Pet") then return false end
    if inst:GetAttribute("PottedPlant") == true then return false end
    local cat = tostring(inst:GetAttribute("MainCategory") or "")
    if cat == "Seed" or cat == "Gear" or cat == "Egg" or cat == "Tool" or cat == "Pet" then
        return false
    end
    -- Jangan fallback IsA("Tool") — itu ikut gear/egg/sprinkler.
    if FruitProxyUtil and type(FruitProxyUtil.IsFruitInstance) == "function" then
        local ok, yes = pcall(FruitProxyUtil.IsFruitInstance, inst)
        if ok and yes then
            local nm = tostring(inst:GetAttribute("FruitName") or inst:GetAttribute("Fruit") or inst.Name or "")
            if _isNonFruitName(nm) then return false end
            return true
        end
        if ok and yes == false then return false end
    end
    if inst:GetAttribute("FruitName") or inst:GetAttribute("Fruit") then
        local nm = tostring(inst:GetAttribute("FruitName") or inst:GetAttribute("Fruit") or "")
        if _isNonFruitName(nm) then return false end
        return true
    end
    if inst:GetAttribute("FruitProxy") == true then return true end
    local hf = inst:GetAttribute("HarvestedFruit")
    if hf == true or (type(hf) == "string" and hf ~= "") then return true end
    if inst:GetAttribute("Id") and inst:GetAttribute("Weight") then return true end
    return false
end

local function _eachFruitTool(fn)
    if type(fn) ~= "function" then return end
    local seen = {}
    local function scan(root)
        if not root then return end
        for _, inst in ipairs(root:GetChildren()) do
            if not seen[inst] and _isFruitTool(inst) then
                seen[inst] = true
                fn(inst)
            end
        end
    end
    scan(LP:FindFirstChild("Backpack") or LP:FindFirstChildOfClass("Backpack"))
    scan(LP.Character)
end

local function _fruitName(tool)
    if not tool then return "" end
    local attr = tool:GetAttribute("FruitName") or tool:GetAttribute("Fruit")
    if attr ~= nil and tostring(attr) ~= "" then
        local n = tostring(attr)
        if not _isNonFruitName(n) then return n end
    end
    local fsv = _fsv()
    if fsv and type(fsv.resolveSeedName) == "function" then
        local ok, name = pcall(fsv.resolveSeedName, tool)
        if ok and name ~= nil and tostring(name) ~= "" then
            local n = tostring(name)
            if not _isNonFruitName(n) then return n end
        end
    end
    local fallback = tostring(tool.Name or "")
    if fallback ~= "" and not _isNonFruitName(fallback) then
        return fallback
    end
    return ""
end

local function _isFavorited(tool)
    if not tool or type(tool.GetAttribute) ~= "function" then return false end
    local function truthy(v)
        return v == true or v == 1 or v == "true" or v == "1"
    end
    return truthy(tool:GetAttribute("IsFavorite"))
        or truthy(tool:GetAttribute("Favorite"))
        or truthy(tool:GetAttribute("Favorited"))
end

local function _espPriceMode()
    local fsv = _fsv()
    if fsv and type(fsv.getEspPriceMode) == "function" then
        local ok, m = pcall(fsv.getEspPriceMode)
        if ok and type(m) == "string" and m ~= "" then
            return (string.lower(m) == "stock") and "stock" or "base"
        end
    end
    local mode = G.FRUIT_BACKPACK_ESP_PRICE_MODE or rawget(_G, "FRUIT_BACKPACK_ESP_PRICE_MODE")
    return (tostring(mode or ""):lower() == "stock") and "stock" or "base"
end

-- Harga per buah = jalur yang sama dengan EspFruitBackpack.
local function _toolPrice(tool)
    if not tool then return 0 end
    local fsv = _fsv()
    local name = _fruitName(tool)
    local id = _fruitId(tool)
    local bid = tonumber(tool:GetAttribute("BidPrice")) or 0
    local multi = 0
    if fsv and type(fsv.resolveMulti) == "function" then
        local ok, m = pcall(fsv.resolveMulti, tool)
        if ok and type(m) == "number" then multi = m end
    end
    if multi <= 0 then
        multi = tonumber(tool:GetAttribute("SizeMultiplier") or tool:GetAttribute("SizeMulti")) or 0
    end
    local mut = tool:GetAttribute("Mutation")
    local decay = tool:GetAttribute("DecayAlpha")
    local mode = _espPriceMode()

    if fsv and type(fsv.getBackpackEspPrice) == "function" and name ~= "" and multi > 0 then
        local ok, p = pcall(fsv.getBackpackEspPrice, name, multi, mut, decay, mode,
            id ~= "" and id or nil, bid)
        if ok and type(p) == "number" and p > 0 then return p end
    end

    local esp = G.EspFruitBackpack or _G.EspFruitBackpack
    if type(esp) == "table" and id ~= "" and type(esp.GetEntryPrice) == "function" then
        local ok, p = pcall(esp.GetEntryPrice, esp, {
            id = id, name = name, multi = multi, mut = mut, decay = decay, bidPrice = bid, tool = tool,
        }, false)
        if ok and type(p) == "number" and p > 0 then return p end
    end

    if fsv and type(fsv.fromFruit) == "function" then
        local ok, p = pcall(fsv.fromFruit, tool, LP)
        if ok and type(p) == "number" and p > 0 then return p end
    end
    return bid
end

local function _toolStockedPrice(tool, mult)
    local base = _toolPrice(tool)
    if base <= 0 then return 0 end
    -- Kalau ESP mode sudah "stock", harga sudah include hot rate — jangan double-apply.
    if _espPriceMode() == "stock" then
        return base
    end
    mult = tonumber(mult) or 1
    local fsv = _fsv()
    local name = _fruitName(tool)
    if fsv and type(fsv.applyStockRate) == "function" and name ~= "" then
        local ok, p = pcall(fsv.applyStockRate, name, base)
        if ok and type(p) == "number" and p > 0 then return p end
    end
    return math.floor(base * mult + 0.5)
end

----------------------------------------------------------------
-- stock snapshot
----------------------------------------------------------------
local function _parseStockSnapshot(raw)
    local entries = {}
    if type(raw) ~= "table" then return entries end
    local src = raw.entries
    if type(src) ~= "table" then
        src = raw
    end
    for name, info in pairs(src) do
        if type(name) == "string" then
            local mult = 1
            if type(info) == "table" then
                mult = tonumber(info.multiplier or info.Multiplier or info.rate or info.Rate) or 1
            elseif type(info) == "number" then
                mult = info
            end
            entries[name] = mult
            entries[string.lower(name)] = mult
        end
    end
    return entries
end

local function _requestStock(force)
    local now = os.clock()
    if not force and (now - stockCache.at) < STOCK_CACHE_SEC and next(stockCache.entries) then
        return stockCache.entries
    end
    local net = _net()
    local req = net and net.FruitStock and net.FruitStock.Request
    if not req or type(req.Fire) ~= "function" then
        return stockCache.entries
    end
    local ok, raw = pcall(function()
        return req:Fire()
    end)
    if ok then
        stockCache.entries = _parseStockSnapshot(raw)
        stockCache.at = now
    end
    return stockCache.entries
end

local function _multForName(entries, name)
    if type(entries) ~= "table" or name == nil or name == "" then return 1 end
    local m = entries[name] or entries[string.lower(name)]
    return tonumber(m) or 1
end

----------------------------------------------------------------
-- Soft-pause AutoSellFruit + AutoFav (toggle/state tidak diubah).
-- Prefer API resmi AutoSellFruit.PausePeers / WithPeerHold.
----------------------------------------------------------------
function M.HoldPeers(reason)
    reason = reason or "stock"
    local as = _autoSellFruit()
    if type(as) == "table" and type(as.PausePeers) == "function" then
        local ok = pcall(function()
            as.PausePeers(reason)
        end)
        return ok == true
    end
    if type(as) == "table" and type(as.Pause) == "function" then
        pcall(function()
            as.Pause(reason)
        end)
    end
    local af = _autoFav()
    if type(af) == "table" and type(af.Pause) == "function" then
        pcall(function()
            af.Pause(reason)
        end)
    end
    return true
end

function M.ReleasePeers()
    local as = _autoSellFruit()
    if type(as) == "table" and type(as.ResumePeers) == "function" then
        local ok = pcall(function()
            as.ResumePeers()
        end)
        return ok == true
    end
    local af = _autoFav()
    if type(af) == "table" and type(af.Resume) == "function" then
        pcall(function()
            af.Resume()
        end)
    end
    if type(as) == "table" and type(as.Resume) == "function" then
        pcall(function()
            as.Resume()
        end)
    end
    return true
end

function M.WithPeerHold(fn, reason, idleTimeout)
    if type(fn) ~= "function" then
        return false, "bad_fn"
    end
    reason = reason or "stock"
    idleTimeout = idleTimeout or 15

    local as = _autoSellFruit()
    if type(as) == "table" and type(as.WithPeerHold) == "function" then
        local okCall, heldOk, a, b, c = pcall(function()
            return as.WithPeerHold(fn, reason, idleTimeout)
        end)
        if okCall then
            return heldOk, a, b, c
        end
        return false, heldOk
    end

    M.HoldPeers(reason)
    if type(as) == "table" and type(as.WaitIdle) == "function" then
        pcall(function()
            as.WaitIdle(idleTimeout)
        end)
    else
        task.wait(0.15)
    end
    local ok, a, b, c = pcall(fn)
    M.ReleasePeers()
    if not ok then
        return false, a
    end
    return true, a, b, c
end

M.holdPeers = M.HoldPeers
M.releasePeers = M.ReleasePeers
M.withPeerHold = M.WithPeerHold

----------------------------------------------------------------
-- config
----------------------------------------------------------------
function M.GetConfig()
    local cfg = _getMainCfg()
    return type(cfg) == "table" and cfg or _defaults()
end

function M.SetConfig(cfg)
    if type(cfg) ~= "table" then return M.GetConfig() end
    local cur = _getMainCfg()
    if not cur then return cfg end
    if cfg.enabled ~= nil then cur.enabled = (cfg.enabled == true) end
    if cfg.minMult ~= nil then cur.minMult = tonumber(cfg.minMult) or cur.minMult end
    if cfg.minBackpackCount ~= nil then
        cur.minBackpackCount = math.max(1, math.floor(tonumber(cfg.minBackpackCount) or 1))
    end
    if cfg.minTotalValue ~= nil then
        cur.minTotalValue = math.max(0, tonumber(cfg.minTotalValue) or 0)
    end
    if cfg.autoUnfav ~= nil then cur.autoUnfav = (cfg.autoUnfav == true) end
    _publish(cur)
    return cur
end

M.setConfig = M.SetConfig
M.getConfig = M.GetConfig

function M.SetEnabled(on)
    return M.SetConfig({ enabled = on == true })
end

M.setEnabled = M.SetEnabled

function M.IsEnabled()
    return M.GetConfig().enabled == true
end

M.isEnabled = M.IsEnabled

function M.IsBusy()
    return busy == true or G.__GAG2_BOOST_SELL_BUSY == true
end

M.isBusy = M.IsBusy

function M.SyncFromState()
    local cfg = M.GetConfig()
    _publish(cfg)
    if cfg.enabled then
        M.Start()
    else
        M.Stop()
    end
    return cfg
end

M.syncFromState = M.SyncFromState

function M.GetStatus()
    return lastStatus
end

----------------------------------------------------------------
-- evaluate (tanpa pause)
----------------------------------------------------------------
-- Total backpack = fav + unfav (bukan PreviewSellAll yang exclude fav).
local bpTotalsCache = { at = 0, count = 0, value = 0 }
local BP_TOTALS_CACHE_SEC = 5

local function _backpackTotals(force)
    local now = os.clock()
    if not force and (now - bpTotalsCache.at) < BP_TOTALS_CACHE_SEC and bpTotalsCache.at > 0 then
        return bpTotalsCache.count, bpTotalsCache.value
    end

    local count = tonumber(LP:GetAttribute("FruitCount")) or 0
    local totalValue = 0
    local scanned = 0

    -- Prefer total yang sama dengan badge ESP backpack.
    local esp = G.EspFruitBackpack or _G.EspFruitBackpack
    if type(esp) == "table" and type(esp.ScanFruits) == "function" and type(esp.GetEntryPrice) == "function" then
        local ok, list = pcall(esp.ScanFruits, esp)
        if ok and type(list) == "table" then
            local seen = {}
            for _, e in ipairs(list) do
                if type(e) == "table" then
                    local id = tostring(e.id or "")
                    local key = id ~= "" and id or (tostring(e.name or "") .. ":" .. tostring(e.multi or 0))
                    if not seen[key] then
                        seen[key] = true
                        scanned += 1
                        local okp, p = pcall(esp.GetEntryPrice, esp, e, false)
                        p = (okp and tonumber(p)) or 0
                        if p > 0 then totalValue += p end
                    end
                end
            end
        end
    end

    if scanned <= 0 or totalValue <= 0 then
        totalValue = 0
        scanned = 0
        _eachFruitTool(function(tool)
            scanned += 1
            totalValue += _toolPrice(tool)
        end)
    end

    if count <= 0 then
        count = scanned
    end
    bpTotalsCache.at = now
    bpTotalsCache.count = count
    bpTotalsCache.value = totalValue
    return count, totalValue
end

function M.Evaluate(opts)
    opts = type(opts) == "table" and opts or {}
    local cfg = M.GetConfig()
    local out = {
        ready = false,
        reason = "disabled",
        estimate = 0,
        matchCount = 0,
        matchNames = {},
        matchTypes = {},
        bpTypes = {},
        matchIds = {},
        backpackCount = 0,
        backpackValue = 0,
        minMult = tonumber(cfg.minMult) or 1,
    }
    if cfg.enabled ~= true and opts.ignoreEnabled ~= true then
        return out
    end

    local entries = _requestStock(opts.forceStock == true)
    local bpCount, bpValue = _backpackTotals(opts.forceTotals == true)
    out.backpackCount = bpCount
    out.backpackValue = bpValue

    local minMult = tonumber(cfg.minMult) or 1
    out.minMult = minMult

    -- Scan semua tipe di BP (untuk status), + match yang lolos minMult.
    local nameSet = {}
    local typeMap = {} -- match ≥ minMult
    local bpMap = {}   -- semua tipe di backpack + stock X
    local ids = {}
    local estimate = 0
    local matchCount = 0
    local seenId = {}

    _eachFruitTool(function(tool)
        local name = _fruitName(tool)
        if name == "" then return end
        local mult = _multForName(entries, name)
        local id = _fruitId(tool)
        if id ~= "" and seenId[id] then return end
        if id ~= "" then seenId[id] = true end

        local bp = bpMap[name]
        if not bp then
            bp = { name = name, mult = mult, count = 0 }
            bpMap[name] = bp
        end
        bp.count += 1
        if mult > (tonumber(bp.mult) or 0) then
            bp.mult = mult
        end

        if mult < minMult then return end
        local fav = _isFavorited(tool)
        if fav and cfg.autoUnfav ~= true then
            return
        end
        matchCount += 1
        nameSet[name] = true
        if id ~= "" then
            ids[#ids + 1] = id
        end
        estimate += _toolStockedPrice(tool, mult)
        local row = typeMap[name]
        if not row then
            row = { name = name, mult = mult, count = 0 }
            typeMap[name] = row
        end
        row.count += 1
        if mult > (tonumber(row.mult) or 0) then
            row.mult = mult
        end
    end)

    local function sortTypes(map)
        local list = {}
        for _, row in pairs(map) do
            list[#list + 1] = row
        end
        table.sort(list, function(a, b)
            local ma, mb = tonumber(a.mult) or 0, tonumber(b.mult) or 0
            if ma ~= mb then return ma > mb end
            return tostring(a.name) < tostring(b.name)
        end)
        return list
    end

    local matchTypes = sortTypes(typeMap)
    local bpTypes = sortTypes(bpMap)
    local bestMult = 0
    if bpTypes[1] then
        bestMult = tonumber(bpTypes[1].mult) or 0
    end

    out.matchCount = matchCount
    out.matchNames = nameSet
    out.matchTypes = matchTypes
    out.bpTypes = bpTypes
    out.bpTypeCount = #bpTypes
    out.bestMult = bestMult
    out.matchIds = ids
    out.estimate = estimate
    do
        local seen, n = {}, 0
        if type(entries) == "table" then
            for k in pairs(entries) do
                if type(k) == "string" then
                    local lk = string.lower(k)
                    if not seen[lk] then
                        seen[lk] = true
                        n += 1
                    end
                end
            end
        end
        out.stockEntryCount = n
    end

    local minN = math.max(1, math.floor(tonumber(cfg.minBackpackCount) or 1))
    local minV = math.max(0, tonumber(cfg.minTotalValue) or 0)
    if bpCount < minN then
        out.reason = "count"
        return out
    end
    if minV > 0 and bpValue < minV then
        out.reason = "value"
        return out
    end

    if matchCount <= 0 then
        out.reason = "no_match"
        return out
    end

    out.ready = true
    out.reason = "ok"
    return out
end

M.evaluate = M.Evaluate

local function _dailyEstimateFallback()
    local daily = _autoDaily()
    if type(daily) == "table" and type(daily.Evaluate) == "function" then
        local ok, probe = pcall(daily.Evaluate, daily, { ignoreEnabled = false })
        if ok and type(probe) == "table" then
            return probe
        end
    end
    return nil
end

local function _shouldYieldToDaily(stockEst)
    local probe = _dailyEstimateFallback()
    if not probe or probe.ready ~= true then return false end
    local dEst = tonumber(probe.estimate) or 0
    -- Prefer Daily on tie (1x / ~12h opportunity).
    return dEst >= (tonumber(stockEst) or 0)
end

----------------------------------------------------------------
-- sell
----------------------------------------------------------------
local function _sellMatched(ids)
    local sold = 0
    local favorited = 0
    for i, id in ipairs(ids) do
        if id and id ~= "" then
            local ok, res = _npcFire("SellFruit", id)
            local success = ok and (
                res == true
                or (type(res) == "table" and (res.Success == true or res.success == true))
                or type(res) == "number"
            )
            if success then
                sold += 1
            elseif type(res) == "table" and (res.Reason == "Favorited" or res.reason == "Favorited") then
                favorited += 1
            end
            if i < #ids then
                task.wait(SELL_GAP)
            end
        end
    end
    return sold, favorited
end

function M.RunOnce(opts)
    opts = type(opts) == "table" and opts or {}
    if busy or G.__GAG2_BOOST_SELL_BUSY == true then
        return false, "busy"
    end
    if not M.IsEnabled() then
        return false, "disabled"
    end

    local probe = M.Evaluate(opts)
    if not probe.ready then
        _setStatus("Stock wait: " .. tostring(probe.reason))
        return false, probe.reason, probe
    end

    if _shouldYieldToDaily(probe.estimate) then
        _setStatus("YIELD Daily (lebih besar)")
        return false, "yield_daily", probe
    end

    busy = true
    G.__GAG2_BOOST_SELL_BUSY = true
    _G.__GAG2_BOOST_SELL_BUSY = true
    _setStatus(string.format("Stock sell %d fruits...", probe.matchCount))

    local heldOk, sold, favBlocked, detail = M.WithPeerHold(function()
        local cfg = M.GetConfig()
        if cfg.autoUnfav == true then
            local af = _autoFav()
            if type(af) == "table" then
                -- Jangan pcall(fn, self, ...) — UnfavBy* signature tanpa self
                if type(af.UnfavByFruitIds) == "function" and type(probe.matchIds) == "table" and #probe.matchIds > 0 then
                    pcall(function()
                        af.UnfavByFruitIds(probe.matchIds, { fireDelay = 0.03 })
                    end)
                elseif type(af.UnfavByFruitNames) == "function" then
                    pcall(function()
                        af.UnfavByFruitNames(probe.matchNames, { fireDelay = 0.03 })
                    end)
                end
                task.wait(UNFAV_SETTLE)
            end
        end
        local again = M.Evaluate({ ignoreEnabled = true, forceStock = false, forceTotals = true })
        local ids = again.matchIds
        if type(ids) ~= "table" or #ids == 0 then
            ids = probe.matchIds
        end
        local n, favN = _sellMatched(ids)
        return n, favN, again
    end, "stock")

    busy = false
    G.__GAG2_BOOST_SELL_BUSY = false
    _G.__GAG2_BOOST_SELL_BUSY = false

    if not heldOk then
        _setStatus("Stock error: " .. tostring(sold))
        return false, sold
    end

    local nSold = tonumber(sold) or 0
    local nFav = tonumber(favBlocked) or 0
    if nSold > 0 then
        _setStatus(string.format("Stock sold %d", nSold))
        return true, { sold = nSold, estimate = probe.estimate }, detail
    end
    if nFav > 0 then
        _setStatus(string.format("Stock blocked fav %d — enable Auto unfav", nFav))
        return false, "favorited", detail
    end
    _setStatus("Stock sell failed / empty")
    return false, "sell_failed", detail
end

M.runOnce = M.RunOnce

----------------------------------------------------------------
-- loop
----------------------------------------------------------------
local function _loop(myId)
    while running and loopId == myId do
        if M.IsEnabled() and not busy and G.__GAG2_BOOST_SELL_BUSY ~= true then
            pcall(M.RunOnce)
        end
        task.wait(LOOP_SEC)
    end
end

function M.Start()
    M.SetEnabled(true)
    if running then return true end
    running = true
    loopId += 1
    local myId = loopId
    task.spawn(function()
        _loop(myId)
    end)
    _setStatus("Stock ON")
    return true
end

function M.Stop()
    running = false
    M.SetEnabled(false)
    _setStatus("Stock OFF")
end

M.start = M.Start
M.stop = M.Stop

function M.IsRunning()
    return running == true
end

M.isRunning = M.IsRunning

G.AutoSellStock = M
G.AutoSellStockModule = M
_G.AutoSellStock = M
_G.AutoSellStockModule = M

return M
