    { key = "SectionAutoSellStock",    name = "Section Auto Sell Stock", factory = function() -- section_auto_sell_stock.lua — UI Auto Sell Stock Price (tab Auto)

local G = (getgenv and getgenv()) or _G
local M = {}

-- Suffix panjang dulu (qi sebelum q, am sebelum m).
local VALUE_SUFFIXES = {
    { "juta", 1e6 }, { "jt", 1e6 },
    { "ribu", 1e3 }, { "rb", 1e3 },
    { "dc", 1e33 }, { "no", 1e30 }, { "oc", 1e27 },
    { "sp", 1e24 }, { "sx", 1e21 },
    { "qi", 1e18 }, { "qn", 1e18 },
    { "qa", 1e15 }, { "qd", 1e15 },
    { "t", 1e12 }, { "b", 1e9 }, { "m", 1e6 }, { "k", 1e3 },
}

local function abbrev(n)
    n = tonumber(n) or 0
    if n <= 0 then return "0" end
    local units = {
        { 1e33, "Dc" }, { 1e30, "No" }, { 1e27, "Oc" },
        { 1e24, "Sp" }, { 1e21, "Sx" },
        { 1e18, "Qi" }, { 1e15, "Qa" },
        { 1e12, "T" }, { 1e9, "B" }, { 1e6, "M" }, { 1e3, "K" },
    }
    for _, u in ipairs(units) do
        if n >= u[1] then
            local v = n / u[1]
            if math.abs(v - math.floor(v + 0.5)) < 1e-6 then
                return string.format("%d%s", math.floor(v + 0.5), u[2])
            end
            return string.format("%.2f%s", v, u[2]):gsub("%.?0+([A-Za-z])", "%1")
        end
    end
    return tostring(math.floor(n + 0.5))
end

-- "1b", "1 qi", "1.5Qa", "1am" (huruf 2+: aa=1e63, ab=1e66, ... am=1e99)
local function parseScaledValue(txt)
    txt = tostring(txt or ""):lower():gsub("%s+", ""):gsub(",", ".")
    if txt == "" then return nil end
    local sign = 1
    if txt:sub(1, 1) == "-" then
        sign = -1
        txt = txt:sub(2)
    end

    for _, pair in ipairs(VALUE_SUFFIXES) do
        local suf, mult = pair[1], pair[2]
        if #txt > #suf and txt:sub(-#suf) == suf then
            local numPart = txt:sub(1, -#suf - 1)
            local n = tonumber(numPart)
            if n then return n * mult * sign end
        end
    end

    -- alphabetical 2–3 huruf (aa, am, aaa, ...), jangan tabrak k/m/b/t
    local numPart, letters = txt:match("^([%d%.]+)([a-z]+)$")
    if numPart and letters and #letters >= 2 then
        local n = tonumber(numPart)
        if n then
            local idx = 0
            for i = 1, #letters do
                local c = letters:byte(i) - 96
                if c < 1 or c > 26 then
                    idx = nil
                    break
                end
                idx = idx * 26 + (c - 1)
            end
            if idx ~= nil then
                -- aa => idx 0 => 1e63; each step ×1000
                local exp = 63 + idx * 3
                return n * (10 ^ exp) * sign
            end
        end
    end

    local n = tonumber(txt)
    if n then return n * sign end
    return nil
end

