function M.GetConfig()
    local cfg = _getMainCfg()
    return type(cfg) == "table" and cfg or _defaults()
end

function M.SetConfig(cfg)
    if type(cfg) ~= "table" then return M.GetConfig() end
    local cur = _getMainCfg()
    if not cur then return cfg end
    if cfg.enabled ~= nil then cur.enabled = (cfg.enabled == true) end
    if cfg.minBackpackCount ~= nil then
        cur.minBackpackCount = math.max(1, math.floor(tonumber(cfg.minBackpackCount) or 1))
    end
    if cfg.minTotalValue ~= nil then
        cur.minTotalValue = math.max(0, tonumber(cfg.minTotalValue) or 0)
    end
    if cfg.autoUnfav ~= nil then cur.autoUnfav = (cfg.autoUnfav == true) end
    _publish(cur)
    return cur
end

M.setConfig = M.SetConfig
M.getConfig = M.GetConfig

function M.SetEnabled(on)
    return M.SetConfig({ enabled = on == true })
end

M.setEnabled = M.SetEnabled

function M.IsEnabled()
