M.syncFromState = M.SyncFromState

function M.GetStatus()
    return lastStatus
end

----------------------------------------------------------------
local function _checkDeal(force)
    local now = os.clock()
    if not force and dealCache.data and (now - dealCache.at) < DEAL_CACHE_SEC then
        return dealCache.data
    end
    local ok, res = _npcFire("CheckDailyDeal")
    if ok and type(res) == "table" then
        dealCache.data = res
        dealCache.at = now
        return res
    end
    return dealCache.data
end

local function _previewSell()
    local ok, a = _npcFire("PreviewSellAll")
    if ok and type(a) == "table" then return a end
    return nil
end

-- Cache scan total (fav+unfav) supaya status/gate tidak berat.
local bpScanCache = { at = 0, total = 0, favExtra = 0, allCount = 0, favCount = 0 }
local BP_SCAN_CACHE_SEC = 5

local function _sumAllBaseAndFav(force)
    local now = os.clock()
    if not force and (now - bpScanCache.at) < BP_SCAN_CACHE_SEC and bpScanCache.at > 0 then
        return bpScanCache.total, bpScanCache.favExtra, bpScanCache.allCount, bpScanCache.favCount
    end
    local total = 0
    local favExtra = 0
    local favCount = 0
    local allCount = 0

    -- Total prefer jalur ESP (sama badge backpack).
    local esp = G.EspFruitBackpack or _G.EspFruitBackpack
    if type(esp) == "table" and type(esp.ScanFruits) == "function" and type(esp.GetEntryPrice) == "function" then
        local ok, list = pcall(esp.ScanFruits, esp)
        if ok and type(list) == "table" then
            local seen = {}
            for _, e in ipairs(list) do
                if type(e) == "table" then
                    local id = tostring(e.id or "")
                    local key = id ~= "" and id or (tostring(e.name or "") .. ":" .. tostring(e.multi or 0))
                    if not seen[key] then
                        seen[key] = true
                        allCount += 1
                        local okp, p = pcall(esp.GetEntryPrice, esp, e, false)
                        p = (okp and tonumber(p)) or 0
                        if p > 0 then total += p end
                    end
                end
            end
        end
    end

    -- Fav extra tetap dari tool scan (untuk estimate Daily).
    local toolTotal = 0
    local toolCount = 0
    _eachFruitTool(function(tool)
        toolCount += 1
        local p = _toolPrice(tool)
        toolTotal += p
        if _isFavorited(tool) then
            favCount += 1
            favExtra += p
        end
    end)
    if total <= 0 then
        total = toolTotal
    end
    if allCount <= 0 then
        allCount = toolCount
    end

    bpScanCache.at = now
    bpScanCache.total = total
    bpScanCache.favExtra = favExtra
    bpScanCache.allCount = allCount
    bpScanCache.favCount = favCount
    return total, favExtra, allCount, favCount
end

function M.Evaluate(opts)
    opts = type(opts) == "table" and opts or {}
    local cfg = M.GetConfig()
    local out = {
        ready = false,
        reason = "disabled",
        estimate = 0,
        available = false,
        timeRemaining = 0,
        backpackCount = 0,
        backpackValue = 0,
        baseValue = 0,
    }
    if cfg.enabled ~= true and opts.ignoreEnabled ~= true then
        return out
    end

    -- Hitung total BP dulu (fav+unfav) — tetap diisi meski Daily CD.
    local scanTotal, favExtra, scanCount, favCount = _sumAllBaseAndFav(opts.forceTotals == true)
    local bpCount = tonumber(LP:GetAttribute("FruitCount")) or 0
    if bpCount < scanCount then bpCount = scanCount end
    local totalValue = scanTotal

    local preview = _previewSell()
    if totalValue <= 0 and type(preview) == "table" then
        -- Fallback jika scan tool = 0 (FSV belum ready): pakai Preview + fav extra.
        local pv = tonumber(preview.TotalValue or preview.totalValue
            or preview.TotalSellValue or preview.SellPrice) or 0
        totalValue = pv + math.max(0, favExtra)
        if totalValue <= 0 then
            totalValue = tonumber(preview.TotalBaseValue or preview.totalBaseValue) or 0
            if cfg.autoUnfav == true then
                totalValue = totalValue + math.max(0, favExtra)
            end
        end
    end

    out.backpackCount = bpCount
    out.backpackValue = totalValue
    out.favCount = favCount

    -- Daily payout estimate (tampilkan juga saat CD).
    local baseValue = 0
    if type(preview) == "table" then
        baseValue = tonumber(preview.TotalBaseValue or preview.totalBaseValue) or 0
    end
    if baseValue <= 0 then
        if cfg.autoUnfav == true then
            baseValue = scanTotal > 0 and scanTotal or totalValue
        else
            baseValue = math.max(0, (scanTotal > 0 and scanTotal or totalValue) - favExtra)
        end
    elseif cfg.autoUnfav == true and favExtra > 0 then
        baseValue = baseValue + favExtra
    end
    out.baseValue = baseValue
    out.estimate = _dailyDealPrice(baseValue)

    local deal = _checkDeal(opts.forceDeal == true)
    if type(deal) ~= "table" then
        out.reason = "no_deal"
        return out
    end
    out.available = (deal.Available == true)
    out.timeRemaining = tonumber(deal.TimeRemaining or deal.Remaining) or 0
    if not out.available then
        out.reason = "cooldown"
        return out
    end

    local minN = math.max(1, math.floor(tonumber(cfg.minBackpackCount) or 1))
    local minV = math.max(0, tonumber(cfg.minTotalValue) or 0)
    if bpCount < minN then
        out.reason = "count"
        return out
    end
    if minV > 0 and totalValue < minV then
        out.reason = "value"
        return out
    end

    -- Without autoUnfav, need at least some sellable (non-fav) fruit.
    if cfg.autoUnfav ~= true then
        local sellable = math.max(0, scanCount - favCount)
        if type(preview) == "table" then
            local pc = tonumber(preview.FruitCount or preview.fruitCount)
            if pc ~= nil then sellable = pc end
        end
        if sellable <= 0 then
            out.reason = "all_favorited"
            return out
        end
    end

    out.ready = true
    out.reason = "ok"
    return out
end

M.evaluate = M.Evaluate

local function _shouldYieldToStock(dailyEst)
    local stock = _autoStock()
    if type(stock) ~= "table" or type(stock.Evaluate) ~= "function" then
        return false
    end
    if type(stock.IsEnabled) == "function" and not stock.IsEnabled(stock) then
        return false
    end
    local ok, probe = pcall(stock.Evaluate, stock)
    if not ok or type(probe) ~= "table" or probe.ready ~= true then
        return false
    end
    local sEst = tonumber(probe.estimate) or 0
    -- Stock wins only if strictly greater; tie → Daily.
    return sEst > (tonumber(dailyEst) or 0)
end

function M.RunOnce(opts)
    opts = type(opts) == "table" and opts or {}
    if busy or G.__GAG2_BOOST_SELL_BUSY == true then
        return false, "busy"
    end
    if not M.IsEnabled() then
        return false, "disabled"
    end

    local probe = M.Evaluate(opts)
    if not probe.ready then
        if probe.reason == "cooldown" then
            _setStatus(string.format("Daily CD (%ds)", math.floor(probe.timeRemaining or 0)))
        else
            _setStatus("Daily wait: " .. tostring(probe.reason))
        end
        return false, probe.reason, probe
    end

    if _shouldYieldToStock(probe.estimate) then
        _setStatus("Daily yield to Stock (more sheckles)")
        return false, "yield_stock", probe
    end

    busy = true
    G.__GAG2_BOOST_SELL_BUSY = true
    _setStatus(string.format("Daily deal (est %s)...", tostring(math.floor(probe.estimate + 0.5))))

    local heldOk, okSell, payload = M.WithPeerHold(function()
        local cfg = M.GetConfig()
        if cfg.autoUnfav == true then
            local af = _autoFav()
            if type(af) == "table" and type(af.UnfavAllFavorited) == "function" then
                pcall(function()
                    af.UnfavAllFavorited({ fireDelay = 0.03 })
                end)
                task.wait(UNFAV_SETTLE)
            end
        end
        local ok, res = _npcFire("UseDailyDealAll")
        if not ok then
            return false, res
        end
        if type(res) == "table" then
            if res.Success == true or res.success == true then
                return true, res
            end
            return false, res.Reason or res.reason or "failed"
        end
        if res == true then
            return true, { Success = true }
        end
        return false, "failed"
    end, "daily")

    busy = false
    G.__GAG2_BOOST_SELL_BUSY = false
    dealCache.at = 0
    dealCache.data = nil

    if not heldOk then
        _setStatus("Daily error: " .. tostring(okSell))
        return false, okSell
    end

    if okSell == true then
        _setStatus(string.format("Daily OK (est %s)", tostring(math.floor(probe.estimate + 0.5))))
        return true, payload or { Success = true }, probe
    end

    _setStatus("Daily failed: " .. tostring(okSell))
    return false, okSell, payload
end

M.runOnce = M.RunOnce

----------------------------------------------------------------
local function _loop(myId)
    while running and loopId == myId do
        if M.IsEnabled() and not busy and G.__GAG2_BOOST_SELL_BUSY ~= true then
            pcall(M.RunOnce)
        end
        task.wait(LOOP_SEC)
    end
end

function M.Start()
    M.SetEnabled(true)
    if running then return true end
    running = true
    loopId += 1
    local myId = loopId
    task.spawn(function()
        _loop(myId)
    end)
    _setStatus("Daily ON")
    return true
end

function M.Stop()
    running = false
    M.SetEnabled(false)
    _setStatus("Daily OFF")
end

M.start = M.Start
M.stop = M.Stop

function M.IsRunning()
    return running == true
end

M.isRunning = M.IsRunning

G.AutoSellDaily = M
G.AutoSellDailyModule = M
_G.AutoSellDaily = M
_G.AutoSellDailyModule = M

return M
 end,                   required = false },
    { key = "SectionAutoSellDaily",    name = "Section Auto Sell Daily", factory = function() -- section_auto_sell_daily.lua — UI Auto Sell Daily Deal (tab Auto)

local G = (getgenv and getgenv()) or _G
local M = {}

local VALUE_SUFFIXES = {
    { "juta", 1e6 }, { "jt", 1e6 },
    { "ribu", 1e3 }, { "rb", 1e3 },
    { "dc", 1e33 }, { "no", 1e30 }, { "oc", 1e27 },
    { "sp", 1e24 }, { "sx", 1e21 },
    { "qi", 1e18 }, { "qn", 1e18 },
    { "qa", 1e15 }, { "qd", 1e15 },
    { "t", 1e12 }, { "b", 1e9 }, { "m", 1e6 }, { "k", 1e3 },
}

local function abbrev(n)
    n = tonumber(n) or 0
    if n <= 0 then return "0" end
    local units = {
        { 1e33, "Dc" }, { 1e30, "No" }, { 1e27, "Oc" },
        { 1e24, "Sp" }, { 1e21, "Sx" },
        { 1e18, "Qi" }, { 1e15, "Qa" },
        { 1e12, "T" }, { 1e9, "B" }, { 1e6, "M" }, { 1e3, "K" },
    }
    for _, u in ipairs(units) do
        if n >= u[1] then
            local v = n / u[1]
            if math.abs(v - math.floor(v + 0.5)) < 1e-6 then
                return string.format("%d%s", math.floor(v + 0.5), u[2])
            end
            return string.format("%.2f%s", v, u[2]):gsub("%.?0+([A-Za-z])", "%1")
        end
    end
    return tostring(math.floor(n + 0.5))
end

local function parseScaledValue(txt)
    txt = tostring(txt or ""):lower():gsub("%s+", ""):gsub(",", ".")
    if txt == "" then return nil end
    local sign = 1
    if txt:sub(1, 1) == "-" then
        sign = -1
        txt = txt:sub(2)
    end

    for _, pair in ipairs(VALUE_SUFFIXES) do
        local suf, mult = pair[1], pair[2]
        if #txt > #suf and txt:sub(-#suf) == suf then
            local numPart = txt:sub(1, -#suf - 1)
            local n = tonumber(numPart)
            if n then return n * mult * sign end
        end
    end

    local numPart, letters = txt:match("^([%d%.]+)([a-z]+)$")
    if numPart and letters and #letters >= 2 then
        local n = tonumber(numPart)
        if n then
            local idx = 0
            for i = 1, #letters do
                local c = letters:byte(i) - 96
                if c < 1 or c > 26 then
                    idx = nil
                    break
                end
                idx = idx * 26 + (c - 1)
            end
            if idx ~= nil then
                local exp = 63 + idx * 3
                return n * (10 ^ exp) * sign
            end
        end
    end

    local n = tonumber(txt)
    if n then return n * sign end
    return nil
end

local function formatRemainSec(sec)
    sec = math.max(0, math.floor(tonumber(sec) or 0))
    local h = sec // 3600
    local m = (sec % 3600) // 60
    local s = sec % 60
    if h > 0 then return string.format("%dh %02dm", h, m) end
    if m > 0 then return string.format("%dm %02ds", m, s) end
    return string.format("%ds", s)
end

function M.Register(ctx)
    if type(ctx) ~= "table" or type(ctx.ui) ~= "table" then return end

    local ui = ctx.ui
    local getAuto = ctx.getAuto
    local patchAuto = ctx.patchAuto
    local patchAutoOnly = ctx.patchAutoOnly
    local registerFlush = ctx.registerFlush

    local ST = getAuto("sellDaily")
    if type(ST) ~= "table" then ST = {} end
    if ST.minBackpackCount == nil then ST.minBackpackCount = 1 end
    if ST.minTotalValue == nil then ST.minTotalValue = 0 end
    ST.enabled = (ST.enabled == true)
    ST.autoUnfav = (ST.autoUnfav == true)

    local function snapshot()
        local api = G.__GAG2_SELL_DAILY_ENABLE_API or rawget(_G, "__GAG2_SELL_DAILY_ENABLE_API")
        if type(api) == "table" and type(api.get) == "function" then
            ST.enabled = (api.get() == true)
        end
        return {
            enabled = (ST.enabled == true),
            minBackpackCount = math.max(1, math.floor(tonumber(ST.minBackpackCount) or 1)),
            minTotalValue = math.max(0, tonumber(ST.minTotalValue) or 0),
            autoUnfav = (ST.autoUnfav == true),
        }
    end

    local function writeGlobals()
        local snap = snapshot()
        for k, v in pairs(snap) do ST[k] = v end
        G.AUTO_SELL_DAILY = snap
        _G.AUTO_SELL_DAILY = snap
        if type(patchAutoOnly) == "function" then
            patchAutoOnly("sellDaily", snap)
        end
    end

    local function syncModule()
        writeGlobals()
        local mod = G.AutoSellDaily or G.AutoSellDailyModule or rawget(_G, "AutoSellDaily")
        if type(mod) == "table" then
            if type(mod.SetConfig) == "function" then
                pcall(mod.SetConfig, mod, snapshot())
            elseif type(mod.setConfig) == "function" then
                pcall(mod.setConfig, mod, snapshot())
            end
            if snapshot().enabled then
                if type(mod.Start) == "function" then pcall(mod.Start, mod) end
            else
                if type(mod.Stop) == "function" then pcall(mod.Stop, mod) end
            end
        end
    end

    local function persist()
        writeGlobals()
        if type(patchAuto) == "function" then
            patchAuto("sellDaily", snapshot(), syncModule)
        else
            syncModule()
        end
    end

    G.__GAG2_PUSH_SELL_DAILY = writeGlobals
    _G.__GAG2_PUSH_SELL_DAILY = writeGlobals
    G.__GAG2_SYNC_AUTO_SELL_DAILY = syncModule
    _G.__GAG2_SYNC_AUTO_SELL_DAILY = syncModule

    if type(registerFlush) == "function" then
        registerFlush("sellDaily", writeGlobals)
    end

    writeGlobals()

    local function reasonLabel(reason, probe)
        reason = tostring(reason or "")
        if reason == "ok" then return "READY"
        elseif reason == "disabled" then return "OFF"
        elseif reason == "count" then return "WAIT COUNT"
        elseif reason == "value" then return "WAIT VALUE"
        elseif reason == "cooldown" then
            return "COOLDOWN " .. formatRemainSec(probe and probe.timeRemaining)
        elseif reason == "all_favorited" then return "ALL FAV"
        elseif reason == "no_deal" then return "UNAVAILABLE"
        end
        return reason ~= "" and string.upper(reason) or "?"
    end

    local function evalDaily()
        local mod = G.AutoSellDaily or G.AutoSellDailyModule or rawget(_G, "AutoSellDaily")
        if type(mod) ~= "table" or type(mod.Evaluate) ~= "function" then return nil end
        local ok, probe = pcall(mod.Evaluate, mod, { ignoreEnabled = true })
        if ok and type(probe) == "table" then
            G.__GAG2_SELL_DAILY_PROBE = probe
            _G.__GAG2_SELL_DAILY_PROBE = probe
            return probe
        end
        return nil
    end

    local function peerStockProbe()
        local cached = G.__GAG2_SELL_STOCK_PROBE or rawget(_G, "__GAG2_SELL_STOCK_PROBE")
        if type(cached) == "table" then return cached end
        return nil
    end

    local function statusText()
        local enabled = (ST.enabled == true)

        local probe = evalDaily()
        local bp = probe and tonumber(probe.backpackCount) or (tonumber(game:GetService("Players").LocalPlayer:GetAttribute("FruitCount")) or 0)
        local bpVal = probe and tonumber(probe.backpackValue) or 0
        local baseV = probe and tonumber(probe.baseValue) or 0
        local est = probe and tonumber(probe.estimate) or 0
        local favN = probe and tonumber(probe.favCount) or 0
        local reason = probe and probe.reason or "…"
        local state = enabled and reasonLabel(reason, probe) or "OFF"

        local vs = ""
        local stock = peerStockProbe()
        local stockOn = false
        do
            local smod = G.AutoSellStock or rawget(_G, "AutoSellStock")
            stockOn = type(smod) == "table" and type(smod.IsEnabled) == "function" and smod.IsEnabled(smod) == true
        end
        if stockOn and stock and probe and probe.ready == true and stock.ready == true then
            local sEst = tonumber(stock.estimate) or 0
            if sEst > est then
                vs = string.format(" · Stock better (%s)", abbrev(sEst))
            else
                vs = string.format(" · ahead of Stock (%s)", abbrev(sEst))
            end
        end

        local line1 = state
        if favN > 0 then
            line1 = string.format("%s · fav %d", state, favN)
        end
        local line2 = string.format("BP %d · %s · base %s → deal %s%s",
            bp, abbrev(bpVal), abbrev(baseV), abbrev(est), vs)
        return line1, line2
    end

    local body = ui:CreateSection("Auto Sell Daily Deal", false)

    local function bindStatusRow(titleLbl)
        if not titleLbl then return end
        titleLbl.TextTruncate = Enum.TextTruncate.AtEnd
        if titleLbl.Parent then
            for _, ch in ipairs(titleLbl.Parent:GetChildren()) do
                if ch:IsA("TextLabel") and ch ~= titleLbl then
                    ch.TextTruncate = Enum.TextTruncate.AtEnd
                end
            end
        end
    end

    local _, statusTitle = ui:CreateRowLabel(body, "…", "Loading daily status…", nil, "accent")
    bindStatusRow(statusTitle)

    local function setStatusLines(lineA, lineB)
        if not (statusTitle and statusTitle.Parent) then return end
        statusTitle.Text = lineA or ""
        for _, ch in ipairs(statusTitle.Parent:GetChildren()) do
            if ch:IsA("TextLabel") and ch ~= statusTitle then
                ch.Text = lineB or ""
                break
            end
        end
    end

    local statusBusy = false
    local function refreshStatus()
        if statusBusy then return end
        statusBusy = true
        task.spawn(function()
            local ok, l1, l2 = pcall(function()
                return statusText()
            end)
            if ok then
                setStatusLines(l1, l2)
            end
            statusBusy = false
        end)
    end

    local function scheduleStatus()
        task.defer(refreshStatus)
    end

    ui:CreateRowInput(
        body,
        "Min backpack count",
        tostring(tonumber(ST.minBackpackCount) or 1),
        function(txt)
            local n = tonumber(txt)
            if n == nil or n < 1 then return end
            ST.minBackpackCount = math.floor(n)
            persist()
            scheduleStatus()
        end,
        false
    )

    local _, setMinValue = ui:CreateRowInput(
        body,
        "Min backpack value (eg 1m 1b)",
        abbrev(tonumber(ST.minTotalValue) or 0),
        function(txt)
            local n = parseScaledValue(txt)
            if n == nil or n < 0 then return end
            ST.minTotalValue = n
            if type(setMinValue) == "function" then
                setMinValue(abbrev(n))
            end
            persist()
            scheduleStatus()
        end,
        false
    )

    ui:CreateRowToggle(
        body,
        "Auto unfav all",
        (ST.autoUnfav == true),
        function(isOn)
            ST.autoUnfav = (isOn == true)
            persist()
            scheduleStatus()
        end
    )

    local _, _, enableApi = ui:CreateRowToggle(
        body,
        "Enable",
        (ST.enabled == true),
        function(isOn)
            ST.enabled = (isOn == true)
            persist()
            scheduleStatus()
        end
    )
    G.__GAG2_SELL_DAILY_ENABLE_API = enableApi
    _G.__GAG2_SELL_DAILY_ENABLE_API = enableApi

    task.spawn(function()
        while body and body.Parent do
            task.wait(5)
            pcall(refreshStatus)
        end
    end)

    task.defer(function()
        syncModule()
        scheduleStatus()
    end)
end

G.SectionAutoSellDaily = M
_G.SectionAutoSellDaily = M

return M
 end,          required = false },
    { key = "AutoMergeEclipseBloom",   name = "Auto Merge Eclipse Bloom", factory = function() -- AutoMergeEclipseBloom.lua — Grow A Garden 2
-- Auto merge Sun Bloom + Moon Bloom → Eclipse Bloom via Networking.Garden.RequestMerge.

local Players           = game:GetService("Players")
local ReplicatedStorage = game:GetService("ReplicatedStorage")

local LP = Players.LocalPlayer
local G  = (getgenv and getgenv()) or _G
local M  = {}

M.ModuleVersion = "20260717d"

local LOOP_IDLE_SEC   = 1.0
local MERGE_SETTLE    = 0.85
local DEFAULT_DELAY   = 2
local DEFAULT_MAX     = 5
local DEFAULT_RANGE   = 25
local PLOT_CACHE_SEC  = 2
local PLANTS_CACHE_SEC = 1.5

local PAIR = {
    ["sunbloom"] = "moonbloom",
    ["moonbloom"] = "sunbloom",
}

local running = false
local loopId  = 0
local busy    = false
local lastStatus = "Idle"
local sessionMerged = 0 -- total merge sejak Enable (batas = max)
local lastProbe = {
    sun = 0,
    moon = 0,
    pairs = 0,
    reason = "idle",
}

local Networking
local MergeFlags
local RequestMergeRemote

local cachedPlot
local cachedPlotAt = 0
local cachedPlantsFolder
local cachedPlantsFolderAt = 0
local cachedPlantVisualizer

pcall(function()
    Networking = require(ReplicatedStorage.SharedModules.Networking)
    RequestMergeRemote = Networking.Garden and Networking.Garden.RequestMerge
end)

pcall(function()
    local sm = ReplicatedStorage:FindFirstChild("SharedModules")
    local flags = sm and sm:FindFirstChild("Flags")
    local inst = flags and flags:FindFirstChild("MergeFlags")
    if not inst and sm then
        inst = sm:FindFirstChild("MergeFlags")
    end
    if inst then
        MergeFlags = require(inst)
    end
end)

local function _defaults()
    return {
        enabled = false,
        delay   = DEFAULT_DELAY,
        max     = DEFAULT_MAX,
    }
end

local function _setStatus(msg)
    lastStatus = tostring(msg or "")
    G.AUTO_MERGE_ECLIPSE_STATUS = lastStatus
    _G.AUTO_MERGE_ECLIPSE_STATUS = lastStatus
end

local function _publish(cfg)
    G.AUTO_MERGE_ECLIPSE = cfg
    _G.AUTO_MERGE_ECLIPSE = cfg
end

local function _getMainCfg()
    local MAIN = rawget(_G, "MAIN") or G.MAIN
    if type(MAIN) ~= "table" then return nil end
    MAIN.auto = MAIN.auto or {}
    if type(MAIN.auto.mergeEclipse) ~= "table" then
        MAIN.auto.mergeEclipse = _defaults()
    end
    return MAIN.auto.mergeEclipse
end

local function _writeMain(patch)
    local MAIN = rawget(_G, "MAIN") or G.MAIN
    if type(MAIN) ~= "table" then return end
    MAIN.auto = MAIN.auto or {}
    MAIN.auto.mergeEclipse = MAIN.auto.mergeEclipse or _defaults()
    for k, v in pairs(patch) do
        MAIN.auto.mergeEclipse[k] = v
    end
    G.MAIN = MAIN
    _G.MAIN = MAIN
end

function M.GetConfig()
    local st = _getMainCfg() or {}
    local g = G.AUTO_MERGE_ECLIPSE or rawget(_G, "AUTO_MERGE_ECLIPSE")
    if type(g) == "table" then
        for k, v in pairs(g) do
            if st[k] == nil then st[k] = v end
        end
    end

    local delay = tonumber(st.delay)
    if delay == nil then delay = DEFAULT_DELAY end
    if delay < 0 then delay = 0 end

    local maxN = tonumber(st.max)
    if maxN == nil then maxN = DEFAULT_MAX end
    if maxN < 0 then maxN = 0 end
    maxN = math.floor(maxN)

    local cfg = {
        enabled = (st.enabled == true),
        delay   = delay,
        max     = maxN,
    }
    _publish(cfg)
    return cfg
end

function M.SetConfig(cfg)
    if type(cfg) ~= "table" then return M.GetConfig() end
    local cur = M.GetConfig()
    if cfg.enabled ~= nil then cur.enabled = (cfg.enabled == true) end
    if cfg.delay ~= nil then
        local n = tonumber(cfg.delay)
        if n ~= nil and n >= 0 then cur.delay = n end
    end
    if cfg.max ~= nil then
        local n = tonumber(cfg.max)
        if n ~= nil and n >= 0 then cur.max = math.floor(n) end
    end
    _writeMain(cur)
    _publish(cur)
    return cur
end

function M.IsEnabled()
    local api = G.__GAG2_MERGE_ECLIPSE_ENABLE_API or rawget(_G, "__GAG2_MERGE_ECLIPSE_ENABLE_API")
    if type(api) == "table" and type(api.get) == "function" then
        local ok, v = pcall(api.get, api)
        if ok then return v == true end
    end
    return M.GetConfig().enabled == true
end

function M.GetStatusText()
    return lastStatus
end

function M.GetProbe()
    return lastProbe
end

function M.GetSessionMerged()
    return sessionMerged
end

local function _configuredMax()
    return math.floor(tonumber(M.GetConfig().max) or 0)
end

local function _maxLabel(maxN)
    maxN = tonumber(maxN) or 0
    if maxN > 0 then return tostring(math.floor(maxN)) end
    return "∞"
end

local function _statusOk(sunN, moonN)
    return string.format(
        "OK %d/%s · S%d M%d",
        sessionMerged,
        _maxLabel(_configuredMax()),
        math.max(0, tonumber(sunN) or 0),
        math.max(0, tonumber(moonN) or 0)
    )
end

local function _hitMax(maxN)
    maxN = tonumber(maxN)
    if maxN == nil then maxN = _configuredMax() end
    return maxN > 0 and sessionMerged >= maxN
end

local function _normName(s)
    return string.lower((tostring(s or ""):gsub("%s+", "")))
end

local function _plantDisplayName(plant)
    if not plant then return "" end
    local AP = G.AutoPlot or G.AutoPlotModule
    if type(AP) == "table" and type(AP.GetPlantDisplayName) == "function" then
        local ok, name = pcall(AP.GetPlantDisplayName, AP, plant)
        if ok and type(name) == "string" and name ~= "" then
            return name
        end
    end
    local AT = G.AutoTrowel or G.AutoTrowelModule
    if type(AT) == "table" and type(AT.GetPlantDisplayName) == "function" then
        local ok, name = pcall(AT.GetPlantDisplayName, AT, plant)
        if ok and type(name) == "string" and name ~= "" then
            return name
        end
    end
    return tostring(
        plant:GetAttribute("SeedName")
            or plant:GetAttribute("PlantName")
            or plant:GetAttribute("ConfigPathName")
            or plant.Name
            or ""
    )
end

local function _isBloomKind(plant)
    local key = _normName(_plantDisplayName(plant))
    if PAIR[key] then return key end
    -- fallback: model name contains sunbloom / moonbloom
    local raw = _normName(plant and plant.Name)
    if raw:find("sunbloom", 1, true) then return "sunbloom" end
    if raw:find("moonbloom", 1, true) then return "moonbloom" end
    return nil
end

local function _isGrown(plant)
    local age = tonumber(plant:GetAttribute("Age"))
    local maxAge = tonumber(plant:GetAttribute("MaxAge"))
    if age == nil or maxAge == nil then return false end
    return age >= maxAge
end

local function _isPotted(plant)
    if plant:GetAttribute("IsPotted") == true then return true end
    local ok, sync = pcall(function()
        local ps = LP:FindFirstChild("PlayerScripts")
        local controllers = ps and ps:FindFirstChild("Controllers")
        local mod = controllers and controllers:FindFirstChild("GardenSyncController")
        if not mod then return nil end
        local ctrl = require(mod)
        local plantId = tostring(plant.Name)
        if type(ctrl.GetPlant) == "function" then
            return ctrl:GetPlant(LP.UserId, plantId)
        end
        return nil
    end)
    if ok and type(sync) == "table" and sync.IsPotted == true then
        return true
    end
    return false
end

local function _plantPos(plant)
    if not plant then return nil end
    if plant:IsA("Model") then
        local ok, pivot = pcall(function()
            return plant:GetPivot()
        end)
        if ok and pivot then
            return pivot.Position
        end
        if plant.PrimaryPart then
            return plant.PrimaryPart.Position
        end
    end
    if plant:IsA("BasePart") then
        return plant.Position
    end
    local part = plant:FindFirstChildWhichIsA("BasePart", true)
    return part and part.Position or nil
end

local function _extractPlantId(plant)
    if not plant then return nil end
    local attr = plant:GetAttribute("Id")
        or plant:GetAttribute("PlantId")
        or plant:GetAttribute("UUID")
        or plant:GetAttribute("Uuid")
    if attr ~= nil and tostring(attr) ~= "" then
        return tostring(attr)
    end
    local name = tostring(plant.Name or "")
    if name == "" then return nil end
    return name:match("^%d+_(.+)$") or name
end

local function _mergeEnabledByGame()
    if type(MergeFlags) ~= "table" then return true end
    if MergeFlags.Enabled == false then return false end
    return true
end

local function _rangeStuds()
    if type(MergeFlags) == "table" then
        local n = tonumber(MergeFlags.RangeStuds)
        if n and n > 0 then return n end
    end
    return DEFAULT_RANGE
end

local function _plotOwnedByLocal(plot)
    if not plot then return false end
    local uid, name = LP.UserId, LP.Name
    local function match(v)
        if v == nil then return false end
        return v == uid or v == name or tostring(v) == tostring(uid) or tostring(v) == name
    end
    return match(plot:GetAttribute("OwnerId"))
        or match(plot:GetAttribute("Owner"))
        or match(plot:GetAttribute("OwnerUserId"))
        or match(plot:GetAttribute("UserId"))
end

local function _getPlayerPlot()
    local now = os.clock()
    if cachedPlot and cachedPlot.Parent and (now - cachedPlotAt) <= PLOT_CACHE_SEC then
        return cachedPlot
    end
    local gardens = workspace:FindFirstChild("Gardens")
    if not gardens then
        cachedPlot = nil
        cachedPlotAt = now
        return nil
    end
    local plotId = LP:GetAttribute("PlotId")
    if plotId ~= nil then
        local plot = gardens:FindFirstChild("Plot" .. tostring(plotId))
        if plot then
            cachedPlot = plot
            cachedPlotAt = now
            return plot
        end
    end
    for _, plot in ipairs(gardens:GetChildren()) do
        if _plotOwnedByLocal(plot) then
            cachedPlot = plot
            cachedPlotAt = now
            return plot
        end
    end
    cachedPlot = nil
    cachedPlotAt = now
    return nil
end

local function _getPlantVisualizer()
    if cachedPlantVisualizer then return cachedPlantVisualizer end
    local ok, vis = pcall(function()
        local ps = LP:FindFirstChild("PlayerScripts")
        local controllers = ps and ps:FindFirstChild("Controllers")
        local mod = controllers and controllers:FindFirstChild("PlantVisualizerController")
        if not mod then return nil end
        return require(mod)
    end)
    if ok and type(vis) == "table" then
        cachedPlantVisualizer = vis
        return vis
    end
    return nil
end

local function _getPlantsFolder()
    local now = os.clock()
    if cachedPlantsFolder and cachedPlantsFolder.Parent
        and (now - cachedPlantsFolderAt) <= PLANTS_CACHE_SEC then
        return cachedPlantsFolder
    end

    local folder = nil
    local vis = _getPlantVisualizer()
    if vis and type(vis.GetPlantsFolder) == "function" then
        local ok, f = pcall(vis.GetPlantsFolder, vis, LP.UserId)
        if ok and f then folder = f end
    end
    if not folder then
        local plot = _getPlayerPlot()
        folder = plot and plot:FindFirstChild("Plants")
    end

    cachedPlantsFolder = folder
    cachedPlantsFolderAt = now
    return folder
end

local function _ensureRemote()
    if RequestMergeRemote and type(RequestMergeRemote.Fire) == "function" then
        return RequestMergeRemote
    end
    pcall(function()
        Networking = require(ReplicatedStorage.SharedModules.Networking)
        RequestMergeRemote = Networking.Garden and Networking.Garden.RequestMerge
    end)
    return RequestMergeRemote
end

local function _listEligible()
    local folder = _getPlantsFolder()
    local suns, moons = {}, {}
    if not folder then
        return suns, moons
    end
    for _, plant in ipairs(folder:GetChildren()) do
        if plant:IsA("Model") then
            local kind = _isBloomKind(plant)
            if kind and _isGrown(plant) and not _isPotted(plant) then
                local pos = _plantPos(plant)
                if pos then
                    local entry = {
                        plant = plant,
                        id = _extractPlantId(plant),
                        pos = pos,
                        kind = kind,
                    }
                    if kind == "sunbloom" then
                        suns[#suns + 1] = entry
                    else
                        moons[#moons + 1] = entry
                    end
                end
            end
        end
    end
    return suns, moons
end

local function _findBestPair(suns, moons)
    local range = _rangeStuds()
    local rangeSq = range * range
    local best, bestDist
    for _, a in ipairs(suns) do
        for _, b in ipairs(moons) do
            local d = (a.pos - b.pos)
            local distSq = d.X * d.X + d.Y * d.Y + d.Z * d.Z
            if distSq <= rangeSq and (bestDist == nil or distSq < bestDist) then
                bestDist = distSq
                best = { a = a, b = b, dist = math.sqrt(distSq) }
            end
        end
    end
    return best
end

function M.Evaluate(opts)
    opts = type(opts) == "table" and opts or {}
    local cfg = M.GetConfig()
    local suns, moons = _listEligible()
    local pair = _findBestPair(suns, moons)
    local reason = "ok"
    local ready = true

    if opts.ignoreEnabled ~= true and not cfg.enabled then
        reason = "disabled"
        ready = false
    elseif not _mergeEnabledByGame() then
        reason = "game_disabled"
        ready = false
    elseif not _ensureRemote() then
        reason = "no_remote"
        ready = false
    elseif #suns < 1 or #moons < 1 then
        reason = "need_pair"
        ready = false
    elseif not pair then
        reason = "out_of_range"
        ready = false
    end

    lastProbe = {
        sun = #suns,
        moon = #moons,
        pairs = pair and 1 or 0,
        ready = ready,
        reason = reason,
        range = _rangeStuds(),
        dist = pair and pair.dist or nil,
    }
    return lastProbe, pair, suns, moons
end

local function _fireMergeArgs(arg1, arg2)
    local remote = _ensureRemote()
    if not remote or type(remote.Fire) ~= "function" then
        return false, "no_remote"
    end
    local ok, err = pcall(function()
        remote:Fire(arg1, arg2)
    end)
    if ok then return true end
    return false, err
end

-- Satu attempt saja — Fire OK ≠ merge OK (verifikasi di RunOnce)
local function _fireMerge(a, b, reverse)
    local idA = a.id or _extractPlantId(a.plant)
    local idB = b.id or _extractPlantId(b.plant)
    if idA and idB then
        if reverse then
            return _fireMergeArgs(idB, idA)
        end
        return _fireMergeArgs(idA, idB)
    end
    if a.plant and b.plant then
        if reverse then
            return _fireMergeArgs(b.plant, a.plant)
        end
        return _fireMergeArgs(a.plant, b.plant)
    end
    return false, "no_ids"
end

-- Merge sukses = Sun ATAU Moon eligible berkurang (bukan sekadar Fire OK)
local function _mergeActuallyWorked(beforeSun, beforeMoon, after, plantA, plantB)
    local afterSun = tonumber(after and after.sun) or 0
    local afterMoon = tonumber(after and after.moon) or 0
    if afterSun < beforeSun or afterMoon < beforeMoon then
        return true
    end
    -- Plant model hilang dari plot
    local aGone = not (plantA and plantA.Parent)
    local bGone = not (plantB and plantB.Parent)
    if aGone or bGone then
        return true
    end
    return false
end

function M.RunOnce(opts)
    if busy then return false, "busy" end
    local probe, pair = M.Evaluate(opts)
    if not probe.ready or not pair then
        if probe.reason == "disabled" then
            _setStatus("OFF")
        elseif probe.reason == "need_pair" then
            _setStatus(string.format("Wait pair · S%d M%d", probe.sun, probe.moon))
        elseif probe.reason == "out_of_range" then
            _setStatus(string.format("Out of range · S%d M%d", probe.sun, probe.moon))
        elseif probe.reason == "game_disabled" then
            _setStatus("Merge disabled (game)")
        else
            _setStatus(tostring(probe.reason))
        end
        return false, probe.reason, probe
    end

    local maxN = _configuredMax()
    if _hitMax(maxN) then
        _setStatus(string.format(
            "Max reached · %d/%d · S%d M%d",
            sessionMerged,
            maxN,
            probe.sun,
            probe.moon
        ))
        return false, "max_reached", probe
    end

    busy = true
    local beforeSun = tonumber(probe.sun) or 0
    local beforeMoon = tonumber(probe.moon) or 0
    local plantA = pair.a and pair.a.plant
    local plantB = pair.b and pair.b.plant
    _setStatus(string.format(
        "Merging %d/%s · S%d M%d",
        sessionMerged + 1,
        _maxLabel(maxN),
        beforeSun,
        beforeMoon
    ))
    local function _verifyAfterFire()
        task.wait(MERGE_SETTLE)
        local after = select(1, M.Evaluate({ ignoreEnabled = true }))
        if not _mergeActuallyWorked(beforeSun, beforeMoon, after, plantA, plantB) then
            task.wait(0.45)
            after = select(1, M.Evaluate({ ignoreEnabled = true }))
        end
        return after
    end

    local ok, err = _fireMerge(pair.a, pair.b, false)
    if not ok then
        _setStatus("Fail: " .. tostring(err))
        busy = false
        return false, err, probe
    end

    local after = _verifyAfterFire()
    if not _mergeActuallyWorked(beforeSun, beforeMoon, after, plantA, plantB) then
        -- Coba urutan argumen terbalik sekali (tanpa naikkan counter)
        local ok2 = _fireMerge(pair.a, pair.b, true)
        if ok2 then
            after = _verifyAfterFire()
        end
    end

    if _mergeActuallyWorked(beforeSun, beforeMoon, after, plantA, plantB) then
        sessionMerged += 1 -- hanya kalau S/M benar-benar berkurang
        if _hitMax(maxN) then
            _setStatus(string.format(
                "Max reached · %d/%d · S%d M%d",
                sessionMerged,
                maxN,
                tonumber(after and after.sun) or 0,
                tonumber(after and after.moon) or 0
            ))
        else
            _setStatus(_statusOk(after and after.sun, after and after.moon))
        end
        busy = false
        return true, "ok", after or probe
    end

    _setStatus(string.format(
        "No merge · %d/%s · S%d M%d",
        sessionMerged,
        _maxLabel(maxN),
        tonumber(after and after.sun) or beforeSun,
        tonumber(after and after.moon) or beforeMoon
    ))
    busy = false
    return false, "no_effect", after or probe
end

M.runOnce = M.RunOnce

local function _loop(myId)
    while running and loopId == myId do
        local cfg = M.GetConfig()
        if not cfg.enabled then
            _setStatus("OFF")
            task.wait(LOOP_IDLE_SEC)
        elseif _hitMax(cfg.max) then
            local probe = lastProbe
            _setStatus(string.format(
                "Max reached · %d/%d · S%d M%d",
                sessionMerged,
                math.floor(tonumber(cfg.max) or 0),
                tonumber(probe and probe.sun) or 0,
                tonumber(probe and probe.moon) or 0
            ))
            task.wait(LOOP_IDLE_SEC)
        else
            local ok, reason = M.RunOnce()
            if ok then
                local delay = tonumber(M.GetConfig().delay) or DEFAULT_DELAY
                if delay > 0 then
                    task.wait(delay)
                else
                    task.wait()
                end
            elseif reason == "max_reached" then
                task.wait(LOOP_IDLE_SEC)
            else
                task.wait(LOOP_IDLE_SEC)
            end
        end
    end
end

function M.Start()
    M.SetConfig({ enabled = true })
    if running then return true end
    running = true
    sessionMerged = 0 -- reset counter tiap Enable
    loopId += 1
    local myId = loopId
    task.spawn(function()
        _loop(myId)
    end)
    _setStatus(string.format("ON · 0/%s", _maxLabel(_configuredMax())))
    return true
end

function M.Stop()
    running = false
    M.SetConfig({ enabled = false })
    _setStatus("OFF")
end

M.start = M.Start
M.stop = M.Stop

function M.IsRunning()
    return running == true
end

M.isRunning = M.IsRunning

function M.SetEnabled(on)
    if on then
        return M.Start()
    end
    M.Stop()
    return true
end

G.AutoMergeEclipseBloom = M
G.AutoMergeEclipseBloomModule = M
_G.AutoMergeEclipseBloom = M
_G.AutoMergeEclipseBloomModule = M

return M
 end,          required = false },
    { key = "SectionAutoMergeEclipseBloom", name = "Section Auto Merge Eclipse Bloom", factory = function() -- section_auto_merge_eclipse_bloom.lua — UI Auto Merge Eclipse Bloom (tab Auto)

local G = (getgenv and getgenv()) or _G
local M = {}

function M.Register(ctx)
    if type(ctx) ~= "table" or type(ctx.ui) ~= "table" then return end

    local ui = ctx.ui
    local getAuto = ctx.getAuto
    local patchAuto = ctx.patchAuto
    local patchAutoOnly = ctx.patchAutoOnly
    local registerFlush = ctx.registerFlush

    local ST = getAuto("mergeEclipse")
    if type(ST) ~= "table" then ST = {} end
    ST.enabled = (ST.enabled == true)
    if ST.delay == nil then ST.delay = 2 end
    if ST.max == nil then ST.max = 5 end

    local function snapshot()
        local api = G.__GAG2_MERGE_ECLIPSE_ENABLE_API or rawget(_G, "__GAG2_MERGE_ECLIPSE_ENABLE_API")
        if type(api) == "table" and type(api.get) == "function" then
            ST.enabled = (api.get() == true)
        end
        local delay = tonumber(ST.delay)
        if delay == nil or delay < 0 then delay = 2 end
        local maxN = tonumber(ST.max)
        if maxN == nil or maxN < 0 then maxN = 5 end
        return {
            enabled = (ST.enabled == true),
            delay = delay,
            max = math.floor(maxN),
        }
    end

    local function writeGlobals()
        local snap = snapshot()
        for k, v in pairs(snap) do ST[k] = v end
        G.AUTO_MERGE_ECLIPSE = snap
        _G.AUTO_MERGE_ECLIPSE = snap
        if type(patchAutoOnly) == "function" then
            patchAutoOnly("mergeEclipse", snap)
        end
    end

    local function syncModule()
        writeGlobals()
        local mod = G.AutoMergeEclipseBloom or G.AutoMergeEclipseBloomModule or rawget(_G, "AutoMergeEclipseBloom")
        if type(mod) ~= "table" then return end
        if type(mod.SetConfig) == "function" then
            pcall(mod.SetConfig, mod, snapshot())
        end
        if snapshot().enabled then
            if type(mod.Start) == "function" then
                pcall(mod.Start, mod)
            elseif type(mod.SetEnabled) == "function" then
                pcall(mod.SetEnabled, mod, true)
            end
        else
            if type(mod.Stop) == "function" then
                pcall(mod.Stop, mod)
            elseif type(mod.SetEnabled) == "function" then
                pcall(mod.SetEnabled, mod, false)
            end
        end
    end

    local function persist()
        writeGlobals()
        if type(patchAuto) == "function" then
            patchAuto("mergeEclipse", snapshot(), syncModule)
        else
            syncModule()
        end
    end

    G.__GAG2_PUSH_MERGE_ECLIPSE = writeGlobals
    _G.__GAG2_PUSH_MERGE_ECLIPSE = writeGlobals
    G.__GAG2_SYNC_AUTO_MERGE_ECLIPSE = syncModule
    _G.__GAG2_SYNC_AUTO_MERGE_ECLIPSE = syncModule

    if type(registerFlush) == "function" then
        registerFlush("mergeEclipse", writeGlobals)
    end

    writeGlobals()

    local body = ui:CreateSection("Auto Merge Eclipse Bloom", false)

    local statusLabel
    local _, statusLbl = ui:CreateRowLabel(body, "Status: Idle", nil, 1, "accent")
    statusLabel = statusLbl

    local function refreshStatus()
        if not (statusLabel and statusLabel.Parent) then return end
        statusLabel.TextTruncate = Enum.TextTruncate.AtEnd
        local mod = G.AutoMergeEclipseBloom or G.AutoMergeEclipseBloomModule or rawget(_G, "AutoMergeEclipseBloom")
        if not ST.enabled then
            statusLabel.Text = "Status: OFF"
            return
        end
        if type(mod) ~= "table" then
            statusLabel.Text = "Status: Module not loaded"
            return
        end

        -- Module status already includes Sun/Moon counts — jangan append lagi.
        local txt = "Running..."
        if type(mod.GetStatusText) == "function" then
            local ok, s = pcall(mod.GetStatusText, mod)
            if ok and type(s) == "string" and s ~= "" then
                txt = s
            end
        end
        statusLabel.Text = "Status: " .. tostring(txt)
    end

    ui:CreateRowInput(
        body,
        "Delay (sec)",
        tostring(tonumber(ST.delay) or 2),
        function(text)
            local n = tonumber(text)
            if n == nil or n < 0 then return end
            if n > 0 and n < 0.1 then n = 0.1 end
            ST.delay = n
            persist()
            task.defer(refreshStatus)
        end,
        false
    )

    ui:CreateRowInput(
        body,
        "Max merges (0 = unlimited)",
        tostring(math.floor(tonumber(ST.max) or 5)),
        function(text)
            local n = tonumber(text)
            if n == nil or n < 0 then return end
            ST.max = math.floor(n)
            persist()
            task.defer(refreshStatus)
        end,
        false
    )

    local _, _, enableApi = ui:CreateRowToggle(
        body,
        "Enable",
        (ST.enabled == true),
        function(isOn)
            ST.enabled = (isOn == true)
            persist()
            task.defer(refreshStatus)
        end
    )
    G.__GAG2_MERGE_ECLIPSE_ENABLE_API = enableApi
    _G.__GAG2_MERGE_ECLIPSE_ENABLE_API = enableApi

    task.spawn(function()
        while body and body.Parent do
            task.wait(2)
            pcall(refreshStatus)
        end
    end)

    task.defer(function()
        syncModule()
        refreshStatus()
    end)
end

G.SectionAutoMergeEclipseBloom = M
_G.SectionAutoMergeEclipseBloom = M

return M
 end, required = false },
    { key = "AutoHopServer",           name = "Auto Hop Server",         factory = function() -- AutoHopServer.lua — Grow A Garden 2
-- Adapted from auto_snipe_hop (NodeHub Market)
-- ✅ 1 Hop Session (serial attempts, no storm)
-- ✅ Anti IsTeleporting spam (lock window)
-- ✅ If target dead/full -> mark & try next candidate
-- ✅ TeleportData confirm -> push visited (persist)
-- ✅ PRE-HOP: mark current server JobId to visited BEFORE building candidates (STATE + FILE)
-- ✅ Candidates filter uses visited from STATE + FILE cache
-- ✅ If visited reached diffServers -> clear visited (STATE + FILE) + invalidate cache ts
-- ✅ Cache candidates to FILE per username + (placeId,targetPlayers,diffServers) to reduce 429
-- ✅ 429 backoff -> stop scan and rely on cache
-- ✅ Works with PSReconnect:HopToServer (keeps QTP gating). Fallback to TeleportToPlaceInstance if needed.

local M = {}

----------------------------------------------------------------
-- Services
----------------------------------------------------------------
local Players         = game:GetService("Players")
local TeleportService = game:GetService("TeleportService")
local HttpService     = game:GetService("HttpService")

local LP = Players.LocalPlayer

local function getLP()
    return Players.LocalPlayer or LP
end

----------------------------------------------------------------
-- Runtime status (for UI)
----------------------------------------------------------------
local _lastStatus = "idle"
local _lastSessionErr = nil
local _lastScanPages = 0
local _lastScanServers = 0
local _debug = false
local function dprint(...)
    if not _debug then return end
    print("[GAG2-AutoHop]", ...)
end

local function now() return os.clock() end
local function low(s) return string.lower(tostring(s or "")) end

----------------------------------------------------------------
-- Utils
----------------------------------------------------------------
local function clampNum(v, minv, maxv, fallback)
    local n = tonumber(v)
    if n == nil then return fallback end
    if minv ~= nil and n < minv then n = minv end
    if maxv ~= nil and n > maxv then n = maxv end
    return n
end

local function isArray(t)
    return type(t) == "table" and rawget(t, 1) ~= nil
end

local function ensureArray(t)
    if type(t) ~= "table" then return {} end
    if isArray(t) then return t end
    return {}
end

local SORT_SPLIT_TARGET = 4
local GAME_SERVER_MAX   = 8
local HOP_CURRENT_PLAYER_MIN     = 1
local HOP_CURRENT_PLAYER_DEFAULT = 1
local HOP_TELEPORT_DELAY_MIN     = 10
local HOP_TELEPORT_DELAY_DEFAULT = 10

local function clampCurrentPlayers(v)
    return clampNum(v, HOP_CURRENT_PLAYER_MIN, 100, HOP_CURRENT_PLAYER_DEFAULT)
end

local function clampTeleportDelay(v)
    return clampNum(v, HOP_TELEPORT_DELAY_MIN, 600, HOP_TELEPORT_DELAY_DEFAULT)
end

-- Auto-adapt: bandingkan Current Player Max vs Target Server
-- current > target  -> server ramai, cari lebih sepi (Asc)
-- current < target  -> server sepi, cari lebih ramai (Desc)
local function getHopMode(currentPlayers, targetPlayers)
    currentPlayers = clampCurrentPlayers(currentPlayers)
    targetPlayers = clampNum(targetPlayers, 1, 100, 1)
    if currentPlayers > targetPlayers then
        return "leave_crowded"
    end
    if currentPlayers < targetPlayers then
        return "leave_quiet"
    end
    return "balanced"
end

local function getSortOrdersForHop(currentPlayers, targetPlayers)
    local mode = getHopMode(currentPlayers, targetPlayers)
    if mode == "leave_crowded" then
        return "Asc", "Desc"
    elseif mode == "leave_quiet" then
        return "Desc", "Asc"
    end
    targetPlayers = clampNum(targetPlayers, 1, 100, 1)
    if targetPlayers <= SORT_SPLIT_TARGET then
        return "Asc", "Desc"
    end
    return "Desc", "Asc"
end

local function preferHigherPlaying(currentPlayers, targetPlayers)
    return getHopMode(currentPlayers, targetPlayers) == "leave_quiet"
end

local function getScanPagesForHop(currentPlayers, targetPlayers, isFallback)
    targetPlayers = clampNum(targetPlayers, 1, 100, 1)
    currentPlayers = clampCurrentPlayers(currentPlayers)
    local gap = math.abs(currentPlayers - targetPlayers)
    local base
    if getHopMode(currentPlayers, targetPlayers) == "leave_crowded" and targetPlayers <= SORT_SPLIT_TARGET then
        base = isFallback and 6 or 10
    else
        base = isFallback and 8 or 12
    end
    if gap >= 5 then
        base += isFallback and 2 or 4
    end
    return base
end

local function getHopTriggerHint(currentPlayers, targetPlayers)
    currentPlayers = clampCurrentPlayers(currentPlayers)
    targetPlayers = clampNum(targetPlayers, 1, 100, 1)
    local mode = getHopMode(currentPlayers, targetPlayers)
    if mode == "leave_crowded" then
        return "Hop when players >= " .. currentPlayers .. " (target ~" .. targetPlayers .. ")"
    elseif mode == "leave_quiet" then
        return "Hop when players <= " .. currentPlayers .. " (target ~" .. targetPlayers .. ")"
    end
    return "Hop when players >= " .. currentPlayers
end

----------------------------------------------------------------
-- FILE CACHE (reduce 429)
----------------------------------------------------------------
local FS_OK = (type(readfile)=="function" and type(writefile)=="function" and type(isfile)=="function")

local function ensureFolder(path)
    if type(makefolder) ~= "function" then return end
    if type(isfolder) == "function" and isfolder(path) then return end
    local parts = {}
    for seg in tostring(path):gmatch("[^/]+") do
        parts[#parts+1] = seg
        local p = table.concat(parts, "/")
        if type(isfolder) ~= "function" or not isfolder(p) then
            pcall(function() makefolder(p) end)
        end
    end
end

local CACHE_DIR = "growagarden2"

local function safeCacheUserName(s)
    s = tostring(s or "player")
    s = s:gsub("[^%w%-_.]", "_")
    s = s:gsub("_+", "_")
    return s:sub(1, 48)
end

local function getCacheFile()
    local lp = getLP()
    local user = (lp and lp.Name) or "player"
    return CACHE_DIR .. "/autohop_cache_" .. safeCacheUserName(user) .. ".json"
end

local function safeJsonDecode(s)
    local ok, t = pcall(function() return HttpService:JSONDecode(s) end)
    if ok and type(t) == "table" then return t end
    return nil
end

local function safeJsonEncode(t)
    local ok, s = pcall(function() return HttpService:JSONEncode(t) end)
    if ok and type(s) == "string" then return s end
    return nil
end

local function readCacheRoot()
    if not FS_OK then return {} end
    local cacheFile = getCacheFile()
    if not isfile(cacheFile) then return {} end
    local ok, content = pcall(function() return readfile(cacheFile) end)
    if not ok or type(content) ~= "string" then return {} end
    return safeJsonDecode(content) or {}
end

local function writeCacheRoot(root)
    if not FS_OK then return end
    ensureFolder(CACHE_DIR)
    local s = safeJsonEncode(root)
    if not s then return end
    pcall(function() writefile(getCacheFile(), s) end)
end

local function makeCacheKey(placeId, currentPlayers, targetPlayers, diffServers)
    currentPlayers = clampCurrentPlayers(currentPlayers)
    targetPlayers = clampNum(targetPlayers, 1, 100, 1)
    diffServers = clampNum(diffServers, 1, 200, 5)
    local primary = select(1, getSortOrdersForHop(currentPlayers, targetPlayers))
    return tostring(placeId)
        .. "|cur=" .. tostring(currentPlayers)
        .. "|tp=" .. tostring(targetPlayers)
        .. "|diff=" .. tostring(diffServers)
        .. "|sort=" .. primary
end

-- root[key] = { ts=os.time(), candidates={...}, visited={...} }
local function cacheLoad(placeId, currentPlayers, targetPlayers, diffServers)
    local root = readCacheRoot()
    local key  = makeCacheKey(placeId, currentPlayers, targetPlayers, diffServers)
    local rec  = (type(root[key])=="table") and root[key] or {}
    return root, key, rec
end

local function cacheSave(placeId, currentPlayers, targetPlayers, diffServers, patch)
    local root, key, rec = cacheLoad(placeId, currentPlayers, targetPlayers, diffServers)
    rec = (type(rec)=="table") and rec or {}
    patch = (type(patch)=="table") and patch or {}
    for k,v in pairs(patch) do rec[k] = v end
    root[key] = rec
    writeCacheRoot(root)
end

local function cacheGetCandidates(placeId, currentPlayers, targetPlayers, diffServers, maxAgeSec)
    maxAgeSec = tonumber(maxAgeSec) or 900
    local _, _, rec = cacheLoad(placeId, currentPlayers, targetPlayers, diffServers)
    local ts  = tonumber(rec.ts) or 0
    local arr = rec.candidates
    if type(arr) ~= "table" then return nil, "no_cache" end
    local age = os.time() - ts
    if age > maxAgeSec then
        return ensureArray(arr), "stale_cache"
    end
    return ensureArray(arr), "fresh_cache"
end

local function cacheSetCandidates(placeId, currentPlayers, targetPlayers, diffServers, candidates)
    candidates = ensureArray(candidates)
    cacheSave(placeId, currentPlayers, targetPlayers, diffServers, {
        ts = os.time(),
        candidates = candidates,
    })
end

local function cacheGetVisited(placeId, currentPlayers, targetPlayers, diffServers)
    local _, _, rec = cacheLoad(placeId, currentPlayers, targetPlayers, diffServers)
    local v = rec.visited
    if type(v) ~= "table" then return {} end
    return ensureArray(v)
end

local function cacheSetVisited(placeId, currentPlayers, targetPlayers, diffServers, visitedArr)
    visitedArr = ensureArray(visitedArr)
    cacheSave(placeId, currentPlayers, targetPlayers, diffServers, {
        visited = visitedArr,
    })
end

----------------------------------------------------------------
-- State read
----------------------------------------------------------------
local function _persistState()
    local G = (getgenv and getgenv()) or _G
    if G.__GAG2_RESETTING == true then return end

    local saveVisited = G.__GAG2_SAVE_AUTO_HOP_VISITED or rawget(_G, "__GAG2_SAVE_AUTO_HOP_VISITED")
    if type(saveVisited) == "function" then
        local visited = {}
        local main = G.MAIN or rawget(_G, "MAIN")
        if type(main) == "table" and type(main.misc) == "table"
            and type(main.misc.rejoin) == "table"
            and type(main.misc.rejoin.auto_hop) == "table"
            and type(main.misc.rejoin.auto_hop.visited) == "table" then
            visited = main.misc.rejoin.auto_hop.visited
        end
        task.defer(function()
            pcall(saveVisited, visited)
        end)
        return
    end

    if type(G.__GAG2_AUTO_SAVE) == "function" then
        task.defer(function() pcall(G.__GAG2_AUTO_SAVE) end)
    end
end

----------------------------------------------------------------
-- State read (GAG2 — MAIN.misc.rejoin.auto_hop)
----------------------------------------------------------------
local function _getState()
    local G = (getgenv and getgenv()) or _G
    local MAIN = G.MAIN or rawget(_G, "MAIN")
    MAIN = (type(MAIN) == "table") and MAIN or {}
    MAIN.misc = (type(MAIN.misc) == "table") and MAIN.misc or {}
    MAIN.misc.rejoin = (type(MAIN.misc.rejoin) == "table") and MAIN.misc.rejoin or {}
    MAIN.misc.rejoin.auto_hop = (type(MAIN.misc.rejoin.auto_hop) == "table") and MAIN.misc.rejoin.auto_hop or {}

    local AH = MAIN.misc.rejoin.auto_hop
    local saved = type(G.__AUTO_HOP_SAVED) == "table" and G.__AUTO_HOP_SAVED

    if AH.enabled == nil then
        if saved and saved.enabled ~= nil then
            AH.enabled = (saved.enabled == true)
        else
            AH.enabled = (G.AUTO_HOP_ENABLED == true)
        end
    end
    if tonumber(AH.current_player) == nil then
        AH.current_player = (saved and tonumber(saved.current))
            or tonumber(AH.current)
            or tonumber(G.AUTO_HOP_CURRENT_PLAYER)
            or HOP_CURRENT_PLAYER_DEFAULT
    end
    if tonumber(AH.max_player) == nil then
        AH.max_player = (saved and tonumber(saved.max))
            or tonumber(AH.max)
            or tonumber(G.AUTO_HOP_MAX_PLAYER)
            or 1
    end
    if tonumber(AH.teleport_delay) == nil then
        AH.teleport_delay = (saved and tonumber(saved.delay))
            or tonumber(G.AUTO_HOP_TELEPORT_DELAY)
            or HOP_TELEPORT_DELAY_DEFAULT
    end
    if tonumber(AH.minutes) == nil then AH.minutes = 8 end
    if tonumber(AH.diff_servers) == nil then AH.diff_servers = 5 end
    AH.visited = ensureArray(AH.visited)

    AH.current_player = clampCurrentPlayers(AH.current_player)
    AH.max_player   = clampNum(AH.max_player, 1, 100, 1)
    AH.teleport_delay = clampTeleportDelay(AH.teleport_delay)
    AH.minutes      = clampNum(AH.minutes, 1, 1440, 8)
    AH.diff_servers = clampNum(AH.diff_servers, 1, 200, 5)

    G.MAIN = MAIN
    _G.MAIN = MAIN

    local STATE = G.STATE or rawget(_G, "STATE")
    if type(STATE) == "table" then
        STATE.rejoin = STATE.rejoin or {}
        STATE.rejoin.auto_hop = AH
    end

    return MAIN, AH
end

local function getCfg()
    local MAIN, AH = _getState()

    local target = clampNum(AH.max_player, 1, 100, 1)

    return {
        enabled        = (AH.enabled == true),
        minutes        = clampNum(AH.minutes, 1, 1440, 8),
        diffServers    = clampNum(AH.diff_servers, 1, 200, 5),
        currentPlayers = clampCurrentPlayers(AH.current_player),
        targetPlayers  = target,
        teleportDelay  = clampTeleportDelay(AH.teleport_delay),
        AH = AH,
        MAIN = MAIN,
    }
end

local function getLocalPlayerCount()
    local n = 0
    pcall(function()
        n = #Players:GetPlayers()
    end)
    return n
end

----------------------------------------------------------------
-- visited helpers (STATE + FILE)
----------------------------------------------------------------
local function buildSetFromArray(arr)
    local set = {}
    arr = ensureArray(arr)
    for _, v in ipairs(arr) do
        local s = tostring(v or "")
        if s ~= "" then set[s] = true end
    end
    return set
end

local function resetVisitedIfNeeded(placeId, currentPlayers, targetPlayers, diffServers, AH)
    local limit = tonumber(AH and AH.diff_servers) or diffServers or 5
    AH.visited = ensureArray(AH and AH.visited)

    if #AH.visited >= limit then
        AH.visited = {}
        dprint("visited reset limit", limit)

        cacheSetVisited(placeId, currentPlayers, targetPlayers, diffServers, AH.visited)
        cacheSave(placeId, currentPlayers, targetPlayers, diffServers, { ts = 0, scanCursor = {} })
        _persistState()
        return true
    end
    return false
end

-- ✅ PRE-HOP: always mark current server to visited (STATE + FILE)
local function pushVisitedPreHop(jobId)
    local cfg = getCfg()
    local placeId = game.PlaceId

    jobId = tostring(jobId or "")
    if jobId == "" then return false end

    local AH = cfg.AH
    AH.visited = ensureArray(AH.visited)

    for _, v in ipairs(AH.visited) do
        if tostring(v) == jobId then
            return false
        end
    end

    table.insert(AH.visited, jobId)
    dprint("visited prehop +1", jobId, "count", #AH.visited)

    cacheSetVisited(placeId, cfg.currentPlayers, cfg.targetPlayers, cfg.diffServers, AH.visited)
    resetVisitedIfNeeded(placeId, cfg.currentPlayers, cfg.targetPlayers, cfg.diffServers, AH)
    _persistState()

    return true
end

local function pushVisitedConfirmed(jobId)
    local cfg = getCfg()
    local placeId = game.PlaceId

    jobId = tostring(jobId or "")
    if jobId == "" then return end

    local AH = cfg.AH
    AH.visited = ensureArray(AH.visited)
    for _, v in ipairs(AH.visited) do
        if tostring(v) == jobId then return end
    end

    table.insert(AH.visited, jobId)
    dprint("visited confirmed +1", jobId, "count", #AH.visited)

    cacheSetVisited(placeId, cfg.currentPlayers, cfg.targetPlayers, cfg.diffServers, AH.visited)
    resetVisitedIfNeeded(placeId, cfg.currentPlayers, cfg.targetPlayers, cfg.diffServers, AH)
    _persistState()
end

----------------------------------------------------------------
-- Local avoid/recent/dead trackers
----------------------------------------------------------------
local AVOID_TTL_SEC    = 240
local AVOID_TTL_DEAD   = 900
local AVOID_TTL_FULL   = 240
local RECENT_TRIED_TTL = 240

local _avoidUntil  = {}
local _recentTried = {}
local _deadUntil   = {}

local function ttlAlive(map, jobId)
    jobId = tostring(jobId or "")
    if jobId == "" then return false end
    local untilT = map[jobId]
    if not untilT then return false end
    if now() >= untilT then
        map[jobId] = nil
        return false
    end
    return true
end

local function isAvoided(jobId) return ttlAlive(_avoidUntil, jobId) end
local function isRecent(jobId)  return ttlAlive(_recentTried, jobId) end
local function isDead(jobId)    return ttlAlive(_deadUntil, jobId) end

local function markAvoid(jobId, sec)
    jobId = tostring(jobId or "")
    if jobId == "" then return end
    sec = tonumber(sec) or AVOID_TTL_SEC
    _avoidUntil[jobId] = now() + sec
end

local function markRecent(jobId, sec)
    jobId = tostring(jobId or "")
    if jobId == "" then return end
    sec = tonumber(sec) or RECENT_TRIED_TTL
    _recentTried[jobId] = now() + sec
end

local function markDead(jobId, sec)
    jobId = tostring(jobId or "")
    if jobId == "" then return end
    sec = tonumber(sec) or AVOID_TTL_DEAD
    _deadUntil[jobId] = now() + sec
end

----------------------------------------------------------------
-- Roblox API backoff (429)
----------------------------------------------------------------
local _apiBlockedUntil = 0
local _api429WinStart  = 0
local _api429Count     = 0

local function apiBackoff(sec, why)
    sec = tonumber(sec) or 30
    local jitter = math.random(0, 8)
    _apiBlockedUntil = now() + sec + jitter
    dprint("API_BACKOFF", math.floor(sec + jitter), "sec", tostring(why or ""))
end

local function httpGet(url)
    if now() < (_apiBlockedUntil or 0) then
        return false, "rate_limited_local", 429
    end

    local req =
        (syn and syn.request) or
        (http and http.request) or
        http_request or
        request or
        (fluxus and fluxus.request)

    if type(req) == "function" then
        local res = req({ Url = url, Method = "GET" })
        local body = res and (res.Body or res.body)
        local code = tonumber(res and (res.StatusCode or res.status_code)) or 0

        if _debug then dprint("http", code, url) end

        if code == 429 then
            local t = now()
            if (t - _api429WinStart) > 60 then
                _api429WinStart = t
                _api429Count = 0
            end
            _api429Count += 1

            local base = 30
            if _api429Count >= 2 then base = 45 end
            if _api429Count >= 4 then base = 75 end
            apiBackoff(base, "http_429")
            return false, "http_429", 429
        end

        if type(body) == "string" and body ~= "" then
            return true, body, code
        end
        return false, "request_failed", code
    end

    local ok, body = pcall(function()
        return HttpService:GetAsync(url)
    end)
    if ok and type(body) == "string" and body ~= "" then
        return true, body, 200
    end

    ok, body = pcall(function()
        return game:HttpGet(url)
    end)
    if not ok then
        return false, body, 0
    end
    return true, body, 200
end

local API_PAGE_LIMIT    = 50   -- limit=100 sering return kosong / cursor null (bug Roblox API)
local API_PAGE_DELAY    = 0.22 -- jeda antar page biar tidak kena 429
local SCAN_EARLY_EXIT   = 22   -- cukup kandidat bagus -> stop scan (hemat API)

local function isServerJoinable(playing, maxPlayers)
    playing = tonumber(playing) or 0
    maxPlayers = tonumber(maxPlayers) or 0
    if maxPlayers <= 0 then return true end
    return playing < maxPlayers
end

-- Target 8 + max server 8 => full (8/8) tidak bisa join; aim ke 7/8
local function scoreTargetForServer(targetPlayers, maxPlayers)
    targetPlayers = clampNum(targetPlayers, 1, 100, 1)
    maxPlayers = tonumber(maxPlayers) or 0
    if maxPlayers <= 0 then
        maxPlayers = GAME_SERVER_MAX
    end
    if targetPlayers >= maxPlayers then
        return maxPlayers - 1
    end
    return targetPlayers
end

local function popScore(playing, targetPlayers, maxPlayers)
    local aim = scoreTargetForServer(targetPlayers, maxPlayers)
    return math.abs((tonumber(playing) or 0) - aim)
end

local function getExcludeFullForTarget(targetPlayers)
    targetPlayers = clampNum(targetPlayers, 1, 100, 1)
    return targetPlayers >= (GAME_SERVER_MAX - 1)
end

local function fetchServers(placeId, cursor, sortOrder, opts)
    opts = type(opts) == "table" and opts or {}
    local limit = clampNum(opts.limit, 10, 100, API_PAGE_LIMIT)
    local excludeFull = opts.excludeFullGames
    if excludeFull == nil then
        excludeFull = getExcludeFullForTarget(opts.targetPlayers or 1)
    end

    sortOrder = (tostring(sortOrder or "Asc") == "Desc") and "Desc" or "Asc"
    local url = ("https://games.roblox.com/v1/games/%d/servers/Public?sortOrder=%s&limit=%d"):format(
        placeId, sortOrder, limit
    )
    if excludeFull then
        url = url .. "&excludeFullGames=true"
    end
    if cursor and cursor ~= "" then
        url = url .. "&cursor=" .. HttpService:UrlEncode(tostring(cursor))
    end

    local ok, body, code = httpGet(url)
    if not ok then
        return nil, nil, ("http_failed:" .. tostring(body) .. "|code=" .. tostring(code))
    end

    local decoded
    local ok2 = pcall(function()
        decoded = HttpService:JSONDecode(body)
    end)
    if not ok2 or type(decoded) ~= "table" then
        return nil, nil, "json_decode_failed"
    end

    local data = decoded.data
    local nextCursor = decoded.nextPageCursor
    if type(data) ~= "table" then data = {} end

    -- Bug Roblox: limit=100 kadang data=[] + cursor null padahal masih ada server
    if #data == 0 and limit >= 100 and not opts._retriedSmaller then
        dprint("empty page limit=100 -> retry limit=50")
        return fetchServers(placeId, cursor, sortOrder, {
            limit = 50,
            excludeFullGames = excludeFull,
            targetPlayers = opts.targetPlayers,
            _retriedSmaller = true,
        })
    end

    return data, nextCursor, nil
end

local function filterCandidates(list, visitedSet, avoidJobId, targetPlayers, currentPlayers)
    local out = {}
    list = ensureArray(list)
    visitedSet = visitedSet or {}
    avoidJobId = tostring(avoidJobId or "")
    targetPlayers = tonumber(targetPlayers) or 1
    currentPlayers = clampCurrentPlayers(currentPlayers)
    local preferHigh = preferHigherPlaying(currentPlayers, targetPlayers)

    for _, rec in ipairs(list) do
        local id = tostring(rec.id or "")
        local playing = tonumber(rec.playing) or 0
        local maxPlayers = tonumber(rec.maxPlayers) or 0

        if id ~= ""
            and id ~= avoidJobId
            and not visitedSet[id]
            and not isDead(id)
            and not isAvoided(id)
            and not isRecent(id)
        then
            if isServerJoinable(playing, maxPlayers) then
                out[#out+1] = {
                    id = id,
                    playing = playing,
                    maxPlayers = maxPlayers,
                    score = popScore(playing, targetPlayers, maxPlayers),
                }
            end
        end
    end

    table.sort(out, function(a, b)
        if a.score ~= b.score then return a.score < b.score end
        if preferHigh then
            return a.playing > b.playing
        end
        return a.playing < b.playing
    end)

    local trimmed = {}
    for i = 1, math.min(#out, 28) do
        local rec = out[i]
        trimmed[#trimmed+1] = { id=rec.id, playing=rec.playing, maxPlayers=rec.maxPlayers }
    end
    return trimmed
end

----------------------------------------------------------------
-- Build candidates (cache-first, scan-later)
----------------------------------------------------------------
local function buildCandidates(placeId, currentPlayers, targetPlayers, diffServers, visitedSet, avoidJobId)
    visitedSet = visitedSet or {}
    avoidJobId = tostring(avoidJobId or "")
    currentPlayers = clampCurrentPlayers(currentPlayers)
    targetPlayers = clampNum(targetPlayers, 1, 100, 1)

    -- ✅ merge visited from file (persist)
    do
        local vfile = cacheGetVisited(placeId, currentPlayers, targetPlayers, diffServers)
        for _, jid in ipairs(ensureArray(vfile)) do
            visitedSet[tostring(jid)] = true
        end
    end

    -- 1) cache first (fresh)
    local cached, cacheState = cacheGetCandidates(placeId, currentPlayers, targetPlayers, diffServers, 900)
    if type(cached) == "table" and #cached > 0 and cacheState == "fresh_cache" then
        local filtered = filterCandidates(cached, visitedSet, avoidJobId, targetPlayers, currentPlayers)
        if #filtered > 0 then
            dprint("use cache candidates (fresh)", #filtered, "from", #cached)
            return filtered, nil, 0, cacheState
        end
        dprint("cache fresh exhausted by filters -> scan")
    end

    -- 2) if blocked -> stale cache only
    if now() < (_apiBlockedUntil or 0) then
        if type(cached) == "table" and #cached > 0 then
            local filtered = filterCandidates(cached, visitedSet, avoidJobId, targetPlayers, currentPlayers)
            if #filtered > 0 then
                dprint("use cache candidates (blocked)", #filtered, cacheState)
                return filtered, nil, 0, cacheState
            end
            dprint("blocked + cache exhausted by filters")
        end
        return nil, "api_blocked_no_cache", 0, cacheState
    end

    -- 3) scan (primary sort, fallback sort if needed)
    local primarySort, fallbackSort = getSortOrdersForHop(currentPlayers, targetPlayers)
    local scanned = 0
    local pagesTotal = 0
    local poolAbove, poolBelow = {}, {}
    local scanErr = nil
    local preferHigh = preferHigherPlaying(currentPlayers, targetPlayers)

    local _, _, cacheRec = cacheLoad(placeId, currentPlayers, targetPlayers, diffServers)
    local scanCursor = (type(cacheRec.scanCursor) == "table") and cacheRec.scanCursor or {}

    local function pushPool(pool, rec, maxN)
        pool[#pool+1] = rec
        if #pool > maxN then
            local worstI, worstS = 1, pool[1].score
            for i = 2, #pool do
                if pool[i].score > worstS then
                    worstS = pool[i].score
                    worstI = i
                end
            end
            table.remove(pool, worstI)
        end
    end

    local function poolCount()
        return #poolAbove + #poolBelow
    end

    local function scanWithSort(sortOrder, maxPages)
        local cursor = scanCursor[sortOrder]
        if cursor == "" then cursor = nil end
        local pagesScanned = 0
        local lastErr = nil

        for page = 1, maxPages do
            local servers, nextCursor, err = fetchServers(placeId, cursor, sortOrder, {
                targetPlayers = targetPlayers,
            })
            if not servers then
                lastErr = err
                break
            end

            pagesScanned += 1
            scanned += #servers

            for _, s in ipairs(servers) do
                local id = tostring(s.id or "")
                local playing = tonumber(s.playing) or 0
                local maxPlayers = tonumber(s.maxPlayers) or 0

                if id ~= ""
                    and id ~= avoidJobId
                    and not visitedSet[id]
                    and not isDead(id)
                    and not isAvoided(id)
                    and not isRecent(id)
                    and isServerJoinable(playing, maxPlayers)
                then
                    local score = popScore(playing, targetPlayers, maxPlayers)
                    local rec = { id=id, playing=playing, maxPlayers=maxPlayers, score=score }
                    local aim = scoreTargetForServer(targetPlayers, maxPlayers)
                    if playing >= aim then
                        pushPool(poolAbove, rec, 14)
                    else
                        pushPool(poolBelow, rec, 14)
                    end
                end
            end

            cursor = nextCursor
            scanCursor[sortOrder] = cursor or ""

            if poolCount() >= SCAN_EARLY_EXIT then
                dprint("scan early exit", sortOrder, "page", pagesScanned, "pool=", poolCount())
                break
            end

            if not nextCursor or nextCursor == "" then
                scanCursor[sortOrder] = ""
                break
            end

            if page < maxPages then
                task.wait(API_PAGE_DELAY)
            end
        end

        return pagesScanned, lastErr
    end

    local p1, errPrimary = scanWithSort(primarySort, getScanPagesForHop(currentPlayers, targetPlayers, false))
    pagesTotal += p1 or 0
    scanErr = errPrimary

    if poolCount() <= 0 then
        local p2, errFallback = scanWithSort(fallbackSort, getScanPagesForHop(currentPlayers, targetPlayers, true))
        pagesTotal += p2 or 0
        if errFallback and not scanErr then
            scanErr = errFallback
        end
        dprint("fallback sort", fallbackSort, "candidates=", poolCount())
    end

    _lastScanPages = pagesTotal
    _lastScanServers = scanned
    cacheSave(placeId, currentPlayers, targetPlayers, diffServers, { scanCursor = scanCursor })

    if poolCount() <= 0 then
        if tostring(scanErr or ""):find("429") or tostring(scanErr or ""):find("code=429") then
            if type(cached) == "table" and #cached > 0 then
                local filtered = filterCandidates(cached, visitedSet, avoidJobId, targetPlayers, currentPlayers)
                if #filtered > 0 then
                    dprint("scan failed 429 -> fallback cache(filtered)", #filtered, cacheState)
                    return filtered, nil, scanned, cacheState
                end
            end
        end
        if scanErr and poolCount() <= 0 then
            return nil, scanErr, scanned, cacheState
        end
    end

    dprint("scan sort primary=", primarySort, "fallback=", fallbackSort,
        "current=", currentPlayers, "target=", targetPlayers,
        "pages=", pagesTotal, "servers=", scanned)

    local candidates = {}
    local function sortPool(pool)
        table.sort(pool, function(a, b)
            if a.score ~= b.score then return a.score < b.score end
            if preferHigh then
                return a.playing > b.playing
            end
            return a.playing < b.playing
        end)
    end
    if #poolAbove > 0 then
        sortPool(poolAbove)
        for _, rec in ipairs(poolAbove) do
            candidates[#candidates+1] = { id=rec.id, playing=rec.playing, maxPlayers=rec.maxPlayers }
        end
    end
    if #poolBelow > 0 then
        sortPool(poolBelow)
        for _, rec in ipairs(poolBelow) do
            candidates[#candidates+1] = { id=rec.id, playing=rec.playing, maxPlayers=rec.maxPlayers }
        end
    end

    if #candidates > 0 then
        cacheSetCandidates(placeId, currentPlayers, targetPlayers, diffServers, candidates)
    end

    dprint("SCAN done scanned=", scanned, "candidates=", #candidates, "target=", targetPlayers)
    return candidates, nil, scanned, cacheState
end

----------------------------------------------------------------
-- Teleport wrappers
----------------------------------------------------------------
local function teleportToJob(placeId, jobId, teleportData)
    placeId = tonumber(placeId) or game.PlaceId
    jobId = tostring(jobId or "")
    if jobId == "" then return false, "jobId_empty" end

    local opts = Instance.new("TeleportOptions")
    if type(teleportData) == "table" then
        pcall(function() opts:SetTeleportData(teleportData) end)
    end
    pcall(function() opts.ServerInstanceId = jobId end)

    local okAsync, errAsync = pcall(function()
        TeleportService:TeleportAsync(placeId, { getLP() }, opts)
    end)
    if okAsync then
        return true, "teleport_async"
    end

    local ok, err = pcall(function()
        TeleportService:TeleportToPlaceInstance(placeId, jobId, getLP(), "", teleportData)
    end)
    if not ok then
        return false, tostring(errAsync or err)
    end
    return true, "teleport_to_place_instance"
end

local function hopToServer(placeId, jobId, fromJobId)
    placeId = tonumber(placeId) or game.PlaceId
    jobId = tostring(jobId or "")
    fromJobId = tostring(fromJobId or game.JobId or "")

    if jobId == "" then return false, "jobId_empty" end

    local td = {
        __gag2_autohop = true,
        fromJobId = fromJobId,
        targetJobId = jobId,
        nonce = tostring(os.time()) .. "_" .. tostring(math.random(100000, 999999)),
    }

    local PR = rawget(_G, "PSReconnect") or rawget((getgenv and getgenv()) or _G, "PSReconnect")
    if type(PR) == "table" and type(PR.HopToServer) == "function" then
        local ok, res = PR.HopToServer(placeId, jobId, td)
        if ok then return true, res end
        dprint("psreconnect hop failed -> fallback", tostring(res))
    end

    return teleportToJob(placeId, jobId, td)
end

----------------------------------------------------------------
-- TeleportData confirm (visited only when really moved)
----------------------------------------------------------------
local _teleDataApplied = false
local function applyTeleportDataOnce()
    if _teleDataApplied then return end
    _teleDataApplied = true

    local data = nil
    pcall(function()
        data = TeleportService:GetLocalPlayerTeleportData()
    end)

    dprint("TPDATA type", typeof(data))
    if type(data) == "table" then
        dprint("TPDATA keys",
            tostring(data.__gag2_autohop),
            tostring(data.fromJobId),
            tostring(data.targetJobId),
            "here="..tostring(game.JobId)
        )
    end

    if type(data) ~= "table" then return end
    if data.__gag2_autohop ~= true then return end

    local targetJob = tostring(data.targetJobId or "")
    local fromJob   = tostring(data.fromJobId or "")
    local hereJob   = tostring(game.JobId or "")

    if targetJob ~= "" and hereJob == targetJob and hereJob ~= fromJob then
        pushVisitedConfirmed(hereJob)
        dprint("teleport confirmed from", fromJob, "to", hereJob)
    else
        dprint("teleportData ignored target", targetJob, "here", hereJob, "from", fromJob)
    end
end

----------------------------------------------------------------
-- Hop Scheduler (no spam)
----------------------------------------------------------------
local _running = false
local _thread  = nil

local _lastHopSuccessAt = 0
local _lastHopTryAt     = 0
local _cooldownHopSec   = 12
local SESSION_FAIL_COOLDOWN = 18

local _lockUntil = 0

local _session = nil
local WATCHDOG_SEC = 12
local _hopThresholdMetAt = 0

local function resetHopDelayTimer()
    _hopThresholdMetAt = 0
end

local function sessionReset()
    _session = nil
end

local function sessionActive()
    return type(_session) == "table" and _session.active == true
end

local function shouldHop(cfg)
    if not cfg or cfg.enabled ~= true then
        return false, "disabled"
    end

    if rawget(_G, "__GAG2_AUTO_HOP_NOW") == true then
        return true, "manual_flag"
    end

    local currentCount = getLocalPlayerCount()
    local currentMax = clampCurrentPlayers(cfg.currentPlayers)
    local targetMax = clampNum(cfg.targetPlayers, 1, 100, 1)
    local delaySec = clampTeleportDelay(cfg.teleportDelay)
    local mode = getHopMode(currentMax, targetMax)

    if mode == "leave_crowded" then
        if currentCount < currentMax then
            _hopThresholdMetAt = 0
            _lastStatus = ("Waiting crowded " .. currentCount .. "/" .. currentMax)
            return false, _lastStatus
        end
    elseif mode == "leave_quiet" then
        if currentCount > currentMax then
            _hopThresholdMetAt = 0
            _lastStatus = ("Waiting quieter " .. currentCount .. "/" .. currentMax)
            return false, _lastStatus
        end
    else
        if currentCount < currentMax then
            _hopThresholdMetAt = 0
            _lastStatus = ("Waiting players " .. currentCount .. "/" .. currentMax)
            return false, _lastStatus
        end
    end

    if delaySec <= 0 then
        local why
        if mode == "leave_crowded" then
            why = ("crowd_reached (" .. currentCount .. ">=" .. currentMax .. " -> " .. targetMax .. ")")
        elseif mode == "leave_quiet" then
            why = ("too_quiet (" .. currentCount .. "<=" .. currentMax .. " -> " .. targetMax .. ")")
        else
            why = ("player_threshold (" .. currentCount .. ">=" .. currentMax .. ")")
        end
        return true, why
    end

    if _hopThresholdMetAt <= 0 then
        _hopThresholdMetAt = now()
        _lastStatus = ("Delay " .. math.ceil(delaySec) .. "s before hop")
        return false, "delay_armed"
    end

    local elapsed = now() - _hopThresholdMetAt
    if elapsed < delaySec then
        local left = math.ceil(delaySec - elapsed)
        _lastStatus = ("Delay " .. left .. "s before hop")
        return false, ("delay_wait (" .. left .. "s)")
    end

    if mode == "leave_crowded" then
        return true, ("crowd_delayed (" .. currentCount .. ">=" .. currentMax .. " -> " .. targetMax .. ")")
    elseif mode == "leave_quiet" then
        return true, ("quiet_delayed (" .. currentCount .. "<=" .. currentMax .. " -> " .. targetMax .. ")")
    end
    return true, ("player_threshold_delayed (" .. currentCount .. ">=" .. currentMax .. ")")
end

local function sessionStart(reason)
    local cfg = getCfg()
    if cfg.enabled ~= true then
        _lastStatus = "disabled"
        return false, "disabled"
    end
    local lp = getLP()
    if not lp then
        _lastStatus = "no_localplayer"
        return false, "no_localplayer"
    end
    if sessionActive() then
        return false, "session_already_active"
    end

    local t = now()
    if (t - (_lastHopTryAt or 0)) < _cooldownHopSec then
        _lastStatus = "Hop cooldown"
        return false, "hop_cooldown"
    end

    local placeId   = game.PlaceId
    local fromJobId = tostring(game.JobId)

    local visitedSet = buildSetFromArray(cfg.AH.visited)
    do
        local vfile = cacheGetVisited(placeId, cfg.currentPlayers, cfg.targetPlayers, cfg.diffServers)
        for _, jid in ipairs(vfile) do
            visitedSet[tostring(jid)] = true
        end
    end
    visitedSet[fromJobId] = true

    local function tryBuild()
        return buildCandidates(placeId, cfg.currentPlayers, cfg.targetPlayers, cfg.diffServers, visitedSet, fromJobId)
    end

    local candidates, err = tryBuild()
    if (type(candidates) ~= "table" or #candidates == 0) and #ensureArray(cfg.AH.visited) > 0 then
        cfg.AH.visited = {}
        cacheSetVisited(placeId, cfg.currentPlayers, cfg.targetPlayers, cfg.diffServers, cfg.AH.visited)
        cacheSave(placeId, cfg.currentPlayers, cfg.targetPlayers, cfg.diffServers, { ts = 0, scanCursor = {} })
        _persistState()
        visitedSet = { [fromJobId] = true }
        candidates, err = tryBuild()
    end

    if type(candidates) ~= "table" or #candidates == 0 then
        local detail = ("pages=%d srv=%d limit=%d"):format(
            _lastScanPages or 0, _lastScanServers or 0, API_PAGE_LIMIT
        )
        _lastSessionErr = (err or "no_candidates") .. " (" .. detail .. ")"
        _lastStatus = tostring(_lastSessionErr)
        if tostring(err or ""):find("429") then
            apiBackoff(35, "no_candidates_429")
        end
        return false, err or "no_candidates"
    end

    _lastHopTryAt = t
    pushVisitedPreHop(fromJobId)
    _hopThresholdMetAt = 0

    _session = {
        active = true,
        reason = tostring(reason or ""),
        placeId = placeId,
        fromJobId = fromJobId,
        targetPlayers = cfg.targetPlayers,
        diffServers = cfg.diffServers,
        candidates = ensureArray(candidates),
        idx = 1,
        attemptedSet = {},
        inFlight = false,
        currentJobId = "",
        startedAt = now(),
        nextActionAt = now(),
    }

    dprint("sessionStart", "reason=", _session.reason, "candidates=", #_session.candidates)
    _lastSessionErr = nil
    _lastStatus = "teleporting"
    return true, "session_started"
end

local function sessionFinish(ok, why)
    if rawget(_G, "__GAG2_AUTO_HOP_NOW") == true then
        _G.__GAG2_AUTO_HOP_NOW = false
    end

    if ok then
        _lastHopSuccessAt = now()
        _hopThresholdMetAt = 0
    else
        _lockUntil = math.max(_lockUntil, now() + SESSION_FAIL_COOLDOWN)
    end

    dprint("sessionFinish", ok, tostring(why or ""))
    _lastSessionErr = tostring(why or "")
    _lastStatus = ok and "idle" or tostring(why or "failed")
    sessionReset()
end

local function pickNextCandidate()
    if not sessionActive() then return nil end
    local s = _session

    for i = s.idx, #s.candidates do
        local rec = s.candidates[i] or {}
        local jobId = tostring(rec.id or "")
        s.idx = i + 1

        if jobId ~= ""
            and jobId ~= s.fromJobId
            and not s.attemptedSet[jobId]
            and not isDead(jobId)
            and not isAvoided(jobId)
            and not isRecent(jobId)
        then
            s.attemptedSet[jobId] = true
            return rec, jobId
        end
    end

    return nil
end

local function startWatchdog(attemptJobId, fromJobId)
    task.delay(WATCHDOG_SEC, function()
        if not sessionActive() then return end
        local s = _session
        if s.inFlight ~= true then return end
        if s.currentJobId ~= tostring(attemptJobId) then return end

        if tostring(game.JobId) == tostring(fromJobId) then
            dprint("WATCHDOG timeout -> treat as stuck, try next")
            markAvoid(attemptJobId, AVOID_TTL_SEC)
            markRecent(attemptJobId, RECENT_TRIED_TTL)
            s.inFlight = false
            s.currentJobId = ""
            s.nextActionAt = now() + 1.0
        end
    end)
end

----------------------------------------------------------------
-- TeleportInitFailed hook (core anti spam)
----------------------------------------------------------------
local _tpFailConn = nil
local function ensureTeleportFailHook()
    if _tpFailConn then return end

    _tpFailConn = TeleportService.TeleportInitFailed:Connect(function(player, result, errMsg)
        local lp = getLP()
        if lp and player ~= lp then return end
        if not sessionActive() then return end

        local s = _session
        if s.inFlight ~= true then return end

        local msg = tostring(errMsg or "")
        local lm  = low(msg)
        local r   = tostring(result)

        dprint("TeleportInitFailed", r, msg)

        local jobId = tostring(s.currentJobId or "")
        if jobId ~= "" then
            if lm:find("gameended")
                or lm:find("could not find requested game instance")
                or lm:find("requested game instance")
            then
                markDead(jobId, AVOID_TTL_DEAD)
                markAvoid(jobId, AVOID_TTL_DEAD)
                markRecent(jobId, math.max(RECENT_TRIED_TTL, AVOID_TTL_DEAD))
                s.nextActionAt = now() + 0.8

            elseif r:find("IsTeleporting") or lm:find("previous teleport") or lm:find("in processing") then
                _lockUntil = math.max(_lockUntil, now() + 12)
                s.nextActionAt = _lockUntil + 0.2

            else
                markAvoid(jobId, AVOID_TTL_FULL)
                markRecent(jobId, RECENT_TRIED_TTL)
                s.nextActionAt = now() + 0.6
            end
        end

        s.inFlight = false
        s.currentJobId = ""
    end)
end

----------------------------------------------------------------
-- Session Tick (state machine)
----------------------------------------------------------------
local function sessionTick()
    if not sessionActive() then return end
    local s = _session

    if now() < (_lockUntil or 0) then
        return
    end

    if now() < (s.nextActionAt or 0) then
        return
    end

    if s.inFlight == true then
        return
    end

    local rec, jobId = pickNextCandidate()
    if not rec then
        sessionFinish(false, "candidates_exhausted")
        return
    end

    markRecent(jobId, RECENT_TRIED_TTL)

    s.currentJobId = jobId
    s.inFlight = true
    _lastStatus = "teleporting"

    dprint(("Hop -> job=%s playing=%s target=%s from=%s"):format(
        jobId, tostring(rec.playing or "?"), tostring(s.targetPlayers), tostring(s.fromJobId)
    ))

    local ok, res = hopToServer(s.placeId, jobId, s.fromJobId)
    if not ok then
        dprint("teleport call failed (pcall)", tostring(res))
        s.inFlight = false
        s.currentJobId = ""
        markAvoid(jobId, AVOID_TTL_SEC)
        s.nextActionAt = now() + 0.6
        return
    end

    startWatchdog(jobId, s.fromJobId)
end

----------------------------------------------------------------
-- Apply TeleportData once per server join
----------------------------------------------------------------
local function tryApplyTeleportDataAndSyncVisited()
    applyTeleportDataOnce()

    -- also sync visited file -> STATE (so UI consistent)
    local cfg = getCfg()
    local placeId = game.PlaceId

    local vfile = cacheGetVisited(placeId, cfg.currentPlayers, cfg.targetPlayers, cfg.diffServers)
    if #vfile > 0 and type(cfg.AH.visited) == "table" then
        local set = buildSetFromArray(cfg.AH.visited)
        local changed = false
        for _, jid in ipairs(vfile) do
            jid = tostring(jid or "")
            if jid ~= "" and not set[jid] then
                table.insert(cfg.AH.visited, jid)
                set[jid] = true
                changed = true
            end
        end
        if changed then
            _persistState()
        end
    end
end

----------------------------------------------------------------
-- Main loop
----------------------------------------------------------------
local function loop()
    while _running do
        local ok, err = pcall(function()
            tryApplyTeleportDataAndSyncVisited()

            local cfg = getCfg()
            local doHop, why = shouldHop(cfg)

            if doHop and not sessionActive() then
                local okS, rs = sessionStart(why)
                dprint("startHop", okS, rs)
                if not okS then
                    _lastStatus = tostring(rs or "start_failed")
                end
            end

            if not sessionActive() and not doHop then
                -- shouldHop already sets _lastStatus with mode-aware message
            end

            if sessionActive() then
                sessionTick()
            end
        end)

        if not ok then
            dprint("loop error", err)
        end

        task.wait(0.6)
    end
end

----------------------------------------------------------------
-- Public API
----------------------------------------------------------------
function M.IsRunning()
    return _running == true
end

function M.GetStatus()
    local cfg = getCfg()
    local pc = getLocalPlayerCount()
    local delaySec = clampTeleportDelay(cfg.teleportDelay)
    local delayLeft = 0
    if _hopThresholdMetAt > 0 and delaySec > 0 then
        delayLeft = math.max(0, math.ceil(delaySec - (now() - _hopThresholdMetAt)))
    end
    local primarySort, fallbackSort = getSortOrdersForHop(cfg.currentPlayers, cfg.targetPlayers)
    local hopMode = getHopMode(cfg.currentPlayers, cfg.targetPlayers)
    local st = {
        running = (_running == true),
        sessionActive = sessionActive(),
        inFlight = sessionActive() and _session.inFlight == true,
        playerCount = pc,
        currentMax = cfg.currentPlayers,
        targetMax = cfg.targetPlayers,
        hopMode = hopMode,
        sortOrder = primarySort .. ">" .. fallbackSort,
        sortPrimary = primarySort,
        sortFallback = fallbackSort,
        triggerHint = getHopTriggerHint(cfg.currentPlayers, cfg.targetPlayers),
        joinableHint = (cfg.targetPlayers >= GAME_SERVER_MAX)
            and ("< " .. tostring(GAME_SERVER_MAX) .. " player (not full)")
            or nil,
        teleportDelay = delaySec,
        delayRemaining = delayLeft,
        status = _lastStatus or "idle",
        lastError = _lastSessionErr,
        scanPages = _lastScanPages,
        scanServers = _lastScanServers,
        pageLimit = API_PAGE_LIMIT,
        candidateCount = sessionActive() and #ensureArray(_session.candidates) or 0,
    }
    return st
end

function M.SetDebug(on)
    _debug = (on == true)
end

function M.ShouldHop()
    return shouldHop(getCfg())
end

function M.ForceHopNow(reason)
    if sessionActive() then
        return false, "session_active"
    end
    local okS, rs = sessionStart(reason or "manual_force")
    return okS, rs
end

function M.Start()
    if _running then return end
    _running = true
    ensureTeleportFailHook()
    tryApplyTeleportDataAndSyncVisited()
    _thread = task.spawn(loop)
    dprint("Start()")
end

function M.Stop()
    _running = false
    _hopThresholdMetAt = 0
    sessionReset()
    dprint("Stop()")
end

function M.ReleaseTeleportLock()
    _lockUntil = 0
    if sessionActive() then
        _session.inFlight = false
        _session.currentJobId = ""
        _session.nextActionAt = now()
    end
end

function M.SetCurrentPlayer(n)
    local _, AH = _getState()
    AH.current_player = clampCurrentPlayers(n)
    local G = (getgenv and getgenv()) or _G
    G.AUTO_HOP_CURRENT_PLAYER = AH.current_player
    _G.AUTO_HOP_CURRENT_PLAYER = AH.current_player
    resetHopDelayTimer()
    return AH.current_player
end

function M.SetTeleportDelay(sec)
    local _, AH = _getState()
    AH.teleport_delay = clampTeleportDelay(sec)
    local G = (getgenv and getgenv()) or _G
    G.AUTO_HOP_TELEPORT_DELAY = AH.teleport_delay
    _G.AUTO_HOP_TELEPORT_DELAY = AH.teleport_delay
    resetHopDelayTimer()
    return AH.teleport_delay
end

M.setTeleportDelay = M.SetTeleportDelay

function M.SetMaxPlayer(n)
    local _, AH = _getState()
    AH.max_player = clampNum(n, 1, 100, 1)
    local G = (getgenv and getgenv()) or _G
    G.AUTO_HOP_MAX_PLAYER = AH.max_player
    _G.AUTO_HOP_MAX_PLAYER = AH.max_player
    resetHopDelayTimer()
    return AH.max_player
end

function M.SetEnabled(on)
    on = (on == true)
    local _, AH = _getState()
    AH.enabled = on
    local G = (getgenv and getgenv()) or _G
    G.AUTO_HOP_ENABLED = on
    _G.AUTO_HOP_ENABLED = on
    if on then
        M.Start()
    else
        M.Stop()
    end
    return on
end

function M.SyncFromGlobals()
    local G = (getgenv and getgenv()) or _G
    local enabled = (G.AUTO_HOP_ENABLED == true)
    local curP = tonumber(G.AUTO_HOP_CURRENT_PLAYER)
    local maxP = tonumber(G.AUTO_HOP_MAX_PLAYER)
    local delayP = tonumber(G.AUTO_HOP_TELEPORT_DELAY)
    if curP then
        M.SetCurrentPlayer(curP)
    end
    if maxP then
        M.SetMaxPlayer(maxP)
    end
    if delayP ~= nil then
        M.SetTeleportDelay(delayP)
    end
    M.SetEnabled(enabled)
end

M.syncFromGlobals = M.SyncFromGlobals

----------------------------------------------------------------
-- Export
----------------------------------------------------------------
local G = (getgenv and getgenv()) or _G
G.AutoHopServer = M
G.AutoHopServerModule = M
_G.AutoHopServer = M
_G.AutoHopServerModule = M
G.__GAG2_SYNC_AUTO_HOP = function()
    local applyFn = G.applyAutoHopModule or _G.applyAutoHopModule
    if type(applyFn) == "function" then
        pcall(applyFn)
    else
        M.SyncFromGlobals()
    end
end
_G.__GAG2_SYNC_AUTO_HOP = G.__GAG2_SYNC_AUTO_HOP

return M
 end,                   required = false },
    { key = "ReduceLag",               name = "Reduce Lag",              factory = function() --[[
    ReduceLag.lua — Grow A Garden 2
    Visual FPS strip (Speed Hub–style), terpisah dari ReduceFPS / Remove Garden.

    PENTING: Jangan Destroy tanah/plot/plant di Workspace.Gardens.
    Flat-disc heuristic sering salah anggap PlantArea/soil = sprinkler radius.

    Toggle UI → MAIN.misc.perf.reduce_lag
    API:
      ReduceLag.SetEnabled(true|false)
      ReduceLag.SyncFromGlobals()
      ReduceLag.Start() / Stop()
      ReduceLag.GetStats() / DumpDebug()
]]

local Players     = game:GetService("Players")
local Lighting    = game:GetService("Lighting")
local RunService  = game:GetService("RunService")
local Workspace   = game:GetService("Workspace")
local Terrain     = Workspace:FindFirstChildOfClass("Terrain")
local LocalPlayer = Players.LocalPlayer

local G = (getgenv and getgenv()) or _G
local M = {}

local DESTROY_CLASSES = {
    Decal = true,
    Texture = true,
    ParticleEmitter = true,
    Trail = true,
    Beam = true,
    Smoke = true,
    Fire = true,
    Sparkles = true,
    Explosion = true,
    PointLight = true,
    SpotLight = true,
    SurfaceLight = true,
}

local FLATTEN_CLASSES = {
    Part = true,
    MeshPart = true,
    UnionOperation = true,
    WedgePart = true,
    CornerWedgePart = true,
    TrussPart = true,
}

local PROTECT_NAME = {
    Important = true,
    Data = true,
    Owner = true,
    Base = true,
    CollisionBlock = true,
    HarvestPart = true,
    HarvestPrompt = true,
    PlantArea = true,
    Soil = true,
    Ground = true,
    Spawn = true,
    Pad = true,
    WateringCanPreview = true,
    WateringCanFx = true,
    WateringCanFX = true,
    WateringCanSFX = true,
    -- Hub UI host (SurfaceGui di depan kamera saat loading) — flat disc, mirip radius
    NodeHubLoadingHost = true,
    NodeHubHostGui = true,
    -- Loading screen game (ProgressBar.Bar dll)
    LoadingScreenMenu = true,
    LoadingGui = true,
    ProgressBar = true,
}

local FX_NAME_EXACT = {
    MovingTextureYAxis1 = true,
    MovingTextureYAxis = true,
    DragonfireSmoke = true,
    DebugGui = true,
    SprinklerRadius = true, -- lingkaran range saat equip sprinkler (CPU killer)
}

local FX_NAME_CONTAINS = {
    "movingtexture",
    "dragonfire",
    "dragonsmoke",
    "leafaura",
    "glowfx",
    "shinefx",
    "sprinklerradius",
    "radiusring",
    "rangeradius",
    "rangeindicator",
    "rangepreview",
    "placementradius",
    "gearradius",
}

-- Post FX boleh dibuang. Sky/Clouds JANGAN Destroy — WeatherController (Eclipse dll)
-- reparent Sky ke Lighting/Skybox; kalau di-Destroy → error "Parent property of Sky is locked".
local LIGHTING_FX_CLASSES = {
    BloomEffect = true,
    BlurEffect = true,
    ColorCorrectionEffect = true,
    SunRaysEffect = true,
    DepthOfFieldEffect = true,
    Atmosphere = true,
    -- Clouds = protected (weather)
    -- Sky = protected (weather)
}

local LIGHTING_WEATHER_KEEP = {
    Sky = true,
    Clouds = true,
}

local running = false
local conns = {}
local token = 0
local stats = {}

local function bump(k, n)
    stats[k] = (stats[k] or 0) + (n or 1)
end

local function disc()
    for _, c in ipairs(conns) do
        pcall(function() c:Disconnect() end)
    end
    table.clear(conns)
end

-- WateringCanPreview (+ child disc di workspace.Temporary) — jangan pernah Destroy.
-- Fast-path: mayoritas instance langsung false (hindari walk parent tiap part).
local cachedTemporary = nil
local function getTemporaryFolder()
    if cachedTemporary and cachedTemporary.Parent then return cachedTemporary end
    cachedTemporary = Workspace:FindFirstChild("Temporary")
    return cachedTemporary
end

local function isWateringCanProtected(inst)
    if not inst then return false end
    local rawName = inst.Name
    local n = string.lower(tostring(rawName or ""))
    if n:find("wateringcan", 1, true) then
        return true
    end
    if PROTECT_NAME[rawName] == true and n:find("watering", 1, true) then
        return true
    end

    local p = inst.Parent
    if not p then return false end
    local pName = p.Name
    -- Parent langsung WateringCan* / Temporary — cek cepat tanpa loop 8 level tiap kali
    local pl = string.lower(tostring(pName or ""))
    if pl:find("wateringcan", 1, true) then
        return true
    end

    local temp = getTemporaryFolder()
    if temp and (p == temp or inst:IsDescendantOf(temp)) then
        if n:find("preview", 1, true) or n == "part" or n == "meshpart" then
            return true
        end
        if inst:IsA("BasePart") then
            local ok, size = pcall(function() return inst.Size end)
            if ok and size then
                local sx, sy, sz = size.X, size.Y, size.Z
                local mx = math.max(sx, sy, sz)
                local mn = math.min(sx, sy, sz)
                local mid = sx + sy + sz - mx - mn
                local tr = 0
                pcall(function() tr = inst.Transparency end)
                if mx >= 6 and mid >= 6 and mn <= 2.5 and tr >= 0.1 then
                    return true
                end
            end
        end
        return false
    end

    -- Ancestor WateringCan* (max 4, cukup untuk Tool hierarchy)
    p = p.Parent
    for _ = 1, 4 do
        if not p then break end
        if string.lower(tostring(p.Name or "")):find("wateringcan", 1, true) then
            return true
        end
        p = p.Parent
    end
    return false
end

local cachedGardens = nil
local function getGardensFolder()
    if cachedGardens and cachedGardens.Parent then return cachedGardens end
    cachedGardens = Workspace:FindFirstChild("Gardens")
    return cachedGardens
end

local function isUnderGardens(inst)
    if not inst then return false end
    local g = getGardensFolder()
    return g ~= nil and (inst == g or inst:IsDescendantOf(g))
end

-- Sprinkler radius sejati di garden (bukan soil/plot flat part)
local function isExplicitSprinklerRadius(inst)
    if not inst then return false end
    local n = string.lower(tostring(inst.Name or ""))
    return n == "sprinklerradius"
        or n:find("sprinklerradius", 1, true) ~= nil
        or n == "radiusring"
        or n:find("rangeradius", 1, true) ~= nil
end

local function safeDestroy(inst)
    if not inst or not inst.Parent then return false end
    if isWateringCanProtected(inst) then return false end
    -- Jangan Destroy BasePart/Model di Gardens (soil/plot/plant)
    if isUnderGardens(inst) and (inst:IsA("BasePart") or inst:IsA("Model") or inst:IsA("Folder")) then
        if not isExplicitSprinklerRadius(inst) then
            return false
        end
    end
    return pcall(function() inst:Destroy() end) == true
end

local function isProtectedName(name)
    return PROTECT_NAME[name] == true
end

local function nameIsFx(name)
    local lower = string.lower(tostring(name or ""))
    if lower:find("wateringcan", 1, true) then
        return false
    end
    if FX_NAME_EXACT[name] then return true end
    for _, needle in ipairs(FX_NAME_CONTAINS) do
        if string.find(lower, needle, 1, true) then
            return true
        end
    end
    return false
end

local function isNodeHubHost(inst)
    if not inst then return false end
    local n = tostring(inst.Name or "")
    if n == "NodeHubLoadingHost" or n == "NodeHubHostGui" then
        return true
    end
    local ok, anc = pcall(function()
        return inst:FindFirstAncestor("NodeHubLoadingHost") ~= nil
    end)
    return ok and anc == true
end

-- Loading screen game (Workspace.LoadingScreenMenu) — flat disc + ProgressBar.
-- JANGAN strip/Destroy: false-positive sprinkler radius → error "Bar is not a valid member of ProgressBar".
local function isLoadingScreenGui(inst)
    if not inst then return false end
    local n = tostring(inst.Name or "")
    if n == "LoadingScreenMenu" or n == "ProgressBar" or n == "LoadingGui" then
        return true
    end
    local ok, hit = pcall(function()
        return inst:FindFirstAncestor("LoadingScreenMenu") ~= nil
            or inst:FindFirstAncestor("LoadingGui") ~= nil
    end)
    return ok and hit == true
end

-- Lingkaran range sprinkler / gear (sering di Character saat equip)
local function isSprinklerRangeVisual(inst)
    if not inst then return false end
    if isNodeHubHost(inst) then return false end
    if isLoadingScreenGui(inst) then return false end
    if isWateringCanProtected(inst) then return false end
    -- Tanah/plot/plant di Gardens MIRIP flat disc — JANGAN pakai heuristic size di sini
    if isUnderGardens(inst) then
        return isExplicitSprinklerRadius(inst)
    end

    local n = tostring(inst.Name or "")
    local lower = string.lower(n)
    if n == "SprinklerRadius" or lower:find("sprinklerradius", 1, true) then
        return true
    end
    -- "Radius" sendirian terlalu generic (bisa nama part plot) — hanya di tool/character
    if lower == "radius" or lower:find("radiusring", 1, true) or lower:find("rangeindicator", 1, true)
        or lower:find("rangepreview", 1, true) or lower:find("placementradius", 1, true)
        or lower:find("gearradius", 1, true) or lower:find("coverageradius", 1, true) then
        return true
    end

    -- flat disc heuristic: HANYA di luar Gardens (tool / Temporary / character)
    if inst:IsA("BasePart") then
        local ok, size = pcall(function() return inst.Size end)
        if ok and size then
            local sx, sy, sz = size.X, size.Y, size.Z
            local mx = math.max(sx, sy, sz)
            local mn = math.min(sx, sy, sz)
            local mid = sx + sy + sz - mx - mn
            if mx >= 8 and mid >= 8 and mn <= 2 then
                local tr = 0
                pcall(function() tr = inst.Transparency end)
                if tr >= 0.15 or (inst.Material == Enum.Material.ForceField)
                    or (inst.Material == Enum.Material.Neon)
                    or (inst.Material == Enum.Material.Glass) then
                    -- wajib di bawah sprinkler tool / ClientHandle
                    local p = inst.Parent
                    for _ = 1, 6 do
                        if not p then break end
                        if p:IsA("Tool") and (p:GetAttribute("Sprinkler") ~= nil
                            or string.lower(tostring(p.Name or "")):find("sprinkler", 1, true)) then
                            return true
                        end
                        if p:GetAttribute("ClientHandle") == true then
                            return true
                        end
                        local pn = string.lower(tostring(p.Name or ""))
                        if pn:find("sprinkler", 1, true) or pn == "build" or pn == "handle" then
                            if mx >= 10 then return true end
                        end
                        p = p.Parent
                    end
                end
            end
        end
    end
    return false
end

-- JANGAN destroy Handle/Build — HeldHandleSelfHeal akan clone ulang (lebih lag)
local function isSprinklerHandleRoot(inst)
    if not inst then return false end
    if inst:GetAttribute("ClientHandle") == true then
        local n = tostring(inst.Name or "")
        return n == "Handle" or n == "Build"
    end
    return false
end

local function killSprinklerRange(inst)
    if not inst or not inst.Parent then return false end
    if isNodeHubHost(inst) then return false end
    if isLoadingScreenGui(inst) then return false end
    if isWateringCanProtected(inst) then return false end
    if isSprinklerHandleRoot(inst) then
        -- strip isi radius saja, biarkan Handle hidup
        local killed = false
        for _, d in ipairs(inst:GetDescendants()) do
            if isSprinklerRangeVisual(d) and not isWateringCanProtected(d) then
                pcall(function() d:Destroy() end)
                killed = true
                bump("sprinkler_range")
            end
        end
        return killed
    end

    -- nuke part radius (bukan Handle)
    for _, d in ipairs(inst:GetDescendants()) do
        if isWateringCanProtected(d) then
            -- skip
        elseif d:IsA("ParticleEmitter") or d:IsA("Beam") or d:IsA("Trail")
            or d:IsA("Decal") or d:IsA("Texture") or d:IsA("Light") then
            pcall(function() d:Destroy() end)
        end
    end
    if safeDestroy(inst) then
        bump("sprinkler_range")
        return true
    end
    pcall(function()
        if inst:IsA("BasePart") then
            inst.Transparency = 1
            inst.LocalTransparencyModifier = 1
            inst.CanCollide = false
            inst.CanQuery = false
            inst.CastShadow = false
            inst.Size = Vector3.new(0.05, 0.05, 0.05)
            bump("sprinkler_range_hide")
        end
    end)
    return true
end

local function disableToolVfx(root)
    if not root then return end
    for _, d in ipairs(root:GetDescendants()) do
        if d:IsA("ParticleEmitter") or d:IsA("Trail") or d:IsA("Beam")
            or d:IsA("Fire") or d:IsA("Smoke") or d:IsA("Sparkles") or d:IsA("Light") then
            pcall(function() d.Enabled = false end)
            bump("sprinkler_vfx_off")
        elseif d:IsA("Decal") or d:IsA("Texture") then
            pcall(function() d.Transparency = 1 end)
        end
    end
end

local ATTR_STRIPPED = "_GAG2RL_SprStrip"

local function stripSprinklerTool(tool)
    if not tool or not tool:IsA("Tool") then return end
    if tool:GetAttribute("Sprinkler") == nil then
        local n = string.lower(tostring(tool.Name or ""))
        if not n:find("sprinkler", 1, true) then return end
    end

    -- Hanya bunuh radius + matikan VFX sekali; jangan GetDescendants 3x tiap heartbeat
    local function killRadiusNamed(root)
        for _, name in ipairs({ "SprinklerRadius", "RadiusRing", "RangeIndicator", "RangePreview" }) do
            local hit = root:FindFirstChild(name, true)
            if hit and not isSprinklerHandleRoot(hit) then
                killSprinklerRange(hit)
            end
        end
    end
    killRadiusNamed(tool)

    -- VFX sekali (mark biar heartbeat murah)
    if tool:GetAttribute(ATTR_STRIPPED) ~= true then
        pcall(function() tool:SetAttribute(ATTR_STRIPPED, true) end)
        disableToolVfx(tool)
        for _, d in ipairs(tool:GetDescendants()) do
            if isSprinklerRangeVisual(d) and not isSprinklerHandleRoot(d) then
                killSprinklerRange(d)
            end
        end
    end
end

-- Bersihkan TEMPLATE di RS supaya clone equip sudah bersih (kunci anti-lag)
local function stripSprinklerAssetTemplates()
    local RS = game:GetService("ReplicatedStorage")
    local assets = RS:FindFirstChild("Assets")
    local folder = assets and assets:FindFirstChild("Sprinklers")
    if not folder then
        bump("sprinkler_assets_missing")
        return
    end

    local function cleanRoot(root)
        disableToolVfx(root)
        local list = root:GetDescendants()
        for i = #list, 1, -1 do
            local d = list[i]
            if isSprinklerRangeVisual(d) then
                pcall(function() d:Destroy() end)
                bump("sprinkler_asset_radius")
            elseif d:IsA("MeshPart") then
                pcall(function()
                    if d.TextureID ~= "" then d.TextureID = "" end
                    d.CastShadow = false
                end)
            elseif d:IsA("Decal") or d:IsA("Texture") then
                pcall(function() d:Destroy() end)
            end
        end
        -- root sendiri kalau BasePart radius
        if isSprinklerRangeVisual(root) then
            pcall(function() root:Destroy() end)
            bump("sprinkler_asset_radius")
        end
    end

    for _, child in ipairs(folder:GetChildren()) do
        cleanRoot(child)
    end

    -- jaga kalau asset baru di-stream
    table.insert(conns, folder.DescendantAdded:Connect(function(d)
        if not running then return end
        if isSprinklerRangeVisual(d) then
            task.defer(function()
                if d and d.Parent and isSprinklerRangeVisual(d) then
                    pcall(function() d:Destroy() end)
                    bump("sprinkler_asset_radius_live")
                end
            end)
        end
    end))

    bump("sprinkler_assets_cleaned")
end

----------------------------------------------------------------
-- config from MAIN / globals
----------------------------------------------------------------
local function _cfg()
    local MAIN = rawget(_G, "MAIN") or G.MAIN
    local perf = MAIN and MAIN.misc and MAIN.misc.perf
    perf = type(perf) == "table" and perf or {}

    local enabled = (G.REDUCE_LAG_ENABLED == true)
        or (rawget(_G, "REDUCE_LAG_ENABLED") == true)
        or (perf.reduce_lag == true)

    return { enabled = enabled == true }
end

----------------------------------------------------------------
-- lighting / terrain / quality
----------------------------------------------------------------
local function optimizeLighting()
    pcall(function() Lighting.GlobalShadows = false end)
    pcall(function()
        if Lighting.Technology ~= Enum.Technology.Compatibility then
            Lighting.Technology = Enum.Technology.Compatibility
        end
    end)
    pcall(function()
        Lighting.EnvironmentDiffuseScale = 0
        Lighting.EnvironmentSpecularScale = 0
    end)
    for _, child in ipairs(Lighting:GetChildren()) do
        local className = child.ClassName
        if LIGHTING_WEATHER_KEEP[className] then
            -- biarkan Sky/Clouds untuk weather Eclipse dll
            continue
        end
        if LIGHTING_FX_CLASSES[className] then
            if safeDestroy(child) then bump("lighting_fx") end
        end
    end
    bump("lighting")
end

local function optimizeTerrain()
    if not Terrain then return end
    pcall(function()
        Terrain.Decoration = false
        Terrain.WaterWaveSize = 0
        Terrain.WaterWaveSpeed = 0
        Terrain.WaterReflectance = 0
        Terrain.WaterTransparency = 1
    end)
    bump("terrain")
end

local function optimizeQuality()
    pcall(function()
        if typeof(settings) == "function" then
            local ren = settings().Rendering
            if ren then
                pcall(function() ren.QualityLevel = Enum.QualityLevel.Level01 end)
                pcall(function() ren.MeshPartDetailLevel = Enum.MeshPartDetailLevel.Level01 end)
            end
        end
    end)
    bump("quality")
end

----------------------------------------------------------------
-- instance strip
----------------------------------------------------------------
local function shouldSkip(inst, char)
    if not inst or not inst.Parent then return true end
    if isWateringCanProtected(inst) then return true end
    if isLoadingScreenGui(inst) then return true end
    -- SELALU boleh bersihin range sprinkler (meski di character sendiri)
    if isSprinklerRangeVisual(inst) or nameIsFx(inst.Name) and (
        tostring(inst.Name) == "SprinklerRadius"
        or string.lower(tostring(inst.Name)):find("sprinkler", 1, true)
        or string.lower(tostring(inst.Name)):find("radius", 1, true)
    ) then
        return false
    end
    if isProtectedName(inst.Name) then return true end
    if inst:IsA("BaseScript") or inst:IsA("ModuleScript") then return true end
    if inst:IsA("RemoteEvent") or inst:IsA("RemoteFunction") or inst:IsA("BindableEvent") then
        return true
    end
    if inst:IsA("ProximityPrompt") or inst:IsA("ValueBase") then return true end
    if char and (inst == char or inst:IsDescendantOf(char)) then
        -- character body skip, kecuali range visual (sudah di-handle di atas)
        return true
    end

    local ok, full = pcall(function() return inst:GetFullName() end)
    if ok and type(full) == "string" then
        if full:find("PlayerGui", 1, true) then return true end
        if full:find("PlayerScripts", 1, true) then return true end
        if full:find("ReplicatedStorage", 1, true) then return true end
        if full:find("StarterGui", 1, true) then return true end
        if full:find("CoreGui", 1, true) then return true end
        if full:find("NodeHubLoadingHost", 1, true) then return true end
        if full:find("LoadingScreenMenu", 1, true) then return true end
        if full:find("LoadingGui", 1, true) then return true end
        -- Preview/FX short-lived di Temporary — jangan flatten Part di sini
        if full:find("Temporary", 1, true) and (
            string.lower(tostring(inst.Name)):find("preview", 1, true)
            or string.lower(tostring(inst.Name)):find("watering", 1, true)
        ) then
            return true
        end
    end
    if not inst:IsDescendantOf(Workspace) then return true end
    return false
end

local function processInstance(inst, char)
    if isWateringCanProtected(inst) then return end
    if isNodeHubHost(inst) then return end
    if isLoadingScreenGui(inst) then return end
    if isProtectedName(inst.Name) then return end

    -- Gardens: jangan Destroy BasePart/Model plot/plant. Cuma FX + SprinklerRadius eksplisit.
    if isUnderGardens(inst) then
        if isExplicitSprinklerRadius(inst) then
            killSprinklerRange(inst)
            return
        end
        local cls = inst.ClassName
        if DESTROY_CLASSES[cls] then
            if safeDestroy(inst) then bump("garden_fx") end
        end
        -- jangan flatten MeshPart/Part di garden (pohon/fruit/soil tetap tampil)
        return
    end

    if isSprinklerRangeVisual(inst) then
        killSprinklerRange(inst)
        return
    end

    if shouldSkip(inst, char) then return end
    local cls = inst.ClassName

    if nameIsFx(inst.Name) then
        if safeDestroy(inst) then bump("fx_named") end
        return
    end

    if DESTROY_CLASSES[cls] then
        if safeDestroy(inst) then bump("destroy_" .. cls) end
        return
    end

    if cls == "MeshPart" then
        pcall(function()
            if inst.TextureID ~= "" then
                inst.TextureID = ""
                bump("mesh_tex")
            end
        end)
    elseif cls == "SpecialMesh" then
        pcall(function()
            if inst.TextureId ~= "" then
                inst.TextureId = ""
                bump("special_tex")
            end
        end)
    end

    if FLATTEN_CLASSES[cls] then
        pcall(function()
            if inst.CastShadow then
                inst.CastShadow = false
                bump("shadow_off")
            end
        end)
        pcall(function()
            if inst.Material ~= Enum.Material.SmoothPlastic then
                inst.Material = Enum.Material.SmoothPlastic
                bump("material")
            end
        end)
    end
end

local function sweepSprinklerRange(root)
    if not root then return end
    if root:IsA("Tool") then
        stripSprinklerTool(root)
        return
    end
    -- tools di character / backpack
    for _, ch in ipairs(root:GetChildren()) do
        if ch:IsA("Tool") then
            stripSprinklerTool(ch)
        end
    end
    local list = root:GetDescendants()
    for i = #list, 1, -1 do
        local inst = list[i]
        if inst:IsA("Tool") then
            stripSprinklerTool(inst)
        elseif isSprinklerRangeVisual(inst) and not isSprinklerHandleRoot(inst) then
            killSprinklerRange(inst)
        end
    end
end

-- Yield tiap ~8ms biar ga script-timeout di farm besar (6GB+ memory)
local STRIP_SLICE_SEC = 0.008

local function stripWorkspace()
    local char = LocalPlayer and LocalPlayer.Character
    if char then sweepSprinklerRange(char) end
    if LocalPlayer and LocalPlayer:FindFirstChild("Backpack") then
        sweepSprinklerRange(LocalPlayer.Backpack)
    end
    local list = Workspace:GetDescendants()
    local t0 = os.clock()
    for i = #list, 1, -1 do
        processInstance(list[i], char)
        if (os.clock() - t0) >= STRIP_SLICE_SEC then
            task.wait()
            t0 = os.clock()
            if not running then return end
        end
    end
end

local function stripOtherCharacters()
    for _, plr in ipairs(Players:GetPlayers()) do
        if plr ~= LocalPlayer then
            local char = plr.Character
            if char then
                for _, inst in ipairs(char:GetDescendants()) do
                    local cls = inst.ClassName
                    if DESTROY_CLASSES[cls] or cls == "Shirt" or cls == "Pants"
                        or cls == "ShirtGraphic" or cls == "CharacterMesh" then
                        if safeDestroy(inst) then bump("other_char") end
                    elseif FLATTEN_CLASSES[cls] then
                        pcall(function()
                            inst.CastShadow = false
                            if inst:IsA("MeshPart") then inst.TextureID = "" end
                        end)
                    end
                end
            end
        end
    end
end

local function hookLive(myToken)
    table.insert(conns, Workspace.DescendantAdded:Connect(function(inst)
        if not running or myToken ~= token then return end
        task.defer(function()
            if not running or myToken ~= token then return end
            processInstance(inst, LocalPlayer and LocalPlayer.Character)
        end)
    end))

    table.insert(conns, Lighting.ChildAdded:Connect(function(child)
        if not running or myToken ~= token then return end
        local className = child.ClassName
        if LIGHTING_WEATHER_KEEP[className] then return end
        if LIGHTING_FX_CLASSES[className] then
            task.defer(function()
                if not child.Parent then return end
                if LIGHTING_WEATHER_KEEP[child.ClassName] then return end
                if safeDestroy(child) then bump("lighting_fx_live") end
            end)
        end
    end))

    table.insert(conns, Players.PlayerAdded:Connect(function(plr)
        table.insert(conns, plr.CharacterAdded:Connect(function()
            task.wait(0.4)
            if running and myToken == token then
                stripOtherCharacters()
            end
        end))
    end))

    -- Character sendiri: strip sprinkler tool radius SEGERA (jangan destroy Handle)
    local function bindChar(char)
        if not char then return end
        sweepSprinklerRange(char)

        table.insert(conns, char.DescendantAdded:Connect(function(inst)
            if not running or myToken ~= token then return end
            -- sync segera — delay = 1 frame lag spike sudah ke-render
            if isSprinklerRangeVisual(inst) and not isSprinklerHandleRoot(inst) then
                killSprinklerRange(inst)
                return
            end
            if inst:GetAttribute("ClientHandle") == true then
                stripSprinklerTool(inst:FindFirstAncestorOfClass("Tool") or inst.Parent)
                return
            end
            if inst:IsA("Tool") then
                stripSprinklerTool(inst)
            end
        end))

        table.insert(conns, char.ChildAdded:Connect(function(ch)
            if not running or myToken ~= token then return end
            if ch:IsA("Tool") then
                stripSprinklerTool(ch)
                -- clone handle muncul beberapa frame kemudian
                task.defer(function()
                    if running then stripSprinklerTool(ch) end
                end)
                task.delay(0.1, function()
                    if running and ch.Parent then stripSprinklerTool(ch) end
                end)
                task.delay(0.35, function()
                    if running and ch.Parent then stripSprinklerTool(ch) end
                end)
            end
        end))

        -- tool yang sudah dipegang
        for _, ch in ipairs(char:GetChildren()) do
            if ch:IsA("Tool") then stripSprinklerTool(ch) end
        end
    end

    if LocalPlayer then
        if LocalPlayer.Character then
            bindChar(LocalPlayer.Character)
        end
        table.insert(conns, LocalPlayer.CharacterAdded:Connect(function(char)
            task.wait(0.1)
            if running and myToken == token then
                bindChar(char)
            end
        end))

        local bp = LocalPlayer:FindFirstChild("Backpack")
        if bp then
            table.insert(conns, bp.ChildAdded:Connect(function(ch)
                if running and ch:IsA("Tool") then
                    stripSprinklerTool(ch)
                end
            end))
        end
    end

    -- heartbeat RINGAN: cuma cari SprinklerRadius (bukan full GetDescendants tool)
    local acc = 0
    table.insert(conns, RunService.Heartbeat:Connect(function(dt)
        if not running or myToken ~= token then return end
        acc += dt
        if acc < 0.5 then return end
        acc = 0
        local char = LocalPlayer and LocalPlayer.Character
        if not char then return end
        for _, ch in ipairs(char:GetChildren()) do
            if ch:IsA("Tool") and (ch:GetAttribute("Sprinkler") ~= nil
                or string.lower(ch.Name):find("sprinkler", 1, true)) then
                local radius = ch:FindFirstChild("SprinklerRadius", true)
                if radius and not isSprinklerHandleRoot(radius) then
                    killSprinklerRange(radius)
                end
                -- radius kadang nama "Radius" di ClientHandle
                local handle = ch:FindFirstChild("Handle") or ch:FindFirstChildWhichIsA("BasePart")
                if handle then
                    local r2 = handle:FindFirstChild("SprinklerRadius", true)
                        or handle:FindFirstChild("RadiusRing", true)
                    if r2 and not isSprinklerHandleRoot(r2) then
                        killSprinklerRange(r2)
                    end
                end
            end
        end
    end))
end

----------------------------------------------------------------
-- API
----------------------------------------------------------------

local function worldLooksReady()
    if not LocalPlayer then return false end
    if not Workspace:FindFirstChild("Gardens") then return false end
    if LocalPlayer:GetAttribute("PlotId") == nil then return false end
    if not LocalPlayer.Character then return false end
    return true
end

local function gardenLoadLooksDone()
    if not LocalPlayer then return false end
    if LocalPlayer:GetAttribute("LoadingScreenDone") == true then
        return true
    end
    local total = tonumber(LocalPlayer:GetAttribute("GardenLoadingTotal"))
    local prog = tonumber(LocalPlayer:GetAttribute("GardenLoadingProgress")) or 0
    if total and total > 0 and prog >= total then
        return true
    end
    -- ReduceFPS sudah jalan = garden sudah di-handle
    if G.REMOVE_GARDEN_ACTIVE == true or rawget(_G, "REMOVE_GARDEN_ACTIVE") == true then
        return true
    end
    return false
end

local function isLoadingActive()
    if not LocalPlayer then return false end
    -- Dunia + plot siap → jangan stuck di LoadingScreenActive / menu sisa
    if worldLooksReady() and gardenLoadLooksDone() then
        return false
    end
    if LocalPlayer:GetAttribute("LoadingScreenDone") == true then
        return false
    end
    if LocalPlayer:GetAttribute("LoadingScreenActive") == true then
        -- Active sering nyangkut setelah skip loading UI — kalau plot sudah ada, anggap selesai
        if worldLooksReady() then
            return false
        end
        return true
    end
    local menu = Workspace:FindFirstChild("LoadingScreenMenu")
    if menu ~= nil then
        local active = true
        pcall(function()
            if menu:IsA("ScreenGui") and menu.Enabled == false then
                active = false
            end
        end)
        if active then
            if worldLooksReady() then
                return false
            end
            return true
        end
    end
    return false
end

local function waitLoadingDone(myToken, timeoutSec)
    -- Soft timeout default 60s: jangan infinite-wait (bug lama = ReduceLag "ON" tapi never strip).
    timeoutSec = tonumber(timeoutSec)
    if timeoutSec == nil or timeoutSec <= 0 then
        timeoutSec = 60
    end
    local t0 = os.clock()
    while running and myToken == token do
        if (os.clock() - t0) >= timeoutSec then
            break
        end
        if not isLoadingActive() or worldLooksReady() then
            task.wait(0.35)
            if not isLoadingActive() or worldLooksReady() then
                return true
            end
        end
        task.wait(0.2)
    end
    if not running or myToken ~= token then
        return false
    end
    if worldLooksReady() then
        warn("[ReduceLag] loading wait timeout — lanjut strip (plot ready)")
        return true
    end
    return not isLoadingActive()
end

local function startResweep(myToken)
    task.spawn(function()
        while running and myToken == token do
            task.wait(12)
            if not running or myToken ~= token then return end
            pcall(optimizeLighting)
            pcall(stripOtherCharacters)
            pcall(stripWorkspace)
            bump("resweep")
        end
    end)
end

function M.Stop()
    running = false
    token += 1
    disc()
    G.REDUCE_LAG_ENABLED = false
    _G.REDUCE_LAG_ENABLED = false
end

function M.Start()
    if running then
        -- Sudah "running" → force strip ulang sekarang (tanpa tunggu loading)
        token += 1
        local myToken = token
        disc()
        stripSprinklerAssetTemplates()
        optimizeQuality()
        optimizeLighting()
        optimizeTerrain()
        task.spawn(function()
            if not running or myToken ~= token then return end
            stripOtherCharacters()
            stripWorkspace()
            hookLive(myToken)
            startResweep(myToken)
            bump("restart_strip")
            -- resweep ringan setelah plot/garden muncul (loading mungkin masih jalan)
            for _, delaySec in ipairs({ 1.5, 4, 10 }) do
                task.wait(delaySec)
                if not running or myToken ~= token then return end
                pcall(optimizeLighting)
                pcall(stripOtherCharacters)
                pcall(stripWorkspace)
                bump("early_resweep")
            end
        end)
        return true
    end

    local cfg = _cfg()
    if not cfg.enabled then
        G.REDUCE_LAG_ENABLED = true
        _G.REDUCE_LAG_ENABLED = true
    end

    running = true
    token += 1
    local myToken = token
    stats = {}
    disc()

    G.REDUCE_LAG_ENABLED = true
    _G.REDUCE_LAG_ENABLED = true

    -- Template RS + lighting SEGERA (jangan nunggu loading)
    stripSprinklerAssetTemplates()
    optimizeQuality()
    optimizeLighting()
    optimizeTerrain()
    bump("boot_immediate")

    -- World strip / hooks SEGERA — LoadingScreenMenu tetap di-protect di strip path
    task.spawn(function()
        if not running or myToken ~= token then return end

        optimizeLighting()
        stripOtherCharacters()
        stripWorkspace()
        hookLive(myToken)
        startResweep(myToken)
        bump("world_strip_early")

        -- Garden/FX sering spawn belakangan saat loading — resweep bertahap
        for _, delaySec in ipairs({ 1.5, 4, 10 }) do
            task.wait(delaySec)
            if not running or myToken ~= token then return end
            pcall(optimizeLighting)
            pcall(stripOtherCharacters)
            pcall(stripWorkspace)
            bump("early_resweep")
        end
        bump("world_strip_done")
    end)

    return true
end

function M.SetEnabled(on)
    on = (on == true)
    G.REDUCE_LAG_ENABLED = on
    _G.REDUCE_LAG_ENABLED = on

    local MAIN = rawget(_G, "MAIN") or G.MAIN
    if type(MAIN) == "table" then
        MAIN.misc = MAIN.misc or {}
        MAIN.misc.perf = type(MAIN.misc.perf) == "table" and MAIN.misc.perf or {}
        MAIN.misc.perf.reduce_lag = on
        G.MAIN = MAIN
        _G.MAIN = MAIN
    end

    if on then
        M.Start()
    else
        M.Stop()
    end
end
M.setEnabled = M.SetEnabled

function M.IsEnabled()
    return running
end
M.isRunning = M.IsEnabled

function M.SyncFromGlobals()
    local cfg = _cfg()
    G.REDUCE_LAG_ENABLED = cfg.enabled
    _G.REDUCE_LAG_ENABLED = cfg.enabled
    if cfg.enabled then
        -- selalu Start: kalau stuck wait-loading, Start ulang akan force strip
        M.Start()
    else
        if running then
            M.Stop()
        end
    end
end

function M.GetStats()
    return {
        running = running,
        enabled = _cfg().enabled,
        stats = stats,
        worldReady = worldLooksReady(),
        loadingActive = isLoadingActive(),
        loadingDoneAttr = LocalPlayer and LocalPlayer:GetAttribute("LoadingScreenDone") == true,
    }
end

function M.DumpDebug()
    local s = M.GetStats()
    local parts = {}
    for k, v in pairs(s.stats or {}) do
        parts[#parts + 1] = tostring(k) .. "=" .. tostring(v)
    end
    table.sort(parts)
    print(string.format(
        "[ReduceLag] dump running=%s worldReady=%s loadingActive=%s doneAttr=%s | %s",
        tostring(s.running),
        tostring(s.worldReady),
        tostring(s.loadingActive),
        tostring(s.loadingDoneAttr),
        table.concat(parts, " ")
    ))
    return s
end
M.dumpDebug = M.DumpDebug

_G.__GAG2_REDUCE_LAG = {
    start = function() M.Start() end,
    stop = function() M.Stop() end,
    stats = function() return M.GetStats() end,
    dump = M.DumpDebug,
    sync = function() M.SyncFromGlobals() end,
}

G.ReduceLag = M
G.ReduceLagModule = M
_G.ReduceLag = M
_G.ReduceLagModule = M

return M
 end,                      required = false, early = true },
    { key = "ReduceFPS",               name = "Reduce FPS",              factory = function() --[[
    ReduceFPS.lua — Grow A Garden 2 (v10.22.4 mut-live)

    Soft shell hemat. OWN: strip OK, jangan Destroy.
    Mutasi buah: stamp boolean dari string Mutation + GardenSync SELAMA session
    (bukan cuma setelah rejoin). Listener AttributeChanged("Mutation").

    API:
      RestoreSoft() / RestoreFull() / DestroyFruit / pruneOwnFruits() / cleanupLooseProxies()
]]

local Players           = game:GetService("Players")
local CollectionService = game:GetService("CollectionService")
local Lighting          = game:GetService("Lighting")
local ReplicatedStorage = game:GetService("ReplicatedStorage")
local RunService        = game:GetService("RunService")
local SoundService      = game:GetService("SoundService")
local Workspace         = game:GetService("Workspace")

local LP = Players.LocalPlayer
if not LP then LP = Players.PlayerAdded:Wait() end

local G = (getgenv and getgenv()) or _G
local M = {}

local CONFIG = {
    mode = "brutal",
    fpsCap = 30,
    clearOtherPlants = true,
    stripOwnVisual = true,
    blockVisualInit = true, -- stub InitPlant + soft fruit shell (hemat)
    blockOtherSpawn = true, -- other: skip duplikat; 1 shell/tipe + SeedName
    -- false = soft shell UUID (default, ringan). true = game InitFruit lalu strip (berat/lag)
    gameManagedFruits = false,
    muteSounds = true,
    restoreOnStop = true,
    restoreBatchSize = 4,
    restoreBatchDelay = 0.55,
    restoreFruitBatchSize = 3,
    restoreFruitBatchDelay = 0.12,
    restoreRehide = true,
    restoreFullVisual = false,
    otherReconcileSec = 25,
    debug = false,
}

