-- FruitProxyUtil saja (JANGAN wrap Packet/Networking — itu bikin CollectFruit lemot).
local FPU_YIELD_MAX = 24
local fpuYieldActive = 0

local function installFruitProxyYieldGate()
    -- v2: hanya FPU — biar reload overwrite flag lama yang sempat wrap Networking
    if rawget(G, "__GAG2_FPU_YIELD_GATE_V2") == true then return true end
    local sm = ReplicatedStorage:FindFirstChild("SharedModules")
    local mod = sm and sm:FindFirstChild("FruitProxyUtil")
    if not mod then return false end
    local ok, FPU = pcall(require, mod)
    if not ok or type(FPU) ~= "table" then return false end

    local skip = {
        IsFruitInstance = true,
        isFruitInstance = true,
    }
    for k, v in pairs(FPU) do
        if type(v) == "function" and not skip[k] and not string.find(tostring(k), "__gag2", 1, true) then
            local orig = v
            if type(orig) == "function" then
                FPU[k] = function(...)
                    while fpuYieldActive >= FPU_YIELD_MAX do
                        task.wait(0.04)
                    end
                    fpuYieldActive += 1
                    local results = table.pack(pcall(orig, ...))
                    fpuYieldActive -= 1
                    if not results[1] then
                        local err = tostring(results[2] or "")
                        if err:find("128 yielded", 1, true) or err:find("yielded threads", 1, true) then
                            task.wait(0.25)
                            return nil
                        end
                        error(results[2], 0)
                    end
                    return table.unpack(results, 2, results.n)
                end
            end
        end
    end

    G.__GAG2_FPU_YIELD_GATE_V2 = true
    _G.__GAG2_FPU_YIELD_GATE_V2 = true
    -- clear flag lama biar tidak menyesatkan
    G.__GAG2_PACKET_YIELD_GATE = nil
    _G.__GAG2_PACKET_YIELD_GATE = nil
    return true
end

local function tagHarvestPrompt(prompt)
    if not prompt or not prompt.Parent then return end
    pcall(function()
        if not CollectionService:HasTag(prompt, "HarvestPrompt") then
            prompt:AddTag("HarvestPrompt")
        end
    end)
end

