local function debugOn()
    if G.REDUCE_FPS_DEBUG == false or rawget(_G, "REDUCE_FPS_DEBUG") == false then return false end
    if G.REDUCE_FPS_DEBUG == true or rawget(_G, "REDUCE_FPS_DEBUG") == true then return true end
    return CONFIG.debug == true
end

local function dlog(fmt, ...)
    if not debugOn() then return end
    local ok, msg = pcall(string.format, tostring(fmt), ...)
    print("[ReduceFPS] " .. (ok and msg or tostring(fmt)))
end

local function markActive()
    local on = alive and running
    G.REMOVE_GARDEN_ACTIVE = on
    _G.REMOVE_GARDEN_ACTIVE = on
end

local function disc(t)
    for _, c in ipairs(t) do pcall(function() c:Disconnect() end) end
    table.clear(t)
end

local function sliceYield()
    if (os.clock() - yieldT) >= SLICE then
        task.wait()
        yieldT = os.clock()
    end
end

local function _cfg()
    local MAIN = rawget(_G, "MAIN") or G.MAIN
    local perf = MAIN and MAIN.misc and MAIN.misc.perf
    perf = type(perf) == "table" and perf or {}
    local enabled = (G.REDUCE_FPS_ENABLED == true)
        or (rawget(_G, "REDUCE_FPS_ENABLED") == true)
        or (perf.enabled == true)
    CONFIG.clearOtherPlants = enabled == true
    -- Strip visual own = hemat FPS (soft shell). Jangan Destroy own (lihat destroyIfOtherPlant).
    CONFIG.stripOwnVisual = enabled == true
    if perf.hide_own == false or perf.strip_own == false then
        CONFIG.stripOwnVisual = false
    end
    if perf.block_visual_init ~= nil then
        CONFIG.blockVisualInit = perf.block_visual_init == true
    else
        CONFIG.blockVisualInit = enabled == true
    end
    if perf.block_other_spawn ~= nil then
        CONFIG.blockOtherSpawn = perf.block_other_spawn == true
    else
        CONFIG.blockOtherSpawn = enabled == true
    end
    if type(perf.restore_batch_size) == "number" and perf.restore_batch_size > 0 then
        CONFIG.restoreBatchSize = math.floor(perf.restore_batch_size)
    end
    if type(perf.restore_batch_delay) == "number" and perf.restore_batch_delay >= 0 then
        CONFIG.restoreBatchDelay = perf.restore_batch_delay
    end
    if type(perf.restore_fruit_batch_size) == "number" and perf.restore_fruit_batch_size > 0 then
        CONFIG.restoreFruitBatchSize = math.floor(perf.restore_fruit_batch_size)
    end
    if type(perf.restore_fruit_batch_delay) == "number" and perf.restore_fruit_batch_delay >= 0 then
        CONFIG.restoreFruitBatchDelay = perf.restore_fruit_batch_delay
    end
    if perf.restore_rehide ~= nil then
        CONFIG.restoreRehide = perf.restore_rehide == true
    end
    if perf.restore_full_visual ~= nil then
        CONFIG.restoreFullVisual = perf.restore_full_visual == true
    end
    -- Debug runtime-only (Misc toggle / _G) — tidak baca MAIN.misc.perf.debug
    CONFIG.debug = (G.REDUCE_FPS_DEBUG == true) or (rawget(_G, "REDUCE_FPS_DEBUG") == true)
    if perf.restore_on_stop ~= nil then
        CONFIG.restoreOnStop = perf.restore_on_stop == true
    end
    local render = perf.render
    if render == nil then render = true end
    CONFIG.mode = (render == false) and "nuclear" or "brutal"
    return { enabled = enabled == true, debug = CONFIG.debug }
end

----------------------------------------------------------------
-- Plot ownership
----------------------------------------------------------------
local function owned(plot)
    if not plot then return false end
    local u, n = LP.UserId, LP.Name
    local function m(v)
        return v ~= nil and (v == u or v == n or tostring(v) == tostring(u))
    end
    return m(plot:GetAttribute("OwnerId")) or m(plot:GetAttribute("Owner"))
        or m(plot:GetAttribute("OwnerUserId")) or m(plot:GetAttribute("UserId"))
end

local function isOwnPlot(plot)
    if not plot or not plot.Parent then return false end
    if cachedPlot and plot == cachedPlot then return true end
    if owned(plot) then
        cachedPlot = plot
        return true
    end
    local id = LP:GetAttribute("PlotId")
    if id ~= nil and plot.Name == ("Plot" .. tostring(id)) then
        cachedPlot = plot
        return true
    end
    if plot.Name == ("Plot" .. LP.Name) then
        cachedPlot = plot
        return true
    end
    return false
end

local function myPlot()
    if cachedPlot and cachedPlot.Parent then return cachedPlot end
    local g = Workspace:FindFirstChild("Gardens")
    if not g then return nil end
    local id = LP:GetAttribute("PlotId")
    if id ~= nil then
        local p = g:FindFirstChild("Plot" .. tostring(id))
        if p then cachedPlot = p return p end
        -- PlotId ada tapi model belom — jangan pakai plot lain
        return nil
    end
    for _, p in ipairs(g:GetChildren()) do
        if owned(p) then cachedPlot = p return p end
    end
    local byName = g:FindFirstChild("Plot" .. LP.Name)
    if byName then cachedPlot = byName return byName end
    return nil
end

local function plotOwnerUserId(plot)
    if not plot then return nil end
    local v = plot:GetAttribute("OwnerUserId")
        or plot:GetAttribute("OwnerId")
        or plot:GetAttribute("UserId")
        or plot:GetAttribute("Owner")
    local n = tonumber(v)
    if n then return n end
    if type(v) == "string" and v ~= "" then
        if v == LP.Name then return LP.UserId end
        local plr = Players:FindFirstChild(v)
        if plr then return plr.UserId end
    end
    return nil
end

-- Hanya true kalau PASTI plot orang lain. Ragu → false (jangan sentuh).
local function isConfirmedOtherPlot(plot)
    if not plot or not plot.Parent then return false end
    if isOwnPlot(plot) then return false end
    if owned(plot) then return false end

    local id = LP:GetAttribute("PlotId")
    if id ~= nil and plot.Name == ("Plot" .. tostring(id)) then
        return false
    end

    local mine = myPlot()
    if not mine or not mine.Parent then
        -- Plot sendiri belum ketahuan → jangan clear siapapun
        return false
    end
    if plot == mine then return false end

    local oid = plotOwnerUserId(plot)
    if oid == nil then return false end
    if oid == LP.UserId then return false end
    return true
end

-- Plant/fruit milik sendiri? Ragu → true (fail-safe: jangan Destroy)
local function isOwnPlantContext(inst)
    if not inst then return true end
    local uid = tonumber(inst:GetAttribute("UserId"))
    if uid == LP.UserId then return true end
    if uid ~= nil and uid ~= LP.UserId then return false end
    local p = inst
    for _ = 1, 14 do
        if not p then break end
        local par = p.Parent
        if par and par.Name == "Gardens" then
            if isOwnPlot(p) then return true end
            if isConfirmedOtherPlot(p) then return false end
            return true
        end
        p = par
    end
    return true
end

local function destroyIfOtherPlant(inst, plot)
    if not inst or not inst.Parent then return false end
    if plot and not isConfirmedOtherPlot(plot) then return false end
    if isOwnPlantContext(inst) then return false end
    local ok = pcall(function() inst:Destroy() end)
    return ok == true
end

local function getPVC()
    local ps = LP:FindFirstChild("PlayerScripts")
    local c = ps and ps:FindFirstChild("Controllers")
    local m = c and c:FindFirstChild("PlantVisualizerController")
    if not m then return nil end
    local ok, mod = pcall(require, m)
    return (ok and type(mod) == "table") and mod or nil
end

local function getFVC()
    local ps = LP:FindFirstChild("PlayerScripts")
    local c = ps and ps:FindFirstChild("Controllers")
    local m = c and c:FindFirstChild("FruitVisualizerController")
    if not m then return nil end
    local ok, mod = pcall(require, m)
    return (ok and type(mod) == "table") and mod or nil
end

local function listPlantFolders(plot, userId)
    local out, seen = {}, {}
    local function add(f)
        if f and f.Parent and not seen[f] and f:IsDescendantOf(plot) then
            seen[f] = true
            out[#out + 1] = f
        end
    end
    if not plot then return out end
    local important = plot:FindFirstChild("Important")
    for _, name in ipairs({ "Plants", "Plants_Physical", "PhysicalPlants" }) do
        add(plot:FindFirstChild(name))
        if important then add(important:FindFirstChild(name)) end
    end
    local vis = getPVC()
    if vis and type(vis.GetPlantsFolder) == "function" and userId then
        local ok, f = pcall(vis.GetPlantsFolder, vis, userId)
        if ok then add(f) end
    end
    return out
end

