local KEEP_FOLDER = {
    Fruits = true,
    Fruit = true,
    FruitSpawnLocations = true,
    FruitSpawnLocation = true,
    SpawnLocations = true,
    [PLANT_STASH] = true, -- jangan stash ulang
    [STASH_NAME] = true,
}

local function isKeepPart(inst)
    if not inst or not inst:IsA("BasePart") then return false end
    local n = tostring(inst.Name or "")
    if n == "HarvestPart" or n == "Harvest" or n == "CollectProxy" then return true end
    if CollectionService:HasTag(inst, PLANTAREA) then return true end
    if n:find("Spawn", 1, true) or n:find("Location", 1, true) then return true end
    return false
end

local function isKeepInstance(inst)
    if not inst then return true end
    if isKeepPart(inst) then return true end
    if inst:IsA("ProximityPrompt") or inst:IsA("ValueBase") or inst:IsA("Attachment") then
        return true
    end
    if inst:IsA("Folder") and KEEP_FOLDER[inst.Name] then return true end
    return false
end

local function isSprinkler(i)
    if not i then return false end
    if i:IsA("Model") and i:GetAttribute("SprinklerId") then return true end
    local c = i.Parent
    while c and c ~= game do
        if c.Name == "Sprinklers" then return true end
        c = c.Parent
    end
    return false
end

local function isFruitModel(model)
    if not model then return false end
    if model:GetAttribute("FruitId") ~= nil then return true end
    local p = model.Parent
    return p ~= nil and (p.Name == "Fruits" or p.Name == "Fruit")
end

local function underFruitsFolder(inst)
    local p = inst
    for _ = 1, 12 do
        if not p then return false end
        if p.Name == "Fruits" or p.Name == "Fruit" then return true end
        if p.Name == "Gardens" then return false end
        p = p.Parent
    end
    return false
end

local function hideHarvestWanted()
    if G.HIDE_HARVEST_PROMPT_ENABLED == true then return true end
    if rawget(_G, "HIDE_HARVEST_PROMPT_ENABLED") == true then return true end
    local MAIN = rawget(_G, "MAIN") or G.MAIN
    local cfg = MAIN and MAIN.misc and MAIN.misc.hide_harvest_prompt
    return type(cfg) == "table" and cfg.enabled == true
end

local function ensureProxy(model)
    -- Hanya Model plant/fruit. JANGAN Folder Fruits / Part lepas (orphan di Fruits).
    if not model or not model:IsA("Model") then return nil, nil end
    if model.Name == "Fruits" or model.Name == "Fruit" then return nil, nil end
    local par = model.Parent
    if par and (par.Name == "Fruits" or par.Name == "Fruit") then
        -- fruit UUID: soft shell pakai HarvestPart/ShellBody saja (bukan CollectProxy plant)
        if model:GetAttribute(FRUIT_SHELL_ATTR) == true then
            return nil, nil
        end
    end
    local hp = model:FindFirstChild("HarvestPart")
    if not (hp and hp:IsA("BasePart")) then
        hp = Instance.new("Part")
        hp.Name = "HarvestPart"
        hp.Size = Vector3.new(1.5, 1.5, 1.5)
        hp.Transparency = 1
        hp.Anchored = true
        hp.CanCollide = false
        hp.CanQuery = false
        hp.CastShadow = false
        hp.Parent = model
    end
    local proxy = model:FindFirstChild("CollectProxy")
    if not (proxy and proxy:IsA("BasePart")) then
        proxy = Instance.new("Part")
        proxy.Name = "CollectProxy"
        proxy.Size = Vector3.new(3, 3, 3)
        proxy.Transparency = 1
        proxy.Anchored = true
        proxy.CanCollide = false
        proxy.CanQuery = true
        proxy.CastShadow = false
        proxy.Parent = model
    else
        pcall(function() proxy.CanQuery = true end)
    end
    pcall(function()
        local cf = model:GetPivot()
        hp.CFrame = cf
        proxy.CFrame = cf
        if model:IsA("Model") then model.PrimaryPart = proxy end
    end)
    return hp, proxy
end

local LOOSE_PROXY_NAMES = {
    CollectProxy = true,
    HarvestPart = true,
    ShellBody = true,
    Harvest = true,
}

-- Hapus CollectProxy/HarvestPart/ShellBody yang nyasar langsung di folder Fruits
local function cleanupLooseFruitProxies(plant)
    if not plant then return 0 end
    local folder = plant:FindFirstChild("Fruits") or plant:FindFirstChild("Fruit")
    if not folder then return 0 end
    local n = 0
    for _, ch in ipairs(folder:GetChildren()) do
        -- Part lepas ATAU Model kosong bernama proxy (bukan fruit UUID)
        if ch:IsA("BasePart") and LOOSE_PROXY_NAMES[ch.Name] then
            if pcall(function() ch:Destroy() end) then n += 1 end
        elseif ch:IsA("Model") and LOOSE_PROXY_NAMES[ch.Name] and ch:GetAttribute("FruitId") == nil then
            if pcall(function() ch:Destroy() end) then n += 1 end
        end
    end
    return n
end

local function cleanupAllOwnLooseProxies()
    local plot = myPlot()
    if not plot then return 0 end
    local n = 0
    for _, folder in ipairs(listPlantFolders(plot, LP.UserId)) do
        for _, plant in ipairs(folder:GetChildren()) do
            if plant:IsA("Model") then
                n += cleanupLooseFruitProxies(plant)
            end
        end
    end
    if n > 0 then
        dlog("cleanupLooseProxies removed=%d", n)
    end
    return n
end

local fruitsFolderBound = {} -- [folder] = conn
local function bindFruitsFolderCleanup(folder)
    if not folder or fruitsFolderBound[folder] then return end
    fruitsFolderBound[folder] = folder.ChildAdded:Connect(function(ch)
        if not alive then return end
        if ch:IsA("BasePart") and LOOSE_PROXY_NAMES[ch.Name] then
            task.defer(function()
                if ch.Parent == folder then
                    pcall(function() ch:Destroy() end)
                end
            end)
        end
    end)
    -- bersihkan yang sudah ada
    cleanupLooseFruitProxies(folder.Parent)
end

-- Type name helpers (Other Sprinkler UI butuh SeedName di model, bukan di fruit/child)
local function looksLikeTypeId(s)
    s = tostring(s or "")
    if s == "" then return true end
    if s:match("^%d+_[%x%-]+") then return true end
    if #s >= 32 and s:match("^[%x%-]+$") then return true end
    if s:find("_", 1, true) and s:find("-", 1, true) and not s:match("^[%a][%a%d ]*$") then
        return true
    end
    return false
end

local function normalizeTypeName(v)
    if type(v) ~= "string" then return nil end
    v = v:gsub("^%s+", ""):gsub("%s+$", "")
    if v == "" or looksLikeTypeId(v) then return nil end
    local tail = v:match("([^/]+)$")
    if tail and not looksLikeTypeId(tail) then return tail end
    return v
end

local function seedNameFromData(data)
    if type(data) ~= "table" then return nil end
    for _, k in ipairs({
        "SeedName", "PlantName", "ItemName", "ConfigPathName",
        "CorePartName", "FruitType", "FruitName", "Type", "Name",
    }) do
        local n = normalizeTypeName(data[k])
        if n then return n end
    end
    return nil
end

local function pickTypeFromInst(inst)
    if not inst then return nil end
    for _, key in ipairs({
        "SeedName", "PlantName", "FruitType", "FruitName",
        "ItemName", "CorePartName", "ConfigPathName",
    }) do
        local n = normalizeTypeName(inst:GetAttribute(key))
        if n then return n end
    end
    return nil
end

local function discoverPlantTypeName(plant)
    if not plant then return nil end
    local n = pickTypeFromInst(plant)
    if n then return n end
    for _, ch in ipairs(plant:GetChildren()) do
        n = pickTypeFromInst(ch)
        if n then return n end
        if ch.Name == "Fruits" or ch.Name == "Fruit" then
            for _, fruit in ipairs(ch:GetChildren()) do
                n = pickTypeFromInst(fruit)
                if n then return n end
            end
        end
    end
    return nil
end

local function stampPlantTypeAttrs(plant, data)
    if not plant then return nil end
    local name = seedNameFromData(data) or discoverPlantTypeName(plant)
    if not name then
        local uid = tonumber(plant:GetAttribute("UserId"))
        local pid = plant:GetAttribute("PlantId")
        if uid and pid ~= nil then
            local ps = LP:FindFirstChild("PlayerScripts")
            local c = ps and ps:FindFirstChild("Controllers")
            local m = c and c:FindFirstChild("GardenSyncController")
            if m then
                pcall(function()
                    local sync = require(m)
                    if type(sync) == "table" and type(sync.GetPlant) == "function" then
                        name = seedNameFromData(sync:GetPlant(uid, pid))
                    end
                end)
            end
        end
    end
    if not name then return nil end
    pcall(function()
        if plant:GetAttribute("SeedName") == nil then
            plant:SetAttribute("SeedName", name)
        end
        if plant:GetAttribute("ItemName") == nil then
            plant:SetAttribute("ItemName", name)
        end
    end)
    return name
end

local function stripOtherPlantShell(plant, data)
    if not plant or not plant.Parent then return end
    -- proxy dulu selagi geometry masih ada (pivot benar untuk watering)
    ensureProxy(plant)
    stampPlantTypeAttrs(plant, data)
    for _, c in ipairs(plant:GetChildren()) do
        if not isKeepInstance(c) then
            if c:IsA("Folder") and (c.Name == "Fruits" or c.Name == "Fruit") then
                pcall(function() c:ClearAllChildren() end)
            else
                pcall(function() c:Destroy() end)
            end
        end
    end
end

local function folderHasTypedPlant(folder, typeName, except)
    if not folder or not typeName then return false end
    local want = string.lower(tostring(typeName))
    for _, ch in ipairs(folder:GetChildren()) do
        if ch ~= except and ch:IsA("Model") and not isSprinkler(ch) then
            local k = normalizeTypeName(ch:GetAttribute("SeedName"))
                or normalizeTypeName(ch:GetAttribute("ItemName"))
                or discoverPlantTypeName(ch)
            if k and string.lower(k) == want then
                return true
            end
        end
    end
    return false
end

local function plantTypeKey(plant)
    -- stamp dulu dari child/fruit sebelum strip (UI sprinkler baca SeedName di model)
    local name = stampPlantTypeAttrs(plant)
        or normalizeTypeName(plant:GetAttribute("SeedName"))
        or normalizeTypeName(plant:GetAttribute("ConfigPathName"))
        or normalizeTypeName(plant:GetAttribute("ItemName"))
        or discoverPlantTypeName(plant)
    if name and name ~= "" then return name end
    -- jangan pakai plant.Name (UUID) — itu bikin keep semua + tipe UI kosong
    return "_pending"
end

local function tunePrompt(pr)
    if not pr or not pr:IsA("ProximityPrompt") then return end
    pcall(function()
        if hideHarvestWanted() then
            pr.Enabled = false
            pr.MaxActivationDistance = 0
            return
        end
        pr.Enabled = true
        pr.MaxActivationDistance = 32
        pr.RequiresLineOfSight = false
        pr.HoldDuration = 0
    end)
end

----------------------------------------------------------------
-- OWN hide: LTM only (jangan reparent — biar restore 100%)
----------------------------------------------------------------
local function ltmTree(inst, on)
    if not inst then return end
    local mod = on and 1 or 0
    local function one(p)
        if not p:IsA("BasePart") then return end
        if isKeepPart(p) then return end
        pcall(function()
            p.LocalTransparencyModifier = mod
            if on then
                p.CastShadow = false
                if p.Name ~= "CollectProxy" and p.Name ~= "HarvestPart" then
                    p.CanCollide = false
                end
            end
        end)
    end
    if inst:IsA("BasePart") then one(inst) end
    for _, d in ipairs(inst:GetDescendants()) do
        if d:IsA("BasePart") then
            one(d)
        elseif on and (d:IsA("ParticleEmitter") or d:IsA("Trail") or d:IsA("Beam")
            or d:IsA("Fire") or d:IsA("Smoke") or d:IsA("Sparkles")
            or d:IsA("Highlight") or d:IsA("SelectionBox")) then
            pcall(function() d.Enabled = false end)
        elseif (not on) and (d:IsA("ParticleEmitter") or d:IsA("Trail") or d:IsA("Beam")
            or d:IsA("Fire") or d:IsA("Smoke") or d:IsA("Sparkles")) then
            pcall(function() d.Enabled = true end)
        end
    end
end

-- nama lama: stashVisual — sekarang LTM only (no Parent move)
local function stashVisual(inst, homePlant)
    if not inst or not inst.Parent or not homePlant then return false end
    if isKeepInstance(inst) then return false end
    if inst.Name == PLANT_STASH or inst.Name == STASH_NAME then return false end
    if stashMap[inst] then
        ltmTree(inst, true)
        return false
    end
    -- legacy: kalau sempat ter-reparent ke _GAG2Stash, kembalikan dulu ke plant
    if inst.Parent and inst.Parent.Name == PLANT_STASH and inst.Parent.Parent == homePlant then
        pcall(function() inst.Parent = homePlant end)
    end
    stashMap[inst] = homePlant
    ltmTree(inst, true)
    stats.stashed += 1
    return true
end

----------------------------------------------------------------
-- Garden spawn (LoadingScreen attrs) — BUKAN tunggu click/skip UI
----------------------------------------------------------------
local function countOwnPlants()
    local plot = myPlot()
    if not plot then return 0 end
    local n = 0
    for _, folder in ipairs(listPlantFolders(plot, LP.UserId)) do
        n += #folder:GetChildren()
    end
    return n
end

local function isGardenSpawnComplete()
    -- Jangan nunggu LoadingScreenDone / click — itu UI only (+ hold 5s)
    if LP:GetAttribute("LoadingScreenDone") == true then
        return true
    end
    local total = tonumber(LP:GetAttribute("GardenLoadingTotal"))
    local prog = tonumber(LP:GetAttribute("GardenLoadingProgress")) or 0
    if total and total > 0 then
        return prog >= total
    end
    return false
end

local function waitGardenSpawnComplete(timeoutSec)
    timeoutSec = tonumber(timeoutSec) or 90
    local t0 = os.clock()
    local lastCount, stableAt = -1, os.clock()
    local sawGardenJob = false
    local dataLoadedAt = nil
    dlog("waitGardenSpawn begin (GardenLoading* attrs only, skip UI hold/click)")
    while os.clock() - t0 < timeoutSec do
        local total = tonumber(LP:GetAttribute("GardenLoadingTotal"))
        local prog = tonumber(LP:GetAttribute("GardenLoadingProgress")) or 0
        if total and total > 0 then
            sawGardenJob = true
        end
        if CollectionService:HasTag(LP, "DataLoaded") and not dataLoadedAt then
            dataLoadedAt = os.clock()
        end

        local count = countOwnPlants()
        if count ~= lastCount then
            lastCount = count
            stableAt = os.clock()
        end
        local stable = (os.clock() - stableAt) >= 1.0

        -- Path A: garden job selesai (progress == total) + plant count settle
        if sawGardenJob and total and total > 0 and prog >= total and stable then
            dlog("waitGardenSpawn OK job %d/%d plants=%d ms=%.0f",
                prog, total, count, (os.clock() - t0) * 1000)
            task.wait(0.3)
            return true
        end

        -- Path B: loading UI sudah selesai (user skip / hide loading)
        if LP:GetAttribute("LoadingScreenDone") == true and stable then
            dlog("waitGardenSpawn via LoadingScreenDone plants=%d", count)
            return true
        end

        -- Path C: DataLoaded lama, tidak pernah ada GardenLoadingTotal (garden kosong / attr hilang)
        if dataLoadedAt and not sawGardenJob and CollectionService:HasTag(LP, "ControllersStarted")
            and (os.clock() - dataLoadedAt) >= 3.0 and stable then
            dlog("waitGardenSpawn no-job path plants=%d ms=%.0f", count, (os.clock() - t0) * 1000)
            return true
        end

        task.wait(0.12)
    end
    dlog("waitGardenSpawn timeout plants=%d complete=%s",
        countOwnPlants(), tostring(isGardenSpawnComplete()))
    return isGardenSpawnComplete() or myPlot() ~= nil
end

----------------------------------------------------------------
-- FRUIT: LTM only (detect tetap)
----------------------------------------------------------------
local function hideFruit(model)
    if not model or not model.Parent then return 0 end
    if not model:IsA("Model") then return 0 end
    -- soft shell: jangan CollectProxy; part hanya di dalam UUID
    if model:GetAttribute(FRUIT_SHELL_ATTR) ~= true then
        ensureProxy(model)
    end
    local n = 0
    for _, d in ipairs(model:GetDescendants()) do
        if d:IsA("ProximityPrompt") then
            tunePrompt(d)
        elseif d:IsA("BasePart") then
            pcall(function()
                d.LocalTransparencyModifier = 1
                d.CastShadow = false
                if d.Name == "CollectProxy" then
                    d.CanQuery = true
                else
                    d.CanCollide = false
                end
            end)
            n += 1
        elseif d:IsA("ParticleEmitter") or d:IsA("Trail") or d:IsA("Beam")
            or d:IsA("Fire") or d:IsA("Smoke") or d:IsA("Sparkles") then
            pcall(function() d.Enabled = false end)
        end
    end
    pcall(function() model:SetAttribute(FRUIT_ATTR, true) end)
    local fp = model.Parent
    if fp and (fp.Name == "Fruits" or fp.Name == "Fruit") then
        cleanupLooseFruitProxies(fp.Parent)
    end
    stats.fruits += 1
    return n
end

----------------------------------------------------------------
-- POHON: LTM hide. Fruits folder → hideFruit.
----------------------------------------------------------------
local function hidePlantTree(plant)
    if not plant or not plant.Parent then return 0 end
    if isSprinkler(plant) then return 0 end
    if isFruitModel(plant) then return hideFruit(plant) end

    ensureProxy(plant)
    local n = 0
    local kids = plant:GetChildren()
    for i = 1, #kids do
        local ch = kids[i]
        if isKeepInstance(ch) then
            if ch:IsA("Folder") and (ch.Name == "Fruits" or ch.Name == "Fruit") then
                bindFruitsFolderCleanup(ch)
                cleanupLooseFruitProxies(plant)
                for _, fruit in ipairs(ch:GetChildren()) do
                    if fruit:IsA("Model") and fruit:GetAttribute("FruitId") ~= nil then
                        n += hideFruit(fruit)
                    elseif fruit:IsA("BasePart") and LOOSE_PROXY_NAMES[fruit.Name] then
                        pcall(function() fruit:Destroy() end)
                    end
                    sliceYield()
                end
            end
        elseif ch:IsA("Model") and isFruitModel(ch) then
            n += hideFruit(ch)
        else
            if stashVisual(ch, plant) then
                n += 1
            end
        end
        if i % BATCH == 0 then sliceYield() end
    end

    pcall(function() plant:SetAttribute(TREE_ATTR, true) end)
    return n
end

----------------------------------------------------------------
-- RESTORE own plants (LTM clear + legacy stash folders)
----------------------------------------------------------------
local function findOwnPlantByKey(key)
    key = tostring(key or "")
    if key == "" then return nil end
    local plot = myPlot()
    if not plot then return nil end
    for _, folder in ipairs(listPlantFolders(plot, LP.UserId)) do
        for _, plant in ipairs(folder:GetChildren()) do
            if tostring(plant:GetAttribute("PlantId") or "") == key
                or plant.Name == key then
                return plant
            end
        end
    end
    return nil
end

local function restoreInstToPlant(inst, home)
    if not inst or not inst.Parent or not home or not home.Parent then return false end
    if inst.Parent ~= home then
        local ok = pcall(function()
            inst.Parent = home
        end)
        if not (ok and inst.Parent == home) then
            return false
        end
    end
    ltmTree(inst, false)
    return true
end

local function restoreOwnPlants()
    local t0 = os.clock()
    local n = 0
    local dead = {}

    for inst, home in pairs(stashMap) do
        if not inst or not inst.Parent then
            dead[#dead + 1] = inst
        else
            local target = (home and home.Parent) and home or inst.Parent
            if target and target.Name == PLANT_STASH then
                target = target.Parent
            end
            if target then
                if restoreInstToPlant(inst, target) then
                    n += 1
                    stats.restored += 1
                else
                    ltmTree(inst, false)
                    n += 1
                    stats.restored += 1
                end
            end
            dead[#dead + 1] = inst
        end
        if n % BATCH == 0 then sliceYield() end
    end
    for i = 1, #dead do
        stashMap[dead[i]] = nil
    end

    local plot = myPlot()
    if plot then
        for _, folder in ipairs(listPlantFolders(plot, LP.UserId)) do
            for _, plant in ipairs(folder:GetChildren()) do
                local bucket = plant:FindFirstChild(PLANT_STASH)
                if bucket and bucket:IsA("Folder") then
                    local kids = bucket:GetChildren()
                    for i = 1, #kids do
                        if restoreInstToPlant(kids[i], plant) then
                            n += 1
                            stats.restored += 1
                        end
                        if i % BATCH == 0 then sliceYield() end
                    end
                    if #bucket:GetChildren() == 0 then
                        pcall(function() bucket:Destroy() end)
                    end
                end

                ltmTree(plant, false)
                pcall(function() plant:SetAttribute(TREE_ATTR, nil) end)

                local fr = plant:FindFirstChild("Fruits") or plant:FindFirstChild("Fruit")
                if fr then
                    for _, fruit in ipairs(fr:GetChildren()) do
                        pcall(function() fruit:SetAttribute(FRUIT_ATTR, nil) end)
                        ltmTree(fruit, false)
                    end
                end
                n += 1
                sliceYield()
            end
        end
    end

    local root = LP:FindFirstChild("PlayerGui")
    root = root and root:FindFirstChild(STASH_NAME)
    if not root then root = LP:FindFirstChild(STASH_NAME) end
    if root then
        for _, bucket in ipairs(root:GetChildren()) do
            local home = findOwnPlantByKey(bucket.Name)
            if home then
                local kids = bucket:GetChildren()
                for i = 1, #kids do
                    if restoreInstToPlant(kids[i], home) then
                        n += 1
                        stats.restored += 1
                    end
                    if i % BATCH == 0 then sliceYield() end
                end
            end
            if #bucket:GetChildren() == 0 then
                pcall(function() bucket:Destroy() end)
            end
        end
        if #root:GetChildren() == 0 then
            pcall(function() root:Destroy() end)
        end
    end

    table.clear(stashMap)
    dlog("RestoreOwn cleared=%d plants=%d ms=%.0f", n, countOwnPlants(), (os.clock() - t0) * 1000)
    return n
end

----------------------------------------------------------------
-- Restore dari garden DATA (PVC / GardenSync) — jalur resmi game
----------------------------------------------------------------
local function getNetworking()
    local ok, net = pcall(function()
        return require(ReplicatedStorage:WaitForChild("SharedModules"):WaitForChild("Networking", 5))
    end)
    return (ok and type(net) == "table") and net or nil
end

local function getGardenSync()
    local ps = LP:FindFirstChild("PlayerScripts")
    local c = ps and ps:FindFirstChild("Controllers")
    local m = c and c:FindFirstChild("GardenSyncController")
    if not m then return nil end
    local ok, mod = pcall(require, m)
    return (ok and type(mod) == "table") and mod or nil
end

local function requestGardensFire()
    local net = getNetworking()
    local rg = net and net.Garden and net.Garden.RequestGardens
    if not rg then
        dlog("RequestGardens missing")
        return false
    end
    local ok, err = pcall(function()
        if type(rg.Fire) == "function" then
            rg:Fire()
        elseif type(rg) == "function" then
            rg()
        end
    end)
    if not ok then
        dlog("RequestGardens fail: %s", tostring(err))
        return false
    end
    dlog("RequestGardens fired")
    return true
end

local function reconcileLocalGarden()
    local sync = getGardenSync()
    if not sync then
        dlog("GardenSyncController missing")
        return false
    end
    if type(sync.ReconcileLocalGarden) == "function" then
        local ok, err = pcall(function()
            sync:ReconcileLocalGarden()
        end)
        if not ok then
            dlog("ReconcileLocalGarden fail: %s", tostring(err))
            return false
        end
        dlog("ReconcileLocalGarden ok")
        return true
    end
    return false
end

-- Isi ulang plant visual yang hilang dari cache PVC (sama OnPlantVisualCheck)
local function respawnMissingOwnPlants()
    local sync = getGardenSync()
    local pvc = getPVC()
    if not sync or not pvc then return 0 end
    if type(sync.GetGarden) ~= "function" or type(pvc.SpawnPlantFromData) ~= "function" then
        return 0
    end
    local garden = nil
    pcall(function()
        garden = sync:GetGarden(LP.UserId)
    end)
    if type(garden) ~= "table" then return 0 end

    local n = 0
    for plantId, data in pairs(garden) do
        if type(data) == "table" then
            local existing = nil
            if type(pvc.GetSpawnedPlant) == "function" then
                pcall(function()
                    existing = pvc:GetSpawnedPlant(LP.UserId, plantId)
                end)
            end
            local need = (not existing) or (typeof(existing) == "Instance" and not existing.Parent)
            if need then
                local ok = pcall(function()
                    pvc:SpawnPlantFromData(LP.UserId, plantId, data)
                end)
                if ok then
                    n += 1
                    stats.restored += 1
                end
                sliceYield()
            end
        end
    end
    if n > 0 then
        dlog("respawnMissingOwnPlants count=%d", n)
    end
    return n
end

-- forward decl
local startPrevent, stopPrevent, restoreGardenFromData, stripPlantKeepDetect, restoreAfterGardenReady
local syncOwnShellHarvestFromSync

----------------------------------------------------------------
-- BLOCK visual init (anti CPU spike saat loading)
----------------------------------------------------------------
-- Strip mesh SAJA. Jangan hancurkan Model / Folder Fruits / attrs (PlantId/FruitId).
-- PENTING: FruitSpawnLocations BasePart HARUS tetap — FVC SpawnFruitFromData gagal diam tanpa itu.
local function isDetectKeepInstance(d)
    if not d then return true end
    if isKeepInstance(d) then return true end
    if d:IsA("ProximityPrompt") or d:IsA("Attachment") or d:IsA("ValueBase") then
        return true
    end
    if d.Name == "HarvestPart" or d.Name == "CollectProxy" or d.Name == "ShellBody"
        or d.Name == PLANT_STASH then
        -- orphan lepas di folder Fruits → jangan keep (biar cleanup bisa destroy)
        local p = d.Parent
        if p and (p.Name == "Fruits" or p.Name == "Fruit") and d:IsA("BasePart") then
            return false
        end
        return true
    end
    if d:IsA("Folder") and (d.Name == "Fruits" or d.Name == "Fruit"
        or d.Name == "FruitSpawnLocations" or d.Name == "FruitSpawnLocation"
        or d.Name == "SpawnLocations") then
        return true
    end
    -- spawn locator parts (anak FruitSpawnLocations)
    if d:IsA("BasePart") then
        local p = d.Parent
        if p and (p.Name == "FruitSpawnLocations" or p.Name == "FruitSpawnLocation"
            or p.Name == "SpawnLocations") then
            return true
        end
        local n = tostring(d.Name or "")
        if n:find("Spawn", 1, true) or n:find("Location", 1, true) then
            return true
        end
    end
    -- container model fruit/plant — jangan Destroy; anak visual di-strip terpisah
    if d:IsA("Model") and (d:GetAttribute("FruitId") ~= nil or d:GetAttribute("PlantId") ~= nil) then
        return true
    end
    return false
end

-- Pastikan FruitSpawnLocations punya BasePart (FVC + status Mx sprinkler/watering)
-- Kapasitas = max buah / pohon (SeedData), BUKAN jumlah buah yang sedang ada.
local _seedSlotCache = {} -- [seedName] = n|false
local function seedFruitCapacity(seedName)
    seedName = tostring(seedName or "")
    if seedName == "" then return nil end
    local cached = _seedSlotCache[seedName]
    if cached == false then return nil end
    if type(cached) == "number" then return cached end
    local n = nil
    pcall(function()
        local pvc = getPVC()
        if pvc and type(pvc.GetSeedData) == "function" then
            local e = pvc:GetSeedData(seedName)
            if type(e) == "table" then
                if e.IsSingleHarvest == true then n = 1 end
                n = n or tonumber(e.FruitSlots) or tonumber(e.MaxFruits) or tonumber(e.MaxFruit)
                    or tonumber(e.MaxFruitCount) or tonumber(e.FruitAmount) or tonumber(e.FruitsPerPlant)
                    or tonumber(e.FruitSpawnCount) or tonumber(e.FruitSpawnAmount)
            end
        end
        if n == nil and pvc and type(pvc.IsSingleHarvestPlant) == "function" then
            local ok, single = pcall(pvc.IsSingleHarvestPlant, pvc, seedName)
            if ok and single == true then n = 1 end
        end
    end)
    if n == nil then
        pcall(function()
            local SeedData = require(ReplicatedStorage.SharedModules.SeedData)
            local e = type(SeedData) == "table" and SeedData[seedName]
            if type(e) ~= "table" and type(SeedData) == "table" then
                local want = string.lower(seedName)
                for k, v in pairs(SeedData) do
                    if type(v) == "table" then
                        local nm = tostring(v.SeedName or v.Name or k)
                        if string.lower(nm) == want then e = v break end
                    end
                end
            end
            if type(e) == "table" then
                if e.IsSingleHarvest == true then n = 1 end
                n = n or tonumber(e.FruitSlots) or tonumber(e.MaxFruits) or tonumber(e.MaxFruit)
                    or tonumber(e.MaxFruitCount) or tonumber(e.FruitAmount) or tonumber(e.FruitsPerPlant)
            end
        end)
    end
    -- Kapasitas nyata bisa 300+/pohon — JANGAN clamp 64 (Mx sprinkler jadi undercount)
    if n and n > 0 then
        _seedSlotCache[seedName] = math.clamp(math.floor(n), 1, 2048)
        return _seedSlotCache[seedName]
    end
    _seedSlotCache[seedName] = false
    return nil
end

-- Kapasitas buah/pohon (untuk attr + Mx). Locator fisik tetap dibatasi terpisah.
local FRUIT_CAP_MAX = 2048
local FRUIT_LOC_PARTS_MAX = 64 -- part locator saja (hemat); bukan kapasitas

local function desiredFruitSpawnSlots(plant)
    if not plant then return 1 end
    local n = tonumber(plant:GetAttribute("FruitSlots"))
        or tonumber(plant:GetAttribute("MaxFruits"))
        or tonumber(plant:GetAttribute("MaxFruit"))
        or tonumber(plant:GetAttribute("MaxFruitCount"))
        or tonumber(plant:GetAttribute("FruitCountMax"))
    if not n or n <= 0 then
        local seedName = plant:GetAttribute("SeedName")
            or plant:GetAttribute("ItemName")
            or plant:GetAttribute("ConfigPathName")
        n = seedFruitCapacity(seedName)
    end
    if n and n > 0 then
        n = math.clamp(math.floor(n), 1, FRUIT_CAP_MAX)
        pcall(function()
            local cur = tonumber(plant:GetAttribute("FruitSlots"))
            if cur == nil or cur < n then
                plant:SetAttribute("FruitSlots", n)
            end
        end)
        return n
    end
    local folder = plant:FindFirstChild("FruitSpawnLocations")
        or plant:FindFirstChild("FruitSpawnLocation")
        or plant:FindFirstChild("SpawnLocations")
    local lc = 0
    if folder then
        for _, ch in ipairs(folder:GetChildren()) do
            if ch:IsA("BasePart") then lc += 1 end
        end
    end
    -- Jangan pakai #Fruits sebagai kapasitas (under-count saat buah belum penuh)
    return math.clamp(math.max(lc, 1), 1, FRUIT_CAP_MAX)
end

local function ensureFruitSpawnLocations(plant, minSlots)
    if not plant or not plant.Parent then return nil end
    local folder = plant:FindFirstChild("FruitSpawnLocations")
        or plant:FindFirstChild("FruitSpawnLocation")
        or plant:FindFirstChild("SpawnLocations")
    if not folder then
        folder = Instance.new("Folder")
        folder.Name = "FruitSpawnLocations"
        folder.Parent = plant
    end
    local parts = {}
    for _, ch in ipairs(folder:GetChildren()) do
        if ch:IsA("BasePart") then
            parts[#parts + 1] = ch
        end
    end
    -- attr kapasitas penuh; part locator cukup sedikit (anti lag)
    local cap = desiredFruitSpawnSlots(plant)
    local want = math.max(
        math.floor(tonumber(minSlots) or 0),
        math.min(cap, FRUIT_LOC_PARTS_MAX),
        #parts
    )
    want = math.clamp(want, 1, FRUIT_LOC_PARTS_MAX)
    local cf = plant:GetPivot()
    while #parts < want do
        local p = Instance.new("Part")
        p.Name = tostring(#parts + 1)
        p.Size = Vector3.new(0.5, 0.5, 0.5)
        p.Transparency = 1
        p.Anchored = true
        p.CanCollide = false
        p.CanTouch = false
        p.CanQuery = false
        p.CastShadow = false
        p.CFrame = cf
        p.Parent = folder
        parts[#parts + 1] = p
    end
    for i = 1, #parts do
        pcall(function()
            parts[i].Transparency = 1
            parts[i].CanCollide = false
            parts[i].CastShadow = false
        end)
    end
    return folder, parts
end

local function _pickDataNum(data, keys)
    if type(data) ~= "table" then return nil end
    for i = 1, #keys do
        local v = tonumber(data[keys[i]])
        if v ~= nil then return v end
    end
    return nil
end

-- Cache: seed → true/false (HANYA flag IsSingleHarvest, bukan MaxFruits==1)
local _seedSingleHarvestCache = {}
local function seedIsSingleHarvest(seedName)
    seedName = tostring(seedName or "")
    if seedName == "" then return false end
    local cached = _seedSingleHarvestCache[seedName]
    if cached ~= nil then return cached == true end
    local single = false
    pcall(function()
        local pvc = getPVC()
        if pvc and type(pvc.IsSingleHarvestPlant) == "function" then
            local ok, v = pcall(pvc.IsSingleHarvestPlant, pvc, seedName)
            if ok and v == true then single = true end
        end
        if not single and pvc and type(pvc.GetSeedData) == "function" then
            local e = pvc:GetSeedData(seedName)
            if type(e) == "table" and e.IsSingleHarvest == true then single = true end
        end
    end)
    if not single then
        pcall(function()
            local SeedData = require(ReplicatedStorage.SharedModules.SeedData)
            local e = type(SeedData) == "table" and SeedData[seedName]
            if type(e) ~= "table" and type(SeedData) == "table" then
                local want = string.lower(seedName)
                for k, v in pairs(SeedData) do
                    if type(v) == "table" then
                        local nm = tostring(v.SeedName or v.Name or k)
                        if string.lower(nm) == want then e = v break end
                    end
                end
            end
            if type(e) == "table" and e.IsSingleHarvest == true then single = true end
        end)
    end
    _seedSingleHarvestCache[seedName] = single
    return single
end

local function plantIsSingleHarvest(plantData, plant)
    if type(plantData) == "table" then
        if plantData.IsSingleHarvest == true or plantData.SingleHarvest == true then
            return true
        end
    end
    if typeof(plant) == "Instance" and plant:GetAttribute("IsSingleHarvest") == true then
        return true
    end
    local seedName = nil
    if type(plantData) == "table" then
        seedName = plantData.SeedName or plantData.ItemName or plantData.PlantName or plantData.FruitType
    end
    if typeof(plant) == "Instance" then
        seedName = seedName
            or plant:GetAttribute("SeedName")
            or plant:GetAttribute("ItemName")
            or plant:GetAttribute("FruitType")
    end
    return seedIsSingleHarvest(seedName)
end

local function resolveFruitDataFromSync(plantId, fruitId, fallback)
    local data = type(fallback) == "table" and fallback or nil
    local sync = getGardenSync()
    if not sync or type(sync.GetPlant) ~= "function" then return data end
    local plantData = nil
    pcall(function()
        plantData = sync:GetPlant(LP.UserId, plantId)
    end)
    if type(plantData) ~= "table" then return data end
    local fruits = plantData.Fruits or plantData.fruits or plantData.Fruit
    local want = tostring(fruitId or "")

    -- Single-harvest / plant-level: Age di plant sync, FruitId ""
    if type(fruits) ~= "table" or next(fruits) == nil or want == "" then
        if want == "" or plantIsSingleHarvest(plantData, nil) then
            if data == nil then return plantData end
            for k, v in pairs(plantData) do
                if data[k] == nil and k ~= "Fruits" and k ~= "fruits" and k ~= "Fruit" then
                    data[k] = v
                end
            end
            return data
        end
        if type(fruits) ~= "table" then
            if data == nil then data = plantData end
            return data
        end
    end

    local found = nil
    if want ~= "" then
        if #fruits > 0 then
            for i = 1, #fruits do
                local d = fruits[i]
                if type(d) == "table" then
                    local id = d.FruitId or d.fruitId or d.Id or d.id or d.UUID or d.Uuid
                    if tostring(id) == want then found = d break end
                end
            end
        else
            for fid, d in pairs(fruits) do
                if tostring(fid) == want and type(d) == "table" then
                    found = d
                    break
                elseif type(d) == "table" then
                    local id = d.FruitId or d.fruitId or d.Id or d.id
                    if tostring(id) == want then found = d break end
                end
            end
        end
    end
    if type(found) == "table" then
        if type(data) == "table" then
            for k, v in pairs(found) do
                if data[k] == nil then data[k] = v end
            end
            return data
        end
        return found
    end
    return data
end

-- Game cuma kasih HarvestPrompt kalau mature. Soft shell kita dulu nempel ke SEMUA
-- buah → match filter besar tapi CollectFruit server tolak (Fire client tetap "ok").
local function fruitDataHarvestReady(data, model)
    data = type(data) == "table" and data or {}
    local isShell = model and model:GetAttribute(FRUIT_SHELL_ATTR) == true
    local age = _pickDataNum(data, { "Age", "age" })
    local maxAge = _pickDataNum(data, { "MaxAge", "maxAge" })
    if model then
        if age == nil then age = tonumber(model:GetAttribute("Age")) end
        if maxAge == nil then maxAge = tonumber(model:GetAttribute("MaxAge")) end
    end

    -- Soft shell: Age/MaxAge WAJIB. Flag Grown/CanHarvest sering true padahal Age < MaxAge
    -- (debug: fakeTagged=178 saat tagged=648).
    if isShell then
        if maxAge == nil or age == nil then
            return false
        end
        return age + 1e-4 >= maxAge
    end

    if data.CanHarvest == true or data.Harvestable == true
        or data.IsReady == true or data.Grown == true
        or data.Ready == true or data.IsGrown == true then
        return true
    end
    local progress = _pickDataNum(data, { "Progress", "GrowthProgress", "GrowProgress", "Percent" })
    if progress ~= nil then
        if progress >= 0.999 or (progress > 1 and progress >= 99.9) then
            return true
        end
        if progress < 0.999 and progress <= 1 then
            return false
        end
    end
    if maxAge == nil then
        return true
    end
    if age == nil then
        return false
    end
    return age + 1e-4 >= maxAge
end

-- AutoCollect skip attribute Collected + butuh tag HarvestPrompt
local function applyShellCollectGate(model, ready)
    if not model then return end
    local pr = model:FindFirstChild("HarvestPrompt", true)
    if not pr or not pr:IsA("ProximityPrompt") then return end
    if ready then
        pcall(function()
            pr:SetAttribute("Collected", nil)
            tagHarvestPrompt(pr)
            tunePrompt(pr)
        end)
    else
        pcall(function()
            pr:SetAttribute("Collected", true)
            pr.Enabled = false
            pr.MaxActivationDistance = 0
            if CollectionService:HasTag(pr, "HarvestPrompt") then
                pr:RemoveTag("HarvestPrompt")
            end
        end)
    end
end

-- Nama mutasi dari game (MutationData / PlantListView) — cache, bukan list manual
local _mutNameCache = nil
local MUT_DATA_SKIP = {
    age = true, maxage = true, weight = true, baseweight = true, sizemulti = true,
    overtimegrowth = true, overtime = true, progress = true, scale = true,
    fruitid = true, plantid = true, userid = true, id = true, uuid = true,
    seedname = true, itemname = true, plantname = true, fruittype = true,
    variant = true, canharvest = true, harvestable = true, isready = true,
    grown = true, ready = true, isgrown = true, mutation = true, mutations = true,
    mutationname = true, fruits = true, position = true, cframe = true,
}

local function listGameMutationNames()
    if _mutNameCache then return _mutNameCache end
    local names, seen = {}, {}
    local function push(n)
        n = tostring(n or ""):match("^%s*(.-)%s*$")
        if not n or n == "" then return end
        local low = string.lower(n)
        if MUT_DATA_SKIP[low] or low == "none" or low == "normal" or low == "nomutation" then
            return
        end
        if seen[low] then return end
        seen[low] = true
        names[#names + 1] = n
    end
    pcall(function()
        local sm = ReplicatedStorage:FindFirstChild("SharedModules")
        local md = sm and sm:FindFirstChild("MutationData")
        if not md then return end
        local function scan(folder)
            if not folder then return end
            for _, ch in ipairs(folder:GetChildren()) do
                if ch:IsA("ModuleScript") then
                    push(ch.Name)
                elseif ch:IsA("Folder") then
                    scan(ch)
                end
            end
        end
        scan(md)
    end)
    pcall(function()
        local PLV = G.PlantListView or rawget(_G, "PlantListView")
        if type(PLV) == "table" and type(PLV.listMutationNames) == "function" then
            local ok, list = pcall(PLV.listMutationNames, PLV)
            if ok and type(list) == "table" then
                for _, n in ipairs(list) do push(n) end
            end
        end
    end)
    _mutNameCache = names
    return names
end

local function stampMutationAttrs(model, data)
    if not model then return end
    data = type(data) == "table" and data or {}
    local found, seen = {}, {}
    local function add(name)
        name = tostring(name or ""):match("^%s*(.-)%s*$")
        if not name or name == "" then return end
        -- pecah kalau ketimpa "Glow+Glow"
        if string.find(name, "[%+%,%/]", 1) then
            for token in string.gmatch(name, "[^%+%,%/]+") do add(token) end
            return
        end
        local low = string.lower(name)
        if MUT_DATA_SKIP[low] or low == "none" or low == "normal" or low == "nomutation" then
            return
        end
        if seen[low] then return end
        seen[low] = true
        found[#found + 1] = name
    end

    -- 1) string Mutation di MODEL (game MutationController sering set ini saja)
    local onModel = model:GetAttribute("Mutation")
    if type(onModel) == "string" and onModel ~= "" then add(onModel) end

    -- 2) data GardenSync
    local raw = data.Mutation or data.mutation or data.MutationName
    if type(raw) == "string" and raw ~= "" then add(raw) end

    local list = data.Mutations or data.mutations
    if type(list) == "table" then
        if #list > 0 then
            for i = 1, #list do add(list[i]) end
        else
            for k, v in pairs(list) do
                if v == true then add(k)
                elseif type(v) == "string" then add(v) end
            end
        end
    elseif type(list) == "string" and list ~= "" then
        add(list)
    end

    local gameNames = listGameMutationNames()
    for i = 1, #gameNames do
        local n = gameNames[i]
        if data[n] == true or model:GetAttribute(n) == true then add(n) end
    end
    for k, v in pairs(data) do
        if v == true and type(k) == "string" then add(k) end
    end

    if #found == 0 then return end

    pcall(function()
        for i = 1, #gameNames do
            local n = gameNames[i]
            if model:GetAttribute(n) == true and not seen[string.lower(n)] then
                model:SetAttribute(n, nil)
            end
        end
        if type(onModel) == "string" and onModel ~= "" then
            for token in string.gmatch(onModel, "[^%+%,%/]+") do
                local t = tostring(token):match("^%s*(.-)%s*$")
                if t and t ~= "" and not seen[string.lower(t)] then
                    model:SetAttribute(t, nil)
                end
            end
        end
        model:SetAttribute("Mutation", table.concat(found, "+"))
        for i = 1, #found do
            model:SetAttribute(found[i], true)
        end
    end)
end

-- Listener: weather set Mutation string → boolean ikut (tanpa rejoin)
local mutListenBound = setmetatable({}, { __mode = "k" })
local function bindFruitMutationListener(fruit)
    if not fruit or mutListenBound[fruit] then return end
    if fruit:GetAttribute("FruitId") == nil and fruit:GetAttribute(FRUIT_SHELL_ATTR) ~= true then
        return
    end
    mutListenBound[fruit] = true
    pcall(function()
        fruit:GetAttributeChangedSignal("Mutation"):Connect(function()
            if fruit.Parent then stampMutationAttrs(fruit, nil) end
        end)
    end)
    -- sudah ada Mutation saat bind
    if fruit:GetAttribute("Mutation") ~= nil then
        stampMutationAttrs(fruit, nil)
    end
end

local function stampFruitDetectAttrs(model, plantId, fruitId, fruitData, plant)
    if not model then return end
    -- PlantId HARUS sama tipe/value dengan plant model (server CollectFruit ketat)
    local pid = plantId
    if typeof(plant) == "Instance" then
        local fromPlant = plant:GetAttribute("PlantId")
        if fromPlant ~= nil then
            pid = fromPlant
        end
    end
    local data = resolveFruitDataFromSync(pid or plantId, fruitId, fruitData) or {}
    local fid = fruitId
    if type(data) == "table" then
        -- FruitId "" = single-harvest — jangan ambil data.Id (sering = PlantId → collect gagal)
        local fromData = data.FruitId or data.fruitId
        if fromData ~= nil then
            fid = fromData
        elseif tostring(fruitId or "") ~= "" then
            fromData = data.Id or data.id or data.UUID or data.Uuid
            if fromData ~= nil then fid = fromData end
        end
    end
    pcall(function()
        -- HarvestPromptController baca PlantId/FruitId HANYA dari model ancestor prompt
        model:SetAttribute("FruitId", fid)
        model:SetAttribute("PlantId", pid)
        model:SetAttribute("UserId", LP.UserId)
        model:SetAttribute(FRUIT_SHELL_ATTR, true)
        if tostring(fid or "") == "" then
            model:SetAttribute("_GAG2PlantHarvest", true)
        else
            model:SetAttribute("_GAG2PlantHarvest", nil)
        end

        local age = _pickDataNum(data, { "Age", "age" })
        local maxAge = _pickDataNum(data, { "MaxAge", "maxAge" })
        local bw = _pickDataNum(data, { "BaseWeight", "baseWeight", "BaseKg" })
        local sm = _pickDataNum(data, { "SizeMulti", "SizeMultiplier", "Scale", "FruitScale" })
        local og = _pickDataNum(data, { "OvertimeGrowth", "Overtime" }) or 1
        local w = _pickDataNum(data, { "Weight", "weight", "Kg", "kg", "DisplayWeight", "HarvestWeight" })
        if (not w or w <= 0) and bw and bw > 0 then
            w = bw * (sm or 1) * (og > 0 and og or 1)
        end
        if maxAge ~= nil then model:SetAttribute("MaxAge", maxAge) end
        if age ~= nil then model:SetAttribute("Age", age) end
        if bw ~= nil then model:SetAttribute("BaseWeight", bw) end
        if sm ~= nil then
            model:SetAttribute("SizeMulti", sm)
        elseif bw ~= nil then
            model:SetAttribute("SizeMulti", 1)
        end
        if og ~= nil and og ~= 1 then model:SetAttribute("OvertimeGrowth", og) end
        if w and w > 0 then model:SetAttribute("Weight", w) end
        if data.Variant ~= nil then model:SetAttribute("Variant", data.Variant) end

        local plantName = data.PlantName or data.SeedName or data.ItemName or data.FruitType
        if (plantName == nil or plantName == "") and typeof(plant) == "Instance" then
            plantName = plant:GetAttribute("SeedName")
                or plant:GetAttribute("ItemName")
                or plant:GetAttribute("FruitType")
                or discoverPlantTypeName(plant)
        end
        if plantName ~= nil then
            local n = normalizeTypeName(plantName) or tostring(plantName)
            if n and n ~= "" then
                model:SetAttribute("SeedName", n)
                model:SetAttribute("ItemName", n)
                model:SetAttribute("FruitType", n)
            end
        end
    end)
    -- Mutation string + boolean (Glow/Gold/Rainbow) — AC baca dari attr buah
    stampMutationAttrs(model, data)
    bindFruitMutationListener(model)
    -- Soft shell: tag HarvestPrompt hanya kalau mature (akurasi CollectFruit)
    applyShellCollectGate(model, fruitDataHarvestReady(data, model))
end

-- HarvestPromptController.rebuildHarvestPartCache skip nama "HarvestPart".
-- Perlu ≥1 BasePart lain supaya prompt di-track & posisi OK.
local function ensureShellBodyPart(model, cf)
    -- WAJIB Model buah (UUID). Jangan Folder Fruits / Part lepas.
    if not model or not model:IsA("Model") then return nil end
    if model.Name == "Fruits" or model.Name == "Fruit" then return nil end
    local body = model:FindFirstChild("ShellBody")
    if body and body:IsA("BasePart") then
        return body
    end
    body = Instance.new("Part")
    body.Name = "ShellBody"
    body.Size = Vector3.new(1.2, 1.2, 1.2)
    body.Transparency = 1
    body.Anchored = true
    body.CanCollide = false
    body.CanTouch = false
    body.CanQuery = true -- HarvestPromptController cache butuh part queryable
    body.CastShadow = false
    body.CFrame = cf or model:GetPivot()
    body.Parent = model
    return body
end

local function markFruitPromptsCollected(model)
    if not model then return end
    for _, d in ipairs(model:GetDescendants()) do
        if d:IsA("ProximityPrompt") then
            pcall(function()
                d:SetAttribute("Collected", true)
                d.Enabled = false
                d.MaxActivationDistance = 0
                d:RemoveTag("HarvestPrompt")
            end)
        end
    end
    if model:IsA("ProximityPrompt") then
        pcall(function()
            model:SetAttribute("Collected", true)
            model.Enabled = false
            model:RemoveTag("HarvestPrompt")
        end)
    end
end

local function cancelQueuedFruitShell(plantId, fruitId)
    local key = string.format("%s_%s_%s", tostring(LP.UserId), tostring(plantId), tostring(fruitId))
    fruitShellQueued[key] = nil
    for i = #fruitShellQueue, 1, -1 do
        local job = fruitShellQueue[i]
        if job and tostring(job.plantId) == tostring(plantId)
            and tostring(job.fruitId) == tostring(fruitId) then
            table.remove(fruitShellQueue, i)
        end
    end
end

local function liveFruitIdSet(plantData)
    local live = {}
    if type(plantData) ~= "table" then return live end
    local fruits = plantData.Fruits or plantData.fruits or plantData.Fruit
    if type(fruits) ~= "table" then return live end
    if #fruits > 0 then
        for i = 1, #fruits do
            local d = fruits[i]
            if type(d) == "table" then
                local id = d.FruitId or d.fruitId or d.Id or d.id or d.UUID or d.Uuid
                if id ~= nil then live[tostring(id)] = true end
            elseif d ~= nil then
                live[tostring(d)] = true
            end
        end
    else
        for fruitId, d in pairs(fruits) do
            if type(d) == "table" then
                local id = d.FruitId or d.fruitId or d.Id or d.id or fruitId
                live[tostring(id)] = true
            elseif d == true or type(d) == "string" or type(d) == "number" then
                live[tostring(fruitId)] = true
            end
        end
    end
    return live
end

local function findOwnPlantModel(plantId)
    local pvc = getPVC()
    local plant = nil
    if pvc and type(pvc.GetSpawnedPlant) == "function" then
        pcall(function()
            plant = pvc:GetSpawnedPlant(LP.UserId, plantId)
        end)
    end
    if typeof(plant) == "Instance" and plant.Parent then return plant end
    local plot = myPlot()
    if not plot then return nil end
    local want = tostring(plantId)
    for _, folder in ipairs(listPlantFolders(plot, LP.UserId)) do
        for _, ch in ipairs(folder:GetChildren()) do
            if ch:IsA("Model") and tostring(ch:GetAttribute("PlantId") or ch.Name) == want then
                return ch
            end
        end
    end
    return nil
end

local function isFruitInSync(plantId, fruitId)
    plantId = tostring(plantId or "")
    fruitId = tostring(fruitId or "")
    if plantId == "" or fruitId == "" then return false end
    local sync = getGardenSync()
    if not sync or type(sync.GetPlant) ~= "function" then
        return true -- unknown → jangan destroy
    end
    local plantData = nil
    pcall(function()
        plantData = sync:GetPlant(LP.UserId, plantId)
    end)
    if type(plantData) ~= "table" then
        return false
    end
    local live = liveFruitIdSet(plantData)
    -- sync kosong / format beda → jangan mass-delete buah valid
    if next(live) == nil then
        return true
    end
    return live[fruitId] == true
end

-- Hanya buang shell yang TIDAK ada di GardenSync. MaxFruits bukan batas server.
local function pruneOrphanShellsOnPlant(plant, liveSet)
    if not plant then return 0 end
    if type(liveSet) ~= "table" or next(liveSet) == nil then return 0 end
    local folder = plant:FindFirstChild("Fruits") or plant:FindFirstChild("Fruit")
    if not folder then return 0 end
    local n = 0
    for _, ch in ipairs(folder:GetChildren()) do
        if ch:IsA("Model") then
            local fid = tostring(ch:GetAttribute("FruitId") or "")
            if fid ~= "" and liveSet[fid] ~= true then
                markFruitPromptsCollected(ch)
                if pcall(function() ch:Destroy() end) then
                    n += 1
                end
            end
        end
    end
    return n
end

local function destroyOwnFruitShell(plantId, fruitId)
    plantId = tostring(plantId or "")
    fruitId = tostring(fruitId or "")
    if plantId == "" or fruitId == "" then return false end
    cancelQueuedFruitShell(plantId, fruitId)
    local plant = findOwnPlantModel(plantId)
    if typeof(plant) ~= "Instance" then return false end
    local folder = plant:FindFirstChild("Fruits") or plant:FindFirstChild("Fruit")
    if not folder then return false end
    local killed = false
    for _, ch in ipairs(folder:GetChildren()) do
        if tostring(ch:GetAttribute("FruitId") or "") == fruitId then
            markFruitPromptsCollected(ch)
            if pcall(function() ch:Destroy() end) then
                killed = true
                statsPrunedFruits += 1
            end
        end
    end
    return killed
end

-- Aman: destroy shell HANYA kalau fruit sudah tidak ada di GardenSync (collect benar-benar sukses)
local function destroyOwnFruitShellIfGone(plantId, fruitId)
    if isFruitInSync(plantId, fruitId) then
        return false
    end
    return destroyOwnFruitShell(plantId, fruitId)
end

-- Hapus shell/fruit client yang sudah tidak ada di GardenSync (setelah collect)
local function pruneOrphanOwnFruits()
    local sync = getGardenSync()
    local pvc = getPVC()
    if not sync or not pvc then return 0 end
    if type(sync.GetGarden) ~= "function" or type(pvc.GetSpawnedPlant) ~= "function" then
        return 0
    end
    local garden = nil
    pcall(function()
        garden = sync:GetGarden(LP.UserId)
    end)
    if type(garden) ~= "table" then return 0 end

    local n = 0
    for plantId, plantData in pairs(garden) do
        if type(plantData) == "table" then
            local plant = nil
            pcall(function()
                plant = pvc:GetSpawnedPlant(LP.UserId, plantId)
            end)
            if typeof(plant) == "Instance" and plant.Parent then
                n += cleanupLooseFruitProxies(plant)
                local live = liveFruitIdSet(plantData)
                local cut = pruneOrphanShellsOnPlant(plant, live)
                n += cut
                statsPrunedFruits += cut
            end
        end
    end

    -- plant yang sudah hilang dari sync: bersihkan fruit folder di model sisa
    local plot = myPlot()
    if plot then
        for _, folder in ipairs(listPlantFolders(plot, LP.UserId)) do
            for _, plant in ipairs(folder:GetChildren()) do
                if plant:IsA("Model") then
                    local pid = plant:GetAttribute("PlantId")
                    if pid ~= nil and garden[pid] == nil and garden[tostring(pid)] == nil then
                        local ff = plant:FindFirstChild("Fruits") or plant:FindFirstChild("Fruit")
                        if ff then
                            for _, ch in ipairs(ff:GetChildren()) do
                                markFruitPromptsCollected(ch)
                                if pcall(function() ch:Destroy() end) then
                                    n += 1
                                    statsPrunedFruits += 1
                                end
                            end
                        end
                    end
                end
            end
        end
    end
    return n
end

-- Shell fruit RINGAN: Model + FruitId + 1 invisible HarvestPart + HarvestPrompt (AutoCollect)
-- TANPA mesh / CollectProxy / FVC clone — anti freeze
local function ensureDetectFruitShell(plant, plantId, fruitId, fruitData)
    if not plant or not plant.Parent then return nil, false end
    -- nil ditolak; "" = single-harvest CollectFruit(plantId, "")
    if fruitId == nil then return nil, false end
    ensureFruitSpawnLocations(plant)
    local fruits = plant:FindFirstChild("Fruits") or plant:FindFirstChild("Fruit")
    if not fruits then
        fruits = Instance.new("Folder")
        fruits.Name = "Fruits"
        fruits.Parent = plant
    end

    bindFruitsFolderCleanup(fruits)
    cleanupLooseFruitProxies(plant)

    local fidKey = tostring(fruitId)
    if fidKey == "" then fidKey = "_plant" end
    local key = string.format("%s_%s_%s", tostring(LP.UserId), tostring(plantId), fidKey)
    local existing = fruits:FindFirstChild(key)
    if not existing then
        for _, ch in ipairs(fruits:GetChildren()) do
            if ch:IsA("Model") and ch:GetAttribute(FRUIT_SHELL_ATTR) == true
                and tostring(ch:GetAttribute("FruitId") or "") == tostring(fruitId) then
                existing = ch
                break
            end
        end
    end
    if existing and existing.Parent and existing:IsA("Model") then
        stampFruitDetectAttrs(existing, plantId, fruitId, fruitData, plant)
        ensureShellBodyPart(existing, existing:GetPivot())
        local pr = existing:FindFirstChild("HarvestPrompt", true)
        if not pr then
            local hp = existing:FindFirstChild("HarvestPart")
            if not (hp and hp:IsA("BasePart")) then
                hp = Instance.new("Part")
                hp.Name = "HarvestPart"
                hp.Size = Vector3.new(1, 1, 1)
                hp.Transparency = 1
                hp.Anchored = true
                hp.CanCollide = false
                hp.CanQuery = true
                hp.CastShadow = false
                hp.CFrame = plant:GetPivot()
                hp.Parent = existing
                existing.PrimaryPart = hp
            end
            pr = Instance.new("ProximityPrompt")
            pr.Style = Enum.ProximityPromptStyle.Custom
            pr.Name = "HarvestPrompt"
            pr.ActionText = "Harvest"
            pr.HoldDuration = 0
            pr.MaxActivationDistance = 10
            pr.RequiresLineOfSight = false
            pr.Parent = hp
        end
        -- stamp sudah gate ripe; pastikan ulang dari data sync
        local data = resolveFruitDataFromSync(plantId, fruitId, fruitData) or {}
        applyShellCollectGate(existing, fruitDataHarvestReady(data, existing))
        return existing, false
    end

    local data = type(fruitData) == "table" and fruitData or {}
    local cf = plant:GetPivot()
    local locFolder = plant:FindFirstChild("FruitSpawnLocations")
    local idx = tonumber(data.SpawnLocationIndex)
    if locFolder and idx and idx >= 1 then
        local loc = locFolder:GetChildren()[idx]
        if loc and loc:IsA("BasePart") then cf = loc.CFrame end
    end

    local model = Instance.new("Model")
    model.Name = key
    stampFruitDetectAttrs(model, plantId, fruitId, data, plant)

    -- Body dulu (bukan HarvestPart) — controller cache parts dari sini
    ensureShellBodyPart(model, cf)

    local hp = Instance.new("Part")
    hp.Name = "HarvestPart"
    hp.Size = Vector3.new(1, 1, 1)
    hp.Transparency = 1
    hp.Anchored = true
    hp.CanCollide = false
    hp.CanTouch = false
    hp.CanQuery = true
    hp.CastShadow = false
    hp.CFrame = cf
    hp.Parent = model
    model.PrimaryPart = hp

    local prompt = Instance.new("ProximityPrompt")
    prompt.Style = Enum.ProximityPromptStyle.Custom
    prompt.Name = "HarvestPrompt"
    prompt.ActionText = "Harvest"
    prompt.HoldDuration = 0
    prompt.MaxActivationDistance = 10
    prompt.RequiresLineOfSight = false
    prompt.Enabled = true
    prompt.Parent = hp
    local syncData = resolveFruitDataFromSync(plantId, fruitId, data) or data
    applyShellCollectGate(model, fruitDataHarvestReady(syncData, model))

    model.Parent = fruits
    return model, true
end

local function drainFruitShellQueue()
    if fruitShellDraining then return end
    fruitShellDraining = true
    task.spawn(function()
        local batch = math.max(1, math.floor(tonumber(CONFIG.restoreFruitBatchSize) or 3))
        local delaySec = math.max(0.02, tonumber(CONFIG.restoreFruitBatchDelay) or 0.12)
        while #fruitShellQueue > 0 do
            if not alive and not running then
                -- Stop sedang restore: tetap drain pelan
            end
            for _ = 1, batch do
                local job = table.remove(fruitShellQueue, 1)
                if not job then break end
                local qk = job.key
                fruitShellQueued[qk] = nil
                local pvc = getPVC()
                local plant = nil
                if pvc and type(pvc.GetSpawnedPlant) == "function" then
                    pcall(function()
                        plant = pvc:GetSpawnedPlant(job.userId, job.plantId)
                    end)
                end
                if typeof(plant) == "Instance" and plant.Parent then
                    local _, created = ensureDetectFruitShell(plant, job.plantId, job.fruitId, job.data)
                    if created then stats.fruits += 1 end
                end
            end
            if #fruitShellQueue > 0 then
                task.wait(delaySec)
            end
        end
        fruitShellDraining = false
    end)
end

local function enqueueFruitShell(userId, plantId, fruitId, data)
    local key = string.format("%s_%s_%s", tostring(userId), tostring(plantId), tostring(fruitId))
    if fruitShellQueued[key] then return end
    fruitShellQueued[key] = true
    fruitShellQueue[#fruitShellQueue + 1] = {
        key = key,
        userId = userId,
        plantId = plantId,
        fruitId = fruitId,
        data = data,
    }
    drainFruitShellQueue()
end

local function stripHeavyVisual(model)
    if not model or not model.Parent then return 0 end
    local isPlant = model:GetAttribute("PlantId") ~= nil and not isFruitModel(model)
    if isPlant then
        ensureProxy(model) -- CollectProxy di PLANT saja
        cleanupLooseFruitProxies(model)
    elseif model:GetAttribute(FRUIT_SHELL_ATTR) ~= true then
        ensureProxy(model) -- buah game-managed
    end
    -- soft shell: jangan ensureProxy (CollectProxy); HarvestPart/ShellBody di UUID
    local kill = {}
    for _, d in ipairs(model:GetDescendants()) do
        -- strip plant: jangan sentuh isi folder Fruits (finalizeFruit yang urus)
        if isPlant and underFruitsFolder(d) then
            continue
        end
        if isDetectKeepInstance(d) then
            -- keep
        elseif d:IsA("BasePart") or d:IsA("MeshPart") or d:IsA("SpecialMesh")
            or d:IsA("Decal") or d:IsA("Texture")
            or d:IsA("ParticleEmitter") or d:IsA("Beam") or d:IsA("Trail")
            or d:IsA("Fire") or d:IsA("Smoke") or d:IsA("Sparkles")
            or d:IsA("Highlight") or d:IsA("SelectionBox")
            or d:IsA("BillboardGui") or d:IsA("SurfaceGui")
            or d:IsA("Sound") or d:IsA("WrapLayer") or d:IsA("WrapTarget") then
            kill[#kill + 1] = d
        end
    end
    local n = 0
    for i = 1, #kill do
        if pcall(function() kill[i]:Destroy() end) then
            n += 1
        end
    end
    if isPlant then
        ensureProxy(model)
        cleanupLooseFruitProxies(model)
    elseif model:GetAttribute(FRUIT_SHELL_ATTR) ~= true then
        ensureProxy(model)
    end
    if n > 0 then
        statsBlocked.stripped += 1
        stats.stashed += 1
    end
    return n
end

-- Setelah FVC/InitFruit game selesai → strip mesh, prompt game tetap
local function stripFruitAfterGameSpawn(fruit)
    if not fruit then return end
    task.defer(function()
        task.wait(0.08)
        if not fruit.Parent or not visualBlockActive then return end
        if CONFIG.stripOwnVisual then
            stripHeavyVisual(fruit)
        end
        -- Mutation string game → boolean (sebelum weather / setelah InitFruit)
        bindFruitMutationListener(fruit)
        stampMutationAttrs(fruit, nil)
    end)
end

-- Strip plant + buah di dalamnya; attrs tetap (detect-safe)
stripPlantKeepDetect = function(plant)
    if not plant or not plant.Parent then return 0 end
    local plantId = plant:GetAttribute("PlantId")
    local n = stripHeavyVisual(plant)

    local function finalizeFruit(f)
        if not (f and f:IsA("Model")) then return end
        if f:GetAttribute("FruitId") == nil then return end
        -- soft shell attr dulu supaya stripHeavyVisual tidak pasang CollectProxy
        if not useGameManagedFruits() then
            pcall(function() f:SetAttribute(FRUIT_SHELL_ATTR, true) end)
        end
        n += stripHeavyVisual(f)
        -- game-managed: jangan rewrite attrs / ShellBody — biarkan prompt game
        if plantId ~= nil and f:GetAttribute("PlantId") == nil then
            pcall(function()
                f:SetAttribute("PlantId", plantId)
            end)
        end
        if not useGameManagedFruits() then
            local fruitId = f:GetAttribute("FruitId")
            if fruitId ~= nil then
                ensureShellBodyPart(f, f:GetPivot())
                local pr = f:FindFirstChild("HarvestPrompt", true)
                if not pr then
                    local hp = f:FindFirstChild("HarvestPart")
                    if not (hp and hp:IsA("BasePart")) then
                        hp = f:FindFirstChild("ShellBody")
                    end
                    if hp and hp:IsA("BasePart") then
                        pr = Instance.new("ProximityPrompt")
                        pr.Style = Enum.ProximityPromptStyle.Custom
                        pr.Name = "HarvestPrompt"
                        pr.ActionText = "Harvest"
                        pr.HoldDuration = 0
                        pr.RequiresLineOfSight = false
                        pr.Parent = hp
                    end
                end
                -- stamp + gate ripe-only (jangan force-tag semua)
                stampFruitDetectAttrs(f, plantId or f:GetAttribute("PlantId"), fruitId, nil, plant)
            end
        else
            local pr = f:FindFirstChild("HarvestPrompt", true)
            if pr then tunePrompt(pr) end
        end
    end

    local fruits = plant:FindFirstChild("Fruits") or plant:FindFirstChild("Fruit")
    if fruits then
        bindFruitsFolderCleanup(fruits)
        cleanupLooseFruitProxies(plant)
        for _, f in ipairs(fruits:GetChildren()) do
            finalizeFruit(f)
        end
        cleanupLooseFruitProxies(plant)
    end
    for _, ch in ipairs(plant:GetChildren()) do
        if ch:IsA("Model") and ch:GetAttribute("FruitId") ~= nil then
            finalizeFruit(ch)
        end
    end
    ensureProxy(plant)
    cleanupLooseFruitProxies(plant)
    ensureFruitSpawnLocations(plant)
    return n
end

local function patchPlantModules()
    if #plantBackups > 0 then return #plantBackups end
    local folder = ReplicatedStorage:FindFirstChild("PlantGenerationModules")
    folder = folder and folder:FindFirstChild("Plants")
    if not folder then return 0 end
    local n = 0
    for _, child in ipairs(folder:GetChildren()) do
        if child:IsA("ModuleScript") then
            local ok, mod = pcall(require, child)
            if ok and type(mod) == "table" then
                plantBackups[#plantBackups + 1] = {
                    mod = mod,
                    InitPlant = mod.InitPlant,
                    BeginPlantGrowth = mod.BeginPlantGrowth,
                }
                mod.BeginPlantGrowth = function() end
                mod.InitPlant = function(plant)
                    statsBlocked.plantInit += 1
                    if plant then
                        pcall(function()
                            plant:AddTag("InitializationComplete")
                            plant:SetAttribute("PlantGrowthReady", true)
                        end)
                        -- Soft strip (hemat CPU) — jangan Destroy plant/plot
                        task.defer(function()
                            if plant.Parent and visualBlockActive and CONFIG.stripOwnVisual then
                                stripHeavyVisual(plant)
                                ensureFruitSpawnLocations(plant)
                            end
                        end)
                    end
                end
                n += 1
            end
        end
    end
    dlog("patched plant modules=%d", n)
    return n
end

local function restorePlantModules()
    for i = 1, #plantBackups do
        local b = plantBackups[i]
        if b and b.mod then
            if b.InitPlant then b.mod.InitPlant = b.InitPlant end
            if b.BeginPlantGrowth then b.mod.BeginPlantGrowth = b.BeginPlantGrowth end
        end
    end
    table.clear(plantBackups)
end

local function patchFruitModules()
    if #fruitBackups > 0 then return #fruitBackups end
    local folder = ReplicatedStorage:FindFirstChild("PlantGenerationModules")
    folder = folder and folder:FindFirstChild("Fruits")
    if not folder then return 0 end
    local n = 0
    for _, child in ipairs(folder:GetChildren()) do
        if child:IsA("ModuleScript") then
            local ok, mod = pcall(require, child)
            if ok and type(mod) == "table" then
                fruitBackups[#fruitBackups + 1] = {
                    mod = mod,
                    BeginFruitGrowth = mod.BeginFruitGrowth,
                    InitFruit = mod.InitFruit,
                }
                mod.BeginFruitGrowth = function() end
                local origInit = mod.InitFruit
                mod.InitFruit = function(fruit, ...)
                    statsBlocked.fruitInit += 1
                    if not fruit then return end
                    if useGameManagedFruits() and type(origInit) == "function" then
                        pcall(origInit, fruit, ...)
                        stripFruitAfterGameSpawn(fruit)
                        return
                    end
                    pcall(function() fruit:AddTag("InitializationComplete") end)
                    task.defer(function()
                        if fruit.Parent and visualBlockActive and CONFIG.stripOwnVisual then
                            stripHeavyVisual(fruit)
                        end
                    end)
                end
                n += 1
            end
        end
    end
    dlog("patched fruit modules=%d", n)
    return n
end

local function restoreFruitModules()
    for i = 1, #fruitBackups do
        local b = fruitBackups[i]
        if b and b.mod then
            if b.BeginFruitGrowth then b.mod.BeginFruitGrowth = b.BeginFruitGrowth end
            if b.InitFruit then b.mod.InitFruit = b.InitFruit end
        end
    end
    table.clear(fruitBackups)
end

local function patchFVC()
    local FVC = getFVC()
    if not FVC or FVC.__GAG2RF9 then return FVC ~= nil end
    fvcBackup = {
        UpdateFruitAges = FVC.UpdateFruitAges,
        UpdateFruitGrowthData = FVC.UpdateFruitGrowthData,
        ApplyOversizedCollision = FVC.ApplyOversizedCollision,
        SpawnFruitFromData = FVC.SpawnFruitFromData,
    }
    -- Age tick = CPU; growth-data HARUS jalan — sering ini yang spawn fruit ke folder Fruits
    FVC.UpdateFruitAges = function() end
    FVC.ApplyOversizedCollision = function() end
    local mutStampQueued = false
    if type(fvcBackup.UpdateFruitGrowthData) == "function" then
        local origGrow = fvcBackup.UpdateFruitGrowthData
        FVC.UpdateFruitGrowthData = function(self, ...)
            local ok, a, b, c, d = pcall(origGrow, self, ...)
            -- Weather/mutasi sering update lewat sini — refresh stamp tanpa tunggu rejoin
            if (forceSoftFruits or (visualBlockActive and CONFIG.stripOwnVisual))
                and not mutStampQueued then
                mutStampQueued = true
                task.defer(function()
                    task.wait(0.15)
                    mutStampQueued = false
                    if alive then pcall(syncOwnShellHarvestFromSync) end
                end)
            end
            if ok then return a, b, c, d end
            return nil
        end
    end
    -- Soft shell tidak masuk cache FVC → RemoveFruit bawaan miss. Wrap semua remove/destroy fruit.
    for k, v in pairs(FVC) do
        if type(v) == "function" and type(k) == "string" and fvcBackup[k] == nil then
            local low = string.lower(k)
            if low:find("fruit", 1, true)
                and (low:find("remove", 1, true) or low:find("destroy", 1, true)
                    or low:find("despawn", 1, true) or low:find("delete", 1, true)
                    or low:find("clear", 1, true)) then
                fvcBackup[k] = v
                FVC[k] = function(self, a, b, c, ...)
                    local plantId, fruitId = b, c
                    if typeof(a) ~= "number" then
                        plantId, fruitId = a, b
                    elseif typeof(b) == "number" and typeof(c) ~= "nil" and tostring(c):find("-", 1, true) then
                        -- (userId, plantId, fruitId)
                        plantId, fruitId = b, c
                    end
                    if plantId ~= nil and fruitId ~= nil and fruitId ~= "" then
                        pcall(destroyOwnFruitShell, plantId, fruitId)
                    end
                    local ok, r1, r2, r3 = pcall(v, self, a, b, c, ...)
                    if ok then return r1, r2, r3 end
                    return nil
                end
            end
        end
    end
    if type(FVC.SpawnFruitFromData) == "function" then
        local orig = fvcBackup.SpawnFruitFromData
        FVC.SpawnFruitFromData = function(self, userId, plantId, fruitId, data, ...)
            if CONFIG.blockOtherSpawn and typeof(userId) == "number" and userId ~= LP.UserId then
                statsBlocked.otherFruitSkip += 1
                return nil
            end
            local isOwn = typeof(userId) == "number" and userId == LP.UserId
            -- Own fruit: biarkan game spawn (AutoCollect akurat), strip mesh belakangan
            if isOwn and useGameManagedFruits() and type(orig) == "function" then
                local ok, result = pcall(orig, self, userId, plantId, fruitId, data, ...)
                if ok then
                    if typeof(result) == "Instance" then
                        stripFruitAfterGameSpawn(result)
                        stats.fruits += 1
                    end
                    return result
                end
                -- fallback shell hanya kalau FVC gagal
                enqueueFruitShell(userId, plantId, fruitId, data)
                return nil
            end
            -- Legacy soft shell (gameManagedFruits=false)
            local soft = forceSoftFruits or (visualBlockActive and CONFIG.stripOwnVisual)
            if soft and isOwn then
                local pvc = getPVC()
                local plant = nil
                if pvc and type(pvc.GetSpawnedPlant) == "function" then
                    pcall(function()
                        plant = pvc:GetSpawnedPlant(userId, plantId)
                    end)
                end
                if typeof(plant) == "Instance" then
                    local folder = plant:FindFirstChild("Fruits") or plant:FindFirstChild("Fruit")
                    if folder then
                        for _, ch in ipairs(folder:GetChildren()) do
                            if tostring(ch:GetAttribute("FruitId") or "") == tostring(fruitId) then
                                stampFruitDetectAttrs(ch, plantId, fruitId, data, plant)
                                return ch
                            end
                        end
                    end
                end
                enqueueFruitShell(userId, plantId, fruitId, data)
                return nil
            end
            local ok, result = pcall(orig, self, userId, plantId, fruitId, data, ...)
            if ok then return result end
            return nil
        end
    end
    FVC.__GAG2RF9 = true
    dlog("patched FVC game-fruit=%s", tostring(useGameManagedFruits()))
    return true
end

local function restoreFVC()
    local FVC = getFVC()
    if not FVC or not FVC.__GAG2RF9 then
        -- legacy flag
        if FVC and FVC.__GAG2RF5 then
            for k, v in pairs(fvcBackup) do
                if v ~= nil then FVC[k] = v end
            end
            FVC.__GAG2RF5 = nil
        end
        table.clear(fvcBackup)
        return
    end
    for k, v in pairs(fvcBackup) do
        if v ~= nil then FVC[k] = v end
    end
    FVC.__GAG2RF9 = nil
    table.clear(fvcBackup)
end

local function patchPVC()
    local PVC = getPVC()
    if not PVC or PVC.__GAG2RF9 then return PVC ~= nil end
    table.clear(pvcBackup)
    local n = 0
    for k, v in pairs(PVC) do
        if type(v) == "function" and type(k) == "string" then
            local low = string.lower(k)
            if k ~= "GetPlantsFolder" and k ~= "GetSpawnedPlant" and k ~= "GetPlantGrowthData"
                and k ~= "SpawnPlantFromData" and k ~= "RemovePlantById" and k ~= "AddHarvestPrompt"
                and k ~= "AddMissingPrompts" and k ~= "GetSeedData" and k ~= "IsSingleHarvestPlant"
                and not low:find("get", 1, true)
                and (low:find("visual", 1, true) or low:find("render", 1, true)
                    or low:find("refresh", 1, true) or low:find("update", 1, true)
                    or low:find("growthsfx", 1, true) or low:find("age", 1, true)) then
                pvcBackup[k] = v
                PVC[k] = function() end
                n += 1
            end
        end
    end
    if type(PVC.AddGrowthSFX) == "function" then
        pvcBackup.AddGrowthSFX = PVC.AddGrowthSFX
        PVC.AddGrowthSFX = function() end
        n += 1
    end
    if type(PVC.SpawnPlantFromData) == "function" then
        pvcBackup.SpawnPlantFromData = PVC.SpawnPlantFromData
        local orig = pvcBackup.SpawnPlantFromData
        PVC.SpawnPlantFromData = function(self, userId, plantId, data, ...)
            local uid = tonumber(userId)
            if CONFIG.blockOtherSpawn and uid ~= nil and uid ~= LP.UserId then
                -- Jangan skip total: sprinkler other butuh 1 shell/tipe + SeedName.
                local typeName = seedNameFromData(data)
                if not typeName and type(self.GetSeedData) == "function" then
                    pcall(function()
                        typeName = seedNameFromData(self:GetSeedData(data))
                    end)
                end
                local folder = nil
                if type(self.GetPlantsFolder) == "function" then
                    pcall(function() folder = self:GetPlantsFolder(uid) end)
                end
                if typeName and folder and folderHasTypedPlant(folder, typeName) then
                    statsBlocked.otherPlantSkip += 1
                    return nil
                end
                local ok, result = pcall(orig, self, userId, plantId, data, ...)
                task.defer(function()
                    local plant = nil
                    if type(self.GetSpawnedPlant) == "function" then
                        pcall(function()
                            plant = self:GetSpawnedPlant(userId, plantId)
                        end)
                    end
                    if typeof(plant) ~= "Instance" or not plant.Parent then return end
                    pcall(function()
                        plant:SetAttribute("UserId", uid)
                        plant:SetAttribute("PlantId", plantId)
                    end)
                    local stamped = stampPlantTypeAttrs(plant, data) or typeName
                    if stamped and folder and folderHasTypedPlant(folder, stamped, plant) then
                        if destroyIfOtherPlant(plant, nil) then
                            stats.destroyedPlants += 1
                            statsBlocked.otherPlantSkip += 1
                        end
                        return
                    end
                    stripOtherPlantShell(plant, data)
                end)
                if ok then return result end
                return nil
            end
            local ok, result = pcall(orig, self, userId, plantId, data, ...)
            task.defer(function()
                local plant = nil
                if type(self.GetSpawnedPlant) == "function" then
                    pcall(function()
                        plant = self:GetSpawnedPlant(userId, plantId)
                    end)
                end
                if typeof(plant) == "Instance" and plant.Parent and visualBlockActive
                    and CONFIG.stripOwnVisual then
                    stripHeavyVisual(plant)
                    ensureFruitSpawnLocations(plant)
                end
            end)
            if ok then return result end
            return nil
        end
        n += 1
    end
    PVC.__GAG2RF9 = true
    dlog("patched PVC block-fn=%d", n)
    return true
end

local function restorePVC()
    local PVC = getPVC()
    if not PVC then
        table.clear(pvcBackup)
        return
    end
    if PVC.__GAG2RF9 then
        for k, v in pairs(pvcBackup) do
            if v ~= nil then PVC[k] = v end
        end
        -- legacy RF5 keys
        for k, v in pairs(PVC) do
            if type(k) == "string" and k:sub(1, 9) == "__GAG2RF5_" then
                PVC[k:sub(10)] = v
                PVC[k] = nil
            end
        end
        PVC.__GAG2RF9 = nil
        PVC.__GAG2RF5 = nil
    elseif PVC.__GAG2RF5 then
        for k, v in pairs(PVC) do
            if type(k) == "string" and k:sub(1, 9) == "__GAG2RF5_" then
                PVC[k:sub(10)] = v
                PVC[k] = nil
            end
        end
        PVC.__GAG2RF5 = nil
    end
    table.clear(pvcBackup)
end

startPrevent = function()
    -- Soft shell OFF kalau fruit diurus game (default)
    forceSoftFruits = (not useGameManagedFruits()) and (CONFIG.stripOwnVisual == true)
    if not CONFIG.blockVisualInit then
        patchFruitModules()
        for _ = 1, 20 do
            if not alive then return end
            if patchFVC() and patchPVC() then break end
            task.wait(0.1)
        end
        visualBlockActive = true
        return
    end
    visualBlockActive = true
    local pn = patchPlantModules()
    local fn = patchFruitModules()
    dlog("startPrevent plants=%d fruits=%d gameFruit=%s", pn, fn, tostring(useGameManagedFruits()))
    -- PVC/FVC mungkin belom ada saat boot — poll
    task.spawn(function()
        for _ = 1, 40 do
            if not alive or not visualBlockActive then return end
            local okF = patchFVC()
            local okP = patchPVC()
            if okF and okP then
                dlog("startPrevent PVC/FVC ready")
                return
            end
            task.wait(0.1)
        end
    end)
end

stopPrevent = function()
    visualBlockActive = false
    -- jangan matikan forceSoftFruits di sini — restore soft masih butuh anti-mesh
    restoreFVC()
    restorePVC()
    restoreFruitModules()
    restorePlantModules()
    dlog("stopPrevent (InitPlant restored) softFruit=%s", tostring(forceSoftFruits))
end

local function waitPlantReady(plant, timeoutSec)
    if not plant then return false end
    local t0 = os.clock()
    local lim = timeoutSec or 2.5
    while plant.Parent and (os.clock() - t0) < lim do
        if plant:HasTag("InitializationComplete") or plant:GetAttribute("PlantGrowthReady") == true then
            return true
        end
        if plant:GetAttribute("PlantId") ~= nil and plant:GetAttribute("SeedName") ~= nil then
            -- attrs sudah ada; InitPlant asli kadang lambat — cukup untuk detect
            if (os.clock() - t0) >= 0.35 then
                return true
            end
        end
        task.wait()
    end
    return plant.Parent ~= nil
end

local function gardenEntryList(garden)
    local list = {}
    for plantId, data in pairs(garden) do
        if type(data) == "table" then
            list[#list + 1] = { id = plantId, data = data }
        end
    end
    table.sort(list, function(a, b)
        return tostring(a.id) < tostring(b.id)
    end)
    return list
end

local function resolvePlantData(sync, plantId, fallback)
    local data = fallback
    if sync and type(sync.GetPlant) == "function" then
        pcall(function()
            local d = sync:GetPlant(LP.UserId, plantId)
            if type(d) == "table" then
                data = d
            end
        end)
    end
    return data
end

-- plantData.Fruits → list { id, data } (map atau array)
-- Single-harvest (IsSingleHarvest saja): Fruits kosong → 1 entry FruitId=""
local function fruitEntriesFromPlantData(plantData, plant, plantId)
    local out = {}
    if type(plantData) ~= "table" then return out end
    local fruits = plantData.Fruits or plantData.fruits or plantData.Fruit

    local function push(fruitId, data)
        if fruitId == nil then return end
        local id = fruitId
        local d = data
        if type(d) ~= "table" then
            d = { FruitId = id }
        else
            id = d.FruitId or d.fruitId or d.Id or d.id or d.UUID or d.Uuid or fruitId
        end
        if id == nil or tostring(id) == "" then return end
        out[#out + 1] = { id = id, data = d }
    end

    if type(fruits) == "table" then
        -- JANGAN pakai index array sebagai FruitId (bikin shell palsu → LIVE > MaxFruits)
        if #fruits > 0 then
            for i = 1, #fruits do
                local d = fruits[i]
                if type(d) == "table" then
                    local fid = d.FruitId or d.fruitId or d.Id or d.id or d.UUID or d.Uuid
                    if fid ~= nil then
                        push(fid, d)
                    end
                end
            end
        else
            for fruitId, d in pairs(fruits) do
                if type(d) == "table" then
                    push(d.FruitId or d.fruitId or d.Id or d.id or d.UUID or d.Uuid or fruitId, d)
                elseif d == true or type(d) == "string" or type(d) == "number" then
                    push(fruitId, { FruitId = fruitId })
                end
            end
        end
    end

    -- Hanya IsSingleHarvest resmi — jangan heuristik Age (itu bikin match palsu)
    if #out == 0 and plantIsSingleHarvest(plantData, plant) then
        out[1] = { id = "", data = plantData }
    end
    return out
end

-- Soft default: shell UUID only, batch kecil (anti freeze). FullVisual: FVC (berat, opt-in).
local function spawnFruitsForPlant(fvc, plant, plantId, plantData, opts)
    opts = type(opts) == "table" and opts or {}
    if typeof(plant) ~= "Instance" or not plant.Parent then return 0 end
    local entries = fruitEntriesFromPlantData(plantData, plant, plantId)
    if #entries == 0 then return 0 end

    local fullVisual = opts.fullVisual == true
    local fruitBatch = math.max(1, math.floor(tonumber(opts.fruitBatchSize) or CONFIG.restoreFruitBatchSize or 3))
    local fruitDelay = math.max(0, tonumber(opts.fruitBatchDelay) or CONFIG.restoreFruitBatchDelay or 0.12)

    local n = 0
    local sinceWait = 0
    for i = 1, #entries do
        local e = entries[i]

        pcall(function()
            plant:AddTag("InitializationComplete")
            plant:SetAttribute("PlantGrowthReady", true)
        end)
        ensureFruitSpawnLocations(plant)

        local plantLevel = tostring(e.id or "") == ""
        if (not plantLevel) and (fullVisual or useGameManagedFruits())
            and fvc and type(fvc.SpawnFruitFromData) == "function" then
            -- Game spawn (default) / full visual — AutoCollect pakai prompt game
            local ok = pcall(function()
                fvc:SpawnFruitFromData(LP.UserId, plantId, e.id, e.data)
            end)
            if ok then
                n += 1
                stats.fruits += 1
                if not fullVisual and CONFIG.stripOwnVisual then
                    -- strip sudah di-hook SpawnFruitFromData / InitFruit
                end
            else
                local _, created = ensureDetectFruitShell(plant, plantId, e.id, e.data)
                if created then n += 1; stats.fruits += 1 end
            end
        else
            -- Soft shell (UUID buah ATAU single-harvest FruitId="")
            local _, created = ensureDetectFruitShell(plant, plantId, e.id, e.data)
            if created then
                n += 1
                stats.fruits += 1
            end
        end

        sinceWait += 1
        if sinceWait >= fruitBatch then
            sinceWait = 0
            if fruitDelay > 0 then
                task.wait(fruitDelay)
            else
                task.wait()
            end
        end
    end
    return n
end

local function respawnMissingOwnFruits(opts)
    opts = type(opts) == "table" and opts or {}
    local sync = getGardenSync()
    local fvc = getFVC()
    local pvc = getPVC()
    if not sync or type(sync.GetGarden) ~= "function" then return 0 end

    local garden = nil
    pcall(function()
        garden = sync:GetGarden(LP.UserId)
    end)
    if type(garden) ~= "table" then return 0 end

    local rehide = opts.rehide
    local fullVisual = opts.fullVisual == true or CONFIG.restoreFullVisual == true
    if rehide == nil then
        rehide = (CONFIG.restoreRehide ~= false) and not fullVisual
    end

    local total = 0
    local list = gardenEntryList(garden)
    for i = 1, #list do
        local entry = list[i]
        local plant = nil
        if pvc and type(pvc.GetSpawnedPlant) == "function" then
            pcall(function()
                plant = pvc:GetSpawnedPlant(LP.UserId, entry.id)
            end)
        end
        if typeof(plant) == "Instance" and plant.Parent then
            local data = resolvePlantData(sync, entry.id, entry.data)
            -- inject PlantName ke tiap fruit data (FVC / CorePartName)
            if type(data) == "table" and data.PlantName then
                local fruits = data.Fruits or data.fruits
                if type(fruits) == "table" then
                    for _, fd in pairs(fruits) do
                        if type(fd) == "table" and fd.PlantName == nil then
                            fd.PlantName = data.PlantName
                        end
                    end
                end
            end
            total += spawnFruitsForPlant(fvc, plant, entry.id, data, {
                rehide = rehide == true,
                fullVisual = fullVisual,
            })
        end
        if i % 10 == 0 then sliceYield() end
    end
    if total > 0 then
        dlog("respawnMissingOwnFruits count=%d rehide=%s", total, tostring(rehide))
    end
    return total
end

-- Hapus shell → spawn ulang BATCH (pelan). rehide = strip mesh setelah tiap batch.
local function rebuildOwnGardenVisuals(opts)
    opts = type(opts) == "table" and opts or {}
    local sync = getGardenSync()
    local pvc = getPVC()
    local fvc = getFVC()
    if not sync or not pvc then return 0 end
    if type(sync.GetGarden) ~= "function" or type(pvc.SpawnPlantFromData) ~= "function" then
        return 0
    end
    local garden = nil
    pcall(function()
        garden = sync:GetGarden(LP.UserId)
    end)
    if type(garden) ~= "table" then return 0 end

    local batchSize = math.max(1, math.floor(tonumber(opts.batchSize) or CONFIG.restoreBatchSize or 6))
    local batchDelay = math.max(0, tonumber(opts.batchDelay) or CONFIG.restoreBatchDelay or 0.45)
    local fullVisual = opts.fullVisual == true or CONFIG.restoreFullVisual == true
    local rehide = opts.rehide
    if rehide == nil then
        rehide = (CONFIG.restoreRehide ~= false) and not fullVisual
    end
    if fullVisual then rehide = false end

    local list = gardenEntryList(garden)
    dlog("rebuild gradual total=%d batch=%d delay=%.2f rehide=%s",
        #list, batchSize, batchDelay, tostring(rehide))

    local removed = 0
    for i = 1, #list do
        if type(pvc.RemovePlantById) == "function" then
            local ok = pcall(function()
                pvc:RemovePlantById(LP.UserId, list[i].id)
            end)
            if ok then removed += 1 end
        end
        -- yield sering biar gak freeze 1 frame 800 Destroy
        if i % 5 == 0 then
            task.wait()
        end
    end
    dlog("rebuild: removed shells=%d", removed)

    requestGardensFire()
    task.wait(0.15)
    reconcileLocalGarden()
    task.wait(0.2)

    -- FVC kadang belom ready pas Stop → tunggu sebentar
    if not fvc then
        for _ = 1, 30 do
            fvc = getFVC()
            if fvc and type(fvc.SpawnFruitFromData) == "function" then break end
            task.wait(0.1)
        end
    end

    -- refresh garden data setelah sync (Fruits sering lengkap di sini)
    pcall(function()
        garden = sync:GetGarden(LP.UserId)
    end)
    if type(garden) == "table" then
        list = gardenEntryList(garden)
    end

    local spawned = 0
    local fruitsSpawned = 0
    local total = #list
    for i = 1, total, batchSize do
        local last = math.min(i + batchSize - 1, total)
        for j = i, last do
            local entry = list[j]
            local plantData = resolvePlantData(sync, entry.id, entry.data)
            local existing = nil
            if type(pvc.GetSpawnedPlant) == "function" then
                pcall(function()
                    existing = pvc:GetSpawnedPlant(LP.UserId, entry.id)
                end)
            end
            local need = (not existing) or (typeof(existing) == "Instance" and not existing.Parent)
            if need then
                local ok = pcall(function()
                    pvc:SpawnPlantFromData(LP.UserId, entry.id, plantData)
                end)
                if ok then
                    spawned += 1
                    stats.restored += 1
                end
            end
            local plant = nil
            if type(pvc.GetSpawnedPlant) == "function" then
                pcall(function()
                    plant = pvc:GetSpawnedPlant(LP.UserId, entry.id)
                end)
            end
            if typeof(plant) == "Instance" then
                waitPlantReady(plant, 2.0)
                -- plant shell ≠ fruit: shell UUID (soft) / FVC (full)
                if not fvc then fvc = getFVC() end
                fruitsSpawned += spawnFruitsForPlant(fvc, plant, entry.id, plantData, {
                    fullVisual = fullVisual,
                    fruitBatchSize = CONFIG.restoreFruitBatchSize,
                    fruitBatchDelay = CONFIG.restoreFruitBatchDelay,
                })
                if rehide then
                    stripPlantKeepDetect(plant)
                end
            end
            sliceYield()
        end
        dlog("rebuild batch %d-%d / %d plants=%d fruits=%d", i, last, total, spawned, fruitsSpawned)
        if last < total and batchDelay > 0 then
            task.wait(batchDelay)
        end
    end

    dlog("rebuild DONE plants=%d fruits=%d rehide=%s fruitBatch=%d",
        spawned, fruitsSpawned, tostring(rehide), tonumber(CONFIG.restoreFruitBatchSize) or 3)
    return spawned + fruitsSpawned
end

restoreGardenFromData = function(reason, opts)
    opts = type(opts) == "table" and opts or {}
    local t0 = os.clock()
    local fullVisual = opts.fullVisual == true or CONFIG.restoreFullVisual == true
    -- soft: kunci fruit shell mode SEBELUM stopPrevent (supaya reconcile gak clone mesh)
    forceSoftFruits = not fullVisual
    stopPrevent()
    -- patch ulang FVC spawn → shell queue (plant InitPlant sudah restored)
    if forceSoftFruits then
        pcall(patchFVC)
    end
    local cleared = restoreOwnPlants()
    local rebuilt = rebuildOwnGardenVisuals(opts)
    local fruits = respawnMissingOwnFruits(opts)
    if not fullVisual then
        forceSoftFruits = CONFIG.stripOwnVisual == true
    else
        forceSoftFruits = false
    end
    dlog("restoreGardenFromData reason=%s cleared=%d rebuilt=%d fruitsMiss=%d softFruit=%s ms=%.0f",
        tostring(reason), cleared or 0, rebuilt or 0, fruits or 0,
        tostring(forceSoftFruits), (os.clock() - t0) * 1000)
    return (cleared or 0) + (rebuilt or 0) + (fruits or 0)
end

restoreAfterGardenReady = function(reason, opts)
    opts = type(opts) == "table" and opts or {}
    restoreGen += 1
    local gen = restoreGen
    task.spawn(function()
        waitGardenSpawnComplete(90)
        if gen ~= restoreGen then return end
        restoreGardenFromData(reason, opts)
        dlog("restore pass1 reason=%s", tostring(reason))
        local rehide = opts.rehide
        if rehide == nil then
            rehide = (CONFIG.restoreRehide ~= false) and not (opts.fullVisual or CONFIG.restoreFullVisual)
        end
        for _, delaySec in ipairs({ 1.2, 2.8 }) do
            task.wait(delaySec)
            if gen ~= restoreGen then return end
            reconcileLocalGarden()
            -- settle ringan: cuma isi fruit yang masih kosong (sudah di-throttle)
            respawnMissingOwnFruits({
                rehide = rehide == true,
                fullVisual = opts.fullVisual == true,
            })
            if not rehide then
                respawnMissingOwnPlants()
            end
            dlog("restore settle +%.1fs reason=%s rehide=%s", delaySec, tostring(reason), tostring(rehide))
        end
    end)
    return true
end

----------------------------------------------------------------
-- Own strip
----------------------------------------------------------------
local function stripOwnPlot(plot)
    if not plot or not CONFIG.stripOwnVisual then return end
    yieldT = os.clock()
    local t0 = os.clock()
    local folders = listPlantFolders(plot, LP.UserId)
    local plants = 0
    for _, folder in ipairs(folders) do
        local kids = folder:GetChildren()
        dlog("stashOwn %s count=%d", folder:GetFullName(), #kids)
        for i = 1, #kids do
            if not alive then return end
            if not isSprinkler(kids[i]) then
                -- block mode: strip + stamp PlantId/Weight/SeedName (AutoCollect filter)
                if CONFIG.blockVisualInit then
                    stripPlantKeepDetect(kids[i])
                else
                    hidePlantTree(kids[i])
                end
                plants += 1
            end
            sliceYield()
        end
    end
    dlog("stashOwn DONE plants=%d stashed=%d fruits=%d ms=%.0f",
        plants, stats.stashed, stats.fruits, (os.clock() - t0) * 1000)
end

local function bindFolderLive(folder, isOther, plot)
    if not folder or folderBound[folder] then return end
    folderBound[folder] = true
    local bucket = isOther and otherConns or plotConns

    table.insert(bucket, folder.ChildAdded:Connect(function(ch)
        if not alive then return end
        if isOther then
            if not CONFIG.clearOtherPlants then return end
            task.defer(function()
                task.wait(0.1)
                if not ch.Parent or not isConfirmedOtherPlot(plot) then return end
                if isOwnPlantContext(ch) then return end
                if isSprinkler(ch) then return end
                if not ch:IsA("Model") then
                    destroyIfOtherPlant(ch, plot)
                    return
                end
                local ownerId = plotOwnerUserId(plot)
                if ownerId and ownerId ~= LP.UserId and ch:GetAttribute("UserId") == nil then
                    pcall(function() ch:SetAttribute("UserId", ownerId) end)
                end
                -- tunggu SeedName sebentar (InitPlant kadang lambat)
                for _ = 1, 12 do
                    if stampPlantTypeAttrs(ch) or discoverPlantTypeName(ch) then break end
                    task.wait(0.05)
                    if not ch.Parent then return end
                end
                if not isConfirmedOtherPlot(plot) or isOwnPlantContext(ch) then return end
                local key = plantTypeKey(ch)
                if key ~= "_pending" and folderHasTypedPlant(folder, key, ch) then
                    if destroyIfOtherPlant(ch, plot) then
                        stats.destroyedPlants += 1
                    end
                    return
                end
                if key == "_pending" then
                    for _, sib in ipairs(folder:GetChildren()) do
                        if sib ~= ch and sib:IsA("Model") and not isSprinkler(sib)
                            and plantTypeKey(sib) == "_pending" then
                            if destroyIfOtherPlant(ch, plot) then
                                stats.destroyedPlants += 1
                            end
                            return
                        end
                    end
                end
                stripOtherPlantShell(ch)
            end)
        else
            if not CONFIG.stripOwnVisual then return end
            task.defer(function()
                if ch.Parent and not isSprinkler(ch) then
                    if CONFIG.blockVisualInit then
                        stripHeavyVisual(ch)
                    else
                        hidePlantTree(ch)
                    end
                end
            end)
        end
    end))

    if not isOther then
        table.insert(bucket, folder.DescendantAdded:Connect(function(d)
            if not alive or not CONFIG.stripOwnVisual then return end
            if d:IsA("ProximityPrompt") then
                tunePrompt(d)
                return
            end
            if isKeepInstance(d) then return end
            -- jangan re-stash yang sudah di dalam _GAG2Stash
            local p = d.Parent
            for _ = 1, 8 do
                if not p then break end
                if p.Name == PLANT_STASH or p.Name == STASH_NAME then return end
                p = p.Parent
            end
            if underFruitsFolder(d) then
                if d:IsA("BasePart") then
                    pcall(function()
                        d.LocalTransparencyModifier = 1
                        d.CastShadow = false
                    end)
                elseif d:IsA("Model") and isFruitModel(d) then
                    task.defer(function()
                        if not d.Parent then return end
                        bindFruitMutationListener(d)
                        stampMutationAttrs(d, nil)
                        hideFruit(d)
                    end)
                end
                return
            end
            -- Visual pohon baru → stash ke plant ancestor
            local plant = d:FindFirstAncestorOfClass("Model")
            while plant and plant.Parent and plant.Parent.Name ~= "Plants"
                and plant.Parent.Name ~= "Plants_Physical"
                and plant.Parent.Name ~= "PhysicalPlants" do
                local up = plant.Parent
                if up:IsA("Model") and up:GetAttribute("PlantId") ~= nil then
                    plant = up
                else
                    break
                end
            end
            if plant and not isFruitModel(plant) then
                -- stash top-level visual child if possible
                local top = d
                while top.Parent and top.Parent ~= plant do
                    top = top.Parent
                end
                if top.Parent == plant and not isKeepInstance(top) then
                    stashVisual(top, plant)
                end
            end
        end))
    end
end

local function bindOwnPlot(plot)
    stripOwnPlot(plot)
    for _, f in ipairs(listPlantFolders(plot, LP.UserId)) do
        bindFolderLive(f, false, plot)
    end
end

----------------------------------------------------------------
-- Other: Destroy keep 1 (no restore)
----------------------------------------------------------------
local function clearOtherPlot(plot)
    if not plot or not CONFIG.clearOtherPlants or not isConfirmedOtherPlot(plot) then return end
    local ownerId = plotOwnerUserId(plot)
    -- Double guard: jangan pernah clear plot sendiri
    if ownerId == nil or ownerId == LP.UserId then return end
    if isOwnPlot(plot) then return end
    yieldT = os.clock()
    local t0 = os.clock()
    local folders = listPlantFolders(plot, ownerId)
    local destroyed, plantsIn = 0, 0
    for _, folder in ipairs(folders) do
        local kids = folder:GetChildren()
        plantsIn += #kids
        local kept, kill = {}, {}
        for i = 1, #kids do
            local p = kids[i]
            if isSprinkler(p) then
            elseif p:IsA("Model") then
                if ownerId and p:GetAttribute("UserId") == nil then
                    pcall(function() p:SetAttribute("UserId", ownerId) end)
                end
                local key = plantTypeKey(p)
                local prev = kept[key]
                if prev then
                    local prevScore = (prev:GetAttribute("SeedName") ~= nil) and 1 or 0
                    local curScore = (p:GetAttribute("SeedName") ~= nil) and 1 or 0
                    if curScore > prevScore then
                        kill[#kill + 1] = prev
                        kept[key] = p
                    else
                        kill[#kill + 1] = p
                    end
                else
                    kept[key] = p
                end
            else
                kill[#kill + 1] = p
            end
        end
        for i = 1, #kill do
            if destroyIfOtherPlant(kill[i], plot) then
                destroyed += 1
                stats.destroyedPlants += 1
            end
            if i % BATCH == 0 then sliceYield() end
        end
        for _, p in pairs(kept) do
            if p and p.Parent and not isOwnPlantContext(p) then
                stripOtherPlantShell(p)
            end
        end
        bindFolderLive(folder, true, plot)
    end
    dlog("clearOther %s plantsIn=%d destroyed=%d ms=%.0f",
        plot.Name, plantsIn, destroyed, (os.clock() - t0) * 1000)
end

local function clearAllOthers()
    local g = Workspace:FindFirstChild("Gardens")
    if not g or not myPlot() then return end
    local t0 = os.clock()
    local n = 0
    for _, p in ipairs(g:GetChildren()) do
        if not alive then return end
        if isConfirmedOtherPlot(p) then
            if not otherBound[p] then
                otherBound[p] = true
                table.insert(otherConns, p.ChildAdded:Connect(function(ch)
                    if ch.Name == "Plants" or ch.Name == "Important" or ch.Name == "Plants_Physical" then
                        task.defer(function()
                            task.wait(0.2)
                            if alive and isConfirmedOtherPlot(p) then clearOtherPlot(p) end
                        end)
                    end
                end))
            end
            clearOtherPlot(p)
            n += 1
            task.wait()
        end
    end
    dlog("clearAllOthers plots=%d ms=%.0f", n, (os.clock() - t0) * 1000)
end

----------------------------------------------------------------
-- Graphics / boot
----------------------------------------------------------------
local function applyGraphics()
    pcall(function()
        Lighting.GlobalShadows = false
        Lighting.Technology = Enum.Technology.Compatibility
        Lighting.EnvironmentDiffuseScale = 0
        Lighting.EnvironmentSpecularScale = 0
        for _, fx in ipairs(Lighting:GetChildren()) do
            if fx:IsA("PostEffect") then fx.Enabled = false end
        end
    end)
    pcall(function()
        settings().Rendering.QualityLevel = Enum.QualityLevel.Level01
    end)
    local cap = tonumber(CONFIG.fpsCap)
    if cap and cap > 0 then
        pcall(function() if setfpscap then setfpscap(math.floor(cap)) end end)
    end
    if CONFIG.mode == "nuclear" then
        pcall(function() RunService:Set3dRenderingEnabled(false) end)
    end
end

local function muteAll()
    if CONFIG.muteSounds then
        pcall(function() SoundService.Volume = 0 end)
    end
end

local function bindSprinklerRadius()
    local function kill(inst)
        local n = string.lower(tostring(inst.Name or ""))
        if n:find("sprinklerradius", 1, true) then
            pcall(function() inst:Destroy() end)
        end
    end
    local function bindChar(char)
        if not char then return end
        table.insert(conns, char.DescendantAdded:Connect(function(d)
            if alive then kill(d) end
        end))
    end
    if LP.Character then bindChar(LP.Character) end
    table.insert(conns, LP.CharacterAdded:Connect(function(c)
        task.defer(function() if alive then bindChar(c) end end)
    end))
end

local function startReconcile(myToken)
    task.spawn(function()
        local gap = tonumber(CONFIG.otherReconcileSec) or 25
        while alive and myToken == token do
            task.wait(gap)
            if not alive or myToken ~= token then return end
            local g = Workspace:FindFirstChild("Gardens")
            if not g or not myPlot() then continue end
            for _, p in ipairs(g:GetChildren()) do
                if not alive then return end
                if isConfirmedOtherPlot(p) then
                    local folders = listPlantFolders(p, plotOwnerUserId(p))
                    local count = 0
                    for _, f in ipairs(folders) do count += #f:GetChildren() end
                    if count > 25 then
                        clearOtherPlot(p)
                        task.wait()
                    end
                end
            end
        end
    end)
end

-- RINGAN: enable/disable tag shell dari Age/MaxAge GardenSync.
-- Jangan stamp penuh / jangan panggil tiap UpdateFruitGrowthData.
syncOwnShellHarvestFromSync = function()
    if useGameManagedFruits() then return 0 end
    if not (forceSoftFruits or (visualBlockActive and CONFIG.stripOwnVisual)) then
        return 0
    end
    local sync = getGardenSync()
    local pvc = getPVC()
    local fvc = getFVC()
    if not sync or not pvc then return 0 end
    if type(sync.GetGarden) ~= "function" or type(pvc.GetSpawnedPlant) ~= "function" then
        return 0
    end
    local garden = nil
    pcall(function()
        garden = sync:GetGarden(LP.UserId)
    end)
    if type(garden) ~= "table" then return 0 end

    local enabled, disabled, scanned = 0, 0, 0
    for plantId, plantData in pairs(garden) do
        if type(plantData) ~= "table" then continue end
        local plant = nil
        pcall(function()
            plant = pvc:GetSpawnedPlant(LP.UserId, plantId)
        end)
        if typeof(plant) ~= "Instance" or not plant.Parent then continue end

        local entries = fruitEntriesFromPlantData(plantData, plant, plantId)
        if #entries == 0 then continue end

        local folder = plant:FindFirstChild("Fruits") or plant:FindFirstChild("Fruit")
        local needShell = (folder == nil)
        if folder then
            local shellN = 0
            for _, ch in ipairs(folder:GetChildren()) do
                if ch:IsA("Model") and ch:GetAttribute(FRUIT_SHELL_ATTR) == true then
                    shellN += 1
                end
            end
            needShell = shellN == 0
        end
        -- Carrot/bamboo: buat shell plant-level kalau belum ada
        if needShell then
            pcall(spawnFruitsForPlant, fvc, plant, plantId, plantData, {
                fruitBatchSize = 1,
                fruitBatchDelay = 0,
            })
            folder = plant:FindFirstChild("Fruits") or plant:FindFirstChild("Fruit")
        end
        if not folder then continue end

        local byId = {}
        for i = 1, #entries do
            byId[tostring(entries[i].id)] = entries[i].data
        end

        for _, ch in ipairs(folder:GetChildren()) do
            if not ch:IsA("Model") then continue end
            local isShell = ch:GetAttribute(FRUIT_SHELL_ATTR) == true
            local fidAttr = ch:GetAttribute("FruitId")
            -- FruitId "" valid (plant-harvest); nil tanpa flag = skip
            if fidAttr == nil and ch:GetAttribute("_GAG2PlantHarvest") ~= true then
                continue
            end
            local fid = tostring(fidAttr or "")
            bindFruitMutationListener(ch)

            local data = byId[fid]
            if type(data) ~= "table" and fid == "" then
                data = plantData
            end

            -- Mutasi: SEMUA buah (shell + game fruit). String Mutation → boolean.
            if type(data) == "table" then
                stampMutationAttrs(ch, data)
            else
                stampMutationAttrs(ch, nil)
            end

            -- Ripe gate / weight cuma soft shell
            if not isShell then
                scanned += 1
                continue
            end

            local pr = ch:FindFirstChild("HarvestPrompt", true)
            local wasOn = pr
                and pr:IsA("ProximityPrompt")
                and CollectionService:HasTag(pr, "HarvestPrompt")
                and pr:GetAttribute("Collected") ~= true

            if type(data) ~= "table" then
                if pr then
                    applyShellCollectGate(ch, false)
                    if wasOn then disabled += 1 end
                end
                continue
            end

            local age = _pickDataNum(data, { "Age", "age" })
            local maxAge = _pickDataNum(data, { "MaxAge", "maxAge" })
            local bw = _pickDataNum(data, { "BaseWeight", "baseWeight", "BaseKg" })
            local sm = _pickDataNum(data, { "SizeMulti", "SizeMultiplier", "Scale", "FruitScale" })
            local og = _pickDataNum(data, { "OvertimeGrowth", "Overtime" }) or 1
            local w = _pickDataNum(data, { "Weight", "weight", "Kg", "kg", "DisplayWeight", "HarvestWeight" })
            if (not w or w <= 0) and bw and bw > 0 then
                w = bw * (sm or 1) * (og > 0 and og or 1)
            end
            pcall(function()
                if age ~= nil then ch:SetAttribute("Age", age) end
                if maxAge ~= nil then ch:SetAttribute("MaxAge", maxAge) end
                if bw ~= nil then ch:SetAttribute("BaseWeight", bw) end
                if w and w > 0 then ch:SetAttribute("Weight", w) end
            end)

            -- strict: cuma Age>=MaxAge (sama multi-buah — anti match palsu)
            local ready = fruitDataHarvestReady(data, ch)
            if ready then
                if not pr then
                    ensureShellBodyPart(ch, ch:GetPivot())
                    local hp = ch:FindFirstChild("HarvestPart") or ch:FindFirstChild("ShellBody")
                    if hp and hp:IsA("BasePart") then
                        pr = Instance.new("ProximityPrompt")
                        pr.Style = Enum.ProximityPromptStyle.Custom
                        pr.Name = "HarvestPrompt"
                        pr.ActionText = "Harvest"
                        pr.HoldDuration = 0
                        pr.RequiresLineOfSight = false
                        pr.Parent = hp
                    end
                end
                if not wasOn then
                    applyShellCollectGate(ch, true)
                    enabled += 1
                end
            else
                if pr then
                    applyShellCollectGate(ch, false)
                    if wasOn then disabled += 1 end
                end
            end

            scanned += 1
            if scanned % 60 == 0 then
                task.wait()
            end
        end
    end
    if enabled > 0 or disabled > 0 then
        dlog("ripe-strict on=%d off=%d scanned=%d", enabled, disabled, scanned)
    end
    return enabled
end

-- Soft shell tidak di-track FVC → setelah collect tetap ada + AutoCollect counter stuck.
local function startFruitShellPrune(myToken)
    task.spawn(function()
        pcall(cleanupAllOwnLooseProxies)
        pcall(pruneOrphanOwnFruits)
        if forceSoftFruits or CONFIG.stripOwnVisual then
            pcall(syncOwnShellHarvestFromSync)
        end
        while alive and myToken == token do
            -- 2s: mutasi weather (Glow) harus cepat ke shell tanpa rejoin
            task.wait(2.0)
            if not alive or myToken ~= token then return end
            pcall(cleanupAllOwnLooseProxies)
            if not (forceSoftFruits or CONFIG.stripOwnVisual) then continue end
            local n = 0
            pcall(function()
                n = pruneOrphanOwnFruits()
            end)
            if n > 0 then
                dlog("prune orphan shells=%d total=%d", n, statsPrunedFruits)
            end
            pcall(syncOwnShellHarvestFromSync)
        end
    end)
end

local function waitReady()
    local t0 = os.clock()
    while alive and os.clock() - t0 < 50 do
        if Workspace:FindFirstChild("Gardens") and LP:GetAttribute("PlotId") and LP.Character then
            task.wait(0.1)
            if myPlot() then
                dlog("waitReady %s ms=%.0f", myPlot().Name, (os.clock() - t0) * 1000)
                return true
            end
        end
        task.wait(0.15)
    end
    return myPlot() ~= nil
end

local function applyAll()
    local t0 = os.clock()
    applyGraphics()
    muteAll()
    local plot = myPlot()
    if not plot then
        dlog("applyAll no plot")
        return
    end
    startPrevent()
    markActive()
    -- Heavy strip/destroy JANGAN barengan loading/skip — itu yang bikin freeze
    task.spawn(function()
        local total = tonumber(LP:GetAttribute("GardenLoadingTotal")) or 0
        if LP:GetAttribute("LoadingScreenActive") == true or total > 0 then
            dlog("applyAll wait garden spawn before strip…")
            waitGardenSpawnComplete(120)
            -- jeda setelah skip biar frame game settle
            task.wait(1.0)
        else
            task.wait(0.35)
        end
        if not alive then return end
        clearAllOthers()
        if not alive then return end
        task.wait(0.2)
        disc(plotConns)
        table.clear(folderBound)
        bindOwnPlot(myPlot() or plot)
        -- JANGAN AddMissingPrompts massal di garden besar — tiap prompt → FruitProxyUtil:Fire
        -- (sering "Cannot have more than 128 yielded threads"). Prompt shell kita sudah ada.
        task.defer(function()
            if not alive then return end
            if (tonumber(stats.fruits) or 0) > 80 or countOwnPlants() > 120 then
                dlog("skip AddMissingPrompts (garden besar fruits=%d plants=%d)",
                    tonumber(stats.fruits) or 0, countOwnPlants())
                return
            end
            task.wait(2.0)
            if not alive then return end
            local FVC = getFVC()
            if FVC and type(FVC.AddMissingPrompts) == "function" then
                pcall(function() FVC:AddMissingPrompts() end)
            end
        end)
        dlog("applyAll DONE ms=%.0f stashed=%d fruits=%d destroyedOther=%d",
            (os.clock() - t0) * 1000, stats.stashed, stats.fruits, stats.destroyedPlants)
    end)
end

local function bindGardens(g)
    if not g then return end
    table.insert(conns, g.ChildAdded:Connect(function(ch)
        if not alive then return end
        task.defer(function()
            task.wait(0.25)
            if alive and isConfirmedOtherPlot(ch) then
                clearOtherPlot(ch)
            end
        end)
    end))
end

