-- API
----------------------------------------------------------------
-- Soft: batch spawn → strip mesh (PlantId/FruitId/proxy tetap → AutoCollect/Trowel OK)
function M.RestoreSoft()
    return restoreAfterGardenReady("RestoreSoft", {
        rehide = true,
        fullVisual = false,
        batchSize = CONFIG.restoreBatchSize,
        batchDelay = CONFIG.restoreBatchDelay,
    })
end
M.restoreSoft = M.RestoreSoft

-- Full: batch spawn, biarkan visual (pelan, anti spike)
function M.RestoreFull()
    return restoreAfterGardenReady("RestoreFull", {
        rehide = false,
        fullVisual = true,
        batchSize = CONFIG.restoreBatchSize,
        batchDelay = CONFIG.restoreBatchDelay,
    })
end
M.restoreFull = M.RestoreFull

function M.RestoreOwn()
    if CONFIG.restoreFullVisual then
        return M.RestoreFull()
    end
    return M.RestoreSoft()
end
M.restoreOwn = M.RestoreOwn
M.Restore = M.RestoreOwn
M.RestoreGarden = M.RestoreOwn

function M.RestoreGardenNow(opts)
    opts = type(opts) == "table" and opts or {
        rehide = CONFIG.restoreRehide ~= false and not CONFIG.restoreFullVisual,
        fullVisual = CONFIG.restoreFullVisual == true,
    }
    return restoreGardenFromData("RestoreGardenNow", opts)
end
M.restoreGardenNow = M.RestoreGardenNow

-- opts.quiet = true → cleanup saja, JANGAN restore (dipakai Start / reload)
function M.Stop(opts)
    opts = type(opts) == "table" and opts or {}
    local quiet = opts.quiet == true or opts.noRestore == true
    local wasRunning = running or alive

    dlog("STOP quiet=%s wasRunning=%s stashed=%d destroyedOther=%d",
        tostring(quiet), tostring(wasRunning), stats.stashed, stats.destroyedPlants)

    alive = false
    running = false
    token += 1
    -- batalkan restore yang sedang nunggu LoadingScreenDone (biar gak freeze setelah skip)
    if quiet or not wasRunning then
        restoreGen += 1
    end
    stopPrevent()
    disc(conns)
    disc(plotConns)
    disc(otherConns)
    for folder, c in pairs(fruitsFolderBound) do
        pcall(function()
            if c then c:Disconnect() end
        end)
        fruitsFolderBound[folder] = nil
    end
    table.clear(fruitsFolderBound)
    table.clear(otherBound)
    table.clear(folderBound)
    cachedPlot = nil
    pcall(function() RunService:Set3dRenderingEnabled(true) end)
    G.REDUCE_FPS_ENABLED = false
    _G.REDUCE_FPS_ENABLED = false
    markActive()

    -- HANYA restore kalau user benar-benar matikan fitur (bukan Start/reload)
    if wasRunning and CONFIG.restoreOnStop and not quiet then
        if CONFIG.restoreFullVisual then
            restoreAfterGardenReady("Stop", { rehide = false, fullVisual = true })
        else
            restoreAfterGardenReady("Stop", { rehide = true, fullVisual = false })
        end
    end
end

function M.Start()
    if running then return true end
    -- JANGAN panggil Stop biasa: itu ngantri restore → freeze pas loading skip selesai
    restoreGen += 1
    M.Stop({ quiet = true })

    _cfg()
    alive = true
    running = true
    token += 1
    local myToken = token
    cachedPlot = nil
    stats = { destroyedPlants = 0, stashed = 0, fruits = 0, restored = 0 }
    statsBlocked = { plantInit = 0, fruitInit = 0, otherPlantSkip = 0, otherFruitSkip = 0, stripped = 0 }
    table.clear(stashMap)
    table.clear(fruitShellQueue)
    table.clear(fruitShellQueued)
    fruitShellDraining = false

    G.REDUCE_FPS_ENABLED = true
    _G.REDUCE_FPS_ENABLED = true
    if G.REDUCE_FPS_DEBUG == nil and rawget(_G, "REDUCE_FPS_DEBUG") == nil then
        G.REDUCE_FPS_DEBUG = CONFIG.debug
        _G.REDUCE_FPS_DEBUG = CONFIG.debug
    end
    markActive()
    -- Gate FruitProxyUtil saja (jangan sentuh CollectFruit/Packet)
    pcall(installFruitProxyYieldGate)
    -- PENTING: block InitPlant SEBELUM plot/garden spawn (anti CPU spike)
    startPrevent()
    dlog("START v10.22.4-mut-live plantBatch=%d fruitBatch=%d/%0.2fs rehide=%s",
        tonumber(CONFIG.restoreBatchSize) or 4,
        tonumber(CONFIG.restoreFruitBatchSize) or 3,
        tonumber(CONFIG.restoreFruitBatchDelay) or 0.12,
        tostring(CONFIG.restoreRehide))

    task.spawn(function()
        if not alive or myToken ~= token then return end
        applyGraphics()
        muteAll()
        bindSprinklerRadius()
        -- pastikan patch nempel kalau Plants folder belom ready di Start sync
        if CONFIG.blockVisualInit then
            patchPlantModules()
            patchFruitModules()
        end
        local g = Workspace:FindFirstChild("Gardens") or Workspace:WaitForChild("Gardens", 25)
        bindGardens(g)
        table.insert(conns, LP:GetAttributeChangedSignal("PlotId"):Connect(function()
            cachedPlot = nil
            disc(plotConns)
            table.clear(folderBound)
            task.defer(function()
                task.wait(0.2)
                if alive and waitReady() then applyAll() end
            end)
        end))
        if waitReady() and alive and myToken == token then
            applyAll()
            startReconcile(myToken)
            startFruitShellPrune(myToken)
        else
            -- plot belom siap saat boot — poll sampai ada
            for _ = 1, 60 do
                if not alive or myToken ~= token then return end
                task.wait(1)
                if myPlot() then
                    applyAll()
                    startReconcile(myToken)
                    startFruitShellPrune(myToken)
                    return
                end
            end
            dlog("START aborted: plot never ready")
        end
    end)
    return true
end

function M.SetEnabled(on)
    on = (on == true)
    G.REDUCE_FPS_ENABLED = on
    _G.REDUCE_FPS_ENABLED = on
    if on then M.Start() else M.Stop() end
end
M.setEnabled = M.SetEnabled

function M.IsEnabled()
    return running
end
M.isRunning = M.IsEnabled

function M.SetDebug(on)
    on = (on == true)
    CONFIG.debug = on
    G.REDUCE_FPS_DEBUG = on
    _G.REDUCE_FPS_DEBUG = on
    return on
end
M.setDebug = M.SetDebug

function M.IsDebug()
    return debugOn()
end

function M.SyncFromGlobals()
    local cfg = _cfg()
    G.REDUCE_FPS_ENABLED = cfg.enabled
    _G.REDUCE_FPS_ENABLED = cfg.enabled
    -- REDUCE_FPS_DEBUG sengaja tidak di-overwrite dari state (session-only)
    -- Jangan Stop+Start ulang kalau sudah jalan (itu yang bikin stash hilang / harus buka tab)
    if cfg.enabled then
        if not running then
            M.Start()
        else
            markActive()
        end
    elseif running then
        M.Stop()
    end
    return cfg
end

function M.GetStats()
    local left = 0
    for _ in pairs(stashMap) do left += 1 end
    return {
        enabled = running,
        plot = cachedPlot and cachedPlot.Name,
        stats = stats,
        stashLeft = left,
        debug = debugOn(),
        version = "v10.22.4-mut-live",
        visualBlockActive = visualBlockActive,
        blocked = statsBlocked,
        prunedFruits = statsPrunedFruits,
        fruitShellQueue = #fruitShellQueue,
        restoreBatchSize = CONFIG.restoreBatchSize,
        restoreRehide = CONFIG.restoreRehide,
        gardenSpawnComplete = isGardenSpawnComplete(),
        gardenProgress = LP:GetAttribute("GardenLoadingProgress"),
        gardenTotal = LP:GetAttribute("GardenLoadingTotal"),
        loadingDone = LP:GetAttribute("LoadingScreenDone") == true,
    }
end

function M.DumpDebug()
    local s = M.GetStats()
    print(string.format(
        "[ReduceFPS] dump v10.7 plot=%s fruits=%d pruned=%d plantBatch=%d fruitBatch=%d/%0.2fs queue=%d rehide=%s garden=%s/%s",
        tostring(s.plot), stats.fruits, statsPrunedFruits,
        tonumber(CONFIG.restoreBatchSize) or 4,
        tonumber(CONFIG.restoreFruitBatchSize) or 3,
        tonumber(CONFIG.restoreFruitBatchDelay) or 0.12,
        #fruitShellQueue,
        tostring(CONFIG.restoreRehide),
        tostring(s.gardenProgress), tostring(s.gardenTotal)
    ))
    return s
end
M.dumpDebug = M.DumpDebug
M.IsGardenSpawnComplete = isGardenSpawnComplete
M.WaitGardenSpawnComplete = waitGardenSpawnComplete
M.RestoreGardenFromData = restoreGardenFromData
M.RespawnMissingOwnFruits = respawnMissingOwnFruits
M.respawnMissingOwnFruits = respawnMissingOwnFruits
