_G.ReduceFPS = M
_G.ReduceFPSModule = M

-- Auto-start sedini mungkin kalau flag sudah ON (kejar Controllers sebelum InitPlant)
task.defer(function()
    local MAIN = rawget(_G, "MAIN") or G.MAIN
    local perf = MAIN and MAIN.misc and MAIN.misc.perf
    local want = (G.REDUCE_FPS_ENABLED == true)
        or (rawget(_G, "REDUCE_FPS_ENABLED") == true)
        or (type(perf) == "table" and perf.enabled == true)
    if want and not running then
        pcall(M.Start)
    elseif want and CONFIG.blockVisualInit then
        -- Start lagi / sudah jalan — pastikan plant modules kepatch
        pcall(startPrevent)
    end
end)

return M
 end,                      required = false, early = true },
    { key = "antiafk",                 name = "Anti AFK",                factory = function() -- antiafk.lua — Grow A Garden 2 (AFK nudge + hide loading + skip when ready + dismiss teleport prompt)

local Players = game:GetService("Players")
local ReplicatedStorage = game:GetService("ReplicatedStorage")
local CoreGui = game:GetService("CoreGui")
local GuiService = game:GetService("GuiService")
local Lighting = game:GetService("Lighting")
local ProximityPromptService = game:GetService("ProximityPromptService")
local UserInputService = game:GetService("UserInputService")
local VirtualUser = game:GetService("VirtualUser")
local VIM = game:GetService("VirtualInputManager")

local LP = Players.LocalPlayer
if not LP then
    LP = Players:GetPropertyChangedSignal("LocalPlayer"):Wait()
end
local G = (getgenv and getgenv()) or _G

local function exportFactory(mod)
    return function()
        return mod
    end
end

local M = G.AntiAFK or G.antiafk
if type(M) ~= "table" then
    M = {}
end
G.__GAG2_ANTIAFK_MODULE_LOADED = true

M.VERSION = 3
M._pulseCount = tonumber(M._pulseCount) or 0
M._lastPulseAt = tonumber(M._lastPulseAt) or 0
M._startedVer = tonumber(M._startedVer) or 0

M.running = M.running == true
M.connection = M.connection
M.thread = M.thread
M.DEBUG = M.DEBUG == true
M._teleportPromptLoop = false
M._hideLoadingLoop = false
M._lastSkip = 0

local HIDE_LOADING_LOOP_WAIT = 0.3
local SKIP_FIRE_COOLDOWN = 1.5

local function dprint(...)
    if M.DEBUG then
        print("[GAG2-AFK]", ...)
    end
end

local function nudge()
    pcall(function()
        VirtualUser:CaptureController()
        VirtualUser:ClickButton2(Vector2.new(0, 0))
    end)
    dprint("nudge")
end

-- Game AntiAfkController hanya lihat UserInputService (bukan VirtualUser).
-- Idle ~1140s → Networking.AntiAfk.RequestHop:Fire() = hop server.
local GAME_ACTIVITY_SEC = 60

local function gameActivityPulse()
    pcall(function()
        local cam = workspace.CurrentCamera
        local mobile = UserInputService.TouchEnabled
            and UserInputService.KeyboardEnabled ~= true
        local mode = "keyboard"

        if mobile and cam then
            mode = "touch"
            local x = cam.ViewportSize.X * 0.5
            local y = cam.ViewportSize.Y * 0.75
            local ok = pcall(function()
                VIM:SendTouchEvent(0, Vector2.new(x, y), false, game, 0)
                task.wait(0.05)
                VIM:SendTouchEvent(0, Vector2.new(x, y), true, game, 0)
            end)
            if not ok then
                mode = "mouse-fallback"
                VIM:SendMouseButtonEvent(x, y, 0, true, game, 0)
                task.wait(0.05)
                VIM:SendMouseButtonEvent(x, y, 0, false, game, 0)
            end
        else
            VIM:SendKeyEvent(Enum.KeyCode.Space, false, true, game)
            task.wait(0.05)
            VIM:SendKeyEvent(Enum.KeyCode.Space, false, false, game)
            if cam then
                local margin = 24
                VIM:SendMouseButtonEvent(margin, margin, 0, true, game, 0)
                task.wait(0.05)
                VIM:SendMouseButtonEvent(margin, margin, 0, false, game, 0)
                mode = "key+mouse"
            end
        end

        M._pulseCount = (M._pulseCount or 0) + 1
        M._lastPulseAt = os.clock()
        dprint(string.format("pulse #%d (%s)", M._pulseCount, mode))
    end)
end

local function blockGameRequestHop()
    pcall(function()
        local Networking = require(ReplicatedStorage:WaitForChild("SharedModules"):WaitForChild("Networking"))
        local req = Networking.AntiAfk and Networking.AntiAfk.RequestHop
        if not req or type(req.Fire) ~= "function" or req.__GAG2_BLOCK then
            return
        end
        req.Fire = function(...)
            dprint("blocked game AntiAfk.RequestHop")
            return nil
        end
        req.__GAG2_BLOCK = true
        dprint("hooked AntiAfk.RequestHop")
    end)
end

local function isHopBlocked()
    local ok, blocked = pcall(function()
        local Networking = require(ReplicatedStorage:WaitForChild("SharedModules"):WaitForChild("Networking"))
        local req = Networking.AntiAfk and Networking.AntiAfk.RequestHop
        return req and req.__GAG2_BLOCK == true
    end)
    return ok and blocked == true
end

local function isLoadingActive()
    if not LP then return false end
    if LP:GetAttribute("LoadingScreenDone") == true then
        return false
    end
    return LP:GetAttribute("LoadingScreenActive") == true
        or LP:GetAttribute("LoadingScreenDone") ~= true
end

local function hideLoadingGloballyEnabled()
    return G.HIDE_LOADING_ENABLED == true or rawget(_G, "HIDE_LOADING_ENABLED") == true
end

local function hideLoadingVisual(menu)
    pcall(function()
        local gui = menu:FindFirstChild("LoadingGui", true)
        if gui then
            gui.Enabled = true
        end

        for _, v in ipairs(menu:GetDescendants()) do
            if v:IsA("TextLabel") or v:IsA("TextButton") then
                v.TextTransparency = 1
                v.BackgroundTransparency = 1
            elseif v:IsA("ImageLabel") or v:IsA("ImageButton") then
                v.ImageTransparency = 1
                v.BackgroundTransparency = 1
            elseif v:IsA("Frame") then
                v.BackgroundTransparency = 1
            elseif v:IsA("UIStroke") then
                v.Transparency = 1
            end
        end
    end)
end

local function isLoadingSkipReady(menu)
    if not menu then return false end

    for _, v in ipairs(menu:GetDescendants()) do
        if v.Name == "SkipTxt" or v.Name == "PressAnyTxt" then
            local t = ""
            pcall(function()
                t = string.lower(v.Text or "")
            end)

            if t:find("click to skip", 1, true)
                or t:find("press any", 1, true)
                or t:find("tap anywhere", 1, true) then
                return true
            end
        end
    end

    return false
end

local function fireSkipLoading()
    if not isLoadingActive() then return end

    local menu = workspace:FindFirstChild("LoadingScreenMenu")
    if not menu or not isLoadingSkipReady(menu) then return end

    if os.clock() - (M._lastSkip or 0) < SKIP_FIRE_COOLDOWN then
        return
    end
    M._lastSkip = os.clock()

    -- Hanya klik virtual ke game — JANGAN getconnections/firesignal InputBegan
    -- (memicu handler shop/gift/UI lain di luar loading screen).
    pcall(function()
        local cam = workspace.CurrentCamera
        if not cam then return end
        local margin = 24
        local x = margin
        local y = cam.ViewportSize.Y - margin
        VIM:SendMouseButtonEvent(x, y, 0, true, game, 0)
        task.wait(0.05)
        VIM:SendMouseButtonEvent(x, y, 0, false, game, 0)
    end)

    dprint("skip fired (VIM only)")
end

local function restoreAfterLoading()
    pcall(function()
        for _, v in ipairs(Lighting:GetChildren()) do
            if v:IsA("BlurEffect") then
                v.Enabled = false
                v.Size = 0
            elseif v:IsA("DepthOfFieldEffect") then
                v.Enabled = false
            end
        end

        local cam = workspace.CurrentCamera
        if cam then
            cam.CameraType = Enum.CameraType.Custom
            cam.FieldOfView = 70
        end

        ProximityPromptService.Enabled = true

        local hrp = LP and LP.Character and LP.Character:FindFirstChild("HumanoidRootPart")
        if hrp then
            hrp.Anchored = false
        end
    end)
end

local function startHideLoadingSkipLoop()
    if M._hideLoadingLoop then return end
    M._hideLoadingLoop = true

    task.spawn(function()
        dprint("hide loading + real skip loop start")
        while M._hideLoadingLoop do
            local menu = workspace:FindFirstChild("LoadingScreenMenu")

            if menu then
                if hideLoadingGloballyEnabled() then
                    hideLoadingVisual(menu)
                end

                if isLoadingSkipReady(menu) then
                    fireSkipLoading()
                end
            end

            if hideLoadingGloballyEnabled() then
                restoreAfterLoading()
            end
            task.wait(HIDE_LOADING_LOOP_WAIT)
        end
        dprint("hide loading + real skip loop stopped")
    end)
end

local TELEPORT_PROMPT_LOOP_WAIT = 0.2
local TELEPORT_PROMPT_HIDE_DELAY = 0.5

local blurGuardWired = false

local function hidePromptGloballyEnabled()
    return G.HIDE_PROMPT_ENABLED == true or rawget(_G, "HIDE_PROMPT_ENABLED") == true
end

local function removeLoadingBlur(force)
    pcall(function()
        local blur = Lighting:FindFirstChild("Blur")
        if blur then
            if force or blur.Enabled or (tonumber(blur.Size) or 0) > 0 then
                blur.Enabled = false
                blur.Size = 0
            end
        end

        local dof = Lighting:FindFirstChild("DepthOfField")
        if dof and (force or dof.Enabled) then
            dof.Enabled = false
        end
    end)

    if force then
        pcall(function()
            local cm = ReplicatedStorage:FindFirstChild("ClientModules")
            local blurMod = cm and cm:FindFirstChild("Blur")
            if blurMod then
                require(blurMod).SetBlur(0, 0)
            end
        end)

        pcall(function()
            local cam = workspace.CurrentCamera
            if cam then
                cam.CameraType = Enum.CameraType.Custom
                cam.FieldOfView = 70
            end
        end)

        pcall(function()
            ProximityPromptService.Enabled = true
        end)
    end
end

local function getPromptText()
    local gui = CoreGui:FindFirstChild("RobloxPromptGui")
    if not gui then return "" end

    local txt = {}
    for _, v in ipairs(gui:GetDescendants()) do
        if v:IsA("TextLabel") or v:IsA("TextButton") then
            if v.Text and v.Text ~= "" then
                txt[#txt + 1] = v.Text
            end
        end
    end

    return table.concat(txt, " ")
end

local function isTeleportFailPrompt(text)
    text = string.lower(tostring(text or ""))
    if text == "" then return false end

    return text:find("teleport failed", 1, true)
        or text:find("teleportasi gagal", 1, true)
        or text:find("error code: 772", 1, true)
        or text:find("kode error: 772", 1, true)
        or text:find("server full", 1, true)
        or text:find("game full", 1, true)
end

-- Bukan Lighting.Blur — buat layer gelap RobloxPromptGui transparan supaya game bisa diklik
local function softenPromptOverlay()
    local gui = CoreGui:FindFirstChild("RobloxPromptGui")
    if not gui then return end

    for _, v in ipairs(gui:GetDescendants()) do
        if v:IsA("GuiObject") then
            local n = string.lower(v.Name)
            if n:find("overlay", 1, true)
                or n:find("background", 1, true)
                or n:find("shade", 1, true)
                or n:find("dark", 1, true) then
                v.BackgroundTransparency = 1
                v.Active = false
                v.Selectable = false
            end
        end
    end
end

local function hidePromptSafe()
    if not hidePromptGloballyEnabled() then
        return
    end

    local gui = CoreGui:FindFirstChild("RobloxPromptGui")
    if not gui or gui.Enabled ~= true then
        return
    end

    pcall(function()
        GuiService:ClearError()
    end)

    softenPromptOverlay()
end

local function startTeleportPromptLoop()
    if M._teleportPromptLoop then return end
    M._teleportPromptLoop = true

    task.spawn(function()
        dprint("teleport prompt loop start")
        while M._teleportPromptLoop do
            local okStep, stepErr = pcall(function()
                if not hidePromptGloballyEnabled() then
                    return
                end

                local text = getPromptText()
                if isTeleportFailPrompt(text) then
                    dprint("Teleport prompt detected:", text)
                    task.wait(TELEPORT_PROMPT_HIDE_DELAY)
                    hidePromptSafe()
                end
            end)

            if not okStep then
                warn("[GAG2-AFK] teleport prompt loop error:", tostring(stepErr))
            end

            task.wait(TELEPORT_PROMPT_LOOP_WAIT)
        end
        dprint("teleport prompt loop stopped")
    end)
end

local function ensureBlurGuard()
    if blurGuardWired then return end
    local blur = Lighting:FindFirstChild("Blur")
    if not blur then return end

    blurGuardWired = true
    removeLoadingBlur(true)

    pcall(function()
        blur:GetPropertyChangedSignal("Enabled"):Connect(function()
            if isLoadingActive() then return end
            if blur.Enabled then
                blur.Enabled = false
            end
        end)
        blur:GetPropertyChangedSignal("Size"):Connect(function()
            if isLoadingActive() then return end
            if (tonumber(blur.Size) or 0) > 0 then
                blur.Size = 0
            end
        end)
    end)
end

local offlineGrowthHooked = false

local function hideOfflineAnimationUi()
    local gui = LP and LP.PlayerGui and LP.PlayerGui:FindFirstChild("OfflineAnimation")
    if not gui then return end
    pcall(function()
        local top = gui:FindFirstChild("TopBar")
        local bottom = gui:FindFirstChild("BottomBar")
        if top then top.BackgroundTransparency = 1 end
        if bottom then bottom.BackgroundTransparency = 1 end
    end)
end

local function clearOfflineCutsceneAttrs()
    pcall(function()
        LP:SetAttribute("OfflineCutscenePlaying", false)
        LP:SetAttribute("CutsceneInputBlocked", false)
    end)
end

local function beginOfflineGrowthBusy()
    G.__GAG2_OFFLINE_GROWTH_BUSY = true
    _G.__GAG2_OFFLINE_GROWTH_BUSY = true
    pcall(function()
        LP:SetAttribute("OfflineCutscenePlaying", true)
        LP:SetAttribute("CutsceneInputBlocked", true)
    end)
    hideOfflineAnimationUi()
end

local function endOfflineGrowthBusy()
    G.__GAG2_OFFLINE_GROWTH_BUSY = false
    _G.__GAG2_OFFLINE_GROWTH_BUSY = false
    clearOfflineCutsceneAttrs()
    hideOfflineAnimationUi()
end

local function hookOfflineGrowthCutscene()
    if offlineGrowthHooked or not LP then return end

    local ps = LP:FindFirstChild("PlayerScripts")
    local controllers = ps and ps:FindFirstChild("Controllers")
    local modScript = controllers and controllers:FindFirstChild("OfflineGrowthAnimationController")
    if not modScript then return end

    local ok, anim = pcall(require, modScript)
    if not ok or type(anim) ~= "table" or anim._gag2SkipHooked then
        if ok and type(anim) == "table" then
            offlineGrowthHooked = true
        end
        return
    end

    anim._gag2SkipHooked = true
    offlineGrowthHooked = true

    anim.PlayOfflineCutscene = function(self, opts)
        beginOfflineGrowthBusy()
        local okRun, result = pcall(function()
            opts = opts or {}
            local uid = opts.targetUserId or LP.UserId

            local changes = self:BuildGrowthChanges(opts.oldPlants, opts.newPlants)
            if #changes == 0 then
                return true
            end

            local ready = self:WaitForGrowthVisualsReady(
                uid,
                changes,
                opts.getSpawnedPlant,
                opts.getPlantGrowthData,
                opts.getSpawnedFruit,
                opts.getFruitGrowthData
            )
            if not ready then
                return false
            end

            self:AttachModelsToGrowthChanges(uid, changes, opts.getSpawnedPlant, opts.getSpawnedFruit)
            self:ApplyFinalGrowthState(
                uid,
                changes,
                opts.getSpawnedPlant,
                opts.getPlantGrowthData,
                opts.isSingleHarvestPlant,
                opts.addPlantHarvestPrompt,
                opts.getSpawnedFruit,
                opts.getFruitGrowthData,
                opts.addFruitHarvestPrompt
            )

            return true
        end)

        endOfflineGrowthBusy()
        if not okRun then
            return false
        end
        return result == true
    end

    dprint("offline growth cutscene skip hooked")
end

local function startOfflineGrowthSkipLoop()
    if M._offlineGrowthSkipLoop then return end
    M._offlineGrowthSkipLoop = true

    task.spawn(function()
        for _ = 1, 120 do
            hookOfflineGrowthCutscene()
            if offlineGrowthHooked then break end
            task.wait(0.25)
        end
    end)
end

local function bootstrapLoadingAssist()
    blockGameRequestHop()
    startHideLoadingSkipLoop()
    startTeleportPromptLoop()
    startOfflineGrowthSkipLoop()
end

function M.SetEnabled(_on)
    bootstrapLoadingAssist()
end

function M.SyncFromGlobals()
    bootstrapLoadingAssist()
    return { enabled = hideLoadingGloballyEnabled() }
end

function M.GetStatus()
    return {
        version = M.VERSION,
        running = M.running == true,
        pulseCount = M._pulseCount or 0,
        lastPulseAt = M._lastPulseAt or 0,
        hopBlocked = isHopBlocked(),
        pulseInterval = GAME_ACTIVITY_SEC,
    }
end

function M.Start()
    if not LP then return end
    bootstrapLoadingAssist()
    blockGameRequestHop()
    M.SyncFromGlobals()

    if M.running and M._startedVer == M.VERSION then
        return
    end
    if M.running then
        M.Stop()
    end
    M._startedVer = M.VERSION
    M.running = true

    if M.connection then
        M.connection:Disconnect()
        M.connection = nil
    end

    M.connection = LP.Idled:Connect(function()
        if not M.running then return end
        nudge()
        gameActivityPulse()
    end)

    M.thread = task.spawn(function()
        local nextNudge = 0
        local nextGame = 0
        while M.running do
            local now = os.clock()
            if now >= nextGame then
                gameActivityPulse()
                nextGame = now + GAME_ACTIVITY_SEC
            end
            if now >= nextNudge then
                nudge()
                nextNudge = now + 600 + math.random(0, 20)
            end
            task.wait(1)
        end
    end)
end

M.start = M.Start

function M.Stop()
    if not M.running then return end
    M.running = false
    if M.connection then
        M.connection:Disconnect()
        M.connection = nil
    end
end

M.stop = M.Stop

function M.IsRunning()
    return M.running == true
end

function M.SetDebug(v)
    M.DEBUG = (v == true)
end

function M.SetHideLoadingEnabled(on)
    G.HIDE_LOADING_ENABLED = (on == true)
    _G.HIDE_LOADING_ENABLED = G.HIDE_LOADING_ENABLED
    bootstrapLoadingAssist()
end

function M.IsHideLoadingEnabled()
    return hideLoadingGloballyEnabled()
end

M.SetHideLoading = M.SetEnabled
M.ForceHideLoading = function() bootstrapLoadingAssist() end
M.ApplyVisualUpkeep = function() removeLoadingBlur(false) end
M.ApplyLoadingSeeThrough = function() removeLoadingBlur(true) end
M.RemoveLoadingBlur = removeLoadingBlur
M.AutoSkipLoading = fireSkipLoading
M.HideLoadingVisual = hideLoadingVisual
M.RestoreAfterLoading = restoreAfterLoading
M.GetPromptText = getPromptText
M.SoftenPromptOverlay = softenPromptOverlay
M.HidePromptSafe = hidePromptSafe

G.AntiAFK = M
G.antiafk = M
_G.AntiAFK = M
_G.antiafk = M

if not M.__gag2HooksWired and LP then
    M.__gag2HooksWired = true

    pcall(function()
        Lighting.ChildAdded:Connect(function(child)
            if child.Name == "Blur" and not isLoadingActive() then
                blurGuardWired = false
                ensureBlurGuard()
            end
        end)
    end)
end

if LP then
    bootstrapLoadingAssist()
end

return exportFactory(M)

 end,                        required = false, early = true },
    { key = "WeatherPredict",          name = "Weather Predict",         factory = function() -- WeatherPredict.lua — Grow A Garden 2
-- Live cycle + moon/map weather prediction overlay

local Players           = game:GetService("Players")
local ReplicatedStorage = game:GetService("ReplicatedStorage")

local LP = Players.LocalPlayer
local G  = (getgenv and getgenv()) or _G
local M  = {}

local COLOR_BG     = Color3.fromRGB(8, 8, 12)
local COLOR_PANEL  = Color3.fromRGB(14, 14, 20)
local COLOR_YELLOW = Color3.fromRGB(255, 211, 0)
local COLOR_LIVE   = Color3.fromRGB(120, 255, 175)
local COLOR_MUTED  = Color3.fromRGB(175, 178, 190)
local MOON_PALETTE = {
    Color3.fromRGB(255, 140, 220),
    Color3.fromRGB(255, 210, 90),
    Color3.fromRGB(255, 95, 95),
    Color3.fromRGB(180, 200, 255),
    Color3.fromRGB(140, 255, 200),
}

local running      = false
local overlayGui   = nil
local overlayGen   = 0
local initDone     = false

local cycle            = { phases = {}, cycleSec = 600, nightIdx = 3, dayIdx = 1, nightPhase = nil }
local weatherRows      = {}
local cycleWeatherRows = {}
local skipPhaseWeathers = {}
local mapWeatherSeedMult = 1000

local function _enabled()
    local MAIN = G.MAIN or rawget(_G, "MAIN")
    if type(MAIN) == "table" and type(MAIN.misc) == "table"
        and type(MAIN.misc.weather_predict) == "table"
        and MAIN.misc.weather_predict.enabled == true then
        return true
    end
    return G.WEATHER_PREDICT_ENABLED == true or rawget(_G, "WEATHER_PREDICT_ENABLED") == true
end

local function _writeEnabled(on)
    on = (on == true)
    G.WEATHER_PREDICT_ENABLED = on
    _G.WEATHER_PREDICT_ENABLED = on

    local MAIN = G.MAIN or rawget(_G, "MAIN")
    if type(MAIN) == "table" then
        MAIN.misc = MAIN.misc or {}
        MAIN.misc.weather_predict = MAIN.misc.weather_predict or {}
        MAIN.misc.weather_predict.enabled = on
        G.MAIN = MAIN
        _G.MAIN = MAIN
    end

    local STATE = G.STATE or rawget(_G, "STATE")
    if type(STATE) == "table" then
        STATE.weather_predict = STATE.weather_predict or {}
        STATE.weather_predict.enabled = on
    end
    return on
end

local function fmtSec(sec)
    sec = math.max(0, math.floor(tonumber(sec) or 0))
    local h = math.floor(sec / 3600)
    local m = math.floor((sec % 3600) / 60)
    local s = sec % 60
    if h > 0 then return string.format("%dh%02dm", h, m) end
    if m > 0 then return string.format("%dm%02ds", m, s) end
    return string.format("%ds", s)
end

local function fmtClock(unixTs)
    unixTs = math.floor(tonumber(unixTs) or 0)
    if unixTs <= 0 then return "?" end
    return os.date("%H:%M", unixTs)
end

-- Semua timing ikut server game (bukan os.time() lokal — bisa selisih ~10 menit)
local function now()
    return workspace:GetServerTimeNow()
end

local function serverNow()
    return now()
end

local function activePhase()
    return workspace:GetAttribute("ActivePhase")
end

local function activeWeather()
    return workspace:GetAttribute("ActiveWeather")
end

local function loadModule(name)
    local SM = ReplicatedStorage:FindFirstChild("SharedModules")
    if not SM then return nil end
    local ok, mod = pcall(function() return require(SM:WaitForChild(name, 5)) end)
    if not ok then return nil end
    return mod
end

local function weatherOccurrence(entry)
    if type(entry) ~= "table" then return nil end
    local occ = entry.Occurrence or entry.Occurance or entry.Chance or entry.Weight
    if type(occ) == "number" and occ > 0 then return occ end
    return nil
end

local function phaseWeatherChance(w)
    if type(w) == "number" and w > 0 then return w end
    if type(w) == "table" then
        local c = w.Chance or w.Weight or w.Occurrence or w.Occurance
        if type(c) == "number" and c > 0 then return c end
    end
    return nil
end

local function buildSkipPhaseWeathers(built)
    local skip = {}
    if not built or not built.phases then return skip end
    for _, p in ipairs(built.phases) do
        if type(p.name) == "string" then
            skip[p.name] = true
        end
        for wName in pairs(p.weathers or {}) do
            if type(wName) == "string" and wName == p.name then
                skip[wName] = true
            end
        end
    end
    return skip
end

local function isSelectableWeather(name)
    return type(name) == "string" and name ~= "" and not skipPhaseWeathers[name]
end

local function getNightMoonNames()
    local names = {}
    local night = cycle.nightPhase
    if not night then return names end
    for wName in pairs(night.weathers or {}) do
        if isSelectableWeather(wName) then
            names[#names + 1] = wName
        end
    end
    table.sort(names)
    return names
end

local function moonLineColor(moonName)
    local moons = getNightMoonNames()
    for i, name in ipairs(moons) do
        if name == moonName then
            return MOON_PALETTE[(i - 1) % #MOON_PALETTE + 1]
        end
    end
    return COLOR_MUTED
end

local function buildPhases(tcd)
    if not tcd or type(tcd.Data) ~= "table" then return nil end
    local phases = {}
    for phaseName, entry in pairs(tcd.Data) do
        if type(entry) == "table" then
            phases[#phases + 1] = {
                name = phaseName,
                duration = entry.Lasts or 0,
                order = entry.StartOrder or 99,
                weathers = entry.Weathers or {},
            }
        end
    end
    table.sort(phases, function(a, b) return a.order < b.order end)
    local cycleSec, offset = 0, 0
    for _, p in ipairs(phases) do
        p.offset = offset
        cycleSec = cycleSec + p.duration
        offset = offset + p.duration
    end
    local nightIdx, nightPhase, dayIdx = nil, nil, nil
    for i, p in ipairs(phases) do
        if p.name == "Night" then nightIdx, nightPhase = i, p end
        if p.name == "Day" or p.name == "Morning" then dayIdx = i end
    end
    if not dayIdx then dayIdx = 1 end
    return { phases = phases, cycleSec = cycleSec, nightIdx = nightIdx, dayIdx = dayIdx, nightPhase = nightPhase }
end

local function rollPhaseWeather(phase, rng)
    if not phase or not phase.weathers then return nil end
    local entries = {}
    for wName, w in pairs(phase.weathers) do
        local chance = phaseWeatherChance(w)
        if type(wName) == "string" and chance then
            entries[#entries + 1] = { name = wName, chance = chance }
        end
    end
    if #entries == 0 then return nil end
    table.sort(entries, function(a, b) return a.name < b.name end)
    local total = 0
    for _, e in ipairs(entries) do total = total + e.chance end
    if total <= 0 then return nil end
    local roll = rng:NextNumber() * total
    local acc = 0
    for _, e in ipairs(entries) do
        acc = acc + e.chance
        if roll <= acc then return e.name end
    end
    return entries[1].name
end

local function getPhaseByName(name)
    for i, p in ipairs(cycle.phases) do
        if p.name == name then return p, i end
    end
    return nil, nil
end

local function getCycleState()
    local phaseName = activePhase()
    local phaseEnd = workspace:GetAttribute("PhaseDuration")
    if not phaseName or type(phaseEnd) ~= "number" then return nil end

    local remaining = math.max(0, phaseEnd - serverNow())
    local phase, phaseIdx = getPhaseByName(phaseName)
    if not phase then return nil end

    return {
        phaseIndex = phaseIdx,
        phaseName = phaseName,
        phase = phase,
        weather = activeWeather(),
        remaining = remaining,
        elapsed = math.max(0, phase.duration - remaining),
        phaseEnd = phaseEnd,
    }
end

local function cycleIndex()
    local st = getCycleState()
    if not st or not cycle.phases or #cycle.phases == 0 then
        return math.floor(serverNow() / math.max(cycle.cycleSec, 1))
    end

    local elapsed = 0
    for i, p in ipairs(cycle.phases) do
        if i < st.phaseIndex then
            elapsed = elapsed + p.duration
        elseif i == st.phaseIndex then
            elapsed = elapsed + math.max(0, p.duration - st.remaining)
            break
        end
    end

    local cycleStart = serverNow() - elapsed
    return math.floor(cycleStart / math.max(cycle.cycleSec, 1))
end

local function predictPhaseWeather(cycleIdx, phaseIdx)
    local phase = cycle.phases[phaseIdx]
    if not phase then return nil end
    return rollPhaseWeather(phase, Random.new(cycleIdx * 1000 + phaseIdx))
end

local function weatherKey(name)
    if type(name) ~= "string" then return "" end
    return string.lower((name:gsub("[%s_%-]", "")))
end

local function weatherMatches(mapName, rolledName)
    if type(mapName) ~= "string" or type(rolledName) ~= "string" then return false end
    local mk = weatherKey(mapName)
    local rk = weatherKey(rolledName)
    if mk == "" or rk == "" then return false end
    return mk == rk
end

local function rollWeatherDataEvent(rng)
    if not rng or #weatherRows == 0 then return nil end
    local entries = {}
    for _, entry in ipairs(weatherRows) do
        if type(entry.Name) == "string" then
            local occ = entry.Occurrence or entry.Occurance or entry.Chance or entry.Weight
            if type(occ) ~= "number" or occ <= 0 then
                occ = 1
            end
            entries[#entries + 1] = { name = entry.Name, chance = occ }
        end
    end
    if #entries == 0 then return nil end
    table.sort(entries, function(a, b) return a.name < b.name end)
    local total = 0
    for _, e in ipairs(entries) do total = total + e.chance end
    if total <= 0 then return nil end
    local roll = rng:NextNumber() * total
    local acc = 0
    for _, e in ipairs(entries) do
        acc = acc + e.chance
        if roll <= acc then return e.name end
    end
    return entries[1].name
end

local function predictMapWeather(cycleIdx)
    local dayIdx = cycle.dayIdx or 1
    local rng = Random.new(cycleIdx * mapWeatherSeedMult + dayIdx)
    local fromData = rollWeatherDataEvent(rng)
    if fromData then return fromData end
    local dayPhase = cycle.phases[dayIdx]
    if dayPhase then
        return rollPhaseWeather(dayPhase, rng)
    end
    return nil
end

local function calibrateMapSeed()
    local st = getCycleState()
    if not st then return end
    local live = activeWeather()
    if type(live) ~= "string" or live == "" or not isSelectableWeather(live) then return end
    if cycle.nightIdx and st.phaseIndex == cycle.nightIdx then return end

    local ci = cycleIndex()
    local dayIdx = cycle.dayIdx or 1
    local dayPhase = cycle.phases[dayIdx]
    for _, mult in ipairs({ 1000, 10000, 1, 9973, 1337, 7777 }) do
        local rng = Random.new(ci * mult + dayIdx)
        local pred = rollWeatherDataEvent(rng)
        if pred and weatherMatches(pred, live) then
            mapWeatherSeedMult = mult
            return
        end
        if dayPhase then
            local phasePred = rollPhaseWeather(dayPhase, rng)
            if phasePred == live or weatherMatches(phasePred, live) then
                mapWeatherSeedMult = mult
                return
            end
        end
    end
end

local function predictDayWeather(cycleIdx)
    local dayIdx = cycle.dayIdx or 1
    local fromData = predictMapWeather(cycleIdx)
    if fromData and isSelectableWeather(fromData) then return fromData end
    local fromPhase = predictPhaseWeather(cycleIdx, dayIdx)
    if fromPhase and isSelectableWeather(fromPhase) then return fromPhase end
    return fromData or fromPhase
end

local function predictNightWeather(cycleIdx)
    if not cycle.nightIdx then return nil end
    return predictPhaseWeather(cycleIdx, cycle.nightIdx)
end

local function cycleStartTime(cycleIdx)
    local st = getCycleState()
    if not st then return nil end
    local ci = cycleIndex()
    local elapsed = 0
    for i, p in ipairs(cycle.phases) do
        if i < st.phaseIndex then
            elapsed = elapsed + p.duration
        elseif i == st.phaseIndex then
            elapsed = elapsed + math.max(0, p.duration - st.remaining)
            break
        end
    end
    return serverNow() - elapsed + (cycleIdx - ci) * cycle.cycleSec
end

local function phaseStartTime(cycleIdx, phaseIdx)
    local cs = cycleStartTime(cycleIdx)
    if not cs or not cycle.phases[phaseIdx] then return nil end
    return cs + (cycle.phases[phaseIdx].offset or 0)
end

local function secondsUntilPhase(cycleIdx, phaseIdx)
    local startT = phaseStartTime(cycleIdx, phaseIdx)
    if not startT then return 0 end
    return math.max(0, startT - serverNow())
end

local function upcomingPhaseWeathers(maxCount)
    maxCount = maxCount or 10
    local out = {}
    local st = getCycleState()
    if not st or #cycle.phases == 0 then return out end

    local now = serverNow()
    local ci = cycleIndex()
    local pi = st.phaseIndex
    local cyc = ci
    local limit = maxCount + #cycle.phases * 2

    for _ = 1, limit do
        pi = pi + 1
        if pi > #cycle.phases then
            pi = 1
            cyc = cyc + 1
        end
        local wName
        if pi == cycle.dayIdx then
            wName = predictDayWeather(cyc)
        elseif pi == cycle.nightIdx then
            wName = predictPhaseWeather(cyc, pi)
        end
        if wName and isSelectableWeather(wName) then
            local inSec = secondsUntilPhase(cyc, pi)
            out[#out + 1] = {
                name = wName,
                phaseName = cycle.phases[pi].name,
                cycleIdx = cyc,
                phaseIdx = pi,
                inSec = inSec,
                at = now + inSec,
            }
            if #out >= maxCount then break end
        end
    end
    return out
end

local function phaseRemaining()
    local st = getCycleState()
    return st and st.remaining or nil
end

local function dur(name, fallback)
    local p = getPhaseByName(name)
    return p and p.duration or fallback
end

local function secondsUntilNightCycle(offset)
    offset = offset or 0
    local st = getCycleState()
    if not st then return 0 end

    local rem = st.remaining
    local cur = st.phaseName
    local nightIdx = cycle.nightIdx

    if offset == 0 then
        if cur == "Night" then return 0 end
        if cur == "Sunset" then return rem end
        if cur == "Day" then return rem + dur("Sunset", 30) end
        return rem
    end

    local toCycleEnd = rem
    for i = st.phaseIndex + 1, #cycle.phases do
        toCycleEnd = toCycleEnd + cycle.phases[i].duration
    end

    local beforeNight = 0
    if nightIdx and nightIdx > 1 then
        for i = 1, nightIdx - 1 do
            beforeNight = beforeNight + (cycle.phases[i].duration or 0)
        end
    else
        beforeNight = dur("Day", 450) + dur("Sunset", 30)
    end

    return toCycleEnd + (offset - 1) * cycle.cycleSec + beforeNight
end

local function findNextMoon(moonName, maxCycles)
    maxCycles = maxCycles or 60
    local now = serverNow()
    local ci = cycleIndex()
    local cur = activePhase()
    local weather = activeWeather()

    for offset = 0, maxCycles do
        local predicted = predictNightWeather(ci + offset)
        if not weatherMatches(moonName, predicted or "") then
            -- skip cycle
        elseif offset == 0 and cur == "Night" then
            if weatherMatches(moonName, weather or "") then
                return { inSec = 0, cycleIdx = ci, live = true }
            end
        else
            local sec = secondsUntilNightCycle(offset)
            return { inSec = sec, cycleIdx = ci + offset, at = now + sec }
        end
    end
    return nil
end

local function readMapWeather(name)
    local WeatherValues = ReplicatedStorage:FindFirstChild("WeatherValues")
    if not WeatherValues then
        return { playing = false, endsIn = nil, endsAt = nil }
    end
    local playing = WeatherValues:GetAttribute(name .. "_Playing")
    local endTime = WeatherValues:GetAttribute(name .. "_EndTime")
    local startTime = WeatherValues:GetAttribute(name .. "_StartTime")
    local duration = WeatherValues:GetAttribute(name .. "_Duration")
    local now = serverNow()

    local endsIn = nil
    if playing == true then
        if type(startTime) == "number" and startTime > 1e9
            and type(duration) == "number" and duration > 0 then
            endsIn = math.max(0, (startTime + duration) - now)
        elseif type(endTime) == "number" and endTime > 1e9 then
            endsIn = math.max(0, endTime - now)
        elseif type(endTime) == "number" and endTime > 0 and endTime < 1e6 then
            endsIn = math.max(0, endTime)
        end
    end

    return {
        playing = playing == true,
        endsIn = endsIn,
        endsAt = (endsIn ~= nil) and fmtClock(now + endsIn) or nil,
    }
end

local function findNextMapWeather(mapName, maxCycles)
    maxCycles = maxCycles or 120
    local st = getCycleState()
    if not st or not cycle.dayIdx then return nil end

    local now = serverNow()
    local ci = cycleIndex()
    local dayIdx = cycle.dayIdx
    local row = readMapWeather(mapName)
    if row.playing then
        return { inSec = 0, live = true, at = now, name = mapName }
    end

    local live = activeWeather()
    if weatherMatches(mapName, live) then
        return { inSec = 0, live = true, at = now, name = live }
    end

    for offset = 0, maxCycles do
        local cyc = ci + offset
        local rolled = predictDayWeather(cyc)
        if rolled and weatherMatches(mapName, rolled) then
            local inSec = secondsUntilPhase(cyc, dayIdx)
            if offset == 0 and st.phaseIndex > dayIdx then
                -- Day phase sudah lewat di cycle ini, coba cycle berikutnya
            elseif inSec <= 0 and offset == 0 and st.phaseIndex == dayIdx then
                if weatherMatches(mapName, live) then
                    return { inSec = 0, live = true, at = now, name = rolled, cycleIdx = cyc }
                end
            else
                return {
                    inSec = inSec,
                    live = false,
                    at = now + inSec,
                    name = rolled,
                    cycleIdx = cyc,
                    phaseIdx = dayIdx,
                }
            end
        end
    end
    return nil
end

local function loadWeatherEventRows(wd)
    local rows = {}
    if not wd or type(wd.Data) ~= "table" then return rows end

    if wd.Data[1] then
        for _, entry in ipairs(wd.Data) do
            if type(entry) == "table" then rows[#rows + 1] = entry end
        end
    else
        for name, entry in pairs(wd.Data) do
            if type(entry) == "table" then
                if type(entry.Name) ~= "string" then entry.Name = name end
                rows[#rows + 1] = entry
            elseif type(name) == "string" then
                rows[#rows + 1] = { Name = name, Occurrence = entry }
            end
        end
        table.sort(rows, function(a, b) return tostring(a.Name) < tostring(b.Name) end)
    end
    return rows
end

local function loadWeatherRowsFromValues()
    local WeatherValues = ReplicatedStorage:FindFirstChild("WeatherValues")
    if not WeatherValues then return {} end
    local rows, seen = {}, {}
    for attrName in pairs(WeatherValues:GetAttributes()) do
        if type(attrName) == "string" then
            local base = attrName:match("^(.+)_Playing$")
            if base and not seen[base] then
                seen[base] = true
                rows[#rows + 1] = { Name = base, Occurrence = 1 }
            end
        end
    end
    table.sort(rows, function(a, b) return a.Name < b.Name end)
    return rows
end

local function buildCycleWeatherRows()
    local rows, seen = {}, {}
    for _, phase in ipairs(cycle.phases) do
        for wName, w in pairs(phase.weathers or {}) do
            if isSelectableWeather(wName) and not seen[wName] then
                seen[wName] = true
                rows[#rows + 1] = {
                    Name = wName,
                    Occurrence = phaseWeatherChance(w) or 1,
                    Phase = phase.name,
                    Source = "TimeCycleData",
                }
            end
        end
    end
    table.sort(rows, function(a, b) return a.Name < b.Name end)
    return rows
end

local function ensureInit()
    if initDone then return true end

    local built = buildPhases(loadModule("TimeCycleData"))
    if built then cycle = built end
    skipPhaseWeathers = buildSkipPhaseWeathers(cycle)

    weatherRows = loadWeatherEventRows(loadModule("WeatherData"))
    for _, row in ipairs(weatherRows) do
        row.Source = "WeatherData"
    end

    cycleWeatherRows = buildCycleWeatherRows()

    if #weatherRows == 0 then
        weatherRows = loadWeatherRowsFromValues()
        for _, row in ipairs(weatherRows) do
            row.Source = "WeatherValues"
        end
    end

    calibrateMapSeed()
    initDone = true
    return true
end

function M.GetLines()
    ensureInit()
    calibrateMapSeed()
    local lines = {}
    local st = getCycleState()
    local rem = st and st.remaining or phaseRemaining()
    local cur = activePhase()
    local weather = activeWeather()
    local ci = cycleIndex()

    if cur then
        local predicted = st and predictPhaseWeather(ci, st.phaseIndex) or nil
        local sub = fmtSec(rem or 0) .. " left"
        if predicted and predicted ~= weather then
            sub = sub .. " · pred ~" .. tostring(predicted)
        end
        lines[#lines + 1] = {
            text = string.format("%s · %s", cur, weather or predicted or "?"),
            sub = sub,
            live = true,
            kind = "cycle",
        }
    else
        lines[#lines + 1] = {
            text = "Waiting ActivePhase...",
            sub = "join server cycle",
            live = false,
            kind = "info",
        }
    end

    local upcoming = upcomingPhaseWeathers(10)
    if #upcoming > 0 then
        lines[#lines + 1] = { text = "Upcoming Weather", sub = "", live = false, kind = "divider" }
        for _, hit in ipairs(upcoming) do
            local liveNow = hit.inSec <= 0
            lines[#lines + 1] = {
                text = hit.name,
                sub = liveNow and "LIVE NOW"
                    or string.format("%s · %s · %s", hit.phaseName or "?", fmtSec(hit.inSec), fmtClock(hit.at)),
                live = liveNow,
                kind = "weather",
            }
        end
    end

    local nextOff = (cur == "Night") and 1 or 0
    local nightIn = secondsUntilNightCycle(nextOff)
    local nextMoon = predictNightWeather(ci + nextOff)
    lines[#lines + 1] = {
        text = "Next Night",
        sub = string.format("%s → %s", fmtSec(nightIn), nextMoon or "?"),
        live = false,
        kind = "night",
    }

    for _, moon in ipairs(getNightMoonNames()) do
        local hit = findNextMoon(moon, 60)
        if hit then
            if hit.live then
                lines[#lines + 1] = {
                    text = moon,
                    sub = "LIVE NOW",
                    live = true,
                    kind = "moon",
                    moon = moon,
                }
            else
                lines[#lines + 1] = {
                    text = moon,
                    sub = string.format("%s · ~%s", fmtSec(hit.inSec), fmtClock(hit.at)),
                    live = false,
                    kind = "moon",
                    moon = moon,
                }
            end
        end
    end

    lines[#lines + 1] = {
        text = string.format("Cycle %s · idx %d", fmtSec(cycle.cycleSec), ci),
        sub = "Tonight ~" .. tostring(predictNightWeather(ci) or "?"),
        live = false,
        kind = "meta",
    }

    lines[#lines + 1] = { text = "Map Weather", sub = "", live = false, kind = "divider" }

    for _, entry in ipairs(weatherRows) do
        local n = entry.Name
        if type(n) == "string" then
            local row = readMapWeather(n)
            if row.playing then
                lines[#lines + 1] = {
                    text = n,
                    sub = string.format("LIVE %s · %s", row.endsAt or "?", fmtSec(row.endsIn)),
                    live = true,
                    kind = "map",
                }
            else
                local hit = findNextMapWeather(n, 120)
                local sub
                if hit then
                    if hit.live then
                        sub = "LIVE NOW"
                    else
                        sub = string.format("~%s · %s", fmtSec(hit.inSec), fmtClock(hit.at))
                    end
                elseif weatherOccurrence(entry) then
                    sub = "Occ " .. weatherOccurrence(entry)
                else
                    sub = "idle"
                end
                lines[#lines + 1] = {
                    text = n,
                    sub = sub,
                    live = hit and hit.live == true or false,
                    kind = "map",
                }
            end
        end
    end

    return lines
end

function M.GetWeatherNames()
    ensureInit()
    local names, seen = {}, {}

    local function addName(n)
        if isSelectableWeather(n) and not seen[n] then
            seen[n] = true
            names[#names + 1] = n
        end
    end

    for _, entry in ipairs(weatherRows) do
        addName(entry.Name)
    end

    for _, entry in ipairs(cycleWeatherRows) do
        addName(entry.Name)
    end

    for _, entry in ipairs(loadWeatherRowsFromValues()) do
        addName(entry.Name)
    end

    table.sort(names)
    return names
end

function M.GetWeatherRows()
    ensureInit()
    local out, seen = {}, {}
    local function push(entry)
        local n = entry.Name
        if not isSelectableWeather(n) or seen[n] then return end
        seen[n] = true
        out[#out + 1] = entry
    end
    for _, entry in ipairs(weatherRows) do push(entry) end
    for _, entry in ipairs(cycleWeatherRows) do push(entry) end
    for _, entry in ipairs(loadWeatherRowsFromValues()) do
        entry.Source = entry.Source or "WeatherValues"
        push(entry)
    end
    table.sort(out, function(a, b) return tostring(a.Name) < tostring(b.Name) end)
    return out
end

function M.GetWeatherOptions()
    local names = M.GetWeatherNames()
    local items = {}
    for _, name in ipairs(names) do
        items[#items + 1] = { key = name, name = name }
    end
    return items
end

function M.GetPhaseNames()
    ensureInit()
    local names = {}
    for _, phase in ipairs(cycle.phases) do
        if type(phase.name) == "string" and phase.name ~= "" then
            names[#names + 1] = phase.name
        end
    end
    table.sort(names)
    return names
end

function M.PhaseMatches(phaseName, livePhase)
    if type(phaseName) ~= "string" or type(livePhase) ~= "string" then return false end
    return weatherKey(phaseName) == weatherKey(livePhase)
end

M.phaseMatches = M.PhaseMatches

local KICK_PREFIX_PHASE   = "P:"
local KICK_PREFIX_WEATHER = "W:"

local function weatherDataDuration(name)
    name = tostring(name or "")
    if name == "" then return nil end
    ensureInit()
    local key = weatherKey(name)
    for _, entry in ipairs(weatherRows or {}) do
        if type(entry) == "table" and weatherKey(entry.Name) == key then
            local d = tonumber(entry.Lasts or entry.Last or entry.Duration or entry.Length)
            if d and d > 0 then return d end
        end
    end
    return nil
end

function M.GetWeatherDuration(name)
    return weatherDataDuration(name)
end

function M.GetKickTargetOptions()
    local items = {}

    for _, opt in ipairs(M.GetWeatherOptions()) do
        local wName = opt.key or opt.name
        if type(wName) == "string" and wName ~= "" then
            local dur = weatherDataDuration(wName)
            local label = opt.name or wName
            if dur then
                local m = math.floor(dur / 60)
                local s = math.floor(dur % 60)
                if m > 0 then
                    label = string.format("%s (%dm%02ds)", label, m, s)
                else
                    label = string.format("%s (%ds)", label, s)
                end
            end
            items[#items + 1] = {
                key = KICK_PREFIX_WEATHER .. wName,
                name = label,
                kind = "weather",
                weather = wName,
                duration = dur,
            }
        end
    end

    return items
end

function M.WeatherMatches(mapName, rolledName)
    return weatherMatches(mapName, rolledName)
end

M.weatherMatches = M.WeatherMatches

function M.IsWeatherLive(name)
    ensureInit()
    name = tostring(name or "")
    if name == "" then return false, nil end

    local live = activeWeather()
    if weatherMatches(name, live or "") then
        return true, live
    end

    if readMapWeather(name).playing then
        return true, name
    end

    local st = getCycleState()
    if st then
        local ci = cycleIndex()
        if cycle.nightIdx and st.phaseIndex == cycle.nightIdx then
            local predicted = predictNightWeather(ci)
            if weatherMatches(name, predicted or "") then
                return true, predicted
            end
        end
        if cycle.dayIdx and st.phaseIndex == cycle.dayIdx then
            local predicted = predictDayWeather(ci)
            if weatherMatches(name, predicted or "") then
                return true, predicted
            end
        end
    end

    return false, nil
end

function M.GetLiveMapWeathers()
    ensureInit()
    local out = {}
    for _, entry in ipairs(weatherRows) do
        local n = entry.Name
        if type(n) == "string" and readMapWeather(n).playing then
            out[#out + 1] = n
        end
    end
    table.sort(out)
    return out
end

function M.GetSnapshot()
    local st = getCycleState()
    return {
        running = running,
        phase = st and st.phaseName or activePhase(),
        weather = st and st.weather or activeWeather(),
        remaining = st and st.remaining or phaseRemaining(),
        lines = M.GetLines(),
    }
end

local function destroyOverlay()
    overlayGen += 1

    local pg = LP and LP:FindFirstChild("PlayerGui")
    if pg then
        local old = pg:FindFirstChild("GAG2_WX_PRED")
        if old then
            pcall(function() old:Destroy() end)
        end
    end

    if overlayGui then
        pcall(function() overlayGui:Destroy() end)
        overlayGui = nil
    end
end

local function lineColor(line)
    if line.live then return COLOR_LIVE end
    if line.kind == "moon" and line.moon then
        return moonLineColor(line.moon)
    end
    if line.kind == "divider" then return COLOR_YELLOW end
    return COLOR_MUTED
end

local function createOverlay()
    local myGen = overlayGen

    local pg = LP:FindFirstChild("PlayerGui") or LP:WaitForChild("PlayerGui", 5)
    if not pg then return false end

    local gui = Instance.new("ScreenGui")
    gui.Name = "GAG2_WX_PRED"
    gui.ResetOnSpawn = false
    gui.IgnoreGuiInset = true
    gui.Enabled = true
    gui.DisplayOrder = 10050
    gui.Parent = pg
    overlayGui = gui

    local frame = Instance.new("Frame")
    frame.Name = "Panel"
    frame.Size = UDim2.fromOffset(340, 200)
    frame.Position = UDim2.new(0, 14, 0.24, 0)
    frame.BackgroundColor3 = COLOR_BG
    frame.BackgroundTransparency = 0.08
    frame.BorderSizePixel = 0
    frame.Parent = gui
    Instance.new("UICorner", frame).CornerRadius = UDim.new(0, 10)

    local stroke = Instance.new("UIStroke")
    stroke.Color = COLOR_YELLOW
    stroke.Thickness = 1.2
    stroke.Transparency = 0.35
    stroke.Parent = frame

    local accent = Instance.new("Frame")
    accent.Size = UDim2.new(1, 0, 0, 3)
    accent.BackgroundColor3 = COLOR_YELLOW
    accent.BorderSizePixel = 0
    accent.Parent = frame
    Instance.new("UICorner", accent).CornerRadius = UDim.new(0, 10)

    local header = Instance.new("TextLabel")
    header.Size = UDim2.new(1, -16, 0, 22)
    header.Position = UDim2.fromOffset(10, 8)
    header.BackgroundTransparency = 1
    header.Font = Enum.Font.GothamBold
    header.TextSize = 13
    header.TextXAlignment = Enum.TextXAlignment.Left
    header.TextColor3 = COLOR_YELLOW
    header.Text = "WEATHER PREDICT"
    header.Parent = frame

    local badge = Instance.new("TextLabel")
    badge.Size = UDim2.fromOffset(52, 16)
    badge.Position = UDim2.new(1, -60, 0, 10)
    badge.BackgroundColor3 = Color3.fromRGB(25, 55, 35)
    badge.BackgroundTransparency = 0.2
    badge.Font = Enum.Font.GothamBold
    badge.TextSize = 9
    badge.Text = "LIVE"
    badge.TextColor3 = COLOR_LIVE
    badge.Parent = frame
    Instance.new("UICorner", badge).CornerRadius = UDim.new(0, 6)

    local list = Instance.new("ScrollingFrame")
    list.Name = "List"
    list.Size = UDim2.new(1, -12, 1, -38)
    list.Position = UDim2.fromOffset(6, 34)
    list.BackgroundTransparency = 1
    list.BorderSizePixel = 0
    list.ScrollBarThickness = 3
    list.ScrollBarImageColor3 = COLOR_YELLOW
    list.CanvasSize = UDim2.new()
    list.AutomaticCanvasSize = Enum.AutomaticSize.Y
    list.Parent = frame

    local layout = Instance.new("UIListLayout")
    layout.Padding = UDim.new(0, 4)
    layout.SortOrder = Enum.SortOrder.LayoutOrder
    layout.Parent = list

    local rows = {}

    local function render()
        if myGen ~= overlayGen or not overlayGui or overlayGui ~= gui or not gui.Parent then
            return
        end
        local lines = M.GetLines()
        local yPad = 0

        for i, line in ipairs(lines) do
            local row = rows[i]
            if not row then
                row = Instance.new("Frame")
                row.BackgroundColor3 = COLOR_PANEL
                row.BackgroundTransparency = line.kind == "divider" and 1 or 0.35
                row.BorderSizePixel = 0
                row.Size = UDim2.new(1, -4, 0, line.kind == "divider" and 18 or 34)
                row.Parent = list
                Instance.new("UICorner", row).CornerRadius = UDim.new(0, 6)

                local title = Instance.new("TextLabel")
                title.Name = "Title"
                title.BackgroundTransparency = 1
                title.Position = UDim2.fromOffset(8, 4)
                title.Size = UDim2.new(1, -12, 0, 14)
                title.Font = Enum.Font.GothamMedium
                title.TextSize = 11
                title.TextXAlignment = Enum.TextXAlignment.Left
                title.Parent = row

                local sub = Instance.new("TextLabel")
                sub.Name = "Sub"
                sub.BackgroundTransparency = 1
                sub.Position = UDim2.fromOffset(8, 18)
                sub.Size = UDim2.new(1, -12, 0, 12)
                sub.Font = Enum.Font.Gotham
                sub.TextSize = 10
                sub.TextXAlignment = Enum.TextXAlignment.Left
                sub.TextColor3 = COLOR_MUTED
                sub.Parent = row

                rows[i] = { frame = row, title = title, sub = sub }
            end

            local r = rows[i]
            if not r or not r.title or not r.title.Parent then
                -- overlay destroyed mid-render
            else
            r.frame.Visible = true
            r.frame.LayoutOrder = i
            r.frame.Size = UDim2.new(1, -4, 0, line.kind == "divider" and 18 or 34)

            local col = lineColor(line)
            r.title.Text = line.text or ""
            r.title.TextColor3 = col
            r.sub.Text = line.sub or ""
            r.sub.Visible = (line.sub or "") ~= ""
            if line.kind == "divider" then
                r.title.Text = "— " .. (line.text or "") .. " —"
                r.sub.Visible = false
            end
            yPad += r.frame.AbsoluteSize.Y + 4
            end
        end

        for i = #lines + 1, #rows do
            if rows[i] then rows[i].frame.Visible = false end
        end
    end

    render()

    task.spawn(function()
        while myGen == overlayGen and overlayGui == gui and gui.Parent do
            task.wait(1)
            if myGen ~= overlayGen or overlayGui ~= gui or not gui.Parent then
                break
            end
            render()
        end
    end)

    return true
end

function M.Start()
    ensureInit()
    running = true
    _G.GAG2_WEATHER_STOP = false
    destroyOverlay()

    local ok = createOverlay()
    if not ok or not overlayGui or not overlayGui.Parent then
        running = false
        return false
    end

    G.GAG2_WEATHER = {
        cycle = cycle,
        state = getCycleState,
        predictPhase = predictPhaseWeather,
        predictMap = predictMapWeather,
        predictDay = predictDayWeather,
        predictNight = predictNightWeather,
        upcoming = upcomingPhaseWeathers,
        nextMap = findNextMapWeather,
        nextMoon = findNextMoon,
        nextNightIn = function(offset) return secondsUntilNightCycle(offset or 0) end,
        readMap = readMapWeather,
        GetLines = M.GetLines,
        GetWeatherNames = M.GetWeatherNames,
        GetWeatherOptions = M.GetWeatherOptions,
        GetPhaseNames = M.GetPhaseNames,
        GetKickTargetOptions = M.GetKickTargetOptions,
        GetWeatherDuration = M.GetWeatherDuration,
        GetWeatherRows = M.GetWeatherRows,
        WeatherMatches = M.WeatherMatches,
        IsWeatherLive = M.IsWeatherLive,
        GetLiveMapWeathers = M.GetLiveMapWeathers,
        PhaseMatches = M.PhaseMatches,
    }
    _G.GAG2_WEATHER = G.GAG2_WEATHER
    return true
end

M.start = M.Start

function M.Stop()
    running = false
    _G.GAG2_WEATHER_STOP = true
    destroyOverlay()
end

M.stop = M.Stop

function M.IsRunning()
    return running == true
end

function M.SetEnabled(on)
    on = (on == true)
    _writeEnabled(on)
    if on then
        return M.Start()
    end
    M.Stop()
    return on
end

function M.EnsureRunning()
    if _enabled() then
        M.Start()
    else
        M.Stop()
    end
end

M.ensureRunning = M.EnsureRunning

function M.SyncFromGlobals()
    M.EnsureRunning()
end

M.syncFromGlobals = M.SyncFromGlobals

G.__GAG2_SYNC_WEATHER_PREDICT = function()
    M.SyncFromGlobals()
end
_G.__GAG2_SYNC_WEATHER_PREDICT = G.__GAG2_SYNC_WEATHER_PREDICT

return M
 end,                required = false },
    { key = "HideHarvestPrompt",       name = "Hide Harvest Prompt",     factory = function() -- HideHarvestPrompt.lua — sembunyikan UI prompt Harvest
-- GaG pakai UI custom → Style=Custom TIDAK cukup; harus Enabled=false + rescan + property lock

local CollectionService = game:GetService("CollectionService")
local ProximityPromptService = game:GetService("ProximityPromptService")
local Workspace = game:GetService("Workspace")

local G = (getgenv and getgenv()) or _G
local M = {}

local HARVEST_TAG = "HarvestPrompt"
local ATTR_DIST = "_GAG2_HH_Dist"
local ATTR_EN = "_GAG2_HH_En"
local RESCAN_SEC = 1.25

local tagConn = nil
local shownConn = nil
local enabled = false
local loopToken = 0
local propConns = {} -- [prompt] = {conn, ...}

local function _hideWanted()
    return enabled == true
        or (G.HIDE_HARVEST_PROMPT_ENABLED == true)
        or (rawget(_G, "HIDE_HARVEST_PROMPT_ENABLED") == true)
end

local function _isHarvestPrompt(prompt)
    if not prompt or not prompt:IsA("ProximityPrompt") then return false end
    if CollectionService:HasTag(prompt, HARVEST_TAG) then return true end
    local n = tostring(prompt.Name or ""):lower()
    if n:find("harvest", 1, true) then return true end
    local action = tostring(prompt.ActionText or ""):lower()
    if action:find("harvest", 1, true) or action:find("collect", 1, true) then
        return true
    end
    local obj = tostring(prompt.ObjectText or ""):lower()
    if obj:find("harvest", 1, true) or obj:find("fruit", 1, true) then
        return true
    end
    return false
end

local function _unbindProps(prompt)
    local list = propConns[prompt]
    if not list then return end
    for _, c in ipairs(list) do
        pcall(function() c:Disconnect() end)
    end
    propConns[prompt] = nil
end

local function _bindProps(prompt)
    if propConns[prompt] then return end
    local list = {}
    local function rehide()
        if not _hideWanted() or not prompt.Parent then return end
        pcall(function()
            if prompt.Enabled then prompt.Enabled = false end
            if prompt.MaxActivationDistance > 0 then
                prompt.MaxActivationDistance = 0
            end
            if prompt.Style ~= Enum.ProximityPromptStyle.Custom then
                prompt.Style = Enum.ProximityPromptStyle.Custom
            end
        end)
    end
    local ok1, c1 = pcall(function()
        return prompt:GetPropertyChangedSignal("Enabled"):Connect(rehide)
    end)
    if ok1 and c1 then list[#list + 1] = c1 end
    local ok2, c2 = pcall(function()
        return prompt:GetPropertyChangedSignal("MaxActivationDistance"):Connect(rehide)
    end)
    if ok2 and c2 then list[#list + 1] = c2 end
    local ok3, c3 = pcall(function()
        return prompt:GetPropertyChangedSignal("Style"):Connect(rehide)
    end)
    if ok3 and c3 then list[#list + 1] = c3 end
    propConns[prompt] = list
end

local function applyPrompt(prompt, hide)
    if not _isHarvestPrompt(prompt) then return end

    pcall(function()
        if hide then
            if prompt:GetAttribute(ATTR_DIST) == nil then
                prompt:SetAttribute(ATTR_DIST, tonumber(prompt.MaxActivationDistance) or 10)
            end
            if prompt:GetAttribute(ATTR_EN) == nil then
                prompt:SetAttribute(ATTR_EN, prompt.Enabled == true)
            end
            -- Matikan UI: GaG custom prompt ikut hilang kalau Enabled=false
            if prompt.Enabled then prompt.Enabled = false end
            if prompt.MaxActivationDistance ~= 0 then
                prompt.MaxActivationDistance = 0
            end
            if prompt.Style ~= Enum.ProximityPromptStyle.Custom then
                prompt.Style = Enum.ProximityPromptStyle.Custom
            end
            _bindProps(prompt)
        else
            _unbindProps(prompt)
            local dist = tonumber(prompt:GetAttribute(ATTR_DIST))
            if dist and dist > 0 then
                prompt.MaxActivationDistance = dist
            elseif prompt.MaxActivationDistance < 8 then
                prompt.MaxActivationDistance = 12
            end
            local wasEn = prompt:GetAttribute(ATTR_EN)
            prompt.Enabled = (wasEn ~= false)
            pcall(function()
                prompt.Style = Enum.ProximityPromptStyle.Default
            end)
            prompt:SetAttribute(ATTR_DIST, nil)
            prompt:SetAttribute(ATTR_EN, nil)
        end
    end)
end

local function scanAll(hide)
    -- Hanya tagged — jangan Gardens:GetDescendants tiap loop (spike CPU)
    local tagged = CollectionService:GetTagged(HARVEST_TAG)
    for i = 1, #tagged do
        applyPrompt(tagged[i], hide)
    end
end

local function bindTag()
    if tagConn then return end
    tagConn = CollectionService:GetInstanceAddedSignal(HARVEST_TAG):Connect(function(inst)
        if _hideWanted() then
            applyPrompt(inst, true)
        end
    end)
end

local function bindPromptShown()
    if shownConn then return end
    shownConn = ProximityPromptService.PromptShown:Connect(function(prompt)
        if not _hideWanted() then return end
        if _isHarvestPrompt(prompt) then
            applyPrompt(prompt, true)
        end
    end)
end

local function unbindTag()
    if tagConn then
        tagConn:Disconnect()
        tagConn = nil
    end
end

local function unbindPromptShown()
    if shownConn then
        shownConn:Disconnect()
        shownConn = nil
    end
end

local function clearPropConns()
    for prompt in pairs(propConns) do
        _unbindProps(prompt)
    end
end

local function stopLoop()
    loopToken += 1
end

local function startLoop()
    stopLoop()
    local my = loopToken
    task.spawn(function()
        while enabled and my == loopToken do
            scanAll(true)
            task.wait(RESCAN_SEC)
        end
    end)
end

function M.SetEnabled(on)
    on = (on == true)
    if enabled == on then
        if on then
            bindTag()
            bindPromptShown()
            startLoop()
            scanAll(true)
        end
        return
    end
    enabled = on
    G.HIDE_HARVEST_PROMPT_ENABLED = on
    _G.HIDE_HARVEST_PROMPT_ENABLED = on
    if on then
        bindTag()
        bindPromptShown()
        scanAll(true)
        startLoop()
    else
        stopLoop()
        unbindTag()
        unbindPromptShown()
        clearPropConns()
        scanAll(false)
    end
end

function M.IsEnabled()
    return enabled
end

function M.SetInterval(sec)
    sec = tonumber(sec)
    if sec and sec >= 0.35 then
        RESCAN_SEC = sec
    end
end

function M.SyncFromGlobals()
    local MAIN = rawget(_G, "MAIN") or G.MAIN
    local cfg = MAIN and MAIN.misc and MAIN.misc.hide_harvest_prompt
    local on = (G.HIDE_HARVEST_PROMPT_ENABLED == true)
        or (rawget(_G, "HIDE_HARVEST_PROMPT_ENABLED") == true)
        or (type(cfg) == "table" and cfg.enabled == true)
    M.SetEnabled(on)
end

function M.Stop()
    M.SetEnabled(false)
end

G.HideHarvestPrompt = M
_G.HideHarvestPrompt = M

return M
