-- LockAt hanya dipanggil SW saat running

local Players = game:GetService("Players")
local RunService = game:GetService("RunService")

local LP = Players.LocalPlayer
local G = (getgenv and getgenv()) or _G
local M = {}

local noclipConn, lockConn, charAddedConn
local flyRestore = {}
local lockedPos = nil

local function getHRP()
    local c = LP.Character
    if not c then return nil end
    local h = c:FindFirstChild("HumanoidRootPart")
    return (h and h:IsA("BasePart")) and h or nil
end

local function getHum()
    local c = LP.Character
    return c and c:FindFirstChildOfClass("Humanoid") or nil
end

function M.SetNoclip(on)
    if noclipConn then
        noclipConn:Disconnect()
        noclipConn = nil
    end
    if on ~= true then return end
    noclipConn = RunService.Stepped:Connect(function()
        local char = LP.Character
        if not char then return end
        for _, inst in ipairs(char:GetDescendants()) do
            if inst:IsA("BasePart") and inst.CanCollide then
                inst.CanCollide = false
            end
        end
    end)
end

