    return noclipConn ~= nil
end

local function stopLockLoop()
    if lockConn then
        lockConn:Disconnect()
        lockConn = nil
    end
end

local function restoreHumanoid()
    local hum = getHum()
    local hrp = getHRP()
    if hum and flyRestore.platformStand ~= nil then
        pcall(function() hum.PlatformStand = flyRestore.platformStand end)
    elseif hum then
        pcall(function() hum.PlatformStand = false end)
    end
    if hum and flyRestore.autoRotate ~= nil then
        pcall(function() hum.AutoRotate = flyRestore.autoRotate end)
    elseif hum then
        pcall(function() hum.AutoRotate = true end)
    end
    if hrp then
        pcall(function()
            hrp.Anchored = false
            hrp.AssemblyLinearVelocity = Vector3.zero
            hrp.AssemblyAngularVelocity = Vector3.zero
        end)
    end
    flyRestore = {}
end

local function applySoftLock(hrp, hum, pos)
    if not hrp or typeof(pos) ~= "Vector3" then return end
    pcall(function()
        if hum then
            hum.PlatformStand = true
            hum.AutoRotate = false
            hum.Sit = false
        end
        hrp.Anchored = false
        hrp.CFrame = CFrame.new(pos)
        hrp.AssemblyLinearVelocity = Vector3.zero
        hrp.AssemblyAngularVelocity = Vector3.zero
