function M.LockAt(pos)
    if typeof(pos) ~= "Vector3" then return false end
    local hrp = getHRP()
    local hum = getHum()
    if not hrp or not hum or hum.Health <= 0 then return false end

    if flyRestore.platformStand == nil then
        flyRestore.platformStand = hum.PlatformStand
        flyRestore.autoRotate = hum.AutoRotate
    end

    lockedPos = pos
    M.SetNoclip(true)
    applySoftLock(hrp, hum, pos)

    if not lockConn then
        lockConn = RunService.Heartbeat:Connect(function()
            if typeof(lockedPos) ~= "Vector3" then return end
            hrp = getHRP()
