local function surfaceSafePos(fromPos)
    if typeof(fromPos) ~= "Vector3" then
        local hrp = getHRP()
        fromPos = hrp and hrp.Position or Vector3.zero
    end
    local origin = Vector3.new(fromPos.X, fromPos.Y + 200, fromPos.Z)
    local params = RaycastParams.new()
    params.FilterType = Enum.RaycastFilterType.Exclude
    local char = LP.Character
    if char then
        params.FilterDescendantsInstances = { char }
    end
    local hit = workspace:Raycast(origin, Vector3.new(0, -500, 0), params)
    if hit then
        return hit.Position + Vector3.new(0, 5, 0)
    end
    return Vector3.new(fromPos.X, math.max(fromPos.Y, 5) + 8, fromPos.Z)
