local function _cfg()
    local MAIN = rawget(_G, "MAIN") or G.MAIN
    local st = MAIN and MAIN.misc and MAIN.misc.fruit_backpack_esp
    st = type(st) == "table" and st or {}
    local mode = G.FRUIT_BACKPACK_ESP_PRICE_MODE or rawget(_G, "FRUIT_BACKPACK_ESP_PRICE_MODE") or st.price_mode
    if tostring(mode or ""):lower() ~= "stock" then
