local function _formatPrice(n)
    n = tonumber(n) or 0
    if n <= 0 then return "0" end
    if n >= 1e9 then return string.format("%.2fB", n / 1e9) end
    if n >= 1e6 then return string.format("%.2fM", n / 1e6) end
    if n >= 1e3 then return string.format("%.1fk", n / 1e3) end
    return tostring(math.floor(n))
end

local function _norm(s)
    return tostring(s or ""):lower():gsub("[%s_%-%.'']+", "")
end

local function _nameOk(a, b)
    a, b = _norm(a), _norm(b)
    if a == "" or b == "" then return false end
    if a == b then return true end
    if #a >= 3 and (a:find(b, 1, true) or b:find(a, 1, true)) then return true end
    return false
end

local function _kgTol(kg)
    return math.max(0.5, (tonumber(kg) or 0) * 0.15)
end

local function _isSeedName(name)
    name = _norm(name)
    if name == "" then return false end
    return name:find("seed", 1, true) ~= nil
        or name == "shovel" or name == "wateringcan"
end

local function _isNonFruitSlot(name)
    name = _norm(name)
    if name == "" then return false end
    if _isSeedName(name) then return true end
    return name:find("sprinkler", 1, true) ~= nil
        or name:find("sprink", 1, true) ~= nil
        or name:find("gear", 1, true) ~= nil
        or name:find("watering", 1, true) ~= nil
        or name:find("fertilizer", 1, true) ~= nil
        or name:find("trap", 1, true) ~= nil
