local function _isVisible(inst)
    if not inst then return false end
    local cur = inst
    while cur and cur ~= game do
        if cur:IsA("GuiObject") and cur.Visible == false then return false end
        if cur:IsA("ScreenGui") and cur.Enabled == false then return false end
        cur = cur.Parent
    end
    return true
end

local function _pick(t, fields)
    if type(t) ~= "table" then return nil end
    for _, f in ipairs(fields) do
        local v = t[f]
        if v ~= nil and tostring(v) ~= "" then return v end
    end
    return nil
end

local function _fruitId(inst)
    if not inst then return "" end
    return tostring(inst:GetAttribute("Id") or inst:GetAttribute("id")
        or inst:GetAttribute("UUID") or inst:GetAttribute("FruitId") or "")
end

local function _entryKey(e)
    local id = tostring(e.id or "")
    if id ~= "" and #id >= 8 then return id end
    return _norm(e.name) .. "|" .. tostring(math.floor((e.kg or 0) * 100))
end

local function _priceCacheKey(e, mode)
