local function _setTotalText(totalRoot, total)
    if not totalRoot then return end
    local valLbl = totalRoot:FindFirstChild(TAG_TOTAL_VAL)
    if valLbl and valLbl:IsA("TextLabel") then
        valLbl.Text = _formatPrice(total)
    end
end

local function _clearAllEsp()
    local pg = LP:FindFirstChild("PlayerGui")
    if not pg then return end
    for _, inst in ipairs(pg:GetDescendants()) do
        if inst.Name == TAG_SLOT
            or inst.Name == TAG_TOTAL
            or inst.Name == TAG_GARDEN_TOTAL
            or inst.Name == "_GAG2FBP_TOTALS_ROW" then
            pcall(function() inst:Destroy() end)
        end
    end
end

----------------------------------------------------------------
-- Scan: tampilkan SEMUA ESP dulu (cepat), tiap 1 detik retry yang masih 0
----------------------------------------------------------------

local function _collectUiSlots(ctx)
    local slots, seen = {}, {}
    local areas, areaSeen = {}, {}
    local function addArea(inst)
        if inst and _isVisible(inst) and not areaSeen[inst] then
            areaSeen[inst] = true
            areas[#areas + 1] = inst
        end
    end
    addArea(ctx.fruitGrid)
    addArea(ctx.hotbar)
    for _, hb in ipairs(_findHotbarRoots(ctx)) do addArea(hb) end
    if #areas == 0 then return slots end

    for _, area in ipairs(areas) do
        for _, lbl in ipairs(area:GetDescendants()) do
            if lbl:IsA("TextLabel") and lbl.Visible and lbl.Name ~= TAG_SLOT then
                if lbl.Name ~= "ToolCount" and not _parseKg(lbl.Text) then
                    continue
                end
                local kg = _parseKg(lbl.Text)
                if kg and kg > 0 and not lbl.Text:match("%d+/%d+") then
                    local root = _findSlotRoot(lbl)
                    if root and not seen[root] and _isVisible(root) then
                        local uiName = _slotNameFromRoot(root, lbl)
                        if not _isNonFruitSlot(uiName) then
                            seen[root] = true
                            slots[#slots + 1] = {
                                root = root,
                                name = uiName,
                                kg = kg,
                                id = _slotId(root),
                            }
                        end
                    end
                end
            end
        end
    end
    return slots
end

local function _cachedPrice(entry)
    if not entry then return 0 end
    return priceByKey[_priceCacheKey(entry, _cfg().price_mode)] or 0
end

local function _sumInventoryTotal(fruits)
    local seen, total = {}, 0
    for _, e in ipairs(fruits) do
        local key = _usedKey(e)
        if not seen[key] then
            seen[key] = true
            _syncEntryBidFromTool(e)
            local price = _cachedPrice(e)
            if price <= 0 then
                price = _fetchPrice(e, false)
            end
            if price > 0 then total += price end
        end
    end
    return total
end

local function _fetchEntriesBatch(entries, predicate)
    local mode = _syncPriceModeCache()
    local toFetch, seenKey = {}, {}
    for _, entry in ipairs(entries) do
        if entry then
            local key = _priceCacheKey(entry, mode)
            if predicate(entry, key) and not seenKey[key] then
                seenKey[key] = true
                toFetch[#toFetch + 1] = entry
            end
        end
    end
    if #toFetch == 0 then return end

    local MAX_FETCH_THREADS = 8
    local idx = 1
    local left = #toFetch
    local deadline = os.clock() + FETCH_WAIT_SEC

    while left > 0 and os.clock() < deadline do
        local batch = math.min(MAX_FETCH_THREADS, left, #toFetch - idx + 1)
        if batch <= 0 then break end
        for _ = 1, batch do
            local entry = toFetch[idx]
            idx += 1
            task.spawn(function()
                pcall(_fetchPrice, entry, true)
                left -= 1
            end)
        end
        task.wait(0.05)
    end
end

local function _fetchAllMissing(entries)
    _fetchEntriesBatch(entries, function(_, key)
        return (priceByKey[key] or 0) <= 0
    end)
end

local function _refreshCachedPrices(entries)
    _fetchEntriesBatch(entries, function(_, key)
        return (priceByKey[key] or 0) > 0
    end)
end

local function _scanOnce(ctx)
    local slots = _collectUiSlots(ctx)
    local fruits, byId = _allFruits()
    if #slots == 0 and #fruits == 0 then return false end

    local used, rows, entries = {}, {}, {}

    for _, slot in ipairs(slots) do
        local entry = _matchFruit(slot.name, slot.kg, slot.id, fruits, byId, used)
        rows[#rows + 1] = { slot = slot, entry = entry }
        if entry then entries[#entries + 1] = entry end
    end

    _fetchAllMissing(fruits)

    local now = os.clock()
    if (now - lastCachedRefreshAt) >= REFRESH_CACHED_SEC then
        lastCachedRefreshAt = now
        task.spawn(function()
            pcall(_refreshCachedPrices, fruits)
        end)
    end

    local total, seen, hasPending = _sumInventoryTotal(fruits), {}, false
    for _, row in ipairs(rows) do
        seen[row.slot.root] = true
        local esp = _ensureSlotLabel(row.slot.root)
        esp.Visible = true
        if row.entry then _syncEntryBidFromTool(row.entry) end
        local price = _cachedPrice(row.entry)
        if price <= 0 then hasPending = true end
        esp.Text = _formatPrice(price)
    end

    local parent = _getBadgeParent(ctx.searchBox, ctx.fruitHeader, ctx.inventory)
    local totalRoot = parent and _ensureTotalLabel(ctx.fruitHeader, ctx.searchBox, ctx.inventory)
    if totalRoot then _setTotalText(totalRoot, total) end

    -- Badge G tampil langsung (0 / cache); value dihitung async di worker.
    do
        local summary = _readGardenValueSummary()
        if summary then
            gardenCache.count = summary.count
            gardenCache.total = summary.total
        end
    end
    local gardenRoot = parent and _ensureGardenTotalLabel(parent)
    if gardenRoot then
        gardenRoot.Visible = true
        _setGardenTotalText(gardenRoot, gardenCache)
    end

    if parent then
        _layoutTotalBadges(parent, gardenRoot, totalRoot, ctx.searchBox, ctx.fruitHeader)
        _deferLayoutBadges(parent, gardenRoot, totalRoot, ctx.searchBox, ctx.fruitHeader)
    end

    for _, inst in ipairs(ctx.screenGui:GetDescendants()) do
        if inst.Name == TAG_SLOT and inst.Parent and not seen[inst.Parent] then
            inst:Destroy()
        end
    end
    return hasPending
end

local function _scanLoop()
    while running do
        if _cfg().enabled then
            local ctx = _findBackpackContext()
            if ctx then
                bpOpen = true
                pcall(function() _scanOnce(ctx) end)
            else
                if bpOpen then
                    bpOpen = false
                    _clearAllEsp()
                end
            end
        end
        task.wait(SCAN_SEC)
    end
end

function M.SetEnabled(a, b)
    local on = a
    if type(a) == "table" then
        on = b
    end
    on = (on == true)
    G.FRUIT_BACKPACK_ESP_ENABLED = on
    _G.FRUIT_BACKPACK_ESP_ENABLED = on
    if on then M.Start() else M.Stop() end
end

function M.IsEnabled()
    return running
end

function M.Start()
    if running then return true end
    running = true
    G.FRUIT_BACKPACK_ESP_ENABLED = true
    _G.FRUIT_BACKPACK_ESP_ENABLED = true
    if scanThread then task.cancel(scanThread) end
    scanThread = task.spawn(_scanLoop)
    if gardenThread then task.cancel(gardenThread) end
    gardenThread = task.spawn(_gardenLoop)
    return true
end

function M.ClearPriceCache()
    table.clear(priceByKey)
    lastCachedRefreshAt = 0
end

function M.SetPriceMode(mode)
    mode = (tostring(mode or ""):lower() == "stock") and "stock" or "base"
    G.FRUIT_BACKPACK_ESP_PRICE_MODE = mode
    _G.FRUIT_BACKPACK_ESP_PRICE_MODE = mode
    G.FRUIT_PRICE_INCLUDE_FRIEND_BOOST = (mode == "stock")
    _G.FRUIT_PRICE_INCLUDE_FRIEND_BOOST = (mode == "stock")
    local fsv = _fsv()
    if fsv then
        if type(fsv.setEspPriceMode) == "function" then
            pcall(fsv.setEspPriceMode, mode)
        elseif type(fsv.clearBidCache) == "function" then
            pcall(fsv.clearBidCache)
        end
    end
    lastPriceMode = nil
    M.ClearPriceCache()
end

function M.Stop()
    running = false
    bpOpen = false
    lastCachedRefreshAt = 0
    if scanThread then task.cancel(scanThread) scanThread = nil end
    if gardenThread then task.cancel(gardenThread) gardenThread = nil end
    table.clear(priceByKey)
    gardenCache.count = 0
    gardenCache.total = 0
    G.FRUIT_BACKPACK_ESP_ENABLED = false
    _G.FRUIT_BACKPACK_ESP_ENABLED = false
    _clearAllEsp()
end

function M.SyncFromGlobals()
    local cfg = _cfg()
    G.FRUIT_BACKPACK_ESP_ENABLED = cfg.enabled
    _G.FRUIT_BACKPACK_ESP_ENABLED = cfg.enabled
    G.FRUIT_BACKPACK_ESP_PRICE_MODE = cfg.price_mode
    _G.FRUIT_BACKPACK_ESP_PRICE_MODE = cfg.price_mode
    lastPriceMode = nil
    M.ClearPriceCache()
    if cfg.enabled then M.Start() else M.Stop() end
    return cfg
end

-- API untuk AutoFav / modul lain: scan + harga sama seperti ESP backpack (cepat, cache)
function M.ScanFruits()
    return _allFruits()
end

function M.GetCachedEntryPrice(entry)
    if not entry then return 0 end
    _syncEntryBidFromTool(entry)
    local mode = _syncPriceModeCache()
    return priceByKey[_priceCacheKey(entry, mode)] or 0
end

function M.GetEntryPrice(entry, force)
    if not entry then return 0 end
    _syncEntryBidFromTool(entry)
    if not force then
        local cached = M.GetCachedEntryPrice(entry)
        if cached > 0 then return cached end
    end
    return _fetchPrice(entry, force == true)
end

M.scanFruits = M.ScanFruits
M.getEntryPrice = M.GetEntryPrice
M.getCachedEntryPrice = M.GetCachedEntryPrice

G.EspFruitBackpack = M
_G.EspFruitBackpack = M

return M
 end,               required = false },
    { key = "EspFruitGarden",          name = "ESP Fruit Garden",        factory = function() -- EspFruitGarden.lua — ESP buah di plot (nama, kg, rarity, harga)
-- Tampilkan top N buah di plot sesuai priority (kg / price) dari UI.

local Players           = game:GetService("Players")
local RunService        = game:GetService("RunService")
local CollectionService = game:GetService("CollectionService")
local ReplicatedStorage = game:GetService("ReplicatedStorage")

local LP = Players.LocalPlayer
local G  = (getgenv and getgenv()) or _G
local M  = {}

local TAG_ROOT  = "_GAG2FG_ESP"
local HARVEST_TAG = "HarvestPrompt"
local POLL_SEC_LIGHT = 0.45
local POLL_SEC_MED   = 0.85
local POLL_SEC_HEAVY = 1.4
local PLOT_CACHE_SEC = 3.0
local DEFAULT_MAX_ESP = 100
-- Saat priority price: prefilter by kg dulu, baru hitung harga (hindari price × 1000 buah)
local PRICE_PREFILTER_MULT = 3
local MAX_PRICE_EVAL = 120
local PROMPT_COMPACT_EVERY = 8

local COL_BG     = Color3.fromRGB(18, 22, 16)
local COL_STROKE = Color3.fromRGB(255, 210, 60)
local COL_GLOW   = Color3.fromRGB(255, 196, 45)

local RARITY_HEX = {
    common    = "#9CA3AF",
    uncommon  = "#34D399",
    rare      = "#60A5FA",
    epic      = "#A78BFA",
    legendary = "#FB923C",
    mythic    = "#F87171",
    divine    = "#FBBF24",
    secret    = "#F472B6",
    super     = "#E879F9",
}

local running = false
local conn = nil
local tickGen = 0
local lastPoll = 0
local nextPollSec = POLL_SEC_LIGHT
local cachedPlot = nil
local cachedPlotAt = 0
local espByKey = {}
local summaryCache = { count = 0, total = 0 }

-- Matikan instance lama (reload script) supaya Heartbeat lama tidak terus buat ESP
do
    local prev = G.EspFruitGarden or rawget(_G, "EspFruitGarden")
    if type(prev) == "table" and prev ~= M and type(prev.Stop) == "function" then
        pcall(prev.Stop, prev)
    end
end

-- Incremental harvest-prompt index (hindari plot:GetDescendants tiap tick)
local promptCache = {}
local promptSet = {}
local promptPlot = nil
local promptConns = {}
local promptScanGen = 0
local lastFruitCount = 0

local FruitSellValue
pcall(function()
    FruitSellValue = require(script.Parent.FruitSellValue)
end)
if type(FruitSellValue) ~= "table" then
    FruitSellValue = G.FruitSellValue or _G.FruitSellValue
end

local function _normalizePriority(v)
    v = tostring(v or ""):lower()
    if v == "price" then return "price" end
    return "kg"
end

local function _clampMaxEsp(n)
    n = math.floor(tonumber(n) or DEFAULT_MAX_ESP)
    if n < 1 then n = 1 end
    if n > 5000 then n = 5000 end
    return n
end

local function _fruitSetFrom(src)
    if type(src) ~= "table" then return {} end
    local out = {}
    if src[1] ~= nil then
        for _, v in ipairs(src) do
            local s = tostring(v)
            if s ~= "" then out[s] = true end
        end
    else
        for k, v in pairs(src) do
            if v == true or v == 1 or v == "true" then
                out[tostring(k)] = true
            end
        end
    end
    return out
end

local function _canonFruitName(s)
    return tostring(s or ""):lower():gsub("[%s_%-]+", "")
end

local function _hasFruitFilter(map)
    if type(map) ~= "table" then return false end
    for _, v in pairs(map) do
        if v == true then return true end
    end
    return false
end

local function _matchFruitFilter(selectedMap, name)
    if not _hasFruitFilter(selectedMap) then return true end
    local needle = _canonFruitName(name)
    if needle == "" then return false end
    for k, v in pairs(selectedMap) do
        if v == true and _canonFruitName(k) == needle then
            return true
        end
    end
    return false
end

local function _cfg()
    local MAIN = rawget(_G, "MAIN") or G.MAIN
    local st = MAIN and MAIN.misc and MAIN.misc.fruit_garden_esp
    st = type(st) == "table" and st or {}
    -- Jangan OR semua sumber: satu yang true menahan ESP tetap hidup saat toggle OFF
    local enabled
    if G.FRUIT_GARDEN_ESP_ENABLED ~= nil then
        enabled = (G.FRUIT_GARDEN_ESP_ENABLED == true)
    elseif rawget(_G, "FRUIT_GARDEN_ESP_ENABLED") ~= nil then
        enabled = (rawget(_G, "FRUIT_GARDEN_ESP_ENABLED") == true)
    else
        enabled = (st.enabled == true)
    end
    local priority = G.FRUIT_GARDEN_ESP_PRIORITY
        or rawget(_G, "FRUIT_GARDEN_ESP_PRIORITY")
        or st.priority
    local maxEsp = G.FRUIT_GARDEN_ESP_MAX
        or rawget(_G, "FRUIT_GARDEN_ESP_MAX")
        or st.max_esp
    local fruits = G.FRUIT_GARDEN_ESP_FRUITS_SELECTED
        or rawget(_G, "FRUIT_GARDEN_ESP_FRUITS_SELECTED")
        or st.fruits
    return {
        enabled = enabled,
        priority = _normalizePriority(priority),
        max_esp = _clampMaxEsp(maxEsp),
        fruits = _fruitSetFrom(fruits),
    }
end

local function _formatPrice(n)
    n = tonumber(n) or 0
    if n <= 0 then return "0" end
    if n >= 1e9 then return string.format("%.2fB", n / 1e9) end
    if n >= 1e6 then return string.format("%.2fM", n / 1e6) end
    if n >= 1e3 then return string.format("%.1fk", n / 1e3) end
    return tostring(math.floor(n))
end

local function _matchOwner(v)
    if v == nil or not LP then return false end
    return v == LP.UserId or v == LP.Name
        or tostring(v) == tostring(LP.UserId) or tostring(v) == LP.Name
end

local function _plotOwned(plot)
    if not plot then return false end
    if _matchOwner(plot:GetAttribute("OwnerId")) then return true end
    if _matchOwner(plot:GetAttribute("Owner")) then return true end
    if _matchOwner(plot:GetAttribute("OwnerUserId")) then return true end
    if _matchOwner(plot:GetAttribute("UserId")) then return true end

    for _, child in ipairs(plot:GetChildren()) do
        if child:IsA("ValueBase") then
            local n = child.Name:lower()
            if n:find("owner") or n:find("userid") or n:find("player") then
                if _matchOwner(child.Value) then return true end
            end
        end
    end

    local myPlot = LP:GetAttribute("Plot") or LP:GetAttribute("PlotName")
        or LP:GetAttribute("GardenPlot") or LP:GetAttribute("PlotId")
    if myPlot and plot.Name == tostring(myPlot) then return true end
    if myPlot and plot.Name == ("Plot" .. tostring(myPlot)) then return true end
    return false
end

local function _findPlotInGardens(gardens, plotId)
    if not gardens or plotId == nil then return nil end
    local idStr = tostring(plotId)
    for _, name in ipairs({ "Plot" .. idStr, idStr, "Plot_" .. idStr }) do
        local plot = gardens:FindFirstChild(name)
        if plot then return plot end
    end
    return nil
end

local function _getPlot(force)
    local now = os.clock()
    if not force and cachedPlot and cachedPlot.Parent and (now - cachedPlotAt) <= PLOT_CACHE_SEC then
        return cachedPlot
    end

    local autoTele = G.AutoTele or G.AutoTeleModule or rawget(_G, "AutoTele")
    if type(autoTele) == "table" and type(autoTele.GetPlayerPlot) == "function" then
        local ok, plot = pcall(autoTele.GetPlayerPlot, autoTele)
        if ok and plot and plot.Parent then
            cachedPlot = plot
            cachedPlotAt = now
            return plot
        end
    end

    local gardens = workspace:FindFirstChild("Gardens")
    if not gardens then
        cachedPlot = nil
        cachedPlotAt = now
        return nil
    end

    local plotId = LP:GetAttribute("PlotId")
    local byId = _findPlotInGardens(gardens, plotId)
    if byId then
        cachedPlot = byId
        cachedPlotAt = now
        return byId
    end

    for _, plot in ipairs(gardens:GetChildren()) do
        if _plotOwned(plot) then
            cachedPlot = plot
            cachedPlotAt = now
            return plot
        end
    end

    local char = LP.Character
    local hrp = char and char:FindFirstChild("HumanoidRootPart")
    if hrp then
        local params = RaycastParams.new()
        params.FilterType = Enum.RaycastFilterType.Include
        params.FilterDescendantsInstances = { gardens }
        local hit = workspace:Raycast(hrp.Position + Vector3.new(0, 6, 0), Vector3.new(0, -40, 0), params)
        if hit then
            for _, plot in ipairs(gardens:GetChildren()) do
                if hit.Instance:IsDescendantOf(plot) then
                    cachedPlot = plot
                    cachedPlotAt = now
                    return plot
                end
            end
        end
    end

    local byName = gardens:FindFirstChild("Plot" .. LP.Name)
    cachedPlot = byName
    cachedPlotAt = now
    return byName
end

local function _isHarvestPrompt(prompt)
    if not prompt or not prompt:IsA("ProximityPrompt") then return false end
    if CollectionService:HasTag(prompt, HARVEST_TAG) then return true end
    local action = tostring(prompt.ActionText or ""):lower()
    if action:find("harvest", 1, true) or action:find("collect", 1, true) then
        return true
    end
    local obj = tostring(prompt.ObjectText or ""):lower()
    if obj:find("harvest", 1, true) or obj:find("fruit", 1, true) then
        return true
    end
    return tostring(prompt.Name or ""):lower():find("harvest", 1, true) ~= nil
end

local function _wipe(t)
    for k in pairs(t) do
        t[k] = nil
    end
end

local function _clearPromptCache()
    for _, c in ipairs(promptConns) do
        pcall(function() c:Disconnect() end)
    end
    for i = #promptConns, 1, -1 do promptConns[i] = nil end
    for i = #promptCache, 1, -1 do promptCache[i] = nil end
    _wipe(promptSet)
    promptPlot = nil
    promptScanGen = 0
end

local function _tryIndexPrompt(prompt)
    if not prompt or not prompt:IsA("ProximityPrompt") then return end
    if promptSet[prompt] then return end
    if not _isHarvestPrompt(prompt) then return end
    promptSet[prompt] = true
    promptCache[#promptCache + 1] = prompt
end

local function _compactPromptCache()
    local live = {}
    for i = 1, #promptCache do
        local p = promptCache[i]
        if p and p.Parent and promptSet[p] then
            live[#live + 1] = p
        elseif p then
            promptSet[p] = nil
        end
    end
    promptCache = live
end

local function _rebuildPromptCache(plot)
    _clearPromptCache()
    if not plot or not plot.Parent then return end
    promptPlot = plot

    -- Full index sekali saat rebuild (bukan tiap Heartbeat)
    for _, d in ipairs(plot:GetDescendants()) do
        if d:IsA("ProximityPrompt") then
            _tryIndexPrompt(d)
        end
    end

    table.insert(promptConns, plot.DescendantAdded:Connect(function(d)
        if d:IsA("ProximityPrompt") then
            _tryIndexPrompt(d)
        end
    end))
    table.insert(promptConns, plot.DescendantRemoving:Connect(function(d)
        if promptSet[d] then
            promptSet[d] = nil
        end
    end))

    local okTagAdd, tagAddSignal = pcall(function()
        return CollectionService:GetInstanceAddedSignal(HARVEST_TAG)
    end)
    if okTagAdd and tagAddSignal then
        table.insert(promptConns, tagAddSignal:Connect(function(inst)
            if promptPlot and inst:IsA("ProximityPrompt") and inst:IsDescendantOf(promptPlot) then
                _tryIndexPrompt(inst)
            end
        end))
    end
end

local function _ensurePromptCache(plot)
    if not plot then
        _clearPromptCache()
        return promptCache
    end
    if promptPlot ~= plot then
        _rebuildPromptCache(plot)
    end
    promptScanGen += 1
    if promptScanGen % PROMPT_COMPACT_EVERY == 0 then
        _compactPromptCache()
    end
    return promptCache
end

local function _adaptivePollSec(fruitCount)
    fruitCount = tonumber(fruitCount) or 0
    if fruitCount >= 800 then return POLL_SEC_HEAVY end
    if fruitCount >= 350 then return POLL_SEC_MED end
    return POLL_SEC_LIGHT
end

local function _fruitFromPrompt(prompt)
    if not prompt or not prompt.Parent then return nil end
    local node, best = prompt.Parent, nil
    while node do
        if node:IsA("Model") then
            local pid = node:GetAttribute("PlantId")
            if pid ~= nil and tostring(pid) ~= "" then
                best = node
                if node:GetAttribute("FruitId") ~= nil then return node end
            end
        end
        if node.Name == "Gardens" then break end
        node = node.Parent
    end
    return best or prompt.Parent:FindFirstAncestorWhichIsA("Model")
end

local function _resolveIds(model)
    if not model then return "", "" end
    local plantId, fruitId = "", ""
    local node, depth = model, 0
    while node and depth < 12 do
        if node:IsA("Model") then
            if plantId == "" then
                local p = node:GetAttribute("PlantId")
                if p ~= nil and tostring(p) ~= "" then plantId = tostring(p) end
            end
            if fruitId == "" then
                local f = node:GetAttribute("FruitId")
                if f ~= nil and tostring(f) ~= "" then fruitId = tostring(f) end
            end
        end
        if node.Name == "Gardens" then break end
        node = node.Parent
        depth += 1
    end
    return plantId, fruitId
end

local function _fsv()
    local f = FruitSellValue or G.FruitSellValue or _G.FruitSellValue
    return type(f) == "table" and f or nil
end

local function _parseKgText(text)
    return tonumber(tostring(text or ""):match("([%d%.]+)%s*[kK][gG]"))
end

local function _parsePriceText(text)
    text = tostring(text or "")
    if text:lower():find("kg", 1, true) then return nil end
    local s = text:gsub(",", "")
    local n = tonumber(s:match("([%d%.]+)%s*[kK]"))
    if n then return n * 1000 end
    n = tonumber(s:match("([%d%.]+)%s*[mM]"))
    if n then return n * 1000000 end
    n = tonumber(s:match("([%d%.]+)%s*[bB]"))
    if n then return n * 1000000000 end
    n = tonumber(s:match("[$%s]*([%d%.]+)"))
    if n and n > 0 then return n end
    return nil
end

local function _readGameBillboard(model)
    if not model then return nil, nil, nil end
    local kg, price, rarity = nil, nil, nil
    for _, d in ipairs(model:GetDescendants()) do
        if d:IsA("TextLabel") and d.Name ~= TAG_ROOT then
            local t = d.Text or ""
            local w = _parseKgText(t)
            if w and w > 0 and (not kg or w > kg) then kg = w end
            local p = _parsePriceText(t)
            if p and p > 0 and (not price or p < price) then price = p end
            if not rarity and t ~= "" and not _parseKgText(t) and not _parsePriceText(t) then
                local low = t:lower()
                if low:find("common") or low:find("uncommon") or low:find("rare")
                    or low:find("epic") or low:find("legend") or low:find("myth")
                    or low:find("divine") or low:find("secret") then
                    rarity = t
                end
            end
        end
    end
    return kg, price, rarity
end

local function _walkModels(model, fn, maxDepth)
    maxDepth = maxDepth or 12
    local node, depth = model, 0
    while node and depth < maxDepth do
        if node:IsA("Model") then
            local stop = fn(node)
            if stop then return stop end
        end
        if node.Name == "Gardens" then break end
        node = node.Parent
        depth += 1
    end
    return nil
end

local function _kgFromAttributes(model)
    local walked = _walkModels(model, function(node)
        local bw = tonumber(node:GetAttribute("BaseWeight"))
        local sm = tonumber(node:GetAttribute("SizeMulti"))
            or tonumber(node:GetAttribute("SizeMultiplier"))
        local og = tonumber(node:GetAttribute("OvertimeGrowth")) or 1
        if bw and bw > 0 and sm and sm > 0 then
            return bw * sm * og
        end
        local w = tonumber(node:GetAttribute("Weight"))
        if w and w > 0 then return w end
        return nil
    end)
    return (type(walked) == "number" and walked > 0) and walked or 0
end

-- Fast path untuk mass scan: NO GetDescendants / billboard walk
local function _displayKgCheap(model)
    if not model then return 0 end

    local fsv = _fsv()
    if fsv and type(fsv.resolveWeight) == "function" then
        local ok, w = pcall(fsv.resolveWeight, model)
        if ok and type(w) == "number" and w > 0 then return w end
    end

    return _kgFromAttributes(model)
end

local function _displayKg(model, allowBillboard)
    if allowBillboard == nil then allowBillboard = true end

    local cheap = _displayKgCheap(model)
    if cheap > 0 then return cheap end
    if not allowBillboard then return 0 end

    local bbKg = select(1, _readGameBillboard(model))
    if bbKg and bbKg > 0 then return bbKg end

    local node, depth = model, 0
    while node and depth < 6 do
        if node:IsA("Model") then
            for _, d in ipairs(node:GetDescendants()) do
                if d:IsA("TextLabel") then
                    local w = _parseKgText(d.Text)
                    if w and w > 0 then return w end
                end
            end
        end
        if node.Name == "Gardens" then break end
        node = node.Parent
        depth += 1
    end
    return 0
end

local function _fruitName(model)
    local fsv = FruitSellValue
    if fsv and type(fsv.resolveSeedName) == "function" then
        local ok, n = pcall(fsv.resolveSeedName, model)
        if ok and type(n) == "string" and n ~= "" then return n end
    end
    return tostring(model:GetAttribute("FruitName")
        or model:GetAttribute("CorePartName")
        or model:GetAttribute("FruitType")
        or model.Name or "?")
end

local function _fruitNameCheap(model)
    if not model then return "?" end
    local n = model:GetAttribute("FruitName")
        or model:GetAttribute("CorePartName")
        or model:GetAttribute("FruitType")
    if n ~= nil and tostring(n) ~= "" then return tostring(n) end
    return tostring(model.Name or "?")
end

local function _fruitRarity(model, name)
    name = tostring(name or "")
    local fsv = _fsv()
    if fsv and type(fsv.getRarity) == "function" and name ~= "" then
        local ok, r = pcall(fsv.getRarity, name)
        if ok and type(r) == "string" and r ~= "" then return r end
    end
    -- Jangan GetDescendants di sini — rarity dari nama cukup untuk ESP mass
    return nil
end

local function _normalizeMutation(raw)
    if raw == nil then return nil end
    if type(raw) == "string" then
        raw = raw:match("^%s*(.-)%s*$")
        if raw == "" or raw:lower() == "none" or raw:lower() == "nomutation" then
            return nil
        end
        return raw
    end
    if type(raw) == "table" then
        local parts = {}
        for _, v in ipairs(raw) do
            if type(v) == "string" and v ~= "" then parts[#parts + 1] = v end
        end
        if #parts > 0 then return table.concat(parts, ",") end
    end
    return nil
end

local function _fruitMutation(model)
    local found = _walkModels(model, function(node)
        local attrs = { "Mutation", "Mutations", "MutationName" }
        for _, key in ipairs(attrs) do
            local norm = _normalizeMutation(node:GetAttribute(key))
            if norm then return norm end
        end
        local fsv = _fsv()
        if fsv and type(fsv.resolveMutation) == "function" then
            local ok, m = pcall(fsv.resolveMutation, node)
            if ok then
                norm = _normalizeMutation(m)
                if norm then return norm end
            end
        end
        return nil
    end)
    return found
end

local function _derivePriceMulti(model)
    local fsv = _fsv()
    local kg = 0
    if fsv and type(fsv.resolveWeight) == "function" then
        local ok, w = pcall(fsv.resolveWeight, model)
        if ok then kg = tonumber(w) or 0 end
    end
    if kg <= 0 then
        kg = tonumber(_displayKg(model)) or 0
    end
    if kg <= 0 then return 0 end

    local derived = _walkModels(model, function(node)
        local bw = tonumber(node:GetAttribute("BaseWeight"))
        local og = tonumber(node:GetAttribute("OvertimeGrowth")) or 1
        if bw and bw > 0 then
            local m = kg / bw / og
            if m > 0 and m <= 25 then return m end
        end
        return nil
    end)
    return tonumber(derived) or 0
end

local function _resolvePriceMulti(model)
    if not model then return 0 end

    local fsv = _fsv()
    if fsv and type(fsv.resolveMulti) == "function" then
        local ok, m = pcall(fsv.resolveMulti, model)
        if ok and type(m) == "number" and m > 0 and m <= 25 then
            return m
        end
    end

    local multOnly = _walkModels(model, function(node)
        local m = tonumber(node:GetAttribute("SizeMultiplier"))
        if m and m > 0 and m <= 25 then return m end
        return nil
    end)
    if type(multOnly) == "number" then return multOnly end

    local fromAttr = _walkModels(model, function(node)
        local m = tonumber(node:GetAttribute("SizeMulti"))
        if m and m > 0 and m <= 25 then return m end
        return nil
    end)
    if type(fromAttr) == "number" then return fromAttr end

    local ok, derived = pcall(_derivePriceMulti, model)
    if ok and type(derived) == "number" and derived > 0 then
        return derived
    end
    return 0
end

local function _mutationVariants(mut)
    if type(mut) ~= "string" or mut == "" then return { nil } end
    local out, seen = {}, {}
    local function add(v)
        if v == nil then
            if not seen["__nil__"] then
                seen["__nil__"] = true
                out[#out + 1] = nil
            end
            return
        end
        v = tostring(v):match("^%s*(.-)%s*$")
        if v == "" or seen[v] then return end
        seen[v] = true
        out[#out + 1] = v
    end
    add(mut)
    for token in string.gmatch(mut, "[^%+%,]+") do
        add(token)
    end
    add(nil)
    return out
end

local function _calcWithMutations(fsv, name, multi, mut, decay)
    if type(fsv.calculate) ~= "function" or multi <= 0 or name == "" then
        return 0
    end
    for _, variant in ipairs(_mutationVariants(mut)) do
        local ok, p = pcall(fsv.calculate, name, multi, variant, LP, decay)
        if ok and type(p) == "number" and p > 0 then return p end
    end
    return 0
end

local function _resolveDecay(model)
    return _walkModels(model, function(node)
        local d = node:GetAttribute("DecayAlpha")
        if d ~= nil then return d end
        return nil
    end)
end

local function _isHarvestFruitId(fid)
    fid = tostring(fid or "")
    if fid == "" or #fid < 8 then return false end
    if fid:match("^%d+_[%x%-]+") then return false end
    if fid:match("^[%x%-]+$") and #fid >= 32 then return true end
    return #fid >= 16
end

local function _fruitPrice(model, name, opts)
    if not model then return 0 end
    opts = type(opts) == "table" and opts or {}

    local fsv = _fsv()
    if not fsv then return 0 end
    -- refresh sekali per tick dari pemanggil, bukan per-buah
    if opts.refresh == true and type(fsv.refresh) == "function" then
        pcall(fsv.refresh, true)
    end

    name = tostring(name or _fruitName(model))
    local multi = 0
    do
        local ok, m = pcall(_resolvePriceMulti, model)
        if ok then multi = tonumber(m) or 0 end
    end
    local mut = _fruitMutation(model)
    local decay = _resolveDecay(model)

    local fruitUuid = _walkModels(model, function(node)
        for _, key in ipairs({ "Id", "id", "UUID", "Uuid" }) do
            local fid = node:GetAttribute(key)
            if _isHarvestFruitId(fid) then return tostring(fid) end
        end
        return nil
    end)

    if type(fsv.getBackpackPrice) == "function" and multi > 0 and name ~= "" then
        for _, variant in ipairs(_mutationVariants(mut)) do
            local ok, p = pcall(fsv.getBackpackPrice, name, multi, variant, fruitUuid, decay)
            if ok and type(p) == "number" and p > 0 then return p end
        end
    end

    local calcPrice = _calcWithMutations(fsv, name, multi, mut, decay)
    if calcPrice > 0 then return calcPrice end

    if type(fsv.fromFruit) == "function" then
        local best = 0
        _walkModels(model, function(node)
            local ok, p = pcall(fsv.fromFruit, node, LP)
            if ok and type(p) == "number" and p > best then best = p end
            return nil
        end)
        if best > 0 then return best end
    end

    if opts.allowBillboard == true then
        local _, bbPrice = _readGameBillboard(model)
        return tonumber(bbPrice) or 0
    end
    return 0
end

local function _adornee(model)
    if not model then return nil end
    if model.PrimaryPart and model.PrimaryPart:IsA("BasePart") then
        return model.PrimaryPart
    end
    return model:FindFirstChildWhichIsA("BasePart", true)
end

local function _destroyEsp(key)
    local rec = espByKey[key]
    if rec and rec.gui then
        pcall(function() rec.gui:Destroy() end)
    end
    espByKey[key] = nil
end

local function _notifySummaryChanged()
    local cb = M.OnSummaryChanged
    if type(cb) ~= "function" then return end
    pcall(cb, summaryCache.count, summaryCache.total)
end

local function _resetSummaryCache()
    summaryCache.count = 0
    summaryCache.total = 0
    _notifySummaryChanged()
end

local function _refreshSummaryCache()
    local count = 0
    local total = 0
    for _, rec in pairs(espByKey) do
        if rec and rec.gui and rec.gui.Parent then
            count += 1
            total += tonumber(rec.price) or 0
        end
    end
    summaryCache.count = count
    summaryCache.total = total
    _notifySummaryChanged()
end

local function _isOurEspGui(inst)
    return inst
        and inst:IsA("BillboardGui")
        and (inst.Name == TAG_ROOT or inst:GetAttribute("_GAG2_ESP") == true)
end

local function _sweepOrphanEsp(root)
    if not root then return end
    for _, d in ipairs(root:GetDescendants()) do
        if _isOurEspGui(d) then
            pcall(function() d:Destroy() end)
        end
    end
end

local function _clearAllEsp()
    for key in pairs(espByKey) do
        _destroyEsp(key)
    end
    espByKey = {}
    local plot = cachedPlot
    if not (plot and plot.Parent) then
        pcall(function()
            plot = _getPlot(true)
        end)
    end
    if plot and plot.Parent then
        _sweepOrphanEsp(plot)
    end
    _resetSummaryCache()
end

local function _escRich(s)
    return tostring(s or ""):gsub("&", "&amp;"):gsub("<", "&lt;"):gsub(">", "&gt;")
end

local function _rarityHex(rarity)
    local key = tostring(rarity or ""):lower():gsub("[%s_]+", "")
    return RARITY_HEX[key] or "#94A3B8"
end

local function _buildRichLine(name, kg, rarity, mutation, price)
    local dot = '<font color="#475569"> · </font>'
    local segments = {}

    if type(rarity) == "string" and rarity ~= "" then
        segments[#segments + 1] = string.format(
            '<font color="%s"><b>%s</b></font>',
            _rarityHex(rarity),
            _escRich(rarity)
        )
    end

    segments[#segments + 1] = string.format(
        '<font color="#F8FAFC"><b>%s</b></font>',
        _escRich(tostring(name))
    )

    if type(mutation) == "string" and mutation ~= "" then
        segments[#segments + 1] = string.format(
            '<font color="#FDE047">%s</font>',
            _escRich(mutation)
        )
    end

    segments[#segments + 1] = string.format(
        '<font color="#86EFAC">%.2fkg</font>',
        tonumber(kg) or 0
    )

    segments[#segments + 1] = string.format(
        '<font color="#FACC15"><b>%s</b></font>',
        _escRich(_formatPrice(price))
    )

    return dot .. table.concat(segments, dot)
end

local function _resizeEsp(rec)
    if not rec or not rec.lineLbl or not rec.gui then return end
    local lbl = rec.lineLbl
    local padX, padY = 16, 8
    local bounds = lbl.TextBounds
    local w = math.max(48, math.ceil(bounds.X) + padX)
    local h = math.max(22, math.ceil(bounds.Y) + padY)
    rec.gui.Size = UDim2.fromOffset(w, h)
end

local function _ensureEsp(key, adornee)
    local rec = espByKey[key]
    if rec and rec.gui and rec.gui.Parent and rec.adornee == adornee then
        return rec
    end
    if rec then _destroyEsp(key) end
    if not adornee then return nil end

    local bb = Instance.new("BillboardGui")
    bb.Name = TAG_ROOT
    bb:SetAttribute("_GAG2_ESP", true)
    bb.Size = UDim2.fromOffset(48, 22)
    bb.StudsOffset = Vector3.new(0, 2.6, 0)
    bb.AlwaysOnTop = true
    bb.MaxDistance = 220
    bb.Enabled = true
    bb.Adornee = adornee
    bb.Parent = adornee

    local frame = Instance.new("Frame")
    frame.Name = "Bg"
    frame.BackgroundColor3 = COL_BG
    frame.BackgroundTransparency = 0.12
    frame.BorderSizePixel = 0
    frame.Size = UDim2.fromScale(1, 1)
    frame.Parent = bb
    Instance.new("UICorner", frame).CornerRadius = UDim.new(1, 0)

    local stroke = Instance.new("UIStroke")
    stroke.Color = COL_STROKE
    stroke.Thickness = 1
    stroke.Transparency = 0.22
    stroke.ApplyStrokeMode = Enum.ApplyStrokeMode.Border
    stroke.Parent = frame

    local glow = Instance.new("UIStroke")
    glow.Name = "Glow"
    glow.Color = COL_GLOW
    glow.Thickness = 2.5
    glow.Transparency = 0.78
    glow.ApplyStrokeMode = Enum.ApplyStrokeMode.Border
    glow.Parent = frame

    local pad = Instance.new("UIPadding")
    pad.PaddingLeft = UDim.new(0, 8)
    pad.PaddingRight = UDim.new(0, 8)
    pad.PaddingTop = UDim.new(0, 4)
    pad.PaddingBottom = UDim.new(0, 4)
    pad.Parent = frame

    local lineLbl = Instance.new("TextLabel")
    lineLbl.Name = "Line"
    lineLbl.BackgroundTransparency = 1
    lineLbl.Size = UDim2.fromScale(1, 1)
    lineLbl.Font = Enum.Font.GothamMedium
    lineLbl.TextSize = 11
    lineLbl.TextXAlignment = Enum.TextXAlignment.Center
    lineLbl.TextYAlignment = Enum.TextYAlignment.Center
    lineLbl.TextWrapped = false
    lineLbl.TextTruncate = Enum.TextTruncate.None
    lineLbl.RichText = true
    lineLbl.TextColor3 = Color3.fromRGB(248, 250, 252)
    lineLbl.TextStrokeTransparency = 0.6
    lineLbl.TextStrokeColor3 = Color3.fromRGB(15, 23, 42)
    lineLbl.Parent = frame

    rec = {
        gui = bb,
        frame = frame,
        adornee = adornee,
        lineLbl = lineLbl,
    }
    espByKey[key] = rec
    return rec
end

local function _setEspText(rec, name, kg, rarity, mutation, price)
    if not rec then return end
    rec.price = tonumber(price) or 0
    if rec.gui then
        rec.gui.Enabled = true
    end
    if rec.lineLbl then
        rec.lineLbl.Text = _buildRichLine(name, kg, rarity, mutation, price)
        _resizeEsp(rec)
    end
end

local function _scanGardenCandidates(plot)
    local candidates = {}
    local seen = {}
    local cfg = _cfg()
    local prompts = _ensurePromptCache(plot)

    for i = 1, #prompts do
        local prompt = prompts[i]
        if not prompt or not prompt.Parent or not promptSet[prompt] then
            continue
        end
        if not prompt:IsA("ProximityPrompt") then continue end
        if prompt:GetAttribute("Collected") then continue end
        if not _isHarvestPrompt(prompt) then continue end

        local fruit = _fruitFromPrompt(prompt)
        if not fruit or not fruit.Parent then continue end
        local plantId, fruitId = _resolveIds(fruit)
        if plantId == "" then continue end
        local key = plantId .. "|" .. fruitId
        if seen[key] then continue end
        seen[key] = true

        local ad = _adornee(fruit)
        if not ad then continue end

        local name = _fruitNameCheap(fruit)
        if not _matchFruitFilter(cfg.fruits, name) then continue end

        candidates[#candidates + 1] = {
            key = key,
            fruit = fruit,
            adornee = ad,
            name = name,
            kg = tonumber(_displayKgCheap(fruit)) or 0,
        }
    end

    lastFruitCount = #candidates
    nextPollSec = _adaptivePollSec(lastFruitCount)

    local priority = cfg.priority
    local limit = math.min(cfg.max_esp, #candidates)

    -- Sort by kg dulu (murah). Price hanya dihitung untuk prefilter kecil.
    table.sort(candidates, function(a, b)
        if a.kg ~= b.kg then return a.kg > b.kg end
        return a.key < b.key
    end)

    if priority == "price" and #candidates > 0 then
        local preN = math.min(
            #candidates,
            math.max(limit * PRICE_PREFILTER_MULT, limit),
            MAX_PRICE_EVAL
        )
        for i = 1, preN do
            local item = candidates[i]
            item.priced = true
            item.price = _fruitPrice(item.fruit, item.name, { allowBillboard = false })
        end
        table.sort(candidates, function(a, b)
            local aPriced = a.priced == true
            local bPriced = b.priced == true
            if aPriced ~= bPriced then return aPriced end
            local pa = tonumber(a.price) or 0
            local pb = tonumber(b.price) or 0
            if pa ~= pb then return pa > pb end
            if a.kg ~= b.kg then return a.kg > b.kg end
            return a.key < b.key
        end)
    end

    local out = {}
    for i = 1, limit do
        out[i] = candidates[i]
    end
    return out
end

local function _tick()
    if not running or not _cfg().enabled then return end

    local now = os.clock()
    if (now - lastPoll) < nextPollSec then return end
    lastPoll = now

    local myGen = tickGen
    local function stillLive()
        -- Jangan re-check _cfg().enabled di tengah scan: save/sync globals bisa
        -- flip false sebentar lalu ESP ikut di-clear padahal masih running.
        return running and myGen == tickGen
    end

    pcall(function()
        if not stillLive() then return end

        local plot = _getPlot()
        if not plot then
            if stillLive() then
                _clearPromptCache()
                _clearAllEsp()
            end
            return
        end

        local fsv = _fsv()
        if fsv and type(fsv.refresh) == "function" then
            pcall(fsv.refresh, true)
        end

        if not stillLive() then return end

        local seen = {}
        local topList = _scanGardenCandidates(plot)

        -- Scan berat (max 5000): Stop bisa sudah jalan di tengah — jangan recreate label
        if not stillLive() then return end

        for _, item in ipairs(topList) do
            if not stillLive() then
                _clearAllEsp()
                return
            end
            seen[item.key] = true
            local name = _fruitName(item.fruit)
            if name == "" or name == "?" then name = item.name end
            local kg = item.kg
            if kg <= 0 then
                kg = tonumber(_displayKg(item.fruit, false)) or 0
            end
            local rarity = _fruitRarity(item.fruit, name)
            local mutation = _fruitMutation(item.fruit)
            local price = tonumber(item.price) or 0
            if price <= 0 then
                price = _fruitPrice(item.fruit, name, { allowBillboard = false })
            end
            local rec = _ensureEsp(item.key, item.adornee)
            _setEspText(rec, name, kg, rarity, mutation, price)
        end

        if not stillLive() then
            _clearAllEsp()
            return
        end

        for key in pairs(espByKey) do
            if not seen[key] then
                _destroyEsp(key)
            end
        end

        _refreshSummaryCache()
    end)
end

function M.GetEspSummary()
    if not running then
        return { count = 0, total = 0, active = false }
    end
    return {
        count = summaryCache.count,
        total = summaryCache.total,
        active = true,
    }
end

M.getEspSummary = M.GetEspSummary

-- Total value seluruh buah di plot — independen dari ESP garden.
-- Rumus inti sama ESP: multi + mutation + getBackpackPrice/calculate (TANPA mutation-variant loop).
-- Non-blocking: worker async + GetTagged (tanpa GetDescendants tiap tick).
local gardenValueCache = { count = 0, total = 0, at = 0, ready = false }
local VALUE_LIST_SEC = 5.0
local VALUE_BATCH = 250
local VALUE_BATCH_WAIT = 0

local valueJob = {
    plot = nil,
    list = {},
    idx = 1,
    count = 0,
    total = 0,
    listAt = 0,
    ready = false,
    wanted = false,
    forceList = false,
}
local valueWorker = nil

local function _fruitValueKey(fruit)
    if not fruit then return nil end
    local plantId, fruitId = _resolveIds(fruit)
    if plantId ~= "" then
        return plantId .. "|" .. fruitId
    end
    for _, key in ipairs({ "FruitId", "Id", "id", "UUID", "Uuid" }) do
        local v = fruit:GetAttribute(key)
        if v ~= nil and tostring(v) ~= "" then
            return key .. ":" .. tostring(v)
        end
    end
    return "inst:" .. tostring(fruit)
end

-- Fast + akurat: 1x resolve multi/mut/name + 1x getBackpackPrice (sama input ESP, tanpa loop variant).
local function _priceFruitFast(fruit)
    if not fruit or not fruit.Parent then return 0 end
    local fsv = _fsv()
    if not fsv then return 0 end

    local name = _fruitNameCheap(fruit)
    if name == "" or name == "?" then
        name = _fruitName(fruit)
    end
    name = tostring(name or "")
    if name == "" or name == "?" then return 0 end

    local multi = 0
    do
        local ok, m = pcall(_resolvePriceMulti, fruit)
        if ok then multi = tonumber(m) or 0 end
    end
    if multi <= 0 then return 0 end

    local mut = nil
    if type(fsv.resolveMutation) == "function" then
        local ok, m = pcall(fsv.resolveMutation, fruit)
        if ok then mut = m end
    end
    if mut == nil then
        mut = fruit:GetAttribute("Mutation")
    end

    local decay = fruit:GetAttribute("DecayAlpha")
    local fruitUuid = fruit:GetAttribute("Id")
        or fruit:GetAttribute("id")
        or fruit:GetAttribute("UUID")
        or fruit:GetAttribute("Uuid")
        or fruit:GetAttribute("FruitId")

    if type(fsv.getBackpackPrice) == "function" then
        local ok, p = pcall(fsv.getBackpackPrice, name, multi, mut, fruitUuid, decay)
        if ok and type(p) == "number" and p > 0 then return p end
    end
    if type(fsv.calculate) == "function" then
        local ok, p = pcall(fsv.calculate, name, multi, mut, nil, decay)
        if ok and type(p) == "number" and p > 0 then return p end
    end
    if type(fsv.fromFruit) == "function" then
        local ok, p = pcall(fsv.fromFruit, fruit)
        if ok and type(p) == "number" and p > 0 then return p end
    end
    return 0
end

local function _tryAddGardenFruit(prompt, seenInst, seenKey, list)
    if not prompt or not prompt.Parent then return end
    if not prompt:IsA("ProximityPrompt") then return end
    if prompt:GetAttribute("Collected") then return end
    if not _isHarvestPrompt(prompt) then return end

    local fruit = _fruitFromPrompt(prompt)
    if not fruit or not fruit.Parent then return end
    if seenInst[fruit] then return end

    local key = _fruitValueKey(fruit)
    if key and seenKey[key] then return end

    seenInst[fruit] = true
    if key then seenKey[key] = true end
    list[#list + 1] = fruit
end

-- Ringan: hanya HarvestPrompt tag + promptCache yang sudah ada (NO GetDescendants).
local function _collectGardenFruitList(plot)
    local list = {}
    if not plot or not plot.Parent then return list end

    local seenInst, seenKey = {}, {}

    if promptPlot == plot then
        for i = 1, #promptCache do
            local prompt = promptCache[i]
            if prompt and promptSet[prompt] then
                _tryAddGardenFruit(prompt, seenInst, seenKey, list)
            end
        end
    end

    local okTag, tagged = pcall(function()
        return CollectionService:GetTagged(HARVEST_TAG)
    end)
    if okTag and type(tagged) == "table" then
        for i = 1, #tagged do
            local prompt = tagged[i]
            if prompt and prompt:IsDescendantOf(plot) then
                _tryAddGardenFruit(prompt, seenInst, seenKey, list)
            end
        end
    end

    return list
end

local function _resetValueJobEmpty()
    valueJob.plot = nil
    valueJob.list = {}
    valueJob.idx = 1
    valueJob.count = 0
    valueJob.total = 0
    valueJob.ready = true
    gardenValueCache.count = 0
    gardenValueCache.total = 0
    gardenValueCache.ready = true
    gardenValueCache.at = os.clock()
end

local function _valueWorkerLoop()
    while valueWorker ~= nil do
        if not valueJob.wanted then
            task.wait(0.25)
            continue
        end

        local plot = _getPlot()
        if not plot then
            _resetValueJobEmpty()
            valueJob.wanted = false
            task.wait(0.5)
            continue
        end

        local now = os.clock()
        local needList = valueJob.forceList
            or valueJob.plot ~= plot
            or (now - (valueJob.listAt or 0)) >= VALUE_LIST_SEC
            or (#valueJob.list == 0 and not valueJob.ready)

        if needList then
            valueJob.forceList = false
            local fsv = _fsv()
            if fsv and type(fsv.refresh) == "function" then
                pcall(fsv.refresh, true)
            end
            valueJob.plot = plot
            valueJob.list = _collectGardenFruitList(plot)
            valueJob.count = #valueJob.list
            valueJob.idx = 1
            valueJob.total = 0
            valueJob.listAt = os.clock()
            valueJob.ready = (valueJob.count == 0)
            gardenValueCache.count = valueJob.count
            -- Jangan nol-kan total lama; biar label tidak loncat ke 0 saat rescan
            if valueJob.ready then
                gardenValueCache.total = 0
                gardenValueCache.ready = true
            else
                gardenValueCache.ready = false
            end
            task.wait()
            continue
        end

        local list = valueJob.list
        local n = #list
        if n <= 0 or valueJob.idx > n then
            valueJob.ready = true
            gardenValueCache.count = n
            gardenValueCache.total = valueJob.total
            gardenValueCache.ready = true
            gardenValueCache.at = os.clock()
            task.wait(0.4)
            continue
        end

        local from = valueJob.idx
        local to = math.min(from + VALUE_BATCH - 1, n)
        local sum = valueJob.total
        for i = from, to do
            local fruit = list[i]
            if fruit and fruit.Parent then
                sum += _priceFruitFast(fruit)
            end
        end
        valueJob.total = sum
        valueJob.idx = to + 1

        gardenValueCache.count = n
        local finished = (valueJob.idx > n)
        if finished or gardenValueCache.total <= 0 or sum >= gardenValueCache.total then
            gardenValueCache.total = sum
        end
        gardenValueCache.ready = finished
        valueJob.ready = finished
        gardenValueCache.at = os.clock()
        task.wait(VALUE_BATCH_WAIT)
    end
end

local function _ensureValueWorker()
    if valueWorker ~= nil then return end
    valueWorker = true
    task.spawn(function()
        local ok, err = pcall(_valueWorkerLoop)
        valueWorker = nil
        if not ok then
            warn("[EspFruitGarden] value worker:", err)
        end
    end)
end

function M.PeekGardenValue()
    return {
        count = gardenValueCache.count,
        total = gardenValueCache.total,
        ready = gardenValueCache.ready == true,
    }
end

M.peekGardenValue = M.PeekGardenValue

-- Non-blocking: hanya minta worker + kembalikan cache.
function M.ComputeGardenValue(a, b)
    local force = a
    if type(a) == "table" then
        force = b
    end
    force = (force == true)

    valueJob.wanted = true
    if force then
        valueJob.forceList = true
    end
    _ensureValueWorker()
    return M.PeekGardenValue()
end

M.computeGardenValue = M.ComputeGardenValue

function M.SummarizeUnharvested()
    return M.ComputeGardenValue()
end

function M.SetEnabled(a, b)
    -- Support both SetEnabled(true) and SetEnabled(self, true)
    local on = a
    if type(a) == "table" then
        on = b
    end
    on = (on == true)
    G.FRUIT_GARDEN_ESP_ENABLED = on
    _G.FRUIT_GARDEN_ESP_ENABLED = on
    if on then M.Start() else M.Stop() end
end

function M.IsEnabled()
    return running
end

function M.Start()
    if running then return true end
    tickGen += 1
    running = true
    G.FRUIT_GARDEN_ESP_ENABLED = true
    _G.FRUIT_GARDEN_ESP_ENABLED = true
    cachedPlot = nil
    cachedPlotAt = 0
    lastPoll = 0
    nextPollSec = POLL_SEC_LIGHT
    lastFruitCount = 0
    _clearPromptCache()
    local fsv = _fsv()
    if fsv and type(fsv.refresh) == "function" then
        pcall(fsv.refresh, true)
    end
    if conn then conn:Disconnect() end
    conn = RunService.Heartbeat:Connect(_tick)
    return true
end

function M.Stop()
    tickGen += 1
    running = false
    if conn then
        conn:Disconnect()
        conn = nil
    end
    cachedPlot = nil
    cachedPlotAt = 0
    lastFruitCount = 0
    nextPollSec = POLL_SEC_LIGHT
    _clearPromptCache()
    G.FRUIT_GARDEN_ESP_ENABLED = false
    _G.FRUIT_GARDEN_ESP_ENABLED = false
    _clearAllEsp()
    _resetSummaryCache()
end

function M.SyncFromGlobals()
    local cfg = _cfg()
    G.FRUIT_GARDEN_ESP_ENABLED = cfg.enabled
    _G.FRUIT_GARDEN_ESP_ENABLED = cfg.enabled
    if cfg.enabled then M.Start() else M.Stop() end
    return cfg
end

G.EspFruitGarden = M
_G.EspFruitGarden = M

return M
 end,                 required = false },
