local function loadBuyPetTargets()
    local SectionBuyPet = getSectionBuyPet()
    local G = getG()
    local MAIN = G.MAIN or rawget(_G, "MAIN")

    local raw = nil
    local store = G.__GAG2_BUY_PET or rawget(_G, "__GAG2_BUY_PET")
    if type(store) == "table" and type(store.targets) == "table" and #store.targets > 0 then
        raw = store.targets
    end
    if not raw or #raw == 0 then
        raw = G.BUY_PET_TARGETS or rawget(_G, "BUY_PET_TARGETS")
    end
    if (not raw or #raw == 0) and type(MAIN) == "table"
        and type(MAIN.auto) == "table"
        and type(MAIN.auto.buy) == "table"
        and type(MAIN.auto.buy.pet) == "table"
        and type(MAIN.auto.buy.pet.targets) == "table"
    then
        raw = MAIN.auto.buy.pet.targets
    end

    if type(SectionBuyPet) == "table" then
        if type(SectionBuyPet.deserializeTargets) == "function" then
            raw = SectionBuyPet.deserializeTargets(raw or {})
        end
        if type(SectionBuyPet.normalizeTargets) == "function" then
            return SectionBuyPet.normalizeTargets(raw or {})
        end
    end
    return type(raw) == "table" and raw or {}
end

local function getPetTierRank(petName)
    petName = tostring(petName or "")
    if petName == "" then return 0 end
    local PLV = getPetListView()
    if type(PLV) == "table" and type(PLV.getPetRarity) == "function" then
        local rarity = PLV.getPetRarity(petName)
        if rarity and tostring(rarity) ~= "" then
            return getRarityRank(rarity)
        end
    end
    return 0
end

local function sortBuyPetTargetsByRarity(targets)
    if type(targets) ~= "table" or #targets <= 1 then return targets end
    local sorted = {}
    for i, t in ipairs(targets) do
        sorted[i] = t
    end
    table.sort(sorted, function(a, b)
        local ra = getPetTierRank(a and a.pet)
        local rb = getPetTierRank(b and b.pet)
        if ra ~= rb then return ra > rb end
        return tostring(a and a.pet or ""):lower() < tostring(b and b.pet or ""):lower()
    end)
    return sorted
end

local function buyPetTargetsFingerprint(targets)
    if type(targets) ~= "table" or #targets == 0 then return "" end
    local chunks = {}
    for _, rule in ipairs(targets) do
        if type(rule) == "table" then
            local types = mapToArray(rule.types or {})
            local sizes = mapToArray(rule.sizes or {})
            chunks[#chunks + 1] = string.format(
                "%s:%s:%s:%s:%s:%s",
                tostring(rule.pet or ""),
                rule.enabled and "1" or "0",
                table.concat(types, ","),
                table.concat(sizes, ","),
                rule.steal == true and "1" or "0",
                tostring(rule.max_steal or rule.max_steal_mult or "")
            )
        end
    end
    table.sort(chunks)
    return table.concat(chunks, "|")
end

