            if not seen[k] then
                seen[k] = true
                names[#names + 1] = n
            end
        end
    end
    table.sort(names)
    return names
end

local function buildListFetchFilters(overrideFilters)
    local filters = overrideFilters
    if type(filters) ~= "table" then
        filters = {
            place_id = game.PlaceId,
            limit = LIST_FETCH_LIMIT,
        }
    end
    if overrideFilters == nil and _cfg.auto_hop and countBuyPetTargets() > 0 then
        filters.pet_names = buyPetTargetNames()
    end
    return filters
end

local function refreshLocalScanIfNeeded(force)
    if not force and HOP_SKIP_PRE_SCAN then
        if (os.clock() - _lastHopLocalScanAt) < HOP_LOCAL_SCAN_INTERVAL_SEC then
            return
        end
    end
    _lastHopLocalScanAt = os.clock()
    M.Scan()
end

local function getPetTypeItems()
    local PLV = getPetListView()
    if type(PLV) == "table" and type(PLV.buildPetItems) == "function" then
        return PLV.buildPetItems() or {}
    end
    return {}
end

local function buildPetAliasLookup()
    local lookup = {}
    for _, item in ipairs(getPetTypeItems()) do
        local key = tostring(item.key or item.name or "")
        if key ~= "" then
            lookup[normalizePetKey(key)] = key
            local display = tostring(item.name or "")
            if display ~= "" then
                lookup[normalizePetKey(display)] = key
            end
        end
    end
    return lookup
end

local function resolvePetCanonicalName(petName, aliasLookup)
    petName = tostring(petName or "")
    if petName == "" then return "" end
    aliasLookup = aliasLookup or buildPetAliasLookup()
    return aliasLookup[normalizePetKey(petName)] or petName
end

local function isSameServerJob(jobId)
    jobId = tostring(jobId or ""):gsub("%s+", "")
    if jobId == "" then return true end
    return jobId:lower() == tostring(game.JobId):lower()
end

local function getSheckles()
    local v = tonumber(LP:GetAttribute("Sheckles"))
    if type(v) == "number" then return v end

    local ls = LP:FindFirstChild("leaderstats")
    if ls then
        for _, name in ipairs({ "Sheckles", "Money", "Cash", "Coins" }) do
            local obj = ls:FindFirstChild(name)
            if obj and (obj:IsA("IntValue") or obj:IsA("NumberValue")) then
                return tonumber(obj.Value)
            end
        end
    end

    return nil
end

local function canAffordPrice(price)
    price = tonumber(price)
    if not price or price <= 0 then return true end
    local money = getSheckles()
    if type(money) ~= "number" then return true end
    return money >= price
end

local function markAvoidJob(jobId, ttlSec)
    jobId = tostring(jobId or ""):lower():gsub("%s+", "")
    if jobId == "" then return end
    _avoidJobs[jobId] = os.clock() + math.max(5, tonumber(ttlSec) or AVOID_JOB_TTL_FULL)
end

local function isAvoidedJob(jobId)
    jobId = tostring(jobId or ""):lower():gsub("%s+", "")
    local untilAt = _avoidJobs[jobId]
    if not untilAt then return false end
    if os.clock() >= untilAt then
        _avoidJobs[jobId] = nil
        return false
    end
    return true
end

local function classifyTeleportFail(result, errMsg)
    local msg = string.lower(tostring(errMsg or ""))
    local r = string.lower(tostring(result or ""))
    if r:find("unauthorized", 1, true)
        or msg:find("private instance", 1, true)
        or msg:find("specific joins", 1, true)
        or msg:find("not authorized", 1, true)
        or msg:find("restricted", 1, true)
        or msg:find("private", 1, true)
    then
        return "private", AVOID_JOB_TTL_DEAD
    end
    if msg:find("gameended", 1, true)
        or msg:find("game full", 1, true)
        or msg:find("could not find requested game instance", 1, true)
        or msg:find("requested game instance", 1, true)
        or msg:find("instance has shutdown", 1, true)
    then
        return "dead_or_full", AVOID_JOB_TTL_DEAD
    end
    if r:find("isteleporting", 1, true)
        or msg:find("previous teleport", 1, true)
        or msg:find("in processing", 1, true)
    then
        return "busy", AVOID_JOB_TTL_BUSY
    end
    return "other", AVOID_JOB_TTL_FULL
end

local function shortJobId(jobId)
    jobId = tostring(jobId or ""):gsub("%s+", "")
    if jobId == "" then return "?" end
    if #jobId > 8 then return jobId:sub(1, 8) .. "…" end
    return jobId
end

local function describeTeleportFail(result, errMsg)
    local kind = classifyTeleportFail(result, errMsg)
    local msg = string.lower(tostring(errMsg or ""))
    if kind == "private" then
        return "Private server", "Can't join this server (private/restricted)"
    end
    if kind == "dead_or_full" then
        if msg:find("full", 1, true) then
            return "Server full", tostring(errMsg or "Game full")
        end
        if msg:find("gameended", 1, true) or msg:find("shutdown", 1, true) then
            return "Server ended", tostring(errMsg or "Game ended")
        end
        if msg:find("could not find", 1, true) or msg:find("requested game instance", 1, true) then
            return "Server not found", tostring(errMsg or "Instance gone")
        end
        return "Server unavailable", tostring(errMsg or "Dead/full")
    end
    if kind == "busy" then
        return "Teleport busy", tostring(errMsg or "Previous teleport in progress")
    end
    return "Teleport failed", tostring(errMsg or tostring(result or "Unknown error"))
end

local function describeHopError(code, rawMsg)
    code = tostring(code or "")
    rawMsg = tostring(rawMsg or "")
    if code == "insufficient_sheckles" then
        return "Not enough sheckles", rawMsg ~= "" and rawMsg or code
    end
    if code == "already on server" then
        return "Already on this server", rawMsg ~= "" and rawMsg or code
    end
    if code == "server_avoided" then
        return "Server skipped (recent fail)", rawMsg ~= "" and rawMsg or code
    end
    if code == "job_id empty" then
        return "Invalid server ID", rawMsg ~= "" and rawMsg or code
    end
    if rawMsg ~= "" and rawMsg ~= code then
        return describeTeleportFail("", rawMsg)
    end
    if code ~= "" then
        return "Hop failed", code
    end
    return "Hop failed", "unknown"
end

local function setHopUiStatus(phase, opts)
    opts = type(opts) == "table" and opts or {}
    _hopUi.phase = tostring(phase or "idle")
    if opts.petName ~= nil then _hopUi.petName = tostring(opts.petName) end
    if opts.rarity ~= nil then _hopUi.rarity = tostring(opts.rarity) end
    if opts.jobId ~= nil then _hopUi.jobId = tostring(opts.jobId) end
    if opts.price ~= nil then _hopUi.price = tonumber(opts.price) or 0 end
    if opts.timeLeft ~= nil then _hopUi.timeLeft = tostring(opts.timeLeft) end
    if opts.failTitle ~= nil then _hopUi.failTitle = tostring(opts.failTitle) end
    if opts.failDetail ~= nil then _hopUi.failDetail = tostring(opts.failDetail) end
    _hopUi.updatedAt = os.clock()
    M._notifyUiHop()
end

function M.GetHopUiStatus()
    return {
        phase = _hopUi.phase,
        petName = _hopUi.petName,
        rarity = _hopUi.rarity,
        jobId = _hopUi.jobId,
        price = _hopUi.price,
        timeLeft = _hopUi.timeLeft,
        failTitle = _hopUi.failTitle,
        failDetail = _hopUi.failDetail,
        updatedAt = _hopUi.updatedAt,
        inFlight = (_hopInFlight == true),
    }
end

local function prepareForHopTeleport()
    local G = getG()
    local PR = rawget(_G, "PSReconnect") or G.PSReconnect
    if type(PR) == "table" and type(PR.ReleaseHopTeleportLock) == "function" then
        pcall(PR.ReleaseHopTeleportLock, PR)
    end
    local AH = G.AutoHopServer or G.AutoHopServerModule or rawget(_G, "AutoHopServer")
    if type(AH) == "table" and type(AH.ReleaseTeleportLock) == "function" then
        pcall(AH.ReleaseTeleportLock, AH)
    end
end

local function invokeHopTeleport(placeId, jobId, td)
    prepareForHopTeleport()
    placeId = tonumber(placeId) or game.PlaceId
    jobId = tostring(jobId or ""):gsub("%s+", "")

    local okLegacy, errLegacy = pcall(function()
        TeleportService:TeleportToPlaceInstance(placeId, jobId, LP, "", td)
    end)
    if okLegacy then
        return true, "teleport_to_place_instance"
    end

    local opts = Instance.new("TeleportOptions")
    pcall(function() opts:SetTeleportData(td) end)
    pcall(function() opts.ServerInstanceId = jobId end)

    local okAsync, errAsync = pcall(function()
        TeleportService:TeleportAsync(placeId, { LP }, opts)
    end)
    if okAsync then
        return true, "teleport_async"
    end

    return false, tostring(errLegacy or errAsync)
end

local function clearHopBurstTried()
    _hopBurstTried = {}
end

local function markHopBurstTried(jobId)
    jobId = tostring(jobId or ""):lower():gsub("%s+", "")
    if jobId ~= "" then
        _hopBurstTried[jobId] = true
    end
end

local function isHopBurstTried(jobId)
    jobId = tostring(jobId or ""):lower():gsub("%s+", "")
    return jobId ~= "" and _hopBurstTried[jobId] == true
end

local function scheduleAutoHopRetry(delaySec)
    delaySec = tonumber(delaySec) or 0
    _lastAutoHopAt = os.clock() - AUTO_HOP_COOLDOWN_SEC
    local function runRetry()
        M.tryAutoHopBurst(true, HOP_BURST_MAX)
    end
    if delaySec <= 0 then
        task.defer(runRetry)
        return
    end
    task.delay(delaySec, function()
        if _cfg.auto_hop then
            runRetry()
        end
    end)
end

local function startHopWatchdog(attemptJobId, fromJobId)
    attemptJobId = tostring(attemptJobId or ""):lower():gsub("%s+", "")
    fromJobId = tostring(fromJobId or "")
    if attemptJobId == "" then return end

    _hopWatchdogToken += 1
    local token = _hopWatchdogToken
    task.delay(HOP_WATCHDOG_SEC, function()
        if token ~= _hopWatchdogToken then return end
        if _pendingHopJobId == "" then return end
        if tostring(_pendingHopJobId):lower() ~= attemptJobId then return end
        if tostring(game.JobId or "") ~= fromJobId then return end

        markAvoidJob(attemptJobId, AVOID_JOB_TTL_DEAD)
        markHopBurstTried(attemptJobId)
        _hopInFlight = false
        _pendingHopJobId = ""
        setHopUiStatus("failed", {
            jobId = attemptJobId,
            failTitle = "Hop timeout",
            failDetail = "Trying next server…",
        })

        if _cfg.auto_hop then
            scheduleAutoHopRetry(0)
        end
    end)
end

function M.ensureTeleportFailHook()
    if _tpFailConn then return end
    _tpFailConn = TeleportService.TeleportInitFailed:Connect(function(player, result, errMsg)
        if LP and player ~= LP then return end

        local failedJob = _pendingHopJobId
        if failedJob == "" then return end

        local kind, ttl = classifyTeleportFail(result, errMsg)

        _hopWatchdogToken += 1
        _hopInFlight = false
        _pendingHopJobId = ""

        markAvoidJob(failedJob, ttl)

        local failTitle, failDetail = describeTeleportFail(result, errMsg)
        setHopUiStatus("failed", {
            jobId = failedJob,
            failTitle = failTitle,
            failDetail = failDetail,
        })

        if _cfg.auto_hop then
            if kind == "busy" then
                _teleportBusyUntil = os.clock() + HOP_BUSY_RETRY_SEC
                scheduleAutoHopRetry(HOP_BUSY_RETRY_SEC)
            else
                scheduleAutoHopRetry(0)
            end
        end
    end)
end

local function countSelectedRarities(map)
    return countSelected(map)
end

local function passesRarityFilter(row)
    local selected = _cfg.filter_rarities
    if countSelectedRarities(selected) <= 0 then
        return true
    end
    local rarity = tostring(row.rarity or "")
    return selected[rarity] == true
end

local function getMinSyncRarityRank()
    for _, name in ipairs({ SYNC_MIN_RARITY, "Rare", "RARE", "rare" }) do
        local r = getRarityRank(name)
        if r > 0 then return r end
    end
    return FALLBACK_RARITY_RANK.rare or 3
end

function M.rebuildDisplayList()
    local rows = {}
    for _, row in ipairs(_lastListRaw or {}) do
        if passesRarityFilter(row) then
            rows[#rows + 1] = row
        end
    end

    table.sort(rows, compareDisplayListRows)

    if LIST_LIMIT > 0 and #rows > LIST_LIMIT then
        local trimmed = {}
        for i = 1, LIST_LIMIT do
            trimmed[i] = rows[i]
        end
        rows = trimmed
    end

    _lastList = rows
end

local function getRequestFn()
    return (syn and syn.request)
        or (http and http.request)
        or http_request
        or (fluxus and fluxus.request)
        or request
end

local function buildHeaders()
    local h = {
        ["Content-Type"] = "application/json",
        ["Accept"] = "application/json",
    }
    if DEFAULT_API_KEY ~= "" then
        h["X-Api-Key"] = DEFAULT_API_KEY
    end
    return h
end

local function apiUrl()
    return tostring(DEFAULT_API_BASE):gsub("/+$", "") .. "/pet_finder_api.php"
end

local function stripNil(tbl)
    local out = {}
    for k, v in pairs(tbl) do
        if v ~= nil then
            out[k] = v
        end
    end
    return out
end

local function syncUrl()
    return apiUrl()
end

local function listUrl()
    return apiUrl()
end

local function gameNow()
    local ok, t = pcall(function()
        return workspace:GetServerTimeNow()
    end)
    if ok and type(t) == "number" then
        return math.floor(t)
    end
    return os.time()
end

local function computeSecondsLeft(row)
    if type(row) ~= "table" then return 0 end
    local expiresAt = tonumber(row.expires_at) or 0
    if expiresAt > 0 then
        return math.max(0, expiresAt - gameNow())
    end
    return math.max(0, math.ceil(tonumber(row.seconds_left) or 0))
end

local function fmtTimeLeft(secondsLeft)
    secondsLeft = math.max(0, math.ceil(tonumber(secondsLeft) or 0))
    if secondsLeft >= 3600 then
        return string.format("%dh %dm", math.floor(secondsLeft / 3600), math.floor((secondsLeft % 3600) / 60))
    end
    if secondsLeft >= 60 then
        return string.format("%dm %ds", math.floor(secondsLeft / 60), secondsLeft % 60)
    end
    return string.format("%ds", secondsLeft)
end

local function fmtPlayerCount(n)
    n = tonumber(n)
    if n == nil then return "" end
    return string.format("%d ply", math.floor(n))
end

local function fmtScannedAgo(row)
    row = type(row) == "table" and row or {}
    local scannedAt = tonumber(row.scanned_at)
    if (not scannedAt or scannedAt <= 0) and row.scanned_ago ~= nil then
        local ago = math.max(0, math.ceil(tonumber(row.scanned_ago) or 0))
        if ago <= 0 then return "" end
        return "scan " .. fmtTimeLeft(ago) .. " ago"
    end
    if not scannedAt or scannedAt <= 0 then
        return ""
    end
    local ago = math.max(0, gameNow() - scannedAt)
    if ago <= 0 then return "scan now" end
    return "scan " .. fmtTimeLeft(ago) .. " ago"
end

local function fmtListMeta(row, secLeft, spawnId, jobShort)
    local parts = {
        string.format("#%s", spawnId),
        fmtTimeLeft(secLeft) .. " left",
    }
    local ply = fmtPlayerCount(row.player_count)
    if ply ~= "" then
        parts[#parts + 1] = ply
    end
    local scanned = fmtScannedAgo(row)
    if scanned ~= "" then
        parts[#parts + 1] = scanned
    end
    parts[#parts + 1] = "srv " .. jobShort .. "…"
    return table.concat(parts, " · ")
end

local function hopMetaFromRow(row)
    row = type(row) == "table" and row or {}
    local secLeft = computeSecondsLeft(row)
    return {
        petName = tostring(row.pet_name or "?"),
        rarity = tostring(row.rarity or "?"),
        jobId = tostring(row.job_id or ""),
        price = tonumber(row.price) or 0,
        timeLeft = secLeft and fmtTimeLeft(secLeft) or "",
        playerCount = tonumber(row.player_count),
        scannedAgo = fmtScannedAgo(row),
    }
end

local function fmtPrice(n)
    n = math.floor(tonumber(n) or 0)
    local negative = n < 0
    local s = tostring(math.abs(n))
    while true do
        local k
        s, k = s:gsub("^(%d+)(%d%d%d)", "%1,%2")
        if k == 0 then break end
    end
    if negative then s = "-" .. s end
    return s
end

local function attr(inst, key, default)
    if not inst then return default end
    local v = inst:GetAttribute(key)
    if v == nil then return default end
    return v
end

local function num(v, default)
    v = tonumber(v)
    if v == nil then return default end
    return v
end

local function str(v, default)
    if v == nil then return default end
    v = tostring(v)
    if v == "" then return default end
    return v
end

local SharedData  = RS:FindFirstChild("SharedData")
local PetTypesMod = SharedData and SharedData:FindFirstChild("PetTypes")
local PetTypes    = PetTypesMod and PetTypesMod:IsA("ModuleScript") and (function()
    local ok, mod = pcall(require, PetTypesMod)
    return ok and mod or nil
end)() or nil

local function extractUuid(refName)
    refName = tostring(refName or "")
    local uuid = refName:match("(%x%x%x%x%x%x%x%x%-%x%x%x%x%-%x%x%x%x%-%x%x%x%x%-%x%x%x%x%x%x%x%x%x%x%x%x)$")
    return uuid or refName
end

local function resolvePetType(raw)
    local SectionBuyPet = getSectionBuyPet()
    if type(SectionBuyPet) == "table" and type(SectionBuyPet.resolvePetTypeRaw) == "function" then
        return SectionBuyPet.resolvePetTypeRaw(raw)
    end
    if raw == nil then return "Normal" end
    if type(raw) == "string" and raw ~= "" then return raw end
    if type(raw) == "number" and PetTypes then
        for name, val in pairs(PetTypes) do
            if val == raw then return name end
        end
    end
    return tostring(raw)
end

local PetSizesCache = nil
local function getPetSizes()
    if PetSizesCache then return PetSizesCache end
    local sd = RS:FindFirstChild("SharedData")
    local ps = sd and sd:FindFirstChild("PetSizes")
    if ps and ps:IsA("ModuleScript") then
        local ok, mod = pcall(require, ps)
        if ok and type(mod) == "table" then PetSizesCache = mod end
    end
    return PetSizesCache
end

local function resolvePetSize(raw)
    if raw == nil then return "Normal" end
    if type(raw) == "string" and raw ~= "" then return raw end
    if type(raw) == "number" then
        local petSizes = getPetSizes()
        if petSizes then
            for name, val in pairs(petSizes) do
                if val == raw then return name end
            end
        end
    end
    return tostring(raw)
end

-- Priority tampilan list: Huge > Big > Rainbow > Normal (lalu rarity, price, expiry)
local TRAIT_LIST_PRIORITY = {
    huge = 3,
    big = 2,
    rainbow = 1,
}

local function traitListPriorityFromRaw(raw, resolver)
    local k = normalizePetKey(resolver(raw))
    return TRAIT_LIST_PRIORITY[k] or 0
end

local function rowTraitListPriority(row)
    if type(row) ~= "table" then return 0 end
    local typeRaw = row.pet_type_raw
    if typeRaw == nil then typeRaw = row.pet_type end
    local sizeRaw = row.pet_size_raw
    if sizeRaw == nil then sizeRaw = row.pet_size end
    return math.max(
        traitListPriorityFromRaw(typeRaw, resolvePetType),
        traitListPriorityFromRaw(sizeRaw, resolvePetSize)
    )
end

compareDisplayListRows = function(a, b)
    local ta = rowTraitListPriority(a)
    local tb = rowTraitListPriority(b)
    if ta ~= tb then return ta > tb end
    local ra = getRarityRank(a.rarity)
    local rb = getRarityRank(b.rarity)
    if ra ~= rb then return ra > rb end
    local pa = tonumber(a.price) or 0
    local pb = tonumber(b.price) or 0
    if pa ~= pb then return pa > pb end
    local ea = tonumber(a.expires_at) or 0
    local eb = tonumber(b.expires_at) or 0
    return ea < eb
end

-- Sync ke API/DB: Rare+ semua; di bawah Rare hanya variant/size non-Normal (NULL di DB = Normal).
local function isNormalTrait(value)
    local v = normalizePetKey(value or "")
    return v == "" or v == "normal"
end

local function syncDbTrait(raw, resolver)
    local resolved = resolver(raw)
    if isNormalTrait(resolved) then return nil end
    return resolved
end

local function syncDbPetType(row)
    if type(row) ~= "table" then return nil end
    local raw = row.pet_type_raw
    if raw == nil then raw = row.pet_type end
    return syncDbTrait(raw, resolvePetType)
end

local function syncDbPetSize(row)
    if type(row) ~= "table" then return nil end
    local raw = row.pet_size_raw
    if raw == nil then raw = row.pet_size end
    return syncDbTrait(raw, resolvePetSize)
end

local function hasNonNormalVariantOrSize(row)
    return syncDbPetType(row) ~= nil or syncDbPetSize(row) ~= nil
end

local function passesSyncRarityFilter(row)
    local minRank = getMinSyncRarityRank()
    local rank = getRarityRank(row and row.rarity)
    if rank >= minRank then
        return true
    end
    return hasNonNormalVariantOrSize(row)
end

local function chipStyleForVariant(name)
    local k = normalizePetKey(name)
    if k == "rainbow" then
        return Color3.fromRGB(120, 55, 190), Color3.fromRGB(250, 230, 255)
    end
    if k == "any" or k == "normal" then
        return Color3.fromRGB(38, 40, 48), Color3.fromRGB(150, 155, 170)
    end
    return Color3.fromRGB(45, 95, 170), Color3.fromRGB(220, 235, 255)
end

local function chipStyleForSize(name)
    local k = normalizePetKey(name)
    if k == "huge" then
        return Color3.fromRGB(210, 130, 20), Color3.fromRGB(255, 245, 210)
    end
    if k == "big" then
        return Color3.fromRGB(35, 110, 210), Color3.fromRGB(220, 240, 255)
    end
    return Color3.fromRGB(38, 40, 48), Color3.fromRGB(150, 155, 170)
end

local function addListTraitChip(parent, text, bg, fg, order)
    local chip = Instance.new("TextLabel")
    chip.Name = "Chip_" .. tostring(text)
    chip.BackgroundColor3 = bg
    chip.BorderSizePixel = 0
    chip.AutomaticSize = Enum.AutomaticSize.X
    chip.Size = UDim2.fromOffset(0, 14)
    chip.Font = Enum.Font.GothamBold
    chip.TextSize = 8
    chip.TextColor3 = fg
    chip.Text = tostring(text):upper()
    chip.LayoutOrder = order
    chip.Parent = parent
    Instance.new("UICorner", chip).CornerRadius = UDim.new(0, 4)

    local chipPad = Instance.new("UIPadding")
    chipPad.PaddingLeft = UDim.new(0, 4)
    chipPad.PaddingRight = UDim.new(0, 4)
    chipPad.Parent = chip

    local chipStroke = Instance.new("UIStroke")
    chipStroke.Color = fg
    chipStroke.Transparency = 0.75
    chipStroke.Thickness = 1
    chipStroke.Parent = chip
end

local function updateListTraitChips(card, row)
    local frame = card.traitChips
    if not frame then return end
    for _, child in ipairs(frame:GetChildren()) do
        if child:IsA("TextLabel") then
            child:Destroy()
        end
    end

    local order = 0
    local pType = syncDbPetType(row)
    if pType then
        order += 1
        local bg, fg = chipStyleForVariant(pType)
        addListTraitChip(frame, pType, bg, fg, order)
    end
    local pSize = syncDbPetSize(row)
    if pSize then
        order += 1
        local bg, fg = chipStyleForSize(pSize)
        addListTraitChip(frame, pSize, bg, fg, order)
    end
    frame.Visible = order > 0
end

local function mapMatchesRowValue(refValue, allowedMap)
    if type(allowedMap) ~= "table" or not next(allowedMap) then return true end
    local canonRef = normalizePetKey(refValue or "Normal")
    if canonRef == "" then canonRef = "normal" end
    for k, v in pairs(allowedMap) do
        if v == true and normalizePetKey(k) == canonRef then return true end
    end
    return false
end

local function petNameMatchesRule(rulePet, rowPetName, aliasLookup)
    rulePet = tostring(rulePet or "")
    rowPetName = tostring(rowPetName or "")
    if rulePet == "" or rowPetName == "" then return false end
    local canonical = resolvePetCanonicalName(rowPetName, aliasLookup)
    if normalizePetKey(rulePet) == normalizePetKey(canonical) then return true end
    return normalizePetKey(rulePet) == normalizePetKey(rowPetName)
end

local function rowHasVariantSizeData(row)
    if type(row) ~= "table" then return false end
    return row.pet_type_raw ~= nil
        or row.pet_size_raw ~= nil
        or row.pet_type ~= nil
        or row.pet_size ~= nil
end

local function rowMatchesBuyPetRule(row, rule, aliasLookup)
    if type(rule) ~= "table" or type(row) ~= "table" then return false end
    if rule.enabled ~= true then return false end
    if not petNameMatchesRule(rule.pet, row.pet_name, aliasLookup) then return false end

    local needsType = type(rule.types) == "table" and next(rule.types)
    local needsSize = type(rule.sizes) == "table" and next(rule.sizes)
    if (needsType or needsSize) and not rowHasVariantSizeData(row) then
        return false
    end

    local SectionBuyPet = getSectionBuyPet()
    local typeRaw = row.pet_type_raw
    if typeRaw == nil then typeRaw = row.pet_type end
    local sizeRaw = row.pet_size_raw
    if sizeRaw == nil then sizeRaw = row.pet_size end

    if type(SectionBuyPet) == "table" and type(SectionBuyPet.variantSizeMatchesRule) == "function" then
        if not SectionBuyPet.variantSizeMatchesRule(
            resolvePetType(typeRaw),
            resolvePetSize(sizeRaw),
            rule.types,
            rule.sizes
        ) then
            return false
        end
    else
        if not mapMatchesRowValue(resolvePetType(typeRaw), rule.types) then return false end
        if not mapMatchesRowValue(resolvePetSize(sizeRaw), rule.sizes) then return false end
    end

    return true
end

local function rowMatchesBuyPetTarget(row, aliasLookup)
    if countEnabledBuyPetTargets() <= 0 then return false end
    local rules = loadBuyPetTargets()
    if #rules == 0 then return false end
    aliasLookup = aliasLookup or buildPetAliasLookup()
    for _, rule in ipairs(rules) do
        if rowMatchesBuyPetRule(row, rule, aliasLookup) then return true end
    end
    return false
end

local function getWildRefFolder()
    local map = workspace:FindFirstChild("Map")
    if not map then return nil end
    local ref = map:FindFirstChild("WildPetRef")
    return (ref and ref:IsA("Folder")) and ref or nil
end

local function getWildSpawnsFolder()
    local map = workspace:FindFirstChild("Map")
    if not map then return nil end
    local spawns = map:FindFirstChild("WildPetSpawns")
    return (spawns and spawns:IsA("Folder")) and spawns or nil
end

local function findSpawnModel(refPart, spawnsFolder)
    if not refPart or not spawnsFolder then return nil end
    local refName = refPart.Name
    local petName = attr(refPart, "PetName", "")
    local expect = "WildPet_" .. tostring(petName) .. "_" .. refName
    local direct = spawnsFolder:FindFirstChild(expect)
    if direct then return direct end
    for _, child in ipairs(spawnsFolder:GetChildren()) do
        if child:IsA("Model") and child.Name:find(refName, 1, true) then
            return child
        end
    end
    return nil
end

local function isOwnedBySelf(ownerUserId)
    return type(ownerUserId) == "number" and ownerUserId == LP.UserId
end

local function isOwnedByOther(ownerUserId)
    if ownerUserId == nil or ownerUserId == 0 then return false end
    if type(ownerUserId) ~= "number" then return false end
    return ownerUserId ~= LP.UserId
end

-- Bisa di-tame: belum ada owner (harga normal) ATAU sudah di-claim orang lain (outbid/steal ~2x).
-- Tidak bisa: sudah milik kamu sendiri.
local function canTameWildPet(ownerUserId)
    if isOwnedBySelf(ownerUserId) then return false end
    return true
end

local function isAvailable(ownerUserId)
    return canTameWildPet(ownerUserId)
end

local function isWildPetAlive(pet, now)
    if type(pet) ~= "table" then return false end
    now = now or gameNow()
    local expiresAt = tonumber(pet.expires_at) or 0
    if expiresAt > 0 and expiresAt <= now then return false end
    return true
end

-- Auto hop: stay selama pet target masih ada di WildPetRef (wandering / taming / jalan ke garden).
-- Beda dengan canTameWildPet — setelah kamu beli, owner = kamu tapi ref masih di map.
local function isWildTargetPresent(pet, aliasLookup, now)
    if not rowMatchesBuyPetTarget(pet, aliasLookup) then return false end
    return isWildPetAlive(pet, now)
end

local function getLocalStayTag(pet)
    if type(pet) ~= "table" then return "" end
    if isOwnedBySelf(pet.owner_user_id) then
        local st = string.lower(tostring(pet.state or ""))
        if st:find("garden", 1, true) or st:find("home", 1, true)
            or st:find("walk", 1, true) or st:find("tame", 1, true)
        then
            return " · going to garden"
        end
        return " · taming"
    end
    if pet.steal == true or pet.owned_by_other == true then
        return " · steal 2x"
    end
    return ""
end

local function buildServerMeta()
    return {
        place_id = game.PlaceId,
        game_id = game.GameId,
        job_id = game.JobId,
        player_count = #Players:GetPlayers(),
        scanned_at = gameNow(),
        reporter_user_id = LP.UserId,
        reporter_name = LP.Name,
    }
end

local function scanOneRef(refPart, spawnsFolder, now)
    local petName = str(attr(refPart, "PetName", nil), nil)
    if not petName then return nil end

    local spawnedAt = num(attr(refPart, "SpawnedAt", nil), nil)
    local lifetime = num(attr(refPart, "Lifetime", nil), nil)
    local expiresAt = (spawnedAt and lifetime) and (spawnedAt + lifetime) or nil
    local secondsLeft = expiresAt and (expiresAt - now) or nil
    local pos = refPart.Position
    local ownerUserId = attr(refPart, "OwnerUserId", nil)
    local spawnModel = findSpawnModel(refPart, spawnsFolder)

    local typeRaw = attr(refPart, "PetType", nil)
    local sizeRaw = attr(refPart, "PetSize", nil)

    return {
        spawn_uuid = extractUuid(refPart.Name),
        ref_name = refPart.Name,
        model_name = spawnModel and spawnModel.Name or nil,
        pet_name = petName,
        rarity = str(attr(refPart, "Rarity", nil), nil),
        pet_type_raw = typeRaw,
        pet_size_raw = sizeRaw,
        pet_type = resolvePetType(typeRaw),
        pet_size = resolvePetSize(sizeRaw),
        price = num(attr(refPart, "Price", nil), nil),
        owner_user_id = ownerUserId,
        owned_by_other = isOwnedByOther(ownerUserId),
        steal = isOwnedByOther(ownerUserId),
        available = canTameWildPet(ownerUserId),
        state = str(attr(refPart, "State", nil), nil),
        spawned_at = spawnedAt,
        lifetime = lifetime,
        expires_at = expiresAt,
        seconds_left = secondsLeft,
        time_left_text = secondsLeft and fmtTimeLeft(secondsLeft) or nil,
        pos_x = math.floor(pos.X * 10 + 0.5) / 10,
        pos_y = math.floor(pos.Y * 10 + 0.5) / 10,
        pos_z = math.floor(pos.Z * 10 + 0.5) / 10,
    }
end

function M.Scan()
    local folder = getWildRefFolder()
    local spawns = getWildSpawnsFolder()
    local now = gameNow()
    local pets = {}

    if not folder then
        _lastScan = {
            ok = false,
            error = "WildPetRef folder not found",
            server = buildServerMeta(),
            pets = {},
            count = 0,
        }
        return _lastScan
    end

    for _, child in ipairs(folder:GetChildren()) do
        if child:IsA("BasePart") then
            local rec = scanOneRef(child, spawns, now)
            if rec then
                pets[#pets + 1] = rec
            end
        end
    end

    table.sort(pets, function(a, b)
        local pa, pb = a.price or 0, b.price or 0
        if pa ~= pb then return pa > pb end
        return tostring(a.pet_name) < tostring(b.pet_name)
    end)

    local availableCount = 0
    for _, p in ipairs(pets) do
        if p.available then availableCount += 1 end
    end

    _lastScan = {
        ok = true,
        server = buildServerMeta(),
        pets = pets,
        count = #pets,
        available_count = availableCount,
    }
    return _lastScan
end

function M.findLocalTargetPets()
    if countBuyPetTargets() <= 0 then
        return {}
    end

    local scan = _lastScan
    if not scan or scan.ok ~= true or type(scan.pets) ~= "table" then
        scan = M.Scan()
    end

    local aliasLookup = buildPetAliasLookup()
    local now = gameNow()
    local found = {}

    for _, pet in ipairs(scan.pets or {}) do
        if isWildTargetPresent(pet, aliasLookup, now) then
            found[#found + 1] = pet
        end
    end

    table.sort(found, function(a, b)
        local ra = getRarityRank(a.rarity)
        local rb = getRarityRank(b.rarity)
        if ra ~= rb then return ra > rb end
        local pa = tonumber(a.price) or 0
        local pb = tonumber(b.price) or 0
        if pa ~= pb then return pa > pb end
        local ea = tonumber(a.expires_at) or 0
        local eb = tonumber(b.expires_at) or 0
        return ea < eb
    end)

    return found
end

function M.hasLocalTargetPet()
    local found = M.findLocalTargetPets()
    if #found > 0 then
        return true, found[1], #found
    end
    return false, nil, 0
end

function M.GetLastScan()
    return _lastScan
end

function M.GetLastList()
    return _lastList
end

function M.GetConfig()
    return {
        filter_rarities = cleanSelectedMap(_cfg.filter_rarities),
        auto_refresh_list = (_cfg.auto_refresh_list == true),
        auto_hop = (_cfg.auto_hop == true),
    }
end

local function rowScannedAt(row)
    row = type(row) == "table" and row or {}
    local scannedAt = tonumber(row.scanned_at)
    if scannedAt and scannedAt > 0 then
        return scannedAt
    end
    local ago = tonumber(row.scanned_ago)
    if ago and ago >= 0 then
        return gameNow() - ago
    end
    return 0
end

local function sortAutoHopRows(a, b)
    -- Race mode: laporan paling baru dulu, baru rarity/price.
    local sa = rowScannedAt(a)
    local sb = rowScannedAt(b)
    if sa ~= sb then return sa > sb end
    local ra = getRarityRank(a.rarity)
    local rb = getRarityRank(b.rarity)
    if ra ~= rb then return ra > rb end
    local pa = tonumber(a.price) or 0
    local pb = tonumber(b.price) or 0
    if pa ~= pb then return pa > pb end
    local ea = tonumber(a.expires_at) or 0
    local eb = tonumber(b.expires_at) or 0
    if ea ~= eb then return ea < eb end
    return tostring(a.job_id or "") < tostring(b.job_id or "")
end

local function refreshHopRarityIndex(rows)
    local extras = {}
    local seen = {}
    for _, row in ipairs(rows or {}) do
        local r = tostring(row.rarity or "")
        if r ~= "" and not seen[r] then
            seen[r] = true
            extras[#extras + 1] = r
        end
    end
    if #extras == 0 then return end
    local PLV = getPetListView()
    if type(PLV) == "table" and type(PLV.refreshRarityIndex) == "function" then
        pcall(PLV.refreshRarityIndex, PLV, extras)
    end
end

local function buildAutoHopCandidates()
    if not _cfg.auto_hop or countBuyPetTargets() <= 0 then
        return {}
    end

    local aliasLookup = buildPetAliasLookup()
    local raw = {}

    for _, row in ipairs(_lastListRaw or {}) do
        if rowMatchesBuyPetTarget(row, aliasLookup) and not isSameServerJob(row.job_id) then
            local expiresAt = tonumber(row.expires_at) or 0
            if expiresAt <= 0 or expiresAt > gameNow() then
                raw[#raw + 1] = row
            end
        end
    end

    if #raw == 0 then
        return {}
    end

    refreshHopRarityIndex(raw)

    local bestByJob = {}
    for _, row in ipairs(raw) do
        local jid = tostring(row.job_id or ""):lower():gsub("%s+", "")
        if jid ~= "" then
            local prev = bestByJob[jid]
            if not prev or sortAutoHopRows(row, prev) then
                bestByJob[jid] = row
            end
        end
    end

    local candidates = {}
    for _, row in pairs(bestByJob) do
        candidates[#candidates + 1] = row
    end
    table.sort(candidates, sortAutoHopRows)

    return candidates
end

function M.buildAutoHopCandidates()
    return buildAutoHopCandidates()
end

function M.pickAutoHopTarget()
    local candidates = buildAutoHopCandidates()
    if #candidates == 0 then
        return nil
    end

    for _, row in ipairs(candidates) do
        if not isAvoidedJob(row.job_id)
            and not isHopBurstTried(row.job_id)
            and canAffordPrice(row.price)
        then
            return row
        end
    end

    if next(_hopBurstTried) ~= nil then
        clearHopBurstTried()
        for _, row in ipairs(candidates) do
            if not isAvoidedJob(row.job_id) and canAffordPrice(row.price) then
                return row
            end
        end
    end
    return nil
end

function M.tryAutoHopToRow(target, forceRetry)
    target = type(target) == "table" and target or nil
    if not target then
        return false, "no_match"
    end

    M.ensureTeleportFailHook()
    if not _cfg.auto_hop then
        return false, "disabled"
    end
    if _hopInFlight then
        return false, "in_flight"
    end
    if os.clock() < (_teleportBusyUntil or 0) then
        return false, "teleport_busy"
    end

    local jobId = tostring(target.job_id or "")
    if not forceRetry
        and jobId == _lastAutoHopJobId
        and (os.clock() - _lastAutoHopAt) < AUTO_HOP_SAME_JOB_SEC
    then
        return false, "recent_same_job"
    end

    markHopBurstTried(jobId)
    _hopInFlight = true
    _lastAutoHopAt = os.clock()
    _lastAutoHopJobId = jobId
    _hopStartedAt = os.clock()
    _hopFromJobId = tostring(game.JobId or "")

    local meta = hopMetaFromRow(target)
    setHopUiStatus("match", meta)

    local ok, err = M.HopToJob(jobId, target.place_id, target.price, meta)
    if not ok then
        _hopWatchdogToken += 1
        _pendingHopJobId = ""
        _hopInFlight = false
        local failTitle, failDetail = describeHopError(err, err)
        setHopUiStatus("failed", {
            petName = meta.petName,
            rarity = meta.rarity,
            jobId = jobId,
            price = meta.price,
            timeLeft = meta.timeLeft,
            failTitle = failTitle,
            failDetail = failDetail,
        })
        if err ~= "insufficient_sheckles" then
            markAvoidJob(jobId, AVOID_JOB_TTL_BUSY)
        end
        return false, err
    end

    setHopUiStatus("teleporting", meta)
    return true, target
end

function M.tryAutoHop(forceRetry)
    M.ensureTeleportFailHook()
    if not _cfg.auto_hop then
        return false, "disabled"
    end
    if _hopInFlight then
        return false, "in_flight"
    end
    if os.clock() < (_teleportBusyUntil or 0) then
        return false, "teleport_busy"
    end
    if countBuyPetTargets() <= 0 then
        return false, "no_target_pets"
    end

    if not forceRetry then
        if HOP_SKIP_PRE_SCAN then
            refreshLocalScanIfNeeded(false)
        else
            M.Scan()
        end
    end
    local hasLocal = M.hasLocalTargetPet()
    if hasLocal then
        return false, "local_target_present"
    end

    if not forceRetry and (os.clock() - _lastAutoHopAt) < AUTO_HOP_COOLDOWN_SEC then
        return false, "cooldown"
    end

    local target = M.pickAutoHopTarget()
    if not target then
        return false, "no_match"
    end

    return M.tryAutoHopToRow(target, forceRetry)
end

function M.tryAutoHopBurst(forceRetry, maxChain)
    M.ensureTeleportFailHook()
    if not _cfg.auto_hop then
        return false, "disabled"
    end
    if _hopInFlight then
        return false, "in_flight"
    end
    if os.clock() < (_teleportBusyUntil or 0) then
        return false, "teleport_busy"
    end
    if countBuyPetTargets() <= 0 then
        return false, "no_target_pets"
    end

    if not forceRetry then
        if HOP_SKIP_PRE_SCAN then
            refreshLocalScanIfNeeded(false)
        else
            M.Scan()
        end
    end
    if M.hasLocalTargetPet() then
        return false, "local_target_present"
    end

    if not forceRetry and (os.clock() - _lastAutoHopAt) < AUTO_HOP_COOLDOWN_SEC then
        return false, "cooldown"
    end

    maxChain = math.max(1, math.floor(tonumber(maxChain) or HOP_BURST_MAX))
    local candidates = buildAutoHopCandidates()
    local tries = 0

    for _, row in ipairs(candidates) do
        if tries >= maxChain then
            break
        end
        local jid = tostring(row.job_id or "")
        if isAvoidedJob(jid) or isHopBurstTried(jid) then
            continue
        end
        if not canAffordPrice(row.price) then
            continue
        end

        tries += 1
        local ok, err = M.tryAutoHopToRow(row, forceRetry or tries > 1)
        if ok then
            return true, row
        end
        if err == "in_flight" or err == "teleport_busy" then
            return false, err
        end
        if err == "insufficient_sheckles" or err == "local_target_present"
            or err == "disabled" or err == "no_target_pets"
        then
            return false, err
        end
        forceRetry = true
    end

    if tries == 0 then
        return false, "no_match"
    end
    return false, "chain_exhausted"
end

local function buildDbPayload(fullPayload)
    local pets = {}
    for _, p in ipairs(fullPayload.pets or {}) do
        if p.spawn_uuid and p.pet_name and p.expires_at and passesSyncRarityFilter(p) then
            local entry = {
                spawn_uuid = p.spawn_uuid,
                pet_name = p.pet_name,
                rarity = p.rarity,
                price = p.price,
                lifetime = p.lifetime,
                expires_at = p.expires_at,
            }
            local dbType = syncDbPetType(p)
            local dbSize = syncDbPetSize(p)
            if dbType then entry.pet_type = dbType end
            if dbSize then entry.pet_size = dbSize end
            pets[#pets + 1] = entry
        end
    end
    return {
        server = fullPayload.server,
        pets = pets,
    }
end

local function buildSyncFingerprint(dbPayload)
    dbPayload = type(dbPayload) == "table" and dbPayload or {}
    local parts = {}
    local server = dbPayload.server or {}
    parts[#parts + 1] = tostring(server.job_id or "")

    local pets = dbPayload.pets or {}
    local sorted = {}
    for _, p in ipairs(pets) do
        sorted[#sorted + 1] = p
    end
    table.sort(sorted, function(a, b)
        return tostring(a.spawn_uuid or "") < tostring(b.spawn_uuid or "")
    end)

    for _, p in ipairs(sorted) do
        parts[#parts + 1] = string.format(
            "%s|%s|%s|%s|%s|%s|%s",
            tostring(p.spawn_uuid or ""),
            tostring(p.pet_name or ""),
            tostring(p.pet_type or ""),
            tostring(p.pet_size or ""),
            tostring(p.rarity or ""),
            tostring(p.price or ""),
            tostring(p.expires_at or "")
        )
    end

    return table.concat(parts, "\n")
end

local function decodeHttpJson(text)
    if type(text) == "table" then
        return text
    end
    if type(text) ~= "string" or text == "" then
        return nil
    end
    local ok, parsed = pcall(function()
        return HttpService:JSONDecode(text)
    end)
    if not ok or type(parsed) ~= "table" then
        return nil
    end
    return parsed
end

local function normalizeApiEnvelope(parsed)
    if type(parsed) ~= "table" then
        return nil
    end
    local success = parsed.success
    if success == nil then
        success = parsed.Success
    end
    local messages = parsed.messages
    if messages == nil then
        messages = parsed.Messages
    end
    local data = parsed.data
    if data == nil then
        data = parsed.Data
    end
    return {
        success = success,
        messages = messages,
        data = data,
    }
end

local function extractApiListRows(env)
    if type(env) ~= "table" then
        return nil, "empty response"
    end
    if env.success == false then
        return nil, tostring(env.messages or "API error")
    end
    local data = env.data
    if data == nil then
        return {}, nil
    end
    if type(data) ~= "table" then
        return nil, "data is not a table"
    end
    if data.ok ~= nil and data[1] == nil then
        return nil, "unexpected sync payload in list"
    end
    return data, nil
end

local function httpPost(url, bodyTbl)
    local reqFn = getRequestFn()
    if not reqFn then
        return false, "HTTP request not supported"
    end

    local okJson, body = pcall(function()
        return HttpService:JSONEncode(bodyTbl)
    end)
    if not okJson then
        return false, "JSON encode failed"
    end

    local ok, res = pcall(function()
        return reqFn({
            Url = url,
            Method = "POST",
            Headers = buildHeaders(),
            Body = body,
        })
    end)
    if not ok then
        return false, tostring(res)
    end

    local status = res.StatusCode or res.status or 0
    local text = res.Body or res.body or ""
    if status < 200 or status >= 300 then
        return false, ("HTTP %s: %s"):format(tostring(status), tostring(text):sub(1, 300))
    end

    local parsed = decodeHttpJson(text)
    if not parsed then
        local preview = tostring(text):gsub("%s+", " "):sub(1, 220)
        if preview:find("Fatal error", 1, true) or preview:find("<b>", 1, true) then
            return false, "PHP error: " .. preview
        end
        return false, "JSON parse failed: " .. preview
    end

    local env = normalizeApiEnvelope(parsed)
    if env and env.success == false then
        return false, tostring(env.messages or "API error")
    end

    return true, env or parsed
end

function M.Sync(payload)
    payload = payload or _lastScan or M.Scan()
    if not payload or not payload.ok then
        _lastSyncOk = false
        _lastSyncMsg = payload and payload.error or "scan failed"
        return false, _lastSyncMsg
    end

    local dbPayload = buildDbPayload(payload)
    local fingerprint = buildSyncFingerprint(dbPayload)
    if fingerprint == _lastSyncFingerprint then
        _lastSyncOk = true
        _lastSyncMsg = "cached (no pet changes)"
        return true, "skipped"
    end

    local ok, result = httpPost(syncUrl(), stripNil({
        action = "sync",
        server = dbPayload.server,
        pets = dbPayload.pets,
    }))
    _lastSyncOk = ok
    if ok then
        _lastSyncFingerprint = fingerprint
        _lastSyncMsg = "OK"
        local data = type(result) == "table" and result.data or nil
        if type(data) == "table" and data.ok ~= nil then
            _lastSyncMsg = string.format("upsert=%s stale=%s", tostring(data.upserted), tostring(data.deleted_stale))
        end
    else
        _lastSyncMsg = tostring(result)
    end
    M._notifyUi()
    return ok, result
end

function M.FetchList(overrideFilters, opts)
    opts = type(opts) == "table" and opts or {}
    local filters = buildListFetchFilters(overrideFilters)

    local ok, result = httpPost(listUrl(), stripNil({
        action = "list",
        place_id = filters.place_id,
        limit = filters.limit,
        pet_names = filters.pet_names,
    }))
    if not ok then
        _lastListErr = tostring(result)
        _lastListRaw = {}
        _lastList = {}
        M._notifyUi()
        return false, result
    end

    local rows, listErr = extractApiListRows(result)
    if rows then
        _lastListRaw = rows
        _lastListErr = ""
        clearHopBurstTried()
        M.rebuildDisplayList()
        if opts.skipAutoHop ~= true then
            M.tryAutoHopBurst(false, HOP_BURST_MAX)
        end
    else
        _lastListRaw = {}
        _lastList = {}
        _lastListErr = tostring(listErr or "invalid response")
    end
    M._notifyUi()
    return true, _lastList
end

function M.HopToJob(jobId, placeId, requiredPrice, hopMeta)
    M.ensureTeleportFailHook()
    hopMeta = type(hopMeta) == "table" and hopMeta or {}
    jobId = tostring(jobId or ""):gsub("%s+", "")
    placeId = tonumber(placeId) or game.PlaceId
    if jobId == "" then
        local t, d = describeHopError("job_id empty", "job_id empty")
        setHopUiStatus("failed", { jobId = jobId, failTitle = t, failDetail = d })
        return false, "job_id empty"
    end
    if isSameServerJob(jobId) then
        local t, d = describeHopError("already on server", "already on server")
        setHopUiStatus("failed", {
            petName = hopMeta.petName,
            rarity = hopMeta.rarity,
            jobId = jobId,
            failTitle = t,
            failDetail = d,
        })
        return false, "already on server"
    end
    if isAvoidedJob(jobId) then
        local t, d = describeHopError("server_avoided", "server_avoided")
        setHopUiStatus("failed", {
            petName = hopMeta.petName,
            rarity = hopMeta.rarity,
            jobId = jobId,
            failTitle = t,
            failDetail = d,
        })
        return false, "server_avoided"
    end
    if not canAffordPrice(requiredPrice) then
        local t, d = describeHopError("insufficient_sheckles", "insufficient_sheckles")
        setHopUiStatus("failed", {
            petName = hopMeta.petName,
            rarity = hopMeta.rarity,
            jobId = jobId,
            price = tonumber(requiredPrice) or 0,
            failTitle = t,
            failDetail = d,
        })
        return false, "insufficient_sheckles"
    end

    local td = {
        __gag2_petfinder = true,
        targetJobId = jobId,
        nonce = tostring(os.time()) .. "_" .. tostring(math.random(100000, 999999)),
    }

    _pendingHopJobId = jobId:lower()
    _hopInFlight = true
    if _hopStartedAt <= 0 then
        _hopStartedAt = os.clock()
        _hopFromJobId = tostring(game.JobId or "")
    end
    setHopUiStatus("teleporting", {
        petName = hopMeta.petName,
        rarity = hopMeta.rarity,
        jobId = jobId,
        price = hopMeta.price or tonumber(requiredPrice) or 0,
        timeLeft = hopMeta.timeLeft,
    })

    local PR = rawget(_G, "PSReconnect") or getG().PSReconnect
    if type(PR) == "table" and type(PR.HopToServer) == "function" then
        prepareForHopTeleport()
        local ok, res = PR.HopToServer(placeId, jobId, td)
        if ok then
            startHopWatchdog(jobId, _hopFromJobId)
            return true, res
        end
        local failTitle, failDetail = describeHopError(tostring(res), tostring(res))
        _hopWatchdogToken += 1
        _pendingHopJobId = ""
        _hopInFlight = false
        setHopUiStatus("failed", {
            petName = hopMeta.petName,
            rarity = hopMeta.rarity,
            jobId = jobId,
            failTitle = failTitle,
            failDetail = failDetail,
        })
        return false, tostring(res)
    end

    local okTp, errTp = invokeHopTeleport(placeId, jobId, td)
    if okTp then
        startHopWatchdog(jobId, _hopFromJobId)
        return true, errTp
    end

    _hopWatchdogToken += 1
    _pendingHopJobId = ""
    _hopInFlight = false
    local failTitle, failDetail = describeHopError(tostring(errTp), tostring(errTp))
    setHopUiStatus("failed", {
        petName = hopMeta.petName,
        rarity = hopMeta.rarity,
        jobId = jobId,
        failTitle = failTitle,
        failDetail = failDetail,
    })
    return false, tostring(errTp)
end

function M.ScanAndSync()
    local payload = M.Scan()
    return M.Sync(payload)
end

function M.StopAutoSync()
    _autoSyncToken += 1
end

function M.StartAutoSync()
    _autoSyncToken += 1
    local token = _autoSyncToken
    task.spawn(function()
        while token == _autoSyncToken do
            M.ScanAndSync()
            task.wait(SYNC_SCAN_INTERVAL_SEC)
        end
    end)
end

function M.StopAutoHopFetch()
    _autoHopFetchToken += 1
end

function M.StartAutoHopFetch()
    M.StopAutoHopFetch()
    if not _cfg.auto_hop then return end
    _autoHopFetchToken += 1
    local token = _autoHopFetchToken
    task.spawn(function()
        while token == _autoHopFetchToken and _cfg.auto_hop do
            M.FetchList(nil, { skipAutoHop = true })
            if not _hopInFlight and os.clock() >= (_teleportBusyUntil or 0) then
                M.tryAutoHopBurst(false, HOP_BURST_MAX)
            end
            task.wait(HOP_FETCH_INTERVAL_SEC)
        end
    end)
    task.spawn(function()
        while token == _autoHopFetchToken and _cfg.auto_hop do
            if not _hopInFlight and os.clock() >= (_teleportBusyUntil or 0) then
                M.tryAutoHop(false)
            end
            task.wait(HOP_FAST_POLL_SEC)
        end
    end)
end

function M.StopAutoRefreshList()
    _autoRefreshToken += 1
end

local function waitWithUiTick(token, intervalSec, shouldRun)
    local t0 = os.clock()
    while token and shouldRun() and (os.clock() - t0) < intervalSec do
        M._notifyUi()
        task.wait(UI_TICK_INTERVAL_SEC)
    end
end

function M.StartAutoRefreshList()
    _autoRefreshToken += 1
    local token = _autoRefreshToken
    task.spawn(function()
        while token == _autoRefreshToken and _cfg.auto_refresh_list do
            if not _cfg.auto_hop then
                M.FetchList(nil, { skipAutoHop = true })
            end
            waitWithUiTick(token, LIST_REFRESH_INTERVAL_SEC, function()
                return token == _autoRefreshToken and _cfg.auto_refresh_list == true
            end)
        end
    end)
end

function M.ApplyConfig(cfg)
    if type(cfg) ~= "table" then return end
    if cfg.filter_rarities ~= nil then
        _cfg.filter_rarities = cleanSelectedMap(cfg.filter_rarities)
    end
    if cfg.auto_refresh_list ~= nil then
        _cfg.auto_refresh_list = (cfg.auto_refresh_list == true)
    end
    if cfg.auto_hop ~= nil then
        _cfg.auto_hop = (cfg.auto_hop == true)
    end

    M.rebuildDisplayList()

    if _cfg.auto_hop then
        M.StartAutoHopFetch()
    else
        M.StopAutoHopFetch()
    end

    if _cfg.auto_refresh_list then
        M.StartAutoRefreshList()
    else
        M.StopAutoRefreshList()
    end
end

function M.SyncFromGlobals()
    local G = getG()
    local MAIN = G.MAIN or rawget(_G, "MAIN")
    local pf = (type(MAIN) == "table" and type(MAIN.misc) == "table" and type(MAIN.misc.pet_finder) == "table")
        and MAIN.misc.pet_finder or {}

    local rarityMap = arrayToMap(pf.filter_rarities)
    if countSelectedRarities(rarityMap) <= 0 and pf.filter_rarity and pf.filter_rarity ~= "" then
        rarityMap = { [tostring(pf.filter_rarity)] = true }
    end
    if countSelectedRarities(rarityMap) <= 0 and type(G.PET_FINDER_FILTER_RARITIES) == "table" then
        rarityMap = arrayToMap(G.PET_FINDER_FILTER_RARITIES)
    end

    M.ApplyConfig({
        filter_rarities = rarityMap,
        auto_refresh_list = pf.auto_refresh_list ~= false,
        auto_hop = pf.auto_hop == true,
    })
end

function M.WriteGlobals(cfg)
    cfg = cfg or M.GetConfig()
    local G = getG()
    local rarityArr = mapToArray(cfg.filter_rarities)
    local payload = {
        filter_rarities = rarityArr,
        auto_refresh_list = (cfg.auto_refresh_list == true),
        auto_hop = (cfg.auto_hop == true),
    }

    local State = G.__GAG2_STATE
    if type(State) == "table" and type(State.patchMisc) == "function" then
        pcall(State.patchMisc, "pet_finder", payload, { noSync = true })
    end

    G.PET_FINDER_FILTER_RARITIES = rarityArr
    G.PET_FINDER_AUTO_REFRESH_LIST = payload.auto_refresh_list
    G.PET_FINDER_AUTO_HOP = payload.auto_hop
    _G.PET_FINDER_FILTER_RARITIES = rarityArr
    _G.PET_FINDER_AUTO_REFRESH_LIST = G.PET_FINDER_AUTO_REFRESH_LIST
    _G.PET_FINDER_AUTO_HOP = G.PET_FINDER_AUTO_HOP

    G.MAIN = G.MAIN or {}
    G.MAIN.misc = G.MAIN.misc or {}
    G.MAIN.misc.pet_finder = payload
    _G.MAIN = G.MAIN
end

local function runUiRefreshers()
    for _, fn in ipairs(_uiRefreshers) do
        pcall(fn)
    end
end

-- Hanya tampilan UI — tidak mempengaruhi tryAutoHop / FetchList / pickAutoHopTarget.
function M._notifyUiHop()
    for _, fn in ipairs(_uiHopRefreshers) do
        pcall(fn)
    end
end

function M._notifyUi(force)
    if #_uiRefreshers == 0 then return end

    if force == true then
        _uiNotifyScheduled = false
        _lastUiNotifyAt = os.clock()
        runUiRefreshers()
        return
    end

    local now = os.clock()
    if (now - _lastUiNotifyAt) >= UI_NOTIFY_MIN_SEC then
        _lastUiNotifyAt = now
        runUiRefreshers()
        return
    end

    if _uiNotifyScheduled then return end
    _uiNotifyScheduled = true
    local delay = UI_NOTIFY_MIN_SEC - (now - _lastUiNotifyAt)
    if delay < 0.05 then delay = 0.05 end
    task.delay(delay, function()
        _uiNotifyScheduled = false
        if #_uiRefreshers == 0 then return end
        _lastUiNotifyAt = os.clock()
        runUiRefreshers()
    end)
end

function M.RegisterUI(ui, STATE, autoSave)
    autoSave = autoSave or function() end
    local G = getG()
    local State = G.__GAG2_STATE
    if type(State) == "table" and type(State.registerFlush) == "function" then
        pcall(State.registerFlush, "pet_finder", function()
            if _uiHydrated then
                M.WriteGlobals(M.GetConfig())
            else
                M.SyncFromGlobals()
            end
        end)
    end

    ui:RegisterSubTab("misc", "petfinder", "Pet Finder", function()
        ui:ClearSubContent()
        _uiRefreshers = {}
        _uiHopRefreshers = {}
        _hopTargetUiFingerprint = ""
        _uiHydrated = true
        M.SyncFromGlobals()

        local cfg = M.GetConfig()

        local function commitCfg(partial)
            local nextCfg = M.GetConfig()
            if type(partial) == "table" then
                for k, v in pairs(partial) do
                    nextCfg[k] = v
                end
            end
            M.ApplyConfig(nextCfg)
            M.WriteGlobals(nextCfg)
            autoSave()
        end

        local bodyHop = ui:CreateSection("Auto Hop", true)

        ui:CreateRowLabel(bodyHop, "Hop targets (from Auto Buy Pet)", nil, 1, "list")

        local hopTargetWrap = Instance.new("Frame")
        hopTargetWrap.Name = "HopBuyTargetList"
        hopTargetWrap.BackgroundTransparency = 1
        hopTargetWrap.Size = UDim2.new(1, 0, 0, 0)
        hopTargetWrap.AutomaticSize = Enum.AutomaticSize.Y
        hopTargetWrap.LayoutOrder = 2
        hopTargetWrap.Parent = bodyHop

        local hopTargetWrapLayout = Instance.new("UIListLayout")
        hopTargetWrapLayout.FillDirection = Enum.FillDirection.Vertical
        hopTargetWrapLayout.SortOrder = Enum.SortOrder.LayoutOrder
        hopTargetWrapLayout.Padding = UDim.new(0, 4)
        hopTargetWrapLayout.Parent = hopTargetWrap

        local hopTargetScroll = Instance.new("Frame")
        hopTargetScroll.Name = "TargetScroll"
        hopTargetScroll.BackgroundColor3 = Color3.fromRGB(10, 10, 12)
        hopTargetScroll.BackgroundTransparency = 0.08
        hopTargetScroll.BorderSizePixel = 0
        hopTargetScroll.Size = UDim2.new(1, 0, 0, 0)
        hopTargetScroll.AutomaticSize = Enum.AutomaticSize.Y
        hopTargetScroll.LayoutOrder = 1
        hopTargetScroll.Parent = hopTargetWrap
        Instance.new("UICorner", hopTargetScroll).CornerRadius = UDim.new(0, 8)

        local hopTargetScrollStroke = Instance.new("UIStroke")
        hopTargetScrollStroke.Color = Color3.fromRGB(42, 42, 48)
        hopTargetScrollStroke.Thickness = 1
        hopTargetScrollStroke.Transparency = 0.35
        hopTargetScrollStroke.Parent = hopTargetScroll

        local hopTargetScrollPad = Instance.new("UIPadding")
        hopTargetScrollPad.PaddingTop = UDim.new(0, 5)
        hopTargetScrollPad.PaddingBottom = UDim.new(0, 5)
        hopTargetScrollPad.PaddingLeft = UDim.new(0, 5)
        hopTargetScrollPad.PaddingRight = UDim.new(0, 5)
        hopTargetScrollPad.Parent = hopTargetScroll

        local hopTargetListLayout = Instance.new("UIListLayout")
        hopTargetListLayout.FillDirection = Enum.FillDirection.Vertical
        hopTargetListLayout.SortOrder = Enum.SortOrder.LayoutOrder
        hopTargetListLayout.Padding = UDim.new(0, 4)
        hopTargetListLayout.Parent = hopTargetScroll

        local hopTargetEmptyLbl = Instance.new("TextLabel")
        hopTargetEmptyLbl.Name = "EmptyHint"
        hopTargetEmptyLbl.BackgroundTransparency = 1
        hopTargetEmptyLbl.Size = UDim2.new(1, 0, 0, 34)
        hopTargetEmptyLbl.Font = Enum.Font.Gotham
        hopTargetEmptyLbl.TextSize = 11
        hopTargetEmptyLbl.TextColor3 = COLOR_MUTED
        hopTargetEmptyLbl.TextXAlignment = Enum.TextXAlignment.Center
        hopTargetEmptyLbl.Text = "No targets — set in Auto → Buy"
        hopTargetEmptyLbl.LayoutOrder = 0
        hopTargetEmptyLbl.Parent = hopTargetScroll

        local hopTargetCards = {}

        local function resolveHopPetIcon(petKey)
            local PLV = getPetListView()
            if type(PLV) == "table" and type(PLV.getPetIcon) == "function" then
                return PLV.getPetIcon(petKey)
            end
            return nil
        end

        local function getBuyPetStore()
            local G = getG()
            return G.__GAG2_BUY_PET or rawget(_G, "__GAG2_BUY_PET") or {}
        end

        local function chipValuesFromMap(map, fallback)
            local arr = mapToArray(map)
            if #arr == 0 then return { fallback or "Any" } end
            table.sort(arr)
            return arr
        end

        local function chipStyleForVariant(name)
            local k = normalizePetKey(name)
            if k == "rainbow" then
                return Color3.fromRGB(120, 55, 190), Color3.fromRGB(250, 230, 255)
            end
            if k == "any" or k == "normal" then
                return Color3.fromRGB(38, 40, 48), Color3.fromRGB(150, 155, 170)
            end
            return Color3.fromRGB(45, 95, 170), Color3.fromRGB(220, 235, 255)
        end

        local function chipStyleForSize(name)
            local k = normalizePetKey(name)
            if k == "huge" then
                return Color3.fromRGB(210, 130, 20), Color3.fromRGB(255, 245, 210)
            end
            if k == "big" then
                return Color3.fromRGB(35, 110, 210), Color3.fromRGB(220, 240, 255)
            end
            return Color3.fromRGB(38, 40, 48), Color3.fromRGB(150, 155, 170)
        end

        local function chipStyleForSteal(name)
            local k = normalizePetKey(name)
            if k == "steal" then
                return Color3.fromRGB(170, 45, 45), Color3.fromRGB(255, 220, 220)
            end
            return Color3.fromRGB(30, 110, 70), Color3.fromRGB(210, 255, 230)
        end

        local function chipStyleForMult()
            return Color3.fromRGB(55, 50, 30), COLOR_ACCENT
        end

        local function chipLabelForVariant(name)
            if normalizePetKey(name) == "any" then return "Any Var" end
            return tostring(name)
        end

        local function chipLabelForSize(name)
            if normalizePetKey(name) == "any" then return "Any Size" end
            return tostring(name)
        end

        local function addHopChip(parent, text, bg, fg, order)
            local chip = Instance.new("TextLabel")
            chip.Name = "Chip_" .. tostring(text)
            chip.BackgroundColor3 = bg
            chip.BorderSizePixel = 0
            chip.AutomaticSize = Enum.AutomaticSize.X
            chip.Size = UDim2.fromOffset(0, 16)
            chip.Font = Enum.Font.GothamBold
            chip.TextSize = 9
            chip.TextColor3 = fg
            chip.Text = tostring(text):upper()
            chip.LayoutOrder = order
            chip.Parent = parent
            Instance.new("UICorner", chip).CornerRadius = UDim.new(0, 4)

            local chipPad = Instance.new("UIPadding")
            chipPad.PaddingLeft = UDim.new(0, 5)
            chipPad.PaddingRight = UDim.new(0, 5)
            chipPad.Parent = chip

            local chipStroke = Instance.new("UIStroke")
            chipStroke.Color = fg
            chipStroke.Transparency = 0.75
            chipStroke.Thickness = 1
            chipStroke.Parent = chip
        end

        local function chipStyleForEnabled(on)
            if on then
                return Color3.fromRGB(30, 110, 70), Color3.fromRGB(210, 255, 230)
            end
            return Color3.fromRGB(45, 45, 50), Color3.fromRGB(130, 130, 140)
        end

        local function stealMetaForRule(rule)
            if rule.steal == true then
                return "Steal", chipStyleForSteal("steal")
            end
            return "Buy", chipStyleForSteal("buy")
        end

        local function destroyHopTargetCards()
            for _, card in ipairs(hopTargetCards) do
                if card and card.Parent then
                    card:Destroy()
                end
            end
            table.clear(hopTargetCards)
        end

        local function buildHopTargetRow(index, rule)
            local isOn = (rule.enabled == true)
            local card = Instance.new("Frame")
            card.Name = "HopBuyTarget_" .. tostring(index)
            card.BackgroundColor3 = isOn and COLOR_CARD or Color3.fromRGB(14, 14, 16)
            card.BackgroundTransparency = isOn and 0 or 0.25
            card.BorderSizePixel = 0
            card.Size = UDim2.new(1, 0, 0, 40)
            card.LayoutOrder = index
            card.Parent = hopTargetScroll
            Instance.new("UICorner", card).CornerRadius = UDim.new(0, 7)

            local cardStroke = Instance.new("UIStroke")
            cardStroke.Color = isOn and Color3.fromRGB(38, 38, 46) or Color3.fromRGB(30, 30, 34)
            cardStroke.Thickness = 1
            cardStroke.Transparency = 0.25
            cardStroke.Parent = card

            local accent = Instance.new("Frame")
            accent.Name = "Accent"
            accent.BackgroundColor3 = isOn and COLOR_ACCENT or Color3.fromRGB(70, 70, 78)
            accent.BorderSizePixel = 0
            accent.Size = UDim2.new(0, 3, 1, -8)
            accent.Position = UDim2.fromOffset(4, 4)
            accent.Parent = card
            Instance.new("UICorner", accent).CornerRadius = UDim.new(1, 0)

            local iconPad = 0
            local iconUrl = resolveHopPetIcon(rule.pet)
            if iconUrl and iconUrl ~= "" then
                iconPad = 22
                local img = Instance.new("ImageLabel")
                img.Name = "PetIcon"
                img.BackgroundTransparency = 1
                img.Size = UDim2.fromOffset(18, 18)
                img.Position = UDim2.new(0, 12, 0.5, -9)
                img.Image = iconUrl
                img.ScaleType = Enum.ScaleType.Fit
                img.Parent = card
            end

            local nameLbl = Instance.new("TextLabel")
            nameLbl.BackgroundTransparency = 1
            nameLbl.Position = UDim2.fromOffset(12 + iconPad, 0)
            nameLbl.Size = UDim2.new(0.42, -12, 1, 0)
            nameLbl.Font = Enum.Font.GothamBold
            nameLbl.TextSize = 11
            nameLbl.TextXAlignment = Enum.TextXAlignment.Left
            nameLbl.TextColor3 = isOn and COLOR_TEXT or COLOR_MUTED
            nameLbl.TextTruncate = Enum.TextTruncate.AtEnd
            nameLbl.Text = tostring(rule.pet or "?")
            nameLbl.Parent = card

            local chips = Instance.new("Frame")
            chips.Name = "Chips"
            chips.BackgroundTransparency = 1
            chips.AnchorPoint = Vector2.new(1, 0.5)
            chips.Position = UDim2.new(1, -6, 0.5, 0)
            chips.Size = UDim2.new(0.56, -8, 0, 16)
            chips.Parent = card

            local chipsLayout = Instance.new("UIListLayout")
            chipsLayout.FillDirection = Enum.FillDirection.Horizontal
            chipsLayout.HorizontalAlignment = Enum.HorizontalAlignment.Right
            chipsLayout.VerticalAlignment = Enum.VerticalAlignment.Center
            chipsLayout.SortOrder = Enum.SortOrder.LayoutOrder
            chipsLayout.Padding = UDim.new(0, 3)
            chipsLayout.Parent = chips

            local chipOrder = 0
            chipOrder += 1
            do
                local bg, fg = chipStyleForEnabled(isOn)
                addHopChip(chips, isOn and "ON" or "OFF", bg, fg, chipOrder)
            end
            for _, variant in ipairs(chipValuesFromMap(rule.types, "Any")) do
                chipOrder += 1
                local bg, fg = chipStyleForVariant(variant)
                addHopChip(chips, chipLabelForVariant(variant), bg, fg, chipOrder)
            end
            for _, sizeName in ipairs(chipValuesFromMap(rule.sizes, "Any")) do
                chipOrder += 1
                local bg, fg = chipStyleForSize(sizeName)
                addHopChip(chips, chipLabelForSize(sizeName), bg, fg, chipOrder)
            end
            chipOrder += 1
            do
                local stealTxt, stealBg, stealFg = stealMetaForRule(rule)
                addHopChip(chips, stealTxt, stealBg, stealFg, chipOrder)
            end
            local maxSteal = tonumber(rule.max_steal or rule.max_steal_mult)
            if maxSteal and maxSteal > 0 then
                chipOrder += 1
                local bg, fg = chipStyleForMult()
                addHopChip(chips, string.format("STEAL ≤%d", math.floor(maxSteal + 0.499)), bg, fg, chipOrder)
            end

            hopTargetCards[#hopTargetCards + 1] = card
        end

        local function refreshHopTargetLabel()
            local SectionBuyPet = getSectionBuyPet()
            local targets = loadBuyPetTargets()
            if type(SectionBuyPet) == "table" and type(SectionBuyPet.normalizeTargets) == "function" then
                targets = SectionBuyPet.normalizeTargets(targets)
            end
            targets = sortBuyPetTargetsByRarity(targets)
            local fp = buyPetTargetsFingerprint(targets)
            if fp == _hopTargetUiFingerprint then return end
            _hopTargetUiFingerprint = fp

            destroyHopTargetCards()
            hopTargetEmptyLbl.Visible = (#targets <= 0)
            for i, rule in ipairs(targets) do
                buildHopTargetRow(i, rule)
            end
        end

        refreshHopTargetLabel()

        ui:CreateRowToggle(bodyHop, "Auto Hop", cfg.auto_hop == true, function(on)
            commitCfg({ auto_hop = (on == true) })
        end, 3)

        local _, hopStatusLbl = ui:CreateRowLabel(bodyHop, "Set buy targets in Auto → Buy, then enable Auto Hop.", nil, 4, "info")

        local bodyList = ui:CreateSection("Pet List", true)

        local rarityRow = ui:CreateRowDropdown(bodyList, {
            label       = "Rarity",
            placeholder = "All Rarities",
            mode        = "multi",
            getItems    = function() return getRarityItems() end,
            initial     = cfg.filter_rarities,
            onChanged   = function(_, selectedMap)
                commitCfg({ filter_rarities = cleanSelectedMap(selectedMap) })
                M._notifyUi()
            end,
        })
        if rarityRow then rarityRow.LayoutOrder = 1 end

        ui:CreateRowToggle(bodyList, "Auto Refresh List", cfg.auto_refresh_list == true, function(on)
            commitCfg({ auto_refresh_list = (on == true) })
        end, 2)

        local _, listStatusLbl = ui:CreateRowLabel(bodyList, "Loading...", nil, 3, "info")

        local listHost = Instance.new("Frame")
        listHost.Name = "PetFinderListHost"
        listHost.BackgroundTransparency = 1
        listHost.Size = UDim2.new(1, 0, 0, 240)
        listHost.LayoutOrder = 4
        listHost.Parent = bodyList

        local listScroll = Instance.new("ScrollingFrame")
        listScroll.Name = "Scroll"
        listScroll.BackgroundColor3 = Color3.fromRGB(10, 10, 12)
        listScroll.BorderSizePixel = 0
        listScroll.Size = UDim2.new(1, 0, 1, 0)
        listScroll.CanvasSize = UDim2.new(0, 0, 0, 0)
        listScroll.ScrollBarThickness = 3
        listScroll.ScrollBarImageColor3 = COLOR_ACCENT
        listScroll.AutomaticCanvasSize = Enum.AutomaticSize.Y
        listScroll.Parent = listHost
        Instance.new("UICorner", listScroll).CornerRadius = UDim.new(0, 10)

        local scrollStroke = Instance.new("UIStroke")
        scrollStroke.Color = Color3.fromRGB(42, 42, 48)
        scrollStroke.Thickness = 1
        scrollStroke.Transparency = 0.35
        scrollStroke.Parent = listScroll

        local listLayout = Instance.new("UIListLayout")
        listLayout.Padding = UDim.new(0, 4)
        listLayout.SortOrder = Enum.SortOrder.LayoutOrder
        listLayout.Parent = listScroll

        local pad = Instance.new("UIPadding")
        pad.PaddingTop = UDim.new(0, 6)
        pad.PaddingBottom = UDim.new(0, 6)
        pad.PaddingLeft = UDim.new(0, 6)
