        end

        local function rowListRenderKey(row)
            row = type(row) == "table" and row or {}
            return table.concat({
                tostring(row.job_id or ""),
                tostring(row.pet_name or ""),
                tostring(row.rarity or ""),
                tostring(row.price or ""),
                tostring(row.pet_type_raw or row.pet_type or ""),
                tostring(row.pet_size_raw or row.pet_size or ""),
                tostring(row.spawn_uuid or ""),
            }, "\31")
        end

        local function renderList()
            local rows = _lastList or {}
            for i, row in ipairs(rows) do
                local card = cardRows[i]
                if not card then
                    card = createCard()
                    cardRows[i] = card
                end

                local rarity = tostring(row.rarity or "Unknown")
                local rarityColor = getRarityColor(rarity)
                local secLeft = computeSecondsLeft(row)
                local spawnId = shortSpawnId(row.spawn_uuid)
                local jobShort = tostring(row.job_id or "?"):sub(1, 8)
                local renderKey = rowListRenderKey(row)

                card._jobId = tostring(row.job_id or "")
                card._placeId = tonumber(row.place_id) or game.PlaceId
                card._price = tonumber(row.price) or 0
                card._petName = tostring(row.pet_name or "?")
                card._rarity = rarity
                local sameServer = card._jobId:lower() == tostring(game.JobId):lower()
                local affordable = canAffordPrice(card._price)
                card.frame.Visible = true
                card.frame.LayoutOrder = i

                if card._renderKey ~= renderKey then
                    card._renderKey = renderKey
                    card.accent.BackgroundColor3 = rarityColor
                    card.badge.Text = rarity:upper()
                    card.badge.TextColor3 = rarityColor
                    card.nameLbl.Text = tostring(row.pet_name or "?")
                    card.priceLbl.Text = fmtPrice(row.price)
                    updateListTraitChips(card, row)
                end

                card.metaLbl.Text = fmtListMeta(row, secLeft, spawnId, jobShort)
                card.hopBtn.Text = sameServer and "Here" or (affordable and "Hop" or "Poor")
                card.hopBtn.BackgroundColor3 = sameServer and Color3.fromRGB(55, 58, 68)
                    or (affordable and COLOR_ACCENT or Color3.fromRGB(55, 58, 68))
                card.hopBtn.TextColor3 = sameServer and COLOR_MUTED
                    or (affordable and Color3.fromRGB(12, 12, 12) or COLOR_MUTED)
                card.hopBtn.Active = not sameServer and affordable
                card.hopBtn.AutoButtonColor = false
            end

            for i = #rows + 1, #cardRows do
                if cardRows[i] and cardRows[i].frame then
                    cardRows[i].frame.Visible = false
                end
            end
        end

        local function formatMatchStatus(target)
            if not target then return nil end
            local meta = hopMetaFromRow(target)
            local priceTxt = meta.price > 0 and fmtPrice(meta.price) or "?"
            local parts = {
                string.format("Match: %s (%s)", meta.petName, meta.rarity),
                priceTxt,
            }
            if meta.timeLeft ~= "" then
                parts[#parts + 1] = meta.timeLeft .. " left"
            end
            if meta.playerCount ~= nil then
                parts[#parts + 1] = tostring(math.floor(meta.playerCount)) .. " ply"
            end
            if meta.scannedAgo ~= nil and meta.scannedAgo ~= "" then
                parts[#parts + 1] = meta.scannedAgo
            end
            parts[#parts + 1] = "srv " .. shortJobId(meta.jobId)
            return table.concat(parts, " · ")
        end

        local cachedHopPickTarget = nil
        local lastHopPickAt = 0

        local function refreshHopStatus()
            if not hopStatusLbl or not hopStatusLbl.Parent then return end
            refreshHopTargetLabel()
            local liveCfg = M.GetConfig()
            if liveCfg.auto_hop ~= true then
                hopStatusLbl.Text = "Set buy targets in Auto → Buy, then enable Auto Hop."
                hopStatusLbl.TextColor3 = COLOR_MUTED
                return
            end
            if countEnabledBuyPetTargets() <= 0 then
                hopStatusLbl.Text = "Auto Hop ON — enable at least one pet in Auto → Buy."
                hopStatusLbl.TextColor3 = COLOR_ACCENT
                return
            end

            local hasLocal, localPet, localCount = M.hasLocalTargetPet()
            if hasLocal and localPet then
                local extra = (localCount or 1) > 1 and (" +" .. tostring(localCount - 1)) or ""
                local stayTag = getLocalStayTag(localPet)
                hopStatusLbl.Text = string.format(
                    "Stay — %s%s on this server (%s left)%s",
                    tostring(localPet.pet_name or "?"),
                    extra,
                    fmtTimeLeft(computeSecondsLeft(localPet)),
                    stayTag
                )
                hopStatusLbl.TextColor3 = Color3.fromRGB(255, 211, 0)
                return
            end

            local now = os.clock()
            local hopUi = M.GetHopUiStatus()
            local failAge = now - (tonumber(hopUi.updatedAt) or 0)
            if hopUi.phase == "failed" and failAge < HOP_FAIL_SHOW_SEC then
                local petPart = hopUi.petName ~= "" and (hopUi.petName .. " · ") or ""
                local detail = tostring(hopUi.failDetail or ""):gsub("%s+", " "):sub(1, 72)
                local retryTxt = liveCfg.auto_hop and " · retrying…" or ""
                hopStatusLbl.Text = string.format(
                    "Hop failed: %s%s%s%s",
                    petPart,
                    tostring(hopUi.failTitle or "Error"),
                    detail ~= "" and (" — " .. detail) or "",
                    retryTxt
                )
                hopStatusLbl.TextColor3 = COLOR_ACCENT
                return
            end

            if hopUi.phase == "teleporting" or _hopInFlight then
                local petPart = hopUi.petName ~= "" and hopUi.petName or "target pet"
                local rarityPart = hopUi.rarity ~= "" and (" (" .. hopUi.rarity .. ")") or ""
                local srvPart = hopUi.jobId ~= "" and (" · srv " .. shortJobId(hopUi.jobId)) or ""
                local hopAge = now - (_hopStartedAt or 0)
                local statusWord = hopAge >= 4 and "Waiting Roblox" or "Attempting hop"
                hopStatusLbl.Text = string.format("%s → %s%s%s…", statusWord, petPart, rarityPart, srvPart)
                hopStatusLbl.TextColor3 = Color3.fromRGB(120, 200, 255)
                return
            end

            if hopUi.phase == "match" and hopUi.petName ~= "" and failAge < 8 then
                local priceTxt = hopUi.price > 0 and fmtPrice(hopUi.price) or "?"
                hopStatusLbl.Text = string.format(
                    "Match: %s (%s) · %s · srv %s · hopping…",
                    hopUi.petName,
                    hopUi.rarity ~= "" and hopUi.rarity or "?",
                    priceTxt,
                    shortJobId(hopUi.jobId)
                )
                hopStatusLbl.TextColor3 = Color3.fromRGB(120, 255, 175)
                return
            end

            if (now - lastHopPickAt) >= 1 then
                lastHopPickAt = now
                cachedHopPickTarget = M.pickAutoHopTarget()
            end
            if cachedHopPickTarget then
                hopStatusLbl.Text = formatMatchStatus(cachedHopPickTarget) .. " · hop ready (highest rarity first)"
                hopStatusLbl.TextColor3 = Color3.fromRGB(120, 255, 175)
            else
                hopStatusLbl.Text = "Auto Hop ON — scanning for buy targets..."
                hopStatusLbl.TextColor3 = Color3.fromRGB(120, 255, 175)
            end
        end

        local function refreshStatus()
            if not listStatusLbl or not listStatusLbl.Parent then return end
            if _lastListErr ~= "" then
                listStatusLbl.Text = "Error: " .. tostring(_lastListErr):sub(1, 120)
                listStatusLbl.TextColor3 = COLOR_ACCENT
            else
                local totalRaw = #(_lastListRaw or {})
                local shown = #(_lastList or {})
                if shown ~= totalRaw then
                    listStatusLbl.Text = string.format("%d pet(s) By Rarity", shown)
                else
                    listStatusLbl.Text = string.format("%d pet(s) found", shown)
                end
                listStatusLbl.TextColor3 = Color3.fromRGB(120, 255, 175)
            end
            renderList()
            refreshHopStatus()
        end

        table.insert(_uiRefreshers, refreshStatus)
        table.insert(_uiHopRefreshers, refreshHopStatus)

        refreshHopTargetLabel()

        task.spawn(function()
            M.FetchList(nil, { skipAutoHop = not _cfg.auto_hop })
            refreshStatus()
        end)

        task.spawn(function()
            while bodyList and bodyList.Parent do
                pcall(refreshStatus)
                task.wait(UI_TICK_INTERVAL_SEC)
            end
            _uiRefreshers = {}
            _uiHopRefreshers = {}
            _hopTargetUiFingerprint = ""
        end)

        refreshStatus()
    end, 3)
end

M.SyncFromGlobals()
M.ensureTeleportFailHook()
M.StartAutoSync()
if _cfg.auto_hop then
    M.StartAutoHopFetch()
end
if _cfg.auto_refresh_list then
    M.StartAutoRefreshList()
end

return M
 end,                      required = false },
    { key = "MiscTabs",                name = "Misc Tabs",               factory = function() -- tabs_misc.lua — Grow A Garden 2
-- Main tab: MISC → sub tab: Rejoin (+ Auto Update Server)

local M = {}

function M.Register(ui, STATE)
    STATE = rawget(_G, "STATE") or STATE or {}
    local G = (getgenv and getgenv()) or _G
    G.STATE = STATE

    local State = G.__GAG2_STATE

    local function saveNow()
        if G.__GAG2_RESETTING == true then return end
        if type(State) == "table" and type(State.saveFromUi) == "function" then
            pcall(State.saveFromUi)
            return
        end
        if ui and type(ui.SaveState) == "function" then
            pcall(function() ui:SaveState() end)
        end
    end

    local function getMisc(key)
        if type(State) == "table" and type(State.getMisc) == "function" then
            local ok, result = pcall(State.getMisc, key)
            if ok and type(result) == "table" then return result end
        end
        local m = G.MAIN or rawget(_G, "MAIN")
        if type(m) == "table" and type(m.misc) == "table" then
            return m.misc[key] or {}
        end
        return {}
    end

    local function patchMisc(key, partial, syncFnOrOpts)
        local syncFn = nil
        local opts = nil
        if type(syncFnOrOpts) == "function" then
            syncFn = syncFnOrOpts
        elseif type(syncFnOrOpts) == "table" then
            opts = syncFnOrOpts
        end

        if type(State) == "table" and type(State.patchMisc) == "function" then
            pcall(State.patchMisc, key, partial, opts or {})
        else
            local m = G.MAIN or rawget(_G, "MAIN")
            if type(m) == "table" and type(partial) == "table" then
                m.misc = m.misc or {}
                local cur = type(m.misc[key]) == "table" and m.misc[key] or {}
                for k, v in pairs(partial) do
                    if type(v) == "table" and type(cur[k]) == "table" and v[1] == nil then
                        for sk, sv in pairs(v) do cur[k][sk] = sv end
                    else
                        cur[k] = v
                    end
                end
                m.misc[key] = cur
                G.MAIN = m
                _G.MAIN = m
            end
        end
        if syncFn then pcall(syncFn) end
        -- noSync/noSave: flush path inside State.saveFromUi — must not re-enter saveNow
        local skipSave = opts and (opts.noSync == true or opts.noSave == true)
        if not skipSave then
            saveNow()
        end
    end

    local function registerFlush(id, fn)
        if type(State) == "table" and type(State.registerFlush) == "function" then
            pcall(State.registerFlush, id, fn)
        end
    end

    local function unregisterFlush(id)
        if type(State) == "table" and type(State.unregisterFlush) == "function" then
            pcall(State.unregisterFlush, id)
        end
    end

    local function cleanSelectedMap(selectedMap)
        local out = {}
        if type(selectedMap) ~= "table" then return out end
        for k, v in pairs(selectedMap) do
            if v == true then
                out[tostring(k)] = true
            elseif type(k) == "number" and (type(v) == "string" or type(v) == "number") then
                local s = tostring(v)
                if s ~= "" then out[s] = true end
            end
        end
        return out
    end

    local function mapToArray(map)
        local arr = {}
        if type(map) == "table" then
            for k, v in pairs(map) do
                if v == true then arr[#arr + 1] = tostring(k) end
            end
        end
        table.sort(arr)
        return arr
    end

    local function arrayToMap(arr)
        local m = {}
        if type(arr) ~= "table" then return m end
        for _, v in ipairs(arr) do
            if v ~= nil and tostring(v) ~= "" then
                m[tostring(v)] = true
            end
        end
        if next(m) then return m end
        for k, v in pairs(arr) do
            if v == true or v == 1 or v == "true" then
                m[tostring(k)] = true
            end
        end
        return m
    end

    local PlantListView = G.PlantListView or rawget(_G, "PlantListView")

    local function autoSave()
        saveNow()
    end

    G.__GAG2_AUTO_SAVE = autoSave
    G.__GAG2_PERSIST_STATE = saveNow
    _G.__GAG2_PERSIST_STATE = saveNow

    ui:RegisterMainTab("misc", "MISC", 2)

    ui:RegisterSubTab("misc", "rejoin", "Rejoin", function()
        ui:ClearSubContent()

        local sectionSetters = {}
        local function createSection(title, defaultOpen)
            local body, setExpanded = ui:CreateSection(title, defaultOpen or false)
            table.insert(sectionSetters, setExpanded)
            return body
        end

        local body1 = createSection("Auto Reconnect / Rejoin", true)

        local function syncReconnectModule()
            pcall(function()
                local R = _G.PSReconnect
                local on = (AUTO_RECONNECT_ENABLED == true)
                if R and type(R.SetEnabled) == "function" then
                    R.SetEnabled(on)
                elseif R and type(R.setEnabled) == "function" then
                    R.setEnabled(on)
                end
            end)
        end

        ui:CreateRowToggle(body1, "Auto Exec", AUTO_START_ON_REJOIN == true, function(on)
            patchMisc("rejoin", { auto_exec = (on == true) }, function()
                task.defer(function()
                    if _G.PSReconnect and _G.PSReconnect.DebugPrint then
                        _G.PSReconnect:DebugPrint()
                    end
                end)
            end)
        end)

        ui:CreateRowToggle(body1, "Auto Reconnect", AUTO_RECONNECT_ENABLED == true, function(on)
            patchMisc("rejoin", { auto_reconnect = (on == true) }, syncReconnectModule)
        end)

        ui:CreateRowToggle(body1, "Rejoin Now", false, function(on)
            if on ~= true then return end
            local R = _G.PSReconnect or (getgenv and getgenv().PSReconnect)
            if not R or type(R.RejoinNow) ~= "function" then
                warn("[GAG2] PSReconnect tidak tersedia")
                return
            end
            R:DebugPrint()
            local ok, err = R:RejoinNow()
            if ok ~= true then
                warn("[GAG2] Rejoin Now gagal:", tostring(err))
            else
                warn("[GAG2] Rejoin Now — teleport dikirim")
            end
        end)

        ----------------------------------------------------------------
        -- Auto Update Server (reserver)
        ----------------------------------------------------------------
        local envUNS = (getgenv and getgenv()) or _G

        local function peekUpdateNewServerCfg()
            local readFn = rawget(_G, "readUpdateNewServerGlobals") or rawget(envUNS, "readUpdateNewServerGlobals")
            if type(readFn) == "function" then
                return readFn()
            end
            return false, 30
        end

        local function setUpdateNewServerCfg(enabled, minute)
            local writeFn = rawget(_G, "writeUpdateNewServerGlobals") or rawget(envUNS, "writeUpdateNewServerGlobals")
            if type(writeFn) == "function" then
                writeFn(enabled, minute)
            end
        end

        local bodyReserve = createSection("Auto Update Server", false)

        local unsEnabled, unsMinute = peekUpdateNewServerCfg()

        local function syncUpdateNewServerModule()
            local applyFn = rawget(_G, "applyUpdateNewServerModule") or rawget(envUNS, "applyUpdateNewServerModule")
            if type(applyFn) == "function" then
                pcall(applyFn, unsEnabled, unsMinute)
            end
        end

        local function commitUpdateNewServerCfg()
            setUpdateNewServerCfg(unsEnabled, unsMinute)
