        syncHideTeleportPrompt()

        local bodyHideHarvestPrompt = ui:CreateSection("Hide Prompt Harvest", false)

        local function syncHideHarvestPrompt()
            local hp = getMisc("hide_harvest_prompt") or {}
            local on = (hp.enabled == true) or (G.HIDE_HARVEST_PROMPT_ENABLED == true)
            G.HIDE_HARVEST_PROMPT_ENABLED = on
