        local hideHarvestCfg = getMisc("hide_harvest_prompt") or {}
        local hideHarvestEnabled = (hideHarvestCfg.enabled == true) or (G.HIDE_HARVEST_PROMPT_ENABLED == true)

        ui:CreateRowToggle(bodyHideHarvestPrompt, "Hide Prompt Harvest", hideHarvestEnabled, function(on)
            hideHarvestEnabled = (on == true)
            patchMisc("hide_harvest_prompt", { enabled = hideHarvestEnabled }, syncHideHarvestPrompt)
        end)

        syncHideHarvestPrompt()

        local bodyHideLoading = ui:CreateSection("Hide Loading Screen", false)

        local function syncHideLoadingScreen()
            local hl = getMisc("hide_loading") or {}
            local on = (hl.enabled == true) or (G.HIDE_LOADING_ENABLED == true)
            G.HIDE_LOADING_ENABLED = on
            _G.HIDE_LOADING_ENABLED = on

            if type(G.applyHideLoadingModule) == "function" then
                pcall(G.applyHideLoadingModule)
            else
                local AF = G.AntiAFK or G.antiafk or rawget(_G, "AntiAFK")
                if type(AF) == "table" and type(AF.SetHideLoadingEnabled) == "function" then
                    pcall(AF.SetHideLoadingEnabled, on)
                end
            end
        end

        local hideLoadingCfg = getMisc("hide_loading") or {}
        local hideLoadingEnabled = (hideLoadingCfg.enabled == true) or (G.HIDE_LOADING_ENABLED == true)

        ui:CreateRowToggle(bodyHideLoading, "Hide Loading Screen", hideLoadingEnabled, function(on)
            hideLoadingEnabled = (on == true)
            patchMisc("hide_loading", { enabled = hideLoadingEnabled }, syncHideLoadingScreen)
        end)

        syncHideLoadingScreen()

        local bodyCharacter = ui:CreateSection("Character", false)

        local function getCharacterModule()
            return G.Character or _G.Character
        end

        local function syncCharacterModule()
            local cfg = getMisc("character") or {}
            local on = (cfg.clip == true) or (G.CHARACTER_CLIP_ENABLED == true)
            G.CHARACTER_CLIP_ENABLED = on
            _G.CHARACTER_CLIP_ENABLED = on

            if type(G.applyCharacterModule) == "function" then
                pcall(G.applyCharacterModule)
            else
                local CH = getCharacterModule()
                if type(CH) == "table" then
                    if type(CH.SetClipEnabled) == "function" then
                        pcall(CH.SetClipEnabled, on)
                    elseif type(CH.SetEnabled) == "function" then
                        pcall(CH.SetEnabled, on)
                    end
                end
            end
        end

        local characterCfg = getMisc("character") or {}
        local clipEnabled = (characterCfg.clip == true) or (G.CHARACTER_CLIP_ENABLED == true)

        ui:CreateRowToggle(bodyCharacter, "Clip", clipEnabled, function(on)
            clipEnabled = (on == true)
            patchMisc("character", { clip = clipEnabled }, syncCharacterModule)
        end)

        syncCharacterModule()

        local body = ui:CreateSection("Reset Script", false)

        local function refreshUiAfterReset()
            task.defer(function()
                if type(G.__GAG2_APPLY_UI_DEFAULTS) == "function" then
                    pcall(G.__GAG2_APPLY_UI_DEFAULTS)
                end
                local mainKey = ui.activeMainKey or "misc"
                local subKey = ui.activeSubKey or "settings"
                if type(ui._setActiveSubTab) == "function" then
                    ui:_setActiveSubTab(mainKey, subKey)
                end
            end)
        end

        G.__GAG2_ON_STATE_RESET = refreshUiAfterReset
        _G.__GAG2_ON_STATE_RESET = refreshUiAfterReset

        ui:CreateRowToggle(
            body,
            "Reset Save / State",
            false,
            function(on)
                if on ~= true then return end
                local resetFn = G.__GAG2_RESET_STATE or rawget(_G, "__GAG2_RESET_STATE")
                if type(resetFn) ~= "function" then
                    warn("[GAG2] Reset handler not available")
                    return
                end
                local ok, err = pcall(resetFn)
                if ok then
                    warn("[GAG2] Save file dihapus. Semua setting dikembalikan ke default.")
                else
                    warn("[GAG2] Reset failed:", tostring(err))
                end
            end,
            nil, nil, true
        )
    end, 4)

    ----------------------------------------------------------------
    -- Boot apply ReduceFPS / ReduceLag — JANGAN tergantung klik gear settings
    ----------------------------------------------------------------
    task.defer(function()
        local MAIN = rawget(_G, "MAIN") or G.MAIN
        local perf = MAIN and MAIN.misc and MAIN.misc.perf
        if type(perf) == "table" and perf.enabled == true then
            -- migrasi save hide_own=false → soft shell + AC filter hidup tanpa buka gear
            patchMisc("perf", { hide_own = true }, nil)
        end

        local RF = G.ReduceFPS or _G.ReduceFPS or G.ReduceFPSModule or _G.ReduceFPSModule
        local RL = G.ReduceLag or _G.ReduceLag or G.ReduceLagModule or _G.ReduceLagModule

        if type(G.applyReduceFpsModule) == "function" then
            pcall(G.applyReduceFpsModule)
        elseif type(RF) == "table" and type(RF.SyncFromGlobals) == "function" then
            pcall(RF.SyncFromGlobals, RF)
        end

        if type(G.applyReduceLagModule) == "function" then
            pcall(G.applyReduceLagModule)
        elseif type(RL) == "table" and type(RL.SyncFromGlobals) == "function" then
            pcall(RL.SyncFromGlobals, RL)
        end
    end)
end

return M
 end,                      required = true },
    { key = "PSReconnect",             name = "PSReconnect",             factory = function() -- PSReconnect.lua (FULL, DEBUG + HARD GATE)
-- ✅ Rejoin (PS-safe) + optional auto reconnect
-- ✅ Auto Exec STRICT dari save file: autohatch/<username>.json -> rejoin.auto_exec
-- ✅ queue_on_teleport hanya dipanggil jika auto_exec true
-- ✅ QTP chunk cek file lagi di server baru (OFF => skip)
-- ✅ QTP chunk nulis marker file + --warn() (biar kebukti jalan / gak jalan)
-- ✅ Kalau auto_exec ON tapi QTP gagal -> CANCEL teleport (biar gak rejoin tanpa autoexec)
-- ✅ Export ke _G/getgenv: _G.PSReconnect selalu ada
-- ✅ Debounce anti spam prompt

--------------------------------------------------
-- SERVICES
--------------------------------------------------
local Players         = game:GetService("Players")
local TeleportService = game:GetService("TeleportService")
local CoreGui         = game:GetService("CoreGui")
local GuiService      = game:GetService("GuiService")
local HttpService     = game:GetService("HttpService")

local LP = Players.LocalPlayer
if not LP then
    LP = Players:GetPropertyChangedSignal("LocalPlayer"):Wait()
end
local M  = {}

--------------------------------------------------
-- PREVENT MULTI LOAD (module ini)
--------------------------------------------------
local G = (getgenv and getgenv()) or _G
local MODULE_VER = 22
if G.__PSRECONNECT_VER == MODULE_VER and type(G.PSReconnect) == "table"
    and type(G.PSReconnect.RejoinNow) == "function" then
    return G.PSReconnect
end
G.__PSRECONNECT_VER = MODULE_VER

--------------------------------------------------
-- CONFIG
--------------------------------------------------
local SCRIPT_URL                 = "https://golaspay.net/scv/n3SAZrTRS89pScgGlTv?psreconnect=1&key=iWf5FiXnF0X"
local SAVE_DIR                   = "growagarden2"
local REJOIN_DELAY_SEC           = 1
local UPDATE_NEW_SERVER_DELAY_SEC = 10
local WEATHER_KICK_REJOIN_DELAY_SEC = 60
local SHUTDOWN_REJOIN_DELAY_SEC  = 1
local PROMPT_DISMISS_SEC         = 2
local REJOIN_RETRY_GAP_SEC       = 5
local REJOIN_ATTEMPT_WAIT_SEC    = 8
local DEBUG_PSRECONNECT          = false

local function normText(s)
    s = tostring(s or "")
    s = s:gsub("%s+", " ")
    s = s:gsub("^%s+", "")
    s = s:gsub("%s+$", "")
    return s
end

local function dprint(...)
    if not DEBUG_PSRECONNECT then return end
    print("[PSReconnect]", ...)
end

-- debounce
local _rejoinInFlight       = false
local _shutdownRejoinBusy   = false
local _lastRejoinT          = 0
local MIN_REJOIN_INTERVAL   = 6
local _teleportAntiPromptStarted = false
local _hideTeleportPromptEnabled = false
local _lastTeleportFailAt   = 0
local _lastTeleportFailMsg  = ""
local _teleportAttemptToken = 0

local function _hidePromptGloballyEnabled()
    if _hideTeleportPromptEnabled == true then
        return true
    end
    local ge = (getgenv and getgenv()) or _G
    return ge.HIDE_PROMPT_ENABLED == true or rawget(_G, "HIDE_PROMPT_ENABLED") == true
end

