local AUTO_RECONNECT_ENABLED = true

--------------------------------------------------
-- FILE HELPERS
--------------------------------------------------
local CAN_FS = (type(readfile)=="function" and type(isfile)=="function")

local function flushSettingsBeforeTeleport()
    local flush = G.__GAG2_FLUSH_TO_MAIN or rawget(_G, "__GAG2_FLUSH_TO_MAIN")
    if type(flush) == "function" then
        pcall(flush)
    end
    local save = G.__GAG2_CHECKPOINT_SAVE or G.__GAG2_STATE_SAVE or rawget(_G, "__GAG2_CHECKPOINT_SAVE") or rawget(_G, "__GAG2_STATE_SAVE")
    if type(save) == "function" then
        pcall(save)
    end
end

local function safeName(s)
    s = tostring(s or "player")
    s = s:gsub("[^%w%-_.]", "_")
    s = s:gsub("_+", "_")
    return s:sub(1, 48)
end

local function getSaveFile()
    if not LP then return nil end
    return (SAVE_DIR .. "/" .. safeName(LP.Name) .. ".json")
end

-- return: autoReconnect(bool), autoExec(bool)
local function readFlagsFromFile()
    local DEFAULT_RECONNECT = true
    local DEFAULT_EXEC      = false

    local memReconnect, memExec = nil, nil
    local main = G.MAIN or rawget(_G, "MAIN")
    if type(main) == "table" and type(main.misc) == "table" and type(main.misc.rejoin) == "table" then
        local r = main.misc.rejoin
        memReconnect = (r.auto_reconnect == true)
        memExec = (r.auto_exec == true)
    end

    if not CAN_FS then
        if memReconnect ~= nil or memExec ~= nil then
            return memReconnect == true, memExec == true
        end
        return DEFAULT_RECONNECT, DEFAULT_EXEC
    end

    local f = getSaveFile()
    if not f or not isfile(f) then
        if memReconnect ~= nil or memExec ~= nil then
            return memReconnect == true, memExec == true
        end
        return DEFAULT_RECONNECT, DEFAULT_EXEC
    end

    local ok, txt = pcall(readfile, f)
    if not ok or type(txt) ~= "string" or txt == "" then
        return DEFAULT_RECONNECT, DEFAULT_EXEC
    end

    local ok2, data = pcall(HttpService.JSONDecode, HttpService, txt)
    if not ok2 or type(data) ~= "table" then
        return DEFAULT_RECONNECT, DEFAULT_EXEC
    end

    local r = {}
    if type(data.rejoin) == "table" then
        r = data.rejoin
    elseif type(data.main) == "table"
        and type(data.main.misc) == "table"
        and type(data.main.misc.rejoin) == "table" then
        r = data.main.misc.rejoin
    elseif type(data.state) == "table" and type(data.state.rejoin) == "table" then
        r = data.state.rejoin
    end

    local autoReconnect = (r.auto_reconnect == true)
    local autoExec      = (r.auto_exec == true)

    if memReconnect ~= nil then autoReconnect = memReconnect end
    if memExec ~= nil then autoExec = memExec end

    return autoReconnect, autoExec
end

local function isAutoReconnectOn()
    if AUTO_RECONNECT_ENABLED == true then
        return true
    end
    if rawget(_G, "AUTO_RECONNECT_ENABLED") == true then
        return true
    end
    local ge = (getgenv and getgenv()) or _G
    if ge.AUTO_RECONNECT_ENABLED == true then
        return true
    end
    return select(1, readFlagsFromFile()) == true
end

