--------------------------------------------------
-- QUEUE ON TELEPORT (STRICT GATED + DEBUG MARKER)
--------------------------------------------------
local function QueueAutoExecIfEnabled()
    flushSettingsBeforeTeleport()

    local _, autoExec = readFlagsFromFile()
    if autoExec ~= true then
        return false, "auto_exec=false"
    end

    local qtp = getQTP()
    if not qtp then
        return false, "qtp not found"
    end

    local template = [[
        task.wait(3)

        local url = "__URL__"
        local SAVE_DIR = "__SAVE_DIR__"

        local Players = game:GetService("Players")
        local HttpService = game:GetService("HttpService")

        --warn("[QTP] running | SAVE_DIR=", SAVE_DIR, "| url=", url)
        --warn("[QTP] fs types:", type(readfile), type(isfile), type(writefile), type(makefolder))

        local function safeName(s)
            s = tostring(s or "player")
            s = s:gsub("[^%w%-_.]", "_")
            s = s:gsub("_+", "_")
            return s:sub(1, 48)
        end

        local function readAutoExecAndFile()
            if type(readfile)~="function" or type(isfile)~="function" then
                return false, nil
            end
            local lp = Players.LocalPlayer
            if not lp then return false, nil end

            local f = (SAVE_DIR .. "/" .. safeName(lp.Name) .. ".json")
            local ex = isfile(f)
            --warn("[QTP] file=", f, "exists=", ex)

            if not ex then return false, f end

            local ok, txt = pcall(readfile, f)
            if not ok or type(txt)~="string" or txt=="" then
                return false, f
            end

            local ok2, data = pcall(HttpService.JSONDecode, HttpService, txt)
            if not ok2 or type(data)~="table" then
                return false, f
            end

            local r
            if type(data.rejoin)=="table" then
                r = data.rejoin
            elseif type(data.state)=="table" and type(data.state.rejoin)=="table" then
                r = data.state.rejoin
            else
                r = {}
            end

            return (r.auto_exec == true), f
        end

        local enabled, fpath = readAutoExecAndFile()

        -- marker: buktiin chunk jalan
        pcall(function()
            if type(writefile)=="function" then
                -- coba bikin folder kalau belum ada
                if type(makefolder)=="function" and type(isfolder)=="function" then
                    if not isfolder(SAVE_DIR) then pcall(makefolder, SAVE_DIR) end
                end
                writefile(SAVE_DIR .. "/_qtp_ran.txt", "ran@"..os.time().."\nfile="..tostring(fpath).."\nenabled="..tostring(enabled))
            end
        end)

        if enabled ~= true then
            --warn("[QTP] auto_exec OFF in new server -> skip load")
            return
        end

        -- reset guard supaya loader tidak skip
        local G = (getgenv and getgenv()) or _G
        G.__NODEHUB_LOADED = nil
        G.__NODEHUB_LOADED_SESSION = nil
        G.__NODEHUB_AUTOEXECED = nil
        G.__MAINUI_LOADED = nil
        G.__UI_LOADED = nil

        local src
        for i=1,5 do
            local ok, res = pcall(function() return game:HttpGet(url) end)
            if ok and type(res)=="string" and #res>0 then
                src = res
                break
            end
            --warn("[QTP] HttpGet fail #"..i, res)
            task.wait(1.5)
        end

        if not src then
            --warn("[QTP] no src -> abort")
            return
        end

        local ok3, err3 = pcall(function()
            loadstring(src)()
        end)

        --warn("[QTP] load result:", ok3, err3)
    ]]

    local chunk = template
        :gsub("__URL__", tostring(SCRIPT_URL))
        :gsub("__SAVE_DIR__", tostring(SAVE_DIR))

    local ok, err = pcall(function()
        qtp(chunk)
    end)

    if not ok then
        return false, tostring(err)
    end
    return true, "queued"
end

--------------------------------------------------
-- ROBLOX PROMPT AUTO-DISMISS (teleport/kick)
-- Hide GUI + clear blur (ClearError saja sering sisakan BlurEffect)
--------------------------------------------------
local Lighting = game:GetService("Lighting")

local function clearPromptBlur()
    -- Lighting blur dari ErrorPrompt / disconnect
    pcall(function()
        for _, v in ipairs(Lighting:GetDescendants()) do
            if v:IsA("BlurEffect") then
                v.Enabled = false
                pcall(function() v.Size = 0 end)
            elseif v:IsA("DepthOfFieldEffect") then
                -- jangan matikan DoF game permanen; hanya BlurEffect
            end
        end
        for _, v in ipairs(Lighting:GetChildren()) do
            if v:IsA("BlurEffect") then
                v.Enabled = false
                pcall(function() v.Size = 0 end)
            end
        end
    end)

    -- kadang blur frame di PlayerGui / CoreGui
    pcall(function()
        local pg = LP and LP:FindFirstChild("PlayerGui")
        if pg then
            for _, v in ipairs(pg:GetDescendants()) do
                if v:IsA("BlurEffect") then
                    v.Enabled = false
                    pcall(function() v.Size = 0 end)
                elseif v:IsA("Frame") or v:IsA("ImageLabel") then
                    local n = string.lower(tostring(v.Name or ""))
                    if (n:find("blur", 1, true) or n:find("errorprompt", 1, true) or n:find("disconnect", 1, true))
                        and v:IsA("GuiObject") then
                        v.Visible = false
                    end
                end
            end
        end
    end)

    pcall(function()
        for _, v in ipairs(CoreGui:GetDescendants()) do
            if v:IsA("BlurEffect") then
                v.Enabled = false
                pcall(function() v.Size = 0 end)
            end
        end
    end)
end

local function hidePromptFast()
    if not _hidePromptGloballyEnabled() then
        return
    end
    pcall(function()
        GuiService:ClearError()
    end)

    pcall(function()
        local gui = CoreGui:FindFirstChild("RobloxPromptGui")
        if not gui then
            return
        end

        gui.Enabled = false

        for _, v in ipairs(gui:GetDescendants()) do
            if v:IsA("GuiObject") then
                v.Visible = false
            end
        end
    end)

    clearPromptBlur()
end

local function restorePromptGui()
    pcall(function()
        local gui = CoreGui:FindFirstChild("RobloxPromptGui")
        if not gui then
            return
        end
        gui.Enabled = true
        local overlay = gui:FindFirstChild("promptOverlay")
        if overlay and overlay:IsA("GuiObject") then
            overlay.Visible = true
        end
    end)
end

local function collectGuiText(root)
    local parts = {}
    if not root then return "" end
    for _, v in ipairs(root:GetDescendants()) do
        if v:IsA("TextLabel") or v:IsA("TextButton") or v:IsA("TextBox") then
            local txt = tostring(v.Text or "")
            if txt ~= "" then
                parts[#parts + 1] = txt
            end
        end
    end
    return normText(table.concat(parts, " "))
end

local function getPromptCombinedText()
    local gui = CoreGui:FindFirstChild("RobloxPromptGui")
    if not gui then
        return ""
    end
    return collectGuiText(gui:FindFirstChild("promptOverlay") or gui)
end

local function isShutdownText(t)
    t = string.lower(normText(t))
    return t:find("server telah dimatikan", 1, true)
        or t:find("kode error: 288", 1, true)
        or t:find("server has shut down", 1, true)
        or t:find("error code: 288", 1, true)
end

local function isUpdateNewServerKickText(t)
    t = string.lower(normText(t))
    return t:find("updatenewserver", 1, true) ~= nil
        or t:find("interval reached", 1, true) ~= nil
end

local function isWeatherKickText(t)
    t = string.lower(normText(t))
    return t:find("weatherkick", 1, true) ~= nil
end

local function isDisconnectText(t)
    t = string.lower(normText(t))
    return t:find("error", 1, true)
        or t:find("disconnected", 1, true)
        or t:find("lost connection", 1, true)
        or t:find("kicked", 1, true)
        or t:find("dikeluarkan", 1, true)
        or t:find("reconnect", 1, true)
        or t:find("koneksi terputus", 1, true)
        or t:find("hubungkan kembali", 1, true)
end

local function isTeleportProblemText(t)
    t = string.lower(normText(t))
    if t == "" then
        return false
    end

    if isShutdownText(t) or isUpdateNewServerKickText(t) or isWeatherKickText(t) then
        return false
    end

    if t:find("teleportasi gagal", 1, true)
        or t:find("teleport failed", 1, true)
        or t:find("teleportation failed", 1, true)
        or t:find("game full", 1, true)
        or t:find("server full", 1, true)
        or t:find("server penuh", 1, true)
        or t:find("gameended", 1, true)
        or t:find("previous teleport", 1, true)
        or t:find("isteleporting", 1, true)
        or t:find("in processing", 1, true)
        or t:find("unable to teleport", 1, true)
        or t:find("teleport bermasalah", 1, true)
        or t:find("join failed", 1, true)
        or t:find("unable to join", 1, true)
        or t:find("could not find requested game", 1, true)
        or t:find("requested game instance", 1, true)
        or t:find("instance has shutdown", 1, true)
        or t:find("kode eror: 772", 1, true)
        or t:find("error code: 772", 1, true)
        or t:find("kode error: 772", 1, true)
        or t:find("kode eror: 773", 1, true)
        or t:find("error code: 773", 1, true)
        or t:find("kode error: 773", 1, true)
        or t:find("dibatasi", 1, true)
        or t:find("restricted", 1, true)
        or t:find("coba lagi nanti", 1, true)
    then
        return true
    end

    if t:find("penuh", 1, true) and (t:find("server", 1, true) or t:find("game", 1, true)) then
        return true
    end

    if (t:find("teleport", 1, true) or t:find("teleportasi", 1, true))
        and (t:find("fail", 1, true) or t:find("gagal", 1, true) or t:find("problem", 1, true)
            or t:find("error", 1, true) or t:find("eror", 1, true) or t:find("masalah", 1, true))
    then
        return true
    end

    return false
end

local function maybeHideTeleportPrompt()
    if not _hidePromptGloballyEnabled() then
        return
    end
    local combined = getPromptCombinedText()
    if isTeleportProblemText(combined) then
        hidePromptFast()
    end
end

local function startTeleportAntiPrompt()
    if _teleportAntiPromptStarted then
        return
    end
    _teleportAntiPromptStarted = true

    task.spawn(function()
        local gui = CoreGui:WaitForChild("RobloxPromptGui", 120)
        if gui then
            pcall(function()
                gui.DescendantAdded:Connect(function()
                    task.defer(maybeHideTeleportPrompt)
                end)
            end)
            pcall(function()
                gui:GetPropertyChangedSignal("Enabled"):Connect(function()
                    if gui.Enabled then
                        task.defer(maybeHideTeleportPrompt)
                    end
                end)
            end)
        end
    end)

    task.spawn(function()
        while true do
            pcall(maybeHideTeleportPrompt)
            task.wait(0.02)
        end
    end)
end

--------------------------------------------------
-- TELEPORT BLOCK (private/restricted)
--------------------------------------------------
TeleportService.TeleportInitFailed:Connect(function(player, result, errMsg)
    if player ~= LP then return end
    local m = string.lower(errMsg or "")
    _lastTeleportFailAt = os.clock()
    _lastTeleportFailMsg = tostring(errMsg or result)

    -- GameFull / server penuh: jangan hard-block, biar retry jalan
    if result == Enum.TeleportResult.GameFull
        or m:find("game full", 1, true)
        or m:find("server penuh", 1, true)
        or m:find("772", 1, true) then
        hidePromptFast()
        return
    end
    -- Unauthorized/private: tandai, tapi retry loop tetap boleh ignoreBlock
    if result == Enum.TeleportResult.Unauthorized
        or m:find("restricted")
        or m:find("private")
        or m:find("not authorized") then
        TELEPORT_BLOCKED = true
    end
    hidePromptFast()
end)

--------------------------------------------------
-- REJOIN CORE
--------------------------------------------------
-- Rejoin selalu PlaceId saja — jangan pakai JobId / ServerInstanceId
-- (di Private Server / VIP, JobId sering bikin teleport gagal)
local function teleportPlaceOnly(placeId)
    placeId = tonumber(placeId) or game.PlaceId
    local ok, err = pcall(function()
        TeleportService:Teleport(placeId, LP)
    end)
    if not ok then
        return false, tostring(err)
    end
    return true, "place_only"
end

local function doTeleport(ignoreBlock, _forceRandom)
    if not LP then
        return false, "no LocalPlayer"
    end
    if TELEPORT_BLOCKED and ignoreBlock ~= true then
        return false, "blocked"
    end
    flushSettingsBeforeTeleport()

    local placeId = game.PlaceId
    _teleportAttemptToken = _teleportAttemptToken + 1
    local token = _teleportAttemptToken
    local failBefore = _lastTeleportFailAt

    local ok, how = teleportPlaceOnly(placeId)
    if ok then
        dprint("doTeleport OK ->", how, "placeId=", tostring(placeId), "token=", token)
    else
        dprint("doTeleport FAIL ->", how)
        _lastTeleportFailAt = os.clock()
        _lastTeleportFailMsg = tostring(how)
    end
    return ok, how, token, failBefore
end

local function stillInGame()
    return LP ~= nil and LP.Parent ~= nil
end

-- Tunggu hasil attempt: keluar game = sukses; TeleportInitFailed / timeout = gagal
local function waitTeleportResult(token, failBefore, waitSec)
    waitSec = tonumber(waitSec) or REJOIN_ATTEMPT_WAIT_SEC
    local t0 = os.clock()
    while (os.clock() - t0) < waitSec do
        if not stillInGame() then
            return true, "left_game"
        end
        if _teleportAttemptToken == token and _lastTeleportFailAt > failBefore then
            return false, _lastTeleportFailMsg ~= "" and _lastTeleportFailMsg or "teleport_init_failed"
        end
        task.wait(0.25)
    end
    -- masih di game setelah wait → anggap belum sukses, retry
    if stillInGame() then
        return false, "still_in_game"
    end
    return true, "left_game"
end

local function clearPendingFlags(pendingUNS, pendingWK)
    if pendingUNS then
        G.__UPDATE_NEW_SERVER_REJOIN_PENDING = nil
        _G.__UPDATE_NEW_SERVER_REJOIN_PENDING = nil
        G.__UPDATE_NEW_SERVER_PENDING_DELAY = nil
        _G.__UPDATE_NEW_SERVER_PENDING_DELAY = nil
    end
    if pendingWK then
        G.__WEATHER_KICK_REJOIN_PENDING = nil
        _G.__WEATHER_KICK_REJOIN_PENDING = nil
        G.__WEATHER_KICK_PENDING_DELAY = nil
        _G.__WEATHER_KICK_PENDING_DELAY = nil
        G.__WEATHER_KICK_PENDING_WEATHER = nil
        _G.__WEATHER_KICK_PENDING_WEATHER = nil
    end
end

-- Retry teleport sampai benar-benar rejoin (keluar dari server ini)
local function rejoinUntilSuccess(opts)
    opts = type(opts) == "table" and opts or {}
    local ignoreBlock = (opts.ignoreBlock == true)
    local attempt = 0

    while stillInGame() do
        attempt = attempt + 1
        dprint("rejoin attempt #", attempt, "| ignoreBlock=", ignoreBlock)

        local okCall, how, token, failBefore = doTeleport(ignoreBlock, true)
        if not okCall then
            dprint("rejoin attempt #", attempt, "call fail:", how)
            task.wait(REJOIN_RETRY_GAP_SEC)
        else
            local okResult, why = waitTeleportResult(token, failBefore, REJOIN_ATTEMPT_WAIT_SEC)
            if okResult then
                dprint("rejoin SUCCESS after attempt #", attempt, why)
                return true
            end
            dprint("rejoin attempt #", attempt, "failed:", why, "-> retry in", REJOIN_RETRY_GAP_SEC, "s")
            hidePromptFast()
            task.wait(REJOIN_RETRY_GAP_SEC)
        end

        -- soft unblock biar retry bisa lanjut setelah error sementara
        if TELEPORT_BLOCKED and ignoreBlock then
            -- keep trying with ignoreBlock
        elseif TELEPORT_BLOCKED then
            dprint("rejoin stopped: TELEPORT_BLOCKED")
            return false
        end
    end

    return true
end

local function canTriggerRejoin()
    local now = os.clock()
    if _rejoinInFlight then return false end
    if (now - _lastRejoinT) < MIN_REJOIN_INTERVAL then return false end
    _lastRejoinT = now
    return true
end

local function tryRejoin()
    if not canTriggerRejoin() then return end
    _rejoinInFlight = true

    local pendingUNS = (G.__UPDATE_NEW_SERVER_REJOIN_PENDING == true)
    local pendingWK = (G.__WEATHER_KICK_REJOIN_PENDING == true)
    if not pendingUNS and not pendingWK and not isAutoReconnectOn() then
        _rejoinInFlight = false
        return
    end

    local delaySec = REJOIN_DELAY_SEC
    if pendingUNS then
        local pendingDelay = tonumber(G.__UPDATE_NEW_SERVER_PENDING_DELAY)
            or tonumber(rawget(_G, "__UPDATE_NEW_SERVER_PENDING_DELAY"))
        if type(pendingDelay) == "number" and pendingDelay > 0 then
            delaySec = pendingDelay
        else
            delaySec = UPDATE_NEW_SERVER_DELAY_SEC
        end
    elseif pendingWK then
        local pendingDelay = tonumber(G.__WEATHER_KICK_PENDING_DELAY)
            or tonumber(rawget(_G, "__WEATHER_KICK_PENDING_DELAY"))
        local cfgDelay = tonumber(G.WEATHER_KICK_REJOIN_DELAY_SEC)
            or tonumber(rawget(_G, "WEATHER_KICK_REJOIN_DELAY_SEC"))
        if type(pendingDelay) == "number" and pendingDelay > 0 then
            delaySec = pendingDelay
        elseif type(cfgDelay) == "number" and cfgDelay > 0 then
            delaySec = cfgDelay
        else
            delaySec = WEATHER_KICK_REJOIN_DELAY_SEC
        end
    end

    task.spawn(function()
        task.wait(delaySec)

        local okQ, reasonQ = QueueAutoExecIfEnabled()
        dprint("queue (auto) =>", okQ, reasonQ)
        if okQ then task.wait(0.8) end

        -- ignoreBlock: retry terus meski sempat Unauthorized/private sementara
        local ok = rejoinUntilSuccess({ ignoreBlock = true })

        if ok then
            clearPendingFlags(pendingUNS, pendingWK)
        end

        _rejoinInFlight = false
    end)
end

local function tryShutdownRejoin()
    if _shutdownRejoinBusy then
        dprint("shutdown rejoin skipped: already busy")
        return
    end

    if not isAutoReconnectOn() then
        dprint("shutdown rejoin skipped: auto reconnect OFF")
        return
    end

    _shutdownRejoinBusy = true
    dprint("shutdown prompt detected -> wait", SHUTDOWN_REJOIN_DELAY_SEC, "sec")

    task.spawn(function()
        task.wait(SHUTDOWN_REJOIN_DELAY_SEC)
        local _, ax = readFlagsFromFile()

        if ax == true then
            local okQ, reasonQ = QueueAutoExecIfEnabled()
            dprint("shutdown queue =>", okQ, reasonQ)

            if not okQ then
                dprint("shutdown teleport CANCEL: QTP failed while auto_exec ON:", reasonQ)
                _shutdownRejoinBusy = false
                return
            end

            task.wait(0.8)
        end

        rejoinUntilSuccess({ ignoreBlock = true })
        _shutdownRejoinBusy = false
    end)
end

local function hookPrompt()
    task.spawn(function()
        local gui = CoreGui:WaitForChild("RobloxPromptGui", 30)
        if not gui then
            dprint("RobloxPromptGui not found")
            return
        end

        local overlay = gui:WaitForChild("promptOverlay", 30)
        if not overlay then
            dprint("promptOverlay not found")
            return
        end

        dprint("prompt hook attached")

        local function scan()
            local combined = collectGuiText(overlay)

            if isTeleportProblemText(combined) then
                hidePromptFast()
                return
            end

            for _, v in ipairs(overlay:GetDescendants()) do
                if v:IsA("TextLabel") or v:IsA("TextButton") then
                    local txt = tostring(v.Text or "")
                    if txt ~= "" then
                        dprint("label:", txt)
                    end

                    -- PRIORITAS 1: shutdown / server dimatikan / error 288
                    if isShutdownText(txt) or isShutdownText(combined) then
                        hidePromptFast() -- clear blur juga kalau Hide Prompt ON
                        tryShutdownRejoin()
                        return
                    end

                    -- PRIORITAS 2: kick UpdateNewServer
                    if isUpdateNewServerKickText(txt) or isUpdateNewServerKickText(combined) then
                        hidePromptFast()
                        G.__UPDATE_NEW_SERVER_REJOIN_PENDING = true
                        _G.__UPDATE_NEW_SERVER_REJOIN_PENDING = true
                        tryRejoin()
                        return
                    end

                    -- PRIORITAS 2b: kick WeatherKick
                    if isWeatherKickText(txt) or isWeatherKickText(combined) then
                        hidePromptFast()
                        G.__WEATHER_KICK_REJOIN_PENDING = true
                        _G.__WEATHER_KICK_REJOIN_PENDING = true
                        tryRejoin()
                        return
                    end

                    -- PRIORITAS 3: disconnect umum (bukan teleport gagal)
                    if (isDisconnectText(txt) or isDisconnectText(combined))
                        and not isTeleportProblemText(combined)
                    then
                        hidePromptFast()
                        if G.__WEATHER_KICK_REJOIN_PENDING == true
                            or _G.__WEATHER_KICK_REJOIN_PENDING == true then
                            tryRejoin()
                        elseif isAutoReconnectOn() then
                            tryRejoin()
                        end
                        return
                    end
                end
            end
        end

        scan()
        overlay.DescendantAdded:Connect(function(obj)
            dprint("DescendantAdded:", obj.ClassName, obj.Name)
            task.defer(function()
                maybeHideTeleportPrompt()
                scan()
            end)
        end)

        pcall(function()
            overlay:GetPropertyChangedSignal("Visible"):Connect(function()
                if overlay.Visible then
                    task.defer(scan)
                end
            end)
        end)

        pcall(function()
            gui:GetPropertyChangedSignal("Enabled"):Connect(function()
                if gui.Enabled then
                    task.defer(scan)
                end
            end)
        end)

        while true do
            task.wait(0.35)
            scan()
        end
    end)
end

hookPrompt()
startTeleportAntiPrompt()

