function M.SetHideTeleportPrompt(on)
    _hideTeleportPromptEnabled = (on == true)
    G.HIDE_PROMPT_ENABLED = _hideTeleportPromptEnabled
    _G.HIDE_PROMPT_ENABLED = _hideTeleportPromptEnabled
    startTeleportAntiPrompt()
    if _hideTeleportPromptEnabled then
        hidePromptFast()
    else
        restorePromptGui()
    end
end

M.RestoreTeleportPrompt = restorePromptGui

function M.SyncFromState(state)
    state = type(state) == "table" and state or G.STATE or rawget(_G, "STATE")
    local on = _hidePromptGloballyEnabled()

    if type(state) == "table" and type(state.hide_prompt) == "table" then
        on = (state.hide_prompt.enabled == true)
    end

    local main = G.MAIN or rawget(_G, "MAIN")
    if type(main) == "table" and type(main.misc) == "table" and type(main.misc.hide_prompt) == "table" then
        on = (main.misc.hide_prompt.enabled == true)
    end

    M.SetHideTeleportPrompt(on)
end

function M.SetEnabled(a, b)
    local on = a
    if type(a) == "table" and b ~= nil then
        on = b
    end
    AUTO_RECONNECT_ENABLED = (on == true)
end

function M.SetDelay(sec)
    REJOIN_DELAY_SEC = tonumber(sec) or REJOIN_DELAY_SEC
end

function M.TryRejoinNow()
    tryRejoin()
end

function M.RejoinOnce(delaySec)
    delaySec = tonumber(delaySec) or 0
    task.delay(math.max(0, delaySec), function()
        tryRejoin()
    end)
end

function M.ClearTeleportBlock()
    TELEPORT_BLOCKED = false
    return true
end

function M.ReleaseHopTeleportLock()
    local AH = G.AutoHopServer or rawget(_G, "AutoHopServer")
    if type(AH) == "table" and type(AH.ReleaseTeleportLock) == "function" then
        pcall(AH.ReleaseTeleportLock, AH)
    end
end

function M.RejoinNow()
    _rejoinInFlight = false
    TELEPORT_BLOCKED = false
    M.ReleaseHopTeleportLock()

    local _, ax = readFlagsFromFile()

    if ax == true then
        local okQ, reasonQ = QueueAutoExecIfEnabled()
        if not okQ then
            return false, reasonQ
        end
        task.wait(0.8)
    end

    task.spawn(function()
        _rejoinInFlight = true
        rejoinUntilSuccess({ ignoreBlock = true })
        _rejoinInFlight = false
    end)
    return true, "retrying_until_rejoin"
end

function M.IsTeleportBlocked()
    return TELEPORT_BLOCKED
end

function M.HideRobloxPrompt()
    hidePromptFast()
end

function M.ScheduleHidePrompt(sec)
    task.delay(tonumber(sec) or PROMPT_DISMISS_SEC, hidePromptFast)
end

function M.DebugPrint()
    local ar, ax = readFlagsFromFile()
    dprint(
        "auto_reconnect=", tostring(ar),
        "| auto_exec=", tostring(ax),
        "| teleport_blocked=", tostring(TELEPORT_BLOCKED),
        "| qtp=", tostring(getQTP() ~= nil),
        "| save=", tostring(getSaveFile())
    )
end

local function fireTravelRemote(toTrade)
    local RS = game:GetService("ReplicatedStorage")
    local TW = RS:WaitForChild("GameEvents"):WaitForChild("TradeWorld")
    local r = TW:WaitForChild(toTrade and "TravelToTradeWorld" or "TravelToMainWorld")

    local ok, err = pcall(function()
        r:FireServer()
    end)
    return ok, err
end

function M.TravelToMarket()
    -- kalau auto_exec ON -> queue loader dulu
    local _, ax = readFlagsFromFile()
    if ax == true then
        local okQ, reasonQ = QueueAutoExecIfEnabled()
        if not okQ then
            -- HARD GATE optional: cancel travel kalau QTP gagal
            return false, "QTP failed: " .. tostring(reasonQ)
        end
        task.wait(0.2)
    end

    return fireTravelRemote(true)
end

function M.TravelToMain()
    local _, ax = readFlagsFromFile()
    if ax == true then
        local okQ, reasonQ = QueueAutoExecIfEnabled()
        if not okQ then
            return false, "QTP failed: " .. tostring(reasonQ)
        end
        task.wait(0.2)
    end

    return fireTravelRemote(false)
end

