    _G.__UPDATE_NEW_SERVER_REJOIN_PENDING = true
    G.__UPDATE_NEW_SERVER_PENDING_DELAY = rejoinDelay
    _G.__UPDATE_NEW_SERVER_PENDING_DELAY = rejoinDelay

