local M = {}
M._running = false
M._thread = nil
M._kickBusy = false
M._weatherConn = nil
M._phaseConn = nil
M._mapConn = nil
M.DEBUG = false
-- true = hide Roblox disconnect prompt. Juga ikut HIDE_PROMPT_ENABLED.
M.HIDE_KICK_PROMPT = false

local Lighting = game:GetService("Lighting")

local function shouldHideKickPrompt()
    if M.HIDE_KICK_PROMPT == true then return true end
    if G.HIDE_PROMPT_ENABLED == true or rawget(_G, "HIDE_PROMPT_ENABLED") == true then
        return true
    end
    return false
end

local function clearKickBlur()
    pcall(function()
        for _, v in ipairs(Lighting:GetChildren()) do
            if v:IsA("BlurEffect") then
                v.Enabled = false
                pcall(function() v.Size = 0 end)
            end
        end
    end)
    pcall(function()
        for _, v in ipairs(CoreGui:GetDescendants()) do
            if v:IsA("BlurEffect") then
                v.Enabled = false
                pcall(function() v.Size = 0 end)
            end
        end
    end)
    local R = G.PSReconnect or rawget(_G, "PSReconnect")
    if type(R) == "table" and type(R.HideRobloxPrompt) == "function" then
        pcall(R.HideRobloxPrompt, R)
    end
end

local function dprint(...)
    if M.DEBUG ~= true then return end
    print("[WeatherKick]", ...)
end

local function truthy(v)
    return (v == true) or (v == 1) or (v == "true") or (v == "1")
end

-- 0 = auto sesuai durasi weather yang match; 1..600 = fixed sec
local function clampDelay(n)
    n = math.floor(tonumber(n) or 60)
    if n < 0 then n = 0 end
    if n > 600 then n = 600 end
    return n
end

local function getWeatherPredict()
    return G.WeatherPredict or G.WeatherPredictModule
        or rawget(_G, "WeatherPredict") or rawget(_G, "WeatherPredictModule")
end

local function defaultWeatherName()
    local WP = getWeatherPredict()
    if type(WP) == "table" and type(WP.GetWeatherNames) == "function" then
        local ok, names = pcall(WP.GetWeatherNames, WP)
        if ok and type(names) == "table" and type(names[1]) == "string" and names[1] ~= "" then
            return names[1]
        end
    end
    return ""
end

local function normalizeNameList(input, legacyName)
    local list = {}
    local seen = {}

    local function add(name)
        name = tostring(name or "")
        if name ~= "" and not seen[name] then
            seen[name] = true
            table.insert(list, name)
        end
    end

    if type(input) == "table" then
        for _, w in ipairs(input) do
            add(w)
        end
    elseif type(input) == "string" then
        add(input)
    end

    if legacyName ~= nil then
        add(legacyName)
    end

    return list
end

local function splitSelectedKeys(selected)
    local weathers, cycles = {}, {}
    local seenW = {}
    if type(selected) ~= "table" then return weathers, cycles end
    for _, rawKey in ipairs(selected) do
        local key = tostring(rawKey or "")
        if key:sub(1, 2) == PREFIX_WEATHER then
            local name = key:sub(3)
            if name ~= "" and not seenW[name] then
                seenW[name] = true
                table.insert(weathers, name)
            end
        end
    end
    table.sort(weathers)
    return weathers, cycles
end

local function buildSelectedFromLegacy(wk)
    local selected, seen = {}, {}
    local function add(key)
        key = tostring(key or "")
        if key == "" or seen[key] then return end
        if key:sub(1, 2) ~= PREFIX_WEATHER then return end
        seen[key] = true
        table.insert(selected, key)
    end
    if type(wk.weathers) == "table" then
        for _, name in ipairs(wk.weathers) do
            add(PREFIX_WEATHER .. tostring(name))
        end
    end
    if #selected == 0 and type(wk.weather) == "string" and wk.weather ~= "" then
        add(PREFIX_WEATHER .. wk.weather)
    end
    return selected
end

local function normalizeWeathers(input, legacyWeather)
    if type(input) == "table" then
        if type(input.weathers) == "table" then
            return normalizeNameList(input.weathers)
        end
        if type(input.cycles) == "table" or type(input.phases) == "table" then
            return normalizeNameList(nil)
        end
        return normalizeNameList(input, input.weather or input.selected_weather)
    end
    return normalizeNameList(input, legacyWeather)
end

local function normalizeCycles(input)
    if type(input) == "table" then
        if type(input.cycles) == "table" then
            return normalizeNameList(input.cycles)
        end
        if type(input.phases) == "table" then
            return normalizeNameList(input.phases)
        end
    end
    return normalizeNameList(input)
end

local function normalizeSelection(input, legacyWeather, legacyCycles)
    local weathers, cycles

    if type(input) == "table" and (type(input.weathers) == "table" or type(input.cycles) == "table" or type(input.phases) == "table") then
        weathers = normalizeWeathers(input)
        cycles = normalizeCycles(input)
    else
        weathers = normalizeWeathers(input, legacyWeather)
        cycles = normalizeCycles(legacyCycles)
    end

    return weathers, cycles
end

local function selectionToText(weathers)
    local parts = {}
    if type(weathers) == "table" then
        for _, name in ipairs(weathers) do
            table.insert(parts, tostring(name))
        end
    end
    if #parts == 0 then return "?" end
    if #parts <= 3 then
        return table.concat(parts, ", ")
    end
    return table.concat(parts, ", ", 1, 3) .. "..."
end

local function publishGlobals(enabled, weathers, delay, selected)
    G.WEATHER_KICK_ENABLED = enabled
    G.WEATHER_KICK_WEATHERS = weathers
    G.WEATHER_KICK_CYCLES = {}
    G.WEATHER_KICK_SELECTED = selected or {}
    G.WEATHER_KICK_REJOIN_DELAY_SEC = delay
    _G.WEATHER_KICK_ENABLED = enabled
    _G.WEATHER_KICK_WEATHERS = weathers
    _G.WEATHER_KICK_CYCLES = {}
    _G.WEATHER_KICK_SELECTED = selected or {}
    _G.WEATHER_KICK_REJOIN_DELAY_SEC = delay
end

local function getMainRejoin()
    local main = G.MAIN or _G.MAIN
    if type(main) == "table" and type(main.misc) == "table" and type(main.misc.rejoin) == "table" then
        return main.misc.rejoin
    end
    return nil
end

local function normalizeWeatherKick(wk)
    wk = type(wk) == "table" and wk or {}
    wk.enabled = (wk.enabled == true)
    if type(wk.selected) == "table" then
        wk.weathers = select(1, splitSelectedKeys(wk.selected))
    else
        wk.weathers = normalizeWeathers(wk)
    end
    wk.cycles = {}
    wk.rejoin_delay_sec = clampDelay(wk.rejoin_delay_sec)
    return wk
end

local function selectedKeysFromWeathers(weathers)
    local selected = {}
    for _, name in ipairs(weathers or {}) do
        selected[#selected + 1] = PREFIX_WEATHER .. tostring(name)
    end
    return selected
end

local function getCfg()
    local enabled, weathers, delay

    local rjMain = getMainRejoin()
    if type(rjMain) == "table" and type(rjMain.weather_kick) == "table" then
        local wk = normalizeWeatherKick(rjMain.weather_kick)
        enabled = wk.enabled
        weathers = wk.weathers
        delay = wk.rejoin_delay_sec
    end

    local STATE = G.STATE or _G.STATE
    if type(STATE) == "table" and type(STATE.rejoin) == "table" and type(STATE.rejoin.weather_kick) == "table" then
        local wk = normalizeWeatherKick(STATE.rejoin.weather_kick)
        if enabled == nil then enabled = wk.enabled end
        if weathers == nil or #weathers == 0 then weathers = wk.weathers end
        if delay == nil then delay = wk.rejoin_delay_sec end
    end

    if type(G.__WEATHER_KICK_SAVED) == "table" then
        if enabled == nil and G.__WEATHER_KICK_SAVED.enabled ~= nil then
            enabled = truthy(G.__WEATHER_KICK_SAVED.enabled)
        end
        if type(G.__WEATHER_KICK_SAVED.selected) == "table" then
            weathers = select(1, splitSelectedKeys(G.__WEATHER_KICK_SAVED.selected))
        end
        if (weathers == nil or #weathers == 0) and type(G.__WEATHER_KICK_SAVED.weathers) == "table" then
            weathers = normalizeNameList(G.__WEATHER_KICK_SAVED.weathers)
        end
        if (weathers == nil or #weathers == 0) and G.__WEATHER_KICK_SAVED.weather ~= nil then
            weathers = normalizeNameList(G.__WEATHER_KICK_SAVED.weather)
        end
        if delay == nil and G.__WEATHER_KICK_SAVED.rejoin_delay_sec ~= nil then
            delay = G.__WEATHER_KICK_SAVED.rejoin_delay_sec
        end
    end

    if enabled == nil then
        enabled = (G.WEATHER_KICK_ENABLED == true) or (rawget(_G, "WEATHER_KICK_ENABLED") == true)
    end
    if weathers == nil or #weathers == 0 then
        local sel = G.WEATHER_KICK_SELECTED or rawget(_G, "WEATHER_KICK_SELECTED")
        if type(sel) == "table" and #sel > 0 then
            weathers = select(1, splitSelectedKeys(sel))
        end
    end
    if weathers == nil or #weathers == 0 then
        weathers = G.WEATHER_KICK_WEATHERS or rawget(_G, "WEATHER_KICK_WEATHERS")
        weathers = normalizeNameList(weathers)
    end
    if delay == nil then
        delay = G.WEATHER_KICK_REJOIN_DELAY_SEC or rawget(_G, "WEATHER_KICK_REJOIN_DELAY_SEC")
    end

    enabled = (enabled == true)
    weathers = normalizeWeathers({ weathers = weathers })
    delay = clampDelay(delay)

    -- Runtime globals (UI / Apply) win over stale MAIN mirror
    if type(G.WEATHER_KICK_ENABLED) == "boolean" then
        enabled = (G.WEATHER_KICK_ENABLED == true)
    elseif rawget(_G, "WEATHER_KICK_ENABLED") ~= nil then
        enabled = (_G.WEATHER_KICK_ENABLED == true)
    end
    if type(G.WEATHER_KICK_WEATHERS) == "table" and #G.WEATHER_KICK_WEATHERS > 0 then
        weathers = normalizeNameList(G.WEATHER_KICK_WEATHERS)
    end
    if G.WEATHER_KICK_REJOIN_DELAY_SEC ~= nil then
        delay = clampDelay(G.WEATHER_KICK_REJOIN_DELAY_SEC)
    end
    weathers = normalizeWeathers({ weathers = weathers })

    local cycles = {}
    local selected = selectedKeysFromWeathers(weathers)

    publishGlobals(enabled, weathers, delay, selected)

    return enabled, weathers, cycles, delay
end

local function liveStr(v)
    if v == nil then return "" end
    return tostring(v)
end

local function nameKey(s)
    s = liveStr(s):gsub("^%s+", ""):gsub("%s+$", "")
    return string.lower(s:gsub("[%s_%-]", ""))
end

local function weatherMatches(selected, live)
    local sk = nameKey(selected)
    local lk = nameKey(live)
    if sk == "" or lk == "" then return false end
    return sk == lk
end

local function phaseMatches(selected, live)
    local sk = nameKey(selected)
    local lk = nameKey(live)
    if sk == "" or lk == "" then return false end
    return sk == lk
end

local function activeWeather()
    return Workspace:GetAttribute("ActiveWeather")
end

local function activePhase()
    return Workspace:GetAttribute("ActivePhase")
end

local function weatherMatchesAny(weathers, live)
    if type(weathers) ~= "table" or #weathers == 0 then return false end
    live = liveStr(live)
    if live == "" then return false end
    for _, selected in ipairs(weathers) do
        if weatherMatches(selected, live) then
            return true
        end
    end
    return false
end

local function readMapWeatherPlaying(name)
    name = tostring(name or "")
    if name == "" then return false end

    local GAG2 = G.GAG2_WEATHER or rawget(_G, "GAG2_WEATHER")
    if type(GAG2) == "table" and type(GAG2.readMap) == "function" then
        local ok, row = pcall(GAG2.readMap, name)
        if ok and type(row) == "table" and row.playing == true then
            return true
        end
    end

    local WP = getWeatherPredict()
    if type(WP) == "table" and type(WP.IsWeatherLive) == "function" then
        local ok, hit, source = pcall(function()
            return WP:IsWeatherLive(name)
        end)
        if ok and hit == true then
            return true
        end
    end

    local WeatherValues = ReplicatedStorage:FindFirstChild("WeatherValues")
    if WeatherValues and WeatherValues:GetAttribute(name .. "_Playing") == true then
        return true
    end
    return false
end

local function isSelectedWeatherLive(selectedName)
    selectedName = tostring(selectedName or "")
    if selectedName == "" then return false, nil end

    local WP = getWeatherPredict()
    if type(WP) == "table" and type(WP.IsWeatherLive) == "function" then
        local ok, live, source = pcall(function()
            return WP:IsWeatherLive(selectedName)
        end)
        if ok and live == true then
            return true, source or selectedName
        end
    end

    local liveWeather = activeWeather()
    if weatherMatches(selectedName, liveWeather or "") then
        return true, liveWeather
    end

    if readMapWeatherPlaying(selectedName) then
        return true, selectedName
    end

    return false, nil
end

local function weatherMatchesAnySelected(weathers)
    if type(weathers) ~= "table" or #weathers == 0 then return false, nil end
    for _, selected in ipairs(weathers) do
        local hit, source = isSelectedWeatherLive(selected)
        if hit then
            return true, source
        end
    end
    return false, nil
end

local function getLiveMapWeatherNames()
    local WP = getWeatherPredict()
    if type(WP) == "table" and type(WP.GetLiveMapWeathers) == "function" then
        local ok, list = pcall(WP.GetLiveMapWeathers, WP)
        if ok and type(list) == "table" then
            return list
        end
    end

    local out = {}
    local WeatherValues = ReplicatedStorage:FindFirstChild("WeatherValues")
    if not WeatherValues then return out end
    for attrName in pairs(WeatherValues:GetAttributes()) do
        if type(attrName) == "string" then
            local base = attrName:match("^(.+)_Playing$")
            if base and WeatherValues:GetAttribute(attrName) == true then
                out[#out + 1] = base
            end
        end
    end
    table.sort(out)
    return out
end

local function phaseMatchesAny(cycles, live)
    if type(cycles) ~= "table" or #cycles == 0 then return false end
    live = liveStr(live)
    if live == "" then return false end
    for _, selected in ipairs(cycles) do
        if phaseMatches(selected, live) then
            return true
        end
    end
    return false
end

local function serverNow()
    local ok, t = pcall(function()
        return Workspace:GetServerTimeNow()
    end)
    if ok and type(t) == "number" then return t end
    return os.time()
end

local function weatherConfigDuration(name)
    name = tostring(name or "")
    if name == "" then return nil end

    local WP = getWeatherPredict()
    if type(WP) == "table" and type(WP.GetWeatherDuration) == "function" then
        local ok, sec = pcall(WP.GetWeatherDuration, WP, name)
        if ok and type(sec) == "number" and sec > 0 then
            return math.floor(sec)
        end
    end

    local SM = ReplicatedStorage:FindFirstChild("SharedModules")
    local wdInst = SM and SM:FindFirstChild("WeatherData")
    if not wdInst then return nil end
    local ok, wd = pcall(require, wdInst)
    if not ok or type(wd) ~= "table" or type(wd.Data) ~= "table" then return nil end

    local key = nameKey(name)
    local function entryDur(entry)
        if type(entry) ~= "table" then return nil end
        local d = tonumber(entry.Lasts or entry.Last or entry.Duration or entry.Length)
        if d and d > 0 then return math.floor(d) end
        return nil
    end

    if wd.Data[1] then
        for _, entry in ipairs(wd.Data) do
            if type(entry) == "table" and nameKey(entry.Name) == key then
                return entryDur(entry)
            end
        end
    else
        for wName, entry in pairs(wd.Data) do
            local n = (type(entry) == "table" and entry.Name) or wName
            if nameKey(n) == key then
                return entryDur(entry)
            end
        end
    end
    return nil
end

local function weatherLiveRemaining(name)
    name = tostring(name or "")
    if name == "" then return nil end
    local WeatherValues = ReplicatedStorage:FindFirstChild("WeatherValues")
    if not WeatherValues then return nil end
    if WeatherValues:GetAttribute(name .. "_Playing") ~= true then return nil end

    local t = serverNow()
    local startTime = WeatherValues:GetAttribute(name .. "_StartTime")
    local duration = tonumber(WeatherValues:GetAttribute(name .. "_Duration"))
    local endTime = WeatherValues:GetAttribute(name .. "_EndTime")

    if type(startTime) == "number" and startTime > 1e9 and type(duration) == "number" and duration > 0 then
        return math.max(1, math.floor((startTime + duration) - t))
    end
    if type(endTime) == "number" and endTime > 1e9 then
        return math.max(1, math.floor(endTime - t))
    end
    if type(duration) == "number" and duration > 0 then
        return math.floor(duration)
    end
    return nil
end

-- delay cfg 0 → pakai durasi weather (sisa live, fallback config Lasts)
local function resolveRejoinDelay(cfgDelay, weatherName)
    cfgDelay = clampDelay(cfgDelay)
    if cfgDelay > 0 then
        return cfgDelay, "fixed"
    end

    local rem = weatherLiveRemaining(weatherName)
    if rem and rem > 0 then
        return math.min(600, rem), "live_remaining"
    end

    local cfg = weatherConfigDuration(weatherName)
    if cfg and cfg > 0 then
        return math.min(600, cfg), "weather_duration"
    end

    return FALLBACK_AUTO_DELAY, "fallback"
end

local function hideDisconnectPrompt()
    if not shouldHideKickPrompt() then return end
    pcall(function()
        GuiService:ClearError()
    end)

    pcall(function()
        local gui = CoreGui:FindFirstChild("RobloxPromptGui")
        if not gui then return end
        gui.Enabled = false
        for _, v in ipairs(gui:GetDescendants()) do
            if v:IsA("GuiObject") then
                v.Visible = false
            end
        end
    end)
    clearKickBlur()
end

local function startAntiPrompt()
    if not shouldHideKickPrompt() then return end
    if G.__WEATHER_KICK_ANTI_PROMPT == true then return end
    G.__WEATHER_KICK_ANTI_PROMPT = true
    task.spawn(function()
        while shouldHideKickPrompt() do
            hideDisconnectPrompt()
            task.wait(0.05)
        end
        G.__WEATHER_KICK_ANTI_PROMPT = nil
    end)
end

local function doKick(reason, weatherName)
    reason = tostring(reason or "weather")
    weatherName = tostring(weatherName or activeWeather() or "")
    local _, _, _, cfgDelay = getCfg()
    cfgDelay = clampDelay(cfgDelay)
    local delay, delaySource = resolveRejoinDelay(cfgDelay, weatherName)
    local hidePrompt = shouldHideKickPrompt()

    dprint("KICK NOW:", reason, "| cfgDelay=", cfgDelay, "| effective=", delay, "(" .. delaySource .. ")")

    G.__WEATHER_KICK_REJOIN_PENDING = true
    _G.__WEATHER_KICK_REJOIN_PENDING = true
    -- delay efektif untuk PSReconnect (cfg 0 tetap tersimpan di MAIN)
    G.__WEATHER_KICK_PENDING_DELAY = delay
    _G.__WEATHER_KICK_PENDING_DELAY = delay
    G.__WEATHER_KICK_PENDING_WEATHER = weatherName
    _G.__WEATHER_KICK_PENDING_WEATHER = weatherName

    if hidePrompt then
        startAntiPrompt()
        hideDisconnectPrompt()
        task.wait(0.15)
        hideDisconnectPrompt()
    end

    -- kalau hide prompt ON: kick kosong; kalau OFF: tampilkan keterangan
    local msg = ""
    if not hidePrompt then
        msg = string.format(
            "WeatherKick: %s | rejoin %ds%s",
            reason,
            delay,
            (cfgDelay == 0) and " (auto weather)" or ""
        )
    end

    local ok, err = pcall(function()
        LP:Kick(msg)
    end)

    if not ok then
        dprint("Kick failed:", tostring(err))
        G.__WEATHER_KICK_REJOIN_PENDING = nil
        _G.__WEATHER_KICK_REJOIN_PENDING = nil
        G.__WEATHER_KICK_PENDING_DELAY = nil
        _G.__WEATHER_KICK_PENDING_DELAY = nil
    end

    if hidePrompt then
        task.defer(hideDisconnectPrompt)
        task.delay(0.2, hideDisconnectPrompt)
        task.delay(0.5, hideDisconnectPrompt)
    end
    return ok
end

local function tryKickForMatch()
    if M._kickBusy then return end

    local enabled, weathers = getCfg()
    if not enabled then return end
    if #weathers == 0 then return end

    local weatherHit, matchSource = weatherMatchesAnySelected(weathers)
    if not weatherHit then return end

    M._kickBusy = true
    local reason = "weather match: " .. tostring(matchSource or activeWeather())
    dprint("Match:", selectionToText(weathers), "~", reason)
    dprint("Match disconnect:", reason, "| selected:", selectionToText(weathers))
    doKick(reason, matchSource or activeWeather())

    task.delay(120, function()
        M._kickBusy = false
    end)
end

function M.GetWeatherOptions()
    local WP = getWeatherPredict()
    if type(WP) == "table" and type(WP.GetKickTargetOptions) == "function" then
        local ok, items = pcall(WP.GetKickTargetOptions, WP)
        if ok and type(items) == "table" and #items > 0 then
            return items
        end
    end
    if type(WP) == "table" and type(WP.GetWeatherOptions) == "function" then
        local ok, items = pcall(WP.GetWeatherOptions, WP)
        if ok and type(items) == "table" and #items > 0 then
            return items
        end
    end
    return {}
end

function M.GetStatus()
    local enabled, weathers, _, delay = getCfg()
    local liveWeather = activeWeather()
    local livePhase = activePhase()
    local liveMap = getLiveMapWeatherNames()
    local weatherHit, matchSource = weatherMatchesAnySelected(weathers)
    local previewWeather = matchSource or (weathers and weathers[1]) or liveWeather
    local effectiveDelay, delaySource = resolveRejoinDelay(delay, previewWeather)
    return {
        enabled = enabled,
        selected = weathers,
        selected_weathers = weathers,
        selected_cycles = {},
        selected_text = selectionToText(weathers),
        live = matchSource or liveWeather,
        live_weather = liveWeather,
        live_map = liveMap,
        live_phase = livePhase,
        live_weather_type = typeof(liveWeather),
        live_phase_type = typeof(livePhase),
        matched = weatherHit,
        matched_weather = weatherHit,
        matched_source = matchSource,
        matched_phase = false,
        rejoin_delay_sec = delay,
        rejoin_delay_auto = (delay == 0),
        rejoin_delay_effective = effectiveDelay,
        rejoin_delay_source = delaySource,
        hide_kick_prompt = (M.HIDE_KICK_PROMPT == true),
        running = M._running == true,
        kickBusy = M._kickBusy == true,
    }
end

local function jsonList(t)
    if type(t) ~= "table" then return "[]" end
    local parts = {}
    for i, v in ipairs(t) do
        parts[i] = string.format("%q", tostring(v))
    end
    return "[" .. table.concat(parts, ", ") .. "]"
end

function M.DebugDump(opts)
    opts = type(opts) == "table" and opts or {}
    local st = M.GetStatus()
    local lines = {
        "=== WeatherKick Debug ===",
        "module_ver=" .. tostring(MODULE_VER),
        "running=" .. tostring(st.running),
        "enabled=" .. tostring(st.enabled),
        "kickBusy=" .. tostring(st.kickBusy),
        "selected_text=" .. tostring(st.selected_text),
        "weathers=" .. jsonList(st.selected_weathers),
        "cycles=" .. jsonList(st.selected_cycles),
        "live_phase=" .. tostring(st.live_phase) .. " (" .. tostring(st.live_phase_type) .. ")",
        "live_weather=" .. tostring(st.live_weather) .. " (" .. tostring(st.live_weather_type) .. ")",
        "live_map=" .. jsonList(st.live_map),
        "matched_source=" .. tostring(st.matched_source),
        "matched=" .. tostring(st.matched),
        "matched_phase=" .. tostring(st.matched_phase),
        "matched_weather=" .. tostring(st.matched_weather),
        "rejoin_delay_sec=" .. tostring(st.rejoin_delay_sec),
    }
    if type(st.selected_cycles) == "table" and st.selected_cycles[1] ~= nil then
        lines[#lines + 1] = "phase_key="
            .. nameKey(st.selected_cycles[1]) .. " vs " .. nameKey(st.live_phase)
    end
    if type(st.selected_weathers) == "table" and st.selected_weathers[1] ~= nil then
        lines[#lines + 1] = "weather_key="
            .. nameKey(st.selected_weathers[1]) .. " vs " .. nameKey(st.live_weather)
    end
    lines[#lines + 1] = "WEATHER_KICK_ENABLED=" .. tostring(G.WEATHER_KICK_ENABLED)
    lines[#lines + 1] = "WEATHER_KICK_SELECTED=" .. jsonList(G.WEATHER_KICK_SELECTED)
    lines[#lines + 1] = "WEATHER_KICK_CYCLES=" .. jsonList(G.WEATHER_KICK_CYCLES)
    lines[#lines + 1] = "WEATHER_KICK_WEATHERS=" .. jsonList(G.WEATHER_KICK_WEATHERS)
    local main = G.MAIN or _G.MAIN
    if type(main) == "table" and type(main.misc) == "table"
        and type(main.misc.rejoin) == "table"
        and type(main.misc.rejoin.weather_kick) == "table" then
        local wk = main.misc.rejoin.weather_kick
        lines[#lines + 1] = "MAIN.selected=" .. jsonList(wk.selected)
        lines[#lines + 1] = "MAIN.enabled=" .. tostring(wk.enabled)
    end
    for _, line in ipairs(lines) do
        if opts.warn == true then
            warn(line)
        else
            print(line)
        end
    end
    if opts.testKick == true then
        warn("[WeatherKick] testKick — manual kick")
        M.KickNow("debug_testKick")
    end
    return st
end

G.GAG2DebugWeatherKick = function(opts) return M.DebugDump(opts) end
_G.GAG2DebugWeatherKick = G.GAG2DebugWeatherKick

function M.KickNow(reason)
    return doKick(reason or "manual")
end

function M.IsRunning()
    return M._running == true
end

function M.Apply(selfOrEnabled, maybeEnabled, maybeSelection, maybeDelay)
    local enabled, selection, delay
    local forcedEnabled = nil

    if selfOrEnabled == M then
        enabled = maybeEnabled
        selection = maybeSelection
        delay = maybeDelay
        if maybeEnabled ~= nil then
            forcedEnabled = truthy(maybeEnabled)
        end
    else
        enabled = selfOrEnabled
        selection = maybeEnabled
        delay = maybeSelection
        if selfOrEnabled ~= nil then
            forcedEnabled = truthy(selfOrEnabled)
        end
    end

    if enabled ~= nil then
        enabled = truthy(enabled)
        G.WEATHER_KICK_ENABLED = enabled
        _G.WEATHER_KICK_ENABLED = enabled
    end

    if selection ~= nil then
        local weathers, selectedKeys
        if type(selection) == "table" and selection[1] ~= nil then
            selectedKeys = selection
            weathers = select(1, splitSelectedKeys(selection))
        elseif type(selection) == "table" and type(selection.selected) == "table" then
            selectedKeys = selection.selected
            weathers = select(1, splitSelectedKeys(selection.selected))
        else
            weathers = normalizeWeathers(selection)
            selectedKeys = selectedKeysFromWeathers(weathers)
        end
        publishGlobals(
            forcedEnabled ~= nil and forcedEnabled or (G.WEATHER_KICK_ENABLED == true),
            weathers,
            G.WEATHER_KICK_REJOIN_DELAY_SEC or 60,
            selectedKeysFromWeathers(weathers)
        )
    end
    if delay ~= nil then
        delay = clampDelay(delay)
        G.WEATHER_KICK_REJOIN_DELAY_SEC = delay
        _G.WEATHER_KICK_REJOIN_DELAY_SEC = delay
    end

    enabled, weathers, _, delay = getCfg()
    if forcedEnabled ~= nil then
        enabled = forcedEnabled
    end
    local selectedKeys = selectedKeysFromWeathers(weathers)
    publishGlobals(enabled, weathers, delay, selectedKeys)
    G.__WEATHER_KICK_SAVED = {
        enabled = enabled,
        selected = selectedKeys,
        rejoin_delay_sec = delay,
    }

    if enabled then
        M._ensureRunning()
    elseif M._running then
        M.Stop("disabled")
    end
end

function M.SetEnabled(on)
    M.Apply((on == true), {
        weathers = G.WEATHER_KICK_WEATHERS or G.WEATHER_KICK_SELECTED,
    }, G.WEATHER_KICK_REJOIN_DELAY_SEC)
end

local function disconnectSignal(conn)
    if conn then
        pcall(function() conn:Disconnect() end)
    end
end

function M._ensureRunning()
    if M._running then
        -- already polling; still check immediately after config change
        task.defer(tryKickForMatch)
        return
    end
    M._running = true
    M._kickBusy = false

    dprint("Started")

    disconnectSignal(M._weatherConn)
    disconnectSignal(M._phaseConn)
    disconnectSignal(M._mapConn)
    M._weatherConn = nil
    M._phaseConn = nil
    M._mapConn = nil

    pcall(function()
        M._weatherConn = Workspace:GetAttributeChangedSignal("ActiveWeather"):Connect(function()
            task.defer(tryKickForMatch)
        end)
    end)

    pcall(function()
        local WeatherValues = ReplicatedStorage:FindFirstChild("WeatherValues")
            or ReplicatedStorage:WaitForChild("WeatherValues", 10)
        if WeatherValues then
            M._mapConn = WeatherValues.AttributeChanged:Connect(function()
                task.defer(tryKickForMatch)
            end)
        end
    end)

    M._thread = task.spawn(function()
        task.wait(2)
        tryKickForMatch()
        while M._running do
            tryKickForMatch()
            task.wait(2)
        end
    end)
end

function M.Start()
    local enabled = select(1, getCfg())
    if enabled ~= true then
        dprint("Start aborted: disabled")
        return
    end
    M._ensureRunning()
end

function M.Stop(reason)
    if M._running ~= true then return end
    M._running = false
    M._thread = nil
    disconnectSignal(M._weatherConn)
    disconnectSignal(M._phaseConn)
    disconnectSignal(M._mapConn)
    M._weatherConn = nil
    M._phaseConn = nil
    M._mapConn = nil
    dprint("Stop:", tostring(reason or "manual"))
end

function M.SyncFromState()
    M.Apply()
end

M.syncFromGlobals = M.SyncFromState

G.WeatherKick = M
_G.WeatherKick = M

return M
 end,                  required = false },
    { key = "OpenEgg",                 name = "Open Egg",                factory = function() -- OpenEgg.lua — Open Egg (AUTO → Pet). Egg-only module.

local Players           = game:GetService("Players")
local ReplicatedStorage = game:GetService("ReplicatedStorage")
local CollectionService = game:GetService("CollectionService")

local LP = Players.LocalPlayer
local G  = (getgenv and getgenv()) or _G

local function _getBackpack()
    if not LP then return nil end
    return LP:FindFirstChild("Backpack") or LP:FindFirstChildOfClass("Backpack")
end

local MODULE_VER = 69

if G.__OPEN_EGG_VER == MODULE_VER and type(G.OpenEgg) == "table" then
    return G.OpenEgg
end
G.__OPEN_EGG_VER = MODULE_VER
G.__AUTO_VULN_VER = MODULE_VER

local POLL_SEC = 2
local EGG_REPLICATE_POLL_SEC = 0.02
local EGG_REPLICATE_ENRICH_SEC = 0.08
local EGG_REPLICATE_FALLBACK_SEC = 0.75
local EGG_OPEN_ALL_BATCH_CAP = 250
local EGG_READY_POLL_SEC = 0.25
local EGG_READY_MAX_WAIT_SEC = 120
local NET_WAIT_SEC = 15

-- forward declare (dipakai webhook sebelum definisi fungsi di bawah)
local countEggs
local _waitEggOpenReady

local M = {}
M._running = false
M._thread = nil
M._eggBusy = false
M._eggPhase = nil
M._eggPhaseUntil = 0
M._eggWaitReadyReason = nil
M._lastEggCount = nil
M._peakEggCount = 0
M._eggCycleActive = false
M._eggOpenedThisCycle = 0
M._eggOpenTarget = 0
M._eggWebhookSent = {}
M._eggWebhookMissingWarned = false
M._eggBatchDone = false
M._uiWantEnabled = false
M._lastEggRoll = nil
M._lastEggOpenRes = nil
M._lastEggRepl = nil
M._eggReplicateConns = {}
M._eggReplicateHooked = false
M._eggReplicateQueue = {}
M._eggMatchStop = false
M.DEBUG = false

local function dprint(...)
    if M.DEBUG ~= true then return end
    print("[OpenEgg]", ...)
end

local function _anyBusy()
    return M._eggBusy == true
end

local function _setEggPhase(phase, untilClock)
    M._eggPhase = phase
    M._eggPhaseUntil = untilClock or 0
end

local function _clearEggPhase()
    M._eggPhase = nil
    M._eggPhaseUntil = 0
    M._eggWaitReadyReason = nil
end

local function _eggWaitReadyStatusText(reason)
    reason = tostring(reason or "")
    if reason == "loading_screen" then
        return " · Loading..."
    end
    if reason == "offline_growth" or reason == "offline_cutscene" then
        return " · Grow offline..."
    end
    if reason == "cutscene_blocked" then
        return " · Cutscene..."
    end
    if reason == "data_not_loaded" then
        return " · Save load..."
    end
    if reason == "player_state" then
        return " · PlayerState..."
    end
    if reason == "no_plot_id" then
        return " · Plot..."
    end
    return " · Wait ready..."
end

local function _eggStatusPhaseText()
    local phase = M._eggPhase
    if phase == "wait_ready" then
        return _eggWaitReadyStatusText(M._eggWaitReadyReason)
    end
    if M._eggCycleActive == true then
        return (" · Opening %d/%d"):format(
            tonumber(M._eggOpenedThisCycle) or 0,
            tonumber(M._eggOpenTarget) or 0
        )
    end
    if phase == "wait" then
        local left = math.ceil(math.max(0, (M._eggPhaseUntil or 0) - os.clock()))
        return (" · Wait %ds"):format(left)
    end
    if M._eggBusy == true then
        return " · Proses..."
    end
    return ""
end

local function _flushEggUiConfig()
    local fn = G.__GAG2_FLUSH_OPEN_EGG or rawget(_G, "__GAG2_FLUSH_OPEN_EGG")
    if type(fn) == "function" then
        pcall(fn)
    end
end

local function _readEggMaxOpen(eggRaw)
    eggRaw = type(eggRaw) == "table" and eggRaw or {}
    local fromState = tonumber(eggRaw.max_open)
    -- Respect explicit 0 (= all) — jangan pakai `fromState or fromG` karena 0 falsy di Lua
    if fromState ~= nil then
        return math.max(0, math.floor(fromState))
    end
    local fromG = G.OPEN_EGG_MAX_OPEN
    if fromG == nil then
        fromG = rawget(_G, "OPEN_EGG_MAX_OPEN")
    end
    fromG = tonumber(fromG)
    if fromG ~= nil and fromG > 0 then
        return math.max(0, math.floor(fromG))
    end
    return 0
end

local function getCfg()
    local main = G.MAIN or rawget(_G, "MAIN")
    local eggRaw = {}
    if type(main) == "table" and type(main.auto) == "table" and type(main.auto.openEgg) == "table" then
        eggRaw = main.auto.openEgg
    elseif type(main) == "table" and type(main.misc) == "table"
        and type(main.misc.auto_vuln) == "table" and type(main.misc.auto_vuln.egg) == "table" then
        eggRaw = main.misc.auto_vuln.egg
    end

    local eggSelected = G.OPEN_EGG_SELECTED or rawget(_G, "OPEN_EGG_SELECTED")
        or G.AUTO_VULN_EGG_SELECTED or rawget(_G, "AUTO_VULN_EGG_SELECTED")
    if type(eggSelected) ~= "table" then
        eggSelected = {}
        if type(eggRaw.eggs) == "table" then
            for _, v in ipairs(eggRaw.eggs) do
                eggSelected[tostring(v)] = true
            end
        end
    end

    local eggRules = G.OPEN_EGG_RULES or rawget(_G, "OPEN_EGG_RULES")
        or G.AUTO_VULN_EGG_RULES or rawget(_G, "AUTO_VULN_EGG_RULES")
    if type(eggRules) ~= "table" then
        eggRules = type(eggRaw.rules) == "table" and eggRaw.rules or {}
    end

    local eggRulesOrder = G.OPEN_EGG_RULES_ORDER or rawget(_G, "OPEN_EGG_RULES_ORDER")
        or G.AUTO_VULN_EGG_RULES_ORDER or rawget(_G, "AUTO_VULN_EGG_RULES_ORDER")
    if type(eggRulesOrder) ~= "table" then
        eggRulesOrder = type(eggRaw.rulesOrder) == "table" and eggRaw.rulesOrder or {}
    end

    local openOn = (G.OPEN_EGG_ENABLED == true) or (rawget(_G, "OPEN_EGG_ENABLED") == true)
        or (G.AUTO_VULN_EGG_OPEN_EGG == true) or (eggRaw.open_egg == true) or (eggRaw.enabled == true)
        or (eggRaw.auto_open == true)

    -- Prefer live global max_open (UI) over stale MAIN when both exist.
    local maxOpen
    local maxOpenG = G.OPEN_EGG_MAX_OPEN
    if maxOpenG == nil then
        maxOpenG = rawget(_G, "OPEN_EGG_MAX_OPEN")
    end
    if tonumber(maxOpenG) ~= nil then
        maxOpen = math.max(0, math.floor(tonumber(maxOpenG)))
    else
        maxOpen = _readEggMaxOpen(eggRaw)
    end

    return {
        egg = {
            enabled = openOn,
            eggs = eggSelected,
            max_open = maxOpen,
            rules = eggRules,
            rulesOrder = eggRulesOrder,
            open_egg = openOn,
        },
    }
end

local function anyEnabled(cfg)
    cfg = cfg or getCfg()
    local eggCfg = type(cfg.egg) == "table" and cfg.egg or {}
    return eggCfg.open_egg == true
end

local function isLoadingActive()
    if not LP then return false end
    if LP:GetAttribute("LoadingScreenDone") == true then
        return false
    end
    if LP:GetAttribute("LoadingScreenActive") == true then
        return true
    end
    return workspace:FindFirstChild("LoadingScreenMenu") ~= nil
end

local PlayerStateClient = nil

local function _ensurePlayerStateClient()
    if PlayerStateClient then return true end
    local cm = ReplicatedStorage:FindFirstChild("ClientModules")
    local modInst = cm and cm:FindFirstChild("PlayerStateClient")
    if not modInst then return false end
    local ok, mod = pcall(require, modInst)
    if ok and type(mod) == "table" then
        PlayerStateClient = mod
        return true
    end
    return false
end

local function _getLocalPlayerReplica(waitSec)
    if not _ensurePlayerStateClient() then return nil end
    if type(PlayerStateClient.GetLocalReplica) ~= "function" then return nil end
    local replica = PlayerStateClient:GetLocalReplica()
    if replica then return replica end
    waitSec = tonumber(waitSec) or 0
    if waitSec > 0 and type(PlayerStateClient.WaitForLocalReplica) == "function" then
        return PlayerStateClient:WaitForLocalReplica(waitSec)
    end
    return nil
end

local function _replicaLooksReady(replica)
    if not replica or type(replica.Data) ~= "table" then return false end
    if type(replica.IsActive) == "function" then
        local ok, active = pcall(replica.IsActive, replica)
        if ok and active ~= true then return false end
    end
    return true
end

local function _isEggOpenBlocked()
    -- Sama AutoPlant: hanya block saat cutscene/offline growth benar-benar jalan.
    if G.__GAG2_OFFLINE_GROWTH_BUSY == true or rawget(_G, "__GAG2_OFFLINE_GROWTH_BUSY") == true then
        return true, "offline_growth"
    end
    if LP and LP:GetAttribute("OfflineCutscenePlaying") == true then
        return true, "offline_cutscene"
    end
    if LP and LP:GetAttribute("CutsceneInputBlocked") == true then
        return true, "cutscene_blocked"
    end
    if isLoadingActive() then
        return true, "loading_screen"
    end
    if LP and not CollectionService:HasTag(LP, "DataLoaded") then
        return true, "data_not_loaded"
    end
    if LP and LP:GetAttribute("PlotId") == nil then
        return true, "no_plot_id"
    end
    if not _replicaLooksReady(_getLocalPlayerReplica(0)) then
        return true, "player_state"
    end
    return false
end

_waitEggOpenReady = function(maxSec)
    maxSec = math.max(1, tonumber(maxSec) or EGG_READY_MAX_WAIT_SEC)
    local deadline = os.clock() + maxSec
    local lastReason = nil

    while os.clock() < deadline do
        local blocked, reason = _isEggOpenBlocked()
        if not blocked then
            if M._eggPhase == "wait_ready" then
                _clearEggPhase()
            end
            return true
        end

        reason = tostring(reason or "blocked")
        if reason ~= lastReason then
            lastReason = reason
            dprint("egg tunggu siap:", reason)
        end

        M._eggWaitReadyReason = reason
        _setEggPhase("wait_ready", deadline)
        task.wait(EGG_READY_POLL_SEC)
    end

    M._eggWaitReadyReason = lastReason
    warn(("[OpenEgg] egg tunggu loading/offline timeout (%ss): %s"):format(
        tostring(maxSec), tostring(lastReason or "unknown")))
    return false
end

local function _ensureEggOpenReady(maxSec)
    if not _isEggOpenBlocked() then
        if M._eggPhase == "wait_ready" then
            _clearEggPhase()
        end
        return true
    end
    return _waitEggOpenReady(maxSec)
end

local function _canonEggName(s)
    return tostring(s or ""):lower():gsub("[%s_%-]+", "")
end

local function _eggNameMatches(name, selectedMap)
    if type(selectedMap) ~= "table" or not next(selectedMap) then
        return true
    end
    local key = _canonEggName(name)
    if key == "" then return false end
    for sel, on in pairs(selectedMap) do
        if on == true then
            local sk = _canonEggName(sel)
            if sk ~= "" and (key == sk or key:find(sk, 1, true) or sk:find(key, 1, true)) then
                return true
            end
        end
    end
    return false
end

local function _normPetKey(s)
    return tostring(s or ""):lower():gsub("[%s_%-]+", "")
end

local function _petNameMatches(want, candidate)
    want = _normPetKey(want)
    candidate = _normPetKey(candidate)
    if want == "" or candidate == "" then return false end
    return want == candidate
        or want:find(candidate, 1, true)
        or candidate:find(want, 1, true)
end

local function _listToMap(list)
    local out = {}
    if type(list) ~= "table" then return out end
    if list[1] ~= nil then
        for _, v in ipairs(list) do
            local key = tostring(v or "")
            if key ~= "" then out[key] = true end
        end
        return out
    end
    for k, v in pairs(list) do
        if v == true or v == 1 or v == "true" then
            out[tostring(k)] = true
        end
    end
    return out
end

local function _normalizeRollField(raw)
    raw = tostring(raw or "")
    if raw == "" or raw:lower() == "normal" then return "Normal" end
    return raw
end

local function _buyPetHelpers()
    return G.SectionAutoBuyPet or rawget(_G, "SectionAutoBuyPet")
end

local function _typeMatchesRule(refType, allowedMap)
    local H = _buyPetHelpers()
    if type(H) == "table" and type(H.typeMatchesRule) == "function" then
        return H.typeMatchesRule(refType, allowedMap) == true
    end
    if type(allowedMap) ~= "table" or not next(allowedMap) then return true end
    refType = _normalizeRollField(refType)
    local canonRef = _normPetKey(refType)
    if canonRef == "" then canonRef = "normal" end
    for k, on in pairs(allowedMap) do
        if on == true and _normPetKey(k) == canonRef then return true end
    end
    return false
end

local function _sizeMatchesRule(refSize, allowedMap)
    local H = _buyPetHelpers()
    if type(H) == "table" and type(H.sizeMatchesRule) == "function" then
        return H.sizeMatchesRule(refSize, allowedMap) == true
    end
    if type(allowedMap) ~= "table" or not next(allowedMap) then return true end
    refSize = _normalizeRollField(refSize)
    local canonRef = _normPetKey(refSize)
    if canonRef == "" then canonRef = "normal" end
    for k, on in pairs(allowedMap) do
        if on == true and _normPetKey(k) == canonRef then return true end
    end
    return false
end

local function _ruleHasFilters(rule)
    if type(rule) ~= "table" then return false end
    return next(_listToMap(rule.pets)) ~= nil
        or next(_listToMap(rule.sizes)) ~= nil
        or next(_listToMap(rule.types)) ~= nil
end

local function _normalizeTypeSizeMode(raw)
    local mode = tostring(raw or "or"):lower()
    if mode == "and" then return "and" end
    return "or"
end

local function _ruleMatchesRoll(rule, roll)
    if type(rule) ~= "table" or rule.enabled == false then return false end
    if not _ruleHasFilters(rule) then return false end
    roll = type(roll) == "table" and roll or {}

    local petsMap = _listToMap(rule.pets)
    if next(petsMap) then
        local petOk = false
        for petKey in pairs(petsMap) do
            if _petNameMatches(petKey, roll.pet) then
                petOk = true
                break
            end
        end
        if not petOk then return false end
    end

    local typesMap = _listToMap(rule.types)
    local sizesMap = _listToMap(rule.sizes)
    local hasTypeFilter = next(typesMap) ~= nil
    local hasSizeFilter = next(sizesMap) ~= nil
    local combineMode = _normalizeTypeSizeMode(rule.type_size_mode)

    if hasTypeFilter and hasSizeFilter then
        local typeOk = _typeMatchesRule(roll.type, typesMap)
        local sizeOk = _sizeMatchesRule(roll.size, sizesMap)
        if combineMode == "and" then
            if not typeOk or not sizeOk then return false end
        elseif not typeOk and not sizeOk then
            return false
        end
    else
        if hasSizeFilter and not _sizeMatchesRule(roll.size, sizesMap) then return false end
        if hasTypeFilter and not _typeMatchesRule(roll.type, typesMap) then return false end
    end
    return true
end

local function _resolveEggRulesList(eggCfg)
    eggCfg = type(eggCfg) == "table" and eggCfg or {}
    local rules = type(eggCfg.rules) == "table" and eggCfg.rules or {}
    local order = type(eggCfg.rulesOrder) == "table" and eggCfg.rulesOrder or {}
    if #order == 0 and rules[1] == nil then
        local ids = {}
        for id in pairs(rules) do ids[#ids + 1] = tostring(id) end
        table.sort(ids)
        order = ids
    end

    local byId = {}
    if rules[1] ~= nil then
        for _, rule in ipairs(rules) do
            if type(rule) == "table" then
                byId[tostring(rule.id or "")] = rule
            end
        end
    else
        byId = rules
    end

    local out = {}
    for _, id in ipairs(order) do
        local rule = byId[tostring(id)]
        if type(rule) == "table" then
            out[#out + 1] = rule
        end
    end
    if #out == 0 and rules[1] ~= nil then
        return rules
    end
    return out
end

function M.EggRollMatchesRules(roll, eggCfg)
    eggCfg = type(eggCfg) == "table" and eggCfg or getCfg().egg
    local rules = _resolveEggRulesList(eggCfg)
    if #rules == 0 then return false end
    for _, rule in ipairs(rules) do
        if _ruleMatchesRoll(rule, roll) then
            return true
        end
    end
    return false
end

local function _isNormalWebhookTrait(v)
    local k = tostring(v or ""):lower():gsub("[%s_%-]+", "")
    return k == "" or k == "normal"
end

local function _webhookDisplayPetSize(size)
    size = _normalizeRollField(size)
    if size:lower() == "huge" then return "Mega" end
    return size
end

local function _normEggRarityKey(s)
    return tostring(s or ""):lower():gsub("[%s_%-]+", "")
end

local _EGG_WEBHOOK_RARITY_TIER = {
    common = 1,
    uncommon = 2,
    rare = 3,
    legendary = 4,
    mythic = 5,
    super = 6,
}

local function _eggWebhookRarityTier(rarity)
    local plv = G.PetListView or rawget(_G, "PetListView")
    if type(plv) == "table" and type(plv.getGag2RarityTier) == "function" then
        local ok, tier = pcall(plv.getGag2RarityTier, rarity)
        if ok and type(tier) == "number" and tier > 0 then
            return tier
        end
    end
    return _EGG_WEBHOOK_RARITY_TIER[_normEggRarityKey(rarity)] or 0
end

local function _eggSizeKey(size)
    return _normalizeRollField(size):lower():gsub("[%s_%-]+", "")
end

local function _isEggRollHuge(size)
    local k = _eggSizeKey(size)
    return k == "huge" or k == "mega"
end

local function _eggRollForWebhook(roll)
    roll = type(roll) == "table" and roll or {}
    local out = {
        pet = tostring(roll.pet or ""),
        size = _normalizeRollField(roll.size),
        type = _normalizeRollField(roll.type),
        eggName = tostring(roll.eggName or ""),
        success = roll.success == true,
    }
    local repl = M._lastEggRepl
    if type(repl) == "table" then
        if repl.size and repl.size ~= "" then
            out.size = _normalizeRollField(repl.size)
        end
        if repl.type and repl.type ~= "" then
            out.type = _normalizeRollField(repl.type)
        end
        if out.eggName == "" and repl.eggName and repl.eggName ~= "" then
            out.eggName = tostring(repl.eggName)
        end
    end
    return out
end

local function _resolveEggPetRarity(petName)
    local plv = G.PetListView or rawget(_G, "PetListView")
    if type(plv) == "table" and type(plv.getPetRarity) == "function" then
        local ok, r = pcall(plv.getPetRarity, petName)
        if ok and type(r) == "string" and r ~= "" and r ~= "Unknown" then
            return r
        end
    end
    return nil
end

local function _shouldSendEggHatchWebhook(roll)
    roll = _eggRollForWebhook(roll)
    if roll.pet == "" then return false end

    local rarity = _resolveEggPetRarity(roll.pet)
    if type(rarity) == "string" and rarity ~= "" and rarity ~= "Unknown" then
        if _eggWebhookRarityTier(rarity) >= (_EGG_WEBHOOK_RARITY_TIER.mythic or 5) then
            return true
        end
    end

    return _isEggRollHuge(roll.size)
end

local function _eggWebhookKey(roll)
    return table.concat({
        tostring(roll.pet or ""),
        _normalizeRollField(roll.size),
        _normalizeRollField(roll.type),
        tostring(roll.eggName or ""),
    }, "|")
end

local function _eggWebhookContext()
    local cfg = getCfg()
    local eggCfg = type(cfg.egg) == "table" and cfg.egg or {}
    local maxOpen = _readEggMaxOpen(eggCfg)
    local eggsLeft = nil
    if type(countEggs) == "function" then
        eggsLeft = countEggs(cfg)
    elseif type(M._lastEggCount) == "number" then
        eggsLeft = M._lastEggCount
    end
    local opened = math.max(0, math.floor(tonumber(M._eggOpenedThisCycle) or 0))
    local target = math.max(0, math.floor(tonumber(M._eggOpenTarget) or 0))
    local batchRemaining = (target > 0) and math.max(0, target - opened) or nil
    return {
        maxOpenEgg = math.max(0, math.floor(tonumber(maxOpen) or 0)),
        eggOpenTarget = target,
        eggOpenedThisCycle = opened,
        eggBatchRemaining = batchRemaining,
        eggsRemaining = (type(eggsLeft) == "number") and math.max(0, math.floor(eggsLeft)) or nil,
    }
end

local EGG_HATCH_WEBHOOK_URL = "https://golas.co.id/grow_a_garden25353466689966/webhook_pet_egg.php"

local function _eggWebhookApiUrl()
    local u = G.WEBHOOK_EGG_API_URL or rawget(_G, "WEBHOOK_EGG_API_URL")
    if type(u) == "string" and u ~= "" then
        return u
    end
    return EGG_HATCH_WEBHOOK_URL
end

local function _eggWebhookHttpPost(payload)
    local wh = G.WebhookModule or G.Webhook or rawget(_G, "WebhookModule") or rawget(_G, "Webhook")
    if type(wh) == "table" and type(wh.PostJson) == "function" then
        local url = (type(wh.GetEggHatchApiUrl) == "function" and wh.GetEggHatchApiUrl()) or _eggWebhookApiUrl()
        return wh.PostJson(url, payload)
    end

    local HttpService = game:GetService("HttpService")
    local url = _eggWebhookApiUrl()
    local body = HttpService:JSONEncode(payload)
    local headers = { ["Content-Type"] = "application/json" }
    local req = (syn and syn.request)
        or (http and http.request)
        or http_request
        or (fluxus and fluxus.request)
        or request
    if type(req) == "function" then
        local ok, res = pcall(function()
            return req({ Url = url, Method = "POST", Headers = headers, Body = body })
        end)
        if ok and type(res) == "table" then
            local code = tonumber(res.StatusCode or res.status) or 0
            if code >= 200 and code < 300 then
                return true, res
            end
            return false, ("HTTP %d"):format(code)
        end
        if not ok then
            return false, tostring(res)
        end
    end
    if HttpService.HttpEnabled then
        local ok, res = pcall(function()
            return HttpService:RequestAsync({
                Url = url,
                Method = "POST",
                Headers = headers,
                Body = body,
            })
        end)
        if ok and type(res) == "table" and res.Success == true then
            return true, res
        end
    end
    return false, "no_http"
end

local function _postEggHatchWebhook(roll, opts)
    roll = _eggRollForWebhook(roll)
    opts = type(opts) == "table" and opts or {}
    if roll.pet == "" then return end

    local petType = _normalizeRollField(roll.type)
    local petSize = _webhookDisplayPetSize(roll.size)
    if _isNormalWebhookTrait(petType) then petType = nil end
    if _isNormalWebhookTrait(petSize) then petSize = nil end
    local eggCtx = _eggWebhookContext()
    local payload = {
        player = LP and LP.Name or "",
        petName = roll.pet,
        petKey = roll.pet,
        petType = petType,
        petSize = petSize,
        eggName = roll.eggName,
        rarity = tostring(_resolveEggPetRarity(roll.pet) or ""),
        match = opts.match == true,
        maxOpenEgg = eggCtx.maxOpenEgg,
        eggOpenTarget = eggCtx.eggOpenTarget,
        eggOpenedThisCycle = eggCtx.eggOpenedThisCycle,
        eggBatchRemaining = eggCtx.eggBatchRemaining,
        eggsRemaining = eggCtx.eggsRemaining,
        matchOpenEgg = (opts.match == true) and eggCtx.eggOpenedThisCycle or nil,
    }

    task.spawn(function()
        local wh = G.WebhookModule or G.Webhook or rawget(_G, "WebhookModule") or rawget(_G, "Webhook")
        if type(wh) == "table" and type(wh.SendEggHatch) == "function" then
            local okCall, sendOk, sendDetail = pcall(wh.SendEggHatch, payload)
            if okCall ~= true then
                warn("[OpenEgg] egg webhook error:", tostring(sendOk))
                return
            end
            if sendOk ~= true then
                warn("[OpenEgg] egg webhook gagal:", tostring(sendDetail))
            elseif type(sendDetail) == "table" and sendDetail.skipped == true then
                warn("[OpenEgg] egg webhook skipped PHP:", tostring(sendDetail.reason or "unknown"))
            end
            return
        end

        if M._eggWebhookMissingWarned ~= true then
            M._eggWebhookMissingWarned = true
            warn("[OpenEgg] Webhook.SendEggHatch tidak ada — pakai HTTP fallback langsung ke PHP")
        end

        payload.event = payload.match and "EGG_HATCH_MATCH" or "EGG_HATCH"
        payload.luaVer = "oe-fallback"
        local ok, detail = _eggWebhookHttpPost(payload)
        if ok ~= true then
            warn("[OpenEgg] egg webhook fallback gagal:", tostring(detail), "→", _eggWebhookApiUrl())
        elseif type(detail) == "table" and detail.skipped == true then
            warn("[OpenEgg] egg webhook fallback skipped PHP:", tostring(detail.reason or "unknown"))
        end
    end)
end

function M.PingEggWebhook()
    local wh = G.WebhookModule or G.Webhook or rawget(_G, "WebhookModule") or rawget(_G, "Webhook")
    if type(wh) == "table" and type(wh.PingEggHatchApi) == "function" then
        return wh.PingEggHatchApi()
    end
    local HttpService = game:GetService("HttpService")
    local url = _eggWebhookApiUrl()
    if HttpService.HttpEnabled then
        local ok, res = pcall(function()
            return HttpService:RequestAsync({ Url = url, Method = "GET" })
        end)
        if ok and type(res) == "table" then
            return res.Success == true, {
                code = res.StatusCode,
                body = tostring(res.Body or ""):sub(1, 300),
                url = url,
            }
        end
    end
    return false, { error = "no_http", url = url }
end

local function _sendEggHatchWebhook(roll)
    if not _shouldSendEggHatchWebhook(roll) then
        dprint("egg webhook skip — bukan Mythic+ / Mega")
        return
    end

    local whRoll = _eggRollForWebhook(roll)
    local key = "hatch|" .. _eggWebhookKey(whRoll)
    if M._eggWebhookSent[key] then return end
    M._eggWebhookSent[key] = true

    _postEggHatchWebhook(roll, { match = false })
end

local function _sendEggMatchWebhook(roll)
    roll = _eggRollForWebhook(roll)
    if roll.pet == "" then return end

    local key = "match|" .. _eggWebhookKey(roll)
    if M._eggWebhookSent[key] then return end
    M._eggWebhookSent[key] = true

    _postEggHatchWebhook(roll, { match = true })
end

local function _countEggToolsInInventory(selectedMap)
    local total = 0
    local function scan(root)
        if not root then return end
        for _, inst in ipairs(root:GetChildren()) do
            if inst:IsA("Tool") then
                local eggName = inst:GetAttribute("Egg")
                if eggName ~= nil and tostring(eggName) ~= "" then
                    if _eggNameMatches(eggName, selectedMap) then
                        local cnt = tonumber(inst:GetAttribute("Count")) or 1
                        total += math.max(1, math.floor(cnt))
                    end
                end
            end
        end
    end
    scan(_getBackpack())
    scan(LP and LP.Character)
    return total
end

local function _eggItemDisplayName(it)
    local name = tostring(it and it.key or "")
    if name == "" and type(it) == "table" and type(it.name) == "string" then
        name = it.name:match("^(.-)%s+x%s+") or it.name
    end
    return name
end

local function _parseEggItemCount(it)
    if type(it) ~= "table" then return 0 end
    local n = tonumber(it.count) or tonumber(it.right)
    if n then return math.max(0, math.floor(n)) end
    if type(it.name) == "string" then
        local tail = it.name:match("%s+x%s+(.+)$")
        if tail then
            tail = tail:gsub(",", "")
            if tail:sub(-1) == "K" then
                return math.max(0, math.floor((tonumber(tail:sub(1, -2)) or 0) * 1000))
            end
            if tail:sub(-1) == "M" then
                return math.max(0, math.floor((tonumber(tail:sub(1, -2)) or 0) * 1000000))
            end
            return math.max(0, math.floor(tonumber(tail) or 0))
        end
    end
    return 1
end

local function _normalizeEggSelectedMap(selected)
    if type(selected) ~= "table" then return {} end
    if selected[1] ~= nil then
        return _listToMap(selected)
    end
    return selected
end

local function _countEggsFromAutoGift(selectedMap)
    local ag = G.AutoGiftModule or G.AutoGift or rawget(_G, "AutoGiftModule") or rawget(_G, "AutoGift")
    if type(ag) ~= "table" or type(ag.BuildInventoryItems) ~= "function" then
        return nil
    end
    local ok, items = pcall(ag.BuildInventoryItems, ag, "Eggs")
    if not ok or type(items) ~= "table" then
        return nil
    end
    local sum = 0
    for _, it in ipairs(items) do
        if _eggNameMatches(_eggItemDisplayName(it), selectedMap) then
            sum += _parseEggItemCount(it)
        end
    end
    return sum
end

countEggs = function(cfg)
    cfg = cfg or getCfg()
    local eggCfg = type(cfg.egg) == "table" and cfg.egg or {}
    local selected = _normalizeEggSelectedMap(eggCfg.eggs)
    local fromGift = _countEggsFromAutoGift(selected)
    if type(fromGift) == "number" then
        return math.max(0, math.floor(fromGift))
    end
    return _countEggToolsInInventory(selected)
end

local function _pickEggNameToOpen(selectedMap)
    local function scan(root)
        if not root then return nil end
        for _, inst in ipairs(root:GetChildren()) do
            if inst:IsA("Tool") then
                local eggName = inst:GetAttribute("Egg")
                if eggName ~= nil and tostring(eggName) ~= "" then
                    if _eggNameMatches(eggName, selectedMap) then
                        local cnt = tonumber(inst:GetAttribute("Count")) or 1
                        if cnt > 0 then
                            return tostring(eggName)
                        end
                    end
                end
            end
        end
        return nil
    end
    local name = scan(_getBackpack()) or scan(LP and LP.Character)
    if name then return name end

    local ag = G.AutoGiftModule or G.AutoGift or rawget(_G, "AutoGiftModule") or rawget(_G, "AutoGift")
    if type(ag) == "table" and type(ag.BuildInventoryItems) == "function" then
        local ok, items = pcall(ag.BuildInventoryItems, ag, "Eggs")
        if ok and type(items) == "table" then
            for _, it in ipairs(items) do
                local eggName = _eggItemDisplayName(it)
                if _eggNameMatches(eggName, selectedMap) and _parseEggItemCount(it) > 0 then
                    return eggName
                end
            end
        end
    end
    return nil
end

local NetEgg = nil

local function _ensureEggNetworking()
    if type(NetEgg) == "table" and NetEgg.Egg then return NetEgg end
    local ok, net = pcall(function()
        local sm = ReplicatedStorage:FindFirstChild("SharedModules")
            or ReplicatedStorage:WaitForChild("SharedModules", NET_WAIT_SEC)
        if not sm then return nil end
        local mod = sm:FindFirstChild("Networking")
            or sm:WaitForChild("Networking", NET_WAIT_SEC)
        if not mod then return nil end
        return require(mod)
    end)
    if ok and type(net) == "table" then
        NetEgg = net
        return NetEgg
    end
    return nil
end

local function _clearEggReplicateQueue()
    M._eggReplicateQueue = {}
end

local function _peekEggReplicateQueue()
    local q = M._eggReplicateQueue
    if type(q) ~= "table" or #q == 0 then return nil end
    return q[1]
end

local function _takeEggReplicateQueue()
    local q = M._eggReplicateQueue
    if type(q) ~= "table" or #q == 0 then return nil end
    return table.remove(q, 1)
end

local function _connectNetworkingEvent(remote, handler)
    if not remote or type(handler) ~= "function" then return false end
    local signal = remote.OnClientEvent
    if signal and type(signal.Connect) == "function" then
        M._eggReplicateConns[#M._eggReplicateConns + 1] = signal:Connect(handler)
        return true
    end
    if typeof(remote) == "Instance" and remote:IsA("RemoteEvent") then
        M._eggReplicateConns[#M._eggReplicateConns + 1] = remote.OnClientEvent:Connect(handler)
        return true
    end
    if type(remote.Connect) == "function" then
        M._eggReplicateConns[#M._eggReplicateConns + 1] = remote:Connect(handler)
        return true
    end
    return false
end

local function _isLocalEggPlayer(playerOrInst)
    if playerOrInst == LP then return true end
    if typeof(playerOrInst) == "Instance" then
        if playerOrInst:IsA("Player") then
            return playerOrInst == LP
        end
        local owner = Players:GetPlayerFromCharacter(playerOrInst)
        if owner then return owner == LP end
    end
    return false
end

local function _queueEggReplicate(eggString, eggName, wonPet, sizeStr, typeStr)
    local q = M._eggReplicateQueue
    if type(q) ~= "table" then
        q = {}
        M._eggReplicateQueue = q
    end
    q[#q + 1] = {
        eggString = tostring(eggString or ""),
        eggName = tostring(eggName or ""),
        pet = tostring(wonPet or ""),
        size = _normalizeRollField(sizeStr),
        type = _normalizeRollField(typeStr),
        at = os.clock(),
    }
end

local function _onReplicateOpenEgg(player, eggString, eggName, wonPet, _pos, sizeStr, typeStr)
    if not _isLocalEggPlayer(player) then return end
    _queueEggReplicate(eggString, eggName, wonPet, sizeStr, typeStr)
end

local function _onReplicateHatchInPlace(player, eggString, eggName, wonPet, _pos, sizeStr, typeStr)
    if not _isLocalEggPlayer(player) then return end
    _queueEggReplicate(eggString, eggName, wonPet, sizeStr, typeStr)
end

local function _ensureEggReplicateHook()
    if M._eggReplicateHooked then return end
    M._eggReplicateQueue = M._eggReplicateQueue or {}
    local net = _ensureEggNetworking()
    local eggNet = net and net.Egg
    if type(eggNet) ~= "table" then return end

    local okOpen = _connectNetworkingEvent(eggNet.ReplicateOpenEgg, _onReplicateOpenEgg)
    local okPlace = _connectNetworkingEvent(eggNet.ReplicateHatchInPlace, _onReplicateHatchInPlace)
    if okOpen or okPlace then
        M._eggReplicateHooked = true
        dprint(("egg replicate hook ok open=%s place=%s"):format(tostring(okOpen), tostring(okPlace)))
    else
        dprint("egg replicate hook gagal — pakai OpenEgg:Fire response")
    end
end

local function _callOpenEgg(eggName)
    eggName = tostring(eggName or "")
    if eggName == "" then return nil, "empty_name" end

    local net = _ensureEggNetworking()
    local remote = net and net.Egg and net.Egg.OpenEgg
    if not remote then return nil, "no_remote" end

    _ensureEggReplicateHook()

    local res
    local ok, err = pcall(function()
        if type(remote.Fire) == "function" then
            res = remote:Fire(eggName)
        elseif type(remote.Invoke) == "function" then
            res = remote:Invoke(eggName)
        else
            error("OpenEgg not callable")
        end
    end)
    if not ok then
        return nil, tostring(err)
    end

    return res
end

local function _confirmEggOpen(res, repl, eggName, roll)
    -- Hanya saat MATCH — commit hatch ke server supaya pet ke-save.
    local net = _ensureEggNetworking()
    local remote = net and net.Egg and net.Egg.ConfirmEgg
    if not remote or type(remote.Fire) ~= "function" then return end

    local eggString = ""
    if type(repl) == "table" and repl.eggString and repl.eggString ~= "" then
        eggString = repl.eggString
    elseif type(res) == "table" then
        eggString = tostring(res.EggString or res.ItemId or res.Id or res.Uuid or "")
    end
    local name = tostring((type(repl) == "table" and repl.eggName ~= "" and repl.eggName)
        or roll.eggName or eggName or "")
    local pet = tostring(roll.pet or "")
    pcall(function()
        remote:Fire(eggString, name, pet)
    end)
end

local function _parseEggOpenResult(res, eggName, repl)
    local roll = {
        pet = "",
        size = "Normal",
        type = "Normal",
        eggName = tostring(eggName or ""),
        success = false,
    }

    if type(res) == "table" then
        roll.success = (res.Success == true)
        roll.pet = tostring(res.WonPet or res.Pet or res.pet or "")
        roll.eggName = tostring(res.EggName or roll.eggName or "")
        local rs = res.Size or res.WonSize or res.size
        local rt = res.Type or res.WonType or res.type
        if rs ~= nil and tostring(rs) ~= "" then
            roll.size = _normalizeRollField(rs)
        end
        if rt ~= nil and tostring(rt) ~= "" then
            roll.type = _normalizeRollField(rt)
        end
    end

    if type(repl) ~= "table" then
        repl = nil
    end
    if type(repl) == "table" then
        if roll.pet == "" and repl.pet ~= "" then
            roll.pet = repl.pet
        end
        if repl.size and repl.size ~= "" then roll.size = repl.size end
        if repl.type and repl.type ~= "" then roll.type = repl.type end
    end

    roll.size = _normalizeRollField(roll.size)
    roll.type = _normalizeRollField(roll.type)
    if roll.pet ~= "" and roll.success ~= true then
        roll.success = true
    end
    return roll
end

local function _replicateReadyForOpen(repl)
    return type(repl) == "table" and tostring(repl.pet or "") ~= ""
end

local function _consumeEggReplicateIfQueued()
    if _replicateReadyForOpen(_peekEggReplicateQueue()) then
        return _takeEggReplicateQueue()
    end
    return nil
end

local function _drainNextEggReplicateAsync()
    task.spawn(function()
        local deadline = os.clock() + 1.5
        while os.clock() < deadline do
            if _replicateReadyForOpen(_peekEggReplicateQueue()) then
                _takeEggReplicateQueue()
                return
            end
            task.wait(EGG_REPLICATE_POLL_SEC)
        end
    end)
end

local function _awaitEggOpenRoll(res, eggName, _eggCfg)
    M._lastEggOpenRes = res
    M._lastEggRepl = nil

    local roll = _parseEggOpenResult(res, eggName, nil)

    local function takeReplicateRoll()
        local repl = _consumeEggReplicateIfQueued()
        if _replicateReadyForOpen(repl) then
            M._lastEggRepl = repl
            return _parseEggOpenResult(res, eggName, repl)
        end
        return nil
    end

    if roll.pet ~= "" then
        local enriched = takeReplicateRoll()
        if enriched then return enriched end

        local deadline = os.clock() + EGG_REPLICATE_ENRICH_SEC
        while os.clock() < deadline do
            enriched = takeReplicateRoll()
            if enriched then return enriched end
            task.wait(EGG_REPLICATE_POLL_SEC)
        end
        _drainNextEggReplicateAsync()
        return roll
    end

    local deadline = os.clock() + EGG_REPLICATE_FALLBACK_SEC
    while os.clock() < deadline do
        local enriched = takeReplicateRoll()
        if enriched then return enriched end
        task.wait(EGG_REPLICATE_POLL_SEC)
    end

    if roll.pet == "" then
        dprint("egg roll kosong — OpenEgg/replicate tidak ada data")
    end
    return roll
end

function M.EggAnyEnabled(eggCfg)
    eggCfg = type(eggCfg) == "table" and eggCfg or {}
    return eggCfg.open_egg == true
end

local function _resetEggCycle()
    M._eggCycleActive = false
    M._eggOpenedThisCycle = 0
    M._eggOpenTarget = 0
    M._eggMatchStop = false
end

local function _setOpenEggEnabled(on, reason)
    on = (on == true)
    G.OPEN_EGG_ENABLED = on
    _G.OPEN_EGG_ENABLED = on
    G.AUTO_VULN_EGG_OPEN_EGG = on
    _G.AUTO_VULN_EGG_OPEN_EGG = on

    local main = G.MAIN or rawget(_G, "MAIN")
    if type(main) == "table" then
        main.auto = type(main.auto) == "table" and main.auto or {}
        main.auto.openEgg = type(main.auto.openEgg) == "table" and main.auto.openEgg or {}
        main.auto.openEgg.open_egg = on
        main.auto.openEgg.enabled = on
        G.MAIN = main
        _G.MAIN = main
    end

    local State = G.__GAG2_STATE or G.State or rawget(_G, "State")
    if type(State) == "table" and type(State.patchAuto) == "function" then
        pcall(State.patchAuto, "openEgg", { open_egg = on, enabled = on }, { noSync = true })
    end

    local apis = G.__GAG2_OPEN_EGG_TOGGLE_APIS or rawget(_G, "__GAG2_OPEN_EGG_TOGGLE_APIS")
    if type(apis) == "table" then
        local api = apis.open_egg
        if type(api) == "table" then
            if on == true and type(api.setOn) == "function" then
                pcall(api.setOn, true) -- silent
            elseif on ~= true and type(api.setOff) == "function" then
                pcall(api.setOff, true) -- silent
            end
        end
    end

    M._uiWantEnabled = on
    if on ~= true then
        M.Stop("disabled")
    end

    -- Persist toggle (auto-off setelah max_open / rule match)
    local persist = G.__GAG2_PERSIST_STATE or rawget(_G, "__GAG2_PERSIST_STATE")
    if type(persist) == "function" then
        pcall(persist)
    elseif type(State) == "table" and type(State.saveFromUi) == "function" then
        pcall(State.saveFromUi)
    end

    dprint("Open Egg toggle →", on and "ON" or "OFF", tostring(reason or ""))
end

local function _resolveEggOpenTarget(maxOpen, eggCount)
    eggCount = math.max(0, math.floor(tonumber(eggCount) or 0))
    maxOpen = math.max(0, math.floor(tonumber(maxOpen) or 0))
    if eggCount <= 0 then
        return 0
    end
    if maxOpen <= 0 then
        -- 0 = open all, chunked by batch cap
        return math.min(eggCount, EGG_OPEN_ALL_BATCH_CAP)
    end
    return math.min(maxOpen, eggCount)
end

local function _startEggCycle(cfg, eggCount)
    cfg = cfg or getCfg()
    local eggCfg = type(cfg.egg) == "table" and cfg.egg or {}
    M._eggCycleActive = true
    M._eggOpenedThisCycle = 0
    M._eggMatchStop = false
    _clearEggReplicateQueue()

    local maxOpen = _readEggMaxOpen(eggCfg)
    eggCount = math.max(0, math.floor(tonumber(eggCount) or 0))
    M._eggOpenTarget = _resolveEggOpenTarget(maxOpen, eggCount)

    dprint(("egg cycle start max=%s count=%s target=%s"):format(
        tostring(maxOpen), tostring(eggCount), tostring(M._eggOpenTarget)))
end

local function _finishEggOpenBatch(eggCfg, matched)
    local liveEggCfg = type(getCfg().egg) == "table" and getCfg().egg or eggCfg
    local maxOpen = _readEggMaxOpen(liveEggCfg)

    if matched then
        M._eggBatchDone = true
        _resetEggCycle()
        dprint("egg match — stop batch")
        _clearEggPhase()
        M._eggBusy = false
        _setOpenEggEnabled(false, "pet_rule_match")
        return
    end

    _resetEggCycle()
    _clearEggPhase()
    M._eggBusy = false

    -- max_open > 0 = hard session limit (bukan per-batch). Selesai → stop + toggle OFF.
    if maxOpen > 0 then
        M._eggBatchDone = true
        _setOpenEggEnabled(false, "max_open_done")
        dprint(("egg batch selesai — max_open=%s, toggle OFF"):format(tostring(maxOpen)))
        return
    end

    -- max_open 0 = open all: lanjut batch berikutnya selama masih ada egg.
    local left = countEggs(getCfg())
    if type(left) == "number" and left > 0 and liveEggCfg.open_egg == true then
        M._eggBatchDone = false
        dprint(("egg batch selesai — sisa %s egg, lanjut batch berikutnya"):format(tostring(left)))
    else
        M._eggBatchDone = true
        _setOpenEggEnabled(false, "all_eggs_done")
        dprint("egg batch selesai — all done, toggle OFF")
    end
end

local function _runEggOpenCycle(cfg)
    if M._eggCycleActive or _anyBusy() or M._eggBatchDone then return end

    _flushEggUiConfig()
    cfg = getCfg()
    local eggCfg = type(cfg.egg) == "table" and cfg.egg or {}
    if eggCfg.open_egg ~= true then return end
    if not M.EggAnyEnabled(eggCfg) then return end

    local eggCount = countEggs(cfg)
    if type(eggCount) ~= "number" or eggCount <= 0 then return end

    _startEggCycle(cfg, eggCount)
    M._eggBusy = true
    _setEggPhase("opening", 0)

    task.spawn(function()
        local matched = false
        local ok, err = pcall(function()
            if not _waitEggOpenReady() then
                dprint("egg batch dibatalkan — loading/offline belum selesai")
                _resetEggCycle()
                _clearEggPhase()
                M._eggBusy = false
                return
            end

            local lastEggName = nil

            while M._eggOpenedThisCycle < M._eggOpenTarget and M._eggMatchStop ~= true do
                local liveCfg = getCfg()
                local liveEggCfg = type(liveCfg.egg) == "table" and liveCfg.egg or eggCfg

                if not _ensureEggOpenReady(12) then
                    dprint("egg batch stop — loading/offline timeout mid-batch")
                    break
                end

                local eggName = _pickEggNameToOpen(liveEggCfg.eggs)
                if not eggName then break end
                lastEggName = eggName

                local res, openErr = _callOpenEgg(eggName)
                local roll = _awaitEggOpenRoll(res, eggName, liveEggCfg)
                M._lastEggRoll = roll

                if roll.success ~= true or roll.pet == "" then
                    warn("[OpenEgg] OpenEgg gagal:", tostring(openErr or "bad_response"))
                    break
                end

                M._eggOpenedThisCycle += 1

                dprint(("egg open %s → %s / %s / %s"):format(
                    tostring(eggName), tostring(roll.pet), tostring(roll.size), tostring(roll.type)))

                local isMatch = M.EggRollMatchesRules(roll, liveEggCfg)

                if isMatch then
                    pcall(_sendEggMatchWebhook, roll)
                end
                pcall(_sendEggHatchWebhook, roll)

                if isMatch then
                    matched = true
                    M._eggMatchStop = true
                    _confirmEggOpen(M._lastEggOpenRes, M._lastEggRepl, lastEggName, roll)
                    break
                end
            end

            _finishEggOpenBatch(eggCfg, matched)
        end)

        if ok ~= true then
            warn("[OpenEgg] egg open cycle error:", tostring(err))
            _resetEggCycle()
            _clearEggPhase()
            M._eggBusy = false
            M._eggBatchDone = false
        end
    end)
end

local function tickEgg(cfg)
    cfg = cfg or getCfg()
    local eggCfg = type(cfg.egg) == "table" and cfg.egg or {}
    if not M.EggAnyEnabled(eggCfg) then
        _resetEggCycle()
        M._eggBatchDone = false
        return
    end

    if eggCfg.open_egg ~= true then
        M._eggBatchDone = false
    end

    local eggs = countEggs(cfg)
    if type(eggs) == "number" then
        if eggs > 0 then
            M._peakEggCount = math.max(M._peakEggCount or 0, eggs)
        end

        M._lastEggCount = eggs

        if eggs > 0 and eggCfg.open_egg == true
            and not M._eggCycleActive and not _anyBusy() and not M._eggBatchDone then
            local blocked = _isEggOpenBlocked()
            if not blocked then
                _runEggOpenCycle(cfg)
            end
        end
    end
end

local function tick(cfg)
    cfg = cfg or getCfg()
    if not anyEnabled(cfg) then return end
    tickEgg(cfg)
end

function M.GetStatus()
    local cfg = getCfg()
    local eggCfg = type(cfg.egg) == "table" and cfg.egg or {}
    local lastRoll = type(M._lastEggRoll) == "table" and M._lastEggRoll or {}
    -- Pakai cache dari tick — jangan countEggs di sini (berat / bikin UI stutter).
    local eggs = M._lastEggCount

    return {
        enabled = anyEnabled(cfg),
        egg_count = eggs,
        egg_active = M.EggAnyEnabled(eggCfg),
        egg_cycle = M._eggCycleActive == true,
        egg_opened = M._eggOpenedThisCycle,
        egg_open_target = M._eggOpenTarget,
        last_egg_pet = tostring(lastRoll.pet or ""),
        last_egg_size = tostring(lastRoll.size or "Normal"),
        last_egg_type = tostring(lastRoll.type or "Normal"),
        egg_busy = M._eggBusy,
        busy = _anyBusy(),
        running = M._running == true,
    }
end

function M.GetEggStatusText()
    local st = M.GetStatus()
    local cfg = getCfg()
    local eggCfg = type(cfg.egg) == "table" and cfg.egg or {}
    local opened = tonumber(st.egg_opened) or 0
    local target = tonumber(st.egg_open_target) or 0
    if st.egg_cycle ~= true then
        opened = 0
        local maxOpen = _readEggMaxOpen(eggCfg)
        if maxOpen > 0 then
            target = maxOpen
        else
            local eggCnt = tonumber(st.egg_count) or 0
            target = _resolveEggOpenTarget(0, eggCnt)
            if target <= 0 and eggCnt > 0 then
                target = eggCnt
            end
        end
        if M._eggBatchDone then
            opened = target > 0 and target or opened
        end
    end
    local maxOpenCfg = _readEggMaxOpen(eggCfg)
    local y
    if st.egg_cycle == true then
        y = target > 0 and tostring(target) or "—"
    elseif maxOpenCfg <= 0 then
        y = target > 0 and tostring(target) or "All"
    else
        y = tostring(target > 0 and target or maxOpenCfg)
    end
    local last = "—"
    if type(st.last_egg_pet) == "string" and st.last_egg_pet ~= "" then
        last = string.format("%s/%s/%s", st.last_egg_pet, st.last_egg_size or "Normal", st.last_egg_type or "Normal")
    end
    local eggCntStr = type(st.egg_count) == "number" and tostring(math.floor(st.egg_count)) or "—"
    return ("Eggs: %s · Opened: %s/%s · Last: %s%s"):format(
        eggCntStr,
        tostring(opened),
        y,
        last,
        _eggStatusPhaseText()
    )
end

function M._ensureRunning()
    if M._running then return end
    M._running = true
    M._thread = task.spawn(function()
        while M._running do
            local ok, err = pcall(tick)
            if not ok then
                warn("[OpenEgg] tick error:", tostring(err))
            end
            task.wait(POLL_SEC)
        end
    end)
end

function M.Stop(reason)
    if not M._running then return end
    M._running = false
    M._thread = nil
    dprint("Stop:", tostring(reason or "manual"))
end

function M.Start()
    M._uiWantEnabled = true
    _setOpenEggEnabled(true, "Start")
    M._eggBatchDone = false
    M._ensureRunning()
end

function M.Apply()
    local cfg = getCfg()
    local enabled = anyEnabled(cfg)
    local wasEnabled = M._uiWantEnabled == true
    M._uiWantEnabled = enabled

    if enabled then
        M._ensureRunning()
        -- Hanya reset batch saat toggle baru ON — jangan restart setelah max_open selesai.
        if not wasEnabled then
            M._eggBatchDone = false
        end
        -- countEggs bisa berat (AutoGift inventory) — jangan block UI thread.
        task.defer(function()
            if not anyEnabled(getCfg()) then return end
            local ne = countEggs(getCfg())
            if type(ne) == "number" then
                if ne > 0 then
                    M._peakEggCount = math.max(M._peakEggCount or 0, ne)
                end
                if M._lastEggCount == nil then
                    M._lastEggCount = ne
                end
            end
        end)
    else
        M.Stop("disabled")
        M._eggBatchDone = false
        _resetEggCycle()
    end
end

function M.SyncFromState()
    M.Apply()
end

M.syncFromGlobals = M.SyncFromState

G.OpenEgg = M
G.OpenEggModule = M
_G.OpenEgg = M
_G.OpenEggModule = M

-- Thin Manual Vuln compatibility aliases
G.AutoVuln = M
G.AutoVulnModule = M
_G.AutoVuln = M
_G.AutoVulnModule = M

task.defer(function()
    M.Apply()
end)

return M
 end,                   required = false },
    { key = "SectionOpenEgg",          name = "Section Open Egg",        factory = function() -- section_open_egg.lua — UI Open Egg (tab Auto → Pet)

local G = (getgenv and getgenv()) or _G
local M = {}

function M.Register(ctx)
    if type(ctx) ~= "table" or type(ctx.ui) ~= "table" then return end

    local ui = ctx.ui
    local getAuto = ctx.getAuto
    local patchAuto = ctx.patchAuto
    local patchAutoOnly = ctx.patchAutoOnly
    local registerFlush = ctx.registerFlush
    local cleanSelectedMap = ctx.cleanSelectedMap
    local arrayToMap = ctx.arrayToMap
    local mapToArrayFn = ctx.mapToArray
    local function mapToArray(map)
        if type(mapToArrayFn) == "function" then
            return mapToArrayFn(map)
        end
        local arr = {}
        if type(map) == "table" then
            for k, v in pairs(map) do
                if v == true then arr[#arr + 1] = tostring(k) end
            end
        end
        table.sort(arr)
        return arr
    end

    local body = ui:CreateSection("Open Egg", false)

    local function buildOpenEggBody(body)
        local ShopListView = G.ShopListView or rawget(_G, "ShopListView")
        local PetListView = G.PetListView or rawget(_G, "PetListView")
        local SectionAutoBuyPet = G.SectionAutoBuyPet or rawget(_G, "SectionAutoBuyPet")

        local ST = getAuto("openEgg") or {}
        -- openEgg state is flat
        local eggST = ST

        if eggST.open_egg == nil then
            eggST.open_egg = (eggST.enabled == true) or (eggST.auto_open == true)
        end
        eggST.open_egg = (eggST.open_egg == true)
        eggST.enabled = eggST.open_egg
        eggST.max_open = math.max(0, math.floor(tonumber(eggST.max_open) or 0))
        eggST.rules = type(eggST.rules) == "table" and eggST.rules or {}
        eggST.rulesOrder = type(eggST.rulesOrder) == "table" and eggST.rulesOrder or {}

        if eggST.rules[1] == nil then
            local arr = {}
            for id, rule in pairs(eggST.rules) do
                if type(rule) == "table" then
                    rule.id = rule.id or tostring(id)
                    arr[#arr + 1] = rule
                end
            end
            table.sort(arr, function(a, b) return tostring(a.id) < tostring(b.id) end)
            if #arr > 0 then
                eggST.rules = arr
                eggST.rulesOrder = {}
                for _, rule in ipairs(arr) do
                    eggST.rulesOrder[#eggST.rulesOrder + 1] = tostring(rule.id)
                end
            end
        end

        local eggsSelected = cleanSelectedMap(arrayToMap(type(eggST.eggs) == "table" and eggST.eggs or {}))

        local function listToMap(list)
            local out = {}
            if type(list) ~= "table" then return out end
            if list[1] ~= nil then
                for _, v in ipairs(list) do
                    local key = tostring(v or "")
                    if key ~= "" then out[key] = true end
                end
                return out
            end
            return cleanSelectedMap(list)
        end

        local function mapFromList(list)
            return listToMap(list)
        end

        local function newRuleId()
            return "evr" .. tostring(math.floor(os.clock() * 1000)) .. "_" .. tostring(math.random(1000, 9999))
        end

        local function normalizeTypeSizeMode(raw)
            local mode = tostring(raw or "or"):lower()
            if mode == "and" then return "and" end
            return "or"
        end

        local function normalizeRulesInPlace()
            local rules = type(eggST.rules) == "table" and eggST.rules or {}
            local order = {}
            local out = {}
            for i, rule in ipairs(rules) do
                if type(rule) == "table" then
                    rule.id = tostring(rule.id or ("rule_" .. i))
                    rule.enabled = rule.enabled ~= false
                    rule.pets = type(rule.pets) == "table" and rule.pets or {}
                    rule.sizes = type(rule.sizes) == "table" and rule.sizes or {}
                    rule.types = type(rule.types) == "table" and rule.types or {}
                    rule.type_size_mode = normalizeTypeSizeMode(rule.type_size_mode)
                    out[#out + 1] = rule
                    order[#order + 1] = rule.id
                end
            end
            eggST.rules = out
            eggST.rulesOrder = order
        end

        normalizeRulesInPlace()

        local maxOpenRow

        local function pullMaxOpenFromInput()
            if maxOpenRow and maxOpenRow.Parent then
                local box = maxOpenRow:FindFirstChild("Input")
                if box and box:IsA("TextBox") then
