                if type(rule) == "table" then
                    rulesOut[#rulesOut + 1] = {
                        id = tostring(rule.id or ""),
                        enabled = rule.enabled ~= false,
                        pets = mapToArray(mapFromList(rule.pets)),
                        sizes = mapToArray(mapFromList(rule.sizes)),
                        types = mapToArray(mapFromList(rule.types)),
                        type_size_mode = normalizeTypeSizeMode(rule.type_size_mode),
                    }
                end
            end
            return {
                enabled = eggST.open_egg == true,
                open_egg = eggST.open_egg == true,
                eggs = mapToArray(eggsSelected),
                max_open = eggST.max_open,
                rules = rulesOut,
                rulesOrder = eggST.rulesOrder,
