        local scrollLayout = Instance.new("UIListLayout")
        scrollLayout.FillDirection = Enum.FillDirection.Vertical
        scrollLayout.SortOrder = Enum.SortOrder.LayoutOrder
        scrollLayout.Padding = UDim.new(0, 4)
        scrollLayout.Parent = scroll

        local emptyLbl = Instance.new("TextLabel")
        emptyLbl.Name = "EmptyHint"
        emptyLbl.BackgroundTransparency = 1
        emptyLbl.Size = UDim2.new(1, 0, 0, 36)
        emptyLbl.Font = Enum.Font.Gotham
        emptyLbl.TextSize = 11
        emptyLbl.TextColor3 = Color3.fromRGB(130, 130, 130)
        emptyLbl.TextXAlignment = Enum.TextXAlignment.Center
        emptyLbl.Text = "No rules yet — tap Add Pet Rule"
        emptyLbl.LayoutOrder = 0
        emptyLbl.Parent = scroll

        local function refreshEmptyHint()
            emptyLbl.Visible = (#eggST.rules <= 0)
        end

        local function destroyRuleCards()
            for _, apis in ipairs(rowApis) do
                if apis.card and apis.card.Parent then
                    apis.card:Destroy()
                end
            end
            table.clear(rowApis)
        end

        local function removeRuleById(ruleId)
            ruleId = tostring(ruleId or "")
            if ruleId == "" then return end
            local nextRules, nextOrder = {}, {}
            for _, r in ipairs(eggST.rules) do
                if tostring(r.id) ~= ruleId then
                    nextRules[#nextRules + 1] = r
                    nextOrder[#nextOrder + 1] = tostring(r.id)
                end
            end
            eggST.rules = nextRules
            eggST.rulesOrder = nextOrder
            patchEgg({ rules = nextRules, rulesOrder = nextOrder })
            rebuildRuleCards()
        end

        local function buildRuleRow(index, rule)
            local petKey = getRulePetKey(rule)
            local capturedId = tostring(rule.id or "")
            local typesMap = mapFromList(rule.types)
            local sizesMap = mapFromList(rule.sizes)

            local card = Instance.new("Frame")
            card.Name = "EggRule_" .. capturedId
            card.BackgroundColor3 = Color3.fromRGB(18, 18, 18)
            card.BorderSizePixel = 0
            card.Size = UDim2.new(1, 0, 0, 0)
            card.AutomaticSize = Enum.AutomaticSize.Y
            card.LayoutOrder = index
            card.Parent = scroll

            local cardCorner = Instance.new("UICorner")
            cardCorner.CornerRadius = UDim.new(0, 5)
            cardCorner.Parent = card

            local cardStroke = Instance.new("UIStroke")
            cardStroke.Color = Color3.fromRGB(50, 50, 50)
            cardStroke.Transparency = 0.55
            cardStroke.Parent = card

            local cardPad = Instance.new("UIPadding")
            cardPad.PaddingTop = UDim.new(0, 4)
            cardPad.PaddingBottom = UDim.new(0, 4)
            cardPad.PaddingLeft = UDim.new(0, 6)
            cardPad.PaddingRight = UDim.new(0, 6)
            cardPad.Parent = card

            local cardLayout = Instance.new("UIListLayout")
            cardLayout.FillDirection = Enum.FillDirection.Vertical
            cardLayout.SortOrder = Enum.SortOrder.LayoutOrder
            cardLayout.Padding = UDim.new(0, 2)
            cardLayout.Parent = card

            local header = Instance.new("Frame")
            header.Name = "Header"
            header.BackgroundTransparency = 1
            header.Size = UDim2.new(1, 0, 0, 24)
            header.LayoutOrder = 0
            header.ZIndex = 2
            header.Parent = card

            local iconPad = resolvePetIcon(petKey) and 22 or 0
            attachPetIcon(header, petKey, 18, 0)

            local nameLbl = Instance.new("TextLabel")
            nameLbl.BackgroundTransparency = 1
            nameLbl.Size = UDim2.new(1, -(iconPad + 34), 1, 0)
            nameLbl.Position = UDim2.new(0, iconPad, 0, 0)
            nameLbl.Font = Enum.Font.GothamBold
            nameLbl.TextSize = 12
            nameLbl.TextXAlignment = Enum.TextXAlignment.Left
            nameLbl.TextColor3 = Color3.fromRGB(240, 240, 240)
            nameLbl.Text = petKey ~= "" and petKey or ("Rule " .. tostring(index))
            nameLbl.ZIndex = 3
            nameLbl.Parent = header

            local removeBtn = Instance.new("TextButton")
            removeBtn.Name = "Remove"
            removeBtn.AutoButtonColor = true
            removeBtn.BackgroundColor3 = Color3.fromRGB(55, 24, 24)
            removeBtn.Size = UDim2.new(0, 24, 0, 20)
            removeBtn.AnchorPoint = Vector2.new(1, 0.5)
            removeBtn.Position = UDim2.new(1, 0, 0.5, 0)
            removeBtn.Font = Enum.Font.GothamBold
            removeBtn.TextSize = 13
            removeBtn.TextColor3 = Color3.fromRGB(255, 120, 120)
            removeBtn.Text = "X"
            removeBtn.ZIndex = 5
            removeBtn.Active = true
            removeBtn.Parent = header

            local rmCorner = Instance.new("UICorner")
            rmCorner.CornerRadius = UDim.new(0, 4)
            rmCorner.Parent = removeBtn

            removeBtn.MouseButton1Click:Connect(function()
                removeRuleById(capturedId)
            end)

            ui:CreateRowToggle(card, "Enabled", rule.enabled ~= false, function(on)
                for _, r in ipairs(eggST.rules) do
                    if tostring(r.id) == capturedId then
                        r.enabled = (on == true)
                        break
                    end
                end
                patchEgg({ rules = eggST.rules })
            end, 0)

            local typeRow = ui:CreateRowDropdown(card, {
                label = "Variant",
                placeholder = "Any",
                mode = "multi",
                deferItemLoad = true,
                labelForKey = function(key)
                    return tostring(key or "")
                end,
                getItems = function()
                    return buildPetTypeItems()
                end,
                initial = typesMap,
                onChanged = function(_, selectedMap)
                    for _, r in ipairs(eggST.rules) do
                        if tostring(r.id) == capturedId then
                            r.types = cleanSelectedMap(selectedMap)
                            break
                        end
                    end
                    patchEgg({ rules = eggST.rules })
                end,
            })
            if typeRow and typeRow:IsA("GuiObject") then
                typeRow.LayoutOrder = 1
            end

            local modeRow = ui:CreateRowDropdown(card, {
                label = "Type/Size",
                placeholder = "OR",
                mode = "single",
                getItems = function()
                    return {
                        { key = "or", name = "OR (salah satu)" },
                        { key = "and", name = "AND (keduanya)" },
                    }
                end,
                labelForKey = function(key)
                    return normalizeTypeSizeMode(key) == "and" and "AND" or "OR"
                end,
                initial = normalizeTypeSizeMode(rule.type_size_mode),
                onChanged = function(_, selectedKey)
                    local mode = normalizeTypeSizeMode(selectedKey)
                    for _, r in ipairs(eggST.rules) do
                        if tostring(r.id) == capturedId then
                            r.type_size_mode = mode
                            break
                        end
                    end
                    patchEgg({ rules = eggST.rules })
                end,
            })
            if modeRow and modeRow:IsA("GuiObject") then
                modeRow.LayoutOrder = 2
            end

            local sizeRow = ui:CreateRowDropdown(card, {
                label = "Size",
                placeholder = "Any",
                mode = "multi",
                deferItemLoad = true,
                labelForKey = function(key)
                    return tostring(key or "")
                end,
                getItems = function()
                    return buildPetSizeItems()
                end,
                initial = sizesMap,
                onChanged = function(_, selectedMap)
                    for _, r in ipairs(eggST.rules) do
                        if tostring(r.id) == capturedId then
                            r.sizes = cleanSelectedMap(selectedMap)
                            break
                        end
                    end
                    patchEgg({ rules = eggST.rules })
                end,
            })
            if sizeRow and sizeRow:IsA("GuiObject") then
                sizeRow.LayoutOrder = 3
            end

            rowApis[#rowApis + 1] = { card = card }
        end

        rebuildRuleCards = function()
            destroyRuleCards()
            normalizeRulesInPlace()
            for i, rule in ipairs(eggST.rules) do
                buildRuleRow(i, rule)
            end
            refreshEmptyHint()
        end

        maxOpenRow = ui:CreateRowInput(body, "Max Egg Open (0 = all, auto-off)", tostring(eggST.max_open), function(text)
            local s = tostring(text or ""):gsub("%s+", "")
            local n = math.max(0, math.floor(tonumber(s) or 0))
            eggST.max_open = n
            patchEgg({ max_open = n })
        end, false)

        _, _, eggToggleApis.open_egg = ui:CreateRowToggle(body, "Open Egg", eggST.open_egg, function(on)
            eggST.open_egg = (on == true)
            eggST.enabled = eggST.open_egg
            patchEgg({ open_egg = eggST.open_egg, enabled = eggST.open_egg }, true)
        end)

        rebuildRuleCards()
        writeEggGlobals()
    end

    -- Build langsung (seperti Buy Pet) supaya flush/save ready + UI load dari getAuto.
    local ok, err = pcall(buildOpenEggBody, body)
    if not ok then
        warn("[GAG2] Open Egg UI build error:", tostring(err))
        pcall(function()
            ui:CreateRowLabel(body, "Open Egg UI error: " .. tostring(err), nil, 0, "muted")
        end)
    end
end

return M end,         required = false },
    { key = "AutoSprinklerOtherGarden", name = "Auto Sprinkler Other Garden", factory = function() -- AutoSprinklerOtherGarden.lua — Sprinkler & watering di garden player lain
-- 2 loop: positionMainLoop (weather+move) | sprinkler/watering (aksi, pause saat malam)
-- Gerak: FlyTo saja (tanpa HoldAt/lock/teleport). Weather: ActivePhase+PhaseDuration saja.

local Players           = game:GetService("Players")
local RunService        = game:GetService("RunService")
local CollectionService = game:GetService("CollectionService")
