local Networking = nil
local PlaceSprinkler = nil
local UseWateringCan = nil
local WateringCanFx = nil

local function ensureNetworking()
    if type(Networking) == "table" then
        return true
    end
    local ok, net = pcall(function()
        local sm = ReplicatedStorage:FindFirstChild("SharedModules")
            or ReplicatedStorage:WaitForChild("SharedModules", 15)
        if not sm then return nil end
        local mod = sm:FindFirstChild("Networking")
            or sm:WaitForChild("Networking", 15)
        if not mod then return nil end
        return require(mod)
    end)
    if not ok or type(net) ~= "table" then
        return false
    end
    Networking = net
    PlaceSprinkler = Networking.Place and Networking.Place.PlaceSprinkler
    UseWateringCan = Networking.WateringCan and Networking.WateringCan.UseWateringCan
    WateringCanFx  = Networking.WateringCan and Networking.WateringCan.WateringCanFx
    return true
end

