-- Diisi setelah getHRP tersedia; dipakai _publish / GetStatusText.
local refreshStatusDist
local appendStatusExtras

local function _publish(key, detail)
    ST.statusKey = tostring(key or "idle")
    local msg = STATUS[ST.statusKey] or ST.statusKey
    if detail and detail ~= "" then
        msg = msg .. " · " .. tostring(detail)
    end
    ST.statusBase = msg
    if refreshStatusDist then
        refreshStatusDist()
    else
        ST.statusDistStuds = nil
        ST.statusText = msg
        G.__GAG2_SW_OTHER_STATUS = msg
        _G.__GAG2_SW_OTHER_STATUS = msg
    end
end

local PlayerStateClient = nil

local function isLoadingActive()
    if not LP then return false end
    if LP:GetAttribute("LoadingScreenDone") == true then
        return false
    end
    if LP:GetAttribute("LoadingScreenActive") == true then
        return true
    end
    return workspace:FindFirstChild("LoadingScreenMenu") ~= nil
end

local function _ensurePlayerStateClient()
    if PlayerStateClient then return true end
    local cm = ReplicatedStorage:FindFirstChild("ClientModules")
    local modInst = cm and cm:FindFirstChild("PlayerStateClient")
    if not modInst then return false end
    local ok, mod = pcall(require, modInst)
    if ok and type(mod) == "table" then
        PlayerStateClient = mod
        return true
    end
    return false
end

local function _getLocalPlayerReplica(waitSec)
    if not _ensurePlayerStateClient() then return nil end
    if type(PlayerStateClient.GetLocalReplica) ~= "function" then return nil end
    local replica = PlayerStateClient:GetLocalReplica()
    if replica then return replica end
    waitSec = tonumber(waitSec) or 0
    if waitSec > 0 and type(PlayerStateClient.WaitForLocalReplica) == "function" then
        return PlayerStateClient:WaitForLocalReplica(waitSec)
    end
    return nil
end

local function _replicaLooksReady(replica)
    if not replica or type(replica.Data) ~= "table" then return false end
    if type(replica.IsActive) == "function" then
        local ok, active = pcall(replica.IsActive, replica)
        if ok and active ~= true then return false end
    end
    return true
end

-- Weather: SATU sumber saja — workspace ActivePhase + PhaseDuration
local function getWeather()
    local phase = workspace:GetAttribute("ActivePhase")
    local phaseEnd = workspace:GetAttribute("PhaseDuration")
    local rem = nil
    if type(phaseEnd) == "number" then
        rem = math.max(0, phaseEnd - workspace:GetServerTimeNow())
    end
    return phase, rem
end

-- Night, atau Sunset dengan sisa <= NIGHT_PREEMPT_SEC (−7)
-- Hormati toggle Pause at Night (default ON).
local function isPauseAtNightEnabled()
    local v = G.SW_OTHER_PAUSE_AT_NIGHT
    if v == nil then v = rawget(_G, "SW_OTHER_PAUSE_AT_NIGHT") end
    if v == nil then
        local main = G.MAIN or rawget(_G, "MAIN")
        local sw = main and main.auto and main.auto.sprinklerOtherGarden
        if type(sw) == "table" and sw.pause_at_night ~= nil then
            v = sw.pause_at_night
        end
    end
    if v == nil then return true end
    return v == true
end

local function isNightOrPreempt()
    local phase, rem = getWeather()
    local night = false
    if phase == "Night" then
        night = true
    elseif phase == "Sunset" and rem ~= nil and rem <= CFG.NIGHT_PREEMPT_SEC then
        night = true
    end
    if not night then
        return false, rem, phase, rem
    end
    if not isPauseAtNightEnabled() then
        return false, rem, phase, rem
    end
    if phase == "Night" then
        return true, 0, phase, rem
    end
    return true, rem, phase, rem
end

-- Character siap gerak (bukan mati / belum spawn)
local function isCharacterAlive()
    local ch = LP.Character
    if not ch or not ch.Parent then return false end
    local hum = ch:FindFirstChildOfClass("Humanoid")
    local hrp = ch:FindFirstChild("HumanoidRootPart")
    if not hum or not hrp or not hrp:IsA("BasePart") then return false end
    if hum.Health <= 0 then return false end
    local ok, state = pcall(function() return hum:GetState() end)
    if ok and state == Enum.HumanoidStateType.Dead then return false end
    return true
end

local function pauseMovementForDeath()
    ST.atTarget = false
    ST.posMoveBusy = false
    local F = G.FlyNoclip or G.FlyNoclipModule or rawget(_G, "FlyNoclip")
    if F then
        -- Stop sudah ReleaseToSurface (noclip off aman)
        if type(F.Stop) == "function" then
            pcall(F.Stop, F)
        else
            if type(F.Unlock) == "function" then pcall(F.Unlock, F) end
            if type(F.SetNoclip) == "function" then pcall(F.SetNoclip, F, false) end
        end
    end
end

-- Setelah respawn: kunci di posisi spawn (jangan BV+noclip hover)
local function armFlyAfterSpawn(char)
    if not ST.running or not char then return end
    task.spawn(function()
        local hrp = char:WaitForChild("HumanoidRootPart", 12)
        task.wait(0.35)
        if not ST.running or LP.Character ~= char then return end
        if not isCharacterAlive() then return end
        ST.atTarget = false
        ST.posMoveBusy = false
        local F = G.FlyNoclip or G.FlyNoclipModule or rawget(_G, "FlyNoclip")
        if F and hrp and hrp:IsA("BasePart") then
            ST.pinnedFlyGoal = hrp.Position
            if type(F.LockAt) == "function" then
                pcall(F.LockAt, F, hrp.Position)
            elseif type(F.PlaceAt) == "function" then
                pcall(F.PlaceAt, F, hrp.Position)
            end
        end
        _publish("idle", "spawn lock")
    end)
end

local function _sessionBlockReason()
    if not LP or not LP.Parent then return "no_player" end
    if not isCharacterAlive() then return "dead" end
    if isLoadingActive() then return "loading_screen" end
    if G.__GAG2_OFFLINE_GROWTH_BUSY == true or rawget(_G, "__GAG2_OFFLINE_GROWTH_BUSY") == true then
        return "offline_growth"
    end
    if LP:GetAttribute("OfflineCutscenePlaying") == true then return "offline_cutscene" end
    if LP:GetAttribute("CutsceneInputBlocked") == true then return "cutscene_blocked" end
    if not CollectionService:HasTag(LP, "DataLoaded") then return "data_not_loaded" end
    if LP:GetAttribute("PlotId") == nil then return "no_plot_id" end
    if not _replicaLooksReady(_getLocalPlayerReplica(0)) then return "player_state" end
    if isNightOrPreempt() then return "night" end
    if ST.workPaused then return "night" end
    if not ST.atTarget then return "pos_not_ready" end
    return nil
end

local function _isSessionBlocked()
    local reason = _sessionBlockReason()
    return reason ~= nil, reason
end

local function _waitReadyDetail(reason)
    reason = tostring(reason or "")
    if reason == "loading_screen" then return "Loading..." end
    if reason == "offline_growth" or reason == "offline_cutscene" then return "Grow offline..." end
    if reason == "cutscene_blocked" then return "Cutscene..." end
    if reason == "data_not_loaded" then return "Save load..." end
    if reason == "player_state" then return "PlayerState..." end
    if reason == "no_plot_id" then return "Plot..." end
    if reason == "pos_not_ready" then return "Moving to plant..." end
    if reason == "dead" then return "Respawn..." end
    if reason == "night" then
        local phase, rem = getWeather()
        if phase == "Sunset" and rem then
            return string.format("Night in %.0fs...", rem)
        end
        return "Night..."
    end
    return "Wait ready..."
end

local function _waitSessionReady(maxSec)
    maxSec = math.max(1, tonumber(maxSec) or CFG.SESSION_READY_MAX_WAIT_SEC)
    local deadline = os.clock() + maxSec
    local lastReason = nil

    while ST.running and os.clock() < deadline do
        local blocked, reason = _isSessionBlocked()
        if not blocked then
            return true
        end

        reason = tostring(reason or "blocked")
        if reason ~= lastReason then
            lastReason = reason
        end
        -- Malam / belum di target / mati: jangan spin wait panjang — loop aksi yang handle
        if reason == "night" or reason == "pos_not_ready" or reason == "dead" then
            return false, reason
        end
        _publish("wait_ready", _waitReadyDetail(reason))
        task.wait(CFG.SESSION_READY_POLL_SEC)
    end

    return false, lastReason
end

local function _ensureSessionReady(maxSec)
    if not _isSessionBlocked() then
        return true
    end
    return _waitSessionReady(maxSec)
end

local function _gateMidCycle()
    if isNightOrPreempt() or ST.workPaused then
        return false
    end
    if not ST.atTarget then
        return false
    end
    if not _isSessionBlocked() then
        return true
    end
    return _ensureSessionReady(CFG.SESSION_MID_CYCLE_WAIT_SEC)
end

local function canRunActions()
    return ST.running and isCharacterAlive() and not ST.workPaused and ST.atTarget == true and not isNightOrPreempt()
end

local function _normalizeSet(src)
    if type(src) ~= "table" then return {} end
    local out = {}
    for i = 1, #src do
        local v = src[i]
        if v ~= nil and tostring(v) ~= "" then
            out[tostring(v)] = true
        end
    end
    if next(out) then return out end
    for k, v in pairs(src) do
        if v == true or v == 1 or v == "true" then
            out[tostring(k)] = true
        end
    end
    return out
end

local function _canon(s)
    return tostring(s or ""):lower():gsub("[^%w]+", "")
end

local function clampMaxUse(n)
    n = math.floor(tonumber(n) or 1)
    return math.max(1, math.min(100, n))
end

local function clampStopCollectMax(n)
    n = math.floor(tonumber(n) or 0)
    if n < 0 then n = 0 end
    if n > 9999 then n = 9999 end
    return n
end

local function clampWateringDelay(n)
    n = math.floor(tonumber(n) or 10)
    if n < 0 then n = 0 end
    if n > 600 then n = 600 end
    return n
end

local function _typeMatch(a, b)
    if a == nil or b == nil then return false end
    if tostring(a) == tostring(b) then return true end
    local ca, cb = _canon(a), _canon(b)
    if ca == cb then return true end
    if ca == "" or cb == "" then return false end
    -- Prefix-only (hindari "common" match di dalam "uncommon")
    if #cb >= 3 and ca:sub(1, #cb) == cb then return true end
    if #ca >= 3 and cb:sub(1, #ca) == ca then return true end
    return false
end

local function _selectedMatch(selected, name)
    if not next(selected) then return true end
    name = tostring(name or "")
    if selected[name] then return true end
    local c = _canon(name)
    for key in pairs(selected) do
        if _canon(key) == c or _typeMatch(name, key) then return true end
    end
    return false
end

local function _looksLikeId(s)
    s = tostring(s or "")
    if s == "" then return true end
    if s:match("^%d+_[%x%-]+") then return true end
    if #s >= 32 and s:match("^[%x%-]+$") then return true end
    if s:find("_", 1, true) and s:find("-", 1, true) and not s:match("^[%a][%a ]*$") then
        return true
    end
    return false
end

local function _pickNameFromInst(inst)
    if not inst then return nil end
    for _, key in ipairs({
        "SeedName", "PlantName", "FruitType", "FruitName",
        "ItemName", "CorePartName", "ConfigPathName",
    }) do
        local v = inst:GetAttribute(key)
        if type(v) == "string" and v ~= "" and not _looksLikeId(v) then
            local tail = v:match("([^/]+)$")
            if tail and not _looksLikeId(tail) then return tail end
            return v
        end
    end
    return nil
end

local function resolvePlantTypeName(plant)
    if not plant then return "" end
    local FSV = G.FruitSellValue or rawget(_G, "FruitSellValue")
    if type(FSV) == "table" and type(FSV.resolveSeedName) == "function" then
        local ok, n = pcall(FSV.resolveSeedName, FSV, plant)
        if ok and type(n) == "string" and n ~= "" and not _looksLikeId(n) then
            return n
        end
    end
    local AS = G.AutoShovel or rawget(_G, "AutoShovel")
    if type(AS) == "table" and type(AS.GetPlantDisplayName) == "function" then
        local ok, n = pcall(AS.GetPlantDisplayName, AS, plant)
        if ok and type(n) == "string" and n ~= "" and not _looksLikeId(n) then
            return n
        end
    end
    local n = _pickNameFromInst(plant)
    if n then return n end
    for _, ch in ipairs(plant:GetChildren()) do
        n = _pickNameFromInst(ch)
        if n then return n end
        if ch.Name == "Fruits" or ch.Name == "Fruit" then
            for _, fruit in ipairs(ch:GetChildren()) do
                n = _pickNameFromInst(fruit)
                if n then return n end
            end
        end
    end
    return ""
end

local function normalizePositionMode(mode)
    mode = tostring(mode or "under"):lower()
    if mode == "above" or mode == "over" then
        return "above"
    end
    return "under"
end

local function getVerticalOffsetY(mode)
    if normalizePositionMode(mode or ST.positionMode) == "above" then
        return CFG.ABOVE_OFFSET
    end
    return CFG.UNDER_OFFSET
end

local function applyPositionMode(cfg)
    local newMode = normalizePositionMode(
        cfg and (cfg.position_mode or cfg.watering_mode) or ST.positionMode
    )
    if ST.positionMode and ST.positionMode ~= newMode then
        ST.approachAnchor = nil
    end
    ST.positionMode = newMode
end

local function getCfg()
    local main = G.MAIN or rawget(_G, "MAIN")
    local sw = {}
    if type(main) == "table" and type(main.auto) == "table"
        and type(main.auto.sprinklerOtherGarden) == "table" then
        sw = main.auto.sprinklerOtherGarden
    elseif type(main) == "table" and type(main.misc) == "table"
        and type(main.misc.auto_vuln) == "table"
        and type(main.misc.auto_vuln.sprinkler_water) == "table" then
        sw = main.misc.auto_vuln.sprinkler_water
    end

    local players = G.SW_OTHER_TARGET_PLAYERS_SELECTED or rawget(_G, "SW_OTHER_TARGET_PLAYERS_SELECTED")
    if type(players) ~= "table" then players = _normalizeSet(sw.target_players) end
    if not next(players) then
        players = _normalizeSet(sw.target_plots)
    end

    local plants = G.SW_OTHER_TARGET_PLANTS_SELECTED or rawget(_G, "SW_OTHER_TARGET_PLANTS_SELECTED")
    if type(plants) ~= "table" then plants = _normalizeSet(sw.target_plants) end

    local sprinklers = G.SW_OTHER_SPRINKLERS_SELECTED or rawget(_G, "SW_OTHER_SPRINKLERS_SELECTED")
    if type(sprinklers) ~= "table" then sprinklers = _normalizeSet(sw.sprinklers) end

    local cans = G.SW_OTHER_WATERING_SELECTED or rawget(_G, "SW_OTHER_WATERING_SELECTED")
    if type(cans) ~= "table" then cans = _normalizeSet(sw.watering_cans) end

    local posMode = G.SW_OTHER_POSITION_MODE or rawget(_G, "SW_OTHER_POSITION_MODE")
    if posMode == nil then
        posMode = sw.position_mode
    end
    if posMode == nil then
        posMode = G.SW_OTHER_WATERING_MODE or rawget(_G, "SW_OTHER_WATERING_MODE")
    end
    if posMode == nil then
        posMode = sw.watering_mode
    end
    posMode = normalizePositionMode(posMode)
    ST.positionMode = posMode

    local enabled = G.SW_OTHER_ENABLED
    if enabled == nil then enabled = rawget(_G, "SW_OTHER_ENABLED") end
    if enabled == nil then enabled = (sw.enabled == true) end

    local sprinklerMax = sw.sprinkler_max_use
    if sprinklerMax == nil then
        sprinklerMax = G.SW_OTHER_SPRINKLER_MAX_USE or rawget(_G, "SW_OTHER_SPRINKLER_MAX_USE")
    end

    local wateringMax = sw.watering_max_use
    if wateringMax == nil then
        wateringMax = G.SW_OTHER_WATERING_MAX_USE or rawget(_G, "SW_OTHER_WATERING_MAX_USE")
    end

    local stopCollectMax = sw.stop_collect_max
    if stopCollectMax == nil then
        stopCollectMax = G.SW_OTHER_STOP_COLLECT_MAX or rawget(_G, "SW_OTHER_STOP_COLLECT_MAX")
    end

    local wateringDelay = sw.watering_delay_sec
    if wateringDelay == nil then
        wateringDelay = G.SW_OTHER_WATERING_DELAY_SEC or rawget(_G, "SW_OTHER_WATERING_DELAY_SEC")
    end

    local pauseAtNight = sw.pause_at_night
    if pauseAtNight == nil then
        pauseAtNight = G.SW_OTHER_PAUSE_AT_NIGHT
    end
    if pauseAtNight == nil then
        pauseAtNight = rawget(_G, "SW_OTHER_PAUSE_AT_NIGHT")
    end
    if pauseAtNight == nil then
        pauseAtNight = true
    end

    return {
        enabled = (enabled == true),
        target_players = _normalizeSet(players),
        target_plants = _normalizeSet(plants),
        sprinklers = _normalizeSet(sprinklers),
        watering_cans = _normalizeSet(cans),
        sprinkler_max_use = clampMaxUse(sprinklerMax),
        watering_max_use = clampMaxUse(wateringMax),
        stop_collect_max = clampStopCollectMax(stopCollectMax),
        watering_delay_sec = clampWateringDelay(wateringDelay),
        pause_at_night = (pauseAtNight == true),
        position_mode = posMode,
        rollback_rejoin = false,
    }
end

function M.GetState()
    return getCfg()
end

local function cleanUsername(name)
    name = tostring(name or ""):gsub("^%s+", ""):gsub("%s+$", ""):gsub("^@", "")
    return name
end

local function plotOwnedByUserId(plot, userId)
    if not plot or not userId then return false end
    local uid = math.floor(tonumber(userId) or 0)
    if uid <= 0 then return false end
    for _, attr in ipairs({ "OwnerUserId", "OwnerId", "UserId" }) do
        local v = plot:GetAttribute(attr)
        if math.floor(tonumber(v) or 0) == uid then return true end
    end
    for _, child in ipairs(plot:GetChildren()) do
        if child:IsA("ValueBase") then
            local n = child.Name:lower()
            if n:find("owner") or n:find("userid") or n:find("player") then
                if math.floor(tonumber(child.Value) or 0) == uid then return true end
            end
        end
    end
    return false
end

local function findPlotForPlayer(plr)
    if not plr then return nil end
    local gardens = workspace:FindFirstChild("Gardens")
    if not gardens then return nil end

    local plotId = plr:GetAttribute("PlotId")
        or plr:GetAttribute("Plot")
        or plr:GetAttribute("PlotName")
        or plr:GetAttribute("GardenPlot")
    if plotId ~= nil then
        local idStr = tostring(plotId)
        for _, name in ipairs({ "Plot" .. idStr, idStr, "Plot_" .. idStr }) do
            local plot = gardens:FindFirstChild(name)
            if plot then return plot end
        end
    end

    for _, plot in ipairs(gardens:GetChildren()) do
        if plotOwnedByUserId(plot, plr.UserId) then
            return plot
        end
    end
    return nil
end

local function findPlayerByUsername(username)
    username = cleanUsername(username)
    if username == "" then return nil end
    local want = username:lower()
    for _, plr in ipairs(Players:GetPlayers()) do
        if plr.Name:lower() == want then return plr end
    end
    return nil
end

local function findPlotForUsername(username)
    return findPlotForPlayer(findPlayerByUsername(username))
end

local function findPlotByKey(plotKey)
    plotKey = tostring(plotKey or "")
    if plotKey == "" or plotKey == "_none" then return nil end
    local gardens = workspace:FindFirstChild("Gardens")
    if not gardens then return nil end
    local plot = gardens:FindFirstChild(plotKey)
    if plot then return plot end
    for _, child in ipairs(gardens:GetChildren()) do
        if tostring(child.Name) == plotKey then return child end
    end
    return nil
end

local function resolveTargetPlotId(plot)
    if not plot then return nil end
    for _, attr in ipairs({ "PlotId", "Id", "Plot", "PlotIndex" }) do
        local v = plot:GetAttribute(attr)
        if v ~= nil then
            local n = tonumber(v)
            if n then return n end
        end
    end
    return tonumber(string.match(tostring(plot.Name), "%d+"))
end

local function listSelectedPlayerNames(cfg)
    local out = {}
    for key, on in pairs(cfg.target_players or {}) do
        if on == true and key ~= "_none" then
            out[#out + 1] = cleanUsername(key)
        end
    end
    table.sort(out, function(a, b)
        return a:lower() < b:lower()
    end)
    return out
end

local function getPlantGroundPos(plant)
    if not plant then return nil end
    if plant:IsA("BasePart") then return plant.Position end
    local ok, pos = pcall(function() return plant:GetPivot().Position end)
    if ok and typeof(pos) == "Vector3" then return pos end
    local part = plant:FindFirstChildWhichIsA("BasePart", true)
    return part and part.Position or nil
end

local function listSelectedPlantTypeKeys(selectedPlants)
    local out = {}
    for key, on in pairs(selectedPlants or {}) do
        if on == true and key ~= "_none" then
            out[#out + 1] = tostring(key)
        end
    end
    table.sort(out)
    return out
end

local function iterPlotPlantFolders(plot)
    local out, seen = {}, {}
    local function add(f)
        if f and not seen[f] then
            seen[f] = true
            out[#out + 1] = f
        end
    end
    if not plot then return out end
    local important = plot:FindFirstChild("Important")
    add(plot:FindFirstChild("Plants"))
    add(plot:FindFirstChild("Plants_Physical"))
    if important then
        add(important:FindFirstChild("Plants"))
        add(important:FindFirstChild("Plants_Physical"))
    end
    return out
end

local function pickSingleTarget(plot, selectedPlants, rotateIndex)
    if not plot or not next(selectedPlants) then return nil end
    local typeKeys = listSelectedPlantTypeKeys(selectedPlants)
    if #typeKeys == 0 then return nil end

    rotateIndex = math.max(1, math.floor(tonumber(rotateIndex) or 1))
    local wantKey = typeKeys[((rotateIndex - 1) % #typeKeys) + 1]

    for _, folder in ipairs(iterPlotPlantFolders(plot)) do
        for _, plant in ipairs(folder:GetChildren()) do
            if plant:IsA("Model") then
                local key = resolvePlantTypeName(plant)
                if key ~= "" and _selectedMatch({ [wantKey] = true }, key) then
                    local pos = getPlantGroundPos(plant)
                    if pos then
                        return { plant = plant, key = key, pos = pos }
                    end
                end
            end
        end
    end
    return nil
end

local function collectPlantAreas(plot)
    local out = {}
    for _, d in ipairs(plot:GetDescendants()) do
        if d:IsA("BasePart") and CollectionService:HasTag(d, "PlantArea") then
            out[#out + 1] = d
        end
    end
    return out
end

local function getPlantAreas(plot)
    if not plot then return {} end
    -- Jangan cache list kosong: plot baru join sering belum punya PlantArea.
    if ST.plantAreaCachePlot == plot and ST.plantAreaCache and #ST.plantAreaCache > 0 then
        return ST.plantAreaCache
    end
    local areas = collectPlantAreas(plot)
    if #areas > 0 then
        ST.plantAreaCachePlot = plot
        ST.plantAreaCache = areas
    else
        ST.plantAreaCachePlot = nil
        ST.plantAreaCache = nil
    end
    return areas
end

local function invalidatePlotCaches()
    ST.plantAreaCachePlot = nil
    ST.plantAreaCache = nil
    ST.sprinklerCachePlot = nil
    ST.sprinklerCacheList = nil
    ST.sprinklerCacheAt = 0
end

local function snapToPlantArea(plot, pos)
    if not plot or not pos then return nil end
    local areas = getPlantAreas(plot)
    if #areas == 0 then return nil end
    local params = RaycastParams.new()
    params.FilterType = Enum.RaycastFilterType.Include
    params.FilterDescendantsInstances = areas
    -- Selalu ray dari atas plot, jangan dari Y karakter (bisa sudah under → miss / Y salah).
    local originY = pos.Y + 80
    local okPlot, plotPivot = pcall(function() return plot:GetPivot().Position end)
    if okPlot and typeof(plotPivot) == "Vector3" then
        originY = math.max(originY, plotPivot.Y + 120)
    end
    for _, part in ipairs(areas) do
        originY = math.max(originY, part.Position.Y + 80)
    end
    local hit = workspace:Raycast(
        Vector3.new(pos.X, originY, pos.Z),
        Vector3.new(0, -800, 0),
        params
    )
    if hit and CollectionService:HasTag(hit.Instance, "PlantArea")
        and hit.Instance:IsDescendantOf(plot) then
        return hit.Position
    end
    return nil
end

-- Plot siap approach: plant dekat plot. PlantArea opsional (rejoin sering belum ada tag).
local function isPlotReadyForApproach(plot, seedPos)
    if not plot or not plot.Parent then return false end
    if typeof(seedPos) ~= "Vector3" then return false end
    local ok, plotPos = pcall(function() return plot:GetPivot().Position end)
    if not ok or typeof(plotPos) ~= "Vector3" then return false end
    local flat = Vector3.new(seedPos.X - plotPos.X, 0, seedPos.Z - plotPos.Z)
    if flat.Magnitude > (CFG.PLOT_SEED_MAX_FLAT or 400) then return false end
    -- Seed di origin dunia hampir pasti belum stream
    if seedPos.Magnitude < 5 and plotPos.Magnitude > 50 then return false end
    local areas = getPlantAreas(plot)
    if #areas == 0 then
        return true -- fallback plant pivot; jangan stuck "plot loading"
    end
    local surface = snapToPlantArea(plot, seedPos)
    return typeof(surface) == "Vector3" or flat.Magnitude <= (CFG.PLOT_SEED_MAX_FLAT or 400)
end

local function makePlotToken(ctx)
    if not ctx or not ctx.plot then return "" end
    return tostring(ctx.plotId or "") .. "|" .. tostring(ctx.plot.Name) .. "|" .. tostring(ctx.plot)
end

local function clearStaleTargetState()
    invalidatePlotCaches()
    ST.approachAnchor = nil
    ST.approachLockTarget = nil
    ST.approachSessionKey = nil
    ST.lockedPlotToken = nil
    ST.nightRetreatOffset = nil
end

local function refreshLivePlantPos(ctx)
    if not ctx then return nil end
    if not ctx.plot or not ctx.plot.Parent then return nil end
    local plant = ctx.target and ctx.target.plant
    local pos = nil
    if plant and plant.Parent then
        pos = getPlantGroundPos(plant)
    end
    if typeof(pos) ~= "Vector3" and typeof(ctx.target and ctx.target.pos) == "Vector3" then
        pos = ctx.target.pos
    end
    if typeof(pos) ~= "Vector3" then
        return typeof(ctx.groundPos) == "Vector3" and ctx.groundPos or nil
    end
    if ctx.target then
        ctx.target.pos = pos
    end
    local snapped = nil
    pcall(function()
        snapped = snapToPlantArea(ctx.plot, pos)
    end)
    ctx.groundPos = (typeof(snapped) == "Vector3" and snapped) or pos
    return ctx.groundPos
end

local function iterInventory()
    local out, seen = {}, {}
    local function add(c)
        if c and not seen[c] then
            seen[c] = true
            out[#out + 1] = c
        end
    end
    add(LP:FindFirstChildOfClass("Backpack"))
    add(LP:FindFirstChild("Backpack"))
    add(LP:FindFirstChild("TasRansel"))
    add(LP.Character)
    for _, ch in ipairs(LP:GetChildren()) do
        if ch:IsA("Folder") or ch:IsA("Model") or ch:IsA("Backpack") then
            local n = ch.Name:lower()
            if n:find("backpack") or n:find("ransel") or n:find("tas") or n:find("inventory") then
                add(ch)
            end
        end
    end
    return out
end

local function findToolsByAttr(attrName, selected)
    local found = {}
    local hasFilter = next(selected or {}) ~= nil
    for _, container in ipairs(iterInventory()) do
        for _, inst in ipairs(container:GetChildren()) do
            if inst:IsA("Tool") then
                local attr = inst:GetAttribute(attrName)
                if attr ~= nil then
                    local name = tostring(attr)
                    if name ~= "" and (not hasFilter or _selectedMatch(selected, name)) then
                        found[#found + 1] = inst
                    end
                end
            end
        end
    end
    return found
end

local function stripToolUpgradeSuffix(name)
    return tostring(name or ""):gsub("%s+%+[%d]+$", ""):gsub("%s+$", "")
end

local function findToolForType(attrName, typeName)
    typeName = tostring(typeName or "")
    local want = stripToolUpgradeSuffix(typeName)
    local wantCanon = _canon(want)
    local bestExact, bestPrefix = nil, nil

    local function consider(tool, label)
        if not tool or not tool:IsA("Tool") then return end
        local labelCanon = _canon(stripToolUpgradeSuffix(label))
        if labelCanon == wantCanon then
            bestExact = tool
            return true
        end
        if not bestPrefix and labelCanon:sub(1, #wantCanon) == wantCanon then
            bestPrefix = tool
        elseif not bestPrefix and wantCanon:sub(1, #labelCanon) == labelCanon then
            bestPrefix = tool
        end
        return false
    end

    for _, container in ipairs(iterInventory()) do
        for _, inst in ipairs(container:GetChildren()) do
            if inst:IsA("Tool") then
                local attr = inst:GetAttribute(attrName)
                if attr ~= nil and consider(inst, tostring(attr)) then
                    return inst
                end
                if consider(inst, inst.Name) then
                    return inst
                end
            end
        end
    end
    return bestExact or bestPrefix
end

local function listSelectedToolKeys(selected)
    local keys = {}
    for key, on in pairs(selected or {}) do
        if on and key ~= "_none" then
            keys[#keys + 1] = tostring(key)
        end
    end
    table.sort(keys, function(a, b)
        return _canon(a) < _canon(b)
    end)
    return keys
end

local function _sprinklerExactMatch(a, b)
    if a == nil or b == nil then return false end
    return _canon(stripToolUpgradeSuffix(a)) == _canon(stripToolUpgradeSuffix(b))
end

local function findSprinklerToolExact(typeName)
    typeName = stripToolUpgradeSuffix(tostring(typeName or ""))
    if typeName == "" then return nil end
    local wantCanon = _canon(typeName)
    for _, container in ipairs(iterInventory()) do
        for _, inst in ipairs(container:GetChildren()) do
            if inst:IsA("Tool") then
                local attr = inst:GetAttribute("Sprinkler")
                if attr ~= nil then
                    local name = stripToolUpgradeSuffix(tostring(attr))
                    if name ~= "" and _canon(name) == wantCanon then
                        return inst
                    end
                end
            end
        end
    end
    return nil
end

local function listSelectedSprinklerTools(selected)
    local out, usedTools = {}, {}
    for _, typeKey in ipairs(listSelectedToolKeys(selected)) do
        local tool = findSprinklerToolExact(typeKey)
        if tool and not usedTools[tool] then
            usedTools[tool] = true
            local name = stripToolUpgradeSuffix(tostring(tool:GetAttribute("Sprinkler") or typeKey))
            out[#out + 1] = {
                typeKey = name,
                name = name,
                tool = tool,
            }
        end
    end
    return out
end

local function listSelectedToolsByType(attrName, selected)
    if attrName == "Sprinkler" then
        return listSelectedSprinklerTools(selected)
    end
    local out, usedTools = {}, {}
    for _, typeKey in ipairs(listSelectedToolKeys(selected)) do
        local tool = findToolForType(attrName, typeKey)
        if tool and not usedTools[tool] then
            usedTools[tool] = true
            out[#out + 1] = {
                typeKey = typeKey,
                name = tostring(tool:GetAttribute(attrName) or typeKey),
                tool = tool,
            }
        end
    end
    if #out == 0 and next(selected or {}) then
        for _, tool in ipairs(findToolsByAttr(attrName, selected)) do
            if not usedTools[tool] then
                usedTools[tool] = true
                local typeKey = tostring(tool:GetAttribute(attrName) or tool.Name)
                out[#out + 1] = {
                    typeKey = typeKey,
                    name = typeKey,
                    tool = tool,
                }
            end
        end
    end
    return out
end

local function refreshToolEntry(entry, attrName)
    if type(entry) ~= "table" then return nil end
    local tool
    if attrName == "Sprinkler" then
        tool = findSprinklerToolExact(entry.typeKey or entry.name)
    else
        tool = findToolForType(attrName, entry.typeKey or entry.name)
    end
    if tool then
        entry.tool = tool
        entry.name = tostring(tool:GetAttribute(attrName) or entry.typeKey or entry.name)
    end
    return entry.tool
end

local function getHumanoid()
    local ch = LP.Character
    if not ch then return nil end
    return ch:FindFirstChildOfClass("Humanoid")
end

-- Anti-burn GhostPepper (client penyiram): RemoveTag + EndBurn/StopLocalBurnEffects
local function getGhostPepperMod()
    if ST.ghostPepperMod ~= nil then
        return ST.ghostPepperMod ~= false and ST.ghostPepperMod or nil
    end

    local names = {
        "GhostPepper", "GhostPepperClient", "GhostPepperController",
        "GhostPepperEffects", "GhostPepperService",
    }
    local roots = {
        ReplicatedStorage:FindFirstChild("ClientModules"),
        ReplicatedStorage:FindFirstChild("Controllers"),
        ReplicatedStorage:FindFirstChild("Modules"),
        ReplicatedStorage:FindFirstChild("SharedModules"),
    }
    for _, root in ipairs(roots) do
        if root then
            for _, name in ipairs(names) do
                local inst = root:FindFirstChild(name, true)
                if inst and inst:IsA("ModuleScript") then
                    local ok, mod = pcall(require, inst)
                    if ok and type(mod) == "table"
                        and (type(mod.StopLocalBurnEffects) == "function" or type(mod.EndBurn) == "function") then
                        ST.ghostPepperMod = mod
                        return mod
                    end
                end
            end
        end
    end

    if type(getgc) == "function" then
        local okGc, found = pcall(function()
            for _, v in ipairs(getgc(true)) do
                if type(v) == "table"
                    and type(rawget(v, "StopLocalBurnEffects")) == "function"
                    and type(rawget(v, "StartLocalBurnEffects")) == "function" then
                    return v
                end
            end
            return nil
        end)
        if okGc and found then
            ST.ghostPepperMod = found
            return found
        end
    end

    ST.ghostPepperMod = false
    return nil
end

local function forceStopLocalBurn()
    local mod = getGhostPepperMod()
    if mod then
        if type(mod.EndBurn) == "function" then
            pcall(mod.EndBurn, mod, LP)
        elseif type(mod.StopLocalBurnEffects) == "function" then
            pcall(mod.StopLocalBurnEffects, mod)
        end
    end

    pcall(function()
        local char = LP.Character
        if not char then return end
        for _, v in ipairs(CollectionService:GetTagged("GhostPepperAppearance")) do
            if v:IsDescendantOf(char) then
                CollectionService:RemoveTag(v, "GhostPepperAppearance")
                if v:IsA("ParticleEmitter") then
                    v.Enabled = false
                end
            end
        end
    end)

    pcall(function()
        if not ensureNetworking() then return end
        local svc = Networking and Networking.GhostPepperService
        if svc and type(svc.TouchEnded) == "table" and type(svc.TouchEnded.Fire) == "function" and LP.Character then
            svc.TouchEnded:Fire(LP.Character)
        end
    end)
end

local function neutralizeGhostPepper(obj)
    if not obj then return end
    pcall(function()
        if CollectionService:HasTag(obj, "GhostPepper") then
            CollectionService:RemoveTag(obj, "GhostPepper")
        end
        if obj:IsA("BasePart") then
            obj.CanQuery = false
            obj.CanTouch = false
        end
    end)
end

local function sweepGhostPepperTags()
    for _, obj in ipairs(CollectionService:GetTagged("GhostPepper")) do
        neutralizeGhostPepper(obj)
    end
    forceStopLocalBurn()
end

local function stopGhostPepperBypass()
    ST.ghostPepperGen = (ST.ghostPepperGen or 0) + 1
    if ST.ghostPepperAddedConn then
        ST.ghostPepperAddedConn:Disconnect()
        ST.ghostPepperAddedConn = nil
    end
end

local function startGhostPepperBypass()
    stopGhostPepperBypass()
    ST.ghostPepperMod = nil
    forceStopLocalBurn()
    sweepGhostPepperTags()

    ST.ghostPepperAddedConn = CollectionService:GetInstanceAddedSignal("GhostPepper"):Connect(function(obj)
        if not ST.running then return end
        task.defer(function()
            if ST.running then
                neutralizeGhostPepper(obj)
                forceStopLocalBurn()
            end
        end)
    end)

    local gen = ST.ghostPepperGen
    task.spawn(function()
        while ST.running and ST.ghostPepperGen == gen do
            sweepGhostPepperTags()
            task.wait(1)
        end
    end)
end

-- Health lock ringan: blok TakeDamage + restore HP max 1x/detik (bukan tiap frame)
local function restoreHumanoidHealth(hum)
    if ST.healthLockRestoring or not hum or not hum.Parent or not ST.running then return end
    local maxH = hum.MaxHealth
    if maxH <= 0 or hum.Health >= maxH then return end
    local now = os.clock()
    if (now - (ST.healthLockLastRestore or 0)) < 1.0 then return end
    ST.healthLockLastRestore = now
    ST.healthLockRestoring = true
    pcall(function()
        hum.Health = maxH
    end)
    ST.healthLockRestoring = false
end

local function unbindHealthLockHumanoid()
    if ST.healthLockHumChanged then
        ST.healthLockHumChanged:Disconnect()
        ST.healthLockHumChanged = nil
    end
end

local function tryHookTakeDamage(hum)
    if ST.healthLockTakeHooked then return true end
    if type(hookfunction) ~= "function" or not hum then return false end
    local ok = pcall(function()
        local oldTake
        oldTake = hookfunction(hum.TakeDamage, function(self, ...)
            if ST.running then
                local my = getHumanoid()
                if my and self == my then
                    return
                end
            end
            return oldTake(self, ...)
        end)
    end)
    if ok then
        ST.healthLockTakeHooked = true
        return true
    end
    return false
end

local function bindHealthLockHumanoid(hum)
    unbindHealthLockHumanoid()
    if not hum then return end
    tryHookTakeDamage(hum)
    ST.healthLockHumChanged = hum.HealthChanged:Connect(function(h)
        if ST.healthLockRestoring or not ST.running then return end
        if h < hum.MaxHealth then
            restoreHumanoidHealth(hum)
        end
    end)
end

local function bindHealthLockCharacter(char)
    if not char then return end
    local hum = char:FindFirstChildOfClass("Humanoid")
    if not hum then
        hum = char:WaitForChild("Humanoid", 5)
        if hum and not hum:IsA("Humanoid") then hum = nil end
    end
    bindHealthLockHumanoid(hum)
end

local function stopHealthLock()
    if ST.healthLockCharAdded then
        ST.healthLockCharAdded:Disconnect()
        ST.healthLockCharAdded = nil
    end
    unbindHealthLockHumanoid()
    ST.healthLockRestoring = false
end

local function startHealthLock()
    stopHealthLock()
    ST.healthLockLastRestore = 0
    bindHealthLockCharacter(LP.Character)
    ST.healthLockCharAdded = LP.CharacterAdded:Connect(function(char)
        if not ST.running then return end
        task.defer(function()
            if ST.running then bindHealthLockCharacter(char) end
        end)
        armFlyAfterSpawn(char)
    end)
end

local function getHRP()
    local ch = LP.Character
    if not ch then return nil end
    local hrp = ch:FindFirstChild("HumanoidRootPart")
    return hrp and hrp:IsA("BasePart") and hrp or nil
end

local function getPlantTargetPos(ctx)
    ctx = ctx or ST.activeFlowCtx or ST.lastTargetCtx
    if not ctx then return nil end
    -- Plot hilang (DC) → jangan tampilkan jarak basi (bisa 8000st)
    if not ctx.plot or not ctx.plot.Parent then
        return nil
    end
    return refreshLivePlantPos(ctx)
end

local function getDistToPlantTarget(ctx)
    local hrp = getHRP()
    local plantPos = getPlantTargetPos(ctx)
    if not hrp or typeof(plantPos) ~= "Vector3" then
        return nil
    end
    return (hrp.Position - plantPos).Magnitude
end

refreshStatusDist = function()
    local base = ST.statusBase or ST.statusText or "Idle"
    if not isCharacterAlive() then
        ST.statusDistStuds = nil
        ST.statusText = base
        G.__GAG2_SW_OTHER_STATUS = base
        _G.__GAG2_SW_OTHER_STATUS = base
        return base
    end
    -- Hapus suffix lama biar tidak double
    base = tostring(base)
        :gsub("%s*·%s*under%s+%-?%d+%.?%d*%s*stud%s*%(flat%s+%-?%d+%.?%d*%)%s*$", "")
        :gsub("%s*·%s*%-?%d+%.?%d*%s*m%s*$", "")
        :gsub("%s*·%s*%-?%d+%.?%d*%s*studs?%s*$", "")
        :gsub("%s*·%s*harvest%s+%d+/%d+(?:%s*·%s*grow%s+%d+)?%s*$", "")
        :gsub("%s+$", "")

    local hrp = getHRP()
    local plantPos = getPlantTargetPos()
    local dist = nil
    if hrp and typeof(plantPos) == "Vector3" then
        dist = (hrp.Position - plantPos).Magnitude
    end
    ST.statusDistStuds = dist
    local msg = base
    -- Saat sudah under: jangan tampil 3D-ke-plant (~23 stud) — itu keliatan "belum sampai"
    if ST.atTarget and hrp and typeof(plantPos) == "Vector3" then
        local dy = hrp.Position.Y - plantPos.Y
        local dx = hrp.Position.X - plantPos.X
        local dz = hrp.Position.Z - plantPos.Z
        local flat = math.sqrt(dx * dx + dz * dz)
        msg = string.format("%s · under %.0f stud (flat %.0f)", base, dy, flat)
    elseif type(dist) == "number" and dist < 2500 then
        msg = string.format("%s · %.0f stud", base, dist)
    end
    if appendStatusExtras then
        msg = appendStatusExtras(msg) or msg
    end
    ST.statusText = msg
    G.__GAG2_SW_OTHER_STATUS = msg
    _G.__GAG2_SW_OTHER_STATUS = msg
    return msg
end

local function zeroRootVel()
    local hrp = getHRP()
    if not hrp then return end
    pcall(function()
        hrp.AssemblyLinearVelocity = Vector3.zero
        hrp.AssemblyAngularVelocity = Vector3.zero
    end)
end

local function flatDistToPos(a, b)
    if typeof(a) ~= "Vector3" or typeof(b) ~= "Vector3" then return math.huge end
    local dx, dz = a.X - b.X, a.Z - b.Z
    return math.sqrt(dx * dx + dz * dz)
end

local function _getFlyMod()
    return G.FlyNoclip or G.FlyNoclipModule or rawget(_G, "FlyNoclip")
end

local function stopFlyEngine()
    local F = _getFlyMod()
    if F and type(F.Stop) == "function" then
        pcall(F.Stop, F)
    end
end

local function setFlyNoclip(on)
    local F = _getFlyMod()
    if F and type(F.SetNoclip) == "function" then
        pcall(F.SetNoclip, F, on == true)
    end
end

-- Recovery / pindah tujuan: LockAt (CFrame + Anchored)
local function placeAt(pos)
    if typeof(pos) ~= "Vector3" then return false end
    local F = _getFlyMod()
    if not F then return false end
    if type(F.LockAt) == "function" then
        local ok = false
        pcall(function() ok = F.LockAt(pos) == true end)
        return ok
    end
    if type(F.PlaceAt) == "function" then
        local ok = false
        pcall(function() ok = F.PlaceAt(pos) == true end)
        return ok
    end
    return false
end

-- Lock fly+noclip di posisi sekarang / pinned.
local function holdFlyAtCurrent()
    if not isCharacterAlive() then return false end
    local hrp = getHRP()
    if not hrp then return false end
    local pos = ST.pinnedFlyGoal
    if typeof(pos) ~= "Vector3" then
        pos = hrp.Position
    end
    ST.pinnedFlyGoal = pos
    return placeAt(pos)
end

local function ensureFlyEngine()
    local F = _getFlyMod()
    if not F then return false end
    if type(F.IsLocked) == "function" and F.IsLocked() then
        return true
    end
    return holdFlyAtCurrent()
end

-- Restart = re-lock di pinned / posisi sekarang
local function hardRestartFly()
    local F = _getFlyMod()
    if not F then return false end
    local pos = ST.pinnedFlyGoal
    local hrp = getHRP()
    if typeof(pos) ~= "Vector3" and hrp then
        pos = hrp.Position
    end
    if typeof(pos) == "Vector3" then
        return placeAt(pos)
    end
    if type(F.HardRestart) == "function" then
        local ok = false
        pcall(function() ok = F.HardRestart(F) == true end)
        return ok
    end
    return false
end

local function isFreefalling()
    if ST.posMoveBusy then return false end
    local F = _getFlyMod()
    if F and type(F.IsLocked) == "function" and F.IsLocked() then
        return false
    end
    local hrp = getHRP()
    if not hrp then return false end
    if hrp.Anchored then return false end
    local vy = 0
    pcall(function() vy = hrp.AssemblyLinearVelocity.Y end)
    return vy < -90
end

local function flyReleaseMove()
    local F = _getFlyMod()
    if F and type(F.ReleaseForMove) == "function" then
        pcall(F.ReleaseForMove, F)
    end
end

-- Diam: kalau sudah ada pinned goal → LockAt; kalau belum → no-op (jangan noclip)
local function releaseAutoFly()
    if not isCharacterAlive() then return false end
    if typeof(ST.pinnedFlyGoal) == "Vector3" then
        return placeAt(ST.pinnedFlyGoal)
    end
    return true
end

-- Alias: stay = lock
local function stayAt(goalPos)
    if typeof(goalPos) == "Vector3" then
        ST.pinnedFlyGoal = goalPos
        return placeAt(goalPos)
    end
    return releaseAutoFly()
end

-- Pindah ke goal: LockAt langsung (bukan FlyTo BV)
local function moveTo(pos)
    if typeof(pos) ~= "Vector3" then return false end
    if not isCharacterAlive() then
        pauseMovementForDeath()
        return false
    end
    if ST.posMoveBusy then return false end
    ST.posMoveBusy = true
    ST.pinnedFlyGoal = pos
    local ok = placeAt(pos)
    ST.posMoveBusy = false
    return ok
end

-- Tunggu singkat; batalkan jika malam / workPaused
local function waitUnlessPaused(sec)
    sec = tonumber(sec) or 0
    if sec <= 0 then return end
    local t0 = os.clock()
    while ST.running and (os.clock() - t0) < sec do
        if isNightOrPreempt() or ST.workPaused then
            break
        end
        task.wait(CFG.RECOVER_POLL_SEC)
    end
end

local function clearApproachAnchor()
    ST.approachAnchor = nil
end

local function _getCharacterMod()
    return G.Character or rawget(_G, "Character")
end

local function _getAutoTeleMod()
    return G.AutoTele or G.AutoTeleModule or rawget(_G, "AutoTele")
end

local function _teleIsOn()
    local mod = _getAutoTeleMod()
    if type(mod) == "table" and type(mod.IsEnabled) == "function" then
        return mod.IsEnabled() == true
    end
    return false
end

local function _teleWasRunning()
    local mod = _getAutoTeleMod()
    if type(mod) == "table" and type(mod.IsRunning) == "function" then
        return mod.IsRunning() == true
    end
    return false
end

local function _teleStopForApproach()
    ST.teleWasOn = _teleIsOn() and _teleWasRunning()
    if not ST.teleWasOn then
        return
    end
    G.__GAG2_AUTO_TELE_SUPPRESS = true
    _G.__GAG2_AUTO_TELE_SUPPRESS = true
    local mod = _getAutoTeleMod()
    if type(mod) == "table" and type(mod.Stop) == "function" then
        pcall(mod.Stop, mod)
    end
end

local function _teleResumeAfterApproach()
    if not ST.teleWasOn then
        G.__GAG2_AUTO_TELE_SUPPRESS = false
        _G.__GAG2_AUTO_TELE_SUPPRESS = false
        return
    end
    ST.teleWasOn = false
    G.__GAG2_AUTO_TELE_SUPPRESS = false
    _G.__GAG2_AUTO_TELE_SUPPRESS = false
    local mod = _getAutoTeleMod()
    if type(mod) == "table" and type(mod.IsEnabled) == "function" and mod.IsEnabled() then
        if type(mod.Start) == "function" then
            pcall(mod.Start, mod)
        end
    end
end

local function pushClip()
    local Char = _getCharacterMod()
    if type(Char) ~= "table" then return end
    if ST.clipRestore == nil then
        if type(Char.IsClipEnabled) == "function" then
            ST.clipRestore = Char.IsClipEnabled() == true
        else
            ST.clipRestore = false
        end
    end
    if type(Char.SetClipEnabled) == "function" then
        pcall(Char.SetClipEnabled, Char, true)
    end
end

local function popClip()
    if ST.clipRestore == nil then return end
    local Char = _getCharacterMod()
    local restore = ST.clipRestore
    ST.clipRestore = nil
    if type(Char) == "table" and type(Char.SetClipEnabled) == "function" then
        pcall(Char.SetClipEnabled, Char, restore)
    end
end

local function resetApproachSession(keepFly)
    keepFly = (keepFly == true)
    ST.activeFlowCtx = nil
    if not keepFly then
        clearApproachAnchor()
        ST.approachSpawnUnder = nil
        ST.approachLockTarget = nil
        ST.approachSessionKey = nil
        ST.lastTargetCtx = nil
        ST.lockedTargetPlayer = nil
        ST.lockedPlotToken = nil
        ST.workPaused = false
        ST.atTarget = false
        ST.posMoveBusy = false
        ST.targetOfflineSince = nil
        local F = _getFlyMod()
        if F and type(F.ReleaseSettle) == "function" then
            pcall(F.ReleaseSettle, F)
        elseif F and type(F.ReleaseToSurface) == "function" then
            pcall(F.ReleaseToSurface, F)
        else
            setFlyNoclip(false)
            stopFlyEngine()
        end
        popClip()
        _teleResumeAfterApproach()
    end
end

local function getSprinklerNear(plot, pos, radius)
    local folder = plot and plot:FindFirstChild("Sprinklers")
    if not folder then return nil end
    radius = tonumber(radius) or 5
    for _, child in ipairs(folder:GetChildren()) do
        if child:IsA("Model") then
            local part = child.PrimaryPart or child:FindFirstChildWhichIsA("BasePart", true)
            if part and pos and (part.Position - pos).Magnitude <= radius then
                return child
            end
        end
    end
    return nil
end

local function getSprinklerTypeName(model)
    if not model then return nil end
    return tostring(
        model:GetAttribute("SprinklerName")
            or model:GetAttribute("Sprinkler")
            or model.Name
    )
end

local function listPlotSprinklers(plot)
    local out = {}
    local folder = plot and plot:FindFirstChild("Sprinklers")
    if not folder then return out end
    for _, inst in ipairs(folder:GetChildren()) do
        if inst:IsA("Model") then
            local part = inst.PrimaryPart or inst:FindFirstChildWhichIsA("BasePart", true)
            if part then
                out[#out + 1] = {
                    model = inst,
                    pos = part.Position,
                    name = getSprinklerTypeName(inst),
                }
            end
        end
    end
    return out
end

local function getPlotSprinklersCached(plot)
    if not plot then return {} end
    if ST.sprinklerCachePlot == plot and ST.sprinklerCacheList
        and (os.clock() - ST.sprinklerCacheAt) < CFG.SPRINKLER_CACHE_TTL_SEC then
        return ST.sprinklerCacheList
    end
    local list = listPlotSprinklers(plot)
    ST.sprinklerCachePlot = plot
    ST.sprinklerCacheList = list
    ST.sprinklerCacheAt = os.clock()
    return list
end

local function invalidateSprinklerCache()
    ST.sprinklerCachePlot = nil
    ST.sprinklerCacheList = nil
    ST.sprinklerCacheAt = 0
end

local function findSprinklerTypeNearPlant(plot, basePos, typeName, radius)
    if not plot or not basePos or not typeName then return nil end
    radius = tonumber(radius) or CFG.PLANT_SPRINKLER_MATCH_RADIUS
    local r2 = radius * radius
    for _, s in ipairs(listPlotSprinklers(plot)) do
        if s.pos and s.name and _sprinklerExactMatch(s.name, typeName) then
            local dx = s.pos.X - basePos.X
            local dz = s.pos.Z - basePos.Z
            if (dx * dx + dz * dz) <= r2 then
                return s
            end
        end
    end
    return nil
end

local function sprinklerStillActive(plot, pos, trackedInst)
    if trackedInst and trackedInst.Parent then
        local part = trackedInst.PrimaryPart or trackedInst:FindFirstChildWhichIsA("BasePart", true)
        if part and pos and (part.Position - pos).Magnitude <= (CFG.PLANT_SPRINKLER_MATCH_RADIUS + 2) then
            return true
        end
    end
    invalidateSprinklerCache()
    return getSprinklerNear(plot, pos, CFG.PLANT_SPRINKLER_MATCH_RADIUS + 2) ~= nil
end

local function computePlaceOffsetPos(basePos, slotIndex)
    slotIndex = math.max(1, math.floor(tonumber(slotIndex) or 1))
    local angle = (slotIndex - 1) * (math.pi * 2 / 10)
    local dist = CFG.PLACE_OFFSET_MIN + ((slotIndex - 1) % 3) * ((CFG.PLACE_OFFSET_MAX - CFG.PLACE_OFFSET_MIN) / 2)
    return basePos + Vector3.new(math.cos(angle) * dist, 0.2, math.sin(angle) * dist)
end

local function findFreePlacePos(plot, basePos, slotIndex)
    local existing = getPlotSprinklersCached(plot)
    for attempt = 0, 11 do
        local pos = computePlaceOffsetPos(basePos, slotIndex + attempt)
        local blocked = false
        for _, s in ipairs(existing) do
            if s.pos and (s.pos - pos).Magnitude < CFG.PLACE_MATCH_RADIUS then
                blocked = true
                break
            end
        end
        if not blocked then
            return pos
        end
    end
    return computePlaceOffsetPos(basePos, slotIndex)
end

local function ensureEquippedLight(tool, waitSec)
    if not tool or not tool:IsA("Tool") then return false, tool end
    local char = LP.Character
    if not char then return false, tool end
    if tool.Parent == char then return true, tool end
    local hum = char:FindFirstChildOfClass("Humanoid")
    if not hum then return false, tool end
    stayAt(nil)
    pcall(function() hum:EquipTool(tool) end)
    local deadline = os.clock() + (waitSec or CFG.EQUIP_WAIT_SEC)
    while os.clock() < deadline do
        pcall(function()
            hum.PlatformStand = true
            hum.Sit = false
        end)
        ensureFlyEngine()
        stayAt(nil)
        if tool.Parent == char then
            local eq = char:FindFirstChild(tool.Name)
            stayAt(nil)
            if eq and eq:IsA("Tool") then
                return true, eq
            end
            return true, tool
        end
        pcall(function() hum:EquipTool(tool) end)
        task.wait(0.05)
    end
    stayAt(nil)
    return tool.Parent == char, tool
end

local function ensureEquipped(tool, waitSec)
    if not tool or not tool:IsA("Tool") then return false, tool end
    local char = LP.Character
    if not char then return false, tool end
    if tool.Parent == char then
        return true, tool
    end
    local hum = char:FindFirstChildOfClass("Humanoid")
    if not hum then return false, tool end
    stayAt(nil)
    local deadline = os.clock() + (waitSec or CFG.EQUIP_WAIT_SEC)
    while os.clock() < deadline do
        pcall(function()
            hum.PlatformStand = true
            hum.Sit = false
        end)
        ensureFlyEngine()
        stayAt(nil)
        if tool.Parent == char then
            local eq = char:FindFirstChild(tool.Name)
            stayAt(nil)
            if eq and eq:IsA("Tool") then
                return true, eq
            end
            return true, tool
        end
        pcall(function() hum:EquipTool(tool) end)
        task.wait(0.05)
    end
    stayAt(nil)
    return tool.Parent == char, tool
end

local function unequipTool(tool)
    local char = LP.Character
    if not char then return end
    local hum = char:FindFirstChildOfClass("Humanoid")
    if not hum then return end
    if tool and tool:IsA("Tool") and tool.Parent == char then
        pcall(function() hum:UnequipTools() end)
    end
    pcall(function()
        hum.PlatformStand = true
        hum.Sit = false
    end)
    ensureFlyEngine()
    stayAt(nil)
end

local function toolHasWaterHandle(tool)
    if not tool or not tool:IsA("Tool") then return false end
    for _, child in ipairs(tool:GetChildren()) do
        if child.Name == "Handle" then return true end
    end
    return false
end

local function ensureWateringCanEquipped(tool, waitSec)
    waitSec = tonumber(waitSec) or CFG.EQUIP_WAIT_SEC
    local ok, useTool = ensureEquipped(tool, waitSec)
    if not ok or not useTool then return false, useTool end
    tool = useTool
    local deadline = os.clock() + math.max(waitSec, CFG.WATER_HANDLE_WAIT_SEC)
    while os.clock() < deadline do
        if toolHasWaterHandle(tool) then return true, tool end
        if tool.Parent ~= LP.Character then break end
        task.wait(0.1)
    end
    return tool.Parent == LP.Character, tool
end

local function _unwrapRemoteEvent(remote)
    if typeof(remote) == "Instance" then
        if remote:IsA("RemoteEvent") or remote:IsA("RemoteFunction") then return remote end
        return remote:FindFirstChildWhichIsA("RemoteEvent", true)
            or remote:FindFirstChildWhichIsA("RemoteFunction", true)
    end
    if type(remote) ~= "table" then return nil end
    for _, key in ipairs({ "Remote", "_remote", "remote", "Event", "_event" }) do
        local inner = remote[key]
        if inner then
            local found = _unwrapRemoteEvent(inner)
            if found then return found end
        end
    end
    return nil
end

local function callPlaceRemote(remote, pos, sprinklerName, tool, plotId)
    if type(remote) ~= "table" and typeof(remote) ~= "Instance" then return false end
    local function try(fn) return pcall(fn) end
    if type(remote.Fire) == "function" then
        if try(function() remote:Fire(pos, sprinklerName, tool, plotId) end) then return true end
        if try(function() remote:Fire(pos, sprinklerName, tool) end) then return true end
    end
    local re = _unwrapRemoteEvent(remote)
    if re and re:IsA("RemoteEvent") then
        if try(function() re:FireServer(pos, sprinklerName, tool, plotId) end) then return true end
        if try(function() re:FireServer(pos, sprinklerName, tool) end) then return true end
    end
    return false
end

local function snapshotSprinklerKeys(plot)
    local keys, count = {}, 0
    local folder = plot and plot:FindFirstChild("Sprinklers")
    if folder then
        for _, child in ipairs(folder:GetChildren()) do
            if child:IsA("Model") then
                count += 1
                local sid = child:GetAttribute("SprinklerId")
                keys[sid ~= nil and tostring(sid) or child.Name] = true
            end
        end
    end
    return keys, count
end

local function sprinklerPlaced(plot, pos, beforeKeys, beforeCount, typeName)
    if not plot then return false end

    local folder = plot:FindFirstChild("Sprinklers")
    if folder then
        for _, child in ipairs(folder:GetChildren()) do
            if child:IsA("Model") then
                local sid = child:GetAttribute("SprinklerId")
                local key = sid ~= nil and tostring(sid) or child.Name
                if not beforeKeys[key] then
                    local part = child.PrimaryPart or child:FindFirstChildWhichIsA("BasePart", true)
                    if part and pos and (part.Position - pos).Magnitude <= CFG.PLACE_MATCH_RADIUS then
                        if not typeName or _sprinklerExactMatch(getSprinklerTypeName(child), typeName) then
                            return true
                        end
                    end
                end
            end
        end
    end

    local nowCount = 0
    if folder then
        for _, child in ipairs(folder:GetChildren()) do
            if child:IsA("Model") then nowCount += 1 end
        end
    end
    return nowCount > (tonumber(beforeCount) or 0)
end

local function placeSprinklerOnPlot(plot, plotId, pos, tool, typeName)
    if not ensureNetworking() or not PlaceSprinkler then return false, nil, "no_remote" end
    if not tool or not tool.Parent then return false, nil, "no_sprinkler" end
    if os.clock() - ST.lastPlaceAt < CFG.PLACE_COOLDOWN then
        task.wait(CFG.PLACE_COOLDOWN)
    end

    local attr = tool:GetAttribute("Sprinkler")
    if attr == nil then return false, nil, "no_sprinkler" end
    attr = tostring(attr)
    typeName = typeName or attr
    if not _sprinklerExactMatch(attr, typeName) then
        return false, nil, "wrong_tool"
    end

    stayAt(nil)
    local okEq, useTool = ensureEquippedLight(tool, CFG.EQUIP_WAIT_SEC)
    stayAt(nil)
    if not okEq then
        return false, nil, "no_sprinkler"
    end
    tool = useTool
    task.wait(0.12)
    stayAt(nil)

    typeName = typeName or attr
    local beforeKeys, beforeCount = snapshotSprinklerKeys(plot)

    local function waitPlaced()
        local deadline = os.clock() + CFG.PLACE_CONFIRM_SEC
        while os.clock() < deadline do
            if not ST.running then return false end
            stayAt(nil)
            if sprinklerPlaced(plot, pos, beforeKeys, beforeCount, typeName) then
                return true
            end
            task.wait(0.1)
        end
        return false
    end

    local placed = false
    if callPlaceRemote(PlaceSprinkler, pos, attr, tool, plotId) and waitPlaced() then
        placed = true
    elseif tool.Name ~= attr
        and callPlaceRemote(PlaceSprinkler, pos, tool.Name, tool, plotId)
        and waitPlaced() then
        placed = true
    end

    unequipTool(tool)
    stayAt(nil)
    invalidateSprinklerCache()

    if placed then
        ST.lastPlaceAt = os.clock()
        return true, getSprinklerNear(plot, pos, CFG.PLACE_MATCH_RADIUS + 0.5), "placed"
    end
    return false, nil, "place_fail"
end

local function bindFxListener(firePos, canName)
    ST.fxHit = false
    if ST.fxConn then ST.fxConn:Disconnect(); ST.fxConn = nil end
    if not (WateringCanFx and WateringCanFx.OnClientEvent) then return end
    ST.fxConn = WateringCanFx.OnClientEvent:Connect(function(fxPos, fxCan, player)
        if player ~= LP or tostring(fxCan) ~= tostring(canName) then return end
        if typeof(fxPos) == "Vector3" and (fxPos - firePos).Magnitude <= CFG.FX_RADIUS then
            ST.fxHit = true
        end
    end)
end

local function snapshotPlantAttrs(plant)
    local out = {}
    if not plant then return out end
    for name, val in pairs(plant:GetAttributes()) do
        out[name] = val
    end
    return out
end

local function attrsChanged(before, after)
    for k, v in pairs(after) do
        if before[k] ~= v then return true end
    end
    for k, v in pairs(before) do
        if after[k] ~= v then return true end
    end
    return false
end

local function waitWaterSuccess(firePos, canName, attrsBefore, plant)
    local t0 = os.clock()
    while (os.clock() - t0) < CFG.FX_WAIT_SEC do
        if not ST.running then return false end
        if ST.fxHit then return true end
        if attrsChanged(attrsBefore, snapshotPlantAttrs(plant)) then return true end
        task.wait(0.1)
    end
    return false
end

local function waterPlantWithTool(plot, target, tool, groundPos)
    if not ensureNetworking() or not UseWateringCan or type(UseWateringCan.Fire) ~= "function" then
        return false, "no_remote"
    end
    if not tool or not tool:IsA("Tool") then
        return false, "no_can"
    end

    groundPos = groundPos or snapToPlantArea(plot, target.pos)
    if not groundPos then return false, "water_fail" end

    local firePos = groundPos - Vector3.new(0, CFG.WATER_Y_OFFSET, 0)
    local canName = tostring(tool:GetAttribute("WateringCan") or tool.Name)
    bindFxListener(firePos, canName)

    for attempt = 1, CFG.MAX_WATER_ATTEMPTS do
        if not ST.running then return false, "stopped" end

        local eqOk, useTool = ensureWateringCanEquipped(tool, CFG.EQUIP_WAIT_SEC)
        if eqOk then
            tool = useTool
            local attrsBefore = snapshotPlantAttrs(target.plant)
            local actualCanName = tostring(tool:GetAttribute("WateringCan") or canName)
            ST.fxHit = false
            waitUnlessPaused(0.15)
            UseWateringCan:Fire(firePos, actualCanName, tool)
            waitUnlessPaused(0.25)
            if waitWaterSuccess(firePos, actualCanName, attrsBefore, target.plant) then
                ST.lastWaterAt = os.clock()
                unequipTool(tool)
                return true, "done"
            end
            unequipTool(tool)
        end

        if attempt >= CFG.MAX_WATER_ATTEMPTS then
            break
        end
        waitUnlessPaused(CFG.WATER_COOLDOWN)
    end

    return false, "water_fail"
end

local LOCK_SPR = "sprinkler"
local LOCK_WAT = "water"

local function acquireActionLock(owner, maxWait)
    maxWait = tonumber(maxWait) or 60
    owner = tostring(owner or "unknown")
    local t0 = os.clock()
    while ST.actionLock and ST.running and (os.clock() - t0) < maxWait do
        task.wait(0.1)
    end
    if ST.actionLock then return false end
    ST.actionLock = true
    ST.actionLockOwner = owner
    return true
end

local function releaseActionLock(owner)
    if ST.actionLock and owner and ST.actionLockOwner ~= owner then
        return
    end
    ST.actionLock = false
    ST.actionLockOwner = nil
end

local function releaseActionLockForWait(owner)
    releaseActionLock(owner)
end

local function reacquireActionLock(owner, maxWait)
    return acquireActionLock(owner, maxWait or 90)
end

local function finishFlowSession(owner)
    if owner == LOCK_SPR then
        ST.sprCycleBusy = false
    elseif owner == LOCK_WAT then
        ST.waterCycleBusy = false
    end
    releaseActionLock(owner)
    if not ST.sprCycleBusy and not ST.waterCycleBusy then
        ST.activeFlowCtx = nil
    end
end

local function _pauseOtherModules()
    for _, name in ipairs({ "AutoSprinkler", "AutoWatering" }) do
        local mod = G[name] or rawget(_G, name)
        if type(mod) == "table" and type(mod.Stop) == "function" then
            pcall(mod.Stop, mod)
        end
    end
end

local function pickTargetForFlow(cfg, plotIndex, plantIndex)
    local playerNames = listSelectedPlayerNames(cfg)
    if #playerNames == 0 then return nil, "no_plot" end
    if not next(cfg.target_plants) then return nil, "no_plants" end

    plotIndex = (plotIndex % #playerNames) + 1
    local playerName = playerNames[plotIndex]
    local plot = findPlotForUsername(playerName)
    if not plot then
        plot = findPlotByKey(playerName)
    end
    if not plot then return nil, "no_plot", plotIndex, plantIndex end

    local plotId = resolveTargetPlotId(plot)
    if not plotId then return nil, "no_plot", plotIndex, plantIndex end

    plantIndex += 1
    local target = pickSingleTarget(plot, cfg.target_plants, plantIndex)
    if not target then return nil, "no_targets", plotIndex, plantIndex end

    return {
        playerName = playerName,
        plotKey = tostring(plot.Name),
        plot = plot,
        plotId = plotId,
        target = target,
        groundPos = snapToPlantArea(plot, target.pos) or target.pos,
        plotIndex = plotIndex,
        plantIndex = plantIndex,
    }, nil, plotIndex, plantIndex
end

local function getUnderGoalPos(ctx)
    if not ctx then return nil end
    refreshLivePlantPos(ctx)
    local s = ctx.groundPos
    if typeof(s) ~= "Vector3" then return nil end
    return Vector3.new(s.X, s.Y + getVerticalOffsetY(), s.Z)
end

local function getNightGoalPos(ctx)
    if not ctx then return nil end
    refreshLivePlantPos(ctx)
    local s = ctx.groundPos
    if typeof(s) ~= "Vector3" then return nil end
    return Vector3.new(
        s.X + CFG.PLANT_HORIZONTAL_OFFSET,
        s.Y + getVerticalOffsetY(),
        s.Z
    )
end

local function flatDistToPlant(ctx)
    local hrp = getHRP()
    if not hrp or not ctx then return nil end
    refreshLivePlantPos(ctx)
    local s = ctx.groundPos
    if typeof(s) ~= "Vector3" then return nil end
    local dx, dz = hrp.Position.X - s.X, hrp.Position.Z - s.Z
    return math.sqrt(dx * dx + dz * dz)
end

local function distToPos(pos)
    local hrp = getHRP()
    if not hrp or typeof(pos) ~= "Vector3" then return nil end
    return (hrp.Position - pos).Magnitude
end

-- Under goal: flat + Y terpisah (lebih stabil dari Magnitude 3D ketat)
local function nearGoal(pos, radius)
    local hrp = getHRP()
    if not hrp or typeof(pos) ~= "Vector3" then return false end
    local r = tonumber(radius) or CFG.FLY_ARRIVE_RADIUS
    local flat = flatDistToPos(hrp.Position, pos)
    local dy = math.abs(hrp.Position.Y - pos.Y)
    return flat <= r and dy <= (r + 6)
end

-- Target shared: reuse lastTargetCtx kalau plant masih ada; else pick baru (index pos terpisah)
local function ensureSharedTarget(cfg)
    cfg = cfg or getCfg()
    if ST.lastTargetCtx and ST.lastTargetCtx.plot and ST.lastTargetCtx.plot.Parent then
        local plant = ST.lastTargetCtx.target and ST.lastTargetCtx.target.plant
        if plant and plant.Parent then
            refreshLivePlantPos(ST.lastTargetCtx)
            if typeof(ST.lastTargetCtx.groundPos) == "Vector3" then
                return ST.lastTargetCtx
            end
        end
    end
    local ctx, err, pIdx, plIdx = pickTargetForFlow(cfg, ST.posPlotIndex or 0, ST.posPlantIndex or 0)
    if ctx then
        ST.posPlotIndex = pIdx
        ST.posPlantIndex = plIdx
        ST.lastTargetCtx = ctx
        return ctx
    end
    return nil, err
end

local function publishPosStatus(detail)
    local key = tostring(ST.statusKey or "")
    if key == "placing" or key == "watering" or key == "waiting_water"
        or key == "waiting_sprinkler" or key == "done" or key == "rollback"
        or key == "fruit_pause" then
        if refreshStatusDist then
            refreshStatusDist()
        end
        return
    end

    local phase, rem = getWeather()
    local remStr = (rem ~= nil) and string.format("%.0fs", rem) or nil
    local d = tostring(detail or "")

    if isNightOrPreempt() or ST.workPaused then
        -- Satu status malam saja (jangan "Paused (night) · Night … · paused ok")
        local quiet = (d == "" or d == "paused ok" or d == "paused +70" or d == "ready"
            or d == "ready · day" or d == "day resume")
        if quiet then
            _publish("night_pause", remStr)
        elseif remStr then
            _publish("night_pause", d .. " · " .. remStr)
        else
            _publish("night_pause", d)
        end
        return
    end

    local w = tostring(phase or "?")
    if remStr then
        w = w .. " " .. remStr
    end
    if d ~= "" then
        _publish("idle", w .. " · " .. d)
    else
        _publish("idle", w)
    end
end

-- LOOP POSISI — FlyTo saja; kalau sudah di target, lepas auto biar karakter bebas gerak
local function positionMainLoop(myId)
    local wasNight = false

    while ST.running and ST.posLoopId == myId do
        local cfg = getCfg()
        if not (cfg and cfg.enabled) then
            ST.workPaused = false
            ST.atTarget = false
            task.wait(CFG.LOOP_MIN_SEC)
            continue
        end

        if not isCharacterAlive() then
            pauseMovementForDeath()
            wasNight = false
            ST.pinnedFlyGoal = nil
            _publish("dead", "wait respawn")
            task.wait(0.5)
            continue
        end

        ensureFlyEngine()

        -- Freefall watchdog (sering abis night di HP)
        if isFreefalling() then
            local ctxFall = ensureSharedTarget(cfg)
            local recover = nil
            if ctxFall then
                recover = getUnderGoalPos(ctxFall)
            end
            recover = recover or ST.pinnedFlyGoal
            if typeof(recover) == "Vector3" then
                publishPosStatus("recover freefall")
                placeAt(recover)
                ST.pinnedFlyGoal = recover
                ST.atTarget = not isNightOrPreempt()
                task.wait(0.2)
                continue
            else
                hardRestartFly()
            end
        end

        local ctx = ensureSharedTarget(cfg)
        if not ctx or not ctx.plot or not ctx.plot.Parent then
            ST.atTarget = false
            ST.workPaused = isNightOrPreempt()
            -- Tetap hold fly selama tunggu target (jangan lepas → freefall mati)
            ensureFlyEngine()
            publishPosStatus("no target")
            task.wait(CFG.POSITION_POLL_SEC)
            continue
        end

        local night = isNightOrPreempt()
        local flat = flatDistToPlant(ctx) or math.huge

        if night then
            ST.workPaused = true
            ST.atTarget = false
            wasNight = true
            if flat >= CFG.PLANT_HORIZONTAL_OFFSET then
                releaseAutoFly()
                publishPosStatus("paused ok")
            else
                local goal = getNightGoalPos(ctx)
                if typeof(goal) == "Vector3" then
                    if not nearGoal(goal, CFG.FLY_ARRIVE_RADIUS) then
                        publishPosStatus("move +70")
                        moveTo(goal)
                        ST.pinnedFlyGoal = goal
                    else
                        ST.pinnedFlyGoal = goal
                        releaseAutoFly()
                        publishPosStatus("paused +70")
                    end
                else
                    releaseAutoFly()
                    publishPosStatus("paused · no goal")
                end
            end
            task.wait(CFG.POSITION_POLL_SEC)
            continue
        end

        -- Day setelah night: JANGAN FlyTo pelan (HP freefall). Restart fly + snap under sekali.
        if wasNight then
            wasNight = false
            ST.workPaused = false
            publishPosStatus("day resume")
            local under = getUnderGoalPos(ctx)
            if typeof(under) == "Vector3" then
                placeAt(under)
                ST.pinnedFlyGoal = under
                ST.atTarget = true
                publishPosStatus("ready · day")
            else
                hardRestartFly()
                ST.atTarget = false
            end
            task.wait(0.3)
            if not ST.running or ST.posLoopId ~= myId then break end
            if isNightOrPreempt() then continue end
            task.wait(CFG.POSITION_POLL_SEC)
            continue
        end

        ST.workPaused = false
        local under = getUnderGoalPos(ctx)
        if typeof(under) ~= "Vector3" then
            ST.atTarget = false
            releaseAutoFly()
            publishPosStatus("plot loading")
            task.wait(CFG.POSITION_POLL_SEC)
            continue
        end

        local arrive = CFG.FLY_ARRIVE_RADIUS
        local leave = CFG.FLY_LEAVE_RADIUS or (arrive * 2.5)
        local d = distToPos(under) or math.huge

        -- Hysteresis: sekali ready, jangan "move under" lagi sebelum benar-benar jauh
        if ST.atTarget and nearGoal(under, leave) then
            ST.pinnedFlyGoal = under
            releaseAutoFly()
            publishPosStatus("ready")
            task.wait(CFG.POSITION_POLL_SEC)
            continue
        end

        if nearGoal(under, arrive) then
            ST.atTarget = true
            ST.pinnedFlyGoal = under
            releaseAutoFly()
            publishPosStatus("ready")
        else
            ST.atTarget = false
            publishPosStatus("move under")
            moveTo(under)
            ST.pinnedFlyGoal = under
            ST.atTarget = nearGoal(under, arrive + 4)
            releaseAutoFly()
            if ST.atTarget then
                publishPosStatus("ready")
            elseif isFreefalling() then
                placeAt(under)
                ST.atTarget = true
                publishPosStatus("ready · recover")
            end
        end

        task.wait(CFG.POSITION_POLL_SEC)
    end
end

local function isAnyTargetOnline(cfg)
    for _, name in ipairs(listSelectedPlayerNames(cfg)) do
        if findPlayerByUsername(name) then
            return true
        end
    end
    return false
end

-- Hitung buah siap harvest — sama logic script CheckFruit (Age >= MaxAge).
local function fruitTypeName(fruit, plant)
    if not fruit then return "" end
    local n = fruit:GetAttribute("CorePartName")
        or fruit:GetAttribute("FruitName")
        or fruit:GetAttribute("SeedName")
        or (plant and (plant:GetAttribute("CorePartName") or plant:GetAttribute("SeedName")))
    if type(n) == "string" and n ~= "" then
        return n
    end
    local key = resolvePlantTypeName(plant)
    if key ~= "" then return key end
    return ""
end

local function fruitMatchesSelected(fruit, plant, selectedPlants)
    if type(selectedPlants) ~= "table" or not next(selectedPlants) then
        return true -- no filter → semua buah
    end
    local n = fruitTypeName(fruit, plant)
    if n ~= "" and _selectedMatch(selectedPlants, n) then
        return true
    end
    local key = resolvePlantTypeName(plant)
    if key ~= "" and _selectedMatch(selectedPlants, key) then
        return true
    end
    return false
end

local function countHarvestableOnPlot(plot, selectedPlants)
    local function scan(filter)
        local ready = 0
        local plants = plot:FindFirstChild("Plants")
        if not plants then return 0 end
        for _, plant in ipairs(plants:GetChildren()) do
            local fruits = plant:FindFirstChild("Fruits")
            if fruits then
                for _, fruit in ipairs(fruits:GetChildren()) do
                    if fruit:IsA("Model") or fruit:IsA("BasePart") then
                        if fruitMatchesSelected(fruit, plant, filter) then
                            local age = tonumber(fruit:GetAttribute("Age")) or 0
                            local maxAge = tonumber(fruit:GetAttribute("MaxAge")) or 0
                            if maxAge <= 0 then maxAge = 1 end
                            if age >= maxAge then
                                ready += 1
                            end
                        end
                    end
                end
            end
        end
        return ready
    end

    if not plot then return 0 end
    local ready = scan(selectedPlants)
    -- Kalau filter tipe plant tidak match sama sekali, fallback scan semua (sama CheckFruit).
    if ready == 0 and type(selectedPlants) == "table" and next(selectedPlants) then
        local any = false
        local plants = plot:FindFirstChild("Plants")
        if plants then
            for _, plant in ipairs(plants:GetChildren()) do
                local fruits = plant:FindFirstChild("Fruits")
                if fruits then
                    for _, fruit in ipairs(fruits:GetChildren()) do
                        if (fruit:IsA("Model") or fruit:IsA("BasePart"))
                            and fruitMatchesSelected(fruit, plant, selectedPlants) then
                            any = true
                            break
                        end
                    end
                end
                if any then break end
            end
        end
        if not any then
            ready = scan(nil)
        end
    end
    return ready
end

local function resolveHarvestPlot(cfg, ctx)
    ctx = ctx or ST.activeFlowCtx or ST.lastTargetCtx
    if ctx and ctx.plot and ctx.plot.Parent then
        return ctx.plot, ctx
    end
    if type(cfg) ~= "table" then return nil, nil end
    for _, name in ipairs(listSelectedPlayerNames(cfg)) do
        local plot = findPlotForUsername(name)
        if plot and plot.Parent then
            return plot, ctx
        end
    end
    return nil, ctx
end

-- Gate pause aksi: target online + dekat posisi kerja.
local function canScanHarvestableFruits(cfg, ctx)
    if not cfg or clampStopCollectMax(cfg.stop_collect_max) <= 0 then
        return false
    end
    if not isAnyTargetOnline(cfg) then
        return false
    end
    local plot
    plot, ctx = resolveHarvestPlot(cfg, ctx)
    if not plot then
        return false
    end
    if ST.atTarget == true then
        return true
    end
    local dist = getDistToPlantTarget(ctx)
    if type(dist) == "number" and dist <= (CFG.FRUIT_SCAN_DIST_STUDS + 8) then
        return true
    end
    if ctx then
        local flat = flatDistToPlant(ctx)
        if type(flat) == "number" and flat <= (CFG.FLY_ARRIVE_RADIUS + 4) then
            return true
        end
    end
    local hrp = getHRP()
    if hrp then
        local ok, piv = pcall(function() return plot:GetPivot().Position end)
        if ok and typeof(piv) == "Vector3" then
            local dx = hrp.Position.X - piv.X
            local dz = hrp.Position.Z - piv.Z
            if math.sqrt(dx * dx + dz * dz) <= 120 then
                return true
            end
        end
    end
    return false
end

local function getHarvestableCountCached(cfg, ctx, force)
    local plot = resolveHarvestPlot(cfg, ctx)
    if not plot then
        return 0
    end
    local now = os.clock()
    if not force
        and ST.harvestScanCachePlot == plot
        and (now - (ST.harvestScanCacheAt or 0)) <= CFG.FRUIT_SCAN_CACHE_SEC
    then
        return ST.harvestScanCacheCount or 0
    end
    local ready = countHarvestableOnPlot(plot, cfg and cfg.target_plants)
    ST.harvestScanCachePlot = plot
    ST.harvestScanCacheAt = now
    ST.harvestScanCacheCount = ready
    ST.harvestPauseCount = ready
    return ready
end

-- true = pause sprinkler+watering sampai jumlah turun lagi.
local function shouldPauseForHarvestable(cfg, ctx)
    local maxN = clampStopCollectMax(cfg and cfg.stop_collect_max)
    if maxN <= 0 then
        ST.harvestPauseCount = 0
        return false, 0, maxN
    end
    if not canScanHarvestableFruits(cfg, ctx) then
        return false, ST.harvestPauseCount or 0, maxN
    end
    local n = getHarvestableCountCached(cfg, ctx, false)
    return n >= maxN, n, maxN
end

-- Status: harvest saja (selalu scan kalau target online + plot ketemu).
appendStatusExtras = function(msg)
    msg = tostring(msg or "")
    msg = msg
        :gsub("%s*·%s*harvest%s+%d+/%d+(?:%s*·%s*grow%s+%d+)?%s*$", "")
        :gsub("%s+$", "")
    local cfg = getCfg()
    local maxN = clampStopCollectMax(cfg and cfg.stop_collect_max)
    if maxN <= 0 then
        return msg
    end

    local ready = ST.harvestPauseCount or 0
    if isAnyTargetOnline(cfg) then
        local plot = resolveHarvestPlot(cfg, nil)
        if plot then
            ready = countHarvestableOnPlot(plot, cfg.target_plants)
            ST.harvestPauseCount = ready
            ST.harvestScanCachePlot = plot
            ST.harvestScanCacheAt = os.clock()
            ST.harvestScanCacheCount = ready
        end
    end

    ready = math.floor(tonumber(ready) or 0)
    return string.format("%s · harvest %d/%d", msg, ready, maxN)
end

local function tickTargetOfflineWatch(cfg)
    if not cfg or not cfg.enabled then
        return false
    end
    if #listSelectedPlayerNames(cfg) == 0 then
        ST.targetOfflineSince = nil
        return false
    end

    -- Plot target hancur (DC) → buang ctx basi biar tidak stuck / jarak 8000st
    if ST.lastTargetCtx and (not ST.lastTargetCtx.plot or not ST.lastTargetCtx.plot.Parent) then
        ST.lastTargetCtx = nil
        clearStaleTargetState()
    end

    if isAnyTargetOnline(cfg) then
        ST.targetOfflineSince = nil
        return false
    end

    local now = os.clock()
    if not ST.targetOfflineSince then
        ST.targetOfflineSince = now
        _publish("wait_ready", "target offline")
        return false
    end

    local left = CFG.TARGET_OFFLINE_REJOIN_SEC - (now - ST.targetOfflineSince)
    if left > 0 then
        _publish("wait_ready", string.format("target offline %.0fs", left))
        return false
    end

    ST.targetOfflineSince = nil
    _publish("wait_ready", "target offline")
    return false
end

local function holdAtTargetWhileWaiting(cfg, ctx, statusKey, detail)
    ctx = ctx or ST.lastTargetCtx
    if not ctx or not ctx.plot or not ctx.plot.Parent then
        tickTargetOfflineWatch(cfg)
        return false
    end
    ST.lastTargetCtx = ctx
    _publish(statusKey, detail or "hold")
    tickTargetOfflineWatch(cfg)
    return true
end

local function runSprinklerFlow(cfg)
    if ST.sprCycleBusy then return false end
    if next(cfg.sprinklers or {}) == nil then return false end
    applyPositionMode(cfg)

    _publish("idle", "sprinkler scan")
    tickTargetOfflineWatch(cfg)

    if not _ensureSessionReady(CFG.SESSION_READY_MAX_WAIT_SEC) then
        _publish("wait_ready", "timeout")
        if ST.lastTargetCtx then
            holdAtTargetWhileWaiting(cfg, ST.lastTargetCtx, "wait_ready", "hold")
        end
        return false
    end
    local ctx, err, newPlotIdx, newPlantIdx = pickTargetForFlow(cfg, ST.sprPlotIndex, ST.sprPlantIndex)
    if not ctx then
        if ST.lastTargetCtx and ST.lastTargetCtx.plot and ST.lastTargetCtx.plot.Parent then
            holdAtTargetWhileWaiting(cfg, ST.lastTargetCtx, err or "no_plot", "hold")
        else
            tickTargetOfflineWatch(cfg)
            _publish(err or "no_plot")
        end
        return false
    end
    ST.sprPlotIndex = newPlotIdx
    ST.sprPlantIndex = newPlantIdx
    ST.lastTargetCtx = ctx

    local pausedHarvest = shouldPauseForHarvestable(cfg, ctx)
    if pausedHarvest then
        holdAtTargetWhileWaiting(cfg, ctx, "fruit_pause")
        return false
    end

    local sprinklerTypes = listSelectedToolsByType("Sprinkler", cfg.sprinklers)
    if #sprinklerTypes == 0 then
        holdAtTargetWhileWaiting(cfg, ctx, "no_sprinkler", "hold")
        return false
    end

    -- Cycle N = tiap tipe selected harus place N kali.
    -- Ada di garden? skip dulu, place yang belum ada. Baru nunggu kalau semua sisa masih aktif.
    local sprinklerCycles = clampMaxUse(cfg.sprinkler_max_use or 1)
    local sprinkleNeed = #sprinklerTypes * sprinklerCycles
    local placedByType = {}
    for _, entry in ipairs(sprinklerTypes) do
        placedByType[entry.typeKey or entry.name] = 0
    end
    local sprinkleDone = 0
    local toolsExhausted = false
    local failed = false
    local startedWithTools = true

    ST.sprCycleBusy = true
    if not acquireActionLock(LOCK_SPR) then
        ST.sprCycleBusy = false
        return false
    end

    if not _gateMidCycle() then
        finishFlowSession(LOCK_SPR)
        if isNightOrPreempt() or ST.workPaused then
            if refreshStatusDist then refreshStatusDist() end
        elseif not ST.atTarget then
            _publish("wait_ready", "Moving to plant...")
        else
            _publish("wait_ready", "timeout")
        end
        return false
    end

    if not canRunActions() then
        ST.lastTargetCtx = ctx
        finishFlowSession(LOCK_SPR)
        if ST.workPaused or isNightOrPreempt() then
            if refreshStatusDist then refreshStatusDist() end
        else
            _publish("wait_ready", "Moving to plant...")
        end
        return false
    end
    ST.activeFlowCtx = ctx

    local waitStart = os.clock()
    while ST.running and sprinkleDone < sprinkleNeed do
        if not _gateMidCycle() then
            failed = true
            break
        end

        local placedThisPass = false
        local waitingTypes = {}

        for _, entry in ipairs(sprinklerTypes) do
            if not ST.running then
                failed = true
                break
            end
            local typeName = entry.typeKey or entry.name
            if (placedByType[typeName] or 0) >= sprinklerCycles then
                continue
            end
            if not _gateMidCycle() then
                failed = true
                break
            end

            invalidateSprinklerCache()
            local existing = findSprinklerTypeNearPlant(ctx.plot, ctx.groundPos, typeName)
            if existing and sprinklerStillActive(ctx.plot, existing.pos, existing.model) then
                waitingTypes[#waitingTypes + 1] = typeName
                continue
            end

            ST.sprPlaceSlot += 1
            local placePos = findFreePlacePos(ctx.plot, ctx.groundPos, ST.sprPlaceSlot)
            _publish("placing", string.format(
                "%s · %d/%d · total %d/%d",
                entry.name, (placedByType[typeName] or 0) + 1, sprinklerCycles, sprinkleDone + 1, sprinkleNeed
            ))

            local useTool = refreshToolEntry(entry, "Sprinkler")
            if not useTool then
                _publish("no_sprinkler", typeName)
                toolsExhausted = true
                failed = true
                break
            end

            local okPlace, _, placeErr = placeSprinklerOnPlot(
                ctx.plot, ctx.plotId, placePos, useTool, typeName
            )
            if not okPlace then
                task.wait(0.35)
                useTool = refreshToolEntry(entry, "Sprinkler")
                if useTool then
                    okPlace, _, placeErr = placeSprinklerOnPlot(
                        ctx.plot, ctx.plotId, placePos, useTool, typeName
                    )
                end
            end
            if not okPlace then
                _publish("place_fail", placeErr or entry.name)
                failed = true
                break
            end

            placedByType[typeName] = (placedByType[typeName] or 0) + 1
            sprinkleDone += 1
            placedThisPass = true
            task.wait(CFG.WAIT_BETWEEN_SPRINKLER_TYPES_SEC)
        end

        if failed then break end
        if sprinkleDone >= sprinkleNeed then break end

        if not placedThisPass then
            if #waitingTypes == 0 then
                failed = true
                break
            end
            if (os.clock() - waitStart) > CFG.WAIT_PER_USE_MAX_SEC then
                _publish("place_fail", "wait sprinkler timeout")
                failed = true
                break
            end
            _publish("waiting_sprinkler", table.concat(waitingTypes, ", ") .. " · tunggu habis")
            releaseActionLockForWait(LOCK_SPR)
            task.wait(0.5)
            if not reacquireActionLock(LOCK_SPR) then
                failed = true
                break
            end
        else
            waitStart = os.clock()
        end
    end

    finishFlowSession(LOCK_SPR)

    if sprinkleDone >= sprinkleNeed then
        ST.vulnSprinklerReady = true
        _publish("done", string.format("sprinkler %d/%d", sprinkleDone, sprinkleNeed))
        return true
    end

    ST.vulnSprinklerReady = false
    resetApproachSession(true)
    return false
end

local function runWateringFlow(cfg)
    if ST.waterCycleBusy then return false end
    if next(cfg.watering_cans or {}) == nil then return false end
    applyPositionMode(cfg)

    _publish("idle", "water scan")
    tickTargetOfflineWatch(cfg)

    if not _ensureSessionReady(CFG.SESSION_READY_MAX_WAIT_SEC) then
        _publish("wait_ready", "timeout")
        if ST.lastTargetCtx then
            holdAtTargetWhileWaiting(cfg, ST.lastTargetCtx, "wait_ready", "hold")
        end
        return false
    end
    local ctx, err, newPlotIdx, newPlantIdx = pickTargetForFlow(cfg, ST.waterPlotIndex, ST.waterPlantIndex)
    if not ctx then
        if ST.lastTargetCtx and ST.lastTargetCtx.plot and ST.lastTargetCtx.plot.Parent then
            holdAtTargetWhileWaiting(cfg, ST.lastTargetCtx, err or "no_plot", "hold")
        else
            tickTargetOfflineWatch(cfg)
            _publish(err or "no_plot")
        end
        return false
    end
    ST.waterPlotIndex = newPlotIdx
    ST.waterPlantIndex = newPlantIdx
    ST.lastTargetCtx = ctx

    local pausedHarvest = shouldPauseForHarvestable(cfg, ctx)
    if pausedHarvest then
        holdAtTargetWhileWaiting(cfg, ctx, "fruit_pause")
        return false
    end

    local wateringTypes = listSelectedToolsByType("WateringCan", cfg.watering_cans)
    if #wateringTypes == 0 then
        holdAtTargetWhileWaiting(cfg, ctx, "no_can", "hold")
        return false
    end

    -- Cycle N = tiap can selected water N kali; delay antar use dari UI.
    local wateringCycles = clampMaxUse(cfg.watering_max_use or 1)
    local waterNeed = #wateringTypes * wateringCycles
    local waterDone = 0
    local toolsExhausted = false
    local failed = false
    local startedWithTools = true

    ST.waterCycleBusy = true
    if not acquireActionLock(LOCK_WAT) then
        ST.waterCycleBusy = false
        return false
    end

    if not _gateMidCycle() then
        finishFlowSession(LOCK_WAT)
        if isNightOrPreempt() or ST.workPaused then
            if refreshStatusDist then refreshStatusDist() end
        elseif not ST.atTarget then
            _publish("wait_ready", "Moving to plant...")
        else
            _publish("wait_ready", "timeout")
        end
        return false
    end

    if not canRunActions() then
        ST.lastTargetCtx = ctx
        finishFlowSession(LOCK_WAT)
        if ST.workPaused or isNightOrPreempt() then
            if refreshStatusDist then refreshStatusDist() end
        else
            _publish("wait_ready", "Moving to plant...")
        end
        return false
    end
    ST.activeFlowCtx = ctx

    for cycleIdx = 1, wateringCycles do
        for typeIdx, entry in ipairs(wateringTypes) do
            if not ST.running then
                failed = true
                break
            end
            if not _gateMidCycle() then
                failed = true
                break
            end

            _publish("watering", string.format(
                "%s · %d/%d · total %d/%d",
                entry.name, cycleIdx, wateringCycles, waterDone + 1, waterNeed
            ))
            local useTool = refreshToolEntry(entry, "WateringCan")
            if not useTool then
                _publish("no_can", entry.typeKey or entry.name)
                toolsExhausted = true
                failed = true
                break
            end

            local okWater = waterPlantWithTool(ctx.plot, ctx.target, useTool, ctx.groundPos)
            if not okWater then
                if not refreshToolEntry(entry, "WateringCan") then
                    toolsExhausted = true
                end
                _publish("water_fail", entry.name)
                failed = true
                break
            end

            waterDone += 1

            if waterDone >= waterNeed then
                break
            end

            -- Delay antar watering (UI: Watering Delay sec)
            local waitWaterSec = clampWateringDelay(cfg.watering_delay_sec)
            if waitWaterSec <= 0 then
                waitWaterSec = 0
            end
            releaseActionLockForWait(LOCK_WAT)
            local t0 = os.clock()
            while ST.running and (os.clock() - t0) < waitWaterSec do
                if isNightOrPreempt() or ST.workPaused then
                    break
                end
                local pausedHarvest = shouldPauseForHarvestable(cfg, ctx)
                if pausedHarvest then
                    _publish("fruit_pause")
                    break
                end
                _publish("waiting_water", string.format(
                    "%.0fs · %d/%d",
                    math.max(0, waitWaterSec - (os.clock() - t0)),
                    waterDone, waterNeed
                ))
                task.wait(0.25)
            end
            if not reacquireActionLock(LOCK_WAT) then
                failed = true
                break
            end
            if shouldPauseForHarvestable(cfg, ctx) then
                failed = true
                break
            end
        end
        if failed or waterDone >= waterNeed then break end
    end

    finishFlowSession(LOCK_WAT)

    if waterDone >= waterNeed then
        ST.vulnWaterReady = true
        _publish("done", string.format("water %d/%d", waterDone, waterNeed))
        return true
    end

    ST.vulnWaterReady = false
    resetApproachSession(true)
    return false
end

local function safeRunSprinklerFlow(cfg)
    local ok, err = pcall(runSprinklerFlow, cfg)
    if ST.sprCycleBusy then finishFlowSession(LOCK_SPR) end
    if ST.actionLockOwner == LOCK_SPR then releaseActionLock(LOCK_SPR) end
    if not ok then
        resetApproachSession(true)
        ST.vulnSprinklerReady = false
        _publish("place_fail", "runtime error")
        warn("[AutoSprinklerOtherGarden/Sprinkler]", err)
    end
end

local function safeRunWateringFlow(cfg)
    local ok, err = pcall(runWateringFlow, cfg)
    if ST.waterCycleBusy then finishFlowSession(LOCK_WAT) end
    if ST.actionLockOwner == LOCK_WAT then releaseActionLock(LOCK_WAT) end
    if not ok then
        resetApproachSession(true)
        ST.vulnWaterReady = false
        _publish("water_fail", "runtime error")
        warn("[AutoSprinklerOtherGarden/Water]", err)
    end
end

local function sprinklerMainLoop(myId)
    while ST.running and ST.sprLoopId == myId do
        local cfg = getCfg()
        local doSpr = cfg.enabled and next(cfg.sprinklers or {}) ~= nil
        if doSpr then
            if not canRunActions() then
                if ST.workPaused or isNightOrPreempt() then
                    -- Status malam hanya dari position loop (1 status)
                    if refreshStatusDist then refreshStatusDist() end
                else
                    _publish("wait_ready", "Moving to plant...")
                end
                task.wait(CFG.SESSION_READY_POLL_SEC)
            elseif ST.sprCycleBusy then
                task.wait(CFG.CYCLE_DELAY_SEC)
            else
                local pausedHarvest = shouldPauseForHarvestable(cfg)
                if pausedHarvest then
                    _publish("fruit_pause")
                    task.wait(CFG.CYCLE_DELAY_SEC)
                else
                    local blocked, reason = _isSessionBlocked()
                    if blocked and reason ~= "pos_not_ready" and reason ~= "night" then
                        _publish("wait_ready", _waitReadyDetail(reason))
                        task.wait(CFG.SESSION_READY_POLL_SEC)
                    else
                        if not tickTargetOfflineWatch(cfg) then
                            if ST.lastTargetCtx and not isAnyTargetOnline(cfg) then
                                holdAtTargetWhileWaiting(cfg, ST.lastTargetCtx, "wait_ready", "target offline")
                            elseif canRunActions() then
                                safeRunSprinklerFlow(cfg)
                            end
                        end
                        task.wait(CFG.CYCLE_DELAY_SEC)
                    end
                end
            end
        else
            ST.vulnSprinklerReady = false
            task.wait(CFG.LOOP_MIN_SEC)
        end
    end
end

local function wateringMainLoop(myId)
    while ST.running and ST.waterLoopId == myId do
        local cfg = getCfg()
        local doWater = cfg.enabled and next(cfg.watering_cans or {}) ~= nil
        if doWater then
            if not canRunActions() then
                if ST.workPaused or isNightOrPreempt() then
                    -- Status malam hanya dari position loop (1 status)
                    if refreshStatusDist then refreshStatusDist() end
                else
                    _publish("wait_ready", "Moving to plant...")
                end
                task.wait(CFG.SESSION_READY_POLL_SEC)
            elseif ST.waterCycleBusy then
                task.wait(CFG.CYCLE_DELAY_SEC)
            else
                local pausedHarvest = shouldPauseForHarvestable(cfg)
                if pausedHarvest then
                    _publish("fruit_pause")
                    task.wait(CFG.CYCLE_DELAY_SEC)
                else
                    local blocked, reason = _isSessionBlocked()
                    if blocked and reason ~= "pos_not_ready" and reason ~= "night" then
                        _publish("wait_ready", _waitReadyDetail(reason))
                        task.wait(CFG.SESSION_READY_POLL_SEC)
                    else
                        if not tickTargetOfflineWatch(cfg) then
                            if ST.lastTargetCtx and not isAnyTargetOnline(cfg) then
                                holdAtTargetWhileWaiting(cfg, ST.lastTargetCtx, "wait_ready", "target offline")
                            elseif canRunActions() then
                                safeRunWateringFlow(cfg)
                            end
                        end
                        task.wait(CFG.CYCLE_DELAY_SEC)
                    end
                end
            end
        else
            ST.vulnWaterReady = false
            task.wait(CFG.LOOP_MIN_SEC)
        end
    end
end

function M.SetEnabled(on)
    on = (on == true)
    G.SW_OTHER_ENABLED = on
    _G.SW_OTHER_ENABLED = on

    if not on and not ST.running then
        return
    end

    if on then
        ST.sprPlotIndex = 0
        ST.waterPlotIndex = 0
        ST.sprPlantIndex = 0
        ST.waterPlantIndex = 0
        ST.posPlotIndex = 0
        ST.posPlantIndex = 0
        ST.sprPlaceSlot = 0
        ST.sprCycleBusy = false
        ST.waterCycleBusy = false
        ST.actionLock = false
        ST.actionLockOwner = nil
        ST.vulnSprinklerReady = false
        ST.vulnWaterReady = false
        ST.targetOfflineSince = nil
        ST.approachSessionKey = nil
        ST.lockedTargetPlayer = nil
        ST.lockedPlotToken = nil
        ST.workPaused = false
        ST.atTarget = false
        ST.posMoveBusy = false
        ST.harvestPauseCount = 0
        ST.harvestGrowingCount = 0
        ST.harvestScanCacheAt = 0
        ST.harvestScanCacheCount = 0
        ST.harvestScanCacheGrowing = 0
        ST.harvestScanCachePlot = nil
        invalidatePlotCaches()
        ST.approachAnchor = nil
        ST.running = true
        ST.pinnedFlyGoal = nil
        ST.sprLoopId += 1
        ST.waterLoopId += 1
        ST.posLoopId += 1
        local sprId = ST.sprLoopId
        local waterId = ST.waterLoopId
        local posId = ST.posLoopId
        _publish("idle", "start")

        -- Semua kerja berat di spawn — toggle UI tidak boleh freeze
        task.spawn(function()
            if not ST.running then return end
            pcall(_pauseOtherModules)
            -- Jangan FlyNoclip/LockAt saat loading — itu yang bikin fall/mati stuck.
            while ST.running and isLoadingActive() do
                task.wait(0.25)
            end
            if not ST.running then return end
            holdFlyAtCurrent()
            for _ = 1, 24 do
                if not ST.running then return end
                local F = _getFlyMod()
                if F and type(F.IsLocked) == "function" and F.IsLocked() then
                    break
                end
                if holdFlyAtCurrent() then
                    break
                end
                task.wait(0.25)
            end
            if not ST.running then return end
            pcall(startGhostPepperBypass)
            pcall(startHealthLock)
            task.spawn(function() positionMainLoop(posId) end)
            task.spawn(function() sprinklerMainLoop(sprId) end)
            task.spawn(function() wateringMainLoop(waterId) end)
        end)
    else
        ST.running = false
        ST.sprLoopId += 1
        ST.waterLoopId += 1
        ST.posLoopId += 1
        ST.sprCycleBusy = false
        ST.waterCycleBusy = false
        ST.actionLock = false
        ST.actionLockOwner = nil
        ST.vulnSprinklerReady = false
        ST.vulnWaterReady = false
        ST.targetOfflineSince = nil
        ST.workPaused = false
        ST.atTarget = false
        ST.posMoveBusy = false
        ST.pinnedFlyGoal = nil
        _publish("disabled")

        task.spawn(function()
            pcall(stopGhostPepperBypass)
            pcall(stopHealthLock)
            local Foff = _getFlyMod()
            if Foff then
                if type(Foff.IsLocked) == "function" and Foff.IsLocked() then
                    if type(Foff.ReleaseToSurface) == "function" then
                        pcall(Foff.ReleaseToSurface, Foff)
                    elseif type(Foff.Stop) == "function" then
                        pcall(Foff.Stop, Foff)
                    end
                elseif type(Foff.Stop) == "function" then
                    pcall(Foff.Stop, Foff)
                end
            end
            pcall(resetApproachSession, false)
            if ST.fxConn then
                ST.fxConn:Disconnect()
                ST.fxConn = nil
            end
        end)
    end
end

function M.Apply()
    local cfg = getCfg()
    if not cfg.enabled then
        -- Sudah off: jangan SetEnabled(false) → itu memanggil FlyNoclip.Stop/restoreHumanoid saat load → fall.
        if ST.running then
            M.SetEnabled(false)
        end
        return
    end
    M.SetEnabled(true)
end

function M.Start() return M.SetEnabled(true) end
function M.Stop() return M.SetEnabled(false) end

function M.IsEnabled()
    return ST.running and getCfg().enabled
end

function M.GetSprinklerWaterStatusText()
    if refreshStatusDist then
        return refreshStatusDist()
    end
    return ST.statusText
end

function M.GetSprinklerWaterStatus()
    local text = M.GetSprinklerWaterStatusText()
    return {
        text = text,
        key = ST.statusKey,
        distStuds = ST.statusDistStuds,
    }
end

function M.GetStatusText()
    return M.GetSprinklerWaterStatusText()
end

function M.GetDistToPlantTarget()
    return getDistToPlantTarget()
end

function M.SyncFromState()
    M.Apply()
end

G.AutoSprinklerOtherGarden = M
G.AutoSprinklerOtherGardenModule = M
_G.AutoSprinklerOtherGarden = M
_G.AutoSprinklerOtherGardenModule = M
-- legacy aliases
G.AutoVulnSprinklerWater = M
G.AutoVulnSprinklerWaterModule = M
_G.AutoVulnSprinklerWater = M
_G.AutoVulnSprinklerWaterModule = M

G.__GAG2_SW_OTHER_STATUS = "Idle"
_G.__GAG2_SW_OTHER_STATUS = "Idle"

return M
 end, required = false },
    { key = "SectionAutoSprinklerOtherGarden", name = "Section Auto Sprinkler Other Garden", factory = function() -- section_auto_sprinkler_other_garden.lua — UI Sprinkler & Watering Other Garden (tab Auto)
-- Body di-build lazy saat section dibuka (hindari freeze saat boot).

local Players = game:GetService("Players")
local LP = Players.LocalPlayer

local G = (getgenv and getgenv()) or _G
local M = {}

local function clampMaxUse(n)
    n = math.floor(tonumber(n) or 1)
    return math.max(1, math.min(100, n))
end

local function clampStopCollectMax(n)
    n = math.floor(tonumber(n) or 0)
    if n < 0 then n = 0 end
    if n > 9999 then n = 9999 end
    return n
end

local function clampWateringDelay(n)
    n = math.floor(tonumber(n) or 10)
    if n < 0 then n = 0 end
    if n > 600 then n = 600 end
    return n
end

local function normalizePositionMode(mode)
    mode = tostring(mode or "under"):lower()
    if mode == "above" or mode == "over" then
        return "above"
    end
    return "under"
end

local function looksLikeId(s)
    s = tostring(s or "")
    if s == "" then return true end
    if s:match("^%d+_[%x%-]+") then return true end
    if #s >= 32 and s:match("^[%x%-]+$") then return true end
    if s:find("_", 1, true) and s:find("-", 1, true) and not s:match("^[%a][%a ]*$") then
        return true
    end
    return false
end

local function pickNameFromInst(inst)
    if not inst then return nil end
    for _, key in ipairs({
        "SeedName", "PlantName", "FruitType", "FruitName",
        "ItemName", "CorePartName", "ConfigPathName",
    }) do
        local v = inst:GetAttribute(key)
        if type(v) == "string" and v ~= "" and not looksLikeId(v) then
            local tail = v:match("([^/]+)$")
            if tail and not looksLikeId(tail) then
                return tail
            end
            return v
        end
    end
    local n = tostring(inst.Name or "")
    if n ~= "" and not looksLikeId(n) then
        return n
    end
    return nil
end

-- Light resolve — no GetDescendants (itu yang bikin freeze di garden besar)
local function resolvePlantTypeName(plant)
    if not plant then return "" end

    local FSV = G.FruitSellValue or rawget(_G, "FruitSellValue")
    if type(FSV) == "table" and type(FSV.resolveSeedName) == "function" then
        local ok, n = pcall(FSV.resolveSeedName, FSV, plant)
        if ok and type(n) == "string" and n ~= "" and not looksLikeId(n) then
            return n
        end
    end

    local AS = G.AutoShovel or G.AutoShovelModule or rawget(_G, "AutoShovel")
    if type(AS) == "table" and type(AS.GetPlantDisplayName) == "function" then
        local ok, n = pcall(AS.GetPlantDisplayName, AS, plant)
        if ok and type(n) == "string" and n ~= "" and not looksLikeId(n) then
            return n
        end
    end

    local n = pickNameFromInst(plant)
    if n then return n end

    for _, ch in ipairs(plant:GetChildren()) do
        if ch:IsA("Model") or ch:IsA("BasePart") or ch:IsA("StringValue") then
            n = pickNameFromInst(ch)
            if n then return n end
        end
        -- Fruits/Fruit folder: SeedName sering di child buah (ReduceFPS hide, jangan skip)
        if ch.Name == "Fruits" or ch.Name == "Fruit" then
            for _, fruit in ipairs(ch:GetChildren()) do
                n = pickNameFromInst(fruit)
                if n then return n end
            end
        end
    end

    return ""
end

local function getPlantTypeKey(plant)
    return resolvePlantTypeName(plant)
end

local function plotOwnedByUserId(plot, userId)
    if not plot or not userId then return false end
    local uid = math.floor(tonumber(userId) or 0)
    if uid <= 0 then return false end

    for _, attr in ipairs({ "OwnerUserId", "OwnerId", "UserId" }) do
        local v = plot:GetAttribute(attr)
        if math.floor(tonumber(v) or 0) == uid then return true end
    end

    for _, child in ipairs(plot:GetChildren()) do
        if child:IsA("ValueBase") then
            local n = child.Name:lower()
            if n:find("owner") or n:find("userid") or n:find("player") then
                if math.floor(tonumber(child.Value) or 0) == uid then return true end
            end
        end
    end
    return false
end

local function findPlotForPlayer(plr)
    if not plr then return nil end
    local gardens = workspace:FindFirstChild("Gardens")
    if not gardens then return nil end

    local plotId = plr:GetAttribute("PlotId")
        or plr:GetAttribute("Plot")
        or plr:GetAttribute("PlotName")
        or plr:GetAttribute("GardenPlot")
    if plotId ~= nil then
        local idStr = tostring(plotId)
        for _, name in ipairs({ "Plot" .. idStr, idStr, "Plot_" .. idStr }) do
            local plot = gardens:FindFirstChild(name)
            if plot then return plot end
        end
    end

    for _, plot in ipairs(gardens:GetChildren()) do
        if plotOwnedByUserId(plot, plr.UserId) then
            return plot
        end
    end
    return nil
end

local function normalizePlantSelectionKey(key)
    key = tostring(key or "")
    local legacy = key:match("::(.+)$")
    if legacy and legacy ~= "" then key = legacy end
    if key == "" or key == "_none" or looksLikeId(key) then return "" end
    return key
end

local function normalizePlantSelectionMap(map)
    local out = {}
    if type(map) ~= "table" then return out end
    for k, v in pairs(map) do
        if v == true then
            local nk = normalizePlantSelectionKey(k)
            if nk ~= "" and nk ~= "_none" then
                out[nk] = true
            end
        end
    end
    return out
end

local function singleKeyFromMap(map)
    local keys = {}
    for k, v in pairs(map or {}) do
        if v == true and k ~= "_none" then
            keys[#keys + 1] = tostring(k)
        end
    end
    table.sort(keys)
    return keys[1] or ""
end

local function mapFromSingleKey(key)
    key = tostring(key or "")
    if key == "" or key == "_none" then return {} end
    return { [key] = true }
end

local function findPlotByKey(plotKey)
    plotKey = tostring(plotKey or "")
    if plotKey == "" then return nil end
    local gardens = workspace:FindFirstChild("Gardens")
    if not gardens then return nil end
    local plot = gardens:FindFirstChild(plotKey)
    if plot then return plot end
    for _, child in ipairs(gardens:GetChildren()) do
        if tostring(child.Name) == plotKey then return child end
    end
    return nil
end

local function findPlotForUsername(username)
    username = tostring(username or ""):gsub("^%s+", ""):gsub("%s+$", ""):gsub("^@", "")
    if username == "" then return nil end
    local want = username:lower()
    for _, plr in ipairs(Players:GetPlayers()) do
        if plr.Name:lower() == want then
            return findPlotForPlayer(plr)
        end
    end
    return nil
end

local function arrayToMapLocal(arr)
    local out = {}
    if type(arr) ~= "table" then return out end
    for _, v in ipairs(arr) do
        local k = tostring(v or "")
        if k ~= "" and k ~= "_none" then
            out[k] = true
        end
    end
    return out
end

local function migrateLegacyPlotKeyToUsername(plotKey)
    plotKey = tostring(plotKey or "")
    if plotKey == "" or plotKey == "_none" then return "" end

    local plr = Players:FindFirstChild(plotKey)
    if plr and plr:IsA("Player") and plr ~= LP then
        return plr.Name
    end

    local plot = findPlotByKey(plotKey)
    if plot then
        for _, p in ipairs(Players:GetPlayers()) do
            if p ~= LP and plotOwnedByUserId(plot, p.UserId) then
                return p.Name
            end
        end
    end
    return ""
end

local function loadPlayersSelected(swST)
    local players = arrayToMapLocal(type(swST.target_players) == "table" and swST.target_players or {})
    if not next(players) then
        local plots = arrayToMapLocal(type(swST.target_plots) == "table" and swST.target_plots or {})
        for plotKey, on in pairs(plots) do
            if on == true then
                local user = migrateLegacyPlotKeyToUsername(plotKey)
                if user ~= "" then
                    players[user] = true
                end
            end
        end
    end
    return players
end

local function buildOtherPlotPlayerItems()
    local items = {}
    local seenUser = {}

    for _, plr in ipairs(Players:GetPlayers()) do
        if plr ~= LP and not seenUser[plr.UserId] then
            -- Cepat: cek PlotId dulu; skip scan semua plot kalau tidak perlu
            local plot = findPlotForPlayer(plr)
            if plot then
                seenUser[plr.UserId] = true
                local display = plr.DisplayName
                if display and display ~= "" and display ~= plr.Name then
                    display = display .. " (@" .. plr.Name .. ")"
                else
                    display = plr.Name
                end
                items[#items + 1] = {
                    key = plr.Name,
                    name = display,
                }
            end
        end
    end

    table.sort(items, function(a, b)
        return tostring(a.name) < tostring(b.name)
    end)

    if #items == 0 then
        items[1] = { key = "_none", name = "(Tidak ada player lain di server)" }
    end
    return items
end

local function buildTargetPlantItems(selectedPlayers)
    local items = {}
    local seen = {}
    selectedPlayers = type(selectedPlayers) == "table" and selectedPlayers or {}
    local scanned = 0
    local MAX_PLANTS = 250

    local function scanFolder(folder)
        if not folder then return end
        for _, plant in ipairs(folder:GetChildren()) do
            if scanned >= MAX_PLANTS then return end
            if plant:IsA("Model") then
                scanned += 1
                local typeKey = getPlantTypeKey(plant)
                if typeKey ~= "" and not looksLikeId(typeKey) and not seen[typeKey] then
                    seen[typeKey] = true
                    items[#items + 1] = {
                        key = typeKey,
                        name = typeKey,
                    }
                end
            end
        end
    end

    for userName, on in pairs(selectedPlayers) do
        if on == true and userName ~= "_none" then
            local plot = findPlotForUsername(userName)
            if plot then
                local important = plot:FindFirstChild("Important")
                scanFolder(plot:FindFirstChild("Plants"))
                scanFolder(plot:FindFirstChild("Plants_Physical"))
                if important then
                    scanFolder(important:FindFirstChild("Plants"))
                    scanFolder(important:FindFirstChild("Plants_Physical"))
                end
            end
        end
    end

    table.sort(items, function(a, b)
        return tostring(a.name) < tostring(b.name)
    end)

    if #items == 0 then
        items[1] = { key = "_none", name = "(Pilih target player dulu)" }
    end
    return items
end

local function buildSectionBody(ctx, body)
    local ui = ctx.ui
    local getAuto = ctx.getAuto
    local patchAuto = ctx.patchAuto
    local patchAutoOnly = ctx.patchAutoOnly
    local registerFlush = ctx.registerFlush
    local cleanSelectedMap = ctx.cleanSelectedMap
    local arrayToMap = ctx.arrayToMap
    local mapToArray = ctx.mapToArray

    local SprinklerListView = G.SprinklerListView or rawget(_G, "SprinklerListView")
    local WateringCanListView = G.WateringCanListView or rawget(_G, "WateringCanListView")

    local swST = getAuto("sprinklerOtherGarden") or {}
    swST.enabled = (swST.enabled == true)
    swST.position_mode = normalizePositionMode(swST.position_mode or swST.watering_mode)
    swST.sprinkler_max_use = clampMaxUse(swST.sprinkler_max_use)
    swST.watering_max_use = clampMaxUse(swST.watering_max_use)
    swST.stop_collect_max = clampStopCollectMax(swST.stop_collect_max)
    swST.watering_delay_sec = clampWateringDelay(swST.watering_delay_sec)
    swST.pause_at_night = (swST.pause_at_night ~= false)

    local playersSelected = cleanSelectedMap(loadPlayersSelected(swST))
    local plantsSelected = normalizePlantSelectionMap(cleanSelectedMap(arrayToMap(type(swST.target_plants) == "table" and swST.target_plants or {})))
    local playerSelectedKey = singleKeyFromMap(playersSelected)
    local plantSelectedKey = singleKeyFromMap(plantsSelected)
    playersSelected = mapFromSingleKey(playerSelectedKey)
    plantsSelected = mapFromSingleKey(plantSelectedKey)
    local sprinklersSelected = cleanSelectedMap(arrayToMap(type(swST.sprinklers) == "table" and swST.sprinklers or {}))
    local wateringSelected = cleanSelectedMap(arrayToMap(type(swST.watering_cans) == "table" and swST.watering_cans or {}))

    local plantDropdownApi

    local function serializeState()
        return {
            enabled = (swST.enabled == true),
            target_players = mapToArray(playersSelected),
            target_plots = {},
            target_plants = mapToArray(plantsSelected),
            sprinklers = mapToArray(sprinklersSelected),
            watering_cans = mapToArray(wateringSelected),
            sprinkler_max_use = swST.sprinkler_max_use,
            watering_max_use = swST.watering_max_use,
            stop_collect_max = swST.stop_collect_max,
            watering_delay_sec = swST.watering_delay_sec,
            pause_at_night = (swST.pause_at_night ~= false),
            position_mode = swST.position_mode,
        }
    end

    local function writeGlobals()
        local snap = serializeState()
        G.SW_OTHER_ENABLED = snap.enabled
        _G.SW_OTHER_ENABLED = snap.enabled
        G.SW_OTHER_TARGET_PLAYERS_SELECTED = playersSelected
        _G.SW_OTHER_TARGET_PLAYERS_SELECTED = playersSelected
        G.SW_OTHER_TARGET_PLOTS_SELECTED = {}
        _G.SW_OTHER_TARGET_PLOTS_SELECTED = {}
        G.SW_OTHER_TARGET_PLANTS_SELECTED = plantsSelected
        _G.SW_OTHER_TARGET_PLANTS_SELECTED = plantsSelected
        G.SW_OTHER_SPRINKLERS_SELECTED = sprinklersSelected
        _G.SW_OTHER_SPRINKLERS_SELECTED = sprinklersSelected
        G.SW_OTHER_WATERING_SELECTED = wateringSelected
        _G.SW_OTHER_WATERING_SELECTED = wateringSelected
        G.SW_OTHER_SPRINKLER_MAX_USE = snap.sprinkler_max_use
        _G.SW_OTHER_SPRINKLER_MAX_USE = snap.sprinkler_max_use
        G.SW_OTHER_WATERING_MAX_USE = snap.watering_max_use
        _G.SW_OTHER_WATERING_MAX_USE = snap.watering_max_use
        G.SW_OTHER_STOP_COLLECT_MAX = snap.stop_collect_max
        _G.SW_OTHER_STOP_COLLECT_MAX = snap.stop_collect_max
        G.SW_OTHER_WATERING_DELAY_SEC = snap.watering_delay_sec
        _G.SW_OTHER_WATERING_DELAY_SEC = snap.watering_delay_sec
        G.SW_OTHER_PAUSE_AT_NIGHT = snap.pause_at_night
        _G.SW_OTHER_PAUSE_AT_NIGHT = snap.pause_at_night
        G.SW_OTHER_POSITION_MODE = snap.position_mode
        _G.SW_OTHER_POSITION_MODE = snap.position_mode
        G.SW_OTHER_WATERING_MODE = snap.position_mode
        _G.SW_OTHER_WATERING_MODE = snap.position_mode
    end

    local function syncModule()
        writeGlobals()
        local VSW = G.AutoSprinklerOtherGarden or G.AutoSprinklerOtherGardenModule or rawget(_G, "AutoSprinklerOtherGarden")
        if type(VSW) == "table" and type(VSW.Apply) == "function" then
            task.defer(function()
                pcall(VSW.Apply, VSW)
            end)
        elseif type(G.applySprinklerOtherGardenModule) == "function" then
            task.defer(function()
                pcall(G.applySprinklerOtherGardenModule)
            end)
        end
    end

    local function patchSw(partial, syncFn)
        for k, v in pairs(partial) do
            swST[k] = v
        end
        patchAuto("sprinklerOtherGarden", serializeState(), syncFn or syncModule)
    end

    -- Flush HANYA tulis MAIN — jangan patchAuto/save (itu bikin save→flush→save loop = freeze)
    registerFlush("sprinkler_other_garden", function()
        writeGlobals()
        if type(patchAutoOnly) == "function" then
            patchAutoOnly("sprinklerOtherGarden", serializeState())
        end
    end)
    G.__GAG2_FLUSH_SPRINKLER_OTHER = function()
        writeGlobals()
        if type(patchAutoOnly) == "function" then
            patchAutoOnly("sprinklerOtherGarden", serializeState())
        end
    end
    _G.__GAG2_FLUSH_SPRINKLER_OTHER = G.__GAG2_FLUSH_SPRINKLER_OTHER

    writeGlobals()

    ui:CreateRowLabel(body, "Sprinkler & watering di garden player lain", nil, 0, "info")

    local _, statusLbl = ui:CreateRowLabel(body, "Status: —", nil, 1, "accent")

    task.spawn(function()
        while body and body.Parent do
            pcall(function()
                local VSW = G.AutoSprinklerOtherGarden or G.AutoSprinklerOtherGardenModule or rawget(_G, "AutoSprinklerOtherGarden")
                if statusLbl and statusLbl.Parent then
                    local txt = "Status: Idle"
                    if type(VSW) == "table" then
                        if type(VSW.GetSprinklerWaterStatusText) == "function" then
                            local ok, out = pcall(VSW.GetSprinklerWaterStatusText, VSW)
                            if ok and type(out) == "string" and out ~= "" then
                                txt = "Status: " .. out
                            end
                        elseif type(VSW.GetStatusText) == "function" then
                            local ok, out = pcall(VSW.GetStatusText, VSW)
                            if ok and type(out) == "string" and out ~= "" then
                                txt = "Status: " .. out
                            end
                        end
                    end
                    statusLbl.Text = txt
                end
            end)
            task.wait(0.5)
        end
    end)

    ui:CreateRowDropdown(body, {
        label = "Target Player",
        placeholder = "Pilih 1 player...",
        mode = "single",
        deferItemLoad = true,
        getItems = buildOtherPlotPlayerItems,
        initial = playerSelectedKey,
        onChanged = function(_, selectedKey)
            local newKey = tostring(selectedKey or "")
            if newKey == "_none" then newKey = "" end
            if newKey == playerSelectedKey then
                return
            end
            playerSelectedKey = newKey
            playersSelected = mapFromSingleKey(playerSelectedKey)
            plantSelectedKey = ""
            plantsSelected = {}
            patchSw({ target_players = mapToArray(playersSelected), target_plots = {}, target_plants = {} })
            if plantDropdownApi and type(plantDropdownApi.refreshItems) == "function" then
                pcall(plantDropdownApi.refreshItems, plantDropdownApi)
            end
            if plantDropdownApi and type(plantDropdownApi.setSelected) == "function" then
                pcall(plantDropdownApi.setSelected, plantSelectedKey)
            end
        end,
    })

    _, plantDropdownApi = ui:CreateRowDropdown(body, {
        label = "Target Plant (tipe)",
        placeholder = "Pilih 1 tipe plant...",
        mode = "single",
        deferItemLoad = true,
        getItems = function()
            return buildTargetPlantItems(playersSelected)
        end,
        initial = plantSelectedKey,
        onChanged = function(_, selectedKey)
            local newKey = tostring(selectedKey or "")
            if newKey == "_none" then newKey = "" end
            newKey = normalizePlantSelectionKey(newKey)
            if newKey == plantSelectedKey then
                return
            end
            plantSelectedKey = newKey
            plantsSelected = mapFromSingleKey(plantSelectedKey)
            patchSw({ target_plants = mapToArray(plantsSelected) })
        end,
    })

    ui:CreateRowDropdown(body, {
        label = "Position Mode",
        placeholder = "Under / Above",
        mode = "single",
        deferItemLoad = true,
        getItems = function()
            return {
                { key = "under", name = "Under" },
                { key = "above", name = "Above" },
            }
        end,
        initial = swST.position_mode,
        onChanged = function(_, selectedKey)
            local mode = normalizePositionMode(selectedKey)
            if mode == swST.position_mode then return end
            swST.position_mode = mode
            patchSw({ position_mode = mode })
        end,
    })

    ui:CreateRowDropdown(body, {
        label = "Sprinkler",
        placeholder = "From inventory...",
        mode = "multi",
        deferItemLoad = true,
        getItems = function()
            if SprinklerListView and type(SprinklerListView.buildInventorySprinklerItems) == "function" then
                return SprinklerListView.buildInventorySprinklerItems() or {}
            end
            if SprinklerListView and type(SprinklerListView.buildSprinklerItems) == "function" then
                return SprinklerListView.buildSprinklerItems() or {}
            end
            return { { key = "_none", name = "(No sprinklers in inventory)" } }
        end,
        initial = sprinklersSelected,
        onChanged = function(_, selectedMap)
            sprinklersSelected = cleanSelectedMap(selectedMap)
            if sprinklersSelected._none then sprinklersSelected._none = nil end
            patchSw({ sprinklers = mapToArray(sprinklersSelected) })
        end,
    })

    ui:CreateRowInput(
        body,
        "Sprinkler Cycle (per type, 1-100)",
        tostring(swST.sprinkler_max_use),
        function(text)
            local n = tonumber(text)
            if n == nil then return end
            swST.sprinkler_max_use = clampMaxUse(n)
            patchSw({ sprinkler_max_use = swST.sprinkler_max_use })
        end,
        false
    )

    ui:CreateRowDropdown(body, {
        label = "Watering Can",
        placeholder = "From inventory...",
        mode = "multi",
        deferItemLoad = true,
        getItems = function()
            if WateringCanListView and type(WateringCanListView.buildInventoryWateringCanItems) == "function" then
                return WateringCanListView.buildInventoryWateringCanItems() or {}
            end
            return { { key = "_none", name = "(No watering cans in inventory)" } }
        end,
        initial = wateringSelected,
        onChanged = function(_, selectedMap)
            wateringSelected = cleanSelectedMap(selectedMap)
            if wateringSelected._none then wateringSelected._none = nil end
            patchSw({ watering_cans = mapToArray(wateringSelected) })
        end,
    })

    ui:CreateRowInput(
        body,
        "Watering Cycle (per type, 1-100)",
        tostring(swST.watering_max_use),
        function(text)
            local n = tonumber(text)
            if n == nil then return end
            swST.watering_max_use = clampMaxUse(n)
            patchSw({ watering_max_use = swST.watering_max_use })
        end,
        false
    )

    ui:CreateRowInput(
        body,
        "Watering Delay (sec)",
        tostring(swST.watering_delay_sec),
        function(text)
            local n = tonumber(text)
            if n == nil then return end
            swST.watering_delay_sec = clampWateringDelay(n)
            patchSw({ watering_delay_sec = swST.watering_delay_sec })
        end,
        false
    )

    ui:CreateRowInput(
        body,
        "Stop if harvestable >= (0=off)",
        tostring(swST.stop_collect_max),
        function(text)
            local n = tonumber(text)
            if n == nil then return end
            swST.stop_collect_max = clampStopCollectMax(n)
            patchSw({ stop_collect_max = swST.stop_collect_max })
        end,
        false
    )

    ui:CreateRowToggle(body, "Pause at Night", swST.pause_at_night ~= false, function(on)
        swST.pause_at_night = (on == true)
        patchSw({ pause_at_night = swST.pause_at_night })
    end)

    ui:CreateRowToggle(body, "Enabled", swST.enabled, function(on)
        swST.enabled = (on == true)
        -- Apply deferred di syncModule — jangan kerja berat di click handler
        patchSw({ enabled = swST.enabled })
    end)

    writeGlobals()
end

function M.Register(ctx)
    if type(ctx) ~= "table" or type(ctx.ui) ~= "table" then return end

    local ui = ctx.ui
    local body = ui:CreateSection("Sprinkler & Watering Other Garden", false)

    -- Tulis globals ringan saja saat boot — jangan scan garden / Apply module.
    do
        local getAuto = ctx.getAuto
        local swST = (type(getAuto) == "function" and getAuto("sprinklerOtherGarden")) or {}
        G.SW_OTHER_ENABLED = (swST.enabled == true)
        _G.SW_OTHER_ENABLED = G.SW_OTHER_ENABLED
    end

    local built = false
    local building = false

    local function tryBuild()
        if built or building then return end
        building = true
        local loadRow = ui:CreateRowLabel(body, "Memuat section...", nil, 0, "muted")
        task.spawn(function()
            local ok, err = pcall(buildSectionBody, ctx, body)
            if loadRow and loadRow.Parent then
                loadRow:Destroy()
            end
            if not ok then
                building = false
                warn("[GAG2] Section Sprinkler Other Garden build error:", tostring(err))
                ui:CreateRowLabel(body, "Load error: " .. tostring(err), nil, 0, "accent")
                return
            end
            built = true
            building = false
        end)
    end

    local section = body.Parent
    local header = section and section:FindFirstChild("Header")
    if header and header:IsA("GuiButton") then
        header.MouseButton1Click:Connect(function()
            tryBuild()
        end)
    else
        -- Fallback: build deferred, jangan block boot thread
        task.defer(tryBuild)
    end
end

return M
 end, required = false },
}

----------------------------------------------------------------
-- HELPERS
----------------------------------------------------------------
local function isLoadedModule(mod)
    return type(mod) == "table" and next(mod) ~= nil
end

local function hasUnreplacedShortcode(s)
    return tostring(s or ""):find("%%%[%[%[") ~= nil
end

local function callMethod(mod, names, ...)
    if type(mod) ~= "table" then return false, "module not table" end
    for _, name in ipairs(names) do
        local fn = mod[name]
        if type(fn) == "function" then
            local ok, res = pcall(fn, mod, ...)
            if ok then return true, res end
            ok, res = pcall(fn, ...)
            if ok then return true, res end
            return false, res
        end
    end
    return false, "method not found"
end

local function moduleStart(mod, ...)
    if type(mod) ~= "table" then return false end
    if type(mod.IsRunning) == "function" then
        local ok, v = pcall(mod.IsRunning, mod)
        if ok and v == true then return true end
    end
    if mod.running == true then return true end
    local ok = callMethod(mod, { "Start", "start" }, ...)
    return ok == true
end

local function isValidAntiafkMod(mod)
    return type(mod) == "table"
        and (type(mod.Start) == "function" or type(mod.start) == "function")
        and type(mod.AutoSkipLoading) == "function"
end

local function resolveFactoryResult(res, def)
    if type(res) == "table" then
        return true, res
    end
    if type(res) == "function" then
        local ok2, res2 = pcall(res)
        if ok2 and type(res2) == "table" then
            return true, res2
        end
    end
    if def and def.key == "antiafk" then
        local cached = G.AntiAFK or G.antiafk or rawget(_G, "AntiAFK")
        if isValidAntiafkMod(cached) then
            return true, cached
        end
    end
    return false, "factory result bukan table"
end

local function runFactory(def)
    local okRun, res = pcall(def.factory)
    if not okRun then
        return false, "factory error: " .. tostring(res)
    end
    return resolveFactoryResult(res, def)
end

local function registerAutoSprinklerSectionLate(uiRef)
    if type(uiRef) ~= "table" then return end
    if G.__GAG2_AUTO_SPRINKLER_UI_DONE or rawget(_G, "__GAG2_AUTO_SPRINKLER_UI_DONE") then return end

    local ctx = G.__GAG2_AUTO_TAB_CTX or rawget(_G, "__GAG2_AUTO_TAB_CTX")
    if type(ctx) ~= "table" and type(uiRef) == "table" then
        local State = G.__GAG2_STATE or rawget(_G, "__GAG2_STATE")

        local function saveNow()
            if G.__GAG2_RESETTING == true then return end
            if type(State) == "table" and type(State.saveFromUi) == "function" then
                pcall(State.saveFromUi)
            elseif uiRef and type(uiRef.SaveState) == "function" then
                pcall(function() uiRef:SaveState() end)
            end
        end

        local function getAuto(key)
            if type(State) == "table" and type(State.getAuto) == "function" then
                local ok, result = pcall(State.getAuto, key)
                if ok and type(result) == "table" then return result end
            end
            local m = rawget(_G, "MAIN") or G.MAIN
            if type(m) == "table" and type(m.auto) == "table" then
                return m.auto[key] or {}
            end
            return {}
        end

        local function patchAuto(key, partial, syncFn)
            if type(State) == "table" and type(State.patchAuto) == "function" then
                pcall(State.patchAuto, key, partial)
            else
                local m = rawget(_G, "MAIN") or G.MAIN
                if type(m) == "table" and type(partial) == "table" then
                    m.auto = m.auto or {}
                    local cur = type(m.auto[key]) == "table" and m.auto[key] or {}
                    for k, v in pairs(partial) do cur[k] = v end
                    m.auto[key] = cur
                    G.MAIN = m
                    _G.MAIN = m
                end
            end
            if syncFn then pcall(syncFn) end
            saveNow()
        end

        local function patchAutoOnly(key, partial)
            if type(State) == "table" and type(State.patchAuto) == "function" then
                pcall(State.patchAuto, key, partial, { noSync = true })
            else
                local m = rawget(_G, "MAIN") or G.MAIN
                if type(m) == "table" and type(partial) == "table" then
                    m.auto = m.auto or {}
                    local cur = type(m.auto[key]) == "table" and m.auto[key] or {}
                    for k, v in pairs(partial) do cur[k] = v end
                    m.auto[key] = cur
                    G.MAIN = m
                    _G.MAIN = m
                end
            end
        end

        local function registerFlush(id, fn)
            if type(State) == "table" and type(State.registerFlush) == "function" then
                pcall(State.registerFlush, id, fn)
            end
        end

        local function toggleApiGet(apiKey)
            local api = G[apiKey] or rawget(_G, apiKey)
            if type(api) == "table" and type(api.get) == "function" then
                return api.get() == true
            end
            return nil
        end

        local function cleanSelectedMap(selectedMap)
            local out = {}
            if type(selectedMap) ~= "table" then return out end
            for k, v in pairs(selectedMap) do
                if v == true then
                    out[tostring(k)] = true
                elseif type(k) == "number" and (type(v) == "string" or type(v) == "number") then
                    local s = tostring(v)
                    if s ~= "" then out[s] = true end
                elseif type(k) == "string" and type(v) == "table" then
                    out[tostring(k)] = true
                end
            end
            return out
        end

        local function mapToArray(map)
            local arr = {}
            if type(map) == "table" then
                for k, v in pairs(map) do
                    if v == true then arr[#arr + 1] = tostring(k) end
                end
            end
            table.sort(arr)
            return arr
        end

        local function arrayToMap(arr)
            local m = {}
            if type(arr) == "table" then
                for _, v in ipairs(arr) do
                    if v ~= nil and tostring(v) ~= "" then m[tostring(v)] = true end
                end
            end
            return m
        end

        ctx = {
            ui               = uiRef,
            getAuto          = getAuto,
            patchAuto        = patchAuto,
            patchAutoOnly    = patchAutoOnly,
            registerFlush    = registerFlush,
            cleanSelectedMap = cleanSelectedMap,
            arrayToMap       = arrayToMap,
            mapToArray       = mapToArray,
            toggleApiGet     = toggleApiGet,
        }
        G.__GAG2_AUTO_TAB_CTX = ctx
        _G.__GAG2_AUTO_TAB_CTX = ctx
    end

    local Sec = G.SectionAutoSprinkler or rawget(_G, "SectionAutoSprinkler")
    if type(ctx) ~= "table" or type(Sec) ~= "table" or type(Sec.Register) ~= "function" then
        warnlog("Auto Sprinkler section skip: module/ctx missing")
        return
    end
    local ok, err = pcall(Sec.Register, ctx)
    if ok then
        G.__GAG2_AUTO_SPRINKLER_UI_DONE = true
        _G.__GAG2_AUTO_SPRINKLER_UI_DONE = true
    else
        warnlog("Auto Sprinkler section error:", tostring(err))
    end
end

local function registerAutoWateringSectionLate(uiRef)
    if type(uiRef) ~= "table" then return end
    if G.__GAG2_AUTO_WATERING_UI_DONE or rawget(_G, "__GAG2_AUTO_WATERING_UI_DONE") then return end

    local ctx = G.__GAG2_AUTO_TAB_CTX or rawget(_G, "__GAG2_AUTO_TAB_CTX")
    if type(ctx) ~= "table" then
        registerAutoSprinklerSectionLate(uiRef)
        ctx = G.__GAG2_AUTO_TAB_CTX or rawget(_G, "__GAG2_AUTO_TAB_CTX")
    end

    local Sec = G.SectionAutoWatering or rawget(_G, "SectionAutoWatering")
    if type(ctx) ~= "table" or type(Sec) ~= "table" or type(Sec.Register) ~= "function" then
        warnlog("Auto Watering section skip: module/ctx missing")
        return
    end
    local ok, err = pcall(Sec.Register, ctx)
    if ok then
        G.__GAG2_AUTO_WATERING_UI_DONE = true
        _G.__GAG2_AUTO_WATERING_UI_DONE = true
    else
        warnlog("Auto Watering section error:", tostring(err))
    end
end

local function stateFromModule(mod)
    if type(mod) ~= "table" then
        return false, "state mod bukan table"
    end
    if type(mod.load) == "function" then
        local okLoad, result = pcall(function() return mod.load(mod) end)
        if okLoad and type(result) == "table" then
            return true, mod, result
        end
        -- Module sudah ada; load gagal → tetap pakai G.STATE kalau valid
        local st = G.STATE or rawget(_G, "STATE")
        if type(st) == "table" then
            warnlog("State.load gagal (pakai STATE existing):", tostring(result))
            return true, mod, st
        end
        return false, "State.load gagal: " .. tostring(result)
    end
    if type(mod.Load) == "function" then
        local okLoad, result = pcall(function() return mod.Load(mod) end)
        if okLoad and type(result) == "table" then
            return true, mod, result
        end
        local st = G.STATE or rawget(_G, "STATE")
        if type(st) == "table" then
            warnlog("State.Load gagal (pakai STATE existing):", tostring(result))
            return true, mod, st
        end
        return false, "State.Load gagal: " .. tostring(result)
    end
    local state = mod.STATE or mod.state or mod
    if type(state) == "table" then
        return true, mod, state
    end
    return false, "state result bukan table"
end

-- Shortcode di LONG STRING + loadstring = chunk terpisah (sama aman kayak state.lua HTTP).
-- Jangan inject A/B mentah ke body main_ui (bisa bikin NodeHub Compile failed).
local function compileLuaSource(src, chunkName)
    if type(src) ~= "string" or src == "" then
        return nil, "source kosong"
    end
    if hasUnreplacedShortcode(src) then
        return nil, "shortcode belum diisi di panel"
    end
    if type(load) == "function" then
        local fn, err = load(src, chunkName)
        if type(fn) == "function" then return fn, nil end
        if err then return nil, err end
    end
    if type(loadstring) == "function" then
        local fn, err = loadstring(src, chunkName)
        if type(fn) == "function" then return fn, nil end
        return nil, err or "loadstring nil"
    end
    return nil, "load/loadstring tidak tersedia"
end

local function runStateSource(src, chunkName)
    local fn, err = compileLuaSource(src, chunkName)
    if type(fn) ~= "function" then
        return false, err or "compile gagal"
    end
    local ok, res = pcall(fn)
    if not ok then
        return false, tostring(res)
    end
    return true, res
end

