local function _giftCatalogKeys()
    local G = (getgenv and getgenv()) or _G
    local ag = G.AutoGift or G.AutoGiftModule
    if type(ag) == "table" and type(ag.GetCategoryKeys) == "function" then
        local ok, keys = pcall(ag.GetCategoryKeys, ag)
        if ok and type(keys) == "table" and #keys > 0 then
            return keys
        end
    end
    return {}
end

local function _defaultGiftCategoryMap()
    local t = {}
    for _, key in ipairs(_giftCatalogKeys()) do
        t[key] = false
    end
    return t
end

