--------------------------------------------------
-- Auto Collect globals (module nanti baca ini)
--------------------------------------------------
local function _arrayToMap(arr)
    local m = {}
    if type(arr) == "table" then
        for _, v in ipairs(arr) do
            if v ~= nil and tostring(v) ~= "" then
                m[tostring(v)] = true
            end
        end
    end
    return m
end

local function _mapToArray(map)
    local arr = {}
    if type(map) ~= "table" then return arr end
    if map[1] ~= nil then
        for _, v in ipairs(map) do
            local s = tostring(v or "")
            if s ~= "" then arr[#arr + 1] = s end
        end
        table.sort(arr)
        return arr
    end
    for k, v in pairs(map) do
        if v == true then arr[#arr + 1] = tostring(k) end
    end
    table.sort(arr)
    return arr
end

local function _normalizeCollectPriority(v)
    local s = tostring(v or "off"):lower():gsub("%s+", "")
    if s == "price" or s == "highestprice" then return "price" end
    if s == "rarity" or s == "highestrarity" then return "rarity" end
    if s == "weight" or s == "heaviest" or s == "heaviestkg" or s == "kg" then return "weight" end
    if s == "off" or s == "normal" or s == "normalscanorder" then return "off" end
    return "off"
end

local function _normalizeKgFilter(kg, mode)
    kg = tonumber(kg) or 0
    mode = tostring(mode or "above")
    if kg < 0 then
        kg = math.abs(kg)
        mode = "below"
    end
    if mode ~= "below" then
        mode = "above"
    end
    return kg, mode
end

local function _normalizePriceFilter(price, mode)
    price = tonumber(price) or 0
    mode = tostring(mode or "above")
    if price < 0 then
        price = math.floor(math.abs(price))
        mode = "below"
    end
    if mode ~= "below" then
        mode = "above"
    end
    price = math.floor(math.max(0, price))
    return price, mode
end

local function _parseKgRuleInput(txt)
    txt = tostring(txt or ""):gsub("%s+", "")
    if txt == "" then return 0, "above" end
    local n = tonumber(txt)
    if not n then return 0, "above" end
    if n < 0 then return math.abs(n), "below" end
    return n, "above"
end

local function _parseScaledNumber(txt)
    txt = tostring(txt or ""):lower():gsub("%s+", ""):gsub(",", "")
    if txt == "" then return nil end
    local sign = 1
    if txt:sub(1, 1) == "-" then
        sign = -1
        txt = txt:sub(2)
    end
    local suffixes = {
        { "juta", 1000000 }, { "jt", 1000000 },
        { "ribu", 1000 }, { "rb", 1000 },
        { "b", 1000000000 }, { "m", 1000000 }, { "k", 1000 },
    }
    for _, pair in ipairs(suffixes) do
        local suf, mult = pair[1], pair[2]
        if #txt > #suf and txt:sub(-#suf) == suf then
            local n = tonumber(txt:sub(1, -#suf - 1))
            if n then return n * mult * sign end
        end
    end
    local n = tonumber(txt)
    if n then return n * sign end
    return nil
end

local function _parsePriceRuleInput(txt)
    local n = _parseScaledNumber(txt)
    if not n then return 0, "above" end
    if n < 0 then return math.floor(math.abs(n)), "below" end
    return math.floor(n), "above"
end

local function _formatKgRule(kg, mode)
    kg = tonumber(kg) or 0
    mode = tostring(mode or "above")
    if kg <= 0 then return "0" end
    if mode == "below" then return "-" .. tostring(kg) end
    return tostring(kg)
end

local function _formatPriceRule(price, mode)
    price = tonumber(price) or 0
    mode = tostring(mode or "above")
    if price <= 0 then return "0" end
    if mode == "below" then return "-" .. tostring(price) end
    return tostring(price)
end

local function _normalizeCollectRuleState(raw)
    raw = type(raw) == "table" and raw or {}
    local function ruleSetToArray(src)
        if type(src) ~= "table" then return {} end
        local out = {}
        for i = 1, #src do
            local v = src[i]
            if v ~= nil and tostring(v) ~= "" then out[#out + 1] = tostring(v) end
        end
        if #out > 0 then
            table.sort(out)
            return out
        end
        for k, v in pairs(src) do
            if v == true or v == 1 or v == "true" then
                out[#out + 1] = tostring(k)
            end
        end
        table.sort(out)
        return out
    end
    local fruits = ruleSetToArray(raw.fruits)
    local mutations = ruleSetToArray(raw.mutations)
    local kg, kgMode = _normalizeKgFilter(raw.kg, raw.kgMode)
    if type(raw.kgRule) == "string" and raw.kgRule:gsub("%s+", "") ~= "" then
        kg, kgMode = _parseKgRuleInput(raw.kgRule)
    end
    local minPrice, minPriceMode = _normalizePriceFilter(raw.minPrice, raw.minPriceMode)
    if type(raw.priceRule) == "string" and raw.priceRule:gsub("%s+", "") ~= "" then
        minPrice, minPriceMode = _parsePriceRuleInput(raw.priceRule)
    end
    return {
        id = tostring(raw.id or ""),
        enabled = raw.enabled ~= false,
        fruits = fruits,
        mutations = mutations,
        kg = kg,
        kgMode = kgMode,
        kgRule = type(raw.kgRule) == "string" and raw.kgRule ~= ""
            and raw.kgRule or _formatKgRule(kg, kgMode),
        minPrice = minPrice,
        minPriceMode = minPriceMode,
        priceRule = type(raw.priceRule) == "string" and raw.priceRule ~= ""
            and raw.priceRule or _formatPriceRule(minPrice, minPriceMode),
        requireMut = raw.requireMut == true,
    }
end

local function _hasLegacyCollectFilter(ac)
    if type(ac.fruits) == "table" and #ac.fruits > 0 then return true end
    if type(ac.mutations) == "table" and #ac.mutations > 0 then return true end
    if tonumber(ac.kg) and tonumber(ac.kg) > 0 then return true end
    if tonumber(ac.minPrice) and tonumber(ac.minPrice) > 0 then return true end
    return false
end

local function _migrateLegacyFruitRules(st, idPrefix)
    st.rules = type(st.rules) == "table" and st.rules or {}
    st.rulesOrder = type(st.rulesOrder) == "table" and st.rulesOrder or {}
    if #st.rules > 0 then
        st.filterMode = "rules"
        return st
    end
    if not _hasLegacyCollectFilter(st) then
        st.filterMode = "rules"
        return st
    end
    idPrefix = tostring(idPrefix or "migrated")
    local ruleId = idPrefix .. "_" .. tostring(os.time())
    st.rules = {
        {
            id = ruleId,
            enabled = true,
            fruits = type(st.fruits) == "table" and st.fruits or {},
            mutations = type(st.mutations) == "table" and st.mutations or {},
            kg = tonumber(st.kg) or 0,
            kgMode = tostring(st.kgMode or "above"),
            kgRule = type(st.kgRule) == "string" and st.kgRule or _formatKgRule(st.kg, st.kgMode),
            minPrice = tonumber(st.minPrice) or 0,
            minPriceMode = tostring(st.minPriceMode or "above"),
            priceRule = type(st.priceRule) == "string" and st.priceRule ~= "" and st.priceRule
                or (type(st.minPriceRule) == "string" and st.minPriceRule ~= "" and st.minPriceRule
                or _formatPriceRule(st.minPrice, st.minPriceMode)),
            requireMut = false,
        },
    }
    st.rulesOrder = { ruleId }
    st.filterMode = "rules"
    return st
end

local function _normalizeRulesState(st, idPrefix)
    st = _migrateLegacyFruitRules(st, idPrefix)
    st.filterMode = "rules"
    st.rules = type(st.rules) == "table" and st.rules or {}
    st.rulesOrder = type(st.rulesOrder) == "table" and st.rulesOrder or {}
    local byId, order, seen = {}, {}, {}
    for i, raw in ipairs(st.rules) do
        local rule = _normalizeCollectRuleState(raw)
        if rule.id == "" then
            rule.id = "r" .. tostring(i)
        end
        byId[rule.id] = rule
    end
    for id, raw in pairs(st.rules) do
        if type(raw) == "table" and type(id) ~= "number" then
            local rule = _normalizeCollectRuleState(raw)
            rule.id = tostring(rule.id ~= "" and rule.id or id)
            byId[rule.id] = rule
        end
    end
    for _, id in ipairs(st.rulesOrder) do
        id = tostring(id or "")
        local rule = byId[id]
        if rule and not seen[id] then
            seen[id] = true
            order[#order + 1] = rule
        end
    end
    for id, rule in pairs(byId) do
        if not seen[id] then
            order[#order + 1] = rule
        end
    end
    st.rules = order
    st.rulesOrder = {}
    for _, rule in ipairs(order) do
        st.rulesOrder[#st.rulesOrder + 1] = rule.id
    end
    return st
end

local function _migrateLegacyCollectToRules(ac)
    return _migrateLegacyFruitRules(ac, "migrated_collect")
end

local function _normalizeAutoCollectState(ac)
    ac = type(ac) == "table" and ac or _deepCopy(DEFAULT_AUTO.collect)
    ac.enabled   = (ac.enabled == true)
    ac.delay     = tonumber(ac.delay)
    if ac.delay == nil then ac.delay = 0.1 end
    if ac.delay < 0 then ac.delay = 0 end
    if ac.delay > 1 then ac.delay = 1 end
    ac.priority  = _normalizeCollectPriority(ac.priority)
    return _normalizeRulesState(ac, "migrated_collect")
end

local function syncAutoCollectGlobalsFromMain()
    MAIN.auto = MAIN.auto or _deepCopy(DEFAULT_AUTO)
    MAIN.auto.collect = _normalizeAutoCollectState(MAIN.auto.collect)
    local ac = MAIN.auto.collect

    AUTO_COLLECT_FRUIT_ENABLED = ac.enabled
    G.AUTO_COLLECT_FRUIT_ENABLED = ac.enabled
    _G.AUTO_COLLECT_FRUIT_ENABLED = ac.enabled

    AUTO_COLLECT_FRUITS_SELECTED = {}
    G.AUTO_COLLECT_FRUITS_SELECTED = AUTO_COLLECT_FRUITS_SELECTED
    _G.AUTO_COLLECT_FRUITS_SELECTED = AUTO_COLLECT_FRUITS_SELECTED

    AUTO_COLLECT_MUTATIONS_SELECTED = {}
    G.AUTO_COLLECT_MUTATIONS_SELECTED = AUTO_COLLECT_MUTATIONS_SELECTED
    _G.AUTO_COLLECT_MUTATIONS_SELECTED = AUTO_COLLECT_MUTATIONS_SELECTED

    G.AUTO_COLLECT_KG = 0
    _G.AUTO_COLLECT_KG = 0
    G.AUTO_COLLECT_KG_MODE = "above"
    _G.AUTO_COLLECT_KG_MODE = "above"
    G.AUTO_COLLECT_KG_RULE = "0"
    _G.AUTO_COLLECT_KG_RULE = "0"
    G.AUTO_COLLECT_DELAY = ac.delay
    _G.AUTO_COLLECT_DELAY = ac.delay
    G.AUTO_COLLECT_PRIORITY = ac.priority
    _G.AUTO_COLLECT_PRIORITY = ac.priority

    G.AUTO_COLLECT_FILTER_MODE = ac.filterMode
    _G.AUTO_COLLECT_FILTER_MODE = ac.filterMode
    G.AUTO_COLLECT_RULES = ac.rules
    _G.AUTO_COLLECT_RULES = ac.rules
    G.AUTO_COLLECT_RULES_ORDER = ac.rulesOrder
    _G.AUTO_COLLECT_RULES_ORDER = ac.rulesOrder

    STATE.auto_collect = _deepCopy(ac)
    G.MAIN = MAIN
    _G.MAIN = MAIN
end

