--------------------------------------------------
-- Auto Plant globals
--------------------------------------------------
local function _normalizePlantPositionId(v)
    if v == nil then return nil end
    if type(v) == "table" then
        v = v.id or v.key
    end
    v = tostring(v)
    if v == "" or v:sub(1, 6) == "table:" then return nil end
    return v
end

local function _normalizePlantPositionEntry(entry)
    if type(entry) ~= "table" then return nil end
    local id = _normalizePlantPositionId(entry.id)
    if not id then return nil end
    local out = {
        id = id,
        x = tonumber(entry.x) or 0,
        y = tonumber(entry.y) or 0,
        z = tonumber(entry.z) or 0,
    }
    local refX, refY, refZ = tonumber(entry.refX), tonumber(entry.refY), tonumber(entry.refZ)
    if refX and refY and refZ then
        out.refX, out.refY, out.refZ = refX, refY, refZ
    end
    if entry.plotId ~= nil then
        out.plotId = tonumber(entry.plotId) or entry.plotId
    end
    return out
end

local function _normalizeAutoPlantState(ap)
    ap = type(ap) == "table" and ap or _deepCopy(DEFAULT_AUTO.plant)
    ap.enabled = (ap.enabled == true)
    ap.seeds = type(ap.seeds) == "table" and ap.seeds or {}
    local positions = {}
    if type(ap.positions) == "table" then
        for _, entry in ipairs(ap.positions) do
            local norm = _normalizePlantPositionEntry(entry)
            if norm then positions[#positions + 1] = norm end
        end
    end
    ap.positions = positions
    if ap.delay ~= nil then
        ap.delay = tonumber(ap.delay)
    end
    if ap.delay == nil then ap.delay = 0.5 end
    if ap.delay < 0 then ap.delay = 0 end
    ap.mode = tostring(ap.mode or "random"):lower()
    if ap.mode ~= "manual" and ap.mode ~= "center" then ap.mode = "random" end
    ap.selectedPositions = _mapToArray(ap.selectedPositions)
    ap.selectedPosition = _normalizePlantPositionId(ap.selectedPosition)
    if ap.selectedPosition and #ap.selectedPositions == 0 then
        ap.selectedPositions = { ap.selectedPosition }
    end
    local validSelected = {}
    for _, id in ipairs(ap.selectedPositions) do
        id = _normalizePlantPositionId(id)
        if id then
            for _, entry in ipairs(ap.positions) do
                if entry.id == id then
                    validSelected[#validSelected + 1] = id
                    break
                end
            end
        end
    end
    ap.selectedPositions = validSelected
    ap.selectedPosition = validSelected[1] or nil
    ap.savePosition = false
    ap.autoManual = false
    if ap.plantTotal ~= nil then
        ap.plantTotal = tonumber(ap.plantTotal)
    end
    if ap.plantTotal == nil then ap.plantTotal = 0 end
    if ap.plantTotal < 0 then ap.plantTotal = 0 end
    ap.plantTotal = math.floor(ap.plantTotal)
    return ap
end

local function _normalizeAutoTrowelState(st)
    st = type(st) == "table" and st or _deepCopy(DEFAULT_AUTO.trowel)
    st.enabled = (st.enabled == true)
    st.positions = type(st.positions) == "table" and st.positions or {}
    if st.delay ~= nil then
        st.delay = tonumber(st.delay)
    end
    if st.delay == nil then st.delay = 1 end
    if st.delay < 0 then st.delay = 0 end
    st.selectedPosition = _normalizePlantPositionId(st.selectedPosition)
    if st.selectedPosition then
        local found = false
        for _, entry in ipairs(st.positions) do
            if type(entry) == "table" and tostring(entry.id) == st.selectedPosition then
                found = true
                break
            end
        end
        if not found then
            st.selectedPosition = nil
        end
    end
    if not st.selectedPosition and #st.positions > 0 then
        local first = st.positions[1]
        if type(first) == "table" and first.id then
            st.selectedPosition = tostring(first.id)
        end
    end
    -- plants (multi) + migrate legacy selectedPlant
    local plantsArr = {}
    local seenPlant = {}
    local function pushPlant(v)
        if type(v) == "table" then
            v = v.key or v.name or v.id
        end
        v = tostring(v or "")
        if v == "" or v == "_none" or v:sub(1, 6) == "table:" then return end
        if seenPlant[v] then return end
        seenPlant[v] = true
        plantsArr[#plantsArr + 1] = v
    end
    if type(st.plants) == "table" then
        if st.plants[1] ~= nil then
            for _, v in ipairs(st.plants) do pushPlant(v) end
        else
            for k, v in pairs(st.plants) do
                if v == true then pushPlant(k) else pushPlant(v) end
            end
        end
    end
    if type(st.selectedPlant) == "table" then
        st.selectedPlant = st.selectedPlant.key or st.selectedPlant.name or st.selectedPlant.id
    end
    if st.selectedPlant ~= nil and tostring(st.selectedPlant) ~= "" then
        st.selectedPlant = tostring(st.selectedPlant)
        if st.selectedPlant == "_none" or st.selectedPlant:sub(1, 6) == "table:" then
            st.selectedPlant = nil
        end
    else
        st.selectedPlant = nil
    end
    if #plantsArr == 0 and st.selectedPlant then
        pushPlant(st.selectedPlant)
    end
    st.plants = plantsArr
    -- keep selectedPlant as first entry for older UI/module reads
    st.selectedPlant = plantsArr[1]
    st.savePosition = false
    if st.moveTotal ~= nil then
        st.moveTotal = tonumber(st.moveTotal)
    end
    if st.moveTotal == nil then st.moveTotal = 0 end
    if st.moveTotal < 0 then st.moveTotal = 0 end
    st.moveTotal = math.floor(st.moveTotal)
    if st.rotation ~= nil then
        st.rotation = tonumber(st.rotation) or 0
    end
    if st.rotation == nil then st.rotation = 0 end
    st.rotation = st.rotation % 360
    st.enabled = false
    return st
end

local function _normalizeSprinklerLocationEntry(entry)
    if type(entry) ~= "table" then return nil end
    local id = _normalizePlantPositionId(entry.id)
    if not id then return nil end
    local out = {
        id = id,
        x = tonumber(entry.x) or 0,
        y = tonumber(entry.y) or 0,
        z = tonumber(entry.z) or 0,
    }
    local refX, refY, refZ = tonumber(entry.refX), tonumber(entry.refY), tonumber(entry.refZ)
    if refX and refY and refZ then
        out.refX, out.refY, out.refZ = refX, refY, refZ
    end
    if entry.plotId ~= nil then
        out.plotId = tonumber(entry.plotId) or entry.plotId
    end
    return out
end

local function _normalizeAutoSprinklerState(st)
    st = type(st) == "table" and st or _deepCopy(DEFAULT_AUTO.sprinkler)
    st.enabled = (st.enabled == true)
    st.sprinklers = type(st.sprinklers) == "table" and st.sprinklers or {}
    st.plants = type(st.plants) == "table" and st.plants or {}
    st.mode = tostring(st.mode or "random"):lower()
    if st.mode ~= "near_plant" and st.mode ~= "location" and st.mode ~= "center" then
        st.mode = "random"
    end
    local locs = {}
    if type(st.locations) == "table" then
        for _, entry in ipairs(st.locations) do
            local norm = _normalizeSprinklerLocationEntry(entry)
            if norm then locs[#locs + 1] = norm end
        end
    end
    st.locations = locs
    st.selectedLocations = _mapToArray(st.selectedLocations)
    local validSelected = {}
    for _, id in ipairs(st.selectedLocations) do
        for _, entry in ipairs(st.locations) do
            if entry.id == id then
                validSelected[#validSelected + 1] = id
                break
            end
        end
    end
    st.selectedLocations = validSelected
    st.saveLocation = false
    if st.delay ~= nil then
        st.delay = tonumber(st.delay)
    end
    if st.delay == nil then st.delay = 2 end
    if st.delay < 0 then st.delay = 0 end
    if st.settleDelay ~= nil then
        st.settleDelay = tonumber(st.settleDelay)
    end
    if st.settleDelay == nil then st.settleDelay = 0 end
    if st.settleDelay < 0 then st.settleDelay = 0 end
    st.pauseSkippedFruit = math.floor(tonumber(st.pauseSkippedFruit) or 0)
    if st.pauseSkippedFruit < 0 then st.pauseSkippedFruit = 0 end
    st.pauseCollectFruit = math.floor(tonumber(st.pauseCollectFruit) or 0)
    if st.pauseCollectFruit < 0 then st.pauseCollectFruit = 0 end
    st.pauseBackpackTotal = math.floor(tonumber(st.pauseBackpackTotal) or 0)
    if st.pauseBackpackTotal < 0 then st.pauseBackpackTotal = 0 end
    st.minFruitHarvest = nil
    st.maxFruitHarvest = nil
    return st
end

local function _normalizeAutoWateringState(st)
    st = type(st) == "table" and st or _deepCopy(DEFAULT_AUTO.watering)
    st.enabled = (st.enabled == true)
    st.plants = type(st.plants) == "table" and st.plants or {}
    st.cans = type(st.cans) == "table" and st.cans or {}
    if st.delay ~= nil then
        st.delay = tonumber(st.delay)
    end
    if st.delay == nil then st.delay = 3 end
    if st.delay < 0 then st.delay = 0 end
    if st.settleDelay ~= nil then
        st.settleDelay = tonumber(st.settleDelay)
    end
    if st.settleDelay == nil then st.settleDelay = 0 end
    if st.settleDelay < 0 then st.settleDelay = 0 end
    st.pauseSkippedFruit = math.floor(tonumber(st.pauseSkippedFruit) or 0)
    if st.pauseSkippedFruit < 0 then st.pauseSkippedFruit = 0 end
    st.pauseCollectFruit = math.floor(tonumber(st.pauseCollectFruit) or 0)
    if st.pauseCollectFruit < 0 then st.pauseCollectFruit = 0 end
    st.pauseBackpackTotal = math.floor(tonumber(st.pauseBackpackTotal) or 0)
    if st.pauseBackpackTotal < 0 then st.pauseBackpackTotal = 0 end
    local tpMode = tostring(st.tpMode or "below"):lower()
    if tpMode == "atas" or tpMode == "top" or tpMode == "over" or tpMode == "above" then
        tpMode = "above"
    else
        tpMode = "below"
    end
    st.tpMode = tpMode
    st.minFruitHarvest = nil
    st.maxFruitHarvest = nil
    return st
end

local function _normalizeAutoPlotState(st)
    st = type(st) == "table" and st or _deepCopy(DEFAULT_AUTO.plot)
    st.autoPot = (st.autoPot == true)
    st.autoPlace = (st.autoPlace == true)
    st.autoCollect = (st.autoCollect == true)
    st.plants = type(st.plants) == "table" and st.plants or {}
    st.placedPlants = type(st.placedPlants) == "table" and st.placedPlants or {}
    st.placeTools = type(st.placeTools) == "table" and st.placeTools or {}
    st.slots = type(st.slots) == "table" and st.slots or {}
    st.selectedSlots = type(st.selectedSlots) == "table" and st.selectedSlots or {}
    st.selectedSlot = _normalizePlantPositionId(st.selectedSlot)
    if st.potDelay ~= nil then
        st.potDelay = tonumber(st.potDelay)
    end
    if st.potDelay == nil then st.potDelay = 1.5 end
    if st.potDelay > 0 and st.potDelay < 0.1 then st.potDelay = 0.1 end
    if st.placeDelay ~= nil then
        st.placeDelay = tonumber(st.placeDelay)
    end
    if st.placeDelay == nil then st.placeDelay = 1 end
    if st.placeDelay > 0 and st.placeDelay < 0.1 then st.placeDelay = 0.1 end
    if st.collectDelay ~= nil then
        st.collectDelay = tonumber(st.collectDelay)
    end
    if st.collectDelay == nil then st.collectDelay = 1 end
    if st.collectDelay > 0 and st.collectDelay < 0.1 then st.collectDelay = 0.1 end
    if st.potTotal ~= nil then
        st.potTotal = tonumber(st.potTotal)
    end
    if st.potTotal == nil then st.potTotal = 0 end
    if st.potTotal < 0 then st.potTotal = 0 end
    st.potTotal = math.floor(st.potTotal)
    if st.placeTotal ~= nil then
        st.placeTotal = tonumber(st.placeTotal)
    end
    if st.placeTotal == nil then st.placeTotal = 0 end
    if st.placeTotal < 0 then st.placeTotal = 0 end
    st.placeTotal = math.floor(st.placeTotal)
    if st.collectTotal ~= nil then
        st.collectTotal = tonumber(st.collectTotal)
    end
    if st.collectTotal == nil then st.collectTotal = 0 end
    if st.collectTotal < 0 then st.collectTotal = 0 end
    st.collectTotal = math.floor(st.collectTotal)
    st.placeMode = tostring(st.placeMode or "saved"):lower()
    if st.placeMode ~= "saved" then st.placeMode = "saved" end
    st.saveSlot = false
    if st.rotation ~= nil then
        st.rotation = tonumber(st.rotation) or 0
    end
    if st.rotation == nil then st.rotation = 0 end
    st.rotation = st.rotation % 360
    return st
end

