-- Auto Fav / Unfav globals
--------------------------------------------------
local function _normalizeAutoFavState(st)
    st = type(st) == "table" and st or _deepCopy(DEFAULT_AUTO.fav)
    st.enabled   = (st.enabled == true)
    st.fruits    = type(st.fruits) == "table" and st.fruits or {}
    st.mutations = type(st.mutations) == "table" and st.mutations or {}

    if type(st.kgRule) == "string" and st.kgRule:gsub("%s+", "") ~= "" then
        local rule = st.kgRule:gsub("%s+", "")
        local n = tonumber(rule)
        if n then
            if n < 0 then
                st.kg = math.abs(n)
                st.kgMode = "below"
            else
                st.kg = n
                st.kgMode = "above"
            end
        end
    end
    st.kg, st.kgMode = _normalizeKgFilter(st.kg, st.kgMode)
    if type(st.kgRule) ~= "string" or st.kgRule:gsub("%s+", "") == "" then
        if st.kgMode == "below" and st.kg > 0 then
            st.kgRule = "-" .. tostring(st.kg)
        else
            st.kgRule = tostring(st.kg or 0)
        end
    end

    if type(st.minPriceRule) == "string" and st.minPriceRule:gsub("%s+", "") ~= "" then
        local rule = st.minPriceRule:gsub("%s+", ""):gsub(",", "")
        local n = tonumber(rule)
        if n and n ~= 0 then
            if n < 0 then
                st.minPrice = math.floor(math.abs(n))
                st.minPriceMode = "below"
            else
                st.minPrice = math.floor(n)
                st.minPriceMode = "above"
            end
        end
    end
    st.minPrice, st.minPriceMode = _normalizePriceFilter(st.minPrice, st.minPriceMode)
    if type(st.minPriceRule) ~= "string" or st.minPriceRule:gsub("%s+", "") == "" then
        if st.minPriceMode == "below" and st.minPrice > 0 then
            st.minPriceRule = "-" .. tostring(st.minPrice)
        else
            st.minPriceRule = tostring(st.minPrice or 0)
        end
    end

    st.delay = tonumber(st.delay) or 0.2
    if st.delay < 0.15 then st.delay = 0.15 end
    return st
end

local _normalizeAutoUnfavState = _normalizeAutoFavState

