local function _normalizeAutoSellStockState(st)
    local d = DEFAULT_AUTO.sellStock
    st = type(st) == "table" and st or _deepCopy(d)
    st.enabled = (st.enabled == true)
    st.minMult = tonumber(st.minMult)
    if st.minMult == nil then st.minMult = d.minMult end
    if st.minMult < 0 then st.minMult = 0 end
    st.minBackpackCount = tonumber(st.minBackpackCount)
    if st.minBackpackCount == nil then st.minBackpackCount = d.minBackpackCount end
    if st.minBackpackCount < 1 then st.minBackpackCount = 1 end
    st.minTotalValue = tonumber(st.minTotalValue)
    if st.minTotalValue == nil then st.minTotalValue = d.minTotalValue end
    if st.minTotalValue < 0 then st.minTotalValue = 0 end
    st.autoUnfav = (st.autoUnfav == true)
    return st
end

local function _normalizeAutoSellDailyState(st)
    local d = DEFAULT_AUTO.sellDaily
    st = type(st) == "table" and st or _deepCopy(d)
    st.enabled = (st.enabled == true)
    st.minBackpackCount = tonumber(st.minBackpackCount)
    if st.minBackpackCount == nil then st.minBackpackCount = d.minBackpackCount end
    if st.minBackpackCount < 1 then st.minBackpackCount = 1 end
    st.minTotalValue = tonumber(st.minTotalValue)
    if st.minTotalValue == nil then st.minTotalValue = d.minTotalValue end
    if st.minTotalValue < 0 then st.minTotalValue = 0 end
    st.autoUnfav = (st.autoUnfav == true)
    return st
end

local function _normalizeAutoSellState(st)
    st = type(st) == "table" and st or _deepCopy(DEFAULT_AUTO.sell)
    -- migrate legacy nested sell.stock / sell.daily → top-level keys
    if type(st.stock) == "table" then
        MAIN.auto = MAIN.auto or {}
        if type(MAIN.auto.sellStock) ~= "table" or next(MAIN.auto.sellStock) == nil then
            MAIN.auto.sellStock = _deepCopy(st.stock)
        end
        st.stock = nil
    end
    if type(st.daily) == "table" then
        MAIN.auto = MAIN.auto or {}
        if type(MAIN.auto.sellDaily) ~= "table" or next(MAIN.auto.sellDaily) == nil then
            MAIN.auto.sellDaily = _deepCopy(st.daily)
        end
        st.daily = nil
    end
    st.enabled = (st.enabled == true)
    if st.minCount ~= nil then
        st.minCount = tonumber(st.minCount)
    end
    if st.minCount == nil then st.minCount = 100 end
    if st.minCount < 1 then st.minCount = 1 end
    if st.delay ~= nil then
        st.delay = tonumber(st.delay)
    end
    if st.delay == nil then st.delay = 2 end
    if st.delay < 0 then st.delay = 0 end
    if st.sellWhenFull == nil then
        st.sellWhenFull = true
    else
        st.sellWhenFull = (st.sellWhenFull == true)
    end
    return _normalizeRulesState(st, "migrated_sell")
end

