--------------------------------------------------
-- Auto Buy globals
--------------------------------------------------
local function _parseAuctionMaxPrice(raw)
    if type(raw) == "number" then
        return math.max(0, math.floor(raw))
    end
    local txt = tostring(raw or ""):lower():gsub("%s+", ""):gsub(",", "")
    if txt == "" then return 0 end
    local suffixes = {
        { "juta", 1000000 }, { "jt", 1000000 },
        { "ribu", 1000 }, { "rb", 1000 },
        { "b", 1000000000 }, { "m", 1000000 }, { "k", 1000 },
    }
    for _, pair in ipairs(suffixes) do
        local suf, mult = pair[1], pair[2]
        if #txt > #suf and txt:sub(-#suf) == suf then
            local n = tonumber(txt:sub(1, -#suf - 1))
            if n then return math.max(0, math.floor(n * mult)) end
        end
    end
    return math.max(0, math.floor(tonumber(txt) or 0))
end

local function _allAuctionCatMaxZero(auction)
    if type(auction) ~= "table" then return true end
    for _, key in ipairs({ "seed", "gear", "seedpack", "egg" }) do
        local cat = auction[key]
        if type(cat) == "table" and _parseAuctionMaxPrice(cat.max_price) > 0 then
            return false
        end
    end
    return true
end

local function _auctionLegacyFromSaveData(data)
    local best = 0
    local function consider(raw)
        local v = _parseAuctionMaxPrice(raw)
        if v > best then best = v end
    end
    local function scanAuction(auction)
        if type(auction) ~= "table" then return end
        consider(auction.max_price)
        consider(auction.legacy_max_price)
    end
    if type(data) ~= "table" then return 0 end
    if type(data.auto_buy) == "table" then scanAuction(data.auto_buy.auction) end
    if type(data.auto) == "table" and type(data.auto.buy) == "table" then
        scanAuction(data.auto.buy.auction)
    end
    if type(data.main) == "table" and type(data.main.auto) == "table" and type(data.main.auto.buy) == "table" then
        scanAuction(data.main.auto.buy.auction)
    end
    return best
end

local function _normalizeBuyItems(items)
    if type(items) ~= "table" then return {} end

    local arr = {}
    for _, v in ipairs(items) do
        if v ~= nil and tostring(v) ~= "" then
            arr[#arr + 1] = tostring(v)
        end
    end
    if #arr > 0 then
        table.sort(arr)
        return arr
    end

    for k, v in pairs(items) do
        if v == true or v == 1 or v == "true" then
            arr[#arr + 1] = tostring(k)
        end
    end
    table.sort(arr)
    return arr
end

local function _normalizeBuyCategory(cat)
    cat = type(cat) == "table" and cat or { enabled = false, items = {} }
    cat.enabled = (cat.enabled == true)
    cat.items = _normalizeBuyItems(cat.items)
    return cat
end

local function _normalizeAutoBuyState(buy)
    buy = type(buy) == "table" and buy or _deepCopy(DEFAULT_AUTO.buy)
    buy.delay = nil
    buy.seed = _normalizeBuyCategory(buy.seed)
    buy.gear = _normalizeBuyCategory(buy.gear)
    buy.props = _normalizeBuyCategory(buy.props)
    buy.pet = _normalizeBuyCategory(buy.pet)
    buy.pet.auto_tame = (buy.pet.auto_tame == true)
    buy.pet.max_price_mult = nil
    local stealPrice = math.floor(tonumber(buy.pet.max_steal_price) or 100000000)
    stealPrice = math.floor((stealPrice + 12500000) / 25000000) * 25000000
    if stealPrice < 25000000 then stealPrice = 25000000 end
    if stealPrice > 500000000 then stealPrice = 500000000 end
    buy.pet.max_steal_price = stealPrice
    buy.auction = type(buy.auction) == "table" and buy.auction or {
        enabled = false,
        seed = { items = {}, max_price = 0 },
        gear = { items = {}, max_price = 0 },
        seedpack = { items = {}, max_price = 0 },
        egg = { items = {}, max_price = 0 },
    }
    buy.auction.enabled = (buy.auction.enabled == true)
    buy.auction.open_auction = nil
    buy.auction.max_price = nil
    buy.auction.legacy_max_price = nil
    for _, key in ipairs({ "seed", "gear", "seedpack", "egg" }) do
        local cat = buy.auction[key]
        if type(cat) ~= "table" then cat = { items = {} } end
        cat.items = _normalizeBuyItems(cat.items)
        cat.max_price = _parseAuctionMaxPrice(cat.max_price)
        buy.auction[key] = cat
    end
    return buy
end

