local function _normalizeAutoSellPetState(st)
    st = type(st) == "table" and st or _deepCopy(DEFAULT_AUTO.sellPet)
    st.enabled = (st.enabled == true)
    local pets = {}
    local seen = {}
    local raw = st.pets
    if type(raw) == "table" then
        if raw[1] ~= nil then
            for _, v in ipairs(raw) do
                local s = tostring(v or "")
                if s ~= "" and not seen[s] then
                    seen[s] = true
                    pets[#pets + 1] = s
                end
            end
        else
            for k, v in pairs(raw) do
                if v == true or v == 1 or v == "true" then
                    local s = tostring(k or "")
                    if s ~= "" and not seen[s] then
                        seen[s] = true
                        pets[#pets + 1] = s
                    end
                end
            end
        end
    end
    table.sort(pets)
    st.pets = pets
    return st
end

