--------------------------------------------------
-- Auto Gift globals
--------------------------------------------------
local function _giftCategoryKeysFromState(st)
    local keys = {}
    local seen = {}
    local function add(key)
        key = tostring(key or "")
        if key ~= "" and not seen[key] then
            keys[#keys + 1] = key
            seen[key] = true
        end
    end
    for _, key in ipairs(_giftCatalogKeys()) do
        add(key)
    end
    if type(st) == "table" then
        if type(st.categories) == "table" then
            for key in pairs(st.categories) do
                if not seen[key] then
                    keys[#keys + 1] = key
                    seen[key] = true
                end
            end
        end
        if type(st.selected) == "table" then
            for key in pairs(st.selected) do
                if not seen[key] then
                    keys[#keys + 1] = key
                    seen[key] = true
                end
            end
        end
    end
    return keys
end

local function _migrateLegacyGiftKeys(st)
    if type(st) ~= "table" then return end
    st.categories = type(st.categories) == "table" and st.categories or {}
    st.selected = type(st.selected) == "table" and st.selected or {}
    st.send_totals = type(st.send_totals) == "table" and st.send_totals or {}
    -- Legacy save keys → current MailboxItemCatalog category names
    local aliases = { Tools = "Pets", DustyPots = "EmptyPots", InstyPots = "EmptyPots" }
    for legacy, canon in pairs(aliases) do
        if st.categories[legacy] == true then
            st.categories[canon] = true
            st.categories[legacy] = false
        end
        if type(st.selected[legacy]) == "table" and next(st.selected[legacy]) then
            st.selected[canon] = st.selected[canon] or {}
            for k, v in pairs(_normalizeBuyItems(st.selected[legacy])) do
                if v == true then st.selected[canon][k] = true end
            end
            st.selected[legacy] = {}
        end
        if st.send_totals[legacy] ~= nil and st.send_totals[canon] == nil then
            st.send_totals[canon] = st.send_totals[legacy]
        end
    end
end

local function _normalizeGiftProfileFieldsState(p, forceSingle)
    p = type(p) == "table" and p or {}
    local catKeys = _giftCategoryKeysFromState(p)
    p.categories = type(p.categories) == "table" and p.categories or {}
    for _, key in ipairs(catKeys) do
        p.categories[key] = (p.categories[key] == true)
    end
    p.selected = type(p.selected) == "table" and p.selected or {}
    for _, key in ipairs(catKeys) do
        p.selected[key] = _normalizeBuyItems(p.selected[key])
    end
    if forceSingle then
        p.category_mode = "single"
    else
        p.category_mode = (tostring(p.category_mode or "single"):lower() == "multi") and "multi" or "single"
    end
    p.send_total = math.floor(tonumber(p.send_total) or 1000)
    if p.send_total < 1 then p.send_total = 1 end
    p.harvest_price_threshold_pct = math.floor(tonumber(p.harvest_price_threshold_pct) or 10)
    if p.harvest_price_threshold_pct < 0 then p.harvest_price_threshold_pct = 0 end
    if p.harvest_price_threshold_pct > 100 then p.harvest_price_threshold_pct = 100 end
    p.harvest_price_calc_mode = (tostring(p.harvest_price_calc_mode or "base"):lower() == "stock") and "stock" or "base"
    if p.send_mode == nil then
        p.send_mode = "total"
    end
    p.send_mode = (tostring(p.send_mode or "total"):lower() == "price") and "price" or "total"
    p.auto_unfav = (p.auto_unfav == true) or (p.autoUnfav == true)
    p.autoUnfav = nil
    p.after_send_mode = (tostring(p.after_send_mode or "keep"):lower() == "reset") and "reset" or "keep"
    p.recipient_username = tostring(p.recipient_username or ""):gsub("^%s+", ""):gsub("%s+$", ""):gsub("^@", "")
    p.recipient_user_id = math.floor(tonumber(p.recipient_user_id) or 0)
    p.recipient_display = tostring(p.recipient_display or "")
    return p
end

local function _migrateGiftProfileRecipientsState(st)
    if type(st) ~= "table" then return end
    st.once = _normalizeGiftProfileFieldsState(st.once, true)
    st.loop = _normalizeGiftProfileFieldsState(st.loop, false)
    local sharedUid = math.floor(tonumber(st.recipient_user_id) or 0)
    local sharedUser = tostring(st.recipient_username or "")
    local sharedDisp = tostring(st.recipient_display or "")
    if sharedUid > 0 or sharedUser ~= "" then
        if st.once.recipient_user_id <= 0 and st.once.recipient_username == "" then
            st.once.recipient_user_id = sharedUid
            st.once.recipient_username = sharedUser
            st.once.recipient_display = sharedDisp
        end
        if st.loop.recipient_user_id <= 0 and st.loop.recipient_username == "" then
            st.loop.recipient_user_id = sharedUid
            st.loop.recipient_username = sharedUser
            st.loop.recipient_display = sharedDisp
        end
    end
    st.recipient_username = st.once.recipient_username
    st.recipient_user_id = st.once.recipient_user_id
    st.recipient_display = st.once.recipient_display
end

local function _giftProfileHasUserData(p)
    p = type(p) == "table" and p or {}
    if type(p.categories) == "table" then
        for _, v in pairs(p.categories) do
            if v == true then return true end
        end
    end
    if type(p.selected) == "table" then
        for _, v in pairs(p.selected) do
            if type(v) == "table" and next(v) ~= nil then return true end
        end
    end
    return false
end

local function _migrateGiftProfilesState(st)
    if type(st) ~= "table" then return end
    local legacyCats = type(st.categories) == "table" and st.categories or nil
    local legacySel = type(st.selected) == "table" and st.selected or nil
    if type(st.once) ~= "table" or not _giftProfileHasUserData(st.once) then
        if type(legacyCats) == "table" or type(legacySel) == "table" then
            st.once = {
                categories = legacyCats and _deepCopy(legacyCats) or _defaultGiftCategoryMap(),
                selected = legacySel and _deepCopy(legacySel) or _defaultGiftSelectedMap(),
                category_mode = "single",
                send_total = st.send_total,
                after_send_mode = st.after_send_mode,
            }
        elseif type(st.once) ~= "table" then
            st.once = {
                categories = _defaultGiftCategoryMap(),
                selected = _defaultGiftSelectedMap(),
                category_mode = "single",
                send_total = st.send_total,
                after_send_mode = st.after_send_mode,
            }
        end
    end
    if type(st.loop) ~= "table" or not _giftProfileHasUserData(st.loop) then
        if type(legacyCats) == "table" or type(legacySel) == "table" then
            local loopCats = _defaultGiftCategoryMap()
            local loopSel = _defaultGiftSelectedMap()
            if type(legacyCats) == "table" then
                for k, v in pairs(legacyCats) do loopCats[k] = v end
            end
            if type(legacySel) == "table" then
                for k, v in pairs(legacySel) do loopSel[k] = _deepCopy(v) end
            end
            st.loop = {
                categories = loopCats,
                selected = loopSel,
                category_mode = st.category_mode,
                after_send_mode = st.after_send_mode,
            }
        elseif type(st.loop) ~= "table" then
            st.loop = {
                categories = _defaultGiftCategoryMap(),
                selected = _defaultGiftSelectedMap(),
                category_mode = st.category_mode,
                after_send_mode = st.after_send_mode,
            }
        end
    end
    st.once = _normalizeGiftProfileFieldsState(st.once, true)
    st.loop = _normalizeGiftProfileFieldsState(st.loop, false)
    _migrateGiftProfileRecipientsState(st)
end

local function _giftProfileStoreFromMainProfile(profile, forceSingle)
    profile = _normalizeGiftProfileFieldsState(profile, forceSingle == true)
    local categories = {}
    local selected = {}
    local catKeys = _giftCategoryKeysFromState(profile)
    for _, key in ipairs(catKeys) do
        categories[key] = (profile.categories[key] == true)
        selected[key] = _arrayToMap(profile.selected[key])
    end
    return {
        categories = categories,
        selected = selected,
        category_mode = forceSingle and "single" or profile.category_mode,
        send_total = profile.send_total,
        after_send_mode = profile.after_send_mode,
        harvest_price_threshold_pct = profile.harvest_price_threshold_pct,
        harvest_price_calc_mode = profile.harvest_price_calc_mode,
        send_mode = profile.send_mode,
        auto_unfav = (profile.auto_unfav == true),
        recipient_username = profile.recipient_username,
        recipient_user_id = profile.recipient_user_id,
        recipient_display = profile.recipient_display,
    }
end

local function _giftProfilePayloadFromStoreProfile(profile, forceSingle)
    profile = type(profile) == "table" and profile or {}
    local catKeys = _giftCategoryKeysFromState(profile)
    local categories = {}
    local selected = {}
    for _, key in ipairs(catKeys) do
        categories[key] = (type(profile.categories) == "table" and profile.categories[key] == true)
        selected[key] = _normalizeBuyItems(profile.selected and profile.selected[key])
    end
    return {
        categories = categories,
        selected = selected,
        category_mode = (forceSingle == true) and "single"
            or ((tostring(profile.category_mode or "single"):lower() == "multi") and "multi" or "single"),
        send_total = math.floor(tonumber(profile.send_total) or 1000),
        after_send_mode = (tostring(profile.after_send_mode or "keep"):lower() == "reset") and "reset" or "keep",
        harvest_price_threshold_pct = math.floor(tonumber(profile.harvest_price_threshold_pct) or 10),
        harvest_price_calc_mode = (tostring(profile.harvest_price_calc_mode or "base"):lower() == "stock") and "stock" or "base",
        send_mode = (tostring(profile.send_mode or "total"):lower() == "price") and "price" or "total",
        auto_unfav = (profile.auto_unfav == true) or (profile.autoUnfav == true),
        recipient_username = tostring(profile.recipient_username or ""),
        recipient_user_id = math.floor(tonumber(profile.recipient_user_id) or 0),
        recipient_display = tostring(profile.recipient_display or ""),
    }
end

local function _normalizeAutoGiftState(st)
    st = type(st) == "table" and st or _deepCopy(DEFAULT_AUTO.gift)
    _migrateLegacyGiftKeys(st)
    st.enabled = (st.enabled == true)
    st.auto_send = (st.auto_send == true)
    st.auto_claim_mail = (st.auto_claim_mail == true)
    st.auto_accept_gift = (st.auto_accept_gift == true)
    st.auto_claim_drop = (st.auto_claim_drop == true)
    st.recipient_username = tostring(st.recipient_username or "")
    st.recipient_user_id = math.floor(tonumber(st.recipient_user_id) or 0)
    st.recipient_display = tostring(st.recipient_display or "")
    st.skip_equipped = (st.skip_equipped ~= false)
    st.max_per_batch = math.floor(math.max(1, math.min(999999, tonumber(st.max_per_batch) or 999999)))
    if st.max_per_batch == 1000 or st.max_per_batch == 9999 or st.max_per_batch == 10000 then
        st.max_per_batch = 999999
    end
    st.note = tostring(st.note or "")
    st.delay_sec = tonumber(st.delay_sec) or 10
    if st.delay_sec < 10 then st.delay_sec = 10 end
    if st.delay_sec > 120 then st.delay_sec = 120 end

    st.categories = type(st.categories) == "table" and st.categories or {}
    local catKeys = _giftCategoryKeysFromState(st)
    for _, key in ipairs(catKeys) do
        st.categories[key] = (st.categories[key] == true)
    end

    st.selected = type(st.selected) == "table" and st.selected or {}
    for _, key in ipairs(catKeys) do
        st.selected[key] = _normalizeBuyItems(st.selected[key])
    end

    st.send_totals = type(st.send_totals) == "table" and st.send_totals or {}
    for _, key in ipairs(catKeys) do
        local n = math.floor(tonumber(st.send_totals[key]) or 20)
        if n < 1 then n = 1 end
        st.send_totals[key] = n
    end

    st.category_mode = tostring(st.category_mode or "single"):lower()
    if st.category_mode ~= "multi" then st.category_mode = "single" end

    local slm = tostring(st.send_list_mode or "loop"):lower():gsub("%s+", "")
    if slm == "sendtotal" or slm == "send_total" or slm == "total" then
        st.send_list_mode = "send_total"
    else
        st.send_list_mode = "loop"
    end

    st.send_total = math.floor(tonumber(st.send_total) or 1000)
    if st.send_total < 1 then st.send_total = 1 end

    st.after_send_mode = tostring(st.after_send_mode or "keep"):lower()
    if st.after_send_mode ~= "reset" then st.after_send_mode = "keep" end

    st.show_gift_history = (st.show_gift_history == true)
    st.gift_history_retain_days = math.floor(math.max(1, math.min(90, tonumber(st.gift_history_retain_days) or 7)))

    _migrateGiftProfilesState(st)
    _migrateGiftProfileRecipientsState(st)
    st.once = _normalizeGiftProfileFieldsState(st.once, true)
    st.loop = _normalizeGiftProfileFieldsState(st.loop, false)
    st.categories = _deepCopy(st.once.categories)
    st.selected = _deepCopy(st.once.selected)
    st.send_total = st.once.send_total
    st.after_send_mode = st.once.after_send_mode
    st.recipient_username = st.once.recipient_username
    st.recipient_user_id = st.once.recipient_user_id
    st.recipient_display = st.once.recipient_display
    st.category_mode = st.loop.category_mode

    return st
end

local function _normalizeAutoNormalGiftState(st)
    st = type(st) == "table" and st or _deepCopy(DEFAULT_AUTO.normalGift)
    st.target_user_id = math.floor(tonumber(st.target_user_id) or 0)
    st.target_name = tostring(st.target_name or "")
    local cat = tostring(st.category or "Seeds")
    if cat == "" then cat = "Seeds" end
    st.category = cat
    st.selected = _normalizeBuyItems(st.selected)
    st.send_mode = (tostring(st.send_mode or "total"):lower() == "price") and "price" or "total"
    st.harvest_price_threshold_pct = math.floor(tonumber(st.harvest_price_threshold_pct) or 10)
    if st.harvest_price_threshold_pct < 0 then st.harvest_price_threshold_pct = 0 end
    if st.harvest_price_threshold_pct > 100 then st.harvest_price_threshold_pct = 100 end
    st.harvest_price_calc_mode = (tostring(st.harvest_price_calc_mode or "base"):lower() == "stock") and "stock" or "base"
    if st.teleport_to_target == nil then st.teleport_to_target = true end
    st.teleport_to_target = (st.teleport_to_target == true)
    local catNorm = cat:lower():gsub("[%s_]+", "")
    local isHarvest = catNorm == "harvestedfruits" or catNorm == "harvestedfruit" or catNorm == "harvestedfruid"
    if st.send_mode == "price" and isHarvest then
        st.send_total = math.floor(math.max(1, tonumber(st.send_total) or 1000))
    else
        st.send_total = math.floor(math.max(1, tonumber(st.send_total) or 1))
    end
    return st
end

local function _normalizeAutoDropState(st)
    st = type(st) == "table" and st or _deepCopy(DEFAULT_AUTO.dropItem)
    local cat = tostring(st.category or "Seeds")
    if cat == "" then cat = "Seeds" end
    st.category = cat
    st.selected = _normalizeBuyItems(st.selected)
    st.drop_total = math.floor(math.max(1, tonumber(st.drop_total) or 1))
    local delay = tonumber(st.drop_delay_sec) or 1
    if delay < 0 then delay = 0 end
    if delay > 30 then delay = 30 end
    st.drop_delay_sec = delay
    st.target_user_id = math.floor(tonumber(st.target_user_id) or 0)
    st.target_name = tostring(st.target_name or "")
    if st.teleport_to_target == nil then st.teleport_to_target = true end
    st.teleport_to_target = (st.teleport_to_target == true)
    return st
end

local function _giftSelectedMapsFromMain(gift)
    local out = {}
    gift = type(gift) == "table" and gift or {}
    local sel = type(gift.selected) == "table" and gift.selected or {}
    local catKeys = _giftCategoryKeysFromState(gift)
    for _, key in ipairs(catKeys) do
        out[key] = _arrayToMap(sel[key])
    end
    return out
end

local function _giftSelectedArraysFromMaps(maps)
    local out = {}
    maps = type(maps) == "table" and maps or {}
    local catKeys = _giftCategoryKeysFromState({ selected = maps })
    for _, key in ipairs(catKeys) do
        out[key] = _normalizeBuyItems(maps[key])
    end
    return out
end

local function _replaceGiftStoreFromMain()
    MAIN.auto = MAIN.auto or _deepCopy(DEFAULT_AUTO)
    MAIN.auto.gift = _normalizeAutoGiftState(MAIN.auto.gift)
    local st = MAIN.auto.gift

    G.__GAG2_AUTO_GIFT = {
        enabled = st.enabled,
        auto_send = st.auto_send,
        auto_claim_mail = st.auto_claim_mail,
        auto_accept_gift = st.auto_accept_gift,
        auto_claim_drop = st.auto_claim_drop,
        recipient_username = st.recipient_username,
        recipient_user_id = st.recipient_user_id,
        recipient_display = st.recipient_display,
        skip_equipped = st.skip_equipped,
        max_per_batch = st.max_per_batch,
        note = st.note,
        delay_sec = st.delay_sec,
        send_totals = _deepCopy(st.send_totals),
        once = _giftProfileStoreFromMainProfile(st.once, true),
        loop = _giftProfileStoreFromMainProfile(st.loop, false),
        categories = _deepCopy(st.categories),
        selected = _giftSelectedMapsFromMain(st),
        category_mode = st.category_mode,
        send_list_mode = st.send_list_mode,
        send_total = st.send_total,
        after_send_mode = st.after_send_mode,
        show_gift_history = st.show_gift_history,
        gift_history_retain_days = st.gift_history_retain_days,
        _hydrated = true,
    }
    _G.__GAG2_AUTO_GIFT = G.__GAG2_AUTO_GIFT
    G.__GAG2_GIFT_STORE_EPOCH = (tonumber(G.__GAG2_GIFT_STORE_EPOCH) or 0) + 1
    _G.__GAG2_GIFT_STORE_EPOCH = G.__GAG2_GIFT_STORE_EPOCH

    G.AUTO_GIFT_ENABLED = st.enabled
    _G.AUTO_GIFT_ENABLED = st.enabled
    G.AUTO_GIFT_AUTO_SEND = st.auto_send
    _G.AUTO_GIFT_AUTO_SEND = st.auto_send
    STATE.auto_gift = _deepCopy(st)
    G.MAIN = MAIN
    _G.MAIN = MAIN
end

local function syncAutoGiftGlobalsFromMain()
    local mainRef = _getMainRef()
    if mainRef ~= MAIN then MAIN = mainRef end

    MAIN.auto = MAIN.auto or _deepCopy(DEFAULT_AUTO)
    MAIN.auto.gift = _normalizeAutoGiftState(MAIN.auto.gift)
    local st = MAIN.auto.gift

    if type(G.__GAG2_AUTO_GIFT) ~= "table" then
        G.__GAG2_AUTO_GIFT = {}
    end
    local store = G.__GAG2_AUTO_GIFT

    store.enabled = (st.enabled == true)
    store.auto_send = (st.auto_send == true)
    store.auto_claim_mail = (st.auto_claim_mail == true)
    store.auto_accept_gift = (st.auto_accept_gift == true)
    store.auto_claim_drop = (st.auto_claim_drop == true)

    if st.recipient_username ~= "" then
        store.recipient_username = st.recipient_username
    elseif store.recipient_username == nil then
        store.recipient_username = ""
    end
    if (tonumber(st.recipient_user_id) or 0) > 0 then
        store.recipient_user_id = math.floor(tonumber(st.recipient_user_id))
    elseif store.recipient_user_id == nil then
        store.recipient_user_id = 0
    end
    if st.recipient_display ~= "" then
        store.recipient_display = st.recipient_display
    elseif store.recipient_display == nil then
        store.recipient_display = ""
    end

    if st.note ~= nil and tostring(st.note) ~= "" then
        store.note = tostring(st.note)
    elseif store.note == nil then
        store.note = ""
    end
    if tonumber(st.delay_sec) then
        store.delay_sec = tonumber(st.delay_sec)
    elseif store.delay_sec == nil then
        store.delay_sec = 10
    end
    if tonumber(st.max_per_batch) then
        store.max_per_batch = tonumber(st.max_per_batch)
    elseif store.max_per_batch == nil then
        store.max_per_batch = 999999
    end
    if st.skip_equipped ~= nil then
        store.skip_equipped = (st.skip_equipped == true)
    elseif store.skip_equipped == nil then
        store.skip_equipped = true
    end

    store.send_totals = type(store.send_totals) == "table" and store.send_totals or {}
    local catKeys = _giftCategoryKeysFromState(st)
    if type(st.send_totals) == "table" then
        for _, key in ipairs(catKeys) do
            store.send_totals[key] = st.send_totals[key]
        end
    end

    store.once = _giftProfileStoreFromMainProfile(st.once, true)
    store.loop = _giftProfileStoreFromMainProfile(st.loop, false)

    store.categories = type(store.categories) == "table" and store.categories or {}
    for _, key in ipairs(catKeys) do
        store.categories[key] = (st.categories[key] == true)
    end

    store.selected = type(store.selected) == "table" and store.selected or {}
    local fromMain = _giftSelectedMapsFromMain(st)
    for _, key in ipairs(catKeys) do
        local cur = _arrayToMap(store.selected[key])
        if next(fromMain[key]) then
            store.selected[key] = fromMain[key]
        elseif next(cur) then
            store.selected[key] = cur
        else
            store.selected[key] = {}
        end
    end

    store.category_mode = st.category_mode
    store.send_list_mode = st.send_list_mode
    store.send_total = st.send_total
    store.after_send_mode = st.after_send_mode

    store._hydrated = true
    _G.__GAG2_AUTO_GIFT = store

    local enabled = store.enabled == true
    local autoSend = store.auto_send == true

    G.AUTO_GIFT_ENABLED = enabled
    _G.AUTO_GIFT_ENABLED = enabled
    G.AUTO_GIFT_AUTO_SEND = autoSend
    _G.AUTO_GIFT_AUTO_SEND = autoSend

    st.enabled = enabled
    st.auto_send = autoSend
    MAIN.auto.gift = _normalizeAutoGiftState(st)
    STATE.auto_gift = _deepCopy(MAIN.auto.gift)
    G.MAIN = MAIN
    _G.MAIN = MAIN
end

local function syncNormalGiftGlobalsFromMain()
    MAIN.auto = MAIN.auto or _deepCopy(DEFAULT_AUTO)
    MAIN.auto.normalGift = _normalizeAutoNormalGiftState(MAIN.auto.normalGift)
    local st = MAIN.auto.normalGift

    G.__GAG2_NORMAL_GIFT = {
        target_user_id = st.target_user_id,
        target_name = st.target_name,
        category = st.category,
        selected = _arrayToMap(st.selected),
        send_total = st.send_total,
        send_mode = st.send_mode,
        harvest_price_threshold_pct = st.harvest_price_threshold_pct,
        harvest_price_calc_mode = st.harvest_price_calc_mode,
        teleport_to_target = st.teleport_to_target == true,
        _hydrated = true,
    }
    _G.__GAG2_NORMAL_GIFT = G.__GAG2_NORMAL_GIFT

    STATE.auto_normal_gift = _deepCopy(st)
    G.MAIN = MAIN
    _G.MAIN = MAIN

    local ng = G.NormalGift or G.NormalGiftModule or rawget(_G, "NormalGift")
    if type(ng) == "table" and type(ng.ApplyConfig) == "function" then
        pcall(ng.ApplyConfig, ng, G.__GAG2_NORMAL_GIFT)
    end
end

local function syncAutoDropGlobalsFromMain()
    MAIN.auto = MAIN.auto or _deepCopy(DEFAULT_AUTO)
    MAIN.auto.dropItem = _normalizeAutoDropState(MAIN.auto.dropItem)
    local st = MAIN.auto.dropItem

    G.__GAG2_AUTO_DROP = {
        category = st.category,
        selected = _arrayToMap(st.selected),
        drop_total = st.drop_total,
        drop_delay_sec = st.drop_delay_sec,
        target_user_id = st.target_user_id,
        target_name = st.target_name,
        teleport_to_target = st.teleport_to_target,
        _hydrated = true,
    }
    _G.__GAG2_AUTO_DROP = G.__GAG2_AUTO_DROP

    STATE.auto_drop_item = _deepCopy(st)
    G.MAIN = MAIN
    _G.MAIN = MAIN

    local ad = G.AutoDrop or G.AutoDropModule or rawget(_G, "AutoDrop")
    if type(ad) == "table" and type(ad.ApplyConfig) == "function" then
        pcall(ad.ApplyConfig, ad, G.__GAG2_AUTO_DROP)
    end
end

