-- state_b.lua — Grow A Garden 2 (part 2/2)

local G = (getgenv and getgenv()) or _G
if not G.__GAG2_STATE_A_LOADED then
    error("[GAG2] state_a belum load — load state_a.lua dulu")
end

-- Re-inject export state_a ke env global (tanpa banyak local — hindari limit 200).
-- Shortcode A/B di IIFE terpisah; bare name di B harus ketemu di getgenv/_G.
do
    local names = {
        "_deepCopy", "DEFAULT_MISC", "DEFAULT_AUTO",
        "_giftCatalogKeys", "_defaultGiftCategoryMap", "_defaultGiftSelectedMap", "_defaultGiftSendTotals",
        "_arrayToMap", "_mapToArray",
        "_normalizeCollectPriority", "_normalizeKgFilter", "_normalizePriceFilter",
        "_parseKgRuleInput", "_parseScaledNumber", "_parsePriceRuleInput",
        "_formatKgRule", "_formatPriceRule",
        "_normalizeCollectRuleState", "_hasLegacyCollectFilter", "_migrateLegacyFruitRules",
        "_normalizeRulesState", "_migrateLegacyCollectToRules",
        "_normalizeAutoCollectState", "syncAutoCollectGlobalsFromMain",
        "_normalizePlantPositionId",
        "_normalizeAutoPlantState", "_normalizeAutoTrowelState",
        "_normalizeAutoSprinklerState", "_normalizeAutoWateringState",
        "syncAutoPlantGlobalsFromMain", "syncAutoTrowelGlobalsFromMain",
        "syncAutoSprinklerGlobalsFromMain", "syncAutoWateringGlobalsFromMain",
        "_normalizeAutoPlotState", "syncAutoPlotGlobalsFromMain",
        "_normalizeAutoFavState", "_normalizeAutoUnfavState",
        "syncAutoFavGlobalsFromMain", "syncAutoUnfavGlobalsFromMain",
        "_normalizeAutoSellState", "syncAutoSellGlobalsFromMain",
        "_normalizeAutoSellStockState", "syncAutoSellStockGlobalsFromMain",
        "_normalizeAutoSellDailyState", "syncAutoSellDailyGlobalsFromMain",
        "_normalizeAutoMergeEclipseState", "syncAutoMergeEclipseGlobalsFromMain",
        "_normalizeAutoShovelState", "syncAutoShovelGlobalsFromMain",
        "_normalizeAutoShovelFruitState", "syncAutoShovelFruitGlobalsFromMain",
        "_parseAuctionMaxPrice", "_allAuctionCatMaxZero", "_auctionLegacyFromSaveData",
        "_normalizeBuyItems", "_normalizeBuyCategory", "_normalizeAutoBuyState",
        "syncAutoBuyGlobalsFromMain", "_getMainRef",
        "_normalizeAutoClaimSeedState", "syncAutoClaimSeedGlobalsFromMain",
        "_normalizeAutoDragonEggState", "syncAutoDragonEggGlobalsFromMain",
        "_normalizeAutoSellPetState", "syncAutoSellPetGlobalsFromMain",
        "_normalizeAutoTeleState", "_replaceAutoTeleStoreFromMain", "syncAutoTeleGlobalsFromMain",
        "_giftCategoryKeysFromState", "_migrateLegacyGiftKeys",
        "_normalizeGiftProfileFieldsState", "_migrateGiftProfileRecipientsState",
        "_giftProfileHasUserData", "_migrateGiftProfilesState",
        "_giftProfileStoreFromMainProfile", "_giftProfilePayloadFromStoreProfile",
        "_normalizeAutoGiftState", "_normalizeAutoNormalGiftState", "_normalizeAutoDropState",
        "_giftSelectedMapsFromMain", "_giftSelectedArraysFromMaps", "_replaceGiftStoreFromMain",
        "syncAutoGiftGlobalsFromMain", "syncNormalGiftGlobalsFromMain", "syncAutoDropGlobalsFromMain",
    }
    local eg = (getgenv and getgenv()) or G
    for i = 1, #names do
        local name = names[i]
        local v = rawget(G, name)
        if v == nil then v = rawget(_G, name) end
        if v ~= nil then
            eg[name] = v
            rawset(_G, name, v)
            if G ~= eg then G[name] = v end
        end
    end
    if type(G.MAIN) == "table" then
        eg.MAIN = G.MAIN
        rawset(_G, "MAIN", G.MAIN)
    end
    if type(rawget(G, "_deepCopy")) ~= "function" then
        error("[GAG2] state_a export _deepCopy hilang — cek GAG2_STATE_A di panel")
    end
end

local Players     = game:GetService("Players")
local HttpService = game:GetService("HttpService")
local LP = Players.LocalPlayer or Players:GetPropertyChangedSignal("LocalPlayer"):Wait()
local STATE = G.STATE

local function _replaceNormalGiftStoreFromMain()
    local fn = syncNormalGiftGlobalsFromMain or G.syncNormalGiftGlobalsFromMain
