local function syncAutoGiftGlobalsToMain()
    local mainRef = (type(_getMainRef) == "function" and _getMainRef())
        or (type(G._getMainRef) == "function" and G._getMainRef())
        or G.MAIN
        or MAIN
    if mainRef ~= MAIN then MAIN = mainRef end

    MAIN.auto = MAIN.auto or _deepCopy(DEFAULT_AUTO)

    local store = G.__GAG2_AUTO_GIFT or _G.__GAG2_AUTO_GIFT
    if type(store) == "table" then
        local oncePayload = _giftProfilePayloadFromStoreProfile(store.once, true)
        local loopPayload = _giftProfilePayloadFromStoreProfile(store.loop, false)
        if type(store.once) ~= "table" and type(store.categories) == "table" then
            oncePayload = {
                categories = _deepCopy(store.categories),
                selected = _giftSelectedArraysFromMaps(type(store.selected) == "table" and store.selected or {}),
                category_mode = "single",
                send_total = store.send_total,
                after_send_mode = store.after_send_mode,
            }
            oncePayload = _normalizeGiftProfileFieldsState(oncePayload, true)
        end
        if type(store.loop) ~= "table" and type(store.categories) == "table" then
            loopPayload = {
                categories = _deepCopy(store.categories),
                selected = _giftSelectedArraysFromMaps(type(store.selected) == "table" and store.selected or {}),
                category_mode = store.category_mode,
                after_send_mode = store.after_send_mode,
            }
            loopPayload = _normalizeGiftProfileFieldsState(loopPayload, false)
        end
        MAIN.auto.gift = _normalizeAutoGiftState({
            enabled = (store.enabled == true),
            auto_send = (store.auto_send == true),
            auto_claim_mail = (store.auto_claim_mail == true),
            auto_accept_gift = (store.auto_accept_gift == true),
            auto_claim_drop = (store.auto_claim_drop == true),
            recipient_username = store.recipient_username,
            recipient_user_id = store.recipient_user_id,
            recipient_display = store.recipient_display,
            skip_equipped = store.skip_equipped,
            max_per_batch = store.max_per_batch,
            note = store.note,
            delay_sec = store.delay_sec,
            send_totals = type(store.send_totals) == "table" and _deepCopy(store.send_totals) or {},
            once = oncePayload,
            loop = loopPayload,
            categories = oncePayload.categories,
            selected = oncePayload.selected,
            category_mode = loopPayload.category_mode,
            send_list_mode = store.send_list_mode,
            send_total = oncePayload.send_total,
            after_send_mode = oncePayload.after_send_mode,
        })
    else
        MAIN.auto.gift = _normalizeAutoGiftState(MAIN.auto.gift)
    end

    if type(G.__GAG2_AUTO_GIFT) ~= "table" then
        G.__GAG2_AUTO_GIFT = {}
    end
    G.__GAG2_AUTO_GIFT.enabled = MAIN.auto.gift.enabled
    G.__GAG2_AUTO_GIFT.auto_send = MAIN.auto.gift.auto_send
    G.__GAG2_AUTO_GIFT.auto_claim_mail = MAIN.auto.gift.auto_claim_mail
    G.__GAG2_AUTO_GIFT.auto_accept_gift = MAIN.auto.gift.auto_accept_gift
    G.__GAG2_AUTO_GIFT.auto_claim_drop = MAIN.auto.gift.auto_claim_drop
    G.__GAG2_AUTO_GIFT.recipient_username = MAIN.auto.gift.recipient_username
    G.__GAG2_AUTO_GIFT.recipient_user_id = MAIN.auto.gift.recipient_user_id
    G.__GAG2_AUTO_GIFT.recipient_display = MAIN.auto.gift.recipient_display
    G.__GAG2_AUTO_GIFT.skip_equipped = MAIN.auto.gift.skip_equipped
    G.__GAG2_AUTO_GIFT.max_per_batch = MAIN.auto.gift.max_per_batch
    G.__GAG2_AUTO_GIFT.note = MAIN.auto.gift.note
    G.__GAG2_AUTO_GIFT.delay_sec = MAIN.auto.gift.delay_sec
    G.__GAG2_AUTO_GIFT.send_totals = _deepCopy(MAIN.auto.gift.send_totals)
    G.__GAG2_AUTO_GIFT.once = _giftProfileStoreFromMainProfile(MAIN.auto.gift.once, true)
    G.__GAG2_AUTO_GIFT.loop = _giftProfileStoreFromMainProfile(MAIN.auto.gift.loop, false)
    G.__GAG2_AUTO_GIFT.category_mode = MAIN.auto.gift.category_mode
    G.__GAG2_AUTO_GIFT.send_list_mode = MAIN.auto.gift.send_list_mode
    G.__GAG2_AUTO_GIFT.send_total = MAIN.auto.gift.send_total
    G.__GAG2_AUTO_GIFT.after_send_mode = MAIN.auto.gift.after_send_mode
    G.__GAG2_AUTO_GIFT.show_gift_history = MAIN.auto.gift.show_gift_history
    G.__GAG2_AUTO_GIFT.gift_history_retain_days = MAIN.auto.gift.gift_history_retain_days
    G.__GAG2_AUTO_GIFT.categories = _deepCopy(MAIN.auto.gift.categories)
    G.__GAG2_AUTO_GIFT.selected = _giftSelectedMapsFromMain(MAIN.auto.gift)
    G.__GAG2_AUTO_GIFT._hydrated = true
    _G.__GAG2_AUTO_GIFT = G.__GAG2_AUTO_GIFT

    G.MAIN = MAIN
    _G.MAIN = MAIN
end

local function syncAutoTeleGlobalsToMain()
    local mainRef = _getMainRef()
    if mainRef ~= MAIN then MAIN = mainRef end

    MAIN.auto = MAIN.auto or _deepCopy(DEFAULT_AUTO)
    local store = G.__GAG2_AUTO_TELE or _G.__GAG2_AUTO_TELE
    if type(store) == "table" then
        MAIN.auto.autoTele = _normalizeAutoTeleState({
            enabled = (store.enabled == true),
            delay = store.delay,
            selectedLocation = store.selectedLocation,
            mode = store.mode,
        })
    else
        MAIN.auto.autoTele = _normalizeAutoTeleState(MAIN.auto.autoTele)
    end
    G.MAIN = MAIN
    _G.MAIN = MAIN
end

