local function _snapshotPetFinderForSave(pf)
    pf = (type(pf) == "table") and pf or {}
    local function listFromMaybeMap(t)
        if type(t) ~= "table" then return {} end
        local cleaned = {}
        if t[1] ~= nil then
            for _, v in ipairs(t) do
                if type(v) == "string" and v ~= "" then
                    cleaned[#cleaned + 1] = v
                end
            end
        else
            for k, v in pairs(t) do
                if v == true then
                    cleaned[#cleaned + 1] = tostring(k)
                elseif type(v) == "string" and v ~= "" then
                    cleaned[#cleaned + 1] = v
                end
            end
        end
        table.sort(cleaned)
        return cleaned
    end

    local rarities = listFromMaybeMap(pf.filter_rarities)
    if #rarities == 0 and pf.filter_rarity and pf.filter_rarity ~= "" then
        rarities = { tostring(pf.filter_rarity) }
    end
    local cleanedPets = listFromMaybeMap(pf.target_pets)
    local autoHop = pf.auto_hop
    if type(autoHop) == "table" then
        autoHop = (autoHop.enabled == true)
    end
    return {
        filter_rarities = rarities,
        auto_refresh_list = (pf.auto_refresh_list ~= false),
        auto_hop = (autoHop == true),
        target_pets = cleanedPets,
    }
end

local function _petFinderListHasData(t)
    if type(t) ~= "table" then return false end
    if #t > 0 then return true end
    for _, v in pairs(t) do
        if v == true or (type(v) == "string" and v ~= "") then
            return true
        end
    end
    return false
end

local function applyPetFinderModule()
    local PF = G.PetFinder or G.PetFinderModule or rawget(_G, "PetFinder")
    if type(PF) == "table" and type(PF.SyncFromGlobals) == "function" then
        pcall(PF.SyncFromGlobals, PF)
    end
end

G.applyPetFinderModule = applyPetFinderModule
_G.applyPetFinderModule = applyPetFinderModule

local function syncPetFinderGlobalsFromMain()
    MAIN.misc = MAIN.misc or _deepCopy(DEFAULT_MISC)
    MAIN.misc.pet_finder = MAIN.misc.pet_finder or _deepCopy(DEFAULT_MISC.pet_finder)
    local pf = _snapshotPetFinderForSave(MAIN.misc.pet_finder)
    MAIN.misc.pet_finder = pf

    G.PET_FINDER_FILTER_RARITIES = _deepCopy(pf.filter_rarities)
    G.PET_FINDER_AUTO_REFRESH_LIST = (pf.auto_refresh_list == true)
    G.PET_FINDER_AUTO_HOP = (pf.auto_hop == true)
    G.PET_FINDER_TARGET_PETS = _deepCopy(pf.target_pets)
    _G.PET_FINDER_FILTER_RARITIES = G.PET_FINDER_FILTER_RARITIES
    _G.PET_FINDER_AUTO_REFRESH_LIST = G.PET_FINDER_AUTO_REFRESH_LIST
    _G.PET_FINDER_AUTO_HOP = G.PET_FINDER_AUTO_HOP
    _G.PET_FINDER_TARGET_PETS = G.PET_FINDER_TARGET_PETS

    STATE.pet_finder = _deepCopy(pf)
    applyPetFinderModule()
end

local function _normalizePerfState(st)
    st = type(st) == "table" and st or _deepCopy(DEFAULT_MISC.perf)
    st.enabled = (st.enabled == true)
    st.reduce_lag = (st.reduce_lag == true)
    if st.hide_others == nil then st.hide_others = true end
    -- Remove Garden ON → hide_own selalu true (soft shell + AC). Migrasi save lama hide_own=false.
    if st.enabled == true then
        st.hide_own = true
    elseif st.hide_own == nil then
        st.hide_own = true
    else
        st.hide_own = (st.hide_own == true)
    end
    if st.render == nil then st.render = true end
    return st
end

local function syncReduceFpsGlobalsFromMain()
    MAIN.misc = MAIN.misc or _deepCopy(DEFAULT_MISC)
    MAIN.misc.perf = _normalizePerfState(MAIN.misc.perf)
    local perf = MAIN.misc.perf

    REDUCE_FPS_ENABLED = perf.enabled
    G.REDUCE_FPS_ENABLED = perf.enabled
    _G.REDUCE_FPS_ENABLED = perf.enabled
    G.REDUCE_LAG_ENABLED = perf.reduce_lag
    _G.REDUCE_LAG_ENABLED = perf.reduce_lag
    G.REDUCE_FPS_HIDE_OTHERS = perf.hide_others
    _G.REDUCE_FPS_HIDE_OTHERS = perf.hide_others
    G.REDUCE_FPS_HIDE_OWN = perf.hide_own
    _G.REDUCE_FPS_HIDE_OWN = perf.hide_own
    G.REDUCE_FPS_RENDER = perf.render
    _G.REDUCE_FPS_RENDER = perf.render

    STATE.perf = _deepCopy(perf)
end

local function syncReduceFpsGlobalsToMain()
    MAIN.misc = MAIN.misc or _deepCopy(DEFAULT_MISC)
    MAIN.misc.perf = _normalizePerfState(MAIN.misc.perf)
    local perf = MAIN.misc.perf

    if REDUCE_FPS_ENABLED ~= nil then
        perf.enabled = (REDUCE_FPS_ENABLED == true)
    end
    if G.REDUCE_LAG_ENABLED ~= nil then
        perf.reduce_lag = (G.REDUCE_LAG_ENABLED == true)
    elseif rawget(_G, "REDUCE_LAG_ENABLED") ~= nil then
        perf.reduce_lag = (_G.REDUCE_LAG_ENABLED == true)
    end
    if G.REDUCE_FPS_HIDE_OTHERS ~= nil then
        perf.hide_others = (G.REDUCE_FPS_HIDE_OTHERS ~= false)
    end
    if G.REDUCE_FPS_HIDE_OWN ~= nil then
        -- true hanya kalau eksplisit true; nil/false → false (lalu normalize default true kalau nil sudah lewat)
        perf.hide_own = (G.REDUCE_FPS_HIDE_OWN == true)
    end
    if G.REDUCE_FPS_RENDER ~= nil then
        perf.render = (G.REDUCE_FPS_RENDER ~= false)
    end

    MAIN.misc.perf = _normalizePerfState(perf)
    STATE.perf = _deepCopy(perf)
    G.MAIN = MAIN
    _G.MAIN = MAIN
end

local function applyReduceFpsModule()
    MAIN.misc = MAIN.misc or _deepCopy(DEFAULT_MISC)
    MAIN.misc.perf = _normalizePerfState(MAIN.misc.perf)
    -- Jangan paksa hide_own: Remove Garden fokus fokus garden orang; own tetap harvestable
    local RF = G.ReduceFPS or rawget(_G, "ReduceFPS")
    if type(RF) ~= "table" then return end
    if type(RF.SyncFromGlobals) == "function" then
        pcall(RF.SyncFromGlobals, RF)
    elseif type(RF.SetEnabled) == "function" then
        pcall(RF.SetEnabled, RF, REDUCE_FPS_ENABLED == true)
    end
end

G.applyReduceFpsModule = applyReduceFpsModule
_G.applyReduceFpsModule = applyReduceFpsModule

local function applyReduceLagModule()
    MAIN.misc = MAIN.misc or _deepCopy(DEFAULT_MISC)
    MAIN.misc.perf = _normalizePerfState(MAIN.misc.perf)
    local RL = G.ReduceLag or rawget(_G, "ReduceLag")
    if type(RL) ~= "table" then return end
    local perf = MAIN.misc.perf
    local wantLag = perf.reduce_lag == true
    local wantGarden = perf.enabled == true
    local function doSync()
        if type(RL.SyncFromGlobals) == "function" then
            pcall(RL.SyncFromGlobals, RL)
        elseif type(RL.SetEnabled) == "function" then
            pcall(RL.SetEnabled, RL, wantLag)
        end
    end
    -- Remove Garden dulu; ReduceLag defer biar tidak bentrok strip Gardens
    if wantLag and wantGarden then
        task.delay(2.0, doSync)
    else
        doSync()
    end
end

G.applyReduceLagModule = applyReduceLagModule
_G.applyReduceLagModule = applyReduceLagModule

local function _normalizeFruitBackpackEspState(st)
    st = type(st) == "table" and st or _deepCopy(DEFAULT_MISC.fruit_backpack_esp)
    st.enabled = (st.enabled == true)
    local mode = tostring(st.price_mode or ""):lower()
    if mode ~= "base" and mode ~= "stock" then
        mode = (st.include_friend_boost == true) and "stock" or "base"
    end
    st.price_mode = mode
    st.include_friend_boost = (mode == "stock")
    return st
end

local function syncFruitBackpackEspGlobalsFromMain()
    MAIN.misc = MAIN.misc or _deepCopy(DEFAULT_MISC)
    MAIN.misc.fruit_backpack_esp = _normalizeFruitBackpackEspState(MAIN.misc.fruit_backpack_esp)
    local cfg = MAIN.misc.fruit_backpack_esp

    G.FRUIT_BACKPACK_ESP_ENABLED = cfg.enabled
    _G.FRUIT_BACKPACK_ESP_ENABLED = cfg.enabled
    G.FRUIT_BACKPACK_ESP_PRICE_MODE = cfg.price_mode
    _G.FRUIT_BACKPACK_ESP_PRICE_MODE = cfg.price_mode
    G.FRUIT_PRICE_INCLUDE_FRIEND_BOOST = cfg.include_friend_boost
    _G.FRUIT_PRICE_INCLUDE_FRIEND_BOOST = cfg.include_friend_boost

    STATE.fruit_backpack_esp = _deepCopy(cfg)
end

local function syncFruitBackpackEspGlobalsToMain()
    MAIN.misc = MAIN.misc or _deepCopy(DEFAULT_MISC)
    MAIN.misc.fruit_backpack_esp = _normalizeFruitBackpackEspState(MAIN.misc.fruit_backpack_esp)
    local cfg = MAIN.misc.fruit_backpack_esp

    if G.FRUIT_BACKPACK_ESP_ENABLED ~= nil then
        cfg.enabled = (G.FRUIT_BACKPACK_ESP_ENABLED == true)
    end
    if rawget(_G, "FRUIT_BACKPACK_ESP_ENABLED") ~= nil then
