local function _normalizeEggTypeSizeMode(mode)
    mode = tostring(mode or "or"):lower()
    if mode == "and" then return "and" end
    return "or"
end

local function _normalizeOpenEggRule(rule, index)
    if type(rule) ~= "table" then return nil end
    return {
        id = tostring(rule.id or ("rule_" .. tostring(index or 0))),
        enabled = rule.enabled ~= false,
        pets = _mapToArray(rule.pets),
        sizes = _mapToArray(rule.sizes),
        types = _mapToArray(rule.types),
        type_size_mode = _normalizeEggTypeSizeMode(rule.type_size_mode),
    }
end

local function _normalizeOpenEggState(egg)
    local defaults = DEFAULT_AUTO.openEgg
    egg = type(egg) == "table" and egg or _deepCopy(defaults)

    if egg.open_egg == nil then
        egg.open_egg = (egg.enabled == true) or (egg.auto_open == true)
    end

    egg.open_egg = (egg.open_egg == true)
    egg.enabled = egg.open_egg
    egg.eggs = _mapToArray(egg.eggs)
    egg.max_open = math.max(0, math.floor(tonumber(egg.max_open) or 0))
    egg.rejoin_delay_sec = nil
    egg.rollback_rejoin = nil

    local rawRules = type(egg.rules) == "table" and egg.rules or {}
    local rawOrder = type(egg.rulesOrder) == "table" and egg.rulesOrder or {}
    local byId = {}

    if rawRules[1] ~= nil then
        for i, rule in ipairs(rawRules) do
            local norm = _normalizeOpenEggRule(rule, i)
            if norm then byId[norm.id] = norm end
        end
    else
        for id, rule in pairs(rawRules) do
            local norm = _normalizeOpenEggRule(rule, id)
            if norm then
                norm.id = tostring(norm.id ~= "" and norm.id or id)
                byId[norm.id] = norm
            end
        end
    end

    if #rawOrder == 0 then
        local ids = {}
        for id in pairs(byId) do ids[#ids + 1] = tostring(id) end
        table.sort(ids)
        rawOrder = ids
    end

    local rules, order = {}, {}
    local seen = {}
    for _, id in ipairs(rawOrder) do
        local rule = byId[tostring(id)]
        if rule then
            rules[#rules + 1] = rule
            order[#order + 1] = rule.id
            seen[rule.id] = true
        end
    end
    for id, rule in pairs(byId) do
        if not seen[id] then
            rules[#rules + 1] = rule
            order[#order + 1] = id
        end
    end

    egg.rules = rules
    egg.rulesOrder = order
    return egg
end

local function normalizePositionMode(mode)
    mode = tostring(mode or "under"):lower()
    if mode == "above" or mode == "over" then
        return "above"
    end
    return "under"
end

local function _normalizeSprinklerOtherGardenState(sw)
    local defaults = DEFAULT_AUTO.sprinklerOtherGarden
    sw = type(sw) == "table" and sw or _deepCopy(defaults)
    sw.target_players = _mapToArray(sw.target_players)
    sw.target_plots = _mapToArray(sw.target_plots)
    sw.target_plants = _mapToArray(sw.target_plants)
    sw.sprinklers = _mapToArray(sw.sprinklers)
    sw.watering_cans = _mapToArray(sw.watering_cans)
    sw.position_mode = normalizePositionMode(sw.position_mode or sw.watering_mode)
    local smu = math.floor(tonumber(sw.sprinkler_max_use) or defaults.sprinkler_max_use or 1)
    sw.sprinkler_max_use = math.max(1, math.min(100, smu))
    local wmu = math.floor(tonumber(sw.watering_max_use) or defaults.watering_max_use or 1)
    sw.watering_max_use = math.max(1, math.min(100, wmu))
    local scm = math.floor(tonumber(sw.stop_collect_max) or defaults.stop_collect_max or 0)
    if scm < 0 then scm = 0 end
    if scm > 9999 then scm = 9999 end
    sw.stop_collect_max = scm
    local wds = tonumber(sw.watering_delay_sec)
    if wds == nil then wds = defaults.watering_delay_sec or 10 end
    wds = math.floor(wds)
    if wds < 0 then wds = 0 end
    if wds > 600 then wds = 600 end
    sw.watering_delay_sec = wds
    sw.pause_at_night = (sw.pause_at_night ~= false)
    sw.rollback_rejoin = false
    sw.enabled = (sw.enabled == true)
    return sw
end

