local function syncSprinklerOtherGardenGlobalsFromMain()
    MAIN.auto = MAIN.auto or _deepCopy(DEFAULT_AUTO)

    -- migrate legacy misc.auto_vuln.sprinkler_water → auto.sprinklerOtherGarden once
    do
        local cur = MAIN.auto.sprinklerOtherGarden
        local legacy = (type(MAIN.misc) == "table" and type(MAIN.misc.auto_vuln) == "table")
            and MAIN.misc.auto_vuln.sprinkler_water or nil
        local curEmpty = type(cur) ~= "table" or (
            cur.enabled ~= true
            and (type(cur.target_players) ~= "table" or not next(cur.target_players))
            and (type(cur.sprinklers) ~= "table" or not next(cur.sprinklers))
            and (type(cur.watering_cans) ~= "table" or not next(cur.watering_cans))
        )
        if curEmpty and type(legacy) == "table" then
            MAIN.auto.sprinklerOtherGarden = legacy
            MAIN.misc.auto_vuln.sprinkler_water = nil
        end
    end

    MAIN.auto.sprinklerOtherGarden = _normalizeSprinklerOtherGardenState(MAIN.auto.sprinklerOtherGarden)
    local swCfg = MAIN.auto.sprinklerOtherGarden

    G.SW_OTHER_ENABLED = (swCfg.enabled == true)
    _G.SW_OTHER_ENABLED = G.SW_OTHER_ENABLED
    G.SW_OTHER_TARGET_PLAYERS_SELECTED = _arrayToMap(swCfg.target_players or {})
    _G.SW_OTHER_TARGET_PLAYERS_SELECTED = G.SW_OTHER_TARGET_PLAYERS_SELECTED
    G.SW_OTHER_TARGET_PLOTS_SELECTED = _arrayToMap(swCfg.target_plots or {})
    _G.SW_OTHER_TARGET_PLOTS_SELECTED = G.SW_OTHER_TARGET_PLOTS_SELECTED
    G.SW_OTHER_TARGET_PLANTS_SELECTED = _arrayToMap(swCfg.target_plants or {})
    _G.SW_OTHER_TARGET_PLANTS_SELECTED = G.SW_OTHER_TARGET_PLANTS_SELECTED
    G.SW_OTHER_SPRINKLERS_SELECTED = _arrayToMap(swCfg.sprinklers or {})
    _G.SW_OTHER_SPRINKLERS_SELECTED = G.SW_OTHER_SPRINKLERS_SELECTED
    G.SW_OTHER_WATERING_SELECTED = _arrayToMap(swCfg.watering_cans or {})
    _G.SW_OTHER_WATERING_SELECTED = G.SW_OTHER_WATERING_SELECTED
    G.SW_OTHER_POSITION_MODE = normalizePositionMode(swCfg.position_mode or swCfg.watering_mode)
    _G.SW_OTHER_POSITION_MODE = G.SW_OTHER_POSITION_MODE
    G.SW_OTHER_WATERING_MODE = G.SW_OTHER_POSITION_MODE
    _G.SW_OTHER_WATERING_MODE = G.SW_OTHER_WATERING_MODE
    G.SW_OTHER_SPRINKLER_MAX_USE = swCfg.sprinkler_max_use or 1
    _G.SW_OTHER_SPRINKLER_MAX_USE = G.SW_OTHER_SPRINKLER_MAX_USE
    G.SW_OTHER_WATERING_MAX_USE = swCfg.watering_max_use or 1
    _G.SW_OTHER_WATERING_MAX_USE = G.SW_OTHER_WATERING_MAX_USE
    G.SW_OTHER_STOP_COLLECT_MAX = swCfg.stop_collect_max or 0
    _G.SW_OTHER_STOP_COLLECT_MAX = G.SW_OTHER_STOP_COLLECT_MAX
    G.SW_OTHER_WATERING_DELAY_SEC = swCfg.watering_delay_sec or 10
    _G.SW_OTHER_WATERING_DELAY_SEC = G.SW_OTHER_WATERING_DELAY_SEC
    G.SW_OTHER_PAUSE_AT_NIGHT = (swCfg.pause_at_night ~= false)
    _G.SW_OTHER_PAUSE_AT_NIGHT = G.SW_OTHER_PAUSE_AT_NIGHT

    STATE.auto_sprinkler_other_garden = _deepCopy(swCfg)
    G.MAIN = MAIN
    _G.MAIN = MAIN
end

