local function syncOpenEggGlobalsFromMain()
    MAIN.auto = MAIN.auto or _deepCopy(DEFAULT_AUTO)

    -- migrate legacy misc.auto_vuln.egg → auto.openEgg once
    do
        local oe = MAIN.auto.openEgg
        local legacy = (type(MAIN.misc) == "table" and type(MAIN.misc.auto_vuln) == "table")
            and MAIN.misc.auto_vuln.egg or nil
        local oeEmpty = type(oe) ~= "table" or (
            oe.open_egg ~= true
            and (tonumber(oe.max_open) or 0) <= 0
            and (type(oe.eggs) ~= "table" or not next(oe.eggs))
            and (type(oe.rules) ~= "table" or not next(oe.rules))
        )
        if oeEmpty and type(legacy) == "table" then
            MAIN.auto.openEgg = legacy
            MAIN.misc.auto_vuln.egg = nil
        end
    end

    MAIN.auto.openEgg = _normalizeOpenEggState(MAIN.auto.openEgg)
    local cfg = MAIN.auto.openEgg

    G.OPEN_EGG_ENABLED = (cfg.open_egg == true)
    _G.OPEN_EGG_ENABLED = G.OPEN_EGG_ENABLED
    G.OPEN_EGG_SELECTED = _arrayToMap(cfg.eggs or {})
    _G.OPEN_EGG_SELECTED = G.OPEN_EGG_SELECTED
    G.OPEN_EGG_MAX_OPEN = cfg.max_open
    _G.OPEN_EGG_MAX_OPEN = cfg.max_open
    G.OPEN_EGG_RULES = cfg.rules or {}
    _G.OPEN_EGG_RULES = G.OPEN_EGG_RULES
    G.OPEN_EGG_RULES_ORDER = cfg.rulesOrder or {}
    _G.OPEN_EGG_RULES_ORDER = G.OPEN_EGG_RULES_ORDER

    STATE.auto_open_egg = _deepCopy(cfg)
    G.MAIN = MAIN
    _G.MAIN = MAIN
end

local function applyOpenEggModule()
    syncOpenEggGlobalsFromMain()
    local OE = G.OpenEgg or G.OpenEggModule or rawget(_G, "OpenEgg")
        or G.AutoVuln or G.AutoVulnModule or rawget(_G, "AutoVuln")
    if type(OE) == "table" and type(OE.Apply) == "function" then
        pcall(OE.Apply, OE)
    end
end

G.applyOpenEggModule = applyOpenEggModule
