    if on ~= nil then MAIN.auto.sellPet.enabled = (on == true) end

    local sel = G.AUTO_SELL_PET_SELECTED or rawget(_G, "AUTO_SELL_PET_SELECTED")
    if type(sel) == "table" and next(sel) then
        MAIN.auto.sellPet.pets = _mapToArray(sel)
    end

    MAIN.auto.sellPet = _normalizeAutoSellPetState(MAIN.auto.sellPet)
    G.MAIN = MAIN
    _G.MAIN = MAIN
end

-- __GAG2_FLUSH_TO_MAIN di-assign setelah _prepareMainForSave() didefinisikan.

--------------------------------------------------
-- UpdateNewServer helpers
--------------------------------------------------
local function __clampUpdateNewServerMinute(n)
    n = tonumber(n) or 30
    n = math.floor(n + 0.5)
    if n < 1 then n = 1 end
    if n > 300 then n = 300 end
    return n
end

local function __truthy(v)
    return (v == true) or (v == 1) or (v == "true") or (v == "1")
end

local __unsApplied = { enabled = nil, minute = nil }

local function readUpdateNewServerGlobals()
    local enabled, minute

    if type(MAIN.misc) == "table" and type(MAIN.misc.rejoin) == "table" then
        local rj = MAIN.misc.rejoin
        if rj.update_new_server ~= nil then
            enabled = __truthy(rj.update_new_server)
        end
        if rj.update_new_server_minute ~= nil then
            minute = rj.update_new_server_minute
        end
    end

    if type(G.__UNS_SAVED) == "table" then
        if enabled == nil and G.__UNS_SAVED.enabled ~= nil then
            enabled = __truthy(G.__UNS_SAVED.enabled)
        end
        if minute == nil and G.__UNS_SAVED.minute ~= nil then
            minute = G.__UNS_SAVED.minute
        end
    end

    local env = (getgenv and getgenv()) or _G
    if enabled == nil then
        enabled = rawget(env, "UPDATE_NEW_SERVER_ENABLED")
        if enabled == nil then enabled = rawget(_G, "UPDATE_NEW_SERVER_ENABLED") end
    end
    if minute == nil then
        minute = rawget(env, "UPDATE_NEW_SERVER_MINUTE")
        if minute == nil then minute = rawget(_G, "UPDATE_NEW_SERVER_MINUTE") end
    end

    enabled = (enabled == true)
    minute  = __clampUpdateNewServerMinute(minute)

    env.UPDATE_NEW_SERVER_ENABLED = enabled
    _G.UPDATE_NEW_SERVER_ENABLED  = enabled
    G.UPDATE_NEW_SERVER_ENABLED   = enabled
    env.UPDATE_NEW_SERVER_MINUTE  = minute
    _G.UPDATE_NEW_SERVER_MINUTE   = minute
    G.UPDATE_NEW_SERVER_MINUTE    = minute

    return enabled, minute
end

local function writeUpdateNewServerGlobals(enabled, minute)
    local env = (getgenv and getgenv()) or _G
    enabled = (enabled == true)
    minute  = __clampUpdateNewServerMinute(minute)

    env.UPDATE_NEW_SERVER_ENABLED = enabled
    _G.UPDATE_NEW_SERVER_ENABLED  = enabled
    G.UPDATE_NEW_SERVER_ENABLED   = enabled
    UPDATE_NEW_SERVER_ENABLED     = enabled

    env.UPDATE_NEW_SERVER_MINUTE = minute
    _G.UPDATE_NEW_SERVER_MINUTE  = minute
    G.UPDATE_NEW_SERVER_MINUTE   = minute
    UPDATE_NEW_SERVER_MINUTE       = minute

    MAIN.misc = MAIN.misc or _deepCopy(DEFAULT_MISC)
    MAIN.misc.rejoin = MAIN.misc.rejoin or _deepCopy(DEFAULT_MISC.rejoin)
    MAIN.misc.rejoin.update_new_server        = enabled
    MAIN.misc.rejoin.update_new_server_minute = minute
    G.MAIN = MAIN
    _G.MAIN = MAIN

    STATE.rejoin = type(STATE.rejoin) == "table" and STATE.rejoin or {}
    STATE.rejoin.update_new_server        = enabled
    STATE.rejoin.update_new_server_minute = minute

    G.__UNS_SAVED = { enabled = enabled, minute = minute }
    __unsApplied.enabled = nil
    __unsApplied.minute  = nil
end

local function applyUpdateNewServerModule(forcedEnabled, forcedMinute)
    local enabled, minute
    if forcedEnabled ~= nil then
        enabled = __truthy(forcedEnabled)
        minute  = __clampUpdateNewServerMinute(forcedMinute)
    else
        enabled, minute = readUpdateNewServerGlobals()
    end

    local UNS = G.UpdateNewServer or _G.UpdateNewServer
    if type(UNS) ~= "table" then return end

    if forcedEnabled == nil and forcedMinute == nil
        and __unsApplied.enabled == enabled
        and __unsApplied.minute == minute then
        return
    end

    if type(UNS.Apply) == "function" then
        pcall(function() UNS:Apply(enabled, minute) end)
        __unsApplied.enabled = enabled
        __unsApplied.minute  = minute
        return
    end

    pcall(function() UNS:SetEnabled(enabled) end)
    pcall(function() UNS:SetMinute(minute) end)
    if enabled == true then
        if type(UNS.Start) == "function" then pcall(function() UNS:Start() end) end
    elseif type(UNS.Stop) == "function" then
        pcall(function() UNS:Stop("disabled") end)
    end

    __unsApplied.enabled = enabled
    __unsApplied.minute  = minute
end

local function publishUpdateNewServer()
    local enabled, minute = readUpdateNewServerGlobals()
    writeUpdateNewServerGlobals(enabled, minute)
    applyUpdateNewServerModule()
end

G.readUpdateNewServerGlobals   = readUpdateNewServerGlobals
_G.readUpdateNewServerGlobals  = readUpdateNewServerGlobals
G.writeUpdateNewServerGlobals  = writeUpdateNewServerGlobals
_G.writeUpdateNewServerGlobals = writeUpdateNewServerGlobals
G.applyUpdateNewServerModule   = applyUpdateNewServerModule
_G.applyUpdateNewServerModule  = applyUpdateNewServerModule
G.publishUpdateNewServer       = publishUpdateNewServer
_G.publishUpdateNewServer      = publishUpdateNewServer

local __autoHopApplied = { enabled = nil, current = nil, max = nil, delay = nil }

local function readAutoHopGlobals()
    local enabled, current, max, delay

    if type(MAIN.misc) == "table" and type(MAIN.misc.rejoin) == "table" then
        local ah = MAIN.misc.rejoin.auto_hop
        if type(ah) == "table" then
            if ah.enabled ~= nil then enabled = (ah.enabled == true) end
            if tonumber(ah.current_player) ~= nil then
                current = tonumber(ah.current_player)
            elseif tonumber(ah.current) ~= nil then
                current = tonumber(ah.current)
            end
            if tonumber(ah.max_player) ~= nil then
                max = tonumber(ah.max_player)
            elseif tonumber(ah.max) ~= nil then
                max = tonumber(ah.max)
            end
            if tonumber(ah.teleport_delay) ~= nil then delay = tonumber(ah.teleport_delay) end
        end
    end

    if type(G.__AUTO_HOP_SAVED) == "table" then
        if enabled == nil and G.__AUTO_HOP_SAVED.enabled ~= nil then
            enabled = (G.__AUTO_HOP_SAVED.enabled == true)
        end
        if current == nil and tonumber(G.__AUTO_HOP_SAVED.current) ~= nil then
            current = tonumber(G.__AUTO_HOP_SAVED.current)
        end
        if max == nil and tonumber(G.__AUTO_HOP_SAVED.max) ~= nil then
            max = tonumber(G.__AUTO_HOP_SAVED.max)
        end
        if delay == nil and tonumber(G.__AUTO_HOP_SAVED.delay) ~= nil then
            delay = tonumber(G.__AUTO_HOP_SAVED.delay)
        end
    end

    local env = (getgenv and getgenv()) or _G
    if enabled == nil then
        enabled = rawget(env, "AUTO_HOP_ENABLED")
        if enabled == nil then enabled = rawget(_G, "AUTO_HOP_ENABLED") end
    end
    if current == nil then
        current = rawget(env, "AUTO_HOP_CURRENT_PLAYER")
        if current == nil then current = rawget(_G, "AUTO_HOP_CURRENT_PLAYER") end
    end
    if max == nil then
        max = rawget(env, "AUTO_HOP_MAX_PLAYER")
        if max == nil then max = rawget(_G, "AUTO_HOP_MAX_PLAYER") end
    end
    if delay == nil then
        delay = rawget(env, "AUTO_HOP_TELEPORT_DELAY")
        if delay == nil then delay = rawget(_G, "AUTO_HOP_TELEPORT_DELAY") end
    end

    enabled = (enabled == true)
    current = math.floor(math.max(1, math.min(100, tonumber(current) or 1)))
    max = math.floor(math.max(1, math.min(100, tonumber(max) or 1)))
    delay = math.floor(math.max(10, math.min(600, tonumber(delay) or 10)))

    env.AUTO_HOP_ENABLED = enabled
    _G.AUTO_HOP_ENABLED = enabled
    G.AUTO_HOP_ENABLED = enabled
    AUTO_HOP_ENABLED = enabled

    env.AUTO_HOP_CURRENT_PLAYER = current
    _G.AUTO_HOP_CURRENT_PLAYER = current
    G.AUTO_HOP_CURRENT_PLAYER = current
    AUTO_HOP_CURRENT_PLAYER = current

    env.AUTO_HOP_MAX_PLAYER = max
    _G.AUTO_HOP_MAX_PLAYER = max
    G.AUTO_HOP_MAX_PLAYER = max
    AUTO_HOP_MAX_PLAYER = max

    env.AUTO_HOP_TELEPORT_DELAY = delay
    _G.AUTO_HOP_TELEPORT_DELAY = delay
    G.AUTO_HOP_TELEPORT_DELAY = delay

    return enabled, current, max, delay
end

local function writeAutoHopGlobals(enabled, current, max, delay)
    local env = (getgenv and getgenv()) or _G
    enabled = (enabled == true)
    current = math.floor(math.max(1, math.min(100, tonumber(current) or 1)))
    max = math.floor(math.max(1, math.min(100, tonumber(max) or 1)))
    delay = math.floor(math.max(10, math.min(600, tonumber(delay) or 10)))

    env.AUTO_HOP_ENABLED = enabled
    _G.AUTO_HOP_ENABLED = enabled
    G.AUTO_HOP_ENABLED = enabled
    AUTO_HOP_ENABLED = enabled

    env.AUTO_HOP_CURRENT_PLAYER = current
    _G.AUTO_HOP_CURRENT_PLAYER = current
    G.AUTO_HOP_CURRENT_PLAYER = current
    AUTO_HOP_CURRENT_PLAYER = current

    env.AUTO_HOP_MAX_PLAYER = max
    _G.AUTO_HOP_MAX_PLAYER = max
    G.AUTO_HOP_MAX_PLAYER = max
    AUTO_HOP_MAX_PLAYER = max

    env.AUTO_HOP_TELEPORT_DELAY = delay
    _G.AUTO_HOP_TELEPORT_DELAY = delay
    G.AUTO_HOP_TELEPORT_DELAY = delay

    MAIN.misc = MAIN.misc or _deepCopy(DEFAULT_MISC)
    MAIN.misc.rejoin = MAIN.misc.rejoin or _deepCopy(DEFAULT_MISC.rejoin)
    local ah = type(MAIN.misc.rejoin.auto_hop) == "table"
        and MAIN.misc.rejoin.auto_hop
        or _deepCopy(DEFAULT_MISC.rejoin.auto_hop)
    local visited = ah.visited
    ah.enabled = enabled
    ah.current_player = current
    ah.max_player = max
    ah.teleport_delay = delay
    if type(visited) == "table" then ah.visited = visited end
    MAIN.misc.rejoin.auto_hop = ah
    G.MAIN = MAIN
    _G.MAIN = MAIN

    STATE.rejoin = type(STATE.rejoin) == "table" and STATE.rejoin or {}
    STATE.rejoin.auto_hop = _deepCopy(ah)

    G.__AUTO_HOP_SAVED = { enabled = enabled, current = current, max = max, delay = delay }
    __autoHopApplied.enabled = nil
    __autoHopApplied.current = nil
    __autoHopApplied.max = nil
    __autoHopApplied.delay = nil
end

local function applyAutoHopModule(forcedEnabled, forcedCurrent, forcedMax, forcedDelay)
    local enabled, current, max, delay
    if forcedEnabled ~= nil then
        enabled = (forcedEnabled == true)
        local readEnabled, readCurrent, readMax, readDelay = readAutoHopGlobals()
        current = math.floor(math.max(1, math.min(100, tonumber(forcedCurrent) or readCurrent or 1)))
        max = math.floor(math.max(1, math.min(100, tonumber(forcedMax) or readMax or 1)))
        delay = math.floor(math.max(10, math.min(600, tonumber(forcedDelay) or readDelay or 10)))
    else
        enabled, current, max, delay = readAutoHopGlobals()
    end

    local AH = G.AutoHopServer or _G.AutoHopServer
    if type(AH) ~= "table" then return end

    if forcedEnabled == nil and forcedCurrent == nil and forcedMax == nil and forcedDelay == nil
        and __autoHopApplied.enabled == enabled
        and __autoHopApplied.current == current
        and __autoHopApplied.max == max
        and __autoHopApplied.delay == delay then
        return
    end

    if type(AH.SetCurrentPlayer) == "function" then
        pcall(AH.SetCurrentPlayer, AH, current)
    end
    if type(AH.SetMaxPlayer) == "function" then
        pcall(AH.SetMaxPlayer, AH, max)
    end
    if type(AH.SetTeleportDelay) == "function" then
        pcall(AH.SetTeleportDelay, AH, delay)
    end
    if enabled then
        if type(AH.Start) == "function" then pcall(AH.Start, AH) end
    elseif type(AH.Stop) == "function" then
        pcall(AH.Stop, AH)
    end

    writeAutoHopGlobals(enabled, current, max, delay)

    __autoHopApplied.enabled = enabled
    __autoHopApplied.current = current
    __autoHopApplied.max = max
    __autoHopApplied.delay = delay
end

G.readAutoHopGlobals   = readAutoHopGlobals
_G.readAutoHopGlobals  = readAutoHopGlobals
G.writeAutoHopGlobals  = writeAutoHopGlobals
_G.writeAutoHopGlobals = writeAutoHopGlobals
G.applyAutoHopModule   = applyAutoHopModule
_G.applyAutoHopModule  = applyAutoHopModule

-- 0 = auto sesuai durasi weather; 1..600 = fixed sec
local function _clampWeatherKickDelay(n)
    n = math.floor(tonumber(n) or 60)
    if n < 0 then n = 0 end
    if n > 600 then n = 600 end
    return n
end

local WK_PREFIX_PHASE   = "P:"
local WK_PREFIX_WEATHER = "W:"

local function _wkSplitSelected(selected)
    local weathers, cycles = {}, {}
    local seenW, seenC = {}, {}
    if type(selected) ~= "table" then return weathers, cycles end
    for _, rawKey in ipairs(selected) do
        local key = tostring(rawKey or "")
        if key:sub(1, 2) == WK_PREFIX_PHASE then
            local name = key:sub(3)
            if name ~= "" and not seenC[name] then
                seenC[name] = true
                cycles[#cycles + 1] = name
            end
        elseif key:sub(1, 2) == WK_PREFIX_WEATHER then
            local name = key:sub(3)
            if name ~= "" and not seenW[name] then
                seenW[name] = true
                weathers[#weathers + 1] = name
            end
        end
    end
    table.sort(weathers)
    table.sort(cycles)
    return weathers, cycles
end

local function _wkFilterSelectedWeatherOnly(selected)
    local out = {}
    if type(selected) ~= "table" then return out end
    for _, rawKey in ipairs(selected) do
        local key = tostring(rawKey or "")
        if key:sub(1, 2) == WK_PREFIX_WEATHER then
            out[#out + 1] = key
        end
    end
    return out
end

local function _wkBuildSelectedFromLegacy(wk)
    local selected, seen = {}, {}
    local function add(key)
        key = tostring(key or "")
        if key == "" or seen[key] then return end
        if key:sub(1, 2) ~= WK_PREFIX_WEATHER then return end
        seen[key] = true
        selected[#selected + 1] = key
    end
    if type(wk.weathers) == "table" then
        for _, name in ipairs(wk.weathers) do
            add(WK_PREFIX_WEATHER .. tostring(name))
        end
    end
    if #selected == 0 and type(wk.weather) == "string" and wk.weather ~= "" then
        add(WK_PREFIX_WEATHER .. wk.weather)
    end
    return selected
end

local function _normalizeWeatherKickState(wk)
    wk = type(wk) == "table" and wk or _deepCopy(DEFAULT_MISC.rejoin.weather_kick)
    wk.enabled = (wk.enabled == true)
    wk.rejoin_delay_sec = _clampWeatherKickDelay(wk.rejoin_delay_sec)

    local selected = {}
    if type(wk.selected) == "table" then
        selected = _wkFilterSelectedWeatherOnly(wk.selected)
    else
        selected = _wkBuildSelectedFromLegacy(wk)
    end
    wk.selected = selected
    wk.weather = nil
    wk.weathers = nil
    wk.cycles = nil
    return wk
end

local function _publishWeatherKickRuntime(enabled, selected, delay)
    local wk = _normalizeWeatherKickState({
        enabled = enabled,
        selected = selected,
        rejoin_delay_sec = delay,
    })
    local weathers, _ = _wkSplitSelected(wk.selected)
    local cycles = {}
    enabled = wk.enabled
    delay = wk.rejoin_delay_sec
    selected = wk.selected

    G.WEATHER_KICK_ENABLED = enabled
    G.WEATHER_KICK_SELECTED = selected
    G.WEATHER_KICK_WEATHERS = weathers
    G.WEATHER_KICK_CYCLES = {}
    G.WEATHER_KICK_REJOIN_DELAY_SEC = delay
    _G.WEATHER_KICK_ENABLED = enabled
    _G.WEATHER_KICK_SELECTED = selected
    _G.WEATHER_KICK_WEATHERS = weathers
    _G.WEATHER_KICK_CYCLES = {}
    _G.WEATHER_KICK_REJOIN_DELAY_SEC = delay
    G.__WEATHER_KICK_SAVED = {
        enabled = enabled,
        selected = _deepCopy(selected),
        rejoin_delay_sec = delay,
    }

    return enabled, selected, weathers, cycles, delay
end

local __weatherKickApplied = { enabled = nil, selected = nil, delay = nil }

local function readWeatherKickGlobals()
    local wk
    if type(MAIN.misc) == "table" and type(MAIN.misc.rejoin) == "table"
        and type(MAIN.misc.rejoin.weather_kick) == "table" then
        wk = _normalizeWeatherKickState(MAIN.misc.rejoin.weather_kick)
    else
        wk = _normalizeWeatherKickState(nil)
    end

    if type(G.__WEATHER_KICK_SAVED) == "table" and type(G.__WEATHER_KICK_SAVED.selected) == "table" then
        wk.selected = _deepCopy(G.__WEATHER_KICK_SAVED.selected)
        if G.__WEATHER_KICK_SAVED.enabled ~= nil then
            wk.enabled = (G.__WEATHER_KICK_SAVED.enabled == true)
        end
        if G.__WEATHER_KICK_SAVED.rejoin_delay_sec ~= nil then
            wk.rejoin_delay_sec = G.__WEATHER_KICK_SAVED.rejoin_delay_sec
        end
        wk = _normalizeWeatherKickState(wk)
    end

    local enabled, selected, weathers, cycles, delay = _publishWeatherKickRuntime(
        wk.enabled,
        wk.selected,
        wk.rejoin_delay_sec
    )
    return enabled, selected, weathers, cycles, delay
end

local function writeWeatherKickGlobals(enabled, selected, delay)
    enabled = (enabled == true)
    delay = _clampWeatherKickDelay(delay)

    local list = {}
    if type(selected) == "table" then
        if type(selected.selected) == "table" then
            selected = selected.selected
        end
        for _, key in ipairs(selected) do
            key = tostring(key or "")
            if key ~= "" then
                list[#list + 1] = key
            end
        end
    end

    local wk = _normalizeWeatherKickState({
        enabled = enabled,
        selected = list,
        rejoin_delay_sec = delay,
    })

    MAIN.misc = MAIN.misc or _deepCopy(DEFAULT_MISC)
    MAIN.misc.rejoin = MAIN.misc.rejoin or _deepCopy(DEFAULT_MISC.rejoin)
    MAIN.misc.rejoin.weather_kick = _deepCopy(wk)
    STATE.rejoin = type(STATE.rejoin) == "table" and STATE.rejoin or {}
    STATE.rejoin.weather_kick = _deepCopy(wk)

    return _publishWeatherKickRuntime(wk.enabled, wk.selected, wk.rejoin_delay_sec)
end

local function applyWeatherKickModule(forcedEnabled, forcedSelected, forcedDelay)
    local enabled, selected, weathers, cycles, delay
    if forcedEnabled ~= nil then
        enabled = (forcedEnabled == true)
        local readEnabled, readSelected, readWeathers, readCycles, readDelay = readWeatherKickGlobals()
        if forcedSelected ~= nil then
            selected = type(forcedSelected) == "table" and forcedSelected or {}
        else
            selected = readSelected
        end
        delay = _clampWeatherKickDelay(forcedDelay or readDelay)
        enabled, selected, weathers, cycles, delay = writeWeatherKickGlobals(enabled, selected, delay)
    else
        enabled, selected, weathers, cycles, delay = readWeatherKickGlobals()
    end

    local WK = G.WeatherKick or _G.WeatherKick
    if type(WK) ~= "table" then return end

    local selectedKey = table.concat(selected or {}, "\31")
    local appliedKey = table.concat(__weatherKickApplied.selected or {}, "\31")
    if forcedEnabled == nil and forcedSelected == nil and forcedDelay == nil
        and __weatherKickApplied.enabled == enabled
        and appliedKey == selectedKey
        and __weatherKickApplied.delay == delay then
        if enabled == true and type(WK._ensureRunning) == "function" then
            pcall(function() WK:_ensureRunning() end)
        end
        return
    end

    if type(WK.Apply) == "function" then
        pcall(function() WK:Apply(enabled, selected, delay) end)
    elseif enabled == true then
        if type(WK.Start) == "function" then pcall(function() WK:Start() end) end
    elseif type(WK.Stop) == "function" then
        pcall(function() WK:Stop("disabled") end)
    end

    __weatherKickApplied.enabled = enabled
    __weatherKickApplied.selected = _deepCopy(selected)
    __weatherKickApplied.delay = delay
end

G.readWeatherKickGlobals   = readWeatherKickGlobals
_G.readWeatherKickGlobals  = readWeatherKickGlobals
G.writeWeatherKickGlobals  = writeWeatherKickGlobals
_G.writeWeatherKickGlobals = writeWeatherKickGlobals
G.applyWeatherKickModule   = applyWeatherKickModule
_G.applyWeatherKickModule  = applyWeatherKickModule

local function _normalizeAutoHopState(ah)
    ah = type(ah) == "table" and ah or _deepCopy(DEFAULT_MISC.rejoin.auto_hop)
    if tonumber(ah.current_player) == nil and tonumber(ah.current) ~= nil then
        ah.current_player = tonumber(ah.current)
    end
    if tonumber(ah.max_player) == nil and tonumber(ah.max) ~= nil then
        ah.max_player = tonumber(ah.max)
    end
    if tonumber(ah.teleport_delay) == nil and tonumber(ah.delay) ~= nil then
        ah.teleport_delay = tonumber(ah.delay)
    end
    ah.enabled = (ah.enabled == true)
    ah.current_player = math.floor(math.max(1, math.min(100, tonumber(ah.current_player) or 1)))
    ah.max_player = math.floor(math.max(1, math.min(100, tonumber(ah.max_player) or 1)))
    ah.teleport_delay = math.floor(math.max(10, math.min(600, tonumber(ah.teleport_delay) or 10)))
    ah.minutes = math.floor(math.max(1, math.min(1440, tonumber(ah.minutes) or 8)))
    ah.diff_servers = math.floor(math.max(1, math.min(200, tonumber(ah.diff_servers) or 5)))
    if type(ah.visited) ~= "table" then ah.visited = {} end
    ah.current = nil
    ah.max = nil
    ah.delay = nil
    return ah
end

local function syncRejoinGlobalsFromMain()
    MAIN.misc = MAIN.misc or _deepCopy(DEFAULT_MISC)
    MAIN.misc.rejoin = MAIN.misc.rejoin or _deepCopy(DEFAULT_MISC.rejoin)
    local rj = MAIN.misc.rejoin

    AUTO_RECONNECT_ENABLED = (rj.auto_reconnect == true)
    AUTO_START_ON_REJOIN = (rj.auto_exec == true)
    G.AUTO_RECONNECT_ENABLED = AUTO_RECONNECT_ENABLED
    G.AUTO_START_ON_REJOIN = AUTO_START_ON_REJOIN
    _G.AUTO_RECONNECT_ENABLED = AUTO_RECONNECT_ENABLED
    _G.AUTO_START_ON_REJOIN = AUTO_START_ON_REJOIN

    rj.auto_hop = _normalizeAutoHopState(rj.auto_hop)
    if type(rj.weather_kick) == "table" then
        rj.weather_kick = _normalizeWeatherKickState(rj.weather_kick)
    end
    local ah = rj.auto_hop
    AUTO_HOP_ENABLED = ah.enabled
    AUTO_HOP_CURRENT_PLAYER = ah.current_player
    AUTO_HOP_MAX_PLAYER = ah.max_player
    G.AUTO_HOP_ENABLED = AUTO_HOP_ENABLED
    G.AUTO_HOP_CURRENT_PLAYER = AUTO_HOP_CURRENT_PLAYER
    G.AUTO_HOP_MAX_PLAYER = AUTO_HOP_MAX_PLAYER
    G.AUTO_HOP_TELEPORT_DELAY = ah.teleport_delay
    _G.AUTO_HOP_ENABLED = AUTO_HOP_ENABLED
    _G.AUTO_HOP_CURRENT_PLAYER = AUTO_HOP_CURRENT_PLAYER
    _G.AUTO_HOP_MAX_PLAYER = AUTO_HOP_MAX_PLAYER
    _G.AUTO_HOP_TELEPORT_DELAY = ah.teleport_delay

    STATE.rejoin = _deepCopy(rj)
    G.MAIN = MAIN
    _G.MAIN = MAIN
end

local function syncRejoinGlobalsToMain()
    MAIN.misc = MAIN.misc or _deepCopy(DEFAULT_MISC)
    MAIN.misc.rejoin = MAIN.misc.rejoin or _deepCopy(DEFAULT_MISC.rejoin)
    local rj = MAIN.misc.rejoin

    rj.auto_reconnect = (AUTO_RECONNECT_ENABLED == true)
    rj.auto_exec      = (AUTO_START_ON_REJOIN == true)

    -- auto_hop: MAIN is source of truth — never overwrite from stale globals on save
    rj.auto_hop = _normalizeAutoHopState(rj.auto_hop)
    syncRejoinGlobalsFromMain()

    STATE.rejoin = STATE.rejoin or {}
    STATE.rejoin.auto_reconnect = rj.auto_reconnect
    STATE.rejoin.auto_exec      = rj.auto_exec
    STATE.rejoin.update_new_server        = rj.update_new_server
    STATE.rejoin.update_new_server_minute = rj.update_new_server_minute
    STATE.rejoin.auto_hop = _deepCopy(rj.auto_hop)
    if type(rj.weather_kick) == "table" then
        STATE.rejoin.weather_kick = _deepCopy(rj.weather_kick)
    end

    G.MAIN = MAIN
    _G.MAIN = MAIN
end

--------------------------------------------------
-- FILE SAVE
--------------------------------------------------
-- Persist (save/load file) — satu pintu untuk semua fitur
-- UI/tabs: tulis ke G.__GAG2_* store + MAIN, lalu panggil G.__GAG2_STATE_SAVE()
-- Boot: loadSelectionsFromFile() -> restore*FromData() -> sync*FromMain()
--------------------------------------------------
local CAN_FS = (typeof(writefile) == "function" and typeof(readfile) == "function"
    and typeof(isfile) == "function" and typeof(makefolder) == "function")

local SAVE_DIR = "growagarden2"

local function _safeName(s)
    s = tostring(s or "player")
    s = s:gsub("[^%w%-_.]", "_"):gsub("_+", "_")
    return s:sub(1, 48)
end

local SAVE_FILE = ("%s/%s.json"):format(SAVE_DIR, _safeName(LP.Name))

local function _ensureFolder()
    if not CAN_FS then return false end
    if not isfolder(SAVE_DIR) then pcall(makefolder, SAVE_DIR) end
    return isfolder(SAVE_DIR)
end

local AUTO_PERSIST_KEYS = {
    "collect", "plant", "trowel", "sprinkler", "watering", "fav", "unfav", "sell",
    "shovel", "shovelFruit", "buy", "claimSeed", "dragonEgg", "openEgg", "sprinklerOtherGarden", "sellPet", "autoTele", "gift",
}

local function _adoptLiveMain()
    local live = G.MAIN or _G.MAIN
    if type(live) ~= "table" then return end

    MAIN.auto = MAIN.auto or _deepCopy(DEFAULT_AUTO)
    if type(live.auto) == "table" then
        for _, key in ipairs(AUTO_PERSIST_KEYS) do
            if type(live.auto[key]) == "table" then
                MAIN.auto[key] = _deepCopy(live.auto[key])
            end
        end
    end

    if type(live.misc) == "table" then
        MAIN.misc = MAIN.misc or _deepCopy(DEFAULT_MISC)
        if type(live.misc.rejoin) == "table" then
            MAIN.misc.rejoin = _deepCopy(live.misc.rejoin)
        end
        if type(live.misc.weather_predict) == "table" then
            MAIN.misc.weather_predict = _deepCopy(live.misc.weather_predict)
        end
        if type(live.misc.pet_finder) == "table" then
            MAIN.misc.pet_finder = _deepCopy(live.misc.pet_finder)
        end
        if type(live.misc.perf) == "table" then
            MAIN.misc.perf = _deepCopy(live.misc.perf)
        end
        if type(live.misc.fruit_backpack_esp) == "table" then
            MAIN.misc.fruit_backpack_esp = _deepCopy(live.misc.fruit_backpack_esp)
        end
        if type(live.misc.fruit_garden_esp) == "table" then
            MAIN.misc.fruit_garden_esp = _deepCopy(live.misc.fruit_garden_esp)
        end
        if type(live.misc.hide_prompt) == "table" then
            MAIN.misc.hide_prompt = _deepCopy(live.misc.hide_prompt)
        end
        if type(live.misc.hide_harvest_prompt) == "table" then
            MAIN.misc.hide_harvest_prompt = _deepCopy(live.misc.hide_harvest_prompt)
        end
        if type(live.misc.hide_loading) == "table" then
            MAIN.misc.hide_loading = _deepCopy(live.misc.hide_loading)
        end
        if type(live.misc.character) == "table" then
            MAIN.misc.character = _deepCopy(live.misc.character)
        end
        if type(live.misc.auto_vuln) == "table" then
            MAIN.misc.auto_vuln = _deepCopy(live.misc.auto_vuln)
        end
    end

    G.MAIN = MAIN
    _G.MAIN = MAIN
end

local function _pullUiStoresIntoMain()
    MAIN.auto = MAIN.auto or _deepCopy(DEFAULT_AUTO)

    local tele = G.__GAG2_AUTO_TELE or _G.__GAG2_AUTO_TELE
    if type(tele) == "table" then
        MAIN.auto.autoTele = _normalizeAutoTeleState({
            enabled = (tele.enabled == true),
            delay = tele.delay,
            selectedLocation = tele.selectedLocation,
            mode = tele.mode,
        })
    end

    local gift = G.__GAG2_AUTO_GIFT or _G.__GAG2_AUTO_GIFT
    if type(gift) == "table" then
        local oncePayload = _giftProfilePayloadFromStoreProfile(gift.once, true)
        local loopPayload = _giftProfilePayloadFromStoreProfile(gift.loop, false)
        if type(gift.once) ~= "table" and type(gift.categories) == "table" then
            local maps = {}
            if type(gift.selected) == "table" then
                for _, key in ipairs(_giftCategoryKeysFromState(gift)) do
                    maps[key] = _arrayToMap(gift.selected[key])
                end
            end
            oncePayload = _normalizeGiftProfileFieldsState({
                categories = _deepCopy(gift.categories),
                selected = _giftSelectedArraysFromMaps(maps),
                category_mode = "single",
                send_total = gift.send_total,
                after_send_mode = gift.after_send_mode,
            }, true)
        end
        if type(gift.loop) ~= "table" and type(gift.categories) == "table" then
            local maps = {}
            if type(gift.selected) == "table" then
                for _, key in ipairs(_giftCategoryKeysFromState(gift)) do
                    maps[key] = _arrayToMap(gift.selected[key])
                end
            end
            loopPayload = _normalizeGiftProfileFieldsState({
                categories = _deepCopy(gift.categories),
                selected = _giftSelectedArraysFromMaps(maps),
                category_mode = gift.category_mode,
                after_send_mode = gift.after_send_mode,
            }, false)
        end
        MAIN.auto.gift = _normalizeAutoGiftState({
            enabled = (gift.enabled == true),
            auto_send = (gift.auto_send == true),
            auto_claim_mail = (gift.auto_claim_mail == true),
            auto_accept_gift = (gift.auto_accept_gift == true),
            auto_claim_drop = (gift.auto_claim_drop == true),
            recipient_username = gift.recipient_username,
            recipient_user_id = gift.recipient_user_id,
            recipient_display = gift.recipient_display,
            skip_equipped = gift.skip_equipped,
            max_per_batch = gift.max_per_batch,
            note = gift.note,
            delay_sec = gift.delay_sec,
            send_totals = type(gift.send_totals) == "table" and _deepCopy(gift.send_totals) or {},
            once = oncePayload,
            loop = loopPayload,
            categories = oncePayload.categories,
            selected = oncePayload.selected,
            category_mode = loopPayload.category_mode,
            send_list_mode = gift.send_list_mode,
            send_total = oncePayload.send_total,
            after_send_mode = oncePayload.after_send_mode,
        })
    end

    local ng = G.__GAG2_NORMAL_GIFT or _G.__GAG2_NORMAL_GIFT
    if type(ng) == "table" then
        MAIN.auto.normalGift = _normalizeAutoNormalGiftState({
            target_user_id = ng.target_user_id,
            target_name = ng.target_name,
            category = ng.category,
            selected = _mapToArray(ng.selected),
            send_total = ng.send_total,
        })
    end

    local claim = G.__GAG2_CLAIM_SEED or _G.__GAG2_CLAIM_SEED
    if type(claim) == "table" then
        MAIN.auto.claimSeed = _normalizeAutoClaimSeedState({
            enabled = (claim.enabled == true),
        })
    end

    local shovel = G.__GAG2_SHOVEL or _G.__GAG2_SHOVEL
    if type(shovel) == "table" then
        MAIN.auto.shovel = _normalizeAutoShovelState({
            enabled = (shovel.enabled == true),
            plants = type(shovel.plants) == "table" and shovel.plants or {},
            heightRule = shovel.heightRule or G.AUTO_SHOVEL_HEIGHT_RULE or "0",
        })
    end

    local flushDe = G.__GAG2_FLUSH_DRAGON_EGG or rawget(_G, "__GAG2_FLUSH_DRAGON_EGG")
    if type(flushDe) == "function" then
        pcall(flushDe)
    else
        syncAutoDragonEggGlobalsToMain()
    end

    local flushOe = G.__GAG2_FLUSH_OPEN_EGG or rawget(_G, "__GAG2_FLUSH_OPEN_EGG")
    if type(flushOe) == "function" then
        pcall(flushOe)
    else
        syncOpenEggGlobalsToMain()
    end

    local flushSw = G.__GAG2_FLUSH_SPRINKLER_OTHER or rawget(_G, "__GAG2_FLUSH_SPRINKLER_OTHER")
    if type(flushSw) == "function" then
        pcall(flushSw)
    else
        syncSprinklerOtherGardenGlobalsToMain()
    end

    local flushSp = G.__GAG2_FLUSH_SELL_PET or rawget(_G, "__GAG2_FLUSH_SELL_PET")
    if type(flushSp) == "function" then
        pcall(flushSp)
    else
        syncAutoSellPetGlobalsToMain()
    end

    local petStore = G.__GAG2_BUY_PET or _G.__GAG2_BUY_PET
    local buySnap = G.__GAG2_AUTO_BUY or _G.__GAG2_AUTO_BUY
    if type(buySnap) == "table" then
        MAIN.auto.buy = _normalizeAutoBuyState(_deepCopy(buySnap))
    end
    if type(petStore) == "table" then
        MAIN.auto.buy = MAIN.auto.buy or _deepCopy(DEFAULT_AUTO.buy)
        local pet = MAIN.auto.buy.pet or _deepCopy(DEFAULT_AUTO.buy.pet)
        pet.enabled = (petStore.enabled == true)
        pet.auto_tame = (petStore.auto_tame == true)
        pet.max_price_mult = nil
        pet.max_steal_price = tonumber(petStore.max_steal_price) or pet.max_steal_price or 100000000
        if type(petStore.selected) == "table" then
            pet.items = _mapToArray(petStore.selected)
        end
        MAIN.auto.buy.pet = pet
        MAIN.auto.buy = _normalizeAutoBuyState(MAIN.auto.buy)
    end

    local col = G.__GAG2_AUTO_COLLECT or _G.__GAG2_AUTO_COLLECT
    if type(col) == "table" then
        MAIN.auto.collect = _normalizeAutoCollectState({
            enabled = (col.enabled == true),
            delay = col.delay,
            fruits = col.fruits,
            mutations = col.mutations,
            kg = col.kg,
            kgMode = col.kgMode,
            kgRule = col.kgRule,
            priority = col.priority,
            rules = col.rules,
            rulesOrder = col.rulesOrder,
            filterMode = "rules",
        })
    end

    local pl = G.__GAG2_AUTO_PLANT or _G.__GAG2_AUTO_PLANT
    if type(pl) == "table" then
        MAIN.auto.plant = _normalizeAutoPlantState({
            enabled = (pl.enabled == true),
            seeds = pl.seeds,
            positions = pl.positions,
            mode = pl.mode,
            delay = pl.delay,
            autoManual = pl.autoManual,
            selectedPosition = pl.selectedPosition,
            selectedPositions = pl.selectedPositions,
            savePosition = pl.savePosition,
        })
    end

    local sl = G.__GAG2_AUTO_SELL or _G.__GAG2_AUTO_SELL
    if type(sl) == "table" then
        local cur = type(MAIN.auto.sell) == "table" and MAIN.auto.sell or {}
        MAIN.auto.sell = _normalizeAutoSellState({
            enabled = (sl.enabled == true),
            minCount = sl.minCount,
            delay = sl.delay,
            sellWhenFull = sl.sellWhenFull,
            rules = cur.rules,
            rulesOrder = cur.rulesOrder,
            filterMode = cur.filterMode,
        })
    end

    local pushSp = G.__GAG2_PUSH_SPRINKLER or rawget(_G, "__GAG2_PUSH_SPRINKLER")
    if type(pushSp) == "function" then
        pcall(pushSp)
    else
        syncAutoSprinklerGlobalsToMain()
    end

    G.MAIN = MAIN
    _G.MAIN = MAIN
end

local function _normalizeMainAutoForSave()
    MAIN.auto.collect = _normalizeAutoCollectState(MAIN.auto.collect)
    MAIN.auto.plant = _normalizeAutoPlantState(MAIN.auto.plant)
    MAIN.auto.trowel = _normalizeAutoTrowelState(MAIN.auto.trowel)
    MAIN.auto.trowel.enabled = false
    MAIN.auto.sprinkler = _normalizeAutoSprinklerState(MAIN.auto.sprinkler)
    MAIN.auto.watering = _normalizeAutoWateringState(MAIN.auto.watering)
    MAIN.auto.plot = _normalizeAutoPlotState(MAIN.auto.plot)
    MAIN.auto.fav = _normalizeAutoFavState(MAIN.auto.fav)
    MAIN.auto.unfav = _normalizeAutoUnfavState(MAIN.auto.unfav)
    MAIN.auto.sell = _normalizeAutoSellState(MAIN.auto.sell)
    MAIN.auto.sellStock = _normalizeAutoSellStockState(MAIN.auto.sellStock)
    MAIN.auto.sellDaily = _normalizeAutoSellDailyState(MAIN.auto.sellDaily)
    MAIN.auto.mergeEclipse = _normalizeAutoMergeEclipseState(MAIN.auto.mergeEclipse)
    MAIN.auto.shovel = _normalizeAutoShovelState(MAIN.auto.shovel)
    MAIN.auto.shovelFruit = _normalizeAutoShovelFruitState(MAIN.auto.shovelFruit)
    MAIN.auto.buy = _normalizeAutoBuyState(MAIN.auto.buy)
    MAIN.auto.claimSeed = _normalizeAutoClaimSeedState(MAIN.auto.claimSeed)
    MAIN.auto.dragonEgg = _normalizeAutoDragonEggState(MAIN.auto.dragonEgg)
    MAIN.auto.openEgg = _normalizeOpenEggState(MAIN.auto.openEgg)
    MAIN.auto.sprinklerOtherGarden = _normalizeSprinklerOtherGardenState(MAIN.auto.sprinklerOtherGarden)
    MAIN.auto.sellPet = _normalizeAutoSellPetState(MAIN.auto.sellPet)
    MAIN.auto.autoTele = _normalizeAutoTeleState(MAIN.auto.autoTele)
    MAIN.auto.gift = _normalizeAutoGiftState(MAIN.auto.gift)
    MAIN.auto.normalGift = _normalizeAutoNormalGiftState(MAIN.auto.normalGift)
end

local function _safeNormalizeMainAutoForSave()
    local ok, err = pcall(_normalizeMainAutoForSave)
    if not ok then
        warn("[GAG2 state] normalize auto for save gagal:", tostring(err))
    end
end

local function _syncAllRuntimeFromMain()
    syncAutoCollectGlobalsFromMain()
    syncAutoPlantGlobalsFromMain()
    syncAutoTrowelGlobalsFromMain()
    syncAutoSprinklerGlobalsFromMain()
    syncAutoWateringGlobalsFromMain()
    syncAutoPlotGlobalsFromMain()
    syncAutoFavGlobalsFromMain()
    syncAutoUnfavGlobalsFromMain()
    syncAutoSellGlobalsFromMain()
    syncAutoShovelGlobalsFromMain()
    syncAutoShovelFruitGlobalsFromMain()
    syncAutoBuyGlobalsFromMain()
    syncAutoClaimSeedGlobalsFromMain()
    syncAutoDragonEggGlobalsFromMain()
    syncOpenEggGlobalsFromMain()
    syncSprinklerOtherGardenGlobalsFromMain()
    syncAutoSellPetGlobalsFromMain()
    syncAutoTeleGlobalsFromMain()
    syncAutoGiftGlobalsFromMain()
    syncNormalGiftGlobalsFromMain()
end

-- Saat save: MAIN = source of truth → snapshot (jangan timpa MAIN dari snapshot stale)
local function _syncAutoHopSnapshotFromMain()
    MAIN.misc = MAIN.misc or _deepCopy(DEFAULT_MISC)
    MAIN.misc.rejoin = MAIN.misc.rejoin or _deepCopy(DEFAULT_MISC.rejoin)
    local ah = _normalizeAutoHopState(MAIN.misc.rejoin.auto_hop)
    MAIN.misc.rejoin.auto_hop = ah

    G.__AUTO_HOP_SAVED = {
        enabled = ah.enabled,
        current = ah.current_player,
        max = ah.max_player,
        delay = ah.teleport_delay,
    }
    _G.__AUTO_HOP_SAVED = G.__AUTO_HOP_SAVED
end

-- Hop cuma update visited — jangan full save (bisa overwrite setting UI ke default)
local function saveAutoHopVisitedOnly(visited)
    if not CAN_FS or not _ensureFolder() then return end

    local out = {}
    if type(visited) == "table" then
        for _, v in ipairs(visited) do
            local s = tostring(v or "")
            if s ~= "" then out[#out + 1] = s end
        end
    end

    local data = {}
    if isfile(SAVE_FILE) then
        local ok, text = pcall(readfile, SAVE_FILE)
        if ok and type(text) == "string" and #text > 0 then
            local ok2, parsed = pcall(function()
                return HttpService:JSONDecode(text)
            end)
            if ok2 and type(parsed) == "table" then
                data = parsed
            end
        end
    end

    data.main = type(data.main) == "table" and data.main or {}
    data.main.misc = type(data.main.misc) == "table" and data.main.misc or {}
    data.main.misc.rejoin = type(data.main.misc.rejoin) == "table" and data.main.misc.rejoin or {}
    local ah = type(data.main.misc.rejoin.auto_hop) == "table" and data.main.misc.rejoin.auto_hop or {}
    data.main.misc.rejoin.auto_hop = ah

    MAIN.misc = MAIN.misc or _deepCopy(DEFAULT_MISC)
    MAIN.misc.rejoin = MAIN.misc.rejoin or _deepCopy(DEFAULT_MISC.rejoin)
    local mainAh = _normalizeAutoHopState(MAIN.misc.rejoin.auto_hop)
    MAIN.misc.rejoin.auto_hop = mainAh

    -- Merge setting dari MAIN (bukan cuma dari file stale) supaya delay/current/max tidak reset
    ah.enabled = mainAh.enabled
    ah.current_player = mainAh.current_player
    ah.max_player = mainAh.max_player
    ah.teleport_delay = mainAh.teleport_delay
    ah.minutes = mainAh.minutes
    ah.diff_servers = mainAh.diff_servers
    ah.visited = _deepCopy(out)
    ah.delay = nil

    MAIN.misc.rejoin.auto_hop.visited = _deepCopy(out)
    G.MAIN = MAIN
    _G.MAIN = MAIN

    _syncAutoHopSnapshotFromMain()

    local ok, json = pcall(function()
        return HttpService:JSONEncode(data)
    end)
    if ok and type(json) == "string" then
        pcall(writefile, SAVE_FILE, json)
    end
end

G.__GAG2_SAVE_AUTO_HOP_VISITED = saveAutoHopVisitedOnly
_G.__GAG2_SAVE_AUTO_HOP_VISITED = saveAutoHopVisitedOnly

local function _prepareMainForSave()
    local live = G.MAIN or _G.MAIN
    if type(live) == "table" then
        MAIN = live
    end
    MAIN.auto = MAIN.auto or _deepCopy(DEFAULT_AUTO)
    MAIN.misc = MAIN.misc or _deepCopy(DEFAULT_MISC)

    _pullUiStoresIntoMain()
    _syncAutoHopSnapshotFromMain()

    _safeNormalizeMainAutoForSave()
    syncRejoinGlobalsToMain()
    syncWeatherPredictGlobalsToMain()
    syncPetFinderGlobalsToMain()
    syncReduceFpsGlobalsToMain()
    syncFruitBackpackEspGlobalsToMain()
    syncFruitGardenEspGlobalsToMain()
    syncHidePromptGlobalsToMain()
    syncHideHarvestPromptGlobalsToMain()
    syncHideLoadingGlobalsToMain()
    syncCharacterGlobalsToMain()
    syncAutoVulnGlobalsToMain()
    _syncAllRuntimeFromMain()
    G.MAIN = MAIN
    _G.MAIN = MAIN
end

local function saveSelectionsToFile()
    if not CAN_FS or not _ensureFolder() then return end

    _prepareMainForSave()

    local enabled, minute = readUpdateNewServerGlobals()
    MAIN.misc.rejoin.update_new_server        = enabled
    MAIN.misc.rejoin.update_new_server_minute  = minute

    local payload = {
        running = (STATE.scriptRunning == true),
        main = {
            misc = {
                rejoin = _deepCopy(MAIN.misc.rejoin),
                weather_predict = _deepCopy(MAIN.misc.weather_predict),
                pet_finder = _snapshotPetFinderForSave(MAIN.misc.pet_finder),
                perf = _deepCopy(MAIN.misc.perf),
                fruit_backpack_esp = _deepCopy(MAIN.misc.fruit_backpack_esp),
                fruit_garden_esp = _deepCopy(MAIN.misc.fruit_garden_esp),
                hide_prompt = _deepCopy(MAIN.misc.hide_prompt),
                hide_harvest_prompt = _deepCopy(MAIN.misc.hide_harvest_prompt),
                hide_loading = _deepCopy(MAIN.misc.hide_loading),
                character = _deepCopy(MAIN.misc.character),
                auto_vuln = _deepCopy(MAIN.misc.auto_vuln),
            },
            auto = {
                collect = _deepCopy(MAIN.auto.collect),
                sell = _deepCopy(MAIN.auto.sell),
                sellStock = _deepCopy(MAIN.auto.sellStock),
                sellDaily = _deepCopy(MAIN.auto.sellDaily),
                mergeEclipse = _deepCopy(MAIN.auto.mergeEclipse),
                shovel = _deepCopy(MAIN.auto.shovel),
                shovelFruit = _deepCopy(MAIN.auto.shovelFruit),
                plant = _deepCopy(MAIN.auto.plant),
                trowel = _deepCopy(MAIN.auto.trowel),
                sprinkler = _deepCopy(MAIN.auto.sprinkler),
                watering = _deepCopy(MAIN.auto.watering),
                plot = _deepCopy(MAIN.auto.plot),
                fav = _deepCopy(MAIN.auto.fav),
                unfav = _deepCopy(MAIN.auto.unfav),
                buy = _deepCopy(MAIN.auto.buy),
                claimSeed = _deepCopy(MAIN.auto.claimSeed),
                dragonEgg = _deepCopy(MAIN.auto.dragonEgg),
                openEgg = _deepCopy(MAIN.auto.openEgg),
                sprinklerOtherGarden = _deepCopy(MAIN.auto.sprinklerOtherGarden),
                sellPet = _deepCopy(MAIN.auto.sellPet),
                autoTele = _deepCopy(MAIN.auto.autoTele),
                gift = _deepCopy(MAIN.auto.gift),
                normalGift = _deepCopy(MAIN.auto.normalGift),
                dropItem = _deepCopy(MAIN.auto.dropItem),
            },
        },
    }

    local ok, json = pcall(function()
        return HttpService:JSONEncode(payload)
    end)
    if ok and type(json) == "string" then
        pcall(writefile, SAVE_FILE, json)
    end
end

