    G.AUTO_START_ON_REJOIN = AUTO_START_ON_REJOIN
    _G.AUTO_RECONNECT_ENABLED = AUTO_RECONNECT_ENABLED
    _G.AUTO_START_ON_REJOIN = AUTO_START_ON_REJOIN

    local ah = rj.auto_hop or {}
    AUTO_HOP_ENABLED = (ah.enabled == true)
    AUTO_HOP_CURRENT_PLAYER = math.floor(math.max(1, math.min(100, tonumber(ah.current_player) or 1)))
    AUTO_HOP_MAX_PLAYER = math.floor(math.max(1, math.min(100, tonumber(ah.max_player) or 1)))
    G.AUTO_HOP_ENABLED = AUTO_HOP_ENABLED
    G.AUTO_HOP_CURRENT_PLAYER = AUTO_HOP_CURRENT_PLAYER
    G.AUTO_HOP_MAX_PLAYER = AUTO_HOP_MAX_PLAYER
    G.AUTO_HOP_TELEPORT_DELAY = math.floor(math.max(10, math.min(600, tonumber(ah.teleport_delay) or 10)))
    _G.AUTO_HOP_ENABLED = AUTO_HOP_ENABLED
    _G.AUTO_HOP_CURRENT_PLAYER = AUTO_HOP_CURRENT_PLAYER
    _G.AUTO_HOP_MAX_PLAYER = AUTO_HOP_MAX_PLAYER
    _G.AUTO_HOP_TELEPORT_DELAY = G.AUTO_HOP_TELEPORT_DELAY

    writeUpdateNewServerGlobals(
        __truthy(rj.update_new_server),
