    G.__GAG2_AUTO_GIFT._hydrated = true
    _G.__GAG2_AUTO_GIFT = G.__GAG2_AUTO_GIFT
    G.__GAG2_GIFT_STORE_EPOCH = (tonumber(G.__GAG2_GIFT_STORE_EPOCH) or 0) + 1
