local function applyResetRuntime()
    local function stopMod(mod)
        if type(mod) ~= "table" then return end
        if type(mod.Stop) == "function" then
            pcall(mod.Stop, mod)
        elseif type(mod.stop) == "function" then
            pcall(mod.stop, mod)
        end
    end

    stopMod(G.AutoCollectFruit or rawget(_G, "AutoCollectFruit"))
    stopMod(G.AutoSellFruit or rawget(_G, "AutoSellFruit"))
    stopMod(G.AutoPlant or rawget(_G, "AutoPlant"))
    stopMod(G.AutoTrowel or rawget(_G, "AutoTrowel"))
    stopMod(G.AutoSprinkler or rawget(_G, "AutoSprinkler"))
    stopMod(G.AutoWatering or rawget(_G, "AutoWatering"))
    stopMod(G.AutoSprinklerOtherGarden or rawget(_G, "AutoSprinklerOtherGarden")
        or G.AutoVulnSprinklerWater or rawget(_G, "AutoVulnSprinklerWater"))
    stopMod(G.AutoFav or rawget(_G, "AutoFav"))
    stopMod(G.AutoBuy or rawget(_G, "AutoBuy"))
    stopMod(G.AutoBuyPet or rawget(_G, "AutoBuyPet"))
    stopMod(G.AutoGift or rawget(_G, "AutoGift"))
    stopMod(G.AutoClaimSeed or rawget(_G, "AutoClaimSeed"))
    stopMod(G.AutoDragonEgg or rawget(_G, "AutoDragonEgg"))
    stopMod(G.AutoSellPet or rawget(_G, "AutoSellPet"))
    stopMod(G.AutoMergeEclipseBloom or rawget(_G, "AutoMergeEclipseBloom"))
    stopMod(G.AutoShovel or rawget(_G, "AutoShovel"))
    stopMod(G.AutoShovelFruit or rawget(_G, "AutoShovelFruit"))
    stopMod(G.AutoHopServer or rawget(_G, "AutoHopServer"))
    stopMod(G.ReduceFPS or rawget(_G, "ReduceFPS"))
    stopMod(G.ReduceLag or rawget(_G, "ReduceLag"))
    stopMod(G.EspFruitBackpack or rawget(_G, "EspFruitBackpack"))
    stopMod(G.EspFruitGarden or rawget(_G, "EspFruitGarden"))
    stopMod(G.Character or rawget(_G, "Character"))

    local R = G.PSReconnect or rawget(_G, "PSReconnect")
    if type(R) == "table" then
        if type(R.SetHideTeleportPrompt) == "function" then
            pcall(R.SetHideTeleportPrompt, R, false)
        end
        if type(R.SetEnabled) == "function" then
            pcall(R.SetEnabled, R, false)
        elseif type(R.setEnabled) == "function" then
            pcall(R.setEnabled, R, false)
        end
    end

    pcall(applyUpdateNewServerModule, false, DEFAULT_MISC.rejoin.update_new_server_minute or 30)

    local function syncModFromGlobals(...)
        for _, name in ipairs({ ... }) do
            local mod = G[name] or rawget(_G, name)
            if type(mod) == "table" then
                if type(mod.SyncFromGlobals) == "function" then
                    pcall(mod.SyncFromGlobals, mod)
                elseif type(mod.syncFromGlobals) == "function" then
                    pcall(mod.syncFromGlobals, mod)
                end
            end
        end
    end

    syncModFromGlobals(
        "AutoCollectFruit", "CollectFruitModule",
        "AutoSellFruit", "AutoPlant", "AutoFav", "AutoBuy", "AutoBuyPet",
        "AutoGift", "NormalGift", "AutoClaimSeed", "AutoDragonEgg", "AutoSellPet", "AutoShovel", "AutoShovelFruit", "AutoHopServer",
        "AutoTele", "WeatherPredict", "PetFinder", "PetFinderModule", "ReduceFPS", "ReduceLag", "EspFruitBackpack", "Character"
    )
end

local function restoreRejoinFromData(data)
    if type(data) ~= "table" then return end

    local rj = {}
    if type(data.main) == "table" and type(data.main.misc) == "table" and type(data.main.misc.rejoin) == "table" then
        for k, v in pairs(data.main.misc.rejoin) do rj[k] = v end
    end
    if type(data.rejoin) == "table" then
        for k, v in pairs(data.rejoin) do
            if rj[k] == nil then rj[k] = v end
        end
    end
    if next(rj) == nil then return end

    if type(rj.auto_reconnect) == "boolean" then
        AUTO_RECONNECT_ENABLED = rj.auto_reconnect
    end
    if type(rj.auto_exec) == "boolean" then
        AUTO_START_ON_REJOIN = rj.auto_exec
    end

    G.AUTO_RECONNECT_ENABLED = AUTO_RECONNECT_ENABLED
    G.AUTO_START_ON_REJOIN   = AUTO_START_ON_REJOIN
    _G.AUTO_RECONNECT_ENABLED = AUTO_RECONNECT_ENABLED
    _G.AUTO_START_ON_REJOIN   = AUTO_START_ON_REJOIN

    MAIN.misc = MAIN.misc or _deepCopy(DEFAULT_MISC)
    MAIN.misc.rejoin = MAIN.misc.rejoin or _deepCopy(DEFAULT_MISC.rejoin)
    for k, v in pairs(rj) do
        if k ~= "auto_hop" then
            MAIN.misc.rejoin[k] = v
        end
    end
    if type(rj.auto_hop) == "table" then
        MAIN.misc.rejoin.auto_hop = _normalizeAutoHopState(_deepCopy(rj.auto_hop))
        local ah = MAIN.misc.rejoin.auto_hop
        writeAutoHopGlobals(ah.enabled, ah.current_player, ah.max_player, ah.teleport_delay)
    end
    if type(rj.weather_kick) == "table" then
        MAIN.misc.rejoin.weather_kick = _normalizeWeatherKickState(_deepCopy(rj.weather_kick))
        local wk = MAIN.misc.rejoin.weather_kick
        writeWeatherKickGlobals(wk.enabled, wk.selected, wk.rejoin_delay_sec)
    end
    G.MAIN = MAIN
    _G.MAIN = MAIN

    if rj.update_new_server ~= nil or rj.update_new_server_minute ~= nil then
        writeUpdateNewServerGlobals(
            __truthy(rj.update_new_server),
            rj.update_new_server_minute or 30
        )
    end

    STATE.rejoin = _deepCopy(MAIN.misc.rejoin)
end

local function restoreAutoCollectFromData(data)
    if type(data) ~= "table" then return end

    local src = {}
    local function merge(from)
        if type(from) ~= "table" then return end
        for k, v in pairs(from) do
            src[k] = v
        end
    end

    merge(type(data.auto_collect) == "table" and data.auto_collect or nil)
    merge(type(data.auto) == "table" and data.auto.collect or nil)
    merge(type(data.main) == "table" and type(data.main.auto) == "table" and data.main.auto.collect or nil)

    if next(src) == nil then return end

    MAIN.auto = MAIN.auto or _deepCopy(DEFAULT_AUTO)
    MAIN.auto.collect = MAIN.auto.collect or _deepCopy(DEFAULT_AUTO.collect)
    for k, v in pairs(src) do
        MAIN.auto.collect[k] = v
    end
    MAIN.auto.collect = _normalizeAutoCollectState(MAIN.auto.collect)

    syncAutoCollectGlobalsFromMain()
end

local function restoreAutoSellFromData(data)
    if type(data) ~= "table" then return end

    local src = {}
    local function merge(from)
        if type(from) ~= "table" then return end
        for k, v in pairs(from) do
            src[k] = v
        end
    end

    merge(type(data.auto_sell) == "table" and data.auto_sell or nil)
    merge(type(data.auto) == "table" and data.auto.sell or nil)
    merge(type(data.main) == "table" and type(data.main.auto) == "table" and data.main.auto.sell or nil)

    if next(src) == nil then return end

    MAIN.auto = MAIN.auto or _deepCopy(DEFAULT_AUTO)
    MAIN.auto.sell = MAIN.auto.sell or _deepCopy(DEFAULT_AUTO.sell)
    for k, v in pairs(src) do
        if k ~= "stock" and k ~= "daily" then
            MAIN.auto.sell[k] = v
        end
    end
    -- legacy nested → top-level
    if type(src.stock) == "table" then
        MAIN.auto.sellStock = _normalizeAutoSellStockState(src.stock)
    end
    if type(src.daily) == "table" then
        MAIN.auto.sellDaily = _normalizeAutoSellDailyState(src.daily)
    end

    syncAutoSellGlobalsFromMain()
    if type(src.stock) == "table" then syncAutoSellStockGlobalsFromMain() end
    if type(src.daily) == "table" then syncAutoSellDailyGlobalsFromMain() end
end

