local function _safeRestoreStep(label, fn, data)
    local ok, err = pcall(fn, data)
    if not ok then
        warn(("[GAG2 state] restore %s gagal: %s"):format(tostring(label), tostring(err)))
    end
end

local function loadSelectionsFromFile()
    if not CAN_FS or not isfile(SAVE_FILE) then return end

    local ok, text = pcall(readfile, SAVE_FILE)
    if not ok or type(text) ~= "string" or #text == 0 then return end

    local ok2, data = pcall(function()
        return HttpService:JSONDecode(text)
    end)
    if not ok2 or type(data) ~= "table" then return end

    if type(data.running) == "boolean" then
        STATE.scriptRunning = data.running
        G.scriptRunning = STATE.scriptRunning
    end

    _safeRestoreStep("rejoin", restoreRejoinFromData, data)
    _safeRestoreStep("collect", restoreAutoCollectFromData, data)
    _safeRestoreStep("plant", restoreAutoPlantFromData, data)
    _safeRestoreStep("trowel", restoreAutoTrowelFromData, data)
    _safeRestoreStep("sprinkler", restoreAutoSprinklerFromData, data)
    _safeRestoreStep("watering", restoreAutoWateringFromData, data)
    _safeRestoreStep("plot", restoreAutoPlotFromData, data)
    _safeRestoreStep("fav", restoreAutoFavFromData, data)
    _safeRestoreStep("unfav", restoreAutoUnfavFromData, data)
    _safeRestoreStep("sell", restoreAutoSellFromData, data)
    _safeRestoreStep("sellStock", restoreAutoSellStockFromData, data)
    _safeRestoreStep("sellDaily", restoreAutoSellDailyFromData, data)
    _safeRestoreStep("mergeEclipse", restoreAutoMergeEclipseFromData, data)
    _safeRestoreStep("shovel", restoreAutoShovelFromData, data)
    _safeRestoreStep("shovelFruit", restoreAutoShovelFruitFromData, data)
    _safeRestoreStep("buy", restoreAutoBuyFromData, data)
    _safeRestoreStep("claimSeed", restoreAutoClaimSeedFromData, data)
    _safeRestoreStep("dragonEgg", restoreAutoDragonEggFromData, data)
    _safeRestoreStep("openEgg", restoreOpenEggFromData, data)
    _safeRestoreStep("sprinklerOtherGarden", restoreSprinklerOtherGardenFromData, data)
    _safeRestoreStep("sellPet", restoreAutoSellPetFromData, data)
    _safeRestoreStep("autoTele", restoreAutoTeleFromData, data)
    _safeRestoreStep("gift", restoreAutoGiftFromData, data)
    _safeRestoreStep("normalGift", restoreNormalGiftFromData, data)
    _safeRestoreStep("dropItem", restoreAutoDropFromData, data)
    _safeRestoreStep("weather_predict", restoreWeatherPredictFromData, data)
    _safeRestoreStep("pet_finder", restorePetFinderFromData, data)
    _safeRestoreStep("perf", restorePerfFromData, data)
    _safeRestoreStep("fruit_backpack_esp", restoreFruitBackpackEspFromData, data)
    _safeRestoreStep("fruit_garden_esp", restoreFruitGardenEspFromData, data)
    _safeRestoreStep("hide_prompt", restoreHidePromptFromData, data)
    _safeRestoreStep("hide_harvest_prompt", restoreHideHarvestPromptFromData, data)
    _safeRestoreStep("character", restoreCharacterFromData, data)
    _safeRestoreStep("auto_vuln", restoreAutoVulnFromData, data)
    _safeRestoreStep("hide_loading", restoreHideLoadingFromData, data)

    local okGift, errGift = pcall(syncAutoGiftGlobalsFromMain)
    if not okGift then
        warn("[GAG2 state] sync gift gagal:", tostring(errGift))
    end
    pcall(syncAutoTeleGlobalsFromMain)
    pcall(syncNormalGiftGlobalsFromMain)
    pcall(syncAutoDropGlobalsFromMain)
end

loadSelectionsFromFile()
syncRejoinGlobalsFromMain()
applyAutoHopModule()
applyWeatherKickModule()
syncAutoCollectGlobalsFromMain()
syncAutoPlantGlobalsFromMain()
syncAutoSprinklerGlobalsFromMain()
syncAutoWateringGlobalsFromMain()
syncAutoFavGlobalsFromMain()
syncAutoUnfavGlobalsFromMain()
syncAutoSellGlobalsFromMain()
syncAutoSellStockGlobalsFromMain()
syncAutoSellDailyGlobalsFromMain()
syncAutoMergeEclipseGlobalsFromMain()
syncAutoShovelGlobalsFromMain()
syncAutoShovelFruitGlobalsFromMain()
syncAutoBuyGlobalsFromMain()
