    sellDaily = _normalizeAutoSellDailyState,
    mergeEclipse = _normalizeAutoMergeEclipseState,
    shovel    = _normalizeAutoShovelState,
    shovelFruit = _normalizeAutoShovelFruitState,
    buy       = _normalizeAutoBuyState,
    claimSeed = _normalizeAutoClaimSeedState,
    dragonEgg = _normalizeAutoDragonEggState,
    openEgg = _normalizeOpenEggState,
    sprinklerOtherGarden = _normalizeSprinklerOtherGardenState,
    sellPet = _normalizeAutoSellPetState,
    autoTele  = _normalizeAutoTeleState,
    gift      = _normalizeAutoGiftState,
    normalGift = _normalizeAutoNormalGiftState,
