    trowel    = syncAutoTrowelGlobalsFromMain,
    sprinkler = syncAutoSprinklerGlobalsFromMain,
    watering  = syncAutoWateringGlobalsFromMain,
    plot      = syncAutoPlotGlobalsFromMain,
    fav       = syncAutoFavGlobalsFromMain,
    unfav     = syncAutoUnfavGlobalsFromMain,
    sell      = syncAutoSellGlobalsFromMain,
    sellStock = syncAutoSellStockGlobalsFromMain,
    sellDaily = syncAutoSellDailyGlobalsFromMain,
    mergeEclipse = syncAutoMergeEclipseGlobalsFromMain,
    shovel    = syncAutoShovelGlobalsFromMain,
    shovelFruit = syncAutoShovelFruitGlobalsFromMain,
    buy       = syncAutoBuyGlobalsFromMain,
    claimSeed = syncAutoClaimSeedGlobalsFromMain,
    dragonEgg = syncAutoDragonEggGlobalsFromMain,
    openEgg = syncOpenEggGlobalsFromMain,
    sprinklerOtherGarden = syncSprinklerOtherGardenGlobalsFromMain,
    sellPet = syncAutoSellPetGlobalsFromMain,
