    gift      = syncAutoGiftGlobalsFromMain,
    normalGift = syncNormalGiftGlobalsFromMain,
    dropItem = syncAutoDropGlobalsFromMain,
}

local function _isArrayLike(t)
    if type(t) ~= "table" then return false end
    if t[1] ~= nil then return true end
    return next(t) == nil
end

local function _mergePartialInto(target, partial)
    if type(target) ~= "table" or type(partial) ~= "table" then return target end
    for k, v in pairs(partial) do
        if type(v) == "table" and type(target[k]) == "table"
            and not _isArrayLike(v) and not _isArrayLike(target[k]) then
            _mergePartialInto(target[k], v)
        else
            target[k] = (type(v) == "table") and _deepCopy(v) or v
        end
    end
    return target
end

local function _sanitizeBuyAuctionMaxPrices(buy)
    if type(buy) ~= "table" or type(buy.auction) ~= "table" then return end
    for _, catKey in ipairs({ "seed", "gear", "seedpack", "egg" }) do
        local cat = buy.auction[catKey]
        if type(cat) == "table" and cat.max_price ~= nil then
            cat.max_price = _parseAuctionMaxPrice(cat.max_price)
        end
    end
end

local function _applyAutoPatch(key, partial)
    if type(key) ~= "string" or type(partial) ~= "table" then return end
    MAIN.auto = MAIN.auto or _deepCopy(DEFAULT_AUTO)
    local cur = type(MAIN.auto[key]) == "table" and _deepCopy(MAIN.auto[key]) or _deepCopy(DEFAULT_AUTO[key] or {})
    _mergePartialInto(cur, partial)
    if key == "buy" then
        _sanitizeBuyAuctionMaxPrices(cur)
    end
    local norm = AUTO_NORMALIZERS[key]
    MAIN.auto[key] = norm and norm(cur) or cur
    G.MAIN = MAIN
    _G.MAIN = MAIN
end

local MISC_SYNC_FROM_MAIN = {
    rejoin              = syncRejoinGlobalsFromMain,
    weather_predict     = syncWeatherPredictGlobalsFromMain,
    pet_finder          = syncPetFinderGlobalsFromMain,
    perf                = syncReduceFpsGlobalsFromMain,
    fruit_backpack_esp  = syncFruitBackpackEspGlobalsFromMain,
    fruit_garden_esp    = syncFruitGardenEspGlobalsFromMain,
    hide_prompt         = syncHidePromptGlobalsFromMain,
    hide_harvest_prompt = syncHideHarvestPromptGlobalsFromMain,
    hide_loading        = syncHideLoadingGlobalsFromMain,
    character           = syncCharacterGlobalsFromMain,
    auto_vuln           = syncAutoVulnGlobalsFromMain,
}

local function _applyMiscPatch(key, partial)
    if type(key) ~= "string" or type(partial) ~= "table" then return end
    MAIN.misc = MAIN.misc or _deepCopy(DEFAULT_MISC)
    if key == "rejoin" then
        local cur = _deepCopy(MAIN.misc.rejoin or DEFAULT_MISC.rejoin)
        local wkReplace = partial.weather_kick
        local partialCopy = _deepCopy(partial)
        if type(wkReplace) == "table" then
            partialCopy.weather_kick = nil
        end
        _mergePartialInto(cur, partialCopy)
        if type(cur.auto_hop) == "table" then
            cur.auto_hop = _normalizeAutoHopState(cur.auto_hop)
        end
        if type(wkReplace) == "table" then
            cur.weather_kick = _normalizeWeatherKickState(_deepCopy(wkReplace))
        elseif type(cur.weather_kick) == "table" then
            cur.weather_kick = _normalizeWeatherKickState(cur.weather_kick)
        end
        MAIN.misc.rejoin = cur
    elseif key == "weather_predict" then
        local cur = _deepCopy(MAIN.misc.weather_predict or DEFAULT_MISC.weather_predict)
        _mergePartialInto(cur, partial)
        cur.enabled = (cur.enabled == true)
        MAIN.misc.weather_predict = cur
    elseif key == "pet_finder" then
        local cur = _deepCopy(MAIN.misc.pet_finder or DEFAULT_MISC.pet_finder)
        _mergePartialInto(cur, partial)
        MAIN.misc.pet_finder = _snapshotPetFinderForSave(cur)
    elseif key == "perf" then
        local cur = _deepCopy(MAIN.misc.perf or DEFAULT_MISC.perf)
        _mergePartialInto(cur, partial)
        MAIN.misc.perf = _normalizePerfState(cur)
    elseif key == "fruit_backpack_esp" then
        local cur = _deepCopy(MAIN.misc.fruit_backpack_esp or DEFAULT_MISC.fruit_backpack_esp)
        _mergePartialInto(cur, partial)
        MAIN.misc.fruit_backpack_esp = _normalizeFruitBackpackEspState(cur)
    elseif key == "fruit_garden_esp" then
        local cur = _deepCopy(MAIN.misc.fruit_garden_esp or DEFAULT_MISC.fruit_garden_esp)
        _mergePartialInto(cur, partial)
        MAIN.misc.fruit_garden_esp = _normalizeFruitGardenEspState(cur)
    elseif key == "hide_prompt" then
        local cur = _deepCopy(MAIN.misc.hide_prompt or DEFAULT_MISC.hide_prompt)
        _mergePartialInto(cur, partial)
        MAIN.misc.hide_prompt = _normalizeHidePromptState(cur)
    elseif key == "hide_harvest_prompt" then
        local cur = _deepCopy(MAIN.misc.hide_harvest_prompt or DEFAULT_MISC.hide_harvest_prompt)
        _mergePartialInto(cur, partial)
        MAIN.misc.hide_harvest_prompt = _normalizeHideHarvestPromptState(cur)
    elseif key == "hide_loading" then
        local cur = _deepCopy(MAIN.misc.hide_loading or DEFAULT_MISC.hide_loading)
        _mergePartialInto(cur, partial)
        MAIN.misc.hide_loading = _normalizeHideLoadingState(cur)
    elseif key == "character" then
        local cur = _deepCopy(MAIN.misc.character or DEFAULT_MISC.character)
        _mergePartialInto(cur, partial)
        MAIN.misc.character = _normalizeCharacterState(cur)
    elseif key == "auto_vuln" then
        local cur = _deepCopy(MAIN.misc.auto_vuln or DEFAULT_MISC.auto_vuln)
        _mergePartialInto(cur, partial)
        MAIN.misc.auto_vuln = _normalizeAutoVulnState(cur)
    end
    G.MAIN = MAIN
    _G.MAIN = MAIN
end

function State.getMisc(key)
    if type(key) ~= "string" then return nil end
    MAIN.misc = MAIN.misc or _deepCopy(DEFAULT_MISC)
    if key == "rejoin" then return MAIN.misc.rejoin end
    if key == "weather_predict" then return MAIN.misc.weather_predict end
    if key == "pet_finder" then return MAIN.misc.pet_finder end
    if key == "perf" then return MAIN.misc.perf end
    if key == "fruit_backpack_esp" then return MAIN.misc.fruit_backpack_esp end
    if key == "fruit_garden_esp" then return MAIN.misc.fruit_garden_esp end
    if key == "hide_prompt" then
        MAIN.misc.hide_prompt = _normalizeHidePromptState(MAIN.misc.hide_prompt)
        return MAIN.misc.hide_prompt
    end
    if key == "hide_harvest_prompt" then
        MAIN.misc.hide_harvest_prompt = _normalizeHideHarvestPromptState(MAIN.misc.hide_harvest_prompt)
        return MAIN.misc.hide_harvest_prompt
    end
    if key == "hide_loading" then
        MAIN.misc.hide_loading = _normalizeHideLoadingState(MAIN.misc.hide_loading)
        return MAIN.misc.hide_loading
    end
    if key == "character" then
        MAIN.misc.character = _normalizeCharacterState(MAIN.misc.character)
        return MAIN.misc.character
    end
    if key == "auto_vuln" then
        MAIN.misc.auto_vuln = _normalizeAutoVulnState(MAIN.misc.auto_vuln)
        return MAIN.misc.auto_vuln
    end
    return nil
end

function State.patchMisc(key, partial, opts)
    opts = type(opts) == "table" and opts or {}
    if type(key) ~= "string" or type(partial) ~= "table" then
        return State.getMisc(key)
    end
    _applyMiscPatch(key, partial)
    if not opts.noSync then
        local sync = MISC_SYNC_FROM_MAIN[key]
        if sync then sync() end
    end
    return State.getMisc(key)
end

function State.getMain()
    G.MAIN = MAIN
    _G.MAIN = MAIN
    return MAIN
end

function State.getAuto(key)
    if type(key) ~= "string" then return nil end
    _applyAutoPatch(key, {})
    return MAIN.auto[key]
end

function State.parseAuctionMaxPrice(raw)
    return _parseAuctionMaxPrice(raw)
end

function State.patchAuto(key, partial, opts)
    opts = type(opts) == "table" and opts or {}
    if type(key) ~= "string" or type(partial) ~= "table" then
        return State.getAuto(key)
    end
    _applyAutoPatch(key, partial)
    if not opts.noSync then
        local sync = AUTO_SYNC_FROM_MAIN[key]
        if sync then sync() end
    end
    return MAIN.auto[key]
end

function State.registerFlush(id, fn)
    if type(id) == "string" and id ~= "" and type(fn) == "function" then
        _UI_FLUSH[id] = fn
    end
end

function State.unregisterFlush(id)
    if type(id) == "string" then
        _UI_FLUSH[id] = nil
    end
end

function State.flushUi()
    if G.__GAG2_RESETTING == true then
        return
    end
    for _, fn in pairs(_UI_FLUSH) do
        pcall(fn)
    end
    _safeNormalizeMainAutoForSave()
end

function State.syncAllMisc()
    syncRejoinGlobalsFromMain()
    syncWeatherPredictGlobalsFromMain()
    syncPetFinderGlobalsFromMain()
    syncReduceFpsGlobalsFromMain()
    syncFruitBackpackEspGlobalsFromMain()
    syncFruitGardenEspGlobalsFromMain()
    syncHidePromptGlobalsFromMain()
    syncHideHarvestPromptGlobalsFromMain()
    syncHideLoadingGlobalsFromMain()
    syncCharacterGlobalsFromMain()
    syncAutoVulnGlobalsFromMain()
end

function State.syncAllAuto()
    _syncAllRuntimeFromMain()
end

function State.save()
    saveSelectionsToFile()
end

function State.saveFromUi()
    -- Guard re-entrancy: flush yang salah panggil saveAgain = freeze
    if G.__GAG2_SAVING_FROM_UI == true then
        return
    end
    G.__GAG2_SAVING_FROM_UI = true
    _G.__GAG2_SAVING_FROM_UI = true
    local ok, err = pcall(function()
        State.flushUi()
        State.syncAllMisc()
        _syncAllRuntimeFromMain()
        saveSelectionsToFile()
    end)
    G.__GAG2_SAVING_FROM_UI = nil
    _G.__GAG2_SAVING_FROM_UI = nil
    if not ok then
        warn("[GAG2 state] saveFromUi gagal:", tostring(err))
    end
end

function State.load()
    local function step(name, fn)
        -- Prefer G[name] (export state_a) lalu local B, lalu _G
        local f = nil
        local gfn = rawget(G, name)
        if type(gfn) == "function" then
            f = gfn
        elseif type(fn) == "function" then
            f = fn
        else
            f = rawget(_G, name)
        end
        if type(f) ~= "function" then
            warn("[GAG2] State.load skip nil:", name)
            return
        end
        local ok, err = pcall(f)
        if not ok then
            warn("[GAG2] State.load fail:", name, tostring(err))
        end
    end

    step("loadSelectionsFromFile", loadSelectionsFromFile)
    step("syncRejoinGlobalsToMain", syncRejoinGlobalsToMain)
    step("applyAutoHopModule", applyAutoHopModule)
    step("applyWeatherKickModule", applyWeatherKickModule)
    step("syncAutoCollectGlobalsFromMain", syncAutoCollectGlobalsFromMain)
    step("syncAutoPlantGlobalsFromMain", syncAutoPlantGlobalsFromMain)
    step("syncAutoTrowelGlobalsFromMain", syncAutoTrowelGlobalsFromMain)
    step("syncAutoSprinklerGlobalsFromMain", syncAutoSprinklerGlobalsFromMain)
    step("syncAutoWateringGlobalsFromMain", syncAutoWateringGlobalsFromMain)
    step("syncAutoPlotGlobalsFromMain", syncAutoPlotGlobalsFromMain)
    step("syncAutoFavGlobalsFromMain", syncAutoFavGlobalsFromMain)
    step("syncAutoUnfavGlobalsFromMain", syncAutoUnfavGlobalsFromMain)
    step("syncAutoSellGlobalsFromMain", syncAutoSellGlobalsFromMain)
    step("syncAutoSellStockGlobalsFromMain", syncAutoSellStockGlobalsFromMain)
    step("syncAutoSellDailyGlobalsFromMain", syncAutoSellDailyGlobalsFromMain)
    step("syncAutoMergeEclipseGlobalsFromMain", syncAutoMergeEclipseGlobalsFromMain)
    step("syncAutoShovelGlobalsFromMain", syncAutoShovelGlobalsFromMain)
    step("syncAutoShovelFruitGlobalsFromMain", syncAutoShovelFruitGlobalsFromMain)
    step("syncAutoBuyGlobalsFromMain", syncAutoBuyGlobalsFromMain)
    step("syncAutoClaimSeedGlobalsFromMain", syncAutoClaimSeedGlobalsFromMain)
    step("syncAutoDragonEggGlobalsFromMain", syncAutoDragonEggGlobalsFromMain)
    step("syncOpenEggGlobalsFromMain", syncOpenEggGlobalsFromMain)
    step("syncSprinklerOtherGardenGlobalsFromMain", syncSprinklerOtherGardenGlobalsFromMain)
    step("syncAutoSellPetGlobalsFromMain", syncAutoSellPetGlobalsFromMain)
    step("syncAutoTeleGlobalsFromMain", syncAutoTeleGlobalsFromMain)
    step("syncAutoGiftGlobalsFromMain", syncAutoGiftGlobalsFromMain)
    step("syncWeatherPredictGlobalsFromMain", syncWeatherPredictGlobalsFromMain)
    step("syncPetFinderGlobalsFromMain", syncPetFinderGlobalsFromMain)
    step("applyPetFinderModule", applyPetFinderModule)
    step("syncReduceFpsGlobalsFromMain", syncReduceFpsGlobalsFromMain)
    step("applyReduceFpsModule", applyReduceFpsModule)
    step("applyReduceLagModule", applyReduceLagModule)
    step("syncFruitBackpackEspGlobalsFromMain", syncFruitBackpackEspGlobalsFromMain)
    step("applyFruitBackpackEspModule", applyFruitBackpackEspModule)
    step("syncFruitGardenEspGlobalsFromMain", syncFruitGardenEspGlobalsFromMain)
    step("applyFruitGardenEspModule", applyFruitGardenEspModule)
    step("syncHidePromptGlobalsFromMain", syncHidePromptGlobalsFromMain)
    step("applyHidePromptModule", applyHidePromptModule)
    step("syncHideHarvestPromptGlobalsFromMain", syncHideHarvestPromptGlobalsFromMain)
    step("applyHideHarvestPromptModule", applyHideHarvestPromptModule)
    step("syncHideLoadingGlobalsFromMain", syncHideLoadingGlobalsFromMain)
    step("applyHideLoadingModule", applyHideLoadingModule)
    step("syncCharacterGlobalsFromMain", syncCharacterGlobalsFromMain)
    step("applyCharacterModule", applyCharacterModule)
    step("syncAutoVulnGlobalsFromMain", syncAutoVulnGlobalsFromMain)
    step("applyAutoVulnModule", applyAutoVulnModule)
    step("syncSprinklerOtherGardenGlobalsFromMain", syncSprinklerOtherGardenGlobalsFromMain)
    step("applySprinklerOtherGardenModule", applySprinklerOtherGardenModule)
    G.STATE = STATE
    _G.STATE = STATE
    return STATE
end

function State.reset()
    G.__GAG2_RESETTING = true
    _G.__GAG2_RESETTING = true
    resetAllToDefaults()
    applyResetRuntime()
    if type(G.__GAG2_APPLY_UI_DEFAULTS) == "function" then
        pcall(G.__GAG2_APPLY_UI_DEFAULTS)
    end
    if type(G.__GAG2_ON_STATE_RESET) == "function" then
        pcall(G.__GAG2_ON_STATE_RESET)
    end
    G.__GAG2_RESETTING = nil
    _G.__GAG2_RESETTING = nil
    return true
end

G.__GAG2_STATE = State
_G.__GAG2_STATE = State

G.__GAG2_RESET_STATE = function()
    return State.reset()
end
_G.__GAG2_RESET_STATE = G.__GAG2_RESET_STATE

G.__GAG2_STATE_SAVE = function()
    State.saveFromUi()
end
_G.__GAG2_STATE_SAVE = G.__GAG2_STATE_SAVE

G.__GAG2_FLUSH_TO_MAIN = function()
    State.flushUi()
    _syncAllRuntimeFromMain()
end
_G.__GAG2_FLUSH_TO_MAIN = G.__GAG2_FLUSH_TO_MAIN

return State

]==========]
    local srcBundle = [==========[
-- state_shortcut.lua — isi panel entry GAG2_STATE (opsional)
-- main_ui lebih prefer GAG2_STATE_A + GAG2_STATE_B langsung (loadstring chunk).
-- File ini hanya fallback bundle.
--
-- JANGAN pakai state.lua HTTP di sini.
--
-- Panel:
--   GAG2_STATE_A = state_a.lua (WAJIB)
--   GAG2_STATE_B = state_b.lua (WAJIB)
--   GAG2_STATE   = file ini (opsional)

(function()
%[[[GAG2_STATE_A%]]]%
end)()

return (function()
%[[[GAG2_STATE_B%]]]%
end)()

]==========]

    srcA = tostring(srcA or ""):gsub("^%s+", ""):gsub("%s+$", "")
    srcB = tostring(srcB or ""):gsub("^%s+", ""):gsub("%s+$", "")
    srcBundle = tostring(srcBundle or ""):gsub("^%s+", ""):gsub("%s+$", "")

    -- 1) A lalu B (chunk terpisah — seperti state.lua runPart)
    if not hasUnreplacedShortcode(srcA) and #srcA > 50 then
        local okA, errA = runStateSource(srcA, "GAG2_STATE_A")
        if not okA then
            lastErr = "GAG2_STATE_A: " .. tostring(errA)
        elseif G.__GAG2_STATE_A_LOADED ~= true and rawget(_G, "__GAG2_STATE_A_LOADED") ~= true then
            lastErr = "GAG2_STATE_A run OK tapi flag __GAG2_STATE_A_LOADED belum true"
        else
            if hasUnreplacedShortcode(srcB) or #srcB < 50 then
                return false, "GAG2_STATE_B kosong / belum diisi di panel (A sudah OK)"
            end
            local okB, modOrErr = runStateSource(srcB, "GAG2_STATE_B")
            if not okB then
                return false, "GAG2_STATE_B: " .. tostring(modOrErr)
            end
            local ok, mod, state = stateFromModule(modOrErr)
            if ok then
                return true, mod, state
            end
            if type(modOrErr) == "table" then
                local st = G.STATE or rawget(_G, "STATE")
                if type(st) == "table" then
                    warnlog("Pakai STATE meski State.load gagal:", tostring(state))
                    return true, modOrErr, st
                end
            end
            return false, "GAG2_STATE_B result: " .. tostring(mod or state)
        end
    else
        lastErr = "GAG2_STATE_A kosong / shortcode belum diganti panel"
    end

    -- 2) Optional bundle GAG2_STATE (= state_shortcut.lua)
    if not hasUnreplacedShortcode(srcBundle) and #srcBundle > 50 then
        local okFac, modOrErr = runStateSource(srcBundle, "GAG2_STATE")
        if okFac then
            local ok, mod, state = stateFromModule(modOrErr)
            if ok then
                return true, mod, state
            end
            lastErr = "GAG2_STATE: " .. tostring(mod or state)
        else
            lastErr = "GAG2_STATE: " .. tostring(modOrErr)
        end
    end

    return false, lastErr or "Isi panel GAG2_STATE_A (=state_a.lua) + GAG2_STATE_B (=state_b.lua)"
end

