----------------------------------------------------------------
-- LOAD STATE DULU (sebelum ReduceLag / Remove Garden / AntiAFK)
----------------------------------------------------------------
local StateModule
local STATE

for attempt = 1, STATE_RETRY do
    local ok, modOrErr, state = loadStateOnce()
    if ok then
        StateModule = modOrErr
        STATE = state
        break
    end
    warnlog("State load gagal:", tostring(modOrErr))
    task.wait(STATE_RETRY_DELAY)
end

if type(STATE) ~= "table" then
    STATE = DEFAULT_STATE_FALLBACK
    warnlog("State fallback dipakai — isi panel GAG2_STATE_A + GAG2_STATE_B (bukan LINK)")
end

G.STATE = STATE
_G.STATE = STATE

local function applyHideLoadingRuntime()
    local applyFn = G.applyHideLoadingModule or rawget(_G, "applyHideLoadingModule")
    if type(applyFn) == "function" then
        pcall(applyFn)
    end
end

local function applyHideHarvestPromptRuntime()
    local applyFn = G.applyHideHarvestPromptModule or rawget(_G, "applyHideHarvestPromptModule")
    if type(applyFn) == "function" then
        pcall(applyFn)
    end
end

local function applyCharacterRuntime()
    local applyFn = G.applyCharacterModule or rawget(_G, "applyCharacterModule")
    if type(applyFn) == "function" then
        pcall(applyFn)
    end
end

if StateModule then
    G.__GAG2_STATE = StateModule
    _G.__GAG2_STATE = StateModule
    if type(StateModule.syncAllMisc) == "function" then
        pcall(StateModule.syncAllMisc)
    end
    if type(StateModule.syncAllAuto) == "function" then
        pcall(StateModule.syncAllAuto)
    end
    applyHideLoadingRuntime()
    applyHideHarvestPromptRuntime()
    applyCharacterRuntime()
else
    warn("[GrowAGarden2] State TIDAK LOAD — isi GAG2_STATE_A (=state_a.lua) + GAG2_STATE_B (=state_b.lua) di panel.")
end

local function applyHidePromptRuntime()
    local applyFn = G.applyHidePromptModule or rawget(_G, "applyHidePromptModule")
    if type(applyFn) == "function" then
        pcall(applyFn)
        return
    end
    local R = G.PSReconnect or rawget(_G, "PSReconnect")
    local on = (G.HIDE_PROMPT_ENABLED == true) or (rawget(_G, "HIDE_PROMPT_ENABLED") == true)
    if type(R) == "table" and type(R.SetHideTeleportPrompt) == "function" then
        pcall(R.SetHideTeleportPrompt, R, on)
    end
end

----------------------------------------------------------------
-- LOAD MODULE WITH RETRY
----------------------------------------------------------------
local function loadOneModule(def)
    local lastErr = "unknown"
    for attempt = 1, BOOT_RETRY do
        local ok, resultOrErr = runFactory(def)
        if ok then
            return true, resultOrErr
        end
        lastErr = tostring(resultOrErr)
        warnlog(("Load gagal %s %d/%d: %s"):format(tostring(def.name), attempt, BOOT_RETRY, lastErr))
        task.wait(RETRY_DELAY)
    end
    return false, lastErr
end

local Loaded = {}

local function exposeEarlyModules()
    local env = (getgenv and getgenv()) or _G
    if type(Loaded.antiafk) == "table" then
        env.AntiAFK = Loaded.antiafk
        env.antiafk = Loaded.antiafk
        _G.AntiAFK = Loaded.antiafk
        _G.antiafk = Loaded.antiafk
    end
    if type(Loaded.PSReconnect) == "table" then
        env.PSReconnect = Loaded.PSReconnect
        _G.PSReconnect = Loaded.PSReconnect
    end
    if type(Loaded.ReduceFPS) == "table" then
        env.ReduceFPS = Loaded.ReduceFPS
        env.ReduceFPSModule = Loaded.ReduceFPS
        _G.ReduceFPS = Loaded.ReduceFPS
        _G.ReduceFPSModule = Loaded.ReduceFPS
        G.ReduceFPS = Loaded.ReduceFPS
        G.ReduceFPSModule = Loaded.ReduceFPS
    end
    if type(Loaded.ReduceLag) == "table" then
        env.ReduceLag = Loaded.ReduceLag
        env.ReduceLagModule = Loaded.ReduceLag
        _G.ReduceLag = Loaded.ReduceLag
        _G.ReduceLagModule = Loaded.ReduceLag
        G.ReduceLag = Loaded.ReduceLag
        G.ReduceLagModule = Loaded.ReduceLag
    end
end

-- Seed flag dari MAIN.misc.perf supaya SyncFromGlobals/Start jalan sebelum UI/tabs
local function seedPerfFlagsFromMain()
    local MAIN = rawget(_G, "MAIN") or G.MAIN
    local perf = MAIN and MAIN.misc and MAIN.misc.perf
    if type(perf) ~= "table" then return end
    if perf.enabled == true then
        -- soft shell wajib dari boot (jangan nunggu klik gear settings)
        perf.hide_own = true
        G.REDUCE_FPS_ENABLED = true
        _G.REDUCE_FPS_ENABLED = true
        G.REDUCE_FPS_HIDE_OWN = true
        _G.REDUCE_FPS_HIDE_OWN = true
    end
    if perf.reduce_lag == true then
        G.REDUCE_LAG_ENABLED = true
        _G.REDUCE_LAG_ENABLED = true
    end
end

-- Urutan wajib: ReduceLag → Remove Garden → AntiAFK
local function syncEarlyPerfModules()
    seedPerfFlagsFromMain()
    local RL = Loaded.ReduceLag
    if type(RL) == "table" then
        if type(RL.SyncFromGlobals) == "function" then
            pcall(RL.SyncFromGlobals, RL)
        elseif (G.REDUCE_LAG_ENABLED == true or rawget(_G, "REDUCE_LAG_ENABLED") == true) then
            moduleStart(RL)
        end
    end
    local RF = Loaded.ReduceFPS
    if type(RF) == "table" then
        if type(RF.SyncFromGlobals) == "function" then
            pcall(RF.SyncFromGlobals, RF)
        elseif (G.REDUCE_FPS_ENABLED == true or rawget(_G, "REDUCE_FPS_ENABLED") == true) then
            moduleStart(RF)
        end
    end
end

local function startEarlyModules()
    exposeEarlyModules()
    -- Sync/Start berurutan (bukan parallel defer) — Lag → Remove Garden → AntiAFK
    syncEarlyPerfModules()
    moduleStart(Loaded.antiafk)
    task.defer(function()
        task.wait(0.2)
        pcall(function()
            callMethod(Loaded.PSReconnect, { "SyncFromState", "syncFromState" }, STATE)
        end)
        moduleStart(Loaded.PSReconnect)
        applyHidePromptRuntime()
    end)
end

local function loadModuleSet(label, filterFn)
    local list = {}
    for _, def in ipairs(MODULE_DEFS) do
        if filterFn(def) then
            list[#list + 1] = def
        end
    end

    for _, def in ipairs(list) do
        local ok, modOrErr = loadOneModule(def)
        if ok then
            Loaded[def.key] = modOrErr
            if def.key == "antiafk" and not isValidAntiafkMod(modOrErr) then
                warnlog("AntiAFK load OK tapi API kurang (Start/AutoSkipLoading)")
                warnlog("Cek entry GAG2_ANTIAFK di panel (upload antiafk.lua terbaru)")
            end
        elseif def.required then
            failBoot(("required module failed: %s | %s"):format(tostring(def.name), tostring(modOrErr)))
        else
            warnlog("Optional module skip:", tostring(def.name), tostring(modOrErr))
            Loaded[def.key] = {}
        end
    end
end

loadModuleSet("Early", function(def) return def.early == true end)
startEarlyModules()

loadModuleSet("Module", function(def) return def.early ~= true end)

local function ensureLoadedModule(key)
    if isLoadedModule(Loaded[key]) then return Loaded[key] end
    for _, def in ipairs(MODULE_DEFS) do
        if def.key == key then
            local ok, modOrErr = loadOneModule(def)
            if ok then
                Loaded[key] = modOrErr
                return modOrErr
            end
            return nil
        end
    end
    return nil
end

G.__GAG2_ENSURE_LOADED_MODULE = ensureLoadedModule
_G.__GAG2_ENSURE_LOADED_MODULE = ensureLoadedModule

