        G.AutoSprinklerOtherGardenModule = VSW
        _G.AutoSprinklerOtherGarden = VSW
        _G.AutoSprinklerOtherGardenModule = VSW
        G.AutoVulnSprinklerWater = VSW
        G.AutoVulnSprinklerWaterModule = VSW
        _G.AutoVulnSprinklerWater = VSW
        _G.AutoVulnSprinklerWaterModule = VSW
    end

    local applyUNS = rawget(_G, "applyUpdateNewServerModule") or rawget(G, "applyUpdateNewServerModule")
    local readUNS  = rawget(_G, "readUpdateNewServerGlobals") or rawget(G, "readUpdateNewServerGlobals")
    if type(applyUNS) == "function" then
        if type(readUNS) == "function" then
            local en, mi = readUNS()
            pcall(applyUNS, en, mi)
        else
            pcall(applyUNS)
        end
    end

    local applyWK = rawget(_G, "applyWeatherKickModule") or rawget(G, "applyWeatherKickModule")
    local readWK  = rawget(_G, "readWeatherKickGlobals") or rawget(G, "readWeatherKickGlobals")
    if type(applyWK) == "function" then
        if type(readWK) == "function" then
            local en, selected, _, _, delay = readWK()
            pcall(applyWK, en, selected, delay)
        else
            pcall(applyWK)
        end
    end

    local applyOE = rawget(_G, "applyOpenEggModule") or rawget(G, "applyOpenEggModule")
        or rawget(_G, "applyAutoVulnModule") or rawget(G, "applyAutoVulnModule")
    if type(applyOE) == "function" then
        pcall(applyOE)
    end

    local applyVSW = rawget(_G, "applySprinklerOtherGardenModule") or rawget(G, "applySprinklerOtherGardenModule")
        or rawget(_G, "applyAutoVulnSprinklerWaterModule") or rawget(G, "applyAutoVulnSprinklerWaterModule")
    if type(applyVSW) == "function" then
        pcall(applyVSW)
    end
end

